async function purgePassVaultFromDevtools() {
  setBusy(true, "Purging UnderPAR vault...");
  setStatus("Purging UnderPAR vault, DCR caches, and saved-query state...", "info");
  state.sessionMonitorSuppressed = true;
  cancelPendingBootstrapSession();
  try {
    await persistManualSignOutHold(true, "vault-purge");
    await clearDebugFlowStorageFromChromeStorage();
    purgeAvatarCaches();
    purgeDcrCaches();
    purgeLegacySavedEsmQueryEntriesFromLocalStorage();
    if (canUseUnderparVaultIndexedDb()) {
      await underparVaultStore.clear().catch(() => false);
    }
    if (chrome?.storage?.local?.remove) {
      await chrome.storage.local.remove([
        UNDERPAR_VAULT_STORAGE_KEY,
        CM_TENANTS_CATALOG_STORAGE_KEY,
        LEGACY_CM_TENANTS_CATALOG_STORAGE_KEY,
      ]);
    }
    const message = "UnderPAR vault purged. Click Sign In when ready.";
    await resetToSignedOutState({
      closeWorkspaceReason: "up-devtools-vault-purge",
      preservePassVault: false,
      statusMessage: message,
      statusType: "success",
    });
    return {
      purged: true,
      vaultPayload: cloneJsonLikeValue(state.passVault, null),
      message,
    };
  } finally {
    setBusy(false);
    render();
  }
}

function getPassVaultServiceProvisioningRank(programmerId = "", appInfo = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const guid = String(appInfo?.guid || "").trim();
  if (!guid) {
    return 0;
  }
  if (normalizedProgrammerId && hasPassVaultServiceClientCredentials(normalizedProgrammerId, appInfo)) {
    return 3;
  }
  const softwareStatement = firstNonEmptyString([
    String(appInfo?.softwareStatement || "").trim(),
    extractSoftwareStatementFromAppData(appInfo?.appData || null),
    extractSoftwareStatementFromAppData(appInfo),
  ]);
  if (softwareStatement) {
    return 2;
  }
  return 1;
}

function pickHighestRankedPassVaultServiceCandidate(appInfos = [], programmerId = "", options = {}) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const candidates = Array.isArray(appInfos) ? appInfos.filter((appInfo) => appInfo?.guid) : [];
  const useDegradationTieBreak = options?.degradationTieBreak === true;
  let bestCandidate = null;
  let bestRank = -1;

  candidates.forEach((candidate) => {
    const candidateRank = getPassVaultServiceProvisioningRank(normalizedProgrammerId, candidate);
    if (!bestCandidate || candidateRank > bestRank) {
      bestCandidate = candidate;
      bestRank = candidateRank;
      return;
    }
    if (candidateRank !== bestRank) {
      return;
    }
    if (useDegradationTieBreak && compareDegradationAppPriority(candidate, bestCandidate) < 0) {
      bestCandidate = candidate;
    }
  });

  return bestCandidate;
}

function collectPassVaultServiceCredentialCandidates(programmerId = "", serviceKey = "", services = null) {
  const normalizedServiceKey = String(serviceKey || "").trim();
  const candidates = [];
  const seen = new Set();
  const pushCandidate = (appInfo) => {
    const guid = String(appInfo?.guid || "").trim();
    if (!guid || seen.has(guid)) {
      return;
    }
    seen.add(guid);
    candidates.push(appInfo);
  };

  if (normalizedServiceKey === "restV2") {
    pushCandidate(services?.restV2 || null);
    if (Array.isArray(services?.restV2Apps)) {
      services.restV2Apps.forEach((appInfo) => pushCandidate(appInfo));
    }
  } else if (normalizedServiceKey === "esm") {
    pushCandidate(services?.esm || null);
    if (Array.isArray(services?.esmApps)) {
      services.esmApps.forEach((appInfo) => pushCandidate(appInfo));
    }
  } else if (normalizedServiceKey === "degradation") {
    pushCandidate(services?.degradation || null);
    if (Array.isArray(services?.degradationApps)) {
      services.degradationApps.forEach((appInfo) => pushCandidate(appInfo));
    }
  }

  return candidates;
}

function buildPassVaultHydrationRegisteredApplications(applicationsData = {}) {
  const source =
    applicationsData && typeof applicationsData === "object" && !Array.isArray(applicationsData) ? applicationsData : {};
  const applications = Object.values(source)
    .map((item) => {
      const application = normalizeRegisteredApplicationRuntimeRecord(item);
      if (!application || typeof application !== "object") {
        return null;
      }

      const appData =
        application?.appData && typeof application.appData === "object" && !Array.isArray(application.appData)
          ? application.appData
          : application?.raw && typeof application.raw === "object" && !Array.isArray(application.raw)
            ? application.raw
            : application;
      const rawScopes = Array.isArray(appData?.scopes)
        ? appData.scopes.map((scope) => String(scope || "").trim()).filter(Boolean)
        : [];
      const scopeLabels = buildRegisteredApplicationScopeLabels(rawScopes);
      const appName = firstNonEmptyString([
        appData?.displayName,
        appData?.name,
        appData?.clientId,
        appData?.label,
        appData?.title,
        application?.name,
        application?.label,
        application?.guid,
        application?.id,
      ]);

      return {
        ...application,
        key: firstNonEmptyString([application?.key, application?.id, application?.guid]),
        id: firstNonEmptyString([application?.id, application?.guid, application?.key]),
        guid: firstNonEmptyString([application?.guid, application?.id, application?.key]),
        name: appName,
        label: buildRegisteredApplicationLabel(appName, scopeLabels, appName),
        clientId: firstNonEmptyString([appData?.clientId, appData?.client_id, application?.clientId]),
        scopes: rawScopes.map((scope) => normalizeScope(scope)).filter(Boolean),
        scopeLabels,
        type: firstNonEmptyString([appData?.type, appData?.applicationType, application?.type]),
        softwareStatement: firstNonEmptyString([
          extractSoftwareStatementFromAppData(appData),
          application?.softwareStatement,
        ]),
        raw: appData,
        appData,
      };
    })
    .filter((item) => item && typeof item === "object");

  applications.sort((left, right) => {
    const leftLabel = firstNonEmptyString([left?.name, left?.label, left?.id]);
    const rightLabel = firstNonEmptyString([right?.name, right?.label, right?.id]);
    return leftLabel.localeCompare(rightLabel, undefined, {
      sensitivity: "base",
    });
  });

  return applications;
}

function buildPassVaultCompactRegisteredApplication(application = null) {
  if (!application || typeof application !== "object") {
    return null;
  }

  const normalizedApplication = {
    key: firstNonEmptyString([application?.key, application?.id, application?.guid]),
    id: firstNonEmptyString([application?.id, application?.guid, application?.key]),
    guid: firstNonEmptyString([application?.guid, application?.id, application?.key]),
    name: firstNonEmptyString([application?.name, application?.displayName]),
    label: firstNonEmptyString([application?.label, application?.name, application?.displayName, application?.guid, application?.id]),
    clientId: firstNonEmptyString([application?.clientId]),
    scopes: (Array.isArray(application?.scopes) ? application.scopes : []).map((scope) => normalizeScope(scope)).filter(Boolean),
    scopeLabels: Array.isArray(application?.scopeLabels) ? application.scopeLabels.filter(Boolean) : [],
    type: firstNonEmptyString([application?.type]),
    softwareStatement: firstNonEmptyString([
      application?.softwareStatement,
      extractSoftwareStatementFromAppData(application?.appData || null),
      extractSoftwareStatementFromAppData(application?.raw || null),
      extractSoftwareStatementFromAppData(application),
    ]),
    raw:
      application?.raw && typeof application.raw === "object" && !Array.isArray(application.raw)
        ? cloneJsonLikeValue(application.raw, null)
        : null,
    appData:
      application?.appData && typeof application.appData === "object" && !Array.isArray(application.appData)
        ? cloneJsonLikeValue(application.appData, null)
        : application?.raw && typeof application.raw === "object" && !Array.isArray(application.raw)
          ? cloneJsonLikeValue(application.raw, null)
          : null,
  };

  return normalizedApplication.guid || normalizedApplication.id || normalizedApplication.key ? normalizedApplication : null;
}

function registeredApplicationMatchesNativeRequiredScope(application = null, requiredScope = "") {
  const normalizedRequiredScope = normalizeScope(requiredScope);
  if (!application || !normalizedRequiredScope) {
    return false;
  }

  return (Array.isArray(application?.scopes) ? application.scopes : [])
    .map((scope) => normalizeScope(scope))
    .filter(Boolean)
    .includes(normalizedRequiredScope);
}

function buildPassVaultExistingHydrationServiceRecord(programmerId = "", existingRecord = null, serviceKey = "") {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedServiceKey = String(serviceKey || "").trim();
  if (!normalizedProgrammerId || !existingRecord || typeof existingRecord !== "object" || !normalizedServiceKey) {
    return null;
  }

  const runtimeServices = buildPassVaultRuntimeServicesSnapshot(existingRecord) || {};
  const registeredApplication =
    runtimeServices?.[normalizedServiceKey] && typeof runtimeServices[normalizedServiceKey] === "object"
      ? cloneJsonLikeValue(runtimeServices[normalizedServiceKey], null)
      : null;
  const guid = String(registeredApplication?.guid || "").trim();
  if (!guid) {
    return null;
  }

  const applicationRecord = getPassVaultRegisteredApplicationsByGuid(existingRecord)?.[guid] || null;
  const client =
    normalizeUnderparVaultCredentialEntry(loadDcrCache(normalizedProgrammerId, guid) || null) ||
    normalizeUnderparVaultCredentialEntry(applicationRecord?.serviceCredentialsByServiceKey?.[normalizedServiceKey] || null) ||
    normalizeUnderparVaultCredentialEntry(applicationRecord?.dcrCache || null) ||
    null;

  return {
    registeredApplication,
    client,
  };
}

function buildPassVaultCompactRegisteredApplicationIdentity(application = null) {
  return firstNonEmptyString([application?.guid, application?.id, application?.key]);
}

function compactPassVaultRegisteredApplicationsMatch(left = null, right = null) {
  const leftIdentity = buildPassVaultCompactRegisteredApplicationIdentity(left);
  const rightIdentity = buildPassVaultCompactRegisteredApplicationIdentity(right);
  return Boolean(leftIdentity) && leftIdentity === rightIdentity;
}

function resolvePassVaultHydrationServiceApplication({
  definition = null,
  programmerId = "",
  registeredApplications = [],
  existingRecord = null,
} = {}) {
  const normalizedDefinition = definition && typeof definition === "object" ? definition : null;
  if (!normalizedDefinition) {
    return null;
  }

  const normalizedApplications = Array.isArray(registeredApplications) ? registeredApplications : [];
  const matchingApplication = normalizedApplications.find((application) =>
    registeredApplicationMatchesNativeRequiredScope(application, normalizedDefinition.requiredScope)
  );
  const existingService = buildPassVaultExistingHydrationServiceRecord(
    programmerId,
    existingRecord,
    normalizedDefinition.serviceKey
  );

  return buildPassVaultCompactRegisteredApplication(
    matchingApplication || (normalizedApplications.length === 0 ? existingService?.registeredApplication : null)
  );
}

function buildPassVaultServiceHydrationEntries({
  programmer = null,
  registeredApplications = [],
  existingRecord = null,
} = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const entries = {};

  UNDERPAR_VAULT_DCR_SERVICE_DEFINITIONS.forEach((definition) => {
    const existingService = buildPassVaultExistingHydrationServiceRecord(
      programmerId,
      existingRecord,
      definition.serviceKey
    );
    const registeredApplication = resolvePassVaultHydrationServiceApplication({
      definition,
      programmerId,
      registeredApplications,
      existingRecord,
    });
    const appGuid = String(registeredApplication?.guid || "").trim();
    const cachedClient =
      normalizeUnderparVaultCredentialEntry((programmerId && appGuid ? loadDcrCache(programmerId, appGuid) : null) || null) ||
      null;
    const client =
      cachedClient ||
      (compactPassVaultRegisteredApplicationsMatch(registeredApplication, existingService?.registeredApplication) &&
      existingService?.client &&
      typeof existingService.client === "object")
        ? {
            ...(cachedClient || existingService.client),
          }
        : null;

    entries[definition.serviceKey] = {
      key: definition.serviceKey,
      label: definition.label,
      available: Boolean(registeredApplication),
      requiredScope: definition.requiredScope,
      registeredApplication: registeredApplication ? cloneJsonLikeValue(registeredApplication, null) : null,
      client,
      status: registeredApplication ? (client?.clientId && client?.clientSecret ? "ready" : "pending") : "unavailable",
    };
  });

  return entries;
}

function serviceClientNeedsPassVaultRefresh(client = null, requiredScope = "", serviceKey = "") {
  const currentClient = normalizeUnderparVaultDcrCache(client || null);
  if (!currentClient?.clientId || !currentClient?.clientSecret) {
    return true;
  }
  if (!currentClient?.accessToken) {
    return true;
  }

  const tokenClaims = parseJwtPayload(String(currentClient.accessToken || "")) || {};
  const expiresAtMs = Number(tokenClaims?.exp || 0) > 0
    ? Number(tokenClaims.exp) * 1000
    : Number(currentClient.tokenExpiresAt || 0);
  if (!Number.isFinite(expiresAtMs) || expiresAtMs <= Date.now() + 60 * 1000) {
    return true;
  }

  const normalizedRequiredScope = normalizeScope(requiredScope);
  if (!normalizedRequiredScope) {
    return false;
  }

  const tokenScope = firstNonEmptyString([currentClient.tokenScope, tokenClaims?.scope]);
  const strictScopeValidation = String(serviceKey || "").trim() === "esm";
  const scopeSatisfied = tokenScopeSatisfiesRequiredScope(
    tokenScope,
    String(currentClient.accessToken || ""),
    normalizedRequiredScope,
    {
      strictUnknown: strictScopeValidation,
      requestedScopeHint: String(currentClient.tokenRequestedScope || currentClient.serviceScope || ""),
    }
  );
  if (scopeSatisfied) {
    return false;
  }

  return !shouldAllowImplicitEsmTokenScope(
    normalizedRequiredScope,
    String(serviceKey || ""),
    String(currentClient.accessToken || ""),
    String(currentClient.tokenRequestedScope || currentClient.serviceScope || "")
  );
}

async function hydratePassVaultServiceRecordWithContext(serviceRecord = null, definition = null, hydrationContext = {}) {
  const normalizedDefinition = definition && typeof definition === "object" ? definition : null;
  const currentRecord = serviceRecord && typeof serviceRecord === "object" ? serviceRecord : {};
  let registeredApplication =
    currentRecord?.registeredApplication && typeof currentRecord.registeredApplication === "object"
      ? cloneJsonLikeValue(currentRecord.registeredApplication, null)
      : null;
  if (!normalizedDefinition || !registeredApplication) {
    return {
      ...currentRecord,
      status: "unavailable",
    };
  }

  const programmerId = String(hydrationContext?.programmerId || "").trim();
  const guid = String(registeredApplication?.guid || "").trim();
  const sharedHydratedApplicationsByGuid =
    hydrationContext?.sharedHydratedApplicationsByGuid instanceof Map
      ? hydrationContext.sharedHydratedApplicationsByGuid
      : null;
  const sharedClientByGuid =
    hydrationContext?.sharedClientByGuid instanceof Map ? hydrationContext.sharedClientByGuid : null;
  const sharedHydratedApplication =
    guid && sharedHydratedApplicationsByGuid?.has(guid)
      ? cloneJsonLikeValue(sharedHydratedApplicationsByGuid.get(guid), null)
      : null;
  if (sharedHydratedApplication && typeof sharedHydratedApplication === "object") {
    registeredApplication = sharedHydratedApplication;
  }
  const applicationLabel = firstNonEmptyString([
    registeredApplication?.name,
    registeredApplication?.label,
    registeredApplication?.appName,
    guid,
  ]);
  const now = Date.now();
  const requiredScope = getPassVaultRequiredScopeForService(normalizedDefinition.serviceKey, registeredApplication);
  const cachedClient =
    normalizeUnderparVaultDcrCache((programmerId && guid ? loadDcrCache(programmerId, guid) : null) || null) || null;
  const sharedClient = normalizeUnderparVaultDcrCache((guid ? sharedClientByGuid?.get(guid) : null) || null) || null;
  const nextClient =
    normalizeUnderparVaultDcrCache(currentRecord?.client || null) ||
    cachedClient ||
    sharedClient ||
    createEmptyUnderparVaultCredential();

  nextClient.serviceScope = String(requiredScope || nextClient.serviceScope || "").trim();
  if (guid && sharedHydratedApplicationsByGuid && !sharedHydratedApplicationsByGuid.has(guid)) {
    sharedHydratedApplicationsByGuid.set(guid, cloneJsonLikeValue(registeredApplication, null));
  }
  if (guid && sharedClientByGuid && (nextClient.clientId || nextClient.clientSecret || nextClient.accessToken)) {
    sharedClientByGuid.set(guid, {
      ...nextClient,
    });
  }

  if (!nextClient.clientId || !nextClient.clientSecret) {
    registeredApplication =
      (await enrichRegisteredApplicationForHydration(registeredApplication, {
        timeoutMs: PREMIUM_APPLICATION_DETAIL_TIMEOUT_MS,
        preferAuthenticatedHeaders: true,
        preferredTabId: Number(hydrationContext?.preferredTabId || 0),
        allowTemporaryPageContextTab: hydrationContext?.allowTemporaryPageContextTab === true,
        pageContextTargetRef:
          hydrationContext?.pageContextTargetRef && typeof hydrationContext.pageContextTargetRef === "object"
            ? hydrationContext.pageContextTargetRef
            : null,
      }).catch(() => registeredApplication)) || registeredApplication;
    if (guid && sharedHydratedApplicationsByGuid) {
      sharedHydratedApplicationsByGuid.set(guid, cloneJsonLikeValue(registeredApplication, null));
    }

    const softwareStatement = firstNonEmptyString([
      registeredApplication?.softwareStatement,
      extractSoftwareStatementFromAppData(registeredApplication?.appData || null),
      extractSoftwareStatementFromAppData(registeredApplication),
    ]);
    if (!softwareStatement) {
      return {
        ...currentRecord,
        available: true,
        requiredScope,
        registeredApplication,
        client: normalizeUnderparVaultCredentialEntry({
          ...nextClient,
          updatedAt: now,
          error: `No software statement found on app ${applicationLabel}`,
        }),
        status: "partial",
      };
    }

    try {
      const registeredClient = await registerClientWithSoftwareStatement(softwareStatement);
      nextClient.clientId = registeredClient.clientId;
      nextClient.clientSecret = registeredClient.clientSecret;
      nextClient.updatedAt = now;
      nextClient.error = "";
      if (programmerId && guid) {
        saveDcrCache(programmerId, guid, nextClient);
      }
      if (guid && sharedClientByGuid) {
        sharedClientByGuid.set(guid, {
          ...nextClient,
        });
      }
    } catch (error) {
      return {
        ...currentRecord,
        available: true,
        requiredScope,
        registeredApplication,
        client: normalizeUnderparVaultCredentialEntry({
          ...nextClient,
          updatedAt: now,
          error: error instanceof Error ? error.message : String(error),
        }),
        status: "partial",
      };
    }
  }

  if (hydrationContext?.forceRefresh === true || serviceClientNeedsPassVaultRefresh(nextClient, requiredScope, normalizedDefinition.serviceKey)) {
    try {
      const strictScopeValidation = normalizedDefinition.serviceKey === "esm";
      const tokenAttemptMode = strictScopeValidation ? "scoped-only" : "default";
      const token = await requestClientCredentialsToken(
        nextClient.clientId,
        nextClient.clientSecret,
        {
          service: normalizedDefinition.serviceKey,
          scope: normalizedDefinition.serviceKey,
          requiredServiceScope: requiredScope,
          appGuid: guid,
          appName: String(registeredApplication?.appName || guid || ""),
        },
        requiredScope,
        {
          strictScopeValidation,
          tokenAttemptMode,
        }
      );
      nextClient.accessToken = token.accessToken;
      nextClient.tokenExpiresAt = token.tokenExpiresAt;
      nextClient.tokenScope = String(token.tokenScope || "");
      nextClient.tokenRequestedScope = String(token.attemptedScope || requiredScope || "").trim();
      nextClient.serviceScope = String(requiredScope || "").trim();
      nextClient.updatedAt = now;
      nextClient.error = "";
      if (programmerId && guid) {
        saveDcrCache(programmerId, guid, nextClient);
      }
      if (guid && sharedClientByGuid) {
        sharedClientByGuid.set(guid, {
          ...nextClient,
        });
      }
    } catch (error) {
      return {
        ...currentRecord,
        available: true,
        requiredScope,
        registeredApplication,
        client: normalizeUnderparVaultCredentialEntry({
          ...nextClient,
          updatedAt: now,
          error: error instanceof Error ? error.message : String(error),
        }),
        status: "partial",
      };
    }
  } else if (programmerId && guid) {
    saveDcrCache(programmerId, guid, nextClient);
  }
  if (guid && sharedClientByGuid) {
    sharedClientByGuid.set(guid, {
      ...nextClient,
    });
  }

  return {
    ...currentRecord,
    available: true,
    requiredScope,
    registeredApplication,
    client: normalizeUnderparVaultCredentialEntry({
      ...nextClient,
      updatedAt: now,
      error: "",
    }),
    status: "ready",
  };
}

async function hydratePassVaultServiceEntries(entries = {}, serviceKeys = null, hydrationContext = {}) {
  const nextEntries = entries && typeof entries === "object" ? { ...entries } : {};
  const requestedServiceKeys = new Set(
    (Array.isArray(serviceKeys) ? serviceKeys : [])
      .map((serviceKey) => String(serviceKey || "").trim())
      .filter(Boolean)
  );
  const definitionsToHydrate = requestedServiceKeys.size > 0
    ? UNDERPAR_VAULT_DCR_SERVICE_DEFINITIONS.filter((definition) => requestedServiceKeys.has(definition.serviceKey))
    : UNDERPAR_VAULT_DCR_SERVICE_DEFINITIONS;
  const pageContextTargetRef =
    hydrationContext?.pageContextTargetRef && typeof hydrationContext.pageContextTargetRef === "object"
      ? hydrationContext.pageContextTargetRef
      : { target: null };
  const sharedHydratedApplicationsByGuid = new Map();
  const sharedClientByGuid = new Map();

  try {
    for (const definition of definitionsToHydrate) {
      nextEntries[definition.serviceKey] = await hydratePassVaultServiceRecordWithContext(
        nextEntries[definition.serviceKey],
        definition,
        {
          ...hydrationContext,
          pageContextTargetRef,
          sharedHydratedApplicationsByGuid,
          sharedClientByGuid,
        }
      );
    }
  } finally {
    await closeTemporaryAdobePageContextTarget(pageContextTargetRef?.target?.temporaryTarget || null).catch(() => null);
  }

  return nextEntries;
}

function mergeHydratedServiceEntriesIntoApplicationsData(applicationsData = {}, hydratedServiceEntries = {}) {
  const nextApplications =
    applicationsData && typeof applicationsData === "object" && !Array.isArray(applicationsData)
      ? cloneJsonLikeValue(applicationsData, {})
      : {};

  Object.values(hydratedServiceEntries || {}).forEach((serviceRecord) => {
    const registeredApplication =
      serviceRecord?.registeredApplication && typeof serviceRecord.registeredApplication === "object"
        ? serviceRecord.registeredApplication
        : null;
    const guid = String(registeredApplication?.guid || "").trim();
    if (!guid) {
      return;
    }

    const existingApplication =
      nextApplications?.[guid] && typeof nextApplications[guid] === "object" && !Array.isArray(nextApplications[guid])
        ? nextApplications[guid]
        : null;
    const mergedApplication = mergeHydratedRegisteredApplication(
      existingApplication || registeredApplication,
      registeredApplication?.appData || registeredApplication,
      registeredApplication?.softwareStatement || ""
    );
    const fetchOrder = Number(existingApplication?.__underparFetchOrder);

    nextApplications[guid] =
      normalizeRegisteredApplicationRuntimeRecord({
        ...(existingApplication || {}),
        ...(mergedApplication || {}),
        appData: {
          ...(existingApplication?.appData && typeof existingApplication.appData === "object" ? existingApplication.appData : {}),
          ...(mergedApplication?.appData && typeof mergedApplication.appData === "object" ? mergedApplication.appData : {}),
        },
        softwareStatement: firstNonEmptyString([
          mergedApplication?.softwareStatement,
          existingApplication?.softwareStatement,
        ]),
        ...(Number.isFinite(fetchOrder) && fetchOrder >= 0 ? { __underparFetchOrder: fetchOrder } : {}),
      }) || existingApplication || mergedApplication;
  });

  return nextApplications;
}

function buildPassVaultDirectPremiumServicesSnapshot(
  programmer = null,
  registeredApplications = [],
  hydratedServiceEntries = {},
  options = {}
) {
  const normalizedApplications = Array.isArray(registeredApplications) ? registeredApplications.filter((app) => app?.guid) : [];
  const restV2Apps = normalizedApplications.filter((application) =>
    registeredApplicationMatchesNativeRequiredScope(application, REST_V2_SCOPE)
  );
  const esmApps = normalizedApplications.filter((application) =>
    registeredApplicationMatchesNativeRequiredScope(application, PREMIUM_SERVICE_SCOPE_BY_KEY.esm)
  );
  const degradationApps = normalizedApplications.filter((application) =>
    registeredApplicationMatchesNativeRequiredScope(application, PREMIUM_SERVICE_SCOPE_BY_KEY.degradation)
  );
  const resetTempPassApps = normalizedApplications.filter((application) =>
    registeredApplicationMatchesNativeRequiredScope(application, PREMIUM_SERVICE_RESET_TEMPPASS_SCOPE)
  );

  return applyPremiumServiceRuntimeSummary(
    programmer,
    {
      restV2Apps,
      restV2: hydratedServiceEntries?.restV2?.registeredApplication || restV2Apps[0] || null,
      esmApps,
      esm: hydratedServiceEntries?.esm?.registeredApplication || esmApps[0] || null,
      degradationApps,
      degradation: hydratedServiceEntries?.degradation?.registeredApplication || degradationApps[0] || null,
      resetTempPassApps,
      resetTempPass: hydratedServiceEntries?.resetTempPass?.registeredApplication || resetTempPassApps[0] || null,
      cm: options?.cmServiceSnapshot ?? null,
      cmMvpd: options?.cmMvpdServiceSnapshot ?? null,
      cmMvpdSelectionKey: String(options?.cmMvpdSelectionKey || "").trim(),
      __underparLiveHydrated: true,
      __underparLiveHydratedAt: Date.now(),
    },
    {
      cmCatalog: state.cmTenantsCatalog,
    }
  );
}

function buildPassVaultDirectCredentialResults(hydratedServiceEntries = {}) {
  return UNDERPAR_VAULT_DCR_SERVICE_DEFINITIONS.map((definition) => {
    const serviceRecord = hydratedServiceEntries?.[definition.serviceKey] || null;
    const guid = String(serviceRecord?.registeredApplication?.guid || "").trim();
    return {
      serviceKey: definition.serviceKey,
      appGuid: guid,
      cache: normalizeUnderparVaultDcrCache(serviceRecord?.client || null),
      error: String(serviceRecord?.client?.error || "").trim(),
    };
  }).filter((result) => String(result?.appGuid || "").trim());
}

function getPassVaultCredentialResultsForServiceKeys(
  credentialResults = [],
  serviceKeys = PREMIUM_REQUIRED_SERVICE_KEYS
) {
  const requestedServiceKeys = new Set(
    (Array.isArray(serviceKeys) && serviceKeys.length > 0 ? serviceKeys : PREMIUM_REQUIRED_SERVICE_KEYS)
      .map((serviceKey) => String(serviceKey || "").trim())
      .filter(Boolean)
  );
  if (requestedServiceKeys.size === 0) {
    return [];
  }
  return (Array.isArray(credentialResults) ? credentialResults : []).filter((result) =>
    requestedServiceKeys.has(String(result?.serviceKey || "").trim())
  );
}

function passVaultCredentialResultHasClientCredentials(result = null) {
  const cache = normalizeUnderparVaultDcrCache(result?.cache || null);
  return Boolean(cache?.clientId && cache?.clientSecret);
}

function getPassVaultCredentialTasks(programmerId = "", services = null) {
  const tasks = [];
  const seen = new Set();
  const pushTask = (serviceKey, appCandidates = []) => {
    const normalizedServiceKey = String(serviceKey || "").trim();
    const orderedCandidates = Array.isArray(appCandidates) ? appCandidates.filter((appInfo) => appInfo?.guid) : [];
    if (!normalizedServiceKey || orderedCandidates.length === 0) {
      return;
    }
    const dedupeKey = `${normalizedServiceKey}:${orderedCandidates.map((appInfo) => appInfo.guid).join(",")}`;
    if (seen.has(dedupeKey)) {
      return;
    }
    seen.add(dedupeKey);
    tasks.push({
      serviceKey: normalizedServiceKey,
      appCandidates: orderedCandidates,
      appInfo: orderedCandidates[0] || null,
    });
  };

  pushTask("restV2", services?.restV2?.guid ? [services.restV2] : []);
  pushTask("esm", services?.esm?.guid ? [services.esm] : []);
  pushTask("degradation", services?.degradation?.guid ? [services.degradation] : []);
  return tasks;
}

function hasPassVaultServiceClientCredentials(programmerId = "", appInfo = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const guid = String(appInfo?.guid || "").trim();
  if (!normalizedProgrammerId || !guid) {
    return false;
  }

  const cache = normalizeUnderparVaultDcrCache(loadDcrCache(normalizedProgrammerId, guid) || null);
  return Boolean(cache?.clientId && cache?.clientSecret);
}

function hasPassVaultCredentialCoverageForServices(programmerId = "", services = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return false;
  }

  const tasks = getPassVaultCredentialTasks(normalizedProgrammerId, services);
  if (tasks.length === 0) {
    return true;
  }

  return tasks.every((task) => hasPassVaultServiceClientCredentials(normalizedProgrammerId, task?.appInfo || null));
}

function buildPassVaultRuntimeServicesSnapshot(record = null) {
  if (!record || typeof record !== "object") {
    return null;
  }
  const applicationsSnapshot = buildPassVaultApplicationsSnapshotFromRegisteredApplications(
    getPassVaultRegisteredApplicationsByGuid(record)
  );
  const detectedServices = findPremiumServiceApplications([], applicationsSnapshot);
  const resolveAppInfo = (guid = "") => buildPassVaultRuntimeAppInfoFromRecord(record, guid, applicationsSnapshot);
  const hasCredentialEntryForService = (serviceKey = "", guid = "") => {
    const normalizedServiceKey = String(serviceKey || "").trim();
    const normalizedGuid = String(guid || "").trim();
    if (!normalizedServiceKey || !normalizedGuid) {
      return false;
    }
    const applicationRecord = getPassVaultRegisteredApplicationsByGuid(record)?.[normalizedGuid] || null;
    const credential = normalizeUnderparVaultCredentialEntry(
      applicationRecord?.serviceCredentialsByServiceKey?.[normalizedServiceKey] || null
    );
    return Boolean(credential?.clientId && credential?.clientSecret);
  };
  const selectPrimaryApp = (serviceKey = "", appInfos = []) => {
    const normalizedServiceKey = String(serviceKey || "").trim();
    const candidates = Array.isArray(appInfos) ? appInfos.filter((appInfo) => appInfo?.guid) : [];
    if (candidates.length === 0) {
      return null;
    }
    const primaryGuid = String(record?.services?.[serviceKey]?.primaryGuid || "").trim();
    const primaryMatch = candidates.find((appInfo) => String(appInfo?.guid || "").trim() === primaryGuid) || null;
    const credentialBackedMatch =
      candidates.find((appInfo) => hasCredentialEntryForService(normalizedServiceKey, appInfo?.guid)) || null;
    const serviceKeyBackedMatch =
      candidates.find((appInfo) => {
        const applicationRecord =
          getPassVaultRegisteredApplicationsByGuid(record)?.[String(appInfo?.guid || "").trim()] || null;
        const serviceKeys = Array.isArray(applicationRecord?.serviceKeys) ? applicationRecord.serviceKeys : [];
        return serviceKeys.includes(normalizedServiceKey);
      }) || null;

    if (primaryMatch && (hasCredentialEntryForService(normalizedServiceKey, primaryGuid) || !credentialBackedMatch)) {
      return primaryMatch;
    }
    return credentialBackedMatch || primaryMatch || serviceKeyBackedMatch || candidates[0] || null;
  };

  const restV2Apps = getPassVaultServiceAppGuidsFromRecord(record, "restV2")
    .map((guid) => resolveAppInfo(guid))
    .filter(Boolean);
  const degradationApps = getPassVaultServiceAppGuidsFromRecord(record, "degradation")
    .map((guid) => resolveAppInfo(guid))
    .filter(Boolean);
  const esmApps = getPassVaultServiceAppGuidsFromRecord(record, "esm")
    .map((guid) => resolveAppInfo(guid))
    .filter(Boolean);
  const resetTempPassApps = uniqueSorted(
    getPassVaultServiceAppGuidsFromRecord(record, "resetTempPass").concat(
      buildPassVaultServiceGuids("resetTempPass", detectedServices)
    )
  )
    .map((guid) => resolveAppInfo(guid))
    .filter(Boolean);
  const esmApp = selectPrimaryApp("esm", esmApps);
  const cmServiceSnapshot = buildPassVaultRuntimeCmServiceSnapshot(record);

  return {
    restV2: selectPrimaryApp("restV2", restV2Apps),
    restV2Apps,
    esm: esmApp,
    esmApps,
    degradation: selectPrimaryApp("degradation", degradationApps),
    degradationApps,
    resetTempPass: selectPrimaryApp("resetTempPass", resetTempPassApps),
    resetTempPassApps,
    cm: cmServiceSnapshot,
    cmMvpd: null,
    cmMvpdSelectionKey: "",
  };
}

function hasPassVaultCmCoverage(record = null) {
  if (!record || typeof record !== "object") {
    return false;
  }

  const cmSummary = record?.services?.cm;
  if (!cmSummary || typeof cmSummary !== "object") {
    return false;
  }

  return (
    cmSummary.checked === true ||
    cmSummary.available === true ||
    Number(cmSummary.matchedTenantCount || 0) > 0 ||
    Boolean(String(cmSummary.loadError || "").trim())
  );
}

function hasPassVaultRuntimeCoverageForAvailableServices(record = null, runtimeServices = null) {
  if (!record || typeof record !== "object") {
    return false;
  }

  const serviceSummaries = record?.services && typeof record.services === "object" ? record.services : {};
  if (serviceSummaries?.restV2?.available === true && collectRestV2AppCandidatesFromPremiumApps(runtimeServices).length === 0) {
    return false;
  }
  if (serviceSummaries?.esm?.available === true && !String(runtimeServices?.esm?.guid || "").trim()) {
    return false;
  }
  if (
    serviceSummaries?.degradation?.available === true &&
    !String(runtimeServices?.degradation?.guid || "").trim() &&
    (Array.isArray(runtimeServices?.degradationApps) ? runtimeServices.degradationApps.length : 0) === 0
  ) {
    return false;
  }
  return true;
}

function hasPassVaultRegisteredApplicationCoverage(record = null, programmerId = "") {
  if (!record || typeof record !== "object") {
    return false;
  }
  const normalizedProgrammerId = String(programmerId || record?.programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return true;
  }
  const programmer = findProgrammerByProgrammerId(normalizedProgrammerId);
  const expectedCount = Array.isArray(programmer?.applications) ? programmer.applications.length : 0;
  if (expectedCount <= 0) {
    return true;
  }
  const actualCount = getPassVaultRegisteredApplicationCount(record);
  return actualCount >= expectedCount;
}

function hasPassVaultUnavailableRequiredService(record = null) {
  if (!record || typeof record !== "object") {
    return true;
  }
  const serviceSummaries = record?.services && typeof record.services === "object" ? record.services : {};
  return PREMIUM_REQUIRED_SERVICE_KEYS.some((serviceKey) => serviceSummaries?.[serviceKey]?.available !== true);
}

function hasPassVaultScopedServiceSummaryMismatch(record = null) {
  if (!record || typeof record !== "object") {
    return false;
  }
  const applicationsSnapshot = buildPassVaultApplicationsSnapshotFromRegisteredApplications(record?.registeredApplicationsByGuid || {});
  const detectedServices = findPremiumServiceApplications([], applicationsSnapshot);
  const serviceSummaries = record?.services && typeof record.services === "object" ? record.services : {};
  if (
    detectedServices?.esm?.guid &&
    !String(serviceSummaries?.esm?.primaryGuid || "").trim() &&
    (Array.isArray(serviceSummaries?.esm?.appGuids) ? serviceSummaries.esm.appGuids.length : 0) === 0
  ) {
    return true;
  }
  if (
    Array.isArray(detectedServices?.restV2Apps) &&
    detectedServices.restV2Apps.length > 0 &&
    (Array.isArray(serviceSummaries?.restV2?.appGuids) ? serviceSummaries.restV2.appGuids.length : 0) === 0
  ) {
    return true;
  }
  if (
    Array.isArray(detectedServices?.degradationApps) &&
    detectedServices.degradationApps.length > 0 &&
    (Array.isArray(serviceSummaries?.degradation?.appGuids) ? serviceSummaries.degradation.appGuids.length : 0) === 0
  ) {
    return true;
  }
  if (
    Array.isArray(detectedServices?.resetTempPassApps) &&
    detectedServices.resetTempPassApps.length > 0 &&
    (Array.isArray(serviceSummaries?.resetTempPass?.appGuids) ? serviceSummaries.resetTempPass.appGuids.length : 0) === 0
  ) {
    return true;
  }
  return false;
}

function getPassVaultProgrammerReuseReadiness(
  programmerId = "",
  environmentKey = getActiveAdobePassEnvironmentKey()
) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return {
      record: null,
      hydrationStatus: UNDERPAR_VAULT_STATUS_PENDING,
      runtimeServices: null,
      runtimeCoverage: false,
      credentialCoverage: false,
      cmCoverage: false,
      unavailableRequiredService: true,
      trustNegativeServiceSummary: false,
      registeredApplicationCoverage: false,
      scopedServiceSummaryMismatch: false,
      detectionVersion: 0,
      reusable: false,
    };
  }

  const record = getPassVaultMediaCompanyRecord(normalizedProgrammerId, environmentKey);
  const hydrationStatus = normalizeUnderparVaultStatus(record?.hydrationStatus);
  const detectionVersion = Math.max(0, Number(record?.premiumDetectionVersion || record?.serviceDetectionVersion || 0));
  const runtimeServices = record ? buildPassVaultRuntimeServicesSnapshot(record) : null;
  const runtimeCoverage = Boolean(record && runtimeServices && hasPassVaultRuntimeCoverageForAvailableServices(record, runtimeServices));
  const credentialCoverage = Boolean(
    record && runtimeServices && hasPassVaultCredentialCoverageForServices(normalizedProgrammerId, runtimeServices)
  );
  const cmCoverage = hasPassVaultCmCoverage(record);
  const unavailableRequiredService = hasPassVaultUnavailableRequiredService(record);
  const registeredApplicationCoverage = hasPassVaultRegisteredApplicationCoverage(record, normalizedProgrammerId);
  const scopedServiceSummaryMismatch = hasPassVaultScopedServiceSummaryMismatch(record);
  const trustNegativeServiceSummary = !unavailableRequiredService || registeredApplicationCoverage;
  const reusable =
    hydrationStatus !== UNDERPAR_VAULT_STATUS_PENDING &&
    runtimeCoverage &&
    cmCoverage &&
    trustNegativeServiceSummary &&
    !scopedServiceSummaryMismatch;

  return {
    record,
    hydrationStatus,
    runtimeServices,
    runtimeCoverage,
    credentialCoverage,
    cmCoverage,
    unavailableRequiredService,
    trustNegativeServiceSummary,
    registeredApplicationCoverage,
    scopedServiceSummaryMismatch,
    detectionVersion,
    reusable,
  };
}

function isPassVaultProgrammerReadyForReuse(programmerId = "", environmentKey = getActiveAdobePassEnvironmentKey()) {
  return getPassVaultProgrammerReuseReadiness(programmerId, environmentKey).reusable === true;
}

function shouldForceLivePassVaultProgrammerHydration(
  programmerId = "",
  environmentKey = getActiveAdobePassEnvironmentKey()
) {
  const readiness = getPassVaultProgrammerReuseReadiness(programmerId, environmentKey);
  if (!readiness.record) {
    return true;
  }
  if (readiness.hydrationStatus === UNDERPAR_VAULT_STATUS_PENDING) {
    return true;
  }
  if (readiness.unavailableRequiredService && readiness.detectionVersion < UNDERPAR_PASS_VAULT_PREMIUM_DETECTION_VERSION) {
    return true;
  }
  // Older VAULT rows can still be perfectly reusable. Do not force a cold hydrate
  // on selection if the current ENV x Media Company record already has the service
  // mappings and CM coverage UnderPAR needs to operate. DCR credentials are now
  // hydrated on demand when a premium workflow actually uses them.
  if (readiness.reusable) {
    return false;
  }
  if (readiness.detectionVersion < UNDERPAR_PASS_VAULT_PREMIUM_DETECTION_VERSION) {
    return true;
  }
  return !(
    readiness.runtimeCoverage &&
    readiness.cmCoverage &&
    readiness.trustNegativeServiceSummary &&
    !readiness.scopedServiceSummaryMismatch
  );
}

function getPassVaultRequiredScopeForService(serviceKey = "", appInfo = null) {
  if (serviceKey === "degradation") {
    return getPreferredDegradationScopeForApp(appInfo) || PREMIUM_SERVICE_SCOPE_BY_KEY.degradation;
  }
  if (serviceKey === "esm") {
    return PREMIUM_SERVICE_SCOPE_BY_KEY.esm;
  }
  if (serviceKey === "resetTempPass") {
    return PREMIUM_SERVICE_RESET_TEMPPASS_SCOPE;
  }
  if (serviceKey === "restV2") {
    return REST_V2_SCOPE;
  }
  return "";
}

function resolvePremiumServiceKeyForAuth(appInfo = null, debugMeta = null) {
  const explicitRequiredScope = normalizeScope(firstNonEmptyString([debugMeta?.requiredServiceScope]));
  if (explicitRequiredScope === normalizeScope(REST_V2_SCOPE)) {
    return "restV2";
  }
  if (explicitRequiredScope === normalizeScope(PREMIUM_SERVICE_SCOPE_BY_KEY.esm)) {
    return "esm";
  }
  if (explicitRequiredScope === normalizeScope(PREMIUM_SERVICE_RESET_TEMPPASS_SCOPE)) {
    return "resetTempPass";
  }
  if (explicitRequiredScope === normalizeScope(getPreferredDegradationScopeForApp(appInfo) || PREMIUM_SERVICE_SCOPE_BY_KEY.degradation)) {
    return "degradation";
  }

  const serviceHint = normalizeScope(firstNonEmptyString([debugMeta?.service, debugMeta?.scope]));
  if (serviceHint.includes("degradation")) {
    return "degradation";
  }
  if (serviceHint.includes("temppass") || serviceHint.includes("temp-pass") || serviceHint.includes("temporary")) {
    return "resetTempPass";
  }
  if (serviceHint.includes("esm")) {
    return "esm";
  }
  if (serviceHint.includes("rest") || serviceHint.includes("profile") || serviceHint.includes("bobtools")) {
    return "restV2";
  }

  const normalizedAppScopes = (Array.isArray(appInfo?.scopes) ? appInfo.scopes : [])
    .map((scope) => normalizeScope(scope))
    .filter(Boolean);
  if (normalizedAppScopes.includes(normalizeScope(PREMIUM_SERVICE_SCOPE_BY_KEY.esm))) {
    return "esm";
  }
  if (normalizedAppScopes.includes(normalizeScope(PREMIUM_SERVICE_RESET_TEMPPASS_SCOPE))) {
    return "resetTempPass";
  }
  if (normalizedAppScopes.includes(normalizeScope(REST_V2_SCOPE))) {
    return "restV2";
  }
  if (
    normalizedAppScopes.includes(
      normalizeScope(getPreferredDegradationScopeForApp(appInfo) || PREMIUM_SERVICE_SCOPE_BY_KEY.degradation)
    )
  ) {
    return "degradation";
  }
  return "";
}

function collectEsmAppCandidatesFromPremiumApps(premiumApps = null, fallbackAppInfo = null) {
  const candidates = [];
  const seen = new Set();
  const pushCandidate = (appInfo) => {
    const guid = String(appInfo?.guid || "").trim();
    if (!guid || seen.has(guid)) {
      return;
    }
    seen.add(guid);
    candidates.push(appInfo);
  };
  pushCandidate(fallbackAppInfo);
  if (Array.isArray(premiumApps?.esmApps)) {
    premiumApps.esmApps.forEach((appInfo) => pushCandidate(appInfo));
  }
  pushCandidate(premiumApps?.esm || null);
  return candidates;
}

function collectResetTempPassAppCandidatesFromPremiumApps(premiumApps = null, fallbackAppInfo = null) {
  const candidates = [];
  const seen = new Set();
  const pushCandidate = (appInfo) => {
    const guid = String(appInfo?.guid || "").trim();
    if (!guid || seen.has(guid)) {
      return;
    }
    seen.add(guid);
    candidates.push(appInfo);
  };
  pushCandidate(fallbackAppInfo);
  if (Array.isArray(premiumApps?.resetTempPassApps)) {
    premiumApps.resetTempPassApps.forEach((appInfo) => pushCandidate(appInfo));
  }
  pushCandidate(premiumApps?.resetTempPass || null);
  return candidates;
}

function selectPreferredResetTempPassAppForRequestor(resetTempPassApps = [], requestorId = "", programmerId = "") {
  const candidates = Array.isArray(resetTempPassApps) ? resetTempPassApps.filter((item) => item?.guid) : [];
  if (candidates.length === 0) {
    return null;
  }
  const normalizedRequestorId = String(requestorId || "").trim();
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (normalizedRequestorId) {
    const mapped =
      candidates.find((appInfo) => appSupportsServiceProvider(appInfo, normalizedRequestorId, normalizedProgrammerId)) ||
      null;
    if (mapped) {
      return mapped;
    }
  }
  return candidates[0] || null;
}

function selectPreferredEsmAppForRequestor(esmApps = [], requestorId = "", programmerId = "") {
  const candidates = Array.isArray(esmApps) ? esmApps.filter((item) => item?.guid) : [];
  if (candidates.length === 0) {
    return null;
  }
  const normalizedRequestorId = String(requestorId || "").trim();
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (normalizedRequestorId) {
    const mapped =
      candidates.find((appInfo) => appSupportsServiceProvider(appInfo, normalizedRequestorId, normalizedProgrammerId)) ||
      null;
    if (mapped) {
      return mapped;
    }
  }
  return candidates[0] || null;
}

function resolveLatestPremiumServiceAppInfo(programmerId = "", fallbackAppInfo = null, debugMeta = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return fallbackAppInfo;
  }
  if (debugMeta?.lockAppSelection === true) {
    return fallbackAppInfo;
  }

  const serviceKey = resolvePremiumServiceKeyForAuth(fallbackAppInfo, debugMeta);
  if (!serviceKey) {
    return fallbackAppInfo;
  }

  const services = getRuntimePremiumServicesSeed(normalizedProgrammerId);
  if (!services || typeof services !== "object") {
    return fallbackAppInfo;
  }

  if (serviceKey === "esm") {
    const requestorId = String(debugMeta?.requestorId || "").trim();
    const candidates = collectEsmAppCandidatesFromPremiumApps(services, fallbackAppInfo);
    return (
      selectPreferredEsmAppForRequestor(candidates, requestorId, normalizedProgrammerId) ||
      (hasEsmScopedApp(services) ? services.esm || fallbackAppInfo : fallbackAppInfo)
    );
  }

  if (serviceKey === "restV2") {
    const requestorId = String(debugMeta?.requestorId || "").trim();
    const candidates = collectRestV2AppCandidatesFromPremiumApps(services);
    return selectPreferredRestV2AppForRequestor(candidates, requestorId, normalizedProgrammerId) || fallbackAppInfo;
  }

  if (serviceKey === "resetTempPass") {
    const requestorId = String(debugMeta?.requestorId || "").trim();
    const candidates = collectResetTempPassAppCandidatesFromPremiumApps(services, fallbackAppInfo);
    return selectPreferredResetTempPassAppForRequestor(candidates, requestorId, normalizedProgrammerId) || fallbackAppInfo;
  }

  if (serviceKey === "degradation") {
    const requestorId = String(debugMeta?.requestorId || "").trim();
    const candidates = resolveDegradationAppCandidates(normalizedProgrammerId, services?.degradation || fallbackAppInfo, {
      requestorId,
      preferredGuid: String(fallbackAppInfo?.guid || "").trim(),
    });
    return candidates[0] || fallbackAppInfo;
  }

  return fallbackAppInfo;
}

function getMissingRequiredPremiumServiceKeys(services = null, requiredServiceKeys = PREMIUM_REQUIRED_SERVICE_KEYS) {
  const keys = Array.isArray(requiredServiceKeys) && requiredServiceKeys.length > 0 ? requiredServiceKeys : PREMIUM_REQUIRED_SERVICE_KEYS;
  return keys.filter((serviceKey) => {
    if (serviceKey === "restV2") {
      return !Boolean(String(services?.restV2?.guid || "").trim());
    }
    if (serviceKey === "esm") {
      return !Boolean(String(services?.esm?.guid || "").trim());
    }
    if (serviceKey === "degradation") {
      return !Boolean(String(services?.degradation?.guid || "").trim());
    }
    if (serviceKey === "resetTempPass") {
      return !Boolean(String(services?.resetTempPass?.guid || "").trim());
    }
    return false;
  });
}

function appendPinnedEsmMediaCompanyQueryParam(rawUrl = "", mediaCompanyId = "") {
  const normalizedUrl = String(rawUrl || "").trim();
  const normalizedMediaCompanyId = String(mediaCompanyId || "").trim();
  if (!normalizedUrl || !normalizedMediaCompanyId) {
    return normalizedUrl;
  }

  const hasAbsoluteScheme = /^[a-z][a-z\d+.-]*:/i.test(normalizedUrl);
  const fallbackBase = String(getActiveAdobePassEnvironment()?.esmBase || `${ADOBE_MGMT_BASE}/esm/v3/media-company/`).trim();
  try {
    const parsed = hasAbsoluteScheme ? new URL(normalizedUrl) : new URL(normalizedUrl, fallbackBase || "https://example.invalid");
    if (!/\/esm\/v3\/media-company\//i.test(String(parsed.pathname || ""))) {
      return normalizedUrl;
    }
    parsed.searchParams.set("media-company", normalizedMediaCompanyId);
    parsed.hash = "";
    return hasAbsoluteScheme ? parsed.toString() : `${String(parsed.pathname || "")}${String(parsed.search || "")}`;
  } catch {
    if (!/\/esm\/v3\/media-company\//i.test(normalizedUrl)) {
      return normalizedUrl;
    }
    const withoutHash = normalizedUrl.split("#")[0] || "";
    const [path, query = ""] = withoutHash.split("?");
    const params = new URLSearchParams(query);
    params.set("media-company", normalizedMediaCompanyId);
    const nextQuery = params.toString();
    return nextQuery ? `${path}?${nextQuery}` : path;
  }
}

function buildEsmHydrationProbeUrl(mediaCompanyId = "") {
  const fallbackBase = String(getActiveAdobePassEnvironment()?.esmBase || `${ADOBE_MGMT_BASE}/esm/v3/media-company/`).trim();
  let seedUrl = "";

  if (Array.isArray(clickEsmEndpoints) && clickEsmEndpoints.length > 0) {
    seedUrl = String(clickEsmEndpoints[0]?.url || "").trim();
  }

  if (!seedUrl) {
    const normalizedBase = fallbackBase.replace(/\/+$/, "");
    seedUrl = `${normalizedBase}/year`;
  }

  try {
    const parsed = new URL(seedUrl, fallbackBase || window.location.href);
    if (!parsed.searchParams.has("limit")) {
      parsed.searchParams.set("limit", "1");
    }
    return appendPinnedEsmMediaCompanyQueryParam(parsed.toString(), mediaCompanyId);
  } catch {
    return appendPinnedEsmMediaCompanyQueryParam(seedUrl, mediaCompanyId);
  }
}

async function probeEsmServiceAccess(programmerId = "", appInfo = null, options = {}) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId || !appInfo?.guid) {
    return false;
  }

  const requestTimeoutMs = Math.max(1000, Number(options?.requestTimeoutMs || PREMIUM_APPLICATION_DETAIL_TIMEOUT_MS));
  const accessToken = await ensureDcrAccessToken(normalizedProgrammerId, appInfo, options?.forceRefresh === true, {
    service: "esm-probe",
    scope: "esm-hydration-probe",
    requiredServiceScope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
    appGuid: String(appInfo?.guid || ""),
    appName: String(appInfo?.appName || appInfo?.guid || ""),
    allowProvisioning: true,
    strictScopeValidation: true,
    tokenAttemptMode: "scoped-only",
    lockAppSelection: options?.lockAppSelection === true,
  });
  const probeUrl = buildEsmHydrationProbeUrl(normalizedProgrammerId);
  const response = await fetchWithRateLimitRetry(
    () =>
      fetchWithAbortTimeout(
        probeUrl,
        {
          method: "GET",
          mode: "cors",
          credentials: "omit",
          referrerPolicy: "no-referrer",
          headers: {
            Accept: "application/json, text/plain, */*",
            Authorization: `Bearer ${accessToken}`,
          },
        },
        requestTimeoutMs
      ),
    "ESM probe"
  );
  const bodyText = await response.text().catch(() => "");
  if (response.ok) {
    return true;
  }
  if (response.status === 401 || response.status === 403) {
    return false;
  }
  if (isServiceProviderTokenMismatchError(bodyText)) {
    return false;
  }
  if (/analytics:client|insufficient[_\s-]*scope|invalid[_\s-]*access[_\s-]*token/i.test(String(bodyText || ""))) {
    return false;
  }
  return true;
}

function mergeUniquePremiumServiceAppInfos(...collections) {
  const merged = [];
  const seen = new Set();

  collections.forEach((collection) => {
    const items = Array.isArray(collection) ? collection : [collection];
    items.forEach((appInfo) => {
      const guid = String(appInfo?.guid || "").trim();
      if (!guid || seen.has(guid)) {
        return;
      }
      seen.add(guid);
      merged.push(appInfo);
    });
  });

  return merged;
}

function selectResolvedPremiumServiceCandidate(candidates = [], currentApp = null, preferredApp = null, programmerId = "") {
  const normalizedCandidates = Array.isArray(candidates) ? candidates.filter((appInfo) => appInfo?.guid) : [];
  if (normalizedCandidates.length === 0) {
    return null;
  }

  const currentGuid = String(currentApp?.guid || "").trim();
  const currentMatch =
    currentGuid ? normalizedCandidates.find((appInfo) => String(appInfo?.guid || "").trim() === currentGuid) || null : null;

  const preferredGuid = String(preferredApp?.guid || "").trim();
  const preferredMatch =
    preferredGuid
      ? normalizedCandidates.find((appInfo) => String(appInfo?.guid || "").trim() === preferredGuid) || preferredApp
      : null;
  return preferredMatch || currentMatch || normalizedCandidates[0] || null;
}

async function queuePassVaultProgrammerCompilation(programmer, services = null, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const scopedKey = getEnvironmentScopedProgrammerKey(programmerId);
  if (!scopedKey) {
    return null;
  }

  const forceRefresh = options?.forceRefresh === true;
  if (state.passVaultCompilePromiseByProgrammerKey.has(scopedKey)) {
    return state.passVaultCompilePromiseByProgrammerKey.get(scopedKey);
  }

  const compilePromise = (async () => {
    const applicationsData =
      options?.applicationsData && typeof options.applicationsData === "object" && !Array.isArray(options.applicationsData)
        ? options.applicationsData
        : getCurrentProgrammerApplicationsSnapshot(programmerId) || {};
    const existingRecord = getPassVaultMediaCompanyRecord(programmerId);
    const currentServices =
      services && typeof services === "object" && !Array.isArray(services)
        ? services
        : getCurrentPremiumAppsSnapshot(programmerId) || buildPassVaultRuntimeServicesSnapshot(existingRecord) || {};
    const cmServiceSnapshot =
      currentServices?.cm ??
      state.cmServiceByProgrammerId.get(programmerId) ??
      buildPassVaultRuntimeCmServiceSnapshot(existingRecord) ??
      null;
    const cmMvpdSelectionKey = buildCurrentCmMvpdSelectionKey(programmer);
    const cmMvpdServiceSnapshot = cmMvpdSelectionKey
      ? state.cmServiceByMvpdSelectionKey.get(cmMvpdSelectionKey) || currentServices?.cmMvpd || null
      : currentServices?.cmMvpd || null;
    const registeredApplications = buildPassVaultHydrationRegisteredApplications(applicationsData);

    setProgrammerPremiumHydrationProgress(programmerId, {
      step: "detect",
      label: "Detecting premium services...",
    });

    setCurrentProgrammerApplicationsSnapshot(programmerId, applicationsData);
    const serviceEntries = buildPassVaultServiceHydrationEntries({
      programmer,
      registeredApplications,
      existingRecord,
    });
    const provisionalServices = buildPassVaultDirectPremiumServicesSnapshot(
      programmer,
      registeredApplications,
      serviceEntries,
      {
        cmServiceSnapshot,
        cmMvpdServiceSnapshot,
        cmMvpdSelectionKey,
      }
    );
    setCurrentPremiumAppsSnapshot(programmerId, provisionalServices);
    const detectedServiceLabels = getDetectedPremiumServiceLabels(provisionalServices);

    setProgrammerPremiumHydrationProgress(programmerId, {
      step: "register",
      label:
        detectedServiceLabels.length > 0
          ? `Registering premium service clients for ${detectedServiceLabels.join(" | ")}...`
          : "Registering premium service clients...",
      detectedServiceLabels,
    });

    const hydratedServiceEntries = await hydratePassVaultServiceEntries(serviceEntries, PREMIUM_REQUIRED_SERVICE_KEYS, {
      programmerId,
      forceRefresh,
      preferredTabId: Number(options?.preferredTabId || 0),
      allowTemporaryPageContextTab: options?.allowTemporaryPageContextTab === true,
    });
    const hydratedApplications = mergeHydratedServiceEntriesIntoApplicationsData(applicationsData, hydratedServiceEntries);
    const hydratedRegisteredApplications = buildPassVaultHydrationRegisteredApplications(hydratedApplications);
    const credentialResults = buildPassVaultDirectCredentialResults(hydratedServiceEntries);
    const mergedServices = buildPassVaultDirectPremiumServicesSnapshot(
      programmer,
      hydratedRegisteredApplications,
      hydratedServiceEntries,
      {
        cmServiceSnapshot,
        cmMvpdServiceSnapshot,
        cmMvpdSelectionKey,
      }
    );

    setCurrentProgrammerApplicationsSnapshot(programmerId, hydratedApplications);
    setCurrentPremiumAppsSnapshot(programmer.programmerId, mergedServices);

    setProgrammerPremiumHydrationProgress(programmerId, {
      step: "vault",
      label: "Saving premium services to VAULT...",
      detectedServiceLabels,
    });

    const usageWarmResult = {
      ok: true,
      skipped: true,
      error: "",
    };
    const blockingCredentialResults = getPassVaultCredentialResultsForServiceKeys(
      credentialResults,
      PREMIUM_REQUIRED_SERVICE_KEYS
    );
    const failedCount = blockingCredentialResults.filter((result) => !passVaultCredentialResultHasClientCredentials(result)).length;
    const firstFailure =
      blockingCredentialResults.find((result) => !passVaultCredentialResultHasClientCredentials(result)) || null;
    const credentialWarningCount = credentialResults.filter((result) => String(result?.error || "").trim()).length;
    const warningCount = credentialWarningCount;
    const hydrationStatus = failedCount > 0 ? UNDERPAR_VAULT_STATUS_PARTIAL : UNDERPAR_VAULT_STATUS_COMPLETE;
    const persistPromise = persistPassVaultProgrammerRecord(programmer, mergedServices, {
      source: "live",
      hydrationStatus,
      serviceCredentialResults: credentialResults,
    }).catch(() => null);
    if (firstFailure) {
      void persistPromise;
      throw new Error(
        firstNonEmptyString([
          String(firstFailure?.error || "").trim(),
          `UnderPAR could not hydrate ${String(firstFailure?.serviceKey || "premium service").trim()}.`,
        ])
      );
    }
    if (hydrationStatus === UNDERPAR_VAULT_STATUS_COMPLETE) {
      clearProgrammerPremiumHydrationProgress(programmerId);
    } else {
      setProgrammerPremiumHydrationProgress(programmerId, {
        step: "pending",
        label: "Finishing premium service hydration...",
        detectedServiceLabels,
      });
    }
    applyMediaCompanyOptionHydrationState();
    void persistPromise.then(() => {
      applyMediaCompanyOptionHydrationState();
    });
    void ensureCmHydratedForProgrammer(programmer, mergedServices, {
      forceRefresh,
      reason: "pass-vault-compilation",
    })
      .then((cmHydration) => {
        const nextServices =
          cmHydration?.services && typeof cmHydration.services === "object"
            ? cmHydration.services
            : mergeProgrammerPremiumServicesWithCm(
                programmer.programmerId,
                mergedServices,
                cmHydration?.cmService ?? mergedServices?.cm ?? null
              );
        setCurrentPremiumAppsSnapshot(programmer.programmerId, nextServices);
        if (String(resolveSelectedProgrammer()?.programmerId || "").trim() === programmerId) {
          if (shouldRenderPremiumServicesUi(programmer.programmerId, nextServices)) {
            renderPremiumServices(nextServices, programmer, {
              controllerReason: "pass-vault-compilation",
            });
          }
          emitPremiumServiceDecisionLogs(programmer, nextServices);
        }
        void persistPassVaultProgrammerRecord(programmer, nextServices, {
          source: "live",
          hydrationStatus,
          serviceCredentialResults: credentialResults,
        }).catch(() => {});
      })
      .catch(() => {});

    return {
      services: mergedServices,
      taskCount: credentialResults.length,
      failedCount,
      warningCount,
      hydrationStatus,
      cmHydration: null,
      usageWarmResult,
    };
  })().finally(() => {
    if (state.passVaultCompilePromiseByProgrammerKey.get(scopedKey) === compilePromise) {
      state.passVaultCompilePromiseByProgrammerKey.delete(scopedKey);
    }
  });

  state.passVaultCompilePromiseByProgrammerKey.set(scopedKey, compilePromise);
  return compilePromise;
}

async function finalizePassVaultProgrammerHydration(programmer, services = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const scopedKey = getEnvironmentScopedProgrammerKey(programmerId);
  if (!scopedKey) {
    return null;
  }

  const existingCompilePromise = state.passVaultCompilePromiseByProgrammerKey.get(scopedKey) || null;
  if (existingCompilePromise) {
    await existingCompilePromise.catch(() => null);
  }

  const currentRecord = getPassVaultMediaCompanyRecord(programmerId);
  const currentStatus = normalizeUnderparVaultStatus(currentRecord?.hydrationStatus);
  const hydrationStatus =
    currentStatus === UNDERPAR_VAULT_STATUS_PARTIAL ? UNDERPAR_VAULT_STATUS_PARTIAL : UNDERPAR_VAULT_STATUS_COMPLETE;

  const nextRecord = await persistPassVaultProgrammerRecord(programmer, services, {
    source: "live",
    hydrationStatus,
  });
  applyMediaCompanyOptionHydrationState();
  return nextRecord;
}

function restorePassVaultCmTenantBundlesToRuntime(record = null) {
  const bundlesByTenantKey = normalizePassVaultCmTenantBundlesByTenantKey(record?.cmTenantBundlesByTenantKey || {});
  Object.entries(bundlesByTenantKey).forEach(([tenantCacheKey, bundle]) => {
    const normalizedTenantCacheKey = String(tenantCacheKey || "").trim();
    if (!normalizedTenantCacheKey || !bundle) {
      return;
    }
    state.cmTenantBundleByTenantKey.set(normalizedTenantCacheKey, {
      fetchedAt: Date.now(),
      bundle: cloneJsonLikeValue(bundle, null),
    });
  });
}

function applyPassVaultRecordToRuntime(programmer, record = null, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId || !record || typeof record !== "object") {
    return false;
  }

  if (getCurrentPremiumAppsSnapshot(programmerId) && options?.forceOverwrite !== true) {
    const currentServices = getCurrentPremiumAppsSnapshot(programmerId) || {};
    const currentCmService =
      currentServices?.cm && typeof currentServices.cm === "object"
        ? currentServices.cm
        : buildPassVaultRuntimeServicesSnapshot(record)?.cm || null;
    if (currentCmService) {
      state.cmServiceByProgrammerId.set(programmerId, cloneJsonLikeValue(currentCmService, null));
    }
    restorePassVaultCmTenantBundlesToRuntime(record);
    restoreDcrCachesFromPassVaultRecord(programmerId, record, {
      forceRestore: options?.forceDcrRestore === true,
    });
    return false;
  }

  const applicationsSnapshot = buildPassVaultApplicationsSnapshotFromRegisteredApplications(
    record?.registeredApplicationsByGuid || {}
  );
  Object.values(applicationsSnapshot).forEach((applicationValue) => markPassVaultBackedValue(applicationValue, record));
  markPassVaultBackedValue(applicationsSnapshot, record);

  const premiumServicesSnapshot = buildPassVaultRuntimeServicesSnapshot(record) || {};
  const cmServiceSnapshot =
    premiumServicesSnapshot?.cm && typeof premiumServicesSnapshot.cm === "object"
      ? cloneJsonLikeValue(premiumServicesSnapshot.cm, null)
      : null;
  collectRestV2AppCandidatesFromPremiumApps(premiumServicesSnapshot).forEach((appInfo) => {
    markPassVaultBackedValue(appInfo, record);
    if (appInfo?.appData && typeof appInfo.appData === "object") {
      markPassVaultBackedValue(appInfo.appData, record);
    }
  });
  collectEsmAppCandidatesFromPremiumApps(premiumServicesSnapshot).forEach((appInfo) => {
    markPassVaultBackedValue(appInfo, record);
    if (appInfo?.appData && typeof appInfo.appData === "object") {
      markPassVaultBackedValue(appInfo.appData, record);
    }
  });
  if (premiumServicesSnapshot?.esm && typeof premiumServicesSnapshot.esm === "object") {
    markPassVaultBackedValue(premiumServicesSnapshot.esm, record);
    if (premiumServicesSnapshot.esm.appData && typeof premiumServicesSnapshot.esm.appData === "object") {
      markPassVaultBackedValue(premiumServicesSnapshot.esm.appData, record);
    }
  }
  (Array.isArray(premiumServicesSnapshot?.degradationApps) ? premiumServicesSnapshot.degradationApps : []).forEach((appInfo) => {
    markPassVaultBackedValue(appInfo, record);
    if (appInfo?.appData && typeof appInfo.appData === "object") {
      markPassVaultBackedValue(appInfo.appData, record);
    }
  });
  markPassVaultBackedValue(premiumServicesSnapshot, record);
  if (cmServiceSnapshot) {
    markPassVaultBackedValue(cmServiceSnapshot, record);
  }

  premiumServicesSnapshot.cm = cmServiceSnapshot;
  premiumServicesSnapshot.cmMvpd = premiumServicesSnapshot.cmMvpd ?? null;
  premiumServicesSnapshot.cmMvpdSelectionKey = String(premiumServicesSnapshot.cmMvpdSelectionKey || "").trim();

  setCurrentProgrammerApplicationsSnapshot(programmerId, applicationsSnapshot);
  setCurrentPremiumAppsSnapshot(programmerId, premiumServicesSnapshot);
  if (cmServiceSnapshot) {
    state.cmServiceByProgrammerId.set(programmerId, cmServiceSnapshot);
  } else {
    state.cmServiceByProgrammerId.delete(programmerId);
  }
  restorePassVaultCmTenantBundlesToRuntime(record);
  restoreDcrCachesFromPassVaultRecord(programmerId, record, {
    forceRestore: options?.forceDcrRestore === true,
  });
  return true;
}

async function hydrateProgrammerFromPassVault(programmer, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId) {
    return null;
  }

  const vault = await ensurePassVaultLoaded({
    forceReload: options?.forceReload === true,
  });
  const record = getPassVaultMediaCompanyRecordFromVault(vault, programmerId);
  if (!record) {
    return null;
  }
  applyPassVaultRecordToRuntime(programmer, record, {
    forceOverwrite: options?.forceOverwrite === true,
    forceDcrRestore: options?.forceDcrRestore === true,
  });
  return record;
}

async function seedCurrentProgrammersFromPassVault(options = {}) {
  const vault = await ensurePassVaultLoaded({
    forceReload: options?.forceReload === true,
  });
  let seededCount = 0;
  for (const programmer of Array.isArray(state.programmers) ? state.programmers : []) {
    const record = getPassVaultMediaCompanyRecordFromVault(vault, programmer?.programmerId);
    if (!record) {
      continue;
    }
    const applied = applyPassVaultRecordToRuntime(programmer, record, {
      forceOverwrite: options?.forceOverwrite === true,
      forceDcrRestore: options?.forceDcrRestore === true,
    });
    if (applied) {
      seededCount += 1;
    }
  }
  applyMediaCompanyOptionHydrationState();
  return seededCount;
}

function getRequestorScopedMvpdCache(requestorId = "") {
  const key = getEnvironmentScopedRequestorKey(requestorId);
  if (!key) {
    return null;
  }
  return state.mvpdCacheByRequestor.get(key) || null;
}

function setRequestorScopedMvpdCache(requestorId = "", value = null) {
  const key = getEnvironmentScopedRequestorKey(requestorId);
  if (!key) {
    return null;
  }
  if (value == null) {
    state.mvpdCacheByRequestor.delete(key);
    return null;
  }
  state.mvpdCacheByRequestor.set(key, value);
  return value;
}

function getRequestorScopedMvpdLoadPromise(requestorId = "") {
  const key = getEnvironmentScopedRequestorKey(requestorId);
  if (!key) {
    return null;
  }
  return state.mvpdLoadPromiseByRequestor.get(key) || null;
}

function setRequestorScopedMvpdLoadPromise(requestorId = "", promise = null) {
  const key = getEnvironmentScopedRequestorKey(requestorId);
  if (!key) {
    return null;
  }
  if (!promise) {
    state.mvpdLoadPromiseByRequestor.delete(key);
    return null;
  }
  state.mvpdLoadPromiseByRequestor.set(key, promise);
  return promise;
}

function getRequestorScopedRestV2AuthContext(requestorId = "") {
  const key = getEnvironmentScopedRequestorKey(requestorId);
  if (!key) {
    return null;
  }
  return state.restV2AuthContextByRequestor.get(key) || null;
}

function setRequestorScopedRestV2AuthContext(requestorId = "", value = null) {
  const key = getEnvironmentScopedRequestorKey(requestorId);
  if (!key) {
    return null;
  }
  if (!value || typeof value !== "object") {
    state.restV2AuthContextByRequestor.delete(key);
    return null;
  }
  const normalized = {
    ...value,
    environmentKey: getActiveAdobePassEnvironmentKey(),
  };
  state.restV2AuthContextByRequestor.set(key, normalized);
  return normalized;
}

function clearEnvironmentAwareRegisteredAppState(reason = "environment-change") {
  state.mvpdCacheByRequestor.clear();
  state.mvpdLoadPromiseByRequestor.clear();
  state.restV2AuthContextByRequestor.clear();
  state.restV2PrewarmedAppsByProgrammerId.clear();
  state.applicationsByProgrammerId.clear();
  state.programmerApplicationsLoadPromiseByProgrammerId.clear();
  state.premiumAppsByProgrammerId.clear();
  state.dcrEnsureTokenPromiseByKey.clear();
  state.restV2ProfileHarvestBySelectionKey.clear();
  state.restV2ProfileHarvestByProgrammerId.clear();
  state.restV2ProfileHarvestBucketByProgrammerId.clear();
  state.restV2ProfileHarvestLast = null;
  clearRestV2PreparedLoginState();
  clearEsmWorkspaceRecordingState(reason);
  clearEsmWorkspaceActivityDebugFlow(reason, { stopFlow: true });
  state.premiumPanelRequestToken = Number(state.premiumPanelRequestToken || 0) + 1;
}

function buildActiveProgrammerConsoleApplicationsUrl(programmerId = "") {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return "";
  }
  const environment = getActiveAdobePassEnvironment();
  const programmersUrl = String(environment?.consoleProgrammersUrl || "").replace(/\/+$/, "");
  if (!programmersUrl) {
    return "";
  }
  return `${programmersUrl}/${encodeURIComponent(normalizedProgrammerId)}/applications`;
}

async function openActiveProgrammerConsoleApplications(programmer = null, options = {}) {
  const resolvedProgrammer = programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
  const programmerId = String(resolvedProgrammer?.programmerId || "").trim();
  const consoleUrl = buildActiveProgrammerConsoleApplicationsUrl(programmerId);
  if (!consoleUrl) {
    throw new Error("Select a Media Company first.");
  }
  return chrome.tabs.create({
    url: consoleUrl,
    active: options.activate !== false,
  });
}

function rewriteAdobePassServiceUrl(urlValue, serviceKey = "console") {
  const registry = getUnderParEnvironmentRegistry();
  if (registry?.rewriteServiceUrl) {
    return registry.rewriteServiceUrl(urlValue, serviceKey, getActiveAdobePassEnvironment());
  }
  return String(urlValue || "").trim();
}

function rewriteAdobePassTemplateForEnvironment(templateHtml = "") {
  const environment = getActiveAdobePassEnvironment();
  const replacements = [
    ["https://console.auth.adobe.com", String(environment.consoleBase || "")],
    ["https://mgmt.auth.adobe.com", String(environment.mgmtBase || "")],
    ["https://sp.auth.adobe.com", String(environment.spBase || "")],
  ];
  let output = String(templateHtml || "");
  replacements.forEach(([source, target]) => {
    if (!source || !target || source === target) {
      return;
    }
    output = output.replaceAll(source, target);
    try {
      output = output.replaceAll(new URL(source).host, new URL(target).host);
    } catch {
      // Ignore host-only rewrite failures.
    }
  });
  return output;
}

function applyAdobePassEnvironment(environment = null) {
  const previousEnvironmentKey =
    String(state?.adobePassEnvironmentKey || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const resolved = resolveAdobePassEnvironment(environment);
  const nextEnvironmentKey = String(resolved.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const environmentChanged = previousEnvironmentKey !== nextEnvironmentKey;
  state.adobePassEnvironment = resolved;
  state.adobePassEnvironmentKey = nextEnvironmentKey;
  ADOBE_CONSOLE_BASE = String(resolved.consoleBase || "");
  CM_CONSOLE_APP_ORIGIN = String(resolved.cmConsoleOrigin || "https://experience.adobe.com");
  CM_CONSOLE_APP_REFERER = `${CM_CONSOLE_APP_ORIGIN.replace(/\/+$/, "")}/`;
  ADOBE_MGMT_BASE = String(resolved.mgmtBase || "");
  ADOBE_SP_BASE = String(resolved.spBase || "");
  DEGRADATION_API_BASE = String(resolved.degradationBase || `${ADOBE_MGMT_BASE}/control/v3/degradation`);
  REST_V2_BASE = String(resolved.restV2Base || `${ADOBE_SP_BASE}/api/v2`);
  PROGRAMMER_ENDPOINTS = buildProgrammerEndpointsForConsoleBase(ADOBE_CONSOLE_BASE);
  REST_V2_REDIRECT_CANDIDATES = buildRestV2RedirectCandidatesForSpBase(ADOBE_SP_BASE);
  clickEsmEndpoints = [];
  clickEsmEndpointsPromise = null;
  clickEsmTemplateHtml = "";
  clickEsmTemplatePromise = null;
  clickDgrTemplateHtml = "";
  clickDgrTemplatePromise = null;
  state.programmersApiEndpoint = null;
  state.consoleCsrfToken = "";
  state.consoleBootstrapState = null;
  if (environmentChanged) {
    clearEnvironmentAwareRegisteredAppState("environment-change");
    clearDegradationWorkspaceRecordingState("environment-change");
    clearDegradationWorkspaceActivityDebugFlow("environment-change", { stopFlow: true });
    clearCmWorkspaceActivityDebugFlow("environment-change", { stopFlow: true });
  }
  return resolved;
}

async function initializeAdobePassEnvironment() {
  const registry = getUnderParEnvironmentRegistry();
  const environment = registry?.getStoredEnvironment
    ? await registry.getStoredEnvironment()
    : resolveAdobePassEnvironment(DEFAULT_ADOBEPASS_ENVIRONMENT.key);
  return applyAdobePassEnvironment(environment);
}

function getAdobePassEnvironmentStorageKey() {
  const registry = getUnderParEnvironmentRegistry();
  return String(registry?.STORAGE_KEY || "underpar_adobepass_environment_v1").trim() || "underpar_adobepass_environment_v1";
}

function captureAdobePassEnvironmentSwitchSelectionSnapshot() {
  const programmer = resolveSelectedProgrammer();
  return {
    programmerId: String(programmer?.programmerId || "").trim(),
    programmerName: String(programmer?.programmerName || programmer?.mediaCompanyName || "").trim(),
    mediaCompanyName: String(programmer?.mediaCompanyName || programmer?.programmerName || "").trim(),
    requestorId: String(state.selectedRequestorId || "").trim(),
    mvpdId: String(state.selectedMvpdId || "").trim(),
  };
}

function hasProgrammerSelectionSnapshot(snapshot = null) {
  if (!snapshot || typeof snapshot !== "object") {
    return false;
  }
  return Boolean(
    firstNonEmptyString([snapshot.programmerId, snapshot.programmerName, snapshot.mediaCompanyName]).trim()
  );
}

function findProgrammerForEnvironmentSwitchSnapshot(snapshot = null) {
  if (!snapshot || typeof snapshot !== "object" || !Array.isArray(state.programmers) || state.programmers.length === 0) {
    return null;
  }

  const programmerId = String(snapshot.programmerId || "").trim().toLowerCase();
  if (programmerId) {
    const byProgrammerId = state.programmers.find(
      (candidate) => String(candidate?.programmerId || "").trim().toLowerCase() === programmerId
    );
    if (byProgrammerId) {
      return byProgrammerId;
    }
  }

  const nameCandidates = [
    String(snapshot.programmerName || "").trim().toLowerCase(),
    String(snapshot.mediaCompanyName || "").trim().toLowerCase(),
  ].filter(Boolean);
  if (nameCandidates.length === 0) {
    return null;
  }

  return (
    state.programmers.find((candidate) => {
      const candidateNames = [
        String(candidate?.programmerName || "").trim().toLowerCase(),
        String(candidate?.mediaCompanyName || "").trim().toLowerCase(),
      ].filter(Boolean);
      return candidateNames.some((candidateName) => nameCandidates.includes(candidateName));
    }) || null
  );
}

function prepareAdobePassEnvironmentSwitchUi(targetEnvironment = null) {
  const environmentLabel = String(targetEnvironment?.label || "selected environment").trim() || "selected environment";
  clearPremiumServiceAutoRefreshTimers();
  state.programmersApiEndpoint = null;
  applyProgrammerEntities([]);
  els.mediaCompanySelect.disabled = true;
  els.mediaCompanySelect.innerHTML = `<option value="">-- Switching to ${escapeHtml(environmentLabel)}... --</option>`;
  els.requestorSelect.disabled = true;
  els.requestorSelect.innerHTML = '<option value="">-- Reloading Content Providers... --</option>';
  els.mvpdSelect.disabled = true;
  els.mvpdSelect.innerHTML = '<option value="">-- Reloading MVPD menu... --</option>';
  setHrContextSectionsVisibility(false);
  if (els.premiumServicesContainer) {
    delete els.premiumServicesContainer.dataset.renderSignature;
    els.premiumServicesContainer.innerHTML = `<p class="metadata-empty">Switching to ${escapeHtml(
      environmentLabel
    )}...</p>`;
  }
}

function findProgrammerByProgrammerId(programmerId = "") {
  const normalizedProgrammerId = String(programmerId || "").trim().toLowerCase();
  if (!normalizedProgrammerId || !Array.isArray(state.programmers)) {
    return null;
  }
  return (
    state.programmers.find(
      (candidate) => String(candidate?.programmerId || "").trim().toLowerCase() === normalizedProgrammerId
    ) || null
  );
}

function getFirstSelectableOptionValue(selectElement = null) {
  const options = Array.from(selectElement?.options || []);
  const firstMatch = options.find((option) => String(option?.value || "").trim());
  return String(firstMatch?.value || "").trim();
}

function selectProgrammerForController(programmer = null, controllerReason = "media-company-change") {
  const resolvedProgrammer = programmer && typeof programmer === "object" ? programmer : null;
  if (resolvedProgrammer?.programmerId) {
    setProgrammerWorkspaceHydrationReady(resolvedProgrammer.programmerId, false);
  }
  state.selectedMediaCompany = String(
    resolvedProgrammer?.mediaCompanyName || resolvedProgrammer?.programmerName || resolvedProgrammer?.programmerId || ""
  ).trim();
  state.selectedProgrammerKey = String(resolvedProgrammer?.key || "").trim();
  state.selectedRequestorId = "";
  state.selectedMvpdId = "";
  if (els.mediaCompanySelect) {
    els.mediaCompanySelect.value = state.selectedProgrammerKey;
  }
  populateRequestorSelect();
  esmWorkspaceBroadcastSelectedControllerState(resolvedProgrammer, null, 0, {
    controllerReason,
    esmAvailabilityResolved: false,
    esmContainerVisible: null,
  });
  cmBroadcastSelectedControllerState(resolvedProgrammer, null, 0, {
    controllerReason,
    cmAvailabilityResolved: false,
    cmContainerVisible: null,
  });
  mvpdWorkspaceBroadcastSelectedControllerState(resolvedProgrammer, null);
  refreshMvpdWorkspaceTools({ controllerReason });
  void mvpdWorkspaceRefreshSelectedSnapshot({
    programmer: resolvedProgrammer,
    services: null,
    forceRefresh: false,
    onlyIfWorkspaceOpen: true,
    surfaceMissingSelectionError: false,
  });
  return resolvedProgrammer;
}

async function hydrateProgrammerSelection(programmer = null, options = {}) {
  const controllerReason = String(options?.controllerReason || "media-company-change").trim() || "media-company-change";
  const forcePremiumRefresh = options.forcePremiumRefresh === true;
  const skipCmBootstrap = options.skipCmBootstrap === true;
  const selectedProgrammer = selectProgrammerForController(programmer, controllerReason);
  const retainedConsoleTabId = Number(options?.preferredTabId || 0);
  const programmerApplicationsPromise = selectedProgrammer?.programmerId
    ? ensureSelectedProgrammerApplicationsLoaded(selectedProgrammer, {
        forceRefresh: forcePremiumRefresh,
        allowTemporaryPageContextTab: false,
        preferredTabId: retainedConsoleTabId,
        requestTimeoutMs: PREMIUM_APPLICATIONS_FETCH_TIMEOUT_MS,
      })
    : Promise.resolve({});
  await refreshProgrammerPanels({
    controllerReason,
    forcePremiumRefresh,
    skipCmBootstrap,
    preferredTabId: retainedConsoleTabId,
    programmerApplicationsPromise,
  });
  return selectedProgrammer;
}

function collectBoundWorkspaceWindowIds(primaryWindowId = 0, tabIdByWindowId = null) {
  const windowIds = new Set();
  const normalizedPrimaryWindowId = Number(primaryWindowId || 0);
  if (normalizedPrimaryWindowId > 0) {
    windowIds.add(normalizedPrimaryWindowId);
  }
  if (tabIdByWindowId instanceof Map) {
    tabIdByWindowId.forEach((tabId, windowId) => {
      if (Number(tabId || 0) > 0 && Number(windowId || 0) > 0) {
        windowIds.add(Number(windowId));
      }
    });
  }
  return windowIds.size > 0 ? Array.from(windowIds) : [];
}

async function refreshOpenWorkspacesForEnvironmentSwitch(programmer = null, services = null) {
  const environmentPayload = {
    adobePassEnvironment: {
      ...getActiveAdobePassEnvironment(),
    },
    reason: "environment-switch",
    updatedAt: Date.now(),
  };

  const esmWindowIds = collectBoundWorkspaceWindowIds(
    state.esmWorkspaceWorkspaceWindowId,
    state.esmWorkspaceWorkspaceTabIdByWindowId
  );
  const esmWorkspaceState = getActiveEsmWorkspaceState();
  const esmAvailabilityResolved = hasResolvedPremiumServiceSnapshotForEsm(services);
  const esmContainerVisible = esmWorkspaceState ? true : esmAvailabilityResolved ? hasEsmScopedApp(services) : null;
  if (esmWindowIds.length > 0) {
    for (const targetWindowId of esmWindowIds) {
      await esmWorkspaceSendWorkspaceMessage(
        "controller-state",
        esmWorkspaceGetSelectedControllerStatePayload(programmer, services, {
          controllerReason: "environment-switch",
          esmAvailabilityResolved,
          esmContainerVisible,
        }),
        {
          targetWindowId,
        }
      );
      await esmWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, {
        targetWindowId,
      });
    }
  }

  const megWindowIds = collectBoundWorkspaceWindowIds(state.megWorkspaceWindowId, state.megWorkspaceTabIdByWindowId);
  if (megWindowIds.length > 0) {
    for (const targetWindowId of megWindowIds) {
      await megWorkspaceSendWorkspaceMessage(
        "controller-state",
        esmWorkspaceGetSelectedControllerStatePayload(programmer, services, {
          controllerReason: "environment-switch",
          esmAvailabilityResolved,
          esmContainerVisible,
        }),
        {
          targetWindowId,
        }
      );
      await megWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, {
        targetWindowId,
      });
    }
  }

  const cmWindowIds = collectBoundWorkspaceWindowIds(state.cmWorkspaceWindowId, state.cmWorkspaceTabIdByWindowId);
  if (cmWindowIds.length > 0) {
    const cmState = getActiveCmState();
    const cmAvailabilityResolved = hasResolvedPremiumServiceSnapshotForCm(services);
    const cmContainerVisible = cmState
      ? true
      : cmAvailabilityResolved && Object.prototype.hasOwnProperty.call(services || {}, "cm")
        ? shouldShowCmService(services?.cm)
        : null;
    for (const targetWindowId of cmWindowIds) {
      await cmSendWorkspaceMessage(
        "controller-state",
        cmGetSelectedControllerStatePayload(programmer, services, {
          controllerReason: "environment-switch",
          cmAvailabilityResolved,
          cmContainerVisible,
        }),
        {
          targetWindowId,
        }
      );
      if (cmState) {
        await cmSendWorkspaceMessage("controller-state", cmGetControllerStatePayload(cmState), {
          targetWindowId,
        });
      }
      await cmSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
    }
  }

  const mvpdWindowIds = collectBoundWorkspaceWindowIds(state.mvpdWorkspaceWindowId, state.mvpdWorkspaceTabIdByWindowId);
  for (const targetWindowId of mvpdWindowIds) {
    mvpdWorkspaceBroadcastSelectedControllerState(programmer, services, targetWindowId);
    await mvpdWorkspaceRefreshSelectedSnapshot({
      programmer,
      services,
      forceRefresh: true,
      targetWindowId,
      onlyIfWorkspaceOpen: true,
      surfaceMissingSelectionError: false,
    });
    void mvpdWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const restSelectionContext = restWorkspaceGetSelectionContextFromCurrentSelection(programmer);
  const restWindowIds = collectBoundWorkspaceWindowIds(state.restWorkspaceWindowId, state.restWorkspaceTabIdByWindowId);
  for (const targetWindowId of restWindowIds) {
    restWorkspaceBroadcastControllerState(programmer, restSelectionContext, targetWindowId);
    void restWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const esmHealthSelectionContext = esmHealthWorkspaceGetSelectionContext(programmer);
  const esmHealthWindowIds = collectBoundWorkspaceWindowIds(
    state.esmHealthWorkspaceWindowId,
    state.esmHealthWorkspaceTabIdByWindowId
  );
  for (const targetWindowId of esmHealthWindowIds) {
    esmHealthWorkspaceBroadcastControllerState(programmer, esmHealthSelectionContext, targetWindowId);
    void esmHealthWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const cmHealthSelectionContext = cmHealthWorkspaceGetSelectionContext(programmer);
  const cmHealthWindowIds = collectBoundWorkspaceWindowIds(
    state.cmHealthWorkspaceWindowId,
    state.cmHealthWorkspaceTabIdByWindowId
  );
  for (const targetWindowId of cmHealthWindowIds) {
    cmHealthWorkspaceBroadcastControllerState(programmer, cmHealthSelectionContext, targetWindowId);
    void cmHealthWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const healthSelectionContext = healthWorkspaceGetSelectionContext(programmer);
  const healthWindowIds = collectBoundWorkspaceWindowIds(state.healthWorkspaceWindowId, state.healthWorkspaceTabIdByWindowId);
  for (const targetWindowId of healthWindowIds) {
    healthWorkspaceBroadcastControllerState(programmer, healthSelectionContext, targetWindowId);
    void healthWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const tempPassSelectionContext = tempPassWorkspaceGetSelectionContext(programmer, services);
  const tempPassWindowIds = collectBoundWorkspaceWindowIds(
    state.tempPassWorkspaceWindowId,
    state.tempPassWorkspaceTabIdByWindowId
  );
  for (const targetWindowId of tempPassWindowIds) {
    tempPassWorkspaceBroadcastControllerState(programmer, services, targetWindowId);
    tempPassWorkspaceBroadcastResults(tempPassSelectionContext.selectionKey, targetWindowId);
    void tempPassWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const degradationSelectionContext = degradationWorkspaceGetSelectionContext(programmer, services);
  const degradationWindowIds = collectBoundWorkspaceWindowIds(
    state.degradationWorkspaceWindowId,
    state.degradationWorkspaceTabIdByWindowId
  );
  for (const targetWindowId of degradationWindowIds) {
    degradationWorkspaceBroadcastControllerState(programmer, services, targetWindowId, {
      controllerReason: "environment-switch",
    });
    degradationWorkspaceBroadcastReports(degradationSelectionContext.selectionKey, targetWindowId);
    void degradationWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
  }

  const bobtoolsWindowIds = collectBoundWorkspaceWindowIds(state.bobtoolsWorkspaceWindowId, state.bobtoolsWorkspaceTabIdByWindowId);
  if (bobtoolsWindowIds.length > 0) {
    const hydrationContext = resolveBobtoolsProfilesHydrationContext(programmer);
    if (hydrationContext?.ok) {
      try {
        await ensureRestV2ProfilesHydratedForBobtools(hydrationContext, {
          force: true,
          source: "environment-switch",
        });
      } catch (error) {
        log("BOBTOOLS environment-switch profile hydration failed", error instanceof Error ? error.message : String(error));
      }
    }
    const bobtoolsSelectionContext = buildBobtoolsWorkspaceSelectionContext(programmer);
    for (const targetWindowId of bobtoolsWindowIds) {
      bobtoolsWorkspaceBroadcastControllerState(programmer, bobtoolsSelectionContext, targetWindowId);
      bobtoolsWorkspaceBroadcastProfiles(programmer, {
        targetWindowId,
        selectedHarvestKey: bobtoolsSelectionContext.selectedHarvestKey,
      });
      void bobtoolsWorkspaceSendWorkspaceMessage("environment-switch-rerun", environmentPayload, { targetWindowId });
    }
  }
}

function collectKnownUnderparWorkspaceTabIds() {
  const tabIds = new Set();
  const pushCandidateTabId = (value) => {
    const normalizedTabId = Number(value || 0);
    if (normalizedTabId > 0) {
      tabIds.add(normalizedTabId);
    }
  };
  const pushMapTabIds = (tabIdByWindowId) => {
    if (!(tabIdByWindowId instanceof Map)) {
      return;
    }
    for (const mappedTabId of tabIdByWindowId.values()) {
      pushCandidateTabId(mappedTabId);
    }
  };

  pushCandidateTabId(state.esmWorkspaceWorkspaceTabId);
  pushMapTabIds(state.esmWorkspaceWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.megWorkspaceTabId);
  pushMapTabIds(state.megWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.cmWorkspaceTabId);
  pushMapTabIds(state.cmWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.mvpdWorkspaceTabId);
  pushMapTabIds(state.mvpdWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.restWorkspaceTabId);
  pushMapTabIds(state.restWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.esmHealthWorkspaceTabId);
  pushMapTabIds(state.esmHealthWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.healthWorkspaceTabId);
  pushMapTabIds(state.healthWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.tempPassWorkspaceTabId);
  pushMapTabIds(state.tempPassWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.degradationWorkspaceTabId);
  pushMapTabIds(state.degradationWorkspaceTabIdByWindowId);
  pushCandidateTabId(state.bobtoolsWorkspaceTabId);
  pushMapTabIds(state.bobtoolsWorkspaceTabIdByWindowId);

  return Array.from(tabIds);
}

function isUnderparWorkspaceTab(tabLike = null) {
  const tabUrl = String(tabLike?.url || "").trim();
  if (!tabUrl) {
    return false;
  }
  return UNDERPAR_WORKSPACE_PATHS.some((path) => tabUrl.startsWith(chrome.runtime.getURL(path)));
}

async function closeOpenUnderparWorkspaceTabs(options = {}) {
  const closeReason = String(options?.reason || "signed-out").trim() || "signed-out";
  const requestedTabIds = new Set(collectKnownUnderparWorkspaceTabIds());
  const matchedTabs = [];

  try {
    const allTabs = await chrome.tabs.query({});
    for (const tab of Array.isArray(allTabs) ? allTabs : []) {
      if (!isUnderparWorkspaceTab(tab)) {
        continue;
      }
      matchedTabs.push(tab);
      const normalizedTabId = Number(tab?.id || 0);
      if (normalizedTabId > 0) {
        requestedTabIds.add(normalizedTabId);
      }
    }
  } catch {
    // Ignore workspace tab enumeration failures and fall back to known bindings only.
  }

  const tabIds = Array.from(requestedTabIds).filter((tabId) => Number(tabId || 0) > 0);
  if (tabIds.length === 0) {
    return {
      requestedCloseCount: 0,
      closedCount: 0,
    };
  }

  const closedTabIds = [];
  for (const tabId of tabIds) {
    try {
      await chrome.tabs.remove(tabId);
      closedTabIds.push(tabId);
    } catch {
      // Ignore tabs that were already closed or became unavailable.
    }
  }

  const matchedWindowIds = new Set(
    matchedTabs
      .filter((tab) => closedTabIds.includes(Number(tab?.id || 0)))
      .map((tab) => Number(tab?.windowId || 0))
      .filter((windowId) => windowId > 0)
  );
  for (const closedTabId of closedTabIds) {
    esmWorkspaceUnbindWorkspaceTab(closedTabId);
    megWorkspaceUnbindWorkspaceTab(closedTabId);
    cmUnbindWorkspaceTab(closedTabId);
    mvpdWorkspaceUnbindWorkspaceTab(closedTabId);
    restWorkspaceUnbindWorkspaceTab(closedTabId);
    tempPassWorkspaceUnbindWorkspaceTab(closedTabId);
    degradationWorkspaceUnbindWorkspaceTab(closedTabId);
    bobtoolsWorkspaceUnbindWorkspaceTab(closedTabId);
  }
  for (const windowId of matchedWindowIds) {
    megWorkspaceClearRememberedSelection(windowId);
  }
  if (matchedWindowIds.size === 0 && closedTabIds.length > 0) {
    megWorkspaceClearRememberedSelection(0);
  }

  log("Closed UnderPAR workspace tabs for signed-out reset.", {
    reason: closeReason,
    requestedCloseCount: tabIds.length,
    closedCount: closedTabIds.length,
  });
  return {
    requestedCloseCount: tabIds.length,
    closedCount: closedTabIds.length,
  };
}

function normalizeUnderparWindowId(value) {
  const normalized = Number(value || 0);
  return Number.isInteger(normalized) && normalized > 0 ? normalized : 0;
}

function clearSidepanelControllerReconnectTimer() {
  if (state.sidepanelControllerReconnectTimerId) {
    window.clearTimeout(state.sidepanelControllerReconnectTimerId);
    state.sidepanelControllerReconnectTimerId = 0;
  }
}

async function resolveSidepanelControllerWindowId(forceRefresh = false) {
  if (!forceRefresh && normalizeUnderparWindowId(state.sidepanelControllerWindowId)) {
    return normalizeUnderparWindowId(state.sidepanelControllerWindowId);
  }

  try {
    const currentWindow = await chrome.windows.getCurrent();
    state.sidepanelControllerWindowId = normalizeUnderparWindowId(currentWindow?.id);
  } catch {
    // Ignore window lookup failures and keep the last known window id.
  }

  return normalizeUnderparWindowId(state.sidepanelControllerWindowId);
}

function buildSidepanelControllerSnapshot(windowId = 0) {
  return {
    windowId: normalizeUnderparWindowId(windowId || state.sidepanelControllerWindowId),
    sessionReady: state.sessionReady === true && Boolean(state.loginData) && state.restricted !== true,
    restricted: state.restricted === true,
    bootstrapping: state.isBootstrapping === true,
  };
}

function getSidepanelControllerSnapshotKey(snapshot = null) {
  const normalizedSnapshot = snapshot && typeof snapshot === "object" ? snapshot : {};
  return [
    normalizeUnderparWindowId(normalizedSnapshot.windowId),
    normalizedSnapshot.sessionReady === true ? 1 : 0,
    normalizedSnapshot.restricted === true ? 1 : 0,
    normalizedSnapshot.bootstrapping === true ? 1 : 0,
  ].join(":");
}

function disconnectSidepanelControllerPort() {
  clearSidepanelControllerReconnectTimer();
  const existingPort = state.sidepanelControllerPort;
  state.sidepanelControllerPort = null;
  state.sidepanelControllerSnapshotKey = "";
  if (existingPort) {
    try {
      existingPort.disconnect();
    } catch {
      // Ignore disconnect failures for stale ports.
    }
  }
}

function scheduleSidepanelControllerReconnect() {
  if (state.sidepanelControllerShutdown || state.sidepanelControllerReconnectTimerId) {
    return;
  }
  state.sidepanelControllerReconnectTimerId = window.setTimeout(() => {
    state.sidepanelControllerReconnectTimerId = 0;
    void syncSidepanelControllerBridge(true);
  }, 250);
}

function ensureSidepanelControllerPort() {
  if (state.sidepanelControllerShutdown) {
    return null;
  }
  if (state.sidepanelControllerPort) {
    return state.sidepanelControllerPort;
  }

  try {
    const port = chrome.runtime.connect({ name: UNDERPAR_SIDEPANEL_SESSION_PORT_NAME });
    port.onMessage.addListener((message) => {
      if (!message || typeof message !== "object" || message.type !== "network-activity") {
        return;
      }
      state.remoteNetworkActivityCount = Math.max(0, Number(message?.activity?.count || 0));
      state.remoteNetworkActivityContext = String(message?.activity?.context || "").trim();
      syncGlobalNetworkActivityIndicator();
      renderDebugConsole();
    });
    port.onDisconnect.addListener(() => {
      if (state.sidepanelControllerPort === port) {
        state.sidepanelControllerPort = null;
      }
      state.sidepanelControllerSnapshotKey = "";
      state.remoteNetworkActivityCount = 0;
      state.remoteNetworkActivityContext = "";
      syncGlobalNetworkActivityIndicator();
      renderDebugConsole();
      if (!state.sidepanelControllerShutdown) {
        scheduleSidepanelControllerReconnect();
      }
    });
    state.sidepanelControllerPort = port;
    return port;
  } catch {
    return null;
  }
}

async function syncSidepanelControllerBridge(force = false) {
  if (state.sidepanelControllerShutdown) {
    return false;
  }

  const windowId = await resolveSidepanelControllerWindowId();
  const snapshot = buildSidepanelControllerSnapshot(windowId);
  const snapshotKey = getSidepanelControllerSnapshotKey(snapshot);
  if (!force && state.sidepanelControllerPort && state.sidepanelControllerSnapshotKey === snapshotKey) {
    return true;
  }

  const port = ensureSidepanelControllerPort();
  if (!port) {
    scheduleSidepanelControllerReconnect();
    return false;
  }

  try {
    port.postMessage({
      type: "session-state",
      ...snapshot,
    });
    state.sidepanelControllerSnapshotKey = snapshotKey;
    return true;
  } catch {
    if (state.sidepanelControllerPort === port) {
      state.sidepanelControllerPort = null;
    }
    state.sidepanelControllerSnapshotKey = "";
    scheduleSidepanelControllerReconnect();
    return false;
  }
}

function startSidepanelControllerBridge() {
  state.sidepanelControllerShutdown = false;
  void syncSidepanelControllerBridge(true);
}

function shutdownSidepanelControllerBridge() {
  state.sidepanelControllerShutdown = true;
  state.remoteNetworkActivityCount = 0;
  syncGlobalNetworkActivityIndicator();
  disconnectSidepanelControllerPort();
}

async function applyGlobalSelectionSnapshot(snapshot = null, options = {}) {
  const result = {
    programmerRestored: false,
    requestorRestored: false,
    mvpdRestored: false,
    missingSelection: "",
  };

  const programmer = findProgrammerForEnvironmentSwitchSnapshot(snapshot);
  if (!programmer) {
    result.missingSelection = String(
      snapshot?.programmerName || snapshot?.mediaCompanyName || snapshot?.programmerId || ""
    ).trim();
    return result;
  }

  state.selectedProgrammerKey = String(programmer.key || "").trim();
  if (els.mediaCompanySelect) {
    els.mediaCompanySelect.value = state.selectedProgrammerKey;
  }
  state.selectedRequestorId = "";
  state.selectedMvpdId = "";
  populateRequestorSelect();
  result.programmerRestored = true;

  const availableRequestorIds = Array.isArray(programmer.requestorIds) ? programmer.requestorIds : [];
  const explicitRequestorId = String(snapshot?.requestorId || "").trim();
  if (explicitRequestorId && availableRequestorIds.includes(explicitRequestorId)) {
    state.selectedRequestorId = explicitRequestorId;
    if (els.requestorSelect) {
      els.requestorSelect.value = explicitRequestorId;
    }
    result.requestorRestored = true;
  }

  // Let refreshProgrammerPanels own VAULT/runtime restore so ENV switching
  // does not restore the same Media Company twice on the critical path.
  await refreshProgrammerPanels({
    controllerReason: String(options?.controllerReason || "environment-switch"),
  });

  if (result.requestorRestored) {
    await populateMvpdSelectForRequestor(explicitRequestorId);
  }

  const explicitMvpdId = String(snapshot?.mvpdId || "").trim();
  const fallbackMvpdId = options?.autoSelectFirstMvpd === true ? getFirstSelectableOptionValue(els.mvpdSelect) : "";
  const mvpdId = firstNonEmptyString([explicitMvpdId, fallbackMvpdId]);
  if (result.requestorRestored && mvpdId && els.mvpdSelect) {
    const mvpdAvailable = Array.from(els.mvpdSelect.options || []).some((option) => String(option?.value || "") === mvpdId);
    if (mvpdAvailable) {
      state.selectedMvpdId = mvpdId;
      els.mvpdSelect.value = mvpdId;
      result.mvpdRestored = true;
      await refreshProgrammerPanels({
        controllerReason: String(options?.mvpdControllerReason || "environment-switch-mvpd-restore"),
        forcePremiumRefresh: false,
      });
    }
  }

  refreshRestV2LoginPanels();
  const esmWorkspaceState = getActiveEsmWorkspaceState();
  if (esmWorkspaceState) {
    esmWorkspaceBroadcastControllerState(esmWorkspaceState);
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
  }
  const degradationState = getActiveDegradationWorkspaceState();
  if (degradationState) {
    degradationSyncGoButtonLabel(degradationState);
    syncDegradationWorkspaceRecordingControls(degradationState);
  }
  const cmState = getActiveCmState();
  if (cmState) {
    cmBroadcastControllerState(cmState);
  }
  const selectedServices = getCurrentPremiumAppsSnapshot(programmer.programmerId);
  mvpdWorkspaceBroadcastSelectedControllerState(programmer, selectedServices);
  refreshMvpdWorkspaceTools();
  void mvpdWorkspaceRefreshSelectedSnapshot({
    programmer,
    services: selectedServices,
    forceRefresh: result.requestorRestored,
    onlyIfWorkspaceOpen: !result.requestorRestored,
    surfaceMissingSelectionError: false,
  });
  await refreshOpenWorkspacesForEnvironmentSwitch(programmer, selectedServices);

  return result;
}

async function restoreAdobePassEnvironmentSwitchSelection(snapshot = null) {
  return applyGlobalSelectionSnapshot(snapshot, {
    controllerReason: "environment-switch",
    mvpdControllerReason: "environment-switch-mvpd-restore",
  });
}

async function switchAdobePassEnvironmentInPlace(environment = null, options = {}) {
  const targetEnvironment = resolveAdobePassEnvironment(environment);
  const targetEnvironmentKey =
    String(targetEnvironment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const currentEnvironmentKey =
    String(state?.adobePassEnvironmentKey || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  if (targetEnvironmentKey === currentEnvironmentKey) {
    renderBuildInfo();
    return {
      ok: true,
      changed: false,
      environment: targetEnvironment,
      sessionReady: state.sessionReady === true,
    };
  }
  if (state.environmentSwitchPromise) {
    return state.environmentSwitchPromise;
  }

  const switchPromise = (async () => {
    const shouldRestoreSelection =
      options?.restoreSelection !== false &&
      state.sessionReady === true &&
      Boolean(state.loginData) &&
      state.restricted !== true;
    const selectionSnapshot = shouldRestoreSelection
      ? options?.selectionSnapshot && typeof options.selectionSnapshot === "object"
        ? {
            ...options.selectionSnapshot,
          }
        : captureAdobePassEnvironmentSwitchSelectionSnapshot()
      : null;
    const retainedLoginData =
      state.loginData && typeof state.loginData === "object"
        ? {
            ...state.loginData,
            cmConsoleAccessToken: "",
            cmConsoleExpiresAt: 0,
            cmConsoleScope: "",
            cmConsoleImsSession: null,
          }
        : null;
    const environmentLabel = String(targetEnvironment?.label || "selected environment").trim() || "selected environment";
    let lastError = null;

    state.sessionMonitorSuppressed = true;
    setBusy(true, `Switching to ${environmentLabel}...`);
    setStatus("", "info");

    try {
      try {
        await maybeAutoStopRestV2RecordingForSelectionChange(
          {
            requestorId: "",
            mvpdId: "",
          },
          {
            reason: `Environment switch to ${environmentLabel}`,
          }
        );
      } catch (error) {
        log("REST V2 auto-stop skipped during environment switch", error instanceof Error ? error.message : String(error));
      }

      applyAdobePassEnvironment(targetEnvironment);
      renderBuildInfo();
      prepareAdobePassEnvironmentSwitchUi(targetEnvironment);
      render();

      let activated = false;
      let activationSource = "none";
      const accessToken = String(retainedLoginData?.accessToken || "").trim();

      if (accessToken) {
        try {
          const reactivated = await activateSession(retainedLoginData, "environment-switch", {
            allowTemporaryPageContextTab: true,
          });
          if (reactivated) {
            activated = true;
            activationSource = "token";
          }
        } catch (error) {
          lastError = error instanceof Error ? error : new Error(String(error));
          log("AdobePASS environment token rehydrate failed", {
            environmentKey: targetEnvironmentKey,
            error: lastError.message,
          });
        }
      }

      if (!activated) {
        state.loginData = retainedLoginData;
        state.sessionReady = false;
        state.restricted = false;
        setStatus(`Sign in is required for ${environmentLabel}.`, "error");
        render();
        return {
          ok: true,
          changed: true,
          requiresSignIn: true,
          environment: targetEnvironment,
          activationSource,
          error: lastError instanceof Error ? lastError.message : lastError ? String(lastError) : "",
        };
      }

      let restoreResult = {
        programmerRestored: false,
        requestorRestored: false,
        mvpdRestored: false,
        missingSelection: "",
      };
      if (shouldRestoreSelection && hasProgrammerSelectionSnapshot(selectionSnapshot)) {
        restoreResult = await applyGlobalSelectionSnapshot(selectionSnapshot, {
          controllerReason: "environment-switch",
          mvpdControllerReason: "environment-switch-mvpd-restore",
          autoSelectFirstMvpd: options?.autoSelectFirstMvpd === true,
        });
      }
      const missingSelectionLabel = String(restoreResult.missingSelection || "").trim();
      if (missingSelectionLabel) {
        setStatus(
          `${missingSelectionLabel} is not available in ${environmentLabel}. Re-select the Media Company in this environment.`,
          "error"
        );
      } else if (state.programmers.length === 0) {
        setStatus("No media company records were returned for this account.", "error");
      } else {
        setStatus("", "info");
      }

      renderBuildInfo();
      render();
      return {
        ok: true,
        changed: true,
        environment: targetEnvironment,
        activationSource,
        ...restoreResult,
      };
    } finally {
      state.sessionMonitorSuppressed = false;
      setBusy(false);
      render();
    }
  })();

  state.environmentSwitchPromise = switchPromise;
  try {
    return await switchPromise;
  } finally {
    if (state.environmentSwitchPromise === switchPromise) {
      state.environmentSwitchPromise = null;
    }
  }
}

function registerAdobePassEnvironmentStorageListener() {
  if (state.adobePassEnvironmentStorageListenerBound || !chrome?.storage?.onChanged?.addListener) {
    return;
  }
  const storageKey = getAdobePassEnvironmentStorageKey();
  chrome.storage.onChanged.addListener((changes, areaName) => {
    if (areaName !== "local" || !changes || !Object.prototype.hasOwnProperty.call(changes, storageKey)) {
      return;
    }
    const nextEnvironmentKey =
      String(changes?.[storageKey]?.newValue || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() ||
      DEFAULT_ADOBEPASS_ENVIRONMENT.key;
    if (nextEnvironmentKey === getActiveAdobePassEnvironmentKey()) {
      renderBuildInfo();
      return;
    }
    void switchAdobePassEnvironmentInPlace(nextEnvironmentKey, {
      source: "storage-change",
      restoreSelection: true,
    }).catch((error) => {
      setStatus(error instanceof Error ? error.message : String(error), "error");
    });
  });
  state.adobePassEnvironmentStorageListenerBound = true;
}

function registerPassVaultStorageListener() {
  if (state.passVaultStorageListenerBound) {
    return;
  }

  const applyPassVaultSync = (vaultPayload = null) => {
    state.passVault = normalizeUnderparVaultPayload(vaultPayload);
    state.passVaultLoaded = true;
    rebuildPassVaultProgrammerStatusIndex(state.passVault);
    refreshAllEsmWorkspaceMegSavedQuerySelectors();
    if (consumePendingPassVaultStorageWrite(state.passVault)) {
      return;
    }

    void seedCurrentProgrammersFromPassVault({
      forceReload: false,
      forceOverwrite: false,
      forceDcrRestore: true,
    }).then(() => {
      const selectedProgrammer = resolveSelectedProgrammer();
      if (!selectedProgrammer) {
        return;
      }
      const cachedServices = getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId);
      if (cachedServices) {
        renderPremiumServices(cachedServices, selectedProgrammer, {
          controllerReason: "vault-storage-change",
        });
      }
    });
  };

  if (canUseUnderparVaultIndexedDb() && typeof underparVaultStore.subscribe === "function") {
    underparVaultStore.subscribe(() => {
      void underparVaultStore
        .readAggregatePayload()
        .then((vaultPayload) => {
          applyPassVaultSync(vaultPayload);
        })
        .catch(() => {});
    });
    state.passVaultStorageListenerBound = true;
    return;
  }
}

function registerUnderparEsmDeeplinkStorageListener() {
  if (state.underparEsmDeeplinkStorageListenerBound || !chrome?.storage?.onChanged?.addListener) {
    return;
  }

  chrome.storage.onChanged.addListener((changes, areaName) => {
    if (areaName !== "local" || !changes || !Object.prototype.hasOwnProperty.call(changes, UNDERPAR_ESM_DEEPLINK_STORAGE_KEY)) {
      return;
    }
    if (!state.sessionReady || !state.loginData || state.restricted) {
      return;
    }
    void consumePendingUnderparEsmDeeplink();
  });

  state.underparEsmDeeplinkStorageListenerBound = true;
}
