function registerCoreInteractionHandlers() {
  if (underparCoreInteractionHandlersBound) {
    return;
  }
  underparCoreInteractionHandlersBound = true;

  if (els.authBtn) {
    els.authBtn.addEventListener("click", () => {
      void onAuthClick();
    });
  }

  if (els.signInHeroBtn) {
    els.signInHeroBtn.addEventListener("click", () => {
      void onPrimarySignInClick();
    });
  }

  if (els.signInZipKeyBtn) {
    els.signInZipKeyBtn.addEventListener("click", () => {
      openZipKeyImportGate();
    });
  }

  if (els.debugToggleButton) {
    els.debugToggleButton.addEventListener("click", (event) => {
      if (event.shiftKey) {
        setDebugConsoleCollapsed(!state.debugConsoleCollapsed);
        return;
      }
      void copyDebugConsoleToClipboard();
    });
  }

  if (els.zipKeyBrowseBtn) {
    els.zipKeyBrowseBtn.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      promptForZipKeyImport();
    });
  }

  if (els.zipKeyContinueBtn) {
    els.zipKeyContinueBtn.addEventListener("click", () => {
      onZipKeyContinue();
    });
  }

  if (els.zipKeyFileInput) {
    els.zipKeyFileInput.addEventListener("change", (event) => {
      const file = event?.target?.files?.[0] || null;
      event.target.value = "";
      if (!file) {
        return;
      }
      void importZipKeyIntoVaultFromFile(file);
    });
  }

  if (els.zipKeyDropzone) {
    els.zipKeyDropzone.addEventListener("click", () => {
      promptForZipKeyImport();
    });
    els.zipKeyDropzone.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") {
        return;
      }
      event.preventDefault();
      promptForZipKeyImport();
    });
    els.zipKeyDropzone.addEventListener("dragenter", (event) => {
      event.preventDefault();
      if (state.zipKeyImportPending) {
        return;
      }
      state.zipKeyImportDragActive = true;
      render();
    });
    els.zipKeyDropzone.addEventListener("dragover", (event) => {
      event.preventDefault();
      if (event.dataTransfer) {
        event.dataTransfer.dropEffect = "copy";
      }
      if (state.zipKeyImportPending || state.zipKeyImportDragActive) {
        return;
      }
      state.zipKeyImportDragActive = true;
      render();
    });
    els.zipKeyDropzone.addEventListener("dragleave", (event) => {
      event.preventDefault();
      if (state.zipKeyImportPending) {
        return;
      }
      const currentTarget = event.currentTarget;
      const relatedTarget = event.relatedTarget;
      if (currentTarget instanceof Node && relatedTarget instanceof Node && currentTarget.contains(relatedTarget)) {
        return;
      }
      state.zipKeyImportDragActive = false;
      render();
    });
    els.zipKeyDropzone.addEventListener("drop", (event) => {
      event.preventDefault();
      if (state.zipKeyImportPending) {
        return;
      }
      state.zipKeyImportDragActive = false;
      render();
      const file = event.dataTransfer?.files?.[0] || null;
      if (!file) {
        const message = "Drop a ZIP.KEY file to load Adobe IMS settings into VAULT.";
        setZipKeyImportFeedback(message, "error");
        setStatus(message, "error");
        render();
        return;
      }
      void importZipKeyIntoVaultFromFile(file);
    });
  }
}

registerCoreInteractionHandlers();

function log(message, details = null) {
  const normalizedMessage = String(message || "").trim() || "(no message)";
  appendDebugLogEntry("app", normalizedMessage, details);
  if (details === null) {
    console.log(`[UnderPAR] ${normalizedMessage}`);
    return;
  }
  console.log(`[UnderPAR] ${normalizedMessage}`, details);
}

function relayDecisionLogToBackground(message, details = null) {
  const payload = {
    type: CONSOLE_LOG_RELAY_REQUEST_TYPE,
    message: String(message || ""),
    details: details && typeof details === "object" ? details : details == null ? null : { value: String(details) },
    origin: "sidepanel",
    at: Date.now(),
  };
  void sendRuntimeMessageSafe(payload).catch(() => {
    // Best-effort mirror only.
  });
}

function logDecisionPoint(message, details = null) {
  log(message, details);
  relayDecisionLogToBackground(message, details);
}

function setTextOutput(element, value) {
  if (!element) {
    return;
  }
  const nextValue = String(value ?? "");
  if ("value" in element) {
    element.value = nextValue;
    element.scrollTop = 0;
    return;
  }
  element.textContent = nextValue;
}

function sanitizeUnderparDebugInfoValue(value, options = {}) {
  const depth = Number(options.depth || 0);
  const keyName = String(options.keyName || "").trim().toLowerCase();
  const seen = options.seen instanceof WeakSet ? options.seen : new WeakSet();
  const sensitiveKey =
    keyName.includes("token") ||
    keyName.includes("secret") ||
    keyName.includes("password") ||
    keyName === "authorization" ||
    keyName === "cookie" ||
    keyName === "set-cookie";

  if (value == null) {
    return value;
  }

  if (typeof value === "string") {
    const redacted = redactSensitiveTokenValues(value);
    if (sensitiveKey && redacted === value) {
      return "<redacted>";
    }
    return truncateDebugText(redacted, 1000);
  }

  if (typeof value === "number" || typeof value === "boolean") {
    return value;
  }

  if (typeof value === "bigint") {
    return String(value);
  }

  if (value instanceof Error) {
    return {
      name: String(value.name || "Error"),
      message: sanitizeUnderparDebugInfoValue(value.message || "", {
        depth: depth + 1,
        keyName: "message",
        seen,
      }),
      stack: truncateDebugText(redactSensitiveTokenValues(String(value.stack || "")), 1200),
    };
  }

  if (value instanceof Headers) {
    return sanitizeUnderparDebugInfoValue(toDebugHeadersObject(value), {
      depth: depth + 1,
      keyName,
      seen,
    });
  }

  if (typeof value !== "object") {
    return sanitizeUnderparDebugInfoValue(String(value), {
      depth: depth + 1,
      keyName,
      seen,
    });
  }

  if (depth >= 4) {
    if (Array.isArray(value)) {
      return `[array:${value.length}]`;
    }
    return `[${String(value?.constructor?.name || "object")}]`;
  }

  if (seen.has(value)) {
    return "[circular]";
  }
  seen.add(value);

  if (Array.isArray(value)) {
    const output = value.slice(0, 16).map((entry) =>
      sanitizeUnderparDebugInfoValue(entry, {
        depth: depth + 1,
        keyName,
        seen,
      })
    );
    if (value.length > 16) {
      output.push(`[+${value.length - 16} more]`);
    }
    return output;
  }

  const output = {};
  const entries = Object.entries(value);
  entries.slice(0, 32).forEach(([entryKey, entryValue]) => {
    output[entryKey] = sanitizeUnderparDebugInfoValue(entryValue, {
      depth: depth + 1,
      keyName: entryKey,
      seen,
    });
  });
  if (entries.length > 32) {
    output.__truncatedKeys = entries.length - 32;
  }
  return output;
}

function stringifyUnderparDebugInfoValue(value) {
  if (value == null) {
    return "";
  }
  if (typeof value === "string") {
    return truncateDebugText(redactSensitiveTokenValues(value), 600);
  }
  const sanitized = sanitizeUnderparDebugInfoValue(value);
  try {
    return truncateDebugText(JSON.stringify(sanitized), 1200);
  } catch {
    return truncateDebugText(String(sanitized), 600);
  }
}

function appendDebugLogEntry(channel = "app", message = "", details = null, options = {}) {
  const normalizedMessage = redactSensitiveTokenValues(String(message || "").trim() || "(no message)");
  const normalizedChannel = String(channel || "app").trim() || "app";
  const normalizedLevel = String(options.level || "info").trim().toLowerCase() || "info";
  const sanitizedDetails =
    details == null
      ? null
      : sanitizeUnderparDebugInfoValue(details, {
          keyName: normalizedChannel,
          seen: new WeakSet(),
        });

  state.logs.unshift({
    at: Date.now(),
    channel: normalizedChannel,
    level: normalizedLevel,
    message: normalizedMessage,
    details: sanitizedDetails,
  });
  state.logs = state.logs.slice(0, UNDERPAR_DEBUG_LOG_LIMIT);
  renderDebugConsole();
}

function appendDebugStatusHistoryEntry(message = "", type = "info", source = "status") {
  const normalizedMessage = redactSensitiveTokenValues(String(message || "").trim());
  if (!normalizedMessage) {
    return;
  }

  const normalizedType = String(type || "info").trim().toLowerCase() || "info";
  const normalizedSource = String(source || "status").trim() || "status";
  state.debugStatusHistory.unshift({
    at: Date.now(),
    type: normalizedType,
    source: normalizedSource,
    message: normalizedMessage,
  });
  state.debugStatusHistory = state.debugStatusHistory.slice(0, UNDERPAR_DEBUG_STATUS_HISTORY_LIMIT);
}

function compactRecentActivityEntries(entries, limit = 12) {
  if (!Array.isArray(entries) || entries.length === 0) {
    return [];
  }

  return entries.slice(0, limit).map((entry) => {
    if (typeof entry === "string") {
      const compact = entry
        .split(/\r?\n+/)
        .map((line) => line.trim())
        .filter(Boolean)
        .join(" | ");
      return compact.length > 420 ? `${compact.slice(0, 417)}...` : compact;
    }
    const timestamp = Number(entry?.at || 0) > 0 ? new Date(Number(entry.at || 0)).toLocaleTimeString() : "n/a";
    const parts = [
      timestamp,
      String(entry?.channel || "app").trim() || "app",
      String(entry?.message || "").trim(),
      stringifyUnderparDebugInfoValue(entry?.details),
    ].filter(Boolean);
    const compact = parts.join(" | ");
    return compact.length > 420 ? `${compact.slice(0, 417)}...` : compact;
  });
}

function compactRecentStatusEntries(entries, limit = UNDERPAR_DEBUG_STATUS_OUTPUT_LIMIT) {
  if (!Array.isArray(entries) || entries.length === 0) {
    return [];
  }

  return entries.slice(0, limit).map((entry) => {
    const timestamp = Number(entry?.at || 0) > 0 ? new Date(Number(entry.at || 0)).toLocaleTimeString() : "n/a";
    const parts = [
      timestamp,
      String(entry?.source || "status").trim() || "status",
      String(entry?.type || "info").trim() || "info",
      String(entry?.message || "").trim(),
    ].filter(Boolean);
    const compact = parts.join(" | ");
    return compact.length > 420 ? `${compact.slice(0, 417)}...` : compact;
  });
}

function getLatestDebugStatusEntry(predicate = null) {
  const history = Array.isArray(state.debugStatusHistory) ? state.debugStatusHistory : [];
  if (typeof predicate !== "function") {
    return history[0] || null;
  }
  return history.find((entry) => {
    try {
      return predicate(entry);
    } catch {
      return false;
    }
  }) || null;
}

function isUnderparDebugErrorEntry(entry = null) {
  if (!entry || typeof entry !== "object") {
    return false;
  }
  const level = String(entry?.level || "").trim().toLowerCase();
  const statusType = String(entry?.details?.type || "").trim().toLowerCase();
  return level === "error" || statusType === "error";
}

function getRecentDebugLogEntries(predicate = null, limit = 6) {
  const history = Array.isArray(state.logs) ? state.logs : [];
  const entries = typeof predicate === "function"
    ? history.filter((entry) => {
        try {
          return predicate(entry);
        } catch {
          return false;
        }
      })
    : [...history];
  return entries.slice(0, limit);
}

function setUnderparDiagnosticMarker(markerKey = "", payload = null) {
  const normalizedKey = String(markerKey || "").trim();
  if (!normalizedKey) {
    return;
  }

  if (!payload || typeof payload !== "object") {
    delete state.debugMarkers[normalizedKey];
    return;
  }

  const sanitizedPayload = sanitizeUnderparDebugInfoValue(payload, {
    keyName: normalizedKey,
    seen: new WeakSet(),
  });
  const markerAt = Number(payload?.at || 0) > 0 ? Number(payload.at) : Date.now();
  state.debugMarkers[normalizedKey] = {
    ...sanitizedPayload,
    at: markerAt,
  };
}

function getUnderparDiagnosticMarker(markerKey = "") {
  const normalizedKey = String(markerKey || "").trim();
  if (!normalizedKey) {
    return null;
  }
  const marker = state.debugMarkers?.[normalizedKey];
  return marker && typeof marker === "object" ? marker : null;
}

function summarizeUnderparDiagnosticMarker(marker = null, preferredKeys = []) {
  if (!marker || typeof marker !== "object") {
    return "n/a";
  }

  const orderedKeys = Array.isArray(preferredKeys) ? preferredKeys : [];
  const consumedKeys = new Set(["at", "status"]);
  const parts = [];
  const status = String(marker?.status || "").trim();
  if (status) {
    parts.push(status);
  }

  const pushField = (key) => {
    if (consumedKeys.has(key)) {
      return;
    }
    consumedKeys.add(key);
    const rawValue = marker?.[key];
    if (rawValue == null || rawValue === "") {
      return;
    }
    const renderedValue = stringifyUnderparDebugInfoValue(rawValue);
    if (!renderedValue) {
      return;
    }
    parts.push(`${key}=${renderedValue}`);
  };

  orderedKeys.forEach(pushField);

  for (const key of Object.keys(marker)) {
    if (parts.length >= 6) {
      break;
    }
    pushField(key);
  }

  parts.push(`at=${new Date(Number(marker.at || Date.now())).toISOString()}`);
  return truncateDebugText(parts.join(" | "), 420);
}

function getUnderparCurrentView() {
  if (state.restricted === true) {
    return "restricted";
  }
  if (shouldShowZipKeyImportGate()) {
    return "zip-key-gate";
  }
  if (state.sessionReady && state.loginData) {
    return "authenticated";
  }
  return "unauthenticated";
}

function buildUnderparDebugSummaryLine(context = {}) {
  const parts = [
    String(context.currentView || getUnderparCurrentView()),
    state.busy ? `busy:${String(state.busyContext || "").trim() || "yes"}` : "idle",
    hasConfiguredUnderparImsClientId() ? "key loaded" : "key missing",
    state.sessionReady && state.loginData ? "session active" : state.restricted ? "restricted" : "no session",
  ];
  if (state.cmTenantsPrecheckComplete === true) {
    parts.push(String(state.cmTenantsPrecheckLastError || "").trim() ? "cm precheck failed" : "cm precheck ready");
  } else if (state.cmTenantsPrecheckPending === true) {
    parts.push("cm precheck pending");
  }
  if (state.updateAvailable === true) {
    parts.push(`update ${String(state.latestVersion || "available").trim() || "available"}`);
  }
  return parts.join(" | ");
}

function pushDebugSection(lines, label, entries) {
  lines.push(`[${label}]`);
  lines.push(...entries);
  lines.push("");
}

function composeUnderparDebugConsoleOutput() {
  const lines = [];
  const loginData = state.loginData && typeof state.loginData === "object" ? state.loginData : null;
  const authContext = loginData ? buildLoginAuthContext(loginData) : {};
  const runtimeConfig = getActiveUnderparImsRuntimeConfig();
  const environment = getActiveAdobePassEnvironment();
  const selectedProgrammer = resolveSelectedProgrammer();
  const selectedProgrammerId = String(selectedProgrammer?.programmerId || "").trim();
  const selectedServices = selectedProgrammerId ? getCurrentPremiumAppsSnapshot(selectedProgrammerId) : null;
  const globalStatus = String(els.status?.textContent || "").trim();
  const selectedMvpdLabel = state.selectedMvpdId
    ? String(getRestV2MvpdPickerLabel(String(state.selectedRequestorId || "").trim(), state.selectedMvpdId) || state.selectedMvpdId).trim()
    : "";
  const workspaceState = {
    esmWindowId: Number(state.esmWorkspaceWorkspaceWindowId || 0),
    cmWindowId: Number(state.cmWorkspaceWindowId || 0),
    degradationWindowId: Number(state.degradationWorkspaceWindowId || 0),
    mvpdWindowId: Number(state.mvpdWorkspaceWindowId || 0),
    restWindowId: Number(state.restWorkspaceWindowId || 0),
    megWindowId: Number(state.megWorkspaceWindowId || 0),
    blondieWindowId: Number(state.blondieTimeWorkspaceWindowId || 0),
  };
  const latestStatusEntry = getLatestDebugStatusEntry();
  const latestErrorStatusEntry = getLatestDebugStatusEntry(
    (entry) => String(entry?.type || "").trim().toLowerCase() === "error"
  );
  const recentStatusEntries = compactRecentStatusEntries(state.debugStatusHistory, UNDERPAR_DEBUG_STATUS_OUTPUT_LIMIT);
  const recentFailureEntries = compactRecentActivityEntries(
    getRecentDebugLogEntries((entry) => isUnderparDebugErrorEntry(entry), UNDERPAR_DEBUG_FAILURE_OUTPUT_LIMIT),
    UNDERPAR_DEBUG_FAILURE_OUTPUT_LIMIT
  );
  const recentNonFetchEntries = compactRecentActivityEntries(
    getRecentDebugLogEntries(
      (entry) => String(entry?.channel || "").trim().toLowerCase() !== "fetch",
      UNDERPAR_DEBUG_NON_FETCH_OUTPUT_LIMIT
    ),
    UNDERPAR_DEBUG_NON_FETCH_OUTPUT_LIMIT
  );
  const bootstrapMarker = getUnderparDiagnosticMarker("bootstrap");
  const authMarker = getUnderparDiagnosticMarker("auth");
  const activationMarker = getUnderparDiagnosticMarker("activation");
  const consoleBootstrapMarker = getUnderparDiagnosticMarker("console_bootstrap");
  const programmersMarker = getUnderparDiagnosticMarker("programmers");
  const cmPrecheckMarker = getUnderparDiagnosticMarker("cm_precheck");
  const recentActivityEntries = compactRecentActivityEntries(state.logs, 12);

  lines.push("UnderPAR DEBUG INFO");
  lines.push(`captured_at=${new Date().toISOString()}`);
  lines.push(`summary=${buildUnderparDebugSummaryLine({ currentView: getUnderparCurrentView() })}`);
  lines.push("");

  pushDebugSection(lines, "app", [
    `build=${BUILD_VERSION || "unknown"}`,
    `view=${getUnderparCurrentView()}`,
    `url=${String(window.location.href || "").trim() || "n/a"}`,
    `busy=${state.busy ? "yes" : "no"}`,
    `busy_context=${String(state.busyContext || "").trim() || "n/a"}`,
    `session_ready=${state.sessionReady ? "yes" : "no"}`,
    `restricted=${state.restricted ? "yes" : "no"}`,
    `zip_key_gate=${shouldShowZipKeyImportGate() ? "visible" : "hidden"}`,
    `zip_key_status=${String(state.zipKeyImportMessage || DEFAULT_ZIP_KEY_IMPORT_STATUS_MESSAGE).trim() || DEFAULT_ZIP_KEY_IMPORT_STATUS_MESSAGE}`,
    `global_status=${globalStatus || "n/a"}`,
    `update_available=${state.updateAvailable ? "yes" : "no"}`,
    `latest_version=${String(state.latestVersion || "").trim() || "n/a"}`,
    `latest_commit=${String(state.latestCommitSha || "").trim() || "n/a"}`,
    `debug_panel=${state.debugConsoleCollapsed ? "collapsed" : "expanded"}`,
  ]);

  pushDebugSection(lines, "identity", [
    `display_name=${String(getLoginDisplayName(loginData) || "n/a").trim() || "n/a"}`,
    `login_email=${String(getLoginEmail(loginData) || "n/a").trim() || "n/a"}`,
    `principal_id=${String(authContext?.principalId || "n/a").trim() || "n/a"}`,
    `auth_id=${String(authContext?.authId || "n/a").trim() || "n/a"}`,
    `user_id=${String(authContext?.userId || "n/a").trim() || "n/a"}`,
    `org_name=${String(authContext?.orgName || "n/a").trim() || "n/a"}`,
    `org_id=${String(authContext?.orgId || "n/a").trim() || "n/a"}`,
  ]);

  pushDebugSection(lines, "session", [
    `client_id=${String(authContext?.clientId || runtimeConfig?.clientId || "n/a").trim() || "n/a"}`,
    `scope=${String(authContext?.scope || runtimeConfig?.scope || "n/a").trim() || "n/a"}`,
    `session_id=${String(authContext?.sessionId || "n/a").trim() || "n/a"}`,
    `token_id=${String(authContext?.tokenId || "n/a").trim() || "n/a"}`,
    `access_token_fingerprint=${String(authContext?.accessTokenFingerprint || "n/a").trim() || "n/a"}`,
    `expires_at=${Number(authContext?.expiresAt || 0) > 0 ? new Date(Number(authContext.expiresAt)).toISOString() : "n/a"}`,
    `session_monitor_source=${String(state.sessionMonitorLastProbeSource || "n/a").trim() || "n/a"}`,
    `session_monitor_busy=${state.sessionMonitorBusy ? "yes" : "no"}`,
    `session_monitor_suppressed=${state.sessionMonitorSuppressed ? "yes" : "no"}`,
  ]);

  pushDebugSection(lines, "diagnostics", [
    `last_status=${latestStatusEntry ? compactRecentStatusEntries([latestStatusEntry], 1)[0] : "n/a"}`,
    `last_error_status=${latestErrorStatusEntry ? compactRecentStatusEntries([latestErrorStatusEntry], 1)[0] : "n/a"}`,
    `last_non_fetch_activity=${recentNonFetchEntries[0] || "n/a"}`,
    `last_failure_activity=${recentFailureEntries[0] || "n/a"}`,
    `bootstrap=${summarizeUnderparDiagnosticMarker(bootstrapMarker, ["reason", "phase", "path"])}`,
    `auth=${summarizeUnderparDiagnosticMarker(authMarker, ["mode", "phase", "interactiveFallback"])}`,
    `activation=${summarizeUnderparDiagnosticMarker(activationMarker, ["source", "phase", "programmersCount"])}`,
    `console_bootstrap=${summarizeUnderparDiagnosticMarker(consoleBootstrapMarker, ["phase", "configurationVersion", "authoritiesCount"])}`,
    `programmers=${summarizeUnderparDiagnosticMarker(programmersMarker, ["phase", "count", "code", "endpoint"])}`,
    `cm_precheck=${summarizeUnderparDiagnosticMarker(cmPrecheckMarker, ["reason", "phase", "tenantCount"])}`,
  ]);

  pushDebugSection(lines, "selection", [
    `environment_key=${String(state.adobePassEnvironmentKey || environment?.key || "n/a").trim() || "n/a"}`,
    `environment_label=${String(environment?.label || "n/a").trim() || "n/a"}`,
    `console_base=${String(environment?.consoleBase || "n/a").trim() || "n/a"}`,
    `mgmt_base=${String(environment?.mgmtBase || "n/a").trim() || "n/a"}`,
    `sp_base=${String(environment?.spBase || "n/a").trim() || "n/a"}`,
    `media_company=${String(selectedProgrammer?.programmerName || selectedProgrammer?.mediaCompanyName || "n/a").trim() || "n/a"}`,
    `programmer_id=${selectedProgrammerId || "n/a"}`,
    `requestor_id=${String(state.selectedRequestorId || "n/a").trim() || "n/a"}`,
    `mvpd_id=${String(state.selectedMvpdId || "n/a").trim() || "n/a"}`,
    `mvpd_label=${selectedMvpdLabel || "n/a"}`,
    `premium_services=${stringifyUnderparDebugInfoValue({
      restV2: Boolean(selectedServices?.restV2),
      esm: Boolean(selectedServices?.esmWorkspace || selectedServices?.esm),
      degradation: Boolean(selectedServices?.degradation),
      cm: Boolean(selectedServices?.cm),
      cmMvpd: Boolean(selectedServices?.cmMvpd),
      resetTempPass: Boolean(hasResetTempPassAvailable(selectedServices)),
    }) || "n/a"}`,
    `premium_services_summary=${String(firstNonEmptyString([selectedServices?.premiumServicesSummary]) || "n/a").trim() || "n/a"}`,
  ]);

  pushDebugSection(lines, "cm", [
    `catalog_hydrated=${state.cmTenantsCatalogHydrated ? "yes" : "no"}`,
    `catalog_runtime_fresh=${state.cmTenantsCatalogRuntimeFresh ? "yes" : "no"}`,
    `precheck_pending=${state.cmTenantsPrecheckPending ? "yes" : "no"}`,
    `precheck_complete=${state.cmTenantsPrecheckComplete ? "yes" : "no"}`,
    `precheck_error=${String(state.cmTenantsPrecheckLastError || "").trim() || "n/a"}`,
    `bootstrap_qualified=${state.cmConsoleBootstrapQualified ? "yes" : "no"}`,
    `bootstrap_summary=${stringifyUnderparDebugInfoValue(state.cmConsoleBootstrapSummary) || "n/a"}`,
  ]);

  pushDebugSection(lines, "network", [
    `local_activity_count=${getLocalGlobalNetworkActivityCount()}`,
    `remote_activity_count=${getRemoteGlobalNetworkActivityCount()}`,
    `local_activity_context=${String(state.globalNetworkActivityContext || "").trim() || "n/a"}`,
    `remote_activity_context=${String(state.remoteNetworkActivityContext || "").trim() || "n/a"}`,
    `sidepanel_bridge_window_id=${Number(state.sidepanelControllerWindowId || 0) || "n/a"}`,
    `sidepanel_bridge_connected=${state.sidepanelControllerPort ? "yes" : "no"}`,
  ]);

  pushDebugSection(lines, "credential", [
    `zip_key_loaded=${runtimeConfig?.clientId ? "yes" : "no"}`,
    `zip_key_client_id=${String(runtimeConfig?.clientId || "n/a").trim() || "n/a"}`,
    `zip_key_scope=${String(runtimeConfig?.scope || "n/a").trim() || "n/a"}`,
    `zip_key_raw_scope=${String(runtimeConfig?.rawScope || "n/a").trim() || "n/a"}`,
    `zip_key_source=${String(runtimeConfig?.source || "n/a").trim() || "n/a"}`,
    `zip_key_imported_at=${String(runtimeConfig?.importedAt || "n/a").trim() || "n/a"}`,
    `manual_gate=${state.manualZipKeyImportGate ? "yes" : "no"}`,
  ]);

  pushDebugSection(lines, "runtime", [
    `extension_id=${String(chrome?.runtime?.id || "n/a").trim() || "n/a"}`,
    `browser_language=${String(navigator?.language || "n/a").trim() || "n/a"}`,
    `browser_timezone=${String(Intl.DateTimeFormat().resolvedOptions().timeZone || "n/a").trim() || "n/a"}`,
    `workspace_windows=${stringifyUnderparDebugInfoValue(workspaceState) || "n/a"}`,
  ]);

  pushDebugSection(
    lines,
    "recent_status",
    recentStatusEntries.length > 0
      ? recentStatusEntries.map((entry, index) => `event_${String(index + 1).padStart(2, "0")}=${entry}`)
      : ["event_01=Waiting for status."]
  );

  pushDebugSection(
    lines,
    "recent_failures",
    recentFailureEntries.length > 0
      ? recentFailureEntries.map((entry, index) => `event_${String(index + 1).padStart(2, "0")}=${entry}`)
      : ["event_01=Waiting for failures."]
  );

  pushDebugSection(
    lines,
    "recent_activity",
    recentActivityEntries.length > 0
      ? recentActivityEntries.map((entry, index) => `event_${String(index + 1).padStart(2, "0")}=${entry}`)
      : ["event_01=Waiting for activity."]
  );

  return lines.join("\n");
}

function composeUnderparDebugConsoleFallback(error = null) {
  const fallbackLines = ["UnderPAR DEBUG INFO", ""];
  const errorLabel = error instanceof Error ? `${error.name}: ${error.message}` : String(error || "").trim();
  const recentActivityEntries = compactRecentActivityEntries(state.logs || []);

  pushDebugSection(fallbackLines, "summary", [
    `build=${String(chrome?.runtime?.getManifest?.()?.version || "n/a").trim() || "n/a"}`,
    `view=${String(state.sessionReady && state.loginData ? "authenticated" : state.restricted ? "restricted" : "unauthenticated").trim()}`,
    `busy=${state.busy ? String(state.busyContext || "yes").trim() || "yes" : "no"}`,
    `zip_key_configured=${hasConfiguredUnderparImsClientId() ? "yes" : "no"}`,
    `debug_panel=${state.debugConsoleCollapsed ? "collapsed" : "expanded"}`,
    errorLabel ? `render_error=${redactSensitiveTokenValues(errorLabel)}` : "render_error=none",
  ]);

  pushDebugSection(
    fallbackLines,
    "recent_activity",
    recentActivityEntries.length > 0
      ? recentActivityEntries.map((entry, index) => `event_${String(index + 1).padStart(2, "0")}=${entry}`)
      : ["event_01=Waiting for activity."]
  );

  return fallbackLines.join("\n");
}

function getUnderparDebugConsoleSnapshot() {
  try {
    return composeUnderparDebugConsoleOutput();
  } catch (error) {
    console.error("[UnderPAR] Unable to compose DEBUG INFO snapshot", error);
    return composeUnderparDebugConsoleFallback(error);
  }
}

function renderDebugConsole() {
  if (!els.debugConsole || !els.debugToggleButton || !els.logOutput) {
    return;
  }

  els.debugConsole.classList.toggle("is-collapsed", state.debugConsoleCollapsed === true);
  if (els.debugConsoleBody) {
    els.debugConsoleBody.hidden = state.debugConsoleCollapsed === true;
  }
  els.debugToggleButton.setAttribute("aria-expanded", state.debugConsoleCollapsed ? "false" : "true");
  els.debugToggleButton.setAttribute(
    "aria-label",
    state.debugConsoleCollapsed
      ? "DEBUG INFO. Click to copy debug info. Shift-click to expand."
      : "DEBUG INFO. Click to copy debug info. Shift-click to collapse."
  );
  els.debugToggleButton.title = state.debugConsoleCollapsed
    ? "Click to copy debug info. Shift+click to expand."
    : "Click to copy debug info. Shift+click to collapse.";
  if (els.debugToggleButtonLabel) {
    els.debugToggleButtonLabel.textContent = DEFAULT_DEBUG_TOGGLE_LABEL;
  }
  if (els.debugToggleButtonMeta) {
    els.debugToggleButtonMeta.textContent = DEFAULT_DEBUG_TOGGLE_META;
  }
  if (els.debugToggleStatus) {
    els.debugToggleStatus.hidden = !state.debugCopyStatus;
    els.debugToggleStatus.textContent = state.debugCopyStatus || DEFAULT_DEBUG_COPY_STATUS;
  }
  setTextOutput(els.logOutput, getUnderparDebugConsoleSnapshot());
}

function setDebugConsoleCollapsed(collapsed) {
  const nextValue = collapsed === true;
  if (state.debugConsoleCollapsed === nextValue) {
    return;
  }
  state.debugConsoleCollapsed = nextValue;
  renderDebugConsole();
}

function setDebugCopyStatus(message = "") {
  state.debugCopyStatus = String(message || "").trim();
  renderDebugConsole();

  window.clearTimeout(debugCopyResetTimer);
  if (!state.debugCopyStatus) {
    return;
  }

  debugCopyResetTimer = window.setTimeout(() => {
    state.debugCopyStatus = "";
    renderDebugConsole();
  }, COPY_DEBUG_RESET_DELAY_MS);
}

async function copyDebugConsoleToClipboard() {
  const snapshot = String(els.logOutput?.value || getUnderparDebugConsoleSnapshot()).trim();
  if (!snapshot) {
    return;
  }

  const copyResult = await copyTextToClipboard(snapshot);
  if (copyResult?.ok) {
    setDebugCopyStatus(DEFAULT_DEBUG_COPY_STATUS);
    return;
  }

  log("Unable to copy UnderPAR debug console", copyResult?.error || "Unknown clipboard failure.");
  window.alert("UnderPAR could not copy the debug console to the clipboard.");
  setDebugCopyStatus("");
}

const UNDERPAR_BROWSER_CONSOLE_TRACE_ENABLED = true;
const UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_DEPTH = 4;
const UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_ITEMS = 24;
const UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_KEYS = 48;
const UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_STRING = 1200;

function summarizeUnderparConsoleSensitiveString(value, keyName = "") {
  const raw = String(value ?? "");
  if (!raw) {
    return "";
  }
  const normalizedKey = String(keyName || "").trim().toLowerCase();
  const normalizedBearerValue = normalizeBearerTokenValue(raw);
  const looksSensitiveKey =
    normalizedKey.includes("token") ||
    normalizedKey.includes("secret") ||
    normalizedKey.includes("password") ||
    normalizedKey === "authorization" ||
    normalizedKey === "cookie" ||
    normalizedKey === "set-cookie";
  if (DEBUG_REDACT_SENSITIVE && normalizedBearerValue && isProbablyJwt(normalizedBearerValue)) {
    return `<redacted-jwt:${normalizedBearerValue.slice(-12)}>`;
  }
  if (DEBUG_REDACT_SENSITIVE && looksSensitiveKey) {
    const redacted = redactSensitiveTokenValues(raw);
    return truncateDebugText(redacted || "<redacted>", UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_STRING);
  }
  return truncateDebugText(redactSensitiveTokenValues(raw), UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_STRING);
}

function sanitizeUnderparConsoleTraceValue(value, options = {}) {
  const depth = Number(options.depth || 0);
  const keyName = String(options.keyName || "").trim();
  const seen = options.seen instanceof WeakSet ? options.seen : new WeakSet();

  if (value == null) {
    return value;
  }
  if (typeof value === "string") {
    return summarizeUnderparConsoleSensitiveString(value, keyName);
  }
  if (typeof value === "number" || typeof value === "boolean") {
    return value;
  }
  if (typeof value === "bigint") {
    return String(value);
  }
  if (value instanceof Error) {
    return {
      name: String(value.name || "Error"),
      message: summarizeUnderparConsoleSensitiveString(value.message || "", keyName || "message"),
      stack: truncateDebugText(redactSensitiveTokenValues(String(value.stack || "")), UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_STRING),
    };
  }
  if (value instanceof Headers) {
    return sanitizeUnderparConsoleTraceValue(toDebugHeadersObject(value), {
      depth: depth + 1,
      keyName,
      seen,
    });
  }
  if (typeof value !== "object") {
    return summarizeUnderparConsoleSensitiveString(String(value), keyName);
  }
  if (depth >= UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_DEPTH) {
    if (Array.isArray(value)) {
      return `[array:${value.length}]`;
    }
    const constructorName = String(value?.constructor?.name || "object");
    return `[${constructorName}]`;
  }
  if (seen.has(value)) {
    return "[circular]";
  }
  seen.add(value);

  if (Array.isArray(value)) {
    const output = value
      .slice(0, UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_ITEMS)
      .map((entry) =>
        sanitizeUnderparConsoleTraceValue(entry, {
          depth: depth + 1,
          keyName,
          seen,
        })
      );
    if (value.length > UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_ITEMS) {
      output.push(`[+${value.length - UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_ITEMS} more]`);
    }
    return output;
  }

  const output = {};
  const entries = Object.entries(value);
  entries.slice(0, UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_KEYS).forEach(([entryKey, entryValue]) => {
    output[entryKey] = sanitizeUnderparConsoleTraceValue(entryValue, {
      depth: depth + 1,
      keyName: entryKey,
      seen,
    });
  });
  if (entries.length > UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_KEYS) {
    output.__truncatedKeys = entries.length - UNDERPAR_BROWSER_CONSOLE_TRACE_MAX_KEYS;
  }
  return output;
}

function emitUnderparBrowserConsoleTrace(channel = "event", message = "", details = null, options = {}) {
  if (UNDERPAR_BROWSER_CONSOLE_TRACE_ENABLED !== true) {
    return;
  }
  const normalizedChannel = String(channel || "event").trim() || "event";
  const normalizedMessage = String(message || "").trim() || "(no message)";
  const requestedConsoleLevel = String(options.level || "").trim().toLowerCase();
  const consoleMethodName =
    requestedConsoleLevel === "debug"
      ? "debug"
      : requestedConsoleLevel === "info"
        ? "info"
        : "log";
  // Trace warnings/errors are intentionally logged as non-errors so Chrome's extension
  // Errors pane only reflects real uncaught failures instead of expected diagnostic noise.
  const consoleMethod = typeof console?.[consoleMethodName] === "function" ? console[consoleMethodName].bind(console) : console.log.bind(console);
  const label = `[UnderPAR Trace][${normalizedChannel}] ${normalizedMessage}`;
  appendDebugLogEntry(normalizedChannel, normalizedMessage, details, {
    level: requestedConsoleLevel || "info",
  });
  if (details == null) {
    consoleMethod(label);
    return;
  }
  consoleMethod(label, sanitizeUnderparConsoleTraceValue(details));
}

function emitGlobalSelectorChangeLog(menuName, value, label = "") {
  const resolvedMenu = String(menuName || "Unknown").trim() || "Unknown";
  const resolvedValue = String(value || "").trim();
  const resolvedLabel = String(label || "").trim();
  const displayValue = resolvedLabel || resolvedValue || "(none)";
  logDecisionPoint(`Global selector changed | ${resolvedMenu} = ${displayValue}`, {
    menu: resolvedMenu,
    value: resolvedValue,
    label: resolvedLabel,
  });
}

function hasResetTempPassAvailable(services = null) {
  if (!services || typeof services !== "object") {
    return false;
  }
  if (String(services?.resetTempPass?.guid || "").trim()) {
    return true;
  }
  return Array.isArray(services?.resetTempPassApps)
    ? services.resetTempPassApps.some((appInfo) => String(appInfo?.guid || "").trim())
    : false;
}

function programmerMatchesCmTenantCatalog(selectedProgrammer = null, cmCatalog = null) {
  if (!selectedProgrammer || typeof selectedProgrammer !== "object") {
    return false;
  }

  const tenants = Array.isArray(cmCatalog?.tenants)
    ? cmCatalog.tenants
    : Array.isArray(cmCatalog)
      ? cmCatalog
      : [];
  if (tenants.length === 0) {
    return false;
  }

  const programmerIdentifiers = new Set(
    [
      selectedProgrammer.programmerId,
      selectedProgrammer.programmerName,
      selectedProgrammer.mediaCompanyName,
      selectedProgrammer.label,
      selectedProgrammer.key,
      selectedProgrammer.tenantId,
      selectedProgrammer.tenantName,
    ]
      .map((value) => normalizeOrganizationIdentifier(value))
      .filter(Boolean)
  );
  if (programmerIdentifiers.size === 0) {
    return false;
  }

  return tenants.some((tenant) =>
    [
      tenant?.tenantId,
      tenant?.tenantName,
      tenant?.label,
      tenant?.key,
      tenant?.raw?.payload?.name,
      tenant?.raw?.consoleId,
      ...(Array.isArray(tenant?.aliases) ? tenant.aliases : []),
    ]
      .map((value) => normalizeOrganizationIdentifier(value))
      .filter(Boolean)
      .some((identifier) => programmerIdentifiers.has(identifier))
  );
}

function applyPremiumServiceRuntimeSummary(programmer = null, services = null, options = {}) {
  const currentServices = services && typeof services === "object" ? { ...services } : {};
  const cmCatalog = options?.cmCatalog && typeof options.cmCatalog === "object" ? options.cmCatalog : state.cmTenantsCatalog;
  const matchedCatalogTenants =
    programmer && Array.isArray(cmCatalog?.tenants) ? findCmTenantMatchesForProgrammer(programmer, cmCatalog.tenants) : [];
  const syntheticCmService =
    !shouldShowCmService(currentServices?.cm) && matchedCatalogTenants.length > 0
      ? {
          ...(currentServices?.cm && typeof currentServices.cm === "object" ? currentServices.cm : {}),
          serviceType: "cm",
          matchedTenants: matchedCatalogTenants,
          sourceUrl: String(cmCatalog?.sourceUrl || currentServices?.cm?.sourceUrl || "").trim(),
          fetchedAt: Number(currentServices?.cm?.fetchedAt || 0) || Date.now(),
          synthetic: true,
          syntheticSource: "cm-catalog",
        }
      : null;
  const resolvedCmService = shouldShowCmService(currentServices?.cm) ? currentServices.cm : syntheticCmService;
  const items = [];
  const labels = [];

  PREMIUM_SERVICE_SCOPE_RULES.forEach((rule) => {
    const serviceValue =
      rule.key === "esmWorkspace"
        ? currentServices?.esm || null
        : rule.key === "resetTempPass"
          ? currentServices?.resetTempPass || null
          : currentServices?.[rule.key] || null;
    const serviceApps =
      rule.key === "esmWorkspace"
        ? currentServices?.esmApps
        : rule.key === "resetTempPass"
          ? currentServices?.resetTempPassApps
          : currentServices?.[`${rule.key}Apps`];
    const matchingApplication =
      (serviceValue && typeof serviceValue === "object" ? serviceValue : null) ||
      (Array.isArray(serviceApps) ? serviceApps.find((appInfo) => String(appInfo?.guid || "").trim()) : null) ||
      null;
    if (!matchingApplication) {
      return;
    }

    const applicationName = firstNonEmptyString([
      matchingApplication?.appName,
      matchingApplication?.name,
      matchingApplication?.displayName,
      matchingApplication?.guid,
      rule.label,
    ]);
    labels.push(rule.label);
    items.push({
      key: `${rule.key}:${applicationName}`,
      label: rule.label,
      applicationName,
    });
  });

  const hasCmDetection = shouldShowCmService(resolvedCmService) || programmerMatchesCmTenantCatalog(programmer, cmCatalog);
  if (hasCmDetection) {
    labels.push(PREMIUM_SERVICE_CONCURRENCY_LABEL);
    items.push({
      key: `cm:${String(programmer?.programmerId || programmer?.programmerName || "programmer").trim()}`,
      label: PREMIUM_SERVICE_CONCURRENCY_LABEL,
      applicationName: firstNonEmptyString([
        currentServices?.restV2?.appName,
        currentServices?.esm?.appName,
        currentServices?.degradation?.appName,
        programmer?.programmerName,
        programmer?.programmerId,
        PREMIUM_SERVICE_CONCURRENCY_LABEL,
      ]),
    });
  }

  return {
    ...currentServices,
    ...(resolvedCmService ? { cm: resolvedCmService } : {}),
    detectedPremiumServiceLabels: labels,
    detectedPremiumServiceItems: items,
    premiumServicesSummary: labels.length > 0 ? labels.join(" | ") : "No premium services detected",
  };
}

function buildPremiumServiceDecisionLogSignature(programmer, services = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const scopedKey = getEnvironmentScopedProgrammerKey(programmerId);
  if (!scopedKey) {
    return "";
  }

  const selectedRequestorId = String(state.selectedRequestorId || "").trim();
  const selectedMvpdId = String(state.selectedMvpdId || "").trim();
  const selectedMvpdLabel = selectedMvpdId
    ? String(getRestV2MvpdPickerLabel(selectedRequestorId, selectedMvpdId) || selectedMvpdId).trim()
    : "";

  return [
    scopedKey,
    `restV2:${Boolean(services?.restV2)}`,
    `esm:${Boolean(services?.esm)}`,
    `degradation:${Boolean(services?.degradation)}`,
    `resetTempPass:${Boolean(hasResetTempPassAvailable(services))}`,
    `cm:${Boolean(shouldShowCmService(services?.cm))}`,
    `cmMvpd:${Boolean(shouldShowCmService(services?.cmMvpd))}`,
    `mvpd:${selectedMvpdLabel || selectedMvpdId || "none"}`,
  ].join("|");
}

function emitPremiumServiceDecisionLogs(programmer, services = null) {
  if (!programmer) {
    return;
  }

  const programmerId = String(programmer?.programmerId || "").trim();
  const scopedKey = getEnvironmentScopedProgrammerKey(programmerId);
  const nextSignature = buildPremiumServiceDecisionLogSignature(programmer, services);
  if (scopedKey && nextSignature && state.premiumServiceDecisionSignatureByProgrammerKey.get(scopedKey) === nextSignature) {
    return;
  }
  if (scopedKey && nextSignature) {
    state.premiumServiceDecisionSignatureByProgrammerKey.set(scopedKey, nextSignature);
  }

  const mediaCompanyLabel = String(
    firstNonEmptyString([programmer.mediaCompanyName, programmer.programmerName, programmer.programmerId]) || ""
  ).trim();
  if (!mediaCompanyLabel) {
    return;
  }

  const hasRestV2 = Boolean(services?.restV2);
  const hasEsm = Boolean(services?.esm);
  const hasDegradation = Boolean(services?.degradation);
  const hasCm = shouldShowCmService(services?.cm);
  const hasMvpdCm = shouldShowCmService(services?.cmMvpd);
  const hasResetTempPass = hasResetTempPassAvailable(services);

  const selectedRequestorId = String(state.selectedRequestorId || "").trim();
  const selectedMvpdId = String(state.selectedMvpdId || "").trim();
  const selectedMvpdLabel = selectedMvpdId
    ? String(getRestV2MvpdPickerLabel(selectedRequestorId, selectedMvpdId) || selectedMvpdId).trim()
    : "";
  const mvpdDecisionLabel = selectedMvpdLabel || selectedMvpdId || "MVPD not selected";

  logDecisionPoint(`Decision | ${mediaCompanyLabel} has REST V2 = ${hasRestV2 ? "YES" : "NO"}`);
  logDecisionPoint(`Decision | ${mediaCompanyLabel} has ESM = ${hasEsm ? "YES" : "NO"}`);
  logDecisionPoint(`Decision | ${mediaCompanyLabel} has DEGRADATION = ${hasDegradation ? "YES" : "NO"}`);
  logDecisionPoint(`Decision | ${mediaCompanyLabel} has Reset TempPASS = ${hasResetTempPass ? "YES" : "NO"}`);
  logDecisionPoint(`Decision | ${mediaCompanyLabel} has Concurency Monitorring = ${hasCm ? "YES" : "NO"}`);
  logDecisionPoint(`Decision | ${mvpdDecisionLabel} has Concurency Monitorring = ${hasMvpdCm ? "YES" : "NO"}`);
}

function setStatus(message = "", type = "info") {
  const normalizedMessage = String(message || "").trim();
  const normalizedType = String(type || "info").trim().toLowerCase();
  const showAsGlobalStatus = normalizedType === "error" && normalizedMessage.length > 0;

  // Global top-of-sidepanel status is intentionally error-only to avoid redundant noise.
  els.status.textContent = showAsGlobalStatus ? normalizedMessage : "";
  els.status.hidden = !showAsGlobalStatus;
  els.status.classList.remove("error", "success");
  if (showAsGlobalStatus) {
    els.status.classList.add("error");
  }
  if (normalizedMessage) {
    appendDebugStatusHistoryEntry(normalizedMessage, normalizedType, "status");
    appendDebugLogEntry("status", normalizedMessage, { type: normalizedType }, { level: normalizedType });
  }
}

function summarizeUnderparImsClientId(clientId = "") {
  const normalized = String(clientId || "").trim();
  if (!normalized) {
    return "";
  }
  if (normalized.length <= 22) {
    return normalized;
  }
  return `${normalized.slice(0, 12)}...${normalized.slice(-6)}`;
}

function hasConfiguredUnderparImsClientId(vault = state.passVault || null) {
  return Boolean(getActiveUnderparImsRuntimeConfig(vault)?.clientId);
}

function shouldShowZipKeyImportGate(vault = state.passVault || null) {
  return !state.sessionReady && !state.restricted && (state.manualZipKeyImportGate === true || !hasConfiguredUnderparImsClientId(vault));
}

function setZipKeyImportFeedback(message = "", type = "info") {
  state.zipKeyImportMessage = String(message || "").trim();
  const normalizedType = String(type || "info").trim().toLowerCase();
  state.zipKeyImportMessageType =
    normalizedType === "error" || normalizedType === "success" ? normalizedType : "info";
}

function syncZipKeyImportView() {
  if (!els.zipKeyImportView) {
    return;
  }

  const show = shouldShowZipKeyImportGate();
  els.zipKeyImportView.hidden = !show;
  if (!show) {
    return;
  }

  const runtimeConfig = getActiveUnderparImsRuntimeConfig();
  const hasClientId = Boolean(runtimeConfig?.clientId);
  const pending = state.zipKeyImportPending === true;
  const dragActive = state.zipKeyImportDragActive === true;
  const explicitStateMessage = String(state.zipKeyImportMessage || "").trim();
  const stateMessage = pending
    ? PENDING_ZIP_KEY_IMPORT_STATUS_MESSAGE
    : explicitStateMessage || (hasClientId ? READY_ZIP_KEY_IMPORT_STATUS_MESSAGE : "");
  const stateType = pending ? "info" : String(state.zipKeyImportMessageType || "info").trim().toLowerCase();
  const hasStateMessage = Boolean(stateMessage);

  if (els.zipKeyImportCard) {
    els.zipKeyImportCard.classList.toggle("is-ready", hasClientId);
    els.zipKeyImportCard.classList.toggle("is-drag-active", dragActive);
    els.zipKeyImportCard.classList.toggle("is-busy", pending);
  }
  if (els.zipKeyImportTitle) {
    els.zipKeyImportTitle.textContent = pending ? "LOADING KEY" : "LOAD KEY";
  }
  if (els.zipKeyImportDescription) {
    els.zipKeyImportDescription.hidden = true;
    els.zipKeyImportDescription.textContent = "";
  }
  if (els.zipKeyImportClient) {
    els.zipKeyImportClient.hidden = true;
    els.zipKeyImportClient.textContent = "";
  }
  if (els.zipKeyDropzoneLabel) {
    els.zipKeyDropzoneLabel.textContent = pending ? "LOADING KEY" : "LOAD KEY";
  }
  if (els.zipKeyDropzone) {
    els.zipKeyDropzone.setAttribute("aria-label", pending ? "Loading key" : "Drop ZIP.KEY here or choose a file");
    els.zipKeyDropzone.setAttribute("aria-disabled", pending ? "true" : "false");
    els.zipKeyDropzone.tabIndex = pending ? -1 : 0;
  }
  if (els.zipKeyBrowseBtn) {
    els.zipKeyBrowseBtn.disabled = pending;
    els.zipKeyBrowseBtn.textContent = pending ? "LOADING..." : "CHOOSE KEY";
  }
  if (els.zipKeyImportState) {
    els.zipKeyImportState.hidden = !hasStateMessage;
    els.zipKeyImportState.textContent = stateMessage;
    els.zipKeyImportState.classList.remove("error", "success", "info");
    if (hasStateMessage) {
      els.zipKeyImportState.classList.add(
        stateType === "error" || stateType === "success" ? stateType : "info"
      );
    }
  }
  if (els.zipKeyFileInput) {
    els.zipKeyFileInput.disabled = pending;
  }
}

function promptForZipKeyImport() {
  if (state.zipKeyImportPending) {
    return;
  }
  setStatus("", "info");
  if (els.zipKeyFileInput) {
    els.zipKeyFileInput.value = "";
    els.zipKeyFileInput.click();
    return;
  }
  if (els.zipKeyDropzone) {
    els.zipKeyDropzone.focus();
  }
}

function openZipKeyImportGate() {
  if (state.sessionReady || state.restricted) {
    return;
  }
  state.manualZipKeyImportGate = true;
  render();
  if (els.zipKeyDropzone && !els.zipKeyDropzone.hidden) {
    els.zipKeyDropzone.focus();
  }
}

function closeZipKeyImportGate() {
  state.manualZipKeyImportGate = false;
  state.zipKeyImportDragActive = false;
  render();
  window.setTimeout(() => {
    if (els.signInHeroBtn && !els.signInHeroBtn.hidden) {
      els.signInHeroBtn.focus();
      return;
    }
    if (els.authBtn && !els.authBtn.hidden) {
      els.authBtn.focus();
    }
  }, 0);
}

function readUnderparTextFile(file = null) {
  return new Promise((resolve, reject) => {
    if (!(file instanceof File)) {
      reject(new Error("ZIP.KEY file is required."));
      return;
    }
    const reader = new FileReader();
    reader.onerror = () => reject(new Error(`Unable to read ${String(file.name || "ZIP.KEY").trim() || "ZIP.KEY"}.`));
    reader.onload = () => {
      const text = typeof reader.result === "string" ? reader.result : "";
      if (!text.trim()) {
        reject(new Error("ZIP.KEY payload is empty."));
        return;
      }
      resolve(text);
    };
    reader.readAsText(file);
  });
}

function focusPostZipKeyImportAction() {
  window.setTimeout(() => {
    if (els.signInHeroBtn && !els.signInHeroBtn.hidden) {
      els.signInHeroBtn.focus();
      return;
    }
    if (els.authBtn) {
      els.authBtn.focus();
    }
  }, 0);
}

async function finalizeSuccessfulZipKeyImport(result = null) {
  state.zipKeyImportPending = false;
  state.manualZipKeyImportGate = false;
  setStatus("", "info");
  setZipKeyImportFeedback(READY_ZIP_KEY_IMPORT_STATUS_MESSAGE, "success");
  render();
  focusPostZipKeyImportAction();
  return {
    ok: true,
    ...(result && typeof result === "object" ? result : {}),
  };
}

function finalizeFailedZipKeyImport(error = null) {
  state.zipKeyImportPending = false;
  const message = error instanceof Error ? error.message : String(error);
  setZipKeyImportFeedback(message, "error");
  setStatus(message, "error");
  render();
  return {
    ok: false,
    error: message,
  };
}

async function importZipKeyIntoVaultFromText(zipKeyText = "", sourceLabel = "ZIP.KEY") {
  state.zipKeyImportPending = true;
  state.zipKeyImportDragActive = false;
  setZipKeyImportFeedback(PENDING_ZIP_KEY_IMPORT_STATUS_MESSAGE, "info");
  render();

  try {
    const result = await importUnderparImsRuntimeConfigFromZipKeyText(zipKeyText, { silent: true });
    return await finalizeSuccessfulZipKeyImport(result);
  } catch (error) {
    return finalizeFailedZipKeyImport(error);
  }
}

async function importZipKeyIntoVaultFromFile(file = null) {
  const label = String(file?.name || "ZIP.KEY").trim() || "ZIP.KEY";
  state.zipKeyImportPending = true;
  state.zipKeyImportDragActive = false;
  setZipKeyImportFeedback(PENDING_ZIP_KEY_IMPORT_STATUS_MESSAGE, "info");
  render();

  try {
    const text = await readUnderparTextFile(file);
    const result = await importUnderparImsRuntimeConfigFromZipKeyText(text, { silent: true });
    return await finalizeSuccessfulZipKeyImport(result);
  } catch (error) {
    return finalizeFailedZipKeyImport(error);
  }
}

function clearStatusUnlessCmTenantsPrecheckBlocked() {
  if (state.cmTenantsPrecheckComplete !== true && String(state.cmTenantsPrecheckLastError || "").trim()) {
    return;
  }
  setStatus("", "info");
}

function getLocalGlobalNetworkActivityCount() {
  return Math.max(0, Number(state.globalNetworkActivityCount || 0));
}

function getRemoteGlobalNetworkActivityCount() {
  return Math.max(0, Number(state.remoteNetworkActivityCount || 0));
}

function getGlobalNetworkActivityCount() {
  return getLocalGlobalNetworkActivityCount() + getRemoteGlobalNetworkActivityCount();
}

function hasGlobalNetworkActivity() {
  return getGlobalNetworkActivityCount() > 0;
}

function shouldShowBlockingBusyCursor() {
  if (state.busy !== true) {
    return false;
  }
  if (state.restricted === true) {
    return true;
  }
  return Boolean(state.sessionReady || state.loginData);
}

function shouldRunExperienceCloudSessionMonitor() {
  return false;
}

function shouldShowLoggedOutAuthActivity() {
  return state.busy === true && isInteractiveAuthBusyContext(state.busyContext);
}

function syncGlobalNetworkActivityIndicator() {
  const networkActivityCount = getGlobalNetworkActivityCount();
  const shouldShowBusy =
    networkActivityCount > 0 ||
    (shouldRunExperienceCloudSessionMonitor() ? state.busy === true : shouldShowLoggedOutAuthActivity());
  const shouldShowBlockingBusy = shouldShowBlockingBusyCursor();
  if (document?.body) {
    document.body.classList.toggle("net-busy", shouldShowBlockingBusy);
    if (shouldShowBlockingBusy) {
      document.body.setAttribute("aria-busy", "true");
    } else {
      document.body.removeAttribute("aria-busy");
    }
    if (networkActivityCount > 0) {
      document.body.dataset.underparNetworkActivityCount = String(networkActivityCount);
    } else {
      delete document.body.dataset.underparNetworkActivityCount;
    }
  }
  if (els?.authBtn) {
    els.authBtn.classList.toggle("net-busy", shouldShowBusy);
    if (shouldShowBusy) {
      els.authBtn.setAttribute("aria-busy", "true");
    } else {
      els.authBtn.removeAttribute("aria-busy");
    }
  }
}

function beginGlobalNetworkActivity(context = "") {
  state.globalNetworkActivityCount = getLocalGlobalNetworkActivityCount() + 1;
  const normalizedContext = String(context || "").trim();
  if (normalizedContext) {
    state.globalNetworkActivityContext = normalizedContext;
  }
  syncGlobalNetworkActivityIndicator();

  let released = false;
  return () => {
    if (released) {
      return;
    }
    released = true;
    state.globalNetworkActivityCount = Math.max(0, getLocalGlobalNetworkActivityCount() - 1);
    if (state.globalNetworkActivityCount === 0) {
      state.globalNetworkActivityContext = "";
    }
    syncGlobalNetworkActivityIndicator();
  };
}

function resolveGlobalNetworkFetchUrl(input = null) {
  if (typeof input === "string" || input instanceof URL) {
    try {
      return new URL(String(input || ""), window.location.href).toString();
    } catch {
      return String(input || "").trim();
    }
  }

  if (input && typeof input === "object" && typeof input.url === "string") {
    try {
      return new URL(String(input.url || ""), window.location.href).toString();
    } catch {
      return String(input.url || "").trim();
    }
  }

  return "";
}

function resolveGlobalNetworkFetchMethod(input = null, init = null) {
  const initMethod = String(init?.method || "").trim().toUpperCase();
  if (initMethod) {
    return initMethod;
  }
  if (input && typeof input === "object" && typeof input.method === "string") {
    const requestMethod = String(input.method || "").trim().toUpperCase();
    if (requestMethod) {
      return requestMethod;
    }
  }
  return "GET";
}

function shouldTrackGlobalNetworkUrl(rawUrl = "") {
  const normalizedUrl = String(rawUrl || "").trim();
  if (!normalizedUrl) {
    return false;
  }

  try {
    const parsed = new URL(normalizedUrl, window.location.href);
    const protocol = String(parsed.protocol || "").trim().toLowerCase();
    return protocol === "http:" || protocol === "https:";
  } catch {
    return /^https?:\/\//i.test(normalizedUrl);
  }
}

function shouldTrackRuntimeNetworkMessage(payload = {}, options = {}) {
  if (options?.trackNetworkActivity === true) {
    return true;
  }
  if (options?.trackNetworkActivity === false) {
    return false;
  }
  const messageType = String(payload?.type || "").trim();
  return GLOBAL_NETWORK_RELAY_MESSAGE_TYPES.has(messageType);
}

function shouldMirrorRuntimeMessageToConsole(payload = {}) {
  const messageType = String(payload?.type || "").trim();
  if (!messageType) {
    return false;
  }
  if (
    messageType === "underpardebug:traceEvent" ||
    messageType === "minclouddebug:traceEvent" ||
    messageType === UNDERPAR_NETWORK_ACTIVITY_MESSAGE_TYPE
  ) {
    return false;
  }
  return true;
}

function installGlobalNetworkFetchTracker() {
  if (state.globalNetworkFetchTrackerInstalled || typeof globalThis.fetch !== "function") {
    return;
  }

  underparTrackedFetchOriginal = underparTrackedFetchOriginal || globalThis.fetch.bind(globalThis);
  const originalFetch = underparTrackedFetchOriginal;
  globalThis.fetch = async (...args) => {
    const requestUrl = resolveGlobalNetworkFetchUrl(args[0]);
    const method = resolveGlobalNetworkFetchMethod(args[0], args[1]);
    const startedAt = Date.now();
    const release = shouldTrackGlobalNetworkUrl(requestUrl) ? beginGlobalNetworkActivity(requestUrl) : null;
    try {
      emitUnderparBrowserConsoleTrace("fetch", `${method} ${requestUrl}`, {
        phase: "request",
        method,
        url: requestUrl,
      });
      const response = await originalFetch(...args);
      emitUnderparBrowserConsoleTrace("fetch", `${method} ${requestUrl}`, {
        phase: "response",
        method,
        url: requestUrl,
        status: Number(response?.status || 0),
        ok: Boolean(response?.ok),
        redirected: Boolean(response?.redirected),
        durationMs: Date.now() - startedAt,
      });
      return response;
    } catch (error) {
      emitUnderparBrowserConsoleTrace(
        "fetch",
        `${method} ${requestUrl}`,
        {
          phase: "error",
          method,
          url: requestUrl,
          durationMs: Date.now() - startedAt,
          error,
        },
        { level: "error" }
      );
      throw error;
    } finally {
      if (typeof release === "function") {
        release();
      }
    }
  };
  state.globalNetworkFetchTrackerInstalled = true;
}

function setBusy(isBusy, context = "") {
  const nextBusy = isBusy === true;
  const nextContext = nextBusy ? String(context || "").trim() : "";
  if (state.busy !== nextBusy || String(state.busyContext || "") !== nextContext) {
    appendDebugLogEntry("busy", nextBusy ? "Busy state entered" : "Busy state cleared", {
      busy: nextBusy,
      context: nextContext || "n/a",
    });
  }
  state.busy = isBusy;
  state.busyContext = nextContext;
  syncGlobalNetworkActivityIndicator();

  const authMenuReady = Boolean(state.sessionReady && state.loginData && !state.restricted);
  els.authBtn.disabled = authMenuReady ? nextBusy : true;
  if (!authMenuReady) {
    const busyLabel = nextBusy ? "UnderPAR activity" : "UnderPAR activity";
    els.authBtn.title = busyLabel;
    els.authBtn.setAttribute("aria-label", busyLabel);
    renderSignInView();
    return;
  }

  els.authBtn.title = nextBusy ? "Working..." : "Account menu";
  renderSignInView();
}

function truncateDebugText(value, limit = DEBUG_TEXT_PREVIEW_LIMIT) {
  const text = typeof value === "string" ? value : String(value ?? "");
  if (text.length <= limit) {
    return text;
  }
  return `${text.slice(0, limit)}... [truncated ${text.length - limit} chars]`;
}

function redactDebugHeaderValue(headerName, value) {
  if (!DEBUG_REDACT_SENSITIVE) {
    return String(value ?? "");
  }

  const key = String(headerName || "").trim().toLowerCase();
  if (key === "authorization" || key === "cookie" || key === "set-cookie" || key === "x-api-key") {
    return "<redacted>";
  }
  return String(value ?? "");
}

function toDebugHeadersObject(headersLike) {
  if (!headersLike) {
    return {};
  }

  const output = {};
  if (headersLike instanceof Headers) {
    for (const [key, value] of headersLike.entries()) {
      output[key] = redactDebugHeaderValue(key, value);
    }
    return output;
  }

  if (Array.isArray(headersLike)) {
    for (const pair of headersLike) {
      if (!Array.isArray(pair) || pair.length < 2) {
        continue;
      }
      const [key, value] = pair;
      output[String(key)] = redactDebugHeaderValue(key, value);
    }
    return output;
  }

  if (typeof headersLike === "object") {
    for (const [key, value] of Object.entries(headersLike)) {
      output[key] = redactDebugHeaderValue(key, value);
    }
  }

  return output;
}

async function sendRuntimeMessageSafe(payload, options = {}) {
  const release = shouldTrackRuntimeNetworkMessage(payload, options)
    ? beginGlobalNetworkActivity(String(payload?.type || "").trim())
    : null;
  const shouldTrace = shouldMirrorRuntimeMessageToConsole(payload);
  const startedAt = Date.now();
  if (shouldTrace) {
    emitUnderparBrowserConsoleTrace("runtime", `send ${String(payload?.type || "message").trim() || "message"}`, {
      phase: "request",
      payload,
      options: {
        attempts: Math.max(1, Number(options?.attempts || 1)),
        retryDelayMs: Math.max(0, Number(options?.retryDelayMs || 0)),
        timeoutMs: Math.max(0, Number(options?.timeoutMs || 0)),
      },
    });
  }
  try {
    const attempts = Math.max(1, Number(options?.attempts || 1));
    const retryDelayMs = Math.max(0, Number(options?.retryDelayMs || 0));
    const timeoutMs = Math.max(0, Number(options?.timeoutMs || 0));
    for (let attempt = 1; attempt <= attempts; attempt += 1) {
      try {
        if (timeoutMs > 0) {
          const response = await Promise.race([
            chrome.runtime.sendMessage(payload),
            new Promise((_, reject) => {
              window.setTimeout(() => {
                reject(new Error(`Runtime message timed out after ${timeoutMs}ms.`));
              }, timeoutMs);
            }),
          ]);
          if (shouldTrace) {
            emitUnderparBrowserConsoleTrace("runtime", `recv ${String(payload?.type || "message").trim() || "message"}`, {
              phase: "response",
              attempt,
              durationMs: Date.now() - startedAt,
              response,
            });
          }
          return response;
        }
        const response = await chrome.runtime.sendMessage(payload);
        if (shouldTrace) {
          emitUnderparBrowserConsoleTrace("runtime", `recv ${String(payload?.type || "message").trim() || "message"}`, {
            phase: "response",
            attempt,
            durationMs: Date.now() - startedAt,
            response,
          });
        }
        return response;
      } catch (error) {
        if (shouldTrace) {
          emitUnderparBrowserConsoleTrace(
            "runtime",
            `${attempt < attempts ? "retry" : "error"} ${String(payload?.type || "message").trim() || "message"}`,
            {
              phase: attempt < attempts ? "retry" : "error",
              attempt,
              attempts,
              durationMs: Date.now() - startedAt,
              error,
              payload,
            },
            { level: attempt < attempts ? "warn" : "error" }
          );
        }
        if (attempt >= attempts) {
          throw error;
        }
        if (attempt < attempts && retryDelayMs > 0) {
          await sleepMs(retryDelayMs);
        }
      }
    }
    return null;
  } finally {
    if (typeof release === "function") {
      release();
    }
  }
}

function normalizeRelayCredentials(value = "", fallback = "omit") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "include" || normalized === "same-origin" || normalized === "omit") {
    return normalized;
  }
  return fallback;
}

function mapRelayPayloadToFetchLikeResponse(payload = {}, requestUrl = "") {
  const bodyText = typeof payload?.bodyText === "string" ? payload.bodyText : "";
  const headers =
    payload?.headers && typeof payload.headers === "object" ? new Headers(payload.headers) : new Headers();
  return {
    ok: Boolean(payload?.ok),
    status: Number(payload?.status || 0),
    statusText: String(payload?.statusText || ""),
    url: String(payload?.url || requestUrl),
    redirected: Boolean(payload?.redirected),
    headers,
    text: async () => bodyText,
  };
}

async function directRelayFetch(url, options = {}, fallbackCredentials = "omit") {
  const method = String(options?.method || "GET").trim().toUpperCase();
  const credentials = normalizeRelayCredentials(options?.credentials, fallbackCredentials);
  const headers = options?.headers && typeof options.headers === "object" ? { ...options.headers } : {};
  const body = typeof options?.body === "string" ? options.body : "";

  const response = await fetch(url, {
    method,
    credentials,
    cache: "no-store",
    redirect: "follow",
    headers,
    body: method === "POST" ? body : undefined,
  });
  const text = await response.text().catch(() => "");
  return mapRelayPayloadToFetchLikeResponse(
    {
      ok: response.ok,
      status: Number(response.status || 0),
      statusText: String(response.statusText || ""),
      url: String(response.url || url),
      redirected: Boolean(response.redirected),
      headers: Object.fromEntries(response.headers.entries()),
      bodyText: text,
    },
    url
  );
}

async function relayImsFetch(endpoint, options = {}) {
  const url = String(endpoint || "").trim();
  if (!url) {
    throw new Error("IMS relay request missing URL.");
  }

  const message = {
    type: IMS_FETCH_REQUEST_TYPE,
    url,
    method: String(options?.method || "GET").trim().toUpperCase(),
    credentials: String(options?.credentials || "omit").trim().toLowerCase(),
    headers: options?.headers && typeof options.headers === "object" ? { ...options.headers } : {},
    body: typeof options?.body === "string" ? options.body : "",
  };

  let response = await sendRuntimeMessageSafe(message, {
    attempts: 3,
    retryDelayMs: 120,
    timeoutMs: IMS_RELAY_MESSAGE_TIMEOUT_MS,
  });
  if (!response?.ok && response?.error && String(response.error).toLowerCase().includes("unsupported")) {
    response = await sendRuntimeMessageSafe(
      {
        ...message,
        type: LEGACY_IMS_FETCH_REQUEST_TYPE,
      },
      {
        attempts: 2,
        retryDelayMs: 120,
        timeoutMs: IMS_RELAY_MESSAGE_TIMEOUT_MS,
      }
    );
  }
  if (!response || response.ok !== true || !response.response || typeof response.response !== "object") {
    throw new Error(String(response?.error || "IMS relay request failed before network dispatch."));
  }

  return mapRelayPayloadToFetchLikeResponse(response.response, url);
}

function isCmRelayEligibleUrl(value = "") {
  const raw = String(value || "").trim();
  if (!raw || !/^https?:\/\//i.test(raw)) {
    return false;
  }
  try {
    const parsed = new URL(raw);
    const host = String(parsed.hostname || "").toLowerCase();
    return (
      host === "config.adobeprimetime.com" ||
      host === "cm-reports.adobeprimetime.com" ||
      host.endsWith(".adobeprimetime.com")
    );
  } catch {
    return false;
  }
}

async function relayCmFetch(endpoint, options = {}) {
  const url = String(endpoint || "").trim();
  if (!url) {
    throw new Error("CM relay request missing URL.");
  }

  const message = {
    type: CM_FETCH_REQUEST_TYPE,
    url,
    method: String(options?.method || "GET").trim().toUpperCase(),
    credentials: String(options?.credentials || "include").trim().toLowerCase(),
    headers: options?.headers && typeof options.headers === "object" ? { ...options.headers } : {},
    body: typeof options?.body === "string" ? options.body : "",
  };

  let response = await sendRuntimeMessageSafe(message);
  if (!response?.ok && response?.error && String(response.error).toLowerCase().includes("unsupported")) {
    response = await sendRuntimeMessageSafe({
      ...message,
      type: LEGACY_CM_FETCH_REQUEST_TYPE,
    });
  }
  if (!response || response.ok !== true || !response.response || typeof response.response !== "object") {
    if (isCmRelayEligibleUrl(url)) {
      try {
        return await directRelayFetch(url, options, "include");
      } catch {
        // Fall through to standard relay error.
      }
    }
    throw new Error(String(response?.error || "CM relay request failed."));
  }

  return mapRelayPayloadToFetchLikeResponse(response.response, url);
}

async function relaySplunkFetch(endpoint, options = {}) {
  const url = String(endpoint || "").trim();
  if (!url) {
    throw new Error("Splunk relay request missing URL.");
  }

  const message = {
    type: SPLUNK_FETCH_REQUEST_TYPE,
    url,
    method: String(options?.method || "GET").trim().toUpperCase(),
    credentials: String(options?.credentials || "include").trim().toLowerCase(),
    headers: options?.headers && typeof options.headers === "object" ? { ...options.headers } : {},
    body: typeof options?.body === "string" ? options.body : "",
  };

  let response = await sendRuntimeMessageSafe(message);
  if (!response?.ok && response?.error && String(response.error).toLowerCase().includes("unsupported")) {
    response = await sendRuntimeMessageSafe({
      ...message,
      type: LEGACY_SPLUNK_FETCH_REQUEST_TYPE,
    });
  }
  if (!response || response.ok !== true || !response.response || typeof response.response !== "object") {
    throw new Error(String(response?.error || "Splunk relay request failed."));
  }

  const payload = response.response;
  const bodyText = typeof payload?.bodyText === "string" ? payload.bodyText : "";
  const headers =
    payload?.headers && typeof payload.headers === "object" ? new Headers(payload.headers) : new Headers();

  return {
    ok: Boolean(payload?.ok),
    status: Number(payload?.status || 0),
    statusText: String(payload?.statusText || ""),
    url: String(payload?.url || url),
    redirected: Boolean(payload?.redirected),
    headers,
    text: async () => bodyText,
  };
}

async function startRestV2DebugFlow(context = {}, trigger = "test-mvpd-login") {
  const response = await sendRuntimeMessageSafe({
    type: "underpardebug:startFlow",
    trigger,
    context,
  });
  if (response?.ok && typeof response.flowId === "string" && response.flowId) {
    return response.flowId;
  }
  return "";
}

function emitRestV2DebugEvent(flowId, event = {}) {
  if (!flowId) {
    return;
  }

  emitUnderparBrowserConsoleTrace(
    "debug",
    `${String(event?.phase || event?.event || event?.service || "event").trim() || "event"} | flow=${String(flowId || "").trim()}`,
    {
      flowId,
      event,
    }
  );

  void sendRuntimeMessageSafe({
    type: "underpardebug:traceEvent",
    flowId,
    event,
  });
}

function getActivePremiumDebugFlowId() {
  if (state.restV2RecordingActive) {
    const restFlowId = String(state.restV2DebugFlowId || "").trim();
    if (restFlowId) {
      return restFlowId;
    }
  }
  return getActiveEsmWorkspaceDebugFlowId();
}

function resolveRestV2DebugFlowIdForHarvest(harvest = null, explicitFlowId = "") {
  const directFlowId = String(explicitFlowId || "").trim();
  if (directFlowId) {
    return directFlowId;
  }
  if (state.restV2RecordingActive === true) {
    const activeFlowId = String(state.restV2DebugFlowId || "").trim();
    if (activeFlowId) {
      return activeFlowId;
    }
  }
  return String(harvest?.flowId || "").trim();
}

function resolveCmDebugFlowId(explicitFlowId = "") {
  const direct = String(explicitFlowId || "").trim();
  if (direct) {
    return direct;
  }
  const activePremiumFlowId = String(getActivePremiumDebugFlowId() || "").trim();
  if (activePremiumFlowId) {
    return activePremiumFlowId;
  }
  return String(state.cmWorkspaceActivityDebugFlowId || "").trim();
}

function detectCmAuthMode(headersLike) {
  if (!headersLike) {
    return "none";
  }

  let authorizationValue = "";
  if (headersLike instanceof Headers) {
    authorizationValue = String(headersLike.get("Authorization") || headersLike.get("authorization") || "").trim();
  } else if (typeof headersLike === "object") {
    const directValue =
      headersLike.Authorization ||
      headersLike.authorization ||
      headersLike.AUTHORIZATION ||
      headersLike["auth-header"] ||
      "";
    authorizationValue = String(directValue || "").trim();
  }

  if (!authorizationValue) {
    return "none";
  }
  if (/^basic\s+/i.test(authorizationValue)) {
    return "basic";
  }
  if (/^bearer\s+/i.test(authorizationValue)) {
    return "bearer";
  }
  return "custom";
}

function hasHeaderName(headersLike, headerName) {
  const normalizedHeaderName = String(headerName || "").trim().toLowerCase();
  if (!normalizedHeaderName || !headersLike || typeof headersLike !== "object") {
    return false;
  }
  return Object.keys(headersLike).some((key) => String(key || "").trim().toLowerCase() === normalizedHeaderName);
}

function isCmReportsRequestUrl(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return false;
  }
  try {
    const parsed = new URL(raw);
    return String(parsed.hostname || "").trim().toLowerCase() === "cm-reports.adobeprimetime.com";
  } catch {
    return false;
  }
}

function isCmConfigRequestUrl(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return false;
  }
  try {
    const parsed = new URL(raw);
    return String(parsed.hostname || "").trim().toLowerCase() === "config.adobeprimetime.com";
  } catch {
    return false;
  }
}

function withCmReportContextHeaders(headersLike = {}, requestUrl = "") {
  const nextHeaders = headersLike && typeof headersLike === "object" ? { ...headersLike } : {};
  if (!isCmReportsRequestUrl(requestUrl) && !isCmConfigRequestUrl(requestUrl)) {
    return nextHeaders;
  }
  if (!hasHeaderName(nextHeaders, "AP-Request-Id")) {
    nextHeaders["AP-Request-Id"] = generateRequestId();
  }
  if (!hasHeaderName(nextHeaders, "Origin")) {
    nextHeaders.Origin = CM_REPORTS_APP_ORIGIN;
  }
  if (!hasHeaderName(nextHeaders, "Referer")) {
    nextHeaders.Referer = CM_REPORTS_APP_REFERER;
  }
  return nextHeaders;
}

function normalizeWorkspaceDebugKey(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  if (!raw) {
    return "";
  }
  if (raw.includes("mvpd")) {
    return "mvpd-workspace";
  }
  if (raw.includes("cmu") || raw.includes("cm-workspace") || raw === "cm") {
    return "cmu-workspace";
  }
  if (raw.includes("esm")) {
    return "esm-workspace";
  }
  if (raw.includes("degrad")) {
    return "degradation-workspace";
  }
  return raw;
}

function getWorkspaceDebugLabel(workspaceKey = "") {
  const normalized = normalizeWorkspaceDebugKey(workspaceKey);
  if (normalized === "esm-workspace") {
    return "ESM Workspace";
  }
  if (normalized === "cmu-workspace") {
    return "CMU Workspace";
  }
  if (normalized === "mvpd-workspace") {
    return "MVPD Workspace";
  }
  if (normalized === "degradation-workspace") {
    return "DEGRADATION Workspace";
  }
  return "";
}

const CM_PENDING_DEBUG_EVENT_LIMIT = 500;

function queuePendingCmDebugEvent(payload = null) {
  if (!payload || typeof payload !== "object") {
    return;
  }

  const queue = Array.isArray(state.cmWorkspacePendingDebugEvents) ? state.cmWorkspacePendingDebugEvents : [];
  queue.push({
    payload: { ...payload },
    queuedAt: Date.now(),
  });
  if (queue.length > CM_PENDING_DEBUG_EVENT_LIMIT) {
    queue.splice(0, queue.length - CM_PENDING_DEBUG_EVENT_LIMIT);
  }
  state.cmWorkspacePendingDebugEvents = queue;
}

async function flushPendingCmDebugEvents(flowId) {
  const normalizedFlowId = String(flowId || "").trim();
  if (!normalizedFlowId) {
    return;
  }
  if (!Array.isArray(state.cmWorkspacePendingDebugEvents) || state.cmWorkspacePendingDebugEvents.length === 0) {
    return;
  }
  if (state.cmWorkspacePendingDebugFlushPromise) {
    await state.cmWorkspacePendingDebugFlushPromise;
  }

  const flushPromise = (async () => {
    const queue = Array.isArray(state.cmWorkspacePendingDebugEvents) ? state.cmWorkspacePendingDebugEvents.splice(0) : [];
    if (queue.length === 0) {
      return;
    }
    for (const entry of queue) {
      const payload = entry?.payload && typeof entry.payload === "object" ? entry.payload : null;
      if (!payload) {
        continue;
      }
      emitRestV2DebugEvent(normalizedFlowId, payload);
    }
  })().finally(() => {
    state.cmWorkspacePendingDebugFlushPromise = null;
  });

  state.cmWorkspacePendingDebugFlushPromise = flushPromise;
  await flushPromise;
}

function emitCmDebugEvent(event = {}, options = {}) {
  const debugContext = options.context && typeof options.context === "object" ? options.context : {};
  const workspaceKey =
    normalizeWorkspaceDebugKey(
      firstNonEmptyString([event?.workspaceKey, debugContext?.workspaceKey, debugContext?.workspaceOrigin])
    ) || "cmu-workspace";
  const workspaceOrigin = firstNonEmptyString([
    event?.workspaceOrigin,
    debugContext?.workspaceOrigin,
    getWorkspaceDebugLabel(workspaceKey),
  ]);
  const payload = {
    source: "extension",
    service: "cm",
    requestScope: String(
      firstNonEmptyString([
        event?.requestScope,
        debugContext?.requestScope,
        workspaceKey === "cmu-workspace" ? "cmu-workspace" : "cm",
      ]) || "cm"
    ),
    requestorId: String(debugContext.requestorId || state.selectedRequestorId || ""),
    mvpd: String(debugContext.mvpd || state.selectedMvpdId || ""),
    programmerId: String(debugContext.programmerId || resolveSelectedProgrammer()?.programmerId || ""),
    tenantId: String(
      firstNonEmptyString([event?.tenantId, debugContext?.tenantId, debugContext?.tenantScope, event?.tenantScope]) || ""
    ),
    tenantName: String(firstNonEmptyString([event?.tenantName, debugContext?.tenantName]) || ""),
    tenantScope: String(firstNonEmptyString([event?.tenantScope, debugContext?.tenantScope, event?.tenantId]) || ""),
    ...(workspaceKey ? { workspaceKey } : {}),
    ...(workspaceOrigin ? { workspaceOrigin } : {}),
    ...event,
  };
  const preferredWindowId = Number(
    options.preferredWindowId ||
      event?.windowId ||
      event?.controllerWindowId ||
      event?.targetWindowId ||
      state.cmWorkspaceWindowId ||
      0
  );
  const fallbackTabId = Number(
    options.fallbackTabId || event?.tabId || event?.workspaceTabId || event?.controllerTabId || state.cmWorkspaceTabId || 0
  );

  const explicitFlowId = String(options.flowId || "").trim();
  const workspaceFlowId = getActiveCmWorkspaceActivityDebugFlowId();
  const useWorkspaceFlow = !explicitFlowId && workspaceKey === "cmu-workspace";
  const flowId = useWorkspaceFlow ? workspaceFlowId : resolveCmDebugFlowId(explicitFlowId);
  if (flowId) {
    emitRestV2DebugEvent(flowId, payload);
    void flushPendingCmDebugEvents(flowId);
    if (flowId === String(state.cmWorkspaceActivityDebugFlowId || "").trim()) {
      void ensureCmWorkspaceActivityDebugFlow({
        reason: String(event?.phase || "cm-activity"),
        preferredWindowId,
        fallbackTabId,
      }).then((resolvedFlowId) => {
        void flushPendingCmDebugEvents(String(resolvedFlowId || flowId).trim());
      });
    }
    return;
  }

  queuePendingCmDebugEvent(payload);
  void ensureCmWorkspaceActivityDebugFlow({
    reason: String(event?.phase || "cm-activity"),
    preferredWindowId,
    fallbackTabId,
  }).then((resolvedFlowId) => {
    const normalizedFlowId = String(resolvedFlowId || "").trim();
    if (!normalizedFlowId) {
      return;
    }
    void flushPendingCmDebugEvents(normalizedFlowId);
  });
}

function emitPremiumDecisionDebugEvent(event = {}, options = {}) {
  const flowId = resolveCmDebugFlowId(options.flowId || "");
  if (!flowId) {
    return;
  }

  const debugContext = options.context && typeof options.context === "object" ? options.context : {};
  const resolvedProgrammer = options.programmer && typeof options.programmer === "object" ? options.programmer : null;
  emitRestV2DebugEvent(flowId, {
    source: "extension",
    service: "premium-decision",
    requestScope: "premium-decision",
    requestorId: String(debugContext.requestorId || state.selectedRequestorId || ""),
    mvpd: String(debugContext.mvpd || state.selectedMvpdId || ""),
    programmerId: String(debugContext.programmerId || resolvedProgrammer?.programmerId || ""),
    mediaCompany: String(
      debugContext.mediaCompany || resolvedProgrammer?.mediaCompanyName || resolvedProgrammer?.programmerName || ""
    ),
    ...event,
  });
}

function emitMvpdWorkspaceDebugEvent(event = {}, options = {}) {
  const debugContext = options.context && typeof options.context === "object" ? options.context : {};
  const workspaceKey = normalizeWorkspaceDebugKey(
    firstNonEmptyString([event?.workspaceKey, debugContext?.workspaceKey, "mvpd-workspace"])
  );
  const workspaceOrigin = firstNonEmptyString([
    event?.workspaceOrigin,
    debugContext?.workspaceOrigin,
    getWorkspaceDebugLabel(workspaceKey),
  ]);
  const payload = {
    source: "extension",
    service: "mvpd-workspace",
    requestScope: "mvpd-workspace",
    requestorId: String(debugContext.requestorId || state.selectedRequestorId || ""),
    mvpd: String(debugContext.mvpd || debugContext.mvpdId || state.selectedMvpdId || ""),
    programmerId: String(debugContext.programmerId || resolveSelectedProgrammer()?.programmerId || ""),
    workspaceKey,
    workspaceOrigin,
    ...event,
  };

  const preferredWindowId = Number(
    options.preferredWindowId ||
      event?.windowId ||
      event?.controllerWindowId ||
      event?.targetWindowId ||
      state.mvpdWorkspaceWindowId ||
      0
  );
  const fallbackTabId = Number(
    options.fallbackTabId ||
      event?.tabId ||
      event?.workspaceTabId ||
      event?.controllerTabId ||
      state.mvpdWorkspaceTabId ||
      0
  );

  const flowId = resolveCmDebugFlowId(options.flowId || "");
  if (flowId) {
    emitRestV2DebugEvent(flowId, payload);
    return;
  }

  void ensureCmWorkspaceActivityDebugFlow({
    reason: String(event?.phase || "mvpd-workspace"),
    preferredWindowId,
    fallbackTabId,
  }).then((resolvedFlowId) => {
    const normalizedFlowId = String(resolvedFlowId || "").trim();
    if (!normalizedFlowId) {
      return;
    }
    emitRestV2DebugEvent(normalizedFlowId, payload);
  });
}

async function bindRestV2DebugFlowToTab(flowId, tabId, metadata = {}) {
  if (!flowId || !Number.isFinite(Number(tabId)) || Number(tabId) <= 0) {
    return false;
  }

  const response = await sendRuntimeMessageSafe({
    type: "underpardebug:bindFlowTab",
    flowId,
    tabId: Number(tabId),
    metadata,
  });
  return Boolean(response?.ok);
}

async function stopRestV2DebugFlowAndSnapshot(flowId, reason = "manual") {
  const normalizedFlowId = String(flowId || "").trim();
  if (!normalizedFlowId) {
    return { ok: false, flow: null };
  }

  const response = await sendRuntimeMessageSafe({
    type: "underpardebug:stopFlow",
    flowId: normalizedFlowId,
    reason,
  });
  if (!response || typeof response !== "object") {
    return { ok: false, flow: null };
  }
  return {
    ok: response.ok === true,
    flow: response.flow && typeof response.flow === "object" ? response.flow : null,
    error: response.error ? String(response.error) : "",
  };
}

async function getRestV2DebugFlowSnapshot(flowId) {
  const normalizedFlowId = String(flowId || "").trim();
  if (!normalizedFlowId) {
    return null;
  }
  let response = await sendRuntimeMessageSafe({
    type: "underpardebug:getFlow",
    flowId: normalizedFlowId,
  });
  if (!response?.ok) {
    response = await sendRuntimeMessageSafe({
      type: "minclouddebug:getFlow",
      flowId: normalizedFlowId,
    });
  }
  if (!response?.ok || !response?.flow || typeof response.flow !== "object") {
    return null;
  }
  return response.flow;
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function parseJsonText(text, fallback = {}) {
  try {
    return text ? JSON.parse(text) : fallback;
  } catch {
    return fallback;
  }
}

function serializeError(error) {
  if (error instanceof Error) {
    return error.message;
  }

  return String(error || "Unknown error");
}

function parseJsonOrFormText(text, fallback = {}) {
  const raw = String(text || "");
  const parsedJson = parseJsonText(raw, null);
  if (parsedJson && typeof parsedJson === "object") {
    return parsedJson;
  }

  const parsedForm = new URLSearchParams(raw);
  const entries = [...parsedForm.entries()];
  if (entries.length === 0) {
    return fallback;
  }

  const output = {};
  entries.forEach(([key, value]) => {
    const normalizedKey = String(key || "").trim();
    if (!normalizedKey) {
      return;
    }
    output[normalizedKey] = value;
  });
  return Object.keys(output).length > 0 ? output : fallback;
}

function redactSensitiveTokenValues(value) {
  const raw = String(value || "");
  if (!raw) {
    return "";
  }

  return raw
    .replace(BEARER_TOKEN_REDACTION_PATTERN, "Bearer <redacted>")
    .replace(NAMED_TOKEN_VALUE_REDACTION_PATTERN, (_match, tokenName, operator) => `${tokenName}${operator}<redacted>`)
    .replace(JWT_VALUE_REDACTION_PATTERN, "<redacted-jwt>");
}

function normalizeHttpErrorMessage(value) {
  const raw = String(value || "");
  if (!raw) {
    return "";
  }

  const collapsed = raw
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, " ")
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const redacted = redactSensitiveTokenValues(collapsed);
  if (!redacted) {
    return "";
  }

  return redacted.length > 220 ? `${redacted.slice(0, 217)}...` : redacted;
}

function extractApiErrorCode(value) {
  if (!value) {
    return "";
  }

  let payload = value;
  if (typeof payload === "string") {
    payload = parseJsonText(payload, null);
  }

  if (!payload || typeof payload !== "object") {
    return "";
  }

  return String(
    firstNonEmptyString([
      payload?.code,
      payload?.error,
      payload?.errorCode,
      payload?.error_code,
      payload?.error?.code,
      payload?.error?.error,
      payload?.error?.errorCode,
      payload?.error?.error_code,
    ]) || ""
  )
    .trim()
    .toLowerCase();
}

function isServiceProviderTokenMismatchError(value) {
  const code = extractApiErrorCode(value);
  if (code === "invalid_access_token_service_provider") {
    return true;
  }

  if (typeof value === "string") {
    return value.toLowerCase().includes("invalid_access_token_service_provider");
  }

  return false;
}

function sleepMs(durationMs) {
  return new Promise((resolve) => {
    setTimeout(resolve, Math.max(0, Number(durationMs) || 0));
  });
}

function withPromiseTimeout(promise, timeoutMs, message) {
  const normalizedTimeoutMs = Math.max(0, Number(timeoutMs || 0));
  if (!normalizedTimeoutMs) {
    return promise;
  }

  return Promise.race([
    promise,
    new Promise((_, reject) => {
      window.setTimeout(() => {
        reject(new Error(String(message || "Operation timed out.")));
      }, normalizedTimeoutMs);
    }),
  ]);
}

function isInteractiveAuthBusyContext(context = "") {
  const normalized = String(context || "").trim().toLowerCase();
  if (!normalized) {
    return false;
  }

  return (
    normalized.includes("signing in") ||
    normalized.includes("refreshing session") ||
    normalized.includes("switching org")
  );
}

function parseRetryAfterMs(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return 0;
  }

  if (/^\d+$/.test(raw)) {
    return Math.max(0, Number(raw) * 1000);
  }

  const parsedDateMs = Date.parse(raw);
  if (!Number.isFinite(parsedDateMs)) {
    return 0;
  }

  return Math.max(0, parsedDateMs - Date.now());
}

function resolveRateLimitDelayMs(response, attemptIndex) {
  const retryAfterMs = parseRetryAfterMs(response.headers?.get("Retry-After"));
  if (retryAfterMs > 0) {
    return Math.min(retryAfterMs, RATE_LIMIT_MAX_DELAY_MS);
  }

  const safeAttempt = Math.max(0, Number(attemptIndex) || 0);
  const baseDelay = RATE_LIMIT_BASE_DELAY_MS * Math.pow(2, safeAttempt);
  const jitter = Math.floor(Math.random() * RATE_LIMIT_JITTER_MS);
  return Math.min(baseDelay + jitter, RATE_LIMIT_MAX_DELAY_MS);
}

async function fetchWithRateLimitRetry(requestFactory, contextLabel, options = {}) {
  const maxRetries =
    Number.isFinite(options.maxRetries) && Number(options.maxRetries) >= 0
      ? Number(options.maxRetries)
      : RATE_LIMIT_MAX_RETRIES;

  let attempt = 0;
  while (true) {
    const response = await requestFactory();
    if (response.status !== 429 || attempt >= maxRetries) {
      return response;
    }

    const delayMs = resolveRateLimitDelayMs(response, attempt);
    const retryCount = attempt + 1;
    const delaySeconds = Math.max(1, Math.ceil(delayMs / 1000));
    log(`${contextLabel} rate limited (429); retrying in ${delaySeconds}s.`, {
      attempt: retryCount,
      maxRetries,
      delayMs,
    });

    if (typeof options.onRetry === "function") {
      try {
        options.onRetry({ attempt: retryCount, maxRetries, delayMs, response });
      } catch {
        // Ignore UI callback failures.
      }
    }

    await response.text().catch(() => "");
    await sleepMs(delayMs);
    attempt = retryCount;
  }
}

function extractAuthorizationCodeUrl(payload) {
  if (!payload || typeof payload !== "object") {
    return "";
  }

  const candidate = firstNonEmptyString([
    payload.authorization_code_url,
    payload.authorizationCodeUrl,
    payload?.error?.authorization_code_url,
    payload?.error?.authorizationCodeUrl,
  ]);

  if (!candidate) {
    return "";
  }

  try {
    const parsed = new URL(candidate);
    if (parsed.protocol !== "https:") {
      return "";
    }
    return parsed.toString();
  } catch {
    return "";
  }
}

function buildDcrDeviceInfo() {
  const screenInfo =
    typeof window !== "undefined" && window.screen
      ? {
          width: Number(window.screen.width || 0),
          height: Number(window.screen.height || 0),
        }
      : {
          width: 0,
          height: 0,
        };

  return JSON.stringify({
    deviceType: "ChromeExtension",
    deviceName: "UnderPAR",
    deviceOS: "Desktop",
    userAgent: typeof navigator !== "undefined" ? navigator.userAgent : "",
    screen: screenInfo,
  });
}

function base64EncodeUtf8(value) {
  return btoa(unescape(encodeURIComponent(String(value || ""))));
}

function encodeDevicePayload(value) {
  const raw = typeof value === "string" ? value : JSON.stringify(value || {});
  return base64EncodeUtf8(raw);
}

function getStableRestV2DeviceIdentifier() {
  try {
    const environmentKey = getActiveAdobePassEnvironmentKey();
    const scopedStorageKey = getRestV2DeviceIdStorageKey(environmentKey);
    const cached = localStorage.getItem(scopedStorageKey);
    if (cached) {
      return cached;
    }

    if (isProductionAdobePassEnvironmentKey(environmentKey)) {
      const legacyCached =
        localStorage.getItem(REST_V2_DEVICE_ID_STORAGE_KEY) || localStorage.getItem(LEGACY_REST_V2_DEVICE_ID_STORAGE_KEY);
      if (legacyCached) {
        localStorage.setItem(scopedStorageKey, legacyCached);
        return legacyCached;
      }
    }

    const generated =
      typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
        ? crypto.randomUUID()
        : `00000000-0000-4000-8000-${Math.random().toString(16).slice(2, 14).padEnd(12, "0")}`;
    localStorage.setItem(scopedStorageKey, generated);
    return generated;
  } catch {
    return typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
      ? crypto.randomUUID()
      : `00000000-0000-4000-8000-${Math.random().toString(16).slice(2, 14).padEnd(12, "0")}`;
  }
}

function detectOsName() {
  const ua = String(navigator.userAgent || "").toLowerCase();
  if (ua.includes("android")) {
    return "Android";
  }
  if (ua.includes("iphone") || ua.includes("ipad") || ua.includes("ipod")) {
    return "iOS";
  }
  if (ua.includes("cros")) {
    return "Chrome OS";
  }
  if (ua.includes("windows")) {
    return "Windows";
  }
  if (ua.includes("mac os") || ua.includes("macintosh")) {
    return "Mac OS";
  }
  if (ua.includes("linux")) {
    return "Linux";
  }
  return "Linux";
}

function detectBrowserInfo() {
  const ua = String(navigator.userAgent || "");
  const normalized = ua.toLowerCase();
  if (normalized.includes("edg/")) {
    const version = (ua.match(/Edg\/([\d.]+)/) || [])[1] || "";
    return { name: "Edge", vendor: "Microsoft", version };
  }
  if (normalized.includes("chrome/") && !normalized.includes("edg/")) {
    const version = (ua.match(/Chrome\/([\d.]+)/) || [])[1] || "";
    return { name: "Chrome", vendor: "Google", version };
  }
  if (normalized.includes("safari/") && !normalized.includes("chrome/")) {
    const version = (ua.match(/Version\/([\d.]+)/) || [])[1] || "";
    return { name: "Safari", vendor: "Apple", version };
  }
  if (normalized.includes("firefox/")) {
    const version = (ua.match(/Firefox\/([\d.]+)/) || [])[1] || "";
    return { name: "Firefox", vendor: "Mozilla", version };
  }
  return { name: "Chrome", vendor: "Google", version: "" };
}

function buildLegacyDeviceInfoPayload(requestorId) {
  const browser = detectBrowserInfo();
  return {
    primaryHardwareType: "Desktop",
    model: navigator.platform || "Desktop",
    version: "1.0",
    osName: detectOsName(),
    osVersion: navigator.userAgent || "",
    browserName: browser.name,
    browserVendor: browser.vendor,
    browserVersion: browser.version,
    userAgent: navigator.userAgent || "",
    connectionType: navigator.connection?.effectiveType || "WiFi",
    connectionSecure: window.location.protocol === "https:",
    applicationId: requestorId || window.location.hostname || "UnderPAR",
  };
}

function buildDeviceIdentifierPayload() {
  const stableId = getStableRestV2DeviceIdentifier();
  return `fingerprint ${base64EncodeUtf8(stableId)}`;
}

function buildRestV2Headers(requestorId, extraHeaders = {}) {
  return {
    Accept: "application/json",
    "AP-Device-Identifier": buildDeviceIdentifierPayload(),
    "X-Device-Info": encodeDevicePayload(buildLegacyDeviceInfoPayload(requestorId)),
    ...extraHeaders,
  };
}

function getProgrammerByKey(key) {
  if (!key) {
    return null;
  }
  return state.programmers.find((item) => item.key === key) || null;
}

function getProgrammersForSelectedMediaCompany() {
  const programmer = getProgrammerByKey(state.selectedProgrammerKey);
  return programmer ? [programmer] : [];
}

function resolveSelectedProgrammer() {
  const mediaProgrammers = getProgrammersForSelectedMediaCompany();
  if (mediaProgrammers.length === 0) {
    state.selectedProgrammerKey = "";
    return null;
  }
  state.selectedProgrammerKey = mediaProgrammers[0].key;
  return mediaProgrammers[0];
}

function buildMetadataItemHtml(key, value) {
  return `
    <article class="metadata-item">
      <p class="metadata-key">${escapeHtml(key)}</p>
      <p class="metadata-value">${escapeHtml(value)}</p>
    </article>
  `;
}

function getPremiumCollapseKey(programmerId, serviceKey) {
  const normalizedEnvironmentKey =
    String(getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const normalizedProgrammerId = String(programmerId || "").trim();
  const scopedProgrammerKey =
    normalizedProgrammerId === "__global__"
      ? "__global__"
      : getEnvironmentScopedProgrammerKey(normalizedProgrammerId, normalizedEnvironmentKey) || normalizedProgrammerId;
  return `${normalizedEnvironmentKey}:${scopedProgrammerKey}:${String(serviceKey || "").trim()}`;
}

function getPremiumSectionCollapsed(programmerId, serviceKey) {
  const key = getPremiumCollapseKey(programmerId, serviceKey);
  if (state.premiumSectionCollapsedByKey.has(key)) {
    return Boolean(state.premiumSectionCollapsedByKey.get(key));
  }
  const globalKey = getPremiumCollapseKey("__global__", serviceKey);
  if (state.premiumSectionCollapsedByKey.has(globalKey)) {
    return Boolean(state.premiumSectionCollapsedByKey.get(globalKey));
  }
  return true;
}

function setPremiumSectionCollapsed(programmerId, serviceKey, isCollapsed) {
  const collapsed = Boolean(isCollapsed);
  state.premiumSectionCollapsedByKey.set(getPremiumCollapseKey(programmerId, serviceKey), collapsed);
  state.premiumSectionCollapsedByKey.set(getPremiumCollapseKey("__global__", serviceKey), collapsed);
}

function getHrContextSectionCollapseKey(sectionKey = "") {
  return `hr-context:${String(sectionKey || "").trim()}`;
}

function getHrContextSectionCollapsed(programmerId, sectionKey) {
  return getPremiumSectionCollapsed(programmerId, getHrContextSectionCollapseKey(sectionKey));
}

function setHrContextSectionCollapsed(programmerId, sectionKey, isCollapsed) {
  setPremiumSectionCollapsed(programmerId, getHrContextSectionCollapseKey(sectionKey), isCollapsed);
}

function getRestV2InteractiveDocsSectionCollapseKey(sectionKey = "") {
  return `rest-v2-learning:${String(sectionKey || "").trim()}`;
}

function getRestV2InteractiveDocsSectionCollapsed(programmerId, sectionKey) {
  const scopedKey = getRestV2InteractiveDocsSectionCollapseKey(sectionKey);
  const programmerScopedKey = getPremiumCollapseKey(programmerId, scopedKey);
  if (state.premiumSectionCollapsedByKey.has(programmerScopedKey)) {
    return Boolean(state.premiumSectionCollapsedByKey.get(programmerScopedKey));
  }
  const globalScopedKey = getPremiumCollapseKey("__global__", scopedKey);
  if (state.premiumSectionCollapsedByKey.has(globalScopedKey)) {
    return Boolean(state.premiumSectionCollapsedByKey.get(globalScopedKey));
  }
  return false;
}

function setRestV2InteractiveDocsSectionCollapsed(programmerId, sectionKey, isCollapsed) {
  setPremiumSectionCollapsed(programmerId, getRestV2InteractiveDocsSectionCollapseKey(sectionKey), isCollapsed);
}

function applyCollapsibleState(toggleButton, containerElement, isCollapsed) {
  if (!toggleButton || !containerElement) {
    return;
  }

  const collapsed = Boolean(isCollapsed);
  toggleButton.classList.toggle("collapsed", collapsed);
  toggleButton.setAttribute("aria-expanded", collapsed ? "false" : "true");
  containerElement.classList.toggle("collapsed", collapsed);
  containerElement.hidden = collapsed;
  containerElement.setAttribute("aria-hidden", collapsed ? "true" : "false");
}

function getCollapsibleSectionState(toggleButton, containerElement) {
  if (!toggleButton || !containerElement) {
    return true;
  }
  return (
    containerElement.hidden === true ||
    containerElement.classList.contains("collapsed") ||
    toggleButton.getAttribute("aria-expanded") === "false"
  );
}

function toggleCollapsibleSection(toggleButton, nextCollapsed = null) {
  const containerElement = toggleButton?.__underparCollapseTarget || null;
  if (!toggleButton || !containerElement) {
    return false;
  }

  const resolvedCollapsed =
    nextCollapsed == null
      ? !getCollapsibleSectionState(toggleButton, containerElement)
      : Boolean(nextCollapsed);
  applyCollapsibleState(toggleButton, containerElement, resolvedCollapsed);
  if (typeof toggleButton.__underparCollapseCallback === "function") {
    toggleButton.__underparCollapseCallback(Boolean(resolvedCollapsed));
  }
  return true;
}

function resolveCollapsibleToggleFromEvent(event) {
  const target = event?.target;
  const sourceElement =
    target instanceof Element
      ? target
      : target?.parentElement instanceof Element
        ? target.parentElement
        : null;
  const toggleButton = sourceElement?.closest?.(".service-box-header, .cm-group-toggle") || null;
  return toggleButton instanceof HTMLElement ? toggleButton : null;
}

function handleCollapsibleToggleEvent(event, toggleButton = null) {
  const resolvedToggleButton =
    toggleButton instanceof HTMLElement ? toggleButton : resolveCollapsibleToggleFromEvent(event);
  if (!resolvedToggleButton) {
    return false;
  }
  if (!toggleCollapsibleSection(resolvedToggleButton)) {
    return false;
  }
  if (typeof event?.preventDefault === "function") {
    event.preventDefault();
  }
  if (typeof event?.stopPropagation === "function") {
    event.stopPropagation();
  }
  return true;
}

function wireCollapsibleSection(toggleButton, containerElement, initialCollapsed, onCollapsedChange = null) {
  if (!toggleButton || !containerElement) {
    return;
  }

  toggleButton.__underparCollapseTarget = containerElement;
  toggleButton.__underparCollapseCallback = onCollapsedChange;
  if (toggleButton.__underparCollapseDirectHandlersBound !== true) {
    toggleButton.addEventListener("click", (event) => {
      handleCollapsibleToggleEvent(event, toggleButton);
    });
    toggleButton.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") {
        return;
      }
      handleCollapsibleToggleEvent(event, toggleButton);
    });
    toggleButton.__underparCollapseDirectHandlersBound = true;
  }
  applyCollapsibleState(toggleButton, containerElement, initialCollapsed);
}

function setRestV2LoginPanelStatus(section, message, type = "") {
  const statusElement = section?.querySelector(".rest-v2-login-status");
  if (!statusElement) {
    return;
  }

  const text = String(message || "").trim();
  statusElement.classList.remove("success", "error");
  if (type === "success" || type === "error") {
    statusElement.classList.add(type);
  }
  statusElement.hidden = text.length === 0;
  statusElement.textContent = text;
}

function stringifyJsonForDisplay(value) {
  if (value == null || value === "") {
    return "{}";
  }
  if (typeof value === "string") {
    const parsed = parseJsonText(value, null);
    if (parsed && typeof parsed === "object") {
      try {
        return JSON.stringify(parsed, null, 2);
      } catch {
        return String(value);
      }
    }
    return String(value);
  }
  try {
    return JSON.stringify(value, null, 2);
  } catch {
    return String(value);
  }
}

function formatTimestampLabel(value) {
  const raw = Number(value || 0);
  if (!Number.isFinite(raw) || raw <= 0) {
    return "Unknown";
  }
  return new Date(raw).toLocaleString();
}

function getRestV2HarvestRecordKey(harvest = null, index = 0) {
  if (!harvest || typeof harvest !== "object") {
    return `harvest-${index + 1}`;
  }
  return (
    buildRestV2ProfileHarvestBucketKey(harvest) ||
    [String(harvest.programmerId || ""), String(harvest.flowId || ""), String(harvest.harvestedAt || "")].join("|") ||
    `harvest-${index + 1}`
  );
}

function getRestV2PreauthorizeHistoryForProgrammer(programmer = null) {
  const programmerId =
    programmer && typeof programmer === "object" ? String(programmer.programmerId || "").trim() : String(programmer || "").trim();
  if (!programmerId) {
    return [];
  }
  const history = state.restV2PreauthorizeHistoryByProgrammerId.get(programmerId);
  if (!Array.isArray(history) || history.length === 0) {
    return [];
  }
  return history
    .filter((item) => item && typeof item === "object")
    .slice()
    .sort((left, right) => Number(right?.checkedAt || 0) - Number(left?.checkedAt || 0));
}

function storeRestV2PreauthorizeHistoryEntry(programmerId, entry = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId || !entry || typeof entry !== "object") {
    return [];
  }
  const existing = getRestV2PreauthorizeHistoryForProgrammer(normalizedProgrammerId);
  const next = [entry, ...existing]
    .filter((item) => item && typeof item === "object")
    .sort((left, right) => Number(right?.checkedAt || 0) - Number(left?.checkedAt || 0))
    .slice(0, REST_V2_PREAUTHORIZE_HISTORY_MAX);
  state.restV2PreauthorizeHistoryByProgrammerId.set(normalizedProgrammerId, next);
  return next;
}

function normalizeRestV2PreauthzCheckDecisionRow(row = null) {
  if (!row || typeof row !== "object") {
    return null;
  }
  const resourceId = String(row?.resourceId || "").trim();
  if (!resourceId) {
    return null;
  }
  const decisionRaw = String(
    firstNonEmptyString([
      row?.decision,
      typeof row?.authorized === "boolean" ? normalizeRestV2DecisionVerdict(row.authorized) : "",
    ]) || "Unknown"
  ).trim();
  const decision =
    decisionRaw.toLowerCase() === "permit"
      ? "Permit"
      : decisionRaw.toLowerCase() === "deny"
        ? "Deny"
        : decisionRaw.toLowerCase() === "unknown"
          ? "Unknown"
          : decisionRaw || "Unknown";
  return {
    resourceId,
    decision,
    authorized: typeof row?.authorized === "boolean" ? row.authorized : null,
    source: String(row?.source || "").trim(),
    serviceProvider: String(row?.serviceProvider || "").trim(),
    mvpd: String(row?.mvpd || "").trim(),
    errorCode: String(row?.errorCode || "").trim(),
    errorDetails: String(row?.errorDetails || "").trim(),
    mediaTokenPresent: row?.mediaTokenPresent === true,
    mediaTokenPreview: String(row?.mediaTokenPreview || "").trim(),
    mediaTokenNotBeforeMs: Number(row?.mediaTokenNotBeforeMs || 0),
    mediaTokenNotAfterMs: Number(row?.mediaTokenNotAfterMs || 0),
    notBeforeMs: Number(row?.notBeforeMs || 0),
    notAfterMs: Number(row?.notAfterMs || 0),
    raw: row?.raw && typeof row.raw === "object" ? cloneJsonLikeValue(row.raw, {}) : {},
  };
}

function buildRestV2PreauthzCheckKey(entry = null) {
  if (!entry || typeof entry !== "object") {
    return "";
  }
  const checkedAt = Number(entry?.checkedAt || 0);
  const resourcePart = (Array.isArray(entry?.resourceIds) ? entry.resourceIds : [])
    .map((item) => String(item || "").trim().toLowerCase())
    .filter(Boolean)
    .join("|");
  const decisionPart = (Array.isArray(entry?.decisionRows) ? entry.decisionRows : [])
    .map((row) => {
      const resourceId = String(row?.resourceId || "").trim().toLowerCase();
      const decision = String(row?.decision || "").trim().toLowerCase();
      const errorCode = String(row?.errorCode || "").trim().toLowerCase();
      return [resourceId, decision, errorCode].join(":");
    })
    .filter(Boolean)
    .join("|");
  const status = Number(entry?.status || 0);
  const error = String(entry?.error || "").trim().toLowerCase();
  return [String(checkedAt), resourcePart, decisionPart, String(status), error].join("|");
}

function normalizeRestV2PreauthzCheckEntry(entry = null) {
  if (!entry || typeof entry !== "object") {
    return null;
  }

  const checkedAtRaw = Number(entry?.checkedAt || 0);
  const checkedAt = Number.isFinite(checkedAtRaw) && checkedAtRaw > 0 ? checkedAtRaw : Date.now();
  const resourceIds = (Array.isArray(entry?.resourceIds) ? entry.resourceIds : [])
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  const decisionRows = (Array.isArray(entry?.decisionRows) ? entry.decisionRows : [])
    .map((row) => normalizeRestV2PreauthzCheckDecisionRow(row))
    .filter(Boolean);
  const fallbackSummary = summarizeRestV2PreauthorizeRows(decisionRows, resourceIds);
  const permitCountRaw = Number(entry?.permitCount);
  const denyCountRaw = Number(entry?.denyCount);
  const unknownCountRaw = Number(entry?.unknownCount);
  const permitCount = Number.isFinite(permitCountRaw) ? permitCountRaw : fallbackSummary.permitCount;
  const denyCount = Number.isFinite(denyCountRaw) ? denyCountRaw : fallbackSummary.denyCount;
  const unknownCount = Number.isFinite(unknownCountRaw) ? unknownCountRaw : fallbackSummary.unknownCount;
  const allRequestedPermitted =
    typeof entry?.allRequestedPermitted === "boolean"
      ? entry.allRequestedPermitted
      : summarizeRestV2PreauthorizeRows(decisionRows, resourceIds).allRequestedPermitted;
  const normalized = {
    checkedAt,
    checkedAtLabel: formatTimestampLabel(checkedAt),
    ok: entry?.ok === true,
    status: Number(entry?.status || 0),
    statusText: String(entry?.statusText || "").trim(),
    programmerId: String(entry?.programmerId || "").trim(),
    appGuid: String(entry?.appGuid || "").trim(),
    appName: String(entry?.appName || "").trim(),
    authMode: String(entry?.authMode || "").trim(),
    endpointUrl: String(entry?.endpointUrl || "").trim(),
    requestBody: entry?.requestBody && typeof entry.requestBody === "object" ? cloneJsonLikeValue(entry.requestBody, {}) : {},
    serviceProviderId: String(entry?.serviceProviderId || "").trim(),
    requestorId: String(entry?.requestorId || "").trim(),
    mvpd: String(entry?.mvpd || "").trim(),
    harvestKey: String(entry?.harvestKey || "").trim(),
    harvestCapturedAt: Number(entry?.harvestCapturedAt || 0),
    subject: String(entry?.subject || "").trim(),
    upstreamUserId: String(entry?.upstreamUserId || "").trim(),
    userId: String(entry?.userId || "").trim(),
    sessionId: String(entry?.sessionId || "").trim(),
    profileKey: String(entry?.profileKey || "").trim(),
    resourceIds,
    decisionRows,
    permitCount,
    denyCount,
    unknownCount,
    allRequestedPermitted,
    responsePreview: String(entry?.responsePreview || "").trim(),
    responsePayload:
      entry?.responsePayload && typeof entry.responsePayload === "object"
        ? cloneJsonLikeValue(entry.responsePayload, {})
        : entry?.responsePayload == null
          ? {}
          : String(entry.responsePayload),
    error: String(entry?.error || "").trim(),
  };
  normalized.checkKey = String(entry?.checkKey || "").trim() || buildRestV2PreauthzCheckKey(normalized);
  return normalized.checkKey ? normalized : null;
}

function normalizeRestV2ProfilePreauthzChecks(checks = []) {
  const byCheckKey = new Map();
  (Array.isArray(checks) ? checks : []).forEach((item) => {
    const normalized = normalizeRestV2PreauthzCheckEntry(item);
    if (!normalized) {
      return;
    }
    const existing = byCheckKey.get(normalized.checkKey) || null;
    if (!existing || Number(normalized.checkedAt || 0) >= Number(existing.checkedAt || 0)) {
      byCheckKey.set(normalized.checkKey, normalized);
    }
  });
  return [...byCheckKey.values()]
    .sort((left, right) => Number(right?.checkedAt || 0) - Number(left?.checkedAt || 0))
    .slice(0, REST_V2_PROFILE_PREAUTHZ_CHECK_MAX);
}

function getRestV2ProfilePreauthzChecks(harvest = null) {
  if (!harvest || typeof harvest !== "object") {
    return [];
  }
  return normalizeRestV2ProfilePreauthzChecks(harvest.preauthzChecks);
}

function mergeRestV2HarvestWithPreauthzChecks(harvest = null, ...sources) {
  if (!harvest || typeof harvest !== "object") {
    return harvest;
  }
  const sourceList = [harvest];
  sources.forEach((source) => {
    if (source && typeof source === "object") {
      sourceList.push(source);
    }
  });
  const mergedChecks = normalizeRestV2ProfilePreauthzChecks(
    sourceList.flatMap((source) => getRestV2ProfilePreauthzChecks(source))
  );
  return {
    ...harvest,
    preauthzChecks: mergedChecks,
  };
}

function buildRestV2ProfilePreauthzCheckEntry(result = null) {
  if (!result || typeof result !== "object") {
    return null;
  }
  return normalizeRestV2PreauthzCheckEntry(result);
}

function storeRestV2ProfilePreauthzCheckEntry(programmerId, harvestKey, result = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedHarvestKey = String(harvestKey || "").trim();
  const checkEntry = buildRestV2ProfilePreauthzCheckEntry(result);
  if (!normalizedProgrammerId || !normalizedHarvestKey || !checkEntry) {
    return null;
  }

  const matchesByIdentity = (harvest = null) => {
    if (!harvest || typeof harvest !== "object") {
      return false;
    }
    const sameRequestor =
      String(harvest?.requestorId || "").trim().toLowerCase() === String(checkEntry?.requestorId || "").trim().toLowerCase();
    const sameMvpd = String(harvest?.mvpd || "").trim().toLowerCase() === String(checkEntry?.mvpd || "").trim().toLowerCase();
    if (!sameRequestor || !sameMvpd) {
      return false;
    }
    const harvestIdentity = firstNonEmptyString([
      String(harvest?.sessionId || "").trim(),
      String(harvest?.profileKey || "").trim(),
      String(harvest?.subject || "").trim(),
      String(harvest?.upstreamUserId || "").trim(),
      String(harvest?.userId || "").trim(),
    ]).toLowerCase();
    const checkIdentity = firstNonEmptyString([
      String(checkEntry?.sessionId || "").trim(),
      String(checkEntry?.profileKey || "").trim(),
      String(checkEntry?.subject || "").trim(),
      String(checkEntry?.upstreamUserId || "").trim(),
      String(checkEntry?.userId || "").trim(),
    ]).toLowerCase();
    return Boolean(harvestIdentity && checkIdentity && harvestIdentity === checkIdentity);
  };

  let updatedHarvest = null;
  const existingBucket = Array.isArray(state.restV2ProfileHarvestBucketByProgrammerId.get(normalizedProgrammerId))
    ? state.restV2ProfileHarvestBucketByProgrammerId.get(normalizedProgrammerId)
    : [];
  if (existingBucket.length > 0) {
    const nextBucket = existingBucket.map((item, index) => {
      if (!item || typeof item !== "object") {
        return item;
      }
      const itemKey = getRestV2HarvestRecordKey(item, index);
      if (itemKey !== normalizedHarvestKey && !matchesByIdentity(item)) {
        return item;
      }
      const mergedHarvest = mergeRestV2HarvestWithPreauthzChecks(
        {
          ...item,
          preauthzChecks: [checkEntry, ...getRestV2ProfilePreauthzChecks(item)],
        },
        item
      );
      updatedHarvest = mergedHarvest;
      return mergedHarvest;
    });
    if (updatedHarvest) {
      nextBucket.sort(compareRestV2HarvestRecency);
      const limitedBucket = nextBucket.slice(0, REST_V2_PROFILE_HARVEST_BUCKET_MAX);
      state.restV2ProfileHarvestBucketByProgrammerId.set(normalizedProgrammerId, limitedBucket);
      state.restV2ProfileHarvestByProgrammerId.set(normalizedProgrammerId, limitedBucket[0] || updatedHarvest);
    }
  }

  for (const [selectionKey, harvest] of state.restV2ProfileHarvestBySelectionKey.entries()) {
    if (!harvest || typeof harvest !== "object") {
      continue;
    }
    if (getRestV2HarvestRecordKey(harvest) !== normalizedHarvestKey && !matchesByIdentity(harvest)) {
      continue;
    }
    const mergedSelectionHarvest =
      updatedHarvest && String(harvest?.programmerId || "").trim() === normalizedProgrammerId
        ? updatedHarvest
        : mergeRestV2HarvestWithPreauthzChecks(
            {
              ...harvest,
              preauthzChecks: [checkEntry, ...getRestV2ProfilePreauthzChecks(harvest)],
            },
            updatedHarvest
          );
    state.restV2ProfileHarvestBySelectionKey.set(selectionKey, mergedSelectionHarvest);
    if (!updatedHarvest && String(mergedSelectionHarvest?.programmerId || "").trim() === normalizedProgrammerId) {
      updatedHarvest = mergedSelectionHarvest;
    }
  }

  const latestHarvest = state.restV2ProfileHarvestLast;
  if (
    latestHarvest &&
    typeof latestHarvest === "object" &&
    (getRestV2HarvestRecordKey(latestHarvest) === normalizedHarvestKey || matchesByIdentity(latestHarvest))
  ) {
    if (updatedHarvest) {
      state.restV2ProfileHarvestLast = updatedHarvest;
    } else {
      const mergedLast = mergeRestV2HarvestWithPreauthzChecks(
        {
          ...latestHarvest,
          preauthzChecks: [checkEntry, ...getRestV2ProfilePreauthzChecks(latestHarvest)],
        },
        latestHarvest
      );
      state.restV2ProfileHarvestLast = mergedLast;
      updatedHarvest = mergedLast;
    }
  }

  if (updatedHarvest) {
    const refreshedBucket = getRestV2ProfileHarvestBucketForProgrammer(normalizedProgrammerId);
    state.restV2ProfileHarvestByProgrammerId.set(normalizedProgrammerId, refreshedBucket[0] || updatedHarvest);
  }

  recomputeRestV2ProfileHarvestLast();
  return updatedHarvest;
}

function stringifyJsonForCsvCell(value, fallback = "") {
  if (value == null || value === "") {
    return fallback;
  }
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function buildRestV2ProfileHarvestExportRows(harvestList = []) {
  const normalizedHarvestList = (Array.isArray(harvestList) ? harvestList : [])
    .filter((item) => item && typeof item === "object")
    .slice()
    .sort(compareRestV2HarvestRecency);
  const rows = [];

  normalizedHarvestList.forEach((harvest, profileIndex) => {
    const checks = getRestV2ProfilePreauthzChecks(harvest);
    const profileBase = {
      "Profile Index": profileIndex + 1,
      "Programmer ID": String(harvest?.programmerId || "").trim(),
      "Requestor ID": String(harvest?.requestorId || "").trim(),
      "Service Provider ID": String(harvest?.serviceProviderId || "").trim(),
      MVPD: String(harvest?.mvpd || "").trim(),
      Subject: String(harvest?.subject || "").trim(),
      "Upstream User ID": String(harvest?.upstreamUserId || "").trim(),
      "User ID": String(harvest?.userId || "").trim(),
      "Session ID": String(harvest?.sessionId || "").trim(),
      "Profile Key": String(harvest?.profileKey || "").trim(),
      "Profile Captured At": formatTimestampLabel(harvest?.harvestedAt),
      "Profile Count": Number(harvest?.profileCount || 0),
      "Profile Check Outcome": String(harvest?.profileCheckOutcome || "").trim(),
      "Profile Check HTTP Status": Number(harvest?.profileCheck?.status || 0),
      "Profile Check HTTP Status Text": String(harvest?.profileCheck?.statusText || "").trim(),
      "Profile Not Before": formatTimestampLabel(harvest?.notBeforeMs),
      "Profile Not After": formatTimestampLabel(harvest?.notAfterMs),
      "Profile Attributes JSON": stringifyJsonForCsvCell(harvest?.profileAttributes, "{}"),
      "Profile Candidate Subjects": (Array.isArray(harvest?.subjectCandidates) ? harvest.subjectCandidates : []).join(" | "),
      "Profile Candidate Sessions": (Array.isArray(harvest?.sessionCandidates) ? harvest.sessionCandidates : []).join(" | "),
      "Profile Candidate IDPs": (Array.isArray(harvest?.idpCandidates) ? harvest.idpCandidates : []).join(" | "),
    };

    if (checks.length === 0) {
      rows.push({
        ...profileBase,
        "Preauthz Check Index": "",
        "Preauthz Checked At": "",
        "Preauthz Verdict": "",
        "Preauthz HTTP Status": "",
        "Preauthz HTTP Status Text": "",
        "Preauthz Error": "",
        "Preauthz Requested Resource IDs": "",
        "Preauthz Permit Count": "",
        "Preauthz Deny Count": "",
        "Preauthz Unknown Count": "",
        "Preauthz Auth Mode": "",
        "Preauthz Application": "",
        "Preauthz Endpoint URL": "",
        "Preauthz Response JSON": "",
        "Decision Index": "",
        "Decision Resource ID": "",
        "Decision Verdict": "",
        "Decision Authorized": "",
        "Decision Source": "",
        "Decision Service Provider": "",
        "Decision MVPD": "",
        "Decision Error Code": "",
        "Decision Error Details": "",
        "Decision Media Token Present": "",
        "Decision Media Token Preview": "",
        "Decision Token Not Before": "",
        "Decision Token Not After": "",
        "Decision Not Before": "",
        "Decision Not After": "",
        "Decision Raw JSON": "",
      });
      return;
    }

    checks.forEach((check, checkIndex) => {
      const checkBase = {
        ...profileBase,
        "Preauthz Check Index": checkIndex + 1,
        "Preauthz Checked At": formatTimestampLabel(check?.checkedAt),
        "Preauthz Verdict": check?.allRequestedPermitted ? "YES" : "NO",
        "Preauthz HTTP Status": Number(check?.status || 0),
        "Preauthz HTTP Status Text": String(check?.statusText || "").trim(),
        "Preauthz Error": String(check?.error || "").trim(),
        "Preauthz Requested Resource IDs": (Array.isArray(check?.resourceIds) ? check.resourceIds : []).join(", "),
        "Preauthz Permit Count": Number(check?.permitCount || 0),
        "Preauthz Deny Count": Number(check?.denyCount || 0),
        "Preauthz Unknown Count": Number(check?.unknownCount || 0),
        "Preauthz Auth Mode": String(check?.authMode || "").trim(),
        "Preauthz Application": String(check?.appName || check?.appGuid || "").trim(),
        "Preauthz Endpoint URL": String(check?.endpointUrl || "").trim(),
        "Preauthz Response JSON": stringifyJsonForCsvCell(check?.responsePayload, "{}"),
      };
      const decisionRows = Array.isArray(check?.decisionRows) ? check.decisionRows : [];
      if (decisionRows.length === 0) {
        rows.push({
          ...checkBase,
          "Decision Index": "",
          "Decision Resource ID": "",
          "Decision Verdict": "",
          "Decision Authorized": "",
          "Decision Source": "",
          "Decision Service Provider": "",
          "Decision MVPD": "",
          "Decision Error Code": "",
          "Decision Error Details": "",
          "Decision Media Token Present": "",
          "Decision Media Token Preview": "",
          "Decision Token Not Before": "",
          "Decision Token Not After": "",
          "Decision Not Before": "",
          "Decision Not After": "",
          "Decision Raw JSON": "",
        });
        return;
      }
      decisionRows.forEach((decisionRow, decisionIndex) => {
        rows.push({
          ...checkBase,
          "Decision Index": decisionIndex + 1,
          "Decision Resource ID": String(decisionRow?.resourceId || "").trim(),
          "Decision Verdict": String(decisionRow?.decision || "").trim(),
          "Decision Authorized": typeof decisionRow?.authorized === "boolean" ? String(decisionRow.authorized) : "",
          "Decision Source": String(decisionRow?.source || "").trim(),
          "Decision Service Provider": String(decisionRow?.serviceProvider || "").trim(),
          "Decision MVPD": String(decisionRow?.mvpd || "").trim(),
          "Decision Error Code": String(decisionRow?.errorCode || "").trim(),
          "Decision Error Details": String(decisionRow?.errorDetails || "").trim(),
          "Decision Media Token Present": decisionRow?.mediaTokenPresent === true ? "true" : "false",
          "Decision Media Token Preview": String(decisionRow?.mediaTokenPreview || "").trim(),
          "Decision Token Not Before": formatTimestampLabel(decisionRow?.mediaTokenNotBeforeMs),
          "Decision Token Not After": formatTimestampLabel(decisionRow?.mediaTokenNotAfterMs),
          "Decision Not Before": formatTimestampLabel(decisionRow?.notBeforeMs),
          "Decision Not After": formatTimestampLabel(decisionRow?.notAfterMs),
          "Decision Raw JSON": stringifyJsonForCsvCell(decisionRow?.raw, "{}"),
        });
      });
    });
  });

  return rows;
}

function downloadRestV2ProfileHarvestCsv(harvestList = [], programmerId = "") {
  const normalizedHarvestList = (Array.isArray(harvestList) ? harvestList : []).filter((item) => item && typeof item === "object");
  if (normalizedHarvestList.length === 0) {
    return { ok: false, error: "No MVPD profiles are available to export." };
  }

  const rows = buildRestV2ProfileHarvestExportRows(normalizedHarvestList);
  if (rows.length === 0) {
    return { ok: false, error: "No MVPD profile rows are available to export." };
  }

  const columns = [
    "Profile Index",
    "Programmer ID",
    "Requestor ID",
    "Service Provider ID",
    "MVPD",
    "Subject",
    "Upstream User ID",
    "User ID",
    "Session ID",
    "Profile Key",
    "Profile Captured At",
    "Profile Count",
    "Profile Check Outcome",
    "Profile Check HTTP Status",
    "Profile Check HTTP Status Text",
    "Profile Not Before",
    "Profile Not After",
    "Profile Attributes JSON",
    "Profile Candidate Subjects",
    "Profile Candidate Sessions",
    "Profile Candidate IDPs",
    "Preauthz Check Index",
    "Preauthz Checked At",
    "Preauthz Verdict",
    "Preauthz HTTP Status",
    "Preauthz HTTP Status Text",
    "Preauthz Error",
    "Preauthz Requested Resource IDs",
    "Preauthz Permit Count",
    "Preauthz Deny Count",
    "Preauthz Unknown Count",
    "Preauthz Auth Mode",
    "Preauthz Application",
    "Preauthz Endpoint URL",
    "Preauthz Response JSON",
    "Decision Index",
    "Decision Resource ID",
    "Decision Verdict",
    "Decision Authorized",
    "Decision Source",
    "Decision Service Provider",
    "Decision MVPD",
    "Decision Error Code",
    "Decision Error Details",
    "Decision Media Token Present",
    "Decision Media Token Preview",
    "Decision Token Not Before",
    "Decision Token Not After",
    "Decision Not Before",
    "Decision Not After",
    "Decision Raw JSON",
  ];
  const lines = [
    columns.map((column) => `"${String(column || "").replace(/"/g, '""')}"`).join(","),
    ...rows.map((row) =>
      columns.map((column) => `"${String(row?.[column] ?? "").replace(/"/g, '""')}"`).join(",")
    ),
  ];

  const programmerSegment = sanitizeDownloadFileSegment(programmerId || "programmer", "programmer");
  const envTag = getAdobePassEnvironmentFileTag();
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  const fileName = `restv2_mvpd_profiles_${programmerSegment}_${envTag}_${stamp}.csv`;
  const blob = new Blob([lines.join("\n")], { type: "text/csv" });
  const blobUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = blobUrl;
  anchor.download = fileName;
  anchor.click();
  URL.revokeObjectURL(blobUrl);

  const checkCount = normalizedHarvestList.reduce((total, harvest) => total + getRestV2ProfilePreauthzChecks(harvest).length, 0);
  return {
    ok: true,
    fileName,
    profileCount: normalizedHarvestList.length,
    checkCount,
    rowCount: rows.length,
  };
}

function getRestV2SectionState(section) {
  if (!section) {
    return {
      selectedHarvestKey: "",
      expandedHarvestKey: "",
      hasProfileExpansionChoice: false,
      resourceInput: REST_V2_DEFAULT_RESOURCE_ID_INPUT,
      resourceInputHarvestKey: "",
      entitlementBusy: false,
      splunkBusy: false,
      splunkBusyHarvestKey: "",
      profileToolCollapsed: true,
      entitlementToolCollapsed: true,
      lastEntitlementResult: null,
      lastSplunkResult: null,
      lastSplunkHarvestKey: "",
    };
  }
  if (!section.__underparRestV2State || typeof section.__underparRestV2State !== "object") {
    section.__underparRestV2State = {
      selectedHarvestKey: "",
      expandedHarvestKey: "",
      hasProfileExpansionChoice: false,
      resourceInput: REST_V2_DEFAULT_RESOURCE_ID_INPUT,
      resourceInputHarvestKey: "",
      entitlementBusy: false,
      splunkBusy: false,
      splunkBusyHarvestKey: "",
      profileToolCollapsed: true,
      entitlementToolCollapsed: true,
      lastEntitlementResult: null,
      lastSplunkResult: null,
      lastSplunkHarvestKey: "",
    };
  }
  if (typeof section.__underparRestV2State.selectedHarvestKey !== "string") {
    section.__underparRestV2State.selectedHarvestKey = "";
  }
  if (typeof section.__underparRestV2State.expandedHarvestKey !== "string") {
    section.__underparRestV2State.expandedHarvestKey = "";
  }
  if (typeof section.__underparRestV2State.hasProfileExpansionChoice !== "boolean") {
    section.__underparRestV2State.hasProfileExpansionChoice = false;
  }
  if (typeof section.__underparRestV2State.resourceInput !== "string") {
    section.__underparRestV2State.resourceInput = REST_V2_DEFAULT_RESOURCE_ID_INPUT;
  }
  if (typeof section.__underparRestV2State.resourceInputHarvestKey !== "string") {
    section.__underparRestV2State.resourceInputHarvestKey = "";
  }
  if (typeof section.__underparRestV2State.entitlementBusy !== "boolean") {
    section.__underparRestV2State.entitlementBusy = false;
  }
  if (typeof section.__underparRestV2State.splunkBusy !== "boolean") {
    section.__underparRestV2State.splunkBusy = false;
  }
  if (typeof section.__underparRestV2State.splunkBusyHarvestKey !== "string") {
    section.__underparRestV2State.splunkBusyHarvestKey = "";
  }
  if (typeof section.__underparRestV2State.profileToolCollapsed !== "boolean") {
    section.__underparRestV2State.profileToolCollapsed = true;
  }
  if (typeof section.__underparRestV2State.entitlementToolCollapsed !== "boolean") {
    section.__underparRestV2State.entitlementToolCollapsed = true;
  }
  if (
    section.__underparRestV2State.lastSplunkResult != null &&
    typeof section.__underparRestV2State.lastSplunkResult !== "object"
  ) {
    section.__underparRestV2State.lastSplunkResult = null;
  }
  if (typeof section.__underparRestV2State.lastSplunkHarvestKey !== "string") {
    section.__underparRestV2State.lastSplunkHarvestKey = "";
  }
  return section.__underparRestV2State;
}

function normalizeBobtoolsRestV2Action(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized) {
    return BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE;
  }
  if (
    normalized === "preauthorize" ||
    normalized === "can-i-watch" ||
    normalized === "can_i_watch" ||
    normalized === "caniwatch"
  ) {
    return BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE;
  }
  if (normalized === "authorize") {
    return BOBTOOLS_REST_V2_ACTION_AUTHORIZE;
  }
  if (normalized === "profiles" || normalized === "profiles-mvpd" || normalized === "profiles_mvpd") {
    return BOBTOOLS_REST_V2_ACTION_PROFILES_MVPD;
  }
  if (normalized === "profiles-all" || normalized === "profiles_all" || normalized === "profilesall") {
    return BOBTOOLS_REST_V2_ACTION_PROFILES_ALL;
  }
  if (normalized === "configuration" || normalized === "config") {
    return BOBTOOLS_REST_V2_ACTION_CONFIGURATION;
  }
  return BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE;
}

function getBobtoolsRestV2ActionLabel(action = "") {
  const normalized = normalizeBobtoolsRestV2Action(action);
  if (normalized === BOBTOOLS_REST_V2_ACTION_AUTHORIZE) {
    return "Authorize";
  }
  if (normalized === BOBTOOLS_REST_V2_ACTION_PROFILES_MVPD) {
    return "Profiles (selected MVPD)";
  }
  if (normalized === BOBTOOLS_REST_V2_ACTION_PROFILES_ALL) {
    return "Profiles (all MVPD)";
  }
  if (normalized === BOBTOOLS_REST_V2_ACTION_CONFIGURATION) {
    return "Configuration";
  }
  return "Can I watch? (Preauthorize)";
}

function bobtoolsRestV2ActionRequiresResources(action = "") {
  const normalized = normalizeBobtoolsRestV2Action(action);
  return normalized === BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE || normalized === BOBTOOLS_REST_V2_ACTION_AUTHORIZE;
}

function bobtoolsRestV2ActionRequiresActiveProfile(action = "") {
  return bobtoolsRestV2ActionRequiresResources(action);
}

function parseRestV2ResourceIdInput(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return [];
  }
  return dedupeRestV2CandidateStrings(
    raw
      .split(/[,\n\r;]+/g)
      .map((item) => String(item || "").trim())
      .filter(Boolean)
  );
}

function formatRestV2CompactValue(value, maxLength = 44) {
  const text = String(value || "").trim();
  if (!text) {
    return "";
  }
  const limit = Math.max(12, Number(maxLength) || 44);
  if (text.length <= limit) {
    return text;
  }
  const prefix = Math.max(4, Math.floor((limit - 3) * 0.6));
  const suffix = Math.max(4, limit - 3 - prefix);
  return `${text.slice(0, prefix)}...${text.slice(-suffix)}`;
}

function resolveRestV2AppInfoForHarvest(harvest = null) {
  if (!harvest || typeof harvest !== "object") {
    return null;
  }
  const programmerId = String(harvest.programmerId || "").trim();
  if (!programmerId) {
    return null;
  }

  const services = getCurrentPremiumAppsSnapshot(programmerId);
  const restV2Candidates = collectRestV2AppCandidatesFromPremiumApps(services);
  const appGuid = String(harvest.appGuid || "").trim();
  if (appGuid) {
    const guidMatch = restV2Candidates.find((item) => String(item?.guid || "").trim() === appGuid);
    if (guidMatch?.guid) {
      return guidMatch;
    }
  }

  const requestorId = String(harvest.requestorId || "").trim();
  if (requestorId) {
    const mapped = resolveRestV2AppForServiceProvider(restV2Candidates, requestorId, programmerId);
    if (mapped?.guid) {
      return mapped;
    }
  }

  if (services?.restV2?.guid) {
    return services.restV2;
  }
  return restV2Candidates[0] || null;
}

function buildRestV2ContextFromHarvest(harvest = null) {
  if (!harvest || typeof harvest !== "object") {
    return null;
  }
  const programmerId = String(harvest.programmerId || "").trim();
  const requestorId = String(harvest.requestorId || harvest.serviceProviderId || "").trim();
  const serviceProviderId = String(harvest.serviceProviderId || harvest.requestorId || "").trim();
  const mvpd = String(harvest.mvpd || "").trim();
  const sessionUrl = normalizeAdobeNavigationUrl(String(harvest.sessionUrl || "").trim());
  const loginUrl = normalizeAdobeNavigationUrl(String(harvest.loginUrl || "").trim());
  const sessionCodeCandidates = collectRestV2SessionCodeCandidates(
    [
      harvest.sessionCode,
      ...(Array.isArray(harvest.sessionCodeCandidates) ? harvest.sessionCodeCandidates : []),
      sessionUrl,
      loginUrl,
    ],
    serviceProviderId
  );
  const sessionCode = firstNonEmptyString([String(harvest.sessionCode || "").trim(), sessionCodeCandidates[0]]);
  const harvestMvpdName = String(harvest.mvpdName || "").trim();
  const cachedMvpdMeta =
    requestorId ? getRequestorScopedMvpdCache(requestorId)?.get(mvpd) || null : null;
  const mvpdMeta = cachedMvpdMeta || (harvestMvpdName ? { id: mvpd, name: harvestMvpdName } : null);
  const appInfo = resolveRestV2AppInfoForHarvest(harvest);
  if (!programmerId || !requestorId || !serviceProviderId || !mvpd || !appInfo?.guid) {
    return null;
  }
  return {
    ok: true,
    programmerId,
    programmerName: String(harvest.programmerName || "").trim(),
    requestorId,
    serviceProviderId,
    mvpd,
    mvpdMeta,
    sessionCode,
    sessionCodeCandidates,
    sessionAction: String(harvest.sessionAction || "").trim(),
    sessionPartner: String(harvest.sessionPartner || "").trim(),
    partnerFrameworkStatus: String(harvest.partnerFrameworkStatus || "").trim(),
    sessionUrl,
    loginUrl,
    appInfo,
    restV2AppCandidates: [appInfo],
  };
}

function normalizeRestV2DecisionVerdict(authorized = null) {
  if (authorized === true) {
    return "Permit";
  }
  if (authorized === false) {
    return "Deny";
  }
  return "Unknown";
}

function parseRestV2DecisionError(errorValue = null) {
  if (!errorValue || typeof errorValue !== "object") {
    return {
      errorCode: "",
      errorDetails: "",
    };
  }
  const errorCode = String(
    firstNonEmptyString([
      errorValue.code,
      errorValue.error,
      errorValue.action,
    ]) || ""
  ).trim();
  const messageValue = errorValue.message;
  const messageText =
    typeof messageValue === "string"
      ? messageValue
      : messageValue && typeof messageValue === "object"
        ? stringifyJsonForDisplay(messageValue)
        : "";
  const errorDetails = String(
    firstNonEmptyString([
      errorValue.details,
      messageText,
    ]) || ""
  ).trim();
  return {
    errorCode,
    errorDetails,
  };
}

function parseRestV2DecisionRowFromPayload(decisionValue = null, fallbackResourceId = "") {
  const decision = decisionValue && typeof decisionValue === "object" ? decisionValue : {};
  const resourceId = firstNonEmptyString([
    decision.resource,
    decision.resourceId,
    fallbackResourceId,
  ]);
  const authorized = typeof decision.authorized === "boolean" ? decision.authorized : null;
  const tokenValue = String(
    firstNonEmptyString([
      decision?.token?.serializedToken,
      decision?.token?.token,
      decision?.token?.mediaToken,
    ]) || ""
  ).trim();
  const errorDetails = parseRestV2DecisionError(decision.error);
  return {
    resourceId: String(resourceId || "").trim(),
    decision: normalizeRestV2DecisionVerdict(authorized),
    authorized,
    source: String(firstNonEmptyString([decision.source]) || "").trim(),
    serviceProvider: String(firstNonEmptyString([decision.serviceProvider]) || "").trim(),
    mvpd: String(firstNonEmptyString([decision.mvpd]) || "").trim(),
    errorCode: String(errorDetails.errorCode || "").trim(),
    errorDetails: String(errorDetails.errorDetails || "").trim(),
    mediaTokenPresent: Boolean(tokenValue),
    mediaTokenPreview: tokenValue ? formatRestV2CompactValue(tokenValue, 30) : "",
    mediaTokenNotBeforeMs: Number(decision?.token?.notBefore || 0),
    mediaTokenNotAfterMs: Number(decision?.token?.notAfter || 0),
    notBeforeMs: Number(decision?.notBefore || 0),
    notAfterMs: Number(decision?.notAfter || 0),
    raw: cloneJsonLikeValue(decision, {}),
  };
}

function mergeRestV2DecisionRowByResource(existing = null, incoming = null) {
  if (!existing) {
    return incoming;
  }
  if (!incoming) {
    return existing;
  }
  const existingRank =
    existing.decision === "Permit" ? 3 : existing.decision === "Deny" ? 2 : existing.decision === "Unknown" ? 1 : 0;
  const incomingRank =
    incoming.decision === "Permit" ? 3 : incoming.decision === "Deny" ? 2 : incoming.decision === "Unknown" ? 1 : 0;
  if (incomingRank > existingRank) {
    return incoming;
  }
  if (incomingRank === existingRank && Number(incoming.notAfterMs || 0) > Number(existing.notAfterMs || 0)) {
    return incoming;
  }
  return existing;
}

function extractRestV2PreauthorizeDecisionRows(payload, requestedResourceIds = []) {
  const requested = Array.isArray(requestedResourceIds)
    ? requestedResourceIds.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  const decisions = Array.isArray(payload?.decisions) ? payload.decisions : [];
  const rowsByResource = new Map();

  decisions.forEach((decision) => {
    const row = parseRestV2DecisionRowFromPayload(decision);
    const key = String(row.resourceId || "").trim().toLowerCase();
    if (!key) {
      return;
    }
    const existing = rowsByResource.get(key) || null;
    rowsByResource.set(key, mergeRestV2DecisionRowByResource(existing, row));
  });

  requested.forEach((resourceId) => {
    const key = resourceId.toLowerCase();
    if (rowsByResource.has(key)) {
      return;
    }
    rowsByResource.set(
      key,
      parseRestV2DecisionRowFromPayload(
        {
          resource: resourceId,
          authorized: null,
          source: "",
        },
        resourceId
      )
    );
  });

  return [...rowsByResource.values()].sort((left, right) =>
    String(left?.resourceId || "").localeCompare(String(right?.resourceId || ""))
  );
}

function applyRestV2TopLevelErrorToDecisionRows(rows = [], payload = null) {
  const list = Array.isArray(rows) ? rows : [];
  const errorCode = String(
    firstNonEmptyString([
      payload?.code,
      payload?.error?.code,
      payload?.error,
    ]) || ""
  ).trim();
  const messageValue = payload?.message;
  const messageText =
    typeof messageValue === "string"
      ? messageValue
      : messageValue && typeof messageValue === "object"
        ? stringifyJsonForDisplay(messageValue)
        : "";
  const errorDetails = String(
    firstNonEmptyString([
      payload?.details,
      messageText,
    ]) || ""
  ).trim();

  if (!errorCode && !errorDetails) {
    return list;
  }
  return list.map((row) => ({
    ...row,
    errorCode: row?.errorCode ? String(row.errorCode) : errorCode,
    errorDetails: row?.errorDetails ? String(row.errorDetails) : errorDetails,
  }));
}

function summarizeRestV2PreauthorizeRows(rows = [], requestedResourceIds = []) {
  const normalizedRows = Array.isArray(rows) ? rows : [];
  const permitCount = normalizedRows.filter((item) => String(item?.decision || "").trim().toLowerCase() === "permit").length;
  const denyCount = normalizedRows.filter((item) => String(item?.decision || "").trim().toLowerCase() === "deny").length;
  const unknownCount = normalizedRows.length - permitCount - denyCount;
  const requestedCount = Array.isArray(requestedResourceIds) ? requestedResourceIds.length : 0;
  const allRequestedPermitted = requestedCount > 0 && permitCount >= requestedCount && denyCount === 0 && unknownCount === 0;
  return {
    permitCount,
    denyCount,
    unknownCount,
    requestedCount,
    allRequestedPermitted,
  };
}

async function fetchRestV2DecisionCheck(harvest, resourceIds, mode = BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE) {
  const normalizedMode = normalizeBobtoolsRestV2Action(mode);
  const decisionMode =
    normalizedMode === BOBTOOLS_REST_V2_ACTION_AUTHORIZE
      ? BOBTOOLS_REST_V2_ACTION_AUTHORIZE
      : BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE;
  const actionLabel = getBobtoolsRestV2ActionLabel(decisionMode);
  const scopeKey = decisionMode === BOBTOOLS_REST_V2_ACTION_AUTHORIZE ? "decisions-authorize" : "decisions-preauthorize";

  const serviceProviderId = String(harvest?.serviceProviderId || harvest?.requestorId || "").trim();
  const selectedMvpd = String(harvest?.mvpd || "").trim();
  const endpointMvpd = String(resolveRestV2DecisionMvpd(harvest) || "").trim();
  const programmerId = String(harvest?.programmerId || "").trim();
  if (!serviceProviderId || !selectedMvpd || !endpointMvpd) {
    throw new Error("Missing service provider or MVPD from the selected MVPD profile.");
  }
  if (!programmerId) {
    throw new Error(`Missing programmer context for ${decisionMode}.`);
  }

  const appInfo = resolveRestV2AppInfoForHarvest(harvest);
  if (!appInfo?.guid) {
    throw new Error(`Unable to resolve REST V2 application context for ${decisionMode}.`);
  }

  const endpointUrl = `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/decisions/${encodeURIComponent(
    decisionMode
  )}/${encodeURIComponent(endpointMvpd)}`;
  const requestHeaders = buildRestV2Headers(serviceProviderId, {
    Accept: "application/json",
    "Content-Type": "application/json",
  });
  const requestBody = JSON.stringify({
    resources: resourceIds,
  });

  const flowId = resolveRestV2DebugFlowIdForHarvest(harvest);
  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: `${scopeKey}-request`,
    method: "POST",
    url: endpointUrl,
    scope: scopeKey,
    requestorId: String(harvest?.requestorId || ""),
    mvpd: selectedMvpd,
    decisionMvpd: endpointMvpd,
    programmerId,
    appGuid: String(appInfo?.guid || ""),
    appName: String(appInfo?.appName || appInfo?.guid || ""),
    authMode: "dcr_client_bearer",
    body: cloneJsonLikeValue({ resources: resourceIds }, {}),
  });

  const response = await fetchWithPremiumAuth(
    programmerId,
    appInfo,
    endpointUrl,
    {
      method: "POST",
      mode: "cors",
      headers: requestHeaders,
      body: requestBody,
    },
    "refresh",
    {
      flowId,
      requestorId: String(harvest?.requestorId || serviceProviderId || ""),
      mvpd: endpointMvpd,
      scope: scopeKey,
      service: "rest-v2-entitlements",
      endpointUrl,
    }
  );
  const responseText = await response.text().catch(() => "");
  const parsedPayload = parseJsonText(responseText, null);
  const decisionRows = applyRestV2TopLevelErrorToDecisionRows(
    extractRestV2PreauthorizeDecisionRows(parsedPayload, resourceIds),
    parsedPayload
  );
  const decisionSummary = summarizeRestV2PreauthorizeRows(decisionRows, resourceIds);
  const checkedAt = Date.now();
  const checkedAtLabel = formatTimestampLabel(checkedAt);
  const resourceIdChips = bobtoolsWorkspaceResolveMappedResourceIdChips(
    programmerId,
    String(harvest?.requestorId || serviceProviderId || "").trim(),
    selectedMvpd,
    resourceIds
  );

  const result = {
    checkedAt,
    checkedAtLabel,
    ok: response.ok === true,
    status: Number(response.status || 0),
    statusText: String(response.statusText || "").trim(),
    programmerId,
    appGuid: String(appInfo?.guid || "").trim(),
    appName: String(appInfo?.appName || appInfo?.guid || "").trim(),
    authMode: "dcr_client_bearer",
    endpointUrl,
    requestBody: {
      resources: resourceIds.slice(),
    },
    method: "POST",
    apiAction: decisionMode,
    apiActionLabel: actionLabel,
    resultType: "decisions",
    serviceProviderId,
    requestorId: String(harvest?.requestorId || serviceProviderId || "").trim(),
    mvpd: selectedMvpd,
    decisionMvpd: endpointMvpd,
    harvestKey: getRestV2HarvestRecordKey(harvest),
    harvestCapturedAt: Number(harvest?.harvestedAt || 0),
    subject: String(harvest?.subject || "").trim(),
    upstreamUserId: String(harvest?.upstreamUserId || "").trim(),
    userId: String(harvest?.userId || "").trim(),
    sessionId: String(harvest?.sessionId || "").trim(),
    profileKey: String(harvest?.profileKey || "").trim(),
    resourceIds: resourceIds.slice(),
    resourceIdChips,
    decisionRows,
    permitCount: decisionSummary.permitCount,
    denyCount: decisionSummary.denyCount,
    unknownCount: decisionSummary.unknownCount,
    allRequestedPermitted: decisionSummary.allRequestedPermitted,
    responsePreview: truncateDebugText(responseText, 3000),
    responsePayload: parsedPayload ?? responseText,
    error: "",
  };

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: `${scopeKey}-response`,
    method: "POST",
    url: endpointUrl,
    scope: scopeKey,
    status: result.status,
    statusText: result.statusText,
    requestorId: result.requestorId,
    mvpd: result.mvpd,
    decisionMvpd: result.decisionMvpd,
    programmerId,
    appGuid: result.appGuid,
    appName: result.appName,
    authMode: result.authMode,
    decisionRows: cloneJsonLikeValue(decisionRows, []),
    permitCount: result.permitCount,
    denyCount: result.denyCount,
    unknownCount: result.unknownCount,
    responsePreview: result.responsePreview,
  });

  if (!response.ok) {
    const errorCode = String(
      firstNonEmptyString([
        parsedPayload?.code,
        parsedPayload?.error?.code,
        parsedPayload?.error,
      ]) || ""
    ).trim();
    const errorMessage =
      firstNonEmptyString([
        errorCode,
        parsedPayload?.error?.code,
        parsedPayload?.error,
        parsedPayload?.details,
        parsedPayload?.message,
        normalizeHttpErrorMessage(responseText),
        result.statusText,
      ]) || `HTTP ${result.status}`;
    const errorHint =
      Number(result.status || 0) === 401
        ? "REST V2 rejected the client bearer token. UnderPAR uses DCR auth for this API, and token refresh is automatic."
        : "";
    result.error = errorHint ? `${errorMessage}. ${errorHint}` : errorMessage;
    throw Object.assign(new Error(`${actionLabel} failed (${result.status}): ${errorMessage}`), { underparResult: result });
  }

  return result;
}

async function fetchRestV2PreauthorizeDecisions(harvest, resourceIds) {
  return fetchRestV2DecisionCheck(harvest, resourceIds, BOBTOOLS_REST_V2_ACTION_PREAUTHORIZE);
}

async function fetchRestV2AuthorizeDecisions(harvest, resourceIds) {
  return fetchRestV2DecisionCheck(harvest, resourceIds, BOBTOOLS_REST_V2_ACTION_AUTHORIZE);
}

function extractRestV2ProfileRowsFromPayload(payload = {}, context = null) {
  const profiles = payload?.profiles && typeof payload.profiles === "object" ? payload.profiles : {};
  const entries = Object.entries(profiles).filter(([, profile]) => profile && typeof profile === "object");
  return entries
    .map(([profileKey, profile]) => getRestV2ProfileSummary(profile, profileKey, context))
    .map((summary) => {
      const attributes = summary?.attributes && typeof summary.attributes === "object" ? summary.attributes : {};
      const attributeRows = Object.entries(attributes)
        .map(([key, value]) => ({
          key: String(key || "").trim(),
          value: String(value || "").trim(),
        }))
        .filter((item) => item.key && item.value)
        .sort((left, right) => left.key.localeCompare(right.key));
      return {
        profileKey: String(summary?.profileKey || "").trim(),
        mvpd: String(summary?.mvpd || "").trim(),
        subject: String(summary?.subject || "").trim(),
        upstreamUserId: String(summary?.upstreamUserId || "").trim(),
        userId: String(summary?.userId || "").trim(),
        sessionId: String(summary?.sessionId || "").trim(),
        notBeforeMs: Number(summary?.notBeforeMs || 0),
        notAfterMs: Number(summary?.notAfterMs || 0),
        attributes: attributeRows,
      };
    })
    .sort((left, right) => String(left?.profileKey || "").localeCompare(String(right?.profileKey || "")));
}

async function fetchRestV2ProfilesForHarvest(harvest, options = {}) {
  const actionMode = normalizeBobtoolsRestV2Action(options?.apiAction || BOBTOOLS_REST_V2_ACTION_PROFILES_MVPD);
  const serviceProviderId = String(harvest?.serviceProviderId || harvest?.requestorId || "").trim();
  const mvpd = String(harvest?.mvpd || "").trim();
  const programmerId = String(harvest?.programmerId || "").trim();
  if (!serviceProviderId) {
    throw new Error("Missing service provider from the selected MVPD profile.");
  }
  if (!programmerId) {
    throw new Error("Missing programmer context for profile lookup.");
  }

  const appInfo = resolveRestV2AppInfoForHarvest(harvest);
  if (!appInfo?.guid) {
    throw new Error("Unable to resolve REST V2 application context for profile lookup.");
  }

  const endpointUrl =
    actionMode === BOBTOOLS_REST_V2_ACTION_PROFILES_ALL
      ? `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/profiles`
      : `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/profiles/${encodeURIComponent(mvpd)}`;
  const actionLabel = getBobtoolsRestV2ActionLabel(actionMode);
  const flowId = resolveRestV2DebugFlowIdForHarvest(harvest);
  const likelySsoContext = isRestV2LikelyPartnerSsoContext(harvest);
  const partnerFrameworkStatus = resolveRestV2PartnerFrameworkStatusFromContext(harvest);
  const requestHeaders = buildRestV2Headers(serviceProviderId, {
    Accept: "application/json",
  });
  if (
    actionMode === BOBTOOLS_REST_V2_ACTION_PROFILES_MVPD &&
    likelySsoContext &&
    partnerFrameworkStatus
  ) {
    requestHeaders["AP-Partner-Framework-Status"] = partnerFrameworkStatus;
  }

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: `${actionMode}-request`,
    method: "GET",
    url: endpointUrl,
    scope: actionMode,
    requestorId: String(harvest?.requestorId || serviceProviderId || ""),
    mvpd,
    programmerId,
    appGuid: String(appInfo?.guid || ""),
    appName: String(appInfo?.appName || appInfo?.guid || ""),
    authMode: "dcr_client_bearer",
    partnerFrameworkStatusPresent: Boolean(
      actionMode === BOBTOOLS_REST_V2_ACTION_PROFILES_MVPD && likelySsoContext && partnerFrameworkStatus
    ),
  });

  const response = await fetchWithPremiumAuth(
    programmerId,
    appInfo,
    endpointUrl,
    {
      method: "GET",
      mode: "cors",
      headers: requestHeaders,
    },
    "refresh",
    {
      flowId,
      requestorId: String(harvest?.requestorId || serviceProviderId || ""),
      mvpd,
      scope: actionMode,
      service: "rest-v2-profiles",
      endpointUrl,
    }
  );

  const responseText = await response.text().catch(() => "");
  const parsedPayload = parseJsonText(responseText, null);
  const profileRows = extractRestV2ProfileRowsFromPayload(parsedPayload || {}, {
    mvpd,
    requestorId: String(harvest?.requestorId || serviceProviderId || "").trim(),
  });
  const checkedAt = Date.now();
  const result = {
    checkedAt,
    checkedAtLabel: formatTimestampLabel(checkedAt),
    ok: response.ok === true,
    status: Number(response.status || 0),
    statusText: String(response.statusText || "").trim(),
    programmerId,
    appGuid: String(appInfo?.guid || "").trim(),
    appName: String(appInfo?.appName || appInfo?.guid || "").trim(),
    authMode: "dcr_client_bearer",
    endpointUrl,
    method: "GET",
    apiAction: actionMode,
    apiActionLabel: actionLabel,
    resultType: "profiles",
    serviceProviderId,
    requestorId: String(harvest?.requestorId || serviceProviderId || "").trim(),
    mvpd,
    harvestKey: getRestV2HarvestRecordKey(harvest),
    harvestCapturedAt: Number(harvest?.harvestedAt || 0),
    subject: String(harvest?.subject || "").trim(),
    upstreamUserId: String(harvest?.upstreamUserId || "").trim(),
    userId: String(harvest?.userId || "").trim(),
    sessionId: String(harvest?.sessionId || "").trim(),
    profileKey: String(harvest?.profileKey || "").trim(),
    profileRows,
    profileCount: profileRows.length,
    profileKeys: profileRows.map((row) => String(row?.profileKey || "").trim()).filter(Boolean),
    responsePreview: truncateDebugText(responseText, 3000),
    responsePayload: parsedPayload ?? responseText,
    error: "",
  };

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: `${actionMode}-response`,
    method: "GET",
    url: endpointUrl,
    scope: actionMode,
    status: result.status,
    statusText: result.statusText,
    requestorId: result.requestorId,
    mvpd: result.mvpd,
    programmerId,
    appGuid: result.appGuid,
    appName: result.appName,
    authMode: result.authMode,
    profileCount: result.profileCount,
    profileKeys: result.profileKeys.slice(0, 24),
    responsePreview: result.responsePreview,
  });

  if (!response.ok) {
    const errorMessage =
      firstNonEmptyString([
        parsedPayload?.code,
        parsedPayload?.error?.code,
        parsedPayload?.error,
        parsedPayload?.details,
        parsedPayload?.message,
        normalizeHttpErrorMessage(responseText),
        result.statusText,
      ]) || `HTTP ${result.status}`;
    result.error = errorMessage;
    throw Object.assign(new Error(`${actionLabel} failed (${result.status}): ${errorMessage}`), { underparResult: result });
  }

  return result;
}

function buildTempPassResultId(actionKey = "") {
  const actionLabel = String(actionKey || "temp-pass").trim().toLowerCase() || "temp-pass";
  if (globalThis.crypto?.randomUUID) {
    return `${actionLabel}-${globalThis.crypto.randomUUID()}`;
  }
  return `${actionLabel}-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
}

function resolveTempPassIdentityPayload(value = "") {
  const rawValue = String(value || "").trim();
  if (!rawValue) {
    return {
      rawJson: "",
      headerValue: "",
      preview: "",
    };
  }

  let parsed = parseJsonText(rawValue, null);
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
    const decoded = decodeBase64TextSafe(rawValue);
    parsed = parseJsonText(decoded, null);
  }
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
    throw new Error("TempPASS identity must be a JSON object or base64-encoded JSON object.");
  }

  const canonical = JSON.stringify(parsed);
  return {
    rawJson: canonical,
    headerValue: base64EncodeUtf8(canonical),
    preview: truncateDebugText(canonical, 320),
  };
}

function buildTempPassRequestHeaders(requestorId = "", options = {}) {
  const headers = buildRestV2Headers(requestorId, {
    Accept: "application/json",
    ...(options?.extraHeaders && typeof options.extraHeaders === "object" ? options.extraHeaders : {}),
  });
  const identityHeaderValue = String(options?.identityHeaderValue || "").trim();
  if (identityHeaderValue) {
    headers["AP-TempPass-Identity"] = identityHeaderValue;
  }
  return headers;
}

function resolveTempPassRestV2AppInfo(programmerId = "", requestorId = "", services = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedRequestorId = String(requestorId || "").trim();
  const premiumApps =
    services && typeof services === "object"
      ? services
      : normalizedProgrammerId
        ? getCurrentPremiumAppsSnapshot(normalizedProgrammerId)
        : null;
  if (!premiumApps) {
    return null;
  }
  const candidates = collectRestV2AppCandidatesFromPremiumApps(premiumApps);
  return selectPreferredRestV2AppForRequestor(candidates, normalizedRequestorId, normalizedProgrammerId) || null;
}

function resolveTempPassResetAppInfo(programmerId = "", requestorId = "", services = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedRequestorId = String(requestorId || "").trim();
  const premiumApps =
    services && typeof services === "object"
      ? services
      : normalizedProgrammerId
        ? getCurrentPremiumAppsSnapshot(normalizedProgrammerId)
        : null;
  if (!premiumApps) {
    return null;
  }
  const candidates = collectResetTempPassAppCandidatesFromPremiumApps(premiumApps);
  return selectPreferredResetTempPassAppForRequestor(candidates, normalizedRequestorId, normalizedProgrammerId) || null;
}

function buildTempPassDebugMeta(payload = {}, options = {}) {
  return {
    requestorId: String(payload?.requestorId || "").trim(),
    mvpd: String(payload?.tempPassMvpd || payload?.mvpd || "").trim(),
    service: String(options?.service || "temp-pass").trim(),
    scope: String(options?.scope || "temp-pass").trim(),
    endpointUrl: String(options?.endpointUrl || "").trim(),
    requiredServiceScope: String(options?.requiredServiceScope || "").trim(),
    workspaceKey: "temp-pass-workspace",
    workspaceOrigin: "TempPASS Workspace",
  };
}

async function fetchTempPassProfilesForSelection(payload = {}, services = null) {
  const programmerId = String(payload?.programmerId || "").trim();
  const requestorId = String(payload?.requestorId || "").trim();
  const tempPassMvpd = String(payload?.tempPassMvpd || "").trim();
  if (!programmerId || !requestorId || !tempPassMvpd) {
    throw new Error("TempPASS profile lookup requires programmer, requestor, and TempPASS MVPD values.");
  }

  const restApp = resolveTempPassRestV2AppInfo(programmerId, requestorId, services);
  if (!restApp?.guid) {
    throw new Error("No REST V2 registered application is available for the selected RequestorId.");
  }

  const identityPayload = resolveTempPassIdentityPayload(payload?.identityJson || "");
  const endpointUrl = `${REST_V2_BASE}/${encodeURIComponent(requestorId)}/profiles/${encodeURIComponent(tempPassMvpd)}`;
  const response = await fetchWithPremiumAuth(
    programmerId,
    restApp,
    endpointUrl,
    {
      method: "GET",
      mode: "cors",
      headers: buildTempPassRequestHeaders(requestorId, {
        identityHeaderValue: identityPayload.headerValue,
      }),
    },
    "refresh",
    buildTempPassDebugMeta(payload, {
      service: "temp-pass-profiles",
      scope: "temp-pass-profiles",
      endpointUrl,
      requiredServiceScope: REST_V2_SCOPE,
    })
  );

  const responseText = await response.text().catch(() => "");
  const parsedPayload = parseJsonText(responseText, null);
  const profileRows = extractRestV2ProfileRowsFromPayload(parsedPayload || {}, {
    mvpd: tempPassMvpd,
    requestorId,
  });
  const checkedAt = Date.now();
  const result = {
    resultId: buildTempPassResultId("profiles"),
    checkedAt,
    checkedAtLabel: formatTimestampLabel(checkedAt),
    ok: response.ok === true,
    status: Number(response.status || 0),
    statusText: String(response.statusText || "").trim(),
    actionKey: "profiles",
    actionLabel: "Profiles",
    resultType: "profiles",
    selectionKey: String(payload?.selectionKey || "").trim(),
    programmerId,
    programmerName: String(payload?.programmerName || "").trim(),
    requestorId,
    tempPassMvpd,
    identityPresent: Boolean(identityPayload.headerValue),
    identityPreview: String(identityPayload.preview || "").trim(),
    endpointUrl,
    method: "GET",
    appGuid: String(restApp?.guid || "").trim(),
    appName: String(restApp?.appName || restApp?.guid || "").trim(),
    profileRows,
    profileCount: profileRows.length,
    responsePreview: truncateDebugText(responseText, 3000),
    responsePayload: parsedPayload ?? responseText,
    error: "",
  };

  if (!response.ok) {
    const errorMessage =
      firstNonEmptyString([
        parsedPayload?.code,
        parsedPayload?.details,
        parsedPayload?.message,
        normalizeHttpErrorMessage(responseText),
        result.statusText,
      ]) || `HTTP ${result.status}`;
    result.error = errorMessage;
    throw Object.assign(new Error(`TempPASS Profiles failed (${result.status}): ${errorMessage}`), {
      underparResult: result,
    });
  }

  return result;
}

async function fetchTempPassAuthorizeForSelection(payload = {}, services = null) {
  const programmerId = String(payload?.programmerId || "").trim();
  const requestorId = String(payload?.requestorId || "").trim();
  const tempPassMvpd = String(payload?.tempPassMvpd || "").trim();
  const resourceIds = Array.isArray(payload?.resourceIds)
    ? payload.resourceIds.map((item) => String(item || "").trim()).filter(Boolean)
    : parseRestV2ResourceIdInput(payload?.resourceIds || "");
  if (!programmerId || !requestorId || !tempPassMvpd) {
    throw new Error("TempPASS authorization requires programmer, requestor, and TempPASS MVPD values.");
  }
  if (resourceIds.length === 0) {
    throw new Error("Enter at least one resource for TempPASS authorization.");
  }

  const restApp = resolveTempPassRestV2AppInfo(programmerId, requestorId, services);
  if (!restApp?.guid) {
    throw new Error("No REST V2 registered application is available for the selected RequestorId.");
  }

  const identityPayload = resolveTempPassIdentityPayload(payload?.identityJson || "");
  const endpointUrl = `${REST_V2_BASE}/${encodeURIComponent(requestorId)}/decisions/authorize/${encodeURIComponent(tempPassMvpd)}`;
  const response = await fetchWithPremiumAuth(
    programmerId,
    restApp,
    endpointUrl,
    {
      method: "POST",
      mode: "cors",
      headers: buildTempPassRequestHeaders(requestorId, {
        identityHeaderValue: identityPayload.headerValue,
        extraHeaders: {
          "Content-Type": "application/json",
        },
      }),
      body: JSON.stringify({
        resources: resourceIds,
      }),
    },
    "refresh",
    buildTempPassDebugMeta(payload, {
      service: "temp-pass-authorize",
      scope: "temp-pass-authorize",
      endpointUrl,
      requiredServiceScope: REST_V2_SCOPE,
    })
  );

  const responseText = await response.text().catch(() => "");
  const parsedPayload = parseJsonText(responseText, null);
  const decisionRows = applyRestV2TopLevelErrorToDecisionRows(
    extractRestV2PreauthorizeDecisionRows(parsedPayload, resourceIds),
    parsedPayload
  );
  const decisionSummary = summarizeRestV2PreauthorizeRows(decisionRows, resourceIds);
  const checkedAt = Date.now();
  const result = {
    resultId: buildTempPassResultId("authorize"),
    checkedAt,
    checkedAtLabel: formatTimestampLabel(checkedAt),
    ok: response.ok === true,
    status: Number(response.status || 0),
    statusText: String(response.statusText || "").trim(),
    actionKey: "authorize",
    actionLabel: "Authorize",
    resultType: "authorize",
    selectionKey: String(payload?.selectionKey || "").trim(),
    programmerId,
    programmerName: String(payload?.programmerName || "").trim(),
    requestorId,
    tempPassMvpd,
    identityPresent: Boolean(identityPayload.headerValue),
    identityPreview: String(identityPayload.preview || "").trim(),
    endpointUrl,
    method: "POST",
    appGuid: String(restApp?.guid || "").trim(),
    appName: String(restApp?.appName || restApp?.guid || "").trim(),
    resourceIds,
    decisionRows,
    permitCount: decisionSummary.permitCount,
    denyCount: decisionSummary.denyCount,
    unknownCount: decisionSummary.unknownCount,
    allRequestedPermitted: decisionSummary.allRequestedPermitted,
    responsePreview: truncateDebugText(responseText, 3000),
    responsePayload: parsedPayload ?? responseText,
    error: "",
  };

  if (!response.ok) {
    const errorMessage =
      firstNonEmptyString([
        parsedPayload?.code,
        parsedPayload?.details,
        parsedPayload?.message,
        normalizeHttpErrorMessage(responseText),
        result.statusText,
      ]) || `HTTP ${result.status}`;
    result.error = errorMessage;
    throw Object.assign(new Error(`TempPASS Authorize failed (${result.status}): ${errorMessage}`), {
      underparResult: result,
    });
  }

  return result;
}

async function resetTempPassForSelection(payload = {}, services = null) {
  const programmerId = String(payload?.programmerId || "").trim();
  const requestorId = String(payload?.requestorId || "").trim();
  const tempPassMvpd = String(payload?.tempPassMvpd || "").trim();
  const actionKey = String(payload?.actionKey || "").trim().toLowerCase();
  const resetMode = actionKey === "reset-generic" ? "generic" : "device";
  const deviceId = String(payload?.deviceId || "").trim();
  const genericKey = String(payload?.genericKey || "").trim();
  const resetAllDevices = payload?.resetAllDevices === true;
  const resetAllGeneric = payload?.resetAllGeneric === true;
  if (!programmerId || !requestorId || !tempPassMvpd) {
    throw new Error("TempPASS reset requires programmer, requestor, and TempPASS MVPD values.");
  }
  if (resetMode === "device" && !resetAllDevices && !deviceId) {
    throw new Error("Enter a device identifier or explicitly enable reset-all-devices.");
  }
  if (resetMode === "generic" && !resetAllGeneric && !genericKey) {
    throw new Error("Enter a generic key hash or explicitly enable reset-all-generic.");
  }

  const resetApp = resolveTempPassResetAppInfo(programmerId, requestorId, services);
  if (!resetApp?.guid) {
    throw new Error("No Reset TempPASS registered application is available for the selected RequestorId.");
  }

  const endpointPath = resetMode === "generic" ? "/reset-tempass/v3/reset/generic" : "/reset-tempass/v3/reset";
  const endpointUrl = new URL(endpointPath, getActiveAdobePassEnvironment()?.mgmtBase || ADOBE_MGMT_BASE);
  endpointUrl.searchParams.set("requestor_id", requestorId);
  endpointUrl.searchParams.set("mvpd_id", tempPassMvpd);
  if (resetMode === "device") {
    endpointUrl.searchParams.set("device_id", resetAllDevices ? "all" : deviceId);
  } else if (!resetAllGeneric && genericKey) {
    endpointUrl.searchParams.set("key", genericKey);
  }

  const response = await fetchWithPremiumAuth(
    programmerId,
    resetApp,
    endpointUrl.toString(),
    {
      method: "DELETE",
      mode: "cors",
      headers: {
        Accept: "application/json",
      },
    },
    "refresh",
    buildTempPassDebugMeta(payload, {
      service: "reset-temp-pass",
      scope: resetMode === "generic" ? "reset-temp-pass-generic" : "reset-temp-pass-device",
      endpointUrl: endpointUrl.toString(),
      requiredServiceScope: PREMIUM_SERVICE_RESET_TEMPPASS_SCOPE,
    })
  );

  const responseText = await response.text().catch(() => "");
  const parsedPayload = parseJsonText(responseText, null);
  const checkedAt = Date.now();
  const result = {
    resultId: buildTempPassResultId(actionKey || "reset"),
    checkedAt,
    checkedAtLabel: formatTimestampLabel(checkedAt),
    ok: response.ok === true,
    status: Number(response.status || 0),
    statusText: String(response.statusText || "").trim(),
    actionKey: resetMode === "generic" ? "reset-generic" : "reset-device",
    actionLabel: resetMode === "generic" ? "Reset Generic" : "Reset Device",
    resultType: "reset",
    resetMode,
    selectionKey: String(payload?.selectionKey || "").trim(),
    programmerId,
    programmerName: String(payload?.programmerName || "").trim(),
    requestorId,
    tempPassMvpd,
    endpointUrl: endpointUrl.toString(),
    method: "DELETE",
    appGuid: String(resetApp?.guid || "").trim(),
    appName: String(resetApp?.appName || resetApp?.guid || "").trim(),
    deviceId: resetMode === "device" ? (resetAllDevices ? "all" : deviceId) : "",
    genericKey: resetMode === "generic" ? (resetAllGeneric ? "" : genericKey) : "",
    resetAllDevices,
    resetAllGeneric,
    responsePreview: truncateDebugText(responseText || "204 No Content", 3000),
    responsePayload: parsedPayload ?? responseText,
    error: "",
  };

  if (!response.ok) {
    const errorMessage =
      firstNonEmptyString([
        parsedPayload?.code,
        parsedPayload?.details,
        parsedPayload?.message,
        normalizeHttpErrorMessage(responseText),
        result.statusText,
      ]) || `HTTP ${result.status}`;
    result.error = errorMessage;
    throw Object.assign(new Error(`${result.actionLabel} failed (${result.status}): ${errorMessage}`), {
      underparResult: result,
    });
  }

  return result;
}

async function fetchRestV2ConfigurationForHarvest(harvest) {
  const serviceProviderId = String(harvest?.serviceProviderId || harvest?.requestorId || "").trim();
  const mvpd = String(harvest?.mvpd || "").trim();
  const programmerId = String(harvest?.programmerId || "").trim();
  if (!serviceProviderId) {
    throw new Error("Missing service provider from the selected MVPD profile.");
  }
  if (!programmerId) {
    throw new Error("Missing programmer context for configuration lookup.");
  }

  const appInfo = resolveRestV2AppInfoForHarvest(harvest);
  if (!appInfo?.guid) {
    throw new Error("Unable to resolve REST V2 application context for configuration lookup.");
  }

  const endpointUrl = `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/configuration`;
  const actionMode = BOBTOOLS_REST_V2_ACTION_CONFIGURATION;
  const actionLabel = getBobtoolsRestV2ActionLabel(actionMode);
  const flowId = resolveRestV2DebugFlowIdForHarvest(harvest);

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: "configuration-request",
    method: "GET",
    url: endpointUrl,
    scope: actionMode,
    requestorId: String(harvest?.requestorId || serviceProviderId || ""),
    mvpd,
    programmerId,
    appGuid: String(appInfo?.guid || ""),
    appName: String(appInfo?.appName || appInfo?.guid || ""),
    authMode: "dcr_client_bearer",
  });

  const response = await fetchWithPremiumAuth(
    programmerId,
    appInfo,
    endpointUrl,
    {
      method: "GET",
      mode: "cors",
      headers: buildRestV2Headers(serviceProviderId, {
        Accept: "application/json",
      }),
    },
    "refresh",
    {
      flowId,
      requestorId: String(harvest?.requestorId || serviceProviderId || ""),
      mvpd,
      scope: actionMode,
      service: "rest-v2-configuration",
      endpointUrl,
    }
  );

  const responseText = await response.text().catch(() => "");
  const parsedPayload = parseJsonText(responseText, null);
  const mvpds = normalizeRestV2MvpdCollection(parsedPayload || {});
  const checkedAt = Date.now();
  const result = {
    checkedAt,
    checkedAtLabel: formatTimestampLabel(checkedAt),
    ok: response.ok === true,
    status: Number(response.status || 0),
    statusText: String(response.statusText || "").trim(),
    programmerId,
    appGuid: String(appInfo?.guid || "").trim(),
    appName: String(appInfo?.appName || appInfo?.guid || "").trim(),
    authMode: "dcr_client_bearer",
    endpointUrl,
    method: "GET",
    apiAction: actionMode,
    apiActionLabel: actionLabel,
    resultType: "configuration",
    serviceProviderId,
    requestorId: String(harvest?.requestorId || serviceProviderId || "").trim(),
    mvpd,
    harvestKey: getRestV2HarvestRecordKey(harvest),
    harvestCapturedAt: Number(harvest?.harvestedAt || 0),
    subject: String(harvest?.subject || "").trim(),
    upstreamUserId: String(harvest?.upstreamUserId || "").trim(),
    userId: String(harvest?.userId || "").trim(),
    sessionId: String(harvest?.sessionId || "").trim(),
    profileKey: String(harvest?.profileKey || "").trim(),
    mvpdRows: mvpds.map((item) => ({
      id: String(item?.id || "").trim(),
      name: String(item?.name || "").trim(),
      isProxy: item?.isProxy === true,
      boardingStatus: String(item?.boardingStatus || "").trim(),
    })),
    mvpdCount: mvpds.length,
    responsePreview: truncateDebugText(responseText, 3000),
    responsePayload: parsedPayload ?? responseText,
    error: "",
  };

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: "configuration-response",
    method: "GET",
    url: endpointUrl,
    scope: actionMode,
    status: result.status,
    statusText: result.statusText,
    requestorId: result.requestorId,
    mvpd: result.mvpd,
    programmerId,
    appGuid: result.appGuid,
    appName: result.appName,
    authMode: result.authMode,
    mvpdCount: result.mvpdCount,
    responsePreview: result.responsePreview,
  });

  if (!response.ok) {
    const errorMessage =
      firstNonEmptyString([
        parsedPayload?.code,
        parsedPayload?.error?.code,
        parsedPayload?.error,
        parsedPayload?.details,
        parsedPayload?.message,
        normalizeHttpErrorMessage(responseText),
        result.statusText,
      ]) || `HTTP ${result.status}`;
    result.error = errorMessage;
    throw Object.assign(new Error(`${actionLabel} failed (${result.status}): ${errorMessage}`), { underparResult: result });
  }

  return result;
}

function buildRestV2EntitlementDecisionReasonText(row = null) {
  const errorCode = String(row?.errorCode || "").trim();
  const errorDetails = String(row?.errorDetails || "").trim();
  const sourceLabel = String(row?.source || "").trim() || "N/A";
  if (errorCode) {
    return `${errorCode}${errorDetails ? `: ${formatRestV2CompactValue(errorDetails, 90)}` : ""}`;
  }
  if (sourceLabel && sourceLabel !== "N/A" && sourceLabel.toLowerCase() !== "mvpd") {
    return `source=${sourceLabel}`;
  }
  return "No additional details";
}

function resolveRestV2ResourceIdChipLookup(options = {}) {
  const explicitChips = bobtoolsWorkspaceNormalizeQuickResourceChips(options?.resourceIdChips || []);
  const lookup = new Map();
  explicitChips.forEach((chip) => {
    const labelKey = String(chip?.label || "").trim().toLowerCase();
    const rawKey = String(chip?.rawValue || "").trim().toLowerCase();
    if (labelKey && !lookup.has(labelKey)) {
      lookup.set(labelKey, chip);
    }
    if (rawKey && !lookup.has(rawKey)) {
      lookup.set(rawKey, chip);
    }
  });
  if (lookup.size > 0) {
    return lookup;
  }
  return bobtoolsWorkspaceBuildResourceIdChipLookup(options?.programmerId, options?.requestorId, options?.mvpd);
}

function resolveRestV2ResourceIdChip(resourceId = "", options = {}) {
  const normalized = String(resourceId || "").trim();
  if (!normalized) {
    return {
      label: "",
      rawValue: "",
      title: "",
    };
  }
  const lookup =
    options?.resourceIdLookup instanceof Map ? options.resourceIdLookup : resolveRestV2ResourceIdChipLookup(options);
  const matched = lookup.get(normalized.toLowerCase()) || null;
  const label = String(matched?.label || normalized).trim() || normalized;
  const rawValue = String(matched?.rawValue || "").trim();
  return {
    label,
    rawValue,
    title: rawValue && rawValue !== label ? `Adobe TMSID: ${rawValue}` : "",
  };
}

function renderRestV2ResourceIdListMarkup(resourceIds = [], options = {}) {
  const chips = (Array.isArray(resourceIds) ? resourceIds : [])
    .map((resourceId) =>
      resolveRestV2ResourceIdChip(resourceId, {
        ...options,
      })
    )
    .filter((chip) => chip.label);
  if (chips.length === 0) {
    return "N/A";
  }
  const displayText = chips.map((chip) => chip.label).join(", ");
  const hoverLines = chips
    .filter((chip) => chip.title)
    .map((chip) => `${chip.label} -> ${chip.rawValue}`);
  if (hoverLines.length === 0) {
    return escapeHtml(displayText);
  }
  return `<span title="${escapeHtml(hoverLines.join("\n"))}">${escapeHtml(displayText)}</span>`;
}

function renderRestV2EntitlementDecisionItems(decisionRows = [], options = {}) {
  const resourceIdLookup = resolveRestV2ResourceIdChipLookup(options);
  return (Array.isArray(decisionRows) ? decisionRows : [])
    .map((row) => {
      const decisionRaw = String(row?.decision || "").trim().toLowerCase();
      const cssClass =
        decisionRaw === "permit" ? "permit" : decisionRaw === "deny" ? "deny" : decisionRaw ? "unknown" : "unknown";
      const reasonText = buildRestV2EntitlementDecisionReasonText(row);
      const resourceChip = resolveRestV2ResourceIdChip(row?.resourceId, {
        ...options,
        resourceIdLookup,
      });
      return `
          <li class="rest-v2-entitlement-decision ${cssClass}">
            <span class="rest-v2-entitlement-decision-resource"${resourceChip.title ? ` title="${escapeHtml(resourceChip.title)}"` : ""}>${escapeHtml(
              resourceChip.label
            )}</span>
            <span class="rest-v2-entitlement-decision-badge ${cssClass}">${escapeHtml(String(row?.decision || "Unknown"))}</span>
            <span class="rest-v2-entitlement-decision-reason">${escapeHtml(reasonText)}</span>
          </li>
        `;
    })
    .join("");
}

function resolveRestV2InlineSplunkColumns(result = null) {
  const explicitColumns = (Array.isArray(result?.columns) ? result.columns : [])
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  if (explicitColumns.length > 0) {
    return explicitColumns.slice(0, REST_V2_SPLUNK_INLINE_MAX_COLUMNS);
  }
  const sampleRows = Array.isArray(result?.rows) ? result.rows : [];
  const discovered = [];
  sampleRows.forEach((row) => {
    if (!row || typeof row !== "object") {
      return;
    }
    Object.keys(row).forEach((key) => {
      const normalized = String(key || "").trim();
      if (!normalized || discovered.includes(normalized)) {
        return;
      }
      discovered.push(normalized);
    });
  });
  return discovered.slice(0, REST_V2_SPLUNK_INLINE_MAX_COLUMNS);
}

function renderRestV2InlineSplunkNetworkEvents(events = []) {
  const rows = (Array.isArray(events) ? events : []).slice(0, 8);
  if (rows.length === 0) {
    return "";
  }
  return `
    <ul class="rest-v2-splunk-inline-network-list">
      ${rows
        .map((event) => {
          const phase = String(event?.phase || "").trim() || "network";
          const method = String(event?.method || "").trim().toUpperCase() || "GET";
          const url = String(event?.url || "").trim();
          const status = Number(event?.status || 0);
          const statusText = String(event?.statusText || "").trim();
          const duration = Number(event?.durationMs || 0);
          return `<li class="rest-v2-splunk-inline-network-item">${escapeHtml(
            `${phase}: ${method} ${url} | HTTP ${status || 0} ${statusText} | ${duration}ms`
          )}</li>`;
        })
        .join("")}
    </ul>
  `;
}

function renderRestV2InlineSplunkReport(result = null) {
  if (!result || typeof result !== "object") {
    return "";
  }
  const checkedAt = formatTimestampLabel(result?.checkedAt);
  const query = String(result?.queryContext?.search || "").trim();
  const sid = String(result?.sid || "").trim();
  const displayedRows = Number(result?.displayedRows || 0);
  const totalRows = Number(result?.totalRows || 0);
  const rowSummary =
    totalRows > displayedRows
      ? `${displayedRows} shown of ${totalRows} rows`
      : `${displayedRows} row${displayedRows === 1 ? "" : "s"}`;
  const networkMarkup = renderRestV2InlineSplunkNetworkEvents(result?.networkEvents || []);
  if (result.ok !== true) {
    return `
      <p class="rest-v2-splunk-inline-head">
        <strong>Checked:</strong> ${escapeHtml(checkedAt)} | <strong>SID:</strong> ${escapeHtml(sid || "N/A")}
      </p>
      <p class="rest-v2-splunk-inline-query"><strong>Query:</strong> ${escapeHtml(query || "(empty)")}</p>
      <p class="rest-v2-splunk-inline-error">${escapeHtml(String(result?.error || "Splunk query failed."))}</p>
      ${networkMarkup}
    `;
  }

  const columns = resolveRestV2InlineSplunkColumns(result);
  const rows = (Array.isArray(result?.rows) ? result.rows : []).slice(0, REST_V2_SPLUNK_INLINE_MAX_ROWS);
  const tableMarkup =
    columns.length === 0 || rows.length === 0
      ? '<p class="rest-v2-splunk-inline-empty">No Splunk events were returned for this upstreamUserID.</p>'
      : `
      <div class="rest-v2-splunk-inline-table-wrap">
        <table class="rest-v2-splunk-inline-table">
          <thead>
            <tr>${columns.map((column) => `<th>${escapeHtml(column)}</th>`).join("")}</tr>
          </thead>
          <tbody>
            ${rows
              .map((row) => {
                const cells = columns
                  .map((column) => `<td>${escapeHtml(String(row?.[column] == null ? "" : row[column]))}</td>`)
                  .join("");
                return `<tr>${cells}</tr>`;
              })
              .join("")}
          </tbody>
        </table>
      </div>
    `;

  return `
    <p class="rest-v2-splunk-inline-head">
      <strong>Checked:</strong> ${escapeHtml(checkedAt)} | <strong>SID:</strong> ${escapeHtml(sid || "N/A")} | <strong>Rows:</strong> ${escapeHtml(
    rowSummary
  )}
    </p>
    <p class="rest-v2-splunk-inline-query"><strong>Query:</strong> ${escapeHtml(query || "(empty)")}</p>
    ${networkMarkup}
    ${tableMarkup}
  `;
}

function renderRestV2ProfileHistoryTool(section, harvestList = []) {
  const tool = section?.querySelector(".rest-v2-profile-history-tool");
  const toggleButton = section?.querySelector(".rest-v2-profile-tool-toggle");
  const bodyElement = section?.querySelector(".rest-v2-profile-tool-body");
  const countElement = section?.querySelector(".rest-v2-profile-count");
  const exportButton = section?.querySelector(".rest-v2-profile-export-btn");
  const listElement = section?.querySelector(".rest-v2-profile-list");
  if (!tool || !listElement || !countElement) {
    return null;
  }

  const sectionState = getRestV2SectionState(section);
  const records = (Array.isArray(harvestList) ? harvestList : [])
    .filter((item) => item && typeof item === "object")
    .map((harvest, index) => {
      const requestorId = String(harvest?.requestorId || "").trim();
      const mvpdId = String(harvest?.mvpd || "").trim();
      const mvpdMeta =
        String(harvest?.mvpdName || "").trim() && mvpdId
          ? {
              id: mvpdId,
              name: String(harvest.mvpdName || "").trim(),
            }
          : null;
      const requestorMvpdLabel = formatRestV2RequestorMvpdDisplay(requestorId, mvpdId, mvpdMeta);
      return {
        harvest,
        key: getRestV2HarvestRecordKey(harvest, index),
        capturedAtLabel: formatTimestampLabel(harvest?.harvestedAt),
        requestorId,
        mvpdId,
        mvpdMeta,
        requestorMvpdLabel,
        mvpdLabel: getRestV2MvpdPickerLabel(requestorId, mvpdId, mvpdMeta),
        title: requestorMvpdLabel,
        subtitle: firstNonEmptyString([
          String(harvest?.upstreamUserId || "").trim(),
          String(harvest?.userId || "").trim(),
          String(harvest?.subject || "").trim(),
          "No subject",
        ]),
        statusLabel: String(harvest?.profileCheckOutcome || "").trim() || "unknown",
      };
    });

  if (records.length === 0) {
    tool.hidden = true;
    tool.classList.remove("has-selected-profile");
    countElement.textContent = "0";
    if (exportButton) {
      exportButton.disabled = true;
    }
    if (toggleButton) {
      toggleButton.setAttribute("aria-expanded", "false");
    }
    if (bodyElement) {
      bodyElement.hidden = true;
    }
    listElement.innerHTML = "";
    sectionState.selectedHarvestKey = "";
    sectionState.expandedHarvestKey = "";
    sectionState.hasProfileExpansionChoice = false;
    sectionState.lastSplunkResult = null;
    sectionState.lastSplunkHarvestKey = "";
    return null;
  }

  tool.hidden = false;
  countElement.textContent = String(records.length);
  if (exportButton) {
    exportButton.disabled = false;
  }
  let selected = records.find((item) => item.key === sectionState.selectedHarvestKey) || records[0];
  sectionState.selectedHarvestKey = selected.key;
  tool.classList.toggle("has-selected-profile", Boolean(selected));
  let expandedHarvestKey = String(sectionState.expandedHarvestKey || "").trim();
  if (expandedHarvestKey && !records.some((item) => item.key === expandedHarvestKey)) {
    expandedHarvestKey = "";
  }
  if (!expandedHarvestKey && sectionState.hasProfileExpansionChoice !== true) {
    expandedHarvestKey = "";
  }
  sectionState.expandedHarvestKey = expandedHarvestKey;

  listElement.innerHTML = records
    .map(
      (record) => {
        const isSelected = record.key === selected.key;
        const isExpanded = record.key === expandedHarvestKey;
        const selectedHarvest = record.harvest;
        const profileCount = Number(selectedHarvest?.profileCount || 0);
        const profileKey = String(selectedHarvest?.profileKey || "").trim() || "N/A";
        const sessionId = String(selectedHarvest?.sessionId || "").trim() || "N/A";
        const profileCheck =
          selectedHarvest?.profileCheck && typeof selectedHarvest.profileCheck === "object" ? selectedHarvest.profileCheck : {};
        const profileTtlText = `${
          Number(selectedHarvest?.notBeforeMs || 0) > 0 ? formatTimestampLabel(selectedHarvest.notBeforeMs) : "N/A"
        } -> ${Number(selectedHarvest?.notAfterMs || 0) > 0 ? formatTimestampLabel(selectedHarvest.notAfterMs) : "N/A"}`;
        const profileStatusText = `${String(selectedHarvest?.profileCheckOutcome || "unknown")} | HTTP ${
          Number(profileCheck?.status || 0) || 0
        } ${String(profileCheck?.statusText || "").trim()}`.trim();
        const attributes =
          selectedHarvest?.profileAttributes && typeof selectedHarvest.profileAttributes === "object"
            ? Object.entries(selectedHarvest.profileAttributes)
            : [];
        const preauthzChecks = getRestV2ProfilePreauthzChecks(selectedHarvest);
        const factRows = [
          ["Requestor", String(selectedHarvest?.requestorId || "").trim() || "N/A"],
          ["Service Provider", String(selectedHarvest?.serviceProviderId || "").trim() || "N/A"],
          ["MVPD", String(record?.mvpdLabel || "").trim() || "N/A"],
          [
            "Subject",
            firstNonEmptyString([String(selectedHarvest?.subject || "").trim(), String(record.subtitle || "").trim(), "N/A"]),
          ],
          ["Session ID", sessionId],
          ["Profiles Returned", String(profileCount)],
          ["Profile TTL", profileTtlText],
          ["Profile Check", profileStatusText || "N/A"],
          ["Next Action", "Can I watch? is shown only when an active MVPD profile session is detected."],
        ];
        const factCards = factRows
          .map(
            ([label, value]) => `
          <div class="rest-v2-profile-fact">
            <span class="rest-v2-profile-fact-label">${escapeHtml(label)}</span>
            <span class="rest-v2-profile-fact-value">${escapeHtml(formatRestV2CompactValue(String(value || ""), 120) || "N/A")}</span>
          </div>
        `
          )
          .join("");
        const attributeMarkup =
          attributes.length > 0
            ? `
            <div class="rest-v2-profile-attributes">
              <p class="rest-v2-profile-attributes-title">Profile Attributes</p>
              <ul class="rest-v2-profile-attributes-list">
                ${attributes
                  .map(
                    ([key, value]) => `
                  <li class="rest-v2-profile-attributes-item">
                    <span class="rest-v2-profile-attributes-key">${escapeHtml(String(key || "").trim())}</span>
                    <span class="rest-v2-profile-attributes-value">${escapeHtml(
                      formatRestV2CompactValue(String(value || "").trim(), 120) || "N/A"
                    )}</span>
                  </li>
                `
                  )
                  .join("")}
              </ul>
            </div>
          `
            : `<p class="rest-v2-profile-attributes-empty">No profile attributes returned.</p>`;
        const preauthzMarkup =
          preauthzChecks.length > 0
            ? `
            <div class="rest-v2-profile-preauthz">
              <p class="rest-v2-profile-preauthz-title">Preauthz Checks</p>
              <ul class="rest-v2-profile-preauthz-list">
                ${preauthzChecks
                  .map((check, checkIndex) => {
                    const verdict = check?.allRequestedPermitted ? "YES" : "NO";
                    const verdictClass = check?.allRequestedPermitted ? "success" : "error";
                    const resultSummary =
                      check?.error && check?.ok !== true
                        ? String(check.error || "").trim()
                        : `${Number(check?.permitCount || 0)} permit, ${Number(check?.denyCount || 0)} deny, ${Number(
                            check?.unknownCount || 0
                          )} unknown`;
                    const resourceLabel = renderRestV2ResourceIdListMarkup(check?.resourceIds || [], {
                      resourceIdChips: check?.resourceIdChips,
                      programmerId,
                      requestorId: String(selectedHarvest?.requestorId || "").trim(),
                      mvpd: String(selectedHarvest?.mvpd || "").trim(),
                    });
                    const decisionItems = renderRestV2EntitlementDecisionItems(check?.decisionRows || [], {
                      resourceIdChips: check?.resourceIdChips,
                      programmerId,
                      requestorId: String(selectedHarvest?.requestorId || "").trim(),
                      mvpd: String(selectedHarvest?.mvpd || "").trim(),
                    });
                    return `
                  <li class="rest-v2-profile-preauthz-item">
                    <p class="rest-v2-profile-preauthz-head">
                      <span>Check #${checkIndex + 1} | ${escapeHtml(formatTimestampLabel(check?.checkedAt))}</span>
                      <span class="rest-v2-profile-preauthz-verdict ${verdictClass}">Can I watch? ${escapeHtml(verdict)}</span>
                    </p>
                    <p class="rest-v2-profile-preauthz-meta"><strong>Request:</strong> ${resourceLabel}</p>
                    <p class="rest-v2-profile-preauthz-result">${escapeHtml(resultSummary)}</p>
                    <ul class="rest-v2-entitlement-decision-list">${decisionItems}</ul>
                  </li>
                `;
                  })
                  .join("")}
              </ul>
            </div>
          `
            : `<p class="rest-v2-profile-preauthz-empty">No Preauthz Checks yet. Select this profile and run Can I watch?.</p>`;
        return `
      <li class="rest-v2-profile-item${isSelected ? " active" : ""}${isExpanded ? " expanded" : ""}">
        <article class="rest-v2-profile-card">
          <div class="rest-v2-profile-card-head">
            <button
              type="button"
              class="rest-v2-profile-card-toggle${isSelected ? " active" : ""}"
              data-harvest-key="${escapeHtml(record.key)}"
              aria-expanded="${isExpanded ? "true" : "false"}"
            >
              <span class="rest-v2-profile-entry-title">
                <span>${escapeHtml(record.title)}</span>
                <span class="rest-v2-profile-collapse-icon" aria-hidden="true">▼</span>
              </span>
              <span class="rest-v2-profile-entry-meta">${escapeHtml(record.subtitle)} | ${escapeHtml(record.capturedAtLabel)}</span>
            </button>
            <button
              type="button"
              class="rest-v2-profile-delete-btn"
              data-harvest-key="${escapeHtml(record.key)}"
              aria-label="Delete captured MVPD profile"
              title="Delete captured MVPD profile"
            >×</button>
          </div>
          <div class="rest-v2-profile-card-body"${isExpanded ? "" : " hidden"}>
            <p class="rest-v2-profile-details-meta">
              subject=${escapeHtml(record.subtitle)} | profileKey=${escapeHtml(profileKey)} | session=${escapeHtml(
          sessionId
        )} | profiles=${escapeHtml(String(profileCount))} | status=${escapeHtml(record.statusLabel)}
            </p>
            <div class="rest-v2-profile-facts-grid">${factCards}</div>
            ${attributeMarkup}
            ${preauthzMarkup}
          </div>
        </article>
      </li>
    `
      }
    )
    .join("");

  const collapsed = sectionState.profileToolCollapsed === true;
  if (toggleButton) {
    toggleButton.setAttribute("aria-expanded", collapsed ? "false" : "true");
  }
  if (bodyElement) {
    bodyElement.hidden = collapsed;
  }
  return selected.harvest;
}

function renderRestV2EntitlementTool(section, programmerId, selectedHarvest = null, options = {}) {
  const tool = section?.querySelector(".rest-v2-entitlement-tool");
  const toggleButton = section?.querySelector(".rest-v2-entitlement-tool-toggle");
  const bodyElement = section?.querySelector(".rest-v2-entitlement-tool-body");
  const contextElement = section?.querySelector(".rest-v2-entitlement-context");
  const copyUpstreamButton = section?.querySelector(".rest-v2-entitlement-copy-upstream-btn");
  const splunkButton = section?.querySelector(".rest-v2-entitlement-splunk-btn");
  const inputElement = section?.querySelector(".rest-v2-resource-input");
  const buttonElement = section?.querySelector(".rest-v2-entitlement-go-btn");
  const statusElement = section?.querySelector(".rest-v2-entitlement-status");
  const summaryElement = section?.querySelector(".rest-v2-entitlement-summary");
  const splunkReportTool = section?.querySelector(".rest-v2-splunk-report-tool");
  const splunkReportSummary = section?.querySelector(".rest-v2-splunk-report-summary");
  if (!tool || !contextElement || !inputElement || !buttonElement || !statusElement || !summaryElement) {
    return;
  }

  const sectionState = getRestV2SectionState(section);
  const renderSplunkInlineBox = (selectedHarvestKey = "", hasUpstream = false) => {
    if (!splunkReportTool || !splunkReportSummary) {
      return;
    }
    const activeResult =
      sectionState.lastSplunkResult &&
      typeof sectionState.lastSplunkResult === "object" &&
      String(sectionState.lastSplunkHarvestKey || "").trim() === selectedHarvestKey
        ? sectionState.lastSplunkResult
        : null;
    if (!selectedHarvestKey || !hasUpstream) {
      splunkReportTool.hidden = true;
      splunkReportSummary.innerHTML = "";
      return;
    }
    splunkReportTool.hidden = false;
    if (activeResult) {
      splunkReportSummary.innerHTML = renderRestV2InlineSplunkReport(activeResult);
      return;
    }
    splunkReportSummary.innerHTML =
      '<p class="rest-v2-splunk-inline-empty">Run SPLUNK to load query results for this upstreamUserID.</p>';
  };

  const activeSession = options?.activeSession === true;
  if (!selectedHarvest || typeof selectedHarvest !== "object") {
    tool.hidden = true;
    if (toggleButton) {
      toggleButton.setAttribute("aria-expanded", "false");
    }
    if (bodyElement) {
      bodyElement.hidden = true;
    }
    contextElement.textContent = "";
    if (copyUpstreamButton) {
      copyUpstreamButton.hidden = true;
      copyUpstreamButton.disabled = true;
      copyUpstreamButton.dataset.copyValue = "";
    }
    if (splunkButton) {
      splunkButton.hidden = true;
      splunkButton.disabled = true;
      splunkButton.classList.remove("net-busy");
    }
    statusElement.hidden = true;
    statusElement.classList.remove("success", "error");
    statusElement.textContent = "";
    summaryElement.hidden = true;
    summaryElement.innerHTML = "";
    inputElement.disabled = true;
    buttonElement.disabled = true;
    renderSplunkInlineBox("", false);
    return;
  }

  tool.hidden = false;
  const collapsed = sectionState.entitlementToolCollapsed === true;
  if (toggleButton) {
    toggleButton.setAttribute("aria-expanded", collapsed ? "false" : "true");
  }
  if (bodyElement) {
    bodyElement.hidden = collapsed;
  }
  const selectedRequestorId = String(selectedHarvest?.requestorId || "").trim();
  const selectedMvpdId = String(selectedHarvest?.mvpd || "").trim();
  const selectedMvpdMeta =
    String(selectedHarvest?.mvpdName || "").trim() && selectedMvpdId
      ? {
          id: selectedMvpdId,
          name: String(selectedHarvest.mvpdName || "").trim(),
        }
      : null;
  const selectedRequestorMvpdLabel = formatRestV2RequestorMvpdDisplay(selectedRequestorId, selectedMvpdId, selectedMvpdMeta);
  const selectedUpstreamUserId = String(selectedHarvest?.upstreamUserId || "").trim();
  const selectedUpstreamChunk = `upstreamUserID=${selectedUpstreamUserId || "N/A"}`;
  contextElement.innerHTML = `Using selected profile <strong class="rest-v2-entitlement-upstream">${escapeHtml(
    selectedUpstreamChunk
  )}</strong> | ${escapeHtml(selectedRequestorMvpdLabel)}.`;
  if (copyUpstreamButton) {
    const canCopyUpstreamUserId = Boolean(selectedUpstreamUserId);
    copyUpstreamButton.hidden = !canCopyUpstreamUserId;
    copyUpstreamButton.disabled = !canCopyUpstreamUserId;
    copyUpstreamButton.dataset.copyValue = canCopyUpstreamUserId ? `upstreamUserID=${selectedUpstreamUserId}` : "";
    copyUpstreamButton.classList.remove("copied");
    const copyLabel = "Copy upstreamUserID to clipboard";
    copyUpstreamButton.title = copyLabel;
    copyUpstreamButton.setAttribute("aria-label", copyLabel);
  }
  if (splunkButton) {
    const hasUpstreamUserId = Boolean(selectedUpstreamUserId);
    const splunkBusy = sectionState.splunkBusy === true;
    splunkButton.hidden = !hasUpstreamUserId;
    splunkButton.disabled = !hasUpstreamUserId || splunkBusy;
    splunkButton.classList.toggle("net-busy", splunkBusy);
    const baseLabel = "Run Splunk RCA lookup in REST Workspace";
    const busyLabel = "Running Splunk RCA lookup in REST Workspace";
    splunkButton.title = splunkBusy ? busyLabel : baseLabel;
    splunkButton.setAttribute("aria-label", splunkBusy ? busyLabel : baseLabel);
  }

  const harvestKey = getRestV2HarvestRecordKey(selectedHarvest);
  renderSplunkInlineBox(harvestKey, Boolean(selectedUpstreamUserId));
  const history = getRestV2PreauthorizeHistoryForProgrammer(programmerId);
  const historyResult = history.find((item) => String(item?.harvestKey || "") === harvestKey) || null;
  const profileCheckResult = getRestV2ProfilePreauthzChecks(selectedHarvest)[0] || null;
  const lastResult =
    sectionState.lastEntitlementResult &&
    typeof sectionState.lastEntitlementResult === "object" &&
    String(sectionState.lastEntitlementResult?.harvestKey || "").trim() === harvestKey
      ? sectionState.lastEntitlementResult
      : null;
  const currentResult =
    lastResult ||
    (profileCheckResult && Number(profileCheckResult?.checkedAt || 0) >= Number(historyResult?.checkedAt || 0)
      ? profileCheckResult
      : historyResult);
  const suggestedResourceInput = Array.isArray(currentResult?.resourceIds)
    ? currentResult.resourceIds.map((item) => String(item || "").trim()).filter(Boolean).join(", ")
    : "";

  const busy = sectionState.entitlementBusy === true;
  if (!busy && document.activeElement !== inputElement) {
    const inputBoundToSelectedHarvest = sectionState.resourceInputHarvestKey === harvestKey;
    const hasTypedInput = String(sectionState.resourceInput || "").trim().length > 0;
    const nextInput = inputBoundToSelectedHarvest && hasTypedInput ? sectionState.resourceInput : suggestedResourceInput;
    sectionState.resourceInput = nextInput;
    sectionState.resourceInputHarvestKey = harvestKey;
    inputElement.value = nextInput;
  }
  const interactive = busy ? false : activeSession;
  inputElement.disabled = !interactive;
  buttonElement.disabled = !interactive;
  buttonElement.textContent = busy ? "GO..." : "GO";

  if (currentResult && typeof currentResult === "object" && !busy) {
    sectionState.lastEntitlementResult = currentResult;
    const authLabel =
      String(currentResult.authMode || "").trim() === "dcr_client_bearer"
        ? `Auth: DCR bearer (${String(currentResult.appName || currentResult.appGuid || "REST V2 app").trim() || "REST V2 app"})`
        : "Auth: unknown";
    statusElement.classList.remove("success", "error");
    if (!activeSession) {
      statusElement.hidden = false;
      statusElement.classList.add("error");
      statusElement.textContent =
        "Can I watch? is available only while an MVPD profile session is active. Click LOGIN to begin a fresh MVPD login test.";
    } else {
      const hasResultError = currentResult.error && !currentResult.ok;
      if (hasResultError) {
        statusElement.hidden = false;
        statusElement.classList.add("error");
        statusElement.textContent = `Can I watch? NO (${currentResult.error})`;
      } else {
        statusElement.hidden = true;
        statusElement.textContent = "";
      }
    }

    summaryElement.hidden = false;
    const decisionRows = Array.isArray(currentResult.decisionRows) ? currentResult.decisionRows : [];
    const hasAuthenticatedProfileMissing = hasRestV2AuthenticatedProfileMissingSignal(currentResult);
    const requestMarkup = renderRestV2ResourceIdListMarkup(currentResult.resourceIds || [], {
      resourceIdChips: currentResult.resourceIdChips,
      programmerId: currentResult.programmerId || programmerId,
      requestorId: currentResult.requestorId || selectedRequestorId,
      mvpd: currentResult.mvpd || selectedMvpdId,
    });
    const summaryItems = renderRestV2EntitlementDecisionItems(decisionRows, {
      resourceIdChips: currentResult.resourceIdChips,
      programmerId: currentResult.programmerId || programmerId,
      requestorId: currentResult.requestorId || selectedRequestorId,
      mvpd: currentResult.mvpd || selectedMvpdId,
    });
    const guidanceMarkup = hasAuthenticatedProfileMissing
      ? `<p class="rest-v2-entitlement-guidance">Profile is no longer active for this MVPD session. Run LOGIN again for this MVPD profile, then retry Can I watch?.</p>`
      : "";
    summaryElement.innerHTML = `
      <p class="rest-v2-entitlement-summary-head">
        <strong>Request:</strong> ${requestMarkup}
        <span> | ${escapeHtml(formatTimestampLabel(currentResult.checkedAt))}</span>
      </p>
      ${guidanceMarkup}
      <ul class="rest-v2-entitlement-decision-list">${summaryItems}</ul>
      <p class="rest-v2-entitlement-summary-meta">${escapeHtml(
        `${authLabel} | POST ${String(currentResult.endpointUrl || "").trim()} | HTTP ${Number(currentResult.status || 0)} ${
          String(currentResult.statusText || "").trim() || ""
        }`
      )}</p>
    `;
    return;
  }

  statusElement.hidden = false;
  statusElement.classList.remove("success", "error");
  if (!activeSession) {
    statusElement.classList.add("error");
    statusElement.textContent =
      "Can I watch? is available only while an MVPD profile session is active. Click LOGIN to begin a fresh MVPD login test.";
  } else {
    statusElement.textContent = busy
      ? "Running entitlement check against REST V2 Decisions..."
      : "Enter resourceIds, then press Enter or GO to check authorization.";
  }
  summaryElement.hidden = true;
  summaryElement.innerHTML = "";
}

function syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo) {
  if (!section) {
    return;
  }
  const context = buildCurrentRestV2SelectionContext(programmer, appInfo);
  const programmerId = context?.ok
    ? String(context.programmerId || "").trim()
    : String(programmer?.programmerId || resolveSelectedProgrammer()?.programmerId || "").trim();

  if (!programmerId) {
    const historyTool = section.querySelector(".rest-v2-profile-history-tool");
    const entitlementTool = section.querySelector(".rest-v2-entitlement-tool");
    const splunkTool = section.querySelector(".rest-v2-splunk-report-tool");
    if (historyTool) {
      historyTool.hidden = true;
    }
    if (entitlementTool) {
      entitlementTool.hidden = true;
    }
    if (splunkTool) {
      splunkTool.hidden = true;
    }
    return;
  }

  const harvestList = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
  const selectedHarvest = renderRestV2ProfileHistoryTool(section, harvestList);
  const selectedHarvestContext = buildRestV2ContextFromHarvest(selectedHarvest);
  const activeWindowEntry = selectedHarvestContext ? getRestV2ActiveProfileWindowEntryForContext(selectedHarvestContext) : null;
  renderRestV2EntitlementTool(section, programmerId, selectedHarvest, {
    activeSession: activeWindowEntry?.active === true,
  });
}

async function runRestV2EntitlementCheck(section, programmer, appInfo) {
  if (!section) {
    return;
  }
  const sectionState = getRestV2SectionState(section);
  if (sectionState.entitlementBusy === true) {
    return;
  }

  const programmerId = String(programmer?.programmerId || resolveSelectedProgrammer()?.programmerId || "").trim();
  if (!programmerId) {
    setStatus("Select a media company before running entitlement checks.", "error");
    return;
  }

  const harvestList = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
  if (harvestList.length === 0) {
    setStatus("No successful MVPD profile captures are available yet.", "error");
    return;
  }

  let selectedHarvest =
    harvestList.find((item, index) => getRestV2HarvestRecordKey(item, index) === sectionState.selectedHarvestKey) || harvestList[0];
  sectionState.selectedHarvestKey = getRestV2HarvestRecordKey(selectedHarvest, 0);
  sectionState.resourceInputHarvestKey = sectionState.selectedHarvestKey;
  const selectedHarvestContext = buildRestV2ContextFromHarvest(selectedHarvest);
  if (!selectedHarvestContext?.ok) {
    sectionState.lastEntitlementResult = {
      checkedAt: Date.now(),
      ok: false,
      status: 0,
      statusText: "",
      endpointUrl: "",
      serviceProviderId: String(selectedHarvest?.serviceProviderId || selectedHarvest?.requestorId || "").trim(),
      requestorId: String(selectedHarvest?.requestorId || "").trim(),
      mvpd: String(selectedHarvest?.mvpd || "").trim(),
      harvestKey: sectionState.selectedHarvestKey,
      resourceIds: [],
      decisionRows: [],
      permitCount: 0,
      denyCount: 0,
      unknownCount: 0,
      allRequestedPermitted: false,
      responsePayload: {},
      error: "Selected MVPD profile is missing REST V2 context. Re-run LOGIN for this MVPD profile and try again.",
      programmerId,
    };
    syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
    return;
  }
  const context = selectedHarvestContext;
  let activeWindowEntry = getRestV2ActiveProfileWindowEntryForContext(context);
  if (activeWindowEntry?.active !== true) {
    activeWindowEntry = await ensureRestV2ActiveProfileWindowForContext(section, programmer, appInfo, {
      context,
      force: true,
    });
    if (activeWindowEntry?.active !== true) {
      sectionState.lastEntitlementResult = {
        checkedAt: Date.now(),
        ok: false,
        status: 0,
        statusText: "",
        endpointUrl: "",
        serviceProviderId: String(selectedHarvest?.serviceProviderId || selectedHarvest?.requestorId || "").trim(),
        requestorId: String(selectedHarvest?.requestorId || "").trim(),
        mvpd: String(selectedHarvest?.mvpd || "").trim(),
        harvestKey: sectionState.selectedHarvestKey,
        resourceIds: [],
        decisionRows: [],
        permitCount: 0,
        denyCount: 0,
        unknownCount: 0,
        allRequestedPermitted: false,
        responsePayload: {},
        error:
          "Can I watch? is available only while an authenticated MVPD profile session is active. Run LOGIN first.",
        programmerId,
      };
      syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
      return;
    }
  }

  const inputElement = section.querySelector(".rest-v2-resource-input");
  if (inputElement && document.activeElement === inputElement) {
    sectionState.resourceInput = String(inputElement.value || "");
  }
  const resourceIds = parseRestV2ResourceIdInput(sectionState.resourceInput);
  if (resourceIds.length === 0) {
    sectionState.lastEntitlementResult = {
      checkedAt: Date.now(),
      ok: false,
      status: 0,
      statusText: "",
      endpointUrl: "",
      serviceProviderId: String(selectedHarvest?.serviceProviderId || selectedHarvest?.requestorId || "").trim(),
      requestorId: String(selectedHarvest?.requestorId || "").trim(),
      mvpd: String(selectedHarvest?.mvpd || "").trim(),
      harvestKey: sectionState.selectedHarvestKey,
      resourceIds: [],
      decisionRows: [],
      permitCount: 0,
      denyCount: 0,
      unknownCount: 0,
      allRequestedPermitted: false,
      responsePayload: {},
      error: "Enter at least one resourceId (comma-delimited supported).",
      programmerId,
    };
    sectionState.resourceInputHarvestKey = sectionState.selectedHarvestKey;
    syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
    return;
  }
  sectionState.resourceInput = resourceIds.join(", ");
  sectionState.resourceInputHarvestKey = sectionState.selectedHarvestKey;

  sectionState.entitlementBusy = true;
  sectionState.lastEntitlementResult = null;
  syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);

  try {
    const preflightContext = buildRestV2ContextFromHarvest(selectedHarvest);
    if (!preflightContext) {
      throw new Error("Selected MVPD profile is missing REST V2 application context.");
    }
    const preflightFlowId = resolveRestV2DebugFlowIdForHarvest(selectedHarvest);
    const preflight = await fetchRestV2ProfileCheckResult(
      preflightContext,
      preflightFlowId,
      "profiles-preauthorize-preflight"
    );
    if (preflight?.harvestedProfile && isUsableRestV2ProfileHarvest(preflight.harvestedProfile)) {
      storeRestV2ProfileHarvest(preflightContext, preflight, preflightFlowId);
    }
    if (!preflight?.ok || Number(preflight?.profileCount || 0) <= 0) {
      const preflightPayload = preflight?.responsePayload && typeof preflight.responsePayload === "object" ? preflight.responsePayload : {};
      const preflightCode = String(
        firstNonEmptyString([
          preflightPayload?.code,
          preflightPayload?.error?.code,
          preflightPayload?.error,
          Number(preflight?.profileCount || 0) <= 0 ? "authenticated_profile_missing" : "",
        ]) || "authenticated_profile_missing"
      ).trim();
      const preflightMessage = String(
        firstNonEmptyString([
          preflightPayload?.details,
          preflightPayload?.message,
          preflight?.error,
          "The authenticated profile associated with this request is missing or expired.",
        ]) || "The authenticated profile associated with this request is missing or expired."
      ).trim();
      const guidance = "Re-run LOGIN for this MVPD profile to refresh the session, then retry Can I watch?.";
      const preflightResult = {
        checkedAt: Date.now(),
        ok: false,
        status: Number(preflight?.status || 403),
        statusText: String(preflight?.statusText || "").trim(),
        programmerId,
        appGuid: String(preflightContext?.appInfo?.guid || "").trim(),
        appName: String(preflightContext?.appInfo?.appName || preflightContext?.appInfo?.guid || "").trim(),
        authMode: "dcr_client_bearer",
        endpointUrl: String(preflight?.url || "").trim(),
        requestBody: {
          resources: resourceIds.slice(),
        },
        serviceProviderId: String(selectedHarvest?.serviceProviderId || selectedHarvest?.requestorId || "").trim(),
        requestorId: String(selectedHarvest?.requestorId || "").trim(),
        mvpd: String(selectedHarvest?.mvpd || "").trim(),
        harvestKey: sectionState.selectedHarvestKey,
        harvestCapturedAt: Number(selectedHarvest?.harvestedAt || 0),
        subject: String(selectedHarvest?.subject || "").trim(),
        upstreamUserId: String(selectedHarvest?.upstreamUserId || "").trim(),
        userId: String(selectedHarvest?.userId || "").trim(),
        sessionId: String(selectedHarvest?.sessionId || "").trim(),
        profileKey: String(selectedHarvest?.profileKey || "").trim(),
        resourceIds: resourceIds.slice(),
        decisionRows: resourceIds.map((resourceId) => ({
          resourceId: String(resourceId || "").trim(),
          decision: "Unknown",
          authorized: null,
          source: "",
          serviceProvider: "",
          mvpd: String(selectedHarvest?.mvpd || "").trim(),
          errorCode: preflightCode,
          errorDetails: preflightMessage,
          mediaTokenPresent: false,
          mediaTokenPreview: "",
          mediaTokenNotBeforeMs: 0,
          mediaTokenNotAfterMs: 0,
          notBeforeMs: 0,
          notAfterMs: 0,
          raw: {},
        })),
        permitCount: 0,
        denyCount: 0,
        unknownCount: resourceIds.length,
        allRequestedPermitted: false,
        responsePreview: String(preflight?.responsePreview || "").trim(),
        responsePayload: preflightPayload,
        error: `${preflightCode}: ${preflightMessage}. ${guidance}`,
      };
      setRestV2ActiveProfileWindowState(context, false, {
        checkedAt: Date.now(),
        profileCount: Number(preflight?.profileCount || 0),
        status: Number(preflight?.status || 0),
        statusText: String(preflight?.statusText || "").trim(),
        error: preflightResult.error,
        source: "preauthorize-preflight",
      });
      throw Object.assign(new Error(preflightResult.error), { underparResult: preflightResult });
    }
    setRestV2ActiveProfileWindowState(context, true, {
      checkedAt: Date.now(),
      profileCount: Number(preflight?.profileCount || 0),
      status: Number(preflight?.status || 0),
      statusText: String(preflight?.statusText || "").trim(),
      error: "",
      source: "preauthorize-preflight",
    });

    const result = await fetchRestV2PreauthorizeDecisions(selectedHarvest, resourceIds);
    const enrichedResult = {
      ...result,
      programmerId,
    };
    setRestV2ActiveProfileWindowState(context, true, {
      checkedAt: Number(enrichedResult?.checkedAt || Date.now()),
      profileCount: Number(preflight?.profileCount || 0),
      status: Number(preflight?.status || 0),
      statusText: String(preflight?.statusText || "").trim(),
      error: "",
      source: "preauthorize",
    });
    sectionState.lastEntitlementResult = enrichedResult;
    storeRestV2PreauthorizeHistoryEntry(programmerId, enrichedResult);
    const updatedHarvest = storeRestV2ProfilePreauthzCheckEntry(
      programmerId,
      String(enrichedResult?.harvestKey || "").trim(),
      enrichedResult
    );
    if (updatedHarvest && sectionState.expandedHarvestKey === "") {
      sectionState.expandedHarvestKey = sectionState.selectedHarvestKey;
      sectionState.hasProfileExpansionChoice = true;
    }
  } catch (error) {
    const resultFromError = error?.underparResult && typeof error.underparResult === "object" ? error.underparResult : null;
    if (resultFromError) {
      const enrichedResult = {
        ...resultFromError,
        programmerId,
      };
      if (hasRestV2AuthenticatedProfileMissingSignal(enrichedResult)) {
        setRestV2ActiveProfileWindowState(context, false, {
          checkedAt: Number(enrichedResult?.checkedAt || Date.now()),
          profileCount: 0,
          status: Number(enrichedResult?.status || 0),
          statusText: String(enrichedResult?.statusText || "").trim(),
          error: String(enrichedResult?.error || "").trim(),
          source: "preauthorize-authenticated-profile-missing",
        });
      }
      sectionState.lastEntitlementResult = enrichedResult;
      storeRestV2PreauthorizeHistoryEntry(programmerId, enrichedResult);
      const updatedHarvest = storeRestV2ProfilePreauthzCheckEntry(
        programmerId,
        String(enrichedResult?.harvestKey || "").trim(),
        enrichedResult
      );
      if (updatedHarvest && sectionState.expandedHarvestKey === "") {
        sectionState.expandedHarvestKey = sectionState.selectedHarvestKey;
        sectionState.hasProfileExpansionChoice = true;
      }
    }
    if (!resultFromError) {
      sectionState.lastEntitlementResult = {
        checkedAt: Date.now(),
        ok: false,
        status: 0,
        statusText: "",
        endpointUrl: "",
        serviceProviderId: String(selectedHarvest?.serviceProviderId || selectedHarvest?.requestorId || "").trim(),
        requestorId: String(selectedHarvest?.requestorId || "").trim(),
        mvpd: String(selectedHarvest?.mvpd || "").trim(),
        harvestKey: sectionState.selectedHarvestKey,
        resourceIds: resourceIds.slice(),
        decisionRows: [],
        permitCount: 0,
        denyCount: 0,
        unknownCount: 0,
        allRequestedPermitted: false,
        responsePayload: {},
        error: error instanceof Error ? error.message : String(error),
        programmerId,
      };
    }
  } finally {
    sectionState.entitlementBusy = false;
    sectionState.resourceInputHarvestKey = sectionState.selectedHarvestKey;
    syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
  }
}

function getSelectedRestV2HarvestForProgrammer(section, programmerId) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const sectionState = getRestV2SectionState(section);
  if (!normalizedProgrammerId) {
    return {
      sectionState,
      harvestList: [],
      selectedHarvest: null,
      selectedHarvestKey: "",
    };
  }
  const harvestList = getRestV2ProfileHarvestBucketForProgrammer(normalizedProgrammerId);
  let selectedHarvest =
    harvestList.find((item, index) => getRestV2HarvestRecordKey(item, index) === sectionState.selectedHarvestKey) || harvestList[0] || null;
  const selectedHarvestKey = selectedHarvest ? getRestV2HarvestRecordKey(selectedHarvest, 0) : "";
  if (selectedHarvestKey) {
    sectionState.selectedHarvestKey = selectedHarvestKey;
  }
  return {
    sectionState,
    harvestList,
    selectedHarvest,
    selectedHarvestKey,
  };
}

function getSplunkSearchIndexForEnvironment(environment = null) {
  const resolved = environment && typeof environment === "object" ? environment : getActiveAdobePassEnvironment();
  const environmentKey = String(resolved?.key || resolved?.route || "").trim().toLowerCase();
  return environmentKey === "release-staging" ? "pass-staging" : "pass-prod";
}

function normalizeSplunkSearchQueryForEnvironment(search = "", upstreamUserId = "") {
  const normalizedSearch = String(search || "").trim();
  if (!normalizedSearch) {
    return buildSplunkSearchQueryForUpstreamUserId(upstreamUserId);
  }
  const targetIndex = getSplunkSearchIndexForEnvironment();
  return normalizedSearch.replace(/\bindex=pass-(?:prod|staging)\b/gi, `index=${targetIndex}`);
}

function buildSplunkSearchQueryForUpstreamUserId(upstreamUserId = "") {
  const normalized = String(upstreamUserId || "").trim();
  if (!normalized) {
    return "";
  }
  const escaped = normalized.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
  return `search index=${getSplunkSearchIndexForEnvironment()} "${escaped}"`;
}

function normalizeSplunkJobSearchQuery(search = "") {
  const normalizedSearch = String(search || "").trim();
  if (!normalizedSearch) {
    return "";
  }
  const normalizedLower = normalizedSearch.toLowerCase();
  const commandPrefixes = [
    "search ",
    "|",
    "savedsearch ",
    "tstats ",
    "mstats ",
    "from ",
    "metadata ",
    "inputlookup ",
    "makeresults ",
    "multisearch ",
    "union ",
    "pivot ",
    "loadjob ",
  ];
  if (commandPrefixes.some((prefix) => normalizedLower.startsWith(prefix))) {
    return normalizedSearch;
  }
  return `search ${normalizedSearch}`;
}

function getSplunkSearchLandingUrl(queryContext = null) {
  const dashboardUrl = String(queryContext?.dashboardUrl || "").trim();
  if (dashboardUrl) {
    return dashboardUrl;
  }
  const baseUrl = new URL(`${SPLUNK_BASE_URL}${SPLUNK_APP_SEARCH_PATH}`);
  const searchExpression = firstNonEmptyString([
    queryContext?.search,
    buildSplunkSearchQueryForUpstreamUserId(queryContext?.upstreamUserId),
  ]);
  if (searchExpression) {
    baseUrl.searchParams.set("q", searchExpression);
  }
  baseUrl.searchParams.set("earliest", String(queryContext?.earliest || SPLUNK_SEARCH_EARLIEST));
  baseUrl.searchParams.set("latest", String(queryContext?.latest || SPLUNK_SEARCH_LATEST));
  return baseUrl.toString();
}

async function openSplunkSearchTabForLogin(options = {}) {
  const shouldActivate = options.activate !== false;
  const requestedWindowId = Number(options.windowId || 0);
  const targetWindowId = requestedWindowId > 0 ? requestedWindowId : await esmWorkspaceGetCurrentWindowId();
  const useWindowFilter = targetWindowId > 0;
  const queryContext = options.queryContext && typeof options.queryContext === "object" ? options.queryContext : null;
  const landingUrl = getSplunkSearchLandingUrl(queryContext);

  let existingTab = null;
  try {
    const tabs = await chrome.tabs.query(useWindowFilter ? { windowId: targetWindowId } : { currentWindow: true });
    existingTab =
      tabs.find((tab) => String(tab?.url || "").startsWith(`${SPLUNK_BASE_URL}/en-US/app/`)) ||
      tabs.find((tab) => String(tab?.url || "").startsWith(`${SPLUNK_BASE_URL}/`)) ||
      null;
  } catch {
    existingTab = null;
  }

  if (existingTab?.id) {
    try {
      const updated = await chrome.tabs.update(existingTab.id, {
        url: landingUrl,
        active: shouldActivate,
      });
      if (shouldActivate && Number(updated?.windowId || 0) > 0) {
        await chrome.windows.update(Number(updated.windowId), { focused: true });
      }
      return {
        ok: true,
        reused: true,
        id: Number(updated?.id || existingTab.id || 0),
        tabId: Number(updated?.id || existingTab.id || 0),
        windowId: Number(updated?.windowId || existingTab.windowId || 0),
        url: landingUrl,
      };
    } catch {
      // Continue with create fallback.
    }
  }

  const created = await chrome.tabs.create({
    url: landingUrl,
    active: shouldActivate,
    ...(useWindowFilter ? { windowId: targetWindowId } : {}),
  });
  return {
    ok: true,
    reused: false,
    id: Number(created?.id || 0),
    tabId: Number(created?.id || 0),
    windowId: Number(created?.windowId || 0),
    url: landingUrl,
  };
}

function parseSplunkSearchTabState(url = "") {
  const rawUrl = String(url || "").trim();
  if (!rawUrl) {
    return {
      url: "",
      sid: "",
      isLogin: false,
      query: "",
      earliest: "",
      latest: "",
    };
  }
  try {
    const parsed = new URL(rawUrl);
    const path = String(parsed.pathname || "").toLowerCase();
    const hashText = String(parsed.hash || "");
    const hashQueryText = hashText.startsWith("#") ? hashText.slice(1) : hashText;
    const hashQueryOnly = hashQueryText.includes("?") ? hashQueryText.split("?").slice(1).join("?") : hashQueryText;
    const hashParams = new URLSearchParams(hashQueryOnly.startsWith("?") ? hashQueryOnly.slice(1) : hashQueryOnly);
    const sid = firstNonEmptyString([
      parsed.searchParams.get("sid"),
      hashParams.get("sid"),
      parsed.searchParams.get("job"),
      hashParams.get("job"),
    ]);
    const query = firstNonEmptyString([parsed.searchParams.get("q"), hashParams.get("q")]);
    const earliest = firstNonEmptyString([parsed.searchParams.get("earliest"), hashParams.get("earliest")]);
    const latest = firstNonEmptyString([parsed.searchParams.get("latest"), hashParams.get("latest")]);
    return {
      url: parsed.toString(),
      sid,
      query,
      earliest,
      latest,
      isLogin: path.includes("/account/login") || path.includes("/signin"),
    };
  } catch {
    return {
      url: rawUrl,
      sid: "",
      isLogin: /\/account\/login|\/signin/i.test(rawUrl),
      query: "",
      earliest: "",
      latest: "",
    };
  }
}

async function findSplunkSearchTab(windowId = 0) {
  const preferredWindowId = Number(windowId || 0);
  let tabs = [];
  try {
    tabs = await chrome.tabs.query(preferredWindowId > 0 ? { windowId: preferredWindowId } : { currentWindow: true });
  } catch {
    tabs = [];
  }
  return (
    tabs.find((tab) => String(tab?.url || "").startsWith(`${SPLUNK_BASE_URL}${SPLUNK_APP_SEARCH_PATH}`)) ||
    tabs.find((tab) => String(tab?.url || "").startsWith(`${SPLUNK_BASE_URL}/en-US/app/`)) ||
    tabs.find((tab) => String(tab?.url || "").startsWith(`${SPLUNK_BASE_URL}/`)) ||
    null
  );
}

async function waitForSplunkSidFromSearchTab(queryContext = null, options = {}) {
  const timeoutMs = Math.max(2500, Number(options.timeoutMs || SPLUNK_SID_WAIT_TIMEOUT_MS));
  const pollIntervalMs = Math.max(200, Number(options.pollIntervalMs || SPLUNK_SID_WAIT_INTERVAL_MS));
  let tab = options.tab && typeof options.tab === "object" ? options.tab : null;
  if (!tab) {
    tab = await findSplunkSearchTab(Number(options.windowId || 0));
  }
  let activeTabId = Number(tab?.id || tab?.tabId || 0);
  if (!activeTabId) {
    return {
      ok: false,
      authRequired: false,
      sid: "",
      error: "Unable to locate Splunk search tab for SID retrieval.",
    };
  }
  const expectedQuery = String(queryContext?.search || "").trim();
  const startedAt = Date.now();
  while (Date.now() - startedAt <= timeoutMs) {
    let currentTab = null;
    try {
      currentTab = await chrome.tabs.get(activeTabId);
    } catch {
      return {
        ok: false,
        authRequired: false,
        sid: "",
        error: "Splunk search tab closed before a SID was produced.",
      };
    }
    const tabState = parseSplunkSearchTabState(currentTab?.url);
    const tabQuery = String(tabState.query || "").trim();
    const queryLooksAligned = !expectedQuery || !tabQuery || tabQuery === expectedQuery;
    if (tabState.sid && queryLooksAligned) {
      return {
        ok: true,
        authRequired: false,
        sid: String(tabState.sid || "").trim(),
        tabId: Number(currentTab?.id || 0),
        windowId: Number(currentTab?.windowId || 0),
        url: String(currentTab?.url || ""),
      };
    }
    if (tabState.isLogin) {
      return {
        ok: false,
        authRequired: true,
        sid: "",
        tabId: Number(currentTab?.id || 0),
        windowId: Number(currentTab?.windowId || 0),
        url: String(currentTab?.url || ""),
        error: "Splunk login screen is active. Complete login/MFA and wait for UnderPAR to continue.",
      };
    }
    activeTabId = Number(currentTab?.id || activeTabId);
    await waitForDelay(pollIntervalMs);
  }
  return {
    ok: false,
    authRequired: false,
    sid: "",
    error: "Splunk did not produce a search SID in time. Keep the Splunk tab active until login and search complete.",
  };
}

function isSplunkAuthRequiredResponse(response, parsed = null, bodyText = "") {
  const status = Number(response?.status || 0);
  if (status === 401 || status === 403) {
    return true;
  }

  const responseUrl = String(response?.url || "").trim().toLowerCase();
  if (responseUrl.includes("/account/login") || responseUrl.includes("/signin")) {
    return true;
  }

  const contentType = String(response?.headers?.get("content-type") || "").trim().toLowerCase();
  const parsedCode = String(extractApiErrorCode(parsed) || "").trim().toLowerCase();
  if (
    parsedCode.includes("login") ||
    parsedCode.includes("unauthorized") ||
    parsedCode.includes("not_authenticated") ||
    parsedCode.includes("invalid_session")
  ) {
    return true;
  }

  const body = String(bodyText || "").trim().toLowerCase();
  if (!contentType.includes("text/html")) {
    return false;
  }
  return (
    body.includes("/account/login") ||
    body.includes("splunk login") ||
    body.includes("sign in") ||
    body.includes("authentication required")
  );
}

function extractSplunkJobSid(payload = null) {
  return firstNonEmptyString([
    payload?.sid,
    payload?.data?.sid,
    payload?.entry?.[0]?.content?.sid,
    payload?.entry?.[0]?.sid,
    payload?.content?.sid,
  ]);
}

function extractSplunkJobResultCount(payload = null) {
  const candidates = [
    payload?.entry?.[0]?.content?.resultCount,
    payload?.entry?.[0]?.content?.eventCount,
    payload?.entry?.[0]?.content?.result_count,
    payload?.entry?.[0]?.content?.event_count,
    payload?.resultCount,
    payload?.eventCount,
    payload?.result_count,
    payload?.event_count,
  ];
  for (const candidate of candidates) {
    const numeric = Number(candidate);
    if (Number.isFinite(numeric) && numeric > 0) {
      return numeric;
    }
  }
  return 0;
}

function parseSplunkBoolean(value) {
  if (typeof value === "boolean") {
    return value;
  }
  const normalized = String(value ?? "").trim().toLowerCase();
  if (!normalized) {
    return false;
  }
  return normalized === "1" || normalized === "true" || normalized === "yes";
}

function parseSplunkJobStatus(payload = null) {
  const content = payload?.entry?.[0]?.content || payload?.content || payload || {};
  const dispatchState = String(content?.dispatchState || content?.dispatch_state || "").trim().toUpperCase();
  const doneProgress = Number(content?.doneProgress ?? content?.done_progress ?? 0);
  const eventCount = Number(content?.eventCount ?? content?.event_count ?? 0);
  const resultCount = Number(content?.resultCount ?? content?.result_count ?? 0);
  const isDone = parseSplunkBoolean(content?.isDone) || dispatchState === "DONE" || doneProgress >= 1;
  const isFailed = parseSplunkBoolean(content?.isFailed) || dispatchState === "FAILED";
  return {
    isDone,
    isFailed,
    dispatchState,
    doneProgress: Number.isFinite(doneProgress) ? doneProgress : 0,
    eventCount: Number.isFinite(eventCount) ? eventCount : 0,
    resultCount: Number.isFinite(resultCount) ? resultCount : 0,
  };
}

function extractSplunkRowsFromResponsePayload(payload = null) {
  if (!payload || typeof payload !== "object") {
    return [];
  }
  const direct = Array.isArray(payload?.results)
    ? payload.results
    : Array.isArray(payload?.events)
      ? payload.events
      : null;
  if (Array.isArray(direct)) {
    return direct;
  }
  const nested = payload?.entry?.[0]?.content;
  if (nested && typeof nested === "object") {
    if (Array.isArray(nested.results)) {
      return nested.results;
    }
    if (Array.isArray(nested.events)) {
      return nested.events;
    }
  }
  return [];
}

function extractSplunkFieldsFromResponsePayload(payload = null) {
  if (!payload || typeof payload !== "object") {
    return [];
  }
  if (Array.isArray(payload?.fields)) {
    return payload.fields;
  }
  const nested = payload?.entry?.[0]?.content;
  if (nested && typeof nested === "object" && Array.isArray(nested.fields)) {
    return nested.fields;
  }
  return [];
}

function normalizeSplunkCellValue(value) {
  if (value == null) {
    return "";
  }
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }
  if (Array.isArray(value)) {
    return value.map((entry) => normalizeSplunkCellValue(entry)).join(", ");
  }
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch {
      return "[object]";
    }
  }
  return String(value);
}

function hasSplunkOmittedLineMarkers(rows = []) {
  const pattern = /\.\.\.\s*\d+\s+lines?\s+omitted\s*\.\.\./i;
  return (Array.isArray(rows) ? rows : []).some((row) => {
    if (!row || typeof row !== "object") {
      return false;
    }
    const values = [row?._raw, row?.raw, row?.value, row?.message];
    return values.some((value) => pattern.test(String(value ?? "")));
  });
}

function collectSplunkColumnOrder(results = [], fields = []) {
  const preferred = ["_time", "event", "eventType", "requestor_id", "mvpd", "resource", "ResourceId", "uid", "subjectId", "plainUid"];
  const seen = new Set();
  const output = [];
  const append = (columnName) => {
    const normalized = String(columnName || "").trim();
    if (!normalized) {
      return;
    }
    const key = normalized.toLowerCase();
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push(normalized);
  };
  preferred.forEach(append);
  (Array.isArray(fields) ? fields : []).forEach((entry) => {
    append(typeof entry === "string" ? entry : entry?.name);
  });
  (Array.isArray(results) ? results : []).forEach((row) => {
    if (!row || typeof row !== "object" || Array.isArray(row)) {
      return;
    }
    Object.keys(row).forEach((key) => append(key));
  });
  return output;
}

function normalizeSplunkRows(results = [], columns = []) {
  const rows = Array.isArray(results) ? results : [];
  const normalizedColumns = Array.isArray(columns) ? columns : [];
  return rows.map((row) => {
    const normalizedRow = {};
    normalizedColumns.forEach((columnName) => {
      normalizedRow[columnName] = normalizeSplunkCellValue(row?.[columnName]);
    });
    return normalizedRow;
  });
}

function buildSplunkRowDedupeKey(row = null, columns = []) {
  if (!row || typeof row !== "object") {
    return "";
  }
  const eventTime = firstNonEmptyString([row?._time, row?.time, row?.timestamp]);
  const rawPayload = firstNonEmptyString([row?._raw, row?.raw, row?.value, row?.message]);
  if (eventTime || rawPayload) {
    return `${normalizeSplunkCellValue(eventTime)}|${normalizeSplunkCellValue(rawPayload)}`;
  }

  const keyColumns = Array.isArray(columns) && columns.length > 0 ? columns : Object.keys(row);
  return keyColumns.map((column) => `${String(column || "").trim()}:${normalizeSplunkCellValue(row?.[column])}`).join("|");
}

function dedupeSplunkRows(results = [], columns = []) {
  const rows = Array.isArray(results) ? results : [];
  const output = [];
  const seen = new Set();
  rows.forEach((row) => {
    const key = buildSplunkRowDedupeKey(row, columns);
    const fallbackKey =
      key ||
      (() => {
        try {
          return JSON.stringify(row || {});
        } catch {
          return "";
        }
      })();
    if (fallbackKey && seen.has(fallbackKey)) {
      return;
    }
    if (fallbackKey) {
      seen.add(fallbackKey);
    }
    output.push(row);
  });
  return output;
}

function buildSplunkAuthErrorReport(queryContext = null, networkEvents = [], options = {}) {
  return {
    ok: false,
    selectionKey: String(queryContext?.selectionKey || "").trim(),
    checkedAt: Date.now(),
    queryContext,
    sid: String(options.sid || "").trim(),
    columns: [],
    rows: [],
    totalRows: 0,
    displayedRows: 0,
    truncatedRows: false,
    endpointUrl: String(options.endpointUrl || `${SPLUNK_SPLUNKD_BASE}/services/search/v2/jobs`),
    status: Number(options.status || 0),
    statusText: String(options.statusText || "").trim(),
    error:
      String(options.error || "").trim() ||
      "Splunk session is not active. Sign in or refresh auth in the opened Splunk tab and wait for UnderPAR to complete.",
    authRequired: options.authRequired !== false,
    networkEvents: Array.isArray(networkEvents) ? networkEvents : [],
  };
}

function buildSplunkReportPayloadFromEvents(queryContext = null, sid = "", eventsUrl = "", eventsResponse = null, networkEvents = [], options = {}) {
  const fields = Array.isArray(eventsResponse?.parsed?.fields) ? eventsResponse.parsed.fields : [];
  const rawRows = Array.isArray(eventsResponse?.parsed?.results) ? eventsResponse.parsed.results : [];
  const columns = collectSplunkColumnOrder(rawRows, fields);
  const uniqueRawRows = dedupeSplunkRows(rawRows, columns);
  const normalizedRows = normalizeSplunkRows(uniqueRawRows, columns);
  const displayedRows = normalizedRows.slice(0, SPLUNK_EVENT_RENDER_LIMIT);
  const totalRows = normalizedRows.length;
  return {
    ok: true,
    selectionKey: String(queryContext?.selectionKey || "").trim(),
    checkedAt: Date.now(),
    queryContext,
    sid: String(sid || "").trim(),
    columns,
    rows: displayedRows,
    totalRows,
    displayedRows: displayedRows.length,
    truncatedRows: totalRows > displayedRows.length,
    endpointUrl: String(eventsUrl || ""),
    status: Number(eventsResponse?.status || 0),
    statusText: String(eventsResponse?.statusText || "").trim(),
    error: "",
    authRequired: false,
    networkEvents: Array.isArray(networkEvents) ? networkEvents : [],
  };
}

async function fetchSplunkReportBySid(queryContext = null, sid = "", networkEvents = [], phasePrefix = "sid-fetch", relayOptions = {}) {
  const normalizedSid = String(sid || "").trim();
  if (!normalizedSid) {
    return {
      ok: false,
      error: "Unable to fetch Splunk results: SID is missing.",
      authRequired: false,
      report: null,
    };
  }
  const encodedSid = encodeURIComponent(normalizedSid);
  const jobsBaseCandidates = [
    `${SPLUNK_SPLUNKD_BASE}/services/search/v2/jobs`,
    `${SPLUNK_SPLUNKD_BASE}/services/search/jobs`,
  ];
  let lastError = "";
  for (const jobsBaseUrl of jobsBaseCandidates) {
    const jobMetaUrl = `${jobsBaseUrl}/${encodedSid}?output_mode=json`;
    const pollStartedAt = Date.now();
    let jobMeta = null;
    let latestStatus = parseSplunkJobStatus(null);
    do {
      jobMeta = await runSplunkRelayRequest(
        jobMetaUrl,
        {
          method: "GET",
          credentials: "include",
          headers: {
            Accept: "*/*",
          },
        },
        networkEvents,
        `${phasePrefix}-job-status`,
        relayOptions
      );
      if (jobMeta.authRequired) {
        return {
          ok: false,
          error: "Splunk session is not active. Sign in or refresh auth in the opened Splunk tab and wait for UnderPAR to complete.",
          authRequired: true,
          report: buildSplunkAuthErrorReport(queryContext, networkEvents, {
            sid: normalizedSid,
            endpointUrl: jobMetaUrl,
            status: jobMeta.status,
            statusText: jobMeta.statusText,
          }),
        };
      }
      if (!jobMeta.ok) {
        lastError = firstNonEmptyString([
          normalizeHttpErrorMessage(jobMeta.text),
          String(jobMeta.statusText || "").trim(),
          `HTTP ${jobMeta.status || 0}`,
        ]);
        break;
      }
      latestStatus = parseSplunkJobStatus(jobMeta.parsed);
      if (latestStatus.isFailed) {
        lastError = "Splunk search job failed before event retrieval.";
        break;
      }
      if (latestStatus.isDone) {
        break;
      }
      await waitForDelay(SPLUNK_JOB_POLL_INTERVAL_MS);
    } while (Date.now() - pollStartedAt < SPLUNK_JOB_POLL_TIMEOUT_MS);

    if (!jobMeta?.ok) {
      continue;
    }

    const totalRowsFromMeta = Math.max(extractSplunkJobResultCount(jobMeta.parsed), Number(latestStatus.eventCount || 0));
    const relayFetchLimit = Number(relayOptions?.tabId || 0) > 0 ? Math.min(SPLUNK_EVENT_FETCH_LIMIT, 180) : SPLUNK_EVENT_FETCH_LIMIT;
    const fetchCount = Math.max(50, Math.min(relayFetchLimit, totalRowsFromMeta > 0 ? totalRowsFromMeta : relayFetchLimit));
    const resultsParams = new URLSearchParams({
      output_mode: "json",
      offset: "0",
      count: String(fetchCount),
      field_list: "_raw,_time,*",
    });
    const resultsUrl = `${jobsBaseUrl}/${encodedSid}/results?${resultsParams.toString()}`;
    const eventsParams = new URLSearchParams({
      output_mode: "json",
      offset: "0",
      count: String(fetchCount),
      segmentation: "none",
      field_list: "_raw,_time,*",
    });
    const eventsUrl = `${jobsBaseUrl}/${encodedSid}/events?${eventsParams.toString()}`;
    const eventsResponse = await runSplunkRelayRequest(
      eventsUrl,
      {
        method: "GET",
        credentials: "include",
        headers: {
          Accept: "*/*",
        },
      },
      networkEvents,
      `${phasePrefix}-events`,
      relayOptions
    );
    if (eventsResponse.authRequired) {
      return {
        ok: false,
        error: "Splunk session is not active. Sign in or refresh auth in the opened Splunk tab and wait for UnderPAR to complete.",
        authRequired: true,
        report: buildSplunkAuthErrorReport(queryContext, networkEvents, {
          sid: normalizedSid,
          endpointUrl: eventsUrl,
          status: eventsResponse.status,
          statusText: eventsResponse.statusText,
        }),
      };
    }
    if (!eventsResponse.ok) {
      lastError = firstNonEmptyString([
        normalizeHttpErrorMessage(eventsResponse.text),
        String(eventsResponse.statusText || "").trim(),
        `HTTP ${eventsResponse.status || 0}`,
      ]);
      continue;
    }

    const eventRows = extractSplunkRowsFromResponsePayload(eventsResponse.parsed);
    const eventFields = extractSplunkFieldsFromResponsePayload(eventsResponse.parsed);
    const omittedLineMarkersDetected = hasSplunkOmittedLineMarkers(eventRows);
    let fallbackResponse = null;
    let fallbackRows = [];
    let fallbackFields = [];

    if ((eventRows.length === 0 && (latestStatus.eventCount > 0 || totalRowsFromMeta > 0)) || omittedLineMarkersDetected) {
      fallbackResponse = await runSplunkRelayRequest(
        resultsUrl,
        {
          method: "GET",
          credentials: "include",
          headers: {
            Accept: "*/*",
          },
        },
        networkEvents,
        `${phasePrefix}-results`,
        relayOptions
      );
      if (fallbackResponse.ok && !fallbackResponse.authRequired) {
        fallbackRows = extractSplunkRowsFromResponsePayload(fallbackResponse.parsed);
        fallbackFields = extractSplunkFieldsFromResponsePayload(fallbackResponse.parsed);
      }
    }

    const chosenResponse = fallbackRows.length > 0 ? fallbackResponse : eventsResponse;
    const chosenRows = fallbackRows.length > 0 ? fallbackRows : eventRows;
    const chosenFields = fallbackRows.length > 0 ? fallbackFields : eventFields;
    const rowsPayload =
      chosenResponse?.parsed && typeof chosenResponse.parsed === "object"
        ? {
            ...chosenResponse.parsed,
            fields: chosenFields,
            results: chosenRows,
          }
        : {
            fields: chosenFields,
            results: chosenRows,
          };

    return {
      ok: true,
      error: "",
      authRequired: false,
      report: buildSplunkReportPayloadFromEvents(queryContext, normalizedSid, String(chosenResponse?.url || eventsUrl), { ...chosenResponse, parsed: rowsPayload }, networkEvents, {
        totalRowsFromMeta: Math.max(totalRowsFromMeta, Number(latestStatus.eventCount || 0)),
      }),
    };
  }
  return {
    ok: false,
    error: lastError || "Unable to fetch Splunk results for search SID.",
    authRequired: false,
    report: null,
  };
}

function isSplunkRelayHostUrl(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return false;
  }
  try {
    const parsed = new URL(raw);
    return String(parsed.hostname || "").trim().toLowerCase() === "splunk-us.corp.adobe.com";
  } catch {
    return false;
  }
}

function shouldAttemptSplunkTabRelayFallback(runtimeOptions = {}, relayResult = null) {
  const tabId = Number(runtimeOptions?.tabId || 0);
  if (!tabId || tabId <= 0 || runtimeOptions?.allowTabRelay === false) {
    return false;
  }
  if (!relayResult || typeof relayResult !== "object") {
    return true;
  }
  if (relayResult.authRequired === true) {
    return true;
  }
  if (!isSplunkRelayHostUrl(relayResult.url)) {
    return true;
  }
  return false;
}

async function runSplunkRelayRequestFromTabContext(tabId = 0, url = "", options = {}) {
  const normalizedTabId = Number(tabId || 0);
  const requestUrl = String(url || "").trim();
  if (!normalizedTabId || !requestUrl || !chrome.debugger || !isSplunkRelayHostUrl(requestUrl)) {
    return null;
  }

  const target = { tabId: normalizedTabId };
  const method = String(options?.method || "GET").trim().toUpperCase();
  const requestBody = typeof options?.body === "string" ? options.body : "";
  const requestHeaders = options?.headers && typeof options.headers === "object" ? options.headers : {};
  const requestPayload = {
    url: requestUrl,
    method,
    credentials: String(options?.credentials || "include").trim().toLowerCase() || "include",
    headers: requestHeaders,
    body: requestBody,
  };

  const expression = `(async () => {
    const req = ${JSON.stringify(requestPayload)};
    try {
      const headers = req.headers && typeof req.headers === "object" ? { ...req.headers } : {};
      const findHeader = (name) => {
        const target = String(name || "").trim().toLowerCase();
        if (!target) return "";
        return Object.keys(headers).find((key) => String(key || "").trim().toLowerCase() === target) || "";
      };
      const setHeaderIfMissing = (name, value) => {
        const existingKey = findHeader(name);
        if (existingKey) {
          const existingValue = String(headers[existingKey] ?? "").trim();
          if (existingValue) return;
          delete headers[existingKey];
        }
        headers[name] = String(value ?? "");
      };
      setHeaderIfMissing("X-Requested-With", "XMLHttpRequest");
      setHeaderIfMissing("Accept", "*/*");
      if (String(req.method || "GET").toUpperCase() === "POST") {
        setHeaderIfMissing("Content-Type", "application/x-www-form-urlencoded;charset=UTF-8");
      }
      if (!findHeader("X-Splunk-Form-Key")) {
        const cookieParts = String(document.cookie || "")
          .split(";")
          .map((part) => String(part || "").trim())
          .filter(Boolean);
        let formKey = "";
        for (const cookiePart of cookieParts) {
          const divider = cookiePart.indexOf("=");
          if (divider <= 0) continue;
          const cookieName = cookiePart.slice(0, divider).trim().toLowerCase();
          const cookieValue = cookiePart.slice(divider + 1).trim();
          if (!/csrf/.test(cookieName) || !cookieValue) continue;
          formKey = cookieValue;
          break;
        }
        if (formKey) {
          setHeaderIfMissing("X-Splunk-Form-Key", formKey);
        }
      }
      const response = await fetch(req.url, {
        method: req.method || "GET",
        credentials: req.credentials || "include",
        cache: "no-store",
        redirect: "follow",
        headers,
        body: req.method === "POST" ? (req.body || "") : undefined,
      });
      const bodyText = await response.text();
      const headersOut = {};
      response.headers.forEach((value, key) => {
        headersOut[key] = value;
      });
      return {
        ok: Boolean(response.ok),
        status: Number(response.status || 0),
        statusText: String(response.statusText || ""),
        url: String(response.url || req.url || ""),
        redirected: Boolean(response.redirected),
        headers: headersOut,
        bodyText: String(bodyText || ""),
      };
    } catch (error) {
      return {
        ok: false,
        status: 0,
        statusText: "",
        url: String(req.url || ""),
        redirected: false,
        headers: {},
        bodyText: "",
        error: error && error.message ? String(error.message) : String(error || "unknown_error"),
      };
    }
  })();`;

  let attachedByThisCall = false;
  try {
    try {
      await chrome.debugger.attach(target, AUTH_DEBUGGER_PROTOCOL_VERSION);
      attachedByThisCall = true;
    } catch (attachError) {
      const attachMessage = String(attachError?.message || attachError || "").trim().toLowerCase();
      if (!attachMessage.includes("already attached")) {
        throw attachError;
      }
    }
    const evaluateResult = await chrome.debugger.sendCommand(target, "Runtime.evaluate", {
      expression,
      returnByValue: true,
      awaitPromise: true,
    });
    const value = evaluateResult?.result?.value;
    return value && typeof value === "object" ? value : null;
  } catch {
    return null;
  } finally {
    if (attachedByThisCall) {
      try {
        await chrome.debugger.detach(target);
      } catch {
        // Ignore detach failures for short-lived tab relay.
      }
    }
  }
}

async function runSplunkRelayRequest(url, options = {}, networkEvents = [], phase = "", runtimeOptions = {}) {
  const method = String(options?.method || "GET").trim().toUpperCase();
  const requestBody = typeof options?.body === "string" ? options.body : "";
  const recordNetworkEvent = (payload = null) => {
    if (!Array.isArray(networkEvents) || !payload || typeof payload !== "object") {
      return;
    }
    networkEvents.push(payload);
  };
  const buildRelayResult = (relayResponse = null, responseText = "", durationMs = 0) => {
    const parsed = parseJsonText(responseText, null);
    return {
      ok: Boolean(relayResponse?.ok),
      status: Number(relayResponse?.status || 0),
      statusText: String(relayResponse?.statusText || "").trim(),
      url: String(relayResponse?.url || url),
      headers: relayResponse?.headers instanceof Headers ? relayResponse.headers : new Headers(),
      text: responseText,
      parsed,
      durationMs: Number(durationMs || 0),
      authRequired: isSplunkAuthRequiredResponse(relayResponse, parsed, responseText),
      redirected: Boolean(relayResponse?.redirected),
    };
  };
  const attemptTabContextFallback = async (reason = "") => {
    if (!shouldAttemptSplunkTabRelayFallback(runtimeOptions, null)) {
      return null;
    }
    const tabStartedAt = Date.now();
    const tabPayload = await runSplunkRelayRequestFromTabContext(Number(runtimeOptions?.tabId || 0), url, {
      method,
      credentials: options.credentials || "include",
      headers: options.headers && typeof options.headers === "object" ? options.headers : {},
      ...(requestBody ? { body: requestBody } : {}),
    });
    if (!tabPayload || typeof tabPayload !== "object") {
      return null;
    }
    const tabDurationMs = Date.now() - tabStartedAt;
    const tabBodyText = typeof tabPayload?.bodyText === "string" ? tabPayload.bodyText : "";
    const tabHeaders = tabPayload?.headers && typeof tabPayload.headers === "object" ? new Headers(tabPayload.headers) : new Headers();
    const relayResponse = {
      ok: Boolean(tabPayload?.ok),
      status: Number(tabPayload?.status || 0),
      statusText: String(tabPayload?.statusText || "").trim(),
      url: String(tabPayload?.url || url),
      redirected: Boolean(tabPayload?.redirected),
      headers: tabHeaders,
    };
    recordNetworkEvent({
      phase: `${String(phase || "request")}-tab-relay`,
      method,
      url: String(relayResponse?.url || url),
      status: Number(relayResponse?.status || 0),
      statusText: String(relayResponse?.statusText || "").trim(),
      ok: Boolean(relayResponse?.ok),
      durationMs: tabDurationMs,
      requestBody: requestBody ? truncateDebugText(requestBody, 800) : "",
      responsePreview: truncateDebugText(tabBodyText || String(tabPayload?.error || ""), 1600),
      relay: "tab",
      reason: String(reason || ""),
    });
    return buildRelayResult(relayResponse, tabBodyText, tabDurationMs);
  };

  const startedAt = Date.now();
  try {
    const response = await relaySplunkFetch(url, {
      method,
      credentials: options.credentials || "include",
      headers: options.headers && typeof options.headers === "object" ? options.headers : {},
      ...(requestBody ? { body: requestBody } : {}),
    });
    const responseText = await response.text().catch(() => "");
    const durationMs = Date.now() - startedAt;
    const result = buildRelayResult(response, responseText, durationMs);
    recordNetworkEvent({
      phase: String(phase || "request"),
      method,
      url: String(result?.url || url),
      status: Number(result?.status || 0),
      statusText: String(result?.statusText || "").trim(),
      ok: Boolean(result?.ok),
      durationMs,
      requestBody: requestBody ? truncateDebugText(requestBody, 800) : "",
      responsePreview: truncateDebugText(responseText, 1600),
      relay: "background",
    });

    if (shouldAttemptSplunkTabRelayFallback(runtimeOptions, result)) {
      const fallbackResult = await attemptTabContextFallback("background-auth-or-redirect");
      if (fallbackResult) {
        return fallbackResult;
      }
    }
    return result;
  } catch (error) {
    const durationMs = Date.now() - startedAt;
    const message = error instanceof Error ? error.message : String(error);
    recordNetworkEvent({
      phase: String(phase || "request"),
      method,
      url: String(url || ""),
      status: 0,
      statusText: "",
      ok: false,
      durationMs,
      requestBody: requestBody ? truncateDebugText(requestBody, 800) : "",
      responsePreview: truncateDebugText(message, 1600),
      error: message,
      relay: "background",
    });
    if (shouldAttemptSplunkTabRelayFallback(runtimeOptions, null)) {
      const fallbackResult = await attemptTabContextFallback("background-exception");
      if (fallbackResult) {
        return fallbackResult;
      }
    }
    throw error;
  }
}

async function checkSplunkSessionActive(queryContext = null, networkEvents = [], runtimeOptions = {}) {
  const probeUrl = `${SPLUNK_SPLUNKD_BASE}/services/authentication/current-context?output_mode=json`;
  const probe = await runSplunkRelayRequest(
    probeUrl,
    {
      method: "GET",
      credentials: "include",
      headers: {
        Accept: "*/*",
      },
    },
    networkEvents,
    "session-probe",
    runtimeOptions
  );
  const hasUserIdentity = Boolean(
    firstNonEmptyString([
      probe?.parsed?.username,
      probe?.parsed?.entry?.[0]?.content?.username,
      probe?.parsed?.entry?.[0]?.name,
      probe?.parsed?.entry?.[0]?.acl?.owner,
      probe?.parsed?.entry?.[0]?.content?.realname,
    ])
  );
  return {
    active: probe.ok && !probe.authRequired && hasUserIdentity,
    probe,
    hasUserIdentity,
    queryContext,
  };
}

async function ensureSplunkSessionReady(queryContext = null, networkEvents = [], options = {}) {
  let targetWindowId = Number(options.targetWindowId || 0);
  let splunkTab = options?.splunkTab && typeof options.splunkTab === "object" ? options.splunkTab : null;
  const shouldForceLogin = options.forceLoginOnAuthFailure !== false;
  const timeoutMs = Math.max(2000, Number(options.timeoutMs || SPLUNK_AUTH_WAIT_TIMEOUT_MS));
  const pollIntervalMs = Math.max(300, Number(options.pollIntervalMs || SPLUNK_AUTH_WAIT_INTERVAL_MS));

  if (!splunkTab && shouldForceLogin) {
    try {
      splunkTab = await openSplunkSearchTabForLogin({
        activate: true,
        windowId: targetWindowId || undefined,
        queryContext,
      });
    } catch {
      splunkTab = null;
    }
  }
  if (Number(splunkTab?.windowId || 0) > 0) {
    targetWindowId = Number(splunkTab.windowId);
  }

  let activeTabId = Number(splunkTab?.tabId || splunkTab?.id || 0);
  if (!activeTabId && targetWindowId > 0) {
    try {
      const foundTab = await findSplunkSearchTab(targetWindowId);
      if (foundTab) {
        splunkTab = foundTab;
        activeTabId = Number(foundTab?.id || 0);
      }
    } catch {
      activeTabId = 0;
    }
  }

  const startedAt = Date.now();
  let lastSession = null;
  do {
    const relayOptions = {
      tabId: activeTabId,
      allowTabRelay: true,
    };
    const session = await checkSplunkSessionActive(queryContext, networkEvents, relayOptions);
    lastSession = session;
    if (session.active) {
      return {
        ok: true,
        session,
        splunkTab,
        targetWindowId,
      };
    }

    if (Date.now() - startedAt >= timeoutMs) {
      break;
    }
    await waitForDelay(pollIntervalMs);

    if (targetWindowId > 0) {
      try {
        const foundTab = await findSplunkSearchTab(targetWindowId);
        if (foundTab) {
          splunkTab = foundTab;
          activeTabId = Number(foundTab?.id || activeTabId || 0);
        }
      } catch {
        // Keep existing tab reference while polling.
      }
    }
  } while (Date.now() - startedAt <= timeoutMs);

  return {
    ok: false,
    session: lastSession,
    splunkTab,
    targetWindowId,
    error: "Splunk login is still pending. Complete login/MFA in the Splunk tab and wait for query auto-retry.",
  };
}

function buildSplunkSearchRequestContext(rawContext = null) {
  const context = rawContext && typeof rawContext === "object" ? rawContext : {};
  const programmerId = String(context.programmerId || "").trim();
  const programmerName = String(context.programmerName || "").trim();
  const requestorId = String(context.requestorId || context.serviceProviderId || "").trim();
  const mvpd = String(context.mvpd || "").trim();
  const mvpdLabel = String(context.mvpdLabel || "").trim();
  const upstreamUserId = String(context.upstreamUserId || "").trim();
  const earliest = String(context.earliest || SPLUNK_SEARCH_EARLIEST).trim() || SPLUNK_SEARCH_EARLIEST;
  const latest = String(context.latest || SPLUNK_SEARCH_LATEST).trim() || SPLUNK_SEARCH_LATEST;
  const search = normalizeSplunkSearchQueryForEnvironment(context.search, upstreamUserId);
  const selectionKey = firstNonEmptyString([
    context.selectionKey,
    buildRestWorkspaceSelectionKey({
      programmerId,
      requestorId,
      mvpd,
      upstreamUserId,
    }),
  ]);
  return {
    programmerId,
    programmerName,
    requestorId,
    mvpd,
    mvpdLabel,
    upstreamUserId,
    earliest,
    latest,
    search,
    selectionKey,
    requestSource: String(context.requestSource || "").trim(),
  };
}

async function runSplunkSearchForQueryContext(rawQueryContext = null, options = {}) {
  const queryContext = buildSplunkSearchRequestContext(rawQueryContext);
  if (!queryContext.programmerId || !queryContext.requestorId || !queryContext.mvpd || !queryContext.search || !queryContext.upstreamUserId) {
    return {
      ok: false,
      error: "Splunk search context is incomplete. Select a captured MVPD profile with upstreamUserID and retry.",
    };
  }

  const openWorkspace = options.openWorkspace !== false;
  const activateWorkspace = options.activateWorkspace !== false;
  const emitRestWorkspace = options.emitRestWorkspace !== false;
  const forceLoginOnAuthFailure = options.forceLoginOnAuthFailure !== false;
  let targetWindowId = Number(options.targetWindowId || 0);

  if (openWorkspace) {
    const workspaceTab = await restWorkspaceEnsureWorkspaceTab({
      activate: activateWorkspace,
      windowId: targetWindowId || undefined,
    });
    targetWindowId = Number(workspaceTab?.windowId || targetWindowId || state.restWorkspaceWindowId || 0);
  }

  if (emitRestWorkspace) {
    const selectionContext = {
      programmerId: queryContext.programmerId,
      programmerName: queryContext.programmerName,
      requestorId: queryContext.requestorId,
      mvpd: queryContext.mvpd,
      mvpdLabel: queryContext.mvpdLabel,
      upstreamUserId: queryContext.upstreamUserId,
      selectionKey: queryContext.selectionKey,
    };
    restWorkspaceBroadcastControllerState(resolveSelectedProgrammer(), selectionContext, targetWindowId);
    void restWorkspaceSendWorkspaceMessage(
      "report-start",
      {
        selectionKey: queryContext.selectionKey,
        queryContext,
        startedAt: Date.now(),
        search: queryContext.search,
        earliest: queryContext.earliest,
        latest: queryContext.latest,
      },
      {
        targetWindowId,
      }
    );
  }

  const networkEvents = [];
  const finalizeReport = (payload) => {
    if (emitRestWorkspace) {
      restWorkspaceStoreLatestReport(payload);
      void restWorkspaceSendWorkspaceMessage("report-result", payload, { targetWindowId });
    }
    return payload;
  };

  try {
    let splunkTab = null;
    const sessionReady = await ensureSplunkSessionReady(queryContext, networkEvents, {
      targetWindowId,
      forceLoginOnAuthFailure,
      timeoutMs: SPLUNK_AUTH_WAIT_TIMEOUT_MS,
      pollIntervalMs: SPLUNK_AUTH_WAIT_INTERVAL_MS,
    });
    if (Number(sessionReady?.targetWindowId || 0) > 0) {
      targetWindowId = Number(sessionReady.targetWindowId);
    }
    splunkTab = sessionReady?.splunkTab || null;
    const splunkTabId = Number(splunkTab?.tabId || splunkTab?.id || 0);
    const relayOptions = {
      tabId: splunkTabId,
      allowTabRelay: true,
    };
    const session = sessionReady?.session || (await checkSplunkSessionActive(queryContext, networkEvents, relayOptions));
    if (!sessionReady?.ok || !session?.active) {
      return finalizeReport(
        buildSplunkAuthErrorReport(queryContext, networkEvents, {
          endpointUrl: `${SPLUNK_SPLUNKD_BASE}/services/authentication/current-context`,
          status: Number(session?.probe?.status || 0),
          statusText: String(session?.probe?.statusText || "").trim(),
          error: firstNonEmptyString([
            sessionReady?.error,
            "Splunk session is not active. Complete Splunk login in the opened tab and retry.",
          ]),
        })
      );
    }

    const createBody = new URLSearchParams({
      search: normalizeSplunkJobSearchQuery(queryContext.search),
      earliest_time: queryContext.earliest,
      latest_time: queryContext.latest,
      output_mode: "json",
    }).toString();
    const createCandidates = [
      `${SPLUNK_SPLUNKD_BASE}/services/search/v2/jobs`,
      `${SPLUNK_SPLUNKD_BASE}/services/search/jobs`,
    ];
    let sawAuthRequired = false;
    let authEndpointUrl = createCandidates[0];
    let authStatus = Number(session?.probe?.status || 0);
    let authStatusText = String(session?.probe?.statusText || "").trim();
    let lastCreateError = "";

    const runCreatePass = async (phaseName = "create-job") => {
      let passSawAuthRequired = false;
      let passAuthEndpointUrl = createCandidates[0];
      let passAuthStatus = Number(session?.probe?.status || 0);
      let passAuthStatusText = String(session?.probe?.statusText || "").trim();
      let passLastError = "";

      for (const createUrl of createCandidates) {
        const response = await runSplunkRelayRequest(
          createUrl,
          {
            method: "POST",
            credentials: "include",
            headers: {
              Accept: "*/*",
              "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8",
              "X-Requested-With": "XMLHttpRequest",
            },
            body: createBody,
          },
          networkEvents,
          phaseName,
          relayOptions
        );
        if (response.authRequired) {
          passSawAuthRequired = true;
          passAuthEndpointUrl = createUrl;
          passAuthStatus = Number(response?.status || 0);
          passAuthStatusText = String(response?.statusText || "").trim();
          passLastError = firstNonEmptyString([
            normalizeHttpErrorMessage(response.text),
            "Splunk requires an authenticated session for job creation.",
          ]);
          continue;
        }
        if (!response.ok) {
          passLastError = firstNonEmptyString([
            normalizeHttpErrorMessage(response.text),
            String(response.statusText || "").trim(),
            `HTTP ${response.status || 0}`,
          ]);
          continue;
        }
        const extractedSid = extractSplunkJobSid(response.parsed);
        if (!extractedSid) {
          passLastError = "Splunk search job was created without a SID.";
          continue;
        }
        const createdJobResult = await fetchSplunkReportBySid(queryContext, extractedSid, networkEvents, phaseName, relayOptions);
        if (createdJobResult.ok && createdJobResult.report) {
          return {
            ok: true,
            report: createdJobResult.report,
            authRequired: false,
            authEndpointUrl: passAuthEndpointUrl,
            authStatus: passAuthStatus,
            authStatusText: passAuthStatusText,
            error: "",
          };
        }
        if (createdJobResult.authRequired) {
          passSawAuthRequired = true;
          passAuthEndpointUrl = createUrl;
          passAuthStatus = Number(createdJobResult?.report?.status || response.status || 0);
          passAuthStatusText = String(createdJobResult?.report?.statusText || response.statusText || "").trim();
        }
        passLastError = firstNonEmptyString([createdJobResult?.error, passLastError]);
        break;
      }

      return {
        ok: false,
        report: null,
        authRequired: passSawAuthRequired,
        authEndpointUrl: passAuthEndpointUrl,
        authStatus: passAuthStatus,
        authStatusText: passAuthStatusText,
        error: passLastError,
      };
    };

    let createPass = await runCreatePass("create-job");
    if (!createPass.ok && createPass.authRequired && forceLoginOnAuthFailure) {
      const refreshedSession = await ensureSplunkSessionReady(queryContext, networkEvents, {
        targetWindowId,
        forceLoginOnAuthFailure: true,
        timeoutMs: SPLUNK_AUTH_WAIT_TIMEOUT_MS,
        pollIntervalMs: SPLUNK_AUTH_WAIT_INTERVAL_MS,
        splunkTab,
      });
      if (refreshedSession?.ok) {
        splunkTab = refreshedSession?.splunkTab || splunkTab;
        createPass = await runCreatePass("create-job-retry");
      }
    }

    if (createPass.ok && createPass.report) {
      return finalizeReport(createPass.report);
    }

    sawAuthRequired = createPass.authRequired === true;
    authEndpointUrl = String(createPass.authEndpointUrl || authEndpointUrl);
    authStatus = Number(createPass.authStatus || authStatus);
    authStatusText = String(createPass.authStatusText || authStatusText);
    lastCreateError = String(createPass.error || "").trim();

    const sidFromTab = await waitForSplunkSidFromSearchTab(queryContext, {
      tab: splunkTab,
      windowId: targetWindowId,
      timeoutMs: SPLUNK_SID_WAIT_TIMEOUT_MS,
      pollIntervalMs: SPLUNK_SID_WAIT_INTERVAL_MS,
    });
    if (sidFromTab.ok && sidFromTab.sid) {
      const sidFallbackResult = await fetchSplunkReportBySid(queryContext, sidFromTab.sid, networkEvents, "sid-fallback", {
        tabId: Number(sidFromTab?.tabId || splunkTabId || 0),
        allowTabRelay: true,
      });
      if (sidFallbackResult.ok && sidFallbackResult.report) {
        return finalizeReport(sidFallbackResult.report);
      }
      if (sidFallbackResult.authRequired && sidFallbackResult.report) {
        return finalizeReport(sidFallbackResult.report);
      }
      lastCreateError = firstNonEmptyString([
        sidFallbackResult?.error,
        lastCreateError,
      ]);
    } else if (sidFromTab.authRequired) {
      return finalizeReport(
        buildSplunkAuthErrorReport(queryContext, networkEvents, {
          endpointUrl: authEndpointUrl,
          status: authStatus,
          statusText: authStatusText,
          error: sidFromTab.error,
        })
      );
    }

    if (sawAuthRequired || !session.active) {
      if (forceLoginOnAuthFailure) {
        try {
          await openSplunkSearchTabForLogin({
            activate: true,
            windowId: targetWindowId || undefined,
            queryContext,
          });
        } catch {
          // Ignore tab-open failures while reporting auth state.
        }
      }
      return finalizeReport(
        buildSplunkAuthErrorReport(queryContext, networkEvents, {
          endpointUrl: authEndpointUrl,
          status: authStatus,
          statusText: authStatusText,
        })
      );
    }

    throw new Error(
      firstNonEmptyString([
        lastCreateError,
        "Unable to create Splunk search job.",
      ])
    );
  } catch (error) {
    if (forceLoginOnAuthFailure) {
      const lowerMessage = String(error instanceof Error ? error.message : error).toLowerCase();
      if (lowerMessage.includes("session") || lowerMessage.includes("auth") || lowerMessage.includes("login")) {
        try {
          await openSplunkSearchTabForLogin({
            activate: true,
            windowId: targetWindowId || undefined,
            queryContext,
          });
        } catch {
          // Ignore open-tab failures when reporting original error.
        }
      }
    }
    const message = error instanceof Error ? error.message : String(error);
    const errorPayload = {
      ok: false,
      selectionKey: queryContext.selectionKey,
      checkedAt: Date.now(),
      queryContext,
      sid: "",
      columns: [],
      rows: [],
      totalRows: 0,
      displayedRows: 0,
      truncatedRows: false,
      endpointUrl: `${SPLUNK_SPLUNKD_BASE}/services/search/v2/jobs`,
      status: 0,
      statusText: "",
      error: message,
      authRequired: false,
      networkEvents,
    };
    return finalizeReport(errorPayload);
  }
}

function buildHealthSplunkQueryContext(rawContext = null) {
  const context = rawContext && typeof rawContext === "object" ? rawContext : {};
  const resolvedProgrammer = resolveSelectedProgrammer();
  const environment = getActiveAdobePassEnvironment();
  const programmerId = String(context.programmerId || resolvedProgrammer?.programmerId || "").trim();
  const programmerName = String(context.programmerName || resolvedProgrammer?.programmerName || "").trim();
  const requestorId = String(context.requestorId || state.selectedRequestorId || "").trim();
  const earliest = String(context.earliest || SPLUNK_SEARCH_EARLIEST).trim() || SPLUNK_SEARCH_EARLIEST;
  const latest = String(context.latest || SPLUNK_SEARCH_LATEST).trim() || SPLUNK_SEARCH_LATEST;
  const environmentKey = String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const environmentLabel = firstNonEmptyString([environment?.label, environment?.shortCode, environmentKey]);
  const environmentIndex = getSplunkSearchIndexForEnvironment(environment);
  const selectionKey = buildHealthWorkspaceSelectionKey({
    programmerId,
    requestorId,
  });
  const dashboardUrl = buildHealthSplunkDashboardUrl({
    requestorId,
    earliest,
    latest,
    environmentIndex,
  });
  return {
    programmerId,
    programmerName,
    requestorId,
    earliest,
    latest,
    environmentKey,
    environmentLabel,
    environmentIndex,
    dashboardUrl,
    selectionKey,
    requestSource: String(context.requestSource || "health-splunk-dashboard").trim() || "health-splunk-dashboard",
    search: buildHealthSplunkLoginSearch({
      requestorId,
      environmentIndex,
    }),
  };
}

function buildHealthSplunkStatusMessage(queryContext = null) {
  const requestorId = String(queryContext?.requestorId || "").trim();
  const environmentLabel = String(queryContext?.environmentLabel || "").trim();
  if (requestorId && environmentLabel) {
    return `${requestorId} | ${environmentLabel}`;
  }
  return requestorId || environmentLabel || "HEALTH Splunk";
}

function buildHealthSplunkLoginSearch(queryContext = null) {
  const environmentIndex = String(queryContext?.environmentIndex || getSplunkSearchIndexForEnvironment()).trim();
  const requestorId = String(queryContext?.requestorId || "").trim();
  if (!environmentIndex) {
    return "";
  }
  if (!requestorId) {
    return `search index=${environmentIndex}`;
  }
  return `search index=${environmentIndex} "${requestorId.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
}

function buildHealthSplunkDashboardUrl(queryContext = null) {
  const requestorId = String(queryContext?.requestorId || "").trim();
  const environmentIndex = String(queryContext?.environmentIndex || getSplunkSearchIndexForEnvironment()).trim();
  const earliest = String(queryContext?.earliest || SPLUNK_SEARCH_EARLIEST).trim() || SPLUNK_SEARCH_EARLIEST;
  const latest = String(queryContext?.latest || SPLUNK_SEARCH_LATEST).trim() || SPLUNK_SEARCH_LATEST;
  const dashboardUrl = new URL(`${SPLUNK_BASE_URL}/en-US/app/app_adobepass/${HEALTH_SPLUNK_DASHBOARD_VIEW_NAME}`);
  dashboardUrl.searchParams.set("form.tr_NmSjmaI0.earliest", earliest);
  dashboardUrl.searchParams.set("form.tr_NmSjmaI0.latest", latest);
  if (requestorId) {
    dashboardUrl.searchParams.set("form.serviceProvider", requestorId);
  }
  if (environmentIndex) {
    dashboardUrl.searchParams.set("form.environment", environmentIndex);
  }
  return dashboardUrl.toString();
}

function getHealthSplunkTableDefinitions(queryContext = null) {
  return HEALTH_SPLUNK_TABLE_DEFINITIONS.map((entry) => ({
    key: String(entry.key || "").trim(),
    jobLabel: String(entry.jobLabel || "").trim(),
    title: String(entry.title || "").trim(),
    queryTemplate: String(entry.queryTemplate || "").trim(),
    query: compileHealthSplunkSearchTemplate(entry.queryTemplate, queryContext),
  }));
}

function escapeSplunkSearchTokenValue(value = "") {
  return String(value || "").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

function decodeHealthSplunkHtmlEntities(value = "") {
  const entityMap = {
    "&amp;": "&",
    "&quot;": '"',
    "&#39;": "'",
    "&apos;": "'",
    "&lt;": "<",
    "&gt;": ">",
    "&nbsp;": " ",
    "&excl;": "!",
  };
  return String(value || "").replace(/&(amp|quot|#39|apos|lt|gt|nbsp|excl);/gi, (match) => entityMap[match] || match);
}

function compileHealthSplunkSearchTemplate(queryTemplate = "", queryContext = null) {
  let compiled = decodeHealthSplunkHtmlEntities(String(queryTemplate || "").trim());
  const replacements = {
    environment: String(queryContext?.environmentIndex || getSplunkSearchIndexForEnvironment()).trim(),
    serviceProvider: escapeSplunkSearchTokenValue(queryContext?.requestorId || ""),
    "tr_NmSjmaI0.earliest": String(queryContext?.earliest || SPLUNK_SEARCH_EARLIEST).trim() || SPLUNK_SEARCH_EARLIEST,
    "tr_NmSjmaI0.latest": String(queryContext?.latest || SPLUNK_SEARCH_LATEST).trim() || SPLUNK_SEARCH_LATEST,
  };
  Object.entries(replacements).forEach(([tokenName, tokenValue]) => {
    const escapedTokenName = tokenName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    compiled = compiled.replace(new RegExp(`\\$${escapedTokenName}\\$`, "g"), String(tokenValue || ""));
  });
  return compiled.trim();
}

function parseSplunkPreviewRowsPayload(payload = null) {
  const fieldNames = (Array.isArray(payload?.fields) ? payload.fields : [])
    .map((entry) => (typeof entry === "string" ? entry : entry?.name))
    .map((value) => String(value || "").trim())
    .filter(Boolean);
  const columnArrays = Array.isArray(payload?.columns) ? payload.columns : [];
  const previewRowCount = columnArrays.reduce(
    (maxCount, columnValues) => Math.max(maxCount, Array.isArray(columnValues) ? columnValues.length : 0),
    0
  );
  if (fieldNames.length > 0 && columnArrays.length > 0 && previewRowCount > 0) {
    const rows = [];
    for (let rowIndex = 0; rowIndex < previewRowCount; rowIndex += 1) {
      const row = {};
      fieldNames.forEach((fieldName, fieldIndex) => {
        const columnValues = Array.isArray(columnArrays[fieldIndex]) ? columnArrays[fieldIndex] : [];
        row[fieldName] = normalizeSplunkCellValue(columnValues[rowIndex]);
      });
      rows.push(row);
    }
    return {
      columns: fieldNames,
      rows,
      totalRows: rows.length,
    };
  }

  const directRows = extractSplunkRowsFromResponsePayload(payload);
  const directFields = extractSplunkFieldsFromResponsePayload(payload);
  const columnOrder = collectSplunkColumnOrder(directRows, directFields);
  const uniqueRows = dedupeSplunkRows(directRows, columnOrder);
  return {
    columns: columnOrder,
    rows: normalizeSplunkRows(uniqueRows, columnOrder),
    totalRows: uniqueRows.length,
  };
}

function buildHealthSplunkTableResult(queryContext = null, tableDefinition = null, options = {}) {
  const columns = Array.isArray(options.columns) ? options.columns.map((value) => String(value || "").trim()).filter(Boolean) : [];
  const rows = Array.isArray(options.rows) ? options.rows : [];
  const totalRowsCandidate = Math.max(Number(options.totalRows || 0), rows.length);
  return {
    ok: options.ok !== false,
    pending: options.pending === true,
    authRequired: options.authRequired === true,
    authPending: options.authPending === true,
    key: String(tableDefinition?.key || "").trim(),
    title: String(tableDefinition?.title || "").trim(),
    query: String(tableDefinition?.query || "").trim(),
    queryTemplate: String(tableDefinition?.queryTemplate || "").trim(),
    selectionKey: String(queryContext?.selectionKey || "").trim(),
    checkedAt: Date.now(),
    queryContext,
    sid: String(options.sid || "").trim(),
    columns,
    rows,
    totalRows: totalRowsCandidate,
    displayedRows: rows.length,
    truncatedRows: totalRowsCandidate > rows.length,
    endpointUrl: String(options.endpointUrl || "").trim(),
    status: Number(options.status || 0),
    statusText: String(options.statusText || "").trim(),
    error: String(options.error || "").trim(),
    networkEvents: Array.isArray(options.networkEvents) ? options.networkEvents : [],
  };
}

function buildHealthSplunkPreviewReportPayload(
  queryContext = null,
  tableDefinition = null,
  sid = "",
  previewResponse = null,
  networkEvents = [],
  options = {}
) {
  const parsedPreview = parseSplunkPreviewRowsPayload(previewResponse?.parsed);
  return buildHealthSplunkTableResult(queryContext, tableDefinition, {
    ok: true,
    sid,
    columns: parsedPreview.columns,
    rows: parsedPreview.rows,
    totalRows: Math.max(Number(options.totalRowsFromMeta || 0), parsedPreview.totalRows),
    endpointUrl: String(previewResponse?.url || "").trim(),
    status: Number(previewResponse?.status || 0),
    statusText: String(previewResponse?.statusText || "").trim(),
    networkEvents,
  });
}

function isHealthSplunkPreviewComplete(payload = null) {
  return parseSplunkBoolean(payload?.preview) !== true;
}

async function fetchHealthSplunkPreviewReportBySid(queryContext = null, tableDefinition = null, sid = "", networkEvents = [], relayOptions = {}) {
  const normalizedSid = String(sid || "").trim();
  if (!normalizedSid) {
    return {
      ok: false,
      error: "Unable to fetch HEALTH Splunk results: SID is missing.",
      authRequired: false,
      report: buildHealthSplunkTableResult(queryContext, tableDefinition, {
        ok: false,
        error: "Unable to fetch HEALTH Splunk results: SID is missing.",
        networkEvents,
      }),
    };
  }

  const encodedSid = encodeURIComponent(normalizedSid);
  const previewParams = new URLSearchParams({
    output_mode: "json_cols",
    count: String(HEALTH_SPLUNK_TABLE_FETCH_LIMIT),
    offset: "0",
    progress: "true",
    requestTotalCount: "true",
    show_metadata: "true",
  });
  const previewUrl = `${HEALTH_SPLUNK_RESULTS_PREVIEW_BASE_URL}/${encodedSid}/results_preview?${previewParams.toString()}`;
  const previewStartedAt = Date.now();
  let lastError = "";
  let timedOut = false;

  do {
    const previewResponse = await runSplunkRelayRequest(
      previewUrl,
      {
        method: "GET",
        credentials: "include",
        headers: {
          Accept: "*/*",
        },
      },
      networkEvents,
      `health-table-${String(tableDefinition?.key || "").trim()}-results-preview`,
      relayOptions
    );
    if (previewResponse.authRequired) {
      return {
        ok: false,
        authRequired: true,
        error: "Splunk session is not active. Complete Splunk login in the opened tab and retry.",
        report: buildHealthSplunkTableResult(queryContext, tableDefinition, {
          ok: false,
          authRequired: true,
          sid: normalizedSid,
          endpointUrl: previewUrl,
          status: Number(previewResponse?.status || 0),
          statusText: String(previewResponse?.statusText || "").trim(),
          error: "Splunk session is not active. Complete Splunk login in the opened tab and retry.",
          networkEvents,
        }),
      };
    }
    if (!previewResponse.ok) {
      lastError = firstNonEmptyString([
        normalizeHttpErrorMessage(previewResponse.text),
        String(previewResponse.statusText || "").trim(),
        `HTTP ${previewResponse.status || 0}`,
      ]);
      break;
    }

    const report = buildHealthSplunkPreviewReportPayload(queryContext, tableDefinition, normalizedSid, previewResponse, networkEvents);

    if (report.rows.length > 0 || isHealthSplunkPreviewComplete(previewResponse.parsed)) {
      return {
        ok: true,
        authRequired: false,
        error: "",
        report,
      };
    }

    await waitForDelay(HEALTH_SPLUNK_JOB_POLL_INTERVAL_MS);
  } while ((timedOut = Date.now() - previewStartedAt >= HEALTH_SPLUNK_JOB_POLL_TIMEOUT_MS) === false);

  return {
    ok: false,
    error: lastError || (timedOut ? "Timed out waiting for HEALTH Splunk preview results." : "Unable to fetch HEALTH Splunk preview results for search SID."),
    authRequired: false,
    report: buildHealthSplunkTableResult(queryContext, tableDefinition, {
      ok: false,
      sid: normalizedSid,
      endpointUrl: previewUrl,
      error: lastError || (timedOut ? "Timed out waiting for HEALTH Splunk preview results." : "Unable to fetch HEALTH Splunk preview results for search SID."),
      networkEvents,
    }),
  };
}

async function runHealthSplunkTableSearch(queryContext = null, tableDefinition = null, options = {}) {
  const compiledTable = {
    key: String(tableDefinition?.key || "").trim(),
    jobLabel: String(tableDefinition?.jobLabel || "").trim(),
    title: String(tableDefinition?.title || "").trim(),
    queryTemplate: String(tableDefinition?.queryTemplate || "").trim(),
    query: firstNonEmptyString([
      tableDefinition?.query,
      compileHealthSplunkSearchTemplate(tableDefinition?.queryTemplate, queryContext),
    ]),
  };
  const networkEvents = [];
  if (!compiledTable.key || !compiledTable.title || !compiledTable.query) {
    return buildHealthSplunkTableResult(queryContext, compiledTable, {
      ok: false,
      error: "HEALTH Splunk table query is not configured.",
      networkEvents,
    });
  }

  const relayOptions = options?.relayOptions && typeof options.relayOptions === "object" ? options.relayOptions : {};
  const createBody = new URLSearchParams({
    search: normalizeSplunkJobSearchQuery(compiledTable.query),
    earliest_time: String(queryContext?.earliest || SPLUNK_SEARCH_EARLIEST).trim() || SPLUNK_SEARCH_EARLIEST,
    latest_time: String(queryContext?.latest || SPLUNK_SEARCH_LATEST).trim() || SPLUNK_SEARCH_LATEST,
    preview: "true",
    sid: "",
    check_risky_command: "true",
    provenance: `UI:dashboard:${HEALTH_SPLUNK_DASHBOARD_VIEW_NAME}`,
    label: String(compiledTable.jobLabel || compiledTable.key || compiledTable.title || "health-splunk-table").trim(),
    output_mode: "json",
  }).toString();
  const createUrl = HEALTH_SPLUNK_JOB_CREATE_URL;
  const response = await runSplunkRelayRequest(
    createUrl,
    {
      method: "POST",
      credentials: "include",
      headers: {
        Accept: "*/*",
        "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8",
        "X-Requested-With": "XMLHttpRequest",
      },
      body: createBody,
    },
    networkEvents,
    `health-table-${compiledTable.key}-create-job`,
    relayOptions
  );
  if (response.authRequired) {
    return buildHealthSplunkTableResult(queryContext, compiledTable, {
      ok: false,
      authRequired: true,
      endpointUrl: createUrl,
      status: Number(response?.status || 0),
      statusText: String(response?.statusText || "").trim(),
      error: "Splunk session is not active. Complete Splunk login in the opened tab and retry.",
      networkEvents,
    });
  }
  if (!response.ok) {
    return buildHealthSplunkTableResult(queryContext, compiledTable, {
      ok: false,
      endpointUrl: createUrl,
      status: Number(response?.status || 0),
      statusText: String(response?.statusText || "").trim(),
      error: firstNonEmptyString([
        normalizeHttpErrorMessage(response.text),
        String(response.statusText || "").trim(),
        `HTTP ${response.status || 0}`,
        "Unable to create HEALTH Splunk search job.",
      ]),
      networkEvents,
    });
  }
  const sid = extractSplunkJobSid(response.parsed);
  if (!sid) {
    return buildHealthSplunkTableResult(queryContext, compiledTable, {
      ok: false,
      endpointUrl: createUrl,
      error: "Splunk search job was created without a SID.",
      networkEvents,
    });
  }
  const previewReport = await fetchHealthSplunkPreviewReportBySid(queryContext, compiledTable, sid, networkEvents, relayOptions);
  if (previewReport.report) {
    return previewReport.report;
  }

  return buildHealthSplunkTableResult(queryContext, compiledTable, {
    ok: false,
    error: String(previewReport.error || "Unable to create HEALTH Splunk search job.").trim() || "Unable to create HEALTH Splunk search job.",
    networkEvents,
  });
}

function buildHealthSplunkDashboardReportPayload(queryContext = null, tableResults = [], options = {}) {
  const tables = Array.isArray(tableResults) ? tableResults.map((entry) => cloneJsonLikeValue(entry, null)).filter(Boolean) : [];
  const successCount = tables.filter((entry) => entry?.ok === true).length;
  const pendingCount = tables.filter((entry) => entry?.pending === true).length;
  const errorCount = tables.filter((entry) => entry?.pending !== true && entry?.ok !== true).length;
  const tableCount = tables.length;
  const pending = pendingCount > 0 && successCount === 0 && errorCount === 0;
  return {
    ok: errorCount === 0 && pendingCount === 0 && tableCount > 0,
    partial: successCount > 0 && (errorCount > 0 || pendingCount > 0),
    pending,
    authPending: options?.authPending === true || tables.some((entry) => entry?.authPending === true),
    selectionKey: String(queryContext?.selectionKey || "").trim(),
    checkedAt: Date.now(),
    queryContext,
    totalTables: tableCount,
    successCount,
    pendingCount,
    errorCount,
    tables,
    pendingMessage: pending
      ? String(options?.pendingMessage || "Waiting for Splunk sign-in/MFA to complete in the opened tab.").trim()
      : "",
    error:
      errorCount === 0 || pending
        ? ""
        : String(options?.error || "One or more HEALTH Splunk tables failed to load.").trim(),
  };
}

async function runHealthSplunkDashboardForSelection(rawQueryContext = null, options = {}) {
  const queryContext = buildHealthSplunkQueryContext(rawQueryContext);
  if (!queryContext.programmerId || !queryContext.requestorId) {
    const missingSelectionPayload = buildHealthSplunkDashboardReportPayload(queryContext, [], {
      error: "Select a Media Company and RequestorId before running HEALTH Splunk.",
    });
    return {
      ...missingSelectionPayload,
      ok: false,
    };
  }

  await ensureHealthWorkspacePremiumContext(queryContext.programmerId, {
    controllerReason: "health-splunk-dashboard",
    requestToken: Math.max(0, Number(options?.requestToken || state.premiumPanelRequestToken || 0)),
  }).catch(() => null);

  const openWorkspace = options.openWorkspace !== false;
  const activateWorkspace = options.activateWorkspace !== false;
  const forceLoginOnAuthFailure = options.forceLoginOnAuthFailure !== false;
  let targetWindowId = Number(options.targetWindowId || 0);

  if (openWorkspace) {
    const workspaceTab = await healthWorkspaceEnsureWorkspaceTab({
      activate: activateWorkspace,
      windowId: targetWindowId || undefined,
    });
    targetWindowId = Number(workspaceTab?.windowId || targetWindowId || state.healthWorkspaceWindowId || 0);
  }

  healthWorkspaceBroadcastControllerState(resolveSelectedProgrammer(), queryContext, targetWindowId);
  const scopedTables = getHealthSplunkTableDefinitions(queryContext);
  void healthWorkspaceSendWorkspaceMessage(
    "report-start",
    {
      selectionKey: queryContext.selectionKey,
      queryContext,
      startedAt: Date.now(),
      tables: scopedTables.map((entry) => ({
        key: entry.key,
        title: entry.title,
        query: entry.query,
      })),
    },
    {
      targetWindowId,
    }
  );

  const finalizeReport = (payload) => {
    healthWorkspaceStoreLatestReport(payload);
    void healthWorkspaceSendWorkspaceMessage("report-result", payload, { targetWindowId });
    return payload;
  };

  const sessionEvents = [];
  const sessionReady = await ensureSplunkSessionReady(queryContext, sessionEvents, {
    targetWindowId,
    forceLoginOnAuthFailure,
    timeoutMs: SPLUNK_AUTH_WAIT_TIMEOUT_MS,
    pollIntervalMs: SPLUNK_AUTH_WAIT_INTERVAL_MS,
  });
  if (Number(sessionReady?.targetWindowId || 0) > 0) {
    targetWindowId = Number(sessionReady.targetWindowId);
  }
  const splunkTab = sessionReady?.splunkTab || null;
  const splunkTabId = Number(splunkTab?.tabId || splunkTab?.id || 0);
  const relayOptions = {
    tabId: splunkTabId,
    allowTabRelay: true,
  };
  const session = sessionReady?.session || (await checkSplunkSessionActive(queryContext, sessionEvents, relayOptions));
  if (!sessionReady?.ok || !session?.active) {
    const authTables = scopedTables.map((entry) =>
      buildHealthSplunkTableResult(queryContext, entry, {
        ok: false,
        pending: true,
        authRequired: true,
        authPending: true,
        endpointUrl: `${SPLUNK_SPLUNKD_BASE}/services/authentication/current-context`,
        status: Number(session?.probe?.status || 0),
        statusText: String(session?.probe?.statusText || "").trim(),
        error: "",
        networkEvents: sessionEvents,
      })
    );
    return finalizeReport(
      buildHealthSplunkDashboardReportPayload(queryContext, authTables, {
        authPending: true,
        pendingMessage: firstNonEmptyString([
          sessionReady?.error,
          "Waiting for Splunk sign-in/MFA to complete in the opened tab.",
        ]),
      })
    );
  }

  const resolvedTables = scopedTables.slice();
  const tableResults = new Array(resolvedTables.length);
  const tablePromises = resolvedTables.map((tableDefinition, index) =>
    runHealthSplunkTableSearch(queryContext, tableDefinition, {
      relayOptions,
    })
      .then((tableResult) => ({ index, tableResult }))
      .catch((error) => ({
        index,
        tableResult: buildHealthSplunkTableResult(queryContext, tableDefinition, {
          ok: false,
          error: error instanceof Error ? error.message : String(error),
        }),
      }))
  );

  await Promise.all(
    tablePromises.map(async (tablePromise) => {
      const { index, tableResult } = await tablePromise;
      tableResults[index] = tableResult;
      const completedTables = tableResults.filter(Boolean).length;
      void healthWorkspaceSendWorkspaceMessage(
        "table-result",
        {
          selectionKey: queryContext.selectionKey,
          queryContext,
          table: tableResult,
          completedTables,
          totalTables: resolvedTables.length,
        },
        {
          targetWindowId,
        }
      );
    })
  );

  return finalizeReport(
    buildHealthSplunkDashboardReportPayload(queryContext, tableResults.filter(Boolean), {
      error: "One or more HEALTH Splunk tables failed to load.",
    })
  );
}

const HEALTH_SPLUNK_ESM_BRIDGE_MVPD_ERROR_TABLE_KEY = "sev2_mvpd_error_codes";
const HEALTH_SPLUNK_ESM_BRIDGE_MVPD_ERROR_PATH = "year/month/day/hour/minute/event/requestor-id/proxy/mvpd/reason/dc.json";
const HEALTH_SPLUNK_ESM_BRIDGE_DEFAULT_LIMIT = 500;

function normalizeHealthSplunkEsmBridgeTimestamp(value = "") {
  const normalizedValue = String(value || "").trim();
  if (!normalizedValue) {
    return null;
  }
  const timestampMs = Date.parse(normalizedValue);
  if (!Number.isFinite(timestampMs)) {
    return null;
  }
  return {
    value: normalizedValue,
    timestampMs,
    iso: new Date(timestampMs).toISOString(),
  };
}

function buildHealthSplunkEsmBridgeTimestampLabel(row = null) {
  const year = String(row?.year || "").trim();
  const month = String(row?.month || "").trim().padStart(2, "0");
  const day = String(row?.day || "").trim().padStart(2, "0");
  const hour = String(row?.hour || "").trim().padStart(2, "0") || "00";
  const minute = String(row?.minute || "").trim().padStart(2, "0") || "00";
  if (!year || !month || !day) {
    return "";
  }
  return `${year}-${month}-${day} ${hour}:${minute}`;
}

function buildHealthSplunkEsmBridgeSourceMeta(queryContext = null, table = null) {
  const rows = Array.isArray(table?.rows) ? table.rows : [];
  const timestampCandidates = rows
    .map((row) => normalizeHealthSplunkEsmBridgeTimestamp(row?._time))
    .filter(Boolean)
    .sort((left, right) => Number(left?.timestampMs || 0) - Number(right?.timestampMs || 0));
  const requestorIds = uniquePreserveOrder([
    ...rows.map((row) => String(row?.serviceProvider || "").trim()),
    String(queryContext?.requestorId || "").trim(),
  ]);
  const mvpdIds = uniquePreserveOrder(
    rows
      .map((row) => String(row?.mvpd || "").trim())
      .filter((value) => value && value !== "-" && value.toLowerCase() !== "all")
  );
  const events = uniquePreserveOrder(
    rows
      .map((row) => String(row?.event || "").trim())
      .filter(Boolean)
  );
  return {
    rowCount: rows.length,
    requestorIds,
    mvpdIds,
    events,
    start: timestampCandidates[0]?.iso || "",
    end: timestampCandidates[timestampCandidates.length - 1]?.iso || "",
    sourceWindowStart: timestampCandidates[0]?.value || "",
    sourceWindowEnd: timestampCandidates[timestampCandidates.length - 1]?.value || "",
  };
}

function buildHealthSplunkEsmBridgeQueryContext(queryContext = null, table = null) {
  const sourceMeta = buildHealthSplunkEsmBridgeSourceMeta(queryContext, table);
  return {
    programmerId: String(queryContext?.programmerId || "").trim(),
    programmerName: String(queryContext?.programmerName || "").trim(),
    mediaCompany: String(queryContext?.programmerId || "").trim(),
    environmentKey: String(queryContext?.environmentKey || "").trim(),
    environmentLabel: String(queryContext?.environmentLabel || "").trim(),
    requestorIds: sourceMeta.requestorIds,
    mvpdIds: sourceMeta.mvpdIds,
    events: sourceMeta.events,
    start: sourceMeta.start,
    end: sourceMeta.end,
    sourceWindowStart: sourceMeta.sourceWindowStart,
    sourceWindowEnd: sourceMeta.sourceWindowEnd,
    sourceRowCount: sourceMeta.rowCount,
    requestSource: "health-splunk-esm-bridge",
  };
}

function buildHealthSplunkEsmBridgeRows(rows = []) {
  const normalizedRows = (Array.isArray(rows) ? rows : [])
    .map((row) => ({
      timestamp: buildHealthSplunkEsmBridgeTimestampLabel(row),
      "requestor-id": String(row?.["requestor-id"] || "").trim(),
      mvpd: String(row?.mvpd || "").trim(),
      event: String(row?.event || "").trim(),
      proxy: String(row?.proxy || "").trim(),
      reason: String(row?.reason || "").trim(),
      dc: String(row?.dc || "").trim(),
      count: String(row?.count ?? "").trim(),
      __timestampMs: Date.UTC(
        Number(row?.year || 0),
        Math.max(0, Number(row?.month || 1) - 1),
        Math.max(1, Number(row?.day || 1)),
        Math.max(0, Number(row?.hour || 0)),
        Math.max(0, Number(row?.minute || 0)),
        0,
        0
      ),
    }))
    .sort((left, right) => {
      const timestampDelta = Number(right?.__timestampMs || 0) - Number(left?.__timestampMs || 0);
      if (timestampDelta !== 0) {
        return timestampDelta;
      }
      return Number(right?.count || 0) - Number(left?.count || 0);
    })
    .map((row) => {
      const { __timestampMs, ...displayRow } = row;
      return displayRow;
    });

  return {
    columns: ["timestamp", "requestor-id", "mvpd", "event", "proxy", "reason", "dc", "count"],
    rows: normalizedRows,
  };
}

async function runHealthSplunkEsmBridgeForTable(rawQueryContext = null, table = null) {
  const tableKey = String(table?.key || "").trim();
  const queryContext = buildHealthSplunkQueryContext(rawQueryContext);
  if (tableKey !== HEALTH_SPLUNK_ESM_BRIDGE_MVPD_ERROR_TABLE_KEY) {
    return {
      ok: false,
      tableKey,
      error: "This HEALTH Splunk table does not have an ESM bridge.",
    };
  }
  if (!queryContext.programmerId) {
    return {
      ok: false,
      tableKey,
      error: "Select a Media Company before loading the ESM bridge.",
    };
  }

  const bridgeContext = buildHealthSplunkEsmBridgeQueryContext(queryContext, table);
  if (!bridgeContext.start || !bridgeContext.end) {
    return {
      ok: true,
      tableKey,
      title: "ESM xref",
      subtitle: "No Splunk rows are available to scope the ESM bridge.",
      queryContext: bridgeContext,
      requestUrl: "",
      columns: ["timestamp", "requestor-id", "mvpd", "event", "proxy", "reason", "dc", "count"],
      rows: [],
      totalRows: 0,
      error: "",
      loadedAt: Date.now(),
    };
  }
  if (bridgeContext.requestorIds.length === 0) {
    return {
      ok: false,
      tableKey,
      error: "Unable to determine a RequestorId from the Splunk result set.",
    };
  }
  if (bridgeContext.events.length === 0) {
    return {
      ok: false,
      tableKey,
      error: "Unable to determine an event from the Splunk result set.",
    };
  }

  const bridgeFetchResult = await fetchEsmHealthJson(bridgeContext, HEALTH_SPLUNK_ESM_BRIDGE_MVPD_ERROR_PATH, {
    limit: HEALTH_SPLUNK_ESM_BRIDGE_DEFAULT_LIMIT,
    requestorIds: bridgeContext.requestorIds,
    mvpdIds: bridgeContext.mvpdIds,
    events: bridgeContext.events,
  });
  const displayRows = buildHealthSplunkEsmBridgeRows(bridgeFetchResult.rows);
  return {
    ok: bridgeFetchResult.ok === true,
    tableKey,
    title: "ESM xref",
    subtitle: "Cross-referenced from Splunk MVPD error rows into the live ESM v3 event tree.",
    queryContext: bridgeContext,
    requestUrl: String(bridgeFetchResult.requestUrl || "").trim(),
    columns: displayRows.columns,
    rows: displayRows.rows,
    totalRows: displayRows.rows.length,
    status: Number(bridgeFetchResult.status || 0),
    statusText: String(bridgeFetchResult.statusText || "").trim(),
    error: String(bridgeFetchResult.error || "").trim(),
    loadedAt: Date.now(),
  };
}

function normalizeEsmHealthGranularity(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  return Object.prototype.hasOwnProperty.call(ESM_HEALTH_GRANULARITY_PATH_BY_KEY, normalized)
    ? normalized
    : ESM_HEALTH_DEFAULT_GRANULARITY;
}

function normalizeEsmHealthIsoDate(value = "") {
  const normalized = String(value || "").trim();
  return /^\d{4}-\d{2}-\d{2}$/.test(normalized) ? normalized : "";
}

function normalizeEsmHealthFilterList(values = []) {
  const source = Array.isArray(values) ? values : [values];
  return uniquePreserveOrder(
    source
      .map((entry) => String(entry || "").trim())
      .filter(Boolean)
  );
}

function getEsmHealthPacificDateParts(timestamp = Date.now()) {
  try {
    const formatter = new Intl.DateTimeFormat("en-CA", {
      timeZone: "America/Los_Angeles",
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
    });
    const parts = formatter.formatToParts(new Date(Number(timestamp || Date.now())));
    const record = {};
    parts.forEach((part) => {
      if (part?.type && part.type !== "literal") {
        record[part.type] = String(part.value || "").trim();
      }
    });
    if (record.year && record.month && record.day) {
      return {
        year: record.year,
        month: record.month,
        day: record.day,
        iso: `${record.year}-${record.month}-${record.day}`,
      };
    }
  } catch {
    // Fall through to UTC fallback.
  }

  const fallback = new Date(Number(timestamp || Date.now()));
  const year = String(fallback.getUTCFullYear());
  const month = String(fallback.getUTCMonth() + 1).padStart(2, "0");
  const day = String(fallback.getUTCDate()).padStart(2, "0");
  return {
    year,
    month,
    day,
    iso: `${year}-${month}-${day}`,
  };
}

function getEsmHealthDefaultDateRange(nowMs = Date.now()) {
  const pacific = getEsmHealthPacificDateParts(nowMs);
  return {
    start: shiftEsmHealthIsoDate(pacific.iso, -1) || pacific.iso,
    end: pacific.iso,
  };
}

function shiftEsmHealthIsoDate(isoDate = "", dayDelta = 0) {
  const normalized = normalizeEsmHealthIsoDate(isoDate);
  const delta = Number(dayDelta || 0);
  if (!normalized || !Number.isFinite(delta) || delta === 0) {
    return normalized;
  }
  const parsed = new Date(`${normalized}T12:00:00Z`);
  if (!Number.isFinite(parsed.getTime())) {
    return normalized;
  }
  parsed.setUTCDate(parsed.getUTCDate() + delta);
  return parsed.toISOString().slice(0, 10);
}

function buildEsmHealthReportPath(granularity = "", dimensionSegments = []) {
  const normalizedGranularity = normalizeEsmHealthGranularity(granularity);
  const basePath = String(
    ESM_HEALTH_GRANULARITY_PATH_BY_KEY[normalizedGranularity] ||
      ESM_HEALTH_GRANULARITY_PATH_BY_KEY[ESM_HEALTH_DEFAULT_GRANULARITY] ||
      ESM_HEALTH_GRANULARITY_PATH_BY_KEY.day ||
      ""
  ).replace(/\.json$/i, "");
  const normalizedSegments = normalizeEsmHealthFilterList(dimensionSegments);
  return `${[basePath, ...normalizedSegments].filter(Boolean).join("/")}.json`;
}

function resolveEsmHealthDateRange(startValue = "", endValue = "") {
  const defaults = getEsmHealthDefaultDateRange();
  let start = normalizeEsmHealthIsoDate(startValue) || defaults.start;
  let end = normalizeEsmHealthIsoDate(endValue) || defaults.end;
  if (start > end) {
    const originalStart = start;
    start = end;
    end = originalStart;
  }
  return {
    start,
    end,
  };
}

function buildEsmHealthWorkspaceBaseSelectionKey(context = null) {
  const environmentKey =
    String(context?.environmentKey || getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() ||
    DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const programmerId = String(context?.programmerId || "").trim();
  if (!programmerId) {
    return "";
  }
  const baseRequestorIds = normalizeEsmHealthFilterList(context?.baseRequestorIds);
  const baseMvpdIds = normalizeEsmHealthFilterList(context?.baseMvpdIds);
  return [environmentKey, programmerId, baseRequestorIds.join(",") || "*", baseMvpdIds.join(",") || "*"].join("|");
}

function buildEsmHealthWorkspaceSelectionKey(context = null) {
  const baseKey = buildEsmHealthWorkspaceBaseSelectionKey(context);
  if (!baseKey) {
    return "";
  }
  const dateRange = resolveEsmHealthDateRange(context?.start, context?.end);
  const granularity = normalizeEsmHealthGranularity(context?.granularity);
  const drilldownRequestorIds = normalizeEsmHealthFilterList(context?.drilldownRequestorIds);
  const drilldownMvpdIds = normalizeEsmHealthFilterList(context?.drilldownMvpdIds);
  const platforms = normalizeEsmHealthFilterList(context?.platforms);
  return [
    baseKey,
    dateRange.start,
    dateRange.end,
    granularity,
    drilldownRequestorIds.join(",") || "*",
    drilldownMvpdIds.join(",") || "*",
    platforms.join(",") || "*",
  ].join("|");
}

function buildEsmHealthWorkspaceControllerContextKey(context = null, premiumPanelRequestToken = state.premiumPanelRequestToken) {
  const controllerSelectionKey = String(
    context?.controllerSelectionKey || buildEsmHealthWorkspaceBaseSelectionKey(context)
  ).trim();
  if (!controllerSelectionKey) {
    return "";
  }
  return `${controllerSelectionKey}::${Math.max(0, Number(premiumPanelRequestToken || 0))}`;
}

function buildEsmHealthDashboardQueryContext(rawContext = null) {
  const context = rawContext && typeof rawContext === "object" ? rawContext : {};
  const resolvedProgrammer = resolveSelectedProgrammer();
  const environment = getActiveAdobePassEnvironment();
  const programmerId = String(context.programmerId || resolvedProgrammer?.programmerId || "").trim();
  const programmerName = firstNonEmptyString([
    context.programmerName,
    resolvedProgrammer?.programmerName,
    resolvedProgrammer?.mediaCompanyName,
  ]);
  const baseRequestorIds = normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(context, "baseRequestorIds") ? context.baseRequestorIds : [state.selectedRequestorId]
  );
  const baseMvpdIds = normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(context, "baseMvpdIds") ? context.baseMvpdIds : [state.selectedMvpdId]
  );
  const drilldownRequestorIds = normalizeEsmHealthFilterList(context.drilldownRequestorIds);
  const drilldownMvpdIds = normalizeEsmHealthFilterList(context.drilldownMvpdIds);
  const platforms = normalizeEsmHealthFilterList(context.platforms);
  const requestorIds = drilldownRequestorIds.length > 0 ? drilldownRequestorIds : baseRequestorIds;
  const mvpdIds = drilldownMvpdIds.length > 0 ? drilldownMvpdIds : baseMvpdIds;
  const dateRange = resolveEsmHealthDateRange(context.start, context.end);
  const granularity = normalizeEsmHealthGranularity(context.granularity);
  const environmentKey = String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const environmentLabel = firstNonEmptyString([environment?.label, environment?.shortCode, environmentKey]);
  const queryContext = {
    programmerId,
    programmerName,
    mediaCompany: programmerId,
    environmentKey,
    environmentLabel,
    baseRequestorIds,
    baseMvpdIds,
    drilldownRequestorIds,
    drilldownMvpdIds,
    requestorIds,
    mvpdIds,
    platforms,
    start: dateRange.start,
    end: dateRange.end,
    granularity,
    timezoneLabel: "PST effective",
    requestSource: String(context.requestSource || "esm-health-dashboard").trim() || "esm-health-dashboard",
  };
  queryContext.controllerSelectionKey = buildEsmHealthWorkspaceBaseSelectionKey(queryContext);
  queryContext.selectionKey = buildEsmHealthWorkspaceSelectionKey(queryContext);
  return queryContext;
}

function rebaseEsmHealthDashboardQueryContextForCurrentSelection(rawContext = null, options = {}) {
  const sourceContext = rawContext && typeof rawContext === "object" ? rawContext : {};
  const currentSelectionContext = esmHealthWorkspaceGetSelectionContext(resolveSelectedProgrammer());
  const sameControllerSelection =
    String(sourceContext?.controllerSelectionKey || "").trim() === String(currentSelectionContext?.controllerSelectionKey || "").trim();
  const rebasedContext = {
    ...currentSelectionContext,
    start: String(sourceContext?.start || currentSelectionContext?.start || "").trim(),
    end: String(sourceContext?.end || currentSelectionContext?.end || "").trim(),
    requestSource:
      String(options?.requestSource || sourceContext?.requestSource || "esm-health-dashboard").trim() ||
      "esm-health-dashboard",
  };
  if (sameControllerSelection) {
    rebasedContext.granularity = normalizeEsmHealthGranularity(sourceContext?.granularity);
    rebasedContext.drilldownRequestorIds = normalizeEsmHealthFilterList(sourceContext?.drilldownRequestorIds);
    rebasedContext.drilldownMvpdIds = normalizeEsmHealthFilterList(sourceContext?.drilldownMvpdIds);
    rebasedContext.platforms = normalizeEsmHealthFilterList(sourceContext?.platforms);
  }
  return buildEsmHealthDashboardQueryContext(rebasedContext);
}

function buildEsmHealthStatusMessage(queryContext = null) {
  const environmentLabel = String(queryContext?.environmentLabel || "").trim();
  const programmerId = String(queryContext?.programmerId || "").trim();
  const requestorLabel = normalizeEsmHealthFilterList(queryContext?.requestorIds).join(", ");
  const mvpdLabel = normalizeEsmHealthFilterList(queryContext?.mvpdIds).join(", ");
  return [programmerId, requestorLabel ? `Requestor ${requestorLabel}` : "", mvpdLabel ? `MVPD ${mvpdLabel}` : "", environmentLabel]
    .filter(Boolean)
    .join(" | ");
}

function getEsmHealthMetricNumber(row = null, key = "") {
  const parsed = Number(row?.[key] ?? 0);
  return Number.isFinite(parsed) ? parsed : 0;
}

function computeEsmHealthDerivedMetrics(source = null) {
  const authnAttempts = Math.max(0, Number(source?.authnAttempts || 0));
  const authnSuccessful = Math.max(0, Number(source?.authnSuccessful || 0));
  const authnFailed = Math.max(0, Number(source?.authnFailed || 0));
  const authzAttempts = Math.max(0, Number(source?.authzAttempts || 0));
  const authzSuccessful = Math.max(0, Number(source?.authzSuccessful || 0));
  const authzFailed = Math.max(0, Number(source?.authzFailed || 0));
  const authzRejected = Math.max(0, Number(source?.authzRejected || 0));
  const authzLatency = Math.max(0, Number(source?.authzLatency || 0));
  const mediaTokens = Math.max(0, Number(source?.mediaTokens || 0));
  const clientlessTokens = Math.max(0, Number(source?.clientlessTokens || 0));
  const clientlessFailures = Math.max(0, Number(source?.clientlessFailures || 0));
  const authzLatencyDenominator = authzSuccessful + authzFailed;
  const clientlessFailureDenominator = clientlessFailures + clientlessTokens;
  const issueEvents = authnFailed + authzFailed + authzRejected + clientlessFailures;
  return {
    authnConversion: authnAttempts > 0 ? authnSuccessful / authnAttempts : null,
    authnFailureRate: authnAttempts > 0 ? authnFailed / authnAttempts : null,
    authzConversion: authzAttempts > 0 ? authzSuccessful / authzAttempts : null,
    authzErrorRate: authzAttempts > 0 ? (authzFailed + authzRejected) / authzAttempts : null,
    avgAuthzLatency: authzLatencyDenominator > 0 ? authzLatency / authzLatencyDenominator : null,
    playRequests: mediaTokens,
    clientlessFailureRate: clientlessFailureDenominator > 0 ? clientlessFailures / clientlessFailureDenominator : null,
    issueEvents,
  };
}

function esmHealthPartsToUtcMs(row = null) {
  const year = Number(row?.year ?? 1970);
  const month = Number(row?.month ?? 1);
  const day = Number(row?.day ?? 1);
  const hour = Number(row?.hour ?? 0);
  return (
    Date.UTC(
      Number.isFinite(year) ? year : 1970,
      Number.isFinite(month) ? month - 1 : 0,
      Number.isFinite(day) ? day : 1,
      Number.isFinite(hour) ? hour : 0,
      0,
      0
    ) -
    ESM_SOURCE_UTC_OFFSET_MINUTES * 60 * 1000
  );
}

function buildEsmHealthBucketMeta(row = null, granularity = ESM_HEALTH_DEFAULT_GRANULARITY) {
  const year = Number(row?.year ?? 1970);
  const month = Number(row?.month ?? 1);
  const day = Number(row?.day ?? 1);
  const hour = Number(row?.hour ?? 0);
  const paddedMonth = String(Math.max(1, month)).padStart(2, "0");
  const paddedDay = String(Math.max(1, day)).padStart(2, "0");
  const paddedHour = String(Math.max(0, hour)).padStart(2, "0");
  const normalizedGranularity = normalizeEsmHealthGranularity(granularity);
  if (normalizedGranularity === "month") {
    return {
      key: `${year}-${paddedMonth}`,
      label: `${paddedMonth}/${year}`,
      timestamp: esmHealthPartsToUtcMs({ year, month, day: 1, hour: 0 }),
    };
  }
  if (normalizedGranularity === "hour") {
    return {
      key: `${year}-${paddedMonth}-${paddedDay}T${paddedHour}`,
      label: `${paddedMonth}/${paddedDay} ${paddedHour}:00`,
      timestamp: esmHealthPartsToUtcMs({ year, month, day, hour }),
    };
  }
  return {
    key: `${year}-${paddedMonth}-${paddedDay}`,
    label: `${paddedMonth}/${paddedDay}/${year}`,
    timestamp: esmHealthPartsToUtcMs({ year, month, day, hour: 0 }),
  };
}

function aggregateEsmHealthBackboneRows(rows = [], granularity = ESM_HEALTH_DEFAULT_GRANULARITY) {
  const buckets = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const meta = buildEsmHealthBucketMeta(row, granularity);
    if (!meta.key) {
      return;
    }
    if (!buckets.has(meta.key)) {
      buckets.set(meta.key, {
        bucketKey: meta.key,
        label: meta.label,
        timestamp: meta.timestamp,
        authnAttempts: 0,
        authnSuccessful: 0,
        authnFailed: 0,
        authzAttempts: 0,
        authzSuccessful: 0,
        authzFailed: 0,
        authzRejected: 0,
        authzLatency: 0,
        mediaTokens: 0,
        clientlessTokens: 0,
        clientlessFailures: 0,
      });
    }
    const bucket = buckets.get(meta.key);
    bucket.authnAttempts += getEsmHealthMetricNumber(row, "authn-attempts");
    bucket.authnSuccessful += getEsmHealthMetricNumber(row, "authn-successful");
    bucket.authnFailed += getEsmHealthMetricNumber(row, "authn-failed");
    bucket.authzAttempts += getEsmHealthMetricNumber(row, "authz-attempts");
    bucket.authzSuccessful += getEsmHealthMetricNumber(row, "authz-successful");
    bucket.authzFailed += getEsmHealthMetricNumber(row, "authz-failed");
    bucket.authzRejected += getEsmHealthMetricNumber(row, "authz-rejected");
    bucket.authzLatency += getEsmHealthMetricNumber(row, "authz-latency");
    bucket.mediaTokens += getEsmHealthMetricNumber(row, "media-tokens");
    bucket.clientlessTokens += getEsmHealthMetricNumber(row, "clientless-tokens");
    bucket.clientlessFailures += getEsmHealthMetricNumber(row, "clientless-failures");
  });

  return Array.from(buckets.values())
    .sort((left, right) => Number(left?.timestamp || 0) - Number(right?.timestamp || 0))
    .map((bucket) => ({
      ...bucket,
      ...computeEsmHealthDerivedMetrics(bucket),
    }));
}

function aggregateEsmHealthUniqueRows(rows = []) {
  const buckets = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const meta = buildEsmHealthBucketMeta(row, "day");
    if (!meta.key) {
      return;
    }
    if (!buckets.has(meta.key)) {
      buckets.set(meta.key, {
        bucketKey: meta.key,
        label: meta.label,
        timestamp: meta.timestamp,
        uniqueAccounts: 0,
        uniqueSessions: 0,
      });
    }
    const bucket = buckets.get(meta.key);
    bucket.uniqueAccounts += getEsmHealthMetricNumber(row, "unique-accounts");
    bucket.uniqueSessions += getEsmHealthMetricNumber(row, "unique-sessions");
  });

  return Array.from(buckets.values()).sort((left, right) => Number(left?.timestamp || 0) - Number(right?.timestamp || 0));
}

function aggregateEsmHealthBreakdownRows(rows = [], dimensionKeys = [], limit = ESM_HEALTH_TOP_ROW_LIMIT, options = {}) {
  const normalizedDimensionKeys = uniquePreserveOrder(
    (Array.isArray(dimensionKeys) ? dimensionKeys : [dimensionKeys])
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
  const buildLabel =
    typeof options?.buildLabel === "function"
      ? options.buildLabel
      : (values) =>
          normalizedDimensionKeys
            .map((key) => String(values?.[key] || "").trim())
            .filter(Boolean)
            .join(" / ");
  const buckets = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const dimensionValues = {};
    normalizedDimensionKeys.forEach((key) => {
      dimensionValues[key] = String(row?.[key] || "").trim() || "(unknown)";
    });
    const bucketKey =
      normalizedDimensionKeys.length > 0
        ? normalizedDimensionKeys.map((key) => String(dimensionValues[key] || "").trim() || "(unknown)").join("\u001f")
        : "(aggregate)";
    const bucketLabel = String(buildLabel(dimensionValues, row) || "").trim() || "(unknown)";
    if (!buckets.has(bucketKey)) {
      buckets.set(bucketKey, {
        label: bucketLabel,
        ...dimensionValues,
        authnAttempts: 0,
        authnSuccessful: 0,
        authnFailed: 0,
        authzAttempts: 0,
        authzSuccessful: 0,
        authzFailed: 0,
        authzRejected: 0,
        authzLatency: 0,
        mediaTokens: 0,
        clientlessTokens: 0,
        clientlessFailures: 0,
      });
    }
    const bucket = buckets.get(bucketKey);
    bucket.authnAttempts += getEsmHealthMetricNumber(row, "authn-attempts");
    bucket.authnSuccessful += getEsmHealthMetricNumber(row, "authn-successful");
    bucket.authnFailed += getEsmHealthMetricNumber(row, "authn-failed");
    bucket.authzAttempts += getEsmHealthMetricNumber(row, "authz-attempts");
    bucket.authzSuccessful += getEsmHealthMetricNumber(row, "authz-successful");
    bucket.authzFailed += getEsmHealthMetricNumber(row, "authz-failed");
    bucket.authzRejected += getEsmHealthMetricNumber(row, "authz-rejected");
    bucket.authzLatency += getEsmHealthMetricNumber(row, "authz-latency");
    bucket.mediaTokens += getEsmHealthMetricNumber(row, "media-tokens");
    bucket.clientlessTokens += getEsmHealthMetricNumber(row, "clientless-tokens");
    bucket.clientlessFailures += getEsmHealthMetricNumber(row, "clientless-failures");
  });

  return Array.from(buckets.values())
    .map((entry) => ({
      ...entry,
      ...computeEsmHealthDerivedMetrics(entry),
    }))
    .sort((left, right) => {
      const issueDelta = Number(right?.issueEvents || 0) - Number(left?.issueEvents || 0);
      if (issueDelta !== 0) {
        return issueDelta;
      }
      const mediaDelta = Number(right?.mediaTokens || 0) - Number(left?.mediaTokens || 0);
      if (mediaDelta !== 0) {
        return mediaDelta;
      }
      const authzDelta = Number(right?.authzAttempts || 0) - Number(left?.authzAttempts || 0);
      if (authzDelta !== 0) {
        return authzDelta;
      }
      const authnDelta = Number(right?.authnAttempts || 0) - Number(left?.authnAttempts || 0);
      if (authnDelta !== 0) {
        return authnDelta;
      }
      return String(left?.label || "").localeCompare(String(right?.label || ""), undefined, {
        numeric: true,
        sensitivity: "base",
      });
    })
    .slice(0, Math.max(1, Number(limit || ESM_HEALTH_TOP_ROW_LIMIT)))
    .map((entry, index) => {
      if (typeof options?.mapRow === "function") {
        return options.mapRow(entry, index);
      }
      return entry;
    });
}

function buildEsmHealthSummary(backboneSeries = [], uniqueSeries = [], breakdowns = {}) {
  const totals = {
    authnAttempts: 0,
    authnSuccessful: 0,
    authnFailed: 0,
    authzAttempts: 0,
    authzSuccessful: 0,
    authzFailed: 0,
    authzRejected: 0,
    authzLatency: 0,
    mediaTokens: 0,
    clientlessTokens: 0,
    clientlessFailures: 0,
  };
  (Array.isArray(backboneSeries) ? backboneSeries : []).forEach((entry) => {
    totals.authnAttempts += Number(entry?.authnAttempts || 0);
    totals.authnSuccessful += Number(entry?.authnSuccessful || 0);
    totals.authnFailed += Number(entry?.authnFailed || 0);
    totals.authzAttempts += Number(entry?.authzAttempts || 0);
    totals.authzSuccessful += Number(entry?.authzSuccessful || 0);
    totals.authzFailed += Number(entry?.authzFailed || 0);
    totals.authzRejected += Number(entry?.authzRejected || 0);
    totals.authzLatency += Number(entry?.authzLatency || 0);
    totals.mediaTokens += Number(entry?.mediaTokens || 0);
    totals.clientlessTokens += Number(entry?.clientlessTokens || 0);
    totals.clientlessFailures += Number(entry?.clientlessFailures || 0);
  });
  const latestUniqueBucket = Array.isArray(uniqueSeries) && uniqueSeries.length > 0 ? uniqueSeries[uniqueSeries.length - 1] : null;
  const mvpdRows = Array.isArray(breakdowns?.mvpdRows) ? breakdowns.mvpdRows : [];
  const requestorRows = Array.isArray(breakdowns?.requestorRows) ? breakdowns.requestorRows : [];
  const platformRows = Array.isArray(breakdowns?.platformRows) ? breakdowns.platformRows : [];
  const applicationRows = Array.isArray(breakdowns?.applicationRows) ? breakdowns.applicationRows : [];
  const apiRows = Array.isArray(breakdowns?.apiRows) ? breakdowns.apiRows : [];
  const sdkRows = Array.isArray(breakdowns?.sdkRows) ? breakdowns.sdkRows : [];
  return {
    ...totals,
    ...computeEsmHealthDerivedMetrics(totals),
    latestUniqueAccounts: Number(latestUniqueBucket?.uniqueAccounts || 0),
    latestUniqueSessions: Number(latestUniqueBucket?.uniqueSessions || 0),
    latestUniqueLabel: String(latestUniqueBucket?.label || "").trim(),
    seriesPoints: Array.isArray(backboneSeries) ? backboneSeries.length : 0,
    activeMvpds: mvpdRows.length,
    activeRequestors: requestorRows.length,
    activePlatforms: platformRows.length,
    activeApplications: applicationRows.length,
    activeApis: apiRows.length,
    activeSdkVersions: sdkRows.length,
    topMvpdLabel: String(mvpdRows[0]?.mvpd || mvpdRows[0]?.label || "").trim(),
    topRequestorLabel: String(requestorRows[0]?.requestorId || requestorRows[0]?.label || "").trim(),
    topPlatformLabel: String(platformRows[0]?.platform || platformRows[0]?.label || "").trim(),
    topApplicationLabel: String(applicationRows[0]?.applicationLabel || applicationRows[0]?.label || "").trim(),
    topApiLabel: String(apiRows[0]?.api || apiRows[0]?.label || "").trim(),
    topSdkLabel: String(sdkRows[0]?.sdkVersionLabel || sdkRows[0]?.label || "").trim(),
  };
}

function addEsmHealthTrafficShare(rows = [], totalPlayRequests = 0) {
  const total = Math.max(0, Number(totalPlayRequests || 0));
  return (Array.isArray(rows) ? rows : []).map((entry) => ({
    ...entry,
    trafficShare: total > 0 ? Number(entry?.mediaTokens || 0) / total : null,
  }));
}

function buildCmHealthWorkspaceBaseSelectionKey(context = null) {
  const environmentKey =
    String(context?.environmentKey || getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() ||
    DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const programmerId = String(context?.programmerId || "").trim();
  const tenantScope = resolveCmUsageTenantScopeValue(context?.tenantScope);
  if (!programmerId) {
    return "";
  }
  return [environmentKey, programmerId, tenantScope || "*"].join("|");
}

function buildCmHealthWorkspaceSelectionKey(context = null) {
  const baseKey = buildCmHealthWorkspaceBaseSelectionKey(context);
  if (!baseKey) {
    return "";
  }
  const dateRange = resolveEsmHealthDateRange(context?.start, context?.end);
  const granularity = normalizeEsmHealthGranularity(context?.granularity || CM_HEALTH_DEFAULT_GRANULARITY);
  const drilldownMvpdIds = normalizeEsmHealthFilterList(context?.drilldownMvpdIds);
  const platforms = normalizeEsmHealthFilterList(context?.platforms);
  const channels = normalizeEsmHealthFilterList(context?.channels);
  return [
    baseKey,
    dateRange.start,
    dateRange.end,
    granularity,
    drilldownMvpdIds.join(",") || "*",
    platforms.join(",") || "*",
    channels.join(",") || "*",
  ].join("|");
}

function buildCmHealthWorkspaceControllerContextKey(context = null, premiumPanelRequestToken = state.premiumPanelRequestToken) {
  const controllerSelectionKey = String(
    context?.controllerSelectionKey || buildCmHealthWorkspaceBaseSelectionKey(context)
  ).trim();
  if (!controllerSelectionKey) {
    return "";
  }
  return `${controllerSelectionKey}::${Math.max(0, Number(premiumPanelRequestToken || 0))}`;
}

function resolveCmHealthFilterMode(context = null) {
  const channels = normalizeEsmHealthFilterList(context?.channels);
  if (channels.length > 0) {
    return "channel";
  }
  const mvpdIds = normalizeEsmHealthFilterList(context?.drilldownMvpdIds || context?.mvpdIds);
  if (mvpdIds.length > 0) {
    return "mvpd";
  }
  const platforms = normalizeEsmHealthFilterList(context?.platforms);
  if (platforms.length > 0) {
    return "platform";
  }
  return "";
}

function buildCmHealthDashboardQueryContext(rawContext = null) {
  const context = rawContext && typeof rawContext === "object" ? rawContext : {};
  const resolvedProgrammer = resolveSelectedProgrammer();
  const environment = getActiveAdobePassEnvironment();
  const programmerId = String(context.programmerId || resolvedProgrammer?.programmerId || "").trim();
  const programmerName = firstNonEmptyString([
    context.programmerName,
    resolvedProgrammer?.programmerName,
    resolvedProgrammer?.mediaCompanyName,
  ]);
  const drilldownMvpdIds = normalizeEsmHealthFilterList(context.drilldownMvpdIds);
  const platforms = normalizeEsmHealthFilterList(context.platforms);
  const channels = normalizeEsmHealthFilterList(context.channels);
  const dateRange = resolveEsmHealthDateRange(context.start, context.end);
  const granularity = normalizeEsmHealthGranularity(context.granularity || CM_HEALTH_DEFAULT_GRANULARITY);
  const environmentKey = String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const environmentLabel = firstNonEmptyString([environment?.label, environment?.shortCode, environmentKey]);
  const tenantScope = resolveCmUsageTenantScopeValue(
    context?.tenantScope,
    getCmTenantScopeForProgrammer(programmerId ? { programmerId } : resolvedProgrammer)
  );
  const queryContext = {
    programmerId,
    programmerName,
    mediaCompany: programmerId,
    environmentKey,
    environmentLabel,
    tenantScope,
    drilldownMvpdIds,
    mvpdIds: drilldownMvpdIds.slice(),
    platforms,
    channels,
    start: dateRange.start,
    end: dateRange.end,
    granularity,
    timezoneLabel: "PST effective",
    requestorHint: String(context.requestorHint || state.selectedRequestorId || "").trim(),
    requestSource: String(context.requestSource || "cm-health-dashboard").trim() || "cm-health-dashboard",
  };
  queryContext.filterMode = resolveCmHealthFilterMode(queryContext);
  if (queryContext.filterMode === "channel") {
    queryContext.drilldownMvpdIds = [];
    queryContext.mvpdIds = [];
  } else if (queryContext.filterMode === "mvpd") {
    queryContext.channels = [];
  }
  queryContext.controllerSelectionKey = buildCmHealthWorkspaceBaseSelectionKey(queryContext);
  queryContext.selectionKey = buildCmHealthWorkspaceSelectionKey(queryContext);
  return queryContext;
}

function rebaseCmHealthDashboardQueryContextForCurrentSelection(rawContext = null, options = {}) {
  const sourceContext = rawContext && typeof rawContext === "object" ? rawContext : {};
  const currentSelectionContext = cmHealthWorkspaceGetSelectionContext(resolveSelectedProgrammer());
  const sameControllerSelection =
    String(sourceContext?.controllerSelectionKey || "").trim() ===
    String(currentSelectionContext?.controllerSelectionKey || "").trim();
  const rebasedContext = {
    ...currentSelectionContext,
    start: String(sourceContext?.start || currentSelectionContext?.start || "").trim(),
    end: String(sourceContext?.end || currentSelectionContext?.end || "").trim(),
    requestSource:
      String(options?.requestSource || sourceContext?.requestSource || "cm-health-dashboard").trim() ||
      "cm-health-dashboard",
  };
  if (sameControllerSelection) {
    rebasedContext.granularity = normalizeEsmHealthGranularity(sourceContext?.granularity || CM_HEALTH_DEFAULT_GRANULARITY);
    rebasedContext.drilldownMvpdIds = normalizeEsmHealthFilterList(sourceContext?.drilldownMvpdIds);
    rebasedContext.platforms = normalizeEsmHealthFilterList(sourceContext?.platforms);
    rebasedContext.channels = normalizeEsmHealthFilterList(sourceContext?.channels);
  }
  return buildCmHealthDashboardQueryContext(rebasedContext);
}

function buildCmHealthStatusMessage(queryContext = null) {
  const programmerId = String(queryContext?.programmerId || "").trim();
  const tenantScope = resolveCmUsageTenantScopeValue(queryContext?.tenantScope);
  const filterMode = String(queryContext?.filterMode || resolveCmHealthFilterMode(queryContext)).trim();
  const filterValue =
    filterMode === "mvpd"
      ? normalizeEsmHealthFilterList(queryContext?.mvpdIds).join(", ")
      : filterMode === "platform"
        ? normalizeEsmHealthFilterList(queryContext?.platforms).join(", ")
        : filterMode === "channel"
          ? normalizeEsmHealthFilterList(queryContext?.channels).join(", ")
          : "";
  const environmentLabel = String(queryContext?.environmentLabel || "").trim();
  return [programmerId, tenantScope ? `Tenant ${tenantScope}` : "", filterValue ? `${filterMode} ${filterValue}` : "", environmentLabel]
    .filter(Boolean)
    .join(" | ");
}

function getCmHealthMetricNumber(row = null, key = "") {
  const parsed = Number(row?.[key] ?? 0);
  return Number.isFinite(parsed) ? parsed : 0;
}

function computeCmHealthDerivedMetrics(source = null) {
  const activeUsers = Math.max(0, Number(source?.activeUsers ?? source?.["active-users"] ?? 0));
  const activeSessions = Math.max(0, Number(source?.activeSessions ?? source?.["active-sessions"] ?? 0));
  const startedSessions = Math.max(0, Number(source?.startedSessions ?? source?.["started-sessions"] ?? 0));
  const completedSessions = Math.max(0, Number(source?.completedSessions ?? source?.["completed-sessions"] ?? 0));
  const failedAttempts = Math.max(0, Number(source?.failedAttempts ?? source?.["failed-attempts"] ?? 0));
  const dismissedSessions = Math.max(0, Number(source?.dismissedSessions ?? source?.["dismissed-sessions"] ?? 0));
  const killedSessions = Math.max(0, Number(source?.killedSessions ?? source?.["killed-sessions"] ?? 0));
  const issueEvents = failedAttempts + dismissedSessions + killedSessions;
  return {
    activeUsers,
    activeSessions,
    startedSessions,
    completedSessions,
    failedAttempts,
    dismissedSessions,
    killedSessions,
    issueEvents,
    completionRate: startedSessions > 0 ? completedSessions / startedSessions : null,
    failureRate: startedSessions > 0 ? failedAttempts / startedSessions : null,
    interruptionRate: startedSessions > 0 ? (dismissedSessions + killedSessions) / startedSessions : null,
    dismissalRate: startedSessions > 0 ? dismissedSessions / startedSessions : null,
    killRate: startedSessions > 0 ? killedSessions / startedSessions : null,
    avgSessionsPerUser: activeUsers > 0 ? activeSessions / activeUsers : null,
  };
}

function cmHealthPartsToUtcMs(row = null) {
  const year = Number(row?.year ?? 1970);
  const month = Number(row?.month ?? 1);
  const day = Number(row?.day ?? 1);
  const hour = Number(row?.hour ?? 0);
  return (
    Date.UTC(
      Number.isFinite(year) ? year : 1970,
      Number.isFinite(month) ? month - 1 : 0,
      Number.isFinite(day) ? day : 1,
      Number.isFinite(hour) ? hour : 0,
      0,
      0
    ) -
    CM_SOURCE_UTC_OFFSET_MINUTES * 60 * 1000
  );
}

function buildCmHealthBucketMeta(row = null, granularity = CM_HEALTH_DEFAULT_GRANULARITY) {
  const year = Number(row?.year ?? 1970);
  const month = Number(row?.month ?? 1);
  const day = Number(row?.day ?? 1);
  const hour = Number(row?.hour ?? 0);
  const paddedMonth = String(Math.max(1, month)).padStart(2, "0");
  const paddedDay = String(Math.max(1, day)).padStart(2, "0");
  const paddedHour = String(Math.max(0, hour)).padStart(2, "0");
  const normalizedGranularity = normalizeEsmHealthGranularity(granularity || CM_HEALTH_DEFAULT_GRANULARITY);
  if (normalizedGranularity === "month") {
    return {
      key: `${year}-${paddedMonth}`,
      label: `${paddedMonth}/${year}`,
      timestamp: cmHealthPartsToUtcMs({ year, month, day: 1, hour: 0 }),
    };
  }
  if (normalizedGranularity === "hour") {
    return {
      key: `${year}-${paddedMonth}-${paddedDay}T${paddedHour}`,
      label: `${paddedMonth}/${paddedDay} ${paddedHour}:00`,
      timestamp: cmHealthPartsToUtcMs({ year, month, day, hour }),
    };
  }
  return {
    key: `${year}-${paddedMonth}-${paddedDay}`,
    label: `${paddedMonth}/${paddedDay}/${year}`,
    timestamp: cmHealthPartsToUtcMs({ year, month, day, hour: 0 }),
  };
}

function aggregateCmHealthBackboneRows(rows = [], granularity = CM_HEALTH_DEFAULT_GRANULARITY) {
  const buckets = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const meta = buildCmHealthBucketMeta(row, granularity);
    if (!meta.key) {
      return;
    }
    if (!buckets.has(meta.key)) {
      buckets.set(meta.key, {
        bucketKey: meta.key,
        label: meta.label,
        timestamp: meta.timestamp,
        activeUsers: 0,
        activeSessions: 0,
        startedSessions: 0,
        completedSessions: 0,
        failedAttempts: 0,
        dismissedSessions: 0,
        killedSessions: 0,
      });
    }
    const bucket = buckets.get(meta.key);
    bucket.activeUsers += getCmHealthMetricNumber(row, "active-users");
    bucket.activeSessions += getCmHealthMetricNumber(row, "active-sessions");
    bucket.startedSessions += getCmHealthMetricNumber(row, "started-sessions");
    bucket.completedSessions += getCmHealthMetricNumber(row, "completed-sessions");
    bucket.failedAttempts += getCmHealthMetricNumber(row, "failed-attempts");
    bucket.dismissedSessions += getCmHealthMetricNumber(row, "dismissed-sessions");
    bucket.killedSessions += getCmHealthMetricNumber(row, "killed-sessions");
  });

  return Array.from(buckets.values())
    .sort((left, right) => Number(left?.timestamp || 0) - Number(right?.timestamp || 0))
    .map((bucket) => ({
      ...bucket,
      ...computeCmHealthDerivedMetrics(bucket),
    }));
}

function aggregateCmHealthBreakdownRows(rows = [], dimensionKeys = [], limit = CM_HEALTH_TOP_ROW_LIMIT, options = {}) {
  const normalizedDimensionKeys = uniquePreserveOrder(
    (Array.isArray(dimensionKeys) ? dimensionKeys : [dimensionKeys])
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
  const buildLabel =
    typeof options?.buildLabel === "function"
      ? options.buildLabel
      : (values) =>
          normalizedDimensionKeys
            .map((key) => String(values?.[key] || "").trim())
            .filter(Boolean)
            .join(" / ");
  const buckets = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const dimensionValues = {};
    normalizedDimensionKeys.forEach((key) => {
      dimensionValues[key] = String(row?.[key] || "").trim() || "(unknown)";
    });
    const bucketKey =
      normalizedDimensionKeys.length > 0
        ? normalizedDimensionKeys.map((key) => String(dimensionValues[key] || "").trim() || "(unknown)").join("\u001f")
        : "(aggregate)";
    const bucketLabel = String(buildLabel(dimensionValues, row) || "").trim() || "(unknown)";
    if (!buckets.has(bucketKey)) {
      buckets.set(bucketKey, {
        label: bucketLabel,
        ...dimensionValues,
        activeUsers: 0,
        activeSessions: 0,
        startedSessions: 0,
        completedSessions: 0,
        failedAttempts: 0,
        dismissedSessions: 0,
        killedSessions: 0,
      });
    }
    const bucket = buckets.get(bucketKey);
    bucket.activeUsers += getCmHealthMetricNumber(row, "active-users");
    bucket.activeSessions += getCmHealthMetricNumber(row, "active-sessions");
    bucket.startedSessions += getCmHealthMetricNumber(row, "started-sessions");
    bucket.completedSessions += getCmHealthMetricNumber(row, "completed-sessions");
    bucket.failedAttempts += getCmHealthMetricNumber(row, "failed-attempts");
    bucket.dismissedSessions += getCmHealthMetricNumber(row, "dismissed-sessions");
    bucket.killedSessions += getCmHealthMetricNumber(row, "killed-sessions");
  });

  return Array.from(buckets.values())
    .map((entry) => ({
      ...entry,
      ...computeCmHealthDerivedMetrics(entry),
    }))
    .sort((left, right) => {
      const issueDelta = Number(right?.issueEvents || 0) - Number(left?.issueEvents || 0);
      if (issueDelta !== 0) {
        return issueDelta;
      }
      const startDelta = Number(right?.startedSessions || 0) - Number(left?.startedSessions || 0);
      if (startDelta !== 0) {
        return startDelta;
      }
      const activeUsersDelta = Number(right?.activeUsers || 0) - Number(left?.activeUsers || 0);
      if (activeUsersDelta !== 0) {
        return activeUsersDelta;
      }
      return String(left?.label || "").localeCompare(String(right?.label || ""), undefined, {
        numeric: true,
        sensitivity: "base",
      });
    })
    .slice(0, Math.max(1, Number(limit || CM_HEALTH_TOP_ROW_LIMIT)))
    .map((entry, index) => {
      if (typeof options?.mapRow === "function") {
        return options.mapRow(entry, index);
      }
      return entry;
    });
}

function aggregateCmHealthUserDistributionRows(rows = [], dimensionKey = "", limit = CM_HEALTH_TOP_ROW_LIMIT, options = {}) {
  const normalizedKey = String(dimensionKey || "").trim();
  if (!normalizedKey) {
    return [];
  }
  const buckets = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const rawValue = String(row?.[normalizedKey] || "").trim() || "(unknown)";
    if (!buckets.has(rawValue)) {
      buckets.set(rawValue, {
        label: rawValue,
        [normalizedKey]: rawValue,
        users: 0,
      });
    }
    const bucket = buckets.get(rawValue);
    bucket.users += getCmHealthMetricNumber(row, "users");
  });

  return Array.from(buckets.values())
    .sort((left, right) => {
      const userDelta = Number(right?.users || 0) - Number(left?.users || 0);
      if (userDelta !== 0) {
        return userDelta;
      }
      return String(left?.label || "").localeCompare(String(right?.label || ""), undefined, {
        numeric: true,
        sensitivity: "base",
      });
    })
    .slice(0, Math.max(1, Number(limit || CM_HEALTH_TOP_ROW_LIMIT)))
    .map((entry, index) => (typeof options?.mapRow === "function" ? options.mapRow(entry, index) : entry));
}

function buildCmHealthSummary(backboneSeries = [], breakdowns = {}) {
  const totals = {
    activeUsers: 0,
    activeSessions: 0,
    startedSessions: 0,
    completedSessions: 0,
    failedAttempts: 0,
    dismissedSessions: 0,
    killedSessions: 0,
  };
  (Array.isArray(backboneSeries) ? backboneSeries : []).forEach((entry) => {
    totals.activeUsers += Number(entry?.activeUsers || 0);
    totals.activeSessions += Number(entry?.activeSessions || 0);
    totals.startedSessions += Number(entry?.startedSessions || 0);
    totals.completedSessions += Number(entry?.completedSessions || 0);
    totals.failedAttempts += Number(entry?.failedAttempts || 0);
    totals.dismissedSessions += Number(entry?.dismissedSessions || 0);
    totals.killedSessions += Number(entry?.killedSessions || 0);
  });
  const latestBucket = Array.isArray(backboneSeries) && backboneSeries.length > 0 ? backboneSeries[backboneSeries.length - 1] : null;
  const platformRows = Array.isArray(breakdowns?.platformRows) ? breakdowns.platformRows : [];
  const applicationRows = Array.isArray(breakdowns?.applicationRows) ? breakdowns.applicationRows : [];
  const channelRows = Array.isArray(breakdowns?.channelRows) ? breakdowns.channelRows : [];
  const mvpdRows = Array.isArray(breakdowns?.mvpdRows) ? breakdowns.mvpdRows : [];
  const concurrencyRows = Array.isArray(breakdowns?.concurrencyRows) ? breakdowns.concurrencyRows : [];
  const activityRows = Array.isArray(breakdowns?.activityRows) ? breakdowns.activityRows : [];
  return {
    ...totals,
    ...computeCmHealthDerivedMetrics(totals),
    latestActiveUsers: Number(latestBucket?.activeUsers || 0),
    latestActiveSessions: Number(latestBucket?.activeSessions || 0),
    latestBucketLabel: String(latestBucket?.label || "").trim(),
    seriesPoints: Array.isArray(backboneSeries) ? backboneSeries.length : 0,
    activePlatforms: platformRows.length,
    activeApplications: applicationRows.length,
    activeChannels: channelRows.length,
    activeMvpds: mvpdRows.length,
    activeConcurrencyLevels: concurrencyRows.length,
    activeActivityLevels: activityRows.length,
    topPlatformLabel: String(platformRows[0]?.platform || platformRows[0]?.label || "").trim(),
    topApplicationLabel: String(applicationRows[0]?.applicationLabel || applicationRows[0]?.label || "").trim(),
    topChannelLabel: String(channelRows[0]?.channel || channelRows[0]?.label || "").trim(),
    topMvpdLabel: String(mvpdRows[0]?.mvpd || mvpdRows[0]?.label || "").trim(),
    topConcurrencyLabel: String(concurrencyRows[0]?.concurrencyLevel || concurrencyRows[0]?.label || "").trim(),
    topActivityLabel: String(activityRows[0]?.activityLevel || activityRows[0]?.label || "").trim(),
  };
}

function addCmHealthTrafficShare(rows = [], totalStartedSessions = 0) {
  const total = Math.max(0, Number(totalStartedSessions || 0));
  return (Array.isArray(rows) ? rows : []).map((entry) => ({
    ...entry,
    trafficShare: total > 0 ? Number(entry?.startedSessions || 0) / total : null,
  }));
}

function addCmHealthUserShare(rows = [], totalUsers = 0) {
  const total = Math.max(0, Number(totalUsers || 0));
  return (Array.isArray(rows) ? rows : []).map((entry) => ({
    ...entry,
    userShare: total > 0 ? Number(entry?.users || 0) / total : null,
  }));
}

function cmHealthExtractRows(payload = null, preferredKeys = []) {
  const collections = collectCmCollections(payload, {
    preferredKeys:
      Array.isArray(preferredKeys) && preferredKeys.length > 0
        ? preferredKeys
        : ["usage", "data", "rows", "results", "records", "report", "items"],
    maxDepth: 5,
  });
  const bestCollection = collections.find((entry) =>
    Array.isArray(entry?.values) &&
    entry.values.some((item) => item && typeof item === "object" && !Array.isArray(item))
  );
  if (bestCollection) {
    return bestCollection.values.filter((item) => item && typeof item === "object" && !Array.isArray(item));
  }
  if (Array.isArray(payload)) {
    return payload.filter((item) => item && typeof item === "object" && !Array.isArray(item));
  }
  return payload && typeof payload === "object" ? [payload] : [];
}

function buildCmHealthRowDateKey(row = null) {
  const year = Number(row?.year);
  const month = Number(row?.month);
  const day = Number(row?.day);
  if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) {
    return "";
  }
  return `${String(year).padStart(4, "0")}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

function cmHealthBuildMatchSet(values = []) {
  return new Set(
    normalizeEsmHealthFilterList(values).map((value) => String(value || "").trim().toLowerCase()).filter(Boolean)
  );
}

function cmHealthMatchesDimension(row = null, key = "", matchSet = null) {
  if (!(matchSet instanceof Set) || matchSet.size === 0) {
    return true;
  }
  const candidate = String(row?.[key] || "").trim().toLowerCase();
  return candidate ? matchSet.has(candidate) : false;
}

function cmHealthFilterUsageRows(rows = [], queryContext = null, options = {}) {
  const start = String(options?.start || queryContext?.start || "").trim();
  const end = String(options?.end || queryContext?.end || "").trim();
  const mvpdSet = cmHealthBuildMatchSet(
    Object.prototype.hasOwnProperty.call(options, "mvpdIds") ? options.mvpdIds : queryContext?.mvpdIds
  );
  const platformSet = cmHealthBuildMatchSet(
    Object.prototype.hasOwnProperty.call(options, "platforms") ? options.platforms : queryContext?.platforms
  );
  const channelSet = cmHealthBuildMatchSet(
    Object.prototype.hasOwnProperty.call(options, "channels") ? options.channels : queryContext?.channels
  );
  return (Array.isArray(rows) ? rows : []).filter((row) => {
    const dateKey = buildCmHealthRowDateKey(row);
    if (dateKey) {
      if (start && dateKey < start) {
        return false;
      }
      if (end && dateKey > end) {
        return false;
      }
    }
    if (!cmHealthMatchesDimension(row, "mvpd", mvpdSet)) {
      return false;
    }
    if (!cmHealthMatchesDimension(row, "platform", platformSet)) {
      return false;
    }
    if (!cmHealthMatchesDimension(row, "channel", channelSet)) {
      return false;
    }
    return true;
  });
}

function normalizeCmHealthUsagePath(pathname = "") {
  const raw = String(pathname || "").trim();
  if (!raw) {
    return "";
  }
  let normalizedPath = raw;
  try {
    normalizedPath = String(new URL(raw, CM_REPORTS_BASE_URL).pathname || "");
  } catch {
    normalizedPath = raw.split("?")[0];
  }
  normalizedPath = `/${String(normalizedPath || "").replace(/^\/+/, "").replace(/\/{2,}/g, "/")}`;
  if (!normalizedPath.startsWith("/v2/")) {
    normalizedPath = `/v2/${normalizedPath.replace(/^\/+/, "")}`;
  }
  return normalizedPath;
}

function extractCmHealthUsagePathParts(pathname = "") {
  return normalizeCmHealthUsagePath(pathname)
    .split("/")
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
}

function buildCmHealthUsageRequestUrl(pathname = "", queryContext = null, options = {}) {
  const normalizedPath = normalizeCmHealthUsagePath(pathname);
  const parsed = buildApiRequestUrl(CM_REPORTS_BASE_URL, normalizedPath, {});
  parsed.searchParams.set("format", "json");
  const tenantScope = resolveCmUsageTenantScopeValue(options?.tenantScope, queryContext?.tenantScope);
  CM_USAGE_TENANT_QUERY_KEYS.forEach((key) => parsed.searchParams.delete(key));
  if (tenantScope && cmUsagePathRequiresTenantScope(parsed.pathname)) {
    applyCmUsageTenantScopeToSearchParams(parsed.searchParams, tenantScope);
  }
  const pathParts = extractCmHealthUsagePathParts(parsed.pathname);
  const mvpdIds = normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(options, "mvpdIds") ? options.mvpdIds : queryContext?.mvpdIds
  );
  parsed.searchParams.delete("mvpd");
  parsed.searchParams.delete("mvpd_id");
  parsed.searchParams.delete("mvpd-id");
  if (Array.isArray(pathParts) && pathParts.includes("mvpd") && mvpdIds.length > 0) {
    parsed.searchParams.set("mvpd", mvpdIds[0]);
  }
  if (Array.isArray(pathParts) && (pathParts.includes("activity-level") || pathParts.includes("concurrency-level"))) {
    parsed.searchParams.set("metrics", "users");
  }
  return parsed.toString();
}

async function fetchCmHealthJson(queryContext = null, pathname = "", options = {}) {
  const requestUrl = buildCmHealthUsageRequestUrl(pathname, queryContext, options);
  try {
    await ensureCmApiAccessToken({
      forceRefresh: options?.forceRefresh === true,
      freshLeewayMs: 60 * 1000,
      allowTemporaryPageContextTab: false,
    });
    const response = await fetchCmJsonWithAuthVariants(
      [requestUrl],
      `CM HEALTH ${String(options?.contextLabel || options?.datasetKey || pathname || "dataset").trim() || "dataset"}`,
      {
        allowTemporaryPageContextTab: false,
        debugMeta: {
          scope: "cm-health",
          datasetKey: String(options?.datasetKey || pathname || "").trim(),
          endpointUrl: requestUrl,
          programmerId: String(queryContext?.programmerId || "").trim(),
          tenantScope: resolveCmUsageTenantScopeValue(options?.tenantScope, queryContext?.tenantScope),
          mvpd: normalizeEsmHealthFilterList(options?.mvpdIds || queryContext?.mvpdIds)[0] || "",
        },
      }
    );
    return {
      ok: true,
      requestUrl,
      status: Number(response.status || 0),
      rows: cmHealthExtractRows(response.parsed, options?.preferredKeys),
      parsed: response.parsed,
      text: String(response.text || ""),
      lastModified: String(response.lastModified || ""),
      error: "",
    };
  } catch (error) {
    return {
      ok: false,
      requestUrl,
      status: 0,
      rows: [],
      parsed: null,
      text: "",
      lastModified: "",
      error:
        normalizeHttpErrorMessage(error instanceof Error ? error.message : String(error)) || "CM HEALTH request failed.",
    };
  }
}

function buildCmHealthBackbonePath(queryContext = null) {
  const filterMode = resolveCmHealthFilterMode(queryContext);
  const useHourly = normalizeEsmHealthGranularity(queryContext?.granularity || CM_HEALTH_DEFAULT_GRANULARITY) === "hour";
  if (filterMode === "channel") {
    return useHourly ? CM_HEALTH_BACKBONE_CHANNEL_HOURLY_PATH : CM_HEALTH_BACKBONE_CHANNEL_DAILY_PATH;
  }
  if (filterMode === "mvpd") {
    return useHourly ? CM_HEALTH_BACKBONE_MVPD_HOURLY_PATH : CM_HEALTH_BACKBONE_MVPD_DAILY_PATH;
  }
  if (filterMode === "platform") {
    return useHourly ? CM_HEALTH_BACKBONE_PLATFORM_HOURLY_PATH : CM_HEALTH_BACKBONE_PLATFORM_DAILY_PATH;
  }
  return useHourly ? CM_HEALTH_BACKBONE_HOURLY_PATH : CM_HEALTH_BACKBONE_DAILY_PATH;
}

function buildCmHealthDashboardReportPayload(queryContext = null, data = null, options = {}) {
  const sectionErrors = data?.sectionErrors && typeof data.sectionErrors === "object" ? { ...data.sectionErrors } : {};
  const sectionMessages = data?.sectionMessages && typeof data.sectionMessages === "object" ? { ...data.sectionMessages } : {};
  const ignoredSections = new Set(
    (Array.isArray(data?.ignoredSections) ? data.ignoredSections : [])
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
  const requestedSections = ["backbone", "platform", "applications", "channel", "mvpd", "concurrency", "activity"];
  const effectiveSections = requestedSections.filter((key) => !ignoredSections.has(key));
  const failedSections = effectiveSections.filter((key) => Boolean(String(sectionErrors?.[key] || "").trim()));
  const loadedSections = effectiveSections.length - failedSections.length;
  const backboneSeries = Array.isArray(data?.backboneSeries) ? data.backboneSeries : [];
  const platformRows = Array.isArray(data?.platformRows) ? data.platformRows : [];
  const applicationRows = Array.isArray(data?.applicationRows) ? data.applicationRows : [];
  const channelRows = Array.isArray(data?.channelRows) ? data.channelRows : [];
  const mvpdRows = Array.isArray(data?.mvpdRows) ? data.mvpdRows : [];
  const concurrencyRows = Array.isArray(data?.concurrencyRows) ? data.concurrencyRows : [];
  const activityRows = Array.isArray(data?.activityRows) ? data.activityRows : [];
  const summary = buildCmHealthSummary(backboneSeries, {
    platformRows,
    applicationRows,
    channelRows,
    mvpdRows,
    concurrencyRows,
    activityRows,
  });
  return {
    ok: failedSections.length === 0 && loadedSections > 0,
    partial: failedSections.length > 0 && loadedSections > 0,
    checkedAt: Date.now(),
    selectionKey: String(queryContext?.selectionKey || "").trim(),
    controllerSelectionKey: String(queryContext?.controllerSelectionKey || "").trim(),
    programmerId: String(queryContext?.programmerId || "").trim(),
    environmentKey: String(queryContext?.environmentKey || "").trim(),
    premiumPanelRequestToken: Math.max(0, Number(options?.premiumPanelRequestToken || 0)),
    workspaceContextKey: String(options?.workspaceContextKey || "").trim(),
    queryContext,
    summary,
    backboneSeries,
    platformRows,
    applicationRows,
    channelRows,
    mvpdRows,
    concurrencyRows,
    activityRows,
    sectionErrors,
    sectionMessages,
    ignoredSections: [...ignoredSections],
    loadedSections,
    totalSections: effectiveSections.length,
    error:
      failedSections.length > 0
        ? String(options?.error || "One or more CM HEALTH datasets failed to load.").trim() ||
          "One or more CM HEALTH datasets failed to load."
        : "",
  };
}

function getHealthWorkspacePremiumContextSnapshot(programmerId = "") {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const adobePassWorkflowActive =
    state.sessionReady === true && Boolean(state.loginData) && shouldHydrateAdobePassWorkflowForSession(state.loginData);
  if (!normalizedProgrammerId || !adobePassWorkflowActive) {
    return {
      programmerId: "",
      services: null,
      hydrationReady: false,
      esmAvailable: false,
    };
  }

  const services =
    getCurrentPremiumAppsSnapshot(normalizedProgrammerId) ||
    getRuntimePremiumServicesSeed(normalizedProgrammerId) ||
    null;
  const hydrationReady =
    isProgrammerWorkspaceHydrationReady(normalizedProgrammerId) ||
    isProgrammerRuntimeServicesReady(normalizedProgrammerId, services);

  return {
    programmerId: normalizedProgrammerId,
    services,
    hydrationReady,
    esmAvailable: hasEsmScopedApp(services),
  };
}

async function ensureHealthWorkspacePremiumContext(programmerId = "", options = {}) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const adobePassWorkflowActive =
    state.sessionReady === true && Boolean(state.loginData) && shouldHydrateAdobePassWorkflowForSession(state.loginData);
  if (!normalizedProgrammerId || !adobePassWorkflowActive) {
    return {
      programmer: null,
      services: null,
      hydrationReady: false,
      esmAvailable: false,
    };
  }

  const programmer =
    findProgrammerByProgrammerId(normalizedProgrammerId) ||
    (resolveSelectedProgrammer()?.programmerId === normalizedProgrammerId ? resolveSelectedProgrammer() : null);
  if (!programmer?.programmerId) {
    return {
      programmer: null,
      services: null,
      hydrationReady: false,
      esmAvailable: false,
    };
  }

  let snapshot = getHealthWorkspacePremiumContextSnapshot(normalizedProgrammerId);
  const hydrationPromise = getProgrammerServiceHydrationPromise(normalizedProgrammerId);
  if (hydrationPromise) {
    const hydratedServices = await hydrationPromise.catch(() => snapshot.services || null);
    snapshot = getHealthWorkspacePremiumContextSnapshot(normalizedProgrammerId);
    if (!snapshot.services && hydratedServices && typeof hydratedServices === "object") {
      snapshot.services = hydratedServices;
      snapshot.esmAvailable = hasEsmScopedApp(hydratedServices);
      snapshot.hydrationReady = isProgrammerRuntimeServicesReady(normalizedProgrammerId, hydratedServices);
    }
  } else if (!snapshot.services || !snapshot.hydrationReady || (options?.forceRefresh === true && programmer)) {
    const hydratedServices = await primeProgrammerServiceHydration(
      programmer,
      snapshot.services || getRuntimePremiumServicesSeed(normalizedProgrammerId) || null,
      {
        forceRefresh: options?.forceRefresh === true,
        controllerReason: String(options?.controllerReason || "health-workspace").trim() || "health-workspace",
        requestToken: Math.max(0, Number(options?.requestToken || state.premiumPanelRequestToken || 0)),
        renderOnReady: false,
      }
    ).catch(() => snapshot.services || null);
    snapshot = getHealthWorkspacePremiumContextSnapshot(normalizedProgrammerId);
    if (!snapshot.services && hydratedServices && typeof hydratedServices === "object") {
      snapshot.services = hydratedServices;
      snapshot.esmAvailable = hasEsmScopedApp(hydratedServices);
      snapshot.hydrationReady = isProgrammerRuntimeServicesReady(normalizedProgrammerId, hydratedServices);
    }
  }

  return {
    programmer,
    services: snapshot.services,
    hydrationReady: snapshot.hydrationReady,
    esmAvailable: snapshot.esmAvailable,
  };
}

async function resolveEsmHealthPremiumAuthContext(queryContext = null, options = {}) {
  const normalizedQueryContext = buildEsmHealthDashboardQueryContext(queryContext);
  const programmerId = String(normalizedQueryContext?.programmerId || "").trim();
  if (!programmerId) {
    throw new Error("Select a Media Company before running ESM HEALTH.");
  }

  const premiumContext = await ensureHealthWorkspacePremiumContext(programmerId, {
    controllerReason: "esm-health-dashboard",
    requestToken: Math.max(0, Number(options?.requestToken || state.premiumPanelRequestToken || 0)),
    forceRefresh: options?.forceRefresh === true,
  });
  const services =
    premiumContext?.services ||
    getCurrentPremiumAppsSnapshot(programmerId) ||
    getRuntimePremiumServicesSeed(programmerId) ||
    null;
  if (!hasEsmScopedApp(services)) {
    throw new Error("Selected Media Company does not have an ESM premium service.");
  }

  const requestorIds = normalizeEsmHealthFilterList(normalizedQueryContext?.requestorIds);
  const mvpdIds = normalizeEsmHealthFilterList(normalizedQueryContext?.mvpdIds);
  const requestorId = String(requestorIds[0] || normalizedQueryContext?.baseRequestorIds?.[0] || "").trim();
  const mvpd = String(mvpdIds[0] || normalizedQueryContext?.baseMvpdIds?.[0] || "").trim();
  const esmCandidates = collectEsmAppCandidatesFromPremiumApps(services, services?.esm || null);
  const appInfo = selectPreferredEsmAppForRequestor(esmCandidates, requestorId, programmerId) || services?.esm || null;
  if (!appInfo?.guid) {
    throw new Error("ESM application details are required before loading ESM HEALTH.");
  }

  const tokenResult = await ensureDcrAccessTokenWithEsmRecovery(programmerId, appInfo, options?.forceRefresh === true, {
    service: "esm",
    scope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
    requiredServiceScope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
    requestorIds,
    mvpdIds,
    requestorId,
    mvpd,
    appGuid: String(appInfo?.guid || ""),
    appName: String(appInfo?.appName || appInfo?.guid || ""),
    allowProvisioning: false,
  });

  return {
    programmer: premiumContext?.programmer || findProgrammerByProgrammerId(programmerId) || null,
    services,
    appInfo: tokenResult?.appInfo || appInfo,
    accessToken: normalizeBearerTokenValue(tokenResult?.accessToken || ""),
    hydrationReady: premiumContext?.hydrationReady === true,
  };
}

function buildEsmHealthRequestUrl(pathname = "", queryContext = null, options = {}) {
  const environment = getActiveAdobePassEnvironment();
  const esmBase = String(environment?.esmBase || `${ADOBE_MGMT_BASE}/esm/v3/media-company/`).trim();
  const parsed = new URL(String(pathname || "").replace(/^\/+/, ""), esmBase.endsWith("/") ? esmBase : `${esmBase}/`);
  parsed.hash = "";
  parsed.searchParams.set("media-company", String(queryContext?.mediaCompany || queryContext?.programmerId || "").trim());
  parsed.searchParams.set("start", String(queryContext?.start || "").trim());
  parsed.searchParams.set("end", String(queryContext?.end || "").trim());
  const metrics = normalizeEsmHealthFilterList(options.metrics);
  if (metrics.length > 0) {
    parsed.searchParams.set("metrics", metrics.join(","));
  }
  const limit = Math.max(0, Number(options.limit || 0));
  if (limit > 0) {
    parsed.searchParams.set("limit", String(limit));
  }
  normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(options, "requestorIds") ? options.requestorIds : queryContext?.requestorIds
  ).forEach((value) => {
    parsed.searchParams.append("requestor-id", value);
  });
  normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(options, "mvpdIds") ? options.mvpdIds : queryContext?.mvpdIds
  ).forEach((value) => {
    parsed.searchParams.append("mvpd", value);
  });
  normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(options, "platforms") ? options.platforms : queryContext?.platforms
  ).forEach((value) => {
    parsed.searchParams.append("platform", value);
  });
  normalizeEsmHealthFilterList(
    Object.prototype.hasOwnProperty.call(options, "events") ? options.events : queryContext?.events
  ).forEach((value) => {
    parsed.searchParams.append("event", value);
  });
  return parsed.toString();
}

function extractEsmHealthReportRows(payload = null) {
  if (Array.isArray(payload?.report)) {
    return payload.report;
  }
  if (Array.isArray(payload)) {
    return payload;
  }
  return [];
}

function buildEsmHealthRequestErrorMessage(status = 0, parsed = null, text = "", statusText = "", pathname = "") {
  const normalizedStatus = Number(status || 0);
  if (normalizedStatus === 404) {
    return `ESM path not available for ${String(pathname || "").replace(/\.json$/i, "")}.`;
  }
  if (normalizedStatus === 401) {
    return "ESM HEALTH bearer expired or is not authorized for the requested dataset.";
  }
  if (normalizedStatus === 403) {
    return "ESM HEALTH access was denied for the requested dataset.";
  }
  return (
    firstNonEmptyString([
      parsed?.error?.message,
      parsed?.error_description,
      parsed?.message,
      normalizeHttpErrorMessage(text),
      statusText,
      normalizedStatus > 0 ? `HTTP ${normalizedStatus}` : "",
    ]) || "ESM HEALTH request failed."
  );
}

async function fetchEsmHealthJson(queryContext = null, pathname = "", options = {}) {
  const requestUrl = buildEsmHealthRequestUrl(pathname, queryContext, options);
  const authState = options?.authState && typeof options.authState === "object" ? options.authState : {};
  const requestOnce = async (forceRefresh = false) => {
    if (forceRefresh === true || !isAccessTokenFreshEnough(authState.accessToken, 60 * 1000)) {
      const authContext = await resolveEsmHealthPremiumAuthContext(queryContext, {
        forceRefresh,
      });
      authState.accessToken = normalizeBearerTokenValue(authContext?.accessToken || "");
      authState.appInfo =
        authContext?.appInfo && typeof authContext.appInfo === "object" ? cloneJsonLikeValue(authContext.appInfo, null) : null;
      authState.programmerId = String(authContext?.programmer?.programmerId || queryContext?.programmerId || "").trim();
    }
    const response = await fetchWithAbortTimeout(
      requestUrl,
      {
        method: "GET",
        mode: "cors",
        credentials: "omit",
        referrerPolicy: "no-referrer",
        headers: {
          Accept: "application/json, text/plain, */*",
          Authorization: `Bearer ${String(authState.accessToken || "").trim()}`,
        },
      },
      ESM_HEALTH_API_REQUEST_TIMEOUT_MS
    );
    const text = await response.text().catch(() => "");
    return {
      response,
      text,
      parsed: parseJsonText(text, null),
    };
  };

  try {
    let attempt = await requestOnce(false);
    if (Number(attempt?.response?.status || 0) === 401) {
      attempt = await requestOnce(true);
    }
    const response = attempt.response;
    if (!response.ok) {
      return {
        ok: false,
        requestUrl,
        status: Number(response.status || 0),
        statusText: String(response.statusText || ""),
        parsed: attempt.parsed,
        text: attempt.text,
        rows: [],
        error: buildEsmHealthRequestErrorMessage(
          response.status,
          attempt.parsed,
          attempt.text,
          response.statusText,
          pathname
        ),
      };
    }
    return {
      ok: true,
      requestUrl,
      status: Number(response.status || 0),
      statusText: String(response.statusText || ""),
      parsed: attempt.parsed,
      text: attempt.text,
      rows: extractEsmHealthReportRows(attempt.parsed),
      error: "",
    };
  } catch (error) {
    return {
      ok: false,
      requestUrl,
      status: 0,
      statusText: "",
      parsed: null,
      text: "",
      rows: [],
      error:
        normalizeHttpErrorMessage(error instanceof Error ? error.message : String(error)) || "ESM HEALTH request failed.",
    };
  }
}

function buildEsmHealthDashboardReportPayload(queryContext = null, data = null, options = {}) {
  const sectionErrors = data?.sectionErrors && typeof data.sectionErrors === "object" ? { ...data.sectionErrors } : {};
  const ignoredSections = new Set(
    (Array.isArray(data?.ignoredSections) ? data.ignoredSections : [])
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
  const requestedSections = ["backbone", "uniques", "mvpd", "requestor", "platform", "applications", "apis", "sdkVersions"];
  const effectiveSections = requestedSections.filter((key) => !ignoredSections.has(key));
  const failedSections = effectiveSections.filter((key) => Boolean(String(sectionErrors?.[key] || "").trim()));
  const loadedSections = effectiveSections.length - failedSections.length;
  const backboneSeries = Array.isArray(data?.backboneSeries) ? data.backboneSeries : [];
  const uniqueSeries = Array.isArray(data?.uniqueSeries) ? data.uniqueSeries : [];
  const mvpdRows = Array.isArray(data?.mvpdRows) ? data.mvpdRows : [];
  const requestorRows = Array.isArray(data?.requestorRows) ? data.requestorRows : [];
  const platformRows = Array.isArray(data?.platformRows) ? data.platformRows : [];
  const applicationRows = Array.isArray(data?.applicationRows) ? data.applicationRows : [];
  const apiRows = Array.isArray(data?.apiRows) ? data.apiRows : [];
  const sdkRows = Array.isArray(data?.sdkRows) ? data.sdkRows : [];
  const summary = buildEsmHealthSummary(backboneSeries, uniqueSeries, {
    mvpdRows,
    requestorRows,
    platformRows,
    applicationRows,
    apiRows,
    sdkRows,
  });
  return {
    ok: failedSections.length === 0 && loadedSections > 0,
    partial: failedSections.length > 0 && loadedSections > 0,
    checkedAt: Date.now(),
    selectionKey: String(queryContext?.selectionKey || "").trim(),
    controllerSelectionKey: String(queryContext?.controllerSelectionKey || "").trim(),
    programmerId: String(queryContext?.programmerId || "").trim(),
    environmentKey: String(queryContext?.environmentKey || "").trim(),
    premiumPanelRequestToken: Math.max(0, Number(options?.premiumPanelRequestToken || 0)),
    workspaceContextKey: String(options?.workspaceContextKey || "").trim(),
    queryContext,
    summary,
    backboneSeries,
    uniqueSeries,
    mvpdRows,
    requestorRows,
    platformRows,
    applicationRows,
    apiRows,
    sdkRows,
    sectionErrors,
    loadedSections,
    totalSections: effectiveSections.length,
    error:
      failedSections.length > 0
        ? String(options?.error || "One or more ESM HEALTH datasets failed to load.").trim() ||
          "One or more ESM HEALTH datasets failed to load."
        : "",
  };
}

async function runEsmHealthDashboardForSelection(rawQueryContext = null, options = {}) {
  const queryContext = buildEsmHealthDashboardQueryContext(rawQueryContext);
  if (!queryContext.programmerId) {
    return buildEsmHealthDashboardReportPayload(queryContext, { sectionErrors: { backbone: "Select a Media Company first." } }, {
      error: "Select a Media Company before running ESM HEALTH.",
    });
  }

  const openWorkspace = options.openWorkspace !== false;
  const activateWorkspace = options.activateWorkspace !== false;
  const premiumPanelRequestToken = Math.max(0, Number(options?.requestToken || state.premiumPanelRequestToken || 0));
  const workspaceContextKey = buildEsmHealthWorkspaceControllerContextKey(queryContext, premiumPanelRequestToken);
  let targetWindowId = Number(options.targetWindowId || 0);

  if (openWorkspace) {
    const workspaceTab = await esmHealthWorkspaceEnsureWorkspaceTab({
      activate: activateWorkspace,
      windowId: targetWindowId || undefined,
    });
    targetWindowId = Number(workspaceTab?.windowId || targetWindowId || state.esmHealthWorkspaceWindowId || 0);
  }

  esmHealthWorkspaceBroadcastControllerState(resolveSelectedProgrammer(), esmHealthWorkspaceGetSelectionContext(resolveSelectedProgrammer()), targetWindowId);
  void esmHealthWorkspaceSendWorkspaceMessage(
    "report-start",
    {
      selectionKey: queryContext.selectionKey,
      controllerSelectionKey: queryContext.controllerSelectionKey,
      programmerId: queryContext.programmerId,
      environmentKey: queryContext.environmentKey,
      premiumPanelRequestToken,
      workspaceContextKey,
      queryContext,
      startedAt: Date.now(),
    },
    {
      targetWindowId,
    }
  );

  const finalizeReport = (payload) => {
    if (payload && typeof payload === "object") {
      payload.premiumPanelRequestToken = premiumPanelRequestToken;
      payload.workspaceContextKey = workspaceContextKey;
      payload.controllerSelectionKey = String(payload.controllerSelectionKey || queryContext.controllerSelectionKey || "").trim();
      payload.programmerId = String(payload.programmerId || queryContext.programmerId || "").trim();
      payload.environmentKey = String(payload.environmentKey || queryContext.environmentKey || "").trim();
    }
    esmHealthWorkspaceStoreLatestReport(payload);
    void esmHealthWorkspaceSendWorkspaceMessage("report-result", payload, { targetWindowId });
    return payload;
  };

  const authState = {};
  try {
    const authContext = await resolveEsmHealthPremiumAuthContext(queryContext, {
      requestToken: premiumPanelRequestToken,
    });
    authState.accessToken = normalizeBearerTokenValue(authContext?.accessToken || "");
    authState.appInfo =
      authContext?.appInfo && typeof authContext.appInfo === "object" ? cloneJsonLikeValue(authContext.appInfo, null) : null;
    authState.programmerId = String(authContext?.programmer?.programmerId || queryContext?.programmerId || "").trim();
  } catch (error) {
    const tokenError = error instanceof Error ? error.message : String(error);
    const tokenSectionErrors = {
      backbone: tokenError,
      uniques: tokenError,
      mvpd: tokenError,
      requestor: tokenError,
      platform: tokenError,
      applications: tokenError,
      apis: tokenError,
      sdkVersions: tokenError,
    };
    return finalizeReport(
      buildEsmHealthDashboardReportPayload(
        queryContext,
        {
          sectionErrors: tokenSectionErrors,
        },
        {
          premiumPanelRequestToken,
          workspaceContextKey,
          error: tokenError,
        }
      )
    );
  }

  const backbonePath = buildEsmHealthReportPath(queryContext.granularity);
  const breakdownGranularity = "day";
  const scopeBreakdownPath = buildEsmHealthReportPath(breakdownGranularity, ["requestor-id", "proxy", "mvpd", "platform"]);
  const applicationBreakdownPath = buildEsmHealthReportPath(breakdownGranularity, [
    "requestor-id",
    "proxy",
    "mvpd",
    "platform",
    "application-name",
    "application-version",
  ]);
  const apiBreakdownPath = buildEsmHealthReportPath(breakdownGranularity, [
    "requestor-id",
    "platform",
    "application-name",
    "application-version",
    "api",
  ]);
  const sdkBreakdownPath = buildEsmHealthReportPath(breakdownGranularity, [
    "requestor-id",
    "proxy",
    "mvpd",
    "platform",
    "nsdk",
    "nsdk-version",
  ]);
  const uniquesPath = buildEsmHealthReportPath("day", ["requestor-id", "proxy", "mvpd", "platform", "dc"]);
  const requestPromises = {
    backbone: fetchEsmHealthJson(queryContext, backbonePath, {
      authState,
    }),
    uniques: fetchEsmHealthJson(queryContext, uniquesPath, {
      authState,
      limit: ESM_HEALTH_BREAKDOWN_LIMIT,
    }),
    scope: fetchEsmHealthJson(queryContext, scopeBreakdownPath, {
      authState,
      limit: ESM_HEALTH_BREAKDOWN_LIMIT,
    }),
    applications: fetchEsmHealthJson(queryContext, applicationBreakdownPath, {
      authState,
      limit: ESM_HEALTH_BREAKDOWN_LIMIT,
    }),
    apis: fetchEsmHealthJson(queryContext, apiBreakdownPath, {
      authState,
      limit: ESM_HEALTH_BREAKDOWN_LIMIT,
    }),
    sdk: fetchEsmHealthJson(queryContext, sdkBreakdownPath, {
      authState,
      limit: ESM_HEALTH_BREAKDOWN_LIMIT,
    }),
  };

  const [backboneResult, uniquesResult, scopeResult, applicationsResult, apiResult, sdkResult] = await Promise.all([
    requestPromises.backbone,
    requestPromises.uniques,
    requestPromises.scope,
    requestPromises.applications,
    requestPromises.apis,
    requestPromises.sdk,
  ]);

  const sectionErrors = {};
  const ignoredSections = [];
  const backboneSeries = backboneResult.ok
    ? aggregateEsmHealthBackboneRows(backboneResult.rows, queryContext.granularity)
    : [];
  if (!backboneResult.ok) {
    sectionErrors.backbone = String(backboneResult.error || "Unable to load ESM HEALTH overview data.").trim();
  }

  const uniquesUnsupported = Number(uniquesResult?.status || 0) === 404;
  const uniqueSeries = uniquesResult.ok ? aggregateEsmHealthUniqueRows(uniquesResult.rows) : [];
  if (uniquesUnsupported) {
    ignoredSections.push("uniques");
  } else if (!uniquesResult.ok) {
    sectionErrors.uniques = String(uniquesResult.error || "Unable to load ESM HEALTH uniques.").trim();
  }

  const scopeRows = scopeResult.ok ? (Array.isArray(scopeResult.rows) ? scopeResult.rows : []) : [];
  if (!scopeResult.ok) {
    const scopeError = String(scopeResult.error || "Unable to load ESM HEALTH scope breakdowns.").trim();
    sectionErrors.mvpd = scopeError;
    sectionErrors.requestor = scopeError;
    sectionErrors.platform = scopeError;
  }
  const mvpdRows = scopeRows.length > 0
    ? aggregateEsmHealthBreakdownRows(scopeRows, ["mvpd"], ESM_HEALTH_TOP_ROW_LIMIT, {
        mapRow: (entry) => ({
          ...entry,
          mvpd: entry.label,
        }),
      })
    : [];
  const requestorRows = scopeRows.length > 0
    ? aggregateEsmHealthBreakdownRows(scopeRows, ["requestor-id"], ESM_HEALTH_TOP_ROW_LIMIT, {
        mapRow: (entry) => ({
          ...entry,
          requestorId: entry.label,
        }),
      })
    : [];
  const platformRows = scopeRows.length > 0
    ? aggregateEsmHealthBreakdownRows(scopeRows, ["platform"], ESM_HEALTH_TOP_ROW_LIMIT, {
        mapRow: (entry) => ({
          ...entry,
          platform: entry.label,
        }),
      })
    : [];

  const applicationScopeRows = applicationsResult.ok ? (Array.isArray(applicationsResult.rows) ? applicationsResult.rows : []) : [];
  if (!applicationsResult.ok) {
    sectionErrors.applications = String(applicationsResult.error || "Unable to load ESM HEALTH app breakdowns.").trim();
  }
  const applicationRows = applicationScopeRows.length > 0
    ? aggregateEsmHealthBreakdownRows(
        applicationScopeRows,
        ["application-name", "application-version"],
        ESM_HEALTH_TOP_ROW_LIMIT,
        {
          buildLabel: (values) =>
            [String(values?.["application-name"] || "").trim(), String(values?.["application-version"] || "").trim()]
              .filter(Boolean)
              .join(" · "),
          mapRow: (entry) => ({
            ...entry,
            applicationName: String(entry?.["application-name"] || "").trim(),
            applicationVersion: String(entry?.["application-version"] || "").trim(),
            applicationLabel: entry.label,
          }),
        }
      )
    : [];
  const apiScopeRows = apiResult.ok ? (Array.isArray(apiResult.rows) ? apiResult.rows : []) : [];
  if (!apiResult.ok) {
    sectionErrors.apis = String(apiResult.error || "Unable to load ESM HEALTH API breakdowns.").trim();
  }
  const apiRows = apiScopeRows.length > 0
    ? aggregateEsmHealthBreakdownRows(apiScopeRows, ["api"], ESM_HEALTH_TOP_ROW_LIMIT, {
        mapRow: (entry) => ({
          ...entry,
          api: entry.label,
        }),
      })
    : [];

  const sdkScopeRows = sdkResult.ok ? (Array.isArray(sdkResult.rows) ? sdkResult.rows : []) : [];
  if (!sdkResult.ok) {
    sectionErrors.sdkVersions = String(sdkResult.error || "Unable to load ESM HEALTH SDK breakdowns.").trim();
  }
  const sdkRows = sdkScopeRows.length > 0
    ? aggregateEsmHealthBreakdownRows(
        sdkScopeRows,
        ["nsdk", "nsdk-version"],
        ESM_HEALTH_TOP_ROW_LIMIT,
        {
          buildLabel: (values) =>
            [String(values?.nsdk || "").trim(), String(values?.["nsdk-version"] || "").trim()]
              .filter(Boolean)
              .join(" · "),
          mapRow: (entry) => ({
            ...entry,
            sdkName: String(entry?.nsdk || "").trim(),
            sdkVersion: String(entry?.["nsdk-version"] || "").trim(),
            sdkVersionLabel: entry.label,
          }),
        }
      )
    : [];

  const totalPlayRequests = backboneSeries.reduce((sum, entry) => sum + Number(entry?.mediaTokens || entry?.playRequests || 0), 0);

  return finalizeReport(
    buildEsmHealthDashboardReportPayload(
      queryContext,
      {
        backboneSeries,
        uniqueSeries,
        mvpdRows: addEsmHealthTrafficShare(mvpdRows, totalPlayRequests),
        requestorRows: addEsmHealthTrafficShare(requestorRows, totalPlayRequests),
        platformRows: addEsmHealthTrafficShare(platformRows, totalPlayRequests),
        applicationRows: addEsmHealthTrafficShare(applicationRows, totalPlayRequests),
        apiRows: addEsmHealthTrafficShare(apiRows, totalPlayRequests),
        sdkRows: addEsmHealthTrafficShare(sdkRows, totalPlayRequests),
        sectionErrors,
        ignoredSections,
      },
      {
        premiumPanelRequestToken,
        workspaceContextKey,
        error: "One or more ESM HEALTH datasets failed to load.",
      }
    )
  );
}

async function runRestV2SplunkLookup(section, programmer, appInfo) {
  if (!section) {
    return;
  }
  const sectionState = getRestV2SectionState(section);
  if (sectionState.splunkBusy === true) {
    return;
  }

  const programmerId = String(programmer?.programmerId || resolveSelectedProgrammer()?.programmerId || "").trim();
  if (!programmerId) {
    setStatus("Select a media company before querying Splunk.", "error");
    return;
  }

  const selectedState = getSelectedRestV2HarvestForProgrammer(section, programmerId);
  const selectedHarvest = selectedState.selectedHarvest;
  if (!selectedHarvest || typeof selectedHarvest !== "object") {
    setStatus("No captured MVPD profile is selected for Splunk query.", "error");
    return;
  }

  const upstreamUserId = String(selectedHarvest?.upstreamUserId || "").trim();
  if (!upstreamUserId) {
    setStatus("Selected MVPD profile does not include upstreamUserID.", "error");
    return;
  }

  const selectionContext = buildRestWorkspaceSelectionContextFromHarvest(selectedHarvest, programmer);
  const queryContext = {
    ...selectionContext,
    search: buildSplunkSearchQueryForUpstreamUserId(upstreamUserId),
    earliest: SPLUNK_SEARCH_EARLIEST,
    latest: SPLUNK_SEARCH_LATEST,
    requestSource: "rest-v2-can-i-watch-splunk",
    appGuid: String(appInfo?.guid || "").trim(),
    appName: String(appInfo?.appName || appInfo?.guid || "").trim(),
    harvestKey: String(selectedState.selectedHarvestKey || "").trim(),
  };

  sectionState.splunkBusy = true;
  sectionState.splunkBusyHarvestKey = String(selectedState.selectedHarvestKey || "").trim();
  sectionState.lastSplunkHarvestKey = String(selectedState.selectedHarvestKey || "").trim();
  syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);

  const result = await runSplunkSearchForQueryContext(queryContext, {
    openWorkspace: true,
    activateWorkspace: true,
    requestSource: "rest-v2-can-i-watch-splunk",
    forceLoginOnAuthFailure: true,
  });

  sectionState.lastSplunkResult = result && typeof result === "object" ? cloneJsonLikeValue(result, null) : null;
  sectionState.splunkBusy = false;
  sectionState.splunkBusyHarvestKey = "";
  syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);

  if (!result?.ok) {
    setStatus(
      firstNonEmptyString([
        result?.error,
        "Splunk query failed. Sign in to Splunk and retry.",
      ]),
      "error"
    );
    return;
  }
}

async function runBobtoolsSplunkLookupForHarvest(harvest = null, options = {}) {
  if (!harvest || typeof harvest !== "object") {
    return {
      ok: false,
      error: "No captured MVPD profile is selected for Splunk query.",
    };
  }

  const upstreamUserId = String(harvest?.upstreamUserId || "").trim();
  if (!upstreamUserId) {
    return {
      ok: false,
      error: "Selected MVPD profile does not include upstreamUserID.",
    };
  }

  const programmer = resolveSelectedProgrammer();
  const appInfo = resolveRestV2AppInfoForHarvest(harvest);
  const selectionContext = buildRestWorkspaceSelectionContextFromHarvest(harvest, programmer);
  const queryContext = {
    ...selectionContext,
    search: buildSplunkSearchQueryForUpstreamUserId(upstreamUserId),
    earliest: SPLUNK_SEARCH_EARLIEST,
    latest: SPLUNK_SEARCH_LATEST,
    requestSource: "bobtools-can-i-watch-splunk",
    appGuid: String(appInfo?.guid || "").trim(),
    appName: String(appInfo?.appName || appInfo?.guid || "").trim(),
    harvestKey: String(getRestV2HarvestRecordKey(harvest) || "").trim(),
  };

  const result = await runSplunkSearchForQueryContext(queryContext, {
    openWorkspace: false,
    emitRestWorkspace: false,
    activateWorkspace: false,
    requestSource: "bobtools-can-i-watch-splunk",
    forceLoginOnAuthFailure: true,
    targetWindowId: Number(options.targetWindowId || 0),
  });
  return result && typeof result === "object"
    ? result
    : {
        ok: false,
        error: "Unable to run Splunk query.",
      };
}

function wireRestV2ProfileAndEntitlementHandlers(section, programmer, appInfo) {
  if (!section || section.__underparRestV2HandlersBound) {
    return;
  }
  section.__underparRestV2HandlersBound = true;

  const profileToolToggle = section.querySelector(".rest-v2-profile-tool-toggle");
  if (profileToolToggle) {
    profileToolToggle.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const sectionState = getRestV2SectionState(section);
      sectionState.profileToolCollapsed = !sectionState.profileToolCollapsed;
      syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
    });
  }

  const entitlementToolToggle = section.querySelector(".rest-v2-entitlement-tool-toggle");
  if (entitlementToolToggle) {
    entitlementToolToggle.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const sectionState = getRestV2SectionState(section);
      sectionState.entitlementToolCollapsed = !sectionState.entitlementToolCollapsed;
      syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
    });
  }

  const listElement = section.querySelector(".rest-v2-profile-list");
  if (listElement) {
    listElement.addEventListener("click", async (event) => {
      const deleteButton = event.target instanceof Element ? event.target.closest(".rest-v2-profile-delete-btn") : null;
      if (deleteButton) {
        event.preventDefault();
        event.stopPropagation();
        const sectionState = getRestV2SectionState(section);
        const harvestKey = String(deleteButton.dataset.harvestKey || "").trim();
        const context = buildCurrentRestV2SelectionContext(programmer, appInfo);
        const programmerId = context?.ok
          ? String(context.programmerId || "").trim()
          : String(programmer?.programmerId || resolveSelectedProgrammer()?.programmerId || "").trim();
        if (!programmerId || !harvestKey) {
          return;
        }
        setStatus("Running REST V2 logout and deleting MVPD profile...");
        const deleteResult = await deleteRestV2ProfileHarvestWithLogout(programmerId, harvestKey, {
          source: "profile-picker-delete",
        });
        if (!deleteResult?.ok) {
          setStatus(String(deleteResult?.error || "Unable to remove the selected MVPD profile."), "error");
          syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
          refreshBobtoolsWorkspaceTools();
          return;
        }
        if (sectionState.selectedHarvestKey === harvestKey) {
          sectionState.selectedHarvestKey = "";
          sectionState.lastEntitlementResult = null;
          sectionState.lastSplunkResult = null;
          sectionState.lastSplunkHarvestKey = "";
        }
        if (sectionState.expandedHarvestKey === harvestKey) {
          sectionState.expandedHarvestKey = "";
        }
        sectionState.hasProfileExpansionChoice = false;
        setStatus(String(deleteResult?.message || "Removed captured MVPD login profile."), "info");
        syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
        refreshBobtoolsWorkspaceTools();
        return;
      }

      const target = event.target instanceof Element ? event.target.closest(".rest-v2-profile-card-toggle") : null;
      if (!target) {
        return;
      }
      const sectionState = getRestV2SectionState(section);
      const harvestKey = String(target.dataset.harvestKey || "").trim();
      if (!harvestKey) {
        return;
      }
      sectionState.selectedHarvestKey = harvestKey;
      if (sectionState.expandedHarvestKey === harvestKey) {
        sectionState.expandedHarvestKey = "";
      } else {
        sectionState.expandedHarvestKey = harvestKey;
      }
      sectionState.hasProfileExpansionChoice = true;
      syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
    });
  }

  const exportButton = section.querySelector(".rest-v2-profile-export-btn");
  if (exportButton) {
    exportButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const context = buildCurrentRestV2SelectionContext(programmer, appInfo);
      const programmerId = context?.ok
        ? String(context.programmerId || "").trim()
        : String(programmer?.programmerId || resolveSelectedProgrammer()?.programmerId || "").trim();
      if (!programmerId) {
        setStatus("Select a media company before exporting MVPD profiles.", "error");
        return;
      }
      const harvestList = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
      const exportResult = downloadRestV2ProfileHarvestCsv(harvestList, programmerId);
      if (!exportResult?.ok) {
        setStatus(exportResult?.error || "Unable to export MVPD profile data.", "error");
        return;
      }
      setStatus(
        `Exported ${Number(exportResult.profileCount || 0)} MVPD profiles (${Number(exportResult.checkCount || 0)} Preauthz checks) to ${String(
          exportResult.fileName || "CSV"
        )}.`,
        "success"
      );
    });
  }

  const copyUpstreamButton = section.querySelector(".rest-v2-entitlement-copy-upstream-btn");
  if (copyUpstreamButton) {
    copyUpstreamButton.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();
      const copyValue = String(copyUpstreamButton.dataset.copyValue || "").trim();
      if (!copyValue) {
        showRestV2CopyButtonFeedback(copyUpstreamButton, false);
        setStatus("No upstreamUserID is available for the selected profile.", "error");
        return;
      }
      const copyResult = await copyTextToClipboard(copyValue);
      if (!copyResult?.ok) {
        showRestV2CopyButtonFeedback(copyUpstreamButton, false);
        setStatus(copyResult?.error || "Unable to copy upstreamUserID to clipboard.", "error");
        return;
      }
      showRestV2CopyButtonFeedback(copyUpstreamButton, true);
      setStatus(`Copied ${copyValue} to clipboard.`, "success");
    });
  }

  const splunkButton = section.querySelector(".rest-v2-entitlement-splunk-btn");
  if (splunkButton) {
    splunkButton.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();
      await runRestV2SplunkLookup(section, programmer, appInfo);
    });
  }

  const inputElement = section.querySelector(".rest-v2-resource-input");
  if (inputElement) {
    inputElement.addEventListener("input", () => {
      const sectionState = getRestV2SectionState(section);
      sectionState.resourceInput = String(inputElement.value || "");
      sectionState.resourceInputHarvestKey = String(sectionState.selectedHarvestKey || "").trim();
    });
  }

  const formElement = section.querySelector(".rest-v2-entitlement-form");
  if (formElement) {
    formElement.addEventListener("submit", async (event) => {
      event.preventDefault();
      await runRestV2EntitlementCheck(section, programmer, appInfo);
    });
  }
}

function getRestV2SelectionKey(context) {
  if (!context?.ok) {
    return "";
  }
  return [getActiveAdobePassEnvironmentKey(), context.programmerId, context.requestorId, context.mvpd]
    .map((value) => String(value || "").trim())
    .join("|");
}

function isRestV2ProfileSessionActiveResult(profileCheckResult = null) {
  if (!profileCheckResult || typeof profileCheckResult !== "object") {
    return false;
  }
  if (profileCheckResult.checked !== true || profileCheckResult.ok !== true) {
    return false;
  }
  return Number(profileCheckResult.profileCount || 0) > 0;
}

function hasRestV2AuthenticatedProfileMissingSignal(result = null) {
  if (!result || typeof result !== "object") {
    return false;
  }
  const errorText = String(result.error || "").trim().toLowerCase();
  if (errorText.includes("authenticated_profile_missing")) {
    return true;
  }
  const decisionRows = Array.isArray(result.decisionRows) ? result.decisionRows : [];
  return decisionRows.some((row) => String(row?.errorCode || "").trim().toLowerCase() === "authenticated_profile_missing");
}

function getRestV2ActiveProfileWindowEntryForContext(context = null) {
  if (!context?.ok) {
    return null;
  }
  const selectionKey = getRestV2SelectionKey(context);
  if (!selectionKey) {
    return null;
  }
  return state.restV2ActiveProfileWindowBySelectionKey.get(selectionKey) || null;
}

function shouldRefreshRestV2ActiveProfileWindowEntry(entry = null, options = {}) {
  if (options.force === true) {
    return true;
  }
  if (!entry || typeof entry !== "object") {
    return true;
  }
  const ageMs = Date.now() - Number(entry.checkedAt || 0);
  if (!Number.isFinite(ageMs) || ageMs < 0) {
    return true;
  }
  return ageMs > REST_V2_ACTIVE_PROFILE_CHECK_COOLDOWN_MS;
}

function setRestV2ActiveProfileWindowState(context, active = false, options = {}) {
  if (!context?.ok) {
    return null;
  }
  const selectionKey = getRestV2SelectionKey(context);
  if (!selectionKey) {
    return null;
  }
  const checkedAtRaw = Number(options.checkedAt || Date.now());
  const checkedAt = Number.isFinite(checkedAtRaw) && checkedAtRaw > 0 ? checkedAtRaw : Date.now();
  const next = {
    selectionKey,
    active: active === true,
    checkedAt,
    profileCount: Math.max(0, Number(options.profileCount || 0)),
    status: Number(options.status || 0),
    statusText: String(options.statusText || "").trim(),
    error: String(options.error || "").trim(),
    source: String(options.source || "").trim(),
  };
  state.restV2ActiveProfileWindowBySelectionKey.set(selectionKey, next);
  return next;
}

function clearRestV2ProfileHarvestSessionState() {
  state.restV2ActiveProfileWindowBySelectionKey.clear();
  state.restV2ActiveProfileWindowPromiseBySelectionKey.clear();
  state.restV2ProfileHarvestBySelectionKey.clear();
  state.restV2ProfileHarvestByProgrammerId.clear();
  state.restV2ProfileHarvestBucketByProgrammerId.clear();
  state.restV2ProfileHarvestLast = null;
  state.restV2PreauthorizeHistoryByProgrammerId.clear();
}

async function ensureRestV2ActiveProfileWindowForContext(section, programmer, appInfo, options = {}) {
  const context = options?.context?.ok ? options.context : buildCurrentRestV2SelectionContext(programmer, appInfo);
  if (!context?.ok) {
    return null;
  }
  const selectionKey = getRestV2SelectionKey(context);
  if (!selectionKey) {
    return null;
  }

  const existingEntry = state.restV2ActiveProfileWindowBySelectionKey.get(selectionKey) || null;
  if (!shouldRefreshRestV2ActiveProfileWindowEntry(existingEntry, options)) {
    return existingEntry;
  }

  const existingPromise = state.restV2ActiveProfileWindowPromiseBySelectionKey.get(selectionKey);
  if (existingPromise) {
    return existingPromise;
  }

  const workPromise = (async () => {
    const profileCheckResult = await fetchRestV2ProfileCheckResult(context, "", "profiles-ui-active-window");
    const hasActiveProfile = isRestV2ProfileSessionActiveResult(profileCheckResult);
    return setRestV2ActiveProfileWindowState(context, hasActiveProfile, {
      checkedAt: Date.now(),
      profileCount: Number(profileCheckResult?.profileCount || 0),
      status: Number(profileCheckResult?.status || 0),
      statusText: String(profileCheckResult?.statusText || "").trim(),
      error: String(profileCheckResult?.error || "").trim(),
      source: "profiles-ui-active-window",
    });
  })()
    .catch((error) => {
      return setRestV2ActiveProfileWindowState(context, false, {
        checkedAt: Date.now(),
        profileCount: 0,
        status: 0,
        statusText: "",
        error: error instanceof Error ? error.message : String(error),
        source: "profiles-ui-active-window-error",
      });
    })
    .finally(() => {
      if (state.restV2ActiveProfileWindowPromiseBySelectionKey.get(selectionKey) === workPromise) {
        state.restV2ActiveProfileWindowPromiseBySelectionKey.delete(selectionKey);
      }
      if (isCurrentRestV2SelectionKey(selectionKey)) {
        refreshRestV2LoginPanels();
      }
    });

  state.restV2ActiveProfileWindowPromiseBySelectionKey.set(selectionKey, workPromise);
  return workPromise;
}

function isRestV2PreparedLoginEntryFresh(entry) {
  if (!entry || typeof entry !== "object") {
    return false;
  }
  const ageMs = Date.now() - Number(entry.preparedAt || 0);
  return Boolean(entry.loginUrl) && Number.isFinite(ageMs) && ageMs >= 0 && ageMs <= REST_V2_PREPARED_LOGIN_MAX_AGE_MS;
}

function getRestV2PreparedLoginEntry(context) {
  const selectionKey = getRestV2SelectionKey(context);
  if (!selectionKey) {
    return null;
  }

  const entry = state.restV2PreparedLoginBySelectionKey.get(selectionKey) || null;
  if (!entry) {
    return null;
  }

  if (!isRestV2PreparedLoginEntryFresh(entry)) {
    state.restV2PreparedLoginBySelectionKey.delete(selectionKey);
    return null;
  }

  return entry;
}

function setRestV2PreparedLoginEntry(context, payload) {
  const selectionKey = getRestV2SelectionKey(context);
  if (!selectionKey) {
    return null;
  }

  const entry = {
    selectionKey,
    preparedAt: Date.now(),
    loginUrl: String(payload?.loginUrl || "").trim(),
    appInfo: payload?.appInfo || context?.appInfo || null,
    sessionData: payload?.sessionData && typeof payload.sessionData === "object" ? payload.sessionData : null,
    sessionResponseHeaders:
      payload?.sessionResponseHeaders && typeof payload.sessionResponseHeaders === "object" ? payload.sessionResponseHeaders : null,
    partnerFrameworkStatus: String(payload?.partnerFrameworkStatus || payload?.sessionData?.partnerFrameworkStatus || "").trim(),
    sessionPartner: String(payload?.sessionPartner || payload?.sessionData?.partner || "").trim(),
    payload: payload?.payload && typeof payload.payload === "object" ? payload.payload : null,
  };
  if (!entry.loginUrl) {
    return null;
  }

  state.restV2PreparedLoginBySelectionKey.set(selectionKey, entry);
  return entry;
}

function clearRestV2PreparedLoginState() {
  if (state.restV2DebugFlowId) {
    void stopRestV2DebugFlowAndSnapshot(state.restV2DebugFlowId, "state-reset");
  }

  void closeExistingRestV2LaunchTarget();

  state.restV2PreparedLoginBySelectionKey.clear();
  state.restV2PreparePromiseBySelectionKey.clear();
  state.restV2PrepareErrorBySelectionKey.clear();
  state.restV2PartnerSsoCreateResultByFlowKey.clear();
  clearRestV2ProfileHarvestSessionState();
  state.restV2LastLaunchTabId = 0;
  state.restV2LastLaunchWindowId = 0;
  state.restV2PreviousTabId = 0;
  state.restV2PreviousTabUrl = "";
  state.restV2RecordingActive = false;
  state.restV2RecordingStartedAt = 0;
  state.restV2RecordingContext = null;
  state.restV2Stopping = false;
  state.restV2DebugFlowId = "";
}

function storeRestV2AuthContextForRequestor(context, selectedAppInfo) {
  if (!context?.requestorId || !selectedAppInfo?.guid) {
    return;
  }

  const existing = getRequestorScopedRestV2AuthContext(context.requestorId) || {};
  const existingCandidateGuids = Array.isArray(existing.candidateGuids) ? existing.candidateGuids : [];
  const contextCandidateGuids = Array.isArray(context.restV2AppCandidates)
    ? context.restV2AppCandidates.map((item) => item?.guid).filter(Boolean)
    : [];

  setRequestorScopedRestV2AuthContext(context.requestorId, {
    programmerId: context.programmerId,
    preferredAppGuid: selectedAppInfo.guid,
    candidateGuids: [...new Set([selectedAppInfo.guid, ...contextCandidateGuids, ...existingCandidateGuids])],
  });
}

async function closeExistingRestV2LaunchTarget() {
  const launchWindowId = Number(state.restV2LastLaunchWindowId || 0);
  const launchTabId = Number(state.restV2LastLaunchTabId || 0);

  if (Number.isFinite(launchWindowId) && launchWindowId > 0) {
    try {
      await chrome.windows.remove(launchWindowId);
    } catch {
      // Ignore if already closed.
    }
  } else if (Number.isFinite(launchTabId) && launchTabId > 0) {
    try {
      await chrome.tabs.remove(launchTabId);
    } catch {
      // Ignore if already closed.
    }
  }

  state.restV2LastLaunchTabId = 0;
  state.restV2LastLaunchWindowId = 0;
}

function syncRestV2CloseLoginButton(section) {
  const closeButton = section?.querySelector(".rest-v2-close-login-btn");
  if (!closeButton) {
    return;
  }

  const activeContext =
    state.restV2RecordingContext && typeof state.restV2RecordingContext === "object" ? state.restV2RecordingContext : null;
  const requestorId = String(activeContext?.requestorId || "").trim();
  const mvpd = String(activeContext?.mvpd || "").trim();
  const hasTuple = Boolean(requestorId) && Boolean(mvpd);
  const mvpdLabel = getRestV2MvpdPickerLabel(
    requestorId,
    mvpd,
    String(activeContext?.mvpdName || "").trim()
      ? {
          id: mvpd,
          name: String(activeContext.mvpdName || "").trim(),
        }
      : null
  );
  const flowLabel = hasTuple ? `${requestorId} X ${mvpdLabel}` : "MVPD";
  const hoverLabel = hasTuple
    ? `Recording HTTP session traffic for ${requestorId} x ${mvpdLabel}. Click STOP to end capture and download HAR.`
    : "Click STOP to end capture and download HAR.";
  const showClose = state.restV2RecordingActive === true;
  closeButton.hidden = !showClose;
  closeButton.disabled = !showClose || state.busy || state.restV2Stopping;
  closeButton.textContent = "STOP";
  closeButton.title = hoverLabel;
  closeButton.setAttribute("aria-label", `${flowLabel} STOP. ${hoverLabel}`);
}

async function getCurrentActiveTab() {
  try {
    const tabs = await chrome.tabs.query({
      active: true,
      lastFocusedWindow: true,
    });
    if (Array.isArray(tabs) && tabs.length > 0) {
      const tab = tabs[0];
      rememberLastDebuggableWebTab(tab);
      return tab;
    }
  } catch {
    // Ignore query failures.
  }
  return null;
}

async function focusChromeWindowFront(windowId, options = {}) {
  const normalizedWindowId = Number(windowId || 0);
  if (!normalizedWindowId) {
    return;
  }
  try {
    await chrome.windows.update(normalizedWindowId, {
      focused: true,
      ...(options.drawAttention === true ? { drawAttention: true } : {}),
    });
  } catch {
    // Ignore focus/update failures.
  }
}

function pulseChromeWindowFront(windowId, delayMs = 120) {
  const normalizedWindowId = Number(windowId || 0);
  if (!normalizedWindowId) {
    return;
  }
  window.setTimeout(() => {
    void focusChromeWindowFront(normalizedWindowId, { drawAttention: true });
  }, Math.max(0, Number(delayMs) || 0));
}

async function openRestV2LoginPopupWindow() {
  ensureRestV2LoginTabWatcher();
  ensureRestV2BobtoolsRedirectWatcher();
  const createData = {
    url: "about:blank",
    focused: true,
    type: "popup",
    width: REST_V2_LOGIN_WINDOW_WIDTH,
    height: REST_V2_LOGIN_WINDOW_HEIGHT,
  };

  try {
    const currentWindow = await chrome.windows.getCurrent();
    if (Number.isFinite(Number(currentWindow?.left)) && Number.isFinite(Number(currentWindow?.top))) {
      createData.left = Number(currentWindow.left) + 24;
      createData.top = Number(currentWindow.top) + 24;
    }
  } catch {
    // Use default placement when current window bounds are unavailable.
  }

  const createdWindow = await chrome.windows.create(createData);
  const launchWindowId =
    Number.isFinite(Number(createdWindow?.id)) && Number(createdWindow.id) > 0 ? Number(createdWindow.id) : 0;
  const launchTabId =
    Number.isFinite(Number(createdWindow?.tabs?.[0]?.id)) && Number(createdWindow.tabs[0].id) > 0
      ? Number(createdWindow.tabs[0].id)
      : 0;

  if (!launchWindowId || !launchTabId) {
    throw new Error("Unable to open dedicated MVPD login window.");
  }

  await focusChromeWindowFront(launchWindowId, { drawAttention: true });
  pulseChromeWindowFront(launchWindowId, 160);
  pulseChromeWindowFront(launchWindowId, 420);

  return {
    windowId: launchWindowId,
    tabId: launchTabId,
  };
}

function getUPTraceViewerUrl(tabId, flowId = "", source = "test-mvpd-login") {
  const url = new URL(chrome.runtime.getURL(UP_TRACE_VIEW_PATH));
  const normalizedTabId = Number(tabId || 0);
  if (Number.isFinite(normalizedTabId) && normalizedTabId > 0) {
    url.searchParams.set("tabId", String(normalizedTabId));
  }
  const normalizedFlowId = String(flowId || "").trim();
  if (normalizedFlowId) {
    url.searchParams.set("flowId", normalizedFlowId);
  }
  url.searchParams.set("source", String(source || "test-mvpd-login"));
  return url.toString();
}

