function isCurrentRestV2SelectionKey(selectionKey) {
  if (!selectionKey) {
    return false;
  }

  const currentContext = buildCurrentRestV2SelectionContext(resolveSelectedProgrammer(), null);
  if (!currentContext?.ok) {
    return false;
  }
  return getRestV2SelectionKey(currentContext) === selectionKey;
}

async function ensurePreparedRestV2LoginForContext(section, context, options = {}) {
  const force = options.force === true;
  const debugFlowId = String(options.debugFlowId || "").trim();
  const selectionKey = getRestV2SelectionKey(context);
  if (!selectionKey) {
    throw new Error("REST V2 login preparation failed: missing selection context.");
  }

  if (force) {
    state.restV2PreparedLoginBySelectionKey.delete(selectionKey);
    state.restV2PrepareErrorBySelectionKey.delete(selectionKey);
  }

  if (!force) {
    const prepared = getRestV2PreparedLoginEntry(context);
    if (prepared) {
      return prepared;
    }
  }

  const existingPromise = state.restV2PreparePromiseBySelectionKey.get(selectionKey);
  if (existingPromise && !force) {
    return existingPromise;
  }
  if (existingPromise && force) {
    state.restV2PreparePromiseBySelectionKey.delete(selectionKey);
  }

  const launchButton = section?.querySelector(".rest-v2-test-login-btn");
  const requestorMvpdLabel = formatRestV2RequestorMvpdDisplay(context.requestorId, context.mvpd, context.mvpdMeta, {
    separator: " x ",
  });
  if (launchButton && isCurrentRestV2SelectionKey(selectionKey)) {
    launchButton.hidden = false;
    launchButton.disabled = true;
  }
  if (section && isCurrentRestV2SelectionKey(selectionKey)) {
    setRestV2LoginPanelStatus(
      section,
      `Preparing ${requestorMvpdLabel} MVPD login target...`
    );
  }

  const workPromise = (async () => {
    try {
      const {
        loginUrl,
        appInfo: selectedAppInfo,
        sessionData,
        payload,
        sessionResponseHeaders,
        partnerFrameworkStatus,
        sessionPartner,
      } = await createRestV2SessionForContext(context, {
        debugFlowId,
      });
      if (!loginUrl) {
        throw new Error("REST V2 session response did not include a login URL.");
      }

      const resolvedAppInfo = selectedAppInfo || context.appInfo;
      storeRestV2AuthContextForRequestor(context, resolvedAppInfo);
      const entry = setRestV2PreparedLoginEntry(context, {
        loginUrl,
        appInfo: resolvedAppInfo,
        sessionData,
        sessionResponseHeaders,
        partnerFrameworkStatus,
        sessionPartner,
        payload,
      });
      if (!entry) {
        throw new Error("REST V2 login preparation failed: unable to cache login URL.");
      }

      state.restV2PrepareErrorBySelectionKey.delete(selectionKey);
      if (section && isCurrentRestV2SelectionKey(selectionKey)) {
        const appName = resolvedAppInfo?.appName || resolvedAppInfo?.guid || context.appInfo?.appName || "REST V2 App";
        setRestV2LoginPanelStatus(
          section,
          `Ready to test ${requestorMvpdLabel} with "${appName}".`,
          "success"
        );
        if (launchButton) {
          launchButton.hidden = false;
          launchButton.disabled = false;
        }
      }

      return entry;
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      state.restV2PrepareErrorBySelectionKey.set(selectionKey, reason);
      if (section && isCurrentRestV2SelectionKey(selectionKey)) {
        setRestV2LoginPanelStatus(section, reason, "error");
        if (launchButton) {
          launchButton.hidden = false;
          launchButton.disabled = false;
        }
      }
      throw error;
    }
  })();

  state.restV2PreparePromiseBySelectionKey.set(selectionKey, workPromise);
  try {
    return await workPromise;
  } finally {
    if (state.restV2PreparePromiseBySelectionKey.get(selectionKey) === workPromise) {
      state.restV2PreparePromiseBySelectionKey.delete(selectionKey);
    }
  }
}

function buildCurrentRestV2SelectionContext(programmer, appInfoOverride = null) {
  const resolvedProgrammer = programmer || resolveSelectedProgrammer();
  if (!resolvedProgrammer || !resolvedProgrammer.programmerId) {
    return { ok: false, reason: "Select a Media Company first." };
  }

  const requestorId = String(state.selectedRequestorId || "").trim();
  if (!requestorId) {
    return { ok: false, reason: "Select a Content Provider first." };
  }

  const mvpd = String(state.selectedMvpdId || els.mvpdSelect?.value || "").trim();
  if (!mvpd) {
    return { ok: false, reason: "Select an MVPD to enable REST V2 test login." };
  }

  const premiumApps = getCurrentPremiumAppsSnapshot(resolvedProgrammer.programmerId);
  const baseCandidates = collectRestV2AppCandidatesFromPremiumApps(premiumApps);
  const byGuid = new Map();
  baseCandidates.forEach((item) => {
    if (item?.guid && !byGuid.has(item.guid)) {
      byGuid.set(item.guid, item);
    }
  });
  const allowAppOverride = Boolean(appInfoOverride?.guid) && baseCandidates.some((item) => item?.guid === appInfoOverride.guid);
  if (allowAppOverride && appInfoOverride?.guid && !byGuid.has(appInfoOverride.guid)) {
    byGuid.set(appInfoOverride.guid, appInfoOverride);
  }

  const cachedAuthContext = getRequestorScopedRestV2AuthContext(requestorId);
  const orderedCandidates = [];
  const pushCandidate = (item) => {
    if (!item?.guid || orderedCandidates.some((entry) => entry.guid === item.guid)) {
      return;
    }
    orderedCandidates.push(item);
  };

  if (
    cachedAuthContext &&
    cachedAuthContext.programmerId === resolvedProgrammer.programmerId &&
    Array.isArray(cachedAuthContext.candidateGuids)
  ) {
    cachedAuthContext.candidateGuids.forEach((guid) => {
      pushCandidate(byGuid.get(guid));
    });
  }

  const mappingPreferred = selectPreferredRestV2AppForRequestor(
    baseCandidates,
    requestorId,
    resolvedProgrammer.programmerId
  );
  pushCandidate(mappingPreferred);
  pushCandidate(allowAppOverride ? appInfoOverride : null);
  baseCandidates.forEach((item) => pushCandidate(item));

  const resolvedApp =
    (cachedAuthContext &&
    cachedAuthContext.programmerId === resolvedProgrammer.programmerId &&
    cachedAuthContext.preferredAppGuid
      ? orderedCandidates.find((item) => item.guid === cachedAuthContext.preferredAppGuid)
      : null) ||
    mappingPreferred ||
    (orderedCandidates.length === 1 ? orderedCandidates[0] : null) ||
    null;

  if (!resolvedApp?.guid) {
    return {
      ok: false,
      reason: `No REST V2 scoped app is mapped to RequestorId "${requestorId}".`,
    };
  }

  const mvpdMeta = getRequestorScopedMvpdCache(requestorId)?.get(mvpd) || null;
  return {
    ok: true,
    programmerId: resolvedProgrammer.programmerId,
    programmerName: resolvedProgrammer.programmerName,
    requestorId,
    serviceProviderId: requestorId,
    mvpd,
    mvpdMeta,
    appInfo: resolvedApp,
    restV2AppCandidates: orderedCandidates,
  };
}

function getRestV2MvpdMeta(requestorId = "", mvpdId = "", mvpdMeta = null) {
  const normalizedRequestorId = String(requestorId || "").trim();
  const normalizedMvpdId = String(mvpdId || "").trim();
  if (!normalizedMvpdId) {
    return null;
  }
  const cacheMeta =
    normalizedRequestorId
      ? getRequestorScopedMvpdCache(normalizedRequestorId)?.get(normalizedMvpdId) || null
      : null;
  const resolvedMeta = mvpdMeta && typeof mvpdMeta === "object" ? mvpdMeta : cacheMeta;
  return resolvedMeta && typeof resolvedMeta === "object" ? resolvedMeta : null;
}

function getRestV2MvpdPickerLabel(requestorId = "", mvpdId = "", mvpdMeta = null) {
  const normalizedMvpdId = String(mvpdId || "").trim();
  if (!normalizedMvpdId) {
    return "MVPD";
  }
  const resolvedMeta = getRestV2MvpdMeta(requestorId, normalizedMvpdId, mvpdMeta);
  return formatMvpdPickerLabel(normalizedMvpdId, resolvedMeta) || normalizedMvpdId;
}

function formatRestV2RequestorMvpdDisplay(requestorId = "", mvpdId = "", mvpdMeta = null, options = {}) {
  const normalizedRequestorId = String(requestorId || "").trim();
  const requestorLabel = normalizedRequestorId || "requestor";
  const normalizedMvpdId = String(mvpdId || "").trim();
  if (!normalizedMvpdId) {
    return requestorLabel;
  }
  const separator = String(options?.separator || " X ");
  return `${requestorLabel}${separator}${getRestV2MvpdPickerLabel(normalizedRequestorId, normalizedMvpdId, mvpdMeta)}`;
}

function syncRestV2BobtoolsLauncher(section, programmer, appInfo) {
  if (!section) {
    return;
  }
  const tool = section.querySelector(".rest-v2-bobtools-tool");
  const button = section.querySelector(".rest-v2-bobtools-open-btn");
  if (!tool || !button) {
    return;
  }

  const context = buildCurrentRestV2SelectionContext(programmer, appInfo);
  const programmerId = context?.ok
    ? String(context.programmerId || "").trim()
    : String(programmer?.programmerId || resolveSelectedProgrammer()?.programmerId || "").trim();
  const harvestList = programmerId ? getRestV2ProfileHarvestBucketForProgrammer(programmerId) : [];
  const hasProfiles = harvestList.length > 0;
  const selectedHarvest = harvestList[0] || null;
  const selectedRequestorId = String(selectedHarvest?.requestorId || selectedHarvest?.serviceProviderId || "").trim();
  const selectedMvpd = String(selectedHarvest?.mvpd || "").trim();
  const mvpdMeta =
    selectedHarvest && String(selectedHarvest?.mvpdName || "").trim() && selectedMvpd
      ? {
          id: selectedMvpd,
          name: String(selectedHarvest.mvpdName || "").trim(),
        }
      : null;
  const requestorMvpdLabel = selectedHarvest
    ? formatRestV2RequestorMvpdDisplay(selectedRequestorId, selectedMvpd, mvpdMeta, { separator: " x " })
    : "";

  tool.hidden = !hasProfiles;
  button.disabled = !hasProfiles;
  if (!hasProfiles) {
    button.title = "BOBTOOLS unlocks after at least one successful MVPD login profile is captured.";
    button.setAttribute("aria-label", "BOBTOOLS unavailable until MVPD login profile is captured");
    return;
  }
  const actionLabel = requestorMvpdLabel ? `Open BOBTOOLS Workspace for ${requestorMvpdLabel}.` : "Open BOBTOOLS Workspace";
  button.title = actionLabel;
  button.setAttribute("aria-label", actionLabel);
}

function hideRestV2MvpdDependentControls(section, options = {}) {
  if (!section) {
    return;
  }
  const preserveLoginTool = options?.preserveLoginTool === true;
  const loginTool = section.querySelector(".rest-v2-login-tool");
  const loginButton = section.querySelector(".rest-v2-test-login-btn");
  const stopButton = section.querySelector(".rest-v2-close-login-btn");
  const profileTool = section.querySelector(".rest-v2-profile-history-tool");
  const entitlementTool = section.querySelector(".rest-v2-entitlement-tool");
  const splunkTool = section.querySelector(".rest-v2-splunk-report-tool");
  const bobtoolsTool = section.querySelector(".rest-v2-bobtools-tool");

  if (loginTool) {
    loginTool.hidden = !preserveLoginTool;
  }
  if (loginButton) {
    loginButton.hidden = true;
    loginButton.disabled = true;
    loginButton.removeAttribute("title");
    loginButton.removeAttribute("aria-label");
  }
  if (stopButton) {
    stopButton.hidden = true;
    stopButton.disabled = true;
  }
  if (profileTool) {
    profileTool.hidden = true;
  }
  if (entitlementTool) {
    entitlementTool.hidden = true;
  }
  if (splunkTool) {
    splunkTool.hidden = true;
  }
  if (bobtoolsTool) {
    bobtoolsTool.hidden = true;
  }
  setRestV2LoginPanelStatus(section, "");
}

function syncRestV2LoginPanel(section, programmer, appInfo) {
  const button = section?.querySelector(".rest-v2-test-login-btn");
  const loginTool = section?.querySelector(".rest-v2-login-tool");
  const hasSelectedMvpd = Boolean(String(state.selectedMvpdId || "").trim());
  const showMvpdUi = hasSelectedMvpd || state.restV2RecordingActive === true || state.restV2Stopping === true;

  if (!showMvpdUi) {
    hideRestV2MvpdDependentControls(section, { preserveLoginTool: true });
    if (loginTool) {
      loginTool.hidden = false;
    }
    setRestV2LoginPanelStatus(section, "Select an MVPD to enable REST V2 LOGIN.");
    return;
  }
  if (loginTool) {
    loginTool.hidden = false;
  }

  const context = buildCurrentRestV2SelectionContext(programmer, appInfo);
  syncRestV2CloseLoginButton(section);
  syncRestV2ProfileAndEntitlementPanels(section, programmer, appInfo);
  syncRestV2BobtoolsLauncher(section, programmer, appInfo);
  if (!button) {
    return;
  }

  if (state.restV2Stopping) {
    button.hidden = state.restV2RecordingActive === true;
    button.disabled = true;
    setRestV2LoginPanelStatus(section, "Finalizing recording and HAR export...");
    return;
  }

  if (state.restV2RecordingActive && state.restV2DebugFlowId) {
    button.hidden = true;
    button.disabled = true;
    const activeContext = state.restV2RecordingContext;
    const captureLabel =
      activeContext?.requestorId && activeContext?.mvpd
        ? formatRestV2RequestorMvpdDisplay(
            activeContext.requestorId,
            activeContext.mvpd,
            String(activeContext?.mvpdName || "").trim()
              ? {
                  id: String(activeContext.mvpd || "").trim(),
                  name: String(activeContext.mvpdName || "").trim(),
                }
              : null,
            { separator: " x " }
          )
        : "active MVPD flow";
    setRestV2LoginPanelStatus(section, `Recording HTTP session traffic for ${captureLabel}.`, "success");
    return;
  }

  if (!context.ok) {
    button.hidden = true;
    button.disabled = true;
    button.removeAttribute("title");
    button.removeAttribute("aria-label");
    setRestV2LoginPanelStatus(section, context.reason);
    return;
  }

  const selectionKey = getRestV2SelectionKey(context);
  const prepareError = state.restV2PrepareErrorBySelectionKey.get(selectionKey) || "";
  const appName = context.appInfo?.appName || context.appInfo?.guid || "REST V2 App";
  const mvpdLabel = getRestV2MvpdPickerLabel(context.requestorId, context.mvpd, context.mvpdMeta);
  const flowLabel = mvpdLabel || "MVPD";
  const readyMessage = `Ready to start recording ${flowLabel} with "${appName}".`;

  button.textContent = `${flowLabel} LOGIN`;
  button.title = readyMessage;
  button.setAttribute("aria-label", readyMessage);
  button.hidden = false;
  button.disabled = false;
  if (prepareError) {
    setRestV2LoginPanelStatus(section, `${prepareError} Click ${button.textContent} to retry.`, "error");
  } else {
    setRestV2LoginPanelStatus(section, "");
  }
}

function refreshRestV2LoginPanels() {
  const sections = document.querySelectorAll(".premium-service-section.service-rest-v2");
  if (!sections || sections.length === 0) {
    refreshBobtoolsWorkspaceTools();
    return;
  }

  const selectedProgrammer = resolveSelectedProgrammer();
  sections.forEach((section) => {
    syncRestV2LoginPanel(section, selectedProgrammer, null);
  });
  refreshBobtoolsWorkspaceTools();
}

async function maybeAutoStopRestV2RecordingForSelectionChange(nextSelection = {}, options = {}) {
  if (state.restV2Stopping || state.restV2RecordingActive !== true || !String(state.restV2DebugFlowId || "").trim()) {
    return false;
  }
  const recordingContext =
    state.restV2RecordingContext && typeof state.restV2RecordingContext === "object" ? state.restV2RecordingContext : null;
  if (!recordingContext) {
    return false;
  }

  const currentRequestorId = String(recordingContext.requestorId || recordingContext.serviceProviderId || "").trim().toLowerCase();
  const currentMvpd = String(recordingContext.mvpd || "").trim().toLowerCase();
  const nextRequestorId = String(nextSelection.requestorId || "").trim().toLowerCase();
  const nextMvpd = String(nextSelection.mvpdId || "").trim().toLowerCase();
  const selectionChanged = currentRequestorId !== nextRequestorId || currentMvpd !== nextMvpd;
  if (!selectionChanged) {
    return false;
  }

  const selectionReason = String(options.reason || "selection change").trim() || "selection change";
  setStatus(`Detected ${selectionReason} while REST V2 recording was active. Auto-stopping previous capture...`, "info");
  const restSection = document.querySelector(".premium-service-section.service-rest-v2");
  await stopRestV2MvpdRecording(restSection || null, resolveSelectedProgrammer(), null);
  return true;
}

function waitForDelay(durationMs) {
  return new Promise((resolve) => {
    setTimeout(resolve, Math.max(0, Number(durationMs) || 0));
  });
}

async function copyTextToClipboard(text = "") {
  const value = String(text || "").trim();
  if (!value) {
    return {
      ok: false,
      error: "Nothing to copy.",
    };
  }

  try {
    if (navigator?.clipboard?.writeText) {
      await navigator.clipboard.writeText(value);
      return { ok: true };
    }
  } catch {
    // Continue to fallback flow.
  }

  let helper = null;
  try {
    helper = document.createElement("textarea");
    helper.value = value;
    helper.setAttribute("readonly", "");
    helper.setAttribute("aria-hidden", "true");
    helper.style.position = "fixed";
    helper.style.left = "-9999px";
    helper.style.top = "0";
    helper.style.opacity = "0";
    document.body.appendChild(helper);
    helper.focus();
    helper.select();
    helper.setSelectionRange(0, helper.value.length);
    const copied = document.execCommand("copy");
    return copied
      ? { ok: true }
      : {
          ok: false,
          error: "Unable to copy upstreamUserID to clipboard.",
        };
  } catch (error) {
    return {
      ok: false,
      error: error instanceof Error ? error.message : String(error),
    };
  } finally {
    if (helper && helper.parentNode) {
      helper.parentNode.removeChild(helper);
    }
  }
}

function showRestV2CopyButtonFeedback(button, success = false) {
  if (!button) {
    return;
  }
  const baseLabel = "Copy upstreamUserID to clipboard";
  const successLabel = "Copied upstreamUserID to clipboard";
  button.classList.toggle("copied", success === true);
  button.title = success ? successLabel : baseLabel;
  button.setAttribute("aria-label", success ? successLabel : baseLabel);

  const existingTimer = Number(button.__underparCopyFeedbackTimer || 0);
  if (existingTimer) {
    clearTimeout(existingTimer);
  }

  if (!success) {
    button.__underparCopyFeedbackTimer = 0;
    return;
  }

  button.__underparCopyFeedbackTimer = window.setTimeout(() => {
    button.classList.remove("copied");
    button.title = baseLabel;
    button.setAttribute("aria-label", baseLabel);
    button.__underparCopyFeedbackTimer = 0;
  }, 1400);
}

function toRestV2RecordingContext(context, appInfoOverride = null, options = {}) {
  if (!context?.ok) {
    return null;
  }
  const serviceProviderId = String(context.serviceProviderId || context.requestorId || "").trim();
  const redirectUrl = normalizeAdobeNavigationUrl(firstNonEmptyString([options?.redirectUrl, context?.redirectUrl]));
  const sessionUrl = normalizeAdobeNavigationUrl(firstNonEmptyString([options?.sessionUrl]));
  const loginUrl = normalizeAdobeNavigationUrl(firstNonEmptyString([options?.loginUrl]));
  const sessionCodeCandidates = collectRestV2SessionCodeCandidates(
    [
      options?.sessionCode,
      ...(Array.isArray(options?.sessionCodeCandidates) ? options.sessionCodeCandidates : []),
      sessionUrl,
      loginUrl,
    ],
    serviceProviderId
  );
  const sessionCode = firstNonEmptyString(sessionCodeCandidates);
  const selectedAppInfo = appInfoOverride || context.appInfo || null;
  const compactAppInfo = selectedAppInfo
    ? {
        guid: String(selectedAppInfo.guid || ""),
        appName: String(selectedAppInfo.appName || selectedAppInfo.guid || ""),
        scopes: Array.isArray(selectedAppInfo.scopes) ? selectedAppInfo.scopes.slice(0, 12) : [],
      }
    : null;
  return {
    programmerId: context.programmerId,
    programmerName: context.programmerName || "",
    requestorId: context.requestorId,
    serviceProviderId,
    mvpd: context.mvpd,
    mvpdName: String(context?.mvpdMeta?.name || "").trim(),
    appInfo: compactAppInfo,
    redirectUrl,
    sessionCode,
    sessionCodeCandidates,
    sessionAction: String(firstNonEmptyString([options?.sessionAction, context?.sessionAction]) || "").trim(),
    sessionPartner: String(firstNonEmptyString([options?.sessionPartner, context?.sessionPartner]) || "").trim(),
    partnerFrameworkStatus: String(options?.partnerFrameworkStatus || context?.partnerFrameworkStatus || "").trim(),
    sessionResponseHeaders:
      options?.sessionResponseHeaders && typeof options.sessionResponseHeaders === "object"
        ? { ...options.sessionResponseHeaders }
        : null,
    sessionUrl,
    loginUrl,
    startedAt: Date.now(),
  };
}

async function launchRestV2MvpdLogin(section, programmer, appInfo) {
  const button = section?.querySelector(".rest-v2-test-login-btn");
  if (button) {
    button.disabled = true;
  }

  let debugFlowId = "";
  try {
    if (state.restV2Stopping) {
      setRestV2LoginPanelStatus(section, "Stopping previous recording. Please wait...");
      return;
    }

    if (state.restV2RecordingActive && state.restV2DebugFlowId) {
      setRestV2LoginPanelStatus(
        section,
        "A recording session is already active. Use STOP to end capture and download HAR."
      );
      return;
    }

    const context = buildCurrentRestV2SelectionContext(programmer, appInfo);
    if (!context.ok) {
      throw new Error(context.reason);
    }
    const requestorMvpdLabel = formatRestV2RequestorMvpdDisplay(context.requestorId, context.mvpd, context.mvpdMeta, {
      separator: " x ",
    });
    setRestV2ActiveProfileWindowState(context, false, {
      checkedAt: Date.now(),
      profileCount: 0,
      status: 0,
      statusText: "",
      error: "",
      source: "start-recording-reset",
    });

    const selectionKey = getRestV2SelectionKey(context);
    if (selectionKey) {
      state.restV2PreparedLoginBySelectionKey.delete(selectionKey);
      state.restV2PrepareErrorBySelectionKey.delete(selectionKey);
      state.restV2PreparePromiseBySelectionKey.delete(selectionKey);
    }

    setRestV2LoginPanelStatus(
      section,
      `Resetting prior ${requestorMvpdLabel} MVPD session before starting a fresh recording...`
    );
    const preStartLogoutResult = await executeRestV2LogoutFlow(context, "");
    if (preStartLogoutResult.attempted !== true || preStartLogoutResult.performed !== true) {
      const logoutReason = firstNonEmptyString([
        String(preStartLogoutResult.error || "").trim(),
        preStartLogoutResult.attempted !== true
          ? "REST V2 logout was not attempted."
          : "REST V2 logout did not fully complete.",
      ]);
      setRestV2LoginPanelStatus(
        section,
        `Logout warning for ${requestorMvpdLabel}: ${logoutReason} Continuing to MVPD login...`,
        "error"
      );
      emitRestV2DebugEvent(debugFlowId, {
        source: "extension",
        phase: "start-recording-logout-warning",
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        attempted: preStartLogoutResult.attempted === true,
        performed: preStartLogoutResult.performed === true,
        warning: logoutReason,
      });
    }

    setRestV2LoginPanelStatus(
      section,
      `Confirming ${requestorMvpdLabel} session reset before new recording...`
    );
    const postLogoutProfiles = await verifyPostLogoutProfilesCleared(context, "");
    if (!postLogoutProfiles.ok) {
      const profileReason =
        String(postLogoutProfiles.error || "").trim() ||
        `${Number(postLogoutProfiles.profileCount || 0)} active profile(s) still returned`;
      setRestV2LoginPanelStatus(
        section,
        `Logout verification warning for ${requestorMvpdLabel}: ${profileReason}. Continuing to MVPD login...`,
        "error"
      );
      emitRestV2DebugEvent(debugFlowId, {
        source: "extension",
        phase: "start-recording-post-logout-warning",
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        blocking: postLogoutProfiles.blocking === true,
        warning: profileReason,
      });
    }

    debugFlowId = await startRestV2DebugFlow(
      {
        programmerId: context.programmerId,
        programmerName: context.programmerName || "",
        requestorId: context.requestorId,
        mvpd: context.mvpd,
      },
      "start-recording-click"
    );
    if (!debugFlowId) {
      throw new Error("Unable to start UP HTTP recording flow.");
    }

    state.restV2DebugFlowId = debugFlowId;
    state.restV2RecordingActive = true;
    state.restV2RecordingStartedAt = Date.now();
    state.restV2RecordingContext = toRestV2RecordingContext(context);

    emitRestV2DebugEvent(debugFlowId, {
      source: "extension",
      phase: "recording-start",
      requestorId: context.requestorId,
      mvpd: context.mvpd,
    });

    setRestV2LoginPanelStatus(
      section,
      `Preparing fresh ${requestorMvpdLabel} MVPD login session...`
    );
    const preparedEntry = await ensurePreparedRestV2LoginForContext(section, context, {
      force: true,
      debugFlowId,
    });
    if (!preparedEntry?.loginUrl) {
      throw new Error("REST V2 session response did not include a login URL.");
    }

    const selectedAppInfo = preparedEntry.appInfo || context.appInfo;
    const configuredRedirectUrl = normalizeAdobeNavigationUrl(
      firstNonEmptyString([
        preparedEntry?.payload?.redirectUrl,
        preparedEntry?.sessionData?.existingParameters?.redirectUrl,
      ])
    );
    const sessionCodeCandidates = collectRestV2SessionCodeCandidates(
      [
        preparedEntry?.sessionData?.code,
        preparedEntry?.sessionData?.sessionCode,
        preparedEntry?.sessionData?.url,
        preparedEntry?.loginUrl,
      ],
      context.serviceProviderId
    );
    storeRestV2AuthContextForRequestor(context, selectedAppInfo);
    state.restV2RecordingContext = toRestV2RecordingContext(context, selectedAppInfo, {
      redirectUrl: configuredRedirectUrl,
      sessionCode: firstNonEmptyString([preparedEntry?.sessionData?.code, sessionCodeCandidates[0]]),
      sessionCodeCandidates,
      sessionAction: String(preparedEntry?.sessionData?.actionName || "").trim(),
      sessionPartner: String(firstNonEmptyString([preparedEntry?.sessionPartner, preparedEntry?.sessionData?.partner]) || "").trim(),
      partnerFrameworkStatus: String(
        firstNonEmptyString([preparedEntry?.partnerFrameworkStatus, preparedEntry?.sessionData?.partnerFrameworkStatus]) || ""
      ).trim(),
      sessionResponseHeaders:
        preparedEntry?.sessionResponseHeaders && typeof preparedEntry.sessionResponseHeaders === "object"
          ? { ...preparedEntry.sessionResponseHeaders }
          : null,
      sessionUrl: normalizeAdobeNavigationUrl(firstNonEmptyString([preparedEntry?.sessionData?.url])),
      loginUrl: preparedEntry?.loginUrl,
    });

    const activeTab = await getCurrentActiveTab();
    state.restV2PreviousTabId =
      Number.isFinite(Number(activeTab?.id)) && Number(activeTab.id) > 0 ? Number(activeTab.id) : 0;
    state.restV2PreviousTabUrl = String(activeTab?.url || "");

    await closeExistingRestV2LaunchTarget();

    const launchedTarget = await openRestV2LoginPopupWindow();
    state.restV2LastLaunchWindowId = Number(launchedTarget.windowId || 0);
    state.restV2LastLaunchTabId = Number(launchedTarget.tabId || 0);
    if (state.restV2LastLaunchTabId > 0) {
      const bound = await bindRestV2DebugFlowToTab(debugFlowId, state.restV2LastLaunchTabId, {
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        loginUrl: preparedEntry.loginUrl,
        redirectUrl: configuredRedirectUrl,
      });
      if (!bound && debugFlowId) {
        emitRestV2DebugEvent(debugFlowId, {
          source: "extension",
          phase: "bind-tab-failed",
          tabId: state.restV2LastLaunchTabId,
        });
      }

      await chrome.tabs.update(state.restV2LastLaunchTabId, {
        url: preparedEntry.loginUrl,
        active: true,
      });
      await focusChromeWindowFront(state.restV2LastLaunchWindowId, { drawAttention: true });
      pulseChromeWindowFront(state.restV2LastLaunchWindowId, 120);

      const traceViewerResult = await openOrFocusUPTraceViewer(state.restV2LastLaunchTabId, debugFlowId);
      if (traceViewerResult.ok) {
        emitRestV2DebugEvent(debugFlowId, {
          source: "extension",
          phase: "trace-view-opened",
          traceTabId: traceViewerResult.tabId || 0,
          traceWindowId: traceViewerResult.windowId || 0,
          traceMode: traceViewerResult.mode || (traceViewerResult.reused ? "reuse" : "unknown"),
        });
      } else {
        emitRestV2DebugEvent(debugFlowId, {
          source: "extension",
          phase: "trace-view-open-failed",
          error: traceViewerResult.error || "Unable to open UP trace viewer.",
        });
      }
    } else {
      throw new Error("Unable to open login window.");
    }

    emitRestV2DebugEvent(debugFlowId, {
      source: "extension",
      phase: "tab-launched",
      tabId: state.restV2LastLaunchTabId,
      windowId: state.restV2LastLaunchWindowId,
      loginUrl: preparedEntry.loginUrl,
      sessionCode:
        String(state.restV2RecordingContext?.sessionCode || "").trim() ||
        String(preparedEntry?.sessionData?.code || "").trim(),
      sessionCodeCandidates: Array.isArray(state.restV2RecordingContext?.sessionCodeCandidates)
        ? state.restV2RecordingContext.sessionCodeCandidates.slice(0, 8)
        : [],
      sessionAction:
        String(state.restV2RecordingContext?.sessionAction || "").trim() ||
        String(preparedEntry?.sessionData?.actionName || "").trim(),
    });

    setRestV2LoginPanelStatus(
      section,
      `Recording started for ${requestorMvpdLabel}. Use STOP to end capture and download HAR.`,
      "success"
    );
    syncRestV2LoginPanel(section, programmer, appInfo);
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    setRestV2LoginPanelStatus(section, reason, "error");
    emitRestV2DebugEvent(debugFlowId || state.restV2DebugFlowId, {
      source: "extension",
      phase: "launch-error",
      error: reason,
    });

    state.restV2RecordingActive = false;
    state.restV2RecordingStartedAt = 0;
    state.restV2RecordingContext = null;

    const flowToStop = String(debugFlowId || state.restV2DebugFlowId || "").trim();
    if (flowToStop) {
      await stopRestV2DebugFlowAndSnapshot(flowToStop, "start-failed");
    }
    state.restV2DebugFlowId = "";
  } finally {
    if (button && !(state.restV2RecordingActive && state.restV2DebugFlowId)) {
      button.disabled = false;
    }
    if (!(state.restV2RecordingActive && state.restV2DebugFlowId)) {
      syncRestV2LoginPanel(section, programmer, appInfo);
    }
  }
}

async function closeRestV2LoginAndReturn(section, options = {}) {
  const suppressStatus = options.suppressStatus === true;
  const phasePrefix = String(options.phasePrefix || "close").trim() || "close";
  const closeButton = section?.querySelector(".rest-v2-close-login-btn");
  if (closeButton) {
    closeButton.disabled = true;
  }

  emitRestV2DebugEvent(state.restV2DebugFlowId, {
    source: "extension",
    phase: `${phasePrefix}-click`,
    tabId: Number(state.restV2LastLaunchTabId || 0),
    windowId: Number(state.restV2LastLaunchWindowId || 0),
  });

  try {
    const launchTabId = Number(state.restV2LastLaunchTabId || 0);
    const launchWindowId = Number(state.restV2LastLaunchWindowId || 0);
    const previousTabId = Number(state.restV2PreviousTabId || 0);
    const previousTabUrl = String(state.restV2PreviousTabUrl || "").trim();

    let returned = false;
    if (Number.isFinite(previousTabId) && previousTabId > 0) {
      try {
        await chrome.tabs.update(previousTabId, { active: true });
        returned = true;
      } catch {
        returned = false;
      }
    }

    if (!returned && previousTabUrl) {
      try {
        await chrome.tabs.create({
          url: previousTabUrl,
          active: true,
        });
        returned = true;
      } catch {
        returned = false;
      }
    }

    if (Number.isFinite(launchWindowId) && launchWindowId > 0) {
      try {
        await chrome.windows.remove(launchWindowId);
      } catch {
        // Ignore if already closed by user.
      }
    } else if (Number.isFinite(launchTabId) && launchTabId > 0) {
      try {
        await chrome.tabs.remove(launchTabId);
      } catch {
        // Ignore if already closed by user.
      }
    }

    state.restV2LastLaunchTabId = 0;
    state.restV2LastLaunchWindowId = 0;

    if (!suppressStatus) {
      if (returned) {
        setRestV2LoginPanelStatus(section, "Closed MVPD login window and returned to your previous page.", "success");
      } else {
        setRestV2LoginPanelStatus(
          section,
          "MVPD login window closed. Previous tab was not available; use Chrome tabs to continue."
        );
      }
    }

    emitRestV2DebugEvent(state.restV2DebugFlowId, {
      source: "extension",
      phase: `${phasePrefix}-complete`,
      returnedToPreviousTab: returned,
      previousTabId,
      closedTabId: launchTabId,
      closedWindowId: launchWindowId,
    });
    return {
      ok: true,
      returned,
      previousTabId,
      closedTabId: launchTabId,
      closedWindowId: launchWindowId,
    };
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    if (!suppressStatus) {
      setRestV2LoginPanelStatus(section, reason, "error");
    }
    emitRestV2DebugEvent(state.restV2DebugFlowId, {
      source: "extension",
      phase: `${phasePrefix}-error`,
      error: reason,
    });
    return {
      ok: false,
      error: reason,
    };
  } finally {
    syncRestV2CloseLoginButton(section);
  }
}

async function waitForTabCompletion(tabId, timeoutMs = REST_V2_LOGOUT_NAVIGATION_TIMEOUT_MS, options = {}) {
  const normalizedTabId = Number(tabId || 0);
  const expectedUrl = String(options?.expectedUrl || "").trim();
  if (!Number.isFinite(normalizedTabId) || normalizedTabId <= 0) {
    return { ok: false, reason: "invalid-tab" };
  }

  return new Promise((resolve) => {
    let settled = false;
    let timeoutId = 0;
    let sawNavigationSignal = false;

    const matchesExpectedUrl = (candidateUrl) => {
      if (!expectedUrl) {
        return true;
      }
      const normalizedCandidateUrl = String(candidateUrl || "").trim();
      if (!normalizedCandidateUrl) {
        return false;
      }
      if (normalizedCandidateUrl === expectedUrl || normalizedCandidateUrl.startsWith(expectedUrl)) {
        return true;
      }
      try {
        const expectedParsed = new URL(expectedUrl);
        const candidateParsed = new URL(normalizedCandidateUrl);
        return candidateParsed.origin === expectedParsed.origin && candidateParsed.pathname === expectedParsed.pathname;
      } catch {
        return false;
      }
    };

    const done = (result) => {
      if (settled) {
        return;
      }
      settled = true;
      chrome.tabs.onUpdated.removeListener(onUpdated);
      chrome.tabs.onRemoved.removeListener(onRemoved);
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
      resolve(result);
    };

    const onUpdated = (updatedTabId, changeInfo, tab) => {
      if (Number(updatedTabId) !== normalizedTabId) {
        return;
      }
      if (changeInfo.status === "loading" || String(changeInfo.url || "").trim()) {
        sawNavigationSignal = true;
      }
      if (changeInfo.status === "complete") {
        const resolvedUrl = String(tab?.url || changeInfo.url || "");
        if (expectedUrl && !sawNavigationSignal && !matchesExpectedUrl(resolvedUrl)) {
          return;
        }
        done({
          ok: true,
          status: "complete",
          url: resolvedUrl,
        });
      }
    };

    const onRemoved = (removedTabId) => {
      if (Number(removedTabId) === normalizedTabId) {
        done({ ok: false, reason: "tab-removed" });
      }
    };

    chrome.tabs.onUpdated.addListener(onUpdated);
    chrome.tabs.onRemoved.addListener(onRemoved);
    timeoutId = setTimeout(() => {
      done({ ok: false, reason: "timeout" });
    }, Math.max(5000, Number(timeoutMs || REST_V2_LOGOUT_NAVIGATION_TIMEOUT_MS)));

    void chrome.tabs
      .get(normalizedTabId)
      .then((tab) => {
        const tabUrl = String(tab?.url || "");
        if (matchesExpectedUrl(tabUrl)) {
          sawNavigationSignal = true;
        }
        if (tab?.status === "complete" && (!expectedUrl || matchesExpectedUrl(tabUrl))) {
          done({
            ok: true,
            status: "already-complete",
            url: tabUrl,
          });
        }
      })
      .catch(() => {
        // Wait for update/remove callbacks.
      });
  });
}

function isRestV2NoActiveProfileSignal(profileCheckResult = null) {
  if (!profileCheckResult || typeof profileCheckResult !== "object") {
    return false;
  }
  if (Number(profileCheckResult.profileCount || 0) > 0) {
    return false;
  }
  const status = Number(profileCheckResult.status || 0);
  const combinedText = [
    String(profileCheckResult.error || "").trim(),
    String(profileCheckResult.responsePayload?.code || "").trim(),
    String(profileCheckResult.responsePayload?.error || "").trim(),
    String(profileCheckResult.responsePayload?.message || "").trim(),
    String(profileCheckResult.responsePayload?.description || "").trim(),
    String(profileCheckResult.statusText || "").trim(),
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
  if (
    /authenticated[_\s-]?profile[_\s-]?missing|no[_\s-]?active[_\s-]?profile|no[_\s-]?profile|no[_\s-]?session|session[_\s-]?missing|already[_\s-]?logged[_\s-]?out|logged[_\s-]?out|authnf/.test(
      combinedText
    )
  ) {
    return true;
  }
  if ((status === 401 || status === 403 || status === 404) && Number(profileCheckResult.profileCount || 0) === 0) {
    return true;
  }
  return false;
}

function normalizeRestV2LogoutCandidate(candidate, fallbackMvpd = "") {
  if (typeof candidate === "string") {
    const normalizedUrl = String(candidate || "").trim();
    if (!normalizedUrl) {
      return null;
    }
    return {
      mvpd: String(fallbackMvpd || "").trim(),
      actionName: "redirect",
      actionType: "redirect",
      url: normalizedUrl,
    };
  }
  if (!candidate || typeof candidate !== "object") {
    return null;
  }

  const actionName = firstNonEmptyString([candidate.actionName, candidate.action, candidate.code]);
  const actionType = firstNonEmptyString([candidate.actionType, candidate.type]);
  const url = firstNonEmptyString([candidate.url, candidate.location, candidate.logoutUrl, candidate.redirectUrl]);
  const mvpd = firstNonEmptyString([candidate.mvpd, candidate.idp, fallbackMvpd]);
  if (!actionName && !actionType && !url) {
    return null;
  }
  return {
    mvpd: String(mvpd || "").trim(),
    actionName: String(actionName || "").trim(),
    actionType: String(actionType || "").trim(),
    url: String(url || "").trim(),
  };
}

function resolveRestV2LogoutAction(payload, mvpd, fallbackLocation = "") {
  const normalizedMvpd = String(mvpd || "").trim();
  const normalizedMvpdLower = normalizedMvpd.toLowerCase();
  const logoutMap = payload?.logouts && typeof payload.logouts === "object" ? payload.logouts : {};
  const matchingCandidates = [];
  const otherCandidates = [];
  for (const [rawKey, rawValue] of Object.entries(logoutMap)) {
    const key = String(rawKey || "").trim();
    const normalizedCandidate = normalizeRestV2LogoutCandidate(rawValue, key || normalizedMvpd);
    if (!normalizedCandidate) {
      continue;
    }
    const candidateMvpdLower = String(normalizedCandidate.mvpd || "").trim().toLowerCase();
    const keyLower = key.toLowerCase();
    const matchesRequestedMvpd =
      !normalizedMvpdLower || keyLower === normalizedMvpdLower || candidateMvpdLower === normalizedMvpdLower;
    if (matchesRequestedMvpd) {
      matchingCandidates.push(normalizedCandidate);
    } else {
      otherCandidates.push(normalizedCandidate);
    }
  }

  if (fallbackLocation) {
    const fallbackCandidate = normalizeRestV2LogoutCandidate(
      {
        mvpd: normalizedMvpd,
        actionName: "redirect",
        actionType: "redirect",
        url: fallbackLocation,
      },
      normalizedMvpd
    );
    if (fallbackCandidate) {
      if (normalizedMvpdLower) {
        matchingCandidates.push(fallbackCandidate);
      } else {
        otherCandidates.push(fallbackCandidate);
      }
    }
  }

  const orderedCandidates = normalizedMvpdLower ? matchingCandidates : [...matchingCandidates, ...otherCandidates];
  for (const candidate of orderedCandidates) {
    return candidate;
  }

  return null;
}

async function openRestV2BackgroundLogoutTarget(logoutUrl, flowId, context = null) {
  const normalizedUrl = String(logoutUrl || "").trim();
  if (!normalizedUrl) {
    return {
      ok: false,
      error: "Missing logout URL.",
      tabId: 0,
      windowId: 0,
      ownsWindow: false,
      mode: "",
    };
  }

  let windowId = 0;
  let tabId = 0;
  let ownsWindow = false;
  let mode = "";

  try {
    const createdWindow = await chrome.windows.create({
      url: normalizedUrl,
      focused: false,
      state: "minimized",
      width: 480,
      height: 640,
    });
    windowId = Number(createdWindow?.id || 0);
    tabId = Number(createdWindow?.tabs?.[0]?.id || 0);
    ownsWindow = true;
    mode = "minimized-window";
  } catch (windowError) {
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "logout-background-window-failed",
      requestorId: String(context?.requestorId || ""),
      mvpd: String(context?.mvpd || ""),
      logoutUrl: normalizedUrl,
      error: windowError instanceof Error ? windowError.message : String(windowError),
    });
    try {
      const createdTab = await chrome.tabs.create({
        url: normalizedUrl,
        active: false,
      });
      tabId = Number(createdTab?.id || 0);
      windowId = Number(createdTab?.windowId || 0);
      mode = "inactive-tab";
    } catch (tabError) {
      return {
        ok: false,
        error: tabError instanceof Error ? tabError.message : String(tabError),
        tabId: 0,
        windowId: 0,
        ownsWindow: false,
        mode: "",
      };
    }
  }

  if (!Number.isFinite(tabId) || tabId <= 0) {
    return {
      ok: false,
      error: "Unable to open a background logout tab.",
      tabId: 0,
      windowId: 0,
      ownsWindow: false,
      mode,
    };
  }

  if (flowId) {
    const bound = await bindRestV2DebugFlowToTab(flowId, tabId, {
      requestorId: String(context?.requestorId || ""),
      mvpd: String(context?.mvpd || ""),
      logoutUrl: normalizedUrl,
      phase: "logout-background",
    });
    if (!bound) {
      emitRestV2DebugEvent(flowId, {
        source: "extension",
        phase: "logout-bind-tab-failed",
        tabId,
        logoutUrl: normalizedUrl,
      });
    }
  }

  return {
    ok: true,
    error: "",
    tabId,
    windowId,
    ownsWindow,
    mode,
  };
}

async function navigateRestV2LogoutUrlInBackground(logoutUrl, flowId, context = null) {
  const normalizedUrl = String(logoutUrl || "").trim();
  if (!normalizedUrl) {
    return { ok: false, reason: "missing-url", mode: "" };
  }
  const target = await openRestV2BackgroundLogoutTarget(normalizedUrl, flowId, context);
  if (!target.ok || !target.tabId) {
    return {
      ok: false,
      reason: target.error || "unable-to-open-background-target",
      mode: target.mode || "",
      tabId: Number(target.tabId || 0),
      windowId: Number(target.windowId || 0),
      ownsWindow: target.ownsWindow === true,
    };
  }
  const launchTabId = Number(target.tabId || 0);
  const launchWindowId = Number(target.windowId || 0);
  const ownsWindow = target.ownsWindow === true;
  let navigationResult = { ok: false, reason: "unknown" };
  try {
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "logout-navigation-start",
      tabId: launchTabId,
      windowId: launchWindowId,
      mode: String(target.mode || ""),
      logoutUrl: normalizedUrl,
    });
    navigationResult = await waitForTabCompletion(launchTabId, REST_V2_LOGOUT_NAVIGATION_TIMEOUT_MS, {
      expectedUrl: normalizedUrl,
    });
    await waitForDelay(REST_V2_LOGOUT_POST_NAV_DELAY_MS);
  } finally {
    if (ownsWindow && Number.isFinite(launchWindowId) && launchWindowId > 0) {
      try {
        await chrome.windows.remove(launchWindowId);
      } catch {
        // Ignore close failures for already-closed windows.
      }
    } else if (Number.isFinite(launchTabId) && launchTabId > 0) {
      try {
        await chrome.tabs.remove(launchTabId);
      } catch {
        // Ignore close failures for already-closed tabs.
      }
    }
  }

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: "logout-navigation-finished",
    tabId: launchTabId,
    windowId: launchWindowId,
    mode: String(target.mode || ""),
    logoutUrl: normalizedUrl,
    ...navigationResult,
  });

  return {
    ...navigationResult,
    mode: String(target.mode || ""),
    tabId: launchTabId,
    windowId: launchWindowId,
    ownsWindow,
  };
}

async function executeRestV2LogoutAction(logoutUrl, flowId, context = null) {
  const normalizedUrl = String(logoutUrl || "").trim();
  if (!normalizedUrl) {
    return { ok: false, reason: "missing-url", mode: "" };
  }

  const navigationResult = await navigateRestV2LogoutUrlInBackground(normalizedUrl, flowId, context);
  if (navigationResult?.ok === true || String(navigationResult?.reason || "") === "tab-removed") {
    return {
      ok: true,
      reason: String(navigationResult?.reason || "").trim(),
      mode: String(navigationResult?.mode || "background-navigation"),
    };
  }

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: "logout-action-navigation-failed",
    requestorId: String(context?.requestorId || ""),
    mvpd: String(context?.mvpd || ""),
    logoutUrl: normalizedUrl,
    mode: String(navigationResult?.mode || ""),
    reason: String(navigationResult?.reason || "").trim(),
  });

  return {
    ok: false,
    reason: String(navigationResult?.reason || "").trim() || "logout user-agent action did not complete",
    mode: String(navigationResult?.mode || ""),
  };
}

function isRestV2LogoutActionCompleted(result = null) {
  const completionSignal = `${String(result?.actionName || "")} ${String(result?.actionType || "")}`.toLowerCase();
  return /complete|success|logged\s*out|loggedout|no[_\s-]?session/.test(completionSignal);
}

function isRestV2LogoutActionInvalid(result = null) {
  const actionSignal = `${String(result?.actionName || "")} ${String(result?.actionType || "")}`.toLowerCase();
  return /invalid/.test(actionSignal);
}

function shouldRunRestV2LogoutUserAgentAction(result = null) {
  const normalizedUrl = String(result?.logoutUrl || "").trim();
  if (!normalizedUrl) {
    return false;
  }
  if (isRestV2LogoutActionCompleted(result) || isRestV2LogoutActionInvalid(result)) {
    return false;
  }
  return true;
}

function isRestV2LogoutApiAccepted(response = null) {
  const status = Number(response?.status || 0);
  return Boolean(response?.ok) || status === 302;
}

function buildRestV2LogoutFailureReason(responseText = "", parsed = {}, response = null) {
  return (
    firstNonEmptyString([
      parsed?.code,
      parsed?.error,
      parsed?.message,
      normalizeHttpErrorMessage(responseText),
      response?.statusText,
    ]) || `Logout failed (${Number(response?.status || 0)}).`
  );
}

function buildRestV2LogoutAcceptedFallbackAction(parsed = {}, result = null) {
  const responseSignal = firstNonEmptyString([parsed?.code, parsed?.error, parsed?.message, parsed?.description]);
  return {
    actionName: String(result?.actionName || responseSignal || "accepted-no-action"),
    actionType: String(result?.actionType || (result?.logoutUrl ? "api+user-agent" : "api")),
  };
}

function buildRestV2ProfileHarvestSelectionKey(context = null) {
  const programmerId = String(context?.programmerId || "").trim().toLowerCase();
  const requestorId = String(context?.requestorId || "").trim().toLowerCase();
  const mvpd = String(context?.mvpd || "").trim().toLowerCase();
  return [programmerId, requestorId, mvpd].join("|");
}

function normalizeRestV2ProfileAttributeValue(value) {
  if (value == null) {
    return "";
  }
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return String(value).trim();
  }
  if (typeof value === "object") {
    if (typeof value.value === "string" || typeof value.value === "number" || typeof value.value === "boolean") {
      return String(value.value).trim();
    }
    if (typeof value.raw === "string" || typeof value.raw === "number" || typeof value.raw === "boolean") {
      return String(value.raw).trim();
    }
  }
  return "";
}

function dedupeRestV2CandidateStrings(values = []) {
  const output = [];
  const seen = new Set();
  (Array.isArray(values) ? values : []).forEach((value) => {
    const normalized = normalizeRestV2ProfileAttributeValue(value);
    if (!normalized) {
      return;
    }
    const key = normalized.toLowerCase();
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push(normalized);
  });
  return output;
}

function cloneJsonLikeValue(value, fallback = null) {
  if (value == null) {
    return fallback;
  }
  try {
    return JSON.parse(JSON.stringify(value));
  } catch {
    return fallback;
  }
}

function getRestV2ProfileAttribute(profile, nameVariants = []) {
  const attributes = profile?.attributes && typeof profile.attributes === "object" ? profile.attributes : {};
  if (!attributes || typeof attributes !== "object") {
    return "";
  }

  const attributeEntries = Object.entries(attributes);
  const normalizedTargets = new Set(
    (Array.isArray(nameVariants) ? nameVariants : [])
      .map((name) => String(name || "").trim().toLowerCase())
      .filter(Boolean)
  );
  if (normalizedTargets.size === 0) {
    return "";
  }

  for (const [rawKey, rawValue] of attributeEntries) {
    const normalizedKey = String(rawKey || "").trim().toLowerCase();
    if (!normalizedTargets.has(normalizedKey)) {
      continue;
    }
    const value = normalizeRestV2ProfileAttributeValue(rawValue);
    if (value) {
      return value;
    }
  }
  return "";
}

function getRestV2ProfileAttributesMap(profile) {
  const attributes = profile?.attributes && typeof profile.attributes === "object" ? profile.attributes : {};
  if (!attributes || typeof attributes !== "object") {
    return {};
  }

  const normalized = {};
  Object.entries(attributes).forEach(([rawKey, rawValue]) => {
    const key = String(rawKey || "").trim();
    if (!key) {
      return;
    }
    const value = normalizeRestV2ProfileAttributeValue(rawValue);
    if (!value) {
      return;
    }
    normalized[key] = value;
  });
  return normalized;
}

function getRestV2ProfileScalarFields(profile) {
  const scalarFields = {};
  if (!profile || typeof profile !== "object") {
    return scalarFields;
  }
  Object.entries(profile).forEach(([rawKey, rawValue]) => {
    const key = String(rawKey || "").trim();
    if (!key || key === "attributes") {
      return;
    }
    const value = normalizeRestV2ProfileAttributeValue(rawValue);
    if (!value) {
      return;
    }
    scalarFields[key] = value;
  });
  return scalarFields;
}

function getRestV2ProfileSummary(profile, profileKey = "", context = null) {
  const normalizedProfile = profile && typeof profile === "object" ? profile : {};
  const attributesMap = getRestV2ProfileAttributesMap(normalizedProfile);
  const scalarFields = getRestV2ProfileScalarFields(normalizedProfile);
  const readValue = (keyCandidates = []) => {
    const normalizedCandidates = (Array.isArray(keyCandidates) ? keyCandidates : [])
      .map((value) => String(value || "").trim().toLowerCase())
      .filter(Boolean);
    if (normalizedCandidates.length === 0) {
      return "";
    }

    for (const candidate of normalizedCandidates) {
      const directValue = Object.entries(scalarFields).find(([key]) => String(key || "").trim().toLowerCase() === candidate)?.[1] || "";
      if (directValue) {
        return directValue;
      }
      const attributeValue =
        Object.entries(attributesMap).find(([key]) => String(key || "").trim().toLowerCase() === candidate)?.[1] || "";
      if (attributeValue) {
        return attributeValue;
      }
    }
    return "";
  };

  const upstreamUserId = firstNonEmptyString([
    readValue(["upstreamuserid", "upstream_user_id", "upstreamuserid", "upstream_userid"]),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.upstreamUserID),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.upstreamUserId),
  ]);
  const userId = firstNonEmptyString([
    readValue(["userid", "user_id", "userid", "sub"]),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.userID),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.userId),
  ]);
  const sessionId = firstNonEmptyString([
    readValue(["sessionid", "session_id", "session", "sessiontoken", "session_token"]),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.sessionId),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.sessionID),
  ]);
  const mvpd = firstNonEmptyString([
    readValue(["mvpd", "idp", "provider", "provider_id"]),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.mvpd),
    normalizeRestV2ProfileAttributeValue(normalizedProfile.idp),
    String(profileKey || "").trim(),
    String(context?.mvpd || "").trim(),
  ]);

  const subjectCandidates = dedupeRestV2CandidateStrings([
    upstreamUserId,
    userId,
    readValue(["subject", "subscriberid", "subscriber_id", "accountid", "account_id", "personaid", "persona_id", "sub"]),
  ]);
  const sessionCandidates = dedupeRestV2CandidateStrings([
    sessionId,
    readValue(["sessionid", "session_id", "session", "sessiontoken", "session_token", "tokenid", "token_id"]),
  ]);
  const idpCandidates = dedupeRestV2CandidateStrings([
    mvpd,
    readValue(["mvpd", "idp", "provider", "providerid", "provider_id"]),
  ]);
  if (idpCandidates.length === 0 && String(context?.mvpd || "").trim()) {
    idpCandidates.push(String(context.mvpd || "").trim());
  }

  const notBeforeMs = Number(normalizedProfile.notBefore || normalizedProfile.not_before || 0);
  const notAfterMs = Number(normalizedProfile.notAfter || normalizedProfile.not_after || 0);
  const subject = firstNonEmptyString(subjectCandidates);

  return {
    profileKey: String(profileKey || "").trim(),
    mvpd: String(mvpd || "").trim(),
    subject: String(subject || "").trim(),
    upstreamUserId: String(upstreamUserId || "").trim(),
    userId: String(userId || "").trim(),
    sessionId: String(sessionId || "").trim(),
    subjectCandidates,
    sessionCandidates,
    idpCandidates,
    notBeforeMs: Number.isFinite(notBeforeMs) && notBeforeMs > 0 ? notBeforeMs : 0,
    notAfterMs: Number.isFinite(notAfterMs) && notAfterMs > 0 ? notAfterMs : 0,
    attributes: attributesMap,
    scalarFields,
    rawProfile: cloneJsonLikeValue(normalizedProfile, {}),
  };
}

function restV2ValueHasSsoMarker(value = "") {
  return String(value || "").trim().toLowerCase().includes("sso");
}

function restV2ProfileSummaryHasSsoMarker(summary = null) {
  if (!summary || typeof summary !== "object") {
    return false;
  }
  const candidates = dedupeRestV2CandidateStrings([
    String(summary?.profileKey || "").trim(),
    String(summary?.mvpd || "").trim(),
    ...(Array.isArray(summary?.idpCandidates) ? summary.idpCandidates : []),
  ]);
  return candidates.some((candidate) => restV2ValueHasSsoMarker(candidate));
}

function restV2HarvestHasSsoMarker(harvest = null, mvpdCandidates = []) {
  if (!harvest || typeof harvest !== "object") {
    return false;
  }
  const candidates = dedupeRestV2CandidateStrings([
    ...(Array.isArray(mvpdCandidates) ? mvpdCandidates : []),
    String(harvest?.mvpd || "").trim(),
    ...(Array.isArray(harvest?.idpCandidates) ? harvest.idpCandidates : []),
    ...(Array.isArray(harvest?.allIdpCandidates) ? harvest.allIdpCandidates : []),
    String(harvest?.sessionAction || "").trim(),
    String(harvest?.sessionPartner || "").trim(),
  ]);
  return candidates.some((candidate) => restV2ValueHasSsoMarker(candidate));
}

function scoreRestV2MvpdCandidateMatch(candidate = "", target = "", options = {}) {
  const candidateValue = String(candidate || "").trim();
  const targetValue = String(target || "").trim();
  if (!candidateValue || !targetValue) {
    return -1;
  }

  const allowSsoAlias = options?.allowSsoAlias === true;
  const candidateLower = candidateValue.toLowerCase();
  const targetLower = targetValue.toLowerCase();
  const candidateCompact = normalizeRestV2MvpdMatchToken(candidateValue);
  const targetCompact = normalizeRestV2MvpdMatchToken(targetValue);
  let score = -1;

  if (candidateLower === targetLower) {
    score = Math.max(score, 180);
  }
  if (candidateCompact && targetCompact && candidateCompact === targetCompact) {
    score = Math.max(score, 165);
  }
  if (isRestV2MvpdMatch(candidateValue, targetValue, { allowSsoAlias: false })) {
    score = Math.max(score, 140);
  }
  if (allowSsoAlias && isRestV2MvpdMatch(candidateValue, targetValue, { allowSsoAlias: true })) {
    score = Math.max(score, 90);
  }
  if (score < 0) {
    return -1;
  }

  const candidateHasSso = restV2ValueHasSsoMarker(candidateValue);
  const targetHasSso = restV2ValueHasSsoMarker(targetValue);
  if (candidateHasSso === targetHasSso) {
    score += 12;
  } else if (targetHasSso && !candidateHasSso) {
    score -= 18;
  }
  return score;
}

function collectRestV2IdentityHintsFromHarvest(harvest = null) {
  if (!harvest || typeof harvest !== "object") {
    return {
      subjectHints: [],
      sessionHints: [],
    };
  }
  return {
    subjectHints: dedupeRestV2CandidateStrings([
      String(harvest?.subject || "").trim(),
      String(harvest?.upstreamUserId || "").trim(),
      String(harvest?.userId || "").trim(),
      ...(Array.isArray(harvest?.subjectCandidates) ? harvest.subjectCandidates : []),
      ...(Array.isArray(harvest?.allSubjectCandidates) ? harvest.allSubjectCandidates : []),
    ]),
    sessionHints: dedupeRestV2CandidateStrings([
      String(harvest?.sessionId || "").trim(),
      ...(Array.isArray(harvest?.sessionCandidates) ? harvest.sessionCandidates : []),
      ...(Array.isArray(harvest?.allSessionCandidates) ? harvest.allSessionCandidates : []),
    ]),
  };
}

function hasRestV2SummaryIdentityOverlap(summary = null, identityHints = null) {
  if (!summary || typeof summary !== "object" || !identityHints || typeof identityHints !== "object") {
    return false;
  }
  const subjectHintSet = new Set(
    (Array.isArray(identityHints.subjectHints) ? identityHints.subjectHints : [])
      .map((value) => String(value || "").trim().toLowerCase())
      .filter(Boolean)
  );
  const sessionHintSet = new Set(
    (Array.isArray(identityHints.sessionHints) ? identityHints.sessionHints : [])
      .map((value) => String(value || "").trim().toLowerCase())
      .filter(Boolean)
  );

  const subjectValues = dedupeRestV2CandidateStrings([
    String(summary?.subject || "").trim(),
    String(summary?.upstreamUserId || "").trim(),
    String(summary?.userId || "").trim(),
    ...(Array.isArray(summary?.subjectCandidates) ? summary.subjectCandidates : []),
  ]).map((value) => String(value || "").trim().toLowerCase());
  if (subjectValues.some((value) => value && subjectHintSet.has(value))) {
    return true;
  }

  const sessionValues = dedupeRestV2CandidateStrings([
    String(summary?.sessionId || "").trim(),
    ...(Array.isArray(summary?.sessionCandidates) ? summary.sessionCandidates : []),
  ]).map((value) => String(value || "").trim().toLowerCase());
  return sessionValues.some((value) => value && sessionHintSet.has(value));
}

function findRestV2PreferredProfileSummary(profileSummaries = [], preferredMvpd = "", options = {}) {
  const summaries = Array.isArray(profileSummaries) ? profileSummaries : [];
  if (summaries.length === 0) {
    return null;
  }

  const preferred = String(preferredMvpd || "").trim();
  const preferredAliases = dedupeRestV2CandidateStrings([
    preferred,
    ...(Array.isArray(options?.preferredAliases) ? options.preferredAliases : []),
  ]);
  if (preferredAliases.length === 0) {
    return summaries[0] || null;
  }

  const allowSsoAlias = options?.allowSsoAlias === true;
  const identityHints = options?.identityHints && typeof options.identityHints === "object" ? options.identityHints : null;
  let bestSummary = null;
  let bestScore = -1;
  let bestExpiry = 0;

  summaries.forEach((summary) => {
    const candidates = dedupeRestV2CandidateStrings([
      String(summary?.profileKey || "").trim(),
      String(summary?.mvpd || "").trim(),
      ...(Array.isArray(summary?.idpCandidates) ? summary.idpCandidates : []),
    ]);
    if (candidates.length === 0) {
      return;
    }
    const matchScore = candidates.reduce(
      (maxScore, candidate) =>
        Math.max(
          maxScore,
          ...preferredAliases.map((alias) =>
            scoreRestV2MvpdCandidateMatch(candidate, alias, {
              allowSsoAlias,
            })
          )
        ),
      -1
    );
    if (matchScore < 0) {
      return;
    }

    let score = matchScore;
    const summaryHasSso = candidates.some((candidate) => restV2ValueHasSsoMarker(candidate));
    const preferredHasSso = preferredAliases.some((alias) => restV2ValueHasSsoMarker(alias));
    if (summaryHasSso === preferredHasSso) {
      score += 8;
    } else if (preferredHasSso && !summaryHasSso) {
      score -= 12;
    }

    if (identityHints) {
      if (hasRestV2SummaryIdentityOverlap(summary, identityHints)) {
        score += 30;
      } else if (preferredHasSso && !summaryHasSso) {
        score -= 20;
      }
    }

    const expiryMs = Number(summary?.notAfterMs || 0);
    if (!bestSummary || score > bestScore || (score === bestScore && expiryMs > bestExpiry)) {
      bestSummary = summary;
      bestScore = score;
      bestExpiry = expiryMs;
    }
  });

  return bestSummary || summaries[0] || null;
}

function buildRestV2ProfileHarvest(context, profileCheckResult, flowId = "") {
  if (!context || !profileCheckResult || profileCheckResult.checked !== true) {
    return null;
  }

  const payload =
    profileCheckResult.responsePayload && typeof profileCheckResult.responsePayload === "object"
      ? profileCheckResult.responsePayload
      : {};
  const profiles =
    payload && typeof payload === "object" && payload.profiles && typeof payload.profiles === "object" ? payload.profiles : {};
  const profileEntries = Object.entries(profiles).filter(([, value]) => value && typeof value === "object");
  const profileSummaries = profileEntries.map(([profileKey, profileValue]) => getRestV2ProfileSummary(profileValue, profileKey, context));
  const previousHarvestCandidate = getRestV2ProfileHarvestForContext(context);
  const previousHarvest =
    previousHarvestCandidate &&
    isRestV2MvpdMatch(previousHarvestCandidate?.mvpd, context?.mvpd, {
      allowSsoAlias: false,
    })
      ? previousHarvestCandidate
      : null;
  const identityHints = collectRestV2IdentityHintsFromHarvest(previousHarvest);
  const cachedMvpdMeta =
    String(context?.requestorId || "").trim() && String(context?.mvpd || "").trim()
      ? getRequestorScopedMvpdCache(String(context.requestorId || "").trim())?.get(String(context.mvpd || "").trim()) || null
      : null;
  const likelySsoContext = isRestV2LikelyPartnerSsoContext(context);
  const preferredSummaryOptions = {
    allowSsoAlias: likelySsoContext,
    identityHints,
    preferredAliases: dedupeRestV2CandidateStrings([
      String(context?.mvpd || "").trim(),
      String(context?.mvpdMeta?.name || "").trim(),
      String(context?.mvpdMeta?.displayName || "").trim(),
      String(cachedMvpdMeta?.name || "").trim(),
      String(cachedMvpdMeta?.displayName || "").trim(),
    ]),
  };
  let selectedSummary = findRestV2PreferredProfileSummary(profileSummaries, context.mvpd, preferredSummaryOptions);
  if (likelySsoContext && selectedSummary && !restV2ProfileSummaryHasSsoMarker(selectedSummary)) {
    const explicitSsoSummaries = profileSummaries.filter((summary) => restV2ProfileSummaryHasSsoMarker(summary));
    if (explicitSsoSummaries.length > 0) {
      const explicitSsoSelection = findRestV2PreferredProfileSummary(
        explicitSsoSummaries,
        context.mvpd,
        preferredSummaryOptions
      );
      if (explicitSsoSelection) {
        selectedSummary = explicitSsoSelection;
      }
    }
  }

  const profileCount = profileSummaries.length;
  const profileKeys = profileSummaries.map((summary) => String(summary?.profileKey || "").trim()).filter(Boolean);
  const allSubjectCandidates = dedupeRestV2CandidateStrings(profileSummaries.flatMap((summary) => summary?.subjectCandidates || []));
  const allSessionCandidates = dedupeRestV2CandidateStrings(profileSummaries.flatMap((summary) => summary?.sessionCandidates || []));
  const allIdpCandidates = dedupeRestV2CandidateStrings(profileSummaries.flatMap((summary) => summary?.idpCandidates || []));

  const subjectCandidates = dedupeRestV2CandidateStrings([
    ...(selectedSummary?.subjectCandidates || []),
    ...(selectedSummary?.upstreamUserId ? [selectedSummary.upstreamUserId] : []),
    ...(selectedSummary?.userId ? [selectedSummary.userId] : []),
    ...(Array.isArray(identityHints?.subjectHints) ? identityHints.subjectHints : []),
  ]);
  const sessionCandidates = dedupeRestV2CandidateStrings([
    ...(selectedSummary?.sessionCandidates || []),
    ...(Array.isArray(identityHints?.sessionHints) ? identityHints.sessionHints : []),
  ]);
  const idpCandidates = dedupeRestV2CandidateStrings([
    ...(selectedSummary?.idpCandidates || []),
    ...(Array.isArray(previousHarvest?.idpCandidates) ? previousHarvest.idpCandidates : []),
    context.mvpd,
  ]);

  const upstreamUserId = firstNonEmptyString([selectedSummary?.upstreamUserId, selectedSummary?.userId, ...subjectCandidates]);
  const userId = firstNonEmptyString([selectedSummary?.userId, selectedSummary?.upstreamUserId, ...subjectCandidates]);
  const sessionId = firstNonEmptyString([selectedSummary?.sessionId, ...sessionCandidates]);
  const mvpd = firstNonEmptyString([context.mvpd, selectedSummary?.mvpd, ...idpCandidates]);
  const profileMvpd = String(selectedSummary?.mvpd || "").trim();
  const decisionMvpd = firstNonEmptyString([
    likelySsoContext && profileMvpd && !restV2ValueHasSsoMarker(profileMvpd) ? profileMvpd : "",
    ...idpCandidates.filter((candidate) => !restV2ValueHasSsoMarker(candidate)),
    profileMvpd,
    String(context?.mvpd || "").trim(),
  ]);
  const cachedMvpdName =
    String(context?.requestorId || "").trim() && String(mvpd || "").trim()
      ? String(
          getRequestorScopedMvpdCache(String(context.requestorId || "").trim())?.get(String(mvpd || "").trim())?.name || ""
        ).trim()
      : "";
  const mvpdName = firstNonEmptyString([
    String(context?.mvpdMeta?.name || "").trim(),
    cachedMvpdName,
    String(selectedSummary?.scalarFields?.displayName || "").trim(),
    String(selectedSummary?.scalarFields?.providerName || "").trim(),
  ]);
  const subject = firstNonEmptyString([selectedSummary?.subject, selectedSummary?.upstreamUserId, selectedSummary?.userId, ...subjectCandidates]);

  const notBeforeMs = Number(selectedSummary?.notBeforeMs || 0);
  const notAfterMs = Number(selectedSummary?.notAfterMs || 0);
  const harvestedAt = Date.now();
  const responseStatus = Number(profileCheckResult.status || 0);
  const responseOk = profileCheckResult.ok === true;
  const responseError = String(profileCheckResult.error || "").trim();
  const profileCheckOutcome = responseError
    ? "error"
    : !responseOk
      ? "http_error"
      : profileCount > 0
        ? "success"
        : "empty";
  const contextServiceProviderId = String(context?.serviceProviderId || context?.requestorId || "").trim();
  const sessionUrl = normalizeAdobeNavigationUrl(String(context?.sessionUrl || "").trim());
  const loginUrl = normalizeAdobeNavigationUrl(String(context?.loginUrl || "").trim());
  const sessionCodeCandidates = collectRestV2SessionCodeCandidates(
    [
      context?.sessionCode,
      ...(Array.isArray(context?.sessionCodeCandidates) ? context.sessionCodeCandidates : []),
      sessionUrl,
      loginUrl,
    ],
    contextServiceProviderId
  );
  const sessionCode = firstNonEmptyString([String(context?.sessionCode || "").trim(), sessionCodeCandidates[0]]);

  return {
    harvestedAt,
    flowId: String(flowId || "").trim(),
    programmerId: String(context.programmerId || "").trim(),
    requestorId: String(context.requestorId || "").trim(),
    serviceProviderId: String(context.serviceProviderId || "").trim(),
    appGuid: String(context.appInfo?.guid || "").trim(),
    appName: String(context.appInfo?.appName || context.appInfo?.guid || "").trim(),
    sessionCode,
    sessionCodeCandidates,
    sessionAction: String(context?.sessionAction || "").trim(),
    sessionPartner: String(context?.sessionPartner || "").trim(),
    partnerFrameworkStatus: String(resolveRestV2PartnerFrameworkStatusFromContext(context) || "").trim(),
    sessionUrl,
    loginUrl,
    profileUrl: String(profileCheckResult.url || "").trim(),
    profileCheckOutcome,
    profileCheck: {
      checked: profileCheckResult.checked === true,
      ok: responseOk,
      status: responseStatus,
      statusText: String(profileCheckResult.statusText || "").trim(),
      error: responseError,
      profileCount,
      url: String(profileCheckResult.url || "").trim(),
      responsePreview: String(profileCheckResult.responsePreview || "").trim(),
    },
    profileCount,
    profileKeys,
    selectedProfileFound: Boolean(selectedSummary),
    profileKey: String(selectedSummary?.profileKey || "").trim(),
    selectedMvpd: String(context?.mvpd || "").trim(),
    mvpd: String(mvpd || "").trim(),
    profileMvpd: String(profileMvpd || "").trim(),
    decisionMvpd: String(decisionMvpd || "").trim(),
    mvpdName: String(mvpdName || "").trim(),
    subject: String(subject || "").trim(),
    upstreamUserId: String(upstreamUserId || "").trim(),
    userId: String(userId || "").trim(),
    sessionId: String(sessionId || "").trim(),
    idpCandidates,
    subjectCandidates,
    sessionCandidates,
    allSubjectCandidates,
    allSessionCandidates,
    allIdpCandidates,
    notBeforeMs: Number.isFinite(notBeforeMs) && notBeforeMs > 0 ? notBeforeMs : 0,
    notAfterMs: Number.isFinite(notAfterMs) && notAfterMs > 0 ? notAfterMs : 0,
    profileAttributes: selectedSummary?.attributes && typeof selectedSummary.attributes === "object" ? { ...selectedSummary.attributes } : {},
    profileScalarFields:
      selectedSummary?.scalarFields && typeof selectedSummary.scalarFields === "object" ? { ...selectedSummary.scalarFields } : {},
    profile: selectedSummary?.rawProfile && typeof selectedSummary.rawProfile === "object" ? { ...selectedSummary.rawProfile } : {},
    preauthzChecks: [],
    profileSummaries: cloneJsonLikeValue(profileSummaries, []),
    profileResponsePayload: cloneJsonLikeValue(payload, {}),
  };
}

function storeRestV2ProfileHarvest(context, profileCheckResult, flowId = "") {
  const harvest = buildRestV2ProfileHarvest(context, profileCheckResult, flowId);
  if (!harvest) {
    return null;
  }

  let mergedHarvest = mergeRestV2HarvestWithPreauthzChecks(harvest);
  const selectionKey = buildRestV2ProfileHarvestSelectionKey(context);
  const selectionHarvest =
    selectionKey && selectionKey !== "||" && state.restV2ProfileHarvestBySelectionKey.has(selectionKey)
      ? state.restV2ProfileHarvestBySelectionKey.get(selectionKey) || null
      : null;
  if (selectionHarvest && typeof selectionHarvest === "object") {
    mergedHarvest = mergeRestV2HarvestWithPreauthzChecks(mergedHarvest, selectionHarvest);
  }
  if (mergedHarvest?.programmerId) {
    const bucketKey = buildRestV2ProfileHarvestBucketKey(mergedHarvest);
    if (bucketKey) {
      const existingBucket = getRestV2ProfileHarvestBucketForProgrammer(mergedHarvest.programmerId);
      const existingBucketMatch =
        existingBucket.find((item) => buildRestV2ProfileHarvestBucketKey(item) === bucketKey) || null;
      if (existingBucketMatch) {
        mergedHarvest = mergeRestV2HarvestWithPreauthzChecks(mergedHarvest, existingBucketMatch);
      }
    }
  }

  if (selectionKey && selectionKey !== "||") {
    state.restV2ProfileHarvestBySelectionKey.set(selectionKey, mergedHarvest);
  }
  if (isUsableRestV2ProfileHarvest(mergedHarvest)) {
    upsertRestV2ProfileHarvestBucketEntry(mergedHarvest);
    if (mergedHarvest.programmerId) {
      const existingBucket = getRestV2ProfileHarvestBucketForProgrammer(mergedHarvest.programmerId);
      state.restV2ProfileHarvestByProgrammerId.set(mergedHarvest.programmerId, existingBucket[0] || mergedHarvest);
    }
  } else if (mergedHarvest.programmerId) {
    const existingBucket = getRestV2ProfileHarvestBucketForProgrammer(mergedHarvest.programmerId);
    if (existingBucket.length > 0) {
      state.restV2ProfileHarvestByProgrammerId.set(mergedHarvest.programmerId, existingBucket[0]);
    }
  }
  state.restV2ProfileHarvestLast = mergedHarvest;
  return mergedHarvest;
}

function isUsableRestV2ProfileHarvest(harvest = null) {
  if (!harvest || typeof harvest !== "object") {
    return false;
  }
  if (String(harvest.profileCheckOutcome || "").trim().toLowerCase() !== "success") {
    return false;
  }
  return Number(harvest.profileCount || 0) > 0;
}

function buildRestV2ProfileHarvestBucketKey(harvest = null) {
  if (!harvest || typeof harvest !== "object") {
    return "";
  }
  const parts = [
    harvest.programmerId,
    harvest.requestorId,
    harvest.mvpd,
    harvest.profileKey,
    harvest.subject,
    harvest.sessionId,
    harvest.upstreamUserId,
    harvest.userId,
  ]
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
  return parts.join("|");
}

function compareRestV2HarvestRecency(left, right) {
  return Number(right?.harvestedAt || 0) - Number(left?.harvestedAt || 0);
}

function getLatestRestV2ProfileHarvestFromBuckets() {
  let latest = null;
  for (const bucket of state.restV2ProfileHarvestBucketByProgrammerId.values()) {
    for (const harvest of Array.isArray(bucket) ? bucket : []) {
      if (!harvest || typeof harvest !== "object") {
        continue;
      }
      if (!latest || Number(harvest.harvestedAt || 0) > Number(latest.harvestedAt || 0)) {
        latest = harvest;
      }
    }
  }
  return latest;
}

function getLatestRestV2ProfileHarvestFromSelectionMap() {
  let latest = null;
  for (const harvest of state.restV2ProfileHarvestBySelectionKey.values()) {
    if (!harvest || typeof harvest !== "object") {
      continue;
    }
    if (!latest || Number(harvest.harvestedAt || 0) > Number(latest.harvestedAt || 0)) {
      latest = harvest;
    }
  }
  return latest;
}

function recomputeRestV2ProfileHarvestLast() {
  const latestFromBuckets = getLatestRestV2ProfileHarvestFromBuckets();
  if (latestFromBuckets) {
    state.restV2ProfileHarvestLast = latestFromBuckets;
    return latestFromBuckets;
  }
  const latestFromSelections = getLatestRestV2ProfileHarvestFromSelectionMap();
  state.restV2ProfileHarvestLast = latestFromSelections || null;
  return state.restV2ProfileHarvestLast;
}

function removeRestV2ProfileHarvestByRecordKey(programmer = null, harvestKey = "") {
  const programmerId =
    programmer && typeof programmer === "object" ? String(programmer.programmerId || "").trim() : String(programmer || "").trim();
  const normalizedHarvestKey = String(harvestKey || "").trim();
  if (!programmerId || !normalizedHarvestKey) {
    return false;
  }

  const bucket = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
  const filteredBucket = bucket.filter((item, index) => getRestV2HarvestRecordKey(item, index) !== normalizedHarvestKey);
  const removed = filteredBucket.length !== bucket.length;
  if (!removed) {
    return false;
  }

  if (filteredBucket.length > 0) {
    filteredBucket.sort(compareRestV2HarvestRecency);
    state.restV2ProfileHarvestBucketByProgrammerId.set(programmerId, filteredBucket);
    state.restV2ProfileHarvestByProgrammerId.set(programmerId, filteredBucket[0]);
  } else {
    state.restV2ProfileHarvestBucketByProgrammerId.delete(programmerId);
    state.restV2ProfileHarvestByProgrammerId.delete(programmerId);
  }

  for (const [selectionKey, harvest] of state.restV2ProfileHarvestBySelectionKey.entries()) {
    if (!harvest || typeof harvest !== "object") {
      continue;
    }
    if (getRestV2HarvestRecordKey(harvest) === normalizedHarvestKey) {
      state.restV2ProfileHarvestBySelectionKey.delete(selectionKey);
    }
  }

  if (state.restV2PreauthorizeHistoryByProgrammerId.has(programmerId)) {
    const history = getRestV2PreauthorizeHistoryForProgrammer(programmerId);
    const filteredHistory = history.filter((entry) => String(entry?.harvestKey || "").trim() !== normalizedHarvestKey);
    if (filteredHistory.length > 0) {
      state.restV2PreauthorizeHistoryByProgrammerId.set(programmerId, filteredHistory);
    } else {
      state.restV2PreauthorizeHistoryByProgrammerId.delete(programmerId);
    }
  }

  recomputeRestV2ProfileHarvestLast();
  return true;
}

async function deleteRestV2ProfileHarvestWithLogout(programmer = null, harvestKey = "", options = {}) {
  const programmerId =
    programmer && typeof programmer === "object" ? String(programmer.programmerId || "").trim() : String(programmer || "").trim();
  const normalizedHarvestKey = String(harvestKey || "").trim();
  if (!programmerId || !normalizedHarvestKey) {
    return {
      ok: false,
      error: "Missing MVPD profile key.",
    };
  }

  const harvest = getRestV2HarvestByRecordKey(normalizedHarvestKey, programmerId);
  if (!harvest) {
    return {
      ok: false,
      error: "Selected MVPD profile was not found.",
    };
  }

  const context = buildRestV2ContextFromHarvest(harvest);
  if (!context?.ok) {
    return {
      ok: false,
      error: "Selected MVPD profile is missing REST V2 logout context. Re-run LOGIN and retry.",
    };
  }
  const requestorMvpdLabel = formatRestV2RequestorMvpdDisplay(context.requestorId, context.mvpd, context.mvpdMeta, {
    separator: " x ",
  });
  const flowId = String(options?.flowId || "").trim() || resolveRestV2DebugFlowIdForHarvest(harvest);
  const warnings = [];
  const logoutResult = await executeRestV2LogoutFlow(context, flowId, {
    skipUserAgentAction: true,
  });
  if (logoutResult?.attempted !== true) {
    const reason = firstNonEmptyString([
      String(logoutResult?.error || "").trim(),
      "REST V2 logout was not attempted.",
    ]);
    return {
      ok: false,
      error: `${requestorMvpdLabel} logout failed: ${reason}`,
      context,
      harvest,
      flowId,
      logoutResult,
    };
  }

  const verifyResult = await verifyPostLogoutProfilesCleared(context, flowId);
  if (verifyResult?.ok !== true) {
    warnings.push(
      firstNonEmptyString([
        String(verifyResult?.error || "").trim(),
        `${Number(verifyResult?.profileCount || 0)} active profile(s) still returned`,
      ]) || "profile state not yet fully cleared"
    );
  }

  clearRestV2ProfileHarvestForContext(context);
  const removedByKey = removeRestV2ProfileHarvestByRecordKey(programmerId, normalizedHarvestKey);
  state.bobtoolsWorkspaceLastResultByHarvestKey.delete(normalizedHarvestKey);

  const hydration = await ensureRestV2ProfilesHydratedForBobtools(context, {
    force: true,
    source: String(options?.source || "profile-delete-logout").trim() || "profile-delete-logout",
  });
  const hydrationOk = hydration?.ok === true || hydration?.skipped === true;
  if (!hydrationOk) {
    warnings.push(
      firstNonEmptyString([
        String(hydration?.error || "").trim(),
        "Profiles (all MVPD) refresh did not confirm state",
      ]) || "profile refresh did not confirm state"
    );
  }

  const refreshedBucket = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
  const remainingHarvest = findRestV2HarvestByRequestorAndMvpd(refreshedBucket, context.requestorId, context.mvpd, {
    allowSsoAlias: isRestV2LikelyPartnerSsoContext(context),
  });
  const removed = removedByKey || !getRestV2HarvestByRecordKey(normalizedHarvestKey, programmerId);
  if (isUsableRestV2ProfileHarvest(remainingHarvest)) {
    warnings.push("profile is still active upstream and remains available");
  }

  const summaryMessage = warnings.length
    ? `Requested logout for ${requestorMvpdLabel}; refreshed profile list (${warnings[0]}).`
    : `Removed ${requestorMvpdLabel} MVPD profile after REST V2 logout and profile refresh.`;
  return {
    ok: true,
    removed,
    warning: warnings.length > 0,
    warningMessage: warnings.join(" | "),
    message: summaryMessage,
    context,
    harvest,
    flowId,
    logoutResult,
    verifyResult,
    hydration,
    remainingHarvest,
  };
}

function upsertRestV2ProfileHarvestBucketEntry(harvest = null) {
  if (!isUsableRestV2ProfileHarvest(harvest)) {
    return;
  }
  const normalizedHarvest = mergeRestV2HarvestWithPreauthzChecks(harvest);
  const programmerId = String(normalizedHarvest?.programmerId || "").trim();
  if (!programmerId) {
    return;
  }

  const existingBucket = Array.isArray(state.restV2ProfileHarvestBucketByProgrammerId.get(programmerId))
    ? state.restV2ProfileHarvestBucketByProgrammerId.get(programmerId)
    : [];
  const harvestKey = buildRestV2ProfileHarvestBucketKey(normalizedHarvest);
  const nextBucket = existingBucket.slice();
  const existingIndex = harvestKey
    ? nextBucket.findIndex((item) => buildRestV2ProfileHarvestBucketKey(item) === harvestKey)
    : -1;
  if (existingIndex >= 0) {
    nextBucket[existingIndex] = mergeRestV2HarvestWithPreauthzChecks(normalizedHarvest, nextBucket[existingIndex]);
  } else {
    nextBucket.push(normalizedHarvest);
  }
  nextBucket.sort(compareRestV2HarvestRecency);
  state.restV2ProfileHarvestBucketByProgrammerId.set(programmerId, nextBucket.slice(0, REST_V2_PROFILE_HARVEST_BUCKET_MAX));
}

function getRestV2ProfileHarvestBucketForProgrammer(programmer = null) {
  const programmerId =
    programmer && typeof programmer === "object" ? String(programmer.programmerId || "").trim() : String(programmer || "").trim();
  if (!programmerId) {
    return [];
  }
  const bucket = state.restV2ProfileHarvestBucketByProgrammerId.get(programmerId);
  if (!Array.isArray(bucket) || bucket.length === 0) {
    return [];
  }
  return bucket
    .filter((item) => item && typeof item === "object")
    .slice()
    .sort(compareRestV2HarvestRecency);
}

function getRestV2ProfileHarvestListForContext(context = null) {
  if (context && typeof context === "object") {
    const programmerId = String(context.programmerId || "").trim();
    if (programmerId) {
      const bucket = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
      if (bucket.length > 0) {
        return bucket;
      }
      const selectionKey = buildRestV2ProfileHarvestSelectionKey(context);
      const selectionHarvest =
        selectionKey && state.restV2ProfileHarvestBySelectionKey.has(selectionKey)
          ? state.restV2ProfileHarvestBySelectionKey.get(selectionKey) || null
          : null;
      return selectionHarvest && typeof selectionHarvest === "object" ? [selectionHarvest] : [];
    }
  }

  const latest = getLatestRestV2ProfileHarvestFromBuckets();
  if (latest) {
    return [latest];
  }

  return state.restV2ProfileHarvestLast && typeof state.restV2ProfileHarvestLast === "object"
    ? [state.restV2ProfileHarvestLast]
    : [];
}

function mergeRestV2ProfileHarvestLists(...lists) {
  const merged = [];
  const keyToIndex = new Map();
  lists.forEach((list) => {
    (Array.isArray(list) ? list : []).forEach((item) => {
      if (!item || typeof item !== "object") {
        return;
      }
      const bucketKey =
        buildRestV2ProfileHarvestBucketKey(item) ||
        [String(item.programmerId || ""), String(item.flowId || ""), String(item.harvestedAt || "")].join("|");
      const existingIndex = keyToIndex.has(bucketKey) ? Number(keyToIndex.get(bucketKey)) : -1;
      if (existingIndex >= 0) {
        const existing = merged[existingIndex];
        const preferred = Number(item.harvestedAt || 0) >= Number(existing?.harvestedAt || 0) ? item : existing;
        merged[existingIndex] = mergeRestV2HarvestWithPreauthzChecks(preferred, existing, item);
      } else {
        keyToIndex.set(bucketKey, merged.length);
        merged.push(mergeRestV2HarvestWithPreauthzChecks(item));
      }
    });
  });
  merged.sort(compareRestV2HarvestRecency);
  return merged;
}

function collectRestV2HarvestCandidateValues(harvestList = []) {
  const list = Array.isArray(harvestList) ? harvestList : [];
  const idpCandidates = dedupeRestV2CandidateStrings(
    list.flatMap((harvest) => [
      String(harvest?.mvpd || "").trim(),
      ...(Array.isArray(harvest?.idpCandidates) ? harvest.idpCandidates : []),
      ...(Array.isArray(harvest?.allIdpCandidates) ? harvest.allIdpCandidates : []),
    ])
  );
  const subjectCandidates = dedupeRestV2CandidateStrings(
    list.flatMap((harvest) => [
      String(harvest?.subject || "").trim(),
      String(harvest?.upstreamUserId || "").trim(),
      String(harvest?.userId || "").trim(),
      ...(Array.isArray(harvest?.subjectCandidates) ? harvest.subjectCandidates : []),
      ...(Array.isArray(harvest?.allSubjectCandidates) ? harvest.allSubjectCandidates : []),
    ])
  );
  const sessionCandidates = dedupeRestV2CandidateStrings(
    list.flatMap((harvest) => [
      String(harvest?.sessionId || "").trim(),
      ...(Array.isArray(harvest?.sessionCandidates) ? harvest.sessionCandidates : []),
      ...(Array.isArray(harvest?.allSessionCandidates) ? harvest.allSessionCandidates : []),
    ])
  );
  return {
    idpCandidates,
    subjectCandidates,
    sessionCandidates,
  };
}

function clearRestV2ProfileHarvestForContext(context = null) {
  if (!context || typeof context !== "object") {
    return;
  }
  const selectionKey = buildRestV2ProfileHarvestSelectionKey(context);
  if (selectionKey && state.restV2ProfileHarvestBySelectionKey.has(selectionKey)) {
    state.restV2ProfileHarvestBySelectionKey.delete(selectionKey);
  }
  const programmerId = String(context.programmerId || "").trim();
  if (!programmerId) {
    return;
  }

  const normalizedRequestorId = String(context.requestorId || "").trim().toLowerCase();
  const normalizedMvpd = String(context.mvpd || "").trim().toLowerCase();
  const existingBucket = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
  if (existingBucket.length > 0) {
    const filteredBucket = existingBucket.filter((harvest) => {
      const harvestRequestorId = String(harvest?.requestorId || "").trim().toLowerCase();
      const harvestMvpd = String(harvest?.mvpd || "").trim().toLowerCase();
      const matchesRequestor = normalizedRequestorId ? harvestRequestorId === normalizedRequestorId : true;
      const matchesMvpd = normalizedMvpd ? harvestMvpd === normalizedMvpd : true;
      return !(matchesRequestor && matchesMvpd);
    });

    if (filteredBucket.length > 0) {
      state.restV2ProfileHarvestBucketByProgrammerId.set(programmerId, filteredBucket);
      state.restV2ProfileHarvestByProgrammerId.set(programmerId, filteredBucket[0]);
    } else {
      state.restV2ProfileHarvestBucketByProgrammerId.delete(programmerId);
      state.restV2ProfileHarvestByProgrammerId.delete(programmerId);
    }
  } else {
    state.restV2ProfileHarvestByProgrammerId.delete(programmerId);
  }

  recomputeRestV2ProfileHarvestLast();
}

function getRestV2ProfileHarvestForContext(context = null) {
  if (context && typeof context === "object") {
    const selectionKey = buildRestV2ProfileHarvestSelectionKey(context);
    const selectionHarvest =
      selectionKey && state.restV2ProfileHarvestBySelectionKey.has(selectionKey)
        ? state.restV2ProfileHarvestBySelectionKey.get(selectionKey) || null
        : null;
    if (isUsableRestV2ProfileHarvest(selectionHarvest)) {
      return selectionHarvest;
    }

    const programmerId = String(context.programmerId || "").trim();
    if (programmerId) {
      const bucket = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
      if (bucket.length > 0) {
        const normalizedRequestorId = String(context.requestorId || "").trim().toLowerCase();
        const normalizedMvpd = String(context.mvpd || "").trim().toLowerCase();
        const strictMatch = bucket.find((harvest) => {
          const harvestRequestorId = String(harvest?.requestorId || "").trim().toLowerCase();
          const harvestMvpd = String(harvest?.mvpd || "").trim().toLowerCase();
          const requestorMatch = normalizedRequestorId ? harvestRequestorId === normalizedRequestorId : true;
          const mvpdMatch = normalizedMvpd ? harvestMvpd === normalizedMvpd : true;
          return requestorMatch && mvpdMatch;
        });
        if (strictMatch) {
          return strictMatch;
        }

        if (normalizedMvpd) {
          const mvpdMatch = bucket.find(
            (harvest) => String(harvest?.mvpd || "").trim().toLowerCase() === normalizedMvpd
          );
          if (mvpdMatch) {
            return mvpdMatch;
          }
        }

        if (normalizedRequestorId) {
          const requestorMatch = bucket.find(
            (harvest) => String(harvest?.requestorId || "").trim().toLowerCase() === normalizedRequestorId
          );
          if (requestorMatch) {
            return requestorMatch;
          }
        }

        return bucket[0];
      }
    }

    if (selectionHarvest && typeof selectionHarvest === "object") {
      return selectionHarvest;
    }

    if (selectionKey && state.restV2ProfileHarvestBySelectionKey.has(selectionKey)) {
      return state.restV2ProfileHarvestBySelectionKey.get(selectionKey) || null;
    }
    if (programmerId && state.restV2ProfileHarvestByProgrammerId.has(programmerId)) {
      return state.restV2ProfileHarvestByProgrammerId.get(programmerId) || null;
    }
  }

  if (isUsableRestV2ProfileHarvest(state.restV2ProfileHarvestLast)) {
    return state.restV2ProfileHarvestLast;
  }

  const latestFromBuckets = getLatestRestV2ProfileHarvestFromBuckets();
  if (latestFromBuckets) {
    return latestFromBuckets;
  }

  return state.restV2ProfileHarvestLast && typeof state.restV2ProfileHarvestLast === "object" ? state.restV2ProfileHarvestLast : null;
}

function resolveRestV2PartnerSsoFlowCacheKey(context = null, flowId = "") {
  const normalizedFlowId = String(flowId || "").trim();
  if (normalizedFlowId) {
    return `flow:${normalizedFlowId}`;
  }
  const programmerId = String(context?.programmerId || "").trim().toLowerCase();
  const requestorId = String(context?.requestorId || "").trim().toLowerCase();
  const mvpd = String(context?.mvpd || "").trim().toLowerCase();
  const sessionCode = String(context?.sessionCode || "").trim().toLowerCase();
  return `context:${programmerId}|${requestorId}|${mvpd}|${sessionCode}`;
}

function getRestV2PartnerSsoCreateResultForFlow(context = null, flowId = "") {
  const key = resolveRestV2PartnerSsoFlowCacheKey(context, flowId);
  if (!key) {
    return null;
  }
  return state.restV2PartnerSsoCreateResultByFlowKey.get(key) || null;
}

function setRestV2PartnerSsoCreateResultForFlow(context = null, flowId = "", result = null) {
  const key = resolveRestV2PartnerSsoFlowCacheKey(context, flowId);
  if (!key || !result || typeof result !== "object") {
    return;
  }
  state.restV2PartnerSsoCreateResultByFlowKey.set(key, {
    ...result,
  });
  const maxEntries = 120;
  while (state.restV2PartnerSsoCreateResultByFlowKey.size > maxEntries) {
    const firstKey = state.restV2PartnerSsoCreateResultByFlowKey.keys().next().value;
    if (!firstKey) {
      break;
    }
    state.restV2PartnerSsoCreateResultByFlowKey.delete(firstKey);
  }
}

function decodeBase64TextSafe(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  const normalized = raw
    .replace(/[\r\n]/g, "")
    .replace(/\s+/g, "")
    .replace(/-/g, "+")
    .replace(/_/g, "/");
  if (!normalized || /[^A-Za-z0-9+/=]/.test(normalized)) {
    return "";
  }
  const padded = normalized + "=".repeat((4 - (normalized.length % 4 || 4)) % 4);
  try {
    return atob(padded);
  } catch {
    return "";
  }
}

function decodeSimpleHtmlEntities(value = "") {
  return String(value || "")
    .replace(/&quot;/gi, '"')
    .replace(/&#34;/g, '"')
    .replace(/&apos;/gi, "'")
    .replace(/&#39;/g, "'")
    .replace(/&#x2b;/gi, "+")
    .replace(/&#43;/g, "+")
    .replace(/&amp;/gi, "&");
}

function normalizeRestV2SamlResponseForPartnerProfile(value = "") {
  const raw = decodeSimpleHtmlEntities(String(value || "").trim());
  if (!raw) {
    return "";
  }
  if (/<\s*(?:\?xml|saml|soap|[A-Za-z0-9_.:-]+:Envelope)/i.test(raw)) {
    return base64EncodeUtf8(raw);
  }

  const candidateValues = dedupeRestV2CandidateStrings([
    raw,
    raw.replace(/\s+/g, "+"),
    decodeURIComponentSafe(raw),
    decodeURIComponentSafe(raw).replace(/\s+/g, "+"),
  ]);

  for (const candidate of candidateValues) {
    const normalized = String(candidate || "").trim().replace(/[\r\n]+/g, "").replace(/\s+/g, "+");
    if (!normalized) {
      continue;
    }
    const decoded = decodeBase64TextSafe(normalized);
    if (decoded && /<\s*(?:\?xml|saml|soap|[A-Za-z0-9_.:-]+:Envelope)/i.test(decoded)) {
      return normalized;
    }
  }

  return "";
}

function extractRestV2SamlResponseFromText(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  if (/<\s*(?:\?xml|saml|soap|[A-Za-z0-9_.:-]+:Envelope)/i.test(raw)) {
    return raw;
  }
  const patterns = [
    /(?:^|[?&])SAMLResponse=([^&#]+)/i,
    /name=["']SAMLResponse["'][^>]*value=["']([^"']+)["']/i,
    /value=["']([^"']+)["'][^>]*name=["']SAMLResponse["']/i,
    /["']SAMLResponse["']\s*[:=]\s*["']([^"']+)["']/i,
  ];
  for (const pattern of patterns) {
    const match = raw.match(pattern);
    if (match?.[1]) {
      return decodeSimpleHtmlEntities(String(match[1] || "").trim());
    }
  }
  return "";
}

function extractRestV2SamlResponseFromWebRequestEvent(event = null) {
  const formData = event?.requestBody?.formData;
  if (!formData || typeof formData !== "object") {
    return "";
  }
  const samlValues =
    formData.SAMLResponse ||
    formData.samlResponse ||
    formData.samlresponse ||
    getRestV2CaseInsensitiveObjectValue(formData, ["SAMLResponse"]);
  if (Array.isArray(samlValues)) {
    return String(samlValues[0] || "").trim();
  }
  return String(samlValues || "").trim();
}

function extractRestV2SamlResponseFromDebugFlow(flow = null) {
  const events = Array.isArray(flow?.events) ? flow.events : [];
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const event = events[index];
    if (!event || typeof event !== "object") {
      continue;
    }
    if (event.source === "tab-network" && String(event.phase || "").trim() === "body") {
      const extracted = extractRestV2SamlResponseFromText(String(event.bodyPreview || "").trim());
      const normalizedSaml = normalizeRestV2SamlResponseForPartnerProfile(extracted);
      if (normalizedSaml) {
        return {
          samlResponse: normalizedSaml,
          source: "tab-network:body",
        };
      }
    }
  }
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const event = events[index];
    if (!event || typeof event !== "object") {
      continue;
    }
    if (event.source === "web-request" && String(event.phase || "").trim() === "onBeforeRequest") {
      const rawSaml = extractRestV2SamlResponseFromWebRequestEvent(event);
      const normalizedSaml = normalizeRestV2SamlResponseForPartnerProfile(rawSaml);
      if (normalizedSaml) {
        return {
          samlResponse: normalizedSaml,
          source: "web-request:onBeforeRequest",
        };
      }
    }
  }
  return {
    samlResponse: "",
    source: "",
  };
}

async function createRestV2PartnerSsoProfileForFlow(context = null, flowId = "", options = {}) {
  const normalizedFlowId = String(flowId || "").trim();
  const cached = getRestV2PartnerSsoCreateResultForFlow(context, normalizedFlowId);
  if (cached && cached.attempted === true) {
    return cached;
  }

  const result = {
    attempted: false,
    created: false,
    ok: false,
    status: 0,
    statusText: "",
    profileCount: 0,
    partner: "",
    frameworkStatusPresent: false,
    endpointUrl: "",
    error: "",
    samlSource: "",
  };

  if (!context?.programmerId || !context?.appInfo?.guid || !context?.serviceProviderId || !context?.mvpd) {
    result.error = "Missing REST V2 context for partner SSO profile creation.";
    return result;
  }
  if (!isRestV2LikelyPartnerSsoContext(context)) {
    result.error = "Selection is not a partner SSO context.";
    return result;
  }

  const partnerFrameworkStatus = resolveRestV2PartnerFrameworkStatusFromContext(context);
  result.frameworkStatusPresent = Boolean(partnerFrameworkStatus);
  if (!partnerFrameworkStatus) {
    result.error = "Missing AP-Partner-Framework-Status from REST session response.";
    setRestV2PartnerSsoCreateResultForFlow(context, normalizedFlowId, result);
    return result;
  }
  const resolvedPartner = String(resolveRestV2PartnerNameFromContext(context) || "").trim();
  const fallbackPartner = isRestV2LikelyPartnerSsoContext(context) ? "Apple" : "";
  const partner = firstNonEmptyString([resolvedPartner, fallbackPartner]);
  result.partner = /^(?:ios|tvos)$/i.test(String(partner || "").trim()) ? "Apple" : String(partner || "").trim();
  if (!result.partner) {
    result.error = "Missing partner for SSO profile creation.";
    setRestV2PartnerSsoCreateResultForFlow(context, normalizedFlowId, result);
    return result;
  }

  const maxSamlCaptureAttempts = Math.max(1, Number(options?.maxSamlCaptureAttempts || 4));
  const samlCaptureDelayMs = Math.max(0, Number(options?.samlCaptureDelayMs || 250));
  let samlDetails = {
    samlResponse: "",
    source: "",
  };
  for (let attempt = 1; attempt <= maxSamlCaptureAttempts; attempt += 1) {
    const flowSnapshot =
      attempt === 1 && options?.flowSnapshot && typeof options.flowSnapshot === "object"
        ? options.flowSnapshot
        : await getRestV2DebugFlowSnapshot(normalizedFlowId);
    samlDetails = extractRestV2SamlResponseFromDebugFlow(flowSnapshot);
    if (String(samlDetails?.samlResponse || "").trim()) {
      break;
    }
    if (attempt < maxSamlCaptureAttempts && samlCaptureDelayMs > 0) {
      await waitForDelay(samlCaptureDelayMs);
    }
  }
  const samlResponse = String(samlDetails?.samlResponse || "").trim();
  result.samlSource = String(samlDetails?.source || "").trim();
  if (!samlResponse) {
    result.error = "SAMLResponse was not captured from response body/request body.";
    setRestV2PartnerSsoCreateResultForFlow(context, normalizedFlowId, result);
    return result;
  }

  const endpointUrl = `${REST_V2_BASE}/${encodeURIComponent(context.serviceProviderId)}/profiles/sso/${encodeURIComponent(result.partner)}`;
  result.endpointUrl = endpointUrl;
  result.attempted = true;
  emitRestV2DebugEvent(normalizedFlowId, {
    source: "extension",
    phase: "profiles-sso-create-request",
    requestorId: String(context.requestorId || ""),
    mvpd: String(context.mvpd || ""),
    partner: String(result.partner || ""),
    endpointUrl,
    frameworkStatusPresent: true,
    samlSource: result.samlSource,
  });

  const requestHeaders = buildRestV2Headers(context.serviceProviderId, {
    Accept: "application/json",
    "Content-Type": "application/x-www-form-urlencoded",
    "AP-Partner-Framework-Status": partnerFrameworkStatus,
  });
  const requestBody = new URLSearchParams();
  requestBody.set("SAMLResponse", samlResponse);

  try {
    const response = await fetchWithPremiumAuth(
      context.programmerId,
      context.appInfo,
      endpointUrl,
      {
        method: "POST",
        mode: "cors",
        headers: requestHeaders,
        body: requestBody.toString(),
      },
      "refresh",
      {
        flowId: normalizedFlowId,
        requestorId: String(context.requestorId || ""),
        mvpd: String(context.mvpd || ""),
        scope: "profiles-sso-create",
        service: "rest-v2-profiles-sso",
        endpointUrl,
      }
    );
    const responseText = await response.text().catch(() => "");
    const parsed = parseJsonText(responseText, {});
    const profileCount = Number(Object.keys(parsed?.profiles && typeof parsed.profiles === "object" ? parsed.profiles : {}).length || 0);
    result.status = Number(response.status || 0);
    result.statusText = String(response.statusText || "").trim();
    result.profileCount = profileCount;
    result.ok = response.ok === true;
    result.created = response.ok === true;
    if (!result.ok) {
      result.error =
        firstNonEmptyString([
          String(parsed?.code || "").trim(),
          String(parsed?.error?.code || "").trim(),
          String(parsed?.error || "").trim(),
          String(parsed?.message || "").trim(),
          normalizeHttpErrorMessage(responseText),
          `HTTP ${result.status || 0} ${result.statusText || ""}`.trim(),
        ]) || "Partner SSO profile creation failed.";
    }
    if (result.ok) {
      context.partnerFrameworkStatus = partnerFrameworkStatus;
      context.sessionPartner = result.partner;
    }
    emitRestV2DebugEvent(normalizedFlowId, {
      source: "extension",
      phase: "profiles-sso-create-response",
      requestorId: String(context.requestorId || ""),
      mvpd: String(context.mvpd || ""),
      partner: String(result.partner || ""),
      endpointUrl,
      status: result.status,
      statusText: result.statusText,
      ok: result.ok,
      created: result.created,
      profileCount,
      error: String(result.error || "").trim(),
      responsePreview: truncateDebugText(responseText, 1200),
    });
  } catch (error) {
    result.error = error instanceof Error ? error.message : String(error);
    emitRestV2DebugEvent(normalizedFlowId, {
      source: "extension",
      phase: "profiles-sso-create-error",
      requestorId: String(context.requestorId || ""),
      mvpd: String(context.mvpd || ""),
      partner: String(result.partner || ""),
      endpointUrl,
      error: result.error,
    });
  }

  setRestV2PartnerSsoCreateResultForFlow(context, normalizedFlowId, result);
  return result;
}

function buildRestV2ProfileCheckEndpointCandidates(context = null) {
  if (!context || typeof context !== "object") {
    return [];
  }
  const serviceProviderId = String(context.serviceProviderId || context.requestorId || "").trim();
  const mvpd = String(context.mvpd || "").trim();
  if (!serviceProviderId) {
    return [];
  }

  const endpoints = [];
  const seen = new Set();
  const pushEndpoint = (endpointKey, url, metadata = {}) => {
    const normalizedUrl = String(url || "").trim();
    if (!endpointKey || !normalizedUrl || seen.has(normalizedUrl)) {
      return;
    }
    seen.add(normalizedUrl);
    endpoints.push({
      endpointKey: String(endpointKey || "").trim(),
      endpointLabel: String(metadata.endpointLabel || endpointKey || "").trim(),
      url: normalizedUrl,
      sessionCode: String(metadata.sessionCode || "").trim(),
    });
  };

  const mvpdProfilesUrl = mvpd
    ? `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/profiles/${encodeURIComponent(mvpd)}`
    : "";
  const allProfilesUrl = `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/profiles`;
  const sessionCodeCandidates = collectRestV2SessionCodeCandidates(
    [
      context.sessionCode,
      ...(Array.isArray(context.sessionCodeCandidates) ? context.sessionCodeCandidates : []),
      context.sessionUrl,
      context.loginUrl,
    ],
    serviceProviderId
  );
  const sessionCodeEndpoints = sessionCodeCandidates.map((sessionCode) => ({
    sessionCode,
    url: `${REST_V2_BASE}/${encodeURIComponent(serviceProviderId)}/profiles/code/${encodeURIComponent(sessionCode)}`,
  }));

  const likelySsoContext = isRestV2LikelyPartnerSsoContext(context);
  if (likelySsoContext) {
    if (mvpdProfilesUrl) {
      pushEndpoint("profiles-mvpd", mvpdProfilesUrl, {
        endpointLabel: "profiles/{mvpd}",
      });
    } else {
      pushEndpoint("profiles-all", allProfilesUrl, {
        endpointLabel: "profiles",
      });
    }
  } else {
    if (mvpdProfilesUrl) {
      pushEndpoint("profiles-mvpd", mvpdProfilesUrl, {
        endpointLabel: "profiles/{mvpd}",
      });
    }
    sessionCodeEndpoints.forEach((item) => {
      pushEndpoint("profiles-code", item.url, {
        endpointLabel: "profiles/code",
        sessionCode: item.sessionCode,
      });
    });
    pushEndpoint("profiles-all", allProfilesUrl, {
      endpointLabel: "profiles",
    });
  }

  return endpoints;
}

function buildRestV2ProfileCheckAttemptSummary(result = null) {
  if (!result || typeof result !== "object") {
    return null;
  }
  return {
    endpointKey: String(result.profileCheckEndpoint || "").trim(),
    endpointLabel: String(result.profileCheckEndpointLabel || "").trim(),
    url: String(result.url || "").trim(),
    ok: result.ok === true,
    checked: result.checked === true,
    status: Number(result.status || 0),
    statusText: String(result.statusText || "").trim(),
    profileCount: Number(result.profileCount || 0),
    error: String(result.error || "").trim(),
    sessionCode: String(result.profileCheckSessionCode || "").trim(),
  };
}

function shouldPreferRestV2ProfileCheckResult(candidate = null, current = null, context = null) {
  if (!candidate || typeof candidate !== "object") {
    return false;
  }
  if (!current || typeof current !== "object") {
    return true;
  }

  const candidateActive = isRestV2ProfileSessionActiveResult(candidate);
  const currentActive = isRestV2ProfileSessionActiveResult(current);
  if (candidateActive !== currentActive) {
    return candidateActive;
  }
  if (candidateActive && currentActive && isRestV2LikelyPartnerSsoContext(context)) {
    const candidateEndpoint = String(candidate?.profileCheckEndpoint || "").trim().toLowerCase();
    const currentEndpoint = String(current?.profileCheckEndpoint || "").trim().toLowerCase();
    if (candidateEndpoint !== currentEndpoint) {
      if (candidateEndpoint === "profiles-code") {
        return true;
      }
      if (currentEndpoint === "profiles-code") {
        return false;
      }
    }
  }

  const candidateOk = candidate.checked === true && candidate.ok === true;
  const currentOk = current.checked === true && current.ok === true;
  if (candidateOk !== currentOk) {
    return candidateOk;
  }

  const candidateProfileCount = Number(candidate.profileCount || 0);
  const currentProfileCount = Number(current.profileCount || 0);
  if (candidateProfileCount !== currentProfileCount) {
    return candidateProfileCount > currentProfileCount;
  }

  const candidateNoActiveSignal = isRestV2NoActiveProfileSignal(candidate);
  const currentNoActiveSignal = isRestV2NoActiveProfileSignal(current);
  if (candidateNoActiveSignal !== currentNoActiveSignal) {
    return candidateNoActiveSignal;
  }

  const candidateError = String(candidate.error || "").trim();
  const currentError = String(current.error || "").trim();
  if (Boolean(candidateError) !== Boolean(currentError)) {
    return !candidateError;
  }

  const candidateStatus = Number(candidate.status || 0);
  const currentStatus = Number(current.status || 0);
  if (candidateStatus !== currentStatus) {
    return candidateStatus > currentStatus;
  }

  return true;
}

async function fetchRestV2ProfileCheckResultFromEndpoint(context, flowId, scope = "profiles-check", endpoint = null) {
  const emptyResult = {
    checked: false,
    ok: false,
    status: 0,
    statusText: "",
    profileCount: 0,
    responsePreview: "",
    url: String(endpoint?.url || "").trim(),
    error: "",
    responsePayload: null,
    harvestedProfile: null,
    profileCheckEndpoint: String(endpoint?.endpointKey || "").trim(),
    profileCheckEndpointLabel: String(endpoint?.endpointLabel || "").trim(),
    profileCheckSessionCode: String(endpoint?.sessionCode || "").trim(),
    attemptedEndpoints: [],
  };

  if (!context?.programmerId || !context?.appInfo?.guid || !context?.serviceProviderId) {
    return {
      ...emptyResult,
      error: "Missing REST V2 profile-check context.",
    };
  }
  if (!endpoint?.url) {
    return {
      ...emptyResult,
      error: "Missing REST V2 profile-check endpoint URL.",
    };
  }

  const endpointScope = `${String(scope || "profiles-check")}:${String(endpoint.endpointKey || "profiles").trim()}`;
  const likelySsoContext = isRestV2LikelyPartnerSsoContext(context);
  const partnerFrameworkStatus = resolveRestV2PartnerFrameworkStatusFromContext(context);
  const requestHeaders = buildRestV2Headers(context.serviceProviderId, {
    Accept: "application/json",
  });
  if (likelySsoContext && partnerFrameworkStatus && String(endpoint?.endpointKey || "").trim() === "profiles-mvpd") {
    requestHeaders["AP-Partner-Framework-Status"] = partnerFrameworkStatus;
  }

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: "profiles-check-request",
    url: endpoint.url,
    requestorId: context.requestorId,
    mvpd: context.mvpd,
    profileCheckEndpoint: endpoint.endpointKey,
    profileCheckEndpointLabel: endpoint.endpointLabel,
    profileCheckSessionCode: endpoint.sessionCode || "",
    partnerFrameworkStatusPresent: Boolean(likelySsoContext && partnerFrameworkStatus),
  });

  try {
    const response = await fetchWithPremiumAuth(
      context.programmerId,
      context.appInfo,
      endpoint.url,
      {
        method: "GET",
        mode: "cors",
        headers: requestHeaders,
      },
      "refresh",
      {
        flowId,
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        scope: endpointScope,
      }
    );

    const responseText = await response.text().catch(() => "");
    const parsed = parseJsonText(responseText, {});
    const selectedMvpd = String(context?.mvpd || "").trim();
    const rawProfiles = parsed?.profiles && typeof parsed.profiles === "object" ? parsed.profiles : {};
    let effectivePayload =
      parsed && typeof parsed === "object"
        ? {
            ...parsed,
          }
        : {};
    let effectiveProfiles = rawProfiles;
    const rawProfileCount = Object.keys(rawProfiles).length;

    const endpointKey = String(endpoint?.endpointKey || "").trim();
    const allowSsoAliasMatch = isRestV2LikelyPartnerSsoContext(context);
    if (endpointKey === "profiles-all" && selectedMvpd) {
      const cachedMvpdMeta =
        String(context?.requestorId || "").trim() && selectedMvpd
          ? getRequestorScopedMvpdCache(String(context.requestorId || "").trim())?.get(selectedMvpd) || null
          : null;
      const selectedAliases = dedupeRestV2CandidateStrings([
        selectedMvpd,
        String(context?.mvpdMeta?.name || "").trim(),
        String(context?.mvpdMeta?.displayName || "").trim(),
        String(cachedMvpdMeta?.name || "").trim(),
        String(cachedMvpdMeta?.displayName || "").trim(),
      ]);
      const strictFilteredProfiles = {};
      const aliasFilteredProfiles = {};
      const selectedHasSso = selectedAliases.some((alias) => restV2ValueHasSsoMarker(alias));
      const requireSsoParity = allowSsoAliasMatch && selectedHasSso;
      for (const [profileKey, profileValue] of Object.entries(rawProfiles)) {
        if (!profileValue || typeof profileValue !== "object") {
          continue;
        }
        const summary = getRestV2ProfileSummary(profileValue, profileKey);
        const candidateMvpds = dedupeRestV2CandidateStrings([
          String(profileKey || "").trim(),
          String(summary?.mvpd || "").trim(),
          ...(Array.isArray(summary?.idpCandidates) ? summary.idpCandidates : []),
        ]);
        const strictMvpdMatch = candidateMvpds.some((candidate) =>
          selectedAliases.some((alias) =>
            isRestV2MvpdMatch(candidate, alias, {
              allowSsoAlias: false,
            })
          )
        );
        if (strictMvpdMatch) {
          strictFilteredProfiles[profileKey] = profileValue;
          continue;
        }
        if (allowSsoAliasMatch) {
          const aliasMvpdMatch = candidateMvpds.some((candidate) =>
            selectedAliases.some((alias) =>
              isRestV2MvpdMatch(candidate, alias, {
                allowSsoAlias: true,
              })
            )
          );
          if (aliasMvpdMatch) {
            aliasFilteredProfiles[profileKey] = profileValue;
          }
        }
      }
      const strictEntries = Object.entries(strictFilteredProfiles);
      const strictFilteredBySsoParity = {};
      strictEntries.forEach(([profileKey, profileValue]) => {
        if (!profileValue || typeof profileValue !== "object") {
          return;
        }
        const summary = getRestV2ProfileSummary(profileValue, profileKey, context);
        const candidateMvpds = dedupeRestV2CandidateStrings([
          String(profileKey || "").trim(),
          String(summary?.mvpd || "").trim(),
          ...(Array.isArray(summary?.idpCandidates) ? summary.idpCandidates : []),
        ]);
        if (candidateMvpds.some((candidate) => restV2ValueHasSsoMarker(candidate) === selectedHasSso)) {
          strictFilteredBySsoParity[profileKey] = profileValue;
        }
      });
      const aliasEntries = Object.entries(aliasFilteredProfiles);
      const aliasFilteredBySsoParity = {};
      aliasEntries.forEach(([profileKey, profileValue]) => {
        if (!profileValue || typeof profileValue !== "object") {
          return;
        }
        const summary = getRestV2ProfileSummary(profileValue, profileKey, context);
        const candidateMvpds = dedupeRestV2CandidateStrings([
          String(profileKey || "").trim(),
          String(summary?.mvpd || "").trim(),
          ...(Array.isArray(summary?.idpCandidates) ? summary.idpCandidates : []),
        ]);
        if (
          candidateMvpds.some((candidate) => restV2ValueHasSsoMarker(candidate) === selectedHasSso)
        ) {
          aliasFilteredBySsoParity[profileKey] = profileValue;
        }
      });
      if (Object.keys(strictFilteredBySsoParity).length > 0) {
        effectiveProfiles = strictFilteredBySsoParity;
        effectivePayload = {
          ...effectivePayload,
          profiles: strictFilteredBySsoParity,
        };
      } else if (Object.keys(strictFilteredProfiles).length > 0 && !requireSsoParity) {
        effectiveProfiles = strictFilteredProfiles;
        effectivePayload = {
          ...effectivePayload,
          profiles: strictFilteredProfiles,
        };
      } else if (Object.keys(aliasFilteredBySsoParity).length > 0) {
        effectiveProfiles = aliasFilteredBySsoParity;
        effectivePayload = {
          ...effectivePayload,
          profiles: aliasFilteredBySsoParity,
        };
      } else if (Object.keys(aliasFilteredProfiles).length > 0 && !requireSsoParity) {
        effectiveProfiles = aliasFilteredProfiles;
        effectivePayload = {
          ...effectivePayload,
          profiles: aliasFilteredProfiles,
        };
      } else if (rawProfileCount > 0 && allowSsoAliasMatch) {
        const scoredProfiles = {};
        const scoredEntries = [];
        for (const [profileKey, profileValue] of Object.entries(rawProfiles)) {
          if (!profileValue || typeof profileValue !== "object") {
            continue;
          }
          const summary = getRestV2ProfileSummary(profileValue, profileKey, context);
          const candidateMvpds = dedupeRestV2CandidateStrings([
            String(profileKey || "").trim(),
            String(summary?.mvpd || "").trim(),
            ...(Array.isArray(summary?.idpCandidates) ? summary.idpCandidates : []),
          ]);
          if (candidateMvpds.length === 0) {
            continue;
          }
          const candidateHasSso = candidateMvpds.some((candidate) => restV2ValueHasSsoMarker(candidate));
          const bestAliasScore = candidateMvpds.reduce(
            (maxScore, candidate) =>
              Math.max(
                maxScore,
                ...selectedAliases.map((alias) =>
                  scoreRestV2MvpdCandidateMatch(candidate, alias, {
                    allowSsoAlias: true,
                  })
                )
              ),
            -1
          );
          scoredEntries.push({
            profileKey,
            profileValue,
            bestAliasScore,
            candidateHasSso,
          });
        }
        const topScore = scoredEntries.reduce((maxScore, entry) => Math.max(maxScore, Number(entry?.bestAliasScore || -1)), -1);
        if (topScore >= 0) {
          scoredEntries
            .filter((entry) => Number(entry?.bestAliasScore || -1) === topScore)
            .forEach((entry) => {
              scoredProfiles[entry.profileKey] = entry.profileValue;
            });
        }
        const parityProfiles = {};
        if (Object.keys(scoredProfiles).length === 0) {
          scoredEntries
            .filter((entry) => entry.candidateHasSso === selectedHasSso)
            .forEach((entry) => {
              parityProfiles[entry.profileKey] = entry.profileValue;
            });
        }
        const fallbackProfiles =
          Object.keys(scoredProfiles).length > 0
            ? scoredProfiles
            : Object.keys(parityProfiles).length > 0
              ? parityProfiles
              : requireSsoParity
                ? {}
                : rawProfiles;
        effectiveProfiles = fallbackProfiles;
        effectivePayload = {
          ...effectivePayload,
          profiles: fallbackProfiles,
        };
      } else {
        effectiveProfiles = requireSsoParity ? {} : strictFilteredProfiles;
        effectivePayload = {
          ...effectivePayload,
          profiles: effectiveProfiles,
        };
      }
    } else {
      effectivePayload = {
        ...effectivePayload,
        profiles: rawProfiles,
      };
    }

    const profileCount = Object.keys(effectiveProfiles).length;
    const status = Number(response.status || 0);
    const statusText = String(response.statusText || "");
    const responsePreview = truncateDebugText(responseText, 1200);
    const errorMessage =
      response.ok === true
        ? ""
        : firstNonEmptyString([
            parsed?.code,
            parsed?.error?.code,
            parsed?.error,
            parsed?.message,
            parsed?.description,
            normalizeHttpErrorMessage(responseText),
            statusText,
          ]) || `HTTP ${status}`;
    const harvestedProfile = buildRestV2ProfileHarvest(
      context,
      {
        checked: true,
        ok: Boolean(response.ok),
        status,
        statusText,
        profileCount,
        responsePreview,
        responsePayload: effectivePayload,
        url: endpoint.url,
        error: errorMessage,
      },
      flowId
    );

    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "profiles-check-response",
      status,
      statusText,
      profileCount,
      rawProfileCount,
      responsePreview,
      profileKeys: Object.keys(effectiveProfiles || {}),
      payload: cloneJsonLikeValue(effectivePayload, {}),
      profileCheckEndpoint: endpoint.endpointKey,
      profileCheckEndpointLabel: endpoint.endpointLabel,
      profileCheckSessionCode: endpoint.sessionCode || "",
      profileHarvest: harvestedProfile ? cloneJsonLikeValue(harvestedProfile, {}) : null,
    });

    const result = {
      checked: true,
      ok: Boolean(response.ok),
      status,
      statusText,
      profileCount,
      responsePreview,
      url: endpoint.url,
      error: errorMessage,
      responsePayload: effectivePayload,
      harvestedProfile,
      profileCheckEndpoint: String(endpoint.endpointKey || "").trim(),
      profileCheckEndpointLabel: String(endpoint.endpointLabel || "").trim(),
      profileCheckSessionCode: String(endpoint.sessionCode || "").trim(),
      attemptedEndpoints: [],
    };
    const summary = buildRestV2ProfileCheckAttemptSummary(result);
    result.attemptedEndpoints = summary ? [summary] : [];
    return result;
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    const errorResult = {
      ...emptyResult,
      checked: true,
      ok: false,
      error: reason,
    };
    const harvestedProfile = buildRestV2ProfileHarvest(
      context,
      {
        ...errorResult,
      },
      flowId
    );
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "profiles-check-error",
      url: endpoint.url,
      error: reason,
      profileCheckEndpoint: endpoint.endpointKey,
      profileCheckEndpointLabel: endpoint.endpointLabel,
      profileCheckSessionCode: endpoint.sessionCode || "",
      profileHarvest: harvestedProfile ? cloneJsonLikeValue(harvestedProfile, {}) : null,
    });
    const result = {
      ...errorResult,
      harvestedProfile,
    };
    const summary = buildRestV2ProfileCheckAttemptSummary(result);
    result.attemptedEndpoints = summary ? [summary] : [];
    return result;
  }
}

async function fetchRestV2ProfileCheckResult(context, flowId, scope = "profiles-check") {
  const emptyResult = {
    checked: false,
    ok: false,
    status: 0,
    statusText: "",
    profileCount: 0,
    responsePreview: "",
    url: "",
    error: "",
    responsePayload: null,
    harvestedProfile: null,
    profileCheckEndpoint: "",
    profileCheckEndpointLabel: "",
    profileCheckSessionCode: "",
    attemptedEndpoints: [],
  };

  if (!context?.programmerId || !context?.appInfo?.guid || !context?.serviceProviderId) {
    return {
      ...emptyResult,
      error: "Missing REST V2 profile-check context.",
    };
  }

  const endpointCandidates = buildRestV2ProfileCheckEndpointCandidates(context);
  if (endpointCandidates.length === 0) {
    return {
      ...emptyResult,
      error: "Missing REST V2 profile-check endpoint candidates.",
    };
  }

  let bestResult = null;
  const attemptedEndpoints = [];

  for (const endpoint of endpointCandidates) {
    const endpointResult = await fetchRestV2ProfileCheckResultFromEndpoint(context, flowId, scope, endpoint);
    const endpointAttempts = Array.isArray(endpointResult?.attemptedEndpoints) ? endpointResult.attemptedEndpoints : [];
    if (endpointAttempts.length > 0) {
      attemptedEndpoints.push(...endpointAttempts);
    } else {
      const summary = buildRestV2ProfileCheckAttemptSummary(endpointResult);
      if (summary) {
        attemptedEndpoints.push(summary);
      }
    }

    if (shouldPreferRestV2ProfileCheckResult(endpointResult, bestResult, context)) {
      bestResult = endpointResult;
    }

    if (isRestV2ProfileSessionActiveResult(endpointResult)) {
      break;
    }
  }

  if (!bestResult) {
    return {
      ...emptyResult,
      error: "REST V2 profile check did not produce a result.",
      attemptedEndpoints,
    };
  }

  return {
    ...bestResult,
    attemptedEndpoints,
  };
}

function buildRestV2ProfileVerdict(profileCheckResult, context = null) {
  if (!profileCheckResult || profileCheckResult.checked !== true) {
    return null;
  }

  const requestorId = String(context?.requestorId || "");
  const mvpd = String(context?.mvpd || "");
  const targetLabel =
    requestorId && mvpd
      ? formatRestV2RequestorMvpdDisplay(
          requestorId,
          mvpd,
          String(context?.mvpdName || "").trim()
            ? {
                id: mvpd,
                name: String(context.mvpdName || "").trim(),
              }
            : null,
          {
            separator: " x ",
          }
        )
      : "selected Requestor x MVPD";

  if (profileCheckResult.error || !profileCheckResult.ok) {
    const reason =
      profileCheckResult.error ||
      `HTTP ${Number(profileCheckResult.status || 0)} ${String(profileCheckResult.statusText || "").trim()}`.trim();
    return {
      panelType: "error",
      mainType: "error",
      panelSuffix: `Profile check: ERROR (${reason || "unknown"}).`,
      mainMessage: `REST V2 Profile Check ERROR for ${targetLabel}: ${reason || "unknown"}.`,
    };
  }

  if (Number(profileCheckResult.profileCount || 0) > 0) {
    return {
      panelType: "success",
      mainType: "success",
      panelSuffix: `Profile check: SUCCESS (populated profiles response).`,
      mainMessage: `REST V2 Profile Check SUCCESS for ${targetLabel} (profiles=${Number(profileCheckResult.profileCount || 0)}).`,
    };
  }

  return {
    panelType: "info",
    mainType: "info",
    panelSuffix: "Profile check: NO ACTIVE PROFILE (empty profiles response).",
    mainMessage: `REST V2 Profile Check found no active profile for ${targetLabel} (empty profiles response).`,
  };
}

function buildRestV2ProfileCheckFallbackResult(errorText = "", options = {}) {
  return {
    checked: false,
    ok: false,
    status: Number(options?.status || 0),
    statusText: String(options?.statusText || "").trim(),
    profileCount: 0,
    responsePreview: String(options?.responsePreview || "").trim(),
    url: String(options?.url || "").trim(),
    error: String(errorText || "").trim(),
    responsePayload: null,
    harvestedProfile: null,
    profileCheckEndpoint: String(options?.profileCheckEndpoint || "").trim(),
    profileCheckEndpointLabel: String(options?.profileCheckEndpointLabel || "").trim(),
    profileCheckSessionCode: String(options?.profileCheckSessionCode || "").trim(),
    attemptedEndpoints: Array.isArray(options?.attemptedEndpoints)
      ? options.attemptedEndpoints.map((item) => (item && typeof item === "object" ? { ...item } : item))
      : [],
  };
}

async function probeRestV2PostAuthProfiles(context, flowId, options = {}) {
  const maxAttempts = Math.max(1, Number(options?.maxAttempts || REST_V2_POST_AUTH_PROFILE_CHECK_RETRIES || 1));
  const delayMs = Math.max(0, Number(options?.delayMs || REST_V2_POST_AUTH_PROFILE_CHECK_DELAY_MS || 0));
  const scopePrefix = String(options?.scopePrefix || "profiles-post-auth").trim() || "profiles-post-auth";
  let lastCheck = buildRestV2ProfileCheckFallbackResult("Profile check not attempted.");

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: `${scopePrefix}-attempt`,
      attempt,
      maxAttempts,
      requestorId: String(context?.requestorId || ""),
      mvpd: String(context?.mvpd || ""),
    });

    if (isRestV2LikelyPartnerSsoContext(context)) {
      const ssoCreateResult = await createRestV2PartnerSsoProfileForFlow(context, flowId);
      emitRestV2DebugEvent(flowId, {
        source: "extension",
        phase: `${scopePrefix}-sso-create`,
        attempt,
        maxAttempts,
        requestorId: String(context?.requestorId || ""),
        mvpd: String(context?.mvpd || ""),
        partner: String(ssoCreateResult?.partner || "").trim(),
        attempted: ssoCreateResult?.attempted === true,
        created: ssoCreateResult?.created === true,
        ok: ssoCreateResult?.ok === true,
        status: Number(ssoCreateResult?.status || 0),
        statusText: String(ssoCreateResult?.statusText || "").trim(),
        error: String(ssoCreateResult?.error || "").trim(),
        samlSource: String(ssoCreateResult?.samlSource || "").trim(),
      });
    }

    lastCheck = await fetchRestV2ProfileCheckResult(context, flowId, `${scopePrefix}-${attempt}`);
    const hasActiveProfile = isRestV2ProfileSessionActiveResult(lastCheck);
    const noActiveProfileSignal = isRestV2NoActiveProfileSignal(lastCheck);

    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: `${scopePrefix}-result`,
      attempt,
      maxAttempts,
      hasActiveProfile,
      noActiveProfileSignal,
      profileCount: Number(lastCheck?.profileCount || 0),
      status: Number(lastCheck?.status || 0),
      statusText: String(lastCheck?.statusText || "").trim(),
      error: String(lastCheck?.error || "").trim(),
      profileCheckEndpoint: String(lastCheck?.profileCheckEndpoint || "").trim(),
      profileCheckEndpointLabel: String(lastCheck?.profileCheckEndpointLabel || "").trim(),
      profileCheckSessionCode: String(lastCheck?.profileCheckSessionCode || "").trim(),
      attemptedEndpoints: Array.isArray(lastCheck?.attemptedEndpoints)
        ? lastCheck.attemptedEndpoints.slice(0, 6)
        : [],
    });

    if (hasActiveProfile) {
      return {
        ok: true,
        attempt,
        maxAttempts,
        result: lastCheck,
      };
    }

    if (attempt < maxAttempts && delayMs > 0) {
      await waitForDelay(delayMs);
    }
  }

  return {
    ok: false,
    attempt: maxAttempts,
    maxAttempts,
    result: lastCheck,
  };
}

async function verifyPostLogoutProfilesCleared(context, flowId) {
  const maxAttempts = Math.max(1, Number(REST_V2_POST_LOGOUT_PROFILE_CHECK_RETRIES || 1));
  const delayMs = Math.max(0, Number(REST_V2_POST_LOGOUT_PROFILE_CHECK_DELAY_MS || 0));
  let lastCheck = null;

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "post-logout-profiles-check-attempt",
      attempt,
      maxAttempts,
      requestorId: String(context?.requestorId || ""),
      mvpd: String(context?.mvpd || ""),
    });

    lastCheck = await fetchRestV2ProfileCheckResult(context, flowId, `post-logout-profiles-check-${attempt}`);
    const profileCount = Number(lastCheck?.profileCount || 0);
    const checkOk = lastCheck?.checked === true && lastCheck?.ok === true;
    const noActiveProfileSignal = isRestV2NoActiveProfileSignal(lastCheck);
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "post-logout-profiles-check-result",
      attempt,
      maxAttempts,
      ok: checkOk,
      noActiveProfileSignal,
      profileCount,
      status: Number(lastCheck?.status || 0),
      statusText: String(lastCheck?.statusText || ""),
      error: String(lastCheck?.error || "").trim(),
      profileCheckEndpoint: String(lastCheck?.profileCheckEndpoint || "").trim(),
      profileCheckEndpointLabel: String(lastCheck?.profileCheckEndpointLabel || "").trim(),
      profileCheckSessionCode: String(lastCheck?.profileCheckSessionCode || "").trim(),
      attemptedEndpoints: Array.isArray(lastCheck?.attemptedEndpoints)
        ? lastCheck.attemptedEndpoints.slice(0, 6)
        : [],
    });

    if ((checkOk && profileCount === 0) || noActiveProfileSignal) {
      clearRestV2ProfileHarvestForContext(context);
      setRestV2ActiveProfileWindowState(
        {
          ok: true,
          programmerId: String(context?.programmerId || "").trim(),
          requestorId: String(context?.requestorId || "").trim(),
          mvpd: String(context?.mvpd || "").trim(),
        },
        false,
        {
          checkedAt: Date.now(),
          profileCount,
          status: Number(lastCheck?.status || 0),
          statusText: String(lastCheck?.statusText || "").trim(),
          error: String(lastCheck?.error || "").trim(),
          source: "post-logout-profiles-check",
        }
      );
      return {
        ok: true,
        attempts: attempt,
        profileCount: 0,
      };
    }

    if (attempt < maxAttempts && delayMs > 0) {
      await waitForDelay(delayMs);
    }
  }

  const profileCount = Number(lastCheck?.profileCount || 0);
  const errorText = String(lastCheck?.error || "").trim();
  const blocking = lastCheck?.checked === true && lastCheck?.ok === true && profileCount > 0;
  return {
    ok: false,
    blocking,
    attempts: maxAttempts,
    profileCount,
    status: Number(lastCheck?.status || 0),
    statusText: String(lastCheck?.statusText || ""),
    error: errorText || (profileCount > 0 ? `${profileCount} active profile(s) still returned` : "profile check failed"),
  };
}

async function executeRestV2LogoutFlow(context, flowId, options = {}) {
  const result = {
    attempted: false,
    performed: false,
    actionName: "",
    actionType: "",
    logoutUrl: "",
    error: "",
  };

  if (!context?.programmerId || !context?.appInfo?.guid || !context?.serviceProviderId || !context?.mvpd) {
    return result;
  }

  const skipUserAgentAction = options?.skipUserAgentAction === true;
  result.attempted = true;
  const redirectUrl = firstNonEmptyString([
    REST_V2_REDIRECT_CANDIDATES[0],
    String(PREMIUM_SERVICE_DOCUMENTATION_URL_BY_KEY.restV2 || "").trim(),
  ]);
  const logoutEndpoint = `${REST_V2_BASE}/${encodeURIComponent(context.serviceProviderId)}/logout/${encodeURIComponent(
    context.mvpd
  )}${redirectUrl ? `?redirectUrl=${encodeURIComponent(redirectUrl)}` : ""}`;

  emitRestV2DebugEvent(flowId, {
    source: "extension",
    phase: "logout-request",
    url: logoutEndpoint,
    requestorId: context.requestorId,
    mvpd: context.mvpd,
  });

  try {
    const response = await fetchWithPremiumAuth(
      context.programmerId,
      context.appInfo,
      logoutEndpoint,
      {
        method: "GET",
        mode: "cors",
        credentials: "include",
        headers: buildRestV2Headers(context.serviceProviderId, {
          Accept: "application/json",
        }),
      },
      "refresh",
      {
        flowId,
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        scope: "logout",
      }
    );

    const responseText = await response.text().catch(() => "");
    const parsed = parseJsonText(responseText, {});
    const locationHeader = response.headers?.get("Location") || "";
    const resolvedAction = resolveRestV2LogoutAction(parsed, context.mvpd, locationHeader);
    if (resolvedAction) {
      result.actionName = resolvedAction.actionName;
      result.actionType = resolvedAction.actionType;
      result.logoutUrl = resolvedAction.url;
    }

    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "logout-response",
      status: Number(response.status || 0),
      statusText: String(response.statusText || ""),
      actionName: result.actionName,
      actionType: result.actionType,
      logoutUrl: result.logoutUrl,
      responsePreview: truncateDebugText(responseText, 2000),
    });

    const responseAccepted = isRestV2LogoutApiAccepted(response);
    if (!responseAccepted) {
      result.error = buildRestV2LogoutFailureReason(responseText, parsed, response);
      return result;
    }

    if (shouldRunRestV2LogoutUserAgentAction(result) && !skipUserAgentAction) {
      const logoutAction = await executeRestV2LogoutAction(result.logoutUrl, flowId, context);
      emitRestV2DebugEvent(flowId, {
        source: "extension",
        phase: "logout-action-result",
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        logoutUrl: String(result.logoutUrl || "").trim(),
        mode: String(logoutAction?.mode || ""),
        ok: logoutAction?.ok === true,
        reason: String(logoutAction?.reason || "").trim(),
      });
      if (logoutAction?.ok !== true) {
        const actionReason = String(logoutAction?.reason || "").trim() || "unable to complete MVPD user-agent logout action";
        result.error = `Logout user-agent action failed: ${actionReason}`;
        return result;
      }
    } else if (shouldRunRestV2LogoutUserAgentAction(result) && skipUserAgentAction) {
      emitRestV2DebugEvent(flowId, {
        source: "extension",
        phase: "logout-action-skipped",
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        logoutUrl: String(result.logoutUrl || "").trim(),
        reason: "skip-user-agent-action",
      });
    }

    result.performed =
      isRestV2LogoutActionCompleted(result) || !shouldRunRestV2LogoutUserAgentAction(result) || skipUserAgentAction;
    if (!result.performed && !result.error) {
      const fallbackAction = buildRestV2LogoutAcceptedFallbackAction(parsed, result);
      result.performed = true;
      result.actionName = fallbackAction.actionName;
      result.actionType = fallbackAction.actionType;
    } else if (result.performed && skipUserAgentAction && !String(result.actionType || "").trim()) {
      result.actionType = "api-skip-user-agent";
    }
    if (result.performed) {
      setRestV2ActiveProfileWindowState(
        {
          ok: true,
          programmerId: String(context?.programmerId || "").trim(),
          requestorId: String(context?.requestorId || "").trim(),
          mvpd: String(context?.mvpd || "").trim(),
        },
        false,
        {
          checkedAt: Date.now(),
          profileCount: 0,
          status: Number(response.status || 0),
          statusText: String(response.statusText || "").trim(),
          error: "",
          source: "logout-flow",
        }
      );
    }
    return result;
  } catch (error) {
    result.error = error instanceof Error ? error.message : String(error);
    emitRestV2DebugEvent(flowId, {
      source: "extension",
      phase: "logout-error",
      error: result.error,
    });
    return result;
  }
}

function pickFlowEventTimestampMs(event, fallbackMs = Date.now()) {
  const iso = Date.parse(String(event?.timestamp || ""));
  if (Number.isFinite(iso) && iso > 0) {
    return iso;
  }

  const raw = Number(event?.timestampMs || 0);
  if (Number.isFinite(raw) && raw > 0) {
    return raw;
  }

  return fallbackMs;
}

function toHarHeadersArray(headersLike) {
  const output = [];
  if (!headersLike) {
    return output;
  }

  if (Array.isArray(headersLike)) {
    for (const entry of headersLike) {
      if (!entry || typeof entry !== "object") {
        continue;
      }
      if (Array.isArray(entry) && entry.length >= 2) {
        output.push({
          name: String(entry[0]),
          value: String(entry[1]),
        });
        continue;
      }
      output.push({
        name: String(entry.name || ""),
        value: String(entry.value || ""),
      });
    }
    return output.filter((item) => item.name);
  }

  if (headersLike instanceof Headers) {
    for (const [name, value] of headersLike.entries()) {
      output.push({ name: String(name), value: String(value) });
    }
    return output;
  }

  if (typeof headersLike === "object") {
    for (const [name, value] of Object.entries(headersLike)) {
      output.push({ name: String(name), value: String(value ?? "") });
    }
  }

  return output.filter((item) => item.name);
}

function getHarHeaderValue(headers, name) {
  const normalizedName = String(name || "").trim().toLowerCase();
  if (!normalizedName || !Array.isArray(headers)) {
    return "";
  }
  const match = headers.find((entry) => String(entry?.name || "").trim().toLowerCase() === normalizedName);
  return match ? String(match.value || "") : "";
}

function toHarQueryStringArray(url) {
  if (!url) {
    return [];
  }

  try {
    const parsed = new URL(url);
    const output = [];
    for (const [name, value] of parsed.searchParams.entries()) {
      output.push({ name, value });
    }
    return output;
  } catch {
    return [];
  }
}

function isPassCriticalPath(pathname = "") {
  const normalized = String(pathname || "").toLowerCase();
  return (
    normalized.startsWith("/api/v2/") ||
    normalized.startsWith("/o/") ||
    normalized.startsWith("/authenticate/")
  );
}

function shouldIgnoreRedirectSiteUrl(url, context = null) {
  const redirectUrl = normalizeAdobeNavigationUrl(firstNonEmptyString([context?.redirectUrl]));
  if (!redirectUrl || !url) {
    return false;
  }

  let redirectParsed;
  let parsed;
  try {
    redirectParsed = new URL(redirectUrl);
    parsed = new URL(String(url));
  } catch {
    return false;
  }

  if (parsed.origin !== redirectParsed.origin) {
    return false;
  }
  if (isPassCriticalPath(parsed.pathname)) {
    return false;
  }

  const mode = String(REDIRECT_IGNORE_MATCHER_MODE || "origin_except_pass").trim().toLowerCase();
  const redirectPath = redirectParsed.pathname || "/";
  if (mode === "exact_path") {
    return parsed.pathname === redirectPath;
  }

  if (parsed.pathname === redirectPath) {
    return true;
  }

  if (mode === "path_tree" && redirectPath !== "/") {
    const redirectDir = redirectPath.endsWith("/")
      ? redirectPath
      : redirectPath.slice(0, redirectPath.lastIndexOf("/") + 1);
    if (redirectDir && redirectDir !== "/" && parsed.pathname.startsWith(redirectDir)) {
      return true;
    }
    return false;
  }

  // Broad mode: same-origin non-PASS endpoints are redirect target app/site noise.
  return mode === "origin_except_pass";
}

function buildWebRequestHarEntries(flowEvents = [], context = null) {
  const records = new Map();

  const getRecord = (event) => {
    const tabId = Number(event?.tabId || 0);
    const requestId = String(event?.requestId || "").trim();
    const fallbackKey = `${tabId}:seq:${String(event?.seq || 0)}`;
    const key = requestId ? `${tabId}:${requestId}` : fallbackKey;
    const existing = records.get(key);
    if (existing) {
      return existing;
    }

    const record = {
      key,
      tabId,
      requestId,
      startedMs: 0,
      endedMs: 0,
      method: "",
      url: "",
      requestHeaders: {},
      responseHeaders: {},
      requestBody: null,
      status: 0,
      statusText: "",
      redirectUrl: "",
      errorText: "",
    };
    records.set(key, record);
    return record;
  };

  for (const event of flowEvents) {
    if (!event || event.source !== "web-request") {
      continue;
    }
    if (shouldIgnoreRedirectSiteUrl(event.url || "", context)) {
      continue;
    }

    const record = getRecord(event);
    const timestampMs = pickFlowEventTimestampMs(event, Date.now());
    if (!record.startedMs || timestampMs < record.startedMs) {
      record.startedMs = timestampMs;
    }
    if (!record.endedMs || timestampMs > record.endedMs) {
      record.endedMs = timestampMs;
    }

    if (!record.method) {
      record.method = String(event.method || "GET").toUpperCase();
    }
    if (!record.url) {
      record.url = String(event.url || "");
    }
    if (!record.requestHeaders || Object.keys(record.requestHeaders).length === 0) {
      if (event.requestHeaders && typeof event.requestHeaders === "object") {
        record.requestHeaders = event.requestHeaders;
      }
    }
    if (event.responseHeaders && typeof event.responseHeaders === "object") {
      record.responseHeaders = event.responseHeaders;
    }
    if (event.requestBody && record.requestBody === null) {
      record.requestBody = event.requestBody;
    }

    if (Number(event.statusCode || 0) > 0) {
      record.status = Number(event.statusCode || 0);
    }
    if (event.statusLine) {
      record.statusText = String(event.statusLine || "");
    }
    if (event.redirectUrl) {
      record.redirectUrl = String(event.redirectUrl || "");
    }
    if (event.error) {
      record.errorText = String(event.error || "");
    }
  }

  const entries = [];
  for (const record of records.values()) {
    if (!record.url) {
      continue;
    }

    const startedMs = record.startedMs || Date.now();
    const endedMs = record.endedMs || startedMs;
    const durationMs = Math.max(0, endedMs - startedMs);
    const requestHeaders = toHarHeadersArray(record.requestHeaders);
    const responseHeaders = toHarHeadersArray(record.responseHeaders);
    const requestBodyText =
      record.requestBody === null
        ? ""
        : typeof record.requestBody === "string"
          ? record.requestBody
          : JSON.stringify(record.requestBody);
    const mimeType = firstNonEmptyString([
      getHarHeaderValue(responseHeaders, "content-type").split(";")[0],
      getHarHeaderValue(requestHeaders, "content-type").split(";")[0],
      "application/octet-stream",
    ]);
    const status = Number(record.status || 0);

    entries.push({
      startedDateTime: new Date(startedMs).toISOString(),
      time: durationMs,
      request: {
        method: record.method || "GET",
        url: record.url,
        httpVersion: "HTTP/1.1",
        headers: requestHeaders,
        queryString: toHarQueryStringArray(record.url),
        cookies: [],
        headersSize: -1,
        bodySize: requestBodyText ? requestBodyText.length : 0,
        postData: requestBodyText
          ? {
              mimeType: firstNonEmptyString([getHarHeaderValue(requestHeaders, "content-type"), "application/json"]),
              text: truncateDebugText(requestBodyText, 10000),
            }
          : undefined,
      },
      response: {
        status,
        statusText: record.errorText || record.statusText || (status > 0 ? "" : "NETWORK_ERROR"),
        httpVersion: "HTTP/1.1",
        headers: responseHeaders,
        cookies: [],
        redirectURL: record.redirectUrl || "",
        headersSize: -1,
        bodySize: -1,
        content: {
          size: 0,
          mimeType,
        },
      },
      cache: {},
      timings: {
        send: 0,
        wait: durationMs,
        receive: 0,
      },
      _underpar: {
        source: "web-request",
        tabId: record.tabId,
        requestId: record.requestId,
      },
    });
  }

  return entries;
}

function buildExtensionHarEntries(flowEvents = []) {
  const entries = [];
  const pendingApiByKey = new Map();
  const pendingTokenByKey = new Map();
  const pendingCmByKey = new Map();
  const completedTokenAttemptIds = new Set();

  const getApiKey = (event) => {
    return [
      String(event?.method || "GET").toUpperCase(),
      String(event?.url || ""),
      String(event?.requestorId || ""),
      String(event?.mvpd || ""),
      String(event?.requestScope || ""),
    ].join("|");
  };
  const getTokenKey = (event) => {
    const attemptId = String(event?.attemptId || "").trim();
    if (attemptId) {
      return `attempt:${attemptId}`;
    }
    return [
      String(event?.transport || ""),
      String(event?.method || "POST").toUpperCase(),
      String(event?.url || ""),
      String(event?.requestorId || ""),
      String(event?.mvpd || ""),
      String(event?.requestScope || ""),
    ].join("|");
  };
  const normalizeCmPhase = (event) => String(event?.phase || "").trim().toLowerCase();
  const isCmRequestStartPhase = (event) => {
    const phase = normalizeCmPhase(event);
    return phase === "cm-request-attempt" || phase === "cm-v2-request";
  };
  const isCmResponsePhase = (event) => {
    const phase = normalizeCmPhase(event);
    return (
      phase === "cm-response" ||
      phase === "cm-request-failed" ||
      phase === "cm-request-error" ||
      phase === "cm-v2-response" ||
      phase === "cm-v2-request-failed" ||
      phase === "cm-v2-request-error"
    );
  };
  const getCmKey = (event) => {
    return [
      String(event?.method || "GET").toUpperCase(),
      String(event?.url || event?.endpointUrl || ""),
      String(event?.requestorId || ""),
      String(event?.mvpd || ""),
      String(event?.programmerId || ""),
      String(event?.cardId || ""),
      String(event?.operationKey || ""),
      String(event?.attempt || ""),
      String(event?.contextLabel || ""),
    ].join("|");
  };

  for (const event of flowEvents) {
    if (!event || event.source !== "extension") {
      continue;
    }

    if (isCmRequestStartPhase(event)) {
      const key = getCmKey(event);
      const queue = pendingCmByKey.get(key) || [];
      queue.push(event);
      pendingCmByKey.set(key, queue);
      continue;
    }

    if (isCmResponsePhase(event)) {
      const key = getCmKey(event);
      const queue = pendingCmByKey.get(key) || [];
      const requestEvent = queue.length > 0 ? queue.shift() : null;
      if (queue.length === 0) {
        pendingCmByKey.delete(key);
      } else {
        pendingCmByKey.set(key, queue);
      }

      const startedMs = pickFlowEventTimestampMs(requestEvent || event, Date.now());
      const endedMs = pickFlowEventTimestampMs(event, startedMs);
      const durationMs = Math.max(0, endedMs - startedMs);
      const requestUrl = String(event?.url || event?.endpointUrl || requestEvent?.url || requestEvent?.endpointUrl || "");
      const requestMethod = String(event?.method || requestEvent?.method || "GET").toUpperCase();
      const status = Number(event?.status || 0);
      const statusText =
        String(event?.statusText || "") ||
        String(event?.error || "") ||
        (status > 0 ? "" : "CM_REQUEST_FAILED");
      const responseBodyText = firstNonEmptyString([String(event?.responsePreview || ""), String(event?.error || "")]);
      const phase = normalizeCmPhase(event);

      entries.push({
        startedDateTime: new Date(startedMs).toISOString(),
        time: durationMs,
        request: {
          method: requestMethod,
          url: requestUrl,
          httpVersion: "HTTP/1.1",
          headers: [],
          queryString: toHarQueryStringArray(requestUrl),
          cookies: [],
          headersSize: -1,
          bodySize: 0,
        },
        response: {
          status,
          statusText,
          httpVersion: "HTTP/1.1",
          headers: [],
          cookies: [],
          redirectURL: "",
          headersSize: -1,
          bodySize: responseBodyText ? responseBodyText.length : -1,
          content: {
            size: responseBodyText.length,
            mimeType: "application/json",
            text: responseBodyText ? truncateDebugText(responseBodyText, 10000) : undefined,
          },
        },
        cache: {},
        timings: {
          send: 0,
          wait: durationMs,
          receive: 0,
        },
        _underpar: {
          source: "extension-cm",
          phase,
          authMode: String(requestEvent?.authMode || event?.authMode || ""),
          contextLabel: String(requestEvent?.contextLabel || event?.contextLabel || ""),
          requestorId: String(event?.requestorId || requestEvent?.requestorId || ""),
          mvpd: String(event?.mvpd || requestEvent?.mvpd || ""),
          programmerId: String(event?.programmerId || requestEvent?.programmerId || ""),
          operationKey: String(event?.operationKey || requestEvent?.operationKey || ""),
          cardId: String(event?.cardId || requestEvent?.cardId || ""),
        },
      });
      continue;
    }

    if (event.phase === "restv2-request") {
      const key = getApiKey(event);
      const queue = pendingApiByKey.get(key) || [];
      queue.push(event);
      pendingApiByKey.set(key, queue);
      continue;
    }

    if (event.phase === "restv2-response") {
      const key = getApiKey(event);
      const queue = pendingApiByKey.get(key) || [];
      const requestEvent = queue.length > 0 ? queue.shift() : null;
      if (queue.length === 0) {
        pendingApiByKey.delete(key);
      } else {
        pendingApiByKey.set(key, queue);
      }

      const startedMs = pickFlowEventTimestampMs(requestEvent || event, Date.now());
      const endedMs = pickFlowEventTimestampMs(event, startedMs);
      const durationMs = Math.max(0, endedMs - startedMs);
      const requestHeaders = toHarHeadersArray(requestEvent?.requestHeaders || {});
      const responseHeaders = toHarHeadersArray(event?.responseHeaders || {});
      const requestBodyText = String(requestEvent?.requestBodyPreview || "");
      const responseBodyText = String(event?.responsePreview || "");
      const requestUrl = String(event?.url || requestEvent?.url || "");
      const status = Number(event?.status || 0);
      const responseMimeType = firstNonEmptyString([
        getHarHeaderValue(responseHeaders, "content-type").split(";")[0],
        "application/json",
      ]);

      entries.push({
        startedDateTime: new Date(startedMs).toISOString(),
        time: durationMs,
        request: {
          method: String(event?.method || requestEvent?.method || "GET").toUpperCase(),
          url: requestUrl,
          httpVersion: "HTTP/1.1",
          headers: requestHeaders,
          queryString: toHarQueryStringArray(requestUrl),
          cookies: [],
          headersSize: -1,
          bodySize: requestBodyText ? requestBodyText.length : 0,
          postData: requestBodyText
            ? {
                mimeType: firstNonEmptyString([getHarHeaderValue(requestHeaders, "content-type"), "text/plain"]),
                text: truncateDebugText(requestBodyText, 10000),
              }
            : undefined,
        },
        response: {
          status,
          statusText: String(event?.statusText || ""),
          httpVersion: "HTTP/1.1",
          headers: responseHeaders,
          cookies: [],
          redirectURL: "",
          headersSize: -1,
          bodySize: responseBodyText ? responseBodyText.length : -1,
          content: {
            size: responseBodyText.length,
            mimeType: responseMimeType,
            text: responseBodyText ? truncateDebugText(responseBodyText, 10000) : undefined,
          },
        },
        cache: {},
        timings: {
          send: 0,
          wait: durationMs,
          receive: 0,
        },
        _underpar: {
          source: "extension-restv2",
          requestorId: String(event?.requestorId || requestEvent?.requestorId || ""),
          mvpd: String(event?.mvpd || requestEvent?.mvpd || ""),
          requestScope: String(event?.requestScope || requestEvent?.requestScope || ""),
        },
      });
      continue;
    }

    if (event.phase === "token-request-attempt") {
      const key = getTokenKey(event);
      const queue = pendingTokenByKey.get(key) || [];
      queue.push(event);
      pendingTokenByKey.set(key, queue);
      continue;
    }

    if (event.phase !== "token-request-attempt-succeeded" && event.phase !== "token-request-attempt-failed") {
      continue;
    }

    const key = getTokenKey(event);
    const queue = pendingTokenByKey.get(key) || [];
    const requestEvent = queue.length > 0 ? queue.shift() : null;
    if (queue.length === 0) {
      pendingTokenByKey.delete(key);
    } else {
      pendingTokenByKey.set(key, queue);
    }

    const startedMs = pickFlowEventTimestampMs(requestEvent || event, Date.now());
    const endedMs = pickFlowEventTimestampMs(event, startedMs);
    const durationMs = Math.max(0, endedMs - startedMs);
    const requestUrl = String(requestEvent?.url || event?.url || `${ADOBE_SP_BASE}/o/client/token`);
    const requestMethod = String(requestEvent?.method || event?.method || "POST").toUpperCase();
    const requestHeaders = toHarHeadersArray(requestEvent?.requestHeaders || event?.requestHeaders || {});
    const responseHeaders = toHarHeadersArray(event?.responseHeaders || {});
    const requestBodyText = String(requestEvent?.requestBodyPreview || event?.requestBodyPreview || "");
    const responseBodyText = String(event?.responsePreview || event?.error || "");
    const status = Number(event?.status || 0);
    const statusText = String(event?.statusText || event?.error || "");
    const tokenBootstrapComment = "DCR credentialed token bootstrap";
    const clientIdIncluded =
      /(?:^|[?&])client_id=/.test(requestUrl) || /(?:^|&)client_id=/.test(requestBodyText);
    const clientSecretIncluded =
      /(?:^|[?&])client_secret=/.test(requestUrl) || /(?:^|&)client_secret=/.test(requestBodyText);
    const responseMimeType = firstNonEmptyString([
      getHarHeaderValue(responseHeaders, "content-type").split(";")[0],
      "application/json",
    ]);

    entries.push({
      startedDateTime: new Date(startedMs).toISOString(),
      time: durationMs,
      request: {
        method: requestMethod,
        url: requestUrl,
        httpVersion: "HTTP/1.1",
        headers: requestHeaders,
        queryString: toHarQueryStringArray(requestUrl),
        cookies: [],
        headersSize: -1,
        bodySize: requestBodyText ? requestBodyText.length : 0,
        postData: requestBodyText
          ? {
              mimeType: firstNonEmptyString([getHarHeaderValue(requestHeaders, "content-type"), "text/plain"]),
              text: truncateDebugText(requestBodyText, 10000),
            }
          : undefined,
      },
      response: {
        status,
        statusText: statusText || (status > 0 ? "" : "TOKEN_REQUEST_FAILED"),
        httpVersion: "HTTP/1.1",
        headers: responseHeaders,
        cookies: [],
        redirectURL: "",
        headersSize: -1,
        bodySize: responseBodyText ? responseBodyText.length : -1,
        content: {
          size: responseBodyText.length,
          mimeType: responseMimeType,
          text: responseBodyText ? truncateDebugText(responseBodyText, 10000) : undefined,
        },
      },
      cache: {},
      timings: {
        send: 0,
        wait: durationMs,
        receive: 0,
      },
      _underpar: {
        source: "extension-token",
        requestorId: String(event?.requestorId || requestEvent?.requestorId || ""),
        mvpd: String(event?.mvpd || requestEvent?.mvpd || ""),
        requestScope: String(event?.requestScope || requestEvent?.requestScope || ""),
        transport: String(event?.transport || requestEvent?.transport || ""),
        attemptId: String(event?.attemptId || requestEvent?.attemptId || ""),
        comment: tokenBootstrapComment,
        authFlow: "dcr-client-credentials",
        clientIdIncluded,
        clientSecretIncluded,
        credentialsIncluded: clientIdIncluded && clientSecretIncluded,
      },
    });

    const completedAttemptId = String(event?.attemptId || requestEvent?.attemptId || "").trim();
    if (completedAttemptId) {
      completedTokenAttemptIds.add(completedAttemptId);
    }
  }

  for (const queue of pendingApiByKey.values()) {
    for (const requestEvent of queue) {
      const startedMs = pickFlowEventTimestampMs(requestEvent, Date.now());
      const requestHeaders = toHarHeadersArray(requestEvent?.requestHeaders || {});
      const requestBodyText = String(requestEvent?.requestBodyPreview || "");
      const requestUrl = String(requestEvent?.url || "");
      entries.push({
        startedDateTime: new Date(startedMs).toISOString(),
        time: 0,
        request: {
          method: String(requestEvent?.method || "GET").toUpperCase(),
          url: requestUrl,
          httpVersion: "HTTP/1.1",
          headers: requestHeaders,
          queryString: toHarQueryStringArray(requestUrl),
          cookies: [],
          headersSize: -1,
          bodySize: requestBodyText ? requestBodyText.length : 0,
          postData: requestBodyText
            ? {
                mimeType: firstNonEmptyString([getHarHeaderValue(requestHeaders, "content-type"), "text/plain"]),
                text: truncateDebugText(requestBodyText, 10000),
              }
            : undefined,
        },
        response: {
          status: 0,
          statusText: "NO_RESPONSE",
          httpVersion: "HTTP/1.1",
          headers: [],
          cookies: [],
          redirectURL: "",
          headersSize: -1,
          bodySize: -1,
          content: {
            size: 0,
            mimeType: "application/json",
          },
        },
        cache: {},
        timings: {
          send: 0,
          wait: 0,
          receive: 0,
        },
        _underpar: {
          source: "extension-restv2",
          requestorId: String(requestEvent?.requestorId || ""),
          mvpd: String(requestEvent?.mvpd || ""),
          requestScope: String(requestEvent?.requestScope || ""),
        },
      });
    }
  }

  for (const queue of pendingTokenByKey.values()) {
    for (const requestEvent of queue) {
      const pendingAttemptId = String(requestEvent?.attemptId || "").trim();
      if (pendingAttemptId && completedTokenAttemptIds.has(pendingAttemptId)) {
        continue;
      }
      const startedMs = pickFlowEventTimestampMs(requestEvent, Date.now());
      const requestUrl = String(requestEvent?.url || `${ADOBE_SP_BASE}/o/client/token`);
      const requestMethod = String(requestEvent?.method || "POST").toUpperCase();
      const requestHeaders = toHarHeadersArray(requestEvent?.requestHeaders || {});
      const requestBodyText = String(requestEvent?.requestBodyPreview || "");
      const tokenBootstrapComment = "DCR credentialed token bootstrap";
      const clientIdIncluded =
        /(?:^|[?&])client_id=/.test(requestUrl) || /(?:^|&)client_id=/.test(requestBodyText);
      const clientSecretIncluded =
        /(?:^|[?&])client_secret=/.test(requestUrl) || /(?:^|&)client_secret=/.test(requestBodyText);
      entries.push({
        startedDateTime: new Date(startedMs).toISOString(),
        time: 0,
        request: {
          method: requestMethod,
          url: requestUrl,
          httpVersion: "HTTP/1.1",
          headers: requestHeaders,
          queryString: toHarQueryStringArray(requestUrl),
          cookies: [],
          headersSize: -1,
          bodySize: requestBodyText ? requestBodyText.length : 0,
          postData: requestBodyText
            ? {
                mimeType: firstNonEmptyString([getHarHeaderValue(requestHeaders, "content-type"), "text/plain"]),
                text: truncateDebugText(requestBodyText, 10000),
              }
            : undefined,
        },
        response: {
          status: 0,
          statusText: "NO_RESPONSE",
          httpVersion: "HTTP/1.1",
          headers: [],
          cookies: [],
          redirectURL: "",
          headersSize: -1,
          bodySize: -1,
          content: {
            size: 0,
            mimeType: "application/json",
          },
        },
        cache: {},
        timings: {
          send: 0,
          wait: 0,
          receive: 0,
        },
        _underpar: {
          source: "extension-token",
          requestorId: String(requestEvent?.requestorId || ""),
          mvpd: String(requestEvent?.mvpd || ""),
          requestScope: String(requestEvent?.requestScope || ""),
          transport: String(requestEvent?.transport || ""),
          attemptId: String(requestEvent?.attemptId || ""),
          comment: tokenBootstrapComment,
          authFlow: "dcr-client-credentials",
          clientIdIncluded,
          clientSecretIncluded,
          credentialsIncluded: clientIdIncluded && clientSecretIncluded,
        },
      });
    }
  }

  for (const queue of pendingCmByKey.values()) {
    for (const requestEvent of queue) {
      const startedMs = pickFlowEventTimestampMs(requestEvent, Date.now());
      const requestUrl = String(requestEvent?.url || requestEvent?.endpointUrl || "");
      const requestMethod = String(requestEvent?.method || "GET").toUpperCase();
      entries.push({
        startedDateTime: new Date(startedMs).toISOString(),
        time: 0,
        request: {
          method: requestMethod,
          url: requestUrl,
          httpVersion: "HTTP/1.1",
          headers: [],
          queryString: toHarQueryStringArray(requestUrl),
          cookies: [],
          headersSize: -1,
          bodySize: 0,
        },
        response: {
          status: 0,
          statusText: "NO_RESPONSE",
          httpVersion: "HTTP/1.1",
          headers: [],
          cookies: [],
          redirectURL: "",
          headersSize: -1,
          bodySize: -1,
          content: {
            size: 0,
            mimeType: "application/json",
          },
        },
        cache: {},
        timings: {
          send: 0,
          wait: 0,
          receive: 0,
        },
        _underpar: {
          source: "extension-cm",
          phase: normalizeCmPhase(requestEvent),
          authMode: String(requestEvent?.authMode || ""),
          contextLabel: String(requestEvent?.contextLabel || ""),
          requestorId: String(requestEvent?.requestorId || ""),
          mvpd: String(requestEvent?.mvpd || ""),
          programmerId: String(requestEvent?.programmerId || ""),
          operationKey: String(requestEvent?.operationKey || ""),
          cardId: String(requestEvent?.cardId || ""),
        },
      });
    }
  }

  return entries;
}

function shouldExcludeInternalExtensionHarEntry(entry = null) {
  if (!entry || typeof entry !== "object") {
    return false;
  }

  const requestUrl = String(entry?.request?.url || "").trim();
  if (!requestUrl) {
    return false;
  }

  try {
    const parsed = new URL(requestUrl);
    return parsed.protocol === "chrome-extension:" || parsed.protocol === "moz-extension:";
  } catch {
    return /^chrome-extension:\/\//i.test(requestUrl) || /^moz-extension:\/\//i.test(requestUrl);
  }
}

function buildHarLogFromFlowSnapshot(flowSnapshot, context = null, logoutResult = null) {
  const flowEvents = Array.isArray(flowSnapshot?.events) ? flowSnapshot.events : [];
  const rawEntries = [...buildWebRequestHarEntries(flowEvents, context), ...buildExtensionHarEntries(flowEvents)];
  const entries = rawEntries
    .filter((entry) => !shouldExcludeInternalExtensionHarEntry(entry))
    .sort((a, b) => {
      const left = Date.parse(a?.startedDateTime || "") || 0;
      const right = Date.parse(b?.startedDateTime || "") || 0;
      return left - right;
    });

  const startedDateTime = entries[0]?.startedDateTime || new Date().toISOString();
  const pageId = `page-${String(flowSnapshot?.flowId || "capture")}`;
  const manifestVersion = chrome.runtime.getManifest().version;
  const pageTitle =
    String(context?.serviceType || "").trim().toLowerCase().includes("esm")
      ? "ESM session"
      : context?.requestorId && context?.mvpd
        ? formatRestV2RequestorMvpdDisplay(
            String(context.requestorId || "").trim(),
            String(context.mvpd || "").trim(),
            String(context?.mvpdName || "").trim()
              ? {
                  id: String(context.mvpd || "").trim(),
                  name: String(context.mvpdName || "").trim(),
                }
              : null,
            { separator: " x " }
          )
        : "MVPD session";
  const compactContext = context
    ? {
        serviceType: String(context.serviceType || ""),
        programmerId: String(context.programmerId || ""),
        requestorId: String(context.requestorId || ""),
        mvpd: String(context.mvpd || ""),
        requestorIds: Array.isArray(context.requestorIds) ? context.requestorIds.slice(0, 24) : [],
        mvpdIds: Array.isArray(context.mvpdIds) ? context.mvpdIds.slice(0, 24) : [],
        serviceProviderId: String(context.serviceProviderId || ""),
        appGuid: String(context?.appInfo?.guid || ""),
        appName: String(context?.appInfo?.appName || ""),
        redirectUrl: String(context?.redirectUrl || ""),
      }
    : null;

  return {
    log: {
      version: "1.2",
      creator: {
        name: "UnderPAR",
        version: String(manifestVersion || "0"),
      },
      browser: {
        name: "Chrome Extension",
        version: String(manifestVersion || "0"),
      },
      pages: [
        {
          startedDateTime,
          id: pageId,
          title: pageTitle,
          pageTimings: {},
        },
      ],
      entries: entries.map((entry) => ({
        ...entry,
        pageref: pageId,
      })),
      _underpar: {
        flowId: String(flowSnapshot?.flowId || ""),
        eventCount: flowEvents.length,
        context: compactContext,
        logoutResult,
        generatedAt: new Date().toISOString(),
      },
    },
  };
}

function sanitizeHarFileSegment(value, fallback = "capture") {
  const normalized = String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return normalized || fallback;
}

function sanitizeDownloadFileSegment(value, fallback = "download") {
  const normalized = String(value || "")
    .trim()
    .replace(/[^\w.-]+/g, "_")
    .replace(/^_+|_+$/g, "");
  return normalized || fallback;
}

function decodeBase64ToUint8Array(base64Value = "") {
  const normalized = String(base64Value || "").replace(/\s+/g, "");
  if (!normalized) {
    return new Uint8Array();
  }
  const raw = atob(normalized);
  const bytes = new Uint8Array(raw.length);
  for (let index = 0; index < raw.length; index += 1) {
    bytes[index] = raw.charCodeAt(index);
  }
  return bytes;
}

async function downloadBlobFile(blob, fileName = "underpar-download.bin") {
  if (!(blob instanceof Blob)) {
    throw new Error("Unable to build the requested UnderPAR download.");
  }
  const normalizedFileName = String(fileName || "").trim() || "underpar-download.bin";
  const objectUrl = URL.createObjectURL(blob);
  let downloadStarted = false;
  try {
    if (chrome?.downloads?.download) {
      await chrome.downloads.download({
        url: objectUrl,
        filename: normalizedFileName,
        saveAs: false,
        conflictAction: "uniquify",
      });
      downloadStarted = true;
    }
  } catch {
    downloadStarted = false;
  }
  if (!downloadStarted) {
    const anchor = document.createElement("a");
    anchor.href = objectUrl;
    anchor.download = normalizedFileName;
    anchor.style.display = "none";
    document.body.appendChild(anchor);
    anchor.click();
    anchor.remove();
  }
  setTimeout(() => {
    URL.revokeObjectURL(objectUrl);
  }, 30000);
}

async function downloadBinaryFile(bytes, fileName = "underpar-download.bin", mimeType = "application/octet-stream") {
  const normalizedBytes =
    bytes instanceof Uint8Array
      ? bytes
      : ArrayBuffer.isView(bytes)
        ? new Uint8Array(bytes.buffer, bytes.byteOffset, bytes.byteLength)
        : bytes instanceof ArrayBuffer
          ? new Uint8Array(bytes)
          : new Uint8Array();
  if (!normalizedBytes.byteLength) {
    throw new Error("The requested UnderPAR download was empty.");
  }
  await downloadBlobFile(new Blob([normalizedBytes], { type: mimeType }), fileName);
}

function downloadJsonFile(payload, fileName = "underpar-export.json") {
  const json = JSON.stringify(payload, null, 2);
  const blob = new Blob([json], { type: "application/json;charset=utf-8" });
  const objectUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = objectUrl;
  anchor.download = String(fileName || "underpar-export.json");
  anchor.style.display = "none";
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  setTimeout(() => {
    URL.revokeObjectURL(objectUrl);
  }, 1500);
}

function getCmTenantDebugOrgId(url = "") {
  const raw = String(url || "").trim();
  if (!raw) {
    return "unknown";
  }
  try {
    const parsed = new URL(raw);
    return sanitizeDownloadFileSegment(parsed.searchParams.get("orgId") || "unknown", "unknown");
  } catch {
    return "unknown";
  }
}

function buildCmTenantDebugFileName(url = "", status = 0) {
  const orgId = getCmTenantDebugOrgId(url);
  const normalizedStatus = Number.isFinite(Number(status)) ? Number(status) : 0;
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  return `underpar-cm-tenants-${orgId}-manual-get-http-${normalizedStatus || "na"}-${stamp}.json`;
}

async function performCmTenantManualGet(url = "") {
  const requestUrl = normalizeCmUrl(url);
  if (!requestUrl) {
    return {
      ok: false,
      status: 0,
      statusText: "invalid_url",
      url: String(url || ""),
      headers: {},
      bodyText: "",
      parsed: null,
      error: "Invalid CM tenant URL.",
    };
  }
  const requestInit = {
    method: "GET",
    credentials: "include",
    headers: {
      Accept: "*/*",
      Origin: "https://cdn.experience.adobe.net",
      Referer: "https://cdn.experience.adobe.net/",
    },
  };
  try {
    const response = isCmRelayEligibleUrl(requestUrl)
      ? await relayCmFetch(requestUrl, requestInit)
      : await fetch(requestUrl, {
          method: "GET",
          mode: "cors",
          credentials: "include",
          referrerPolicy: "no-referrer",
          headers: requestInit.headers,
        });
    const bodyText = await response.text().catch(() => "");
    const parsed = parseJsonText(bodyText, null);
    const headers = {};
    if (response?.headers?.forEach) {
      response.headers.forEach((value, key) => {
        headers[String(key || "").trim()] = String(value || "");
      });
    }
    return {
      ok: Boolean(response?.ok),
      status: Number(response?.status || 0),
      statusText: String(response?.statusText || ""),
      url: String(response?.url || requestUrl),
      headers,
      bodyText,
      parsed,
      error: "",
    };
  } catch (error) {
    return {
      ok: false,
      status: 0,
      statusText: "",
      url: requestUrl,
      headers: {},
      bodyText: "",
      parsed: null,
      error: error instanceof Error ? error.message : String(error),
    };
  }
}

async function maybeExportCmTenantDebugSnapshot(url = "", reason = "") {
  if (!CM_TENANT_DEBUG_EXPORT_ENABLED) {
    return;
  }
  const requestUrl = normalizeCmUrl(url);
  if (!requestUrl) {
    return;
  }
  if (state.cmTenantDebugExportedByUrl.has(requestUrl)) {
    return;
  }
  state.cmTenantDebugExportedByUrl.add(requestUrl);

  const result = await performCmTenantManualGet(requestUrl);
  const payload = {
    exportedAt: new Date().toISOString(),
    reason: String(reason || "").trim(),
    underparVersion: String(chrome?.runtime?.getManifest?.()?.version || ""),
    request: {
      method: "GET",
      url: requestUrl,
      credentials: "include",
      headers: {
        Accept: "*/*",
        Origin: "https://cdn.experience.adobe.net",
        Referer: "https://cdn.experience.adobe.net/",
      },
    },
    response: {
      ok: Boolean(result?.ok),
      status: Number(result?.status || 0),
      statusText: String(result?.statusText || ""),
      url: String(result?.url || requestUrl),
      headers: result?.headers && typeof result.headers === "object" ? result.headers : {},
      bodyLength: String(result?.bodyText || "").length,
      error: String(result?.error || ""),
    },
    parsed: result?.parsed != null ? result.parsed : null,
    bodyText: String(result?.bodyText || ""),
  };

  const fileName = buildCmTenantDebugFileName(requestUrl, result?.status || 0);
  downloadJsonFile(payload, fileName);
  logDecisionPoint("CM tenant manual GET debug export downloaded", {
    url: requestUrl,
    orgId: getCmTenantDebugOrgId(requestUrl),
    status: Number(result?.status || 0),
    ok: Boolean(result?.ok),
    fileName,
    reason: String(reason || "").trim(),
  });
}

async function exportCmTenantDebugSnapshots(reason = "") {
  const urls = (Array.isArray(CM_TENANT_DEBUG_EXPORT_URLS) ? CM_TENANT_DEBUG_EXPORT_URLS : [])
    .map((value) => normalizeCmUrl(value))
    .filter(Boolean);
  for (const url of urls) {
    await maybeExportCmTenantDebugSnapshot(url, reason);
  }
}

function isRestV2EntitlementSignalValue(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized) {
    return false;
  }
  return (
    normalized.includes("/decisions/") ||
    normalized.includes("preauthorize") ||
    normalized.includes("authorize") ||
    normalized.includes("entitlement")
  );
}

function summarizeRestV2EntitlementPhaseSignals(flowSnapshot = null) {
  const flowEvents = Array.isArray(flowSnapshot?.events) ? flowSnapshot.events : [];
  let signalCount = 0;
  let deniedCount = 0;
  let errorCount = 0;
  const samples = [];

  const pushSample = (source, method, url, status, statusText) => {
    if (samples.length >= 8) {
      return;
    }
    samples.push({
      source: String(source || "").trim(),
      method: String(method || "").trim().toUpperCase(),
      url: String(url || "").trim(),
      status: Number(status || 0),
      statusText: String(statusText || "").trim(),
    });
  };

  flowEvents.forEach((event) => {
    if (!event || typeof event !== "object") {
      return;
    }
    if (event.source === "web-request") {
      const url = String(event?.url || "").trim();
      if (!isRestV2EntitlementSignalValue(url)) {
        return;
      }
      const status = Number(event?.statusCode || 0);
      const statusText = String(event?.statusLine || "").trim();
      signalCount += 1;
      if (status === 401 || status === 403) {
        deniedCount += 1;
      }
      if (status >= 400) {
        errorCount += 1;
      }
      pushSample("web-request", event?.method, url, status, statusText);
      return;
    }

    if (event.source === "extension" && String(event?.phase || "").trim() === "restv2-response") {
      const requestScope = String(event?.requestScope || "").trim();
      const url = String(event?.url || "").trim();
      if (!isRestV2EntitlementSignalValue(requestScope) && !isRestV2EntitlementSignalValue(url)) {
        return;
      }
      const status = Number(event?.status || 0);
      const statusText = String(event?.statusText || "").trim();
      signalCount += 1;
      if (status === 401 || status === 403) {
        deniedCount += 1;
      }
      if (status >= 400) {
        errorCount += 1;
      }
      pushSample("extension", event?.method, url, status, statusText);
    }
  });

  return {
    signalCount,
    deniedCount,
    errorCount,
    hasEntitlementPhase: signalCount > 0,
    samples,
  };
}

function buildRestV2HarFilename(context = null, logoutResult = null, profileCheckResult = null) {
  const requestor = sanitizeHarFileSegment(context?.requestorId || "requestor", "requestor");
  const mvpd = sanitizeHarFileSegment(context?.mvpd || "mvpd", "mvpd");
  const hasProfile = Boolean(profileCheckResult?.ok) && Number(profileCheckResult?.profileCount || 0) > 0;
  const mode = logoutResult?.performed ? "full-login-logout" : hasProfile ? "login-profile-retained" : "login-no-active-profile";
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  return `underpar-restv2-${requestor}-${mvpd}-${mode}-${stamp}.har`;
}

function downloadHarFile(harPayload, fileName) {
  const json = JSON.stringify(harPayload, null, 2);
  const blob = new Blob([json], { type: "application/json;charset=utf-8" });
  const objectUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = objectUrl;
  anchor.download = fileName;
  anchor.style.display = "none";
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  setTimeout(() => {
    URL.revokeObjectURL(objectUrl);
  }, 1500);
}

async function exportBlondieTimeWorkspacePdf(tabId, fileName = "underpar_bt_ws_session.pdf") {
  const normalizedTabId = Math.max(0, Number(tabId || 0));
  if (!chrome?.debugger || !normalizedTabId) {
    throw new Error("Blondie Time Workspace tab is no longer available for PDF export.");
  }

  const target = { tabId: normalizedTabId };
  const tab = await chrome.tabs.get(normalizedTabId).catch(() => null);
  if (!tab || !blondieTimeWorkspaceIsWorkspaceTab(tab)) {
    throw new Error("Blondie Time Workspace tab is no longer available for PDF export.");
  }

  const normalizedFileNameBase = sanitizeDownloadFileSegment(String(fileName || "").trim(), "underpar_bt_ws_session.pdf");
  const normalizedFileName = normalizedFileNameBase.toLowerCase().endsWith(".pdf")
    ? normalizedFileNameBase
    : `${normalizedFileNameBase}.pdf`;
  let debuggerAttached = false;

  try {
    await chrome.debugger.attach(target, AUTH_DEBUGGER_PROTOCOL_VERSION);
    debuggerAttached = true;
    await chrome.debugger.sendCommand(target, "Page.enable");
    await chrome.debugger.sendCommand(target, "Emulation.setEmulatedMedia", {
      media: "print",
    });
    await sleepMs(80);
    const pdfResult = await chrome.debugger.sendCommand(target, "Page.printToPDF", {
      landscape: true,
      printBackground: true,
      preferCSSPageSize: true,
      displayHeaderFooter: false,
      scale: 1,
    });
    const pdfData = String(pdfResult?.data || "").trim();
    if (!pdfData) {
      throw new Error("BT monitoring session PDF returned no data.");
    }
    await downloadBinaryFile(decodeBase64ToUint8Array(pdfData), normalizedFileName, "application/pdf");
    return {
      ok: true,
      fileName: normalizedFileName,
    };
  } catch (error) {
    throw new Error(error instanceof Error ? error.message : String(error));
  } finally {
    if (debuggerAttached) {
      try {
        await chrome.debugger.sendCommand(target, "Emulation.setEmulatedMedia", {
          media: "screen",
        });
      } catch {
        // Ignore media reset failures during teardown.
      }
      try {
        await chrome.debugger.detach(target);
      } catch {
        // Ignore detach failures during teardown.
      }
    }
  }
}

function normalizeBlondieTimeCloseGuardCard(card = null) {
  if (!card || typeof card !== "object") {
    return null;
  }
  const endpointUrl = String(card?.endpointUrl || "").trim();
  const requestUrl = String(card?.requestUrl || "").trim();
  const cardId = String(card?.cardId || card?.originCardKey || endpointUrl || requestUrl || "").trim();
  if (!cardId) {
    return null;
  }
  return {
    cardId,
    originCardKey: String(card?.originCardKey || "").trim(),
    endpointUrl,
    requestUrl: requestUrl || endpointUrl,
    zoomKey: String(card?.zoomKey || "").trim(),
    columns: Array.isArray(card?.columns) ? card.columns.map((value) => String(value || "").trim()).filter(Boolean) : [],
    displayNodeLabel: String(card?.displayNodeLabel || "").trim(),
    preserveQueryContext: card?.preserveQueryContext === true,
    presetLocalFilterBootstrapPending: card?.presetLocalFilterBootstrapPending === true,
    seedEndpointUrl: String(card?.seedEndpointUrl || "").trim(),
    seedRequestUrl: String(card?.seedRequestUrl || "").trim(),
    seedLocalColumnFilters: cloneJsonLikeValue(card?.seedLocalColumnFilters, {}),
    seedLocalColumnExclusions: cloneJsonLikeValue(card?.seedLocalColumnExclusions, {}),
    seedPresetLocalFilterBootstrapPending: card?.seedPresetLocalFilterBootstrapPending === true,
    localColumnFilters: cloneJsonLikeValue(card?.localColumnFilters, {}),
    localColumnExclusions: cloneJsonLikeValue(card?.localColumnExclusions, {}),
  };
}

function normalizeBlondieTimeCloseGuardSnapshot(value = null) {
  if (!value || typeof value !== "object") {
    return null;
  }
  return {
    schemaVersion: Math.max(1, Number(value?.schemaVersion || 1)),
    workspace: String(value?.workspace || "bt").trim().toLowerCase() || "bt",
    capturedAt: Math.max(0, Number(value?.capturedAt || 0)),
    windowId: Math.max(0, Number(value?.windowId || 0)),
    tabId: Math.max(0, Number(value?.tabId || 0)),
    runId: String(value?.runId || "").trim(),
    workspaceContextKey: String(value?.workspaceContextKey || "").trim(),
    programmerId: String(value?.programmerId || "").trim(),
    programmerName: String(value?.programmerName || "").trim(),
    activeRuntime: value?.activeRuntime === true,
    lapCount: Math.max(0, Number(value?.lapCount || 0)),
    sessionStartedAt: Math.max(0, Number(value?.sessionStartedAt || 0)),
    sessionStoppedAt: Math.max(0, Number(value?.sessionStoppedAt || 0)),
    sessionWindow: {
      start: String(value?.sessionWindow?.start || "").trim(),
      end: String(value?.sessionWindow?.end || "").trim(),
    },
    cards: (Array.isArray(value?.cards) ? value.cards : []).map((card) => normalizeBlondieTimeCloseGuardCard(card)).filter(Boolean),
  };
}

async function readBlondieTimeCloseGuardSnapshot() {
  try {
    const payload = await chrome.storage.local.get(BLONDIE_TIME_CLOSE_GUARD_STORAGE_KEY);
    return normalizeBlondieTimeCloseGuardSnapshot(payload?.[BLONDIE_TIME_CLOSE_GUARD_STORAGE_KEY] || null);
  } catch {
    return null;
  }
}

async function clearBlondieTimeCloseGuardSnapshot() {
  try {
    await chrome.storage.local.remove(BLONDIE_TIME_CLOSE_GUARD_STORAGE_KEY);
  } catch {
    // Ignore close-guard cleanup failures.
  }
}

async function buildBlondieTimeSessionCsvExport(esmWorkspaceState, requestToken, cards = [], sessionWindow = {}, options = {}) {
  const normalizedCards = Array.isArray(cards) ? cards : [];
  const requestWindowStart = String(sessionWindow?.start || "").trim();
  const requestWindowEnd = String(sessionWindow?.end || "").trim();
  if (!requestWindowStart || !requestWindowEnd) {
    return { ok: false, error: "A BT monitoring session window is required for full CSV export." };
  }
  if (normalizedCards.length === 0) {
    return { ok: false, error: "No BT analysis tables were available for full CSV export." };
  }

  const combinedColumns = ["Analysis Table"];
  const columnSeen = new Set(combinedColumns);
  const rowMaps = [];
  const targetWindowId = Number(options?.targetWindowId || 0);
  const defaultWorkspaceWindowId = Number(options?.defaultWorkspaceWindowId || 0);

  for (const card of normalizedCards) {
    const endpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, card?.endpointUrl, card || {});
    if (!endpoint) {
      return { ok: false, error: "A BT analysis table no longer maps to an active ESM endpoint." };
    }
    let capturedResult = null;
    await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, String(card?.cardId || generateRequestId()), requestToken, {
      emitStart: false,
      requestSource: "workspace",
      targetWindowId,
      defaultWorkspaceWindowId,
      workspaceMessageSender(eventName, payload) {
        if (String(eventName || "").trim().toLowerCase() === "report-result") {
          capturedResult = payload && typeof payload === "object" ? payload : null;
        }
        return undefined;
      },
      requestUrlOverride: buildBlondieTimeEsmSessionRequestUrlOverride(card, sessionWindow),
      skipOriginLookup: true,
      originCardKey: card?.originCardKey,
      presetLocalFilterBootstrapPending: card?.presetLocalFilterBootstrapPending === true,
      seedEndpointUrl: card?.seedEndpointUrl,
      seedRequestUrl: card?.seedRequestUrl,
      seedLocalColumnFilters: card?.seedLocalColumnFilters,
      seedLocalColumnExclusions: card?.seedLocalColumnExclusions,
      seedPresetLocalFilterBootstrapPending: card?.seedPresetLocalFilterBootstrapPending === true,
      localColumnFilters: card?.localColumnFilters,
      localColumnExclusions: card?.localColumnExclusions,
      displayNodeLabel: String(card?.displayNodeLabel || "").trim(),
    });
    if (!capturedResult?.ok) {
      return {
        ok: false,
        error: capturedResult?.error || "Unable to fetch the full BT monitoring session CSV from ESM.",
      };
    }

    const analysisTableLabel = firstNonEmptyString([
      capturedResult?.displayNodeLabel,
      card?.displayNodeLabel,
      card?.endpointUrl,
      card?.cardId,
      "Analysis Table",
    ]);
    const cardColumns = [];
    const cardColumnSeen = new Set();
    (Array.isArray(capturedResult?.columns) ? capturedResult.columns : []).forEach((columnName) => {
      const normalizedColumn = String(columnName || "").trim();
      if (!normalizedColumn || cardColumnSeen.has(normalizedColumn)) {
        return;
      }
      cardColumnSeen.add(normalizedColumn);
      cardColumns.push(normalizedColumn);
    });
    (Array.isArray(capturedResult?.rows) ? capturedResult.rows : []).forEach((row) => {
      Object.keys(row && typeof row === "object" ? row : {}).forEach((columnName) => {
        const normalizedColumn = String(columnName || "").trim();
        if (!normalizedColumn || cardColumnSeen.has(normalizedColumn)) {
          return;
        }
        cardColumnSeen.add(normalizedColumn);
        cardColumns.push(normalizedColumn);
      });
    });
    cardColumns.forEach((columnName) => {
      if (columnSeen.has(columnName)) {
        return;
      }
      columnSeen.add(columnName);
      combinedColumns.push(columnName);
    });
    (Array.isArray(capturedResult?.rows) ? capturedResult.rows : []).forEach((row) => {
      rowMaps.push({
        "Analysis Table": analysisTableLabel,
        ...(row && typeof row === "object" ? row : {}),
      });
    });
  }

  const csvText = [combinedColumns]
    .concat(rowMaps.map((rowMap) => combinedColumns.map((columnName) => (rowMap?.[columnName] == null ? "" : String(rowMap[columnName])))))
    .map((row) => row.map((value) => escapeUnderparCsvValue(value)).join(","))
    .join("\r\n");
  const programmerSegment = sanitizeDownloadFileSegment(
    firstNonEmptyString([options?.programmerId, esmWorkspaceState?.programmer?.programmerId, esmWorkspaceState?.programmer?.displayName, "media-company"]),
    "media-company"
  ).slice(0, 40);
  const startSegment = sanitizeDownloadFileSegment(requestWindowStart, "start").slice(0, 32);
  const endSegment = sanitizeDownloadFileSegment(requestWindowEnd, "end").slice(0, 32);
  return {
    ok: true,
    csvText,
    rowCount: rowMaps.length,
    tableCount: normalizedCards.length,
    requestWindowStart,
    requestWindowEnd,
    fileName: [
      "underpar",
      "bt_ws",
      "session",
      programmerSegment || "media-company",
      startSegment || "start",
      endSegment || "end",
    ]
      .filter(Boolean)
      .join("_")
      .concat(".csv"),
  };
}

async function autoExportBlondieTimeCloseGuardSnapshotForTab(tabId = 0) {
  const normalizedTabId = Math.max(0, Number(tabId || 0));
  if (!normalizedTabId) {
    return false;
  }
  const snapshot = await readBlondieTimeCloseGuardSnapshot();
  if (!snapshot || Number(snapshot.tabId || 0) !== normalizedTabId) {
    return false;
  }
  if (!snapshot.activeRuntime || Number(snapshot.lapCount || 0) < BLONDIE_TIME_CLOSE_GUARD_MIN_LAPS) {
    await clearBlondieTimeCloseGuardSnapshot();
    return false;
  }

  let esmWorkspaceState = getActiveEsmWorkspaceState();
  if (!esmWorkspaceState) {
    esmWorkspaceState = await resolveEsmStateForWorkspaceAction({
      controllerWindowId: Number(snapshot.windowId || state.blondieTimeWorkspaceWindowId || 0),
      reason: "bt-close-auto-export",
    }).catch(() => null);
  }
  if (!esmWorkspaceState) {
    return false;
  }

  const requestToken = Number(state.premiumPanelRequestToken || 0);
  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    return false;
  }

  try {
    const exportResult = await buildBlondieTimeSessionCsvExport(esmWorkspaceState, requestToken, snapshot.cards, snapshot.sessionWindow, {
      targetWindowId: Number(snapshot.windowId || esmWorkspaceState.controllerWindowId || state.blondieTimeWorkspaceWindowId || 0),
      defaultWorkspaceWindowId: Number(snapshot.windowId || state.blondieTimeWorkspaceWindowId || 0),
      programmerId: snapshot.programmerId,
    });
    if (!exportResult?.ok) {
      return false;
    }
    await downloadBlobFile(
      new Blob([String(exportResult.csvText || "")], { type: "text/csv;charset=utf-8" }),
      String(exportResult.fileName || "underpar_bt_ws_session.csv")
    );
    await clearBlondieTimeCloseGuardSnapshot();
    return true;
  } catch (error) {
    console.warn("UnderPAR BT close-guard auto-export failed.", error);
    return false;
  }
}

async function stopRestV2MvpdRecording(section, programmer, appInfo) {
  if (state.restV2Stopping) {
    return;
  }
  state.restV2Stopping = true;
  let finalPanelMessage = "";
  let finalPanelType = "info";

  try {
    const closeButton = section?.querySelector(".rest-v2-close-login-btn");
    if (closeButton) {
      closeButton.disabled = true;
    }

    const activeFlowId = String(state.restV2DebugFlowId || "").trim();
    if (!activeFlowId) {
      state.restV2RecordingActive = false;
      state.restV2RecordingStartedAt = 0;
      state.restV2RecordingContext = null;
      finalPanelMessage = "No active recording session was found.";
      finalPanelType = "info";
      return;
    }

    const fallbackContextCandidate = buildCurrentRestV2SelectionContext(programmer, appInfo);
    const recordingContext =
      (state.restV2RecordingContext && typeof state.restV2RecordingContext === "object"
        ? state.restV2RecordingContext
        : null) || (fallbackContextCandidate.ok ? toRestV2RecordingContext(fallbackContextCandidate) : null);

    emitRestV2DebugEvent(activeFlowId, {
      source: "extension",
      phase: "recording-stop-request",
      requestorId: String(recordingContext?.requestorId || ""),
      mvpd: String(recordingContext?.mvpd || ""),
    });

    let profileCheckResult = {
      checked: false,
      ok: false,
      status: 0,
      statusText: "",
      profileCount: 0,
      responsePreview: "",
      url: "",
      error: "",
      responsePayload: null,
      harvestedProfile: null,
    };
    const harLogoutContext = {
      attempted: false,
      performed: false,
      actionName: "",
      actionType: "",
      logoutUrl: "",
      error: "",
    };
    let closeResult = { ok: true };
    let operationError = "";
    const hasRecordingContext = Boolean(
      recordingContext?.programmerId &&
        recordingContext?.appInfo?.guid &&
        recordingContext?.serviceProviderId &&
        recordingContext?.mvpd
    );

    try {
      if (hasRecordingContext) {
        const postAuthProbe = await probeRestV2PostAuthProfiles(recordingContext, activeFlowId, {
          scopePrefix: "profiles-stop",
          maxAttempts: REST_V2_POST_AUTH_PROFILE_CHECK_RETRIES,
          delayMs: REST_V2_POST_AUTH_PROFILE_CHECK_DELAY_MS,
        });
        profileCheckResult = postAuthProbe?.result || profileCheckResult;
        const activeWindowContext = {
          ok: true,
          programmerId: String(recordingContext.programmerId || "").trim(),
          requestorId: String(recordingContext.requestorId || "").trim(),
          mvpd: String(recordingContext.mvpd || "").trim(),
        };
        setRestV2ActiveProfileWindowState(activeWindowContext, isRestV2ProfileSessionActiveResult(profileCheckResult), {
          checkedAt: Date.now(),
          profileCount: Number(profileCheckResult?.profileCount || 0),
          status: Number(profileCheckResult?.status || 0),
          statusText: String(profileCheckResult?.statusText || "").trim(),
          error: String(profileCheckResult?.error || "").trim(),
          source: "recording-stop-profiles-check",
        });
        const harvestedProfile = storeRestV2ProfileHarvest(recordingContext, profileCheckResult, activeFlowId);
        if (harvestedProfile) {
          emitRestV2DebugEvent(activeFlowId, {
            source: "extension",
            phase: "profiles-harvested",
            requestorId: recordingContext.requestorId,
            mvpd: recordingContext.mvpd,
            subject: harvestedProfile.subject,
            sessionId: harvestedProfile.sessionId,
            profileCheckOutcome: harvestedProfile.profileCheckOutcome,
            profileCount: Number(harvestedProfile.profileCount || 0),
            profileHarvest: cloneJsonLikeValue(harvestedProfile, {}),
            profileCheck:
              harvestedProfile.profileCheck && typeof harvestedProfile.profileCheck === "object"
                ? { ...harvestedProfile.profileCheck }
                : null,
          });
        } else {
          clearRestV2ProfileHarvestForContext(recordingContext);
        }
        const explicitNoActiveProfile = isRestV2NoActiveProfileSignal(profileCheckResult);
        const checkedNoProfiles =
          profileCheckResult?.checked === true &&
          profileCheckResult?.ok === true &&
          Number(profileCheckResult?.profileCount || 0) === 0;
        if (explicitNoActiveProfile || checkedNoProfiles) {
          clearRestV2ProfileHarvestForContext(recordingContext);
        }

        const selectedProgrammer = resolveSelectedProgrammer();
        if (selectedProgrammer?.programmerId && selectedProgrammer.programmerId === recordingContext.programmerId) {
          const selectedServices = getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId);
          cmBroadcastSelectedControllerState(selectedProgrammer, selectedServices);
          const activeCmState = getActiveCmState();
          if (activeCmState && String(activeCmState.programmer?.programmerId || "") === String(selectedProgrammer.programmerId)) {
            cmBroadcastControllerState(activeCmState);
          }
        }
        refreshBobtoolsWorkspaceTools();
      }

      closeResult = await closeRestV2LoginAndReturn(section, {
        suppressStatus: true,
        phasePrefix: "recording-close",
      });
    } catch (error) {
      operationError = error instanceof Error ? error.message : String(error);
    }

    await waitForDelay(900);
    const stopResult = await stopRestV2DebugFlowAndSnapshot(activeFlowId, "user-stop");
    const entitlementPhaseSummary = stopResult?.flow ? summarizeRestV2EntitlementPhaseSignals(stopResult.flow) : null;
    if (entitlementPhaseSummary) {
      emitRestV2DebugEvent(activeFlowId, {
        source: "extension",
        phase: "recording-stop-entitlement-phase-summary",
        signalCount: Number(entitlementPhaseSummary.signalCount || 0),
        deniedCount: Number(entitlementPhaseSummary.deniedCount || 0),
        errorCount: Number(entitlementPhaseSummary.errorCount || 0),
        hasEntitlementPhase: entitlementPhaseSummary.hasEntitlementPhase === true,
        samples: Array.isArray(entitlementPhaseSummary.samples) ? entitlementPhaseSummary.samples.slice(0, 8) : [],
      });
    }

    state.restV2DebugFlowId = "";
    state.restV2RecordingActive = false;
    state.restV2RecordingStartedAt = 0;
    state.restV2RecordingContext = null;

    const profileVerdict = buildRestV2ProfileVerdict(profileCheckResult, recordingContext);
    let panelMessage = "";
    let panelType = operationError ? "error" : "success";
    let harFileName = "";

    if (stopResult?.flow) {
      const harPayload = buildHarLogFromFlowSnapshot(stopResult.flow, recordingContext, harLogoutContext);
      harFileName = buildRestV2HarFilename(recordingContext, harLogoutContext, profileCheckResult);
      downloadHarFile(harPayload, harFileName);

      const hasProfile = Boolean(profileCheckResult.ok) && Number(profileCheckResult.profileCount || 0) > 0;
      if (closeResult?.ok === false) {
        panelMessage = `Recording stopped. HAR downloaded as ${harFileName}. Login window close note: ${closeResult.error || "unknown"}.`;
        panelType = "error";
      } else if (operationError) {
        panelMessage = `Recording stopped. HAR downloaded as ${harFileName}. Operation note: ${operationError}`;
        panelType = "error";
      } else {
        panelMessage = hasProfile
          ? `Recording stopped. HAR downloaded as ${harFileName}. MVPD profile retained for Can I watch?.`
          : `Recording stopped. HAR downloaded as ${harFileName}.`;
        if (!hasProfile && entitlementPhaseSummary?.hasEntitlementPhase) {
          panelMessage += ` Entitlement phase activity was detected (${Number(
            entitlementPhaseSummary.signalCount || 0
          )} calls). A deny/reject is treated as authZ, not authN.`;
        }
      }
    } else {
      const failureReason = stopResult?.error || operationError || "Flow snapshot unavailable.";
      panelMessage = `Recording stopped, but HAR export failed: ${failureReason}`;
      panelType = "error";
    }

    if (profileVerdict) {
      panelMessage = `${panelMessage} ${profileVerdict.panelSuffix}`;
      if (panelType !== "error") {
        panelType = profileVerdict.panelType;
      }
      setStatus(profileVerdict.mainMessage, profileVerdict.mainType);
    }

    finalPanelMessage = panelMessage || (harFileName ? `Recording stopped. HAR downloaded as ${harFileName}.` : "Recording stopped.");
    finalPanelType = panelType;
  } finally {
    state.restV2DebugFlowId = "";
    state.restV2RecordingActive = false;
    state.restV2RecordingStartedAt = 0;
    state.restV2RecordingContext = null;
    state.restV2Stopping = false;
    syncRestV2LoginPanel(section, programmer, appInfo);
    if (finalPanelMessage) {
      setRestV2LoginPanelStatus(section, finalPanelMessage, finalPanelType);
    }
  }
}

function esmPartsToUtcMs(row) {
  const year = Number(row?.year ?? 1970);
  const month = Number(row?.month ?? 1);
  const day = Number(row?.day ?? 1);
  const hour = Number(row?.hour ?? 0);
  const minute = Number(row?.minute ?? 0);

  return (
    Date.UTC(
      Number.isFinite(year) ? year : 1970,
      Number.isFinite(month) ? month - 1 : 0,
      Number.isFinite(day) ? day : 1,
      Number.isFinite(hour) ? hour : 0,
      Number.isFinite(minute) ? minute : 0
    ) -
    ESM_SOURCE_UTC_OFFSET_MINUTES * 60 * 1000
  );
}

function getLastModifiedSourceTimezone(rawHttpDate) {
  if (rawHttpDate == null || typeof rawHttpDate !== "string") {
    return "";
  }
  const tail = rawHttpDate.trim().split(/\s+/).pop();
  if (!tail) {
    return "";
  }
  if (/^[A-Z]{2,4}$/i.test(tail)) {
    return tail.toUpperCase();
  }
  if (/^[+-]\d{4}$/.test(tail)) {
    return tail;
  }
  return "";
}

function formatLastModifiedForDisplay(rawHttpDate) {
  if (rawHttpDate == null || String(rawHttpDate).trim() === "") {
    return rawHttpDate;
  }
  const date = new Date(rawHttpDate);
  if (Number.isNaN(date.getTime())) {
    return rawHttpDate;
  }

  const formatter = new Intl.DateTimeFormat("en-US", {
    timeZone: CLIENT_TIMEZONE,
    month: "2-digit",
    day: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hourCycle: "h23",
    timeZoneName: "short",
  });

  const parts = formatter.formatToParts(date);
  const getPart = (type) => parts.find((part) => part.type === type)?.value ?? "";
  const tzName = getPart("timeZoneName");
  return `${getPart("month")}/${getPart("day")}/${getPart("year")} ${getPart("hour")}:${getPart("minute")}:${getPart("second")} ${tzName || CLIENT_TIMEZONE}`;
}

function esmToNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

function esmSafeRate(numerator, denominator) {
  const n = esmToNumber(numerator);
  const d = esmToNumber(denominator);
  if (n == null || d == null || d <= 0) {
    return null;
  }
  const rate = n / d;
  return Number.isFinite(rate) ? rate : null;
}

function getDefaultEsmSortStack() {
  return [{ col: "DATE", dir: "DESC" }];
}

function getEsmCellValue(row, columnKey, context) {
  if (columnKey === "DATE") {
    return esmPartsToUtcMs(row);
  }

  if (context.hasAuthN && columnKey === "AuthN Success") {
    const rate = esmSafeRate(row["authn-successful"], row["authn-attempts"]);
    return rate == null ? -1 : rate;
  }

  if (context.hasAuthZ && columnKey === "AuthZ Success") {
    const rate = esmSafeRate(row["authz-successful"], row["authz-attempts"]);
    return rate == null ? -1 : rate;
  }

  if (columnKey === "COUNT") {
    const value = esmToNumber(row.count);
    return value == null ? 0 : value;
  }

  const rawValue = row[columnKey];
  if (rawValue == null) {
    return "";
  }

  if (typeof rawValue === "number" && Number.isFinite(rawValue)) {
    return rawValue;
  }

  const converted = esmToNumber(rawValue);
  if (converted != null) {
    return converted;
  }

  return String(rawValue).toLowerCase();
}

function sortEsmRows(rows, sortStack, context) {
  const stack = Array.isArray(sortStack) && sortStack.length > 0 ? sortStack : getDefaultEsmSortStack();

  return [...rows].sort((left, right) => {
    for (const sortRule of stack) {
      const factor = sortRule.dir === "ASC" ? 1 : -1;
      const leftValue = getEsmCellValue(left, sortRule.col, context);
      const rightValue = getEsmCellValue(right, sortRule.col, context);

      if (leftValue < rightValue) {
        return -1 * factor;
      }
      if (leftValue > rightValue) {
        return 1 * factor;
      }
    }

    return getEsmCellValue(right, "DATE", context) - getEsmCellValue(left, "DATE", context);
  });
}

function downloadEsmCsv(rows, sortRule, context, fileName) {
  if (!Array.isArray(rows) || rows.length === 0) {
    return;
  }

  const sortedRows = sortEsmRows(rows, sortRule ? [sortRule] : getDefaultEsmSortStack(), context);
  const headers = Object.keys(sortedRows[0]);
  const lines = [
    headers.join(","),
    ...sortedRows.map((row) =>
      headers
        .map((header) => `"${String(row[header] ?? "").replace(/"/g, '""')}"`)
        .join(",")
    ),
  ];

  const blob = new Blob([lines.join("\n")], { type: "text/csv" });
  const blobUrl = URL.createObjectURL(blob);
  const downloadLink = document.createElement("a");
  downloadLink.href = blobUrl;
  downloadLink.download = fileName || "esm-report.csv";
  downloadLink.click();
  URL.revokeObjectURL(blobUrl);
}

function isEsmServiceRequestActive(section, requestToken, programmerId) {
  if (section?.__underparDetachedEsmState === true) {
    if (Number(requestToken || 0) !== Number(state.premiumPanelRequestToken || 0)) {
      return false;
    }
    const selected = resolveSelectedProgrammer();
    return Boolean(selected && selected.programmerId === programmerId);
  }
  if (!section || !section.isConnected) {
    return false;
  }
  if (requestToken !== state.premiumPanelRequestToken) {
    return false;
  }
  const selected = resolveSelectedProgrammer();
  return Boolean(selected && selected.programmerId === programmerId);
}

function resolveCurrentPremiumPanelRequestToken(programmerId = "", fallbackToken = 0) {
  const normalizedFallbackToken = Math.max(0, Number(fallbackToken || 0));
  const normalizedCurrentToken = Math.max(0, Number(state.premiumPanelRequestToken || 0));
  if (normalizedCurrentToken <= 0) {
    return normalizedFallbackToken;
  }
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return normalizedCurrentToken;
  }
  const selectedProgrammerId = String(resolveSelectedProgrammer()?.programmerId || "").trim();
  if (!selectedProgrammerId || selectedProgrammerId !== normalizedProgrammerId) {
    return normalizedFallbackToken;
  }
  return normalizedCurrentToken;
}

const CLICK_ESM_ZOOM_OPTIONS = ["", "YR", "MO", "DAY", "HR", "MIN"];
const CLICK_ESM_ZOOM_TOKEN_BY_KEY = {
  YR: "/year",
  MO: "/month",
  DAY: "/day",
  HR: "/hour",
  MIN: "/minute",
};

function clickEsmEscapeRegExp(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function clickEsmNormalizeSearchTerm(rawValue) {
  return String(rawValue || "")
    .toLowerCase()
    .split(" ")
    .join("");
}

function clickEsmNormalizeSearchColumns(columns = []) {
  const output = [];
  const seen = new Set();
  (Array.isArray(columns) ? columns : []).forEach((value) => {
    const normalized = String(value || "")
      .replace(/<[^>]*>/g, " ")
      .replace(/\s+/g, " ")
      .trim();
    if (!normalized) {
      return;
    }
    const lower = normalized.toLowerCase();
    // Match clickESM's visible dd.col-list corpus more closely:
    // keep legacy/deprecated dimensions searchable, but suppress the injected
    // media-company token that is not part of the original FINDIT surface.
    if (lower === "media-company" || seen.has(lower)) {
      return;
    }
    seen.add(lower);
    output.push(normalized);
  });
  return output;
}

function clickEsmGetZoomKey(endpoint) {
  const explicit = String(endpoint?.zoomKey || "").trim().toUpperCase();
  if (CLICK_ESM_ZOOM_OPTIONS.includes(explicit)) {
    return explicit;
  }

  const href = String(endpoint?.url || "");
  let detected = "";
  let bestIndex = -1;
  Object.entries(CLICK_ESM_ZOOM_TOKEN_BY_KEY).forEach(([key, token]) => {
    const index = href.lastIndexOf(token);
    if (index > bestIndex) {
      detected = key;
      bestIndex = index;
    }
  });
  return detected;
}

function stripServerManagedTimeParams(urlValue, baseUrl = window.location.href) {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return "";
  }
  try {
    const parsed = new URL(raw, baseUrl);
    parsed.searchParams.delete("start");
    parsed.searchParams.delete("end");
    return parsed.toString();
  } catch {
    return raw;
  }
}

function popupSafeDecodeUrlSegment(segment = "") {
  const raw = String(segment || "");
  try {
    return decodeURIComponent(raw);
  } catch {
    return raw;
  }
}

function popupParseEsmRawQueryPairs(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return [];
  }
  const queryIndex = raw.indexOf("?");
  if (queryIndex < 0) {
    return [];
  }
  const hashIndex = raw.indexOf("#", queryIndex + 1);
  const queryText = raw.slice(queryIndex + 1, hashIndex >= 0 ? hashIndex : undefined).trim();
  if (!queryText) {
    return [];
  }
  return queryText
    .split("&")
    .map((entry) => String(entry || "").trim())
    .filter(Boolean)
    .map((entry) => {
      const equalsIndex = entry.indexOf("=");
      if (equalsIndex < 0) {
        return {
          key: popupSafeDecodeUrlSegment(entry.replace(/\+/g, " ")),
          value: "",
          hasValue: false,
          hasAssignment: false,
        };
      }
      const value = entry.slice(equalsIndex + 1);
      return {
        key: popupSafeDecodeUrlSegment(entry.slice(0, equalsIndex).replace(/\+/g, " ")),
        value,
        hasValue: String(value || "").trim().length > 0,
        hasAssignment: true,
      };
    });
}

function normalizeEsmDisplayDimensionKey(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized) {
    return "";
  }
  return normalized.endsWith("!") ? normalized.slice(0, -1) : normalized;
}

function popupSerializeEsmRawQueryPairs(queryPairs = []) {
  return (Array.isArray(queryPairs) ? queryPairs : [])
    .map((pair) => {
      const key = encodeURIComponent(String(pair?.key || "").trim()).replace(/%20/g, "+");
      if (!key) {
        return "";
      }
      if (pair?.hasValue && String(pair?.value || "").trim().length > 0) {
        return `${key}=${String(pair?.value || "")}`;
      }
      if (pair?.hasAssignment === true) {
        return `${key}=`;
      }
      return key;
    })
    .filter(Boolean)
    .join("&");
}

function esmWorkspaceMergeLocalColumnFilters(...filterSources) {
  const merged = {};
  (Array.isArray(filterSources) ? filterSources : []).forEach((source) => {
    const normalized = esmWorkspaceNormalizeLocalColumnFilters(source);
    Object.entries(normalized).forEach(([columnName, values]) => {
      const current = new Set(Array.isArray(merged[columnName]) ? merged[columnName] : []);
      (Array.isArray(values) ? values : []).forEach((value) => {
        const normalizedValue = String(value || "").trim();
        if (normalizedValue) {
          current.add(normalizedValue);
        }
      });
      if (current.size > 0) {
        merged[columnName] = [...current].sort((left, right) =>
          String(left).localeCompare(String(right), undefined, { numeric: true, sensitivity: "base" })
        );
      }
    });
  });
  return merged;
}

function esmWorkspaceShouldApplyGlobalSeedLocalColumnFilters(requestSource = "") {
  const normalizedRequestSource = String(requestSource || "").trim().toLowerCase();
  if (!normalizedRequestSource) {
    return true;
  }
  if (normalizedRequestSource.startsWith("workspace") || normalizedRequestSource.includes("saved-query")) {
    return false;
  }
  return true;
}

function esmWorkspaceBuildGlobalSeedLocalColumnFilters(existingFilters = {}, requestSource = "") {
  if (!esmWorkspaceShouldApplyGlobalSeedLocalColumnFilters(requestSource)) {
    return {};
  }

  const normalizedExistingFilters = esmWorkspaceNormalizeLocalColumnFilters(existingFilters);
  const selections = getGlobalRequestorMvpdSelections();
  const nextFilters = {};

  if (
    Array.isArray(selections.requestorIds) &&
    selections.requestorIds.length > 0 &&
    !Object.prototype.hasOwnProperty.call(normalizedExistingFilters, "requestor-id")
  ) {
    nextFilters["requestor-id"] = selections.requestorIds.slice();
  }

  if (
    Array.isArray(selections.mvpdIds) &&
    selections.mvpdIds.length > 0 &&
    !Object.prototype.hasOwnProperty.call(normalizedExistingFilters, "mvpd")
  ) {
    nextFilters.mvpd = selections.mvpdIds.slice();
  }

  return nextFilters;
}

function esmWorkspaceExtractPresetLocalFilterContext(urlValue = "") {
  const rawUrl = String(urlValue || "").trim();
  if (!rawUrl) {
    return {
      baseUrl: "",
      localColumnFilters: {},
      localColumnExclusions: {},
      columns: [],
    };
  }

  const preservedPairs = [];
  const extractedFilters = {};
  const extractedExclusions = {};
  const extractedColumns = [];
  const extractedColumnSet = new Set();

  popupParseEsmRawQueryPairs(rawUrl).forEach((pair) => {
    const normalizedColumn = String(pair?.key || "").trim().toLowerCase();
    const exclusionColumn = normalizedColumn.endsWith("!") ? normalizedColumn.slice(0, -1) : "";
    const decodedValue = popupSafeDecodeUrlSegment(String(pair?.value || "").replace(/\+/g, " ")).trim();
    const isSupportedLocalFilter =
      pair?.hasValue === true &&
      normalizedColumn &&
      !/[!<>~]$/.test(normalizedColumn) &&
      normalizedColumn !== "media-company" &&
      !ESM_LOCAL_FILTER_EXCLUDED_COLUMNS.has(normalizedColumn) &&
      !ESM_DEPRECATED_COLUMN_KEYS.has(normalizedColumn) &&
      ESM_WORKSPACE_LOCAL_FILTER_DIMENSION_KEYS.has(normalizedColumn);
    const isSupportedLocalExclusion =
      pair?.hasValue === true &&
      exclusionColumn &&
      exclusionColumn !== "media-company" &&
      !ESM_LOCAL_FILTER_EXCLUDED_COLUMNS.has(exclusionColumn) &&
      !ESM_DEPRECATED_COLUMN_KEYS.has(exclusionColumn) &&
      ESM_WORKSPACE_LOCAL_FILTER_DIMENSION_KEYS.has(exclusionColumn);

    if (!isSupportedLocalFilter || !decodedValue) {
      if (isSupportedLocalExclusion && decodedValue) {
        if (!Array.isArray(extractedExclusions[exclusionColumn])) {
          extractedExclusions[exclusionColumn] = [];
        }
        if (!extractedExclusions[exclusionColumn].includes(decodedValue)) {
          extractedExclusions[exclusionColumn].push(decodedValue);
        }
        if (!extractedColumnSet.has(exclusionColumn)) {
          extractedColumnSet.add(exclusionColumn);
          extractedColumns.push(exclusionColumn);
        }
        preservedPairs.push(pair);
        return;
      }
      preservedPairs.push(pair);
      return;
    }

    if (!Array.isArray(extractedFilters[normalizedColumn])) {
      extractedFilters[normalizedColumn] = [];
    }
    if (!extractedFilters[normalizedColumn].includes(decodedValue)) {
      extractedFilters[normalizedColumn].push(decodedValue);
    }
    if (!extractedColumnSet.has(normalizedColumn)) {
      extractedColumnSet.add(normalizedColumn);
      extractedColumns.push(normalizedColumn);
    }
  });

  let baseUrl = rawUrl;
  try {
    const parsed = new URL(rawUrl, window.location.href);
    parsed.hash = "";
    const preservedQuery = popupSerializeEsmRawQueryPairs(preservedPairs);
    parsed.search = preservedQuery ? `?${preservedQuery}` : "";
    baseUrl = parsed.toString();
  } catch {
    const pathOnly = rawUrl.split(/[?#]/, 1)[0] || rawUrl;
    const preservedQuery = popupSerializeEsmRawQueryPairs(preservedPairs);
    baseUrl = preservedQuery ? `${pathOnly}?${preservedQuery}` : pathOnly;
  }

  return {
    baseUrl,
    localColumnFilters: extractedFilters,
    localColumnExclusions: extractedExclusions,
    columns: extractedColumns,
  };
}

function clickEsmGetSelectedValues(selectElement) {
  if (!selectElement) {
    return [];
  }
  return [...selectElement.selectedOptions].map((option) => String(option.value || "").trim()).filter(Boolean);
}

function extractEsmDisplayDimensionsFromHref(href = "") {
  const rawHref = String(href || "").trim();
  if (!rawHref) {
    return [];
  }

  let path = "";
  try {
    const parsed = new URL(rawHref, window.location.href);
    path = String(parsed.pathname || "");
  } catch {
    path = rawHref.split("?", 1)[0] || "";
  }

  const segments = path
    .split("/")
    .map((segment) => decodeURIComponent(String(segment || "").trim().toLowerCase()))
    .filter(Boolean);
  if (!segments.length) {
    return [];
  }

  const v3Index = segments.findIndex((segment, index) => segment === "v3" && segments[index - 1] === "esm");
  const startIndex = v3Index >= 0 ? v3Index + 1 : 0;
  let dimensionSegments = segments.slice(startIndex);
  if (dimensionSegments[0] === "media-company" || dimensionSegments[0] === "mvpd") {
    dimensionSegments = dimensionSegments.slice(1);
  }

  const output = [];
  const seen = new Set();
  dimensionSegments.forEach((segment) => {
    const normalized = String(segment || "").trim().toLowerCase();
    if (
      !normalized ||
      normalized === "media-company" ||
      ESM_LOCAL_FILTER_EXCLUDED_COLUMNS.has(normalized) ||
      ESM_DEPRECATED_COLUMN_KEYS.has(normalized) ||
      seen.has(normalized)
    ) {
      return;
    }
    seen.add(normalized);
    output.push(normalized);
  });

  popupParseEsmRawQueryPairs(rawHref).forEach((pair) => {
    const normalized = normalizeEsmDisplayDimensionKey(pair?.key);
    if (
      !normalized ||
      normalized === "media-company" ||
      ESM_QUERY_DISPLAY_EXCLUDED_COLUMNS.has(normalized) ||
      ESM_DEPRECATED_COLUMN_KEYS.has(normalized) ||
      seen.has(normalized)
    ) {
      return;
    }
    seen.add(normalized);
    output.push(normalized);
  });
  return output;
}

function normalizeEsmColumns(columns, options = {}) {
  const href = String(options?.href || "").trim();
  const output = [];
  const seen = new Set();

  (Array.isArray(columns) ? columns : []).forEach((value) => {
    const normalized = String(value || "")
      .replace(/<[^>]*>/g, " ")
      .replace(/\s+/g, " ")
      .trim();
    if (!normalized) {
      return;
    }

    if (/^no\s+report\s+columns$/i.test(normalized)) {
      return;
    }

    const lower = normalized.toLowerCase();
    if (ESM_DEPRECATED_COLUMN_KEYS.has(lower) || lower === "media-company") {
      return;
    }
    if (!seen.has(lower)) {
      output.push(normalized);
      seen.add(lower);
    }
  });

  if (output.length === 0 && href) {
    return extractEsmDisplayDimensionsFromHref(href);
  }
  return output;
}

function normalizeClickCmuColumns(columns) {
  const output = [];
  const seen = new Set();
  (Array.isArray(columns) ? columns : []).forEach((value) => {
    const normalized = String(value || "")
      .replace(/<[^>]*>/g, " ")
      .replace(/\s+/g, " ")
      .trim();
    if (!normalized || /^no\s+report\s+columns$/i.test(normalized)) {
      return;
    }
    const lower = normalized.toLowerCase();
    if (seen.has(lower)) {
      return;
    }
    seen.add(lower);
    output.push(normalized);
  });
  return output;
}

const CMU_STATIC_COLUMN_EXCLUDED_KEYS = new Set(["cmu", "v2", "tenant", "tenant-id", "tenant_id", "view"]);
const CMU_STATIC_METRIC_COLUMN_KEYS = new Set([
  "users",
  "active-sessions",
  "completed-sessions",
  "dismissed-sessions",
  "failed-attempts",
  "killed-sessions",
  "started-sessions",
]);

function normalizeClickCmuStaticColumnName(value = "") {
  return String(value || "").trim().toLowerCase();
}

function isClickCmuStaticMetricColumn(value = "") {
  const normalized = normalizeClickCmuStaticColumnName(value);
  if (!normalized) {
    return false;
  }
  const canonical = normalized.replace(/_/g, "-");
  if (CMU_STATIC_METRIC_COLUMN_KEYS.has(canonical)) {
    return true;
  }
  if (/^bstreams-\d+$/.test(canonical)) {
    return true;
  }
  if (/^duration-(?:under|over)-/.test(canonical)) {
    return true;
  }
  if (/^duration-[^-]+-[^-]+$/.test(canonical)) {
    return true;
  }
  return false;
}

function normalizeClickCmuStaticColumns(columns = []) {
  const output = [];
  const seen = new Set();
  normalizeClickCmuColumns(columns)
    .map((value) => normalizeClickCmuStaticColumnName(value))
    .filter(Boolean)
    .forEach((value) => {
      if (CMU_STATIC_COLUMN_EXCLUDED_KEYS.has(value) || isClickCmuStaticMetricColumn(value) || seen.has(value)) {
        return;
      }
      seen.add(value);
      output.push(value);
    });
  return output;
}

async function loadClickEsmEndpoints() {
  if (Array.isArray(clickEsmEndpoints) && clickEsmEndpoints.length > 0) {
    return clickEsmEndpoints;
  }
  if (clickEsmEndpointsPromise) {
    return clickEsmEndpointsPromise;
  }

  clickEsmEndpointsPromise = (async () => {
    const resourceUrl = chrome.runtime.getURL(CLICK_ESM_ENDPOINTS_PATH);
    const response = await fetch(resourceUrl, {
      method: "GET",
      credentials: "omit",
      cache: "no-cache",
    });
    if (!response.ok) {
      throw new Error(`Unable to load ESM endpoint catalog (${response.status}).`);
    }

    const payload = await response.json().catch(() => null);
    const endpoints = Array.isArray(payload?.endpoints) ? payload.endpoints : [];
    clickEsmEndpoints = endpoints
      .map((endpoint) => {
        if (!endpoint || typeof endpoint !== "object") {
          return null;
        }
        const url = rewriteAdobePassServiceUrl(String(endpoint.url || "").trim(), "mgmt");
        if (!url) {
          return null;
        }
        const zoomKey = clickEsmGetZoomKey(endpoint);
        const normalizedColumns = normalizeEsmColumns(endpoint.columns, { href: url });
        const searchColumns = clickEsmNormalizeSearchColumns(endpoint.columns);

        return {
          url,
          zoomClass: String(endpoint.zoomClass || "").trim(),
          zoomKey,
          columns: normalizedColumns,
          searchColumns,
        };
      })
      .filter(Boolean);

    return clickEsmEndpoints;
  })();

  try {
    return await clickEsmEndpointsPromise;
  } finally {
    clickEsmEndpointsPromise = null;
  }
}

async function loadClickCmuEndpoints() {
  if (Array.isArray(clickCmuEndpoints) && clickCmuEndpoints.length > 0) {
    return clickCmuEndpoints;
  }
  if (clickCmuEndpointsPromise) {
    return clickCmuEndpointsPromise;
  }

  clickCmuEndpointsPromise = (async () => {
    const resourceUrl = chrome.runtime.getURL(CLICK_CMU_ENDPOINTS_PATH);
    const response = await fetch(resourceUrl, {
      method: "GET",
      credentials: "omit",
      cache: "no-cache",
    });
    if (!response.ok) {
      throw new Error(`Unable to load CMU endpoint catalog (${response.status}).`);
    }

    const payload = await response.json().catch(() => null);
    const endpoints = Array.isArray(payload?.endpoints) ? payload.endpoints : [];
    clickCmuEndpoints = endpoints
      .map((endpoint, index) => {
        if (!endpoint || typeof endpoint !== "object") {
          return null;
        }
        const url = ensureCmUsageEndpointFormat(endpoint.url);
        if (!url) {
          return null;
        }
        let pathname = "";
        try {
          pathname = String(new URL(url, CM_REPORTS_BASE_URL).pathname || "");
        } catch {
          pathname = String(url || "").split("?")[0];
        }
        if (!isCanonicalCmuUsagePath(pathname)) {
          return null;
        }
        const normalizedColumns = normalizeClickCmuColumns(endpoint.columns);
        return {
          id: String(endpoint.id || `cmu-${index + 1}`).trim() || `cmu-${index + 1}`,
          label: String(endpoint.label || "").trim() || formatCmUsageLabelFromPath(new URL(url, CM_REPORTS_BASE_URL).pathname),
          url,
          zoomClass: String(endpoint.zoomClass || "").trim(),
          zoomKey: String(endpoint.zoomKey || "").trim().toUpperCase(),
          columns: normalizedColumns,
          columnsKnown: Array.isArray(endpoint.columns),
        };
      })
      .filter(Boolean);

    return clickCmuEndpoints;
  })();

  try {
    return await clickCmuEndpointsPromise;
  } finally {
    clickCmuEndpointsPromise = null;
  }
}

function normalizeCmUsageExampleSection(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "monthly" || normalized === "daily" || normalized === "hourly") {
    return normalized;
  }
  return "usage";
}

function normalizeCmUsageExampleSectionLabel(section = "") {
  const normalized = normalizeCmUsageExampleSection(section);
  if (normalized === "monthly") {
    return "Monthly";
  }
  if (normalized === "daily") {
    return "Daily";
  }
  if (normalized === "hourly") {
    return "Hourly";
  }
  return "Usage";
}

function normalizeCmUsageExamplePath(pathValue = "") {
  const raw = String(pathValue || "").trim();
  if (!raw) {
    return "";
  }
  const withoutOrigin = raw.replace(/^https?:\/\/[^/]+/i, "");
  const withoutLeadingSlash = withoutOrigin.replace(/^\/+/, "");
  if (!withoutLeadingSlash) {
    return "";
  }
  const withoutCmuPrefix = withoutLeadingSlash.replace(/^cmu\/+/i, "");
  const normalizedPath = /^v2\//i.test(withoutCmuPrefix)
    ? withoutCmuPrefix
    : `v2/${withoutCmuPrefix.replace(/^v2\/?/i, "")}`;
  return `/${normalizedPath.replace(/^\/+/, "")}`;
}

function normalizeCmUsageExampleTokenList(values) {
  const list = Array.isArray(values) ? values : [];
  const output = [];
  const seen = new Set();
  list.forEach((value) => {
    const token = String(value || "").trim().toLowerCase();
    if (!token || seen.has(token)) {
      return;
    }
    seen.add(token);
    output.push(token);
  });
  return output;
}

function normalizeCmUsageReportExampleEntry(entry, index = 0) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const path = normalizeCmUsageExamplePath(entry.path || entry.url || "");
  if (!path) {
    return null;
  }
  const section = normalizeCmUsageExampleSection(entry.section);
  const sectionLabel = String(entry.sectionLabel || normalizeCmUsageExampleSectionLabel(section)).trim() || "Usage";
  const dimensions = normalizeCmUsageExampleTokenList(entry.dimensions);
  const metrics = normalizeCmUsageExampleTokenList(entry.metrics);
  const hasMvpdDimension = entry.hasMvpdDimension === true || dimensions.includes("mvpd") || /\/mvpd(?:\/|$)/i.test(path);
  const normalizedName = String(entry.name || "").trim() || formatCmUsageLabelFromPath(path);
  const normalizedId = String(entry.id || `${section}-${String(index + 1).padStart(2, "0")}`).trim();
  return {
    id: normalizedId || `${section}-${String(index + 1).padStart(2, "0")}`,
    section,
    sectionLabel,
    name: normalizedName,
    path,
    dimensions,
    metrics,
    hasMvpdDimension,
  };
}

async function loadCmUsageReportExamplesCatalog() {
  if (Array.isArray(cmUsageReportExamples) && cmUsageReportExamples.length > 0) {
    return cmUsageReportExamples;
  }
  if (cmUsageReportExamplesPromise) {
    return cmUsageReportExamplesPromise;
  }

  cmUsageReportExamplesPromise = (async () => {
    const resourceUrl = chrome.runtime.getURL(CM_USAGE_REPORT_EXAMPLES_PATH);
    const response = await fetch(resourceUrl, {
      method: "GET",
      credentials: "omit",
      cache: "no-cache",
    });
    if (!response.ok) {
      throw new Error(`Unable to load CM usage report examples (${response.status}).`);
    }
    const payload = await response.json().catch(() => null);
    const entries = Array.isArray(payload?.reports) ? payload.reports : [];
    const normalized = entries
      .map((entry, index) => normalizeCmUsageReportExampleEntry(entry, index))
      .filter(Boolean);
    cmUsageReportExamples = normalized;
    return cmUsageReportExamples;
  })();

  try {
    return await cmUsageReportExamplesPromise;
  } finally {
    cmUsageReportExamplesPromise = null;
  }
}

function cmExtractRawUsagePathParts(pathname = "") {
  return String(pathname || "")
    .split("/")
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean)
    .filter((value) => value !== "cmu" && value !== "v2");
}

function cmBuildUsageExamplePathProfile(pathOrUrl = "") {
  const pathParts = cmuUsageExtractPathParts(pathOrUrl);
  const tokenSet = new Set(
    pathParts
      .map((value) => String(value || "").trim().toLowerCase())
      .filter(Boolean)
  );
  return {
    pathParts,
    tokenSet,
    zoomKey: cmuUsageGetZoomKey(pathParts, pathOrUrl),
  };
}

function cmComputeUsageExamplePathMatchScore(exampleProfile = null, candidateProfile = null) {
  if (!exampleProfile || !candidateProfile) {
    return Number.POSITIVE_INFINITY;
  }
  const requiredTokens = [...(exampleProfile.tokenSet || new Set())].filter(
    (token) => !CM_USAGE_ROOT_SEGMENT_SET.has(token)
  );
  for (const token of requiredTokens) {
    if (!(candidateProfile.tokenSet instanceof Set) || !candidateProfile.tokenSet.has(token)) {
      return Number.POSITIVE_INFINITY;
    }
  }

  const candidateExtras = [...(candidateProfile.tokenSet || new Set())].filter(
    (token) => !CM_USAGE_ROOT_SEGMENT_SET.has(token) && !(exampleProfile.tokenSet instanceof Set && exampleProfile.tokenSet.has(token))
  );
  const zoomMismatchPenalty =
    exampleProfile.zoomKey && candidateProfile.zoomKey && exampleProfile.zoomKey !== candidateProfile.zoomKey ? 64 : 0;
  const pathLengthPenalty = Math.abs(
    Number(candidateProfile.pathParts?.length || 0) - Number(exampleProfile.pathParts?.length || 0)
  );
  return candidateExtras.length * 4 + pathLengthPenalty + zoomMismatchPenalty;
}

function cmResolveUsageExampleSourceEndpointUrl(example = null, usageRecords = [], options = {}) {
  const normalizedPath = normalizeCmUsageExamplePath(example?.path || "");
  if (!normalizedPath) {
    return "";
  }
  const exampleProfile = cmBuildUsageExamplePathProfile(normalizedPath);
  const tenantScope = resolveCmUsageTenantScopeValue(
    options?.tenantScope,
    options?.tenantId,
    getCmTenantScopeForProgrammer({ programmerId: String(options?.programmerId || "").trim() })
  );
  const records = Array.isArray(usageRecords) ? usageRecords : [];
  let bestMatch = null;

  records.forEach((record) => {
    if (!record || String(record?.kind || "").trim().toLowerCase() !== "usage") {
      return;
    }
    if (record?.payload && typeof record.payload === "object" && record.payload.usageExample === true) {
      return;
    }
    const candidateUrl = ensureCmUsageEndpointFormat(
      firstNonEmptyString([record?.sourceUrl, record?.requestUrl, record?.endpointUrl]),
      {
        tenantScope: resolveCmUsageTenantScopeValue(record?.tenantId, record?.tenantName, tenantScope),
      }
    );
    if (!candidateUrl) {
      return;
    }
    const candidateProfile = cmBuildUsageExamplePathProfile(candidateUrl);
    const score = cmComputeUsageExamplePathMatchScore(exampleProfile, candidateProfile);
    if (!Number.isFinite(score)) {
      return;
    }
    if (!bestMatch || score < bestMatch.score) {
      bestMatch = {
        score,
        url: candidateUrl,
      };
    }
  });

  if (bestMatch?.url) {
    return bestMatch.url;
  }
  return ensureCmUsageEndpointFormat(`${CM_REPORTS_BASE_URL}${normalizedPath}`, {
    tenantScope,
    tenantId: options?.tenantId,
    programmerId: options?.programmerId,
  });
}

function cmBuildUsageReportExampleRequestUrl(example = null, options = {}) {
  const tenantScope = resolveCmUsageTenantScopeValue(
    options?.tenantScope,
    options?.tenantId,
    getCmTenantScopeForProgrammer({ programmerId: String(options?.programmerId || "").trim() })
  );
  const sourceEndpointUrl = firstNonEmptyString([
    String(options?.sourceEndpointUrl || "").trim(),
    normalizeCmUrl(`${CM_REPORTS_BASE_URL}${normalizeCmUsageExamplePath(example?.path || "")}`),
  ]);
  const baseUrl = ensureCmUsageEndpointFormat(sourceEndpointUrl, {
    tenantScope,
    tenantId: options?.tenantId,
    programmerId: options?.programmerId,
  });
  if (!baseUrl) {
    return "";
  }
  try {
    const parsed = new URL(stripServerManagedTimeParams(baseUrl, CM_REPORTS_BASE_URL), CM_REPORTS_BASE_URL);
    parsed.searchParams.delete("start");
    parsed.searchParams.delete("end");
    parsed.searchParams.set("format", "json");
    CM_USAGE_TENANT_QUERY_KEYS.forEach((key) => parsed.searchParams.delete(key));
    if (tenantScope && cmUsagePathRequiresTenantScope(parsed.pathname)) {
      applyCmUsageTenantScopeToSearchParams(parsed.searchParams, tenantScope);
    }
    if (example?.hasMvpdDimension === true) {
      const mvpdId = String(options?.mvpdId || state.selectedMvpdId || "").trim();
      parsed.searchParams.delete("mvpd");
      parsed.searchParams.delete("mvpd_id");
      parsed.searchParams.delete("mvpd-id");
      if (mvpdId) {
        parsed.searchParams.set("mvpd", mvpdId);
      }
    }
    return parsed.toString();
  } catch {
    return baseUrl;
  }
}

function cmBuildUsageReportExampleWorkspaceRecords(examples = [], options = {}) {
  const list = Array.isArray(examples) ? examples : [];
  if (list.length === 0) {
    return [];
  }

  const programmer = options?.programmer && typeof options.programmer === "object" ? options.programmer : null;
  const tenantId = resolveCmUsageTenantScopeValue(
    options?.tenantScope,
    options?.tenantId,
    programmer?.programmerId
  );
  const tenantName = firstNonEmptyString([
    options?.tenantName,
    options?.tenantId,
    programmer?.programmerName,
    programmer?.mediaCompanyName,
    programmer?.programmerId,
    tenantId,
    "CM",
  ]);
  const programmerId = String(programmer?.programmerId || "").trim();
  const liveUsageRecords = Array.isArray(options?.usageRecords) ? options.usageRecords : [];
  const output = [];

  list.forEach((example, index) => {
    const normalizedExample = normalizeCmUsageReportExampleEntry(example, index);
    if (!normalizedExample) {
      return;
    }
    const sourceEndpointUrl = cmResolveUsageExampleSourceEndpointUrl(normalizedExample, liveUsageRecords, {
      tenantScope: tenantId,
      tenantId,
      programmerId,
    });
    const resolvedHasMvpdDimension =
      normalizedExample.hasMvpdDimension === true || /\/mvpd(?:\/|$)/i.test(String(sourceEndpointUrl || ""));
    const requestUrl = cmBuildUsageReportExampleRequestUrl(
      {
        ...normalizedExample,
        hasMvpdDimension: resolvedHasMvpdDimension,
      },
      {
      tenantScope: tenantId,
      tenantId,
      programmerId,
      mvpdId: options?.mvpdId,
      sourceEndpointUrl,
      }
    );
    if (!requestUrl) {
      return;
    }
    const recordIdSeed = String(normalizedExample.id || `usage-example-${index + 1}`).trim() || `usage-example-${index + 1}`;
    output.push({
      cardId: cmBuildRecordId("usage-example", tenantId || "cm", recordIdSeed, index),
      kind: "usage",
      title: `${normalizedExample.sectionLabel} · ${normalizedExample.name}`,
      subtitle: `CM Usage Report Example | ${tenantName}`,
      endpointUrl: requestUrl,
      requestUrl,
      payload: {
        usageExample: true,
        usageExampleId: normalizedExample.id,
        usageExampleSection: normalizedExample.section,
        usageExampleName: normalizedExample.name,
        usageExamplePath: normalizedExample.path,
        usageExampleSourceEndpointUrl: sourceEndpointUrl,
        usageExampleDimensions: normalizedExample.dimensions,
        usageExampleMetrics: normalizedExample.metrics,
        hasMvpdDimension: resolvedHasMvpdDimension,
      },
      columns: [],
      lastModified: "",
      tenantId: String(tenantId || ""),
      tenantName: String(tenantName || ""),
    });
  });

  return output;
}

function isModernClickEsmTemplate(templateHtml) {
  const text = String(templateHtml || "");
  if (!text.trim()) {
    return false;
  }
  if (
    !text.includes(CLICK_ESM_TEMPLATE_PLACEHOLDER_CID) ||
    !text.includes(CLICK_ESM_TEMPLATE_PLACEHOLDER_CSC) ||
    !text.includes(CLICK_ESM_TEMPLATE_PLACEHOLDER_ACCESS_TOKEN)
  ) {
    return false;
  }
  return CLICK_ESM_TEMPLATE_REQUIRED_MARKERS.every((marker) => text.includes(marker));
}

function buildClickEsmTemplateResourceUrl({ forceBypassCache = false } = {}) {
  const manifestVersion = String(chrome?.runtime?.getManifest?.()?.version || "").trim();
  const params = new URLSearchParams();
  if (manifestVersion) {
    params.set("v", manifestVersion);
  }
  if (forceBypassCache) {
    params.set("t", String(Date.now()));
  }
  const base = chrome.runtime.getURL(CLICK_ESM_TEMPLATE_PATH);
  const query = params.toString();
  return query ? `${base}?${query}` : base;
}

async function fetchClickEsmTemplateHtml({ forceBypassCache = false } = {}) {
  const resourceUrl = buildClickEsmTemplateResourceUrl({ forceBypassCache });
  const response = await fetch(resourceUrl, {
    method: "GET",
    credentials: "omit",
    cache: forceBypassCache ? "reload" : "no-cache",
  });
  if (!response.ok) {
    throw new Error(`Unable to load clickESM template (${response.status}).`);
  }
  return await response.text();
}

async function loadClickEsmTemplateHtml() {
  if (isModernClickEsmTemplate(clickEsmTemplateHtml)) {
    return clickEsmTemplateHtml;
  }
  if (clickEsmTemplatePromise) {
    return clickEsmTemplatePromise;
  }

  clickEsmTemplatePromise = (async () => {
    let templateHtml = await fetchClickEsmTemplateHtml({ forceBypassCache: false });
    if (!isModernClickEsmTemplate(templateHtml)) {
      templateHtml = await fetchClickEsmTemplateHtml({ forceBypassCache: true });
    }
    if (!isModernClickEsmTemplate(templateHtml)) {
      throw new Error("clickESM template is not the latest skinned/export build.");
    }
    clickEsmTemplateHtml = templateHtml;
    return clickEsmTemplateHtml;
  })();

  try {
    return await clickEsmTemplatePromise;
  } finally {
    clickEsmTemplatePromise = null;
  }
}

function clickEsmReplaceTitleHotspot(templateHtml, titleText) {
  const safeTitle = escapeHtml(String(titleText || "").trim());
  if (!safeTitle) {
    throw new Error("clickESM title is required.");
  }
  let output = String(templateHtml || "");
  if (output.includes(CLICK_ESM_TEMPLATE_PLACEHOLDER_TITLE)) {
    output = output.replaceAll(CLICK_ESM_TEMPLATE_PLACEHOLDER_TITLE, safeTitle);
    return output;
  }
  if (/<title[\s\S]*?<\/title>/i.test(output)) {
    return output.replace(/<title[\s\S]*?<\/title>/i, `<title>${safeTitle}</title>`);
  }
  throw new Error("clickESM template is missing the <title> hotspot.");
}

function clickEsmReplaceHiddenInputHotspot(templateHtml, inputName, value, placeholderToken) {
  const safeName = String(inputName || "").trim();
  if (!safeName) {
    throw new Error("clickESM hidden input name is required.");
  }
  const safeValue = escapeHtml(String(value || "").trim());
  if (!safeValue) {
    throw new Error(`clickESM hidden input "${safeName}" is required.`);
  }

  let output = String(templateHtml || "");
  const placeholder = String(placeholderToken || "").trim();
  if (placeholder && output.includes(placeholder)) {
    return output.replaceAll(placeholder, safeValue);
  }

  const escapedName = clickEsmEscapeRegExp(safeName);
  const inputPattern = new RegExp(
    `(<input\\b[^>]*\\bname=(["'])${escapedName}\\2[^>]*\\bvalue=(["']))([^"']*)(\\3[^>]*>)`,
    "i"
  );
  if (inputPattern.test(output)) {
    output = output.replace(inputPattern, `$1${safeValue}$5`);
    return output;
  }

  throw new Error(`clickESM template is missing hidden input "${safeName}".`);
}

function replaceTemplateTokenHotspot(templateHtml, placeholderToken, value, label = "") {
  const output = String(templateHtml || "");
  const token = String(placeholderToken || "").trim();
  if (!token) {
    throw new Error("Template placeholder token is required.");
  }
  if (!output.includes(token)) {
    const labelText = String(label || token).trim();
    throw new Error(`Template is missing placeholder "${labelText}".`);
  }
  return output.replaceAll(token, escapeHtml(String(value == null ? "" : value)));
}

function buildUnderparTearsheetExportPayload(programmer = null, options = {}) {
  const environment =
    options?.environment && typeof options.environment === "object"
      ? cloneJsonLikeValue(options.environment, null)
      : cloneJsonLikeValue(getActiveAdobePassEnvironment(), null);
  const programmerId = String(programmer?.programmerId || options?.programmerId || "").trim();
  const passVaultRecord =
    options?.passVaultRecord && typeof options.passVaultRecord === "object"
      ? cloneJsonLikeValue(options.passVaultRecord, null)
      : programmerId
        ? cloneJsonLikeValue(getPassVaultMediaCompanyRecord(programmerId, String(environment?.key || "")), null)
        : null;
  const requestorIds = Array.isArray(options?.requestorIds)
    ? options.requestorIds.map((value) => String(value || "").trim()).filter(Boolean)
    : [];
  const requestorCatalogIds = Array.isArray(options?.requestorCatalogIds)
    ? options.requestorCatalogIds.map((value) => String(value || "").trim()).filter(Boolean)
    : [];
  const mvpdIds = Array.isArray(options?.mvpdIds)
    ? options.mvpdIds.map((value) => String(value || "").trim()).filter(Boolean)
    : [];
  return {
    schemaVersion: UNDERPAR_VAULT_SCHEMA_VERSION,
    exportedAt: new Date().toISOString(),
    serviceKey: String(options?.serviceKey || "").trim(),
    environment,
    programmer: programmerId
      ? {
          programmerId,
          programmerName: String(programmer?.programmerName || programmer?.mediaCompanyName || programmerId).trim() || programmerId,
          mediaCompanyName:
            String(programmer?.mediaCompanyName || programmer?.programmerName || programmerId).trim() || programmerId,
        }
      : null,
    requestorIds,
    requestorCatalogIds,
    mvpdIds,
    tenantScope: String(options?.tenantScope || "").trim(),
    selectedApplication:
      options?.appInfo && typeof options.appInfo === "object" ? cloneJsonLikeValue(options.appInfo, null) : null,
    credential:
      options?.credential && typeof options.credential === "object"
        ? normalizeUnderparVaultDcrCache(options.credential)
        : null,
    passVaultRecord,
    savedQueries: options?.includeSavedQueries === true ? cloneJsonLikeValue(getUnderparVaultSavedQueries(state.passVault), {}) : {},
  };
}

function appendUnderparTearsheetExportPayload(htmlText = "", exportPayload = null) {
  if (!exportPayload || typeof exportPayload !== "object") {
    return String(htmlText || "");
  }
  const payloadJson = JSON.stringify(exportPayload).replace(/</g, "\\u003c").replace(/<\/script/gi, "<\\/script");
  const payloadNode = `\n<script id="underpar-tearsheet-export-payload" type="application/json">${payloadJson}</script>\n`;
  const output = String(htmlText || "");
  if (output.includes('id="underpar-tearsheet-export-payload"')) {
    return output.replace(
      /<script id="underpar-tearsheet-export-payload" type="application\/json">[\s\S]*?<\/script>/i,
      payloadNode.trim()
    );
  }
  if (/<\/body>/i.test(output)) {
    return output.replace(/<\/body>/i, `${payloadNode}</body>`);
  }
  return `${output}${payloadNode}`;
}

function buildClickEsmHtmlFromTemplate(templateHtml, context = {}) {
  const programmerLabel = String(context.programmerLabel || "").trim();
  const titleText = `${programmerLabel || "Media Company"} CLICK ESM`;
  const themeScope = String(context.themeScope || context.programmerId || programmerLabel || "MediaCompany").trim();
  const requestorCatalog = uniqueSorted(
    (Array.isArray(context.requestorCatalogIds) ? context.requestorCatalogIds : [])
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
  const encodedRequestorCatalog = encodeURIComponent(JSON.stringify(requestorCatalog));
  let output = clickEsmReplaceTitleHotspot(rewriteAdobePassTemplateForEnvironment(templateHtml), titleText);
  output = clickEsmReplaceHiddenInputHotspot(output, "cid", context.clientId, CLICK_ESM_TEMPLATE_PLACEHOLDER_CID);
  output = clickEsmReplaceHiddenInputHotspot(output, "csc", context.clientSecret, CLICK_ESM_TEMPLATE_PLACEHOLDER_CSC);
  output = clickEsmReplaceHiddenInputHotspot(
    output,
    "access_token",
    context.accessToken,
    CLICK_ESM_TEMPLATE_PLACEHOLDER_ACCESS_TOKEN
  );
  output = clickEsmReplaceHiddenInputHotspot(
    output,
    "requestor_ids_json",
    encodedRequestorCatalog,
    CLICK_ESM_TEMPLATE_PLACEHOLDER_REQUESTOR_IDS_JSON
  );
  output = clickEsmReplaceHiddenInputHotspot(
    output,
    "theme_scope",
    themeScope,
    CLICK_ESM_TEMPLATE_PLACEHOLDER_THEME_SCOPE
  );
  return output;
}

