function megWorkspaceNormalizeSelection(endpoint = null, options = {}) {
  const endpointUrl = stripMegWorkspaceMediaCompanyQueryParam(String(endpoint?.url || options.endpointUrl || "").trim());
  if (!endpointUrl) {
    return null;
  }

  let endpointPath = endpointUrl;
  try {
    const parsed = new URL(endpointUrl);
    endpointPath = `${String(parsed.pathname || "")}${String(parsed.search || "")}`;
  } catch {
    endpointPath = endpointUrl;
  }

  const endpointSegments = esmWorkspaceNormalizeEndpointSegments(
    Array.isArray(endpoint?.segs) && endpoint.segs.length > 0 ? endpoint.segs : esmWorkspaceExtractSegments(endpointUrl)
  );
  const endpointLabel =
    String(options.endpointLabel || "").trim() ||
    endpointSegments.join(" / ") ||
    endpointPath;

  return {
    endpointUrl,
    endpointPath,
    endpointSegments,
    endpointLabel,
    launchToken: String(options.launchToken || "").trim() || generateRequestId(),
  };
}

function megWorkspaceRememberSelection(windowId, selection) {
  const normalizedSelection =
    selection && typeof selection === "object"
      ? {
          endpointUrl: stripMegWorkspaceMediaCompanyQueryParam(String(selection.endpointUrl || "").trim()),
          endpointPath: stripMegWorkspaceMediaCompanyQueryParam(String(selection.endpointPath || "").trim()),
          endpointSegments: Array.isArray(selection.endpointSegments) ? selection.endpointSegments.slice(0, 24) : [],
          endpointLabel: String(selection.endpointLabel || "").trim(),
          launchToken: String(selection.launchToken || "").trim(),
        }
      : null;
  if (!normalizedSelection?.endpointPath && !normalizedSelection?.endpointUrl) {
    return;
  }
  const normalizedWindowId = Number(windowId || 0);
  if (normalizedWindowId > 0) {
    state.megWorkspaceSelectionByWindowId.set(normalizedWindowId, normalizedSelection);
  }
  state.megWorkspaceLastSelection = normalizedSelection;
}

function megWorkspaceGetRememberedSelection(windowId = 0) {
  const normalizedWindowId = Number(windowId || 0);
  if (normalizedWindowId > 0) {
    const mapped = state.megWorkspaceSelectionByWindowId.get(normalizedWindowId);
    if (mapped && typeof mapped === "object") {
      return {
        ...mapped,
        endpointSegments: Array.isArray(mapped.endpointSegments) ? mapped.endpointSegments.slice(0, 24) : [],
      };
    }
  }
  const fallback = state.megWorkspaceLastSelection;
  return fallback && typeof fallback === "object"
    ? {
        ...fallback,
        endpointSegments: Array.isArray(fallback.endpointSegments) ? fallback.endpointSegments.slice(0, 24) : [],
      }
    : null;
}

function megWorkspaceClearRememberedSelection(windowId = 0) {
  const normalizedWindowId = Number(windowId || 0);
  const previousSelection =
    normalizedWindowId > 0 ? state.megWorkspaceSelectionByWindowId.get(normalizedWindowId) || null : null;
  if (normalizedWindowId > 0) {
    state.megWorkspaceSelectionByWindowId.delete(normalizedWindowId);
  } else {
    state.megWorkspaceSelectionByWindowId.clear();
  }
  if (
    normalizedWindowId <= 0 ||
    state.megWorkspaceSelectionByWindowId.size === 0 ||
    (previousSelection && state.megWorkspaceLastSelection === previousSelection)
  ) {
    state.megWorkspaceLastSelection = null;
  }
}

function megWorkspaceBuildAbsoluteServiceUrl(baseOrigin, value) {
  const rawValue = String(value || "").trim();
  if (!rawValue) {
    return "";
  }

  try {
    return new URL(rawValue, String(baseOrigin || ADOBE_MGMT_BASE).trim()).toString();
  } catch {
    const normalizedBase = String(baseOrigin || ADOBE_MGMT_BASE).replace(/\/+$/, "");
    const normalizedValue = rawValue.replace(/^\/+/, "");
    return `${normalizedBase}/${normalizedValue}`;
  }
}

function stripMegWorkspaceScopedQueryParams(rawUrl = "") {
  const normalized = String(rawUrl || "").trim();
  if (!normalized) {
    return "";
  }
  const withoutHash = normalized.split("#")[0] || "";
  const queryIndex = withoutHash.indexOf("?");
  if (queryIndex < 0) {
    return withoutHash;
  }
  const path = withoutHash.slice(0, queryIndex);
  const query = withoutHash.slice(queryIndex + 1);
  const nextQuery = query
    .split("&")
    .filter((segment) => {
      if (!segment) {
        return false;
      }
      const keySegment = segment.includes("=") ? segment.slice(0, segment.indexOf("=")) : segment;
      try {
        return decodeURIComponent(keySegment.replace(/\+/g, "%20")).trim().toLowerCase() !== "media-company";
      } catch (_error) {
        return keySegment.trim().toLowerCase() !== "media-company";
      }
    })
    .join("&");
  return nextQuery ? `${path}?${nextQuery}` : path;
}

function stripMegWorkspaceMediaCompanyQueryParam(rawUrl = "") {
  return stripMegWorkspaceScopedQueryParams(rawUrl);
}

function megWorkspaceCheckForCountCall(url) {
  const rawUrl = stripMegWorkspaceMediaCompanyQueryParam(String(url || "").trim());
  if (!rawUrl) {
    return "";
  }

  const [path, query] = rawUrl.split("?");
  let nextUrl = rawUrl;

  if (nextUrl.includes("channel")) {
    nextUrl = nextUrl.replace(/(metrics=)[^&]*/, (match, prefix) => {
      const metrics = match
        .split("=")[1]
        .split(",")
        .filter((metric) => !metric.startsWith("authn-"))
        .join(",");
      return `${prefix}${metrics}`;
    });
  }

  if (!path.includes("/event") && !path.includes("/event/")) {
    return nextUrl;
  }

  const params = query ? query.split("&") : [];
  const filteredParams = params.filter((param) => !param.startsWith("metrics="));
  const sanitizedQuery = filteredParams.join("&");
  return sanitizedQuery ? `${path}?${sanitizedQuery}` : path;
}

const MEG_WORKSPACE_EXPORT_FORMATS = new Set(["json", "xml", "csv", "html"]);
const MEG_WORKSPACE_EXPORT_MIME_BY_FORMAT = Object.freeze({
  json: "application/json;charset=utf-8",
  xml: "application/xml;charset=utf-8",
  csv: "text/csv;charset=utf-8",
  html: "text/html;charset=utf-8",
});

function megWorkspaceNormalizeExportFormat(rawValue, fallback = "") {
  const normalized = String(rawValue || "").trim().toLowerCase();
  if (MEG_WORKSPACE_EXPORT_FORMATS.has(normalized)) {
    return normalized;
  }
  const fallbackValue = String(fallback || "").trim().toLowerCase();
  return MEG_WORKSPACE_EXPORT_FORMATS.has(fallbackValue) ? fallbackValue : "";
}

function megWorkspaceApplyFormatToPath(pathname, format = "") {
  const normalizedFormat = megWorkspaceNormalizeExportFormat(format);
  const trimmedPath = String(pathname || "").trim();
  const withoutFormatSuffix = (trimmedPath || "/").replace(/\.(json|xml|csv|html)$/i, "");
  if (!normalizedFormat) {
    return withoutFormatSuffix || "/";
  }
  return `${withoutFormatSuffix || "/"}.${normalizedFormat}`;
}

function megWorkspaceBuildRequestUrl(rawUrl, options = {}) {
  const environment = getActiveAdobePassEnvironment();
  const format = megWorkspaceNormalizeExportFormat(options.format, "");
  const requestUrl = megWorkspaceBuildAbsoluteServiceUrl(
    environment?.mgmtBase || ADOBE_MGMT_BASE,
    stripMegWorkspaceMediaCompanyQueryParam(String(rawUrl || "").trim())
  );
  if (!requestUrl) {
    return "";
  }

  const parsed = new URL(requestUrl);
  parsed.hash = "";
  parsed.pathname = megWorkspaceApplyFormatToPath(parsed.pathname, format);
  parsed.searchParams.delete("format");
  parsed.searchParams.delete("media-company");

  return megWorkspaceCheckForCountCall(parsed.toString());
}

async function megWorkspaceResolveContext(requestToken) {
  const context = await resolveClickEsmDownloadContext(getActiveEsmWorkspaceState());
  if (!context?.programmer?.programmerId || !context?.appInfo?.guid) {
    throw new Error("Select an ESM-scoped programmer to run MEGSPACE.");
  }
  if (
    context?.section &&
    !isEsmServiceRequestActive(context.section, requestToken, context.programmer.programmerId)
  ) {
    throw new Error("ESM controller is no longer active for the selected programmer.");
  }
  return context;
}

async function megWorkspaceFetchResponse(rawUrl, requestToken, options = {}) {
  const context =
    options?.context && typeof options.context === "object" ? options.context : await megWorkspaceResolveContext(requestToken);
  const normalizedFormat = megWorkspaceNormalizeExportFormat(options.format, "json");

  const requestUrl = megWorkspaceBuildRequestUrl(rawUrl, {
    format: options.format,
  });
  if (!requestUrl) {
    throw new Error("ESM endpoint URL is required.");
  }
  const scopedRequestUrl = appendPinnedEsmMediaCompanyQueryParam(
    requestUrl,
    String(context?.programmer?.programmerId || "")
  );

  const response = await fetchWithPremiumAuth(
    context.programmer.programmerId,
    context.appInfo,
    scopedRequestUrl,
    {
      method: "GET",
    },
    "refresh",
    {
      requestorId: String(context?.requestorIds?.[0] || ""),
      mvpd: String(context?.mvpdIds?.[0] || ""),
      requestorIds: Array.isArray(context?.requestorIds) ? context.requestorIds.slice(0, 24) : [],
      mvpdIds: Array.isArray(context?.mvpdIds) ? context.mvpdIds.slice(0, 24) : [],
      service: "esm",
      endpointUrl: String(rawUrl || ""),
      scope: normalizedFormat === "json" ? "meg-workspace" : `meg-${normalizedFormat}`,
      workspaceKey: "meg-workspace",
      workspaceOrigin: "MEGSPACE",
    }
  );

  const bodyText = await response.text().catch(() => "");
  return {
    requestUrl: scopedRequestUrl,
    responseOk: response.ok,
    status: Number(response.status || 0),
    statusText: String(response.statusText || ""),
    bodyText,
    contentType: String(response.headers.get("content-type") || ""),
  };
}

function megWorkspaceBuildExportFileName(context, rawUrl, format) {
  const normalizedFormat = megWorkspaceNormalizeExportFormat(format, "csv");
  const absoluteUrl = megWorkspaceBuildAbsoluteServiceUrl(
    getActiveAdobePassEnvironment()?.mgmtBase || ADOBE_MGMT_BASE,
    String(rawUrl || "").trim()
  );
  let endpointPath = "endpoint";
  try {
    const parsed = new URL(absoluteUrl);
    endpointPath = megWorkspaceApplyFormatToPath(parsed.pathname, "")
      .replace(/^\/+/, "")
      .replace(/\//g, "-");
  } catch {
    endpointPath = "endpoint";
  }

  const requestorId = sanitizeHarFileSegment(
    Array.isArray(context?.requestorIds) && context.requestorIds.length > 0 ? context.requestorIds.join("-") : "all-requestors",
    "all-requestors"
  );
  const mvpdId = sanitizeHarFileSegment(
    Array.isArray(context?.mvpdIds) && context.mvpdIds.length > 0 ? context.mvpdIds.join("-") : "all-mvpds",
    "all-mvpds"
  );
  const endpointSegment = sanitizeHarFileSegment(endpointPath, "endpoint");
  const envTag = getAdobePassEnvironmentFileTag();
  const stamp = Date.now();
  return `esm_${sanitizeHarFileSegment(
    context?.programmer?.programmerId,
    "programmer"
  )}_${requestorId}_${mvpdId}_${endpointSegment}_${envTag}_${stamp}.${normalizedFormat}`;
}

function megWorkspaceResolveDownloadMimeType(format, responseContentType = "") {
  const normalizedFormat = megWorkspaceNormalizeExportFormat(format, "csv");
  const contentType = String(responseContentType || "").trim();
  return contentType || MEG_WORKSPACE_EXPORT_MIME_BY_FORMAT[normalizedFormat] || "application/octet-stream";
}

function megWorkspaceDownloadFile(payloadText, fileName, mimeType) {
  const blob = new Blob([String(payloadText || "")], { type: String(mimeType || "application/octet-stream") });
  const blobUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = blobUrl;
  anchor.download = String(fileName || "esm-export.txt");
  anchor.click();
  URL.revokeObjectURL(blobUrl);
}

function rewriteMegWorkspaceHtmlExportLinks(htmlText, context = {}) {
  const sourceHtml = String(htmlText || "");
  if (!sourceHtml.trim() || typeof DOMParser !== "function") {
    return sourceHtml;
  }

  let documentNode = null;
  try {
    documentNode = new DOMParser().parseFromString(sourceHtml, "text/html");
  } catch {
    return sourceHtml;
  }
  if (!documentNode?.querySelectorAll) {
    return sourceHtml;
  }

  const programmerId = String(context?.programmerId || "").trim();
  const programmerName = String(context?.programmerName || "").trim();
  const environmentKey =
    String(context?.environmentKey || getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() ||
    DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const environmentLabel = String(context?.environmentLabel || getActiveAdobePassEnvironment()?.label || "").trim();
  let rewriteCount = 0;

  documentNode.querySelectorAll("a[href]").forEach((anchor) => {
    const rawHref = String(anchor.getAttribute("href") || "").trim();
    const requestPath = normalizeUnderparEsmRequestPath(rawHref);
    if (!requestPath) {
      return;
    }
    const displayNodeLabel = firstNonEmptyString([
      String(anchor.textContent || "").trim(),
      String(anchor.getAttribute("title") || "").trim(),
      requestPath,
    ]);
    const deeplinkUrl = buildUnderparDirectEsmBridgeUrl(requestPath, {
      displayNodeLabel,
      programmerId,
      programmerName,
      environmentKey,
      environmentLabel,
      source: "megspace-html-export",
    });
    if (!deeplinkUrl) {
      return;
    }
    anchor.setAttribute("href", deeplinkUrl);
    anchor.setAttribute("target", UNDERPAR_ESM_HTML_EXPORT_TARGET_NAME);
    anchor.setAttribute("rel", "noopener noreferrer");
    anchor.setAttribute("data-underpar-esm-request-path", requestPath);
    const existingTitle = String(anchor.getAttribute("title") || "").trim();
    const underparTitle = displayNodeLabel
      ? `Open ${displayNodeLabel} in UnderPAR ESM Workspace`
      : "Open in UnderPAR ESM Workspace";
    anchor.setAttribute("title", existingTitle ? `${existingTitle} | ${underparTitle}` : underparTitle);
    rewriteCount += 1;
  });

  if (!rewriteCount || !documentNode.documentElement) {
    return sourceHtml;
  }
  const existingBridgeFrame = documentNode.getElementById(UNDERPAR_ESM_HTML_EXPORT_BRIDGE_FRAME_ID);
  if (existingBridgeFrame?.parentNode) {
    existingBridgeFrame.parentNode.removeChild(existingBridgeFrame);
  }
  return `<!doctype html>\n${documentNode.documentElement.outerHTML}`;
}

async function megWorkspaceDownloadExport(rawUrl, requestToken, format = "csv") {
  const normalizedFormat = megWorkspaceNormalizeExportFormat(format, "csv");
  const context = await megWorkspaceResolveContext(requestToken);
  const response = await megWorkspaceFetchResponse(rawUrl, requestToken, {
    format: normalizedFormat,
    context,
  });
  if (!response.responseOk) {
    throw new Error(String(response.bodyText || `${normalizedFormat.toUpperCase()} request failed (${response.status || 0})`));
  }

  const fileName = megWorkspaceBuildExportFileName(context, rawUrl, normalizedFormat);
  const mimeType = megWorkspaceResolveDownloadMimeType(normalizedFormat, response.contentType);
  const payloadText =
    normalizedFormat === "html"
      ? rewriteMegWorkspaceHtmlExportLinks(response.bodyText, {
          programmerId: String(context?.programmer?.programmerId || "").trim(),
          programmerName: String(context?.programmer?.programmerName || context?.programmer?.displayName || "").trim(),
          environmentKey: String(getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim(),
          environmentLabel: String(getActiveAdobePassEnvironment()?.label || "").trim(),
        })
      : response.bodyText;
  megWorkspaceDownloadFile(payloadText, fileName, mimeType);
  return {
    fileName,
    format: normalizedFormat,
  };
}

async function megWorkspaceDownloadTearsheet(requestToken, options = {}) {
  const context = await megWorkspaceResolveContext(requestToken);
  const programmer = context?.programmer || null;
  if (!programmer?.programmerId) {
    throw new Error("Select an ESM-scoped programmer to generate MEGTOOL.");
  }
  const authContext = await resolveClickEsmAuthContext(context, requestToken, {
    source: "meg-workspace-tearsheet",
  });
  const exportPayload = buildUnderparTearsheetExportPayload(programmer, {
    serviceKey: "esm",
    appInfo: context?.appInfo || null,
    credential:
      normalizeUnderparVaultDcrCache(
        loadDcrCache(String(programmer?.programmerId || ""), String(context?.appInfo?.guid || "")) || null
      ) || {
        clientId: String(authContext?.clientId || "").trim(),
        clientSecret: String(authContext?.clientSecret || "").trim(),
        accessToken: String(authContext?.accessToken || "").trim(),
        tokenExpiresAt: 0,
        tokenScope: "",
        serviceScope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
        tokenRequestedScope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
      },
    passVaultRecord: context?.passVaultRecord || null,
    requestorIds: Array.isArray(context?.requestorIds) ? context.requestorIds : [],
    requestorCatalogIds: Array.isArray(context?.requestorCatalogIds) ? context.requestorCatalogIds : [],
    mvpdIds: Array.isArray(context?.mvpdIds) ? context.mvpdIds : [],
    includeSavedQueries: true,
  });
  const snapshot = buildMegWorkspaceTearsheetSnapshot(context, {
    ...options,
    exportPayload,
  });
  const [templateText, stylesheetText, runtimeText] = await Promise.all([
    loadMegWorkspaceTemplateText(),
    loadMegWorkspaceStylesheetText(),
    loadMegWorkspaceRuntimeText(),
  ]);
  const outputHtml = buildMegWorkspaceTearsheetHtml(snapshot, templateText, stylesheetText, runtimeText, {
    clientId: authContext.clientId,
    clientSecret: authContext.clientSecret,
    accessToken: authContext.accessToken,
    mgmtBase: String(snapshot?.adobePassEnvironment?.mgmtBase || DEFAULT_ADOBEPASS_ENVIRONMENT.mgmtBase).trim(),
    spBase: String(snapshot?.adobePassEnvironment?.spBase || DEFAULT_ADOBEPASS_ENVIRONMENT.spBase).trim(),
  });
  const fileName = buildMegWorkspaceTearsheetFileName(snapshot);
  await downloadClickEsmHtmlFile(outputHtml, fileName);
  return {
    fileName,
    programmerLabel: authContext.programmerLabel,
  };
}

function nextEsmWorkspaceControllerStateVersion() {
  state.esmWorkspaceControllerStateVersion = Number(state.esmWorkspaceControllerStateVersion || 0) + 1;
  return state.esmWorkspaceControllerStateVersion;
}

function buildEsmWorkspaceControllerContextKey(
  programmerId = "",
  requestToken = state.premiumPanelRequestToken,
  environmentKey = getActiveAdobePassEnvironmentKey()
) {
  const normalizedEnvironmentKey =
    String(environmentKey || getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() ||
    DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const normalizedProgrammerId = String(programmerId || "").trim() || "no-programmer";
  const normalizedRequestToken = Math.max(0, Number(requestToken || 0));
  return `${normalizedEnvironmentKey}::${normalizedProgrammerId}::${normalizedRequestToken}`;
}

function esmWorkspaceGetControllerStatePayload(esmWorkspaceState) {
  const selections = getGlobalRequestorMvpdSelections();
  const requestorIds = selections.requestorIds;
  const mvpdIds = selections.mvpdIds;
  const profileHarvestContext = {
    programmerId: String(esmWorkspaceState?.programmer?.programmerId || ""),
    requestorId: String(requestorIds[0] || ""),
    mvpd: String(mvpdIds[0] || ""),
  };
  const profileHarvest = getRestV2ProfileHarvestForContext(profileHarvestContext);
  const profileHarvestList = getRestV2ProfileHarvestBucketForProgrammer(profileHarvestContext.programmerId);
  const adobePassEnvironment = {
    ...getActiveAdobePassEnvironment(),
  };
  const programmerId = String(esmWorkspaceState?.programmer?.programmerId || "");
  const premiumPanelRequestToken = Math.max(0, Number(state.premiumPanelRequestToken || 0));
  const workspaceContextKey = buildEsmWorkspaceControllerContextKey(
    programmerId,
    premiumPanelRequestToken,
    adobePassEnvironment?.key
  );
  return {
    controllerOnline: Boolean(esmWorkspaceState?.section?.isConnected),
    slack: getUnderparWorkspaceSlackStatePayload(),
    esmAvailable: true,
    esmAvailabilityResolved: true,
    esmContainerVisible: true,
    programmerId,
    programmerName: String(esmWorkspaceState?.programmer?.programmerName || ""),
    programmerHydrationReady: isProgrammerWorkspaceHydrationReady(programmerId),
    adobePassEnvironment,
    adobePassEnvironmentKey: String(adobePassEnvironment?.key || "").trim(),
    requestorIds,
    mvpdIds,
    premiumPanelRequestToken,
    workspaceContextKey,
    controllerStateVersion: nextEsmWorkspaceControllerStateVersion(),
    profileHarvest:
      profileHarvest && typeof profileHarvest === "object"
        ? {
            ...profileHarvest,
          }
        : null,
    profileHarvestList:
      profileHarvestList.length > 0
        ? profileHarvestList.map((item) => ({
            ...item,
          }))
        : [],
    updatedAt: Date.now(),
  };
}

function hasResolvedPremiumServiceSnapshotForEsm(services = null) {
  if (!services || typeof services !== "object") {
    return false;
  }
  const keys = ["degradation", "degradationApps", "esm", "restV2", "restV2Apps", "cm", "cmMvpd"];
  return keys.some((key) => Object.prototype.hasOwnProperty.call(services, key));
}

function esmWorkspaceGetSelectedControllerStatePayload(programmer = null, services = null, options = {}) {
  const resolvedProgrammer =
    programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
  // `services === null` means "loading / unknown" and must not fallback to cached service state.
  const resolvedServices = services && typeof services === "object" ? services : null;
  const controllerReason = String(options?.controllerReason || "").trim();
  const hasResolvedSnapshot = hasResolvedPremiumServiceSnapshotForEsm(resolvedServices);

  const selections = getGlobalRequestorMvpdSelections();
  const requestorIds = selections.requestorIds;
  const mvpdIds = selections.mvpdIds;
  let esmAvailable = null;
  if (hasResolvedSnapshot) {
    esmAvailable = hasEsmScopedApp(resolvedServices);
  }
  let esmContainerVisible = null;
  if (options?.esmContainerVisible === true) {
    esmContainerVisible = true;
  } else if (options?.esmContainerVisible === false) {
    esmContainerVisible = false;
  } else if (hasResolvedSnapshot) {
    esmContainerVisible = hasEsmScopedApp(resolvedServices);
  }
  if (esmContainerVisible === true) {
    esmAvailable = true;
  }
  const esmAvailabilityResolved =
    options?.esmAvailabilityResolved === true || options?.esmAvailabilityResolved === false
      ? options.esmAvailabilityResolved === true
      : hasResolvedSnapshot || esmContainerVisible === true || esmContainerVisible === false;
  const profileHarvestContext = {
    programmerId: String(resolvedProgrammer?.programmerId || ""),
    requestorId: String(requestorIds[0] || ""),
    mvpd: String(mvpdIds[0] || ""),
  };
  const profileHarvest = getRestV2ProfileHarvestForContext(profileHarvestContext);
  const profileHarvestList = getRestV2ProfileHarvestBucketForProgrammer(profileHarvestContext.programmerId);
  const adobePassEnvironment = {
    ...getActiveAdobePassEnvironment(),
  };
  const programmerId = String(resolvedProgrammer?.programmerId || "");
  const premiumPanelRequestToken = Math.max(0, Number(state.premiumPanelRequestToken || 0));
  const programmerHydrationReady =
    options?.programmerHydrationReady === true || options?.programmerHydrationReady === false
      ? options.programmerHydrationReady === true
      : isProgrammerWorkspaceHydrationReady(programmerId);
  const workspaceContextKey = buildEsmWorkspaceControllerContextKey(
    programmerId,
    premiumPanelRequestToken,
    adobePassEnvironment?.key
  );

  return {
    controllerOnline: false,
    slack: getUnderparWorkspaceSlackStatePayload(),
    esmAvailable,
    esmAvailabilityResolved,
    esmContainerVisible,
    programmerId,
    programmerName: String(resolvedProgrammer?.programmerName || ""),
    programmerHydrationReady,
    adobePassEnvironment,
    adobePassEnvironmentKey: String(adobePassEnvironment?.key || "").trim(),
    requestorIds,
    mvpdIds,
    premiumPanelRequestToken,
    workspaceContextKey,
    controllerStateVersion: nextEsmWorkspaceControllerStateVersion(),
    profileHarvest:
      profileHarvest && typeof profileHarvest === "object"
        ? {
            ...profileHarvest,
          }
        : null,
    profileHarvestList:
      profileHarvestList.length > 0
        ? profileHarvestList.map((item) => ({
            ...item,
          }))
        : [],
    controllerReason,
    updatedAt: Date.now(),
  };
}

function hasEsmScopedApp(services) {
  return Boolean(String(services?.esm?.guid || "").trim());
}

function esmWorkspaceBroadcastSelectedControllerState(programmer = null, services = null, targetWindowId = 0, options = {}) {
  const resolvedWindowId = Number(targetWindowId || 0) || Number(state.esmWorkspaceWorkspaceWindowId || 0);
  const payload = esmWorkspaceGetSelectedControllerStatePayload(programmer, services, options);
  void esmWorkspaceSendWorkspaceMessage("controller-state", payload, {
    targetWindowId: resolvedWindowId,
  });
  blondieTimeWorkspaceBroadcastSelectedControllerState(programmer, services, 0, options);
  megWorkspaceBroadcastSelectedControllerState(programmer, services, 0, options);
}

async function esmWorkspaceSendWorkspaceMessage(event, payload = {}, options = {}) {
  const targetWindowId = Number(options.targetWindowId || 0);
  try {
    const message = {
      type: ESM_WORKSPACE_MESSAGE_TYPE,
      channel: "workspace-event",
      event: String(event || ""),
      payload,
    };
    if (targetWindowId > 0) {
      message.targetWindowId = targetWindowId;
    }
    await chrome.runtime.sendMessage(message);
  } catch {
    // Ignore when no workspace listener is active.
  }
}

async function esmWorkspaceSendControllerQuery(action, payload = {}, options = {}) {
  const targetWindowId = Number(options.targetWindowId || 0);
  try {
    const message = {
      type: ESM_WORKSPACE_MESSAGE_TYPE,
      channel: "controller-query",
      action: String(action || ""),
      ...payload,
    };
    if (targetWindowId > 0) {
      message.targetWindowId = targetWindowId;
    }
    return await chrome.runtime.sendMessage(message);
  } catch {
    return null;
  }
}

function esmWorkspaceBuildCanonicalRequestIdentity(rawValue = "") {
  const normalizedRequestPath = normalizeUnderparEsmRequestPath(rawValue);
  if (!normalizedRequestPath) {
    return "";
  }
  try {
    const baseUrl =
      String(getActiveAdobePassEnvironment()?.esmBase || `${ADOBE_MGMT_BASE}${UNDERPAR_ESM_NODE_PATH_PREFIX}/`).trim() ||
      `${ADOBE_MGMT_BASE}${UNDERPAR_ESM_NODE_PATH_PREFIX}/`;
    const parsed = new URL(normalizedRequestPath, baseUrl || ADOBE_MGMT_BASE);
    parsed.hash = "";
    parsed.searchParams.delete("media-company");
    const normalizedPath = String(parsed.pathname || "").replace(/\/+$/g, "") || "/";
    const entries = [];
    parsed.searchParams.forEach((value, key) => {
      const normalizedKey = String(key || "").trim();
      if (!normalizedKey) {
        return;
      }
      entries.push([normalizedKey, String(value || "").trim()]);
    });
    entries.sort((left, right) => {
      const leftKey = `${String(left[0] || "").trim().toLowerCase()}\u0000${String(left[1] || "").trim()}`;
      const rightKey = `${String(right[0] || "").trim().toLowerCase()}\u0000${String(right[1] || "").trim()}`;
      return leftKey.localeCompare(rightKey, undefined, { numeric: true, sensitivity: "base" });
    });
    const search = entries
      .map(([key, value]) => `${encodeURIComponent(String(key || "").trim())}=${encodeURIComponent(String(value || "").trim())}`)
      .join("&");
    return `${normalizedPath}${search ? `?${search}` : ""}`;
  } catch {
    return normalizedRequestPath;
  }
}

function esmWorkspaceBuildOriginCardKey(endpoint, options = {}) {
  const explicitKey = esmWorkspaceBuildCanonicalRequestIdentity(options?.originCardKey || "");
  if (explicitKey) {
    return explicitKey;
  }
  const environment = getActiveAdobePassEnvironment();
  const baseUrl =
    String(environment?.esmBase || environment?.mgmtBase || ADOBE_MGMT_BASE).trim() || ADOBE_MGMT_BASE;
  const candidateUrls = [
    options?.seedEndpointUrl,
    options?.requestUrlOverride,
    endpoint?.url,
    options?.seedRequestUrl,
  ];
  const rawOriginUrl =
    candidateUrls
      .map((value) => stripMegWorkspaceMediaCompanyQueryParam(String(value || "").trim()))
      .find(Boolean) || "";
  if (!rawOriginUrl) {
    return "";
  }
  const directIdentity = esmWorkspaceBuildCanonicalRequestIdentity(rawOriginUrl);
  if (directIdentity) {
    return directIdentity;
  }
  try {
    const absoluteIdentity = esmWorkspaceBuildCanonicalRequestIdentity(new URL(rawOriginUrl, baseUrl).toString());
    if (absoluteIdentity) {
      return absoluteIdentity;
    }
  } catch {
    // Ignore malformed fallback URLs and keep the raw stripped value below.
  }
  return stripMegWorkspaceMediaCompanyQueryParam(String(rawOriginUrl || "").split("#", 1)[0].trim());
}

async function esmWorkspaceFindExistingOriginCard(originCardKey = "", targetWindowId = 0) {
  const normalizedOriginCardKey = String(originCardKey || "").trim();
  if (!normalizedOriginCardKey) {
    return null;
  }
  const result = await esmWorkspaceSendControllerQuery(
    "find-origin-card",
    { originCardKey: normalizedOriginCardKey },
    { targetWindowId }
  );
  if (result?.ok !== true || !result?.card || typeof result.card !== "object") {
    return null;
  }
  return result.card;
}

function esmWorkspaceBroadcastControllerState(esmWorkspaceState, targetWindowId = 0) {
  if (!esmWorkspaceState) {
    return;
  }
  const resolvedWindowId =
    Number(targetWindowId || 0) || Number(esmWorkspaceState.controllerWindowId || 0) || Number(state.esmWorkspaceWorkspaceWindowId || 0);
  const payload = esmWorkspaceGetControllerStatePayload(esmWorkspaceState);
  void esmWorkspaceSendWorkspaceMessage("controller-state", payload, {
    targetWindowId: resolvedWindowId,
  });
  blondieTimeWorkspaceBroadcastControllerState(esmWorkspaceState);
  megWorkspaceBroadcastControllerState(esmWorkspaceState);
}

async function esmWorkspaceEnsureWorkspaceTab(options = {}) {
  ensureEsmWorkspaceRuntimeListener();
  ensureEsmWorkspaceWorkspaceTabWatcher();
  const shouldActivate = options.activate !== false;
  const requestedWindowId = Number(options.windowId || 0);
  const targetWindowId = requestedWindowId > 0 ? requestedWindowId : await esmWorkspaceGetCurrentWindowId();
  const useWindowFilter = targetWindowId > 0;
  let workspaceTab = null;
  let createdWorkspaceTab = false;
  let reusedReadyCandidate = false;

  const boundTabId = esmWorkspaceGetBoundWorkspaceTabId(targetWindowId);
  if (boundTabId > 0) {
    try {
      const existing = await chrome.tabs.get(boundTabId);
      if (esmWorkspaceIsWorkspaceTab(existing) && (!useWindowFilter || Number(existing.windowId || 0) === targetWindowId)) {
        workspaceTab = existing;
        reusedReadyCandidate = String(existing?.status || "").trim().toLowerCase() === "complete";
      }
    } catch {
      esmWorkspaceUnbindWorkspaceTab(boundTabId);
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    try {
      const allTabs = await chrome.tabs.query(useWindowFilter ? { windowId: targetWindowId } : { currentWindow: true });
      workspaceTab = allTabs.find((tab) => esmWorkspaceIsWorkspaceTab(tab)) || null;
      reusedReadyCandidate = String(workspaceTab?.status || "").trim().toLowerCase() === "complete";
    } catch {
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    workspaceTab = await chrome.tabs.create({
      url: esmWorkspaceGetWorkspaceUrl(),
      active: shouldActivate,
      ...(useWindowFilter ? { windowId: targetWindowId } : {}),
    });
    createdWorkspaceTab = Boolean(workspaceTab?.id);
  } else if (shouldActivate && workspaceTab.id) {
    try {
      workspaceTab = await chrome.tabs.update(workspaceTab.id, { active: true });
      if (Number(workspaceTab?.windowId || 0) > 0) {
        await chrome.windows.update(Number(workspaceTab.windowId), { focused: true });
      }
    } catch {
      // Ignore activation failures; workspace may still be available.
    }
  }

  esmWorkspaceBindWorkspaceTab(workspaceTab?.windowId, workspaceTab?.id);
  if (createdWorkspaceTab) {
    esmInvalidateWorkspaceReady(workspaceTab?.windowId, workspaceTab?.id);
  } else if (reusedReadyCandidate || esmIsWorkspaceReady(workspaceTab?.windowId, workspaceTab?.id)) {
    esmMarkWorkspaceReady(workspaceTab?.windowId, workspaceTab?.id);
  }
  return workspaceTab;
}

async function blondieTimeWorkspaceSendWorkspaceMessage(event, payload = {}, options = {}) {
  const targetWindowId = Number(options.targetWindowId || 0);
  try {
    const message = {
      type: BLONDIE_TIME_WORKSPACE_MESSAGE_TYPE,
      channel: "workspace-event",
      event: String(event || ""),
      payload,
    };
    if (targetWindowId > 0) {
      message.targetWindowId = targetWindowId;
    }
    await chrome.runtime.sendMessage(message);
  } catch {
    // Ignore when no workspace listener is active.
  }
}

function blondieTimeWorkspaceBroadcastSelectedControllerState(programmer = null, services = null, targetWindowId = 0, options = {}) {
  const targetWindowIds = targetWindowId > 0
    ? [Number(targetWindowId)]
    : collectBoundWorkspaceWindowIds(state.blondieTimeWorkspaceWindowId, state.blondieTimeWorkspaceTabIdByWindowId);
  if (targetWindowIds.length === 0) {
    return;
  }
  const payload = esmWorkspaceGetSelectedControllerStatePayload(programmer, services, options);
  for (const resolvedWindowId of targetWindowIds) {
    void blondieTimeWorkspaceSendWorkspaceMessage("controller-state", payload, {
      targetWindowId: resolvedWindowId,
    });
  }
}

function blondieTimeWorkspaceBroadcastControllerState(esmWorkspaceState, targetWindowId = 0) {
  if (!esmWorkspaceState) {
    return;
  }
  const targetWindowIds = targetWindowId > 0
    ? [Number(targetWindowId)]
    : collectBoundWorkspaceWindowIds(state.blondieTimeWorkspaceWindowId, state.blondieTimeWorkspaceTabIdByWindowId);
  if (targetWindowIds.length === 0) {
    return;
  }
  const payload = esmWorkspaceGetControllerStatePayload(esmWorkspaceState);
  for (const resolvedWindowId of targetWindowIds) {
    void blondieTimeWorkspaceSendWorkspaceMessage("controller-state", payload, {
      targetWindowId: resolvedWindowId,
    });
  }
}

async function blondieTimeWorkspaceEnsureWorkspaceTab(options = {}) {
  ensureBlondieTimeWorkspaceRuntimeListener();
  ensureBlondieTimeWorkspaceTabWatcher();
  const shouldActivate = options.activate !== false;
  const requestedWindowId = Number(options.windowId || 0);
  const targetWindowId = requestedWindowId > 0 ? requestedWindowId : await esmWorkspaceGetCurrentWindowId();
  const useWindowFilter = targetWindowId > 0;
  let workspaceTab = null;

  const boundTabId = blondieTimeWorkspaceGetBoundWorkspaceTabId(targetWindowId);
  if (boundTabId > 0) {
    try {
      const existing = await chrome.tabs.get(boundTabId);
      if (
        blondieTimeWorkspaceIsWorkspaceTab(existing) &&
        (!useWindowFilter || Number(existing.windowId || 0) === targetWindowId)
      ) {
        workspaceTab = existing;
      }
    } catch {
      blondieTimeWorkspaceUnbindWorkspaceTab(boundTabId);
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    try {
      const allTabs = await chrome.tabs.query(useWindowFilter ? { windowId: targetWindowId } : { currentWindow: true });
      workspaceTab = allTabs.find((tab) => blondieTimeWorkspaceIsWorkspaceTab(tab)) || null;
    } catch {
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    workspaceTab = await chrome.tabs.create({
      url: blondieTimeWorkspaceGetWorkspaceUrl(),
      active: shouldActivate,
      ...(useWindowFilter ? { windowId: targetWindowId } : {}),
    });
  } else if (shouldActivate && workspaceTab.id) {
    try {
      workspaceTab = await chrome.tabs.update(workspaceTab.id, { active: true });
      if (Number(workspaceTab?.windowId || 0) > 0) {
        await chrome.windows.update(Number(workspaceTab.windowId), { focused: true });
      }
    } catch {
      // Ignore activation failures; workspace may still be available.
    }
  }

  blondieTimeWorkspaceBindWorkspaceTab(workspaceTab?.windowId, workspaceTab?.id);
  return workspaceTab;
}

async function megWorkspaceSendWorkspaceMessage(event, payload = {}, options = {}) {
  const targetWindowId = Number(options.targetWindowId || 0);
  try {
    const message = {
      type: MEG_WORKSPACE_MESSAGE_TYPE,
      channel: "workspace-event",
      event: String(event || ""),
      payload,
    };
    if (targetWindowId > 0) {
      message.targetWindowId = targetWindowId;
    }
    await chrome.runtime.sendMessage(message);
  } catch {
    // Ignore when no workspace listener is active.
  }
}

function megWorkspaceGetBroadcastWindowIds(targetWindowId = 0) {
  const normalizedTargetWindowId = Number(targetWindowId || 0);
  if (normalizedTargetWindowId > 0) {
    return [normalizedTargetWindowId];
  }
  return collectBoundWorkspaceWindowIds(state.megWorkspaceWindowId, state.megWorkspaceTabIdByWindowId);
}

function megWorkspaceBroadcastSelectedControllerState(programmer = null, services = null, targetWindowId = 0, options = {}) {
  const targetWindowIds = megWorkspaceGetBroadcastWindowIds(targetWindowId);
  if (targetWindowIds.length === 0) {
    return;
  }
  const payload = esmWorkspaceGetSelectedControllerStatePayload(programmer, services, options);
  for (const resolvedWindowId of targetWindowIds) {
    void megWorkspaceSendWorkspaceMessage("controller-state", payload, {
      targetWindowId: resolvedWindowId,
    });
  }
}

function megWorkspaceBroadcastControllerState(esmWorkspaceState, targetWindowId = 0) {
  if (!esmWorkspaceState) {
    return;
  }
  const targetWindowIds = megWorkspaceGetBroadcastWindowIds(targetWindowId);
  if (targetWindowIds.length === 0) {
    return;
  }
  const payload = esmWorkspaceGetControllerStatePayload(esmWorkspaceState);
  for (const resolvedWindowId of targetWindowIds) {
    void megWorkspaceSendWorkspaceMessage("controller-state", payload, {
      targetWindowId: resolvedWindowId,
    });
  }
}

async function megWorkspaceEnsureWorkspaceTab(options = {}) {
  ensureMegWorkspaceRuntimeListener();
  ensureMegWorkspaceWorkspaceTabWatcher();
  const shouldActivate = options.activate !== false;
  const requestedWindowId = Number(options.windowId || 0);
  const targetWindowId = requestedWindowId > 0 ? requestedWindowId : await esmWorkspaceGetCurrentWindowId();
  const useWindowFilter = targetWindowId > 0;
  let workspaceTab = null;

  const boundTabId = megWorkspaceGetBoundWorkspaceTabId(targetWindowId);
  if (boundTabId > 0) {
    try {
      const existing = await chrome.tabs.get(boundTabId);
      if (megWorkspaceIsWorkspaceTab(existing) && (!useWindowFilter || Number(existing.windowId || 0) === targetWindowId)) {
        workspaceTab = existing;
      }
    } catch {
      megWorkspaceUnbindWorkspaceTab(boundTabId);
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    try {
      const allTabs = await chrome.tabs.query(useWindowFilter ? { windowId: targetWindowId } : { currentWindow: true });
      workspaceTab = allTabs.find((tab) => megWorkspaceIsWorkspaceTab(tab)) || null;
    } catch {
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    workspaceTab = await chrome.tabs.create({
      url: megWorkspaceGetWorkspaceUrl(),
      active: shouldActivate,
      ...(useWindowFilter ? { windowId: targetWindowId } : {}),
    });
  } else if (shouldActivate && workspaceTab.id) {
    try {
      workspaceTab = await chrome.tabs.update(workspaceTab.id, { active: true });
      if (Number(workspaceTab?.windowId || 0) > 0) {
        await chrome.windows.update(Number(workspaceTab.windowId), { focused: true });
      }
    } catch {
      // Ignore activation failures; workspace may still be available.
    }
  }

  megWorkspaceBindWorkspaceTab(workspaceTab?.windowId, workspaceTab?.id);
  return workspaceTab;
}

function getEsmWorkspaceRecordingSelections() {
  return getGlobalRequestorMvpdSelections();
}

function toEsmWorkspaceRecordingContext(esmWorkspaceState) {
  const selections = getEsmWorkspaceRecordingSelections();
  return {
    serviceType: "esm",
    programmerId: String(esmWorkspaceState?.programmer?.programmerId || ""),
    programmerName: String(esmWorkspaceState?.programmer?.programmerName || ""),
    requestorIds: selections.requestorIds.slice(0, 24),
    mvpdIds: selections.mvpdIds.slice(0, 24),
    requestorId: String(selections.requestorIds[0] || ""),
    mvpd: String(selections.mvpdIds[0] || ""),
    appInfo: esmWorkspaceState?.appInfo
      ? {
          guid: String(esmWorkspaceState.appInfo.guid || ""),
          appName: String(esmWorkspaceState.appInfo.appName || esmWorkspaceState.appInfo.guid || ""),
          scopes: Array.isArray(esmWorkspaceState.appInfo.scopes) ? esmWorkspaceState.appInfo.scopes.slice(0, 12) : [],
        }
      : null,
    startedAt: Date.now(),
  };
}

function getActiveEsmWorkspaceDebugFlowId() {
  if (!state.esmWorkspaceRecordingActive) {
    return "";
  }
  return String(state.esmWorkspaceDebugFlowId || "").trim();
}

function isEsmWorkspaceDebuggableTab(tab = null) {
  const tabId = Number(tab?.id || 0);
  if (!Number.isFinite(tabId) || tabId <= 0) {
    return false;
  }

  const url = String(tab?.url || tab?.pendingUrl || "").trim().toLowerCase();
  if (!url) {
    return false;
  }

  if (
    url.startsWith("chrome-extension://") ||
    url.startsWith("chrome://") ||
    url.startsWith("edge://") ||
    url.startsWith("about:") ||
    url.startsWith("devtools://")
  ) {
    return false;
  }

  return /^https?:\/\//.test(url);
}

function rememberLastDebuggableWebTab(tab = null) {
  if (!isEsmWorkspaceDebuggableTab(tab)) {
    return;
  }
  state.lastDebuggableWebTabId = Number(tab?.id || 0);
}

function scoreDebuggableWebTab(tab = null, preferredWindowId = 0) {
  if (!isEsmWorkspaceDebuggableTab(tab)) {
    return Number.NEGATIVE_INFINITY;
  }
  const tabId = Number(tab?.id || 0);
  const windowId = Number(tab?.windowId || 0);
  const active = tab?.active === true;
  const lastAccessed = Number(tab?.lastAccessed || 0);
  const url = String(tab?.url || tab?.pendingUrl || "").trim().toLowerCase();
  let score = 0;
  if (tabId > 0 && tabId === Number(state.lastDebuggableWebTabId || 0)) {
    score += 2200;
  }
  if (preferredWindowId > 0 && windowId === preferredWindowId) {
    score += 1600;
  }
  if (active) {
    score += 700;
  }
  if (url.includes("experience.adobe.com/#/@adobepass") || url.includes("experience.adobe.com/?shell_ims=prod#/@adobepass")) {
    score += 550;
  }
  if (url.includes("experience-stage.adobe.com/#/@adobepass") || url.includes("experience-stage.adobe.com/?shell_ims=prod#/@adobepass")) {
    score += 550;
  }
  if (
    url.includes("experience.adobe.com") ||
    url.includes("experience-stage.adobe.com") ||
    /(?:sp|api)\.auth(?:-staging)?\.adobe\.com/i.test(url) ||
    url.includes("config.adobeprimetime.com") ||
    url.includes("cm-reports.adobeprimetime.com")
  ) {
    score += 300;
  }
  if (Number.isFinite(lastAccessed) && lastAccessed > 0) {
    score += Math.floor(lastAccessed / 1000);
  }
  return score;
}

async function findBestDebuggableWebTab(preferredWindowId = 0) {
  let tabs = [];
  try {
    tabs = await chrome.tabs.query({});
  } catch {
    tabs = [];
  }
  if (!Array.isArray(tabs) || tabs.length === 0) {
    return null;
  }
  const debuggableTabs = tabs.filter((tab) => isEsmWorkspaceDebuggableTab(tab));
  if (debuggableTabs.length === 0) {
    return null;
  }
  debuggableTabs.sort((left, right) => {
    const scoreDiff = scoreDebuggableWebTab(right, preferredWindowId) - scoreDebuggableWebTab(left, preferredWindowId);
    if (scoreDiff !== 0) {
      return scoreDiff;
    }
    return Number(right?.id || 0) - Number(left?.id || 0);
  });
  const winner = debuggableTabs[0] || null;
  if (winner) {
    rememberLastDebuggableWebTab(winner);
  }
  return winner;
}

async function getEsmWorkspaceDebuggableTabById(tabId) {
  const normalizedTabId = Number(tabId || 0);
  if (!Number.isFinite(normalizedTabId) || normalizedTabId <= 0) {
    return null;
  }

  try {
    const tab = await chrome.tabs.get(normalizedTabId);
    if (!isEsmWorkspaceDebuggableTab(tab)) {
      return null;
    }
    rememberLastDebuggableWebTab(tab);
    return tab;
  } catch {
    return null;
  }
}

async function getEsmWorkspaceActiveTabForWindow(windowId = 0) {
  const normalizedWindowId = Number(windowId || 0);
  if (!Number.isFinite(normalizedWindowId) || normalizedWindowId <= 0) {
    return null;
  }

  try {
    const tabs = await chrome.tabs.query({
      active: true,
      windowId: normalizedWindowId,
    });
    return Array.isArray(tabs) && tabs.length > 0 ? tabs[0] : null;
  } catch {
    return null;
  }
}

async function resolveEsmWorkspaceDebugTargetTabId(options = {}) {
  const preferredWindowId = Number(options.preferredWindowId || 0);
  const fallbackTabId = Number(options.fallbackTabId || 0);

  const candidateTabIds = [];
  const pushCandidateTabId = (tabId) => {
    const normalizedTabId = Number(tabId || 0);
    if (!Number.isFinite(normalizedTabId) || normalizedTabId <= 0) {
      return;
    }
    if (!candidateTabIds.includes(normalizedTabId)) {
      candidateTabIds.push(normalizedTabId);
    }
  };

  pushCandidateTabId(state.esmWorkspaceActivityDebugTargetTabId);
  pushCandidateTabId(fallbackTabId);
  pushCandidateTabId(state.restV2LastLaunchTabId);
  pushCandidateTabId(state.lastDebuggableWebTabId);

  const preferredWindowTab = await getEsmWorkspaceActiveTabForWindow(preferredWindowId);
  if (preferredWindowTab) {
    pushCandidateTabId(preferredWindowTab.id);
  }

  const activeTab = await getCurrentActiveTab();
  if (activeTab) {
    pushCandidateTabId(activeTab.id);
  }

  for (const candidateTabId of candidateTabIds) {
    const tab = await getEsmWorkspaceDebuggableTabById(candidateTabId);
    if (tab) {
      state.esmWorkspaceActivityDebugTargetTabId = Number(tab.id || 0);
      return Number(tab.id || 0);
    }
  }

  const fallbackTab = await findBestDebuggableWebTab(preferredWindowId);
  if (fallbackTab) {
    state.esmWorkspaceActivityDebugTargetTabId = Number(fallbackTab.id || 0);
    return Number(fallbackTab.id || 0);
  }

  state.esmWorkspaceActivityDebugTargetTabId = 0;
  return 0;
}

function buildEsmWorkspaceDebugContext(esmWorkspaceState = null) {
  const selections = getGlobalRequestorMvpdSelections();
  const programmer = esmWorkspaceState?.programmer || resolveSelectedProgrammer() || null;
  return {
    serviceType: "esm",
    programmerId: String(programmer?.programmerId || ""),
    programmerName: String(programmer?.programmerName || ""),
    requestorId: String(selections.requestorIds[0] || ""),
    mvpd: String(selections.mvpdIds[0] || ""),
    requestorIds: selections.requestorIds.slice(0, 24),
    mvpdIds: selections.mvpdIds.slice(0, 24),
  };
}

async function ensureEsmWorkspaceActivityDebugFlow(options = {}) {
  const activeRecordingFlowId = getActiveEsmWorkspaceDebugFlowId();
  if (activeRecordingFlowId) {
    return activeRecordingFlowId;
  }

  const preferredWindowId = Number(options.preferredWindowId || 0);
  const fallbackTabId = Number(options.fallbackTabId || 0);
  const existingFlowId = String(state.esmWorkspaceActivityDebugFlowId || "").trim();

  if (existingFlowId) {
    const previousTargetTabId = Number(state.esmWorkspaceActivityDebugTargetTabId || 0);
    const targetTabId = await resolveEsmWorkspaceDebugTargetTabId({
      preferredWindowId,
      fallbackTabId,
    });
    if (targetTabId > 0 && targetTabId !== previousTargetTabId) {
      const context = buildEsmWorkspaceDebugContext(getActiveEsmWorkspaceState());
      const bound = await bindRestV2DebugFlowToTab(existingFlowId, targetTabId, {
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        serviceType: "esm",
        eventsOnly: true,
        captureNetwork: false,
      });
      if (bound) {
        state.esmWorkspaceActivityDebugTargetTabId = targetTabId;
      }
    }
    return existingFlowId;
  }

  if (state.esmWorkspaceActivityDebugFlowPromise) {
    return state.esmWorkspaceActivityDebugFlowPromise;
  }

  const createPromise = (async () => {
    const context = buildEsmWorkspaceDebugContext(getActiveEsmWorkspaceState());
    if (!context.programmerId) {
      return "";
    }

    const flowId = await startRestV2DebugFlow(context, "esm-activity");
    if (!flowId) {
      return "";
    }

    state.esmWorkspaceActivityDebugFlowId = flowId;

    const targetTabId = await resolveEsmWorkspaceDebugTargetTabId({
      preferredWindowId,
      fallbackTabId,
    });
    if (targetTabId > 0) {
      const bound = await bindRestV2DebugFlowToTab(flowId, targetTabId, {
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        serviceType: "esm",
        eventsOnly: true,
        captureNetwork: false,
      });
      if (bound) {
        state.esmWorkspaceActivityDebugTargetTabId = targetTabId;
      }
    }

    emitRestV2DebugEvent(flowId, {
      source: "extension",
      service: "esm",
      phase: "activity-flow-start",
      trigger: String(options.reason || "esm-activity"),
      programmerId: context.programmerId,
      requestorId: context.requestorId,
      mvpd: context.mvpd,
      tabId: Number(state.esmWorkspaceActivityDebugTargetTabId || 0),
    });

    return flowId;
  })()
    .catch(() => "")
    .finally(() => {
      state.esmWorkspaceActivityDebugFlowPromise = null;
    });

  state.esmWorkspaceActivityDebugFlowPromise = createPromise;
  return createPromise;
}

function clearEsmWorkspaceActivityDebugFlow(reason = "state-reset", options = {}) {
  const normalizedReason = String(reason || "state-reset").trim() || "state-reset";
  const flowId = String(state.esmWorkspaceActivityDebugFlowId || "").trim();
  const shouldStopFlow = options?.stopFlow === true;

  if (flowId && shouldStopFlow) {
    void stopRestV2DebugFlowAndSnapshot(flowId, normalizedReason);
  }

  state.esmWorkspaceActivityDebugFlowId = "";
  state.esmWorkspaceActivityDebugFlowPromise = null;
  state.esmWorkspaceActivityDebugTargetTabId = 0;
}

function emitEsmWorkspaceDebugEvent(flowId, event = {}) {
  const workspaceKey = normalizeWorkspaceDebugKey(firstNonEmptyString([event?.workspaceKey, "esm-workspace"]));
  const workspaceOrigin = firstNonEmptyString([event?.workspaceOrigin, getWorkspaceDebugLabel(workspaceKey)]);
  const payload = {
    source: "extension",
    service: "esm",
    requestScope: String(event?.requestScope || "esm-workspace"),
    workspaceKey,
    workspaceOrigin,
    ...event,
  };

  const explicitFlowId = String(flowId || "").trim();
  if (explicitFlowId) {
    emitRestV2DebugEvent(explicitFlowId, payload);
    return;
  }

  const activityFlowId = String(state.esmWorkspaceActivityDebugFlowId || "").trim();
  if (activityFlowId) {
    emitRestV2DebugEvent(activityFlowId, payload);
    void ensureEsmWorkspaceActivityDebugFlow({
      reason: String(event?.phase || "esm-activity"),
      preferredWindowId: Number(event?.windowId || event?.controllerWindowId || 0),
      fallbackTabId: Number(event?.tabId || event?.workspaceTabId || 0),
    });
    return;
  }

  void ensureEsmWorkspaceActivityDebugFlow({
    reason: String(event?.phase || "esm-activity"),
    preferredWindowId: Number(event?.windowId || event?.controllerWindowId || 0),
    fallbackTabId: Number(event?.tabId || event?.workspaceTabId || 0),
  }).then((resolvedFlowId) => {
    const normalizedFlowId = String(resolvedFlowId || "").trim();
    if (!normalizedFlowId) {
      return;
    }
    emitRestV2DebugEvent(normalizedFlowId, payload);
  });
}

function setEsmWorkspaceRecordingStatus(esmWorkspaceState, message = "", type = "info") {
  if (!esmWorkspaceState?.recordingStatusElement) {
    return;
  }

  esmWorkspaceState.recordingStatusElement.textContent = String(message || "").trim();
  esmWorkspaceState.recordingStatusElement.classList.remove("success", "error");
  if (type === "success") {
    esmWorkspaceState.recordingStatusElement.classList.add("success");
  } else if (type === "error") {
    esmWorkspaceState.recordingStatusElement.classList.add("error");
  }
}

function syncEsmWorkspaceRecordingControls(esmWorkspaceState) {
  if (!esmWorkspaceState) {
    return;
  }

  const toggleButton = esmWorkspaceState.recordingToggleButton;
  const context = toEsmWorkspaceRecordingContext(esmWorkspaceState);
  const hasProgrammer = Boolean(context.programmerId);

  if (!toggleButton) {
    return;
  }

  const icon = toggleButton.querySelector(".esm-workspace-record-btn-icon");
  const setToggleState = (mode = "idle") => {
    const isRecording = mode === "recording" || mode === "stopping";
    const isStopping = mode === "stopping";

    toggleButton.classList.toggle("is-recording", isRecording);
    toggleButton.classList.toggle("is-stopping", isStopping);
    toggleButton.classList.toggle("is-idle", !isRecording);

    if (icon) {
      icon.classList.remove("esm-workspace-record-btn-icon--record", "esm-workspace-record-btn-icon--stop");
      icon.classList.add(isRecording ? "esm-workspace-record-btn-icon--stop" : "esm-workspace-record-btn-icon--record");
    }
  };

  if (state.esmWorkspaceStopping) {
    setToggleState("stopping");
    toggleButton.disabled = true;
    toggleButton.title = "Finalizing ESM recording...";
    toggleButton.setAttribute("aria-label", "Finalizing ESM recording");
    setEsmWorkspaceRecordingStatus(esmWorkspaceState, "Finalizing ESM recording...");
    return;
  }

  const activeFlowId = getActiveEsmWorkspaceDebugFlowId();
  if (activeFlowId) {
    setToggleState("recording");
    toggleButton.disabled = false;
    toggleButton.title = "Stop ESM recording";
    toggleButton.setAttribute("aria-label", "Stop ESM recording");

    const requestorLabel = context.requestorIds.length > 0 ? context.requestorIds.join(", ") : "all requestors";
    const mvpdLabel = context.mvpdIds.length > 0 ? context.mvpdIds.join(", ") : "all MVPDs";
    setEsmWorkspaceRecordingStatus(
      esmWorkspaceState,
      `Recording ESM flow for ${requestorLabel} / ${mvpdLabel}. Click STOP to end capture.`,
      "success"
    );
    return;
  }

  setToggleState("idle");
  toggleButton.disabled = !hasProgrammer;
  toggleButton.title = "Record ESM";
  toggleButton.setAttribute("aria-label", "Record ESM");

  if (!hasProgrammer) {
    setEsmWorkspaceRecordingStatus(esmWorkspaceState, "Select a Media Company first.");
    return;
  }

  setEsmWorkspaceRecordingStatus(
    esmWorkspaceState,
    "Click RECORD ESM to capture token + ESM API activity in the UP trace."
  );
}

function buildEsmWorkspaceHarFilename(recordingContext = null) {
  const programmer = sanitizeHarFileSegment(recordingContext?.programmerId || "programmer", "programmer");
  const requestors = sanitizeHarFileSegment(
    Array.isArray(recordingContext?.requestorIds) && recordingContext.requestorIds.length > 0
      ? recordingContext.requestorIds.join("-")
      : "all-requestors",
    "all-requestors"
  );
  const mvpds = sanitizeHarFileSegment(
    Array.isArray(recordingContext?.mvpdIds) && recordingContext.mvpdIds.length > 0
      ? recordingContext.mvpdIds.join("-")
      : "all-mvpds",
    "all-mvpds"
  );
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  return `underpar-esm-${programmer}-${requestors}-${mvpds}-${stamp}.har`;
}

function clearEsmWorkspaceRecordingState(reason = "state-reset", options = {}) {
  const shouldStopFlow = options?.stopFlow !== false;
  const activeFlowId = String(state.esmWorkspaceDebugFlowId || "").trim();
  if (activeFlowId && shouldStopFlow) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "recording-force-stop",
      reason: String(reason || "state-reset"),
    });
    void stopRestV2DebugFlowAndSnapshot(activeFlowId, String(reason || "state-reset"));
  }

  state.esmWorkspaceDebugFlowId = "";
  state.esmWorkspaceRecordingActive = false;
  state.esmWorkspaceRecordingStartedAt = 0;
  state.esmWorkspaceRecordingContext = null;
  state.esmWorkspaceStopping = false;
  state.esmWorkspaceTraceViewerWindowId = 0;
  state.esmWorkspaceTraceViewerTabId = 0;
}

async function startEsmWorkspaceEsmRecording(esmWorkspaceState, requestToken) {
  if (!esmWorkspaceState) {
    return;
  }
  if (state.esmWorkspaceStopping) {
    return;
  }
  if (state.esmWorkspaceRecordingActive && state.esmWorkspaceDebugFlowId) {
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    return;
  }
  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    setEsmWorkspaceRecordingStatus(esmWorkspaceState, "ESM view is stale. Refresh this panel first.", "error");
    return;
  }

  const recordingContext = toEsmWorkspaceRecordingContext(esmWorkspaceState);
  if (!recordingContext.programmerId || !recordingContext.appInfo?.guid) {
    setEsmWorkspaceRecordingStatus(esmWorkspaceState, "Missing ESM app context for recording.", "error");
    return;
  }

  state.esmWorkspaceStopping = true;
  syncEsmWorkspaceRecordingControls(esmWorkspaceState);

  try {
    const workspaceTab = await esmWorkspaceEnsureWorkspaceTab({
      activate: true,
      windowId: Number(esmWorkspaceState.controllerWindowId || 0),
    });
    const workspaceTabId = Number(workspaceTab?.id || esmWorkspaceGetBoundWorkspaceTabId(esmWorkspaceState.controllerWindowId));
    if (!Number.isFinite(workspaceTabId) || workspaceTabId <= 0) {
      throw new Error("Unable to open ESM Workspace tab.");
    }

    const flowId = await startRestV2DebugFlow(
      {
        serviceType: "esm",
        programmerId: recordingContext.programmerId,
        programmerName: recordingContext.programmerName,
        requestorId: recordingContext.requestorId,
        mvpd: recordingContext.mvpd,
        requestorIds: recordingContext.requestorIds,
        mvpdIds: recordingContext.mvpdIds,
      },
      "start-esm-recording"
    );
    if (!flowId) {
      throw new Error("Unable to start UP ESM recording flow.");
    }

    state.esmWorkspaceDebugFlowId = flowId;
    state.esmWorkspaceRecordingActive = true;
    state.esmWorkspaceRecordingStartedAt = Date.now();
    state.esmWorkspaceRecordingContext = recordingContext;

    const debugTargetTabId = await resolveEsmWorkspaceDebugTargetTabId({
      preferredWindowId: Number(esmWorkspaceState.controllerWindowId || 0),
      fallbackTabId: workspaceTabId,
    });
    const flowBoundTabId = Number(debugTargetTabId || workspaceTabId);

    emitEsmWorkspaceDebugEvent(flowId, {
      phase: "recording-start",
      workspaceTabId,
      flowBoundTabId,
      programmerId: recordingContext.programmerId,
      requestorIds: recordingContext.requestorIds,
      mvpdIds: recordingContext.mvpdIds,
    });

    const bound = await bindRestV2DebugFlowToTab(flowId, flowBoundTabId, {
      requestorId: recordingContext.requestorId,
      mvpd: recordingContext.mvpd,
      serviceType: "esm",
    });
    if (!bound) {
      emitEsmWorkspaceDebugEvent(flowId, {
        phase: "workspace-bind-failed",
        workspaceTabId,
        flowBoundTabId,
      });
    }

    const traceViewerResult = await openOrFocusEsmWorkspaceTraceViewer(flowBoundTabId, flowId);
    if (traceViewerResult.ok) {
      emitEsmWorkspaceDebugEvent(flowId, {
        phase: "trace-view-opened",
        traceTabId: traceViewerResult.tabId || 0,
        traceWindowId: traceViewerResult.windowId || 0,
        traceMode: traceViewerResult.mode || (traceViewerResult.reused ? "reuse" : "unknown"),
      });
    } else {
      emitEsmWorkspaceDebugEvent(flowId, {
        phase: "trace-view-open-failed",
        error: traceViewerResult.error || "Unable to open UP trace viewer.",
      });
    }

    try {
      const tokenResult = await ensureDcrAccessTokenWithEsmRecovery(recordingContext.programmerId, esmWorkspaceState.appInfo, false, {
        flowId,
        scope: "esm-access-token",
        requestorId: recordingContext.requestorId,
        mvpd: recordingContext.mvpd,
        service: "esm",
        allowProvisioning: true,
      });
      emitEsmWorkspaceDebugEvent(flowId, {
        phase: "access-token-ready",
        appGuid: String(tokenResult?.appInfo?.guid || recordingContext.appInfo.guid || ""),
      });
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      emitEsmWorkspaceDebugEvent(flowId, {
        phase: "access-token-prime-failed",
        error: reason,
      });
      throw new Error(`Unable to fetch a fresh ESM access token: ${reason}`);
    }

    state.esmWorkspaceStopping = false;
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    setEsmWorkspaceRecordingStatus(
      esmWorkspaceState,
      "ESM recording started. Run reports / CSV actions and watch events live in the UP tab.",
      "success"
    );
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    emitEsmWorkspaceDebugEvent(state.esmWorkspaceDebugFlowId, {
      phase: "recording-start-failed",
      error: reason,
    });
    clearEsmWorkspaceRecordingState("start-failed");
    state.esmWorkspaceStopping = false;
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    setEsmWorkspaceRecordingStatus(esmWorkspaceState, reason, "error");
  }
}

async function stopEsmWorkspaceEsmRecording(esmWorkspaceState) {
  if (state.esmWorkspaceStopping) {
    return;
  }

  const activeFlowId = String(state.esmWorkspaceDebugFlowId || "").trim();
  if (!activeFlowId) {
    clearEsmWorkspaceRecordingState("stop-empty");
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    setEsmWorkspaceRecordingStatus(esmWorkspaceState, "No active ESM recording session was found.");
    return;
  }

  state.esmWorkspaceStopping = true;
  syncEsmWorkspaceRecordingControls(esmWorkspaceState);

  const recordingContext =
    state.esmWorkspaceRecordingContext && typeof state.esmWorkspaceRecordingContext === "object"
      ? state.esmWorkspaceRecordingContext
      : toEsmWorkspaceRecordingContext(esmWorkspaceState);

  emitEsmWorkspaceDebugEvent(activeFlowId, {
    phase: "recording-stop-request",
    requestorIds: recordingContext?.requestorIds || [],
    mvpdIds: recordingContext?.mvpdIds || [],
  });

  try {
    await waitForDelay(400);
    const stopResult = await stopRestV2DebugFlowAndSnapshot(activeFlowId, "esm-user-stop");
    clearEsmWorkspaceRecordingState("stop-complete", { stopFlow: false });
    state.esmWorkspaceStopping = false;
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);

    if (stopResult?.flow) {
      const harPayload = buildHarLogFromFlowSnapshot(stopResult.flow, recordingContext, null);
      const fileName = buildEsmWorkspaceHarFilename(recordingContext);
      downloadHarFile(harPayload, fileName);
      setEsmWorkspaceRecordingStatus(
        esmWorkspaceState,
        `ESM recording stopped. HAR downloaded as ${fileName}.`,
        "success"
      );
      return;
    }

    setEsmWorkspaceRecordingStatus(
      esmWorkspaceState,
      `Recording stopped, but snapshot export failed: ${stopResult?.error || "unknown error"}.`,
      "error"
    );
  } catch (error) {
    clearEsmWorkspaceRecordingState("stop-failed");
    state.esmWorkspaceStopping = false;
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    setEsmWorkspaceRecordingStatus(
      esmWorkspaceState,
      error instanceof Error ? error.message : String(error),
      "error"
    );
  }
}

function esmWorkspaceSetNetworkBusy(esmWorkspaceState, isBusy) {
  if (!esmWorkspaceState?.contentElement) {
    return;
  }
  const shell = esmWorkspaceState.contentElement.querySelector(".esm-workspace-shell");
  const indicator = esmWorkspaceState.contentElement.querySelector(".esm-workspace-net-indicator");
  if (shell) {
    shell.classList.toggle("net-busy", Boolean(isBusy));
  }
  if (indicator) {
    indicator.hidden = !isBusy;
  }
}

function esmWorkspaceStartNetwork(esmWorkspaceState) {
  if (!esmWorkspaceState) {
    return;
  }
  esmWorkspaceState.netInFlight = Number(esmWorkspaceState.netInFlight || 0) + 1;
  if (esmWorkspaceState.netInFlight === 1) {
    esmWorkspaceSetNetworkBusy(esmWorkspaceState, true);
  }
}

function esmWorkspaceEndNetwork(esmWorkspaceState) {
  if (!esmWorkspaceState) {
    return;
  }
  esmWorkspaceState.netInFlight = Math.max(0, Number(esmWorkspaceState.netInFlight || 0) - 1);
  if (esmWorkspaceState.netInFlight === 0) {
    esmWorkspaceSetNetworkBusy(esmWorkspaceState, false);
  }
}

function esmWorkspaceBuildEndpointUrl(esmWorkspaceState, endpoint) {
  const environment = getActiveAdobePassEnvironment();
  const activeEsmBase = String(environment?.esmBase || `${ADOBE_MGMT_BASE}/esm/v3/media-company/`).trim();
  const preserveQueryContext = endpoint?.preserveQueryContext === true;

  const endpointSegments = Array.isArray(endpoint?.segs)
    ? endpoint.segs.map((segment) => String(segment || "").trim()).filter(Boolean)
    : [];
  const rawEndpointUrl = String(endpoint?.url || "").trim();
  const parsed = new URL(activeEsmBase || rawEndpointUrl || ADOBE_MGMT_BASE);
  if (endpointSegments.length > 0) {
    parsed.pathname = `/esm/v3/media-company/${endpointSegments.join("/")}`;
  } else if (rawEndpointUrl) {
    const source = new URL(stripMegWorkspaceMediaCompanyQueryParam(rawEndpointUrl), activeEsmBase || ADOBE_MGMT_BASE);
    parsed.pathname = String(source.pathname || parsed.pathname || "");
    parsed.search = String(source.search || "");
  }
  parsed.hash = "";
  parsed.searchParams.delete("media-company");
  if (preserveQueryContext) {
    return parsed.toString();
  }
  parsed.searchParams.delete("start");
  parsed.searchParams.delete("end");
  parsed.searchParams.set("format", "json");
  return parsed.toString();
}

function esmWorkspaceNormalizeRunRequestUrlOverride(endpointUrl, requestUrlOverride) {
  const endpointRaw = stripMegWorkspaceMediaCompanyQueryParam(String(endpointUrl || "").trim());
  const overrideRaw = stripMegWorkspaceMediaCompanyQueryParam(String(requestUrlOverride || "").trim());
  if (!endpointRaw || !overrideRaw) {
    return "";
  }

  try {
    const endpointParsed = new URL(endpointRaw);
    const overrideParsed = new URL(overrideRaw);
    const endpointPath = String(endpointParsed.pathname || "").replace(/\/+$/g, "");
    const overridePath = String(overrideParsed.pathname || "").replace(/\/+$/g, "");
    if (endpointParsed.origin !== overrideParsed.origin || endpointPath !== overridePath) {
      return "";
    }
    overrideParsed.searchParams.delete("media-company");
    overrideParsed.hash = "";
    return overrideParsed.toString();
  } catch (_error) {
    return "";
  }
}

function buildBlondieTimeEsmRequestUrlOverride(card = null, intervalMinutes = 0, options = {}) {
  const normalizedIntervalMinutes = Math.max(0, Number(intervalMinutes || 0));
  if (normalizedIntervalMinutes <= 0 || !BLONDIE_TIME_LOGIC?.buildLegacyEsmIntervalRequestUrl) {
    return "";
  }
  const sourceCard = card && typeof card === "object" ? card : {};
  const sourceRequestUrl = firstNonEmptyString([
    String(sourceCard.seedRequestUrl || "").trim(),
    String(sourceCard.seedEndpointUrl || "").trim(),
    String(sourceCard.requestUrl || "").trim(),
    String(sourceCard.endpointUrl || "").trim(),
  ]);
  if (!sourceRequestUrl) {
    return "";
  }
  const overriddenUrl = BLONDIE_TIME_LOGIC.buildLegacyEsmIntervalRequestUrl(sourceRequestUrl, normalizedIntervalMinutes, {
    nowMs: Number(options?.nowMs || Date.now()),
    format: "json",
    limitCap: Number(BLONDIE_TIME_LOGIC.DEFAULT_ESM_QUERY_LIMIT || 1000),
  });
  return esmWorkspaceNormalizeRunRequestUrlOverride(
    String(sourceCard.endpointUrl || sourceRequestUrl).trim(),
    overriddenUrl
  );
}

function buildBlondieTimeEsmSessionRequestUrlOverride(card = null, sessionWindow = null, options = {}) {
  if (!BLONDIE_TIME_LOGIC?.buildLegacyEsmWindowRequestUrl) {
    return "";
  }
  const sourceCard = card && typeof card === "object" ? card : {};
  const sourceRequestUrl = firstNonEmptyString([
    String(sourceCard.seedRequestUrl || "").trim(),
    String(sourceCard.seedEndpointUrl || "").trim(),
    String(sourceCard.requestUrl || "").trim(),
    String(sourceCard.endpointUrl || "").trim(),
  ]);
  if (!sourceRequestUrl) {
    return "";
  }
  const overriddenUrl = BLONDIE_TIME_LOGIC.buildLegacyEsmWindowRequestUrl(
    sourceRequestUrl,
    sessionWindow && typeof sessionWindow === "object" ? sessionWindow : {},
    {
      format: "json",
      limitCap: Number(options?.limitCap || BLONDIE_TIME_LOGIC.DEFAULT_ESM_QUERY_LIMIT || 1000),
    }
  );
  return esmWorkspaceNormalizeRunRequestUrlOverride(
    String(sourceCard.endpointUrl || sourceRequestUrl).trim(),
    overriddenUrl
  );
}

function esmWorkspaceNormalizeLocalColumnFilters(rawFilters) {
  const output = {};
  const appendValues = (columnName, values) => {
    const normalizedColumn = String(columnName || "").trim().toLowerCase();
    if (
      !normalizedColumn ||
      normalizedColumn === "media-company" ||
      ESM_LOCAL_FILTER_EXCLUDED_COLUMNS.has(normalizedColumn)
    ) {
      return;
    }
    const nextValues = [];
    const seen = new Set();
    (Array.isArray(values) ? values : []).forEach((value) => {
      const normalizedValue = String(value || "").trim();
      if (!normalizedValue || seen.has(normalizedValue)) {
        return;
      }
      seen.add(normalizedValue);
      nextValues.push(normalizedValue);
    });
    if (nextValues.length > 0) {
      output[normalizedColumn] = nextValues;
    }
  };

  if (rawFilters instanceof Map) {
    rawFilters.forEach((values, columnName) => {
      appendValues(columnName, values instanceof Set ? [...values] : values);
    });
    return output;
  }
  if (Array.isArray(rawFilters)) {
    rawFilters.forEach((entry) => {
      if (!entry || typeof entry !== "object") {
        return;
      }
      appendValues(entry.column, entry.values);
    });
    return output;
  }
  if (rawFilters && typeof rawFilters === "object") {
    Object.entries(rawFilters).forEach(([columnName, values]) => {
      appendValues(columnName, values);
    });
  }
  return output;
}

function esmWorkspaceBuildLocalFilterResetKeys(normalizedFilters = {}) {
  const keys = new Set();
  Object.keys(normalizedFilters || {}).forEach((columnName) => {
    const normalized = String(columnName || "").trim().toLowerCase();
    if (!normalized || normalized === "media-company") {
      return;
    }
    keys.add(normalized);
  });
  return keys;
}

function esmWorkspaceAppendLocalColumnFilters(urlValue, rawFilters) {
  const normalizedFilters = esmWorkspaceNormalizeLocalColumnFilters(rawFilters);
  const rawUrl = String(urlValue || "").trim();
  if (!rawUrl) {
    return "";
  }
  const entries = Object.entries(normalizedFilters);
  const resetKeys = esmWorkspaceBuildLocalFilterResetKeys(normalizedFilters);

  try {
    const parsed = new URL(rawUrl);
    resetKeys.forEach((columnName) => {
      parsed.searchParams.delete(columnName);
    });
    entries.forEach(([columnName, values]) => {
      (Array.isArray(values) ? values : []).forEach((value) => {
        parsed.searchParams.append(columnName, value);
      });
    });
    return parsed.toString();
  } catch (_error) {
    const params = [];
    entries.forEach(([columnName, values]) => {
      (Array.isArray(values) ? values : []).forEach((value) => {
        params.push(`${encodeURIComponent(columnName)}=${encodeURIComponent(value)}`);
      });
    });
    if (params.length === 0) {
      return rawUrl;
    }
    const separator = rawUrl.includes("?") ? "&" : "?";
    return `${rawUrl}${separator}${params.join("&")}`;
  }
}

function esmWorkspaceMatchesLocalFilterValue(rowValue, selectedValues = []) {
  const values = Array.isArray(selectedValues) ? selectedValues : [];
  if (!values.length || rowValue == null) {
    return false;
  }

  const rowText = String(rowValue).trim();
  if (!rowText) {
    return false;
  }

  if (values.includes(rowText)) {
    return true;
  }

  const rowLower = rowText.toLowerCase();
  const rowNumber = Number(rowText);
  const rowIsNumber = Number.isFinite(rowNumber);

  for (const selectedValue of values) {
    const selectedText = String(selectedValue || "").trim();
    if (!selectedText) {
      continue;
    }
    if (selectedText.toLowerCase() === rowLower) {
      return true;
    }
    if (rowIsNumber) {
      const selectedNumber = Number(selectedText);
      if (Number.isFinite(selectedNumber) && selectedNumber === rowNumber) {
        return true;
      }
    }
  }

  return false;
}

function esmWorkspaceApplyLocalColumnFiltersToRows(rows, rawFilters = {}) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) {
    return list;
  }

  const normalizedFilters = esmWorkspaceNormalizeLocalColumnFilters(rawFilters);
  const entries = Object.entries(normalizedFilters || {}).filter(
    ([columnName, values]) =>
      String(columnName || "").trim() &&
      String(columnName || "").trim().toLowerCase() !== "media-company" &&
      !ESM_LOCAL_FILTER_EXCLUDED_COLUMNS.has(String(columnName || "").trim().toLowerCase()) &&
      Array.isArray(values) &&
      values.length > 0
  );

  if (!entries.length) {
    return list;
  }

  return list.filter((row) => {
    if (!row || typeof row !== "object" || Array.isArray(row)) {
      return false;
    }
    for (const [columnName, values] of entries) {
      if (!esmWorkspaceMatchesLocalFilterValue(row[columnName], values)) {
        return false;
      }
    }
    return true;
  });
}

function esmWorkspaceBuildRequestMetadata(esmWorkspaceState) {
  const selections = getGlobalRequestorMvpdSelections();
  const requestorIds = selections.requestorIds;
  const mvpds = selections.mvpdIds;
  return {
    requestorIds,
    mvpdIds: mvpds,
    requestorId: requestorIds[0] || "",
    mvpd: mvpds[0] || "",
  };
}

async function esmWorkspaceFetchWithPremiumAuth(esmWorkspaceState, url, options = {}, debugMeta = {}) {
  const finalUrl = appendPinnedEsmMediaCompanyQueryParam(
    String(url || "").trim(),
    String(esmWorkspaceState?.programmer?.programmerId || "")
  );
  const requestMeta = esmWorkspaceBuildRequestMetadata(esmWorkspaceState);
  const activeFlowId = getActiveEsmWorkspaceDebugFlowId();
  const requestScope = String(debugMeta?.scope || "esm").trim() || "esm";
  esmWorkspaceStartNetwork(esmWorkspaceState);
  try {
    return await fetchWithPremiumAuth(
      esmWorkspaceState.programmer?.programmerId,
      esmWorkspaceState.appInfo,
      finalUrl,
      options,
      "refresh",
      {
        flowId: activeFlowId,
        requestorId: requestMeta.requestorId,
        mvpd: requestMeta.mvpd,
        requestorIds: requestMeta.requestorIds,
        mvpdIds: requestMeta.mvpdIds,
        service: "esm",
        endpointUrl: String(debugMeta?.endpointUrl || ""),
        cardId: String(debugMeta?.cardId || ""),
        scope: requestScope,
        workspaceKey: "esm-workspace",
        workspaceOrigin: "ESM Workspace",
      }
    );
  } finally {
    esmWorkspaceEndNetwork(esmWorkspaceState);
  }
}

function esmWorkspaceNormalizeSortRule(rule) {
  if (!rule || typeof rule !== "object") {
    return null;
  }
  const col = String(rule.col || "").trim();
  if (!col) {
    return null;
  }
  const dir = String(rule.dir || "DESC").toUpperCase() === "ASC" ? "ASC" : "DESC";
  return { col, dir };
}

function esmWorkspaceBuildCsvFileName(esmWorkspaceState, endpointUrl) {
  let endpointPath = "endpoint";
  try {
    const parsed = new URL(endpointUrl);
    endpointPath = parsed.pathname.replace(/^\/+/, "").replace(/\//g, "-");
  } catch {
    endpointPath = "endpoint";
  }

  const selections = getGlobalRequestorMvpdSelections();
  const selectedRequestorIds = selections.requestorIds;
  const selectedMvpds = selections.mvpdIds;
  const requestorId = sanitizeHarFileSegment(selectedRequestorIds.join("-") || "all-requestors", "all-requestors");
  const mvpdId = sanitizeHarFileSegment(selectedMvpds.join("-") || "all-mvpds", "all-mvpds");
  const endpointSegment = sanitizeHarFileSegment(endpointPath, "endpoint");
  const envTag = getAdobePassEnvironmentFileTag();
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  return `esm_${sanitizeHarFileSegment(
    esmWorkspaceState?.programmer?.programmerId,
    "programmer"
  )}_${requestorId}_${mvpdId}_${endpointSegment}_${envTag}_${stamp}.csv`;
}

function esmWorkspaceFindEndpointByUrl(esmWorkspaceState, endpointUrl, fallback = {}) {
  const normalizedUrl = stripMegWorkspaceMediaCompanyQueryParam(String(endpointUrl || "").trim());
  if (!normalizedUrl) {
    return null;
  }
  const mappedEndpoint = esmWorkspaceState?.endpointByUrl?.get(normalizedUrl) || null;
  if (mappedEndpoint) {
    return {
      ...mappedEndpoint,
      url: normalizedUrl,
      zoomKey: String(fallback?.zoomKey || mappedEndpoint?.zoomKey || clickEsmGetZoomKey({ url: normalizedUrl }) || ""),
      columns: normalizeEsmColumns(
        [
          ...normalizeEsmColumns(mappedEndpoint?.columns, { href: normalizedUrl }),
          ...normalizeEsmColumns(fallback?.columns, { href: normalizedUrl }),
        ],
        { href: normalizedUrl }
      ),
      preserveQueryContext:
        fallback?.preserveQueryContext === true || mappedEndpoint?.preserveQueryContext === true,
      displayNodeLabel: String(fallback?.displayNodeLabel || mappedEndpoint?.displayNodeLabel || "").trim(),
    };
  }
  return {
    url: normalizedUrl,
    zoomKey: String(fallback.zoomKey || clickEsmGetZoomKey({ url: normalizedUrl }) || ""),
    columns: normalizeEsmColumns(fallback.columns, { href: normalizedUrl }),
    preserveQueryContext: fallback?.preserveQueryContext === true,
    displayNodeLabel: String(fallback?.displayNodeLabel || "").trim(),
  };
}

async function esmWorkspaceDownloadCsvForCard(esmWorkspaceState, endpoint, sortRule, requestToken, cardId = "", localColumnFilters = {}) {
  const targetWindowId = Number(esmWorkspaceState?.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0);
  const normalizedSort = esmWorkspaceNormalizeSortRule(sortRule);
  const endpointUrl = stripMegWorkspaceMediaCompanyQueryParam(String(endpoint?.url || "").trim());
  const dataUrl = esmWorkspaceAppendLocalColumnFilters(esmWorkspaceBuildEndpointUrl(esmWorkspaceState, endpoint), localColumnFilters);
  const activeFlowId = getActiveEsmWorkspaceDebugFlowId();
  emitEsmWorkspaceDebugEvent(activeFlowId, {
    phase: "csv-download-start",
    endpointUrl,
    cardId: String(cardId || ""),
    requestUrl: dataUrl,
  });
  let response;
  try {
    response = await esmWorkspaceFetchWithPremiumAuth(
      esmWorkspaceState,
      dataUrl,
      { method: "GET" },
      {
        scope: "esm-csv",
        endpointUrl,
        cardId: String(cardId || ""),
      }
    );
  } catch (error) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "csv-download-error",
      endpointUrl,
      cardId: String(cardId || ""),
      error: error instanceof Error ? error.message : String(error),
    });
    throw error;
  }
  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    return;
  }
  if (!response.ok) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "csv-download-failed",
      endpointUrl,
      cardId: String(cardId || ""),
      status: Number(response.status || 0),
      statusText: String(response.statusText || ""),
    });
    throw new Error(`CSV request failed (${response.status})`);
  }

  const payload = await response.json().catch(() => null);
  const rows = Array.isArray(payload?.report) ? payload.report : [];
  const filteredRows = esmWorkspaceApplyLocalColumnFiltersToRows(rows, localColumnFilters);
  if (filteredRows.length === 0) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "csv-download-no-data",
      endpointUrl,
      cardId: String(cardId || ""),
    });
    return;
  }

  const firstRow = filteredRows[0];
  const context = {
    hasAuthN: firstRow["authn-attempts"] != null && firstRow["authn-successful"] != null,
    hasAuthZ: firstRow["authz-attempts"] != null && firstRow["authz-successful"] != null,
  };

  downloadEsmCsv(
    filteredRows,
    normalizedSort || getDefaultEsmSortStack()[0],
    context,
    esmWorkspaceBuildCsvFileName(esmWorkspaceState, endpointUrl)
  );
  emitEsmWorkspaceDebugEvent(activeFlowId, {
    phase: "csv-download-complete",
    endpointUrl,
    cardId: String(cardId || ""),
    rowCount: filteredRows.length,
  });
  if (cardId) {
    void esmWorkspaceSendWorkspaceMessage("csv-complete", {
      cardId: String(cardId),
      endpointUrl,
      completedAt: Date.now(),
    }, {
      targetWindowId,
    });
  }
}

async function esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, cardId, requestToken, options = {}) {
  const rawEndpointUrl = String(endpoint?.url || "").trim();
  const sanitizedEndpointUrl = stripMegWorkspaceMediaCompanyQueryParam(rawEndpointUrl);
  if (!sanitizedEndpointUrl) {
    return;
  }
  const normalizedEndpoint =
    sanitizedEndpointUrl === rawEndpointUrl
      ? endpoint
      : {
          ...endpoint,
          url: sanitizedEndpointUrl,
        };
  const normalizedCardId = String(cardId || generateRequestId());
  const runId = generateRequestId();
  const requestSource = String(options.requestSource || "").trim().toLowerCase();
  const requestUrlOverride = esmWorkspaceNormalizeRunRequestUrlOverride(normalizedEndpoint.url, options.requestUrlOverride);
  const workspaceMessageSender =
    typeof options.workspaceMessageSender === "function" ? options.workspaceMessageSender : esmWorkspaceSendWorkspaceMessage;
  const defaultWorkspaceWindowId = Number(options.defaultWorkspaceWindowId || 0) || Number(state.esmWorkspaceWorkspaceWindowId || 0);
  const targetWindowId =
    Number(options.targetWindowId || 0) ||
    Number(esmWorkspaceState?.controllerWindowId || 0) ||
    defaultWorkspaceWindowId;
  const sanitizedSeedEndpointUrl = stripMegWorkspaceMediaCompanyQueryParam(String(options.seedEndpointUrl || "").trim());
  const sanitizedSeedRequestUrl = stripMegWorkspaceMediaCompanyQueryParam(String(options.seedRequestUrl || "").trim());
  const originCardKey = esmWorkspaceBuildOriginCardKey(normalizedEndpoint, {
    originCardKey: options.originCardKey,
    requestUrlOverride,
    seedEndpointUrl: sanitizedSeedEndpointUrl,
    seedRequestUrl: sanitizedSeedRequestUrl,
  });
    if (options.skipOriginLookup !== true && originCardKey && targetWindowId > 0) {
      const existingCard = await esmWorkspaceFindExistingOriginCard(originCardKey, targetWindowId);
      const existingCardId = String(existingCard?.cardId || "").trim();
      if (existingCard && existingCardId && existingCardId !== normalizedCardId) {
        const existingEndpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, existingCard.endpointUrl, existingCard);
        if (existingEndpoint) {
          await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, existingEndpoint, existingCardId, requestToken, {
            emitStart: options.emitStart !== false,
            requestSource: "workspace",
            targetWindowId,
            originCardKey,
            requestUrlOverride: String(existingCard?.requestUrl || "").trim(),
            skipOriginLookup: true,
            displayNodeLabel: String(existingCard?.displayNodeLabel || ""),
            presetLocalFilterBootstrapPending: existingCard?.presetLocalFilterBootstrapPending === true,
            seedEndpointUrl: stripMegWorkspaceMediaCompanyQueryParam(String(existingCard?.seedEndpointUrl || "").trim()),
            seedRequestUrl: stripMegWorkspaceMediaCompanyQueryParam(String(existingCard?.seedRequestUrl || "").trim()),
          seedLocalColumnFilters: existingCard?.seedLocalColumnFilters,
          seedLocalColumnExclusions: existingCard?.seedLocalColumnExclusions,
          seedPresetLocalFilterBootstrapPending: existingCard?.seedPresetLocalFilterBootstrapPending === true,
          localColumnFilters: existingCard?.localColumnFilters,
          localColumnExclusions: existingCard?.localColumnExclusions,
        });
        return;
      }
    }
  }
  const baseRequestUrl = stripMegWorkspaceMediaCompanyQueryParam(
    requestUrlOverride || esmWorkspaceBuildEndpointUrl(esmWorkspaceState, normalizedEndpoint)
  );
  const presetLocalFilterContext = esmWorkspaceExtractPresetLocalFilterContext(baseRequestUrl);
  const requestedLocalColumnFilters = esmWorkspaceMergeLocalColumnFilters(
    presetLocalFilterContext.localColumnFilters,
    options.localColumnFilters
  );
  const globalSeedLocalColumnFilters = esmWorkspaceBuildGlobalSeedLocalColumnFilters(
    requestedLocalColumnFilters,
    requestSource
  );
  const normalizedLocalColumnFilters = esmWorkspaceMergeLocalColumnFilters(
    requestedLocalColumnFilters,
    globalSeedLocalColumnFilters
  );
  const normalizedLocalColumnExclusions = esmWorkspaceMergeLocalColumnFilters(
    presetLocalFilterContext.localColumnExclusions,
    options.localColumnExclusions
  );
  const effectiveBaseRequestUrl =
    stripMegWorkspaceMediaCompanyQueryParam(String(presetLocalFilterContext.baseUrl || baseRequestUrl).trim()) || baseRequestUrl;
  const requestUrl = stripMegWorkspaceMediaCompanyQueryParam(
    esmWorkspaceAppendLocalColumnFilters(effectiveBaseRequestUrl, normalizedLocalColumnFilters)
  );
  const computedPresetLocalFilterBootstrapPending =
    Object.keys(globalSeedLocalColumnFilters || {}).length > 0 ||
    Object.keys(presetLocalFilterContext.localColumnFilters || {}).length > 0 ||
    Object.keys(presetLocalFilterContext.localColumnExclusions || {}).length > 0;
  const hasSeedOrigin = Boolean(sanitizedSeedEndpointUrl || sanitizedSeedRequestUrl);
  const seedLocalColumnFilters = esmWorkspaceMergeLocalColumnFilters(
    options.seedLocalColumnFilters,
    hasSeedOrigin ? {} : normalizedLocalColumnFilters
  );
  const seedLocalColumnExclusions = esmWorkspaceMergeLocalColumnFilters(
    options.seedLocalColumnExclusions,
    hasSeedOrigin ? {} : normalizedLocalColumnExclusions
  );
  const seedEndpointUrl =
    sanitizedSeedEndpointUrl || effectiveBaseRequestUrl;
  const seedRequestUrl =
    sanitizedSeedRequestUrl || requestUrl;
  const seedPresetLocalFilterBootstrapPending =
    options.seedPresetLocalFilterBootstrapPending === true || computedPresetLocalFilterBootstrapPending;
  const activeFlowId = getActiveEsmWorkspaceDebugFlowId();
  const reportColumns = normalizeEsmColumns(
    [
      ...normalizeEsmColumns(normalizedEndpoint.columns, { href: normalizedEndpoint.url }),
      ...presetLocalFilterContext.columns,
      ...Object.keys(normalizedLocalColumnFilters || {}),
      ...Object.keys(normalizedLocalColumnExclusions || {}),
    ],
    { href: normalizedEndpoint.url }
  );
  const reportMeta = {
    cardId: normalizedCardId,
    originCardKey,
    endpointUrl: effectiveBaseRequestUrl,
    requestUrl,
    programmerId: String(esmWorkspaceState?.programmer?.programmerId || "").trim(),
    adobePassEnvironmentKey: String(getActiveAdobePassEnvironmentKey() || "").trim(),
    premiumPanelRequestToken: Math.max(0, Number(requestToken || 0)),
    workspaceContextKey: buildEsmWorkspaceControllerContextKey(
      String(esmWorkspaceState?.programmer?.programmerId || "").trim(),
      requestToken,
      getActiveAdobePassEnvironmentKey()
    ),
    zoomKey: clickEsmGetZoomKey(normalizedEndpoint),
    columns: reportColumns,
    preserveQueryContext: normalizedEndpoint?.preserveQueryContext === true,
    displayNodeLabel: String(options.displayNodeLabel || normalizedEndpoint?.displayNodeLabel || "").trim(),
    presetLocalFilterBootstrapPending:
      options.presetLocalFilterBootstrapPending === true || computedPresetLocalFilterBootstrapPending,
    seedEndpointUrl,
    seedRequestUrl,
    seedLocalColumnFilters,
    seedLocalColumnExclusions,
    seedPresetLocalFilterBootstrapPending,
    localColumnFilters: normalizedLocalColumnFilters,
    localColumnExclusions: normalizedLocalColumnExclusions,
    runId,
  };

  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    return;
  }

  if (options.emitStart !== false) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "report-start",
      cardId: normalizedCardId,
      endpointUrl: normalizedEndpoint.url,
      requestUrl,
      requestSource: String(requestSource || "tree"),
    });
    await workspaceMessageSender("report-start", {
      ...reportMeta,
      requestSource: String(requestSource || "tree"),
      startedAt: Date.now(),
    }, {
      targetWindowId,
    });
  }

  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    void workspaceMessageSender(
      "report-result",
      {
        ...reportMeta,
        ok: false,
        superseded: true,
        error: "Request superseded by a newer ESM selection.",
        rows: [],
        completedAt: Date.now(),
      },
      {
        targetWindowId,
      }
    );
    return;
  }

  let response;
  try {
    response = await esmWorkspaceFetchWithPremiumAuth(
      esmWorkspaceState,
      requestUrl,
      { method: "GET" },
      {
        scope: "esm-report",
        endpointUrl: normalizedEndpoint.url,
        cardId: normalizedCardId,
      }
    );
  } catch (error) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "report-fetch-error",
      cardId: normalizedCardId,
      endpointUrl: normalizedEndpoint.url,
      error: error instanceof Error ? error.message : String(error),
    });
    void workspaceMessageSender("report-result", {
      ...reportMeta,
      ok: false,
      error: error instanceof Error ? error.message : String(error),
      rows: [],
      completedAt: Date.now(),
    }, {
      targetWindowId,
    });
    return;
  }

  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    void workspaceMessageSender(
      "report-result",
      {
        ...reportMeta,
        ok: false,
        superseded: true,
        error: "Request superseded by a newer ESM selection.",
        rows: [],
        completedAt: Date.now(),
      },
      {
        targetWindowId,
      }
    );
    return;
  }

  if (!response.ok) {
    const bodyText = await response.text().catch(() => "");
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "report-http-error",
      cardId: normalizedCardId,
      endpointUrl: normalizedEndpoint.url,
      status: Number(response.status || 0),
      statusText: String(response.statusText || ""),
      responsePreview: truncateDebugText(bodyText, 2000),
    });
    void workspaceMessageSender("report-result", {
      ...reportMeta,
      ok: false,
      error: `HTTP ${response.status} ${normalizeHttpErrorMessage(bodyText) || response.statusText || "Request failed"}`,
      status: Number(response.status || 0),
      rows: [],
      completedAt: Date.now(),
    }, {
      targetWindowId,
    });
    return;
  }

  const bodyText = await response.text().catch(() => "");
  let payload = null;
  if (bodyText) {
    try {
      payload = JSON.parse(bodyText);
    } catch {
      payload = null;
    }
  }

  if (!payload && bodyText.trim()) {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "report-parse-error",
      cardId: normalizedCardId,
      endpointUrl: normalizedEndpoint.url,
      error: "Response was not valid JSON.",
      responsePreview: truncateDebugText(bodyText, 2000),
    });
    void workspaceMessageSender("report-result", {
      ...reportMeta,
      ok: false,
      error: bodyText.trim(),
      rows: [],
      completedAt: Date.now(),
    }, {
      targetWindowId,
    });
    return;
  }

  const rows = Array.isArray(payload?.report) ? payload.report : [];
  const filteredRows = esmWorkspaceApplyLocalColumnFiltersToRows(rows, normalizedLocalColumnFilters);
  emitEsmWorkspaceDebugEvent(activeFlowId, {
    phase: "report-result",
    cardId: normalizedCardId,
    endpointUrl: normalizedEndpoint.url,
    rowCount: filteredRows.length,
    noData: filteredRows.length === 0,
    lastModified: response.headers.get("Last-Modified") || response.headers.get("Date") || "",
  });
  void workspaceMessageSender("report-result", {
    ...reportMeta,
    ok: true,
    rows: filteredRows,
    noData: filteredRows.length === 0,
    lastModified: response.headers.get("Last-Modified") || response.headers.get("Date") || "",
    completedAt: Date.now(),
  }, {
    targetWindowId,
  });
}

