function esmWorkspaceParsePathParts(rawValue) {
  if (typeof rawValue !== "string" || rawValue.trim() === "") {
    return [];
  }
  try {
    const parsed = JSON.parse(rawValue);
    if (!Array.isArray(parsed)) {
      return [];
    }
    return parsed.map((value) => String(value || "").trim()).filter(Boolean);
  } catch {
    return [];
  }
}

function esmWorkspacePathPartsToKey(pathParts) {
  if (!Array.isArray(pathParts)) {
    return "";
  }
  return esmWorkspaceNormalizeEndpointSegments(pathParts)
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean)
    .join("/");
}

function esmWorkspaceResolveEndpointByPathParts(esmWorkspaceState, pathParts) {
  const normalizedParts = esmWorkspaceNormalizeEndpointSegments(pathParts);
  if (!normalizedParts.length) {
    return null;
  }
  const map = esmWorkspaceState?.endpointIndexByPathKey instanceof Map ? esmWorkspaceState.endpointIndexByPathKey : null;
  const catalog = Array.isArray(esmWorkspaceState?.catalog) ? esmWorkspaceState.catalog : [];

  for (let size = normalizedParts.length; size >= 1; size -= 1) {
    const candidateParts = normalizedParts.slice(0, size);
    const candidateKey = esmWorkspacePathPartsToKey(candidateParts);
    if (!candidateKey) {
      continue;
    }
    const mappedIndex = Number(map ? map.get(candidateKey) : -1);
    if (Number.isInteger(mappedIndex) && mappedIndex >= 0) {
      return catalog[mappedIndex] || null;
    }
    const fallbackIndex = catalog.findIndex((entry) => esmWorkspacePathPartsToKey(entry?.segs) === candidateKey);
    if (fallbackIndex >= 0) {
      if (map) {
        map.set(candidateKey, fallbackIndex);
      }
      return catalog[fallbackIndex] || null;
    }
  }
  return null;
}

function esmWorkspaceRenderLabelChips(labelElement, pathParts, term = "", highlightPattern = null, options = {}) {
  if (!labelElement) {
    return;
  }
  const onSegmentClick = typeof options.onSegmentClick === "function" ? options.onSegmentClick : null;
  const normalizedParts = Array.isArray(pathParts)
    ? pathParts.map((value) => String(value || "").trim()).filter(Boolean)
    : [];
  const normalizedTerm = String(term || "").trim();
  labelElement.innerHTML = "";
  normalizedParts.forEach((segment, index) => {
    const chip = document.createElement("span");
    chip.className = "esm-workspace-chip";
    chip.dataset.raw = segment;
    chip.dataset.segmentIndex = String(index);
    const segHay = segment.toLowerCase().replace(/\s+/g, "");
    const showHighlight = Boolean(normalizedTerm && highlightPattern && segHay.includes(normalizedTerm));
    if (showHighlight) {
      chip.innerHTML = segment.replace(highlightPattern, (match) => `<mark>${escapeHtml(match)}</mark>`);
    } else {
      chip.textContent = segment;
    }
    esmWorkspaceApplyChipColor(chip, segment);
    if (onSegmentClick) {
      const segmentPathParts = normalizedParts.slice(0, index + 1);
      const runSegment = () => {
        onSegmentClick(segmentPathParts, segment, index);
      };
      chip.classList.add("esm-workspace-chip-clickable");
      chip.tabIndex = 0;
      chip.setAttribute("role", "button");
      chip.setAttribute("aria-label", `Open ESM table for ${segmentPathParts.join(" / ")}`);
      chip.title = `Load ${segmentPathParts.join("/")}`;
      chip.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        runSegment();
      });
      chip.addEventListener("keydown", (event) => {
        if (event.key !== "Enter" && event.key !== " ") {
          return;
        }
        event.preventDefault();
        event.stopPropagation();
        runSegment();
      });
    }
    labelElement.appendChild(chip);
  });
}

async function esmWorkspaceRunEndpointFromUi(esmWorkspaceState, endpoint, requestToken, requestSource = "tree") {
  if (!esmWorkspaceState || !endpoint?.url) {
    return;
  }
  try {
    const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
      esmWorkspaceState?.programmer?.programmerId,
      requestToken || esmWorkspaceState?.requestToken || 0
    );
    esmWorkspaceState.requestToken = liveRequestToken;
    if (!isEsmServiceRequestActive(esmWorkspaceState.section, liveRequestToken, esmWorkspaceState.programmer?.programmerId)) {
      return;
    }
    const workspaceTab = await esmWorkspaceEnsureWorkspaceTab({ activate: true, windowId: esmWorkspaceState.controllerWindowId });
    const targetWindowId = Number(workspaceTab?.windowId || esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0);
    await esmWaitForWorkspaceReady(targetWindowId, Number(workspaceTab?.id || 0), 6000).catch(() => false);
    esmWorkspaceBroadcastControllerState(esmWorkspaceState, targetWindowId);
    await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, generateRequestId(), liveRequestToken, {
      emitStart: true,
      requestSource,
      targetWindowId,
    });
  } catch (error) {
    setStatus(`Unable to open ESM Workspace: ${error instanceof Error ? error.message : String(error)}`, "error");
  }
}

function popupNormalizeSavedEsmQueryName(value = "") {
  return String(value || "").replace(/\|+/g, " ").replace(/\s+/g, " ").trim();
}

function popupBuildSavedEsmQueryRecord(name = "", rawUrl = "") {
  const normalizedName = popupNormalizeSavedEsmQueryName(name);
  const normalizedUrl = stripMegWorkspaceScopedQueryParams(String(rawUrl || "").trim());
  if (!normalizedName || !normalizedUrl) {
    return null;
  }
  return {
    name: normalizedName,
    url: normalizedUrl,
  };
}

function popupBuildSavedEsmQueryPayload(name = "", rawUrl = "") {
  const record = popupBuildSavedEsmQueryRecord(name, rawUrl);
  if (!record) {
    return "";
  }
  return record.url;
}

function popupParseSavedEsmQueryRecord(storageKey = "", payload = "") {
  const normalizedStorageKey = String(storageKey || "").trim();
  if (!normalizedStorageKey.startsWith(SAVED_ESM_QUERY_STORAGE_PREFIX)) {
    return null;
  }
  const storedName = decodeURIComponent(normalizedStorageKey.slice(SAVED_ESM_QUERY_STORAGE_PREFIX.length) || "");
  const normalizedPayload = String(payload || "").trim();
  try {
    const parsed = JSON.parse(normalizedPayload);
    if (parsed && typeof parsed === "object") {
      const record = popupBuildSavedEsmQueryRecord(parsed.name || storedName, parsed.url || parsed.esmUrl || "");
      if (record) {
        return {
          storageKey: normalizedStorageKey,
          ...record,
        };
      }
    }
  } catch (_error) {
    // Fall through to legacy string parsing.
  }
  const separatorIndex = normalizedPayload.indexOf("|");
  if (separatorIndex <= 0) {
    const record = popupBuildSavedEsmQueryRecord(storedName, normalizedPayload);
    if (record) {
      return {
        storageKey: normalizedStorageKey,
        ...record,
      };
    }
    return null;
  }
  const record = popupBuildSavedEsmQueryRecord(
    normalizedPayload.slice(0, separatorIndex),
    String(normalizedPayload.slice(separatorIndex + 1) || "").trim()
  );
  if (!record) {
    return null;
  }
  return {
    storageKey: normalizedStorageKey,
    ...record,
  };
}

function readLegacySavedEsmQueryEntriesFromLocalStorage() {
  const normalizedEntries = {};
  try {
    for (let index = 0; index < localStorage.length; index += 1) {
      const storageKey = String(localStorage.key(index) || "").trim();
      if (!storageKey.startsWith(SAVED_ESM_QUERY_STORAGE_PREFIX)) {
        continue;
      }
      const payload = localStorage.getItem(storageKey);
      const record = popupParseSavedEsmQueryRecord(storageKey, payload);
      if (!record) {
        continue;
      }
      const normalizedPayload = popupBuildSavedEsmQueryPayload(record.name, record.url);
      if (payload !== normalizedPayload) {
        localStorage.setItem(storageKey, normalizedPayload);
      }
      normalizedEntries[record.name] = record.url;
    }
  } catch (_error) {
    return {};
  }
  return normalizedEntries;
}

function purgeLegacySavedEsmQueryEntriesFromLocalStorage() {
  try {
    const keysToRemove = [];
    for (let index = 0; index < localStorage.length; index += 1) {
      const storageKey = String(localStorage.key(index) || "").trim();
      if (storageKey.startsWith(SAVED_ESM_QUERY_STORAGE_PREFIX)) {
        keysToRemove.push(storageKey);
      }
    }
    keysToRemove.forEach((storageKey) => {
      localStorage.removeItem(storageKey);
    });
  } catch {
    // Ignore legacy saved-query cleanup failures.
  }
}

function getVaultSavedEsmQueryRecords(vault = null) {
  return Object.entries(getUnderparVaultSavedQueries(vault))
    .map(([name, rawUrl]) => {
      const record = popupBuildSavedEsmQueryRecord(name, rawUrl);
      if (!record) {
        return null;
      }
      return {
        storageKey: `${SAVED_ESM_QUERY_STORAGE_PREFIX}${encodeURIComponent(record.name)}`,
        ...record,
      };
    })
    .filter(Boolean)
    .sort((left, right) => left.name.localeCompare(right.name, undefined, { sensitivity: "base" }));
}

function getMergedSavedEsmQueryEntries(vault = null) {
  return {
    ...readLegacySavedEsmQueryEntriesFromLocalStorage(),
    ...getUnderparVaultSavedQueries(vault),
  };
}

function popupGetSavedEsmQueryRecords() {
  return getVaultSavedEsmQueryRecords({
    underpar: {
      app: {
        savedQueries: getMergedSavedEsmQueryEntries(state.passVault),
      },
    },
  });
}

async function ensureSavedEsmQueryVaultMirror(options = {}) {
  const forceReload = options?.forceReload === true;
  const vault = normalizeUnderparVaultPayload(
    state.passVault || (await ensurePassVaultLoaded({ forceReload }))
  );
  const mergedSavedQueries = getMergedSavedEsmQueryEntries(vault);
  const currentSavedQueries = getUnderparVaultSavedQueries(vault);
  if (JSON.stringify(currentSavedQueries) === JSON.stringify(mergedSavedQueries)) {
    state.passVault = vault;
    return vault;
  }
  setUnderparVaultSavedQueries(vault, mergedSavedQueries);
  vault.updatedAt = Date.now();
  state.passVault = vault;
  await persistPassVaultPayloadToStorage(vault, { silent: true });
  return vault;
}

function syncLegacySavedEsmQueryRecordToLocalStorage(name = "", rawUrl = "") {
  const record = popupBuildSavedEsmQueryRecord(name, rawUrl);
  if (!record) {
    return null;
  }
  const storageKey = `${SAVED_ESM_QUERY_STORAGE_PREFIX}${encodeURIComponent(record.name)}`;
  try {
    localStorage.setItem(storageKey, popupBuildSavedEsmQueryPayload(record.name, record.url));
  } catch {
    // Ignore local fallback sync failures.
  }
  return {
    storageKey,
    ...record,
  };
}

function removeLegacySavedEsmQueryRecordFromLocalStorage(storageKey = "") {
  const normalizedStorageKey = String(storageKey || "").trim();
  if (!normalizedStorageKey) {
    return;
  }
  try {
    localStorage.removeItem(normalizedStorageKey);
  } catch {
    // Ignore local fallback sync failures.
  }
}

async function popupPersistSavedEsmQueryRecord(name = "", rawUrl = "") {
  const record = popupBuildSavedEsmQueryRecord(name, rawUrl);
  if (!record) {
    throw new Error("Saved Query name and URL are required.");
  }

  return enqueuePassVaultPersist(async () => {
    const vault = await ensureSavedEsmQueryVaultMirror({ forceReload: false });
    const nextSavedQueries = getMergedSavedEsmQueryEntries(vault);
    const existed = Object.prototype.hasOwnProperty.call(nextSavedQueries, record.name);
    nextSavedQueries[record.name] = record.url;
    setUnderparVaultSavedQueries(vault, nextSavedQueries);
    vault.updatedAt = Date.now();

    syncLegacySavedEsmQueryRecordToLocalStorage(record.name, record.url);
    await persistPassVaultPayloadToStorage(vault, { silent: true });
    refreshAllEsmWorkspaceMegSavedQuerySelectors();

    return {
      storageKey: `${SAVED_ESM_QUERY_STORAGE_PREFIX}${encodeURIComponent(record.name)}`,
      existed,
      ...record,
    };
  });
}

async function popupDeleteSavedEsmQueryRecord(storageKey = "") {
  const normalizedStorageKey = String(storageKey || "").trim();
  if (!normalizedStorageKey.startsWith(SAVED_ESM_QUERY_STORAGE_PREFIX)) {
    throw new Error("Saved Query storage key is required.");
  }

  const storedName = decodeURIComponent(normalizedStorageKey.slice(SAVED_ESM_QUERY_STORAGE_PREFIX.length) || "");
  const normalizedName = popupNormalizeSavedEsmQueryName(storedName);
  if (!normalizedName) {
    throw new Error("Saved Query storage key is required.");
  }

  return enqueuePassVaultPersist(async () => {
    const vault = await ensureSavedEsmQueryVaultMirror({ forceReload: false });
    const nextSavedQueries = getMergedSavedEsmQueryEntries(vault);
    delete nextSavedQueries[normalizedName];
    setUnderparVaultSavedQueries(vault, nextSavedQueries);
    vault.updatedAt = Date.now();

    removeLegacySavedEsmQueryRecordFromLocalStorage(normalizedStorageKey);
    await persistPassVaultPayloadToStorage(vault, { silent: true });
    refreshAllEsmWorkspaceMegSavedQuerySelectors();

    return {
      storageKey: normalizedStorageKey,
      name: normalizedName,
    };
  });
}

function esmWorkspaceBuildMegOptionLabel(endpoint) {
  const segments = Array.isArray(endpoint?.segs)
    ? endpoint.segs.map((segment) => String(segment || "").trim()).filter(Boolean)
    : [];
  return segments.join(" / ") || String(endpoint?.url || "").trim();
}

function esmWorkspaceBuildMegLaunchTooltip(endpointUrl = "") {
  const normalizedUrl = stripMegWorkspaceMediaCompanyQueryParam(String(endpointUrl || "").trim());
  if (!normalizedUrl) {
    return "No ESM node available to load in MEGSPACE";
  }
  return `Launch ${normalizedUrl} load in MEGSPACE`;
}

async function esmWorkspaceOpenRequestPathInWorkspace(esmWorkspaceState, requestPath, requestToken, options = {}) {
  const normalizedRequestPath = normalizeUnderparEsmRequestPath(requestPath);
  if (!esmWorkspaceState || !normalizedRequestPath) {
    throw new Error("ESM request path is required.");
  }
  const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
    esmWorkspaceState?.programmer?.programmerId,
    requestToken || esmWorkspaceState?.requestToken || 0
  );
  esmWorkspaceState.requestToken = liveRequestToken;
  if (!isEsmServiceRequestActive(esmWorkspaceState.section, liveRequestToken, esmWorkspaceState.programmer?.programmerId)) {
    throw new Error("ESM controller is no longer active for the selected media company.");
  }
  const targetWindowId = Number(options?.targetWindowId || esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0);
  const environment = getActiveAdobePassEnvironment();
  const absoluteRequestUrl = megWorkspaceBuildAbsoluteServiceUrl(
    String(environment?.esmBase || environment?.mgmtBase || ADOBE_MGMT_BASE).trim(),
    normalizedRequestPath
  );
  const workspaceTab = await esmWorkspaceEnsureWorkspaceTab({ activate: true, windowId: targetWindowId });
  const resolvedTargetWindowId = Number(workspaceTab?.windowId || targetWindowId || state.esmWorkspaceWorkspaceWindowId || 0);
  await esmWaitForWorkspaceReady(resolvedTargetWindowId, Number(workspaceTab?.id || 0), 6000).catch(() => false);
  esmWorkspaceBroadcastControllerState(esmWorkspaceState, resolvedTargetWindowId);
  const displayNodeLabel = String(options?.displayNodeLabel || "").trim();
  const endpoint =
    esmWorkspaceFindEndpointByUrl(esmWorkspaceState, absoluteRequestUrl, {
      url: absoluteRequestUrl,
      zoomKey: String(clickEsmGetZoomKey({ url: absoluteRequestUrl }) || ""),
      columns: normalizeEsmColumns([], { href: absoluteRequestUrl }),
      preserveQueryContext: true,
      displayNodeLabel,
    }) || null;
  if (!endpoint) {
    throw new Error("ESM request path is required.");
  }
  await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, generateRequestId(), liveRequestToken, {
    emitStart: true,
    requestSource: String(options?.requestSource || "workspace").trim() || "workspace",
    displayNodeLabel,
    targetWindowId: resolvedTargetWindowId,
  });
  return {
    requestPath: normalizedRequestPath,
    requestUrl: absoluteRequestUrl,
    targetWindowId: resolvedTargetWindowId,
  };
}

async function esmWorkspaceOpenSavedQueryFromUi(esmWorkspaceState, savedQueryUrl, requestToken, savedQueryName = "") {
  const normalizedSavedQueryUrl = stripMegWorkspaceMediaCompanyQueryParam(String(savedQueryUrl || "").trim());
  if (!esmWorkspaceState || !normalizedSavedQueryUrl) {
    return;
  }
  const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
    esmWorkspaceState?.programmer?.programmerId,
    requestToken || esmWorkspaceState?.requestToken || 0
  );
  esmWorkspaceState.requestToken = liveRequestToken;

  try {
    await esmWorkspaceOpenRequestPathInWorkspace(esmWorkspaceState, normalizedSavedQueryUrl, liveRequestToken, {
      requestSource: "saved-query",
      displayNodeLabel: savedQueryName,
    });
  } catch (error) {
    const suffix = savedQueryName ? ` "${savedQueryName}"` : "";
    setStatus(`Unable to open Saved Query${suffix} in ESM Workspace: ${error instanceof Error ? error.message : String(error)}`, "error");
  }
}

async function consumePendingUnderparEsmDeeplink() {
  if (state.pendingUnderparEsmDeeplinkPromise) {
    return state.pendingUnderparEsmDeeplinkPromise;
  }
  state.pendingUnderparEsmDeeplinkPromise = (async () => {
    try {
      if (!state.sessionReady || !state.loginData || state.restricted) {
        return { ok: false, pending: true };
      }
      let openedCount = 0;
      while (true) {
        const pendingLaunch = await readPendingUnderparEsmDeeplink();
        if (!pendingLaunch) {
          return { ok: openedCount > 0, pending: false };
        }

        const pendingEnvironmentKey =
          String(pendingLaunch.environmentKey || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
        if (pendingEnvironmentKey !== String(getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim()) {
          const switchResult = await switchAdobePassEnvironmentInPlace(pendingEnvironmentKey, {
            restoreSelection: false,
          });
          if (!switchResult?.ok) {
            throw new Error(`Unable to switch UnderPAR to ${pendingLaunch.environmentLabel || pendingEnvironmentKey}.`);
          }
        }

        let programmer = resolveSelectedProgrammer();
        if (pendingLaunch.programmerId) {
          const matchedProgrammer = findProgrammerByProgrammerId(pendingLaunch.programmerId);
          if (!matchedProgrammer) {
            throw new Error(`Media Company ${pendingLaunch.programmerId} is not available in this UnderPAR session.`);
          }
          const selectedProgrammerId = String(programmer?.programmerId || "").trim();
          const needsSelectionRefresh =
            selectedProgrammerId !== String(matchedProgrammer.programmerId || "").trim() ||
            !isProgrammerWorkspaceHydrationReady(String(matchedProgrammer.programmerId || "").trim()) ||
            !hasResolvedPremiumServiceSnapshotForEsm(getCurrentPremiumAppsSnapshot(String(matchedProgrammer.programmerId || "").trim()));
          if (needsSelectionRefresh) {
            programmer = selectProgrammerForController(matchedProgrammer, "esm-deeplink");
            await refreshProgrammerPanels({
              forcePremiumRefresh: false,
              controllerReason: "esm-deeplink",
            });
          } else {
            programmer = matchedProgrammer;
          }
        }

        programmer = programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
        if (!programmer?.programmerId) {
          throw new Error("Select a Media Company in UnderPAR before opening this ESM deeplink.");
        }
        const services = getCurrentPremiumAppsSnapshot(programmer.programmerId);
        if (!hasResolvedPremiumServiceSnapshotForEsm(services)) {
          await refreshProgrammerPanels({
            forcePremiumRefresh: false,
            controllerReason: "esm-deeplink",
          });
        }
        const refreshedServices = getCurrentPremiumAppsSnapshot(programmer.programmerId);
        if (hasResolvedPremiumServiceSnapshotForEsm(refreshedServices) && !hasEsmScopedApp(refreshedServices)) {
          throw new Error(
            `${String(programmer.programmerName || programmer.programmerId || "Selected Media Company").trim()} is not ESM scoped.`
          );
        }
        const esmWorkspaceState = getActiveEsmWorkspaceState();
        if (!esmWorkspaceState) {
          throw new Error("ESM controller is not ready yet.");
        }

        await esmWorkspaceOpenRequestPathInWorkspace(
          esmWorkspaceState,
          pendingLaunch.requestPath,
          Number(state.premiumPanelRequestToken || 0),
          {
            requestSource: "slack-blondie-deeplink",
            displayNodeLabel: String(pendingLaunch.displayNodeLabel || "").trim(),
          }
        );
        await clearPendingUnderparEsmDeeplink();
        openedCount += 1;
        const openedLabel = String(pendingLaunch.displayNodeLabel || pendingLaunch.requestPath || "ESM report").trim();
        setStatus(`Opened ${openedLabel} in ESM Workspace.`, "success");
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      if (/not ready yet/i.test(message)) {
        return { ok: false, pending: true };
      }
      await clearPendingUnderparEsmDeeplink();
      setStatus(`Unable to open Slack ESM deeplink: ${message}`, "error");
      return { ok: false, pending: false, error: message };
    } finally {
      state.pendingUnderparEsmDeeplinkPromise = null;
    }
  })();
  return state.pendingUnderparEsmDeeplinkPromise;
}

function esmWorkspaceSyncMegSavedQueryUi(esmWorkspaceState) {
  const selectElement = esmWorkspaceState?.megSavedQuerySelectElement || null;
  if (!selectElement) {
    return;
  }

  const records = popupGetSavedEsmQueryRecords();
  selectElement.innerHTML = "";

  const defaultOption = document.createElement("option");
  defaultOption.value = "";
  defaultOption.textContent = "Saved Queries";
  defaultOption.title = "Saved Queries";
  selectElement.appendChild(defaultOption);

  if (records.length === 0) {
    selectElement.hidden = true;
    selectElement.disabled = true;
    selectElement.title = "Saved Queries";
    selectElement.setAttribute("aria-label", "Saved Queries");
    return;
  }

  records.forEach((record) => {
    const option = document.createElement("option");
    option.value = record.url;
    option.textContent = record.name;
    option.title = record.url;
    selectElement.appendChild(option);
  });

  selectElement.value = "";
  selectElement.hidden = false;
  selectElement.disabled = false;
  selectElement.title = "Saved Queries";
  selectElement.setAttribute("aria-label", "Saved Queries");
}

function refreshAllEsmWorkspaceMegSavedQuerySelectors() {
  const sections = document.querySelectorAll(".premium-service-section.service-esm");
  sections.forEach((section) => {
    const esmWorkspaceState = section?.__underparEsmWorkspaceState || null;
    if (esmWorkspaceState?.section?.isConnected) {
      esmWorkspaceSyncMegSavedQueryUi(esmWorkspaceState);
    }
  });
}

window.addEventListener("storage", (event) => {
  const normalizedKey = String(event?.key || "").trim();
  if (normalizedKey && !normalizedKey.startsWith(SAVED_ESM_QUERY_STORAGE_PREFIX)) {
    return;
  }
  refreshAllEsmWorkspaceMegSavedQuerySelectors();
});

function esmWorkspaceSyncMegSelectionUi(esmWorkspaceState) {
  const selectElement = esmWorkspaceState?.megSelectElement;
  const launchButton = esmWorkspaceState?.megLaunchButton;
  if (!selectElement || !launchButton) {
    return;
  }

  const selectedUrl = String(selectElement.value || esmWorkspaceState.megSelectedEndpointUrl || "").trim();
  const endpointIndexes = Array.isArray(esmWorkspaceState.visibleEndpointIndexes)
    ? esmWorkspaceState.visibleEndpointIndexes
    : Array.isArray(esmWorkspaceState.catalog)
      ? esmWorkspaceState.catalog.map((_, index) => index)
      : [];

  const options = [...new Set(endpointIndexes)]
    .map((endpointIndex) => Number(endpointIndex))
    .filter((endpointIndex) => Number.isInteger(endpointIndex) && endpointIndex >= 0)
    .map((endpointIndex) => esmWorkspaceState.catalog?.[endpointIndex])
    .filter((endpoint) => endpoint && typeof endpoint === "object" && String(endpoint.url || "").trim());

  selectElement.innerHTML = "";
  if (options.length === 0) {
    const emptyOption = document.createElement("option");
    emptyOption.value = "";
    emptyOption.textContent = "No ESM nodes match current JellyBean filters";
    selectElement.appendChild(emptyOption);
    selectElement.disabled = true;
    launchButton.disabled = true;
    launchButton.title = esmWorkspaceBuildMegLaunchTooltip("");
    launchButton.setAttribute("aria-label", esmWorkspaceBuildMegLaunchTooltip(""));
    esmWorkspaceState.megSelectedEndpointUrl = "";
    return;
  }

  let nextSelectedUrl = selectedUrl;
  options.forEach((endpoint, index) => {
    const option = document.createElement("option");
    option.value = String(endpoint.url || "");
    option.textContent = esmWorkspaceBuildMegOptionLabel(endpoint);
    option.title = String(endpoint.url || "");
    selectElement.appendChild(option);
    if (!nextSelectedUrl && index === 0) {
      nextSelectedUrl = option.value;
    }
  });

  const hasSelectedMatch = options.some((endpoint) => String(endpoint.url || "") === nextSelectedUrl);
  const finalSelectedUrl = hasSelectedMatch ? nextSelectedUrl : String(options[0]?.url || "");
  selectElement.value = finalSelectedUrl;
  selectElement.disabled = false;
  launchButton.disabled = !finalSelectedUrl;
  launchButton.title = esmWorkspaceBuildMegLaunchTooltip(finalSelectedUrl);
  launchButton.setAttribute("aria-label", esmWorkspaceBuildMegLaunchTooltip(finalSelectedUrl));
  esmWorkspaceState.megSelectedEndpointUrl = finalSelectedUrl;
}

function esmWorkspaceSetMegPanelCollapsed(esmWorkspaceState, collapsed = true) {
  const panelElement = esmWorkspaceState?.megPanelElement || null;
  const toggleButton = esmWorkspaceState?.megToggleButton || null;
  const bodyElement = esmWorkspaceState?.megBodyElement || null;
  if (!panelElement || !toggleButton || !bodyElement) {
    return;
  }
  const isCollapsed = Boolean(collapsed);
  panelElement.classList.toggle("is-collapsed", isCollapsed);
  bodyElement.hidden = isCollapsed;
  toggleButton.setAttribute("aria-expanded", isCollapsed ? "false" : "true");
  toggleButton.setAttribute("aria-label", isCollapsed ? "Expand MEGSPACE" : "Collapse MEGSPACE");
  toggleButton.title = ESM_MEGTOOL_FILTER_TOOLTIP;
}

function esmWorkspaceGetSelectedMegEndpoint(esmWorkspaceState) {
  const selectedUrl = String(
    esmWorkspaceState?.megSelectElement?.value || esmWorkspaceState?.megSelectedEndpointUrl || ""
  ).trim();
  if (!selectedUrl) {
    return null;
  }
  return esmWorkspaceState?.endpointByUrl?.get(selectedUrl) || esmWorkspaceFindEndpointByUrl(esmWorkspaceState, selectedUrl);
}

async function megWorkspaceOpenEndpointFromUi(esmWorkspaceState, endpoint, requestToken) {
  if (!esmWorkspaceState || !endpoint?.url) {
    return;
  }
  const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
    esmWorkspaceState?.programmer?.programmerId,
    requestToken || esmWorkspaceState?.requestToken || 0
  );
  esmWorkspaceState.requestToken = liveRequestToken;

  const targetWindowId = Number(esmWorkspaceState.controllerWindowId || state.megWorkspaceWindowId || 0);
  try {
    const workspaceTab = await megWorkspaceEnsureWorkspaceTab({
      activate: true,
      windowId: targetWindowId,
    });
    const selection = megWorkspaceNormalizeSelection(endpoint, {
      launchToken: generateRequestId(),
      endpointLabel: esmWorkspaceBuildMegOptionLabel(endpoint),
    });
    const resolvedWindowId = Number(workspaceTab?.windowId || targetWindowId || 0);
    megWorkspaceRememberSelection(resolvedWindowId, selection);
    megWorkspaceBroadcastControllerState(esmWorkspaceState, resolvedWindowId);
    await megWorkspaceSendWorkspaceMessage(
      "selection-change",
      {
        ...selection,
        autoRun: true,
        requestToken: liveRequestToken,
        requestedAt: Date.now(),
      },
      {
        targetWindowId: resolvedWindowId,
      }
    );
  } catch (error) {
    setStatus(`Unable to open MEGSPACE: ${error instanceof Error ? error.message : String(error)}`, "error");
  }
}

async function esmWorkspaceMakeClickEsmFromUi(esmWorkspaceState, requestToken, source = "sidepanel") {
  if (!esmWorkspaceState) {
    return;
  }
  const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
    esmWorkspaceState?.programmer?.programmerId,
    requestToken || esmWorkspaceState?.requestToken || 0
  );
  esmWorkspaceState.requestToken = liveRequestToken;
  const triggerButton = esmWorkspaceState.makeClickEsmButton;
  if (triggerButton) {
    triggerButton.disabled = true;
  }
  try {
    const context = await resolveClickEsmDownloadContext(esmWorkspaceState);
    if (!context) {
      throw new Error("Select a media company with ESM access to generate clickESM.");
    }
    await makeClickEsmDownload(context, liveRequestToken, { source });
  } catch (error) {
    setStatus(`Unable to generate clickESM: ${error instanceof Error ? error.message : String(error)}`, "error");
  } finally {
    if (
      triggerButton &&
      isEsmServiceRequestActive(esmWorkspaceState.section, liveRequestToken, esmWorkspaceState.programmer?.programmerId)
    ) {
      triggerButton.disabled = false;
    }
  }
}

function esmWorkspaceRenderTreeNode(esmWorkspaceState, node, parentUl, requestToken, parentPathParts = []) {
  const item = document.createElement("li");
  const nodeRow = document.createElement("div");
  nodeRow.className = "esm-workspace-node";

  const twisty = document.createElement("span");
  twisty.className = "esm-workspace-twisty";
  const hasChildren = Array.isArray(node.children) && node.children.length > 0;
  twisty.textContent = hasChildren ? "+" : "";
  if (!hasChildren) {
    twisty.classList.add("hidden");
  }

  const label = document.createElement("span");
  label.className = "esm-workspace-label";
  const parts = Array.isArray(node.parts) ? node.parts.map((value) => String(value || "").trim()).filter(Boolean) : [];
  const fullPathParts = [...(Array.isArray(parentPathParts) ? parentPathParts : []), ...parts];
  item.dataset.nodeParts = JSON.stringify(parts);
  item.dataset.pathParts = JSON.stringify(fullPathParts);
  item.dataset.pathHay = fullPathParts.join(" ").toLowerCase().replace(/\s+/g, "");
  esmWorkspaceRenderLabelChips(label, parts);

  const meta = document.createElement("span");
  meta.className = "esm-workspace-meta";
  meta.textContent = "";

  nodeRow.appendChild(twisty);
  nodeRow.appendChild(label);
  nodeRow.appendChild(meta);

  if (node.endpointIndex != null) {
    const endpoint = esmWorkspaceState.catalog[node.endpointIndex];
    item.dataset.endpointIndex = String(node.endpointIndex);
    item.dataset.zoomKey = String(endpoint?.zoomKey || "");
    item.dataset.hay = String(endpoint?.hay || "");
    item.dataset.href = String(endpoint?.url || "");
    if (endpoint?.zoomKey) {
      meta.textContent = `[${endpoint.zoomKey}]`;
    }

    const runButton = document.createElement("button");
    runButton.className = "esm-workspace-run";
    runButton.type = "button";
    runButton.textContent = "▶";
    runButton.title = "Run this endpoint in Workspace";
    runButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void esmWorkspaceRunEndpointFromUi(esmWorkspaceState, endpoint, requestToken, "tree");
    });
    nodeRow.appendChild(runButton);
  }

  const toggleNode = () => {
    const childList = item.querySelector(":scope > ul");
    if (!childList) {
      return;
    }
    const collapsed = childList.style.display === "none";
    childList.style.display = collapsed ? "" : "none";
    twisty.textContent = collapsed ? "−" : "+";
    esmWorkspaceSyncTreeToggleButton(esmWorkspaceState);
  };

  twisty.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    toggleNode();
  });

  label.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    const isLeaf = !hasChildren;
    if (isLeaf && node.endpointIndex != null) {
      const endpoint = esmWorkspaceState.catalog[node.endpointIndex];
      void esmWorkspaceRunEndpointFromUi(esmWorkspaceState, endpoint, requestToken, "tree");
      return;
    }
    if (hasChildren) {
      toggleNode();
    }
  });

  item.appendChild(nodeRow);
  if (hasChildren) {
    const childUl = document.createElement("ul");
    childUl.style.display = "none";
    node.children.forEach((child) => {
      esmWorkspaceRenderTreeNode(esmWorkspaceState, child, childUl, requestToken, fullPathParts);
    });
    item.appendChild(childUl);
  }
  parentUl.appendChild(item);
}

function esmWorkspaceSetTreeCollapsed(esmWorkspaceState, shouldCollapse) {
  const scrollElement = esmWorkspaceState?.treeScrollElement;
  const toggleElement = esmWorkspaceState?.treeToggleButton || esmWorkspaceState?.treeHeadElement;
  if (!scrollElement) {
    return;
  }
  const collapsed = Boolean(shouldCollapse);
  esmWorkspaceState.treePanelCollapsed = collapsed;
  scrollElement.hidden = collapsed;
  if (toggleElement) {
    toggleElement.setAttribute("aria-expanded", collapsed ? "false" : "true");
    toggleElement.setAttribute("aria-label", collapsed ? "Expand JellyBeans" : "Collapse JellyBeans");
  }
}

function esmWorkspaceSyncTreeToggleButton(esmWorkspaceState) {
  const scrollElement = esmWorkspaceState?.treeScrollElement;
  const root = esmWorkspaceState?.treeRootElement;
  if (!scrollElement || !root) {
    return;
  }
  const hasRows = root.querySelector("ul.esm-workspace-root > li[data-endpoint-index]") != null;
  if (!hasRows) {
    esmWorkspaceSetTreeCollapsed(esmWorkspaceState, true);
  }
}

function esmWorkspaceSyncPanelLoadAllButtons(esmWorkspaceState, endpointIndexes = []) {
  const normalizedIndexes = [...new Set(
    (Array.isArray(endpointIndexes) ? endpointIndexes : [])
      .map((value) => Number(value))
      .filter((value) => Number.isInteger(value) && value >= 0)
  )];
  const visibleCount = normalizedIndexes.length;
  const loadAllBusy = esmWorkspaceState?.loadAllBusy === true;

  const setCount = (element) => {
    if (element) {
      element.textContent = String(visibleCount);
    }
  };
  setCount(esmWorkspaceState?.treeCountElement);

  const setButtonState = (button) => {
    if (!button) {
      return;
    }
    button.disabled = visibleCount === 0 || loadAllBusy;
    button.classList.toggle("net-busy", loadAllBusy);
    if (loadAllBusy) {
      button.setAttribute("aria-busy", "true");
    } else {
      button.removeAttribute("aria-busy");
    }
  };
  setButtonState(esmWorkspaceState?.treeLoadAllButton);
}

function esmWorkspaceApplyTreeFilters(esmWorkspaceState, options = {}) {
  const root = esmWorkspaceState?.treeRootElement;
  if (!root) {
    return { visibleEndpointCount: 0 };
  }

  const zoomFilter = String(options.zoomFilter ?? esmWorkspaceState.zoomFilterSelect?.value ?? "")
    .trim()
    .toUpperCase();
  const term = clickEsmNormalizeSearchTerm(options.term ?? esmWorkspaceState.searchInput?.value ?? "");
  const searchMode = Boolean(term);
  const doHighlight = Boolean(options.highlight && term);
  const highlightPattern = doHighlight ? new RegExp(clickEsmEscapeRegExp(term), "gi") : null;
  const visibleEndpointIndexes = [];
  root.classList.toggle("esm-workspace-search-mode", searchMode);

  const endpointItems = root.querySelectorAll("ul.esm-workspace-root > li[data-endpoint-index]");
  endpointItems.forEach((item) => {
    const endpointZoom = String(item.dataset.zoomKey || "").trim().toUpperCase();
    const haystack = String(item.dataset.hay || "").toLowerCase();
    const zoomPass = !zoomFilter || endpointZoom === zoomFilter;
    const termPass = !term || haystack.includes(term);
    const isVisible = zoomPass && termPass;

    item.style.display = isVisible ? "" : "none";
    item.classList.remove("esm-workspace-search-parent");

    if (isVisible) {
      const endpointIndex = Number(item.dataset.endpointIndex || -1);
      if (Number.isInteger(endpointIndex) && endpointIndex >= 0) {
        visibleEndpointIndexes.push(endpointIndex);
      }
    }

    const label = item.querySelector(":scope > .esm-workspace-node > .esm-workspace-label");
    if (label) {
      const partsForRender = esmWorkspaceParsePathParts(item.dataset.pathParts);
      esmWorkspaceRenderLabelChips(label, partsForRender, doHighlight ? term : "", highlightPattern, {
        onSegmentClick: (segmentPathParts) => {
          const endpoint = esmWorkspaceResolveEndpointByPathParts(esmWorkspaceState, segmentPathParts);
          if (!endpoint) {
            return;
          }
          void esmWorkspaceRunEndpointFromUi(esmWorkspaceState, endpoint, options.requestToken || esmWorkspaceState?.requestToken || 0, "tree");
        },
      });
      const pathHay = String(item.dataset.pathHay || "");
      const segMatch = Boolean(term && pathHay.includes(term));
      const colOnlyMatch = Boolean(term && termPass && !segMatch);
      label.classList.toggle("esm-workspace-col-match", colOnlyMatch);
    }
  });

  esmWorkspaceState.visibleEndpointIndexes = visibleEndpointIndexes.slice();
  esmWorkspaceSyncPanelLoadAllButtons(esmWorkspaceState, visibleEndpointIndexes);
  esmWorkspaceSyncTreeToggleButton(esmWorkspaceState);
  esmWorkspaceSyncMegSelectionUi(esmWorkspaceState);
  return {
    visibleEndpointCount: visibleEndpointIndexes.length,
    visibleEndpointIndexes: visibleEndpointIndexes.slice(),
  };
}

function esmWorkspaceBuildTree(esmWorkspaceState, requestToken) {
  const treeRoot = esmWorkspaceState?.treeRootElement;
  if (!treeRoot) {
    return;
  }

  const catalog = Array.isArray(esmWorkspaceState.catalog) ? esmWorkspaceState.catalog : [];
  const sortedEntries = catalog
    .map((endpoint, endpointIndex) => {
      const pathParts = esmWorkspaceNormalizeEndpointSegments(endpoint?.segs);
      return {
        endpoint,
        endpointIndex,
        pathParts,
        searchHay: `${pathParts.join(" ")} ${Array.isArray(endpoint?.searchColumns) ? endpoint.searchColumns.join(" ") : ""}`
          .toLowerCase()
          .replace(/\s+/g, ""),
      };
    })
    .filter((entry) => Array.isArray(entry.pathParts) && entry.pathParts.length > 0)
    .sort((left, right) => {
      const lengthDelta = left.pathParts.length - right.pathParts.length;
      if (lengthDelta !== 0) {
        return lengthDelta;
      }
      const pathDelta = esmWorkspaceComparePathParts(left.pathParts, right.pathParts);
      if (pathDelta !== 0) {
        return pathDelta;
      }
      return String(left.endpoint?.url || "").localeCompare(String(right.endpoint?.url || ""), undefined, {
        sensitivity: "base",
      });
    });

  esmWorkspaceState.endpointIndexByPathKey = new Map();
  sortedEntries.forEach(({ endpointIndex, pathParts }) => {
    const key = esmWorkspacePathPartsToKey(pathParts);
    if (!key || esmWorkspaceState.endpointIndexByPathKey.has(key)) {
      return;
    }
    esmWorkspaceState.endpointIndexByPathKey.set(key, endpointIndex);
  });

  treeRoot.innerHTML = "";
  const rootList = document.createElement("ul");
  rootList.className = "esm-workspace-root";

  sortedEntries.forEach(({ endpoint, endpointIndex, pathParts, searchHay }) => {
    const item = document.createElement("li");
    item.dataset.endpointIndex = String(endpointIndex);
    item.dataset.zoomKey = String(endpoint?.zoomKey || "");
    item.dataset.hay = String(searchHay || "");
    item.dataset.href = String(endpoint?.url || "");
    item.dataset.nodeParts = JSON.stringify(pathParts);
    item.dataset.pathParts = JSON.stringify(pathParts);
    item.dataset.pathHay = pathParts.join(" ").toLowerCase().replace(/\s+/g, "");

    const nodeRow = document.createElement("div");
    nodeRow.className = "esm-workspace-node";

    const label = document.createElement("span");
    label.className = "esm-workspace-label";
    label.title = String(endpoint?.url || "");
    esmWorkspaceRenderLabelChips(label, pathParts, "", null, {
      onSegmentClick: (segmentPathParts) => {
        const segmentEndpoint = esmWorkspaceResolveEndpointByPathParts(esmWorkspaceState, segmentPathParts);
        if (!segmentEndpoint) {
          return;
        }
        void esmWorkspaceRunEndpointFromUi(esmWorkspaceState, segmentEndpoint, requestToken, "tree");
      },
    });
    label.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void esmWorkspaceRunEndpointFromUi(esmWorkspaceState, endpoint, requestToken, "tree");
    });
    nodeRow.appendChild(label);

    item.appendChild(nodeRow);
    rootList.appendChild(item);
  });

  treeRoot.appendChild(rootList);
  esmWorkspaceState.treeModel = null;
  esmWorkspaceApplyTreeFilters(esmWorkspaceState, { highlight: false });
}

function wireEsmWorkspaceInteractions(esmWorkspaceState, requestToken) {
  if (!esmWorkspaceState?.contentElement) {
    return;
  }
  const getLiveRequestToken = () => {
    const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
      esmWorkspaceState?.programmer?.programmerId,
      esmWorkspaceState?.requestToken || requestToken || 0
    );
    esmWorkspaceState.requestToken = liveRequestToken;
    return liveRequestToken;
  };

  const toggleTreePanel = () => {
    const expanded = String(
      esmWorkspaceState.treeToggleButton?.getAttribute("aria-expanded") ||
        (esmWorkspaceState.treeScrollElement?.hidden ? "false" : "true")
    ) !== "false";
    esmWorkspaceSetTreeCollapsed(esmWorkspaceState, expanded);
  };

  const runVisibleEndpointsToWorkspace = async (source = "esm-jelly-load-all") => {
    if (esmWorkspaceState.loadAllBusy === true) {
      return;
    }
    const endpointIndexes = Array.isArray(esmWorkspaceState.visibleEndpointIndexes)
      ? esmWorkspaceState.visibleEndpointIndexes
      : [];
    const endpointQueue = [...new Set(endpointIndexes)]
      .map((endpointIndex) => Number(endpointIndex))
      .filter((endpointIndex) => Number.isInteger(endpointIndex) && endpointIndex >= 0)
      .map((endpointIndex) => esmWorkspaceState.catalog?.[endpointIndex])
      .filter((endpoint) => endpoint && typeof endpoint === "object" && String(endpoint.url || "").trim());
    if (endpointQueue.length === 0) {
      return;
    }

    esmWorkspaceState.loadAllBusy = true;
    esmWorkspaceSyncPanelLoadAllButtons(esmWorkspaceState, endpointIndexes);
    try {
      const workspaceTab = await esmWorkspaceEnsureWorkspaceTab({
        activate: true,
        windowId: Number(esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0),
      });
      const targetWindowId = Number(
        workspaceTab?.windowId || esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0
      );
      await esmWaitForWorkspaceReady(targetWindowId, Number(workspaceTab?.id || 0), 6000).catch(() => false);
      esmWorkspaceBroadcastControllerState(esmWorkspaceState);

      for (const endpoint of endpointQueue) {
        const runRequestToken = getLiveRequestToken();
        if (!isEsmServiceRequestActive(esmWorkspaceState.section, runRequestToken, esmWorkspaceState.programmer?.programmerId)) {
          break;
        }
        await esmWorkspaceRunEndpointToWorkspace(
          esmWorkspaceState,
          endpoint,
          generateRequestId(),
          runRequestToken,
          {
            emitStart: true,
            requestSource: source,
          }
        );
      }
    } catch (error) {
      setStatus(`Unable to load visible ESM endpoints: ${error instanceof Error ? error.message : String(error)}`, "error");
    } finally {
      esmWorkspaceState.loadAllBusy = false;
      esmWorkspaceSyncPanelLoadAllButtons(esmWorkspaceState, esmWorkspaceState.visibleEndpointIndexes);
    }
  };

  const applyEsmWorkspaceSearchFilters = ({ highlight = false, normalizeInput = false } = {}) => {
    const normalizedTerm = clickEsmNormalizeSearchTerm(esmWorkspaceState.searchInput?.value || "");
    const normalizedZoomFilter = String(esmWorkspaceState.zoomFilterSelect?.value || "").trim().toUpperCase();
    if (esmWorkspaceState.searchInput && normalizeInput) {
      esmWorkspaceState.searchInput.value = normalizedTerm;
    }
    const filterResult = esmWorkspaceApplyTreeFilters(esmWorkspaceState, {
      zoomFilter: normalizedZoomFilter,
      term: normalizedTerm,
      highlight: Boolean(highlight && normalizedTerm),
    });
    return filterResult;
  };

  esmWorkspaceState.recordingToggleButton?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    if (state.esmWorkspaceStopping) {
      return;
    }
    if (getActiveEsmWorkspaceDebugFlowId()) {
      void stopEsmWorkspaceEsmRecording(esmWorkspaceState);
      return;
    }
    void startEsmWorkspaceEsmRecording(esmWorkspaceState, getLiveRequestToken());
  });

  esmWorkspaceState.resetButton?.addEventListener("click", () => {
    if (esmWorkspaceState.searchInput) {
      esmWorkspaceState.searchInput.value = "";
    }
    if (esmWorkspaceState.zoomFilterSelect) {
      esmWorkspaceState.zoomFilterSelect.value = "";
    }
    applyEsmWorkspaceSearchFilters({ highlight: false, normalizeInput: true });
  });

  esmWorkspaceState.makeClickEsmButton?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    void esmWorkspaceMakeClickEsmFromUi(esmWorkspaceState, getLiveRequestToken(), "sidepanel");
  });

  esmWorkspaceState.megSelectElement?.addEventListener("change", (event) => {
    esmWorkspaceState.megSelectedEndpointUrl = String(event.target?.value || "").trim();
    esmWorkspaceSyncMegSelectionUi(esmWorkspaceState);
  });

  esmWorkspaceState.megSavedQuerySelectElement?.addEventListener("change", (event) => {
    const selectElement = event.target;
    const savedQueryUrl = String(selectElement?.value || "").trim();
    if (!savedQueryUrl) {
      return;
    }
    const savedQueryName = String(selectElement?.selectedOptions?.[0]?.textContent || "").trim();
    selectElement.value = "";
    selectElement.title = "Saved Queries";
    selectElement.setAttribute("aria-label", "Saved Queries");
    void esmWorkspaceOpenSavedQueryFromUi(esmWorkspaceState, savedQueryUrl, getLiveRequestToken(), savedQueryName);
  });

  esmWorkspaceState.megToggleButton?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    esmWorkspaceSyncMegSavedQueryUi(esmWorkspaceState);
    esmWorkspaceSetMegPanelCollapsed(
      esmWorkspaceState,
      !esmWorkspaceState?.megPanelElement?.classList.contains("is-collapsed")
    );
  });

  esmWorkspaceState.megLaunchButton?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    const endpoint = esmWorkspaceGetSelectedMegEndpoint(esmWorkspaceState);
    if (!endpoint) {
      return;
    }
    void megWorkspaceOpenEndpointFromUi(esmWorkspaceState, endpoint, getLiveRequestToken());
  });

  esmWorkspaceState.zoomFilterSelect?.addEventListener("change", () => {
    applyEsmWorkspaceSearchFilters({ highlight: true });
  });

  esmWorkspaceState.searchInput?.addEventListener("input", () => {
    applyEsmWorkspaceSearchFilters({ highlight: true });
  });

  esmWorkspaceState.searchInput?.addEventListener("change", () => {
    applyEsmWorkspaceSearchFilters({ highlight: true });
  });

  esmWorkspaceState.searchInput?.addEventListener("keydown", (event) => {
    if (event.key !== "Enter" || event.isComposing || event.keyCode === 229) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    applyEsmWorkspaceSearchFilters({ highlight: true, normalizeInput: true });
  });

  esmWorkspaceState.treeToggleButton?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    toggleTreePanel();
  });

  esmWorkspaceState.treeLoadAllButton?.addEventListener("click", async (event) => {
    event.preventDefault();
    event.stopPropagation();
    await runVisibleEndpointsToWorkspace("esm-jelly-tree-load-all");
  });
}

function getActiveEsmWorkspaceState() {
  const sections = document.querySelectorAll(".premium-service-section.service-esm");
  for (const section of sections) {
    const esmWorkspaceState = section?.__underparEsmWorkspaceState || null;
    if (esmWorkspaceState?.section?.isConnected) {
      return esmWorkspaceState;
    }
  }
  return null;
}

async function handleEsmWorkspaceWorkspaceAction(message, sender = null) {
  const action = String(message?.action || "").trim().toLowerCase();
  let esmWorkspaceState = getActiveEsmWorkspaceState();
  const senderWindowId = Number(sender?.tab?.windowId || 0);
  const senderTabId = Number(sender?.tab?.id || 0);
  const controllerWindowId = esmWorkspaceState
    ? Number(esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0)
    : 0;
  const mappedSenderTabId =
    senderWindowId > 0 ? Number(state.esmWorkspaceWorkspaceTabIdByWindowId.get(senderWindowId) || 0) : 0;

  if (senderWindowId > 0 && controllerWindowId > 0 && senderWindowId !== controllerWindowId) {
    return { ok: false, error: "ESM controller is attached to a different window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && mappedSenderTabId > 0 && senderTabId !== mappedSenderTabId) {
    return { ok: false, error: "This is not the bound ESM Workspace tab for the window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && (!mappedSenderTabId || mappedSenderTabId <= 0)) {
    esmWorkspaceBindWorkspaceTab(senderWindowId, senderTabId);
  }
  if (esmWorkspaceState && senderWindowId > 0 && Number(esmWorkspaceState.controllerWindowId || 0) <= 0) {
    esmWorkspaceState.controllerWindowId = senderWindowId;
  }

  if (action === "workspace-ready") {
    emitEsmWorkspaceDebugEvent(getActiveEsmWorkspaceDebugFlowId(), {
      phase: "workspace-ready",
      source: "workspace",
      windowId: senderWindowId,
      tabId: senderTabId,
    });
    if (!esmWorkspaceState) {
      esmWorkspaceState = await resolveEsmStateForWorkspaceAction({
        controllerWindowId: senderWindowId || Number(state.esmWorkspaceWorkspaceWindowId || 0),
        reason: "workspace-ready",
      }).catch(() => null);
    }
    if (esmWorkspaceState) {
      if (senderWindowId > 0) {
        esmWorkspaceBindWorkspaceTab(senderWindowId, senderTabId);
      }
      esmMarkWorkspaceReady(senderWindowId || Number(esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0), senderTabId);
      esmWorkspaceBroadcastControllerState(esmWorkspaceState, senderWindowId);
    } else {
      const selectedProgrammer = resolveSelectedProgrammer();
      const selectedServices = selectedProgrammer?.programmerId
        ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
        : null;
      esmMarkWorkspaceReady(senderWindowId || Number(state.esmWorkspaceWorkspaceWindowId || 0), senderTabId);
      esmWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices, senderWindowId);
    }
    return { ok: true, controllerOnline: Boolean(esmWorkspaceState) };
  }

  if (action === "make-clickesm") {
    const context = await resolveClickEsmDownloadContext(esmWorkspaceState);
    if (!context) {
      return { ok: false, error: "Select a media company with ESM access to generate clickESM." };
    }
    const requestToken = Number(state.premiumPanelRequestToken || 0);
    const result = await makeClickEsmDownload(context, requestToken, { source: "workspace" });
    return {
      ok: true,
      fileName: result.fileName,
      programmerLabel: result.programmerLabel,
    };
  }

  if (action === "resolve-clickesmws-auth") {
    const context = await resolveClickEsmDownloadContext(esmWorkspaceState);
    if (!context) {
      return { ok: false, error: "Select a media company with ESM access to generate clickESM workspace tearsheet." };
    }
    const requestToken = Number(state.premiumPanelRequestToken || 0);
    const authContext = await resolveClickEsmAuthContext(context, requestToken, {
      source: "workspace-tearsheet",
    });
    return {
      ok: true,
      programmerLabel: authContext.programmerLabel,
      clientId: authContext.clientId,
      clientSecret: authContext.clientSecret,
      accessToken: authContext.accessToken,
      requestorIds: Array.isArray(context?.requestorIds) ? context.requestorIds.slice(0, 24) : [],
      mvpdIds: Array.isArray(context?.mvpdIds) ? context.mvpdIds.slice(0, 24) : [],
      vaultExportPayload: buildUnderparTearsheetExportPayload(context?.programmer || null, {
        serviceKey: "esm",
        appInfo: context?.appInfo || null,
        credential:
          normalizeUnderparVaultDcrCache(
            loadDcrCache(
              String(context?.programmer?.programmerId || ""),
              String(context?.appInfo?.guid || "")
            ) || null
          ) || {
            clientId: String(authContext?.clientId || "").trim(),
            clientSecret: String(authContext?.clientSecret || "").trim(),
            accessToken: String(authContext?.accessToken || "").trim(),
            tokenExpiresAt: 0,
            tokenScope: "",
            serviceScope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
            tokenRequestedScope: PREMIUM_SERVICE_SCOPE_BY_KEY.esm,
          },
        passVaultRecord: context?.passVaultRecord || null,
        requestorIds: Array.isArray(context?.requestorIds) ? context.requestorIds : [],
        requestorCatalogIds: Array.isArray(context?.requestorCatalogIds) ? context.requestorCatalogIds : [],
        mvpdIds: Array.isArray(context?.mvpdIds) ? context.mvpdIds : [],
      }),
    };
  }

  if (!esmWorkspaceState) {
    esmWorkspaceState = await resolveEsmStateForWorkspaceAction({
      controllerWindowId: senderWindowId || Number(state.esmWorkspaceWorkspaceWindowId || 0),
      reason: action || "workspace-action",
    }).catch(() => null);
  }

  if (!esmWorkspaceState) {
    return { ok: false, error: "Select a media company with ESM access to run reports." };
  }

  const requestToken = Number(state.premiumPanelRequestToken || 0);
  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    return { ok: false, error: "ESM controller is no longer active for the selected media company." };
  }
  const activeFlowId = getActiveEsmWorkspaceDebugFlowId();

  if (action === "open-workspace") {
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "workspace-action",
      action: "open-workspace",
      source: "workspace",
      windowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0),
    });
    const targetWindowId = senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0);
    await esmWorkspaceEnsureWorkspaceTab({ activate: true, windowId: targetWindowId });
    esmWorkspaceBroadcastControllerState(esmWorkspaceState, targetWindowId);
    return { ok: true };
  }

  if (action === "run-card") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    const requestSourceRaw = String(message?.requestSource || "").trim().toLowerCase();
    const requestSource = requestSourceRaw || "workspace";
    const requestUrlOverride = String(card?.requestUrl || "").trim();
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "workspace-action",
      action: "run-card",
      source: "workspace",
      cardId: String(card?.cardId || ""),
      endpointUrl: String(card?.endpointUrl || ""),
      requestSource,
    });
    const endpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, card.endpointUrl, card);
    if (!endpoint) {
      return { ok: false, error: "Endpoint URL is required." };
    }
    await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, String(card.cardId || generateRequestId()), requestToken, {
      emitStart: true,
      requestSource,
      targetWindowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0),
      requestUrlOverride,
      originCardKey: card?.originCardKey,
      presetLocalFilterBootstrapPending: card?.presetLocalFilterBootstrapPending === true,
      seedEndpointUrl: card?.seedEndpointUrl,
      seedRequestUrl: card?.seedRequestUrl,
      seedLocalColumnFilters: card?.seedLocalColumnFilters,
      seedLocalColumnExclusions: card?.seedLocalColumnExclusions,
      seedPresetLocalFilterBootstrapPending: card?.seedPresetLocalFilterBootstrapPending === true,
      localColumnFilters: card?.localColumnFilters,
      localColumnExclusions: card?.localColumnExclusions,
    });
    return { ok: true };
  }

  if (action === "rerun-all") {
    const cards = Array.isArray(message?.cards) ? message.cards : [];
    const reason = String(message?.reason || "").trim().toLowerCase();
    const requestSourceForRerun = reason === "programmer-switch" ? "workspace-programmer-switch" : "workspace";
    const workspaceContextKey = buildEsmWorkspaceControllerContextKey(
      String(esmWorkspaceState?.programmer?.programmerId || "").trim(),
      requestToken,
      getActiveAdobePassEnvironmentKey()
    );
    const adobePassEnvironmentKey = String(getActiveAdobePassEnvironmentKey() || "").trim();
    const programmerId = String(esmWorkspaceState?.programmer?.programmerId || "").trim();
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "workspace-action",
      action: "rerun-all",
      source: "workspace",
      cardCount: cards.length,
    });
    void esmWorkspaceSendWorkspaceMessage("batch-start", {
      total: cards.length,
      reason,
      programmerId,
      adobePassEnvironmentKey,
      premiumPanelRequestToken: requestToken,
      workspaceContextKey,
      startedAt: Date.now(),
    }, {
      targetWindowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0),
    });
    for (const card of cards) {
      const endpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, card?.endpointUrl, card || {});
      if (!endpoint) {
        continue;
      }
      await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, String(card?.cardId || generateRequestId()), requestToken, {
        emitStart: true,
        requestSource: requestSourceForRerun,
        targetWindowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0),
        requestUrlOverride: String(card?.requestUrl || "").trim(),
        originCardKey: card?.originCardKey,
        presetLocalFilterBootstrapPending: card?.presetLocalFilterBootstrapPending === true,
        seedEndpointUrl: card?.seedEndpointUrl,
        seedRequestUrl: card?.seedRequestUrl,
        seedLocalColumnFilters: card?.seedLocalColumnFilters,
        seedLocalColumnExclusions: card?.seedLocalColumnExclusions,
        seedPresetLocalFilterBootstrapPending: card?.seedPresetLocalFilterBootstrapPending === true,
        localColumnFilters: card?.localColumnFilters,
        localColumnExclusions: card?.localColumnExclusions,
      });
    }
    void esmWorkspaceSendWorkspaceMessage("batch-end", {
      total: cards.length,
      reason,
      programmerId,
      adobePassEnvironmentKey,
      premiumPanelRequestToken: requestToken,
      workspaceContextKey,
      completedAt: Date.now(),
    }, {
      targetWindowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0),
    });
    return { ok: true };
  }

  if (action === "download-csv") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    emitEsmWorkspaceDebugEvent(activeFlowId, {
      phase: "workspace-action",
      action: "download-csv",
      source: "workspace",
      cardId: String(card?.cardId || ""),
      endpointUrl: String(card?.endpointUrl || ""),
    });
    const endpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, card.endpointUrl, card);
    if (!endpoint) {
      return { ok: false, error: "Endpoint URL is required." };
    }
    await esmWorkspaceDownloadCsvForCard(
      esmWorkspaceState,
      endpoint,
      esmWorkspaceNormalizeSortRule(message?.sortRule),
      requestToken,
      String(card.cardId || ""),
      card?.localColumnFilters
    );
    return { ok: true };
  }

  if (action === "blondie-export") {
    const exportPayload = withUnderparBlondieCsvFileName(
      message?.exportPayload || null,
      buildUnderparBlondieEsmCsvFileName(message?.card || null, message?.exportPayload || null)
    );
    return await sendUnderparBlondieExportToSlack(exportPayload, {
      interactive: true,
      deliveryTarget: message?.deliveryTarget || null,
      noteText: message?.noteText || "",
    });
  }

  return { ok: false, error: `Unsupported workspace action: ${action}` };
}

async function handleBlondieTimeWorkspaceAction(message, sender = null) {
  const action = String(message?.action || "").trim().toLowerCase();
  let esmWorkspaceState = getActiveEsmWorkspaceState();
  const senderWindowId = Number(sender?.tab?.windowId || 0);
  const senderTabId = Number(sender?.tab?.id || 0);
  const controllerWindowId = esmWorkspaceState
    ? Number(esmWorkspaceState.controllerWindowId || state.blondieTimeWorkspaceWindowId || 0)
    : Number(state.blondieTimeWorkspaceWindowId || 0);
  const mappedSenderTabId =
    senderWindowId > 0 ? Number(state.blondieTimeWorkspaceTabIdByWindowId.get(senderWindowId) || 0) : 0;

  if (senderWindowId > 0 && controllerWindowId > 0 && senderWindowId !== controllerWindowId) {
    return { ok: false, error: "BT_WS controller is attached to a different window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && mappedSenderTabId > 0 && senderTabId !== mappedSenderTabId) {
    return { ok: false, error: "This is not the bound Blondie Time Workspace tab for the window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && (!mappedSenderTabId || mappedSenderTabId <= 0)) {
    blondieTimeWorkspaceBindWorkspaceTab(senderWindowId, senderTabId);
  }
  if (action === "workspace-ready") {
    if (!esmWorkspaceState) {
      esmWorkspaceState = await resolveEsmStateForWorkspaceAction({
        controllerWindowId: senderWindowId || Number(state.blondieTimeWorkspaceWindowId || 0),
        reason: "bt-workspace-ready",
      }).catch(() => null);
    }
    if (esmWorkspaceState) {
      if (senderWindowId > 0) {
        blondieTimeWorkspaceBindWorkspaceTab(senderWindowId, senderTabId);
      }
      blondieTimeWorkspaceBroadcastControllerState(esmWorkspaceState, senderWindowId);
    } else {
      const selectedProgrammer = resolveSelectedProgrammer();
      const selectedServices = selectedProgrammer?.programmerId
        ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
        : null;
      blondieTimeWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices, senderWindowId);
    }
    return { ok: true, controllerOnline: Boolean(esmWorkspaceState) };
  }

  if (!esmWorkspaceState) {
    esmWorkspaceState = await resolveEsmStateForWorkspaceAction({
      controllerWindowId: senderWindowId || Number(state.blondieTimeWorkspaceWindowId || 0),
      reason: action || "bt-workspace-action",
    }).catch(() => null);
  }

  if (!esmWorkspaceState) {
    return { ok: false, error: "Select a media company with ESM access to run BT_WS analysis." };
  }

  const requestToken = Number(state.premiumPanelRequestToken || 0);
  if (!isEsmServiceRequestActive(esmWorkspaceState.section, requestToken, esmWorkspaceState.programmer?.programmerId)) {
    return { ok: false, error: "ESM controller is no longer active for the selected media company." };
  }

  if (action === "rerun-all") {
    const cards = Array.isArray(message?.cards) ? message.cards : [];
    const reason = String(message?.reason || "").trim();
    const intervalMinutes = Math.max(0, Number(message?.intervalMinutes || 0));
    const requestedAt = Math.max(0, Number(message?.requestedAt || Date.now())) || Date.now();
    const targetWindowId = senderWindowId || Number(esmWorkspaceState.controllerWindowId || state.blondieTimeWorkspaceWindowId || 0);
    void blondieTimeWorkspaceSendWorkspaceMessage(
      "batch-start",
      {
        total: cards.length,
        reason,
        startedAt: Date.now(),
      },
      { targetWindowId }
    );
    try {
      for (const card of cards) {
        const endpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, card?.endpointUrl, card || {});
        if (!endpoint) {
          continue;
        }
        const requestUrlOverride = buildBlondieTimeEsmRequestUrlOverride(card, intervalMinutes, {
          nowMs: requestedAt,
        });
        await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, String(card?.cardId || generateRequestId()), requestToken, {
          emitStart: true,
          requestSource: "workspace",
          targetWindowId,
          defaultWorkspaceWindowId: state.blondieTimeWorkspaceWindowId,
          workspaceMessageSender: blondieTimeWorkspaceSendWorkspaceMessage,
          requestUrlOverride,
          skipOriginLookup: true,
          originCardKey: card?.originCardKey,
          presetLocalFilterBootstrapPending: card?.presetLocalFilterBootstrapPending === true,
          seedEndpointUrl: card?.seedEndpointUrl,
          seedRequestUrl: card?.seedRequestUrl,
          seedLocalColumnFilters: card?.seedLocalColumnFilters,
          seedLocalColumnExclusions: card?.seedLocalColumnExclusions,
          seedPresetLocalFilterBootstrapPending: card?.seedPresetLocalFilterBootstrapPending === true,
          localColumnFilters: card?.localColumnFilters,
          localColumnExclusions: card?.localColumnExclusions,
          displayNodeLabel: String(card?.displayNodeLabel || "").trim(),
        });
      }
    } finally {
      void blondieTimeWorkspaceSendWorkspaceMessage(
        "batch-end",
        {
          total: cards.length,
          reason,
          completedAt: Date.now(),
        },
        { targetWindowId }
      );
    }
    return { ok: true };
  }

  if (action === "send-to-esm-workspace") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    const endpoint = esmWorkspaceFindEndpointByUrl(esmWorkspaceState, card?.endpointUrl, card);
    if (!endpoint) {
      return { ok: false, error: "Endpoint URL is required." };
    }
    const workspaceTab = await esmWorkspaceEnsureWorkspaceTab({
      activate: true,
      windowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || 0),
    });
    const targetWindowId = Number(workspaceTab?.windowId || senderWindowId || esmWorkspaceState.controllerWindowId || state.esmWorkspaceWorkspaceWindowId || 0);
    esmWorkspaceBroadcastControllerState(esmWorkspaceState, targetWindowId);
    await esmWorkspaceRunEndpointToWorkspace(esmWorkspaceState, endpoint, String(card?.cardId || generateRequestId()), requestToken, {
      emitStart: true,
      requestSource: "workspace",
      targetWindowId,
      requestUrlOverride: String(card?.requestUrl || "").trim(),
      originCardKey: card?.originCardKey,
      presetLocalFilterBootstrapPending: card?.presetLocalFilterBootstrapPending === true,
      seedEndpointUrl: card?.seedEndpointUrl,
      seedRequestUrl: card?.seedRequestUrl,
      seedLocalColumnFilters: card?.seedLocalColumnFilters,
      seedLocalColumnExclusions: card?.seedLocalColumnExclusions,
      seedPresetLocalFilterBootstrapPending: card?.seedPresetLocalFilterBootstrapPending === true,
      localColumnFilters: card?.localColumnFilters,
      localColumnExclusions: card?.localColumnExclusions,
      displayNodeLabel: String(card?.displayNodeLabel || "").trim(),
    });
    return { ok: true };
  }

  if (action === "export-session-pdf") {
    const targetTabId = Number(
      senderTabId || mappedSenderTabId || blondieTimeWorkspaceGetBoundWorkspaceTabId(senderWindowId || controllerWindowId || 0) || 0
    );
    if (!targetTabId) {
      return { ok: false, error: "Blondie Time Workspace tab is no longer available for PDF export." };
    }
    const exportResult = await exportBlondieTimeWorkspacePdf(targetTabId, message?.fileName || "underpar_bt_ws_session.pdf");
    return {
      ok: true,
      fileName: exportResult.fileName || "underpar_bt_ws_session.pdf",
    };
  }

  if (action === "export-session-csv") {
    return await buildBlondieTimeSessionCsvExport(
      esmWorkspaceState,
      requestToken,
      Array.isArray(message?.cards) ? message.cards : [],
      message?.sessionWindow && typeof message.sessionWindow === "object" ? message.sessionWindow : {},
      {
        targetWindowId: senderWindowId || Number(esmWorkspaceState.controllerWindowId || state.blondieTimeWorkspaceWindowId || 0),
        defaultWorkspaceWindowId: state.blondieTimeWorkspaceWindowId,
      }
    );
  }

  if (action === "blondie-export-all") {
    if (message?.exportPayload) {
      return await sendUnderparBlondieExportToSlack(message.exportPayload, {
        interactive: true,
        deliveryTarget: message?.deliveryTarget || null,
        noteText: message?.noteText || "",
      });
    }
    const exportPayloads = Array.isArray(message?.exportPayloads) ? message.exportPayloads : [];
    if (exportPayloads.length > 0) {
      return await sendUnderparBlondieExportBatchToSlack(exportPayloads, {
        interactive: true,
        deliveryTarget: message?.deliveryTarget || null,
        noteText: message?.noteText || "",
        emptyError: "No BT_WS report data was available for :blondiebtn:.",
        genericError: "Unable to deliver Blondie Time Results with :blondiebtn:.",
      });
    }
    return { ok: false, error: "No BT_WS report data was provided for :blondiebtn:." };
  }

  return { ok: false, error: `Unsupported Blondie Time Workspace action: ${action}` };
}

async function handleMegWorkspaceWorkspaceAction(message, sender = null) {
  const action = String(message?.action || "").trim().toLowerCase();
  const esmWorkspaceState = getActiveEsmWorkspaceState();
  const senderWindowId = Number(sender?.tab?.windowId || 0);
  const senderTabId = Number(sender?.tab?.id || 0);
  const controllerWindowId = esmWorkspaceState
    ? Number(esmWorkspaceState.controllerWindowId || state.megWorkspaceWindowId || 0)
    : Number(state.megWorkspaceWindowId || 0);
  const mappedSenderTabId =
    senderWindowId > 0 ? Number(state.megWorkspaceTabIdByWindowId.get(senderWindowId) || 0) : 0;

  if (senderWindowId > 0 && controllerWindowId > 0 && senderWindowId !== controllerWindowId) {
    return { ok: false, error: "MEGSPACE controller is attached to a different window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && mappedSenderTabId > 0 && senderTabId !== mappedSenderTabId) {
    return { ok: false, error: "This is not the bound MEGSPACE tab for the window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && (!mappedSenderTabId || mappedSenderTabId <= 0)) {
    megWorkspaceBindWorkspaceTab(senderWindowId, senderTabId);
  }

  if (action === "workspace-ready") {
    if (senderWindowId > 0) {
      megWorkspaceBindWorkspaceTab(senderWindowId, senderTabId);
    }
    if (esmWorkspaceState) {
      megWorkspaceBroadcastControllerState(esmWorkspaceState, senderWindowId);
    } else {
      const selectedProgrammer = resolveSelectedProgrammer();
      const selectedServices = selectedProgrammer?.programmerId
        ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
        : null;
      megWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices, senderWindowId);
    }
    const selection = megWorkspaceGetRememberedSelection(senderWindowId);
    if (selection) {
      void megWorkspaceSendWorkspaceMessage(
        "selection-change",
        {
          ...selection,
          autoRun: true,
        },
        {
          targetWindowId: senderWindowId || Number(state.megWorkspaceWindowId || 0),
        }
      );
    }
    return { ok: true, controllerOnline: Boolean(esmWorkspaceState) };
  }

  if (action === "open-workspace") {
    const targetWindowId = senderWindowId || controllerWindowId || Number(state.megWorkspaceWindowId || 0);
    const workspaceTab = await megWorkspaceEnsureWorkspaceTab({
      activate: true,
      windowId: targetWindowId,
    });
    const resolvedWindowId = Number(workspaceTab?.windowId || targetWindowId || 0);
    if (esmWorkspaceState) {
      megWorkspaceBroadcastControllerState(esmWorkspaceState, resolvedWindowId);
    } else {
      const selectedProgrammer = resolveSelectedProgrammer();
      const selectedServices = selectedProgrammer?.programmerId
        ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
        : null;
      megWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices, resolvedWindowId);
    }
    const selection = megWorkspaceGetRememberedSelection(resolvedWindowId);
    if (selection) {
      void megWorkspaceSendWorkspaceMessage("selection-change", selection, {
        targetWindowId: resolvedWindowId,
      });
    }
    return { ok: true };
  }

  if (action === "workspace-clear") {
    megWorkspaceClearRememberedSelection(senderWindowId || Number(state.megWorkspaceWindowId || 0));
    void megWorkspaceSendWorkspaceMessage("workspace-clear", {}, {
      targetWindowId: senderWindowId || Number(state.megWorkspaceWindowId || 0),
    });
    return { ok: true };
  }

  if (action === "resolve-run-context") {
    const context = await resolveClickEsmDownloadContext(esmWorkspaceState);
    if (!context) {
      return { ok: false, error: "Select an ESM-scoped programmer to run MEGSPACE." };
    }
    const requestToken = Number(state.premiumPanelRequestToken || 0);
    const authContext = await resolveClickEsmAuthContext(context, requestToken, {
      source: String(message?.payload?.source || message?.source || "meg-workspace"),
      requireAccessToken: false,
    });
    const selectedProgrammer = resolveSelectedProgrammer();
    const selectedServices = selectedProgrammer?.programmerId
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
      : null;
    const controllerState = esmWorkspaceState
      ? esmWorkspaceGetControllerStatePayload(esmWorkspaceState)
      : esmWorkspaceGetSelectedControllerStatePayload(selectedProgrammer, selectedServices);
    return {
      ok: true,
      controllerState,
      selection: megWorkspaceGetRememberedSelection(senderWindowId || Number(state.megWorkspaceWindowId || 0)),
      programmerLabel: authContext.programmerLabel,
      clientId: authContext.clientId,
      clientSecret: authContext.clientSecret,
      accessToken: authContext.accessToken,
      requestorIds: Array.isArray(context?.requestorIds) ? context.requestorIds.slice(0, 24) : [],
      mvpdIds: Array.isArray(context?.mvpdIds) ? context.mvpdIds.slice(0, 24) : [],
    };
  }

  if (action === "fetch-esm") {
    const requestToken = Number(state.premiumPanelRequestToken || 0);
    const response = await megWorkspaceFetchResponse(String(message?.payload?.url || ""), requestToken, {
      format: String(message?.payload?.format || "json"),
    });
    return {
      ok: true,
      ...response,
    };
  }

  if (action === "make-tearsheet") {
    const requestToken = Number(state.premiumPanelRequestToken || 0);
    const result = await megWorkspaceDownloadTearsheet(requestToken, {
      currentUrl: String(message?.payload?.currentUrl || "").trim(),
      currentStart: String(message?.payload?.currentStart || "").trim(),
      currentEnd: String(message?.payload?.currentEnd || "").trim(),
      selection: message?.payload?.selection && typeof message.payload.selection === "object" ? message.payload.selection : null,
    });
    return {
      ok: true,
      fileName: result.fileName || "",
      programmerLabel: result.programmerLabel || "",
    };
  }

  if (action === "download-csv" || action === "download-export") {
    const requestToken = Number(state.premiumPanelRequestToken || 0);
    const format =
      action === "download-csv"
        ? "csv"
        : megWorkspaceNormalizeExportFormat(String(message?.payload?.format || ""), "csv");
    const result = await megWorkspaceDownloadExport(String(message?.payload?.url || ""), requestToken, format);
    return {
      ok: true,
      fileName: result.fileName || "",
      format: result.format || format,
    };
  }

  if (action === "saved-query-get-records") {
    await ensureSavedEsmQueryVaultMirror({ forceReload: false });
    return {
      ok: true,
      records: popupGetSavedEsmQueryRecords(),
    };
  }

  if (action === "saved-query-put-record") {
    const result = await popupPersistSavedEsmQueryRecord(
      String(message?.payload?.name || ""),
      String(message?.payload?.url || "")
    );
    return {
      ok: true,
      storageKey: String(result?.storageKey || ""),
      existed: result?.existed === true,
      records: popupGetSavedEsmQueryRecords(),
    };
  }

  if (action === "saved-query-delete-record") {
    const result = await popupDeleteSavedEsmQueryRecord(String(message?.payload?.storageKey || ""));
    return {
      ok: true,
      storageKey: String(result?.storageKey || ""),
      records: popupGetSavedEsmQueryRecords(),
    };
  }

  if (action === "saved-query-sync-sidepanel") {
    await ensureSavedEsmQueryVaultMirror({ forceReload: false });
    refreshAllEsmWorkspaceMegSavedQuerySelectors();
    return {
      ok: true,
      records: popupGetSavedEsmQueryRecords(),
    };
  }

  return { ok: false, error: `Unsupported MEGSPACE action: ${action}` };
}

function ensureEsmWorkspaceRuntimeListener() {
  if (state.esmWorkspaceRuntimeListenerBound) {
    return;
  }
  chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
    if (!ESM_WORKSPACE_MESSAGE_TYPES.has(String(message?.type || "")) || message?.channel !== "workspace-action") {
      return false;
    }

    void handleEsmWorkspaceWorkspaceAction(message, sender)
      .then((result) => {
        sendResponse(result && typeof result === "object" ? result : { ok: true });
      })
      .catch((error) => {
        sendResponse({ ok: false, error: error instanceof Error ? error.message : String(error) });
      });
    return true;
  });
  state.esmWorkspaceRuntimeListenerBound = true;
}

