async function loadEsmWorkspaceService(programmer, appInfo, section, contentElement, requestToken) {
  if (!contentElement) {
    return;
  }
  let currentServices = programmer?.programmerId ? getCurrentPremiumAppsSnapshot(programmer.programmerId) : null;
  let resolvedAppInfo = hasEsmScopedApp(currentServices) ? currentServices.esm : appInfo;
  if (programmer?.programmerId && !resolvedAppInfo?.guid) {
    const inFlightHydration = getProgrammerServiceHydrationPromise(programmer.programmerId);
    if (inFlightHydration) {
      const hydratedServices = await inFlightHydration.catch(() => null);
      currentServices =
        (hydratedServices && typeof hydratedServices === "object" ? hydratedServices : null) ||
        getCurrentPremiumAppsSnapshot(programmer.programmerId) ||
        currentServices;
      resolvedAppInfo = hasEsmScopedApp(currentServices) ? currentServices.esm : resolvedAppInfo;
    }
  }
  if (programmer?.programmerId && !resolvedAppInfo?.guid) {
    const hydratedServices =
      (await getProgrammerServiceHydrationPromise(programmer.programmerId)?.catch(() => null)) ||
      (await primeProgrammerServiceHydration(programmer, currentServices, {
        forceRefresh: false,
        controllerReason: "esm-panel-open",
        requestToken,
      }).catch(() => null));
    currentServices =
      (hydratedServices && typeof hydratedServices === "object" ? hydratedServices : null) ||
      getCurrentPremiumAppsSnapshot(programmer.programmerId) ||
      currentServices;
    resolvedAppInfo = hasEsmScopedApp(currentServices) ? currentServices.esm : appInfo;
  }
  if (!programmer?.programmerId || !resolvedAppInfo?.guid) {
    contentElement.innerHTML = "";
    return;
  }

  section.__underparEsmWorkspaceState = null;
  if (
    state.esmWorkspaceRecordingActive &&
    state.esmWorkspaceRecordingContext &&
    String(state.esmWorkspaceRecordingContext.programmerId || "") &&
    String(state.esmWorkspaceRecordingContext.programmerId || "") !== String(programmer.programmerId || "")
  ) {
    clearEsmWorkspaceRecordingState("programmer-change");
  }

  try {
    const controllerWindowId = await esmWorkspaceGetCurrentWindowId();
    const endpoints = await loadClickEsmEndpoints();
    if (!isEsmServiceRequestActive(section, requestToken, programmer.programmerId)) {
      return;
    }
    if (!Array.isArray(endpoints) || endpoints.length === 0) {
      contentElement.innerHTML = "";
      return;
    }

    const catalog = esmWorkspaceBuildCatalog(endpoints);
    const endpointByUrl = new Map();
    catalog.forEach((item) => {
      endpointByUrl.set(item.url, {
        url: item.url,
        zoomKey: item.zoomKey,
        columns: item.columns,
        segs: Array.isArray(item.segs) ? item.segs.slice(0, 24) : [],
      });
    });

    contentElement.innerHTML = esmWorkspaceBuildShellHtml();
    const esmWorkspaceState = {
      serviceType: "esmWorkspace",
      controllerWindowId: Number(controllerWindowId || 0),
      section,
      contentElement,
      programmer,
      appInfo: resolvedAppInfo,
      endpoints,
      catalog,
      endpointByUrl,
      treeModel: null,
      netInFlight: 0,
      requestToken,
      zoomFilterSelect: contentElement.querySelector(".esm-workspace-zoom-filter"),
      searchInput: contentElement.querySelector(".esm-workspace-search"),
      resetButton: contentElement.querySelector(".esm-workspace-reset-btn"),
      makeClickEsmButton: contentElement.querySelector(".esm-workspace-make-clickesm-btn"),
      treeHeadElement: contentElement.querySelector(".esm-workspace-tree-head"),
      treeToggleButton: contentElement.querySelector(".esm-workspace-tree-toggle"),
      treeScrollElement: contentElement.querySelector(".esm-workspace-tree-scroll"),
      treeRootElement: contentElement.querySelector(".esm-workspace-tree-root"),
      treeLoadAllButton: contentElement.querySelector(".esm-workspace-tree-load-all"),
      treeCountElement: contentElement.querySelector(".esm-workspace-tree-count"),
      megPanelElement: contentElement.querySelector(".esm-workspace-meg-panel"),
      megToggleButton: contentElement.querySelector(".esm-workspace-meg-toggle"),
      megBodyElement: contentElement.querySelector(".esm-workspace-meg-body"),
      megSelectElement: contentElement.querySelector(".esm-workspace-meg-select"),
      megSavedQuerySelectElement: contentElement.querySelector(".esm-workspace-meg-saved-select"),
      megLaunchButton: contentElement.querySelector(".esm-workspace-meg-open-btn"),
      megSelectedEndpointUrl: "",
      visibleEndpointIndexes: [],
      loadAllBusy: false,
      treePanelCollapsed: true,
      recordingStatusElement: contentElement.querySelector(".esm-workspace-recording-status"),
      recordingToggleButton: contentElement.querySelector(".esm-workspace-record-toggle-btn"),
    };

    if (esmWorkspaceState.treeToggleButton) {
      esmWorkspaceState.treeToggleButton.setAttribute("aria-expanded", "false");
      esmWorkspaceState.treeToggleButton.setAttribute("aria-label", "Expand JellyBeans");
      esmWorkspaceState.treeToggleButton.title = ESM_JELLYBEANS_FILTER_TOOLTIP;
    }

    section.__underparEsmWorkspaceState = esmWorkspaceState;
    wireEsmWorkspaceInteractions(esmWorkspaceState, requestToken);
    esmWorkspaceSetTreeCollapsed(esmWorkspaceState, true);
    esmWorkspaceSetMegPanelCollapsed(esmWorkspaceState, true);
    esmWorkspaceSyncMegSavedQueryUi(esmWorkspaceState);
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    esmWorkspaceBuildTree(esmWorkspaceState, requestToken);
    syncEsmWorkspaceRecordingControls(esmWorkspaceState);

    ensureEsmWorkspaceRuntimeListener();
    ensureEsmWorkspaceWorkspaceTabWatcher();
    ensureMegWorkspaceRuntimeListener();
    ensureMegWorkspaceWorkspaceTabWatcher();
    esmWorkspaceBroadcastControllerState(esmWorkspaceState);
  } catch (error) {
    if (!isEsmServiceRequestActive(section, requestToken, programmer.programmerId)) {
      return;
    }
    contentElement.innerHTML = `<div class="service-error">${escapeHtml(
      error instanceof Error ? error.message : String(error)
    )}</div>`;
  }
}

function isCmServiceRequestActive(section, requestToken, programmerId) {
  if (section?.__underparDetachedCmState === true) {
    const selected = resolveSelectedProgrammer();
    return Boolean(selected && selected.programmerId === programmerId);
  }
  if (!section || !section.isConnected) {
    return false;
  }
  if (requestToken !== state.premiumPanelRequestToken) {
    return false;
  }
  const selected = resolveSelectedProgrammer();
  return Boolean(selected && selected.programmerId === programmerId);
}

function cmGetWorkspaceUrl() {
  return chrome.runtime.getURL(CM_WORKSPACE_PATH);
}

function cmIsWorkspaceTab(tabLike) {
  return String(tabLike?.url || "").startsWith(cmGetWorkspaceUrl());
}

function cmBindWorkspaceTab(windowId, tabId) {
  const normalizedWindowId = Number(windowId || 0);
  const normalizedTabId = Number(tabId || 0);
  if (normalizedWindowId > 0 && normalizedTabId > 0) {
    state.cmWorkspaceTabIdByWindowId.set(normalizedWindowId, normalizedTabId);
  }
  if (normalizedWindowId > 0) {
    state.cmWorkspaceWindowId = normalizedWindowId;
  }
  if (normalizedTabId > 0) {
    state.cmWorkspaceTabId = normalizedTabId;
  }
}

function cmMarkWorkspaceReady(windowId, tabId = 0) {
  const normalizedWindowId = Number(windowId || 0);
  const normalizedTabId = Number(tabId || 0);
  if (normalizedWindowId <= 0) {
    return;
  }
  state.cmWorkspaceReadyByWindowId.set(normalizedWindowId, {
    tabId: normalizedTabId,
    readyAt: Date.now(),
  });
  const waiters = state.cmWorkspaceReadyWaitersByWindowId.get(normalizedWindowId);
  if (Array.isArray(waiters) && waiters.length > 0) {
    state.cmWorkspaceReadyWaitersByWindowId.delete(normalizedWindowId);
    waiters.forEach((waiter) => {
      try {
        if (waiter?.timerId) {
          clearTimeout(waiter.timerId);
        }
      } catch {
        // Ignore cleanup failures.
      }
      try {
        waiter?.resolve?.(true);
      } catch {
        // Ignore waiter resolution failures.
      }
    });
  }
}

function cmInvalidateWorkspaceReady(windowId, tabId = 0) {
  const normalizedWindowId = Number(windowId || 0);
  const normalizedTabId = Number(tabId || 0);
  if (normalizedWindowId <= 0) {
    return;
  }
  const existingReady = state.cmWorkspaceReadyByWindowId.get(normalizedWindowId);
  if (!existingReady) {
    return;
  }
  if (!normalizedTabId || Number(existingReady?.tabId || 0) <= 0 || Number(existingReady?.tabId || 0) === normalizedTabId) {
    state.cmWorkspaceReadyByWindowId.delete(normalizedWindowId);
  }
}

function cmIsWorkspaceReady(windowId, tabId = 0) {
  const normalizedWindowId = Number(windowId || 0);
  const normalizedTabId = Number(tabId || 0);
  if (normalizedWindowId <= 0) {
    return false;
  }
  const readyInfo = state.cmWorkspaceReadyByWindowId.get(normalizedWindowId);
  if (!readyInfo) {
    return false;
  }
  if (normalizedTabId > 0 && Number(readyInfo?.tabId || 0) > 0 && Number(readyInfo.tabId) !== normalizedTabId) {
    return false;
  }
  return true;
}

async function cmWaitForWorkspaceReady(windowId, tabId = 0, timeoutMs = 2500) {
  const normalizedWindowId = Number(windowId || 0);
  const normalizedTabId = Number(tabId || 0);
  if (normalizedWindowId <= 0) {
    return false;
  }
  if (cmIsWorkspaceReady(normalizedWindowId, normalizedTabId)) {
    return true;
  }
  return new Promise((resolve) => {
    const waiter = {
      resolve,
      timerId: setTimeout(() => {
        const waiters = state.cmWorkspaceReadyWaitersByWindowId.get(normalizedWindowId);
        if (Array.isArray(waiters)) {
          state.cmWorkspaceReadyWaitersByWindowId.set(
            normalizedWindowId,
            waiters.filter((entry) => entry !== waiter)
          );
          if ((state.cmWorkspaceReadyWaitersByWindowId.get(normalizedWindowId) || []).length === 0) {
            state.cmWorkspaceReadyWaitersByWindowId.delete(normalizedWindowId);
          }
        }
        resolve(false);
      }, Math.max(500, Number(timeoutMs || 0) || 2500)),
    };
    const existingWaiters = state.cmWorkspaceReadyWaitersByWindowId.get(normalizedWindowId);
    if (Array.isArray(existingWaiters)) {
      existingWaiters.push(waiter);
    } else {
      state.cmWorkspaceReadyWaitersByWindowId.set(normalizedWindowId, [waiter]);
    }
  });
}

function cmUnbindWorkspaceTab(tabId) {
  const normalizedTabId = Number(tabId || 0);
  if (normalizedTabId > 0 && Number(state.cmWorkspaceActivityDebugTargetTabId || 0) === normalizedTabId) {
    state.cmWorkspaceActivityDebugTargetTabId = 0;
  }
  if (normalizedTabId > 0) {
    for (const [windowId, mappedTabId] of state.cmWorkspaceTabIdByWindowId.entries()) {
      if (Number(mappedTabId || 0) === normalizedTabId) {
        cmInvalidateWorkspaceReady(windowId, normalizedTabId);
        state.cmWorkspaceTabIdByWindowId.delete(windowId);
      }
    }
  }

  if (!normalizedTabId || Number(state.cmWorkspaceTabId || 0) === normalizedTabId) {
    cmInvalidateWorkspaceReady(state.cmWorkspaceWindowId, normalizedTabId);
    state.cmWorkspaceTabId = 0;
    state.cmWorkspaceWindowId = 0;
  }
}

function cmGetBoundWorkspaceTabId(windowId) {
  const normalizedWindowId = Number(windowId || 0);
  if (normalizedWindowId > 0) {
    const mapped = Number(state.cmWorkspaceTabIdByWindowId.get(normalizedWindowId) || 0);
    if (mapped > 0) {
      return mapped;
    }
  }
  return Number(state.cmWorkspaceTabId || 0);
}

function nextCmWorkspaceControllerStateVersion() {
  state.cmWorkspaceControllerStateVersion = Number(state.cmWorkspaceControllerStateVersion || 0) + 1;
  return state.cmWorkspaceControllerStateVersion;
}

function getCmControllerAuthPayload() {
  const accessToken = normalizeBearerTokenValue(getPreferredCmRequestAccessTokenCandidate());
  const tokenClaims = parseJwtPayload(accessToken) || {};
  const envGlobalCmAuth = getPassVaultCmGlobalAuthFromVault();
  const hints = resolveCmImsTokenHints(accessToken);
  return {
    accessToken,
    clientIds: uniquePreserveOrder([
      firstNonEmptyString([tokenClaims.client_id, tokenClaims.clientId]),
      getConfiguredUnderparImsClientId(),
      CM_IMS_PRIMARY_CLIENT_ID,
    ].filter(Boolean)),
    userId: firstNonEmptyString([
      hints.userId,
      tokenClaims.user_id,
      tokenClaims.userId,
      envGlobalCmAuth?.userId,
      state.loginData?.imsSession?.userId,
    ]),
    scope: firstNonEmptyString([
      tokenClaims.scope,
      envGlobalCmAuth?.scope,
      CM_IMS_CHECK_DEFAULT_SCOPE,
    ]),
  };
}

function buildCmWorkspaceControllerContextKey(
  programmerId = "",
  requestToken = state.premiumPanelRequestToken,
  environmentKey = getActiveAdobePassEnvironmentKey()
) {
  const normalizedEnvironmentKey =
    String(environmentKey || getActiveAdobePassEnvironmentKey() || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() ||
    DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const normalizedProgrammerId = String(programmerId || "").trim() || "no-programmer";
  const normalizedRequestToken = Math.max(0, Number(requestToken || 0));
  return `${normalizedEnvironmentKey}::${normalizedProgrammerId}::${normalizedRequestToken}`;
}

function cmGetControllerStatePayload(cmState) {
  const requestorIds = state.selectedRequestorId ? [String(state.selectedRequestorId)] : [];
  const mvpdIds = state.selectedMvpdId ? [String(state.selectedMvpdId)] : [];
  const profileHarvest = getCmProfileHarvestForProgrammer(cmState?.programmer || null);
  const profileHarvestList = getCmProfileHarvestListForProgrammer(cmState?.programmer || null);
  const adobePassEnvironment = {
    ...getActiveAdobePassEnvironment(),
  };
  const programmerId = String(cmState?.programmer?.programmerId || "");
  const premiumPanelRequestToken = Math.max(0, Number(state.premiumPanelRequestToken || 0));
  const tenantScope = resolveCmUsageTenantScopeValue(
    getCmPrimaryUsageTenantScopeFromState(cmState),
    cmState?.tenantScope,
    cmState?.cmService?.matchedTenants?.[0]?.tenantId,
    cmState?.cmService?.matchedTenants?.[0]?.tenantName,
    getCmTenantScopeForProgrammer(cmState?.programmer)
  );
  const workspaceContextKey = buildCmWorkspaceControllerContextKey(
    programmerId,
    premiumPanelRequestToken,
    adobePassEnvironment?.key
  );
  return {
    controllerOnline: Boolean(cmState?.section?.isConnected),
    slack: getUnderparWorkspaceSlackStatePayload(),
    cmAvailable: true,
    cmAvailabilityResolved: true,
    cmContainerVisible: true,
    programmerId,
    programmerName: String(cmState?.programmer?.programmerName || ""),
    programmerHydrationReady: isProgrammerWorkspaceHydrationReady(programmerId),
    adobePassEnvironment,
    adobePassEnvironmentKey: String(adobePassEnvironment?.key || "").trim(),
    tenantScope,
    requestorIds,
    mvpdIds,
    cmAuth: getCmControllerAuthPayload(),
    premiumPanelRequestToken,
    workspaceContextKey,
    controllerStateVersion: nextCmWorkspaceControllerStateVersion(),
    profileHarvest:
      profileHarvest && typeof profileHarvest === "object"
        ? {
            ...profileHarvest,
          }
        : null,
    profileHarvestList:
      profileHarvestList.length > 0
        ? profileHarvestList.map((item) => ({
            ...item,
          }))
        : [],
    updatedAt: Date.now(),
  };
}

function hasResolvedPremiumServiceSnapshotForCm(services = null) {
  return (
    services &&
    typeof services === "object" &&
    (Object.prototype.hasOwnProperty.call(services, "cm") ||
      Object.prototype.hasOwnProperty.call(services, "cmMvpd") ||
      Object.prototype.hasOwnProperty.call(services, "esm") ||
      Object.prototype.hasOwnProperty.call(services, "restV2") ||
      Object.prototype.hasOwnProperty.call(services, "degradation"))
  );
}

function cmGetSelectedControllerStatePayload(programmer = null, services = null, options = {}) {
  const resolvedProgrammer =
    programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
  // `services === null` means loading/unknown and must not fallback to cached CM service state.
  const resolvedServices = services && typeof services === "object" ? services : null;
  const controllerReason = String(options?.controllerReason || "").trim();
  const hasResolvedSnapshot = hasResolvedPremiumServiceSnapshotForCm(resolvedServices);

  let cmAvailable = null;
  if (hasResolvedSnapshot && Object.prototype.hasOwnProperty.call(resolvedServices, "cm")) {
    cmAvailable = shouldShowCmService(resolvedServices.cm);
  }
  let cmContainerVisible = null;
  if (options?.cmContainerVisible === true) {
    cmContainerVisible = true;
  } else if (options?.cmContainerVisible === false) {
    cmContainerVisible = false;
  } else if (hasResolvedSnapshot && Object.prototype.hasOwnProperty.call(resolvedServices, "cm")) {
    cmContainerVisible = shouldShowCmService(resolvedServices.cm);
  }
  if (cmContainerVisible === true) {
    cmAvailable = true;
  }
  const cmAvailabilityResolved =
    options?.cmAvailabilityResolved === true || options?.cmAvailabilityResolved === false
      ? options.cmAvailabilityResolved === true
      : hasResolvedSnapshot || cmContainerVisible === true || cmContainerVisible === false;

  const requestorIds = state.selectedRequestorId ? [String(state.selectedRequestorId)] : [];
  const mvpdIds = state.selectedMvpdId ? [String(state.selectedMvpdId)] : [];
  const profileHarvest = getCmProfileHarvestForProgrammer(resolvedProgrammer);
  const profileHarvestList = getCmProfileHarvestListForProgrammer(resolvedProgrammer);
  const adobePassEnvironment = {
    ...getActiveAdobePassEnvironment(),
  };
  const programmerId = String(resolvedProgrammer?.programmerId || "");
  const premiumPanelRequestToken = Math.max(0, Number(state.premiumPanelRequestToken || 0));
  const programmerHydrationReady =
    options?.programmerHydrationReady === true || options?.programmerHydrationReady === false
      ? options.programmerHydrationReady === true
      : isProgrammerWorkspaceHydrationReady(programmerId);
  const workspaceContextKey = buildCmWorkspaceControllerContextKey(
    programmerId,
    premiumPanelRequestToken,
    adobePassEnvironment?.key
  );
  return {
    controllerOnline: false,
    slack: getUnderparWorkspaceSlackStatePayload(),
    cmAvailable,
    cmAvailabilityResolved,
    cmContainerVisible,
    programmerId,
    programmerName: String(resolvedProgrammer?.programmerName || ""),
    programmerHydrationReady,
    adobePassEnvironment,
    adobePassEnvironmentKey: String(adobePassEnvironment?.key || "").trim(),
    tenantScope: getCmTenantScopeForProgrammer(resolvedProgrammer),
    requestorIds,
    mvpdIds,
    cmAuth: getCmControllerAuthPayload(),
    premiumPanelRequestToken,
    workspaceContextKey,
    controllerStateVersion: nextCmWorkspaceControllerStateVersion(),
    profileHarvest:
      profileHarvest && typeof profileHarvest === "object"
        ? {
            ...profileHarvest,
          }
        : null,
    profileHarvestList:
      profileHarvestList.length > 0
        ? profileHarvestList.map((item) => ({
            ...item,
          }))
        : [],
    controllerReason,
    updatedAt: Date.now(),
  };
}

async function cmSendWorkspaceMessage(event, payload = {}, options = {}) {
  const targetWindowId = Number(options.targetWindowId || 0);
  try {
    const message = {
      type: CM_MESSAGE_TYPE,
      channel: "workspace-event",
      event: String(event || ""),
      payload,
    };
    if (targetWindowId > 0) {
      message.targetWindowId = targetWindowId;
    }
    await chrome.runtime.sendMessage(message);
  } catch {
    // Ignore when no CM workspace listener is active.
  }
}

function cmBroadcastSelectedControllerState(programmer = null, services = null, targetWindowId = 0, options = {}) {
  const resolvedWindowId = Number(targetWindowId || 0) || Number(state.cmWorkspaceWindowId || 0);
  void cmSendWorkspaceMessage("controller-state", cmGetSelectedControllerStatePayload(programmer, services, options), {
    targetWindowId: resolvedWindowId,
  });
}

function cmBroadcastControllerState(cmState, targetWindowId = 0) {
  if (!cmState) {
    return;
  }
  const resolvedWindowId =
    Number(targetWindowId || 0) || Number(cmState.controllerWindowId || 0) || Number(state.cmWorkspaceWindowId || 0);
  void cmSendWorkspaceMessage("controller-state", cmGetControllerStatePayload(cmState), {
    targetWindowId: resolvedWindowId,
  });
}

async function cmEnsureWorkspaceTab(options = {}) {
  ensureCmRuntimeListener();
  ensureCmWorkspaceTabWatcher();
  const shouldActivate = options.activate !== false;
  const requestedWindowId = Number(options.windowId || 0);
  const targetWindowId = requestedWindowId > 0 ? requestedWindowId : await esmWorkspaceGetCurrentWindowId();
  const useWindowFilter = targetWindowId > 0;
  let workspaceTab = null;
  let createdWorkspaceTab = false;
  let reusedReadyCandidate = false;

  const boundTabId = cmGetBoundWorkspaceTabId(targetWindowId);
  if (boundTabId > 0) {
    try {
      const existing = await chrome.tabs.get(boundTabId);
      if (cmIsWorkspaceTab(existing) && (!useWindowFilter || Number(existing.windowId || 0) === targetWindowId)) {
        workspaceTab = existing;
        reusedReadyCandidate = String(existing?.status || "").trim().toLowerCase() === "complete";
      }
    } catch {
      cmUnbindWorkspaceTab(boundTabId);
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    try {
      const allTabs = await chrome.tabs.query(useWindowFilter ? { windowId: targetWindowId } : { currentWindow: true });
      workspaceTab = allTabs.find((tab) => cmIsWorkspaceTab(tab)) || null;
      reusedReadyCandidate = String(workspaceTab?.status || "").trim().toLowerCase() === "complete";
    } catch {
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    workspaceTab = await chrome.tabs.create({
      url: cmGetWorkspaceUrl(),
      active: shouldActivate,
      ...(useWindowFilter ? { windowId: targetWindowId } : {}),
    });
    createdWorkspaceTab = Boolean(workspaceTab?.id);
  } else if (shouldActivate && workspaceTab.id) {
    try {
      workspaceTab = await chrome.tabs.update(workspaceTab.id, { active: true });
      if (Number(workspaceTab?.windowId || 0) > 0) {
        await chrome.windows.update(Number(workspaceTab.windowId), { focused: true });
      }
    } catch {
      // Ignore activation failures.
    }
  }

  cmBindWorkspaceTab(workspaceTab?.windowId, workspaceTab?.id);
  if (createdWorkspaceTab) {
    cmInvalidateWorkspaceReady(workspaceTab?.windowId, workspaceTab?.id);
  } else if (reusedReadyCandidate || cmIsWorkspaceReady(workspaceTab?.windowId, workspaceTab?.id)) {
    cmMarkWorkspaceReady(workspaceTab?.windowId, workspaceTab?.id);
  }
  return workspaceTab;
}

function getActiveCmWorkspaceActivityDebugFlowId() {
  return String(state.cmWorkspaceActivityDebugFlowId || "").trim();
}

function buildCmWorkspaceDebugContext(cmState = null) {
  const selections = getGlobalRequestorMvpdSelections();
  const activeCmState = cmState || getActiveCmState() || null;
  const programmer = activeCmState?.programmer || resolveSelectedProgrammer() || null;
  const tenantScope = resolveCmUsageTenantScopeValue(
    getCmPrimaryUsageTenantScopeFromState(activeCmState),
    activeCmState?.tenantScope,
    activeCmState?.cmService?.matchedTenants?.[0]?.tenantId,
    activeCmState?.cmService?.matchedTenants?.[0]?.tenantName,
    getCmTenantScopeForProgrammer(programmer)
  );
  return {
    serviceType: "cm",
    programmerId: String(programmer?.programmerId || ""),
    programmerName: String(programmer?.programmerName || ""),
    tenantScope,
    requestorId: String(selections.requestorIds[0] || ""),
    mvpd: String(selections.mvpdIds[0] || ""),
    requestorIds: selections.requestorIds.slice(0, 24),
    mvpdIds: selections.mvpdIds.slice(0, 24),
  };
}

async function resolveCmWorkspaceDebugTargetTabId(options = {}) {
  const preferredWindowId = Number(options.preferredWindowId || 0);
  const fallbackTabId = Number(options.fallbackTabId || 0);

  const candidateTabIds = [];
  const pushCandidateTabId = (tabId) => {
    const normalizedTabId = Number(tabId || 0);
    if (!Number.isFinite(normalizedTabId) || normalizedTabId <= 0) {
      return;
    }
    if (!candidateTabIds.includes(normalizedTabId)) {
      candidateTabIds.push(normalizedTabId);
    }
  };

  pushCandidateTabId(state.cmWorkspaceActivityDebugTargetTabId);
  pushCandidateTabId(fallbackTabId);
  pushCandidateTabId(cmGetBoundWorkspaceTabId(preferredWindowId));
  pushCandidateTabId(state.cmWorkspaceTabId);
  pushCandidateTabId(state.restV2LastLaunchTabId);
  pushCandidateTabId(state.lastDebuggableWebTabId);

  const preferredWindowTab = await getEsmWorkspaceActiveTabForWindow(preferredWindowId);
  if (preferredWindowTab) {
    pushCandidateTabId(preferredWindowTab.id);
  }

  const activeTab = await getCurrentActiveTab();
  if (activeTab) {
    pushCandidateTabId(activeTab.id);
  }

  for (const candidateTabId of candidateTabIds) {
    const tab = await getEsmWorkspaceDebuggableTabById(candidateTabId);
    if (tab) {
      state.cmWorkspaceActivityDebugTargetTabId = Number(tab.id || 0);
      return Number(tab.id || 0);
    }
  }

  const fallbackTab = await findBestDebuggableWebTab(preferredWindowId);
  if (fallbackTab) {
    state.cmWorkspaceActivityDebugTargetTabId = Number(fallbackTab.id || 0);
    return Number(fallbackTab.id || 0);
  }

  state.cmWorkspaceActivityDebugTargetTabId = 0;
  return 0;
}

async function ensureCmWorkspaceActivityDebugFlow(options = {}) {
  const activePremiumFlowId = String(getActivePremiumDebugFlowId() || "").trim();
  if (activePremiumFlowId) {
    return activePremiumFlowId;
  }

  const preferredWindowId = Number(options.preferredWindowId || 0);
  const fallbackTabId = Number(options.fallbackTabId || 0);
  const existingFlowId = getActiveCmWorkspaceActivityDebugFlowId();

  if (existingFlowId) {
    const previousTargetTabId = Number(state.cmWorkspaceActivityDebugTargetTabId || 0);
    const targetTabId = await resolveCmWorkspaceDebugTargetTabId({
      preferredWindowId,
      fallbackTabId,
    });
    if (targetTabId > 0 && targetTabId !== previousTargetTabId) {
      const context = buildCmWorkspaceDebugContext(getActiveCmState());
      const bound = await bindRestV2DebugFlowToTab(existingFlowId, targetTabId, {
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        serviceType: "cm",
        tenantScope: String(context.tenantScope || ""),
        eventsOnly: true,
        captureNetwork: false,
      });
      if (bound) {
        state.cmWorkspaceActivityDebugTargetTabId = targetTabId;
      }
    }
    return existingFlowId;
  }

  if (state.cmWorkspaceActivityDebugFlowPromise) {
    return state.cmWorkspaceActivityDebugFlowPromise;
  }

  const createPromise = (async () => {
    const context = buildCmWorkspaceDebugContext(getActiveCmState());
    const flowId = await startRestV2DebugFlow(context, "cm-activity");
    if (!flowId) {
      return "";
    }

    state.cmWorkspaceActivityDebugFlowId = flowId;

    const targetTabId = await resolveCmWorkspaceDebugTargetTabId({
      preferredWindowId,
      fallbackTabId,
    });
    if (targetTabId > 0) {
      const bound = await bindRestV2DebugFlowToTab(flowId, targetTabId, {
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        serviceType: "cm",
        tenantScope: String(context.tenantScope || ""),
        eventsOnly: true,
        captureNetwork: false,
      });
      if (bound) {
        state.cmWorkspaceActivityDebugTargetTabId = targetTabId;
      }
    }

    emitRestV2DebugEvent(flowId, {
      source: "extension",
      service: "cm",
      phase: "activity-flow-start",
      trigger: String(options.reason || "cm-activity"),
      programmerId: context.programmerId,
      tenantScope: String(context.tenantScope || ""),
      requestorId: context.requestorId,
      mvpd: context.mvpd,
      tabId: Number(state.cmWorkspaceActivityDebugTargetTabId || 0),
    });

    return flowId;
  })()
    .catch(() => "")
    .finally(() => {
      state.cmWorkspaceActivityDebugFlowPromise = null;
    });

  state.cmWorkspaceActivityDebugFlowPromise = createPromise;
  return createPromise;
}

function clearCmWorkspaceActivityDebugFlow(reason = "state-reset", options = {}) {
  const normalizedReason = String(reason || "state-reset").trim() || "state-reset";
  const flowId = getActiveCmWorkspaceActivityDebugFlowId();
  const shouldStopFlow = options?.stopFlow === true;

  if (flowId && shouldStopFlow) {
    void stopRestV2DebugFlowAndSnapshot(flowId, normalizedReason);
  }

  state.cmWorkspaceActivityDebugFlowId = "";
  state.cmWorkspaceActivityDebugFlowPromise = null;
  state.cmWorkspaceActivityDebugTargetTabId = 0;
  state.cmWorkspacePendingDebugEvents = [];
  state.cmWorkspacePendingDebugFlushPromise = null;
}

function cmBuildRecordId(kind, tenantId, entityId, index = 0) {
  return [String(kind || "cm"), String(tenantId || "tenant"), String(entityId || `item-${index + 1}`)]
    .map((value) => value.replace(/[^\w\-.:]+/g, "_"))
    .join(":");
}

function getCmProfileHarvestForProgrammer(programmer = null) {
  const programmerId = String(programmer?.programmerId || programmer || "").trim();
  if (!programmerId) {
    return null;
  }
  const context = {
    programmerId,
    requestorId: String(state.selectedRequestorId || "").trim(),
    mvpd: String(state.selectedMvpdId || "").trim(),
  };
  return getRestV2ProfileHarvestForContext(context) || getRestV2ProfileHarvestBucketForProgrammer(programmerId)[0] || null;
}

function getCmProfileHarvestListForProgrammer(programmer = null) {
  const programmerId = String(programmer?.programmerId || programmer || "").trim();
  if (!programmerId) {
    return [];
  }
  return getRestV2ProfileHarvestBucketForProgrammer(programmerId);
}

function normalizeCmCredentialValue(value) {
  if (value == null) {
    return "";
  }
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return String(value).trim();
  }
  if (typeof value === "object") {
    if (typeof value.value === "string" || typeof value.value === "number" || typeof value.value === "boolean") {
      return String(value.value).trim();
    }
    if (typeof value.raw === "string" || typeof value.raw === "number" || typeof value.raw === "boolean") {
      return String(value.raw).trim();
    }
  }
  return "";
}

function findCmValueByCandidateKeys(source, keyCandidates = [], maxDepth = 4) {
  const targetKeys = new Set((Array.isArray(keyCandidates) ? keyCandidates : []).map((key) => String(key || "").trim().toLowerCase()).filter(Boolean));
  if (targetKeys.size === 0 || !source || typeof source !== "object") {
    return "";
  }

  const stack = [{ node: source, depth: 0 }];
  const seen = new Set();
  while (stack.length > 0) {
    const current = stack.pop();
    const node = current?.node;
    const depth = Number(current?.depth || 0);
    if (!node || typeof node !== "object" || depth > maxDepth || seen.has(node)) {
      continue;
    }
    seen.add(node);

    if (Array.isArray(node)) {
      node.forEach((item) => {
        if (item && typeof item === "object") {
          stack.push({ node: item, depth: depth + 1 });
        }
      });
      continue;
    }

    for (const [rawKey, rawValue] of Object.entries(node)) {
      const normalizedKey = String(rawKey || "").trim().toLowerCase();
      if (targetKeys.has(normalizedKey)) {
        const value = normalizeCmCredentialValue(rawValue);
        if (value) {
          return value;
        }
      }
      if (rawValue && typeof rawValue === "object") {
        stack.push({ node: rawValue, depth: depth + 1 });
      }
    }
  }

  return "";
}

function cmExtractCredentialHintsFromBundles(bundles = []) {
  const hints = [];
  const seen = new Set();

  (Array.isArray(bundles) ? bundles : []).forEach((bundle) => {
    const tenantId = String(bundle?.tenant?.tenantId || "").trim();
    const tenantName = String(bundle?.tenant?.tenantName || tenantId).trim();
    const rows = Array.isArray(bundle?.applications?.rows) ? bundle.applications.rows : [];
    rows.forEach((row) => {
      if (!row || typeof row !== "object") {
        return;
      }
      const raw = row.raw && typeof row.raw === "object" ? row.raw : row;
      const applicationId = firstNonEmptyString([
        row.entityId,
        row.consoleId,
        raw.id,
        raw.applicationId,
        raw.application_id,
        raw.appId,
        raw.app_id,
      ]);
      const applicationName = firstNonEmptyString([
        row.name,
        raw.name,
        raw.displayName,
        raw.display_name,
        applicationId,
      ]);
      const username = firstNonEmptyString([
        findCmValueByCandidateKeys(raw, ["basicauthusername", "username", "clientid", "client_id", "authuser", "auth_user"]),
        applicationId,
      ]);
      const password = firstNonEmptyString([
        findCmValueByCandidateKeys(raw, [
          "basicauthpassword",
          "password",
          "clientsecret",
          "client_secret",
          "secret",
          "authpass",
          "auth_pass",
        ]),
      ]);
      if (!username) {
        return;
      }

      const dedupeKey = `${tenantId}|${username}`.toLowerCase();
      if (seen.has(dedupeKey)) {
        return;
      }
      seen.add(dedupeKey);

      hints.push({
        tenantId,
        tenantName,
        applicationId: String(applicationId || ""),
        applicationName: String(applicationName || username),
        username: String(username || ""),
        password: String(password || ""),
      });
    });
  });

  return hints;
}

function cmBuildCredentialHintRecords(hints = [], programmer = null) {
  return (Array.isArray(hints) ? hints : [])
    .map((hint, index) => {
      const username = String(hint?.username || "").trim();
      if (!username) {
        return null;
      }
      const tenantId = String(hint?.tenantId || programmer?.programmerId || "cm").trim();
      const applicationId = String(hint?.applicationId || username).trim();
      const applicationName = String(hint?.applicationName || applicationId || username).trim();
      const hasPassword = Boolean(String(hint?.password || "").trim());
      const payload = {
        mediaCompany: String(programmer?.programmerName || programmer?.programmerId || "").trim(),
        tenantId: String(hint?.tenantId || "").trim(),
        tenantName: String(hint?.tenantName || "").trim(),
        applicationId,
        applicationName,
        basicAuthUsername: username,
        basicAuthPassword: hasPassword ? String(hint?.password || "").trim() : "(not exposed by current CM APIs)",
        passwordAvailableFromApi: hasPassword ? "Yes" : "No",
      };
      return {
        cardId: cmBuildRecordId("credential", tenantId || "cm", applicationId || username, index),
        kind: "credential",
        title: applicationName,
        subtitle: `${String(hint?.tenantName || hint?.tenantId || "tenant")} | Basic user: ${username}`,
        endpointUrl: "",
        requestUrl: "",
        payload,
        columns: cmColumnsFromPayload(payload),
        tenantId: tenantId || "cm",
        tenantName: String(hint?.tenantName || hint?.tenantId || "CM"),
      };
    })
    .filter(Boolean);
}

function cmCollectCmV2ContextDefaults(programmer = null, credentialHints = []) {
  const profileHarvestList = getCmProfileHarvestListForProgrammer(programmer);
  const profileHarvest = getCmProfileHarvestForProgrammer(programmer) || profileHarvestList[0] || null;
  const aggregatedCandidates = collectRestV2HarvestCandidateValues(profileHarvestList);
  const hints = Array.isArray(credentialHints) ? credentialHints : [];
  const primaryCredentialHint =
    hints.find((hint) => String(hint?.password || "").trim()) || hints.find((hint) => String(hint?.username || "").trim()) || null;
  const harvestIdpCandidates = dedupeRestV2CandidateStrings([
    ...(Array.isArray(profileHarvest?.idpCandidates) ? profileHarvest.idpCandidates : []),
    ...aggregatedCandidates.idpCandidates,
  ]);
  const harvestSubjectCandidates = dedupeRestV2CandidateStrings([
    ...(Array.isArray(profileHarvest?.subjectCandidates) ? profileHarvest.subjectCandidates : []),
    ...aggregatedCandidates.subjectCandidates,
  ]);
  const harvestSessionCandidates = dedupeRestV2CandidateStrings([
    ...(Array.isArray(profileHarvest?.sessionCandidates) ? profileHarvest.sessionCandidates : []),
    ...aggregatedCandidates.sessionCandidates,
  ]);
  const contextDefaults = {
    baseUrl: CM_V2_API_BASE_DEFAULT,
    idp: firstNonEmptyString([profileHarvest?.mvpd, ...harvestIdpCandidates, state.selectedMvpdId]),
    subject: firstNonEmptyString([
      profileHarvest?.subject,
      profileHarvest?.upstreamUserId,
      profileHarvest?.userId,
      ...harvestSubjectCandidates,
      state.selectedRequestorId,
    ]),
    session: firstNonEmptyString([profileHarvest?.sessionId, ...harvestSessionCandidates]),
    xTerminate: "",
    authUser: String(primaryCredentialHint?.username || "").trim(),
    authPass: String(primaryCredentialHint?.password || "").trim(),
    mediaCompany: String(programmer?.programmerName || programmer?.mediaCompanyName || "").trim(),
    programmerId: String(programmer?.programmerId || "").trim(),
    profileHarvest: profileHarvest && typeof profileHarvest === "object" ? { ...profileHarvest } : null,
    profileHarvestList: profileHarvestList.map((harvest) => ({ ...harvest })),
  };
  return contextDefaults;
}

function cmBuildCmV2OperationRecords(programmer = null, credentialHints = []) {
  const contextDefaults = cmCollectCmV2ContextDefaults(programmer, credentialHints);
  return CM_V2_OPERATION_DEFINITIONS.map((definition, index) => {
    const method = String(definition?.method || "GET").toUpperCase();
    const pathTemplate = String(definition?.pathTemplate || "").trim();
    const opKey = String(definition?.key || `operation-${index + 1}`).trim() || `operation-${index + 1}`;
    return {
      cardId: cmBuildRecordId("cmv2", contextDefaults.programmerId || "cmv2", opKey, index),
      kind: "cmv2-op",
      title: String(definition?.label || `${method} ${pathTemplate}`),
      subtitle: `${method} ${pathTemplate}`,
      endpointUrl: normalizeCmUrl(`${contextDefaults.baseUrl}${pathTemplate}`) || `${contextDefaults.baseUrl}${pathTemplate}`,
      requestUrl: normalizeCmUrl(`${contextDefaults.baseUrl}${pathTemplate}`) || `${contextDefaults.baseUrl}${pathTemplate}`,
      payload: {
        operation: {
          key: opKey,
          label: String(definition?.label || `${method} ${pathTemplate}`),
          method,
          pathTemplate,
          parameters: Array.isArray(definition?.parameters) ? definition.parameters.map((item) => ({ ...item })) : [],
          security: "basicAuth",
        },
        formDefaults: { ...contextDefaults },
        profileHarvest:
          contextDefaults.profileHarvest && typeof contextDefaults.profileHarvest === "object"
            ? { ...contextDefaults.profileHarvest }
            : null,
        profileHarvestList: Array.isArray(contextDefaults.profileHarvestList)
          ? contextDefaults.profileHarvestList.map((harvest) => ({ ...harvest }))
          : [],
      },
      columns: [],
      tenantId: contextDefaults.programmerId || "cmv2",
      tenantName: contextDefaults.mediaCompany || contextDefaults.programmerId || "CM V2",
    };
  });
}

function cmBuildCrossReferenceLabel(requestorId = "", mvpd = "", mvpdMeta = null) {
  return (
    formatRestV2RequestorMvpdDisplay(String(requestorId || "").trim(), String(mvpd || "").trim(), mvpdMeta, {
      separator: " x ",
    }) ||
    firstNonEmptyString([String(requestorId || "").trim(), String(mvpd || "").trim(), "Cross Reference"])
  );
}

function cmBuildCrossReferenceRowMeta(context = null, options = {}) {
  const source = context && typeof context === "object" ? context : {};
  const override = options && typeof options === "object" ? options : {};
  return {
    MediaCompany: String(firstNonEmptyString([override.programmerName, source.programmerName, source.programmerId]) || "").trim(),
    Environment: String(firstNonEmptyString([override.environmentKey, source.environmentKey]) || "").trim(),
    CmTenantScope: String(firstNonEmptyString([override.tenantScope, source.tenantScope]) || "").trim(),
    CmMatchedTenantCount: Math.max(
      0,
      Number(
        Object.prototype.hasOwnProperty.call(override, "matchedTenantCount")
          ? override.matchedTenantCount
          : Array.isArray(source.matchedTenants)
            ? source.matchedTenants.length
            : 0
      ) || 0
    ),
    CmMatchedTenants: Array.isArray(source.matchedTenants)
      ? source.matchedTenants
          .map((tenant) => String(tenant?.tenantName || tenant?.tenantId || "").trim())
          .filter(Boolean)
          .join(", ")
      : "",
    RestV2App: String(firstNonEmptyString([override.restV2AppName, source.restV2App?.appName, source.restV2App?.guid]) || "").trim(),
    RestV2AppGuid: String(firstNonEmptyString([override.restV2AppGuid, source.restV2App?.guid]) || "").trim(),
    EsmApp: String(firstNonEmptyString([override.esmAppName, source.esmApp?.appName, source.esmApp?.guid]) || "").trim(),
    EsmAppGuid: String(firstNonEmptyString([override.esmAppGuid, source.esmApp?.guid]) || "").trim(),
  };
}

function cmResolveCrossReferenceContext(programmer = null, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const services =
    options?.services ||
    getCurrentPremiumAppsSnapshot(programmerId) ||
    getRuntimePremiumServicesSeed(programmerId) ||
    null;
  const cmService =
    options?.cmService ||
    services?.cmMvpd ||
    services?.cm ||
    state.cmServiceByProgrammerId.get(programmerId) ||
    null;
  const matchedTenants = Array.isArray(cmService?.matchedTenants) ? cmService.matchedTenants.filter(Boolean) : [];
  const profileHarvestList = getCmProfileHarvestListForProgrammer(programmer);
  const profileHarvest = getCmProfileHarvestForProgrammer(programmer) || profileHarvestList[0] || null;
  const requestorId = String(
    firstNonEmptyString([
      options?.requestorId,
      state.selectedRequestorId,
      profileHarvest?.requestorId,
      profileHarvest?.serviceProviderId,
      cmService?.requestorId,
    ]) || ""
  ).trim();
  const mvpd = String(
    firstNonEmptyString([
      options?.mvpdId,
      state.selectedMvpdId,
      profileHarvest?.mvpd,
      cmService?.mvpdId,
      cmService?.mvpd,
    ]) || ""
  ).trim();
  const mvpdMeta = requestorId && mvpd ? getRestV2MvpdMeta(requestorId, mvpd) : null;
  const mvpdLabel = mvpd
    ? firstNonEmptyString([getRestV2MvpdPickerLabel(requestorId, mvpd, mvpdMeta), mvpd])
    : "";
  const tenantScope = resolveCmUsageTenantScopeValue(
    options?.tenantScope,
    cmService?.matchedTenants?.[0]?.tenantId,
    cmService?.matchedTenants?.[0]?.tenantName,
    getCmTenantScopeForProgrammer(programmer)
  );
  const restV2AppCandidates = collectRestV2AppCandidatesFromPremiumApps(services);
  const restV2App =
    selectPreferredRestV2AppForRequestor(restV2AppCandidates, requestorId, programmerId) || services?.restV2 || null;
  const esmCandidates = collectEsmAppCandidatesFromPremiumApps(services, services?.esm || null);
  const esmApp = selectPreferredEsmAppForRequestor(esmCandidates, requestorId, programmerId) || services?.esm || null;
  const environment = getActiveAdobePassEnvironment();
  return {
    programmerId,
    programmerName: String(
      firstNonEmptyString([programmer?.programmerName, programmer?.mediaCompanyName, programmerId]) || ""
    ).trim(),
    services,
    cmService,
    matchedTenants,
    tenantScope,
    profileHarvest,
    profileHarvestList,
    preauthorizeHistory: getRestV2PreauthorizeHistoryForProgrammer(programmerId),
    requestorId,
    mvpd,
    mvpdMeta,
    mvpdLabel,
    restV2App,
    esmApp,
    environmentKey: String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key,
    environmentLabel: String(
      firstNonEmptyString([environment?.label, environment?.shortCode, environment?.key, DEFAULT_ADOBEPASS_ENVIRONMENT.key]) || ""
    ).trim(),
  };
}

function cmBuildRestV2ProfileCorrelationRecords(context = null) {
  const source = context && typeof context === "object" ? context : {};
  const profileHarvestList = Array.isArray(source.profileHarvestList) ? source.profileHarvestList : [];
  if (profileHarvestList.length === 0) {
    return [];
  }

  return profileHarvestList.map((profileHarvest, recordIndex) => {
    const capturedAtLabel = profileHarvest.harvestedAt
      ? new Date(Number(profileHarvest.harvestedAt || 0)).toLocaleString()
      : "Unknown";
    const profileCheck =
      profileHarvest.profileCheck && typeof profileHarvest.profileCheck === "object" ? profileHarvest.profileCheck : null;
    const profileCheckStatus = profileCheck
      ? profileCheck.error
        ? `ERROR (${profileCheck.error})`
        : profileCheck.ok
          ? Number(profileCheck.profileCount || 0) > 0
            ? "SUCCESS (profiles returned)"
            : "NO ACTIVE PROFILE (empty profiles)"
          : `ERROR (HTTP ${Number(profileCheck.status || 0)} ${String(profileCheck.statusText || "").trim()})`
      : "Unknown";
    const summaryRowsSource = Array.isArray(profileHarvest.profileSummaries) ? profileHarvest.profileSummaries : [];
    const rowMeta = cmBuildCrossReferenceRowMeta(source);
    const summaryRows =
      summaryRowsSource.length > 0
        ? summaryRowsSource.map((summary, index) => ({
            Row: index + 1,
            RequestorId: String(profileHarvest.requestorId || "").trim(),
            ServiceProviderId: String(profileHarvest.serviceProviderId || "").trim(),
            ProfileCheckOutcome: String(profileHarvest.profileCheckOutcome || "").trim(),
            ProfileCheckStatus: profileCheckStatus,
            ProfileCheckHttpStatus: profileCheck ? Number(profileCheck.status || 0) : 0,
            ProfileCheckHttpText: profileCheck ? String(profileCheck.statusText || "").trim() : "",
            ProfileCheckError: profileCheck ? String(profileCheck.error || "").trim() : "",
            ProfileCheckResponsePreview: profileCheck ? String(profileCheck.responsePreview || "").trim() : "",
            ProfileCount: Number(profileHarvest.profileCount || profileCheck?.profileCount || 0),
            ProfileKeys: Array.isArray(profileHarvest.profileKeys) ? profileHarvest.profileKeys.join(", ") : "",
            HarvestedAt: capturedAtLabel,
            ProfileUrl: String(profileHarvest.profileUrl || "").trim(),
            ProfileKey: String(summary?.profileKey || "").trim(),
            Mvpd: String(summary?.mvpd || profileHarvest.mvpd || "").trim(),
            Subject: String(summary?.subject || profileHarvest.subject || "").trim(),
            UpstreamUserId: String(summary?.upstreamUserId || profileHarvest.upstreamUserId || "").trim(),
            UserId: String(summary?.userId || profileHarvest.userId || "").trim(),
            SessionId: String(summary?.sessionId || profileHarvest.sessionId || "").trim(),
            IdpCandidates: Array.isArray(summary?.idpCandidates) ? summary.idpCandidates.join(", ") : "",
            SubjectCandidates: Array.isArray(summary?.subjectCandidates) ? summary.subjectCandidates.join(", ") : "",
            SessionCandidates: Array.isArray(summary?.sessionCandidates) ? summary.sessionCandidates.join(", ") : "",
            NotBeforeMs: Number(summary?.notBeforeMs || 0),
            NotAfterMs: Number(summary?.notAfterMs || 0),
            ProfileAttributesJson: stringifyJsonForDisplay(summary?.attributes),
            ProfileScalarFieldsJson: stringifyJsonForDisplay(summary?.scalarFields),
            ProfileRawJson: stringifyJsonForDisplay(summary?.rawProfile),
            ProfileResponsePayloadJson: stringifyJsonForDisplay(profileHarvest.profileResponsePayload),
            ...rowMeta,
          }))
        : [
            {
              Row: 1,
              RequestorId: String(profileHarvest.requestorId || "").trim(),
              ServiceProviderId: String(profileHarvest.serviceProviderId || "").trim(),
              ProfileCheckOutcome: String(profileHarvest.profileCheckOutcome || "").trim(),
              ProfileCheckStatus: profileCheckStatus,
              ProfileCheckHttpStatus: profileCheck ? Number(profileCheck.status || 0) : 0,
              ProfileCheckHttpText: profileCheck ? String(profileCheck.statusText || "").trim() : "",
              ProfileCheckError: profileCheck ? String(profileCheck.error || "").trim() : "",
              ProfileCheckResponsePreview: profileCheck ? String(profileCheck.responsePreview || "").trim() : "",
              ProfileCount: Number(profileHarvest.profileCount || profileCheck?.profileCount || 0),
              ProfileKeys: Array.isArray(profileHarvest.profileKeys) ? profileHarvest.profileKeys.join(", ") : "",
              HarvestedAt: capturedAtLabel,
              ProfileUrl: String(profileHarvest.profileUrl || "").trim(),
              ProfileKey: String(profileHarvest.profileKey || "").trim(),
              Mvpd: String(profileHarvest.mvpd || "").trim(),
              Subject: String(profileHarvest.subject || "").trim(),
              UpstreamUserId: String(profileHarvest.upstreamUserId || "").trim(),
              UserId: String(profileHarvest.userId || "").trim(),
              SessionId: String(profileHarvest.sessionId || "").trim(),
              IdpCandidates: Array.isArray(profileHarvest.idpCandidates) ? profileHarvest.idpCandidates.join(", ") : "",
              SubjectCandidates: Array.isArray(profileHarvest.subjectCandidates) ? profileHarvest.subjectCandidates.join(", ") : "",
              SessionCandidates: Array.isArray(profileHarvest.sessionCandidates) ? profileHarvest.sessionCandidates.join(", ") : "",
              NotBeforeMs: Number(profileHarvest.notBeforeMs || 0),
              NotAfterMs: Number(profileHarvest.notAfterMs || 0),
              ProfileAttributesJson: stringifyJsonForDisplay(profileHarvest.profileAttributes),
              ProfileScalarFieldsJson: stringifyJsonForDisplay(profileHarvest.profileScalarFields),
              ProfileRawJson: stringifyJsonForDisplay(profileHarvest.profile),
              ProfileResponsePayloadJson: stringifyJsonForDisplay(profileHarvest.profileResponsePayload),
              ...rowMeta,
            },
          ];
    const payload = {
      mediaCompany: source.programmerName,
      requestorId: String(profileHarvest.requestorId || "").trim(),
      serviceProviderId: String(profileHarvest.serviceProviderId || "").trim(),
      mvpd: String(profileHarvest.mvpd || "").trim(),
      mvpdLabel: String(
        firstNonEmptyString([
          source.requestorId &&
          String(profileHarvest.requestorId || "").trim().toLowerCase() === String(source.requestorId || "").trim().toLowerCase()
            ? source.mvpdLabel
            : "",
          profileHarvest?.mvpdName,
          profileHarvest?.mvpd,
        ]) || ""
      ).trim(),
      profileCheckOutcome: String(profileHarvest.profileCheckOutcome || "").trim(),
      profileCheckStatus,
      profileCount: Number(profileHarvest.profileCount || profileCheck?.profileCount || 0),
      profileKeys: Array.isArray(profileHarvest.profileKeys) ? profileHarvest.profileKeys.join(", ") : "",
      selectedProfileFound: profileHarvest.selectedProfileFound === true ? "Yes" : "No",
      profileUrl: String(profileHarvest.profileUrl || "").trim(),
      items: summaryRows,
      harvestedAt: capturedAtLabel,
      ...rowMeta,
    };

    const correlationKey =
      buildRestV2ProfileHarvestBucketKey(profileHarvest) ||
      `${String(profileHarvest.requestorId || "requestor")}_${String(profileHarvest.mvpd || "mvpd")}_${recordIndex + 1}`;
    const rowMvpdMeta = String(profileHarvest?.mvpdName || "").trim()
      ? {
          id: String(profileHarvest.mvpd || "").trim(),
          name: String(profileHarvest.mvpdName || "").trim(),
        }
      : String(source.mvpd || "").trim() &&
          String(payload.requestorId || "").trim().toLowerCase() === String(source.requestorId || "").trim().toLowerCase()
        ? source.mvpdMeta
        : null;
    return {
      cardId: cmBuildRecordId(
        "restv2-profile-xref",
        String(profileHarvest.programmerId || source.programmerId || "cm"),
        correlationKey,
        recordIndex
      ),
      kind: "restv2-profile-xref",
      title: "MVPD Authenticated Profile",
      subtitle: `${cmBuildCrossReferenceLabel(String(payload.requestorId || "").trim(), String(payload.mvpd || "").trim(), rowMvpdMeta)} | ${profileCheckStatus} | ${capturedAtLabel}`,
      endpointUrl: "",
      requestUrl: "",
      payload,
      columns: cmColumnsFromPayload(payload),
      tenantId: String(profileHarvest.programmerId || source.programmerId || ""),
      tenantName: String(source.programmerName || profileHarvest.programmerId || "CM"),
      lastModified: "",
    };
  });
}

function cmBuildRestV2PreauthzCorrelationRecords(context = null) {
  const source = context && typeof context === "object" ? context : {};
  const entries = Array.isArray(source.preauthorizeHistory) ? source.preauthorizeHistory.slice(0, 8) : [];
  if (entries.length === 0) {
    return [];
  }

  return entries.map((entry, recordIndex) => {
    const requestorId = String(entry?.requestorId || entry?.serviceProviderId || source.requestorId || "").trim();
    const mvpd = String(entry?.mvpd || source.mvpd || "").trim();
    const mvpdMeta = requestorId && mvpd ? getRestV2MvpdMeta(requestorId, mvpd) || source.mvpdMeta : source.mvpdMeta;
    const checkedAtLabel = String(firstNonEmptyString([entry?.checkedAtLabel, formatTimestampLabel(entry?.checkedAt)]) || "Unknown").trim();
    const verdict =
      entry?.allRequestedPermitted === true ? "YES" : entry?.allRequestedPermitted === false ? "NO" : "UNKNOWN";
    const decisionRows = Array.isArray(entry?.decisionRows) ? entry.decisionRows : [];
    const rowMeta = cmBuildCrossReferenceRowMeta(source);
    const items =
      decisionRows.length > 0
        ? decisionRows.map((decision, index) => ({
            Row: index + 1,
            CheckedAt: checkedAtLabel,
            Verdict: verdict,
            RequestorId: requestorId,
            ServiceProviderId: String(entry?.serviceProviderId || requestorId || "").trim(),
            Mvpd: mvpd,
            MvpdLabel: String(firstNonEmptyString([getRestV2MvpdPickerLabel(requestorId, mvpd, mvpdMeta), mvpd]) || "").trim(),
            Subject: String(entry?.subject || "").trim(),
            UpstreamUserId: String(entry?.upstreamUserId || "").trim(),
            UserId: String(entry?.userId || "").trim(),
            SessionId: String(entry?.sessionId || "").trim(),
            ProfileKey: String(entry?.profileKey || "").trim(),
            ResourceId: String(decision?.resourceId || "").trim(),
            Decision: String(decision?.decision || "").trim(),
            Authorized: typeof decision?.authorized === "boolean" ? (decision.authorized ? "Yes" : "No") : "",
            ErrorCode: String(decision?.errorCode || "").trim(),
            ErrorDetails: String(decision?.errorDetails || "").trim(),
            Source: String(decision?.source || "").trim(),
            MediaTokenPresent: decision?.mediaTokenPresent === true ? "Yes" : decision?.mediaTokenPresent === false ? "No" : "",
            MediaTokenPreview: String(decision?.mediaTokenPreview || "").trim(),
            MediaTokenNotBeforeMs: Number(decision?.mediaTokenNotBeforeMs || 0),
            MediaTokenNotAfterMs: Number(decision?.mediaTokenNotAfterMs || 0),
            DecisionNotBeforeMs: Number(decision?.notBeforeMs || 0),
            DecisionNotAfterMs: Number(decision?.notAfterMs || 0),
            HttpStatus: Number(entry?.status || 0),
            HttpStatusText: String(entry?.statusText || "").trim(),
            Error: String(entry?.error || "").trim(),
            ResourceIds: (Array.isArray(entry?.resourceIds) ? entry.resourceIds : []).join(", "),
            RequestBodyJson: stringifyJsonForDisplay(entry?.requestBody),
            ResponsePayloadJson: stringifyJsonForDisplay(entry?.responsePayload),
            DecisionRawJson: stringifyJsonForDisplay(decision?.raw),
            ...rowMeta,
          }))
        : [
            {
              Row: 1,
              CheckedAt: checkedAtLabel,
              Verdict: verdict,
              RequestorId: requestorId,
              ServiceProviderId: String(entry?.serviceProviderId || requestorId || "").trim(),
              Mvpd: mvpd,
              MvpdLabel: String(firstNonEmptyString([getRestV2MvpdPickerLabel(requestorId, mvpd, mvpdMeta), mvpd]) || "").trim(),
              Subject: String(entry?.subject || "").trim(),
              UpstreamUserId: String(entry?.upstreamUserId || "").trim(),
              UserId: String(entry?.userId || "").trim(),
              SessionId: String(entry?.sessionId || "").trim(),
              ProfileKey: String(entry?.profileKey || "").trim(),
              ResourceId: "",
              Decision: "",
              Authorized: "",
              ErrorCode: "",
              ErrorDetails: "",
              Source: "",
              MediaTokenPresent: "",
              MediaTokenPreview: "",
              MediaTokenNotBeforeMs: 0,
              MediaTokenNotAfterMs: 0,
              DecisionNotBeforeMs: 0,
              DecisionNotAfterMs: 0,
              HttpStatus: Number(entry?.status || 0),
              HttpStatusText: String(entry?.statusText || "").trim(),
              Error: String(entry?.error || "").trim(),
              ResourceIds: (Array.isArray(entry?.resourceIds) ? entry.resourceIds : []).join(", "),
              RequestBodyJson: stringifyJsonForDisplay(entry?.requestBody),
              ResponsePayloadJson: stringifyJsonForDisplay(entry?.responsePayload),
              DecisionRawJson: "",
              ...rowMeta,
            },
          ];
    const payload = {
      mediaCompany: source.programmerName,
      requestorId,
      serviceProviderId: String(entry?.serviceProviderId || requestorId || "").trim(),
      mvpd,
      mvpdLabel: String(firstNonEmptyString([getRestV2MvpdPickerLabel(requestorId, mvpd, mvpdMeta), mvpd]) || "").trim(),
      checkedAt: checkedAtLabel,
      verdict,
      permitCount: Number(entry?.permitCount || 0),
      denyCount: Number(entry?.denyCount || 0),
      unknownCount: Number(entry?.unknownCount || 0),
      resourceIds: (Array.isArray(entry?.resourceIds) ? entry.resourceIds : []).join(", "),
      responsePreview: String(entry?.responsePreview || "").trim(),
      items,
      ...rowMeta,
    };
    const correlationKey = buildRestV2PreauthzCheckKey(entry) || `${requestorId}_${mvpd}_${recordIndex + 1}`;
    return {
      cardId: cmBuildRecordId("restv2-preauthz-xref", String(source.programmerId || "cm"), correlationKey, recordIndex),
      kind: "restv2-preauthz-xref",
      title: "REST V2 Preauthorize",
      subtitle: `${cmBuildCrossReferenceLabel(requestorId, mvpd, mvpdMeta)} | Can I watch? ${verdict} | ${checkedAtLabel}`,
      endpointUrl: String(entry?.endpointUrl || "").trim(),
      requestUrl: "",
      payload,
      columns: cmColumnsFromPayload(payload),
      tenantId: String(source.programmerId || ""),
      tenantName: String(source.programmerName || source.programmerId || "CM"),
      lastModified: "",
    };
  });
}

function cmBuildEsmHealthCorrelationRecords(context = null) {
  const source = context && typeof context === "object" ? context : {};
  if (!source.programmerId || !source.requestorId || !source.esmApp?.guid) {
    return [];
  }
  const reportPath = buildEsmHealthReportPath("day", ["requestor-id", "proxy", "mvpd", "platform"]);
  const queryContext = buildEsmHealthDashboardQueryContext({
    programmerId: source.programmerId,
    programmerName: source.programmerName,
    baseRequestorIds: [source.requestorId],
    baseMvpdIds: source.mvpd ? [source.mvpd] : [],
    requestSource: "cm-esm-health-xref",
  });
  const limit = Math.max(25, Math.min(ESM_HEALTH_BREAKDOWN_LIMIT, 250));
  const requestUrl = buildEsmHealthRequestUrl(reportPath, queryContext, {
    limit,
  });
  const rowMeta = cmBuildCrossReferenceRowMeta(source);
  const summaryRow = {
    RequestorId: source.requestorId,
    Mvpd: source.mvpd,
    MvpdLabel: source.mvpdLabel,
    DateStart: String(queryContext.start || "").trim(),
    DateEnd: String(queryContext.end || "").trim(),
    ReportPath: reportPath,
    RequestUrl: requestUrl,
    ...rowMeta,
  };
  const payload = {
    mediaCompany: source.programmerName,
    requestorId: source.requestorId,
    mvpd: source.mvpd,
    mvpdLabel: source.mvpdLabel,
    reportPath,
    limit,
    requestUrl,
    queryContext: cloneJsonLikeValue(queryContext, queryContext),
    items: [summaryRow],
    ...rowMeta,
  };
  return [
    {
      cardId: cmBuildRecordId("esm-health-xref", String(source.programmerId || "cm"), source.requestorId, 0),
      kind: "esm-health-xref",
      title: "ESM Health Scope",
      subtitle: `${cmBuildCrossReferenceLabel(source.requestorId, source.mvpd, source.mvpdMeta)} | ${String(queryContext.start || "").trim()} to ${String(queryContext.end || "").trim()}`,
      endpointUrl: requestUrl,
      requestUrl,
      payload,
      columns: cmColumnsFromPayload(payload),
      tenantId: String(source.programmerId || ""),
      tenantName: String(source.programmerName || source.programmerId || "ESM"),
      lastModified: "",
    },
  ];
}

function cmBuildRestV2CorrelationRecords(programmer = null, options = {}) {
  const context = cmResolveCrossReferenceContext(programmer, options);
  return [
    ...cmBuildRestV2ProfileCorrelationRecords(context),
    ...cmBuildRestV2PreauthzCorrelationRecords(context),
    ...cmBuildEsmHealthCorrelationRecords(context),
  ];
}

function cmBuildWorkspaceDataset(programmer = null, cmService = null, bundles = [], options = {}) {
  const normalizedBundles = (Array.isArray(bundles) ? bundles : []).filter(Boolean);
  const bundleRecords = cmBuildWorkspaceRecordsFromBundles(normalizedBundles);
  const credentialHints = cmExtractCredentialHintsFromBundles(normalizedBundles);
  const credentialRecords = cmBuildCredentialHintRecords(credentialHints, programmer);
  const cmV2OperationRecords = cmBuildCmV2OperationRecords(programmer, credentialHints);
  const correlationRecords = cmBuildRestV2CorrelationRecords(programmer, {
    cmService,
    tenantScope: options?.tenantScope,
    services: options?.services,
  });
  const records = [...correlationRecords, ...bundleRecords, ...cmV2OperationRecords, ...credentialRecords];
  const groupDefinitions = [
    {
      key: "correlation",
      label: "Live Cross References",
      records: correlationRecords,
    },
    {
      key: "cmv2",
      label: "CM V2 Live APIs",
      records: cmV2OperationRecords,
    },
    {
      key: "tenants",
      label: "CM Tenants",
      records: records.filter((record) => record.kind === "tenant"),
    },
    {
      key: "applications",
      label: "CM Applications",
      records: records.filter((record) => record.kind === "applications"),
    },
    {
      key: "credentials",
      label: "CM Credential Hints",
      records: records.filter((record) => record.kind === "credential"),
    },
    {
      key: "policies",
      label: "CM Policies",
      records: records.filter((record) => record.kind === "policies"),
    },
    {
      key: "usage",
      label: "CMU Usage",
      records: records.filter((record) => record.kind === "usage"),
    },
  ];
  return {
    bundleRecords,
    credentialHints,
    credentialRecords,
    cmV2OperationRecords,
    correlationRecords,
    records,
    groupDefinitions,
  };
}

function cmBuildWorkspaceRecordsFromBundles(bundles) {
  const output = [];
  const seen = new Set();
  const pushRecord = (record) => {
    if (!record?.cardId || seen.has(record.cardId)) {
      return;
    }
    seen.add(record.cardId);
    output.push(record);
  };
  const buildCmApplicationDetailUrl = (tenantId = "", applicationId = "") => {
    const normalizedTenantId = String(tenantId || "").trim();
    const normalizedApplicationId = String(applicationId || "").trim();
    if (!normalizedTenantId || !normalizedApplicationId) {
      return "";
    }
    return normalizeCmUrl(
      `${CM_CONFIG_BASE_URL}/maitai/applications/${encodeURIComponent(normalizedApplicationId)}?orgId=${encodeURIComponent(normalizedTenantId)}`
    );
  };

  const resolveApplicationId = (row = null) =>
    firstNonEmptyString([
      row?.applicationId,
      row?.application_id,
      row?.appId,
      row?.app_id,
      row?.entityId,
      row?.id,
      row?.raw?.applicationId,
      row?.raw?.application_id,
      row?.raw?.appId,
      row?.raw?.app_id,
      row?.raw?.id,
      row?.payload?.applicationId,
      row?.payload?.application_id,
      row?.payload?.appId,
      row?.payload?.app_id,
      row?.payload?.id,
    ]);

  const extractApplicationIdFromDetailUrl = (urlValue = "") => {
    const raw = String(urlValue || "").trim();
    if (!raw) {
      return "";
    }
    try {
      const parsed = new URL(raw);
      const match = String(parsed.pathname || "").match(/\/maitai\/applications\/([^/?#]+)/i);
      return match?.[1] ? decodeURIComponent(match[1]) : "";
    } catch {
      const match = raw.match(/\/maitai\/applications\/([^/?#]+)/i);
      if (!match?.[1]) {
        return "";
      }
      try {
        return decodeURIComponent(match[1]);
      } catch {
        return String(match[1] || "").trim();
      }
    }
  };

  const resolvePrimaryGroupRecordUrl = (groupKind, row, tenantId, entityId, fallbackUrl) => {
    const links = (Array.isArray(row?.links) ? row.links : []).map((value) => normalizeCmUrl(value)).filter(Boolean);
    const normalizedKind = String(groupKind || "").trim().toLowerCase();
    if (normalizedKind === "applications") {
      const applicationId = firstNonEmptyString([resolveApplicationId(row), entityId]);
      const applicationLinks = links.filter(
        (value) => /\/maitai\/applications\/[^/?#]+/i.test(String(value || "")) && !cmIsApplicationsListRequestUrl(value)
      );
      if (applicationLinks.length > 0 && applicationId) {
        const matchingApplicationLink = applicationLinks.find(
          (value) => extractApplicationIdFromDetailUrl(value) === applicationId
        );
        if (matchingApplicationLink) {
          return matchingApplicationLink;
        }
      }
      const detailUrl = buildCmApplicationDetailUrl(tenantId, applicationId);
      if (detailUrl) {
        return detailUrl;
      }
      if (applicationLinks.length > 0) {
        return applicationLinks[0];
      }
      const nonListLink = links.find((value) => !cmIsApplicationsListRequestUrl(value));
      if (nonListLink) {
        return nonListLink;
      }
      return "";
    }
    return firstNonEmptyString([
      links[0],
      row?.sourceUrl,
      fallbackUrl,
    ]);
  };

  (Array.isArray(bundles) ? bundles : []).forEach((bundle, bundleIndex) => {
    const tenant = bundle?.tenant || {};
    const tenantId = String(tenant?.tenantId || `tenant-${bundleIndex + 1}`);
    const tenantName = String(tenant?.tenantName || tenantId);
    const tenantPayload = bundle?.tenantDetail?.payload || tenant?.raw || {};
    pushRecord({
      cardId: cmBuildRecordId("tenant", tenantId, tenantId, bundleIndex),
      kind: "tenant",
      title: tenantName,
      subtitle: tenantId,
      endpointUrl: String(bundle?.tenantDetail?.url || tenant?.sourceUrl || tenant?.links?.[0] || ""),
      requestUrl: String(bundle?.tenantDetail?.url || tenant?.sourceUrl || tenant?.links?.[0] || ""),
      payload: tenantPayload,
      columns: cmColumnsFromPayload(tenantPayload),
      lastModified: String(bundle?.tenantDetail?.lastModified || ""),
      tenantId,
      tenantName,
    });

    const groups = [
      {
        kind: "applications",
        rows: Array.isArray(bundle?.applications?.rows) ? bundle.applications.rows : [],
        fallbackUrl: String(bundle?.applications?.url || ""),
        lastModified: String(bundle?.applications?.lastModified || ""),
      },
      {
        kind: "policies",
        rows: Array.isArray(bundle?.policies?.rows) ? bundle.policies.rows : [],
        fallbackUrl: String(bundle?.policies?.url || ""),
        lastModified: String(bundle?.policies?.lastModified || ""),
      },
      {
        kind: "usage",
        rows: Array.isArray(bundle?.usage?.rows) ? bundle.usage.rows : [],
        fallbackUrl: String(bundle?.usage?.url || ""),
        lastModified: String(bundle?.usage?.lastModified || ""),
      },
    ];

    groups.forEach((group) => {
      group.rows.forEach((row, rowIndex) => {
        const entityId = String(row?.entityId || row?.name || `${group.kind}-${rowIndex + 1}`);
        const isUsageRecord = group.kind === "usage";
        const payload = isUsageRecord ? null : row?.raw && typeof row.raw === "object" ? row.raw : row;
        const primaryUrl = String(resolvePrimaryGroupRecordUrl(group.kind, row, tenantId, entityId, group.fallbackUrl) || "");
        pushRecord({
          cardId: cmBuildRecordId(group.kind, tenantId, entityId, rowIndex),
          kind: group.kind,
          title: String(row?.name || entityId),
          subtitle: `${tenantName} (${tenantId})`,
          endpointUrl: primaryUrl,
          requestUrl: primaryUrl,
          payload,
          columns: payload != null ? cmColumnsFromPayload(payload) : [],
          lastModified: group.lastModified,
          tenantId,
          tenantName,
        });
      });
    });
  });

  return output;
}

function cmFormatRecordKindLabel(kind) {
  const normalized = String(kind || "").trim().toLowerCase();
  const labels = {
    tenant: "Tenant",
    applications: "Application",
    policies: "Policy",
    usage: "Usage",
    "restv2-profile-xref": "REST V2 Profile",
    "restv2-preauthz-xref": "REST V2 Preauthz",
    "esm-health-xref": "ESM Health",
    correlation: "Cross Reference",
    credential: "Credential",
    "cmv2-op": "CM V2 API",
    "group-list": "List",
  };
  if (labels[normalized]) {
    return labels[normalized];
  }
  if (!normalized) {
    return "CM";
  }
  return normalized.replace(/[-_]+/g, " ").replace(/\b\w/g, (char) => char.toUpperCase());
}

function cmBuildGroupWorkspaceRecord(groupKey, groupLabel, records, programmer = null, index = 0) {
  const programmerId = String(programmer?.programmerId || "cm").trim() || "cm";
  const programmerName = String(programmer?.programmerName || programmer?.mediaCompanyName || programmerId).trim() || programmerId;
  const normalizedGroupKey = String(groupKey || groupLabel || `group-${index + 1}`)
    .trim()
    .toLowerCase()
    .replace(/[^\w\-.:]+/g, "_");
  const normalizedGroupLabel = String(groupLabel || normalizedGroupKey || "CM Group").trim() || "CM Group";
  const listRows = (Array.isArray(records) ? records : []).map((record) => {
    const endpoint = String(record?.requestUrl || record?.endpointUrl || "").trim();
    return {
      VIEW: "VIEW",
      Name: String(record?.title || "").trim(),
      Type: cmFormatRecordKindLabel(record?.kind),
      Tenant: String(record?.tenantName || record?.tenantId || "").trim(),
      Summary: String(record?.subtitle || "").trim(),
      Endpoint: endpoint,
      __cmViewRecordId: String(record?.cardId || "").trim(),
    };
  });
  const payload = {
    items: listRows,
  };
  return {
    cardId: cmBuildRecordId("group-list", programmerId, normalizedGroupKey, index),
    kind: "group-list",
    title: `${normalizedGroupLabel} List`,
    subtitle: `${listRows.length} item${listRows.length === 1 ? "" : "s"} | ${programmerName}`,
    endpointUrl: "",
    requestUrl: "",
    payload,
    columns: ["VIEW", "Name", "Type", "Tenant", "Summary", "Endpoint"],
    tenantId: programmerId,
    tenantName: programmerName,
    lastModified: "",
  };
}

function cmBuildGroupListHtml(groupKey, groupLabel, records, groupRecordId = "") {
  const rows = Array.isArray(records) ? records : [];
  const recordId = String(groupRecordId || "").trim();
  const normalizedGroupKey = String(groupKey || groupLabel || "group")
    .trim()
    .toLowerCase()
    .replace(/[^\w\-.:]+/g, "_");
  const bodyDomId = `cm-group-body-${String(recordId || normalizedGroupKey || "group").replace(/[^\w-]+/g, "_")}`;
  const loadAllDisabled = rows.length === 0 || !recordId;
  const headerMarkup = `
    <div class="cm-group-title">
      <button
        type="button"
        class="cm-group-toggle"
        data-group-key="${escapeHtml(normalizedGroupKey)}"
        aria-expanded="false"
        aria-controls="${escapeHtml(bodyDomId)}"
      >
        <span class="cm-group-toggle-icon" aria-hidden="true">▾</span>
        <span class="cm-group-title-text">${escapeHtml(groupLabel)}</span>
      </button>
      <button
        type="button"
        class="cm-group-load-all"
        data-record-id="${escapeHtml(recordId)}"
        title="Load all ${escapeHtml(groupLabel)} into CM Workspace"
        ${loadAllDisabled ? "disabled" : ""}
      >
        <span class="cm-group-title-count">${rows.length}</span>
      </button>
    </div>
  `;
  if (rows.length === 0) {
    return `
      <section class="cm-group is-collapsed" data-group-key="${escapeHtml(normalizedGroupKey)}">
        ${headerMarkup}
        <div class="cm-group-body" id="${escapeHtml(bodyDomId)}">
          <p class="cm-group-empty">No ${escapeHtml(groupLabel.toLowerCase())} detected for this tenant set.</p>
        </div>
      </section>
    `;
  }

  const items = rows
    .map(
      (record) => `
      <li class="cm-group-item">
        <button type="button" class="cm-record-link" data-record-id="${escapeHtml(record.cardId)}">
          <span class="cm-record-name">${escapeHtml(record.title)}</span>
          <span class="cm-record-meta">${escapeHtml(record.subtitle || "")}</span>
        </button>
      </li>
    `
    )
    .join("");

  return `
    <section class="cm-group is-collapsed" data-group-key="${escapeHtml(normalizedGroupKey)}">
      ${headerMarkup}
      <div class="cm-group-body" id="${escapeHtml(bodyDomId)}">
        <ul class="cm-group-list">${items}</ul>
      </div>
    </section>
  `;
}

function cmuUsageExtractPathParts(endpointUrl) {
  const rawUrl = String(endpointUrl || "").trim();
  if (!rawUrl) {
    return [];
  }
  let pathname = "";
  try {
    pathname = String(new URL(rawUrl).pathname || "");
  } catch {
    pathname = rawUrl.replace(/^https?:\/\/[^/]+/i, "").split("?")[0];
  }
  const parts = pathname
    .split("/")
    .map((value) => String(value || "").trim())
    .filter(Boolean);
  return canonicalizeCmuUsagePathParts(parts);
}

function cmuUsageGetZoomKey(pathParts, endpointUrl = "") {
  const normalizeZoomValue = (value = "") => {
    const normalized = String(value || "")
      .trim()
      .toUpperCase()
      .replace(/[^A-Z]/g, "");
    if (!normalized) {
      return "";
    }
    if (normalized === "YR" || normalized === "YEAR" || normalized === "YEARLY") {
      return "YR";
    }
    if (normalized === "MO" || normalized === "MON" || normalized === "MONTH" || normalized === "MONTHLY") {
      return "MO";
    }
    if (normalized === "DAY" || normalized === "DAILY" || normalized === "D") {
      return "DAY";
    }
    if (normalized === "HR" || normalized === "HOUR" || normalized === "HOURLY" || normalized === "H") {
      return "HR";
    }
    if (normalized === "MIN" || normalized === "MINUTE" || normalized === "MINUTELY" || normalized === "M") {
      return "MIN";
    }
    return "";
  };

  const rawEndpointUrl = String(endpointUrl || "").trim();
  if (rawEndpointUrl) {
    try {
      const parsed = new URL(rawEndpointUrl, CM_REPORTS_BASE_URL);
      const queryZoom = normalizeZoomValue(
        firstNonEmptyString([
          parsed.searchParams.get("zm"),
          parsed.searchParams.get("zoom"),
          parsed.searchParams.get("zoomLevel"),
          parsed.searchParams.get("zoom_level"),
          parsed.searchParams.get("zoom-level"),
        ])
      );
      if (queryZoom) {
        return queryZoom;
      }
    } catch {
      const queryMatch = rawEndpointUrl.match(/[?&](?:zm|zoom(?:[_-]?level)?)=([^&#]+)/i);
      if (queryMatch?.[1]) {
        try {
          const parsedZoom = normalizeZoomValue(decodeURIComponent(queryMatch[1]));
          if (parsedZoom) {
            return parsedZoom;
          }
        } catch {
          const rawZoom = normalizeZoomValue(queryMatch[1]);
          if (rawZoom) {
            return rawZoom;
          }
        }
      }
    }
  }

  const normalizedParts = Array.isArray(pathParts)
    ? pathParts.map((value) => String(value || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const normalizedPath = `/${normalizedParts.join("/")}`;
  const normalizedUrl = String(endpointUrl || "").trim().toLowerCase();
  const haystack = `${normalizedPath} ${normalizedUrl}`;
  if (haystack.includes("/minute")) {
    return "MIN";
  }
  if (haystack.includes("/hour")) {
    return "HR";
  }
  if (haystack.includes("/day")) {
    return "DAY";
  }
  if (haystack.includes("/month")) {
    return "MO";
  }
  if (haystack.includes("/year")) {
    return "YR";
  }
  return "";
}

function cmuUsagePathPartsToKey(pathParts) {
  return (Array.isArray(pathParts) ? pathParts : [])
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean)
    .join("/");
}

function cmuUsageBuildPathLookupCandidates(pathParts) {
  const normalizedInput = esmWorkspaceNormalizeEndpointSegments(pathParts)
    .map((value) => normalizeCmuUsagePathSegment(value))
    .filter(Boolean)
    .filter((value) => value !== "cmu" && value !== "v2");
  if (normalizedInput.length === 0) {
    return [];
  }
  const canonical = canonicalizeCmuUsagePathParts(normalizedInput);
  if (canonical.length > 0) {
    return [canonical];
  }
  const extras = [];
  const seenExtras = new Set();
  normalizedInput.forEach((part) => {
    if (CM_USAGE_ROOT_SEGMENT_SET.has(part) || seenExtras.has(part)) {
      return;
    }
    seenExtras.add(part);
    extras.push(part);
  });
  return [[...CM_USAGE_ROOT_SEGMENTS, ...extras]];
}

function cmuUsageBuildCatalog(usageRecords) {
  const recordsByPathKey = new Map();
  const catalog = [];
  (Array.isArray(usageRecords) ? usageRecords : []).forEach((record) => {
    const endpointUrl = String(record?.requestUrl || record?.endpointUrl || "").trim();
    const pathParts = cmuUsageExtractPathParts(endpointUrl);
    if (!endpointUrl || pathParts.length === 0) {
      return;
    }
    const pathKey = cmuUsagePathPartsToKey(pathParts);
    if (!pathKey) {
      return;
    }
    const queue = Array.isArray(recordsByPathKey.get(pathKey)) ? recordsByPathKey.get(pathKey) : [];
    queue.push(record);
    recordsByPathKey.set(pathKey, queue);
    if (queue.length > 1) {
      return;
    }
    const zoomKey = cmuUsageGetZoomKey(pathParts, endpointUrl);
    const columns = Array.isArray(record?.columns) ? record.columns.map((value) => String(value || "").trim()).filter(Boolean) : [];
    const searchHay = `${pathParts.join(" ")} ${columns.join(" ")}`.toLowerCase().replace(/\s+/g, "");
    catalog.push({
      key: pathKey,
      pathParts,
      segs: pathParts.slice(),
      pathHay: pathParts.join(" ").toLowerCase().replace(/\s+/g, ""),
      zoomKey,
      columns,
      endpointUrl,
      searchHay,
    });
  });

  catalog.sort((left, right) => {
    const lengthDelta = left.pathParts.length - right.pathParts.length;
    if (lengthDelta !== 0) {
      return lengthDelta;
    }
    return esmWorkspaceComparePathParts(left.pathParts, right.pathParts);
  });

  return {
    catalog,
    recordsByPathKey,
  };
}

function cmuUsageBuildShellHtml() {
  const zoomOptions = CLICK_ESM_ZOOM_OPTIONS.filter((key) => key !== "MIN").map((key) => {
    const value = escapeHtml(key);
    const label = key ? escapeHtml(key) : "";
    return `<option value="${value}">${label}</option>`;
  }).join("");

  return `
    <div class="cmu-jelly-shell">
      <div class="esm-workspace-toolbar cmu-jelly-toolbar">
        <select class="esm-workspace-zoom-filter cmu-jelly-zoom-filter" title="Zoom Level">${zoomOptions}</select>
        <input type="text" class="esm-workspace-search cmu-jelly-search" placeholder="CMU Column search..." />
        <button type="button" class="esm-workspace-reset-btn cmu-jelly-reset-btn">RESET</button>
      </div>
      <div class="esm-workspace-tree-panel cmu-jelly-tree-panel">
        <div class="esm-workspace-tree-head cmu-jelly-tree-head">
          <button type="button" class="cmu-jelly-panel-toggle cmu-jelly-tree-toggle" aria-expanded="false">
            <span class="cmu-jelly-panel-toggle-icon" aria-hidden="true">▾</span>
            <span class="esm-workspace-tree-title">JellyBeans</span>
          </button>
          <button
            type="button"
            class="cmu-jelly-panel-load-all cmu-jelly-tree-load-all"
            title="Load all visible JellyBeans into CM Workspace"
            aria-label="Load all visible JellyBeans into CM Workspace"
            disabled
          >
            <span class="cmu-jelly-panel-count cmu-jelly-tree-count">0</span>
          </button>
        </div>
        <div class="esm-workspace-tree-scroll cmu-jelly-tree-scroll" hidden>
          <div class="esm-workspace-tree-root cmu-jelly-tree-root"></div>
        </div>
      </div>
      <div class="esm-workspace-footer cmu-jelly-footer">
        <div class="esm-workspace-footer-status" aria-hidden="true">
          <span class="esm-workspace-net-indicator" title="Loading" aria-label="Loading" hidden></span>
        </div>
        <div class="esm-workspace-footer-actions">
          <button
            type="button"
            class="cmu-jelly-make-clickcmu-btn esm-workspace-toolbar-icon-btn esm-workspace-toolbar-icon-btn--tearsheet"
            title="Generate CMU tearsheet (clickCMU)"
            aria-label="Generate CMU tearsheet (clickCMU)"
          >
            <span class="esm-workspace-toolbar-icon esm-workspace-toolbar-icon--tearsheet" aria-hidden="true">
              <svg viewBox="0 0 24 24" focusable="false">
                <path d="M7 3.75h7.25L19 8.5v11.75A1.75 1.75 0 0 1 17.25 22H7A1.75 1.75 0 0 1 5.25 20.25V5.5A1.75 1.75 0 0 1 7 3.75Z" />
                <path d="M14.25 3.75V8.5H19" />
                <path d="M9.5 12.75 10 14.25 11.5 14.75 10 15.25 9.5 16.75 9 15.25 7.5 14.75 9 14.25 9.5 12.75Z" />
                <path d="M14 12.25 14.3 13.1 15.2 13.4 14.3 13.7 14 14.55 13.7 13.7 12.8 13.4 13.7 13.1 14 12.25Z" />
              </svg>
            </span>
          </button>
        </div>
      </div>
    </div>
  `;
}

function cmuUsageNormalizeRecordUrl(record) {
  return normalizeCmUrl(String(record?.requestUrl || record?.endpointUrl || "").trim());
}

function cmuUsageDeduplicateRecords(records = []) {
  const deduped = [];
  const seen = new Set();
  (Array.isArray(records) ? records : []).forEach((record) => {
    if (!record || typeof record !== "object") {
      return;
    }
    const endpointUrl = cmuUsageNormalizeRecordUrl(record);
    const key = endpointUrl || String(record?.cardId || "").trim();
    if (!key || seen.has(key)) {
      return;
    }
    seen.add(key);
    deduped.push(record);
  });
  return deduped;
}

function cmuUsageResolveRecordsByEndpointIndexes(cmuUsageState, endpointIndexes = []) {
  const catalog = Array.isArray(cmuUsageState?.catalog) ? cmuUsageState.catalog : [];
  const output = [];
  [...new Set(
    (Array.isArray(endpointIndexes) ? endpointIndexes : [])
      .map((value) => Number(value))
      .filter((value) => Number.isInteger(value) && value >= 0 && value < catalog.length)
  )].forEach((endpointIndex) => {
    const endpoint = catalog[endpointIndex];
    if (!endpoint || !Array.isArray(endpoint.pathParts) || endpoint.pathParts.length === 0) {
      return;
    }
    const records = cmuUsageResolveRecordsByPath(cmuUsageState, endpoint.pathParts);
    if (Array.isArray(records) && records.length > 0) {
      output.push(...records);
    }
  });
  return cmuUsageDeduplicateRecords(output);
}

function cmuUsageSyncPanelLoadAllButtons(cmuUsageState, endpointIndexes = []) {
  const normalizedIndexes = [...new Set(
    (Array.isArray(endpointIndexes) ? endpointIndexes : [])
      .map((value) => Number(value))
      .filter((value) => Number.isInteger(value) && value >= 0)
  )];
  const visibleCount = normalizedIndexes.length;
  const loadAllBusy = cmuUsageState?.loadAllBusy === true;
  const setCount = (element) => {
    if (element) {
      element.textContent = String(visibleCount);
    }
  };
  setCount(cmuUsageState?.treeCountElement);
  const setDisabled = (button) => {
    if (button) {
      button.disabled = visibleCount === 0 || loadAllBusy;
      button.classList.toggle("net-busy", loadAllBusy);
      if (loadAllBusy) {
        button.setAttribute("aria-busy", "true");
      } else {
        button.removeAttribute("aria-busy");
      }
    }
  };
  setDisabled(cmuUsageState?.treeLoadAllButton);
}

function cmuUsageResolveRecordsByPath(cmuUsageState, pathParts, options = {}) {
  const map = cmuUsageState?.recordsByPathKey instanceof Map ? cmuUsageState.recordsByPathKey : null;
  if (!map) {
    return [];
  }
  const allowPrefixFallback = options?.allowPrefixFallback === true;
  const lookupCandidates = cmuUsageBuildPathLookupCandidates(pathParts);
  for (const candidateParts of lookupCandidates) {
    const minSize = allowPrefixFallback ? 1 : candidateParts.length;
    for (let size = candidateParts.length; size >= minSize; size -= 1) {
      const key = cmuUsagePathPartsToKey(candidateParts.slice(0, size));
      if (!key) {
        continue;
      }
      const records = map.get(key);
      if (Array.isArray(records) && records.length > 0) {
        const deduped = cmuUsageDeduplicateRecords(records);
        if (deduped.length > 0) {
          return deduped;
        }
      }
    }
  }
  return [];
}

async function cmuUsageRunRecordsFromUi(cmState, cmuUsageState, records, requestToken, source = "cmu-jelly") {
  const queue = cmuUsageDeduplicateRecords(records);
  if (!cmState || !cmuUsageState || queue.length === 0) {
    return;
  }
  const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
    cmState?.programmer?.programmerId,
    requestToken || cmuUsageState?.requestToken || cmState?.requestToken || 0
  );
  cmState.requestToken = liveRequestToken;
  cmuUsageState.requestToken = liveRequestToken;
  try {
    const requestSource = String(source || "").trim();
    emitCmDebugEvent(
      {
        phase: "cmu-jelly-open",
        source: requestSource || "cmu-jelly",
        recordCount: queue.length,
        endpoints: queue.map((record) => String(record?.requestUrl || record?.endpointUrl || "").trim()).filter(Boolean),
      },
      {
        context: {
          programmerId: String(cmState?.programmer?.programmerId || ""),
          requestorId: String(state.selectedRequestorId || ""),
          mvpd: String(state.selectedMvpdId || ""),
          workspaceKey: "cmu-workspace",
          workspaceOrigin: "CMU Workspace",
        },
      }
    );
    await cmOpenRecordsInWorkspace(cmState, queue, liveRequestToken, {
      activate: true,
      emitStart: true,
      forceRefetch: true,
    });
  } catch (error) {
    setStatus(`Unable to open CM Usage report: ${error instanceof Error ? error.message : String(error)}`, "error");
  }
}

function cmuUsageApplyFilters(cmState, cmuUsageState, requestToken, options = {}) {
  const root = cmuUsageState?.treeRootElement;
  if (!root) {
    return { visibleEndpointCount: 0 };
  }

  const zoomFilter = String(options.zoomFilter ?? cmuUsageState.zoomFilterSelect?.value ?? "")
    .trim()
    .toUpperCase();
  const term = clickEsmNormalizeSearchTerm(options.term ?? cmuUsageState.searchInput?.value ?? "");
  const searchMode = Boolean(term);
  const doHighlight = Boolean(options.highlight && term);
  const highlightPattern = doHighlight ? new RegExp(clickEsmEscapeRegExp(term), "gi") : null;
  const visibleEndpointIndexes = [];
  root.classList.toggle("esm-workspace-search-mode", searchMode);

  const endpointItems = root.querySelectorAll("ul.esm-workspace-root > li[data-endpoint-index]");
  endpointItems.forEach((item) => {
    const endpointZoom = String(item.dataset.zoomKey || "").trim().toUpperCase();
    const haystack = String(item.dataset.hay || "").toLowerCase();
    const zoomPass = !zoomFilter || endpointZoom === zoomFilter;
    const termPass = !term || haystack.includes(term);
    const isVisible = zoomPass && termPass;

    item.style.display = isVisible ? "" : "none";
    if (isVisible) {
      const endpointIndex = Number(item.dataset.endpointIndex || -1);
      if (Number.isInteger(endpointIndex) && endpointIndex >= 0) {
        visibleEndpointIndexes.push(endpointIndex);
      }
    }

    const label = item.querySelector(":scope > .esm-workspace-node > .esm-workspace-label");
    if (label) {
      const pathParts = esmWorkspaceParsePathParts(item.dataset.pathParts);
      esmWorkspaceRenderLabelChips(label, pathParts, doHighlight ? term : "", highlightPattern, {
        onSegmentClick: (segmentPathParts) => {
          const records = cmuUsageResolveRecordsByPath(cmuUsageState, segmentPathParts);
          void cmuUsageRunRecordsFromUi(cmState, cmuUsageState, records, requestToken, "cmu-jelly-segment");
        },
      });
      const pathHay = String(item.dataset.pathHay || "");
      const segMatch = Boolean(term && pathHay.includes(term));
      const colOnlyMatch = Boolean(term && termPass && !segMatch);
      label.classList.toggle("esm-workspace-col-match", colOnlyMatch);
    }
  });

  cmuUsageState.visibleEndpointIndexes = visibleEndpointIndexes.slice();
  cmuUsageSyncPanelLoadAllButtons(cmuUsageState, visibleEndpointIndexes);
  esmWorkspaceSyncTreeToggleButton(cmuUsageState);
  return {
    visibleEndpointCount: visibleEndpointIndexes.length,
    visibleEndpointIndexes: visibleEndpointIndexes.slice(),
  };
}

function cmuUsageBuildTree(cmState, cmuUsageState, requestToken) {
  const treeRoot = cmuUsageState?.treeRootElement;
  if (!treeRoot) {
    return;
  }
  const catalog = Array.isArray(cmuUsageState.catalog) ? cmuUsageState.catalog : [];
  treeRoot.innerHTML = "";
  if (catalog.length === 0) {
    treeRoot.innerHTML = '<div class="cmu-jelly-empty">No CM Usage endpoints available for JellyBeans.</div>';
    return;
  }
  const rootList = document.createElement("ul");
  rootList.className = "esm-workspace-root";

  cmuUsageState.endpointIndexByPathKey = new Map();
  catalog.forEach((entry, entryIndex) => {
    const pathKey = cmuUsagePathPartsToKey(entry.pathParts);
    if (pathKey && !cmuUsageState.endpointIndexByPathKey.has(pathKey)) {
      cmuUsageState.endpointIndexByPathKey.set(pathKey, entryIndex);
    }

    const item = document.createElement("li");
    item.dataset.endpointIndex = String(entryIndex);
    item.dataset.zoomKey = String(entry.zoomKey || "");
    item.dataset.hay = String(entry.searchHay || "");
    item.dataset.pathParts = JSON.stringify(entry.pathParts);
    item.dataset.pathHay = String(entry.pathHay || "");

    const nodeRow = document.createElement("div");
    nodeRow.className = "esm-workspace-node";

    const label = document.createElement("span");
    label.className = "esm-workspace-label";
    label.title = String(entry.endpointUrl || "");
    esmWorkspaceRenderLabelChips(label, entry.pathParts, "", null, {
      onSegmentClick: (segmentPathParts) => {
        const records = cmuUsageResolveRecordsByPath(cmuUsageState, segmentPathParts);
        void cmuUsageRunRecordsFromUi(cmState, cmuUsageState, records, requestToken, "cmu-jelly-segment");
      },
    });
    label.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const records = cmuUsageResolveRecordsByPath(cmuUsageState, entry.pathParts);
      void cmuUsageRunRecordsFromUi(cmState, cmuUsageState, records, requestToken, "cmu-jelly-pill");
    });
    nodeRow.appendChild(label);
    item.appendChild(nodeRow);
    rootList.appendChild(item);
  });

  treeRoot.appendChild(rootList);
  cmuUsageApplyFilters(cmState, cmuUsageState, requestToken, { highlight: false });
}

function cmuUsageWireInteractions(cmState, cmuUsageState, requestToken) {
  if (!cmState || !cmuUsageState) {
    return;
  }
  const getLiveRequestToken = () => {
    const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
      cmState?.programmer?.programmerId,
      cmuUsageState?.requestToken || cmState?.requestToken || requestToken || 0
    );
    cmState.requestToken = liveRequestToken;
    cmuUsageState.requestToken = liveRequestToken;
    return liveRequestToken;
  };
  const applyFilters = ({ highlight = false, normalizeInput = false } = {}) => {
    const normalizedTerm = clickEsmNormalizeSearchTerm(cmuUsageState.searchInput?.value || "");
    const normalizedZoomFilter = String(cmuUsageState.zoomFilterSelect?.value || "").trim().toUpperCase();
    if (cmuUsageState.searchInput && normalizeInput) {
      cmuUsageState.searchInput.value = normalizedTerm;
    }
    const result = cmuUsageApplyFilters(cmState, cmuUsageState, requestToken, {
      zoomFilter: normalizedZoomFilter,
      term: normalizedTerm,
      highlight: Boolean(highlight && normalizedTerm),
    });
    if ((normalizedTerm || normalizedZoomFilter) && Number(result?.visibleEndpointCount || 0) >= 0) {
      esmWorkspaceSetTreeCollapsed(cmuUsageState, false);
    }
  };

  cmuUsageState.resetButton?.addEventListener("click", () => {
    if (cmuUsageState.searchInput) {
      cmuUsageState.searchInput.value = "";
    }
    if (cmuUsageState.zoomFilterSelect) {
      cmuUsageState.zoomFilterSelect.value = "";
    }
    applyFilters({ highlight: false, normalizeInput: true });
  });

  cmuUsageState.zoomFilterSelect?.addEventListener("change", () => {
    applyFilters({ highlight: true });
  });
  cmuUsageState.searchInput?.addEventListener("input", () => {
    applyFilters({ highlight: true });
  });
  cmuUsageState.searchInput?.addEventListener("change", () => {
    applyFilters({ highlight: true });
  });
  cmuUsageState.searchInput?.addEventListener("keydown", (event) => {
    if (event.key !== "Enter" || event.isComposing || event.keyCode === 229) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    applyFilters({ highlight: true, normalizeInput: true });
  });

  const toggleTree = () => {
    const expanded = String(
      cmuUsageState.treeHeadElement?.getAttribute("aria-expanded") || (cmuUsageState.treeScrollElement?.hidden ? "false" : "true")
    ) !== "false";
    esmWorkspaceSetTreeCollapsed(cmuUsageState, expanded);
  };
  const runVisibleEndpointsToWorkspace = async (source = "cmu-jelly-load-all") => {
    if (cmuUsageState.loadAllBusy === true) {
      return;
    }
    const endpointIndexes = Array.isArray(cmuUsageState.visibleEndpointIndexes) ? cmuUsageState.visibleEndpointIndexes : [];
    const records = cmuUsageResolveRecordsByEndpointIndexes(cmuUsageState, endpointIndexes);
    if (records.length === 0) {
      return;
    }

    cmuUsageState.loadAllBusy = true;
    cmuUsageSyncPanelLoadAllButtons(cmuUsageState, endpointIndexes);
    cmSetLoadAllButtonsBusy(cmState, [cmuUsageState.treeLoadAllButton], true);
    try {
      await cmuUsageRunRecordsFromUi(cmState, cmuUsageState, records, getLiveRequestToken(), source);
    } finally {
      cmSetLoadAllButtonsBusy(cmState, [cmuUsageState.treeLoadAllButton], false);
      cmuUsageState.loadAllBusy = false;
      cmuUsageSyncPanelLoadAllButtons(cmuUsageState, cmuUsageState.visibleEndpointIndexes);
    }
  };

  cmuUsageState.treeHeadElement?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    toggleTree();
  });
  cmuUsageState.treeLoadAllButton?.addEventListener("click", async (event) => {
    event.preventDefault();
    event.stopPropagation();
    await runVisibleEndpointsToWorkspace("cmu-jelly-tree-load-all");
  });
}

function cmMountUsageJellyBeans(cmState, usageRecords, requestToken) {
  const host = cmState?.contentElement?.querySelector(".cmu-jelly-host");
  if (!host) {
    return;
  }
  const usageCatalog = cmuUsageBuildCatalog(usageRecords);
  host.innerHTML = cmuUsageBuildShellHtml();
  const cmuUsageState = {
    catalog: Array.isArray(usageCatalog.catalog) ? usageCatalog.catalog : [],
    recordsByPathKey: usageCatalog.recordsByPathKey,
    endpointIndexByPathKey: new Map(),
    visibleEndpointIndexes: [],
    requestToken,
    treeHeadElement: host.querySelector(".cmu-jelly-tree-toggle"),
    treeScrollElement: host.querySelector(".cmu-jelly-tree-scroll"),
    treeRootElement: host.querySelector(".cmu-jelly-tree-root"),
    zoomFilterSelect: host.querySelector(".cmu-jelly-zoom-filter"),
    searchInput: host.querySelector(".cmu-jelly-search"),
    resetButton: host.querySelector(".cmu-jelly-reset-btn"),
    makeClickCmuButton: host.querySelector(".cmu-jelly-make-clickcmu-btn"),
    treeLoadAllButton: host.querySelector(".cmu-jelly-tree-load-all"),
    treeCountElement: host.querySelector(".cmu-jelly-tree-count"),
    loadAllBusy: false,
  };

  cmState.cmuUsageState = cmuUsageState;
  if (cmuUsageState.treeHeadElement) {
    cmuUsageState.treeHeadElement.setAttribute("aria-expanded", "false");
    cmuUsageState.treeHeadElement.setAttribute("aria-label", "Toggle JellyBeans");
  }
  cmuUsageWireInteractions(cmState, cmuUsageState, requestToken);
  cmuUsageBuildTree(cmState, cmuUsageState, requestToken);
  esmWorkspaceSetTreeCollapsed(cmuUsageState, true);
}

function getActiveCmStateForServiceClass(serviceClass = "service-cm") {
  const normalizedServiceClass = String(serviceClass || "").trim();
  if (!normalizedServiceClass) {
    return null;
  }
  const sections = document.querySelectorAll(`.premium-service-section.${normalizedServiceClass}`);
  for (const section of sections) {
    const cmState = section?.__underparCmState || null;
    if (cmState?.section?.isConnected) {
      return cmState;
    }
  }
  return null;
}

function getActiveCmState() {
  return getActiveCmStateForServiceClass("service-cm");
}

function getActiveCmMvpdState() {
  return getActiveCmStateForServiceClass("service-cm-mvpd");
}

function buildDetachedCmWorkspaceState(programmer, cmService = null, requestToken = 0, options = {}) {
  if (!programmer?.programmerId || !cmService || !shouldShowCmService(cmService)) {
    return null;
  }

  const cachedRenderContext = getCachedCmRenderContext(programmer, cmService, {
    allowSynthetic: true,
    tenantScope: options?.tenantScope,
  });
  if (!cachedRenderContext || !Array.isArray(cachedRenderContext.bundles) || cachedRenderContext.bundles.length === 0) {
    return null;
  }

  const serviceType = String(options?.serviceType || cmService?.serviceType || "cm").trim();
  const isMvpdService = serviceType === "cmMvpd";
  const workspaceKey = String(options?.workspaceKey || (isMvpdService ? "mvpd-workspace" : "cmu-workspace")).trim();
  const workspaceOrigin = String(options?.workspaceOrigin || (isMvpdService ? "MVPD Workspace" : "CMU Workspace")).trim();
  const bundles = cachedRenderContext.bundles.filter(Boolean);
  const workspaceDataset = cmBuildWorkspaceDataset(programmer, cmService, bundles, {
    tenantScope: cachedRenderContext.tenantScope,
  });
  const records = workspaceDataset.records.slice();
  const groupDefinitions = workspaceDataset.groupDefinitions.slice();
  const groupChildRecordIdsByGroupRecordId = new Map();
  groupDefinitions.forEach((group, index) => {
    const groupRecord = cmBuildGroupWorkspaceRecord(group.key, group.label, group.records, programmer, index);
    records.push(groupRecord);
    if (groupRecord?.cardId) {
      const childRecordIds = (Array.isArray(group.records) ? group.records : [])
        .map((record) => String(record?.cardId || "").trim())
        .filter(Boolean);
      groupChildRecordIdsByGroupRecordId.set(groupRecord.cardId, childRecordIds);
    }
  });

  return {
    detached: true,
    serviceType,
    workspaceKey,
    workspaceOrigin,
    section: {
      isConnected: true,
      __underparDetachedCmState: true,
    },
    programmer,
    tenantScope: cachedRenderContext.tenantScope,
    cmService,
    contentElement: null,
    requestToken: Number(requestToken || 0),
    bundles,
    recordsById: new Map(records.map((record) => [record.cardId, record])),
    groupChildRecordIdsByGroupRecordId,
    controllerWindowId: Number(options?.controllerWindowId || state.cmWorkspaceWindowId || 0),
    loadAllBusyCount: 0,
  };
}

async function resolveCmStateForWorkspaceAction(options = {}) {
  const liveCmState = getActiveCmState();
  if (liveCmState) {
    return liveCmState;
  }

  const programmer = resolveSelectedProgrammer();
  if (!programmer?.programmerId) {
    return null;
  }

  await hydrateProgrammerFromPassVault(programmer, {
    forceReload: false,
    forceOverwrite: false,
    forceDcrRestore: true,
  }).catch(() => null);

  const programmerId = String(programmer.programmerId || "").trim();
  let services = getCurrentPremiumAppsSnapshot(programmerId) || {};
  let cmService =
    services?.cm ||
    state.cmServiceByProgrammerId.get(programmerId) ||
    buildPassVaultRuntimeCmServiceSnapshot(getPassVaultMediaCompanyRecord(programmerId)) ||
    null;

  if (
    shouldShowCmService(cmService) &&
    !hasCachedCmTenantBundleCoverage(cmService) &&
    (isPassVaultBackedValue(cmService) || isPassVaultProgrammerHydrated(programmerId))
  ) {
    restorePassVaultCmTenantBundlesToRuntime(getPassVaultMediaCompanyRecord(programmerId));
  }

  const needsHydration =
    !shouldShowCmService(cmService) ||
    !hasReusableCmSnapshotForSelection(cmService) ||
    !hasCachedCmTenantBundleCoverage(cmService);

  if (needsHydration) {
    const hydrated = await ensureCmHydratedForProgrammer(programmer, services, {
      forceRefresh: false,
      reason: String(options?.reason || "workspace-action"),
      freshLeewayMs: 45 * 1000,
    }).catch(() => null);
    services = hydrated?.services || getCurrentPremiumAppsSnapshot(programmerId) || services;
    cmService = hydrated?.cmService || services?.cm || cmService;
  }

  if (!shouldShowCmService(cmService)) {
    return null;
  }

  return buildDetachedCmWorkspaceState(programmer, cmService, Number(state.premiumPanelRequestToken || 0), {
    controllerWindowId: Number(options?.controllerWindowId || state.cmWorkspaceWindowId || 0),
    reason: String(options?.reason || "workspace-action"),
  });
}

function cmFindRecordByCard(cmState, card) {
  if (!cmState?.recordsById) {
    return null;
  }
  const cardId = String(card?.cardId || "").trim();
  if (cardId && cmState.recordsById.has(cardId)) {
    return cmState.recordsById.get(cardId);
  }
  const endpointUrl = String(card?.requestUrl || card?.endpointUrl || "").trim();
  if (!endpointUrl) {
    return null;
  }
  for (const record of cmState.recordsById.values()) {
    if (String(record?.requestUrl || record?.endpointUrl || "").trim() === endpointUrl) {
      return record;
    }
  }
  return null;
}

function cmGetOperationForRecord(record) {
  if (!record || typeof record !== "object") {
    return null;
  }
  const payload = record.payload && typeof record.payload === "object" ? record.payload : null;
  const operation = payload?.operation && typeof payload.operation === "object" ? payload.operation : null;
  if (!operation) {
    return null;
  }
  const parameters = Array.isArray(operation.parameters)
    ? operation.parameters
        .map((item) => {
          if (!item || typeof item !== "object") {
            return null;
          }
          return {
            name: String(item.name || "").trim(),
            in: String(item.in || "path").trim().toLowerCase(),
            required: item.required === true,
            description: String(item.description || "").trim(),
          };
        })
        .filter((item) => item?.name)
    : [];
  return {
    key: String(operation.key || "").trim(),
    label: String(operation.label || "").trim(),
    method: String(operation.method || "GET").trim().toUpperCase(),
    pathTemplate: String(operation.pathTemplate || "").trim(),
    parameters,
    security: String(operation.security || "").trim(),
  };
}

function cmGetOperationDefaultFormValues(record) {
  const payload = record?.payload && typeof record.payload === "object" ? record.payload : null;
  const rawDefaults = payload?.formDefaults && typeof payload.formDefaults === "object" ? payload.formDefaults : {};
  const payloadHarvest = payload?.profileHarvest && typeof payload.profileHarvest === "object" ? payload.profileHarvest : null;
  const payloadHarvestList =
    Array.isArray(payload?.profileHarvestList) && payload.profileHarvestList.length > 0
      ? payload.profileHarvestList.filter((item) => item && typeof item === "object")
      : [];
  const programmerId = String(rawDefaults.programmerId || record?.tenantId || "").trim();
  const contextHarvest = getRestV2ProfileHarvestForContext({
    programmerId,
    requestorId: state.selectedRequestorId,
    mvpd: state.selectedMvpdId,
  });
  const profileHarvest = isUsableRestV2ProfileHarvest(contextHarvest) ? contextHarvest : null;
  const profileHarvestList = getRestV2ProfileHarvestBucketForProgrammer(programmerId);
  const mergedHarvestList = mergeRestV2ProfileHarvestLists(
    payloadHarvest ? [payloadHarvest] : [],
    payloadHarvestList,
    profileHarvest ? [profileHarvest] : [],
    profileHarvestList
  );
  const aggregatedCandidates = collectRestV2HarvestCandidateValues(mergedHarvestList);
  const payloadIdpCandidates = Array.isArray(payloadHarvest?.idpCandidates) ? payloadHarvest.idpCandidates : [];
  const profileIdpCandidates = Array.isArray(profileHarvest?.idpCandidates) ? profileHarvest.idpCandidates : [];
  const payloadSubjectCandidates = Array.isArray(payloadHarvest?.subjectCandidates) ? payloadHarvest.subjectCandidates : [];
  const profileSubjectCandidates = Array.isArray(profileHarvest?.subjectCandidates) ? profileHarvest.subjectCandidates : [];
  const payloadSessionCandidates = Array.isArray(payloadHarvest?.sessionCandidates) ? payloadHarvest.sessionCandidates : [];
  const profileSessionCandidates = Array.isArray(profileHarvest?.sessionCandidates) ? profileHarvest.sessionCandidates : [];
  return {
    baseUrl: firstNonEmptyString([rawDefaults.baseUrl, CM_V2_API_BASE_DEFAULT]) || CM_V2_API_BASE_DEFAULT,
    idp: firstNonEmptyString([
      rawDefaults.idp,
      payloadHarvest?.mvpd,
      ...payloadIdpCandidates,
      profileHarvest?.mvpd,
      ...profileIdpCandidates,
      ...aggregatedCandidates.idpCandidates,
      state.selectedMvpdId,
    ]),
    subject: firstNonEmptyString([
      rawDefaults.subject,
      payloadHarvest?.subject,
      payloadHarvest?.upstreamUserId,
      payloadHarvest?.userId,
      ...payloadSubjectCandidates,
      profileHarvest?.subject,
      profileHarvest?.upstreamUserId,
      profileHarvest?.userId,
      ...profileSubjectCandidates,
      ...aggregatedCandidates.subjectCandidates,
      state.selectedRequestorId,
    ]),
    session: firstNonEmptyString([
      rawDefaults.session,
      payloadHarvest?.sessionId,
      ...payloadSessionCandidates,
      profileHarvest?.sessionId,
      ...profileSessionCandidates,
      ...aggregatedCandidates.sessionCandidates,
    ]),
    xTerminate: String(rawDefaults.xTerminate || "").trim(),
    authUser: String(rawDefaults.authUser || "").trim(),
    authPass: String(rawDefaults.authPass || "").trim(),
  };
}

function cmNormalizeOperationFormValues(record, formValues = {}) {
  const defaults = cmGetOperationDefaultFormValues(record);
  const source = formValues && typeof formValues === "object" ? formValues : {};
  return {
    baseUrl: firstNonEmptyString([source.baseUrl, defaults.baseUrl, CM_V2_API_BASE_DEFAULT]) || CM_V2_API_BASE_DEFAULT,
    idp: String(source.idp || defaults.idp || "").trim(),
    subject: String(source.subject || defaults.subject || "").trim(),
    session: String(source.session || defaults.session || "").trim(),
    xTerminate: String(source.xTerminate || defaults.xTerminate || "").trim(),
    authUser: String(source.authUser || defaults.authUser || "").trim(),
    authPass: String(source.authPass || defaults.authPass || "").trim(),
  };
}

function cmBuildOperationRequest(record, formValues = {}) {
  const operation = cmGetOperationForRecord(record);
  if (!operation) {
    throw new Error("CM V2 operation metadata is missing.");
  }
  if (!operation.pathTemplate) {
    throw new Error("CM V2 operation path template is missing.");
  }

  const values = cmNormalizeOperationFormValues(record, formValues);
  const baseUrlRaw = String(values.baseUrl || CM_V2_API_BASE_DEFAULT).trim();
  const baseUrl = baseUrlRaw.replace(/\/+$/, "");
  if (!baseUrl) {
    throw new Error("CM V2 base URL is required.");
  }

  const pathParams = operation.parameters.filter((item) => item.in === "path");
  const headerParams = operation.parameters.filter((item) => item.in === "header");
  const queryParams = operation.parameters.filter((item) => item.in === "query");

  let resolvedPath = operation.pathTemplate;
  pathParams.forEach((param) => {
    const fieldName = String(param.name || "").trim();
    if (!fieldName) {
      return;
    }
    const lookupKey = fieldName.toLowerCase() === "x-terminate" ? "xTerminate" : fieldName;
    const value = String(values[lookupKey] || "").trim();
    if (!value && param.required) {
      throw new Error(`CM V2 parameter "${fieldName}" is required.`);
    }
    const placeholderPattern = new RegExp(`\\{${fieldName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\}`, "g");
    resolvedPath = resolvedPath.replace(placeholderPattern, encodeURIComponent(value));
  });

  if (/\{[^}]+\}/.test(resolvedPath)) {
    throw new Error(`CM V2 path contains unresolved parameters: ${resolvedPath}`);
  }

  const query = new URLSearchParams();
  queryParams.forEach((param) => {
    const fieldName = String(param.name || "").trim();
    if (!fieldName) {
      return;
    }
    const value = String(values[fieldName] || "").trim();
    if (!value && param.required) {
      throw new Error(`CM V2 query parameter "${fieldName}" is required.`);
    }
    if (value) {
      query.append(fieldName, value);
    }
  });

  const headers = {
    Accept: "application/json, text/plain, */*",
  };
  headerParams.forEach((param) => {
    const fieldName = String(param.name || "").trim();
    if (!fieldName) {
      return;
    }
    const lookupKey = fieldName.toLowerCase() === "x-terminate" ? "xTerminate" : fieldName;
    const rawValue = String(values[lookupKey] || "").trim();
    if (!rawValue && param.required) {
      throw new Error(`CM V2 header "${fieldName}" is required.`);
    }
    if (!rawValue) {
      return;
    }
    if (fieldName.toLowerCase() === "x-terminate") {
      const normalized = rawValue
        .split(/[\n,]+/)
        .map((item) => item.trim())
        .filter(Boolean)
        .join(",");
      if (normalized) {
        headers[fieldName] = normalized;
      }
      return;
    }
    headers[fieldName] = rawValue;
  });

  if (values.authUser || values.authPass) {
    headers.Authorization = `Basic ${base64EncodeUtf8(`${values.authUser || ""}:${values.authPass || ""}`)}`;
  }

  const queryText = query.toString();
  const url = normalizeCmUrl(`${baseUrl}${resolvedPath}${queryText ? `?${queryText}` : ""}`);
  return {
    url,
    method: operation.method || "GET",
    headers,
    operation,
    formValues: values,
  };
}

function cmResolveRequestorMvpdContext(cmState = null) {
  const selectedRequestorId = String(state.selectedRequestorId || "").trim();
  const selectedMvpdId = String(state.selectedMvpdId || "").trim();
  const serviceRequestorId = String(cmState?.cmService?.requestorId || "").trim();
  const serviceMvpdId = String(cmState?.cmService?.mvpdId || "").trim();
  const requestorId = firstNonEmptyString([selectedRequestorId, serviceRequestorId]);
  const mvpdId = firstNonEmptyString([selectedMvpdId, serviceMvpdId]);
  const mvpdLabel = mvpdId ? firstNonEmptyString([getRestV2MvpdPickerLabel(requestorId, mvpdId), mvpdId]) : "";
  return {
    requestorId,
    mvpdId,
    mvpdLabel,
  };
}

function cmBuildWorkspaceReportContextPayload(cmState = null, requestToken = 0) {
  const programmerId = String(cmState?.programmer?.programmerId || "").trim();
  const adobePassEnvironmentKey = String(getActiveAdobePassEnvironmentKey() || "").trim();
  const premiumPanelRequestToken = Math.max(0, Number(requestToken || 0));
  return {
    programmerId,
    adobePassEnvironmentKey,
    premiumPanelRequestToken,
    workspaceContextKey: buildCmWorkspaceControllerContextKey(
      programmerId,
      premiumPanelRequestToken,
      adobePassEnvironmentKey
    ),
  };
}

function cmResolveEsmHealthXrefRecordConfig(record = null, cmState = null) {
  const payload = record?.payload && typeof record.payload === "object" ? record.payload : {};
  const seededQueryContext =
    payload?.queryContext && typeof payload.queryContext === "object" ? cloneJsonLikeValue(payload.queryContext, {}) : {};
  const programmerId = String(
    firstNonEmptyString([seededQueryContext.programmerId, cmState?.programmer?.programmerId, record?.tenantId]) || ""
  ).trim();
  const programmerName = String(
    firstNonEmptyString([seededQueryContext.programmerName, cmState?.programmer?.programmerName, record?.tenantName, programmerId]) || ""
  ).trim();
  const requestorId = String(
    firstNonEmptyString([payload?.requestorId, state.selectedRequestorId, cmState?.cmService?.requestorId]) || ""
  ).trim();
  const mvpdId = String(firstNonEmptyString([payload?.mvpd, state.selectedMvpdId, cmState?.cmService?.mvpdId]) || "").trim();
  const queryContext = buildEsmHealthDashboardQueryContext({
    ...seededQueryContext,
    programmerId,
    programmerName,
    baseRequestorIds: requestorId ? [requestorId] : normalizeEsmHealthFilterList(seededQueryContext.baseRequestorIds),
    baseMvpdIds: mvpdId ? [mvpdId] : normalizeEsmHealthFilterList(seededQueryContext.baseMvpdIds),
    requestSource: "cm-esm-health-xref",
  });
  const reportPath = String(payload?.reportPath || buildEsmHealthReportPath("day", ["requestor-id", "proxy", "mvpd", "platform"])).trim();
  const limit = Math.max(1, Number(payload?.limit || ESM_HEALTH_BREAKDOWN_LIMIT || 0) || ESM_HEALTH_BREAKDOWN_LIMIT);
  const requestUrl = buildEsmHealthRequestUrl(reportPath, queryContext, {
    limit,
  });
  return {
    queryContext,
    reportPath,
    limit,
    requestUrl,
  };
}

async function cmFetchEsmHealthXrefReport(record = null, cmState = null) {
  const config = cmResolveEsmHealthXrefRecordConfig(record, cmState);
  const result = await fetchEsmHealthJson(config.queryContext, config.reportPath, {
    limit: config.limit,
  });
  if (!result?.ok) {
    throw new Error(String(result?.error || "Unable to load the scoped ESM HEALTH cross reference.").trim());
  }
  const rows = Array.isArray(result.rows) ? result.rows : [];
  const fallbackRows =
    rows.length > 0
      ? rows
      : [
          {
            RequestorId: String(config.queryContext?.requestorIds?.[0] || "").trim(),
            Mvpd: String(config.queryContext?.mvpdIds?.[0] || "").trim(),
            DateStart: String(config.queryContext?.start || "").trim(),
            DateEnd: String(config.queryContext?.end || "").trim(),
            Message: "No ESM HEALTH rows matched the current scoped window.",
            RequestUrl: String(result?.requestUrl || config.requestUrl || "").trim(),
          },
        ];
  return {
    requestUrl: String(result?.requestUrl || config.requestUrl || "").trim(),
    rows: fallbackRows,
    columns: cmColumnsFromRows(fallbackRows),
    lastModified: "",
  };
}

async function cmRunOperationRecordToWorkspace(cmState, record, requestToken, options = {}) {
  if (!cmState || !record) {
    return;
  }
  if (!isCmServiceRequestActive(cmState.section, requestToken, cmState.programmer?.programmerId)) {
    return;
  }

  const operation = cmGetOperationForRecord(record);
  if (!operation) {
    throw new Error("CM V2 operation metadata is missing.");
  }

  const cardId = String(options.cardId || record.cardId || generateRequestId());
  const targetWorkspace = cmResolveWorkspaceTarget(cmState, options);
  const targetWindowId =
    Number(options.targetWindowId || 0) ||
    Number(cmState.controllerWindowId || 0) ||
    Number(targetWorkspace === "mvpd" ? state.mvpdWorkspaceWindowId : state.cmWorkspaceWindowId || 0);
  const requestContext = cmResolveRequestorMvpdContext(cmState);
  const targetRequestorId = String(requestContext.requestorId || "").trim();
  const targetMvpdId = String(requestContext.mvpdId || "").trim();
  const targetMvpdLabel = String(requestContext.mvpdLabel || "").trim();
  const cmWorkspaceKey = targetWorkspace === "mvpd" ? "mvpd-workspace" : "cmu-workspace";
  const cmWorkspaceOrigin = targetWorkspace === "mvpd" ? "MVPD Workspace" : "CMU Workspace";
  const cmWorkspaceDebugContext = {
    programmerId: String(cmState?.programmer?.programmerId || ""),
    requestorId: targetRequestorId,
    mvpd: targetMvpdId,
    workspaceKey: cmWorkspaceKey,
    workspaceOrigin: cmWorkspaceOrigin,
  };
  const workspaceReportContext = cmBuildWorkspaceReportContextPayload(cmState, requestToken);
  const formValues = cmNormalizeOperationFormValues(record, options.formValues || {});
  if (record.payload && typeof record.payload === "object") {
    record.payload.formDefaults = { ...formValues };
  }

  const displayPath = String(operation.pathTemplate || "").trim();
  const fallbackUrl = normalizeCmUrl(`${String(formValues.baseUrl || CM_V2_API_BASE_DEFAULT).replace(/\/+$/, "")}${displayPath}`);

  if (options.emitForm !== false) {
    cmSendReportWorkspaceMessage(
      targetWorkspace,
      "report-form",
      {
        ...workspaceReportContext,
        cardId,
        endpointUrl: fallbackUrl || displayPath,
        requestUrl: fallbackUrl || displayPath,
        zoomKey: "CMV2",
        columns: [],
        operation,
        formValues,
        programmerId: String(cmState?.programmer?.programmerId || ""),
        requestorId: targetRequestorId,
        mvpdId: targetMvpdId,
        mvpdLabel: targetMvpdLabel,
      },
      { targetWindowId }
    );
  }

  if (options.execute !== true) {
    return;
  }

  cmSendReportWorkspaceMessage(
    targetWorkspace,
    "report-start",
    {
      ...workspaceReportContext,
      cardId,
      endpointUrl: fallbackUrl || displayPath,
      requestUrl: fallbackUrl || displayPath,
      zoomKey: "CMV2",
      columns: [],
      programmerId: String(cmState?.programmer?.programmerId || ""),
      requestorId: targetRequestorId,
      mvpdId: targetMvpdId,
      mvpdLabel: targetMvpdLabel,
    },
    { targetWindowId }
  );

  try {
    const request = cmBuildOperationRequest(record, formValues);
    emitCmDebugEvent(
      {
        phase: "cm-v2-request",
        cardId,
        operationKey: String(operation.key || ""),
        operationLabel: String(operation.label || ""),
        method: request.method,
        url: request.url,
        authMode: detectCmAuthMode(request.headers),
      },
      {
        context: cmWorkspaceDebugContext,
      }
    );
    const basicAuthHeader = String(request?.headers?.Authorization || request?.headers?.authorization || "").trim();
    const usesBasicAuth = /^basic\s+/i.test(basicAuthHeader);
    let responseUrl = String(request.url || "");
    let responseStatus = 0;
    let responseStatusText = "";
    let responseLastModified = "";
    let text = "";
    let parsed = null;

    if (usesBasicAuth) {
      const response = await fetch(request.url, {
        method: request.method,
        mode: "cors",
        credentials: "include",
        referrerPolicy: "no-referrer",
        headers: request.headers,
      });
      responseUrl = String(response.url || request.url || "");
      responseStatus = Number(response.status || 0);
      responseStatusText = String(response.statusText || "");
      responseLastModified = String(response.headers?.get("Last-Modified") || "");
      text = await response.text().catch(() => "");
      parsed = parseJsonText(text, null);
      if (!response.ok) {
        const errorDetails = truncateDebugText(text || response.statusText || "Request failed.", 1600);
        emitCmDebugEvent(
          {
            phase: "cm-v2-request-failed",
            cardId,
            operationKey: String(operation.key || ""),
            method: request.method,
            url: request.url,
            status: Number(response.status || 0),
            statusText: String(response.statusText || ""),
            error: errorDetails,
          },
          {
            context: cmWorkspaceDebugContext,
          }
        );
        throw new Error(`CM V2 ${request.method} ${request.url} failed (${response.status}): ${errorDetails}`);
      }
    } else {
      const response = await fetchCmJsonWithAuthVariants(
        [request.url],
        `CM V2 ${request.method} ${String(operation.label || operation.key || "operation").trim() || "operation"}`,
        {
          method: request.method,
          mode: "cors",
          credentials: "include",
          referrerPolicy: "no-referrer",
          headers: request.headers,
          debugMeta: {
            ...cmWorkspaceDebugContext,
            scope: "cm-v2-operation",
            cardId,
            operationKey: String(operation.key || ""),
            operationLabel: String(operation.label || ""),
          },
        }
      );
      responseUrl = String(response.url || request.url || "");
      responseStatus = Number(response.status || 0);
      responseStatusText = responseStatus > 0 ? "OK" : "";
      responseLastModified = String(response.lastModified || "");
      text = String(response.text || "");
      parsed = response.parsed ?? parseJsonText(text, null);
    }

    emitCmDebugEvent(
      {
        phase: "cm-v2-response",
        cardId,
        operationKey: String(operation.key || ""),
        operationLabel: String(operation.label || ""),
        method: request.method,
        url: responseUrl || request.url,
        status: responseStatus,
        statusText: responseStatusText,
        responsePreview: truncateDebugText(text, 1600),
      },
      {
        context: cmWorkspaceDebugContext,
      }
    );
    const normalizedPayload = parsed ?? text;
    const rows = cmRowsFromPayload(normalizedPayload);
    const summaryRows =
      rows.length > 0
        ? rows
        : [
            {
              status: responseStatus,
              statusText: responseStatusText,
              method: request.method,
              url: responseUrl || request.url,
              message: text ? truncateDebugText(text, 1200) : "(no body)",
            },
          ];

    record.requestUrl = responseUrl || request.url;
    record.endpointUrl = responseUrl || request.url;
    record.lastModified = responseLastModified;
    record.columns = cmColumnsFromPayload(normalizedPayload);

    cmSendReportWorkspaceMessage(
      targetWorkspace,
      "report-result",
      {
        ...workspaceReportContext,
        ok: true,
        cardId,
        endpointUrl: responseUrl || request.url,
        requestUrl: responseUrl || request.url,
        zoomKey: "CMV2",
        columns: record.columns,
        rows: summaryRows,
        lastModified: record.lastModified,
        programmerId: String(cmState?.programmer?.programmerId || ""),
        requestorId: targetRequestorId,
        mvpdId: targetMvpdId,
        mvpdLabel: targetMvpdLabel,
      },
      { targetWindowId }
    );
  } catch (error) {
    emitCmDebugEvent(
      {
        phase: "cm-v2-request-error",
        cardId,
        operationKey: String(operation.key || ""),
        operationLabel: String(operation.label || ""),
        endpointUrl: fallbackUrl || displayPath,
        error: error instanceof Error ? error.message : String(error),
      },
      {
        context: cmWorkspaceDebugContext,
      }
    );
    cmSendReportWorkspaceMessage(
      targetWorkspace,
      "report-result",
      {
        ...workspaceReportContext,
        ok: false,
        cardId,
        endpointUrl: fallbackUrl || displayPath,
        requestUrl: fallbackUrl || displayPath,
        error: error instanceof Error ? error.message : String(error),
        programmerId: String(cmState?.programmer?.programmerId || ""),
        requestorId: targetRequestorId,
        mvpdId: targetMvpdId,
        mvpdLabel: targetMvpdLabel,
      },
      { targetWindowId }
    );
  }
}

function cmIsApplicationsListRequestUrl(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return false;
  }
  try {
    const parsed = new URL(raw, CM_CONFIG_BASE_URL);
    const path = String(parsed.pathname || "").replace(/\/+$/, "").toLowerCase();
    return path === "/maitai/applications";
  } catch {
    const path = String(raw.split("?")[0] || "").replace(/\/+$/, "").toLowerCase();
    return path.endsWith("/maitai/applications");
  }
}

function cmExtractApplicationIdFromDetailUrl(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return "";
  }
  const readApplicationIdFromPath = (pathValue = "") => {
    const match = String(pathValue || "").match(/\/maitai\/applications\/([^/?#]+)/i);
    if (!match?.[1]) {
      return "";
    }
    try {
      return decodeURIComponent(match[1]);
    } catch {
      return String(match[1] || "").trim();
    }
  };
  try {
    const parsed = new URL(raw, CM_CONFIG_BASE_URL);
    return readApplicationIdFromPath(parsed.pathname || "");
  } catch {
    return readApplicationIdFromPath(raw.split("?")[0] || "");
  }
}

function cmIsApplicationDetailRequestUrl(urlValue = "") {
  return Boolean(cmExtractApplicationIdFromDetailUrl(urlValue));
}

function cmExtractPolicyIdFromDetailUrl(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return "";
  }
  const readPolicyIdFromPath = (pathValue = "") => {
    const match = String(pathValue || "").match(/\/maitai\/policy\/([^/?#]+)/i);
    if (!match?.[1]) {
      return "";
    }
    try {
      return decodeURIComponent(match[1]);
    } catch {
      return String(match[1] || "").trim();
    }
  };
  try {
    const parsed = new URL(raw, CM_CONFIG_BASE_URL);
    return readPolicyIdFromPath(parsed.pathname || "");
  } catch {
    return readPolicyIdFromPath(raw.split("?")[0] || "");
  }
}

function cmNormalizeRecordKind(kindValue = "") {
  const normalized = String(kindValue || "").trim().toLowerCase();
  if (!normalized) {
    return "";
  }
  if (
    normalized === "restv2-profile-xref" ||
    normalized === "restv2-profile" ||
    normalized === "rest-v2-profile" ||
    normalized === "rest_v2_profile"
  ) {
    return "restv2-profile-xref";
  }
  if (
    normalized === "restv2-preauthz-xref" ||
    normalized === "restv2-preauthz" ||
    normalized === "rest-v2-preauthz" ||
    normalized === "rest_v2_preauthz"
  ) {
    return "restv2-preauthz-xref";
  }
  if (
    normalized === "esm-health-xref" ||
    normalized === "esmhealthxref" ||
    normalized === "esm-health" ||
    normalized === "esm_health"
  ) {
    return "esm-health-xref";
  }
  if (normalized === "application" || normalized === "applications") {
    return "applications";
  }
  if (normalized === "policy" || normalized === "policies") {
    return "policies";
  }
  if (normalized === "usage" || normalized === "cmu") {
    return "usage";
  }
  if (normalized === "tenant" || normalized === "tenants") {
    return "tenant";
  }
  if (normalized === "cmv2-op" || normalized === "cmv2" || normalized === "cm-v2" || normalized === "cm_v2") {
    return "cmv2-op";
  }
  return normalized;
}

function cmInferRecordKindFromCard(card = null, fallbackUrl = "") {
  const explicitKind = cmNormalizeRecordKind(card?.kind);
  if (explicitKind) {
    return explicitKind;
  }

  const zoomKind = cmNormalizeRecordKind(card?.zoomKey);
  if (zoomKind) {
    return zoomKind;
  }

  if (card?.operation && typeof card.operation === "object") {
    return "cmv2-op";
  }

  const requestUrl = String(
    firstNonEmptyString([card?.requestUrl, card?.endpointUrl, card?.baseRequestUrl, fallbackUrl])
  ).trim();
  if (!requestUrl) {
    return "cm";
  }
  if (cmIsApplicationsListRequestUrl(requestUrl) || cmIsApplicationDetailRequestUrl(requestUrl)) {
    return "applications";
  }
  if (/\/maitai\/policy(?:\/|\?|$)/i.test(requestUrl)) {
    return "policies";
  }
  try {
    const parsed = new URL(requestUrl, CM_REPORTS_BASE_URL);
    if (isClickCmuUsagePath(parsed.pathname)) {
      return "usage";
    }
  } catch {
    if (isClickCmuUsagePath(requestUrl)) {
      return "usage";
    }
  }
  return "cm";
}

function cmBuildFallbackRecordFromCard(cmState, card = null, options = {}) {
  const normalizedCard = card && typeof card === "object" ? card : {};
  const fallbackUrl = String(
    firstNonEmptyString([normalizedCard.requestUrl, normalizedCard.endpointUrl, normalizedCard.baseRequestUrl])
  ).trim();
  const recordKind = cmInferRecordKindFromCard(normalizedCard, fallbackUrl);
  const payload = normalizedCard.payload && typeof normalizedCard.payload === "object" ? { ...normalizedCard.payload } : null;
  const entityId = firstNonEmptyString([
    normalizedCard.entityId,
    payload?.entityId,
    payload?.entity_id,
    payload?.id,
  ]);
  const applicationId = firstNonEmptyString([
    normalizedCard.applicationId,
    normalizedCard.appId,
    payload?.applicationId,
    payload?.application_id,
    payload?.appId,
    payload?.app_id,
    recordKind === "applications" ? entityId : "",
    cmExtractApplicationIdFromDetailUrl(fallbackUrl),
  ]);
  const policyId = firstNonEmptyString([
    normalizedCard.policyId,
    payload?.policyId,
    payload?.policy_id,
    payload?.policy?.id,
    payload?.applicationPolicyId,
    payload?.application_policy_id,
    recordKind === "policies" ? entityId : "",
    cmExtractPolicyIdFromDetailUrl(fallbackUrl),
  ]);
  const tenantId = firstNonEmptyString(
    [
      ...(Array.isArray(options?.tenantIdCandidates) ? options.tenantIdCandidates : []),
      normalizedCard.tenantId,
      payload?.ownerId,
      payload?.tenantId,
      payload?.tenant_id,
      payload?.orgId,
      payload?.org_id,
      payload?.policyOwnerId,
      payload?.policy_owner_id,
    ]
  );
  const tenantName = firstNonEmptyString(
    [
      ...(Array.isArray(options?.tenantNameCandidates) ? options.tenantNameCandidates : []),
      normalizedCard.tenantName,
      payload?.tenantName,
      payload?.tenant_name,
      payload?.ownerName,
      payload?.owner_name,
      payload?.ownerId,
      payload?.policyOwnerId,
    ]
  );

  return {
    cardId: String(normalizedCard.cardId || generateRequestId()),
    kind: recordKind || "cm",
    title: String(
      firstNonEmptyString([
        normalizedCard.title,
        recordKind === "applications" ? "CM application" : "",
        recordKind === "policies" ? "CM policy" : "",
        recordKind === "usage" ? "CM usage" : "",
        "CM item",
      ])
    ),
    subtitle: String(normalizedCard.subtitle || ""),
    endpointUrl: fallbackUrl,
    requestUrl: fallbackUrl,
    payload,
    columns: Array.isArray(normalizedCard?.columns) ? normalizedCard.columns : [],
    lastModified: String(normalizedCard.lastModified || ""),
    tenantId: String(tenantId || ""),
    tenantName: String(tenantName || ""),
    applicationId: String(applicationId || ""),
    policyId: String(policyId || ""),
  };
}

function cmResolveApplicationDetailUrl(record, fallbackUrl = "") {
  const fallback = String(fallbackUrl || "").trim();
  const normalizedKind = String(record?.kind || "").trim().toLowerCase();
  if (normalizedKind !== "applications" && normalizedKind !== "policies") {
    return fallback;
  }
  const payload = record?.payload && typeof record.payload === "object" ? record.payload : null;
  const tenantId = firstNonEmptyString([
    record?.tenantId,
    payload?.ownerId,
    payload?.tenantId,
    payload?.tenant_id,
    payload?.orgId,
    payload?.org_id,
    payload?.policyOwnerId,
    payload?.policy_owner_id,
  ]);
  if (normalizedKind === "policies") {
    const policyId = firstNonEmptyString([
      record?.policyId,
      payload?.policyId,
      payload?.policy_id,
      payload?.policy?.id,
      payload?.applicationPolicyId,
      payload?.application_policy_id,
      cmExtractPolicyIdFromDetailUrl(fallback),
    ]);
    if (!tenantId || !policyId) {
      return fallback;
    }
    return normalizeCmUrl(
      `${CM_CONFIG_BASE_URL}/maitai/policy/${encodeURIComponent(String(policyId || "").trim())}?orgId=${encodeURIComponent(tenantId)}`
    );
  }
  const applicationId = firstNonEmptyString([
    record?.applicationId,
    record?.entityId,
    payload?.applicationId,
    payload?.application_id,
    payload?.appId,
    payload?.app_id,
    payload?.id,
  ]);
  if (applicationId && tenantId) {
    return normalizeCmUrl(
      `${CM_CONFIG_BASE_URL}/maitai/applications/${encodeURIComponent(String(applicationId || "").trim())}?orgId=${encodeURIComponent(tenantId)}`
    );
  }
  if (cmIsApplicationsListRequestUrl(fallback)) {
    return "";
  }
  const policyId = firstNonEmptyString([
    record?.policyId,
    payload?.policyId,
    payload?.policy_id,
    payload?.policy?.id,
    payload?.applicationPolicyId,
    payload?.application_policy_id,
  ]);
  const entityId = firstNonEmptyString([
    policyId,
    payload?.policyId,
    payload?.policy_id,
    payload?.policy?.id,
    payload?.applicationPolicyId,
    payload?.application_policy_id,
    record?.policyId,
  ]);
  if (!tenantId || !entityId) {
    return fallback;
  }
  return normalizeCmUrl(
    `${CM_CONFIG_BASE_URL}/maitai/policy/${encodeURIComponent(String(entityId || "").trim())}?orgId=${encodeURIComponent(tenantId)}`
  );
}

function cmResolveUsageTenantScope(cmState, record = null) {
  return resolveCmUsageTenantScopeValue(
    record?.tenantId,
    record?.tenantName,
    cmState?.tenantScope,
    cmState?.cmService?.matchedTenants?.[0]?.tenantId,
    cmState?.cmService?.matchedTenants?.[0]?.tenantName,
    getCmTenantScopeForProgrammer(cmState?.programmer)
  );
}

function cmApplyUsageExampleRequestContext(urlValue, record = null, cmState = null) {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return "";
  }
  const payload = record?.payload && typeof record.payload === "object" ? record.payload : null;
  if (payload?.usageExample !== true) {
    return raw;
  }
  const hasMvpdDimension = payload?.hasMvpdDimension === true;
  const selectedMvpdId = String(state.selectedMvpdId || "").trim();
  try {
    const parsed = new URL(stripServerManagedTimeParams(raw, CM_REPORTS_BASE_URL), CM_REPORTS_BASE_URL);
    parsed.searchParams.set("format", "json");
    parsed.searchParams.delete("start");
    parsed.searchParams.delete("end");
    const tenantScope = cmResolveUsageTenantScope(cmState, record);
    CM_USAGE_TENANT_QUERY_KEYS.forEach((key) => parsed.searchParams.delete(key));
    if (tenantScope && cmUsagePathRequiresTenantScope(parsed.pathname)) {
      applyCmUsageTenantScopeToSearchParams(parsed.searchParams, tenantScope);
    }
    if (hasMvpdDimension) {
      parsed.searchParams.delete("mvpd");
      parsed.searchParams.delete("mvpd_id");
      parsed.searchParams.delete("mvpd-id");
      if (selectedMvpdId) {
        parsed.searchParams.set("mvpd", selectedMvpdId);
      }
    }
    return parsed.toString();
  } catch {
    return raw;
  }
}

function cmScopeUsageRequestUrl(urlValue, cmState, record = null) {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return "";
  }
  try {
    const parsed = new URL(raw, CM_REPORTS_BASE_URL);
    const payload = record?.payload && typeof record.payload === "object" ? record.payload : null;
    if (payload?.usageExample === true) {
      return cmApplyUsageExampleRequestContext(parsed.toString(), record, cmState);
    }
    if (!isClickCmuUsagePath(parsed.pathname)) {
      return parsed.toString();
    }
    const normalizedUsageUrl = ensureCmUsageEndpointFormat(parsed.toString(), {
      tenantScope: cmResolveUsageTenantScope(cmState, record),
    });
    const normalizedParsed = new URL(normalizedUsageUrl, CM_REPORTS_BASE_URL);
    const pathParts = cmuUsageExtractPathParts(normalizedParsed.pathname);
    const hasMvpdDimension = Array.isArray(pathParts) && pathParts.includes("mvpd");
    const selectedMvpdId = String(
      firstNonEmptyString([state.selectedMvpdId, cmState?.cmService?.mvpdId, cmState?.cmService?.mvpd])
    ).trim();
    normalizedParsed.searchParams.delete("mvpd");
    normalizedParsed.searchParams.delete("mvpd_id");
    normalizedParsed.searchParams.delete("mvpd-id");
    if (hasMvpdDimension && selectedMvpdId) {
      normalizedParsed.searchParams.set("mvpd", selectedMvpdId);
    }
    return normalizedParsed.toString();
  } catch {
    return raw;
  }
}

function cmSendReportWorkspaceMessage(targetWorkspace = "cm", event = "", payload = {}, options = {}) {
  const normalizedTargetWorkspace = String(targetWorkspace || "cm").trim().toLowerCase();
  const normalizedEvent = String(event || "").trim();
  if (!normalizedEvent) {
    return;
  }
  if (normalizedTargetWorkspace === "mvpd") {
    void mvpdWorkspaceSendWorkspaceMessage(`cm-${normalizedEvent}`, payload, {
      targetWindowId: Number(options?.targetWindowId || 0),
    });
    return;
  }
  void cmSendWorkspaceMessage(normalizedEvent, payload, {
    targetWindowId: Number(options?.targetWindowId || 0),
  });
}

function cmCardHasExplicitRequestContext(card = null) {
  if (!card || typeof card !== "object") {
    return false;
  }
  return [
    card?.requestUrl,
    card?.baseRequestUrl,
    card?.seedRequestUrl,
    card?.seedBaseRequestUrl,
  ]
    .map((value) => String(value || "").trim())
    .some(Boolean);
}

async function cmRunRecordToWorkspace(cmState, record, requestToken, options = {}) {
  if (!cmState || !record) {
    return;
  }
  const liveRequestToken = resolveCurrentPremiumPanelRequestToken(
    cmState?.programmer?.programmerId,
    requestToken || cmState?.requestToken || 0
  );
  cmState.requestToken = liveRequestToken;
  if (!isCmServiceRequestActive(cmState.section, liveRequestToken, cmState.programmer?.programmerId)) {
    return;
  }

  if (String(record?.kind || "").toLowerCase() === "cmv2-op") {
    const targetWorkspace = cmResolveWorkspaceTarget(cmState, options);
    await cmRunOperationRecordToWorkspace(cmState, record, liveRequestToken, {
      emitForm: options.emitForm !== false,
      execute: options.execute === true,
      formValues: options.formValues && typeof options.formValues === "object" ? options.formValues : {},
      cardId: options.cardId,
      targetWindowId: options.targetWindowId,
      targetWorkspace,
    });
    return;
  }

  const cardId = String(options.cardId || record.cardId || generateRequestId());
  const targetWorkspace = cmResolveWorkspaceTarget(cmState, options);
  const requestContext = cmResolveRequestorMvpdContext(cmState);
  const targetRequestorId = String(requestContext.requestorId || "").trim();
  const targetMvpdId = String(requestContext.mvpdId || "").trim();
  const targetMvpdLabel = String(requestContext.mvpdLabel || "").trim();
  const scopedRecord =
    targetWorkspace === "mvpd"
      ? {
          ...(record && typeof record === "object" ? record : {}),
          tenantId: firstNonEmptyString([
            String(record?.tenantId || "").trim(),
            String(cmState?.cmService?.matchedTenants?.[0]?.tenantId || "").trim(),
            targetMvpdId,
            String(cmState?.tenantScope || "").trim(),
          ]),
          tenantName: firstNonEmptyString([
            String(record?.tenantName || "").trim(),
            String(cmState?.cmService?.matchedTenants?.[0]?.tenantName || "").trim(),
            targetMvpdLabel,
            targetMvpdId,
            "MVPD",
          ]),
        }
      : record;
  const resolvedUsageTenantScope = cmResolveUsageTenantScope(cmState, scopedRecord);
  const reportTenantId = String(
    firstNonEmptyString([
      String(scopedRecord?.tenantId || "").trim(),
      targetWorkspace === "mvpd" ? targetMvpdId : "",
      resolvedUsageTenantScope,
    ])
  ).trim();
  const reportTenantName = String(
    firstNonEmptyString([
      String(scopedRecord?.tenantName || "").trim(),
      targetWorkspace === "mvpd" ? targetMvpdLabel : "",
      targetWorkspace === "mvpd" ? targetMvpdId : "",
      resolvedUsageTenantScope,
      String(cmState?.programmer?.programmerName || "").trim(),
      targetWorkspace === "mvpd" ? "MVPD" : "CM",
    ])
  ).trim();
  const requestSource = String(options.requestSource || "workspace").trim().toLowerCase() || "workspace";
  const preserveExactRequestContext =
    requestSource === "workspace-path-link" || requestSource === "workspace-path-node";
  const endpointUrl = String(record.endpointUrl || record.requestUrl || "").trim();
  const recordKind = String(record?.kind || "").trim().toLowerCase();
  const baseRequestUrlRaw = String(options.baseRequestUrl || record.requestUrl || endpointUrl).trim();
  const baseRequestUrl = preserveExactRequestContext
    ? baseRequestUrlRaw
    : cmScopeUsageRequestUrl(baseRequestUrlRaw, cmState, scopedRecord) || baseRequestUrlRaw;
  const requestUrlOverride = String(options.requestUrlOverride || "").trim();
  let requestUrl = requestUrlOverride || baseRequestUrl;
  if (recordKind === "esm-health-xref") {
    requestUrl = cmResolveEsmHealthXrefRecordConfig(record, cmState).requestUrl;
  }
  if (!preserveExactRequestContext) {
    requestUrl = cmResolveApplicationDetailUrl(scopedRecord, requestUrl);
    requestUrl = cmScopeUsageRequestUrl(requestUrl, cmState, scopedRecord) || requestUrl;
  }
  const normalizedLocalColumnFilters =
    options.localColumnFilters && typeof options.localColumnFilters === "object" ? { ...options.localColumnFilters } : {};
  const cmWorkspaceKey = targetWorkspace === "mvpd" ? "mvpd-workspace" : "cmu-workspace";
  const cmWorkspaceOrigin = targetWorkspace === "mvpd" ? "MVPD Workspace" : "CMU Workspace";
  const targetWindowId =
    Number(options.targetWindowId || 0) ||
    Number(cmState.controllerWindowId || 0) ||
    Number(targetWorkspace === "mvpd" ? state.mvpdWorkspaceWindowId : state.cmWorkspaceWindowId || 0);
  const workspaceReportContext = cmBuildWorkspaceReportContextPayload(cmState, liveRequestToken);
  if (options.emitStart !== false) {
    cmSendReportWorkspaceMessage(
      targetWorkspace,
      "report-start",
      {
        ...workspaceReportContext,
        cardId,
        endpointUrl,
        requestUrl,
        baseRequestUrl,
        zoomKey: String(record.kind || "").toUpperCase(),
        columns: Array.isArray(record.columns) ? record.columns : [],
        localColumnFilters: normalizedLocalColumnFilters,
        seedEndpointUrl: String(options.seedEndpointUrl || ""),
        seedRequestUrl: String(options.seedRequestUrl || ""),
        seedBaseRequestUrl: String(options.seedBaseRequestUrl || ""),
        seedLocalColumnFilters:
          options.seedLocalColumnFilters && typeof options.seedLocalColumnFilters === "object"
            ? { ...options.seedLocalColumnFilters }
            : {},
        tenantId: reportTenantId,
        tenantName: reportTenantName,
        programmerId: String(cmState?.programmer?.programmerId || ""),
        requestorId: targetRequestorId,
        mvpdId: targetMvpdId,
        mvpdLabel: targetMvpdLabel,
        requestSource,
      },
      { targetWindowId }
    );
  }

  let payload = record.payload;
  let lastModified = String(record.lastModified || "");
  const recordRequestUrl = preserveExactRequestContext
    ? String(record.requestUrl || endpointUrl || "").trim()
    : cmScopeUsageRequestUrl(String(record.requestUrl || endpointUrl || "").trim(), cmState, scopedRecord);
  const hasUrlOverrideDiffersFromRecord =
    Boolean(requestUrlOverride) && requestUrl !== recordRequestUrl;
  const applicationsListRequest = recordKind === "applications" && cmIsApplicationsListRequestUrl(requestUrl);
  const shouldRefetchForRecordKind =
    recordKind === "usage" ||
    (recordKind === "applications" &&
      (!payload || (Boolean(String(requestUrl || "").trim()) && !applicationsListRequest)));
  const shouldRefetch =
    options.forceRefetch === true || shouldRefetchForRecordKind || payload == null || hasUrlOverrideDiffersFromRecord;
  const allowPayloadFallbackOnFetchError =
    payload != null &&
    (recordKind === "applications" || !shouldRefetchForRecordKind) &&
    !hasUrlOverrideDiffersFromRecord &&
    options.forceRefetch !== true;
  emitCmDebugEvent(
    {
      phase: "cm-report-request",
      contextLabel: String(record.kind || "item"),
      method: "GET",
      url: requestUrl,
      endpointUrl: String(endpointUrl || ""),
      baseRequestUrl: String(baseRequestUrl || ""),
      cardId,
      shouldRefetch,
      hasUrlOverride: Boolean(requestUrlOverride),
      tenantId: reportTenantId,
      tenantName: reportTenantName,
      tenantScope: resolvedUsageTenantScope,
      workspaceKey: cmWorkspaceKey,
      workspaceOrigin: cmWorkspaceOrigin,
    },
    {
      flowId: resolveCmDebugFlowId(),
      context: {
        scope: String(record.kind || "report"),
        cardId,
        endpointUrl: requestUrl,
        programmerId: String(cmState?.programmer?.programmerId || ""),
        requestorId: targetRequestorId,
        mvpd: targetMvpdId,
        workspaceKey: cmWorkspaceKey,
        workspaceOrigin: cmWorkspaceOrigin,
        tenantId: reportTenantId,
        tenantName: reportTenantName,
        tenantScope: resolvedUsageTenantScope,
      },
    }
  );
  if (recordKind === "esm-health-xref") {
    try {
      const response = await cmFetchEsmHealthXrefReport(record, cmState);
      requestUrl = String(response.requestUrl || requestUrl || "").trim();
      const rows = Array.isArray(response.rows) ? response.rows : [];
      const columns = Array.isArray(response.columns) ? response.columns : cmColumnsFromRows(rows);
      lastModified = String(response.lastModified || lastModified || "").trim();
      record.columns = columns;
      if (!hasUrlOverrideDiffersFromRecord) {
        record.requestUrl = requestUrl;
        record.endpointUrl = requestUrl;
      }
      cmSendReportWorkspaceMessage(
        targetWorkspace,
        "report-result",
        {
          ...workspaceReportContext,
          ok: true,
          cardId,
          endpointUrl: requestUrl || endpointUrl,
          requestUrl,
          baseRequestUrl,
          zoomKey: String(record.kind || "").toUpperCase(),
          columns,
          rows,
          lastModified,
          localColumnFilters: normalizedLocalColumnFilters,
          tenantId: reportTenantId,
          tenantName: reportTenantName,
          programmerId: String(cmState?.programmer?.programmerId || ""),
          requestorId: targetRequestorId,
          mvpdId: targetMvpdId,
          mvpdLabel: targetMvpdLabel,
        },
        { targetWindowId }
      );
      return;
    } catch (error) {
      cmSendReportWorkspaceMessage(
        targetWorkspace,
        "report-result",
        {
          ...workspaceReportContext,
          ok: false,
          cardId,
          endpointUrl: requestUrl || endpointUrl,
          requestUrl,
          baseRequestUrl,
          localColumnFilters: normalizedLocalColumnFilters,
          tenantId: reportTenantId,
          tenantName: reportTenantName,
          error: error instanceof Error ? error.message : String(error),
          programmerId: String(cmState?.programmer?.programmerId || ""),
          requestorId: targetRequestorId,
          mvpdId: targetMvpdId,
          mvpdLabel: targetMvpdLabel,
        },
        { targetWindowId }
      );
      return;
    }
  }
  if (requestUrl && shouldRefetch) {
    try {
      const response = await fetchCmJsonWithAuthVariants([requestUrl], `CM ${record.kind || "item"} report`, {
        allowTemporaryPageContextTab: false,
        debugMeta: {
          scope: String(record.kind || "report"),
          cardId,
          endpointUrl: requestUrl,
          programmerId: String(cmState?.programmer?.programmerId || ""),
          requestorId: targetRequestorId,
          mvpd: targetMvpdId,
          workspaceKey: cmWorkspaceKey,
          workspaceOrigin: cmWorkspaceOrigin,
        },
      });
      payload = response.parsed;
      lastModified = response.lastModified || lastModified;
      if (!hasUrlOverrideDiffersFromRecord) {
        record.payload = payload;
        record.lastModified = lastModified;
      }
    } catch (error) {
      if (!allowPayloadFallbackOnFetchError) {
        cmSendReportWorkspaceMessage(
          targetWorkspace,
          "report-result",
          {
            ...workspaceReportContext,
            ok: false,
            cardId,
            endpointUrl,
            requestUrl,
            baseRequestUrl,
            localColumnFilters: normalizedLocalColumnFilters,
            tenantId: reportTenantId,
            tenantName: reportTenantName,
            error: error instanceof Error ? error.message : String(error),
            programmerId: String(cmState?.programmer?.programmerId || ""),
            requestorId: targetRequestorId,
            mvpdId: targetMvpdId,
            mvpdLabel: targetMvpdLabel,
          },
          { targetWindowId }
        );
        return;
      }
    }
  }

  const rows = cmRowsFromPayloadForRecord(payload, record, requestUrl);
  const columns = cmColumnsFromRows(rows);
  record.columns = columns;
  emitCmDebugEvent(
    {
      phase: "cm-report-result",
      contextLabel: String(record.kind || "item"),
      method: "GET",
      url: requestUrl,
      endpointUrl: String(endpointUrl || ""),
      cardId,
      rowCount: rows.length,
      columnCount: columns.length,
      emptyResult: rows.length === 0,
      tenantId: reportTenantId,
      tenantName: reportTenantName,
      tenantScope: resolvedUsageTenantScope,
      workspaceKey: cmWorkspaceKey,
      workspaceOrigin: cmWorkspaceOrigin,
    },
    {
      flowId: resolveCmDebugFlowId(),
      context: {
        scope: String(record.kind || "report"),
        cardId,
        endpointUrl: requestUrl,
        programmerId: String(cmState?.programmer?.programmerId || ""),
        requestorId: targetRequestorId,
        mvpd: targetMvpdId,
        workspaceKey: cmWorkspaceKey,
        workspaceOrigin: cmWorkspaceOrigin,
        tenantId: reportTenantId,
        tenantName: reportTenantName,
        tenantScope: resolvedUsageTenantScope,
      },
    }
  );
  cmSendReportWorkspaceMessage(
    targetWorkspace,
    "report-result",
    {
      ...workspaceReportContext,
      ok: true,
      cardId,
      endpointUrl,
      requestUrl,
      baseRequestUrl,
      zoomKey: String(record.kind || "").toUpperCase(),
      columns,
      rows,
      lastModified,
      localColumnFilters: normalizedLocalColumnFilters,
      tenantId: reportTenantId,
      tenantName: reportTenantName,
      programmerId: String(cmState?.programmer?.programmerId || ""),
      requestorId: targetRequestorId,
      mvpdId: targetMvpdId,
      mvpdLabel: targetMvpdLabel,
    },
    { targetWindowId }
  );
}

async function handleCmWorkspaceAction(message, sender = null) {
  const action = String(message?.action || "").trim().toLowerCase();
  let cmState = getActiveCmState();
  const senderWindowId = Number(sender?.tab?.windowId || 0);
  const senderTabId = Number(sender?.tab?.id || 0);
  const controllerWindowId = cmState ? Number(cmState.controllerWindowId || state.cmWorkspaceWindowId || 0) : 0;
  const mappedSenderTabId = senderWindowId > 0 ? Number(state.cmWorkspaceTabIdByWindowId.get(senderWindowId) || 0) : 0;

  if (senderWindowId > 0 && controllerWindowId > 0 && senderWindowId !== controllerWindowId) {
    return { ok: false, error: "CM controller is attached to a different window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && mappedSenderTabId > 0 && senderTabId !== mappedSenderTabId) {
    return { ok: false, error: "This is not the bound CM workspace tab for the window." };
  }
  if (senderWindowId > 0 && senderTabId > 0 && (!mappedSenderTabId || mappedSenderTabId <= 0)) {
    cmBindWorkspaceTab(senderWindowId, senderTabId);
  }
  if (cmState && senderWindowId > 0 && Number(cmState.controllerWindowId || 0) <= 0) {
    cmState.controllerWindowId = senderWindowId;
  }

  if (action === "workspace-ready") {
    if (!cmState) {
      cmState = await resolveCmStateForWorkspaceAction({
        controllerWindowId: senderWindowId || Number(state.cmWorkspaceWindowId || 0),
        reason: "workspace-ready",
      }).catch(() => null);
    }
    if (cmState) {
      void ensureCmWorkspaceActivityDebugFlow({
        reason: "cm-workspace-ready",
        preferredWindowId: senderWindowId || Number(cmState.controllerWindowId || state.cmWorkspaceWindowId || 0),
        fallbackTabId: senderTabId || mappedSenderTabId || cmGetBoundWorkspaceTabId(senderWindowId || 0),
      });
      if (senderWindowId > 0) {
        cmBindWorkspaceTab(senderWindowId, senderTabId);
      }
      cmMarkWorkspaceReady(senderWindowId || Number(cmState.controllerWindowId || state.cmWorkspaceWindowId || 0), senderTabId);
      cmBroadcastControllerState(cmState, senderWindowId);
    } else {
      const selectedProgrammer = resolveSelectedProgrammer();
      const selectedServices = selectedProgrammer?.programmerId
        ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
        : null;
      cmMarkWorkspaceReady(senderWindowId || Number(state.cmWorkspaceWindowId || 0), senderTabId);
      cmBroadcastSelectedControllerState(selectedProgrammer, selectedServices, senderWindowId);
    }
    return { ok: true, controllerOnline: Boolean(cmState) };
  }

  if (!cmState) {
    cmState = await resolveCmStateForWorkspaceAction({
      controllerWindowId: senderWindowId || Number(state.cmWorkspaceWindowId || 0),
      reason: action || "workspace-action",
    }).catch(() => null);
  }

  if (!cmState) {
    return { ok: false, error: "Select a media company with Concurrency Monitoring access to run reports." };
  }

  const requestToken = Number(state.premiumPanelRequestToken || 0);
  if (senderWindowId > 0 && Number(cmState.controllerWindowId || 0) <= 0) {
    cmState.controllerWindowId = senderWindowId;
  }
  if (!isCmServiceRequestActive(cmState.section, requestToken, cmState.programmer?.programmerId)) {
    return { ok: false, error: "CM controller is no longer active for the selected media company." };
  }
  void ensureCmWorkspaceActivityDebugFlow({
    reason: `cm-workspace-${action || "action"}`,
    preferredWindowId: senderWindowId || Number(cmState.controllerWindowId || state.cmWorkspaceWindowId || 0),
    fallbackTabId: senderTabId || mappedSenderTabId || cmGetBoundWorkspaceTabId(senderWindowId || 0),
  });

  if (action === "make-clickcmu") {
    const clickCmuContext = await resolveClickCmuDownloadContext(cmState);
    if (!clickCmuContext) {
      return { ok: false, error: "Select a media company with Concurrency Monitoring access to generate clickCMU." };
    }
    const exportResult = await makeClickCmuDownload(clickCmuContext, requestToken, {
      source: "workspace",
    });
    return {
      ok: true,
      fileName: exportResult.fileName,
      programmerLabel: exportResult.programmerLabel,
      endpointCount: Number(exportResult?.endpointCount || 0),
    };
  }

  if (action === "resolve-clickcmuws-auth") {
    const clickCmuContext = await resolveClickCmuDownloadContext(cmState);
    if (!clickCmuContext) {
      return { ok: false, error: "Select a media company with Concurrency Monitoring access to generate clickCMU workspace tearsheet." };
    }
    const authContext = await resolveClickCmuAuthContext(clickCmuContext, requestToken, {
      source: "workspace-tearsheet",
    });
    return {
      ok: true,
      programmerLabel: authContext.programmerLabel,
      accessToken: authContext.accessToken,
      clientIds: Array.isArray(authContext.clientIds) ? authContext.clientIds : [],
      userId: String(authContext.userId || ""),
      scope: String(authContext.scope || CM_IMS_CHECK_DEFAULT_SCOPE || ""),
      vaultExportPayload: buildUnderparTearsheetExportPayload(clickCmuContext?.programmer || null, {
        serviceKey: "cm",
        passVaultRecord: clickCmuContext?.passVaultRecord || null,
        mvpdIds: clickCmuContext?.mvpdId ? [clickCmuContext.mvpdId] : [],
        tenantScope:
          String(clickCmuContext?.tenantScope || "").trim() ||
          getCmTenantScopeForProgrammer(clickCmuContext?.programmer),
      }),
    };
  }

  if (action === "make-clickcmuws") {
    const cards = Array.isArray(message?.cards) ? message.cards : [];
    if (cards.length === 0) {
      return { ok: false, error: "Open at least one workspace report before generating clickCMUWS_TEARSHEET." };
    }
    const clickCmuContext = await resolveClickCmuDownloadContext(cmState);
    if (!clickCmuContext) {
      return { ok: false, error: "Select a media company with Concurrency Monitoring access to generate clickCMUWS_TEARSHEET." };
    }
    const exportResult = await makeClickCmuWorkspaceDownload(clickCmuContext, cards, requestToken, {
      source: "workspace-tearsheet",
    });
    return {
      ok: true,
      fileName: exportResult.fileName,
      programmerLabel: exportResult.programmerLabel,
      endpointCount: Number(exportResult?.endpointCount || 0),
    };
  }

  if (action === "resolve-run-context") {
    const forceRefresh = message?.forceRefresh === true;
    let accessToken = normalizeBearerTokenValue(getPreferredCmRequestAccessTokenCandidate());
    if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken) || forceRefresh || !isAccessTokenFreshEnough(accessToken, 45 * 1000)) {
      accessToken = normalizeBearerTokenValue(
        await ensureCmApiAccessToken({
          forceRefresh,
          freshLeewayMs: 45 * 1000,
          allowTemporaryPageContextTab: false,
        }).catch(() => "")
      );
    }
    const cmAuth = getCmControllerAuthPayload();
    const resolvedAccessToken = normalizeBearerTokenValue(
      firstNonEmptyString([accessToken, cmAuth?.accessToken || ""])
    );
    const resolvedCmAuth = resolvedAccessToken
      ? {
          ...(cmAuth && typeof cmAuth === "object" ? cmAuth : {}),
          accessToken: resolvedAccessToken,
        }
      : cmAuth;
    if (!normalizeBearerTokenValue(resolvedCmAuth?.accessToken || "")) {
      return {
        ok: false,
        error: "UnderPAR could not auto-hydrate a cm-console-ui bearer from the current Adobe IMS session. Sign in again and retry.",
        cmAuth: resolvedCmAuth,
      };
    }
    return {
      ok: true,
      cmAuth: resolvedCmAuth,
      tenantScope: resolveCmUsageTenantScopeValue(
        getCmPrimaryUsageTenantScopeFromState(cmState),
        cmState?.tenantScope,
        getCmTenantScopeForProgrammer(cmState?.programmer)
      ),
      programmerId: String(cmState?.programmer?.programmerId || ""),
      programmerName: String(cmState?.programmer?.programmerName || ""),
    };
  }

  if (action === "open-workspace") {
    const targetWindowId = senderWindowId || Number(cmState.controllerWindowId || 0);
    await cmEnsureWorkspaceTab({ activate: true, windowId: targetWindowId });
    cmBroadcastControllerState(cmState, targetWindowId);
    return { ok: true };
  }

  if (action === "run-card") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    const requestSourceRaw = String(message?.requestSource || "").trim().toLowerCase();
    const requestSource = requestSourceRaw || "workspace";
    const shouldForceRefetch = message?.forceRefetch !== false;
    const requestUrlOverride = String(card?.requestUrl || "").trim();
    const baseRequestUrl = String(card?.baseRequestUrl || card?.endpointUrl || requestUrlOverride || "").trim();
    const localColumnFilters = card?.localColumnFilters && typeof card.localColumnFilters === "object" ? card.localColumnFilters : {};
    const matchedRecord = cmFindRecordByCard(cmState, card);
    if (!matchedRecord) {
      const fallbackUrl = String(card?.requestUrl || card?.endpointUrl || "").trim();
      if (!fallbackUrl) {
        return { ok: false, error: "CM card request URL is missing." };
      }
      const fallbackRecord = cmBuildFallbackRecordFromCard(cmState, card, {
        tenantIdCandidates: [
          String(cmState?.tenantScope || "").trim(),
          String(cmState?.programmer?.programmerId || "").trim(),
          String(card?.tenantId || "").trim(),
        ],
        tenantNameCandidates: [
          String(cmState?.programmer?.programmerName || "").trim(),
          String(cmState?.programmer?.programmerId || "").trim(),
          String(card?.tenantName || "").trim(),
          String(card?.tenantId || "").trim(),
          "CM",
        ],
      });
      await cmRunRecordToWorkspace(
        cmState,
        fallbackRecord,
        requestToken,
        {
          emitStart: true,
          forceRefetch: shouldForceRefetch,
          cardId: String(card.cardId || generateRequestId()),
          targetWindowId: senderWindowId || Number(cmState.controllerWindowId || 0),
          requestSource,
          requestUrlOverride: requestUrlOverride || fallbackUrl,
          baseRequestUrl: baseRequestUrl || fallbackUrl,
          localColumnFilters,
          seedEndpointUrl: String(card?.seedEndpointUrl || ""),
          seedRequestUrl: String(card?.seedRequestUrl || ""),
          seedBaseRequestUrl: String(card?.seedBaseRequestUrl || ""),
          seedLocalColumnFilters: card?.seedLocalColumnFilters && typeof card.seedLocalColumnFilters === "object" ? card.seedLocalColumnFilters : {},
        }
      );
      return { ok: true };
    }

    await cmRunRecordToWorkspace(cmState, matchedRecord, requestToken, {
      emitStart: true,
      forceRefetch: shouldForceRefetch,
      cardId: String(card?.cardId || matchedRecord.cardId || generateRequestId()),
      targetWindowId: senderWindowId || Number(cmState.controllerWindowId || 0),
      requestSource,
      requestUrlOverride,
      baseRequestUrl: baseRequestUrl || String(matchedRecord.requestUrl || matchedRecord.endpointUrl || ""),
      localColumnFilters,
      seedEndpointUrl: String(card?.seedEndpointUrl || ""),
      seedRequestUrl: String(card?.seedRequestUrl || ""),
      seedBaseRequestUrl: String(card?.seedBaseRequestUrl || ""),
      seedLocalColumnFilters: card?.seedLocalColumnFilters && typeof card.seedLocalColumnFilters === "object" ? card.seedLocalColumnFilters : {},
    });
    return { ok: true };
  }

  if (action === "run-api-operation") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    const formValues = message?.formValues && typeof message.formValues === "object" ? message.formValues : {};
    let matchedRecord = cmFindRecordByCard(cmState, card);
    if ((!matchedRecord || String(matchedRecord?.kind || "").toLowerCase() !== "cmv2-op") && card?.operation) {
      matchedRecord = {
        cardId: String(card?.cardId || generateRequestId()),
        kind: "cmv2-op",
        title: String(card?.operation?.label || "CM V2 Operation"),
        subtitle: `${String(card?.operation?.method || "GET").toUpperCase()} ${String(card?.operation?.pathTemplate || "").trim()}`,
        endpointUrl: String(card?.endpointUrl || ""),
        requestUrl: String(card?.requestUrl || card?.endpointUrl || ""),
        payload: {
          operation: card.operation,
          formDefaults: { ...formValues },
        },
        columns: Array.isArray(card?.columns) ? card.columns.map((value) => String(value || "")).filter(Boolean) : [],
      };
    }
    if (!matchedRecord || String(matchedRecord?.kind || "").toLowerCase() !== "cmv2-op") {
      return { ok: false, error: "CM V2 API operation record could not be resolved." };
    }
    await cmRunRecordToWorkspace(cmState, matchedRecord, requestToken, {
      emitForm: false,
      execute: true,
      formValues,
      cardId: String(card?.cardId || matchedRecord.cardId || generateRequestId()),
      targetWindowId: senderWindowId || Number(cmState.controllerWindowId || 0),
    });
    return { ok: true };
  }

  if (action === "download-csv") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    const sortRule = esmWorkspaceNormalizeSortRule(message?.sortRule);
    const matchedRecord = cmFindRecordByCard(cmState, card);
    const fallbackUrl = String(card?.requestUrl || card?.endpointUrl || "").trim();
    const fallbackRecord = cmBuildFallbackRecordFromCard(cmState, card, {
      tenantIdCandidates: [
        String(cmState?.tenantScope || "").trim(),
        String(cmState?.programmer?.programmerId || "").trim(),
        String(card?.tenantId || "").trim(),
      ],
      tenantNameCandidates: [
        String(cmState?.programmer?.programmerName || "").trim(),
        String(cmState?.programmer?.programmerId || "").trim(),
        String(card?.tenantName || "").trim(),
        String(card?.tenantId || "").trim(),
        "CM",
      ],
    });
    fallbackRecord.columns = Array.isArray(card?.columns)
      ? card.columns.map((value) => String(value || "")).filter(Boolean)
      : [];
    const record = matchedRecord || fallbackRecord;
    if (!matchedRecord && !fallbackUrl && (!Array.isArray(card?.rows) || card.rows.length === 0)) {
      return { ok: false, error: "CM card request URL is missing." };
    }

    const csvResult = await cmDownloadCsvForCard(cmState, record, card, sortRule, requestToken);
    if (!csvResult?.ok) {
      return { ok: false, error: csvResult?.error || "Unable to download CM CSV." };
    }
    return { ok: true, fileName: csvResult.fileName || "" };
  }

  if (action === "blondie-export") {
    const card = message?.card && typeof message.card === "object" ? message.card : {};
    const exportPayload = withUnderparBlondieCsvFileName(
      message?.exportPayload || null,
      buildUnderparBlondieCmCsvFileName(cmState, card, {
        tenantIdCandidates: [
          String(cmState?.tenantScope || "").trim(),
          String(cmState?.programmer?.programmerId || "").trim(),
          String(card?.tenantId || "").trim(),
        ],
        tenantNameCandidates: [
          String(cmState?.programmer?.programmerName || "").trim(),
          String(cmState?.programmer?.programmerId || "").trim(),
          String(card?.tenantName || "").trim(),
          String(card?.tenantId || "").trim(),
          "CM",
        ],
      })
    );
    return await sendUnderparBlondieExportToSlack(exportPayload, {
      interactive: true,
      deliveryTarget: message?.deliveryTarget || null,
      noteText: message?.noteText || "",
    });
  }

  if (action === "rerun-all") {
    const cards = Array.isArray(message?.cards) ? message.cards : [];
    const reason = String(message?.reason || "").trim().toLowerCase();
    const requestSourceForRerun = reason === "programmer-switch" ? "workspace-programmer-switch" : "workspace";
    const targetWindowId = senderWindowId || Number(cmState.controllerWindowId || 0);
    const workspaceReportContext = cmBuildWorkspaceReportContextPayload(cmState, requestToken);
    void cmSendWorkspaceMessage(
      "batch-start",
      {
        ...workspaceReportContext,
        total: cards.length,
        reason,
        startedAt: Date.now(),
      },
      { targetWindowId }
    );
    for (const card of cards) {
      const preserveCardRequestContext = reason !== "manual-reload" || cmCardHasExplicitRequestContext(card);
      let record = cmFindRecordByCard(cmState, card);
      if (!record && card?.operation && typeof card.operation === "object") {
        record = {
          cardId: String(card?.cardId || generateRequestId()),
          kind: "cmv2-op",
          title: String(card?.operation?.label || "CM V2 Operation"),
          subtitle: `${String(card?.operation?.method || "GET").toUpperCase()} ${String(card?.operation?.pathTemplate || "").trim()}`,
          endpointUrl: String(card?.endpointUrl || ""),
          requestUrl: String(card?.requestUrl || card?.endpointUrl || ""),
          payload: {
            operation: card.operation,
            formDefaults: card?.formValues && typeof card.formValues === "object" ? { ...card.formValues } : {},
          },
          columns: Array.isArray(card?.columns) ? card.columns.map((value) => String(value || "")).filter(Boolean) : [],
        };
      }
      if (!record) {
        const fallbackEndpointUrl = String(card?.endpointUrl || "").trim();
        const fallbackRequestUrl = preserveCardRequestContext
          ? String(card?.requestUrl || fallbackEndpointUrl || "").trim()
          : String(fallbackEndpointUrl || card?.baseRequestUrl || card?.requestUrl || "").trim();
        const fallbackBaseRequestUrl = preserveCardRequestContext
          ? String(card?.baseRequestUrl || fallbackEndpointUrl || fallbackRequestUrl || "").trim()
          : String(fallbackEndpointUrl || card?.baseRequestUrl || card?.requestUrl || "").trim();
        const fallbackCardContext = {
          ...(card && typeof card === "object" ? card : {}),
          endpointUrl: fallbackEndpointUrl || fallbackBaseRequestUrl || fallbackRequestUrl,
          requestUrl: fallbackRequestUrl || fallbackBaseRequestUrl || fallbackEndpointUrl,
          baseRequestUrl: fallbackBaseRequestUrl || fallbackRequestUrl || fallbackEndpointUrl,
        };
        record = cmBuildFallbackRecordFromCard(cmState, fallbackCardContext, {
          tenantIdCandidates: [
            String(cmState?.tenantScope || "").trim(),
            String(cmState?.programmer?.programmerId || "").trim(),
            String(card?.tenantId || "").trim(),
          ],
          tenantNameCandidates: [
            String(cmState?.programmer?.programmerName || "").trim(),
            String(cmState?.programmer?.programmerId || "").trim(),
            String(card?.tenantName || "").trim(),
            String(card?.tenantId || "").trim(),
            "CM",
          ],
        });
        if (record && !String(record.requestUrl || record.endpointUrl || "").trim()) {
          record.requestUrl = fallbackRequestUrl || fallbackBaseRequestUrl;
          record.endpointUrl = fallbackBaseRequestUrl || fallbackRequestUrl;
        }
      }
      if (!record) {
        continue;
      }
      if (String(record?.kind || "").toLowerCase() === "cmv2-op") {
        await cmRunRecordToWorkspace(cmState, record, requestToken, {
          emitForm: false,
          execute: true,
          formValues: card?.formValues && typeof card.formValues === "object" ? card.formValues : {},
          cardId: String(card?.cardId || record.cardId || generateRequestId()),
          targetWindowId,
        });
        continue;
      }
      const requestUrlOverride = preserveCardRequestContext ? String(card?.requestUrl || "").trim() : "";
      const baseRequestUrl = preserveCardRequestContext
        ? String(card?.baseRequestUrl || card?.requestUrl || record.requestUrl || record.endpointUrl || "").trim()
        : String(record.requestUrl || record.endpointUrl || card?.baseRequestUrl || card?.requestUrl || "").trim();
      await cmRunRecordToWorkspace(cmState, record, requestToken, {
        emitStart: true,
        forceRefetch: true,
        cardId: String(card?.cardId || record.cardId || generateRequestId()),
        targetWindowId,
        requestSource: requestSourceForRerun,
        requestUrlOverride,
        baseRequestUrl,
        localColumnFilters: card?.localColumnFilters && typeof card.localColumnFilters === "object" ? card.localColumnFilters : {},
        seedEndpointUrl: String(card?.seedEndpointUrl || ""),
        seedRequestUrl: String(card?.seedRequestUrl || ""),
        seedBaseRequestUrl: String(card?.seedBaseRequestUrl || ""),
        seedLocalColumnFilters: card?.seedLocalColumnFilters && typeof card.seedLocalColumnFilters === "object" ? card.seedLocalColumnFilters : {},
      });
    }
    void cmSendWorkspaceMessage(
      "batch-end",
      {
        ...workspaceReportContext,
        total: cards.length,
        reason,
        completedAt: Date.now(),
      },
      { targetWindowId }
    );
    return { ok: true };
  }

  return { ok: false, error: `Unsupported CM workspace action: ${action}` };
}

function ensureCmRuntimeListener() {
  if (state.cmRuntimeListenerBound) {
    return;
  }
  chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
    if (!CM_MESSAGE_TYPES.has(String(message?.type || "")) || message?.channel !== "workspace-action") {
      return false;
    }
    void handleCmWorkspaceAction(message, sender)
      .then((result) => {
        sendResponse(result && typeof result === "object" ? result : { ok: true });
      })
      .catch((error) => {
        sendResponse({ ok: false, error: error instanceof Error ? error.message : String(error) });
      });
    return true;
  });
  state.cmRuntimeListenerBound = true;
}

function ensureCmWorkspaceTabWatcher() {
  if (state.cmWorkspaceTabWatcherBound) {
    return;
  }
  chrome.tabs.onRemoved.addListener((tabId) => {
    cmUnbindWorkspaceTab(tabId);
  });
  chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
    const normalizedTabId = Number(tabId || 0);
    if (!normalizedTabId || !changeInfo?.url) {
      return;
    }
    if (cmIsWorkspaceTab(tab)) {
      cmBindWorkspaceTab(tab?.windowId, normalizedTabId);
      return;
    }
    const boundTabId = Number(state.cmWorkspaceTabId || 0);
    let isMappedTab = false;
    for (const mappedTabId of state.cmWorkspaceTabIdByWindowId.values()) {
      if (Number(mappedTabId || 0) === normalizedTabId) {
        isMappedTab = true;
        break;
      }
    }
    if (isMappedTab || normalizedTabId === boundTabId) {
      cmUnbindWorkspaceTab(normalizedTabId);
    }
  });
  state.cmWorkspaceTabWatcherBound = true;
}

function mvpdWorkspaceGetWorkspaceUrl() {
  return chrome.runtime.getURL(MVPD_WORKSPACE_PATH);
}

function mvpdWorkspaceIsWorkspaceTab(tabLike) {
  return String(tabLike?.url || "").startsWith(mvpdWorkspaceGetWorkspaceUrl());
}

function mvpdWorkspaceBindWorkspaceTab(windowId, tabId) {
  const normalizedWindowId = Number(windowId || 0);
  const normalizedTabId = Number(tabId || 0);
  if (normalizedWindowId > 0 && normalizedTabId > 0) {
    state.mvpdWorkspaceTabIdByWindowId.set(normalizedWindowId, normalizedTabId);
  }
  if (normalizedWindowId > 0) {
    state.mvpdWorkspaceWindowId = normalizedWindowId;
  }
  if (normalizedTabId > 0) {
    state.mvpdWorkspaceTabId = normalizedTabId;
  }
}

function mvpdWorkspaceUnbindWorkspaceTab(tabId) {
  const normalizedTabId = Number(tabId || 0);
  if (normalizedTabId > 0) {
    for (const [windowId, mappedTabId] of state.mvpdWorkspaceTabIdByWindowId.entries()) {
      if (Number(mappedTabId || 0) === normalizedTabId) {
        state.mvpdWorkspaceTabIdByWindowId.delete(windowId);
      }
    }
  }
  if (!normalizedTabId || Number(state.mvpdWorkspaceTabId || 0) === normalizedTabId) {
    state.mvpdWorkspaceTabId = 0;
    state.mvpdWorkspaceWindowId = 0;
  }
}

function mvpdWorkspaceGetBoundWorkspaceTabId(windowId) {
  const normalizedWindowId = Number(windowId || 0);
  if (normalizedWindowId > 0) {
    const mapped = Number(state.mvpdWorkspaceTabIdByWindowId.get(normalizedWindowId) || 0);
    if (mapped > 0) {
      return mapped;
    }
  }
  return Number(state.mvpdWorkspaceTabId || 0);
}

function mvpdWorkspaceGetSelectionContext(programmer = null, services = null) {
  const resolvedProgrammer = programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
  let resolvedServices = services;
  if (!resolvedServices && resolvedProgrammer?.programmerId) {
    resolvedServices = getCurrentPremiumAppsSnapshot(resolvedProgrammer.programmerId);
  }
  const requestorId = String(state.selectedRequestorId || "").trim();
  const mvpdId = String(state.selectedMvpdId || "").trim();
  const hasRestV2Service = Boolean(String(resolvedServices?.restV2?.guid || "").trim());
  const cmMvpdService = resolvedServices?.cmMvpd && typeof resolvedServices.cmMvpd === "object" ? resolvedServices.cmMvpd : null;
  const cmMvpdMatchedTenants = Array.isArray(cmMvpdService?.matchedTenants) ? cmMvpdService.matchedTenants : [];
  const mvpdCmTenantScope = resolveCmUsageTenantScopeValue(
    cmMvpdMatchedTenants?.[0]?.tenantId,
    cmMvpdMatchedTenants?.[0]?.tenantName
  );
  const hasMvpdCmTenant = Boolean(mvpdCmTenantScope);
  return {
    programmer: resolvedProgrammer,
    services: resolvedServices,
    programmerId: String(resolvedProgrammer?.programmerId || "").trim(),
    programmerName: String(resolvedProgrammer?.programmerName || "").trim(),
    requestorId,
    mvpdId,
    hasRestV2Service,
    hasMvpdCmTenant,
    mvpdCmTenantScope,
    cmMvpdTenantCount: cmMvpdMatchedTenants.length,
    isReady: Boolean(String(resolvedProgrammer?.programmerId || "").trim() && requestorId && mvpdId),
  };
}

function mvpdWorkspaceGetSelectionMvpdLabel(selectionContext = null) {
  const context =
    selectionContext && typeof selectionContext === "object" ? selectionContext : mvpdWorkspaceGetSelectionContext();
  if (!context?.mvpdId) {
    return "";
  }
  return getRestV2MvpdPickerLabel(context.requestorId, context.mvpdId);
}

function mvpdWorkspaceGetSelectedControllerStatePayload(programmer = null, services = null) {
  const context = mvpdWorkspaceGetSelectionContext(programmer, services);
  const mvpdLabel = mvpdWorkspaceGetSelectionMvpdLabel(context);
  const mvpdMeta = context.mvpdId ? getRestV2MvpdMeta(context.requestorId, context.mvpdId) : null;
  const requestorMvpdLabel =
    context.requestorId && context.mvpdId
      ? formatRestV2RequestorMvpdDisplay(context.requestorId, context.mvpdId, mvpdMeta, { separator: " x " })
      : "";
  const cacheKey = mvpdWorkspaceGetSnapshotCacheKey(context);
  const cachedSnapshot = cacheKey ? state.mvpdWorkspaceSnapshotCacheBySelectionKey.get(cacheKey) || null : null;
  return {
    controllerOnline: true,
    slack: getUnderparWorkspaceSlackStatePayload(),
    adobePassEnvironment: {
      ...getActiveAdobePassEnvironment(),
    },
    mvpdReady: context.isReady,
    hasRestV2Service: context.hasRestV2Service,
    hasMvpdCmTenant: context.hasMvpdCmTenant === true,
    mvpdCmTenantScope: String(context.mvpdCmTenantScope || "").trim(),
    cmMvpdTenantCount: Number(context.cmMvpdTenantCount || 0),
    programmerId: context.programmerId,
    programmerName: context.programmerName,
    requestorId: context.requestorId,
    mvpdId: context.mvpdId,
    requestorIds: context.requestorId ? [context.requestorId] : [],
    mvpdIds: context.mvpdId ? [context.mvpdId] : [],
    mvpdLabel,
    mvpdLabels: mvpdLabel ? [mvpdLabel] : [],
    requestorMvpdLabel,
    resolvedIntegration: String(cachedSnapshot?.resolvedIntegration || "").trim(),
    integrationRef: String(cachedSnapshot?.integrationRef || cachedSnapshot?.resolvedIntegration || "").trim(),
    integrationRecordUrl: String(cachedSnapshot?.integrationRecordUrl || "").trim(),
    updatedAt: Date.now(),
  };
}

async function mvpdWorkspaceSendWorkspaceMessage(event, payload = {}, options = {}) {
  const targetWindowId = Number(options.targetWindowId || 0);
  try {
    const message = {
      type: MVPD_WORKSPACE_MESSAGE_TYPE,
      channel: "workspace-event",
      event: String(event || ""),
      payload,
    };
    if (targetWindowId > 0) {
      message.targetWindowId = targetWindowId;
    }
    await chrome.runtime.sendMessage(message);
  } catch {
    // Ignore when workspace listener is inactive.
  }
}

function mvpdWorkspaceBroadcastSelectedControllerState(programmer = null, services = null, targetWindowId = 0) {
  const resolvedWindowId = Number(targetWindowId || 0) || Number(state.mvpdWorkspaceWindowId || 0);
  void mvpdWorkspaceSendWorkspaceMessage(
    "controller-state",
    mvpdWorkspaceGetSelectedControllerStatePayload(programmer, services),
    {
      targetWindowId: resolvedWindowId,
    }
  );
}

async function mvpdWorkspaceEnsureWorkspaceTab(options = {}) {
  ensureMvpdWorkspaceRuntimeListener();
  ensureMvpdWorkspaceTabWatcher();
  const shouldActivate = options.activate !== false;
  const requestedWindowId = Number(options.windowId || 0);
  const targetWindowId = requestedWindowId > 0 ? requestedWindowId : await esmWorkspaceGetCurrentWindowId();
  const useWindowFilter = targetWindowId > 0;
  let workspaceTab = null;

  const boundTabId = mvpdWorkspaceGetBoundWorkspaceTabId(targetWindowId);
  if (boundTabId > 0) {
    try {
      const existing = await chrome.tabs.get(boundTabId);
      if (mvpdWorkspaceIsWorkspaceTab(existing) && (!useWindowFilter || Number(existing.windowId || 0) === targetWindowId)) {
        workspaceTab = existing;
      }
    } catch {
      mvpdWorkspaceUnbindWorkspaceTab(boundTabId);
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    try {
      const allTabs = await chrome.tabs.query(useWindowFilter ? { windowId: targetWindowId } : { currentWindow: true });
      workspaceTab = allTabs.find((tab) => mvpdWorkspaceIsWorkspaceTab(tab)) || null;
    } catch {
      workspaceTab = null;
    }
  }

  if (!workspaceTab) {
    workspaceTab = await chrome.tabs.create({
      url: mvpdWorkspaceGetWorkspaceUrl(),
      active: shouldActivate,
      ...(useWindowFilter ? { windowId: targetWindowId } : {}),
    });
  } else if (shouldActivate && workspaceTab.id) {
    try {
      workspaceTab = await chrome.tabs.update(workspaceTab.id, { active: true });
      if (Number(workspaceTab?.windowId || 0) > 0) {
        await chrome.windows.update(Number(workspaceTab.windowId), { focused: true });
      }
    } catch {
      // Ignore activation failures.
    }
  }

  mvpdWorkspaceBindWorkspaceTab(workspaceTab?.windowId, workspaceTab?.id);
  return workspaceTab;
}

function mvpdWorkspaceNormalizeFlatValue(value) {
  const normalized = redactSensitiveTokenValues(String(value || ""))
    .replace(/\s+/g, " ")
    .trim();
  if (!normalized) {
    return "";
  }
  if (normalized.length > 260) {
    return `${normalized.slice(0, 257)}...`;
  }
  return normalized;
}

function mvpdWorkspaceCollectFlatEntries(sourceKey, value, options = {}) {
  const maxEntries = Math.max(50, Number(options.maxEntries || 1200));
  const maxDepth = Math.max(2, Number(options.maxDepth || 6));
  const flattened = [];
  flattenPrimitiveFields(value, "", flattened, {
    depth: 0,
    maxDepth,
    maxEntries,
    seen: new WeakSet(),
  });
  return flattened
    .map((entry) => {
      const path = String(entry?.key || "").trim();
      const entryValue = mvpdWorkspaceNormalizeFlatValue(entry?.value);
      if (!path || !entryValue) {
        return null;
      }
      return {
        source: String(sourceKey || ""),
        path,
        value: entryValue,
      };
    })
    .filter(Boolean);
}

function mvpdWorkspaceExtractConfigurationVersion(payload = null, fallback = 0) {
  const fallbackValue = Number.isFinite(Number(fallback)) ? Number(fallback) : 0;
  const coerceConfigurationVersion = (value) => {
    if (typeof value === "number") {
      return Number.isFinite(value) && value >= 0 ? value : null;
    }
    if (typeof value === "string") {
      const trimmed = value.trim();
      if (!trimmed) {
        return null;
      }
      const match = trimmed.match(/^\d+$/);
      return match ? Number(match[0]) : null;
    }
    return null;
  };

  if (payload == null) {
    return fallbackValue;
  }
  const directPrimitive = coerceConfigurationVersion(payload);
  if (directPrimitive !== null) {
    return directPrimitive;
  }
  if (Array.isArray(payload)) {
    for (const item of payload) {
      const nested = mvpdWorkspaceExtractConfigurationVersion(item, Number.NaN);
      if (Number.isFinite(nested) && nested >= 0) {
        return nested;
      }
    }
    return fallbackValue;
  }
  if (typeof payload === "object") {
    const directFieldCandidates = [
      payload.configurationVersion,
      payload.latestActivatedConsoleConfigurationVersion,
      payload.configuration_version,
      payload.latest_activated_console_configuration_version,
      payload.version,
      payload.value,
    ];
    for (const candidate of directFieldCandidates) {
      const direct = coerceConfigurationVersion(candidate);
      if (direct !== null) {
        return direct;
      }
    }

    const nestedCandidates = [
      payload.configurationInfo,
      payload.configuration_info,
      payload.data,
      payload.response,
      payload.result,
      payload.body,
    ];
    for (const nestedValue of nestedCandidates) {
      const nested = mvpdWorkspaceExtractConfigurationVersion(nestedValue, Number.NaN);
      if (Number.isFinite(nested) && nested >= 0) {
        return nested;
      }
    }
  }
  return fallbackValue;
}

function mvpdWorkspaceCollectSectionEntries(entries = [], pattern, maxEntries = 200) {
  if (!(pattern instanceof RegExp)) {
    return [];
  }
  const output = [];
  const seen = new Set();
  (Array.isArray(entries) ? entries : []).forEach((entry) => {
    if (output.length >= maxEntries) {
      return;
    }
    const path = String(entry?.path || "").trim();
    const value = String(entry?.value || "").trim();
    const hay = `${path} ${value}`;
    if (!pattern.test(hay)) {
      return;
    }
    const key = `${entry?.source || ""}|${path}|${value}`.toLowerCase();
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push({
      source: String(entry?.source || "").trim(),
      path,
      value,
    });
  });
  return output;
}

function mvpdWorkspaceCollectChipValues(entries = [], pathRegex, valueRegex = null, maxValues = 120) {
  const output = [];
  const seen = new Set();
  const pushValue = (value) => {
    const normalized = String(value || "").trim();
    if (!normalized) {
      return;
    }
    const key = normalized.toLowerCase();
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push(normalized);
  };

  (Array.isArray(entries) ? entries : []).forEach((entry) => {
    if (output.length >= maxValues) {
      return;
    }
    const path = String(entry?.path || "").trim();
    const value = String(entry?.value || "").trim();
    if (!path || !value) {
      return;
    }
    const pathMatches = pathRegex instanceof RegExp ? pathRegex.test(path) : false;
    const valueMatches = valueRegex instanceof RegExp ? valueRegex.test(value) : false;
    if (!pathMatches && !valueMatches) {
      return;
    }
    const parts = value.split(/[\\n,;|]+/g).map((part) => part.trim()).filter(Boolean);
    if (parts.length > 1) {
      parts.forEach((part) => {
        if (output.length < maxValues) {
          pushValue(part);
        }
      });
    } else {
      pushValue(value);
    }
  });

  return output.slice(0, maxValues);
}

function mvpdWorkspaceFilterChipValues(values = [], maxValues = 120) {
  const output = [];
  const seen = new Set();
  const blocked = new Set(["", "null", "true", "false", "undefined", "n/a", "na", "none", "[]", "{}"]);
  (Array.isArray(values) ? values : []).forEach((value) => {
    if (output.length >= maxValues) {
      return;
    }
    const normalized = String(value || "").trim();
    const lowered = normalized.toLowerCase();
    if (!normalized || blocked.has(lowered) || normalized.length > 220) {
      return;
    }
    if (!/[a-z0-9]/i.test(normalized)) {
      return;
    }
    if (seen.has(lowered)) {
      return;
    }
    seen.add(lowered);
    output.push(normalized);
  });
  return output.slice(0, maxValues);
}

function mvpdWorkspaceBuildMappedChipValues(entries = [], maxValues = 120) {
  const output = [];
  const seen = new Set();
  const blocked = new Set(["", "null", "true", "false", "undefined", "n/a", "na", "none", "[]", "{}"]);
  (Array.isArray(entries) ? entries : []).forEach((entry) => {
    if (output.length >= maxValues) {
      return;
    }
    const label = String(entry?.label || entry?.value || "").trim();
    const rawValue = String(entry?.rawValue || entry?.value || "").trim();
    const lowered = label.toLowerCase();
    if (!label || blocked.has(lowered) || label.length > 220) {
      return;
    }
    if (!/[a-z0-9]/i.test(label)) {
      return;
    }
    const rawKey = rawValue.toLowerCase();
    const dedupeKey = `${lowered}|${rawKey}`;
    if (seen.has(dedupeKey)) {
      return;
    }
    seen.add(dedupeKey);
    output.push({
      label,
      rawValue,
    });
  });
  return output.slice(0, maxValues);
}

function mvpdWorkspaceIsLikelyResourceId(value = "") {
  const normalized = String(value || "").trim();
  if (!normalized) {
    return false;
  }
  const lowered = normalized.toLowerCase();
  if (normalized.startsWith("@")) {
    return false;
  }
  if (/(authenticationproviderconfiguration|authorizationproviderconfiguration|logoutproviderconfiguration)/i.test(lowered)) {
    return false;
  }
  if (/(integrationconfiguration|platformconfiguration|serviceprovider|mvpd:)/i.test(lowered)) {
    return false;
  }
  if (/^[a-z]+:[a-z0-9._-]+$/i.test(normalized) && !/^urn:/i.test(normalized)) {
    return false;
  }
  if (!/[a-z0-9]/i.test(normalized)) {
    return false;
  }
  return true;
}

function mvpdWorkspaceNormalizeEntityRef(value) {
  const normalized = String(value || "").trim();
  return normalized.startsWith("@") ? normalized.slice(1) : normalized;
}

function mvpdWorkspaceSplitEntityRef(value) {
  const normalized = mvpdWorkspaceNormalizeEntityRef(value);
  if (!normalized) {
    return { ref: "", type: "", id: "" };
  }
  const separatorIndex = normalized.indexOf(":");
  if (separatorIndex <= 0) {
    return { ref: normalized, type: "", id: normalized };
  }
  return {
    ref: normalized,
    type: normalized.slice(0, separatorIndex),
    id: normalized.slice(separatorIndex + 1),
  };
}

function mvpdWorkspaceExtractEntityList(payload = null) {
  if (Array.isArray(payload?.entities)) {
    return payload.entities.filter((entry) => entry && typeof entry === "object");
  }
  if (Array.isArray(payload)) {
    return payload.filter((entry) => entry && typeof entry === "object");
  }
  if (payload && typeof payload === "object" && (payload.key || payload.entityData)) {
    return [payload];
  }
  return [];
}

function mvpdWorkspaceFindEntityById(payload = null, targetId = "", typePrefix = "") {
  const normalizedId = String(targetId || "").trim().toLowerCase();
  if (!normalizedId) {
    return null;
  }
  const normalizedType = String(typePrefix || "").trim().toLowerCase();
  const entities = mvpdWorkspaceExtractEntityList(payload);
  for (const entity of entities) {
    const key = String(entity?.key || "").trim();
    const keyLower = key.toLowerCase();
    const keyType = keyLower.includes(":") ? keyLower.split(":")[0] : "";
    if (normalizedType && keyType && keyType !== normalizedType) {
      continue;
    }
    const entityId = firstNonEmptyString([
      entity?.entityData?.id,
      key.includes(":") ? key.split(":").slice(1).join(":") : "",
      entity?.id,
    ]);
    const entityIdLower = String(entityId || "").trim().toLowerCase();
    if (entityIdLower && entityIdLower === normalizedId) {
      return entity;
    }
    if (keyLower.endsWith(`:${normalizedId}`) && (!normalizedType || keyType === normalizedType)) {
      return entity;
    }
  }
  return null;
}

function mvpdWorkspaceFindServiceProviderEntity(payload = null, requestorId = "") {
  return mvpdWorkspaceFindEntityById(payload, requestorId, "serviceprovider");
}

function mvpdWorkspaceFindIntegrationRefFromServiceProvider(serviceProviderEntity = null, mvpdId = "") {
  const normalizedMvpd = String(mvpdId || "").trim().toLowerCase();
  const integrations = serviceProviderEntity?.entityData?.integrations;
  if (!normalizedMvpd || !integrations || typeof integrations !== "object") {
    return "";
  }
  let fallback = "";
  for (const [ownerKey, integrationRef] of Object.entries(integrations)) {
    const normalizedOwner = mvpdWorkspaceNormalizeEntityRef(ownerKey).toLowerCase();
    const normalizedRef = mvpdWorkspaceNormalizeEntityRef(integrationRef);
    if (!normalizedRef) {
      continue;
    }
    if (normalizedOwner === `mvpd:${normalizedMvpd}` || normalizedOwner === `mvpdproxy:${normalizedMvpd}`) {
      return normalizedRef;
    }
    if (!fallback && normalizedOwner.endsWith(`:${normalizedMvpd}`)) {
      fallback = normalizedRef;
    }
  }
  return fallback;
}

function mvpdWorkspaceFindIntegrationEntity(payload = null, context = null, integrationRef = "", serviceProviderEntity = null) {
  const entities = mvpdWorkspaceExtractEntityList(payload);
  if (entities.length === 0) {
    return null;
  }

  const normalizedRef = mvpdWorkspaceNormalizeEntityRef(integrationRef).toLowerCase();
  if (normalizedRef) {
    const { id: refId } = mvpdWorkspaceSplitEntityRef(normalizedRef);
    const directMatch = entities.find((entity) => {
      const keyLower = String(entity?.key || "").trim().toLowerCase();
      const idLower = String(entity?.entityData?.id || "").trim().toLowerCase();
      return keyLower === normalizedRef || (refId && idLower === refId);
    });
    if (directMatch) {
      return directMatch;
    }
  }

  const normalizedRequestor = String(context?.requestorId || "").trim().toLowerCase();
  const normalizedMvpd = String(context?.mvpdId || "").trim().toLowerCase();
  const guessedId = normalizedRequestor && normalizedMvpd ? `${normalizedRequestor}_${normalizedMvpd}` : "";
  let fallback = null;
  for (const entity of entities) {
    const entityData = entity?.entityData || {};
    const entityId = String(entityData?.id || "").trim().toLowerCase();
    if (guessedId && entityId === guessedId) {
      return entity;
    }
    const owner = mvpdWorkspaceNormalizeEntityRef(entityData?.owner).toLowerCase();
    const serviceProvider = mvpdWorkspaceNormalizeEntityRef(entityData?.serviceProvider).toLowerCase();
    const ownerMatch = normalizedMvpd ? owner.endsWith(`:${normalizedMvpd}`) : false;
    const serviceMatch = normalizedRequestor ? serviceProvider.endsWith(`:${normalizedRequestor}`) : true;
    if (ownerMatch && serviceMatch) {
      if (
        serviceProviderEntity &&
        serviceProvider &&
        serviceProvider === `serviceprovider:${normalizedRequestor}`
      ) {
        return entity;
      }
      fallback = fallback || entity;
    }
  }
  return fallback;
}

function mvpdWorkspaceCollectEntityRefs(value, outputSet = new Set(), options = {}) {
  const maxRefs = Math.max(20, Number(options.maxRefs || 180));
  const maxDepth = Math.max(2, Number(options.maxDepth || 5));
  const seenObjects = options.seenObjects instanceof WeakSet ? options.seenObjects : new WeakSet();

  const walk = (current, depth) => {
    if (outputSet.size >= maxRefs || current == null || depth > maxDepth) {
      return;
    }
    if (typeof current === "string") {
      const normalized = mvpdWorkspaceNormalizeEntityRef(current).replace(/[),.;]+$/g, "");
      if (/^[A-Z][A-Za-z0-9]+:[^\s]+$/.test(normalized)) {
        outputSet.add(normalized);
      }
      return;
    }
    if (Array.isArray(current)) {
      for (const entry of current) {
        if (outputSet.size >= maxRefs) {
          break;
        }
        walk(entry, depth + 1);
      }
      return;
    }
    if (typeof current === "object") {
      if (seenObjects.has(current)) {
        return;
      }
      seenObjects.add(current);
      const values = Object.values(current);
      for (const valueEntry of values) {
        if (outputSet.size >= maxRefs) {
          break;
        }
        walk(valueEntry, depth + 1);
      }
    }
  };

  walk(value, 0);
  return outputSet;
}

