const MVPD_WORKSPACE_DOS_FIELDS = ["failedAttempts", "deltaTime", "banInterval", "enabled"];
const MVPD_WORKSPACE_PREFLIGHT_FIELDS = ["isolated", "executorWaitTimeout", "type", "maxNumberOfResources"];
