async function degradationOpenWorkspaceFromPanel(panelState, options = {}) {
  const workspaceTab = await degradationWorkspaceEnsureWorkspaceTab({
    activate: options.activate !== false,
    windowId: panelState?.controllerWindowId || undefined,
  });
  const targetWindowId = Number(workspaceTab?.windowId || state.degradationWorkspaceWindowId || 0);
  const services = {
    degradation: panelState?.appInfo || null,
  };
  const selectionContext = degradationWorkspaceGetSelectionContext(panelState?.programmer || null, services);
  degradationWorkspaceBroadcastControllerState(panelState?.programmer || null, services, targetWindowId);
  if (options.syncReports !== false) {
    degradationWorkspaceBroadcastReports(selectionContext.selectionKey, targetWindowId);
  }
  emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
    phase: "open-workspace",
    source: "sidepanel",
    requestScope: "degradation-workspace",
    workspaceTabId: Number(workspaceTab?.id || 0),
    windowId: Number(workspaceTab?.windowId || targetWindowId || 0),
    workspaceKey: "degradation-workspace",
    workspaceOrigin: "DEGRADATION Workspace",
  });
  return {
    workspaceTab,
    targetWindowId,
    selectionContext,
  };
}

async function degradationRunStatusEndpointFromPanel(panelState, endpointKey, options = {}) {
  const endpointSpec = getDegradationStatusEndpointSpec(endpointKey);
  if (!endpointSpec || !panelState) {
    return null;
  }
  const requestToken = Number(options.requestToken || panelState.requestToken || 0);
  if (
    !isDegradationServiceRequestActive(panelState.section, requestToken, panelState.programmer?.programmerId, {
      allowDetachedSection: options.allowDetachedControllerContext === true,
    })
  ) {
    return null;
  }

  const manageBusy = options.manageBusy !== false;
  const queryValues =
    options.queryValues && typeof options.queryValues === "object"
      ? {
          ...options.queryValues,
        }
      : degradationCollectFormValues(panelState);
  const runGroupId = String(options.runGroupId || buildDegradationRunGroupId()).trim();
  if (!degradationRequireSelectedRequestor(panelState, queryValues)) {
    return null;
  }
  if (!queryValues.programmerId) {
    degradationSetControllerStatus(
      panelState,
      "Programmer value could not be derived from the selected RequestorId.",
      "error"
    );
    return null;
  }
  degradationSetControllerStatus(panelState, "");

  if (manageBusy) {
    degradationSetBusy(panelState, true);
  }

  let targetWindowId = Number(options.targetWindowId || 0);
  try {
    if (options.openWorkspace !== false) {
      const workspaceResult = await degradationOpenWorkspaceFromPanel(panelState, {
        activate: options.activateWorkspace !== false,
      });
      targetWindowId = Number(workspaceResult?.targetWindowId || targetWindowId || 0);
    } else if (!targetWindowId && degradationWorkspaceHasOpenTab()) {
      targetWindowId = Number(state.degradationWorkspaceWindowId || 0);
    }

    const selectedApp =
      options?.selectedApp && typeof options.selectedApp === "object" && String(options.selectedApp?.guid || "").trim()
        ? options.selectedApp
        : panelState.appInfo || null;
    const selectionContext = degradationWorkspaceGetSelectionContext(panelState.programmer, {
      degradation: selectedApp,
    });
    const selectionKey = String(selectionContext.selectionKey || "").trim();
    let endpointUrl = `${DEGRADATION_API_BASE}/${endpointSpec.path}`;
    try {
      endpointUrl = degradationBuildRequestUrl(panelState, endpointSpec, queryValues).toString();
    } catch {
      endpointUrl = `${DEGRADATION_API_BASE}/${endpointSpec.path}`;
    }
    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: "report-start",
      requestScope: `degradation:${endpointSpec.path}`,
      endpointKey: endpointSpec.key,
      endpointUrl,
      selectionKey,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
      controllerWindowId: Number(panelState.controllerWindowId || 0),
      targetWindowId,
      programmerId: String(queryValues.programmerId || ""),
      mvpd: String(queryValues.mvpd || ""),
      includeAllMvpd: queryValues.includeAllMvpd === true,
    });
    const report = await degradationExecuteStatusRequest(panelState, endpointSpec, {
      queryValues,
      selectionKey,
      runGroupId,
      selectedApp,
    });
    degradationWorkspaceStoreReport(report, queryValues);
    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: report.ok ? "report-result" : "report-error",
      requestScope: `degradation:${endpointSpec.path}`,
      endpointKey: endpointSpec.key,
      endpointUrl: String(report.requestUrl || `${DEGRADATION_API_BASE}/${endpointSpec.path}`),
      selectionKey: String(report.selectionKey || selectionKey),
      rowCount: Number(report.rowCount || 0),
      activeCount: Number(report.activeCount || 0),
      status: Number(report.status || 0),
      statusText: String(report.statusText || ""),
      error: String(report.error || ""),
      targetWindowId,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
    });
    if (targetWindowId > 0) {
      void degradationWorkspaceFlushReportsToTarget(selectionKey, targetWindowId, {
        reportPayload: report,
      });
    }
    const scopeLabel = report.mvpdScopeLabel || degradationBuildScopeLabel(queryValues);
    if (report.ok) {
      degradationSetControllerStatus(panelState, "");
    } else {
      degradationSetControllerStatus(
        panelState,
        `${report.endpointTitle} | ${scopeLabel} | HTTP ${report.status}: ${report.error || "Request failed."}`,
        "error"
      );
    }
    return report;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    const selectedApp =
      options?.selectedApp && typeof options.selectedApp === "object" && String(options.selectedApp?.guid || "").trim()
        ? options.selectedApp
        : panelState.appInfo || null;
    const selectionContext = degradationWorkspaceGetSelectionContext(panelState.programmer, {
      degradation: selectedApp,
    });
    const errorReport = degradationBuildReportPayload(endpointSpec, queryValues, {
      selectionKey: String(selectionContext.selectionKey || "").trim(),
      runGroupId,
      ok: false,
      status: 0,
      statusText: "",
      error: degradationBuildPremiumErrorMessage(0, "", message),
      rows: [],
      requestUrl: "",
      fetchedAt: Date.now(),
      durationMs: 0,
    });
    degradationWorkspaceStoreReport(errorReport, queryValues);
    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: "report-error",
      requestScope: `degradation:${endpointSpec.path}`,
      endpointKey: endpointSpec.key,
      endpointUrl: String(errorReport.requestUrl || ""),
      selectionKey: String(errorReport.selectionKey || selectionContext.selectionKey || ""),
      error: message,
      status: Number(errorReport.status || 0),
      statusText: String(errorReport.statusText || ""),
      targetWindowId,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
    });
    if (targetWindowId > 0) {
      void degradationWorkspaceFlushReportsToTarget(String(errorReport.selectionKey || selectionContext.selectionKey || "").trim(), targetWindowId, {
        reportPayload: errorReport,
      });
    }
    degradationSetControllerStatus(panelState, `${endpointSpec.title}: ${message}`, "error");
    return errorReport;
  } finally {
    if (manageBusy) {
      degradationSetBusy(panelState, false);
    }
  }
}

async function degradationRunAllStatusEndpointsFromPanel(panelState, options = {}) {
  if (!panelState) {
    return [];
  }
  const requestToken = Number(options.requestToken || panelState.requestToken || 0);
  if (!isDegradationServiceRequestActive(panelState.section, requestToken, panelState.programmer?.programmerId)) {
    return [];
  }

  const queryValues =
    options?.queryValues && typeof options.queryValues === "object"
      ? {
          ...options.queryValues,
        }
      : degradationCollectFormValues(panelState);
  if (!degradationRequireSelectedRequestor(panelState, queryValues)) {
    return [];
  }
  if (!queryValues.programmerId) {
    degradationSetControllerStatus(
      panelState,
      "Programmer value could not be derived from the selected RequestorId.",
      "error"
    );
    return [];
  }

  degradationSetControllerStatus(panelState, "");
  degradationSetBusy(panelState, true);
  const reports = [];
  const runGroupId = buildDegradationRunGroupId();
  try {
    let targetWindowId = Number(options.targetWindowId || 0);
    if (options.openWorkspace !== false) {
      const workspaceResult = await degradationOpenWorkspaceFromPanel(panelState, {
        activate: options.activateWorkspace !== false,
      });
      targetWindowId = Number(workspaceResult?.targetWindowId || targetWindowId || 0);
    }
    const selectedApp = degradationRefreshSelectedAppForRequest(panelState, {
      requestorId: String(queryValues.requestorId || "").trim(),
      requestScope: "degradation-run-all",
      targetWindowId,
    });
    if (!selectedApp?.guid) {
      throw new Error("No DEGRADATION scoped registered application is selected for this media company.");
    }
    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: "sweep-start",
      requestScope: "degradation-run-all",
      programmerId: String(queryValues.programmerId || ""),
      mvpd: String(queryValues.mvpd || ""),
      includeAllMvpd: queryValues.includeAllMvpd === true,
      endpointCount: 1,
      targetWindowId,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
    });
    const selectionContext = degradationWorkspaceGetSelectionContext(panelState.programmer, {
      degradation: selectedApp,
    });
    const megaReport = await degradationExecuteStatusRequest(panelState, DEGRADATION_MEGA_STATUS_ENDPOINT_SPEC, {
      queryValues,
      selectionKey: String(selectionContext.selectionKey || "").trim(),
      runGroupId,
      selectedApp,
      targetWindowId,
    });
    const splitReports = degradationBuildEndpointReportsFromMegaStatusReport(megaReport, queryValues);
    splitReports.forEach((report) => {
      degradationWorkspaceStoreReport(report, queryValues);
      reports.push(report);
    });
    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: megaReport.ok === true ? "sweep-mega-result" : "sweep-mega-error",
      requestScope: "degradation-run-all",
      endpoint: DEGRADATION_MEGA_STATUS_ENDPOINT_SPEC.path,
      status: Number(megaReport.status || 0),
      statusText: String(megaReport.statusText || ""),
      rowCount: Number(megaReport.rowCount || 0),
      activeCount: Number(megaReport.activeCount || 0),
      error: String(megaReport.error || ""),
      programmerId: String(queryValues.programmerId || ""),
      mvpd: String(queryValues.mvpd || ""),
      includeAllMvpd: queryValues.includeAllMvpd === true,
      targetWindowId,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
    });
    if (targetWindowId > 0) {
      degradationWorkspaceBroadcastReports(selectionContext.selectionKey, targetWindowId);
    }
    const okCount = reports.filter((report) => report?.ok === true).length;
    const totalRows = reports.reduce((count, report) => count + Number(report?.rowCount || 0), 0);
    const totalActive = reports.reduce((count, report) => count + Number(report?.activeCount || 0), 0);
    if (okCount !== reports.length) {
      degradationSetControllerStatus(
        panelState,
        `DEGRADATION GET sweep completed (${okCount}/${reports.length} successful) | Active rows: ${totalActive}/${totalRows}.`,
        "error"
      );
    } else {
      degradationSetControllerStatus(panelState, "");
    }
    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: "sweep-complete",
      requestScope: "degradation-run-all",
      programmerId: String(queryValues.programmerId || ""),
      mvpd: String(queryValues.mvpd || ""),
      includeAllMvpd: queryValues.includeAllMvpd === true,
      okCount,
      totalEndpoints: reports.length,
      totalRows,
      totalActive,
      targetWindowId,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
    });
    return reports;
  } finally {
    degradationSetBusy(panelState, false);
  }
}

async function degradationRunMegaProgrammerSweepFromPanel(panelState, options = {}) {
  if (!panelState) {
    return [];
  }
  const queryValues = degradationCollectFormValues(panelState);
  if (!degradationRequireSelectedRequestor(panelState, queryValues)) {
    return [];
  }
  degradationSetControllerStatus(panelState, "");
  emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
    phase: "mega-button-clicked",
    requestScope: "degradation-all",
    programmerId: String(queryValues.programmerId || ""),
    mediaCompanyId: String(panelState?.programmer?.programmerId || "").trim(),
    includeAllMvpd: queryValues.includeAllMvpd === true,
    workspaceKey: "degradation-workspace",
    workspaceOrigin: "DEGRADATION Workspace",
  });

  const endpointSpec = DEGRADATION_MEGA_STATUS_ENDPOINT_SPEC;
  const requestToken = Number(options?.requestToken || panelState.requestToken || 0);
  if (!isDegradationServiceRequestActive(panelState.section, requestToken, panelState.programmer?.programmerId)) {
    degradationSetControllerStatus(panelState, "DEGRADATION panel context is stale. Refresh and retry.", "error");
    return [];
  }

  let targetWindowId = 0;
  degradationSetBusy(panelState, true);
  const runGroupId = buildDegradationRunGroupId();
  try {
    if (options.openWorkspace !== false) {
      const workspaceResult = await degradationOpenWorkspaceFromPanel(panelState, {
        activate: options.activateWorkspace !== false,
      });
      targetWindowId = Number(workspaceResult?.targetWindowId || workspaceResult?.workspaceTab?.windowId || 0);
    } else if (degradationWorkspaceHasOpenTab()) {
      targetWindowId = Number(state.degradationWorkspaceWindowId || 0);
    }

    const selectionContext = degradationWorkspaceGetSelectionContext(panelState.programmer, {
      degradation: panelState.appInfo,
    });
    const report = await degradationExecuteStatusRequest(panelState, endpointSpec, {
      queryValues,
      selectionKey: selectionContext.selectionKey,
      runGroupId,
      targetWindowId,
    });
    degradationWorkspaceStoreReport(report, queryValues);

    emitDegradationWorkspaceDebugEvent(getActiveDegradationWorkspaceDebugFlowId(), {
      phase: "mega-report-result",
      requestScope: "degradation-all",
      endpoint: endpointSpec.path,
      ok: report.ok === true,
      status: Number(report.status || 0),
      rows: Number(report.rowCount || 0),
      activeRows: Number(report.activeCount || 0),
      mediaCompanyId: String(panelState?.programmer?.programmerId || "").trim(),
      programmerId: String(queryValues.programmerId || ""),
      includeAllMvpd: true,
      workspaceKey: "degradation-workspace",
      workspaceOrigin: "DEGRADATION Workspace",
    });

    if (targetWindowId > 0) {
      void degradationWorkspaceFlushReportsToTarget(String(report.selectionKey || selectionContext.selectionKey || "").trim(), targetWindowId, {
        reportPayload: report,
      });
    }

    if (report.ok) {
      degradationSetControllerStatus(panelState, "");
    } else {
      degradationSetControllerStatus(panelState, `${endpointSpec.title}: ${report.error || "Request failed."}`, "error");
    }
    return [report];
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    const selectionContext = degradationWorkspaceGetSelectionContext(panelState.programmer, {
      degradation: panelState.appInfo,
    });
    const errorReport = degradationBuildReportPayload(endpointSpec, queryValues, {
      selectionKey: selectionContext.selectionKey,
      runGroupId,
      ok: false,
      status: 0,
      statusText: "",
      error: degradationBuildPremiumErrorMessage(0, "", message),
      rows: [],
      requestUrl: "",
      fetchedAt: Date.now(),
      durationMs: 0,
    });
    degradationWorkspaceStoreReport(errorReport, queryValues);
    if (targetWindowId > 0) {
      void degradationWorkspaceFlushReportsToTarget(String(errorReport.selectionKey || selectionContext.selectionKey || "").trim(), targetWindowId, {
        reportPayload: errorReport,
      });
    }
    degradationSetControllerStatus(panelState, `${endpointSpec.title}: ${message}`, "error");
    return [errorReport];
  } finally {
    degradationSetBusy(panelState, false);
  }
}

async function degradationMakeClickDgrFromUi(panelState, requestToken, source = "sidepanel") {
  if (!panelState) {
    return;
  }
  const triggerButton = panelState.makeClickDgrButton;
  if (triggerButton) {
    triggerButton.disabled = true;
  }
  try {
    const context = await resolveClickDgrDownloadContext(panelState);
    if (!context) {
      throw new Error("Select a media company with DEGRADATION access to generate clickDGR.");
    }
    const result = await makeClickDgrDownload(context, requestToken, { source });
    degradationSetControllerStatus(panelState, `Generated ${result.fileName}.`, "success");
  } catch (error) {
    degradationSetControllerStatus(
      panelState,
      `Unable to generate clickDGR: ${error instanceof Error ? error.message : String(error)}`,
      "error"
    );
  } finally {
    if (
      triggerButton &&
      isDegradationServiceRequestActive(panelState.section, Number(requestToken || 0), panelState.programmer?.programmerId)
    ) {
      triggerButton.disabled = false;
    }
  }
}

function wireDegradationPanelInteractions(panelState, requestToken) {
  if (!panelState) {
    return;
  }
  panelState.requestToken = Number(requestToken || 0);
  syncDegradationWorkspaceRecordingControls(panelState);
  degradationSetControllerStatus(panelState, "");
  degradationSyncGoButtonLabel(panelState);

  if (panelState.runGoButton) {
    panelState.runGoButton.addEventListener("click", async (event) => {
      event.stopPropagation();
      const endpointKey = firstNonEmptyString([
        String(panelState.endpointSelect?.value || "").trim().toLowerCase(),
        "all",
      ]);
      const runOptions = {
        requestToken: panelState.requestToken,
        openWorkspace: true,
        activateWorkspace: false,
      };
      if (endpointKey === "all") {
        await degradationRunAllStatusEndpointsFromPanel(panelState, runOptions);
        void degradationWorkspaceActivateTarget();
        return;
      }
      await degradationRunStatusEndpointFromPanel(panelState, endpointKey, runOptions);
      void degradationWorkspaceActivateTarget();
    });
  }

  if (panelState.recordingToggleButton) {
    panelState.recordingToggleButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      if (state.degradationWorkspaceStopping) {
        return;
      }
      if (getActiveDegradationWorkspaceDebugFlowId()) {
        void stopDegradationWorkspaceRecording(panelState);
        return;
      }
      void startDegradationWorkspaceRecording(panelState, panelState.requestToken);
    });
  }

  if (panelState.makeClickDgrButton) {
    panelState.makeClickDgrButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void degradationMakeClickDgrFromUi(panelState, panelState.requestToken, "sidepanel");
    });
  }

  if (panelState.copyCurlButton) {
    panelState.copyCurlButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const endpointKey = String(panelState.endpointSelect?.value || "").trim().toLowerCase();
      void degradationGenerateCheatSheetFromUi(panelState, {
        endpointKey,
      })
        .catch((error) => {
          const activePanelState = getActiveDegradationWorkspaceState() || panelState;
          degradationSetControllerStatus(
            activePanelState,
            error instanceof Error ? error.message : String(error),
            "error"
          );
        });
    });
  }
}

async function loadDegradationService(programmer, appInfo, section, contentElement, requestToken) {
  if (!contentElement) {
    return;
  }
  let currentServices = programmer?.programmerId ? getCurrentPremiumAppsSnapshot(programmer.programmerId) : null;
  let resolvedAppInfo = resolveDegradationAppCandidates(
    String(programmer?.programmerId || "").trim(),
    currentServices?.degradation || appInfo,
    {
      preferredGuid: String(appInfo?.guid || "").trim(),
      requestorId: String(state.selectedRequestorId || "").trim(),
    }
  )[0] || appInfo;
  if (programmer?.programmerId && !resolvedAppInfo?.guid) {
    const inFlightHydration = getProgrammerServiceHydrationPromise(programmer.programmerId);
    if (inFlightHydration) {
      const hydratedServices = await inFlightHydration.catch(() => null);
      const latestHydratedServices =
        (hydratedServices && typeof hydratedServices === "object" ? hydratedServices : null) ||
        getCurrentPremiumAppsSnapshot(programmer.programmerId) ||
        currentServices;
      const hydratedCandidates = resolveDegradationAppCandidates(
        String(programmer?.programmerId || "").trim(),
        latestHydratedServices?.degradation || resolvedAppInfo,
        {
          preferredGuid: String(resolvedAppInfo?.guid || "").trim(),
          requestorId: String(state.selectedRequestorId || "").trim(),
        }
      );
      currentServices = latestHydratedServices;
      resolvedAppInfo = hydratedCandidates[0] || resolvedAppInfo;
    }
  }
  if (programmer?.programmerId && !resolvedAppInfo?.guid) {
    const hydratedServices =
      (await getProgrammerServiceHydrationPromise(programmer.programmerId)?.catch(() => null)) ||
      (await primeProgrammerServiceHydration(programmer, currentServices, {
        forceRefresh: false,
        controllerReason: "degradation-panel-open",
        requestToken,
      }).catch(() => null));
    const latestHydratedServices =
      (hydratedServices && typeof hydratedServices === "object" ? hydratedServices : null) ||
      getCurrentPremiumAppsSnapshot(programmer.programmerId) ||
      null;
    const hydratedCandidates = resolveDegradationAppCandidates(
      String(programmer?.programmerId || "").trim(),
      latestHydratedServices?.degradation || resolvedAppInfo,
      {
        preferredGuid: String(resolvedAppInfo?.guid || "").trim(),
        requestorId: String(state.selectedRequestorId || "").trim(),
      }
    );
    resolvedAppInfo = hydratedCandidates[0] || resolvedAppInfo;
  }
  if (!programmer?.programmerId || !resolvedAppInfo?.guid) {
    contentElement.innerHTML = "";
    return;
  }

  section.__underparDegradationState = null;
  if (
    state.degradationWorkspaceRecordingActive &&
    state.degradationWorkspaceRecordingContext &&
    String(state.degradationWorkspaceRecordingContext.programmerId || "") &&
    String(state.degradationWorkspaceRecordingContext.programmerId || "") !== String(programmer.programmerId || "")
  ) {
    clearDegradationWorkspaceRecordingState("programmer-change");
  }

  try {
    const controllerWindowId = await esmWorkspaceGetCurrentWindowId();
    if (!isDegradationServiceRequestActive(section, requestToken, programmer.programmerId)) {
      return;
    }
    const initialCandidates = resolveDegradationAppCandidates(
      String(programmer?.programmerId || "").trim(),
      resolvedAppInfo,
      {
        preferredGuid: String(resolvedAppInfo?.guid || "").trim(),
        requestorId: String(state.selectedRequestorId || "").trim(),
      }
    );
    const resolvedInitialApp = initialCandidates[0] || null;
    if (!resolvedInitialApp?.guid) {
      contentElement.innerHTML =
        '<div class="service-error">No properly scoped DEGRADATION software statement was found for this media company.</div>';
      return;
    }
    contentElement.innerHTML = degradationBuildControllerHtml(programmer, resolvedInitialApp);
    const panelState = {
      serviceType: "degradation",
      section,
      contentElement,
      programmer,
      appInfo: resolvedInitialApp,
      appCandidates: initialCandidates,
      requestToken,
      controllerWindowId: Number(controllerWindowId || 0),
      busy: false,
      appLabelElement: contentElement.querySelector(".degradation-app-label"),
      runnerForm: contentElement.querySelector(".degradation-runner-form"),
      endpointSelect: contentElement.querySelector(".degradation-endpoint-select"),
      recordingToggleButton: contentElement.querySelector(".degradation-record-toggle-btn"),
      makeClickDgrButton: contentElement.querySelector(".degradation-make-clickdgr-btn"),
      runGoButton: contentElement.querySelector(".degradation-run-go-btn"),
      copyCurlButton: contentElement.querySelector(".degradation-copy-curl-btn"),
      cheatSheetRow: contentElement.querySelector(".degradation-cheat-sheet-row"),
    };
    section.__underparDegradationState = panelState;
    setDegradationPanelActiveApp(panelState, resolvedInitialApp, {
      requestScope: "degradation-panel-load",
      requestorId: String(state.selectedRequestorId || "").trim(),
      targetWindowId: Number(controllerWindowId || 0),
      emitEvent: false,
    });
    wireDegradationPanelInteractions(panelState, requestToken);
    syncDegradationWorkspaceRecordingControls(panelState);
    ensureDegradationWorkspaceRuntimeListener();
    ensureDegradationWorkspaceTabWatcher();
    degradationWorkspaceBroadcastControllerState(programmer, { degradation: panelState.appInfo });
  } catch (error) {
    if (!isDegradationServiceRequestActive(section, requestToken, programmer.programmerId)) {
      return;
    }
    contentElement.innerHTML = `<div class="service-error">${escapeHtml(
      error instanceof Error ? error.message : String(error)
    )}</div>`;
  }
}

function tempPassBuildControllerHtml(programmer, context = {}) {
  const requestorId = String(state.selectedRequestorId || "").trim();
  const hasRestApp = Boolean(String(context?.restApp?.guid || "").trim());
  const hasResetApp = Boolean(String(context?.resetApp?.guid || "").trim());
  const restAppLabel = firstNonEmptyString([
    context?.restApp?.appName,
    context?.restApp?.guid,
    requestorId ? "REST V2 app unavailable for selected RequestorId" : "Select RequestorId to resolve REST V2 app",
  ]);
  const resetAppLabel = firstNonEmptyString([
    context?.resetApp?.appName,
    context?.resetApp?.guid,
    "No Reset TempPASS app detected",
  ]);
  const deviceId = String(context?.deviceId || getStableRestV2DeviceIdentifier() || "").trim();
  const canOpenWorkspace = Boolean(requestorId && (hasRestApp || hasResetApp));
  let helperText = "Select a RequestorId above to enable TempPASS workspace actions.";
  if (requestorId && hasRestApp && hasResetApp) {
    helperText = "Workspace uses the current UnderPAR RequestorId with PROFILE, AUTHORIZE, and reset actions ready.";
  } else if (requestorId && hasRestApp) {
    helperText = "Workspace opens with PROFILE and AUTHORIZE ready. Reset actions stay disabled until a Reset TempPASS app is available.";
  } else if (requestorId && hasResetApp) {
    helperText = "Workspace opens with reset actions ready. PROFILE and AUTHORIZE stay disabled until a REST V2 app is available.";
  } else if (requestorId) {
    helperText = "No TempPASS DCR apps are available for the selected RequestorId.";
  }
  return `
    <div class="temp-pass-panel">
      <div class="temp-pass-meta-grid">
        ${buildMetadataItemHtml("RequestorId", requestorId || "Not selected")}
        ${buildMetadataItemHtml("REST V2 App", restAppLabel)}
        ${buildMetadataItemHtml("Reset App", resetAppLabel)}
        ${buildMetadataItemHtml("Device ID", deviceId || "Unavailable")}
      </div>
      <div class="temp-pass-panel-actions">
        <button type="button" class="temp-pass-open-workspace-btn"${canOpenWorkspace ? "" : " disabled"}>OPEN WORKSPACE</button>
      </div>
      <p class="temp-pass-panel-hint">${escapeHtml(helperText)}</p>
      <p class="temp-pass-panel-status" hidden></p>
    </div>
  `;
}

function tempPassSetControllerStatus(panelState = null, message = "", type = "info") {
  const statusElement = panelState?.statusElement || null;
  if (!statusElement) {
    return;
  }
  const text = String(message || "").trim();
  statusElement.textContent = text;
  statusElement.hidden = text.length === 0;
  statusElement.classList.remove("success", "error");
  if (type === "success" || type === "error") {
    statusElement.classList.add(type);
  }
}

async function tempPassOpenWorkspaceFromPanel(panelState = null, options = {}) {
  if (!panelState?.programmer?.programmerId) {
    throw new Error("Select a Media Company before opening TempPASS Workspace.");
  }
  const workspaceTab = await tempPassWorkspaceEnsureWorkspaceTab({
    activate: options.activate !== false,
    windowId: panelState?.controllerWindowId || undefined,
  });
  const targetWindowId = Number(workspaceTab?.windowId || state.tempPassWorkspaceWindowId || 0);
  const services = getCurrentPremiumAppsSnapshot(panelState.programmer.programmerId) || {
    restV2: panelState.restApp || null,
    resetTempPass: panelState.resetApp || null,
  };
  const selectionContext = tempPassWorkspaceGetSelectionContext(panelState.programmer, services);
  tempPassWorkspaceBroadcastControllerState(panelState.programmer, services, targetWindowId);
  tempPassWorkspaceBroadcastResults(selectionContext.selectionKey, targetWindowId);
  return {
    workspaceTab,
    targetWindowId,
    selectionContext,
  };
}

function wireTempPassPanelInteractions(panelState = null) {
  if (!panelState?.openWorkspaceButton) {
    return;
  }
  panelState.openWorkspaceButton.addEventListener("click", async (event) => {
    event.preventDefault();
    event.stopPropagation();
    tempPassSetControllerStatus(panelState, "");
    try {
      await tempPassOpenWorkspaceFromPanel(panelState, {
        activate: true,
      });
      tempPassSetControllerStatus(panelState, "TempPASS Workspace opened.", "success");
    } catch (error) {
      tempPassSetControllerStatus(panelState, error instanceof Error ? error.message : String(error), "error");
    }
  });
}

async function loadTempPassService(programmer, appInfo, section, contentElement, requestToken) {
  if (!contentElement) {
    return;
  }
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId) {
    contentElement.innerHTML = "";
    return;
  }

  section.__underparTempPassState = null;
  section.__underparTempPassRequestToken = Number(requestToken || 0);

  try {
    const currentServices = getCurrentPremiumAppsSnapshot(programmerId) || {
      resetTempPass: appInfo || null,
    };
    const requestorId = String(state.selectedRequestorId || "").trim();
    const resetApp = resolveTempPassResetAppInfo(programmerId, requestorId, currentServices) || appInfo || null;
    const restApp = resolveTempPassRestV2AppInfo(programmerId, requestorId, currentServices) || null;
    if (!resetApp?.guid && !restApp?.guid) {
      contentElement.innerHTML = '<div class="service-error">No TempPASS DCR applications were found for this media company.</div>';
      return;
    }
    const controllerWindowId = await esmWorkspaceGetCurrentWindowId();
    if (Number(section.__underparTempPassRequestToken || 0) !== Number(requestToken || 0)) {
      return;
    }

    contentElement.innerHTML = tempPassBuildControllerHtml(programmer, {
      restApp,
      resetApp,
      deviceId: getStableRestV2DeviceIdentifier(),
    });
    const panelState = {
      section,
      contentElement,
      programmer,
      requestToken: Number(requestToken || 0),
      controllerWindowId: Number(controllerWindowId || 0),
      restApp,
      resetApp,
      openWorkspaceButton: contentElement.querySelector(".temp-pass-open-workspace-btn"),
      statusElement: contentElement.querySelector(".temp-pass-panel-status"),
    };
    section.__underparTempPassState = panelState;
    wireTempPassPanelInteractions(panelState);
    ensureTempPassWorkspaceRuntimeListener();
    ensureTempPassWorkspaceTabWatcher();
    tempPassWorkspaceBroadcastControllerState(programmer, currentServices);
  } catch (error) {
    contentElement.innerHTML = `<div class="service-error">${escapeHtml(
      error instanceof Error ? error.message : String(error)
    )}</div>`;
  }
}

function applyServiceBoxSectionShell(section, options = {}) {
  if (!section) {
    return {
      detailsElement: null,
      toggleButton: null,
      container: null,
      contentElement: null,
    };
  }

  const title = String(options?.title || "").trim();
  const hoverMessage = String(options?.hoverMessage || "").trim();
  const initialCollapsed = options?.initialCollapsed === true;
  const contentClassName = String(options?.contentClassName || "service-content").trim() || "service-content";
  const bodyHtml = String(options?.bodyHtml || "");
  const onCollapsedChange = typeof options?.onCollapsedChange === "function" ? options.onCollapsedChange : null;
  const useNativeDetailsToggle = options?.useNativeDetailsToggle === true;
  const shellBodyHtml = `
    <div class="metadata-container service-box-container">
      <div class="${escapeHtml(contentClassName)}" data-service-box-content="true">
        ${bodyHtml}
      </div>
    </div>
  `;

  section.innerHTML = useNativeDetailsToggle
    ? `
      <details class="service-box-details"${initialCollapsed ? "" : " open"}>
        <summary
          class="metadata-header service-box-header"
          title="${escapeHtml(hoverMessage)}"
          aria-label="${escapeHtml(hoverMessage)}"
        >
          <span>${escapeHtml(title)}</span>
          <span class="collapse-icon">▼</span>
        </summary>
        ${shellBodyHtml}
      </details>
    `
    : `
      <button
        type="button"
        class="metadata-header service-box-header"
        title="${escapeHtml(hoverMessage)}"
        aria-label="${escapeHtml(hoverMessage)}"
      >
        <span>${escapeHtml(title)}</span>
        <span class="collapse-icon">▼</span>
      </button>
      ${shellBodyHtml}
    `;

  const detailsElement = section.querySelector(".service-box-details");
  const toggleButton = section.querySelector(".service-box-header");
  const container = section.querySelector(".service-box-container");
  const contentElement = section.querySelector('[data-service-box-content="true"]');
  if (detailsElement && toggleButton && container) {
    const persistShellCollapsedState = (collapsed) => {
      applyCollapsibleState(toggleButton, container, collapsed);
      if (onCollapsedChange) {
        onCollapsedChange(collapsed);
      }
    };
    const isSummaryToggle =
      toggleButton instanceof Element && String(toggleButton.tagName || "").trim().toLowerCase() === "summary";
    if (isSummaryToggle && useNativeDetailsToggle) {
      detailsElement.open = initialCollapsed !== true;
      applyCollapsibleState(toggleButton, container, initialCollapsed);
      detailsElement.addEventListener("toggle", () => {
        persistShellCollapsedState(detailsElement.open !== true);
      });
    } else {
      const syncShellDetailsState = (collapsed) => {
        detailsElement.open = collapsed !== true;
      };
      wireCollapsibleSection(toggleButton, container, initialCollapsed, (collapsed) => {
        syncShellDetailsState(collapsed);
        persistShellCollapsedState(collapsed);
      });
      syncShellDetailsState(initialCollapsed);
    }
  } else if (toggleButton && container) {
    wireCollapsibleSection(toggleButton, container, initialCollapsed, (collapsed) => {
      applyCollapsibleState(toggleButton, container, collapsed);
      if (onCollapsedChange) {
        onCollapsedChange(collapsed);
      }
    });
  }

  return {
    detailsElement,
    toggleButton,
    container,
    contentElement,
  };
}

function wireHrContextSectionActions(section) {
  if (!section || section.__underparHrActionsBound === true) {
    return;
  }

  section.addEventListener("click", (event) => {
    if (event.defaultPrevented) {
      return;
    }
    const target = event.target instanceof Element ? event.target : null;
    if (!target) {
      return;
    }
    const restV2DocsButton = target.closest("[data-restv2-doc-entry-key]");
    if (restV2DocsButton) {
      event.preventDefault();
      event.stopPropagation();
      void openRestV2InteractiveDocsEntry(
        String(restV2DocsButton.getAttribute("data-restv2-doc-entry-key") || ""),
        String(restV2DocsButton.getAttribute("data-restv2-doc-url") || "")
      );
      return;
    }

    const healthActionButton = target.closest("[data-health-action]");
    if (healthActionButton) {
      event.preventDefault();
      event.stopPropagation();
      void handleHrContextHealthAction(
        String(healthActionButton.getAttribute("data-health-action") || ""),
        resolveSelectedProgrammer()
      );
      return;
    }

    const serviceDocButton = target.closest("[data-service-doc-key][data-service-doc-url]");
    if (!serviceDocButton) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    void openPremiumServiceDocumentation(
      String(serviceDocButton.getAttribute("data-service-doc-key") || ""),
      String(serviceDocButton.getAttribute("data-service-doc-url") || "")
    );
  });

  section.__underparHrActionsBound = true;
}

function createPremiumServiceSection(programmer, serviceKey, appInfo) {
  const title = PREMIUM_SERVICE_TITLE_BY_KEY[serviceKey] || serviceKey;
  const servicesForProgrammer =
    programmer?.programmerId && state.premiumAppsByProgrammerId.has(programmer.programmerId)
      ? getCurrentPremiumAppsSnapshot(programmer.programmerId)
      : null;
  const serviceScopedAppByKey = {
    esmWorkspace: servicesForProgrammer?.esm || null,
    degradation: servicesForProgrammer?.degradation || null,
    resetTempPass: servicesForProgrammer?.resetTempPass || null,
    restV2: servicesForProgrammer?.restV2 || null,
  };
  const resolvedServiceApp =
    (serviceKey === "esmWorkspace" ? appInfo || serviceScopedAppByKey.esmWorkspace : appInfo || serviceScopedAppByKey[serviceKey]) ||
    null;
  const resolvedRegisteredApp = String(resolvedServiceApp?.appName || resolvedServiceApp?.guid || "").trim();
  const registeredAppLabel = resolvedRegisteredApp || "No registered application selected";
  const hoverServiceLabelByKey = {
    restV2: "REST",
    esmWorkspace: "ESM",
    degradation: "DEGRADATION",
    resetTempPass: "TempPASS",
  };
  const serviceHoverMessage = hoverServiceLabelByKey[serviceKey]
    ? `${hoverServiceLabelByKey[serviceKey]} premium service is powered by registered application '${registeredAppLabel}'.`
    : serviceKey === "cmMvpd"
      ? "MVPD Concurrency Monitoring is powered by CM tenant APIs (not a registered application scope)."
      : "Concurrency Monitoring is powered by CM tenant APIs (not a registered application scope).";

  const section = document.createElement("article");
  section.className = `metadata-section premium-service-section ${PREMIUM_SERVICE_THEME_CLASS_BY_KEY[serviceKey] || ""}`;
  section.dataset.programmerId = String(programmer?.programmerId || "").trim();
  section.dataset.serviceKey = String(serviceKey || "").trim();
  section.dataset.appGuid = String(resolvedServiceApp?.guid || "").trim();
  const restV2LoginToolHtml =
    serviceKey === "restV2"
      ? `
        <section class="rest-v2-login-tool">
          <p class="mvpd-workspace-active-label">MVPD Not Active</p>
          <div class="rest-v2-login-actions">
            <div class="rest-v2-login-actions-left">
              <button type="button" class="rest-v2-test-login-btn" disabled hidden>LOGIN</button>
              <button type="button" class="rest-v2-close-login-btn" disabled hidden>STOP</button>
            </div>
          </div>
          <p class="rest-v2-login-status" hidden></p>
        </section>
        <section class="rest-v2-bobtools-tool" hidden>
          <div class="rest-v2-tool-head">
            <p class="rest-v2-tool-title">BOBTOOLS</p>
          </div>
          <button
            type="button"
            class="rest-v2-bobtools-open-btn"
            aria-label="Open BOBTOOLS Workspace"
            title="Open BOBTOOLS Workspace"
          >
            <img
              class="rest-v2-bobtools-open-icon"
              src="${escapeHtml(BOBTOOLS_INLINE_ICON_PATH)}"
              alt=""
              loading="lazy"
              decoding="async"
            />
          </button>
        </section>
        `
      : "";
  const serviceBodyHtml =
    serviceKey === "esmWorkspace" ||
    serviceKey === "degradation" ||
    serviceKey === "resetTempPass" ||
    serviceKey === "cm" ||
    serviceKey === "cmMvpd"
      ? ""
      : buildPremiumServiceSummaryHtml(programmer, serviceKey, appInfo);
  const sectionLabel =
    serviceKey === "cm" || serviceKey === "cmMvpd" ? String(title || serviceKey).toUpperCase() : title;
  const initialCollapsed = getPremiumSectionCollapsed(programmer?.programmerId, serviceKey);
  const { detailsElement, contentElement } = applyServiceBoxSectionShell(section, {
    title: sectionLabel,
    hoverMessage: serviceHoverMessage,
    initialCollapsed,
    useNativeDetailsToggle: serviceKey === "cm" || serviceKey === "cmMvpd",
    contentClassName: "service-content",
    bodyHtml: `
      ${restV2LoginToolHtml}
      ${serviceBodyHtml}
    `,
    onCollapsedChange: (collapsed) => {
      setPremiumSectionCollapsed(programmer?.programmerId, serviceKey, collapsed);
    },
  });

  if (serviceKey === "esmWorkspace") {
    section.__underparRefreshEsmWorkspace = () => {
      if (section.__underparEsmWorkspaceLoadPending) {
        return Promise.resolve();
      }
      section.__underparEsmWorkspaceLoadPending = true;
      const requestToken = state.premiumPanelRequestToken;
      return loadEsmWorkspaceService(programmer, appInfo, section, contentElement, requestToken).finally(() => {
        section.__underparEsmWorkspaceLoadPending = false;
      });
    };
    void section.__underparRefreshEsmWorkspace();
  } else if (serviceKey === "degradation") {
    section.__underparRefreshDegradation = () => {
      if (section.__underparDegradationLoadPending) {
        return Promise.resolve();
      }
      section.__underparDegradationLoadPending = true;
      const requestToken = state.premiumPanelRequestToken;
      return loadDegradationService(programmer, appInfo, section, contentElement, requestToken).finally(() => {
        section.__underparDegradationLoadPending = false;
      });
    };
    void section.__underparRefreshDegradation();
  } else if (serviceKey === "resetTempPass") {
    section.__underparRefreshTempPass = () => {
      if (section.__underparTempPassLoadPending) {
        return Promise.resolve();
      }
      section.__underparTempPassLoadPending = true;
      const requestToken = state.premiumPanelRequestToken;
      return loadTempPassService(programmer, appInfo, section, contentElement, requestToken).finally(() => {
        section.__underparTempPassLoadPending = false;
      });
    };
    void section.__underparRefreshTempPass();
  } else if (serviceKey === "cm" || serviceKey === "cmMvpd") {
    section.__underparRefreshCm = () => {
      if (section.__underparCmLoadPending) {
        return Promise.resolve();
      }
      section.__underparCmLoadPending = true;
      const requestToken = state.premiumPanelRequestToken;
      return loadCmService(programmer, appInfo, section, contentElement, requestToken, {
        serviceType: serviceKey,
      }).finally(() => {
        section.__underparCmLoadPending = false;
      });
    };
    const mountCachedCmContent = () =>
      renderCachedCmServiceContent(
        programmer,
        (serviceKey === "cmMvpd"
          ? getCurrentPremiumAppsSnapshot(programmer?.programmerId || "")?.cmMvpd ||
            state.cmServiceByMvpdSelectionKey.get(buildCurrentCmMvpdSelectionKey(programmer))
          : getCurrentPremiumAppsSnapshot(programmer?.programmerId || "")?.cm ||
            state.cmServiceByProgrammerId.get(programmer?.programmerId || "")) || appInfo,
        section,
        contentElement,
        state.premiumPanelRequestToken,
        {
          serviceType: serviceKey,
          allowSynthetic: true,
        }
      );
    const preloadCmContent = () => {
      if (section.__underparCmState || section.__underparCmLoadPending) {
        return;
      }
      void section.__underparRefreshCm();
    };
    const ensureCmContentReady = () => {
      const cachedRenderResult = mountCachedCmContent();
      if (cachedRenderResult?.rendered && cachedRenderResult.synthetic !== true) {
        return;
      }
      if (!detailsElement?.open) {
        if (cachedRenderResult?.synthetic === true) {
          preloadCmContent();
        }
        return;
      }
      preloadCmContent();
    };
    const initialCachedRender = mountCachedCmContent();
    if (!initialCachedRender?.rendered || initialCachedRender.synthetic === true) {
      preloadCmContent();
    }
    if (detailsElement) {
      detailsElement.addEventListener("toggle", ensureCmContentReady);
    }
    ensureCmContentReady();
  }

  if (serviceKey === "restV2") {
    const testLoginButton = section.querySelector(".rest-v2-test-login-btn");
    const closeLoginButton = section.querySelector(".rest-v2-close-login-btn");
    const openBobtoolsButton = section.querySelector(".rest-v2-bobtools-open-btn");
    if (testLoginButton) {
      testLoginButton.addEventListener("click", async (event) => {
        event.stopPropagation();
        await launchRestV2MvpdLogin(section, programmer, appInfo);
      });
    }
    if (closeLoginButton) {
      closeLoginButton.addEventListener("click", async (event) => {
        event.stopPropagation();
        await stopRestV2MvpdRecording(section, programmer, appInfo);
      });
    }
    if (openBobtoolsButton) {
      openBobtoolsButton.addEventListener("click", async (event) => {
        event.stopPropagation();
        try {
          await bobtoolsWorkspaceOpenFromRestV2(programmer, {
            activate: true,
            forceRefresh: false,
          });
        } catch (error) {
          setStatus(error instanceof Error ? error.message : String(error), "error");
        }
      });
    }

    wireRestV2ProfileAndEntitlementHandlers(section, programmer, appInfo);
    syncRestV2LoginPanel(section, programmer, appInfo);
    syncMvpdWorkspaceToolForSection(section, programmer, servicesForProgrammer);
  }
  return section;
}

function buildPremiumServicesRenderSignature(programmer = null, services = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId || !services || typeof services !== "object") {
    return "";
  }
  const selectedRequestorId = String(state.selectedRequestorId || "").trim();
  const selectedMvpdId = String(state.selectedMvpdId || "").trim();
  const availableKeys = getDetectedPremiumServiceKeys(services);
  const serviceSegments = availableKeys.map((serviceKey) => {
    const appInfo = serviceKey === "esmWorkspace" ? services?.esm : services?.[serviceKey];
    const appGuid = String(appInfo?.guid || "").trim();
    return `${serviceKey}:${appGuid}`;
  });
  return [programmerId, selectedRequestorId, selectedMvpdId, ...serviceSegments].join("|");
}

function buildRestV2InteractiveDocsPanelSignature(programmer = null, services = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId || !services?.restV2) {
    return "";
  }
  return getRestV2InteractiveDocsSections()
    .flatMap((section) =>
      section.entries.map((entry) => {
        const activationState = buildRestV2InteractiveDocsEntryActivationState(entry, programmer, services);
        const pendingFields = Array.isArray(activationState?.pendingFields) ? activationState.pendingFields.join(",") : "";
        return `${String(entry?.key || "").trim()}:${activationState?.ready === true ? "1" : "0"}:${pendingFields}`;
      })
    )
    .join("|");
}

function buildHrSectionsRenderSignature(programmer = null, services = null, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId || !services || typeof services !== "object") {
    return "";
  }
  const selectedRequestorId = String(state.selectedRequestorId || "").trim();
  const selectedMvpdId = String(state.selectedMvpdId || "").trim();
  const availableKeys = getDetectedPremiumServiceKeys(services);
  const errorText = String(options?.error || "").trim();
  const loadingFlag = options?.loading === true ? "loading" : "ready";
  const restV2LearningSignature = availableKeys.includes("restV2")
    ? buildRestV2InteractiveDocsPanelSignature(programmer, services)
    : "";
  return [
    programmerId,
    selectedRequestorId,
    selectedMvpdId,
    loadingFlag,
    errorText,
    ...availableKeys,
    restV2LearningSignature,
  ].join("|");
}

function hasRenderablePremiumServiceSections(services = null) {
  if (!els.premiumServicesContainer) {
    return false;
  }
  const expectedKeys = getDetectedPremiumServiceKeys(services);
  if (expectedKeys.length === 0) {
    return false;
  }
  const sections = Array.from(els.premiumServicesContainer.querySelectorAll(".premium-service-section"));
  if (sections.length !== expectedKeys.length) {
    return false;
  }
  const actualKeys = sections.map((section) => String(section?.dataset?.serviceKey || "").trim());
  return expectedKeys.every((serviceKey, index) => actualKeys[index] === serviceKey);
}

function hasRenderableHrContextSections() {
  if (!els.hrServicesContainer) {
    return false;
  }
  const sections = Array.from(els.hrServicesContainer.querySelectorAll(".hr-context-section"));
  if (sections.length !== HR_CONTEXT_SECTION_DISPLAY_ORDER.length) {
    return false;
  }
  const actualKeys = sections.map((section) => String(section?.dataset?.hrSectionKey || "").trim());
  return HR_CONTEXT_SECTION_DISPLAY_ORDER.every((sectionKey, index) => actualKeys[index] === sectionKey);
}

function shouldHydrateExistingPremiumServiceSection(section, serviceKey = "") {
  const normalizedServiceKey = String(serviceKey || "").trim().toLowerCase();
  if (!section || !normalizedServiceKey) {
    return false;
  }

  const contentElement =
    typeof section.querySelector === "function" ? section.querySelector('[data-service-box-content="true"]') : null;
  const hasContent = Boolean(
    contentElement &&
      (Number(contentElement.childElementCount || 0) > 0 || String(contentElement.textContent || "").trim())
  );
  if (normalizedServiceKey === "esmworkspace") {
    return !section.__underparEsmWorkspaceState && section.__underparEsmWorkspaceLoadPending !== true && !hasContent;
  }
  if (normalizedServiceKey === "degradation") {
    return !section.__underparDegradationState && section.__underparDegradationLoadPending !== true && !hasContent;
  }
  if (normalizedServiceKey === "resettemppass") {
    return !section.__underparTempPassState && section.__underparTempPassLoadPending !== true && !hasContent;
  }
  if (normalizedServiceKey === "cm" || normalizedServiceKey === "cmmvpd") {
    return !section.__underparCmState && section.__underparCmLoadPending !== true && !hasContent;
  }
  return false;
}

function rebindMountedPremiumServiceSectionState(
  section,
  programmer = null,
  serviceKey = "",
  serviceApp = null,
  requestToken = state.premiumPanelRequestToken
) {
  const normalizedServiceKey = String(serviceKey || section?.dataset?.serviceKey || "").trim();
  const normalizedRequestToken = Math.max(0, Number(requestToken || state.premiumPanelRequestToken || 0));
  if (!section || !normalizedServiceKey || !programmer?.programmerId) {
    return;
  }

  if (normalizedServiceKey === "esmWorkspace") {
    const esmWorkspaceState = section.__underparEsmWorkspaceState;
    if (esmWorkspaceState && typeof esmWorkspaceState === "object") {
      esmWorkspaceState.programmer = programmer;
      esmWorkspaceState.appInfo = serviceApp || esmWorkspaceState.appInfo || null;
      esmWorkspaceState.requestToken = normalizedRequestToken;
    }
    return;
  }

  if (normalizedServiceKey === "degradation") {
    const degradationState = section.__underparDegradationState;
    if (degradationState && typeof degradationState === "object") {
      degradationState.programmer = programmer;
      degradationState.appInfo = serviceApp || degradationState.appInfo || null;
      degradationState.requestToken = normalizedRequestToken;
    }
    return;
  }

  if (normalizedServiceKey === "resetTempPass") {
    section.__underparTempPassRequestToken = normalizedRequestToken;
    const tempPassState = section.__underparTempPassState;
    if (tempPassState && typeof tempPassState === "object") {
      tempPassState.programmer = programmer;
      tempPassState.requestToken = normalizedRequestToken;
      tempPassState.resetApp = serviceApp || tempPassState.resetApp || null;
    }
    return;
  }

  if (normalizedServiceKey === "cm" || normalizedServiceKey === "cmMvpd") {
    const cmState = section.__underparCmState;
    if (cmState && typeof cmState === "object") {
      cmState.programmer = programmer;
      cmState.cmService = serviceApp || cmState.cmService || null;
      cmState.requestToken = normalizedRequestToken;
      if (cmState.cmuUsageState && typeof cmState.cmuUsageState === "object") {
        cmState.cmuUsageState.requestToken = normalizedRequestToken;
      }
    }
  }
}

function refreshExistingPremiumServiceSections(programmer, services = null) {
  if (!els.premiumServicesContainer || !programmer?.programmerId || !services || typeof services !== "object") {
    return;
  }

  const sections = els.premiumServicesContainer.querySelectorAll(".premium-service-section");
  sections.forEach((section) => {
    if (!(section instanceof HTMLElement)) {
      return;
    }
    const serviceKey = String(section.dataset.serviceKey || "").trim();
    if (!serviceKey) {
      return;
    }
    const serviceApp = serviceKey === "esmWorkspace" ? services?.esm || null : services?.[serviceKey] || null;
    section.dataset.appGuid = String(serviceApp?.guid || "").trim();
    rebindMountedPremiumServiceSectionState(
      section,
      programmer,
      serviceKey,
      serviceApp,
      Number(state.premiumPanelRequestToken || 0)
    );
    if (serviceKey === "esmWorkspace" && typeof section.__underparRefreshEsmWorkspace === "function") {
      if (shouldHydrateExistingPremiumServiceSection(section, serviceKey)) {
        void section.__underparRefreshEsmWorkspace();
      }
      return;
    }
    if (serviceKey === "restV2") {
      syncRestV2LoginPanel(section, programmer, serviceApp);
      syncMvpdWorkspaceToolForSection(section, programmer, services);
      return;
    }
    if (serviceKey === "resetTempPass" && typeof section.__underparRefreshTempPass === "function") {
      if (shouldHydrateExistingPremiumServiceSection(section, serviceKey)) {
        void section.__underparRefreshTempPass();
      }
      return;
    }
    if (serviceKey === "degradation" && typeof section.__underparRefreshDegradation === "function") {
      if (shouldHydrateExistingPremiumServiceSection(section, serviceKey)) {
        void section.__underparRefreshDegradation();
      }
      return;
    }
    if ((serviceKey === "cm" || serviceKey === "cmMvpd") && typeof section.__underparRefreshCm === "function") {
      if (shouldHydrateExistingPremiumServiceSection(section, serviceKey)) {
        void section.__underparRefreshCm();
      }
    }
  });
}

function renderPremiumServicesLoading(programmer, options = {}) {
  renderHrSections(null, programmer, { loading: true });
  if (!els.premiumServicesContainer) {
    return;
  }
  clearPremiumServiceAutoRefreshTimers();
  const controllerReason = String(options?.controllerReason || "").trim();
  esmWorkspaceBroadcastSelectedControllerState(programmer, null, 0, {
    controllerReason,
    esmAvailabilityResolved: false,
    esmContainerVisible: null,
  });
  cmBroadcastSelectedControllerState(programmer, null, 0, {
    controllerReason,
    cmAvailabilityResolved: false,
    cmContainerVisible: null,
  });
  mvpdWorkspaceBroadcastSelectedControllerState(programmer, null);
  tempPassWorkspaceBroadcastControllerState(programmer, null, 0);
  degradationWorkspaceBroadcastControllerState(programmer, null, 0, {
    controllerReason,
  });

  const label = programmer?.programmerName
    ? `Loading premium services for ${programmer.programmerName}...`
    : "Loading premium services...";
  const hydrationProgress =
    options?.hydrationProgress && typeof options.hydrationProgress === "object"
      ? options.hydrationProgress
      : getProgrammerPremiumHydrationProgress(String(programmer?.programmerId || "").trim());
  const progressLabel = String(hydrationProgress?.label || "").trim();
  const displayLabel = progressLabel || label;
  delete els.premiumServicesContainer.dataset.renderSignature;
  els.premiumServicesContainer.innerHTML = `<p class="metadata-empty">${escapeHtml(displayLabel)}</p>`;
}

function renderPremiumServicesError(error, options = {}) {
  const reason = error instanceof Error ? error.message : String(error);
  renderHrSections(null, resolveSelectedProgrammer(), { error: reason });
  if (!els.premiumServicesContainer) {
    return;
  }
  clearPremiumServiceAutoRefreshTimers();
  const controllerReason = String(options?.controllerReason || "").trim();
  esmWorkspaceBroadcastSelectedControllerState(resolveSelectedProgrammer(), null, 0, {
    controllerReason,
    esmAvailabilityResolved: false,
    esmContainerVisible: null,
  });
  cmBroadcastSelectedControllerState(resolveSelectedProgrammer(), null, 0, {
    controllerReason,
    cmAvailabilityResolved: false,
    cmContainerVisible: null,
  });
  mvpdWorkspaceBroadcastSelectedControllerState(resolveSelectedProgrammer(), null);
  tempPassWorkspaceBroadcastControllerState(resolveSelectedProgrammer(), null, 0);
  degradationWorkspaceBroadcastControllerState(resolveSelectedProgrammer(), null, 0, {
    controllerReason,
  });
  delete els.premiumServicesContainer.dataset.renderSignature;
  els.premiumServicesContainer.innerHTML = `<p class="metadata-empty service-error">${escapeHtml(reason)}</p>`;
}

function shouldShowCmService(cmService) {
  if (!cmService || typeof cmService !== "object") {
    return false;
  }

  const matchedTenants = Array.isArray(cmService.matchedTenants) ? cmService.matchedTenants : [];
  return matchedTenants.length > 0;
}

function getDetectedPremiumServiceKeys(services) {
  if (!services || typeof services !== "object") {
    return [];
  }
  return PREMIUM_SERVICE_DISPLAY_ORDER.filter((serviceKey) => {
    if (serviceKey === "esmWorkspace") {
      return hasEsmScopedApp(services);
    }
    if (serviceKey === "cm" || serviceKey === "cmMvpd") {
      return shouldShowCmService(services?.[serviceKey]);
    }
    return Boolean(services?.[serviceKey]);
  });
}

function getDetectedPremiumServiceLabels(services) {
  return getDetectedPremiumServiceKeys(services).map((serviceKey) => PREMIUM_SERVICE_TITLE_BY_KEY[serviceKey] || serviceKey);
}

function getDetectedPremiumServiceEntries(services) {
  return getDetectedPremiumServiceKeys(services).map((serviceKey) => ({
    serviceKey,
    label: PREMIUM_SERVICE_TITLE_BY_KEY[serviceKey] || serviceKey,
    documentationUrl: String(PREMIUM_SERVICE_DOCUMENTATION_URL_BY_KEY[serviceKey] || "").trim(),
  }));
}

function getHrContextSummary(programmer = null) {
  const environment = getActiveAdobePassEnvironment();
  const environmentLabel = String(environment?.label || environment?.key || "Environment").trim() || "Environment";
  const mediaCompanyLabel =
    firstNonEmptyString([
      String(programmer?.mediaCompanyName || "").trim(),
      String(programmer?.programmerName || "").trim(),
      String(programmer?.programmerId || "").trim(),
    ]) || "Media Company";
  return {
    environmentLabel,
    mediaCompanyLabel,
    compositeLabel: `${environmentLabel} x ${mediaCompanyLabel}`,
    hasProgrammerContext: Boolean(
      String(programmer?.mediaCompanyName || programmer?.programmerName || programmer?.programmerId || "").trim()
    ),
  };
}

function shouldRevealHrContextSections(programmer = null, services = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  return Boolean(programmerId) && getDetectedPremiumServiceKeys(services).length > 0;
}

function setHrContextSectionsVisibility(visible = false) {
  if (!els.hrServicesContainer) {
    return;
  }
  const shouldShow = visible === true;
  els.hrServicesContainer.hidden = !shouldShow;
  els.hrServicesContainer.setAttribute("aria-hidden", shouldShow ? "false" : "true");
  if (!shouldShow) {
    delete els.hrServicesContainer.dataset.renderSignature;
    els.hrServicesContainer.innerHTML = "";
  }
}

function buildHrServiceListHtml(entries, fallbackText = "") {
  if (Array.isArray(entries) && entries.length > 0) {
    return `
      <article class="metadata-item">
        <p class="metadata-key">Detected Adobe PASS Services</p>
        <ul class="hr-context-service-list">
          ${entries
            .map((entry) => {
              const label = String(entry?.label || "").trim();
              const serviceKey = String(entry?.serviceKey || "").trim();
              const documentationUrl = String(entry?.documentationUrl || "").trim();
              const pillLabel = label || serviceKey || "Service";
              const actionTitle = `Open ${pillLabel} documentation in main content`;
              const themeClass = String(PREMIUM_SERVICE_THEME_CLASS_BY_KEY[serviceKey] || "").trim();
              return `<li>
                <button
                  type="button"
                  class="hr-context-service-pill${themeClass ? ` hr-context-service-pill--${themeClass}` : ""}"
                  data-service-doc-key="${escapeHtml(serviceKey)}"
                  data-service-doc-url="${escapeHtml(documentationUrl)}"
                  title="${escapeHtml(actionTitle)}"
                  aria-label="${escapeHtml(actionTitle)}"
                >${escapeHtml(pillLabel)}</button>
              </li>`;
            })
            .join("")}
        </ul>
      </article>
    `;
  }
  return buildMetadataItemHtml("Detected Adobe PASS Services", fallbackText);
}

function buildRestV2InteractiveDocsUrl(anchor = "") {
  const baseUrl = String(PREMIUM_SERVICE_DOCUMENTATION_URL_BY_KEY.restV2 || "").trim();
  const normalizedAnchor = String(anchor || "").trim().replace(/^#/, "");
  if (!baseUrl || !normalizedAnchor) {
    return baseUrl;
  }
  return `${baseUrl}#${normalizedAnchor}`;
}

function getRestV2InteractiveDocsEntry(entryKey = "") {
  const normalizedEntryKey = String(entryKey || "").trim().toLowerCase();
  if (!normalizedEntryKey) {
    return null;
  }
  return (
    REST_V2_INTERACTIVE_DOC_ENTRIES.find((entry) => String(entry?.key || "").trim().toLowerCase() === normalizedEntryKey) || null
  );
}

function getRestV2InteractiveDocsSections() {
  const sections = [];
  const byKey = new Map();
  REST_V2_INTERACTIVE_DOC_ENTRIES.forEach((entry) => {
    if (!entry || typeof entry !== "object") {
      return;
    }
    const sectionKey = String(entry.sectionKey || "").trim();
    if (!sectionKey) {
      return;
    }
    if (!byKey.has(sectionKey)) {
      const section = {
        sectionKey,
        sectionLabel: String(entry.sectionLabel || sectionKey).trim(),
        tagAnchor: String(entry.tagAnchor || "").trim(),
        entries: [],
      };
      byKey.set(sectionKey, section);
      sections.push(section);
    }
    byKey.get(sectionKey).entries.push(entry);
  });
  return sections;
}

function resolveRestV2LearningRecordingContext(programmerId = "", requestorId = "", mvpd = "") {
  const recordingContext = buildRestV2SelectionContextFromRecordingContext(state.restV2RecordingContext);
  if (!recordingContext?.ok) {
    return null;
  }
  const normalizedProgrammerId = String(programmerId || "").trim().toLowerCase();
  const normalizedRequestorId = String(requestorId || "").trim().toLowerCase();
  const normalizedMvpd = String(mvpd || "").trim();
  if (
    normalizedProgrammerId &&
    String(recordingContext.programmerId || "").trim().toLowerCase() !== normalizedProgrammerId
  ) {
    return null;
  }
  if (
    normalizedRequestorId &&
    String(recordingContext.requestorId || recordingContext.serviceProviderId || "").trim().toLowerCase() !== normalizedRequestorId
  ) {
    return null;
  }
  if (!normalizedMvpd) {
    return recordingContext;
  }
  const allowSsoAlias = isRestV2LikelyPartnerSsoContext(recordingContext);
  return isRestV2MvpdMatch(String(recordingContext.mvpd || "").trim(), normalizedMvpd, {
    allowSsoAlias,
  })
    ? recordingContext
    : null;
}

function collectRestV2LearningResourceIds(harvest = null, preauthorizeHistory = null) {
  const sourceValues = [];
  const appendValues = (value) => {
    if (Array.isArray(value)) {
      value.forEach((item) => appendValues(item));
      return;
    }
    const normalized = String(value || "").trim();
    if (normalized) {
      sourceValues.push(normalized);
    }
  };

  getRestV2ProfilePreauthzChecks(harvest).forEach((check) => {
    appendValues(check?.resourceIds);
  });

  (Array.isArray(preauthorizeHistory) ? preauthorizeHistory : [preauthorizeHistory]).forEach((entry) => {
    appendValues(entry?.resourceIds);
  });

  return uniquePreserveOrder(sourceValues);
}

function sampleRestV2LearningResourceIds(resourceIds = [], maxCount = 10) {
  const uniqueIds = uniquePreserveOrder(
    (Array.isArray(resourceIds) ? resourceIds : []).map((item) => String(item || "").trim()).filter(Boolean)
  );
  const limit = Math.max(1, Number(maxCount || 0) || 10);
  if (uniqueIds.length <= limit) {
    return uniqueIds;
  }

  const shuffled = uniqueIds.slice();
  for (let index = shuffled.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1));
    const temp = shuffled[index];
    shuffled[index] = shuffled[swapIndex];
    shuffled[swapIndex] = temp;
  }
  return shuffled.slice(0, limit);
}

function getFirstCachedMvpdIdForRequestor(requestorId = "") {
  const cache = getRequestorScopedMvpdCache(requestorId);
  if (!cache || typeof cache?.keys !== "function") {
    return "";
  }
  const firstEntry = cache.keys().next();
  return String(firstEntry?.value || "").trim();
}

function collectRestV2LearningRequestorDomainNames(programmer = null, requestorId = "") {
  const normalizedRequestorId = normalizeEntityToken(extractEntityIdFromToken(requestorId));
  if (!normalizedRequestorId) {
    return [];
  }

  const domainNames = [];
  const appendDomainName = (value) => {
    if (value == null) {
      return;
    }
    if (Array.isArray(value)) {
      value.forEach((item) => appendDomainName(item));
      return;
    }
    if (typeof value === "object") {
      appendDomainName(value.domainName);
      appendDomainName(value.domain);
      appendDomainName(value.name);
      return;
    }
    const normalizedValue = String(value || "").trim();
    if (!normalizedValue) {
      return;
    }
    if (normalizeEntityToken(normalizedValue) === "all-domains") {
      return;
    }
    domainNames.push(normalizedValue);
  };

  const matchesRequestor = (candidate = null) => {
    const candidateIds = [
      candidate?.id,
      candidate?.key,
      candidate?.raw?.id,
      candidate?.entityData?.id,
    ]
      .map((value) => normalizeEntityToken(extractEntityIdFromToken(value)))
      .filter(Boolean);
    return candidateIds.includes(normalizedRequestorId);
  };

  const channelCandidates = [
    ...(Array.isArray(programmer?.requestorOptions) ? programmer.requestorOptions : []),
    ...(Array.isArray(state?.consoleBootstrapState?.channels) ? state.consoleBootstrapState.channels : []),
  ];
  channelCandidates.forEach((candidate) => {
    if (!matchesRequestor(candidate)) {
      return;
    }
    appendDomainName(candidate?.domains);
    appendDomainName(candidate?.raw?.domains);
    appendDomainName(candidate?.entityData?.domains);
  });

  return uniquePreserveOrder(domainNames);
}

function resolveRestV2LearningRequestorDomainName(programmer = null, requestorId = "") {
  return String(collectRestV2LearningRequestorDomainNames(programmer, requestorId)[0] || "").trim();
}

async function enrichRestV2LearningResourcesFromConsoleContext(context = null, options = {}) {
  const resolvedContext = context && typeof context === "object" ? context : null;
  if (!resolvedContext?.programmerId) {
    return resolvedContext;
  }

  const programmerId = String(resolvedContext.programmerId || "").trim();
  const requestorId = firstNonEmptyString([
    String(resolvedContext.requestorId || "").trim(),
    String(resolvedContext.serviceProviderId || "").trim(),
  ]);
  const mvpdId = String(resolvedContext.mvpd || "").trim();
  if (!programmerId || !requestorId || !mvpdId) {
    return resolvedContext;
  }

  let quickResourceOptions = bobtoolsWorkspaceResolveQuickResourceOptions(programmerId, requestorId, mvpdId);
  let consoleResourceIds = bobtoolsWorkspaceNormalizeQuickResourceIds(
    Array.isArray(quickResourceOptions?.resourceIds) ? quickResourceOptions.resourceIds : []
  );

  const refreshSnapshotResources = async (forceRefresh = false) => {
    try {
      const snapshot = await mvpdWorkspaceEnsureSnapshot(
        {
          programmerId,
          programmerName: String(resolvedContext.programmerName || "").trim(),
          requestorId,
          mvpdId,
          isReady: true,
        },
        {
          forceRefresh,
        }
      );
      quickResourceOptions = bobtoolsWorkspaceResolveQuickResourceOptions(programmerId, requestorId, mvpdId);
      consoleResourceIds = bobtoolsWorkspaceNormalizeQuickResourceIds(
        Array.isArray(quickResourceOptions?.resourceIds) && quickResourceOptions.resourceIds.length > 0
          ? quickResourceOptions.resourceIds
          : Array.isArray(snapshot?.resourceIds) && snapshot.resourceIds.length > 0
            ? snapshot.resourceIds
            : snapshot?.resourceIdsRaw
      );
      return snapshot;
    } catch {
      // Leave resourceIds as-is when console-backed resource hydration is unavailable.
      return null;
    }
  };

  if (consoleResourceIds.length === 0) {
    await refreshSnapshotResources(false);
  }

  if (consoleResourceIds.length === 0 && options?.forceRefresh !== false) {
    await refreshSnapshotResources(true);
  }

  if (consoleResourceIds.length === 0) {
    return resolvedContext;
  }

  return {
    ...resolvedContext,
    resourceIdPool: consoleResourceIds.slice(),
    resourceIds: sampleRestV2LearningResourceIds(consoleResourceIds, 10),
    resourceIdPoolSource: "console-tms-map",
  };
}

function findRestV2PreauthorizeHistoryEntriesForLearning(programmerId = "", requestorId = "", mvpd = "") {
  const history = getRestV2PreauthorizeHistoryForProgrammer(programmerId);
  const normalizedRequestorId = String(requestorId || "").trim().toLowerCase();
  const normalizedMvpd = String(mvpd || "").trim().toLowerCase();
  if (normalizedRequestorId || normalizedMvpd) {
    const exactMatches = history.filter((entry) => {
      const entryRequestorId = String(entry?.requestorId || entry?.serviceProviderId || "").trim().toLowerCase();
      const entryMvpd = String(entry?.mvpd || "").trim().toLowerCase();
      const requestorMatch = normalizedRequestorId ? entryRequestorId === normalizedRequestorId : true;
      const mvpdMatch = normalizedMvpd ? entryMvpd === normalizedMvpd : true;
      return requestorMatch && mvpdMatch;
    });
    if (exactMatches.length > 0) {
      return exactMatches;
    }
  }
  return history.slice(0, 1);
}

function findRestV2PreauthorizeHistoryEntryForLearning(programmerId = "", requestorId = "", mvpd = "") {
  return findRestV2PreauthorizeHistoryEntriesForLearning(programmerId, requestorId, mvpd)[0] || null;
}

function collectRestV2LearningRequestorCandidates(programmer = null, services = null) {
  const resolvedProgrammer = programmer && typeof programmer === "object" ? programmer : null;
  const programmerId = String(resolvedProgrammer?.programmerId || "").trim();
  const candidates = [];
  const seen = new Set();
  const pushCandidate = (value) => {
    const candidateId = extractEntityIdFromToken(value);
    const normalizedCandidate = normalizeEntityToken(candidateId);
    const matchesProgrammerId = candidateId === programmerId;
    if (!candidateId || !normalizedCandidate || matchesProgrammerId || seen.has(normalizedCandidate)) {
      return;
    }
    seen.add(normalizedCandidate);
    candidates.push(candidateId);
  };

  (Array.isArray(resolvedProgrammer?.requestorIds) ? resolvedProgrammer.requestorIds : []).forEach((requestorId) => {
    pushCandidate(requestorId);
  });

  const restV2Candidates = collectRestV2AppCandidatesFromPremiumApps(services);
  restV2Candidates.forEach((appInfo) => {
    collectRestV2ServiceProviderCandidatesFromApp(appInfo, programmerId).forEach((candidate) => {
      pushCandidate(candidate);
    });
  });

  return candidates;
}

function resolveRestV2LearningRequestorContext(programmer = null, services = null) {
  const selectedRequestorId = String(state.selectedRequestorId || "").trim();
  if (selectedRequestorId) {
    return {
      requestorId: selectedRequestorId,
      autoResolved: false,
      candidateCount: 1,
    };
  }

  const candidates = collectRestV2LearningRequestorCandidates(programmer, services);
  if (candidates.length === 1) {
    return {
      requestorId: String(candidates[0] || "").trim(),
      autoResolved: true,
      candidateCount: 1,
    };
  }

  return {
    requestorId: "",
    autoResolved: false,
    candidateCount: candidates.length,
  };
}

function resolveRestV2InteractiveDocsAppRequestorContext(appInfo = null, programmerId = "") {
  const primaryRequestorId = sanitizePassVaultHintValue(
    appInfo?.appData?.requestor,
    appInfo?.appData?.serviceProvider,
    extractPassVaultPrimaryRequestorHintFromAppData(appInfo?.appData, appInfo?.softwareStatement)
  );
  if (primaryRequestorId && primaryRequestorId !== programmerId) {
    return {
      requestorId: primaryRequestorId,
      autoResolved: true,
      candidateCount: 1,
    };
  }

  const candidates = collectRestV2ServiceProviderCandidatesFromApp(appInfo, programmerId).filter((candidate) => {
    const candidateId = String(candidate || "").trim();
    const normalizedCandidateId = normalizeEntityToken(candidateId);
    return candidateId && normalizedCandidateId && candidateId !== programmerId;
  });
  if (candidates.length === 1) {
    return {
      requestorId: String(candidates[0] || "").trim(),
      autoResolved: true,
      candidateCount: 1,
    };
  }

  return {
    requestorId: "",
    autoResolved: false,
    candidateCount: candidates.length,
  };
}

function buildRestV2InteractiveDocsContext(programmer = null, entry = null) {
  const resolvedProgrammer = programmer || resolveSelectedProgrammer();
  const resolvedEntry = entry && typeof entry === "object" ? entry : null;
  if (!resolvedProgrammer?.programmerId) {
    return {
      ok: false,
      error: "Select a Media Company first.",
    };
  }

  const programmerId = String(resolvedProgrammer.programmerId || "").trim();
  const services = getCurrentPremiumAppsSnapshot(programmerId) || null;
  const requestorContext = resolveRestV2LearningRequestorContext(resolvedProgrammer, services);
  const requestorId = String(requestorContext.requestorId || "").trim();
  if (!requestorId) {
    if (resolvedEntry?.operationId === "handleRequestUsingGET") {
      const restV2Candidates = collectRestV2AppCandidatesFromPremiumApps(services);
      const seededApp = services?.restV2 || restV2Candidates[0] || null;
      const appRequestorContext = resolveRestV2InteractiveDocsAppRequestorContext(seededApp, programmerId);
      const serviceProviderId = String(appRequestorContext.requestorId || "").trim();
      if (!serviceProviderId) {
        return {
          ok: false,
          error:
            "Select a Content Provider first. UnderPAR could not resolve a REST V2 service provider from the mapped application.",
        };
      }
      const preferredApp =
        resolveRestV2AppForServiceProvider(restV2Candidates, serviceProviderId, programmerId) ||
        seededApp;
      if (!preferredApp?.guid) {
        return {
          ok: false,
          error: `No REST V2 scoped app is mapped to ${serviceProviderId}.`,
        };
      }
      return {
        ok: true,
        programmerId,
        programmerName: String(resolvedProgrammer.programmerName || "").trim(),
        requestorId: serviceProviderId,
        requestorAutoResolved: appRequestorContext.autoResolved === true,
        serviceProviderId,
        mvpd: "",
        mvpdMeta: null,
        appInfo: preferredApp,
        services,
        activeRecordingContext: null,
        harvest: null,
        harvestContext: null,
        resourceIds: [],
        resourceIdPool: [],
        sessionUrl: "",
        loginUrl: "",
        sessionCode: "",
        sessionCodeCandidates: [],
        redirectUrl: "",
        domainName: "",
        partnerFrameworkStatus: "",
        partner: "",
        flowId: "",
      };
    }
    return {
      ok: false,
      error:
        "Select a Content Provider first. REST V2 interactive docs require a valid RequestorId/service provider, not just a Media Company.",
    };
  }

  const restV2Candidates = collectRestV2AppCandidatesFromPremiumApps(services);
  const preferredApp =
    selectPreferredRestV2AppForRequestor(restV2Candidates, requestorId, programmerId) ||
    services?.restV2 ||
    restV2Candidates[0] ||
    null;
  if (!preferredApp?.guid) {
    return {
      ok: false,
      error: `No REST V2 scoped app is mapped to ${requestorId}.`,
    };
  }

  const selectedMvpd = String(state.selectedMvpdId || "").trim();
  const activeRecordingContext = resolveRestV2LearningRecordingContext(programmerId, requestorId, selectedMvpd);
  const harvestLookupMvpd = firstNonEmptyString([
    selectedMvpd,
    String(activeRecordingContext?.mvpd || "").trim(),
  ]);
  const harvest = getRestV2ProfileHarvestForContext({
    programmerId,
    requestorId,
    mvpd: harvestLookupMvpd,
  });
  const harvestContext = buildRestV2ContextFromHarvest(harvest);
  const fallbackMvpd = firstNonEmptyString([
    selectedMvpd,
    String(activeRecordingContext?.mvpd || "").trim(),
    String(harvestContext?.mvpd || "").trim(),
    String(harvest?.mvpd || "").trim(),
  ]);
  const mvpdMeta =
    getRestV2MvpdMeta(requestorId, fallbackMvpd) ||
    activeRecordingContext?.mvpdMeta ||
    (String(harvest?.mvpdName || "").trim() && fallbackMvpd
      ? {
          id: fallbackMvpd,
          name: String(harvest.mvpdName || "").trim(),
        }
      : null);
  const preauthorizeHistoryEntries = findRestV2PreauthorizeHistoryEntriesForLearning(programmerId, requestorId, fallbackMvpd);
  const quickResourceOptions = bobtoolsWorkspaceResolveQuickResourceOptions(programmerId, requestorId, fallbackMvpd);
  const resourceIdPool = collectRestV2LearningResourceIds(harvest, [
    ...preauthorizeHistoryEntries,
    {
      resourceIds: Array.isArray(quickResourceOptions?.resourceIds) ? quickResourceOptions.resourceIds : [],
    },
  ]);
  const resourceIds = sampleRestV2LearningResourceIds(resourceIdPool, 10);
  const sessionUrl = normalizeAdobeNavigationUrl(
    firstNonEmptyString([
      String(activeRecordingContext?.sessionUrl || "").trim(),
      String(harvestContext?.sessionUrl || "").trim(),
      String(harvest?.sessionUrl || "").trim(),
    ])
  );
  const loginUrl = normalizeAdobeNavigationUrl(
    firstNonEmptyString([
      String(activeRecordingContext?.loginUrl || "").trim(),
      String(harvestContext?.loginUrl || "").trim(),
      String(harvest?.loginUrl || "").trim(),
    ])
  );
  const sessionCodeCandidates = collectRestV2SessionCodeCandidates(
    [
      String(activeRecordingContext?.sessionCode || "").trim(),
      ...(Array.isArray(activeRecordingContext?.sessionCodeCandidates) ? activeRecordingContext.sessionCodeCandidates : []),
      String(harvestContext?.sessionCode || "").trim(),
      ...(Array.isArray(harvestContext?.sessionCodeCandidates) ? harvestContext.sessionCodeCandidates : []),
      String(harvest?.sessionCode || "").trim(),
      ...(Array.isArray(harvest?.sessionCodeCandidates) ? harvest.sessionCodeCandidates : []),
      sessionUrl,
      loginUrl,
    ],
    requestorId
  );
  const sessionCode = firstNonEmptyString([
    String(activeRecordingContext?.sessionCode || "").trim(),
    String(harvestContext?.sessionCode || "").trim(),
    String(harvest?.sessionCode || "").trim(),
    sessionCodeCandidates[0],
  ]);
  const operationRedirectUrl =
    resolvedEntry?.usesBodyRedirectUrl === true || resolvedEntry?.usesQueryRedirectUrl === true
      ? buildRestV2InteractiveDocsUrl(resolvedEntry.operationAnchor || resolvedEntry.tagAnchor || "")
      : "";
  const redirectUrl = normalizeAdobeNavigationUrl(
    firstNonEmptyString([
      String(operationRedirectUrl || "").trim(),
      String(activeRecordingContext?.redirectUrl || "").trim(),
      String(harvest?.redirectUrl || "").trim(),
    ])
  );
  const requestorDomainName = resolveRestV2LearningRequestorDomainName(resolvedProgrammer, requestorId);
  const domainName = firstNonEmptyString([
    String(requestorDomainName || "").trim(),
    String(activeRecordingContext?.domainName || "").trim(),
    String(harvest?.domainName || "").trim(),
  ]);
  const partnerFrameworkStatus = firstNonEmptyString([
    String(activeRecordingContext?.partnerFrameworkStatus || "").trim(),
    String(resolveRestV2PartnerFrameworkStatusFromContext(harvestContext || harvest) || "").trim(),
  ]);
  const partner = firstNonEmptyString([
    String(resolveRestV2PartnerNameFromContext(activeRecordingContext) || "").trim(),
    String(resolveRestV2PartnerNameFromContext(harvestContext || harvest) || "").trim(),
    String(harvest?.sessionPartner || "").trim(),
  ]);
  const flowId = firstNonEmptyString([
    state.restV2RecordingActive === true ? String(state.restV2DebugFlowId || "").trim() : "",
    resolveRestV2DebugFlowIdForHarvest(harvest),
  ]);
  return {
    ok: true,
    programmerId,
    programmerName: String(resolvedProgrammer.programmerName || "").trim(),
    requestorId,
    requestorAutoResolved: requestorContext.autoResolved === true,
    serviceProviderId: requestorId,
    mvpd: String(fallbackMvpd || "").trim(),
    mvpdMeta,
    appInfo: preferredApp,
    services,
    activeRecordingContext: activeRecordingContext || null,
    harvest: harvest || null,
    harvestContext: harvestContext || null,
    resourceIds,
    resourceIdPool,
    sessionUrl,
    loginUrl,
    sessionCode: String(sessionCode || "").trim(),
    sessionCodeCandidates,
    redirectUrl: String(redirectUrl || "").trim(),
    domainName: String(domainName || "").trim(),
    partnerFrameworkStatus: String(partnerFrameworkStatus || "").trim(),
    partner: String(partner || "").trim(),
    flowId: String(flowId || "").trim(),
  };
}

async function prepareRestV2InteractiveDocsContextForEntry(entry = null, context = null) {
  const resolvedEntry = entry && typeof entry === "object" ? entry : null;
  const resolvedContext = context && typeof context === "object" ? context : null;
  if (!resolvedEntry?.key || !resolvedContext?.ok) {
    return resolvedContext;
  }
  const preparedContext = {
    ...resolvedContext,
  };
  if (resolvedEntry.usesBodySamlResponse !== true || String(preparedContext.samlResponse || "").trim()) {
    if (resolvedEntry.usesBodyResources === true) {
      return enrichRestV2LearningResourcesFromConsoleContext(preparedContext);
    }
    return preparedContext;
  }
  if (resolvedEntry.usesBodyResources === true) {
    Object.assign(preparedContext, await enrichRestV2LearningResourcesFromConsoleContext(preparedContext));
  }
  const flowId = firstNonEmptyString([
    String(preparedContext.flowId || "").trim(),
    resolveRestV2DebugFlowIdForHarvest(preparedContext.harvest),
  ]);
  if (!flowId) {
    return preparedContext;
  }
  preparedContext.flowId = flowId;
  try {
    const flowSnapshot = await getRestV2DebugFlowSnapshot(flowId);
    const samlDetails = extractRestV2SamlResponseFromDebugFlow(flowSnapshot);
    if (String(samlDetails?.samlResponse || "").trim()) {
      preparedContext.samlResponse = String(samlDetails.samlResponse || "").trim();
      preparedContext.samlSource = String(samlDetails.source || "").trim();
    }
  } catch {
    // Leave samlResponse empty and allow the docs form to remain partially hydrated.
  }
  return preparedContext;
}

function buildRestV2InteractiveDocsHydrationPlan(entry, context, accessToken = "") {
  const resolvedEntry = entry && typeof entry === "object" ? entry : null;
  const resolvedContext = context && typeof context === "object" ? context : null;
  if (!resolvedEntry?.key || !resolvedContext?.serviceProviderId) {
    throw new Error("REST V2 learning hydration is missing entry or selection context.");
  }
  const operationDocsUrl = buildRestV2InteractiveDocsUrl(resolvedEntry.operationAnchor || resolvedEntry.tagAnchor || "");
  const redirectUrlValue =
    resolvedEntry.usesBodyRedirectUrl === true || resolvedEntry.usesQueryRedirectUrl === true
      ? String(operationDocsUrl || resolvedContext.redirectUrl || "").trim()
      : String(resolvedContext.redirectUrl || "").trim();

  const fieldValues = {
    server: String(REST_V2_BASE || "").trim(),
    "path.serviceProvider": String(resolvedContext.serviceProviderId || "").trim(),
    "header.Accept": "application/json",
    "header.User-Agent": typeof navigator !== "undefined" ? String(navigator.userAgent || "").trim() : "UnderPAR",
  };
  const requiredFields = ["path.serviceProvider"];
  const notes = [];
  if (resolvedContext.requestorAutoResolved === true && String(resolvedContext.requestorId || "").trim()) {
    notes.push(`Using the only REST V2 RequestorId mapped in UnderPAR: ${String(resolvedContext.requestorId || "").trim()}.`);
  }
  if (resolvedEntry.requiresAccessToken !== false) {
    fieldValues["header.Authorization"] = accessToken ? `Bearer ${String(accessToken || "").trim()}` : "";
    requiredFields.push("header.Authorization");
  }
  if (resolvedEntry.usesDeviceHeaders === true) {
    const deviceHeaders = buildRestV2Headers(resolvedContext.serviceProviderId, {});
    fieldValues["header.AP-Device-Identifier"] = String(deviceHeaders["AP-Device-Identifier"] || "").trim();
    fieldValues["header.X-Device-Info"] = String(deviceHeaders["X-Device-Info"] || "").trim();
  }
  if (resolvedEntry.contentType) {
    fieldValues["header.Content-Type"] = String(resolvedEntry.contentType || "").trim();
  }
  if (resolvedEntry.usesPartnerFrameworkStatus === true && String(resolvedContext.partnerFrameworkStatus || "").trim()) {
    fieldValues["header.AP-Partner-Framework-Status"] = String(resolvedContext.partnerFrameworkStatus || "").trim();
  }
  if (resolvedEntry.usesSessionCode === true) {
    if (String(resolvedContext.sessionCode || "").trim()) {
      fieldValues["path.code"] = String(resolvedContext.sessionCode || "").trim();
    }
    if (resolvedEntry.requireSessionCode === true) {
      requiredFields.push("path.code");
    }
  }
  if (resolvedEntry.usesMvpdPath === true) {
    if (String(resolvedContext.mvpd || "").trim()) {
      fieldValues["path.mvpd"] = String(resolvedContext.mvpd || "").trim();
    }
    if (resolvedEntry.requireMvpdPath === true) {
      requiredFields.push("path.mvpd");
    }
  }
  if (resolvedEntry.usesBodyMvpd === true && String(resolvedContext.mvpd || "").trim()) {
    fieldValues["body.mvpd"] = String(resolvedContext.mvpd || "").trim();
  }
  if (resolvedEntry.usesBodyDomainName === true) {
    if (String(resolvedContext.domainName || "").trim()) {
      fieldValues["body.domainName"] = String(resolvedContext.domainName || "").trim();
    }
    if (resolvedEntry.requireBodyDomainName === true) {
      requiredFields.push("body.domainName");
    }
  }
  if (resolvedEntry.usesBodyRedirectUrl === true) {
    if (redirectUrlValue) {
      fieldValues["body.redirectUrl"] = redirectUrlValue;
    }
    if (resolvedEntry.requireBodyRedirectUrl === true) {
      requiredFields.push("body.redirectUrl");
    }
  }
  if (resolvedEntry.usesQueryRedirectUrl === true && redirectUrlValue) {
    fieldValues["query.redirectUrl"] = redirectUrlValue;
  }
  if (resolvedEntry.usesPartnerPath === true) {
    if (String(resolvedContext.partner || "").trim()) {
      fieldValues["path.partner"] = String(resolvedContext.partner || "").trim();
    }
    if (resolvedEntry.requirePartnerPath === true) {
      requiredFields.push("path.partner");
    }
  }
  if (resolvedEntry.usesBodyResources === true) {
    if (Array.isArray(resolvedContext.resourceIds) && resolvedContext.resourceIds.length > 0) {
      fieldValues["body.resources"] = resolvedContext.resourceIds.slice();
      const poolCount = Array.isArray(resolvedContext.resourceIdPool) ? resolvedContext.resourceIdPool.length : 0;
      const selectedCount = resolvedContext.resourceIds.length;
      if (selectedCount > 0) {
        notes.push(
          poolCount > selectedCount
            ? `Using ${selectedCount} random resourceIds from the selected MVPD pool (${poolCount} available).`
            : `Using ${selectedCount} resourceIds from the selected MVPD pool.`
        );
      }
    }
    if (resolvedEntry.requireBodyResources === true) {
      requiredFields.push("body.resources");
    }
  }
  if (resolvedEntry.usesBodySamlResponse === true) {
    if (String(resolvedContext.samlResponse || "").trim()) {
      fieldValues["body.SAMLResponse"] = String(resolvedContext.samlResponse || "").trim();
    }
    if (resolvedEntry.requireBodySamlResponse === true) {
      requiredFields.push("body.SAMLResponse");
    }
    if (String(resolvedContext.samlSource || "").trim()) {
      notes.push(`Using SAMLResponse captured from ${String(resolvedContext.samlSource || "").trim()}.`);
    }
  }

  const normalizedFieldValues = Object.entries(fieldValues).reduce((result, [key, value]) => {
    if (Array.isArray(value)) {
      if (value.length > 0) {
        result[key] = value.slice();
      }
      return result;
    }
    const normalizedValue = String(value || "").trim();
    if (normalizedValue) {
      result[key] = normalizedValue;
    }
    return result;
  }, {});

  const missingRequiredFields = requiredFields.filter((fieldName) => {
    if (!fieldName) {
      return false;
    }
    if (Object.prototype.hasOwnProperty.call(normalizedFieldValues, fieldName)) {
      return false;
    }
    return true;
  });
  if (missingRequiredFields.includes("path.code")) {
    notes.push("Run LOGIN first to capture a REST V2 session code for this selection.");
  }
  if (missingRequiredFields.includes("body.resources")) {
    notes.push("Run a real authorize or preauthorize check first, or enter real resourceIds before Send.");
  }
  if (missingRequiredFields.includes("path.partner")) {
    notes.push("Run a real Partner SSO flow first, or choose the correct partner before Send.");
  }
  if (missingRequiredFields.includes("body.domainName")) {
    notes.push("UnderPAR could not resolve the first configured Channel domain for this RequestorId.");
  }
  if (missingRequiredFields.includes("body.redirectUrl") || missingRequiredFields.includes("query.redirectUrl")) {
    notes.push("UnderPAR could not resolve this operation's docs redirectUrl.");
  }
  if (missingRequiredFields.includes("body.SAMLResponse")) {
    notes.push("Complete a Partner SSO login first so UnderPAR can capture SAMLResponse for this selection.");
  }

  return {
    entryKey: String(resolvedEntry.key || "").trim(),
    docsUrl: operationDocsUrl,
    operationId: String(resolvedEntry.operationId || "").trim(),
    operationSummary: String(resolvedEntry.operationSummary || resolvedEntry.label || "").trim(),
    fieldValues: normalizedFieldValues,
    requiredFields,
    missingRequiredFields,
    notes,
  };
}

function summarizeRestV2InteractiveDocsActivationLockReason(pendingFields = [], plan = null) {
  const normalizedPendingFields = Array.isArray(pendingFields)
    ? pendingFields.map((fieldName) => String(fieldName || "").trim()).filter(Boolean)
    : [];
  const hasPendingField = (...candidates) =>
    candidates.some((candidate) => normalizedPendingFields.includes(String(candidate || "").trim()));
  const messages = [];

  if (hasPendingField("path.code")) {
    messages.push("Run LOGIN first to capture a REST V2 session code.");
  }
  if (hasPendingField("path.mvpd", "body.mvpd")) {
    messages.push("Select an MVPD and complete LOGIN first.");
  }
  if (hasPendingField("body.domainName")) {
    messages.push("UnderPAR could not resolve the first configured Channel domain for this RequestorId.");
  }
  if (hasPendingField("body.redirectUrl", "query.redirectUrl")) {
    messages.push("UnderPAR could not resolve this operation's docs redirectUrl.");
  }
  if (hasPendingField("body.resources")) {
    messages.push("Run PREAUTHORIZE or AUTHORIZE first to capture resourceIds.");
  }
  if (hasPendingField("path.partner")) {
    messages.push("Run a Partner SSO flow first to capture partner context.");
  }
  if (hasPendingField("body.SAMLResponse")) {
    messages.push("Complete Partner SSO login first to capture SAMLResponse.");
  }
  if (messages.length === 0 && Array.isArray(plan?.notes)) {
    const fallbackNote = String(plan.notes.find((note) => String(note || "").trim()) || "").trim();
    if (fallbackNote) {
      messages.push(fallbackNote);
    }
  }

  return messages.length > 0
    ? messages.slice(0, 2).join(" ")
    : "UnderPAR needs more runtime context before this call can fire.";
}

function buildRestV2InteractiveDocsEntryActivationState(entry, programmer = null, services = null) {
  const resolvedEntry = entry && typeof entry === "object" ? entry : null;
  if (!resolvedEntry?.key) {
    return {
      ready: false,
      pendingFields: [],
      reason: "This REST V2 learning entry is not configured.",
      context: null,
      plan: null,
    };
  }

  const context = buildRestV2InteractiveDocsContext(programmer, resolvedEntry);
  if (!context?.ok) {
    return {
      ready: false,
      pendingFields: [],
      reason: String(context?.error || "REST V2 learning needs more UnderPAR context.").trim(),
      context,
      plan: null,
    };
  }

  let plan = null;
  try {
    const previewAccessToken = resolvedEntry.requiresAccessToken !== false ? "__underpar_learning_preview_token__" : "";
    plan = buildRestV2InteractiveDocsHydrationPlan(resolvedEntry, context, previewAccessToken);
  } catch (error) {
    return {
      ready: false,
      pendingFields: [],
      reason: error instanceof Error ? error.message : String(error || "REST V2 learning plan failed."),
      context,
      plan: null,
    };
  }

  const pendingFields = [];
  const planFieldValues = plan?.fieldValues && typeof plan.fieldValues === "object" ? plan.fieldValues : {};
  const hasPlannedValue = (fieldName = "") => {
    const normalizedFieldName = String(fieldName || "").trim();
    if (!normalizedFieldName || !Object.prototype.hasOwnProperty.call(planFieldValues, normalizedFieldName)) {
      return false;
    }
    const value = planFieldValues[normalizedFieldName];
    if (Array.isArray(value)) {
      return value.length > 0;
    }
    return String(value || "").trim().length > 0;
  };
  const hasContextValue = (value) => {
    if (Array.isArray(value)) {
      return value.length > 0;
    }
    return String(value || "").trim().length > 0;
  };
  const pushPendingField = (fieldName, satisfied) => {
    const normalizedFieldName = String(fieldName || "").trim();
    if (!normalizedFieldName || satisfied || pendingFields.includes(normalizedFieldName)) {
      return;
    }
    pendingFields.push(normalizedFieldName);
  };

  (Array.isArray(plan?.missingRequiredFields) ? plan.missingRequiredFields : []).forEach((fieldName) => {
    if (String(fieldName || "").trim() === "header.Authorization") {
      return;
    }
    pushPendingField(fieldName, false);
  });

  pushPendingField("path.code", resolvedEntry.usesSessionCode !== true || hasPlannedValue("path.code") || hasContextValue(context.sessionCode));
  pushPendingField(
    resolvedEntry.usesMvpdPath === true ? "path.mvpd" : "body.mvpd",
    (resolvedEntry.usesMvpdPath !== true && resolvedEntry.usesBodyMvpd !== true) ||
      hasPlannedValue("path.mvpd") ||
      hasPlannedValue("body.mvpd") ||
      hasContextValue(context.mvpd)
  );
  pushPendingField(
    "body.domainName",
    resolvedEntry.usesBodyDomainName !== true || hasPlannedValue("body.domainName") || hasContextValue(context.domainName)
  );
  pushPendingField(
    resolvedEntry.usesBodyRedirectUrl === true ? "body.redirectUrl" : "query.redirectUrl",
    (resolvedEntry.usesBodyRedirectUrl !== true && resolvedEntry.usesQueryRedirectUrl !== true) ||
      hasPlannedValue("body.redirectUrl") ||
      hasPlannedValue("query.redirectUrl") ||
      hasContextValue(context.redirectUrl)
  );
  pushPendingField("path.partner", resolvedEntry.usesPartnerPath !== true || hasPlannedValue("path.partner") || hasContextValue(context.partner));
  pushPendingField(
    "body.resources",
    resolvedEntry.usesBodyResources !== true ||
      hasPlannedValue("body.resources") ||
      (Array.isArray(context.resourceIds) && context.resourceIds.length > 0)
  );
  pushPendingField(
    "body.SAMLResponse",
    resolvedEntry.usesBodySamlResponse !== true ||
      hasPlannedValue("body.SAMLResponse") ||
      hasContextValue(context.samlResponse) ||
      hasContextValue(context.flowId)
  );

  return {
    ready: pendingFields.length === 0,
    pendingFields,
    reason:
      pendingFields.length === 0
        ? "Ready to hydrate UnderPAR context and focus Send."
        : summarizeRestV2InteractiveDocsActivationLockReason(pendingFields, plan),
    context,
    plan,
  };
}

function buildRestV2InteractiveDocsSectionHtml(section = null, programmer = null) {
  const resolvedSection = section && typeof section === "object" ? section : null;
  if (!resolvedSection?.sectionKey) {
    return "";
  }

  const sectionKey = String(resolvedSection.sectionKey || "").trim();
  const sectionLabel = String(resolvedSection.sectionLabel || sectionKey).trim();
  const toggleActionLabel = `Toggle ${sectionLabel} REST API V2 interactive docs section`;
  const initialCollapsed = getRestV2InteractiveDocsSectionCollapsed(programmer?.programmerId, sectionKey);
  const totalEntries = Array.isArray(resolvedSection.entries) ? resolvedSection.entries.length : 0;
  const readyCount = Number(resolvedSection.readyCount || 0);
  const readinessLabel = `${readyCount}/${totalEntries} ready`;
  const methodCountLabel = `${totalEntries} interactive method${totalEntries === 1 ? "" : "s"}`;
  const sectionDomId = `rest-v2-doc-section-${String(programmer?.programmerId || "global")
    .trim()
    .toLowerCase()
    .replace(/[^\w-]+/g, "-")}-${sectionKey.toLowerCase().replace(/[^\w-]+/g, "-")}`;

  return `
    <section
      class="hr-rest-v2-doc-section"
      data-restv2-doc-section-key="${escapeHtml(sectionKey)}"
      data-restv2-doc-section-initial-collapsed="${initialCollapsed ? "true" : "false"}"
    >
      <button
        type="button"
        class="metadata-header service-box-header hr-rest-v2-doc-section-toggle"
        aria-controls="${escapeHtml(sectionDomId)}"
        title="${escapeHtml(toggleActionLabel)}"
        aria-label="${escapeHtml(toggleActionLabel)}"
      >
        <span class="hr-rest-v2-doc-section-toggle-copy">
          <span class="hr-rest-v2-doc-section-toggle-label">${escapeHtml(sectionLabel)}</span>
          <span class="hr-rest-v2-doc-section-toggle-meta">
            <span class="hr-rest-v2-doc-section-count">${escapeHtml(readinessLabel)}</span>
            <span class="hr-rest-v2-doc-section-status">${escapeHtml(methodCountLabel)}</span>
          </span>
        </span>
        <span class="collapse-icon" aria-hidden="true">▼</span>
      </button>
      <div class="metadata-container service-box-container hr-rest-v2-doc-section-shell" id="${escapeHtml(sectionDomId)}">
        <div class="hr-rest-v2-doc-section-grid">
          ${resolvedSection.entries
            .map((entry) => {
              const entryUrl = buildRestV2InteractiveDocsUrl(entry.operationAnchor || entry.tagAnchor || "");
              const activationState = entry.activationState || {};
              const isReady = activationState.ready === true;
              const entryActionLabel = isReady
                ? `Open and hydrate ${entry.label} in Adobe PASS REST API V2 interactive docs`
                : `${entry.label} is locked. ${String(activationState.reason || "").trim()}`;
              const readinessLabel = isReady ? "READY NOW" : "SETUP NEEDED";
              return `
                <button
                  type="button"
                  class="hr-rest-v2-doc-entry ${isReady ? "is-ready" : "is-locked"}"
                  data-restv2-doc-entry-key="${escapeHtml(entry.key)}"
                  data-restv2-doc-url="${escapeHtml(entryUrl)}"
                  data-restv2-doc-state="${isReady ? "ready" : "locked"}"
                  title="${escapeHtml(entryActionLabel)}"
                  aria-label="${escapeHtml(entryActionLabel)}"
                  ${isReady ? "" : "disabled"}
                >
                  <span class="hr-rest-v2-doc-entry-topline">
                    <span class="hr-rest-v2-doc-entry-label">${escapeHtml(entry.label)}</span>
                    <span class="hr-rest-v2-doc-entry-method">${escapeHtml(entry.methodLabel || "")}</span>
                  </span>
                  <span class="hr-rest-v2-doc-entry-summary">${escapeHtml(entry.operationSummary || "")}</span>
                  <span class="hr-rest-v2-doc-entry-readiness">
                    <span class="hr-rest-v2-doc-entry-state-badge hr-rest-v2-doc-entry-state-badge--${isReady ? "ready" : "locked"}">${escapeHtml(readinessLabel)}</span>
                    <span class="hr-rest-v2-doc-entry-state-text">${escapeHtml(String(activationState.reason || "").trim())}</span>
                  </span>
                </button>
              `;
            })
            .join("")}
        </div>
      </div>
    </section>
  `;
}

function buildRestV2InteractiveDocsPanelHtml(programmer = null, services = null) {
  if (!services?.restV2) {
    return "";
  }
  const docsUrl = buildRestV2InteractiveDocsUrl();
  const sections = getRestV2InteractiveDocsSections().map((section) => {
    const entries = section.entries.map((entry) => ({
      ...entry,
      activationState: buildRestV2InteractiveDocsEntryActivationState(entry, programmer, services),
    }));
    return {
      ...section,
      entries,
      readyCount: entries.filter((entry) => entry.activationState?.ready === true).length,
    };
  });
  const context = getHrContextSummary(programmer);
  const actionLabel = `Open REST API V2 interactive docs in main content for ${context.compositeLabel}`;
  return `
    <article class="metadata-item hr-rest-v2-docs-card">
      <div class="hr-rest-v2-docs-head">
        <a
          href="${escapeHtml(docsUrl)}"
          class="hr-rest-v2-docs-title"
          data-service-doc-key="restV2"
          data-service-doc-url="${escapeHtml(docsUrl)}"
          title="${escapeHtml(actionLabel)}"
          aria-label="${escapeHtml(actionLabel)}"
        >
          REST API V2 Interactive Docs
        </a>
        <p class="hr-rest-v2-docs-subtitle">Every customer-facing REST V2 operation, hydrated from UnderPAR context when available.</p>
      </div>
      <div class="hr-rest-v2-docs-grid">
        ${sections.map((section) => buildRestV2InteractiveDocsSectionHtml(section, programmer)).join("")}
      </div>
    </article>
  `;
}

function wireRestV2InteractiveDocsSectionCollapsibles(section, programmer = null) {
  if (!section) {
    return;
  }

  const collapsibleSections = section.querySelectorAll("[data-restv2-doc-section-key]");
  collapsibleSections.forEach((sectionElement) => {
    if (!(sectionElement instanceof HTMLElement)) {
      return;
    }

    const sectionKey = String(sectionElement.dataset.restv2DocSectionKey || "").trim();
    if (!sectionKey) {
      return;
    }

    const toggleButton = sectionElement.querySelector(".hr-rest-v2-doc-section-toggle");
    const containerElement = sectionElement.querySelector(".hr-rest-v2-doc-section-shell");
    if (!(toggleButton instanceof HTMLElement) || !(containerElement instanceof HTMLElement)) {
      return;
    }

    const initialCollapsedAttr = String(sectionElement.dataset.restv2DocSectionInitialCollapsed || "").trim().toLowerCase();
    const initialCollapsed =
      initialCollapsedAttr === "true" || getRestV2InteractiveDocsSectionCollapsed(programmer?.programmerId, sectionKey);
    wireCollapsibleSection(toggleButton, containerElement, initialCollapsed, (collapsed) => {
      setRestV2InteractiveDocsSectionCollapsed(programmer?.programmerId, sectionKey, collapsed);
    });
  });
}

function buildHrContextHealthStatusItemHtml(programmer = null) {
  const context = getHrContextSummary(programmer);
  const selectionContext = healthWorkspaceGetSelectionContext(programmer);
  const premiumContext = getHealthWorkspacePremiumContextSnapshot(String(selectionContext?.programmerId || "").trim());
  const services =
    premiumContext?.services ||
    getCurrentPremiumAppsSnapshot(String(selectionContext?.programmerId || "").trim()) ||
    getRuntimePremiumServicesSeed(String(selectionContext?.programmerId || "").trim()) ||
    null;
  const adobePassWorkflowActive =
    state.sessionReady === true && Boolean(state.loginData) && shouldHydrateAdobePassWorkflowForSession(state.loginData);
  const esmReady = Boolean(selectionContext?.programmerId && premiumContext?.hydrationReady && premiumContext?.esmAvailable);
  const cmReady = Boolean(selectionContext?.programmerId && premiumContext?.hydrationReady && shouldShowCmService(services?.cm));
  const healthReady = Boolean(selectionContext?.programmerId && selectionContext?.requestorId && premiumContext?.hydrationReady);
  const adobePassOrgRequiredLabel = "Adobe Pass org required";
  const healthActionGroupLabel = !selectionContext?.programmerId
    ? "HEALTH actions. Select a Media Company and RequestorId to unlock ESM HEALTH, CM HEALTH, and HEALTH SPLUNK."
    : !adobePassWorkflowActive
      ? `HEALTH actions. ${adobePassOrgRequiredLabel}. Switch to the Adobe Pass org profile to unlock ESM HEALTH, CM HEALTH, and HEALTH SPLUNK.`
      : !premiumContext?.hydrationReady
        ? `HEALTH actions. Preparing HEALTH workspaces for ${selectionContext.programmerName || selectionContext.programmerId}.`
        : healthReady
          ? `HEALTH actions for ${selectionContext.requestorId} in ${selectionContext.environmentLabel}.`
          : esmReady || cmReady
            ? `HEALTH actions for ${selectionContext.programmerName || selectionContext.programmerId} in ${selectionContext.environmentLabel}. Select a RequestorId to unlock HEALTH SPLUNK.`
          : context.hasProgrammerContext
            ? "HEALTH actions. Select a RequestorId to unlock HEALTH SPLUNK and scope ESM HEALTH."
            : "HEALTH actions. Select a Media Company and RequestorId to unlock ESM HEALTH, CM HEALTH, and HEALTH SPLUNK.";

  return `
    <article class="metadata-item hr-health-status-value">
      <p class="metadata-key">Status</p>
      <div class="metadata-value hr-health-status-body">
        <div class="hr-health-action-row" role="group" aria-label="${escapeHtml(healthActionGroupLabel)}">
          <button
            type="button"
            class="hr-health-action-btn hr-health-action-btn--secondary"
            data-health-action="esm"
            title="${escapeHtml(
              esmReady ? "Open ESM HEALTH dashboard" : "UnderPAR is still hydrating the ESM HEALTH context"
            )}"
            aria-label="${escapeHtml(
              esmReady ? "Open ESM HEALTH dashboard" : "UnderPAR is still hydrating the ESM HEALTH context"
            )}"
            ${esmReady ? "" : "disabled"}
          >ESM</button>
          <button
            type="button"
            class="hr-health-action-btn hr-health-action-btn--secondary"
            data-health-action="cm"
            title="${escapeHtml(
              !premiumContext?.hydrationReady
                ? "UnderPAR is still hydrating the CM HEALTH context"
                : cmReady
                  ? `Open CM HEALTH dashboard for ${selectionContext.programmerName || selectionContext.programmerId}`
                  : "Selected Media Company does not have a Concurrency Monitoring tenant match"
            )}"
            aria-label="${escapeHtml(
              !premiumContext?.hydrationReady
                ? "UnderPAR is still hydrating the CM HEALTH context"
                : cmReady
                  ? `Open CM HEALTH dashboard for ${selectionContext.programmerName || selectionContext.programmerId}`
                  : "Selected Media Company does not have a Concurrency Monitoring tenant match"
            )}"
            ${cmReady ? "" : "disabled"}
          >CM</button>
          <button
            type="button"
            class="hr-health-action-btn hr-health-action-btn--accent"
            data-health-action="splunk"
            title="${escapeHtml(
              !premiumContext?.hydrationReady
                ? "UnderPAR is still hydrating the HEALTH Splunk context"
                : healthReady
                ? `Open HEALTH Splunk workspace for ${selectionContext.requestorId}`
                : "Select a RequestorId to unlock HEALTH SPLUNK"
            )}"
            aria-label="${escapeHtml(
              !premiumContext?.hydrationReady
                ? "UnderPAR is still hydrating the HEALTH Splunk context"
                : healthReady
                ? `Open HEALTH Splunk workspace for ${selectionContext.requestorId}`
                : "Select a RequestorId to unlock HEALTH SPLUNK"
            )}"
            ${healthReady ? "" : "disabled"}
          >SPLUNK</button>
        </div>
      </div>
    </article>
  `;
}

async function handleHrContextHealthAction(action = "", programmer = null) {
  const normalizedAction = String(action || "").trim().toLowerCase();
  if (!normalizedAction) {
    return;
  }

  if (!shouldHydrateAdobePassWorkflowForSession(state.loginData)) {
    setStatus("Switch to the Adobe Pass org profile before opening HEALTH workspaces.", "error");
    return;
  }

  if (normalizedAction === "esm") {
    const programmerId = String(programmer?.programmerId || "").trim();
    const premiumContext = await ensureHealthWorkspacePremiumContext(programmerId, {
      controllerReason: "hr-health-esm",
      requestToken: Math.max(0, Number(state.premiumPanelRequestToken || 0)),
    });
    const queryContext = buildEsmHealthDashboardQueryContext({
      programmerId,
      programmerName: String(programmer?.programmerName || programmer?.mediaCompanyName || "").trim(),
      requestSource: "hr-health-esm",
    });
    if (!queryContext.programmerId) {
      setStatus("Select a Media Company before running ESM HEALTH.", "error");
      return;
    }
    if (!premiumContext?.esmAvailable) {
      setStatus("Selected Media Company does not have an ESM premium service.", "error");
      return;
    }
    setStatus(`Loading ESM HEALTH for ${buildEsmHealthStatusMessage(queryContext)}...`);
    const report = await runEsmHealthDashboardForSelection(queryContext, {
      openWorkspace: true,
      activateWorkspace: true,
      requestSource: "hr-health-esm",
    });
    if (report?.ok === true) {
      setStatus(`Loaded ESM HEALTH dashboard (${Number(report?.loadedSections || 0)}/${Number(report?.totalSections || 0)} sections).`, "success");
      return;
    }
    if (report?.partial === true) {
      setStatus(`Loaded ESM HEALTH dashboard with partial data (${Number(report?.loadedSections || 0)}/${Number(report?.totalSections || 0)} sections).`, "success");
      return;
    }
    setStatus(String(report?.error || "Unable to load ESM HEALTH dashboard."), "error");
    return;
  }

  if (normalizedAction === "cm") {
    const programmerId = String(programmer?.programmerId || "").trim();
    const premiumContext = await ensureHealthWorkspacePremiumContext(programmerId, {
      controllerReason: "hr-health-cm",
      requestToken: Math.max(0, Number(state.premiumPanelRequestToken || 0)),
    });
    const services =
      premiumContext?.services ||
      getCurrentPremiumAppsSnapshot(programmerId) ||
      getRuntimePremiumServicesSeed(programmerId) ||
      null;
    const queryContext = buildCmHealthDashboardQueryContext({
      programmerId,
      programmerName: String(programmer?.programmerName || programmer?.mediaCompanyName || "").trim(),
      requestSource: "hr-health-cm",
    });
    if (!queryContext.programmerId) {
      setStatus("Select a Media Company before running CM HEALTH.", "error");
      return;
    }
    if (!shouldShowCmService(services?.cm)) {
      setStatus("Selected Media Company does not have a Concurrency Monitoring tenant match.", "error");
      return;
    }
    setStatus(`Loading CM HEALTH for ${buildCmHealthStatusMessage(queryContext)}...`);
    const report = await runCmHealthDashboardForSelection(queryContext, {
      openWorkspace: true,
      activateWorkspace: true,
      requestSource: "hr-health-cm",
    });
    if (report?.ok === true) {
      setStatus(`Loaded CM HEALTH dashboard (${Number(report?.loadedSections || 0)}/${Number(report?.totalSections || 0)} sections).`, "success");
      return;
    }
    if (report?.partial === true) {
      setStatus(`Loaded CM HEALTH dashboard with partial data (${Number(report?.loadedSections || 0)}/${Number(report?.totalSections || 0)} sections).`, "success");
      return;
    }
    setStatus(String(report?.error || "Unable to load CM HEALTH dashboard."), "error");
    return;
  }

  if (normalizedAction !== "splunk") {
    return;
  }

  const programmerId = String(programmer?.programmerId || "").trim();
  await ensureHealthWorkspacePremiumContext(programmerId, {
    controllerReason: "hr-health-splunk",
    requestToken: Math.max(0, Number(state.premiumPanelRequestToken || 0)),
  });
  const queryContext = buildHealthSplunkQueryContext({
    programmerId,
    programmerName: String(programmer?.programmerName || "").trim(),
    requestSource: "hr-health-splunk",
  });
  if (!queryContext.programmerId || !queryContext.requestorId) {
    setStatus("Select a Media Company and RequestorId before running HEALTH Splunk.", "error");
    return;
  }

  setStatus(`Running HEALTH Splunk for ${buildHealthSplunkStatusMessage(queryContext)}...`);
  const report = await runHealthSplunkDashboardForSelection(queryContext, {
    openWorkspace: true,
    activateWorkspace: true,
    requestSource: "hr-health-splunk",
    forceLoginOnAuthFailure: true,
  });
  if (report?.ok === true) {
    setStatus(`Loaded ${Number(report?.successCount || 0)} HEALTH Splunk tables.`, "success");
    return;
  }
  if (report?.pending === true) {
    setStatus(String(report?.pendingMessage || "Waiting for Splunk sign-in/MFA to complete in the opened tab."));
    return;
  }
  if (report?.partial === true) {
    const loadedCount = Number(report?.successCount || 0);
    const totalCount = Number(report?.totalTables || 0);
    setStatus(`Loaded ${loadedCount}/${totalCount} HEALTH Splunk tables.`, "success");
    return;
  }
  setStatus(String(report?.error || "Unable to load HEALTH Splunk tables."), "error");
}

function buildHrContextSectionBodyHtml(sectionKey, programmer = null, services = null, options = {}) {
  const context = getHrContextSummary(programmer);
  const contextItemHtml = buildMetadataItemHtml("Context", context.compositeLabel);
  if (sectionKey === "health") {
    return `${contextItemHtml}${buildHrContextHealthStatusItemHtml(programmer)}`;
  }

  const detectedServiceEntries = getDetectedPremiumServiceEntries(services);
  const detectedServiceLabels = detectedServiceEntries.map((entry) => String(entry?.label || "").trim()).filter(Boolean);
  const detectedServiceSummary = detectedServiceLabels.join(", ");
  const errorText = String(options?.error || "").trim();
  let fallbackSummary = "";
  if (errorText) {
    fallbackSummary = `Service detection unavailable: ${errorText}`;
  } else if (options.loading === true && context.hasProgrammerContext) {
    fallbackSummary = `Detecting Adobe PASS services for ${context.compositeLabel}...`;
  } else if (context.hasProgrammerContext) {
    fallbackSummary = "No Adobe PASS services detected yet.";
  } else {
    fallbackSummary = "Select a media company to view detected services.";
  }
  const howtoSubject = detectedServiceSummary || fallbackSummary;
  const restV2DocsPanelHtml = buildRestV2InteractiveDocsPanelHtml(programmer, services);
  const docsItemHtml = restV2DocsPanelHtml ? "" : buildMetadataItemHtml("Docs", `HOWTO: ${howtoSubject} quick docs coming soon...`);
  return `
    ${contextItemHtml}
    ${buildHrServiceListHtml(detectedServiceEntries, fallbackSummary)}
    ${restV2DocsPanelHtml}
    ${docsItemHtml}
  `;
}

async function openPremiumServiceDocumentation(serviceKey = "", requestedUrl = "") {
  const normalizedServiceKey = String(serviceKey || "").trim();
  const documentationUrl = String(requestedUrl || PREMIUM_SERVICE_DOCUMENTATION_URL_BY_KEY[normalizedServiceKey] || "").trim();
  const serviceLabel = PREMIUM_SERVICE_TITLE_BY_KEY[normalizedServiceKey] || normalizedServiceKey || "service";

  if (!documentationUrl) {
    setStatus(`Documentation URL is not configured for ${serviceLabel}.`, "error");
    return { ok: false, error: "missing-documentation-url" };
  }

  try {
    const targetWindowId = await resolveSidepanelControllerWindowId(false);
    const created = await chrome.tabs.create({
      url: documentationUrl,
      active: true,
      ...(targetWindowId > 0 ? { windowId: targetWindowId } : {}),
    });
    const windowId = Number(created?.windowId || targetWindowId || 0);
    if (windowId > 0) {
      await chrome.windows.update(windowId, { focused: true }).catch(() => null);
    }
    return {
      ok: true,
      reused: false,
      tabId: Number(created?.id || 0),
      windowId,
      url: documentationUrl,
    };
  } catch (error) {
    setStatus(
      error instanceof Error ? error.message : `Unable to open ${serviceLabel} documentation in main content.`,
      "error"
    );
    return {
      ok: false,
      error: error instanceof Error ? error.message : String(error || "Unable to open service documentation."),
    };
  }
}

async function runRestV2InteractiveDocsHydrator(config = {}) {
  const normalize = (value) => String(value || "").trim();
  const parseFieldReference = (fieldName = "") => {
    const normalizedFieldName = normalize(fieldName);
    const dotIndex = normalizedFieldName.indexOf(".");
    if (dotIndex < 0) {
      return {
        scope: "",
        name: normalizedFieldName,
      };
    }
    return {
      scope: normalize(normalizedFieldName.slice(0, dotIndex)).toLowerCase(),
      name: normalize(normalizedFieldName.slice(dotIndex + 1)),
    };
  };
  const collectDescendants = (root) => {
    if (!root || typeof root.querySelectorAll !== "function") {
      return [];
    }
    try {
      return Array.from(root.querySelectorAll("*"));
    } catch {
      return [];
    }
  };
  const isFormControlElement = (element) =>
    Boolean(element?.CodeMirror) ||
    element instanceof HTMLInputElement ||
    element instanceof HTMLSelectElement ||
    element instanceof HTMLTextAreaElement;
  const getElementTextHaystack = (element, options = {}) => {
    if (!element) {
      return "";
    }
    const includeParentText = options?.includeParentText === true;
    const parts = [
      normalize(element.textContent),
      normalize(element.getAttribute?.("data-param-name")),
      normalize(element.getAttribute?.("data-param-in")),
      normalize(element.getAttribute?.("data-name")),
      normalize(element.getAttribute?.("name")),
      normalize(element.getAttribute?.("aria-label")),
      normalize(element.getAttribute?.("placeholder")),
      normalize(element.id),
      normalize(element.className),
    ];
    if (includeParentText) {
      parts.push(normalize(element.parentElement?.textContent));
    }
    return parts.filter(Boolean).join(" ").toLowerCase();
  };
  const findEmbeddedControlWithin = (element) => {
    if (!element) {
      return null;
    }
    if (isFormControlElement(element)) {
      return element;
    }
    return collectDescendants(element).find((candidate) => isFormControlElement(candidate)) || null;
  };
  const formatEditorBodyValue = (fieldName, rawValue) => {
    const normalizedFieldName = normalize(fieldName);
    if (normalizedFieldName === "body.resources") {
      const resources = Array.isArray(rawValue)
        ? rawValue.map((item) => String(item || "").trim()).filter(Boolean)
        : [String(rawValue || "").trim()].filter(Boolean);
      return JSON.stringify({ resources }, null, 2);
    }
    if (normalizedFieldName === "body.SAMLResponse") {
      return JSON.stringify({ SAMLResponse: String(rawValue ?? "") }, null, 2);
    }
    if (Array.isArray(rawValue) || (rawValue && typeof rawValue === "object")) {
      return JSON.stringify(rawValue, null, 2);
    }
    return String(rawValue ?? "");
  };
  const findActionButton = (scope, matchers = []) => {
    if (!scope) {
      return null;
    }
    const buttons = Array.from(scope.querySelectorAll("button"));
    return (
      buttons.find((button) =>
        matchers.some((matcher) => {
          if (typeof matcher === "string") {
            return normalize(button.textContent).toLowerCase() === matcher;
          }
          if (matcher instanceof RegExp) {
            return matcher.test(normalize(button.textContent));
          }
          if (typeof matcher === "function") {
            return matcher(button);
          }
          return false;
        })
      ) || null
    );
  };
  const sleepFor = (ms = 0) =>
    new Promise((resolve) => {
      window.setTimeout(resolve, Math.max(0, Number(ms || 0)));
    });
  const waitFor = async (resolver, timeoutMs = 15000, intervalMs = 120) => {
    const deadline = Date.now() + Math.max(1000, Number(timeoutMs || 0) || 15000);
    while (Date.now() < deadline) {
      const resolved = resolver();
      if (resolved) {
        return resolved;
      }
      await sleepFor(intervalMs);
    }
    return null;
  };
  const tryParseJsonText = (value, fallback = null) => {
    try {
      return JSON.parse(String(value || ""));
    } catch {
      return fallback;
    }
  };
  const getElementCurrentValue = (element) => {
    if (!element) {
      return "";
    }
    if (element?.CodeMirror && typeof element.CodeMirror.getValue === "function") {
      return String(element.CodeMirror.getValue() || "");
    }
    if (typeof element.value === "string") {
      return element.value;
    }
    return "";
  };
  const setElementValue = (element, rawValue, fieldName = "") => {
    if (!element) {
      return false;
    }
    if (element?.CodeMirror && typeof element.CodeMirror.setValue === "function") {
      element.CodeMirror.setValue(formatEditorBodyValue(fieldName, rawValue));
      if (typeof element.CodeMirror.save === "function") {
        element.CodeMirror.save();
      }
      element.dispatchEvent(new Event("input", { bubbles: true }));
      element.dispatchEvent(new Event("change", { bubbles: true }));
      return true;
    }
    if (element instanceof HTMLSelectElement) {
      const targetValue = normalize(rawValue);
      const options = Array.from(element.options || []);
      const matchedOption =
        options.find((option) => normalize(option.value) === targetValue) ||
        options.find((option) => normalize(option.textContent) === targetValue) ||
        options.find((option) => normalize(option.value).toLowerCase() === targetValue.toLowerCase()) ||
        options.find((option) => normalize(option.textContent).toLowerCase() === targetValue.toLowerCase());
      if (!matchedOption) {
        return false;
      }
      element.value = matchedOption.value;
      element.dispatchEvent(new Event("input", { bubbles: true }));
      element.dispatchEvent(new Event("change", { bubbles: true }));
      return true;
    }

    const valueText =
      element instanceof HTMLTextAreaElement && Array.isArray(rawValue)
        ? JSON.stringify(rawValue, null, 2)
        : Array.isArray(rawValue)
          ? rawValue.join(", ")
          : String(rawValue ?? "");

    if (element instanceof HTMLInputElement) {
      const descriptor = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, "value");
      if (descriptor?.set) {
        descriptor.set.call(element, valueText);
      } else {
        element.value = valueText;
      }
    } else if (element instanceof HTMLTextAreaElement) {
      const descriptor = Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, "value");
      if (descriptor?.set) {
        descriptor.set.call(element, valueText);
      } else {
        element.value = valueText;
      }
    } else {
      element.value = valueText;
    }

    element.dispatchEvent(new Event("input", { bubbles: true }));
    element.dispatchEvent(new Event("change", { bubbles: true }));
    element.dispatchEvent(new Event("blur", { bubbles: true }));
    return true;
  };
  const findLabeledControl = (operation, fieldName) => {
    const { scope, name } = parseFieldReference(fieldName);
    const normalizedName = String(name || "").trim().toLowerCase();
    if (!operation || !normalizedName) {
      return null;
    }
    const descendants = collectDescendants(operation);
    const candidates = descendants.filter((element) => {
      const haystack = getElementTextHaystack(element);
      if (!haystack || !haystack.includes(normalizedName)) {
        return false;
      }
      if (!scope) {
        return true;
      }
      const dataScope = normalize(element.getAttribute?.("data-param-in")).toLowerCase();
      return !dataScope || dataScope === scope || haystack.includes(scope);
    });
    for (const candidate of candidates) {
      const control = findEmbeddedControlWithin(candidate);
      if (control) {
        return control;
      }
    }
    return null;
  };
  const findRequestBodyEditor = (operation) => {
    if (!operation) {
      return null;
    }
    const explicitBodyEditor =
      operation.querySelector('[data-cy="console-request-body"] .CodeMirror') ||
      operation.querySelector('[data-cy="console-request-body"] textarea') ||
      operation.querySelector('[data-cy="console-request-body"] .react-codemirror2') ||
      operation.querySelector(".react-codemirror2 .CodeMirror") ||
      operation.querySelector(".react-codemirror2");
    if (explicitBodyEditor) {
      return findEmbeddedControlWithin(explicitBodyEditor) || explicitBodyEditor;
    }
    const descendants = collectDescendants(operation);
    const bodyCandidates = descendants.filter((element) => {
      if (!isFormControlElement(element)) {
        return false;
      }
      if (element instanceof HTMLInputElement || element instanceof HTMLSelectElement) {
        return false;
      }
      return true;
    });
    const prioritized = bodyCandidates.find((element) => {
      const haystack = getElementTextHaystack(element, { includeParentText: true });
      return haystack.includes("request body") || haystack.includes("body-param") || haystack.includes("body");
    });
    return prioritized || bodyCandidates[0] || null;
  };
  const buildRequestBodyEditorValue = (bodyEntries, editorElement, normalizedFieldValues) => {
    const contentType = String(
      normalizedFieldValues?.["header.Content-Type"] || config?.contentType || ""
    )
      .trim()
      .toLowerCase();
    const bodyRecord = {};
    bodyEntries.forEach(([fieldName, rawValue]) => {
      const { name } = parseFieldReference(fieldName);
      if (!name) {
        return;
      }
      bodyRecord[name] = Array.isArray(rawValue) ? rawValue.slice() : String(rawValue ?? "");
    });
    if (contentType.includes("application/x-www-form-urlencoded")) {
      const params = new URLSearchParams();
      Object.entries(bodyRecord).forEach(([key, value]) => {
        if (Array.isArray(value)) {
          value.forEach((item) => params.append(key, String(item ?? "")));
          return;
        }
        params.set(key, String(value ?? ""));
      });
      return params.toString();
    }
    const existingValue = getElementCurrentValue(editorElement);
    const existingObject = tryParseJsonText(existingValue, null);
    const mergedObject =
      existingObject && typeof existingObject === "object" && !Array.isArray(existingObject) ? { ...existingObject } : {};
    Object.entries(bodyRecord).forEach(([key, value]) => {
      mergedObject[key] = value;
    });
    return JSON.stringify(mergedObject, null, 2);
  };
  const findControl = (operation, fieldName) => {
    const normalizedFieldName = normalize(fieldName);
    if (!operation || !normalizedFieldName) {
      return null;
    }
    if (normalizedFieldName === "server") {
      return operation.querySelector("select");
    }
    const byId = document.getElementById(normalizedFieldName);
    if (byId && operation.contains(byId)) {
      return byId;
    }
    const escapedName = normalizedFieldName.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
    const byName = operation.querySelector(`[name="${escapedName}"]`);
    if (byName) {
      return byName;
    }
    if (normalizedFieldName === "body.resources") {
      return findRequestBodyEditor(operation);
    }
    if (normalizedFieldName === "body.SAMLResponse") {
      return findRequestBodyEditor(operation) || operation.querySelector('input[type="text"], input:not([type])');
    }
    const byLabel = findLabeledControl(operation, normalizedFieldName);
    if (byLabel) {
      return byLabel;
    }
    return null;
  };

  const operationId = normalize(config?.operationId);
  if (!operationId) {
    return {
      ok: false,
      error: "REST V2 docs hydrator is missing an operation id.",
    };
  }

  const operationElement = await waitFor(() => document.getElementById(`operation/${operationId}`), config?.timeoutMs || 18000, 140);
  if (!operationElement) {
    return {
      ok: false,
      error: `REST V2 docs did not render operation/${operationId}.`,
    };
  }

  if (location.hash !== `#operation/${operationId}`) {
    location.hash = `#operation/${operationId}`;
    await sleepFor(120);
  }

  operationElement.scrollIntoView({
    behavior: "auto",
    block: "center",
  });
  await sleepFor(200);

  const normalizedFieldValues = config?.fieldValues && typeof config.fieldValues === "object" ? config.fieldValues : {};
  const fieldNames = Object.keys(normalizedFieldValues);
  const hasInteractiveControlsMounted = () => {
    if (fieldNames.length === 0) {
      return collectDescendants(operationElement).some((element) => isFormControlElement(element));
    }
    return fieldNames.every((fieldName) => {
      if (fieldName.startsWith("body.")) {
        return Boolean(findControl(operationElement, fieldName) || findRequestBodyEditor(operationElement));
      }
      return Boolean(findControl(operationElement, fieldName));
    });
  };
  const requestButton = findActionButton(operationElement, ["request", "edit request"]);
  if (requestButton) {
    requestButton.click();
    await sleepFor(120);
  }

  const sendButtonSelector = () =>
    operationElement.querySelector('[data-cy="send-button"]') || findActionButton(operationElement, ["send", "resend"]);
  const tryItButton = await waitFor(
    () => operationElement.querySelector('[data-cy="try-it"]') || findActionButton(operationElement, [/^try it$/i]),
    config?.timeoutMs || 18000,
    140
  );
  if (tryItButton instanceof HTMLElement && (!sendButtonSelector() || !hasInteractiveControlsMounted())) {
    tryItButton.click();
  }
  const interactiveState =
    (await waitFor(() => {
      const sendButton = sendButtonSelector();
      if (!sendButton) {
        return null;
      }
      return hasInteractiveControlsMounted()
        ? {
            sendButton,
          }
        : null;
    }, config?.timeoutMs || 18000, 140)) || null;
  const sendButton = interactiveState?.sendButton || sendButtonSelector() || null;
  const filledFields = [];
  const missingControls = [];
  const bodyEditorEntries = [];
  const sharedBodyEditor = findRequestBodyEditor(operationElement);

  for (const [fieldName, rawValue] of Object.entries(normalizedFieldValues)) {
    const normalizedFieldName = normalize(fieldName);
    const control = findControl(operationElement, fieldName);
    if (normalizedFieldName.startsWith("body.") && control && sharedBodyEditor && control === sharedBodyEditor) {
      bodyEditorEntries.push([fieldName, rawValue]);
      continue;
    }
    if (!control) {
      if (normalizedFieldName.startsWith("body.")) {
        bodyEditorEntries.push([fieldName, rawValue]);
        continue;
      }
      missingControls.push(fieldName);
      continue;
    }
    if (setElementValue(control, rawValue, fieldName)) {
      filledFields.push(fieldName);
    } else {
      missingControls.push(fieldName);
    }
  }
  if (bodyEditorEntries.length > 0) {
    const bodyEditor =
      (await waitFor(() => findRequestBodyEditor(operationElement), config?.timeoutMs || 18000, 140)) || null;
    if (bodyEditor) {
      const bodyEditorValue = buildRequestBodyEditorValue(bodyEditorEntries, bodyEditor, normalizedFieldValues);
      if (setElementValue(bodyEditor, bodyEditorValue, "body")) {
        bodyEditorEntries.forEach(([fieldName]) => {
          filledFields.push(fieldName);
        });
      } else {
        bodyEditorEntries.forEach(([fieldName]) => {
          missingControls.push(fieldName);
        });
      }
    } else {
      bodyEditorEntries.forEach(([fieldName]) => {
        missingControls.push(fieldName);
      });
    }
  }

  const requiredFields = Array.isArray(config?.requiredFields) ? config.requiredFields.map((item) => normalize(item)).filter(Boolean) : [];
  const missingRequiredFields = Array.isArray(config?.missingRequiredFields)
    ? config.missingRequiredFields.map((item) => normalize(item)).filter(Boolean)
    : [];
  const unresolvedRequiredFields = [...new Set([...missingRequiredFields, ...missingControls.filter((item) => requiredFields.includes(item))])];
  const firstPendingField = unresolvedRequiredFields[0] || missingControls[0] || "";
  const firstPendingControl = firstPendingField ? findControl(operationElement, firstPendingField) : null;
  if (firstPendingControl instanceof HTMLElement) {
    firstPendingControl.focus();
  } else if (sendButton instanceof HTMLElement) {
    sendButton.focus();
  }

  return {
    ok: unresolvedRequiredFields.length === 0,
    operationId,
    operationTitle: normalize(operationElement.querySelector("h2")?.textContent),
    filledFields,
    missingControls,
    unresolvedRequiredFields,
    sendButtonFound: Boolean(sendButton),
    currentHash: normalize(location.hash),
  };
}

async function hydrateRestV2InteractiveDocsTab(tabId, plan = null) {
  const normalizedTabId = Number(tabId || 0);
  if (!chrome.scripting?.executeScript) {
    throw new Error("Chrome scripting is unavailable. Reload UnderPAR and retry.");
  }
  if (normalizedTabId <= 0) {
    throw new Error("REST V2 docs hydrator is missing a usable tab target.");
  }
  const executionResults = await chrome.scripting.executeScript({
    target: { tabId: normalizedTabId },
    world: "MAIN",
    args: [
      {
        operationId: String(plan?.operationId || "").trim(),
        requiredFields: Array.isArray(plan?.requiredFields) ? plan.requiredFields.slice() : [],
        missingRequiredFields: Array.isArray(plan?.missingRequiredFields) ? plan.missingRequiredFields.slice() : [],
        fieldValues: plan?.fieldValues && typeof plan.fieldValues === "object" ? { ...plan.fieldValues } : {},
        timeoutMs: 18000,
      },
    ],
    func: runRestV2InteractiveDocsHydrator,
  });
  const result = executionResults?.[0]?.result && typeof executionResults[0].result === "object" ? executionResults[0].result : null;
  if (!result) {
    throw new Error("REST V2 docs hydration returned no result.");
  }
  if (result.ok !== true && result.error) {
    throw new Error(String(result.error || "REST V2 docs hydration failed."));
  }
  return result;
}

async function openRestV2InteractiveDocsEntry(entryKey = "", requestedUrl = "") {
  const entry = getRestV2InteractiveDocsEntry(entryKey);
  if (!entry) {
    setStatus("UnderPAR could not resolve the requested REST V2 learning entry.", "error");
    return {
      ok: false,
      error: "missing-restv2-learning-entry",
    };
  }
  const targetUrl = String(requestedUrl || buildRestV2InteractiveDocsUrl(entry.operationAnchor || entry.tagAnchor || "")).trim();
  const openPartialDocs = async (message, type = "info") => {
    const opened = await openPremiumServiceDocumentation("restV2", targetUrl);
    if (opened?.ok !== true) {
      return opened;
    }
    const guidance = String(message || "").trim();
    setStatus(
      guidance
        ? `Opened ${entry.label} docs without full UnderPAR context. ${guidance}`
        : `Opened ${entry.label} docs without full UnderPAR context.`,
      type
    );
    return {
      ok: false,
      partial: true,
      error: guidance || "partial-restv2-learning-context",
      tabId: Number(opened?.tabId || 0),
      windowId: Number(opened?.windowId || 0),
      url: String(opened?.url || targetUrl).trim(),
    };
  };

  const context = buildRestV2InteractiveDocsContext(resolveSelectedProgrammer(), entry);
  if (!context?.ok) {
    return openPartialDocs(String(context?.error || "REST V2 learning needs a Media Company selection."));
  }

  setStatus(`Opening ${entry.label} interactive docs with UnderPAR context...`, "info");

  let tokenResult = {
    accessToken: "",
    appInfo: context.appInfo,
  };
  if (entry.requiresAccessToken !== false) {
    try {
      tokenResult = await ensureDcrAccessTokenWithServiceRecovery(context.programmerId, context.appInfo, false, {
        requestorId: context.requestorId,
        service: "rest-v2-learning",
        scope: `rest-v2-learning-${String(entry.key || "").trim()}`,
        requiredServiceScope: REST_V2_SCOPE,
        allowProvisioning: true,
        lockAppSelection: true,
      });
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      return openPartialDocs(reason, "error");
    }
  }

  let resolvedContext = null;
  let plan = null;
  try {
    resolvedContext = await prepareRestV2InteractiveDocsContextForEntry(entry, {
      ...context,
      appInfo: tokenResult?.appInfo || context.appInfo,
    });
    plan = buildRestV2InteractiveDocsHydrationPlan(entry, resolvedContext, String(tokenResult?.accessToken || "").trim());
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    return openPartialDocs(reason, "error");
  }

  const opened = await openPremiumServiceDocumentation("restV2", targetUrl);
  if (opened?.ok !== true) {
    return opened;
  }

  const tabId = Number(opened?.tabId || 0);
  if (tabId <= 0) {
    setStatus(`Opened ${entry.label} docs, but UnderPAR could not target the tab for hydration.`, "error");
    return {
      ok: false,
      error: "missing-restv2-doc-tab",
    };
  }

  await waitForTabCompletion(tabId, 20000, {
    expectedUrl: PREMIUM_SERVICE_DOCUMENTATION_URL_BY_KEY.restV2,
  }).catch(() => null);

  let hydrationResult = null;
  let lastHydrationError = null;
  for (let attempt = 1; attempt <= 3; attempt += 1) {
    try {
      hydrationResult = await hydrateRestV2InteractiveDocsTab(tabId, plan);
      break;
    } catch (error) {
      lastHydrationError = error instanceof Error ? error : new Error(String(error));
      await sleep(220 * attempt);
    }
  }

  if (!hydrationResult) {
    const reason = String(lastHydrationError?.message || "REST V2 docs hydration failed.").trim();
    setStatus(`Opened ${entry.label} docs, but UnderPAR could not hydrate the interactive form: ${reason}`, "error");
    return {
      ok: false,
      error: reason,
      tabId,
      windowId: Number(opened?.windowId || 0),
      url: targetUrl,
    };
  }

  const unresolvedRequiredFields = Array.isArray(hydrationResult.unresolvedRequiredFields)
    ? hydrationResult.unresolvedRequiredFields.filter(Boolean)
    : [];
  if (unresolvedRequiredFields.length > 0) {
    setStatus(
      `Opened ${entry.label} docs with partial UnderPAR context. Fill ${unresolvedRequiredFields.join(", ")} before Send.`,
      "info"
    );
  } else if (Array.isArray(plan.notes) && plan.notes.length > 0) {
    setStatus(`Opened ${entry.label} docs with UnderPAR context. ${plan.notes[0]}`, "info");
  } else {
    setStatus(`Opened ${entry.label} docs with UnderPAR context and focused Send.`, "success");
  }

  return {
    ok: unresolvedRequiredFields.length === 0,
    partial: unresolvedRequiredFields.length > 0,
    tabId,
    windowId: Number(opened?.windowId || 0),
    url: targetUrl,
    hydrationResult,
    plan,
  };
}

function createHrContextSection(programmer, sectionKey, services = null, options = {}) {
  const title = HR_CONTEXT_SECTION_TITLE_BY_KEY[sectionKey] || String(sectionKey || "").trim().toUpperCase();
  const context = getHrContextSummary(programmer);
  const hoverMessage = `${title} guidance for ${context.compositeLabel}`;
  const section = document.createElement("article");
  section.className = `metadata-section hr-context-section hr-context-section--${sectionKey}`;
  section.dataset.hrSectionKey = String(sectionKey || "").trim();
  const initialCollapsed = getHrContextSectionCollapsed(programmer?.programmerId, sectionKey);
  applyServiceBoxSectionShell(section, {
    title,
    hoverMessage,
    initialCollapsed,
    contentClassName: "hr-context-content",
    bodyHtml: buildHrContextSectionBodyHtml(sectionKey, programmer, services, options),
    onCollapsedChange: (collapsed) => {
      setHrContextSectionCollapsed(programmer?.programmerId, sectionKey, collapsed);
    },
  });
  if (sectionKey === "learning") {
    wireRestV2InteractiveDocsSectionCollapsibles(section, programmer);
  }
  wireHrContextSectionActions(section);

  return section;
}

function renderHrSections(services, programmer = null, options = {}) {
  if (!els.hrServicesContainer) {
    return;
  }

  if (!shouldRevealHrContextSections(programmer, services)) {
    delete els.hrServicesContainer.dataset.renderSignature;
    setHrContextSectionsVisibility(false);
    return;
  }

  const renderSignature = buildHrSectionsRenderSignature(programmer, services, options);
  if (
    renderSignature &&
    String(els.hrServicesContainer.dataset.renderSignature || "") === renderSignature &&
    hasRenderableHrContextSections()
  ) {
    setHrContextSectionsVisibility(true);
    return;
  }

  setHrContextSectionsVisibility(true);
  els.hrServicesContainer.innerHTML = "";
  const topDivider = document.createElement("div");
  topDivider.className = "hr-context-divider";
  topDivider.setAttribute("aria-hidden", "true");
  els.hrServicesContainer.appendChild(topDivider);
  for (const sectionKey of HR_CONTEXT_SECTION_DISPLAY_ORDER) {
    els.hrServicesContainer.appendChild(createHrContextSection(programmer, sectionKey, services, options));
  }
  const bottomDivider = document.createElement("div");
  bottomDivider.className = "hr-context-divider";
  bottomDivider.setAttribute("aria-hidden", "true");
  els.hrServicesContainer.appendChild(bottomDivider);
  els.hrServicesContainer.dataset.renderSignature = renderSignature;
}

function renderPremiumServices(services, programmer = null, options = {}) {
  renderHrSections(services, programmer);
  esmHealthWorkspaceBroadcastControllerState(programmer);
  healthWorkspaceBroadcastControllerState(programmer);
  if (!els.premiumServicesContainer) {
    return;
  }
  clearPremiumServiceAutoRefreshTimers();
  const controllerReason = String(options?.controllerReason || "").trim();

  if (!services) {
    esmWorkspaceBroadcastSelectedControllerState(programmer, null, 0, {
      controllerReason,
      esmAvailabilityResolved: false,
      esmContainerVisible: null,
    });
    cmBroadcastSelectedControllerState(programmer, null, 0, {
      controllerReason,
      cmAvailabilityResolved: false,
      cmContainerVisible: null,
    });
    mvpdWorkspaceBroadcastSelectedControllerState(programmer, null);
    degradationWorkspaceBroadcastControllerState(programmer, null, 0, {
      controllerReason,
    });
    bobtoolsWorkspaceBroadcastControllerState(programmer, {
      programmerId: String(programmer?.programmerId || "").trim(),
      programmerName: String(programmer?.programmerName || "").trim(),
      userLabel: getUnderparActiveUserLabel(),
      hasProfiles: false,
      requestorId: "",
      mvpd: "",
      mvpdLabel: "",
      selectedHarvestKey: "",
    });
    void bobtoolsWorkspaceSendWorkspaceMessage("profiles-update", {
      programmerId: "",
      programmerName: "",
      userLabel: getUnderparActiveUserLabel(),
      requestorId: "",
      mvpd: "",
      mvpdLabel: "",
      selectedHarvestKey: "",
      profileCount: 0,
      profiles: [],
      updatedAt: Date.now(),
    });
    delete els.premiumServicesContainer.dataset.renderSignature;
    els.premiumServicesContainer.innerHTML = programmer?.programmerId
      ? '<p class="metadata-empty">No premium scoped applications loaded yet.</p>'
      : '<p class="metadata-empty">Select a Media Company to load premium scoped applications.</p>';
    return;
  }
  const availableKeys = getDetectedPremiumServiceKeys(services);
  const hasCmContainer = availableKeys.includes("cm") || availableKeys.includes("cmMvpd");
  cmBroadcastSelectedControllerState(programmer, services, 0, {
    controllerReason,
    cmAvailabilityResolved: true,
    cmContainerVisible: hasCmContainer,
  });
  mvpdWorkspaceBroadcastSelectedControllerState(programmer, services);
  degradationWorkspaceBroadcastControllerState(programmer, services, 0, {
    controllerReason,
  });
  const hasEsmContainer = availableKeys.includes("esmWorkspace");
  esmWorkspaceBroadcastSelectedControllerState(programmer, services, 0, {
    controllerReason,
    esmAvailabilityResolved: true,
    esmContainerVisible: hasEsmContainer,
  });
  if (availableKeys.length === 0) {
    delete els.premiumServicesContainer.dataset.renderSignature;
    els.premiumServicesContainer.innerHTML =
      '<p class="metadata-empty">No premium scoped applications found for this media company.</p>';
    return;
  }

  const renderSignature = buildPremiumServicesRenderSignature(programmer, services);
  if (
    renderSignature &&
    String(els.premiumServicesContainer.dataset.renderSignature || "") === renderSignature &&
    hasRenderablePremiumServiceSections(services)
  ) {
    refreshExistingPremiumServiceSections(programmer, services);
    refreshMvpdWorkspaceTools();
    refreshRestV2LoginPanels();
    return;
  }

  els.premiumServicesContainer.innerHTML = "";
  for (const serviceKey of availableKeys) {
    const appInfo = serviceKey === "esmWorkspace" ? services.esm : services[serviceKey];
    const section = createPremiumServiceSection(programmer, serviceKey, appInfo);
    els.premiumServicesContainer.appendChild(section);
  }
  els.premiumServicesContainer.dataset.renderSignature = renderSignature;
  refreshMvpdWorkspaceTools();
  refreshRestV2LoginPanels();
}

