function randomStateValue() {
  const bytes = new Uint8Array(16);
  crypto.getRandomValues(bytes);
  return Array.from(bytes, (value) => value.toString(16).padStart(2, "0")).join("");
}

function generateRequestId() {
  return `${Date.now()}-${Math.floor(Math.random() * 1000000)}`;
}

function isAuthFlowUrl(url) {
  if (!url) {
    return false;
  }

  const value = String(url).toLowerCase();
  return (
    value.includes("adobelogin.com") ||
    value.includes("auth.services.adobe.com") ||
    value.includes("experience.adobe.com") ||
    value.includes("experience-stage.adobe.com") ||
    /console\.auth(?:-staging)?\.adobe\.com/i.test(value) ||
    value.includes("pps.services.adobe.com")
  );
}

function summarizeUrl(url) {
  if (!url) {
    return "";
  }

  try {
    const parsed = new URL(url);
    return `${parsed.origin}${parsed.pathname}`;
  } catch {
    return String(url);
  }
}

function applyCapturedAvatarToProfile(profilePayload, avatarCandidate) {
  const normalizedAvatar = normalizeAvatarCandidate(avatarCandidate) || normalizeInlineAvatarData(avatarCandidate);
  if (!normalizedAvatar) {
    return profilePayload && typeof profilePayload === "object" ? profilePayload : null;
  }

  const baseProfile = profilePayload && typeof profilePayload === "object" ? { ...profilePayload } : {};
  const additionalInfo =
    baseProfile.additional_info && typeof baseProfile.additional_info === "object"
      ? { ...baseProfile.additional_info }
      : {};

  const existingBest = getBestNonSyntheticProfileAvatarCandidate(baseProfile) || extractProfileImageUrl(baseProfile);
  const identity = getProfileIdentityValue(baseProfile);
  const existingIsSyntheticIdentity = existingBest ? isImsAvatarForIdentity(existingBest, identity) : false;
  const shouldPreferCaptured = !existingBest || existingIsSyntheticIdentity || isPpsProfileImageUrl(normalizedAvatar);

  if (shouldPreferCaptured) {
    baseProfile.user_image_url = normalizedAvatar;
    baseProfile.userImageUrl = normalizedAvatar;
    baseProfile.avatarUrl = normalizedAvatar;
    baseProfile.avatar = normalizedAvatar;
    baseProfile.avatar_url = normalizedAvatar;
  } else {
    if (!baseProfile.user_image_url) {
      baseProfile.user_image_url = normalizedAvatar;
    }
    if (!baseProfile.userImageUrl) {
      baseProfile.userImageUrl = normalizedAvatar;
    }
    if (!baseProfile.avatarUrl && !baseProfile.avatar && !baseProfile.avatar_url) {
      baseProfile.avatarUrl = normalizedAvatar;
    }
  }

  if (!additionalInfo.user_image_url || shouldPreferCaptured) {
    additionalInfo.user_image_url = normalizedAvatar;
  }
  if (!additionalInfo.userImageUrl || shouldPreferCaptured) {
    additionalInfo.userImageUrl = normalizedAvatar;
  }
  if ((!additionalInfo.avatar && !additionalInfo.avatarUrl && !additionalInfo.avatar_url) || shouldPreferCaptured) {
    additionalInfo.avatarUrl = normalizedAvatar;
  }

  baseProfile.additional_info = additionalInfo;
  return normalizeProfileAvatarFields(baseProfile);
}

function extractAuthParams(responseUrl) {
  const response = new URL(responseUrl);
  const params = new URLSearchParams(response.search);

  let hash = response.hash.startsWith("#") ? response.hash.slice(1) : response.hash;
  if (hash) {
    hash = hash.replace(/from_ims=true\?/gi, "from_ims=true&").replace(/#/g, "&");
    const hashParams = new URLSearchParams(hash);
    for (const [key, value] of hashParams.entries()) {
      if (!params.has(key)) {
        params.set(key, value);
      }
    }
  }

  return params;
}

function decodeBase64UrlText(value) {
  const normalized = String(value || "").trim();
  if (!normalized) {
    return "";
  }

  let padded = normalized.replace(/-/g, "+").replace(/_/g, "/");
  const remainder = padded.length % 4;
  if (remainder) {
    padded += "=".repeat(4 - remainder);
  }

  try {
    return decodeURIComponent(escape(atob(padded)));
  } catch {
    try {
      return atob(padded);
    } catch {
      return "";
    }
  }
}

function parseJwtPayload(accessToken = "") {
  const token = String(accessToken || "").trim();
  if (!token) {
    return null;
  }

  const parts = token.split(".");
  if (parts.length < 2) {
    return null;
  }

  const decodedPayload = decodeBase64UrlText(parts[1]);
  const parsedPayload = parseJsonText(decodedPayload, null);
  return parsedPayload && typeof parsedPayload === "object" ? parsedPayload : null;
}

function parseImsStatePayload(rawState = "") {
  const normalized = String(rawState || "").trim();
  if (!normalized || !normalized.startsWith("{")) {
    return null;
  }
  const parsed = parseJsonText(normalized, null);
  return parsed && typeof parsed === "object" ? parsed : null;
}

function mergeImsSessionSnapshots(baseSession, incomingSession) {
  const base = baseSession && typeof baseSession === "object" ? baseSession : {};
  const incoming = incomingSession && typeof incomingSession === "object" ? incomingSession : {};
  const merged = pruneEmptyObject({
    tokenId: firstNonEmptyString([incoming.tokenId, incoming.id, base.tokenId, base.id]),
    sessionId: firstNonEmptyString([incoming.sessionId, incoming.sid, base.sessionId, base.sid]),
    sessionUrl: firstNonEmptyString([incoming.sessionUrl, incoming.session, base.sessionUrl, base.session]),
    userId: firstNonEmptyString([incoming.userId, incoming.user_id, base.userId, base.user_id]),
    authId: firstNonEmptyString([incoming.authId, incoming.aa_id, base.authId, base.aa_id]),
    clientId: firstNonEmptyString([incoming.clientId, incoming.client_id, base.clientId, base.client_id]),
    tokenType: firstNonEmptyString([incoming.tokenType, incoming.type, base.tokenType, base.type]),
    scope: firstNonEmptyString([incoming.scope, base.scope]),
    as: firstNonEmptyString([incoming.as, base.as]),
    fg: firstNonEmptyString([incoming.fg, base.fg]),
    moi: firstNonEmptyString([incoming.moi, base.moi]),
    pba: firstNonEmptyString([incoming.pba, base.pba]),
    keyAlias: firstNonEmptyString([incoming.keyAlias, incoming.key_alias, base.keyAlias, base.key_alias]),
    stateNonce: firstNonEmptyString([incoming.stateNonce, incoming.nonce, base.stateNonce, base.nonce]),
    stateJslibVersion: firstNonEmptyString([
      incoming.stateJslibVersion,
      incoming.jslibver,
      base.stateJslibVersion,
      base.jslibver,
    ]),
    createdAt: Number(incoming.createdAt || incoming.created_at || base.createdAt || base.created_at || 0),
    issuedAt: Number(incoming.issuedAt || incoming.issued_at || base.issuedAt || base.issued_at || 0),
    expiresAt: Number(incoming.expiresAt || incoming.expires_at || base.expiresAt || base.expires_at || 0),
  });

  return Object.keys(merged).length > 0 ? merged : null;
}

function deriveImsSessionSnapshotFromToken(accessToken = "") {
  const claims = parseJwtPayload(accessToken);
  if (!claims) {
    return null;
  }

  const statePayload = parseImsStatePayload(firstNonEmptyString([claims.state]));
  const expSeconds = Number(claims.exp || 0);
  const iatSeconds = Number(claims.iat || 0);
  const createdAtRaw = Number(claims.created_at || 0);
  const createdAtMs =
    createdAtRaw > 0 && createdAtRaw < 1000000000000 ? createdAtRaw * 1000 : createdAtRaw > 0 ? createdAtRaw : 0;

  return mergeImsSessionSnapshots(null, {
    tokenId: claims.id,
    sessionId: claims.sid,
    sessionUrl: firstNonEmptyString([claims.session, statePayload?.session]),
    userId: firstNonEmptyString([claims.user_id, claims.userId]),
    authId: firstNonEmptyString([claims.aa_id, claims.authId]),
    clientId: firstNonEmptyString([claims.client_id, claims.clientId]),
    tokenType: firstNonEmptyString([claims.type]),
    scope: firstNonEmptyString([claims.scope]),
    as: claims.as,
    fg: claims.fg,
    moi: claims.moi,
    pba: claims.pba,
    keyAlias: firstNonEmptyString([claims.key_alias, claims.keyAlias]),
    stateNonce: statePayload?.nonce,
    stateJslibVersion: firstNonEmptyString([statePayload?.jslibver, statePayload?.jslibVersion]),
    createdAt: createdAtMs,
    issuedAt: Number.isFinite(iatSeconds) && iatSeconds > 0 ? iatSeconds * 1000 : 0,
    expiresAt: Number.isFinite(expSeconds) && expSeconds > 0 ? expSeconds * 1000 : 0,
  });
}

function coercePositiveNumber(value) {
  const numeric = Number(value);
  return Number.isFinite(numeric) && numeric > 0 ? numeric : 0;
}

function resolveAuthResponseExpiry(accessToken, expiresInValue) {
  const tokenSnapshot = deriveImsSessionSnapshotFromToken(accessToken);
  const tokenExpiresAt = coercePositiveNumber(tokenSnapshot?.expiresAt);
  const expiresIn = coercePositiveNumber(expiresInValue);
  const now = Date.now();

  if (!expiresIn) {
    return {
      expiresAt: tokenExpiresAt,
      tokenSnapshot,
    };
  }

  const expiresAtFromSeconds = now + expiresIn * 1000;
  const expiresAtFromMilliseconds = now + expiresIn;
  if (tokenExpiresAt > 0) {
    const candidates = [tokenExpiresAt, expiresAtFromSeconds];
    if (expiresIn >= 1000) {
      candidates.push(expiresAtFromMilliseconds);
    }

    let bestCandidate = tokenExpiresAt;
    let bestDelta = Number.POSITIVE_INFINITY;
    for (const candidate of candidates) {
      if (!Number.isFinite(candidate) || candidate <= 0) {
        continue;
      }
      const delta = Math.abs(candidate - tokenExpiresAt);
      if (delta < bestDelta) {
        bestDelta = delta;
        bestCandidate = candidate;
      }
    }

    return {
      expiresAt: bestCandidate,
      tokenSnapshot,
    };
  }

  const appearsToBeMilliseconds = expiresIn >= 100000 && expiresIn <= 24 * 60 * 60 * 1000;
  return {
    expiresAt: appearsToBeMilliseconds ? expiresAtFromMilliseconds : expiresAtFromSeconds,
    tokenSnapshot,
  };
}

function getDefaultUnderparImsAuthConfiguration() {
  return {
    issuer: IMS_ISSUER_URL,
    authorization_endpoint: IMS_DEFAULT_AUTHORIZATION_ENDPOINT,
    token_endpoint: IMS_DEFAULT_TOKEN_ENDPOINT,
    userinfo_endpoint: IMS_DEFAULT_USERINFO_ENDPOINT,
    revocation_endpoint: IMS_DEFAULT_REVOCATION_ENDPOINT,
  };
}

function getActiveUnderparImsRuntimeConfig(vault = state?.passVault || null) {
  return (
    getUnderparVaultImsRuntimeConfig(vault) || {
      schemaVersion: 1,
      clientId: "",
      scope: IMS_SCOPE,
      rawScope: IMS_SCOPE,
      droppedScopes: [],
      organizations: [],
      source: "defaults",
      importedAt: "",
      updatedAt: 0,
    }
  );
}

async function requireUnderparImsRuntimeConfig() {
  const vault = state.passVault || (await ensurePassVaultLoaded({ forceReload: false }));
  const runtimeConfig = getActiveUnderparImsRuntimeConfig(vault);
  if (runtimeConfig?.clientId) {
    return runtimeConfig;
  }
  throw new Error("Adobe IMS client ID is not configured. Drop or choose a ZIP.KEY with adobe.ims.client_id in the VAULT import panel first.");
}

function getUnderparImsRedirectUri() {
  try {
    return chrome.identity?.getRedirectURL ? chrome.identity.getRedirectURL("ims-callback") : "";
  } catch {
    return "";
  }
}

function getUnderparImsClientIdCandidates(accessToken = "", ...hints) {
  const tokenClaims = parseJwtPayload(accessToken) || {};
  const runtimeConfig = getActiveUnderparImsRuntimeConfig();
  return uniquePreserveOrder(
    [
      ...hints,
      firstNonEmptyString([tokenClaims?.client_id, tokenClaims?.clientId]),
      runtimeConfig?.clientId,
    ]
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
}

async function fetchValidateTokenSessionSnapshot(accessToken = "") {
  const token = String(accessToken || "").trim();
  if (!token) {
    return null;
  }

  const endpoint = `${IMS_BASE_URL}/ims/validate_token/v1?jslVersion=underpar`;
  const clientIds = getUnderparImsClientIdCandidates(token);

  for (const clientId of clientIds) {
    const body = new URLSearchParams({
      type: "access_token",
      client_id: clientId,
      token,
    });
    const attempts = [
      { credentials: "omit" },
      { credentials: "include" },
    ];

    for (const attempt of attempts) {
      try {
        const response = await relayImsFetch(endpoint, {
          method: "POST",
          credentials: attempt.credentials,
          headers: {
            Accept: "application/json, text/plain, */*",
            "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8",
          },
          body: body.toString(),
        });
        if (!response.ok) {
          continue;
        }

        const parsed = parseJsonText(await response.text().catch(() => ""), null);
        if (!parsed || typeof parsed !== "object") {
          continue;
        }

        const tokenPayload = parsed?.token && typeof parsed.token === "object" ? parsed.token : {};
        const statePayload = parseImsStatePayload(firstNonEmptyString([tokenPayload?.state]));
        const createdAtRaw = Number(tokenPayload?.created_at || 0);
        const createdAtMs =
          createdAtRaw > 0 && createdAtRaw < 1000000000000 ? createdAtRaw * 1000 : createdAtRaw > 0 ? createdAtRaw : 0;

        const snapshot = mergeImsSessionSnapshots(null, {
          tokenId: tokenPayload?.id,
          sessionId: tokenPayload?.sid,
          sessionUrl: firstNonEmptyString([statePayload?.session]),
          userId: firstNonEmptyString([tokenPayload?.user_id]),
          authId: firstNonEmptyString([tokenPayload?.aa_id]),
          clientId: firstNonEmptyString([tokenPayload?.client_id, clientId]),
          tokenType: firstNonEmptyString([tokenPayload?.type]),
          scope: firstNonEmptyString([tokenPayload?.scope]),
          as: tokenPayload?.as,
          fg: tokenPayload?.fg,
          moi: tokenPayload?.moi,
          pba: tokenPayload?.pba,
          keyAlias: firstNonEmptyString([tokenPayload?.key_alias]),
          stateNonce: statePayload?.nonce,
          stateJslibVersion: firstNonEmptyString([statePayload?.jslibver, statePayload?.jslibVersion]),
          createdAt: createdAtMs,
          expiresAt: Number(parsed?.expires_at || 0),
        });
        if (snapshot) {
          return snapshot;
        }
      } catch {
        // Continue best-effort across client/credential variants.
      }
    }
  }

  return null;
}

async function getTabByIdSafe(tabId) {
  const normalizedTabId = Number(tabId || 0);
  if (!Number.isInteger(normalizedTabId) || normalizedTabId <= 0 || !chrome.tabs?.get) {
    return null;
  }
  try {
    return await chrome.tabs.get(normalizedTabId);
  } catch {
    return null;
  }
}

function buildUnderparImsAuthError(parsed, text, fallbackMessage = "Adobe IMS request failed.") {
  const payload = parsed && typeof parsed === "object" ? parsed : {};
  const code = firstNonEmptyString([
    String(payload?.error || "").trim(),
    String(payload?.code || "").trim(),
    String(payload?.errorCode || "").trim(),
  ]);
  const description = firstNonEmptyString([
    String(payload?.error_description || "").trim(),
    String(payload?.errorDescription || "").trim(),
    String(payload?.message || "").trim(),
    String(payload?.errorMessage || "").trim(),
    normalizeHttpErrorMessage(text),
  ]);
  const message = code && description ? `${code}: ${description}` : description || code || fallbackMessage;
  return new Error(redactSensitiveTokenValues(message));
}

async function revokeUnderparImsToken({ revocationEndpoint = IMS_DEFAULT_REVOCATION_ENDPOINT, clientId = "", token = "" } = {}) {
  const normalizedToken = String(token || "").trim();
  const normalizedClientId = String(clientId || "").trim();
  if (!normalizedToken || !normalizedClientId) {
    return;
  }

  const endpoint = new URL(String(revocationEndpoint || IMS_DEFAULT_REVOCATION_ENDPOINT));
  endpoint.searchParams.set("client_id", normalizedClientId);

  let response;
  try {
    response = await relayImsFetch(endpoint.toString(), {
      method: "POST",
      credentials: "omit",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        token: normalizedToken,
      }).toString(),
    });
  } catch (error) {
    throw new Error(`Unable to revoke Adobe token: ${error instanceof Error ? error.message : String(error)}`);
  }

  if (response.ok) {
    return;
  }

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  throw buildUnderparImsAuthError(parsed, text, "Adobe token revocation failed.");
}

function getUnderparLogoutClientId(loginData = null) {
  const sessionData = loginData && typeof loginData === "object" ? loginData : {};
  const accessTokenClaims = parseJwtPayload(firstNonEmptyString([sessionData?.accessToken])) || {};
  const runtimeConfig = getActiveUnderparImsRuntimeConfig();
  return firstNonEmptyString([
    accessTokenClaims?.client_id,
    accessTokenClaims?.clientId,
    sessionData?.imsSession?.clientId,
    sessionData?.imsSession?.client_id,
    runtimeConfig?.clientId,
  ]);
}

async function revokeUnderparLoginTokensForLogout(loginData = null) {
  const sessionData = loginData && typeof loginData === "object" ? loginData : {};
  const clientId = getUnderparLogoutClientId(sessionData);
  if (!clientId) {
    return;
  }

  const authConfiguration = await fetchUnderparImsOpenIdConfiguration().catch(() => getDefaultUnderparImsAuthConfiguration());
  const revocationEndpoint = firstNonEmptyString([
    authConfiguration?.revocation_endpoint,
    IMS_DEFAULT_REVOCATION_ENDPOINT,
  ]);
  const tokensToRevoke = uniquePreserveOrder([
    firstNonEmptyString([sessionData?.accessToken]),
    firstNonEmptyString([sessionData?.refreshToken]),
  ]).filter(Boolean);
  if (tokensToRevoke.length === 0) {
    return;
  }

  const revocationResults = await Promise.allSettled(
    tokensToRevoke.map((token) =>
      revokeUnderparImsToken({
        revocationEndpoint,
        clientId,
        token,
      })
    )
  );

  for (const result of revocationResults) {
    if (result.status === "rejected") {
      log("Adobe token revocation failed", result.reason instanceof Error ? result.reason.message : String(result.reason));
    }
  }
}

async function fetchUnderparImsOpenIdConfiguration() {
  const defaults = getDefaultUnderparImsAuthConfiguration();
  try {
    const response = await relayImsFetch(IMS_OPENID_CONFIGURATION_URL, {
      method: "GET",
      credentials: "omit",
      headers: {
        Accept: "application/json",
      },
    });
    const text = await response.text().catch(() => "");
    const parsed = parseJsonText(text, null);
    if (!response.ok) {
      throw buildUnderparImsAuthError(parsed, text, "Adobe IMS discovery failed.");
    }
    if (!parsed || typeof parsed !== "object") {
      return defaults;
    }
    return {
      ...defaults,
      ...parsed,
    };
  } catch {
    return defaults;
  }
}

function buildPkceCodeVerifier(length = 64) {
  const normalizedLength = Number.isFinite(Number(length)) ? Math.max(43, Math.min(128, Number(length))) : 64;
  const bytes = new Uint8Array(normalizedLength);
  crypto.getRandomValues(bytes);
  let output = "";
  for (const byte of bytes) {
    output += PKCE_VERIFIER_CHARSET[byte % PKCE_VERIFIER_CHARSET.length];
  }
  return output;
}

async function buildPkceCodeChallenge(codeVerifier = "") {
  const verifier = String(codeVerifier || "").trim();
  if (verifier.length < 43) {
    throw new Error("PKCE code verifier is too short.");
  }
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(verifier));
  const bytes = new Uint8Array(digest);
  let binary = "";
  for (const byte of bytes) {
    binary += String.fromCharCode(byte);
  }
  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function buildUnderparImsAuthorizationCodeUrl({
  authorizationEndpoint = IMS_DEFAULT_AUTHORIZATION_ENDPOINT,
  clientId = "",
  redirectUri = "",
  scope = IMS_SCOPE,
  state = "",
  codeChallenge = "",
  prompt = "",
  extraParams = {},
} = {}) {
  const params = new URLSearchParams({
    client_id: String(clientId || "").trim(),
    redirect_uri: String(redirectUri || "").trim(),
    response_type: "code",
    scope: normalizeImsScopeList(scope, IMS_SCOPE),
    state: String(state || "").trim(),
    code_challenge_method: "S256",
    code_challenge: String(codeChallenge || "").trim(),
    response_mode: "query",
  });
  if (prompt) {
    params.set("prompt", String(prompt));
  }
  for (const [key, value] of Object.entries(extraParams || {})) {
    const normalizedKey = String(key || "").trim().toLowerCase();
    if (
      normalizedKey === "client_id" ||
      normalizedKey === "redirect_uri" ||
      normalizedKey === "response_type" ||
      normalizedKey === "response_mode" ||
      normalizedKey === "code_challenge" ||
      normalizedKey === "code_challenge_method"
    ) {
      continue;
    }
    if (value !== undefined && value !== null && value !== "") {
      params.set(key, String(value));
    }
  }
  return `${String(authorizationEndpoint || IMS_DEFAULT_AUTHORIZATION_ENDPOINT).trim()}?${params.toString()}`;
}

function buildUnderparImsLogoutUrl({
  logoutEndpoint = IMS_DEFAULT_LOGOUT_ENDPOINT,
  accessToken = "",
  redirectUri = "",
  clientId = "",
} = {}) {
  const params = new URLSearchParams();
  const normalizedAccessToken = String(accessToken || "").trim();
  const normalizedRedirectUri = String(redirectUri || "").trim();
  const normalizedClientId = String(clientId || "").trim();

  if (normalizedAccessToken) {
    params.set("access_token", normalizedAccessToken);
  }
  if (normalizedRedirectUri) {
    params.set("redirect_uri", normalizedRedirectUri);
  }
  if (normalizedClientId) {
    params.set("client_id", normalizedClientId);
  }

  return `${String(logoutEndpoint || IMS_DEFAULT_LOGOUT_ENDPOINT).trim()}?${params.toString()}`;
}

function parseUnderparImsAuthorizationCodeResponse(responseUrl, expectedState = "") {
  const authParams = extractAuthParams(responseUrl);
  const authError = authParams.get("error");
  if (authError) {
    throw buildUnderparImsAuthError(
      {
        error: authError,
        error_description: authParams.get("error_description"),
      },
      "",
      "Adobe IMS authorization failed."
    );
  }

  const returnedState = String(authParams.get("state") || "").trim();
  const normalizedExpectedState = String(expectedState || "").trim();
  if (normalizedExpectedState && returnedState !== normalizedExpectedState) {
    throw new Error("State validation failed.");
  }

  const code = String(authParams.get("code") || "").trim();
  if (!code) {
    throw new Error("No authorization code returned from Adobe IMS.");
  }

  return {
    code,
    state: returnedState,
  };
}

async function exchangeUnderparImsAuthorizationCode({
  tokenEndpoint = IMS_DEFAULT_TOKEN_ENDPOINT,
  clientId = "",
  code = "",
  codeVerifier = "",
} = {}) {
  const endpoint = new URL(String(tokenEndpoint || IMS_DEFAULT_TOKEN_ENDPOINT));
  endpoint.searchParams.set("client_id", String(clientId || "").trim());
  const body = new URLSearchParams({
    code: String(code || "").trim(),
    grant_type: "authorization_code",
    code_verifier: String(codeVerifier || "").trim(),
  });
  const response = await relayImsFetch(endpoint.toString(), {
    method: "POST",
    credentials: "omit",
    headers: {
      Accept: "application/json",
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: body.toString(),
  });
  const text = await response.text().catch(() => "");
  const parsed = parseJsonOrFormText(text, null);
  if (!response.ok) {
    throw buildUnderparImsAuthError(parsed, text, "Adobe IMS token exchange failed.");
  }
  if (!parsed || typeof parsed !== "object") {
    throw new Error("Adobe IMS token exchange returned an invalid response.");
  }
  return parsed;
}

async function fetchUnderparImsUserInfo({
  userInfoEndpoint = IMS_DEFAULT_USERINFO_ENDPOINT,
  accessToken = "",
  clientId = "",
} = {}) {
  const token = String(accessToken || "").trim();
  if (!token) {
    return null;
  }

  const endpoint = new URL(String(userInfoEndpoint || IMS_DEFAULT_USERINFO_ENDPOINT));
  if (clientId) {
    endpoint.searchParams.set("client_id", String(clientId).trim());
  }
  const response = await relayImsFetch(endpoint.toString(), {
    method: "GET",
    credentials: "omit",
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${token}`,
    },
  });
  const text = await response.text().catch(() => "");
  const parsed = normalizeProfileAvatarFields(parseJsonText(text, null));
  if (!response.ok) {
    throw buildUnderparImsAuthError(parsed, text, "Adobe IMS user info request failed.");
  }
  return parsed && typeof parsed === "object" ? parsed : null;
}

function shouldRetryUnderparImsLoginWithIdentityScope(error, configuredScope = "") {
  void error;
  void configuredScope;
  return false;
}

function shouldRetryUnderparImsLoginWithConfiguredScope(error, attemptedScope = "", configuredScope = "") {
  const message = String(error?.message || error || "").toLowerCase();
  return (
    message.includes("invalid_scope") &&
    normalizeImsScopeList(attemptedScope, IMS_SCOPE) !== normalizeImsScopeList(configuredScope, IMS_SCOPE)
  );
}

function isExpectedUnderparSilentAuthMiss(error) {
  const message = String(error?.message || error || "").toLowerCase();
  return [
    "authorization page could not be loaded",
    "login_required",
    "interaction_required",
    "consent_required",
    "access_denied",
    "no authorization code returned",
  ].some((token) => message.includes(token));
}

async function launchUnderparImsAuthorizationFlow(authorizeUrl, interactive = true) {
  if (!chrome.identity || typeof chrome.identity.launchWebAuthFlow !== "function") {
    throw new Error("chrome.identity.launchWebAuthFlow is unavailable.");
  }

  if (interactive) {
    return await chrome.identity.launchWebAuthFlow({
      url: authorizeUrl,
      interactive: true,
    });
  }

  return await chrome.identity.launchWebAuthFlow({
    url: authorizeUrl,
    interactive: false,
    abortOnLoadForNonInteractive: false,
    timeoutMsForNonInteractive: NON_INTERACTIVE_AUTH_TIMEOUT_MS,
  });
}

async function runUnderparImsBrowserLogout(options = {}) {
  const interactive = options?.interactive !== false;
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([options?.accessToken, state.loginData?.accessToken])
  );
  const redirectUri = firstNonEmptyString([options?.redirectUri, getUnderparImsRedirectUri()]);
  const clientId = firstNonEmptyString([options?.clientId, ...getUnderparImsClientIdCandidates(accessToken)]);
  if (!redirectUri || (!accessToken && !clientId)) {
    return false;
  }

  const logoutUrl = buildUnderparImsLogoutUrl({
    accessToken,
    redirectUri,
    clientId,
  });

  log("Starting UnderPAR Adobe IMS browser logout", {
    interactive,
    hasAccessToken: Boolean(accessToken),
    clientId,
    redirectUri,
  });

  try {
    await launchUnderparImsAuthorizationFlow(logoutUrl, interactive);
    return true;
  } catch (error) {
    log("UnderPAR Adobe IMS browser logout failed", {
      interactive,
      clientId,
      error: error instanceof Error ? error.message : String(error),
    });
    return false;
  }
}

function normalizeUnderparImsPrompt(promptValue = "", interactive = true) {
  if (interactive !== true) {
    return "none";
  }

  const normalizedPrompt = String(promptValue || "").trim().toLowerCase();
  return normalizedPrompt === "login" ? "login" : "";
}

async function runUnderparPkceLogin(options = {}) {
  const interactive = options?.interactive !== false;
  const extraParams = options?.extraParams && typeof options.extraParams === "object" ? options.extraParams : {};
  const prompt = normalizeUnderparImsPrompt(options?.prompt, interactive);
  const runtimeConfig = await requireUnderparImsRuntimeConfig();
  const authConfiguration = await fetchUnderparImsOpenIdConfiguration();
  const redirectUri = getUnderparImsRedirectUri();
  if (!redirectUri) {
    throw new Error("Unable to generate the UnderPAR Adobe IMS redirect URI.");
  }

  const runAttempt = async (requestedScope, reason = "configured-scope") => {
    const requestState = randomStateValue();
    const codeVerifier = buildPkceCodeVerifier();
    const codeChallenge = await buildPkceCodeChallenge(codeVerifier);
    const authorizeUrl = buildUnderparImsAuthorizationCodeUrl({
      authorizationEndpoint: firstNonEmptyString([
        authConfiguration?.authorization_endpoint,
        IMS_DEFAULT_AUTHORIZATION_ENDPOINT,
      ]),
      clientId: runtimeConfig.clientId,
      redirectUri,
      scope: requestedScope,
      state: requestState,
      codeChallenge,
      prompt,
      extraParams,
    });

    log("Starting UnderPAR Adobe IMS PKCE login", {
      interactive,
      reason,
      clientId: runtimeConfig.clientId,
      scope: requestedScope,
      prompt,
      redirectUri,
    });

    let responseUrl = "";
    let capturedAvatarUrl = "";
    let authPopupTabId = 0;
    if (interactive) {
      responseUrl = String(await launchUnderparImsAuthorizationFlow(authorizeUrl, true));
    } else {
      responseUrl = String(await launchUnderparImsAuthorizationFlow(authorizeUrl, false));
    }

    const authResponse = parseUnderparImsAuthorizationCodeResponse(responseUrl, requestState);
    const tokenPayload = await exchangeUnderparImsAuthorizationCode({
      tokenEndpoint: firstNonEmptyString([authConfiguration?.token_endpoint, IMS_DEFAULT_TOKEN_ENDPOINT]),
      clientId: runtimeConfig.clientId,
      code: authResponse.code,
      codeVerifier,
    });

    const accessToken = String(tokenPayload?.access_token || "").trim();
    if (!accessToken) {
      throw new Error("Adobe IMS token exchange returned no access token.");
    }

    const tokenExpiry = resolveAuthResponseExpiry(accessToken, tokenPayload?.expires_in);
    const accessTokenClaims = parseJwtPayload(accessToken) || {};
    const idToken = String(tokenPayload?.id_token || "").trim();
    const idTokenClaims = parseJwtPayload(idToken) || {};
    const returnedScope = compactStorageString(
      resolveGrantedUnderparImsScope(
        accessToken,
        firstNonEmptyString([String(tokenPayload?.scope || "").trim(), requestedScope]),
        requestedScope
      ),
      2048
    );
    const expiresAt = coercePositiveNumber(tokenExpiry?.expiresAt);
    const tokenType = compactStorageString(firstNonEmptyString([String(tokenPayload?.token_type || "").trim()]), 60) || "bearer";
    const mergedImsSession = mergeImsSessionSnapshots(
      mergeImsSessionSnapshots(tokenExpiry?.tokenSnapshot || null, {
        userId: firstNonEmptyString([idTokenClaims?.sub]),
        sessionId: firstNonEmptyString([idTokenClaims?.sid]),
        authId: firstNonEmptyString([idTokenClaims?.aa_id, idTokenClaims?.authId]),
      }),
      {
        clientId: firstNonEmptyString([accessTokenClaims?.client_id, accessTokenClaims?.clientId, runtimeConfig.clientId]),
        tokenType,
        scope: returnedScope,
        expiresAt,
      }
    );

    const [userInfoResult, profileResult, organizationsResult] = await Promise.allSettled([
      fetchUnderparImsUserInfo({
        userInfoEndpoint: firstNonEmptyString([authConfiguration?.userinfo_endpoint, IMS_DEFAULT_USERINFO_ENDPOINT]),
        accessToken,
        clientId: runtimeConfig.clientId,
      }),
      fetchProfile(accessToken),
      fetchOrganizations(accessToken),
    ]);
    const mergedProfile = mergeProfilePayloads(
      userInfoResult.status === "fulfilled" ? userInfoResult.value : null,
      profileResult.status === "fulfilled" ? profileResult.value : null
    );

    return {
      accessToken,
      expiresAt,
      tokenType,
      scope: returnedScope,
      idToken: compactStorageString(idToken, 4096),
      refreshToken: compactStorageString(firstNonEmptyString([String(tokenPayload?.refresh_token || "").trim()]), 4096),
      imsSession: mergedImsSession,
      profile: mergedProfile,
      organizations:
        organizationsResult.status === "fulfilled" && organizationsResult.value && typeof organizationsResult.value === "object"
          ? organizationsResult.value
          : null,
      capturedAvatarUrl,
      authPopupTabId,
    };
  };

  const configuredScope = normalizeImsScopeList(firstNonEmptyString([runtimeConfig.scope, IMS_SCOPE]), IMS_SCOPE);
  const effectiveConfiguredScope = interactive ? resolveInteractiveUnderparRequestedScope(configuredScope) : configuredScope;
  const scopePlan = buildUnderparRequestedScopePlan(effectiveConfiguredScope);
  let lastError = null;
  for (const [index, requestedScope] of scopePlan.entries()) {
    try {
      return await runAttempt(
        requestedScope,
        index === 0
          ? requestedScope === effectiveConfiguredScope
            ? "configured-scope"
            : "preferred-org-discovery-scope"
          : "configured-scope-fallback"
      );
    } catch (error) {
      lastError = error;
      if (
        shouldRetryUnderparImsLoginWithConfiguredScope(error, requestedScope, effectiveConfiguredScope) &&
        index < scopePlan.length - 1
      ) {
        continue;
      }
      if (!shouldRetryUnderparImsLoginWithIdentityScope(error, effectiveConfiguredScope)) {
        throw error;
      }
      break;
    }
  }

  throw lastError || new Error("Adobe IMS login failed.");
}

async function startLogin(options = {}) {
  const interactive = options?.interactive !== false;
  try {
    const authData = await runUnderparPkceLogin(options);
    return authData;
  } catch (error) {
    if (!interactive && isExpectedUnderparSilentAuthMiss(error)) {
      throw error;
    }
    throw error;
  }
}

function buildImsProfileHeaders(accessToken = "", clientId = "") {
  const headers = {
    Accept: "application/json, text/plain, */*",
    "Content-Type": "application/json;charset=utf-8",
  };

  const normalizedClientId = String(clientId || "").trim();
  if (normalizedClientId) {
    headers["X-IMS-ClientId"] = normalizedClientId;
    headers["x-api-key"] = normalizedClientId;
    headers.client_id = normalizedClientId;
  }

  if (accessToken) {
    headers.Authorization = `Bearer ${accessToken}`;
  }

  return headers;
}

function getProfileIdentityValue(profilePayload) {
  if (!profilePayload || typeof profilePayload !== "object") {
    return "";
  }

  return firstNonEmptyString([
    profilePayload?.userId,
    profilePayload?.user_id,
    profilePayload?.sub,
    profilePayload?.id,
  ]);
}

function isImsAvatarForIdentity(candidate, identityValue) {
  const normalized = normalizeAvatarCandidate(candidate);
  const identity = String(identityValue || "").trim();
  if (!normalized || !identity || !isImsAvatarDownloadUrl(normalized)) {
    return false;
  }

  try {
    const parsed = new URL(normalized);
    const match = parsed.pathname.match(/\/ims\/avatar\/download\/([^/?#]+)/i);
    if (!match) {
      return false;
    }

    const decodedIdentity = decodeURIComponent(String(match[1] || "")).trim();
    return decodedIdentity === identity;
  } catch {
    return false;
  }
}

function isSyntheticIdentityAvatarCandidate(profilePayload, candidate) {
  const identity = getProfileIdentityValue(profilePayload);
  if (!identity) {
    return false;
  }
  return isImsAvatarForIdentity(candidate, identity);
}

function getNonSyntheticProfileAvatarCandidates(profilePayload) {
  if (!profilePayload || typeof profilePayload !== "object") {
    return [];
  }

  const allCandidates = [
    ...getProfileInlineAvatarDataCandidates(profilePayload),
    ...getProfileAvatarCandidates(profilePayload),
    ...collectAvatarCandidatesFromProfileShape(profilePayload),
  ]
    .map((value) => normalizeAvatarCandidate(value) || normalizeInlineAvatarData(value))
    .filter(Boolean);

  const unique = [...new Set(allCandidates)];
  const nonSynthetic = unique.filter((candidate) => !isSyntheticIdentityAvatarCandidate(profilePayload, candidate));
  return prioritizeAvatarCandidates(nonSynthetic);
}

function getBestNonSyntheticProfileAvatarCandidate(profilePayload) {
  return getNonSyntheticProfileAvatarCandidates(profilePayload)[0] || "";
}

function scoreProfileAvatarPayload(profilePayload) {
  if (!profilePayload || typeof profilePayload !== "object") {
    return Number.NEGATIVE_INFINITY;
  }

  const nonSyntheticCandidates = getNonSyntheticProfileAvatarCandidates(profilePayload);
  if (nonSyntheticCandidates.length === 0) {
    const fallbackCandidates = getProfileAvatarCandidates(profilePayload).filter(Boolean);
    return fallbackCandidates.length > 0 ? -20 : -100;
  }

  const bestCandidateScore = nonSyntheticCandidates
    .slice(0, 10)
    .reduce((bestScore, candidate) => Math.max(bestScore, scoreAvatarCandidatePriority(candidate)), -100);
  return bestCandidateScore + Math.min(nonSyntheticCandidates.length, 10) * 4;
}

function normalizeProfileAvatarFields(profilePayload) {
  if (!profilePayload || typeof profilePayload !== "object") {
    return profilePayload;
  }

  const inlineAvatar = getProfileInlineAvatarDataUrl(profilePayload);
  const directAvatar = normalizeAvatarCandidate(
    firstNonEmptyString([
      profilePayload?.user_image_url,
      profilePayload?.userImageUrl,
      profilePayload?.avatar,
      profilePayload?.avatarUrl,
      profilePayload?.avatar_url,
      profilePayload?.additional_info?.user_image_url,
      profilePayload?.additional_info?.userImageUrl,
      profilePayload?.additional_info?.avatar,
      profilePayload?.additional_info?.avatarUrl,
      profilePayload?.additional_info?.avatar_url,
    ])
  );
  const discoveredAvatar = getBestNonSyntheticProfileAvatarCandidate(profilePayload);
  const avatar = directAvatar || inlineAvatar || discoveredAvatar;
  if (!avatar) {
    return profilePayload;
  }

  if (!profilePayload.user_image_url) {
    profilePayload.user_image_url = avatar;
  }
  if (!profilePayload.userImageUrl) {
    profilePayload.userImageUrl = avatar;
  }
  if (!profilePayload.avatar && !profilePayload.avatarUrl && !profilePayload.avatar_url) {
    profilePayload.avatarUrl = avatar;
  }
  return profilePayload;
}

async function fetchProfile(accessToken) {
  const clientIdCandidates = getUnderparImsClientIdCandidates(accessToken);
  const endpoints = [
    ...clientIdCandidates.map((clientId) => ({
      url: `${IMS_PROFILE_URL}?client_id=${encodeURIComponent(clientId)}`,
      clientId,
    })),
    {
      url: IMS_PROFILE_URL,
      clientId: "",
    },
  ];

  let lastError = null;
  let bestPayload = null;
  let bestPayloadScore = Number.NEGATIVE_INFINITY;
  for (const endpoint of endpoints) {
    const attempts = [
      { credentials: "omit" },
      { credentials: "include" },
    ];

    for (const attempt of attempts) {
      try {
        const response = await relayImsFetch(endpoint.url, {
          method: "GET",
          credentials: attempt.credentials,
          headers: buildImsProfileHeaders(accessToken, endpoint.clientId),
        });

        const text = await response.text().catch(() => "");
        if (!response.ok) {
          lastError = new Error(
            `Profile request failed (${response.status} ${response.statusText})${
              text ? ` - ${normalizeHttpErrorMessage(text)}` : ""
            }`
          );
          continue;
        }

        const parsed = parseJsonText(text, null);
        if (!parsed || typeof parsed !== "object") {
          continue;
        }

        const normalizedPayload = normalizeProfileAvatarFields(parsed);
        const payloadScore = scoreProfileAvatarPayload(normalizedPayload);
        if (payloadScore > bestPayloadScore) {
          bestPayload = normalizedPayload;
          bestPayloadScore = payloadScore;
        }
        if (payloadScore >= 320) {
          return normalizedPayload;
        }
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));
      }
    }
  }

  if (bestPayload) {
    return bestPayload;
  }

  throw lastError || new Error("Profile request failed.");
}

async function resolveProfileAfterLogin(authData) {
  const capturedAvatarUrl = normalizeAvatarCandidate(
    firstNonEmptyString([authData?.capturedAvatarUrl, authData?.imageUrl])
  );
  const hasInlineProfile = Boolean(authData && Object.prototype.hasOwnProperty.call(authData, "profile"));
  if (hasInlineProfile) {
    if (authData?.profile && typeof authData.profile === "object") {
      return applyCapturedAvatarToProfile(normalizeProfileAvatarFields(authData.profile), capturedAvatarUrl);
    }
    return applyCapturedAvatarToProfile({}, capturedAvatarUrl) || {};
  }

  const fetchedProfile = await fetchProfile(authData?.accessToken || "");
  return applyCapturedAvatarToProfile(fetchedProfile, capturedAvatarUrl) || fetchedProfile;
}

function mergeProfilePayloads(baseProfile, updateProfile) {
  const base = baseProfile && typeof baseProfile === "object" ? baseProfile : {};
  const update = updateProfile && typeof updateProfile === "object" ? updateProfile : {};
  return {
    ...base,
    ...update,
    additional_info: {
      ...(base.additional_info && typeof base.additional_info === "object" ? base.additional_info : {}),
      ...(update.additional_info && typeof update.additional_info === "object" ? update.additional_info : {}),
    },
  };
}

async function fetchImsSessionProfile(accessToken = "") {
  const normalizedAccessToken = normalizeBearerTokenValue(accessToken);
  if (!normalizedAccessToken) {
    return null;
  }

  const imsBase = IMS_BASE_URL;
  const clientIdCandidates = getUnderparImsClientIdCandidates(normalizedAccessToken);
  const endpoints = [
    ...clientIdCandidates.map((clientId) => `${IMS_PROFILE_URL}?client_id=${encodeURIComponent(clientId)}`),
    IMS_PROFILE_URL,
    ...clientIdCandidates.map((clientId) => `${imsBase}/ims/userinfo/v2?client_id=${encodeURIComponent(clientId)}`),
  ];

  const variants = [];
  const dedupeKeys = new Set();
  const pushVariant = (clientId, credentials, includeToken) => {
    const headers = buildImsProfileHeaders(includeToken ? normalizedAccessToken : "", clientId);
    const key = `${clientId}|${credentials}|${includeToken ? "token" : "notoken"}`;
    if (dedupeKeys.has(key)) {
      return;
    }
    dedupeKeys.add(key);
    variants.push({ credentials, headers });
  };

  for (const clientId of clientIdCandidates) {
    pushVariant(clientId, "omit", true);
    pushVariant(clientId, "include", true);
  }

  pushVariant("", "omit", true);
  pushVariant("", "include", true);

  let bestPayload = null;
  let bestPayloadScore = Number.NEGATIVE_INFINITY;
  for (const endpoint of endpoints) {
    for (const variant of variants) {
      try {
        const response = await relayImsFetch(endpoint, {
          method: "GET",
          credentials: variant.credentials,
          headers: variant.headers,
        });
        if (!response.ok) {
          continue;
        }

        const text = await response.text().catch(() => "");
        const parsed = parseJsonText(text, null);
        if (!parsed || typeof parsed !== "object") {
          continue;
        }

        const normalizedPayload = normalizeProfileAvatarFields(parsed);
        const payloadScore = scoreProfileAvatarPayload(normalizedPayload);
        if (payloadScore > bestPayloadScore) {
          bestPayload = normalizedPayload;
          bestPayloadScore = payloadScore;
        }
        if (payloadScore >= 320) {
          return normalizedPayload;
        }
      } catch {
        // Continue to next endpoint/variant.
      }
    }
  }

  return bestPayload;
}

async function fetchOrganizations(accessToken) {
  const normalizedAccessToken = normalizeBearerTokenValue(accessToken);
  if (!normalizedAccessToken) {
    throw new Error("Organizations request failed: missing Adobe IMS access token.");
  }
  const grantedScope = resolveGrantedUnderparImsScope(normalizedAccessToken, "", "");
  if (getMissingUnderparImsScopeTokens(grantedScope, "read_organizations").length > 0) {
    throw new Error('Organizations request failed: token does not have the "read_organizations" scope.');
  }

  const clientIdCandidates = getUnderparImsClientIdCandidates(normalizedAccessToken);
  const endpoints = [
    ...clientIdCandidates.map((clientId) => ({
      url: `${IMS_ORGS_URL}?client_id=${encodeURIComponent(clientId)}`,
      clientId,
    })),
    {
      url: IMS_ORGS_URL,
      clientId: "",
    },
  ];

  let lastError = null;
  let bestPayload = null;
  let bestPayloadScore = Number.NEGATIVE_INFINITY;
  for (const endpoint of endpoints) {
    const attempts = [
      { credentials: "omit" },
      { credentials: "include" },
    ];

    for (const attempt of attempts) {
      try {
        const response = await relayImsFetch(endpoint.url, {
          method: "GET",
          credentials: attempt.credentials,
          headers: buildImsProfileHeaders(normalizedAccessToken, endpoint.clientId),
        });
        const text = await response.text().catch(() => "");
        if (!response.ok) {
          lastError = new Error(
            `Organizations request failed (${response.status} ${response.statusText})${
              text ? ` - ${normalizeHttpErrorMessage(text)}` : ""
            }`
          );
          continue;
        }

        const parsed = parseJsonText(text, null);
        if (!parsed || typeof parsed !== "object") {
          continue;
        }

        const payloadScore = flattenOrganizations(parsed).length;
        if (payloadScore > bestPayloadScore) {
          bestPayload = parsed;
          bestPayloadScore = payloadScore;
        }
        if (payloadScore > 0) {
          return parsed;
        }
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));
      }
    }
  }

  if (bestPayload) {
    return bestPayload;
  }

  throw lastError || new Error("Organizations request failed.");
}

function extractUnifiedShellErrorMessage(parsedPayload, rawText = "") {
  if (parsedPayload && typeof parsedPayload === "object") {
    const directMessage = firstNonEmptyString([
      parsedPayload.message,
      parsedPayload.error,
      parsedPayload.error_description,
      parsedPayload.detail,
      parsedPayload.reason,
    ]);
    if (directMessage) {
      return directMessage;
    }

    if (Array.isArray(parsedPayload.errors)) {
      const firstError =
        parsedPayload.errors.find((value) => value && typeof value === "object") || parsedPayload.errors[0];
      if (firstError && typeof firstError === "object") {
        return firstNonEmptyString([
          firstError.message,
          firstError.detail,
          firstError.error,
          firstError.reason,
        ]);
      }
      return firstNonEmptyString(parsedPayload.errors);
    }
  }

  return firstNonEmptyString([normalizeHttpErrorMessage(rawText), String(rawText || "").trim()]);
}

function normalizeUnderparUnifiedShellOrganizationNode(organization, cluster = null) {
  if (!organization || typeof organization !== "object") {
    return null;
  }

  const tenantId = firstNonEmptyString([organization.tenantId, organization.tenant_id]);
  const imsOrgId = firstNonEmptyString([organization.imsOrgId, organization.ims_org_id]);
  const orgName = firstNonEmptyString([
    organization.orgName,
    organization.org_name,
    organization.organizationName,
    organization.organization_name,
  ]);
  const id = firstNonEmptyString([tenantId, imsOrgId, organization.id]);
  if (!id && !orgName) {
    return null;
  }

  return {
    id,
    orgId: id,
    tenantId,
    imsOrgId,
    name: orgName || id,
    orgName: orgName || id,
    organizationName: orgName || id,
    aepRegion: firstNonEmptyString([organization.aepRegion, organization.aep_region]),
    hasAEP: organization.hasAEP === true,
    aemInstances: Array.isArray(organization.aemInstances) ? organization.aemInstances : [],
    clusterIndex: Number.isFinite(cluster?.index) ? cluster.index : -1,
    clusterUserId: firstNonEmptyString([cluster?.userId]),
    clusterUserType: firstNonEmptyString([cluster?.userType]),
    clusterRestricted: cluster?.restricted === true,
    consolidatedAccount: cluster?.consolidatedAccount === true,
  };
}

function collectUnderparUnifiedShellOrganizations(parsedPayload = null, options = {}) {
  const clusterRows = Array.isArray(parsedPayload?.data?.imsExtendedAccountClusterData?.data)
    ? parsedPayload.data.imsExtendedAccountClusterData.data
    : [];
  const selectedOrg = normalizeOrganizationIdentifier(firstNonEmptyString([options?.selectedOrg]));
  const activeOrganization = options?.activeOrganization && typeof options.activeOrganization === "object"
    ? options.activeOrganization
    : null;
  const activeIdentifiers = new Set(
    [
      firstNonEmptyString([activeOrganization?.key]),
      firstNonEmptyString([activeOrganization?.id]),
      firstNonEmptyString([activeOrganization?.orgId]),
      firstNonEmptyString([activeOrganization?.tenantId]),
      firstNonEmptyString([activeOrganization?.imsOrgId]),
      firstNonEmptyString([activeOrganization?.name]),
      firstNonEmptyString([activeOrganization?.label]),
    ].map((value) => normalizeOrganizationIdentifier(value)).filter(Boolean)
  );
  const candidateMap = new Map();
  const idIndex = new Map();
  const nameIndex = new Map();

  const upsertOrganization = (organization, source, cluster = null) => {
    const normalized = normalizeUnderparUnifiedShellOrganizationNode(organization, cluster);
    if (!normalized) {
      return;
    }

    const orgId = firstNonEmptyString([normalized.orgId, normalized.id, normalized.tenantId, normalized.imsOrgId]);
    const userId = firstNonEmptyString([normalized.clusterUserId, normalized.userId]);
    const name =
      firstNonEmptyString([normalized.name, normalized.orgName, normalized.organizationName, orgId ? `Adobe IMS Org ${orgId}` : ""]) ||
      "Adobe organization";
    const normalizedId = normalizeOrganizationIdentifier(orgId);
    const normalizedName = normalizeOrganizationIdentifier(name);
    let existingKey = normalizedId ? idIndex.get(normalizedId) : "";
    if (!existingKey && normalizedName) {
      existingKey = nameIndex.get(normalizedName) || "";
    }

    const key = firstNonEmptyString([
      normalized.key,
      buildRestrictedOrgOptionKey({
        orgId,
        userId,
        name,
      }),
    ]);
    const label = firstNonEmptyString([
      normalized.label,
      buildRestrictedOrgOptionLabel({
        name,
        orgId,
        userId,
      }),
      name,
    ]);
    const hinted =
      normalized.hinted === true ||
      activeIdentifiers.has(normalizedId) ||
      activeIdentifiers.has(normalizedName) ||
      activeIdentifiers.has(normalizeOrganizationIdentifier(key)) ||
      (selectedOrg && selectedOrg === normalizeOrganizationIdentifier(normalized.tenantId));

    if (!existingKey) {
      if (!key) {
        return;
      }

      const nextCandidate = {
        ...normalized,
        key,
        id: orgId,
        orgId,
        tenantId: firstNonEmptyString([normalized.tenantId, orgId && !/@adobeorg$/i.test(orgId) ? orgId : ""]),
        imsOrgId: firstNonEmptyString([normalized.imsOrgId, /@adobeorg$/i.test(orgId) ? orgId : ""]),
        userId,
        name,
        label,
        source,
        sources: source ? [source] : [],
        hinted,
        isAdobePass: matchesAdobePassOrg(normalized),
        raw: organization,
      };
      candidateMap.set(key, nextCandidate);
      if (normalizedId) {
        idIndex.set(normalizedId, key);
      }
      if (normalizedName) {
        nameIndex.set(normalizedName, key);
      }
      return;
    }

    const existingCandidate = candidateMap.get(existingKey);
    if (!existingCandidate) {
      return;
    }

    existingCandidate.id = firstNonEmptyString([existingCandidate.id, orgId]);
    existingCandidate.orgId = firstNonEmptyString([existingCandidate.orgId, orgId]);
    existingCandidate.tenantId = firstNonEmptyString([
      existingCandidate.tenantId,
      normalized.tenantId,
      existingCandidate.orgId && !/@adobeorg$/i.test(existingCandidate.orgId) ? existingCandidate.orgId : "",
    ]);
    existingCandidate.imsOrgId = firstNonEmptyString([
      existingCandidate.imsOrgId,
      normalized.imsOrgId,
      /@adobeorg$/i.test(existingCandidate.orgId) ? existingCandidate.orgId : "",
    ]);
    existingCandidate.userId = firstNonEmptyString([existingCandidate.userId, userId]);
    const existingSourceRank = rankRestrictedOrganizationSource(existingCandidate.source);
    const incomingSourceRank = rankRestrictedOrganizationSource(source);
    existingCandidate.name =
      incomingSourceRank < existingSourceRank && firstNonEmptyString([name])
        ? name
        : choosePreferredOrganizationName(existingCandidate.name, name, existingCandidate.orgId || orgId);
    existingCandidate.label = buildRestrictedOrgOptionLabel({
      name: existingCandidate.name,
      orgId: existingCandidate.orgId,
      userId: existingCandidate.userId,
    });
    existingCandidate.aepRegion = firstNonEmptyString([existingCandidate.aepRegion, normalized.aepRegion]);
    existingCandidate.hasAEP = existingCandidate.hasAEP === true || normalized.hasAEP === true;
    if ((!Array.isArray(existingCandidate.aemInstances) || existingCandidate.aemInstances.length === 0) && Array.isArray(normalized.aemInstances)) {
      existingCandidate.aemInstances = normalized.aemInstances;
    }
    existingCandidate.clusterIndex =
      existingCandidate.clusterIndex >= 0 ? existingCandidate.clusterIndex : Number(normalized.clusterIndex || -1);
    existingCandidate.clusterUserId = firstNonEmptyString([existingCandidate.clusterUserId, normalized.clusterUserId, normalized.userId]);
    existingCandidate.clusterUserType = firstNonEmptyString([existingCandidate.clusterUserType, normalized.clusterUserType]);
    existingCandidate.clusterRestricted = existingCandidate.clusterRestricted === true || normalized.clusterRestricted === true;
    existingCandidate.consolidatedAccount =
      existingCandidate.consolidatedAccount === true || normalized.consolidatedAccount === true;
    existingCandidate.hinted =
      existingCandidate.hinted === true ||
      hinted === true;
    existingCandidate.isAdobePass = existingCandidate.isAdobePass === true || matchesAdobePassOrg(normalized);
    if (source && !existingCandidate.sources.includes(source)) {
      existingCandidate.sources.push(source);
    }
    if (!existingCandidate.source || incomingSourceRank < existingSourceRank) {
      existingCandidate.source = source;
      existingCandidate.raw = organization;
    }
  };

  clusterRows.forEach((cluster) => {
    if (!cluster || typeof cluster !== "object") {
      return;
    }
    const normalizedCluster = {
      index: Number.isFinite(cluster?.index) ? cluster.index : clusterRows.indexOf(cluster),
      consolidatedAccount: cluster?.consolidatedAccount === true,
      restricted: cluster?.restricted === true,
      userId: firstNonEmptyString([cluster?.userId]),
      userType: firstNonEmptyString([cluster?.userType]),
    };
    upsertOrganization(
      cluster.owningOrg,
      `unifiedShell.imsExtendedAccountClusterData[${normalizedCluster.index}].owningOrg`,
      normalizedCluster
    );
    (Array.isArray(cluster.orgs) ? cluster.orgs : []).forEach((organization, organizationIndex) => {
      upsertOrganization(
        organization,
        `unifiedShell.imsExtendedAccountClusterData[${normalizedCluster.index}].orgs[${organizationIndex}]`,
        normalizedCluster
      );
    });
  });

  return Array.from(candidateMap.values());
}

function resolveRestrictedPickerSelectedOrg(preferredOrg = null, sessionData = null) {
  const activeOrganization = preferredOrg && typeof preferredOrg === "object" ? preferredOrg : null;
  const session = sessionData && typeof sessionData === "object" ? sessionData : null;
  const profile = resolveLoginProfile(session);
  const requestedTargetOrganization = normalizeRequestedTargetOrganization(session?.targetOrganization);
  const targetSelectedOrg = firstNonEmptyString([
    requestedTargetOrganization?.tenantId,
    requestedTargetOrganization?.id && !/@adobeorg$/i.test(String(requestedTargetOrganization?.id || "").trim())
      ? requestedTargetOrganization.id
      : "",
  ]);
  if (targetSelectedOrg) {
    return targetSelectedOrg;
  }

  const previousSelectedOrg = firstNonEmptyString([session?.unifiedShell?.selectedOrg]);
  if (previousSelectedOrg && !/@adobeorg$/i.test(previousSelectedOrg)) {
    return previousSelectedOrg;
  }

  const activeId = firstNonEmptyString([activeOrganization?.tenantId, activeOrganization?.id]);
  if (activeId && !/@adobeorg$/i.test(activeId)) {
    return activeId;
  }

  const projectedProductContexts = [
    ...(Array.isArray(profile?.projectedProductContext) ? profile.projectedProductContext : []),
    ...(Array.isArray(profile?.additional_info?.projectedProductContext)
      ? profile.additional_info.projectedProductContext
      : []),
    ...(Array.isArray(session?.console?.extendedProfile?.userProfile?.projectedProductContext)
      ? session.console.extendedProfile.userProfile.projectedProductContext
      : []),
  ];
  for (const entry of projectedProductContexts) {
    const prodCtx = entry?.prodCtx && typeof entry.prodCtx === "object" ? entry.prodCtx : entry;
    const tenantId = firstNonEmptyString([prodCtx?.tenantId, prodCtx?.tenant_id, prodCtx?.companyId, prodCtx?.company_id]);
    if (tenantId) {
      return tenantId;
    }
  }

  return firstNonEmptyString([
    previousSelectedOrg,
    activeId,
    profile?.tenantId,
    profile?.tenant_id,
  ]);
}

function buildOrganizationContextFromSession(sessionData = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : {};
  return buildRestrictedOrganizationContext(
    resolveCachedOrganizationsFromLoginData(currentSession),
    currentSession,
    null
  );
}

function resolveProgrammerAccessContext(sessionData = null) {
  return resolveAdobePassAccessContext(sessionData);
}

function hasRequestedAdobePassTargetOrganization(sessionData = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : null;
  const targetOrganization =
    currentSession?.targetOrganization && typeof currentSession.targetOrganization === "object"
      ? currentSession.targetOrganization
      : null;
  return matchesAdobePassOrg(targetOrganization);
}

function shouldHydrateAdobePassWorkflowForSession(sessionData = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : null;
  if (!currentSession?.accessToken) {
    return false;
  }
  return resolveProgrammerAccessContext(currentSession).activeIsAdobePass === true;
}

function shouldOfferAdobePassRecoveryForSession(sessionData = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : null;
  if (!currentSession) {
    return false;
  }
  return hasRequestedAdobePassTargetOrganization(currentSession) && !shouldHydrateAdobePassWorkflowForSession(currentSession);
}

function findAdobePassOrganizationCandidate(organizations = []) {
  return findAdobePassOrg(Array.isArray(organizations) ? organizations : []) || null;
}

function isAdobePassOrganization(organization = null) {
  return matchesAdobePassOrg(organization);
}

async function fetchUnderparUnifiedShellInit(accessToken = "", options = {}) {
  const normalizedAccessToken = normalizeBearerTokenValue(accessToken);
  if (!normalizedAccessToken) {
    throw new Error("Unified Shell request is missing the Adobe IMS access token.");
  }

  const selectedOrg = firstNonEmptyString([options?.selectedOrg]);
  let response;
  try {
    response = await fetch(UNIFIED_SHELL_GRAPHQL_URL, {
      method: "POST",
      mode: "cors",
      credentials: "include",
      cache: "no-store",
      redirect: "follow",
      headers: {
        Accept: "application/json",
        Authorization: `Bearer ${normalizedAccessToken}`,
        "Content-Type": "application/json",
        "x-api-key": UNIFIED_SHELL_API_KEY,
      },
      body: JSON.stringify({
        operationName: UNIFIED_SHELL_OPERATION_NAME,
        query: UNIFIED_SHELL_INIT_QUERY,
        variables: {
          selectedOrg: selectedOrg || null,
          useConsolidatedAccounts: false,
        },
      }),
    });
  } catch (error) {
    throw new Error(
      `Unable to reach Unified Shell GraphQL: ${error instanceof Error ? error.message : String(error)}`
    );
  }

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  if (!response.ok) {
    const message = extractUnifiedShellErrorMessage(parsed, text);
    throw new Error(`Unified Shell GraphQL returned ${response.status}${message ? `: ${message}` : ""}`);
  }
  if (Array.isArray(parsed?.errors) && parsed.errors.length > 0) {
    const message = extractUnifiedShellErrorMessage(parsed, text);
    throw new Error(`Unified Shell GraphQL returned an application error${message ? `: ${message}` : ""}`);
  }

  return parsed ?? { data: {} };
}

async function fetchUnderparUnifiedShellOrganizations(accessToken = "", options = {}) {
  const parsed = await fetchUnderparUnifiedShellInit(accessToken, options);
  return collectUnderparUnifiedShellOrganizations(parsed, {
    selectedOrg: firstNonEmptyString([options?.selectedOrg]),
    activeOrganization: options?.activeOrganization || null,
  });
}

async function buildUnifiedShellContext(session, reason = "post-login") {
  const currentSession = session && typeof session === "object" ? session : {};
  const previousUnifiedShell =
    currentSession?.unifiedShell && typeof currentSession.unifiedShell === "object" ? currentSession.unifiedShell : {};
  const accessToken = firstNonEmptyString([currentSession?.accessToken]);
  const hydratedAt = new Date().toISOString();
  const activeOrganization = buildOrganizationContextFromSession(currentSession).activeOrganization;
  const selectedOrg = resolveRestrictedPickerSelectedOrg(activeOrganization, currentSession);

  if (!accessToken) {
    return {
      ...previousUnifiedShell,
      hydratedAt,
      selectedOrg,
      status: "unavailable",
      organizations: [],
      clusterCount: 0,
      userProfile: null,
      errors: {
        init: "Adobe IMS access token is unavailable.",
      },
    };
  }

  log(`Hydrating Unified Shell org context from ${UNIFIED_SHELL_GRAPHQL_URL} (${reason}).`);
  const initResult = await settle(() =>
    fetchUnderparUnifiedShellInit(accessToken, {
      selectedOrg,
      activeOrganization,
    })
  );

  if (!initResult.ok) {
    log(`Unified Shell org hydration failed: ${serializeError(initResult.error)}`);
    return {
      ...previousUnifiedShell,
      hydratedAt,
      selectedOrg,
      status: "unavailable",
      organizations: [],
      clusterCount: 0,
      userProfile: null,
      errors: {
        init: serializeError(initResult.error),
      },
    };
  }

  const payload = initResult.value?.data && typeof initResult.value.data === "object" ? initResult.value.data : {};
  const clusterMeta =
    payload?.imsExtendedAccountClusterData && typeof payload.imsExtendedAccountClusterData === "object"
      ? payload.imsExtendedAccountClusterData
      : {};
  const clusterRows = Array.isArray(clusterMeta?.data) ? clusterMeta.data : [];
  const organizations = collectUnderparUnifiedShellOrganizations(initResult.value, {
    selectedOrg,
    activeOrganization,
  });
  const userProfile = payload?.userProfileJson && typeof payload.userProfileJson === "object" ? payload.userProfileJson : null;

  return {
    ...previousUnifiedShell,
    hydratedAt,
    selectedOrg,
    status: organizations.length > 0 || userProfile ? "ready" : "limited",
    clusterCount: clusterRows.length,
    next: firstNonEmptyString([clusterMeta?.next]),
    timestamp: firstNonEmptyString([clusterMeta?.timestamp]),
    preferredLanguages: Array.isArray(clusterMeta?.preferredLanguages) ? clusterMeta.preferredLanguages.filter(Boolean) : [],
    organizations,
    userProfile,
    errors: {
      init: "",
    },
  };
}

function isReadOrganizationsScopeError(error) {
  const message = error instanceof Error ? error.message : String(error || "");
  return /read_organizations/i.test(message);
}

function tokenHasReadOrganizationsScope(accessToken = "") {
  const token = normalizeBearerTokenValue(accessToken);
  if (!token) {
    return false;
  }
  const grantedScope = resolveGrantedUnderparImsScope(token, "", "");
  return getMissingUnderparImsScopeTokens(grantedScope, "read_organizations").length === 0;
}

function collectObjects(value, output = []) {
  if (!value) {
    return output;
  }

  if (Array.isArray(value)) {
    for (const item of value) {
      collectObjects(item, output);
    }
    return output;
  }

  if (typeof value === "object") {
    output.push(value);
    for (const nestedValue of Object.values(value)) {
      if (nestedValue && (Array.isArray(nestedValue) || typeof nestedValue === "object")) {
        collectObjects(nestedValue, output);
      }
    }
  }

  return output;
}

function flattenOrganizations(payload) {
  const objects = collectObjects(payload, []);
  const seen = new Set();
  const flattened = [];

  for (const org of objects) {
    const key = JSON.stringify(org);
    if (!seen.has(key)) {
      seen.add(key);
      flattened.push(org);
    }
  }

  return flattened;
}

function hasCanonicalRestrictedStoredOrganizations(organizations = []) {
  return Array.isArray(organizations) && organizations.some((organization) => {
    if (!organization || typeof organization !== "object") {
      return false;
    }

    return ["key", "label", "source", "sources", "hinted"].some((field) =>
      Object.prototype.hasOwnProperty.call(organization, field)
    );
  });
}

function normalizeStoredRestrictedOrganizationCandidates(organizations = []) {
  if (!Array.isArray(organizations)) {
    return [];
  }

  const normalizedOrganizations = [];
  const seenKeys = new Set();

  organizations.forEach((organization, index) => {
    if (!organization || typeof organization !== "object") {
      return;
    }

    const orgId = firstNonEmptyString([
      organization.id,
      organization.orgId,
      organization.organizationId,
      extractOrganizationId(organization),
    ]);
    const userId = firstNonEmptyString([
      organization.userId,
      organization.clusterUserId,
      extractUserId(organization),
    ]);
    const name =
      firstNonEmptyString([
        organization.name,
        extractOrganizationName(organization),
        organization.label,
        orgId ? `Adobe IMS Org ${orgId}` : "",
      ]) || "Adobe organization";
    const label = firstNonEmptyString([
      organization.label,
      buildRestrictedOrgOptionLabel({
        name,
        orgId,
        userId,
      }),
      name,
    ]);
    const key = firstNonEmptyString([
      organization.key,
      buildRestrictedOrgOptionKey({
        orgId,
        userId,
        name: label,
      }),
    ]);
    if (!key || seenKeys.has(key)) {
      return;
    }
    seenKeys.add(key);

    const source = firstNonEmptyString([
      organization.source,
      Array.isArray(organization.sources) ? organization.sources[0] : "",
      `session.organizations[${index}]`,
    ]);
    const sources = [];
    [source, ...(Array.isArray(organization.sources) ? organization.sources : [])].forEach((value) => {
      const normalizedSource = String(value || "").trim();
      if (normalizedSource && !sources.includes(normalizedSource)) {
        sources.push(normalizedSource);
      }
    });

    normalizedOrganizations.push({
      key,
      id: firstNonEmptyString([organization.id, organization.orgId, organization.organizationId, orgId]),
      orgId: firstNonEmptyString([organization.orgId, organization.id, organization.organizationId, orgId]),
      tenantId: firstNonEmptyString([
        organization.tenantId,
        organization.tenant_id,
        extractTenantOrganizationId(organization),
        orgId && !/@adobeorg$/i.test(orgId) ? orgId : "",
      ]),
      imsOrgId: firstNonEmptyString([
        organization.imsOrgId,
        organization.ims_org_id,
        extractImsOrganizationId(organization),
        /@adobeorg$/i.test(orgId) ? orgId : "",
      ]),
      userId,
      clusterUserId: firstNonEmptyString([organization.clusterUserId, organization.userId]),
      clusterUserType: firstNonEmptyString([organization.clusterUserType, organization.userType]),
      name,
      label,
      source,
      sources,
      hinted: organization.hinted === true,
      isAdobePass: organization.isAdobePass === true || matchesAdobePassOrg(organization),
      raw: organization.raw && typeof organization.raw === "object" ? organization.raw : organization,
    });
  });

  return normalizedOrganizations;
}

function collectCanonicalRestrictedDetectedOrganizations(sessionData = null, organizations = []) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : {};
  const providedOrganizations = Array.isArray(organizations) ? organizations : [];
  if (hasCanonicalRestrictedStoredOrganizations(providedOrganizations)) {
    return normalizeStoredRestrictedOrganizationCandidates(providedOrganizations);
  }
  if (providedOrganizations.length === 0 && hasCanonicalRestrictedStoredOrganizations(currentSession?.detectedOrganizations)) {
    return normalizeStoredRestrictedOrganizationCandidates(currentSession.detectedOrganizations);
  }

  return collectRestrictedOrganizationCandidates({
    profile: resolveLoginProfile(currentSession),
    accessClaims: parseJwtPayload(currentSession?.accessToken),
    idClaims: parseJwtPayload(currentSession?.idToken),
    organizations: providedOrganizations,
    configuredOrganizations: [],
  });
}

function mergeRestrictedDetectedOrganizations({
  existingOrganizations = [],
  additionalOrganizations = [],
  activeOrganizationHint = null,
} = {}) {
  const candidateMap = new Map();
  const idIndex = new Map();
  const nameIndex = new Map();
  const activeIdentifiers = new Set(
    [
      firstNonEmptyString([activeOrganizationHint?.key]),
      firstNonEmptyString([activeOrganizationHint?.id]),
      firstNonEmptyString([activeOrganizationHint?.orgId]),
      firstNonEmptyString([activeOrganizationHint?.tenantId]),
      firstNonEmptyString([activeOrganizationHint?.imsOrgId]),
      firstNonEmptyString([activeOrganizationHint?.name]),
    ]
      .map((value) => normalizeOrganizationIdentifier(value))
      .filter(Boolean)
  );

  const upsert = (organization, defaultSource) => {
    if (!organization || typeof organization !== "object") {
      return;
    }

    const orgId = firstNonEmptyString([
      organization.orgId,
      organization.id,
      organization.organizationId,
      organization.tenantId,
      organization.imsOrgId,
    ]);
    const userId = firstNonEmptyString([organization.userId, organization.clusterUserId]);
    const name = firstNonEmptyString([organization.name, organization.label, orgId ? `Adobe IMS Org ${orgId}` : ""]);
    if (!orgId && !name) {
      return;
    }

    const normalizedId = normalizeOrganizationIdentifier(orgId);
    const normalizedName = normalizeOrganizationIdentifier(name);
    let existingKey = normalizedId ? idIndex.get(normalizedId) : "";
    if (!existingKey && normalizedName) {
      existingKey = nameIndex.get(normalizedName) || "";
    }

    const source = firstNonEmptyString([
      organization.source,
      Array.isArray(organization.sources) ? organization.sources[0] : "",
      defaultSource,
    ]);
    const sources = [];
    [source, ...(Array.isArray(organization.sources) ? organization.sources : [])].forEach((value) => {
      const normalizedSource = String(value || "").trim();
      if (normalizedSource && !sources.includes(normalizedSource)) {
        sources.push(normalizedSource);
      }
    });

    if (!existingKey) {
      const key = firstNonEmptyString([
        organization.key,
        buildRestrictedOrgOptionKey({
          orgId,
          userId,
          name,
        }),
      ]);
      if (!key) {
        return;
      }

      const nextCandidate = {
        key,
        id: firstNonEmptyString([organization.id, organization.orgId, organization.organizationId, orgId]),
        orgId: firstNonEmptyString([organization.orgId, organization.id, organization.organizationId, orgId]),
        tenantId: firstNonEmptyString([
          organization.tenantId,
          orgId && !/@adobeorg$/i.test(orgId) ? orgId : "",
        ]),
        imsOrgId: firstNonEmptyString([
          organization.imsOrgId,
          /@adobeorg$/i.test(orgId) ? orgId : "",
        ]),
        userId,
        clusterUserId: firstNonEmptyString([organization.clusterUserId, organization.userId]),
        clusterUserType: firstNonEmptyString([organization.clusterUserType, organization.userType]),
        name,
        label: firstNonEmptyString([
          organization.label,
          buildRestrictedOrgOptionLabel({
            name,
            orgId,
            userId,
          }),
        ]),
        source,
        sources,
        hinted:
          organization.hinted === true ||
          activeIdentifiers.has(normalizedId) ||
          activeIdentifiers.has(normalizedName) ||
          activeIdentifiers.has(normalizeOrganizationIdentifier(organization.key)),
        isAdobePass: organization.isAdobePass === true || matchesAdobePassOrg(organization),
        aepRegion: firstNonEmptyString([organization.aepRegion]),
        hasAEP: organization.hasAEP === true,
        aemInstances: Array.isArray(organization.aemInstances) ? organization.aemInstances : [],
        clusterIndex: Number.isFinite(organization.clusterIndex) ? organization.clusterIndex : -1,
        clusterRestricted: organization.clusterRestricted === true || organization.restricted === true,
        consolidatedAccount: organization.consolidatedAccount === true,
        raw: organization.raw && typeof organization.raw === "object" ? organization.raw : organization,
      };

      candidateMap.set(key, nextCandidate);
      if (normalizedId) {
        idIndex.set(normalizedId, key);
      }
      if (normalizedName) {
        nameIndex.set(normalizedName, key);
      }
      return;
    }

    const existingCandidate = candidateMap.get(existingKey);
    if (!existingCandidate) {
      return;
    }

    existingCandidate.id = firstNonEmptyString([existingCandidate.id, organization.id, orgId]);
    existingCandidate.orgId = firstNonEmptyString([existingCandidate.orgId, organization.orgId, orgId]);
    existingCandidate.tenantId = firstNonEmptyString([
      existingCandidate.tenantId,
      organization.tenantId,
      existingCandidate.orgId && !/@adobeorg$/i.test(existingCandidate.orgId) ? existingCandidate.orgId : "",
    ]);
    existingCandidate.imsOrgId = firstNonEmptyString([
      existingCandidate.imsOrgId,
      organization.imsOrgId,
      /@adobeorg$/i.test(existingCandidate.orgId) ? existingCandidate.orgId : "",
    ]);
    existingCandidate.userId = firstNonEmptyString([existingCandidate.userId, userId]);
    const existingSourceRank = rankRestrictedOrganizationSource(existingCandidate.source);
    const incomingSourceRank = rankRestrictedOrganizationSource(source);
    existingCandidate.name =
      incomingSourceRank < existingSourceRank && firstNonEmptyString([name])
        ? name
        : choosePreferredOrganizationName(existingCandidate.name, name, existingCandidate.orgId || orgId);
    existingCandidate.label = buildRestrictedOrgOptionLabel({
      name: existingCandidate.name,
      orgId: existingCandidate.orgId,
      userId: existingCandidate.userId,
    });
    existingCandidate.aepRegion = firstNonEmptyString([existingCandidate.aepRegion, organization.aepRegion]);
    existingCandidate.hasAEP = existingCandidate.hasAEP === true || organization.hasAEP === true;
    if ((!Array.isArray(existingCandidate.aemInstances) || existingCandidate.aemInstances.length === 0) && Array.isArray(organization.aemInstances)) {
      existingCandidate.aemInstances = organization.aemInstances;
    }
    existingCandidate.clusterIndex =
      existingCandidate.clusterIndex >= 0 ? existingCandidate.clusterIndex : Number(organization.clusterIndex || -1);
    existingCandidate.clusterUserId = firstNonEmptyString([existingCandidate.clusterUserId, organization.clusterUserId, organization.userId]);
    existingCandidate.clusterUserType = firstNonEmptyString([existingCandidate.clusterUserType, organization.clusterUserType, organization.userType]);
    existingCandidate.clusterRestricted =
      existingCandidate.clusterRestricted === true ||
      organization.clusterRestricted === true ||
      organization.restricted === true;
    existingCandidate.consolidatedAccount =
      existingCandidate.consolidatedAccount === true || organization.consolidatedAccount === true;
    existingCandidate.hinted =
      existingCandidate.hinted === true ||
      organization.hinted === true ||
      activeIdentifiers.has(normalizedId) ||
      activeIdentifiers.has(normalizedName) ||
      activeIdentifiers.has(normalizeOrganizationIdentifier(organization.key));
    existingCandidate.isAdobePass = existingCandidate.isAdobePass === true || matchesAdobePassOrg(organization);

    sources.forEach((value) => {
      if (!existingCandidate.sources.includes(value)) {
        existingCandidate.sources.push(value);
      }
    });
    if (!existingCandidate.source || incomingSourceRank < existingSourceRank) {
      existingCandidate.source = source;
      existingCandidate.raw = organization.raw && typeof organization.raw === "object" ? organization.raw : organization;
    }
  };

  (Array.isArray(existingOrganizations) ? existingOrganizations : []).forEach((organization, index) => {
    upsert(organization, `existingOrganizations[${index}]`);
  });
  (Array.isArray(additionalOrganizations) ? additionalOrganizations : []).forEach((organization, index) => {
    upsert(organization, `additionalOrganizations[${index}]`);
  });

  return Array.from(candidateMap.values());
}

function resolveCachedOrganizationsFromLoginData(loginData) {
  if (!loginData || typeof loginData !== "object") {
    return [];
  }
  if (hasCanonicalRestrictedStoredOrganizations(loginData.detectedOrganizations)) {
    return normalizeStoredRestrictedOrganizationCandidates(loginData.detectedOrganizations);
  }
  if (hasCanonicalRestrictedStoredOrganizations(loginData.organizations)) {
    return normalizeStoredRestrictedOrganizationCandidates(loginData.organizations);
  }
  if (Array.isArray(loginData.detectedOrganizations) && loginData.detectedOrganizations.length > 0) {
    return flattenOrganizations(loginData.detectedOrganizations);
  }
  return flattenOrganizations(loginData.organizations);
}

function extractOrgId(org) {
  const candidates = [
    org?.orgId,
    org?.orgID,
    org?.org_id,
    org?.organizationId,
    org?.organizationID,
    org?.organization_id,
    org?.tenantId,
    org?.tenant_id,
    org?.imsOrgId,
    org?.ims_org_id,
    org?.customerOrgId,
    org?.customer_org_id,
    org?.companyId,
    org?.company_id,
  ];
  return candidates.find((value) => value !== undefined && value !== null && value !== "") || null;
}

function extractUserId(org) {
  const candidates = [
    org?.userId,
    org?.user_id,
    org?.profileGuid,
    org?.profile_guid,
    org?.profileId,
    org?.profile_id,
    org?.userGuid,
    org?.user_guid,
    org?.userProfileId,
    org?.user_profile_id,
    org?.accountId,
    org?.account_id,
  ];
  return candidates.find((value) => value !== undefined && value !== null && value !== "") || null;
}

function extractOrgName(org) {
  const candidates = [
    org?.orgName,
    org?.org_name,
    org?.organizationName,
    org?.organization_name,
    org?.imsOrgName,
    org?.ims_org_name,
    org?.label,
    org?.displayName,
    org?.display_name,
    org?.companyName,
    org?.company_name,
    org?.tenantName,
    org?.tenant_name,
    org?.title,
    org?.name,
  ];
  return candidates.find((value) => typeof value === "string" && value.trim()) || "";
}

function extractOrgAvatarUrl(org) {
  const candidates = [
    org?.logo,
    org?.logoUrl,
    org?.logo_url,
    org?.tenantLogo,
    org?.tenantLogoUrl,
    org?.tenant_logo,
    org?.tenant_logo_url,
    org?.companyLogo,
    org?.companyLogoUrl,
    org?.company_logo,
    org?.company_logo_url,
    org?.organizationLogo,
    org?.organizationLogoUrl,
    org?.organization_logo,
    org?.organization_logo_url,
    org?.orgLogo,
    org?.orgLogoUrl,
    org?.org_logo,
    org?.org_logo_url,
    org?.avatar,
    org?.avatarUrl,
    org?.avatar_url,
    org?.image,
    org?.imageUrl,
    org?.image_url,
    org?.icon,
    org?.iconUrl,
    org?.icon_url,
    org?.links?.logo?.href,
    org?.links?.avatar?.href,
    org?.links?.icon?.href,
  ];

  return (
    candidates.find((value) => typeof value === "string" && /^https?:\/\//i.test(value)) || ""
  );
}

function objectContainsAdobePass(value) {
  return objectContainsText(value, ADOBEPASS_ORG_KEYWORD);
}

function objectContainsText(value, keyword) {
  if (!value) {
    return false;
  }

  try {
    return JSON.stringify(value).toLowerCase().includes(String(keyword || "").toLowerCase());
  } catch {
    return false;
  }
}

function isOrgIdAllowed(orgId) {
  if (!orgId || ADOBEPASS_ORG_ID_ALLOWLIST.length === 0) {
    return false;
  }
  return ADOBEPASS_ORG_ID_ALLOWLIST.map((value) => normalizeOrganizationIdentifier(value)).includes(
    normalizeOrganizationIdentifier(orgId)
  );
}

function matchesAdobePassOrg(org) {
  if (!org || typeof org !== "object") {
    return false;
  }

  const candidateValues = collectRestrictedOrganizationIdentifierSet(org);
  if (candidateValues.size === 0) {
    return false;
  }

  const adobePassIdentifiers = new Set(
    [
      "adobepass",
      `org:${ADOBEPASS_ORG_KEYWORD}`,
      `org:${ADOBEPASS_ORG_HANDLE}`,
      ADOBEPASS_ORG_HANDLE,
      ADOBEPASS_ORG_DISPLAY_NAME,
      ADOBEPASS_IMS_ORG_ID,
      ...ADOBEPASS_ORG_ID_ALLOWLIST,
    ]
      .map((value) => normalizeOrganizationIdentifier(value))
      .filter(Boolean)
  );

  for (const candidateValue of candidateValues) {
    if (adobePassIdentifiers.has(candidateValue) || isOrgIdAllowed(candidateValue)) {
      return true;
    }
  }

  return false;
}

function findAdobePassOrg(organizations) {
  return organizations.find((org) => matchesAdobePassOrg(org)) || null;
}

function findProfileOrgAvatar(profile, org) {
  if (!profile || typeof profile !== "object") {
    return "";
  }

  const orgId = extractOrgId(org);
  const orgName = extractOrgName(org);
  const objects = collectObjects(profile, []);

  for (const object of objects) {
    const matches =
      (orgId && objectContainsText(object, orgId)) ||
      (orgName && objectContainsText(object, orgName)) ||
      objectContainsAdobePass(object);

    if (!matches) {
      continue;
    }

    const avatar = extractOrgAvatarUrl(object);
    if (avatar) {
      return avatar;
    }
  }

  return "";
}

function toAdobePassOrgDescriptor(org, profile = null) {
  if (!org || typeof org !== "object") {
    return null;
  }

  const explicitOrgAvatar = extractOrgAvatarUrl(org);
  const profileOrgAvatar = explicitOrgAvatar ? "" : findProfileOrgAvatar(profile, org);

  return {
    orgId: extractOrgId(org),
    userId: extractUserId(org),
    name: extractOrgName(org),
    avatarUrl: explicitOrgAvatar || profileOrgAvatar || "",
  };
}

function normalizeOrganizationIdentifier(value) {
  return String(value || "").trim().toLowerCase();
}

function extractStrongOrganizationId(value) {
  if (!value || typeof value !== "object") {
    return "";
  }

  return firstNonEmptyString([
    value.organizationId,
    value.organizationID,
    value.organization_id,
    value.orgId,
    value.orgID,
    value.org_id,
    value.imsOrgId,
    value.ims_org_id,
    value.tenantId,
    value.tenant_id,
    value.companyId,
    value.company_id,
    value.customerOrgId,
    value.customer_org_id,
  ]);
}

function looksLikeOrganizationObject(value, path = "") {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }

  if (/(projectedproductcontext|organization|org|tenant|company)/i.test(path)) {
    return true;
  }

  return Boolean(
    extractStrongOrganizationId(value) ||
      firstNonEmptyString([
        value.organizationName,
        value.organization_name,
        value.orgName,
        value.org_name,
        value.imsOrgName,
        value.ims_org_name,
        value.companyName,
        value.company_name,
        value.tenantName,
        value.tenant_name,
      ])
  );
}

function extractOrganizationId(value) {
  if (!value || typeof value !== "object") {
    return "";
  }

  return firstNonEmptyString([
    extractStrongOrganizationId(value),
    looksLikeOrganizationObject(value) ? firstNonEmptyString([value.id, value.code]) : "",
  ]);
}

function extractTenantOrganizationId(value) {
  if (!value || typeof value !== "object") {
    return "";
  }

  return firstNonEmptyString([value.tenantId, value.tenant_id, value.companyId, value.company_id]);
}

function extractImsOrganizationId(value) {
  if (!value || typeof value !== "object") {
    return "";
  }

  return firstNonEmptyString([
    value.imsOrgId,
    value.ims_org_id,
    /@adobeorg$/i.test(String(value.id || "").trim()) ? String(value.id || "").trim() : "",
  ]);
}

function extractOrganizationName(value) {
  if (!value || typeof value !== "object") {
    return "";
  }

  return firstNonEmptyString([
    value.organizationName,
    value.organization_name,
    value.orgName,
    value.org_name,
    value.imsOrgName,
    value.ims_org_name,
    value.companyName,
    value.company_name,
    value.tenantName,
    value.tenant_name,
    looksLikeOrganizationObject(value) ? firstNonEmptyString([value.displayName, value.name, value.title]) : "",
  ]);
}

function buildRestrictedOrgCandidateMergeKey({ orgId, name }) {
  const normalizedId = normalizeOrganizationIdentifier(orgId);
  if (normalizedId) {
    return `org:${normalizedId}`;
  }

  const normalizedName = normalizeOrganizationIdentifier(name);
  return normalizedName ? `name:${normalizedName}` : "";
}

function buildRestrictedOrgOptionKey({ orgId, userId, name }) {
  const keyBase = [
    normalizeOrganizationIdentifier(orgId),
    normalizeOrganizationIdentifier(userId),
    normalizeOrganizationIdentifier(name),
  ]
    .filter(Boolean)
    .join("::");
  return keyBase || "";
}

function buildRestrictedOrgOptionLabel({ name, orgId, userId }) {
  const labelSegments = [];
  const seenSegments = new Set();
  const appendSegment = (value) => {
    const parts = String(value || "")
      .split("|")
      .map((entry) => entry.trim())
      .filter(Boolean);
    for (const part of parts) {
      const normalized = normalizeOrganizationIdentifier(part);
      if (!normalized || seenSegments.has(normalized)) {
        continue;
      }
      seenSegments.add(normalized);
      labelSegments.push(part);
    }
  };

  const normalizedName = normalizeOrganizationIdentifier(name);
  const normalizedOrgId = normalizeOrganizationIdentifier(orgId);
  const normalizedGeneratedName = orgId
    ? normalizeOrganizationIdentifier(`Adobe IMS Org ${String(orgId || "").trim()}`)
    : "";

  appendSegment(name);
  if (
    normalizedOrgId &&
    normalizedName !== normalizedOrgId &&
    normalizedName !== normalizedGeneratedName
  ) {
    appendSegment(orgId);
  }

  return labelSegments.join(" | ");
}

function isLikelyRestrictedOrganizationIdentifier(value) {
  const normalized = String(value || "").trim();
  if (!normalized) {
    return false;
  }
  if (/^https?:\/\//i.test(normalized)) {
    return false;
  }
  if (/\s/.test(normalized)) {
    return false;
  }
  return /^[a-z0-9@._-]+$/i.test(normalized);
}

function pickRestrictedOrganizationIdentifier(candidates = []) {
  return (
    (Array.isArray(candidates) ? candidates : []).find((candidate) =>
      isLikelyRestrictedOrganizationIdentifier(candidate)
    ) || ""
  );
}

function choosePreferredOrganizationName(currentName, nextName, organizationId = "") {
  const current = firstNonEmptyString([currentName]);
  const next = firstNonEmptyString([nextName]);
  if (!current) {
    return next;
  }
  if (!next) {
    return current;
  }
  if (isGeneratedOrganizationName(current, organizationId) && !isGeneratedOrganizationName(next, organizationId)) {
    return next;
  }
  if (isGeneratedOrganizationName(next, organizationId) && !isGeneratedOrganizationName(current, organizationId)) {
    return current;
  }

  return next.length > current.length ? next : current;
}

function isGeneratedOrganizationName(name, organizationId = "") {
  const normalizedId = String(organizationId || "").trim();
  if (!normalizedId) {
    return false;
  }

  return normalizeOrganizationIdentifier(name) === normalizeOrganizationIdentifier(`Adobe IMS Org ${normalizedId}`);
}

function rankRestrictedOrganizationSource(source = "") {
  const normalizedSource = String(source || "").trim();
  if (!normalizedSource) {
    return 99;
  }
  if (/^organizations\[\d+\]/.test(normalizedSource)) {
    return 0;
  }
  if (/^unifiedShell\./.test(normalizedSource)) {
    return 1;
  }
  if (/^runtimeConfig\.organizations\[\d+\]/.test(normalizedSource)) {
    return 2;
  }
  if (/projectedProductContext/i.test(normalizedSource)) {
    return 3;
  }
  if (/^profile/.test(normalizedSource)) {
    return 4;
  }
  if (/^idClaims/.test(normalizedSource)) {
    return 5;
  }
  if (/^accessClaims/.test(normalizedSource)) {
    return 6;
  }

  return 7;
}

function collectOrganizationObjects(value, path = "payload", results = [], seen = new WeakSet()) {
  if (!value || typeof value !== "object") {
    return results;
  }
  if (seen.has(value)) {
    return results;
  }
  seen.add(value);

  if (looksLikeOrganizationObject(value, path)) {
    results.push({ value, source: path });
  }

  if (Array.isArray(value)) {
    value.forEach((entry, index) => {
      collectOrganizationObjects(entry, `${path}[${index}]`, results, seen);
    });
    return results;
  }

  for (const [key, entry] of Object.entries(value)) {
    if (entry && typeof entry === "object") {
      collectOrganizationObjects(entry, `${path}.${key}`, results, seen);
    }
  }

  return results;
}

function collectRestrictedOrganizationCandidates({
  profile,
  accessClaims,
  idClaims,
  organizations = [],
  configuredOrganizations = [],
}) {
  const candidateMap = new Map();
  const idIndex = new Map();
  const nameIndex = new Map();
  const orgIdHints = [];

  const upsertCandidate = (value, source) => {
    if (!value || typeof value !== "object") {
      return;
    }

    const orgId = extractOrganizationId(value);
    const tenantId = extractTenantOrganizationId(value);
    const imsOrgId = extractImsOrganizationId(value);
    const name = extractOrganizationName(value);
    const userId = firstNonEmptyString([extractUserId(value)]);
    if (!orgId && !name) {
      return;
    }

    const normalizedId = normalizeOrganizationIdentifier(orgId);
    const normalizedName = normalizeOrganizationIdentifier(name);
    let existingKey = normalizedId ? idIndex.get(normalizedId) : "";
    if (!existingKey && normalizedName) {
      existingKey = nameIndex.get(normalizedName) || "";
    }

    if (!existingKey) {
      const mergeKey = buildRestrictedOrgCandidateMergeKey({ orgId, name });
      if (!mergeKey) {
        return;
      }

      candidateMap.set(mergeKey, {
        mergeKey,
        key: firstNonEmptyString([value.key]),
        orgId,
        tenantId: firstNonEmptyString([tenantId, orgId && !/@adobeorg$/i.test(orgId) ? orgId : ""]),
        imsOrgId: firstNonEmptyString([imsOrgId, /@adobeorg$/i.test(orgId) ? orgId : ""]),
        userId,
        clusterUserId: firstNonEmptyString([value.clusterUserId, value.userId]),
        clusterUserType: firstNonEmptyString([value.clusterUserType, value.userType]),
        name,
        label: firstNonEmptyString([value.label]),
        source,
        sources: source ? [source] : [],
        hinted: value.hinted === true,
        isAdobePass: matchesAdobePassOrg(value),
        raw: value,
      });
      if (normalizedId) {
        idIndex.set(normalizedId, mergeKey);
      }
      if (normalizedName) {
        nameIndex.set(normalizedName, mergeKey);
      }
      return;
    }

    const existingCandidate = candidateMap.get(existingKey);
    if (!existingCandidate) {
      return;
    }

    const existingSourceRank = rankRestrictedOrganizationSource(existingCandidate.source);
    const incomingSourceRank = rankRestrictedOrganizationSource(source);
    existingCandidate.orgId = firstNonEmptyString([existingCandidate.orgId, orgId]);
    existingCandidate.tenantId = firstNonEmptyString([
      existingCandidate.tenantId,
      tenantId,
      existingCandidate.orgId && !/@adobeorg$/i.test(existingCandidate.orgId) ? existingCandidate.orgId : "",
    ]);
    existingCandidate.imsOrgId = firstNonEmptyString([
      existingCandidate.imsOrgId,
      imsOrgId,
      /@adobeorg$/i.test(existingCandidate.orgId) ? existingCandidate.orgId : "",
    ]);
    existingCandidate.userId = firstNonEmptyString([existingCandidate.userId, userId]);
    existingCandidate.clusterUserId = firstNonEmptyString([existingCandidate.clusterUserId, value.clusterUserId, value.userId]);
    existingCandidate.clusterUserType = firstNonEmptyString([existingCandidate.clusterUserType, value.clusterUserType, value.userType]);
    existingCandidate.name =
      incomingSourceRank < existingSourceRank && firstNonEmptyString([name])
        ? name
        : choosePreferredOrganizationName(existingCandidate.name, name, existingCandidate.orgId || orgId);
    existingCandidate.label = buildRestrictedOrgOptionLabel({
      name: existingCandidate.name,
      orgId: existingCandidate.orgId,
      userId: existingCandidate.userId,
    });
    existingCandidate.hinted = existingCandidate.hinted === true || value.hinted === true;
    existingCandidate.isAdobePass = existingCandidate.isAdobePass || matchesAdobePassOrg(value);
    if (source && !existingCandidate.sources.includes(source)) {
      existingCandidate.sources.push(source);
    }
    if (!existingCandidate.source || incomingSourceRank < existingSourceRank) {
      existingCandidate.source = source;
      existingCandidate.raw = value;
    }

    const mergedId = normalizeOrganizationIdentifier(existingCandidate.orgId);
    const mergedName = normalizeOrganizationIdentifier(existingCandidate.name);
    if (mergedId) {
      idIndex.set(mergedId, existingCandidate.mergeKey);
    }
    if (mergedName) {
      nameIndex.set(mergedName, existingCandidate.mergeKey);
    }
  };

  const collectCandidatesFromValue = (value, sourceRoot) => {
    collectOrganizationObjects(value, sourceRoot).forEach((entry) => {
      const orgId = extractOrganizationId(entry.value);
      if (orgId) {
        orgIdHints.push(orgId);
      }
      upsertCandidate(entry.value, entry.source);
    });
  };

  organizations.forEach((organization, index) => {
    const source = isRestrictedOrganizationPickerRecord(organization)
      ? firstNonEmptyString([
          organization?.source,
          Array.isArray(organization?.sources) ? organization.sources[0] : "",
          `organizations[${index}]`,
        ])
      : `organizations[${index}]`;
    upsertCandidate(organization, source);
  });
  configuredOrganizations.forEach((organization, index) => {
    const source = firstNonEmptyString([
      organization?.source,
      Array.isArray(organization?.sources) ? organization.sources[0] : "",
      `runtimeConfig.organizations[${index}]`,
    ]);
    upsertCandidate(organization, source);
  });
  collectCandidatesFromValue(profile, "profile");
  collectCandidatesFromValue(profile?.additional_info, "profile.additional_info");
  collectCandidatesFromValue(profile?.projectedProductContext, "profile.projectedProductContext");
  collectCandidatesFromValue(profile?.additional_info?.projectedProductContext, "profile.additional_info.projectedProductContext");
  collectCandidatesFromValue(accessClaims, "accessClaims");
  collectCandidatesFromValue(idClaims, "idClaims");

  const hintedOrgIds = new Set(orgIdHints.map(normalizeOrganizationIdentifier).filter(Boolean));
  return Array.from(candidateMap.values())
    .map((candidate, index) => {
      const displayName =
        firstNonEmptyString([
          candidate.name,
          candidate.orgId ? `Adobe IMS Org ${candidate.orgId}` : "",
          candidate.isAdobePass ? "@AdobePass" : "",
        ]) || "Adobe organization";
      const orgId = firstNonEmptyString([candidate.orgId]);
      const userId = firstNonEmptyString([candidate.userId]);
      if (!orgId && candidate.isAdobePass !== true) {
        return null;
      }
      if (/^https?:\/\//i.test(orgId) || isLikelyUrlWithoutScheme(orgId)) {
        return null;
      }
      const key =
        firstNonEmptyString([candidate.key]) ||
        buildRestrictedOrgOptionKey({
          orgId,
          userId,
          name: displayName,
        }) || `org-index-${index}`;

      return {
        key,
        orgId,
        id: orgId,
        tenantId: firstNonEmptyString([candidate.tenantId, orgId && !/@adobeorg$/i.test(orgId) ? orgId : ""]),
        imsOrgId: firstNonEmptyString([candidate.imsOrgId, /@adobeorg$/i.test(orgId) ? orgId : ""]),
        userId,
        clusterUserId: firstNonEmptyString([candidate.clusterUserId, candidate.userId]),
        clusterUserType: firstNonEmptyString([candidate.clusterUserType]),
        name: displayName,
        hinted: candidate.hinted === true || Boolean(orgId && hintedOrgIds.has(normalizeOrganizationIdentifier(orgId))),
        source: firstNonEmptyString([candidate.source, "returned-payload"]),
        sources: Array.isArray(candidate.sources) ? [...candidate.sources] : [],
        isAdobePass: candidate.isAdobePass === true,
        raw: candidate.raw,
        label:
          firstNonEmptyString([candidate.label]) ||
          buildRestrictedOrgOptionLabel({
            name: displayName,
            orgId,
            userId,
          }) || `Organization ${index + 1}`,
      };
    })
    .filter(Boolean);
}

function collectRestrictedOrganizationIdentifierSet(organization = null) {
  if (!organization) {
    return new Set();
  }

  const values =
    typeof organization === "string"
      ? [organization]
      : [
          organization.key,
          organization.id,
          organization.orgId,
          organization.organizationId,
          organization.tenantId,
          organization.tenant_id,
          organization.companyId,
          organization.company_id,
          organization.imsOrgId,
          organization.ims_org_id,
          organization.name,
          organization.label,
          organization.orgName,
          organization.organizationName,
          extractOrganizationId(organization),
          extractTenantOrganizationId(organization),
          extractImsOrganizationId(organization),
          extractOrganizationName(organization),
        ];

  return new Set(values.map((value) => normalizeOrganizationIdentifier(value)).filter(Boolean));
}

function restrictedOrganizationMatchesAnyIdentifier(organization = null, identifiers = []) {
  const candidateIdentifiers = collectRestrictedOrganizationIdentifierSet(organization);
  if (candidateIdentifiers.size === 0) {
    return false;
  }

  return (Array.isArray(identifiers) ? identifiers : []).some((identifier) =>
    candidateIdentifiers.has(normalizeOrganizationIdentifier(identifier))
  );
}

function hasRestrictedOrganizationIdentifierIntersection(leftIdentifiers = new Set(), rightIdentifiers = new Set()) {
  for (const identifier of leftIdentifiers) {
    if (rightIdentifiers.has(identifier)) {
      return true;
    }
  }
  return false;
}

function compareRestrictedOrganizationCandidatePriority(left, right) {
  const leftHintScore = left?.hinted === true ? 0 : 1;
  const rightHintScore = right?.hinted === true ? 0 : 1;
  if (leftHintScore !== rightHintScore) {
    return leftHintScore - rightHintScore;
  }

  const leftSourceRank = rankRestrictedOrganizationSource(left?.source);
  const rightSourceRank = rankRestrictedOrganizationSource(right?.source);
  if (leftSourceRank !== rightSourceRank) {
    return leftSourceRank - rightSourceRank;
  }

  const leftIdentifierCount = collectRestrictedOrganizationIdentifierSet(left).size;
  const rightIdentifierCount = collectRestrictedOrganizationIdentifierSet(right).size;
  if (leftIdentifierCount !== rightIdentifierCount) {
    return rightIdentifierCount - leftIdentifierCount;
  }

  return String(left?.label || left?.name || "").localeCompare(String(right?.label || right?.name || ""), undefined, {
    sensitivity: "base",
  });
}

function findMatchingRestrictedOrganizationCandidate(organizationCandidates = [], identifiers = []) {
  const normalizedIdentifiers = Array.isArray(identifiers)
    ? identifiers.map((identifier) => normalizeOrganizationIdentifier(identifier)).filter(Boolean)
    : [];
  if (normalizedIdentifiers.length === 0) {
    return null;
  }

  return [...(Array.isArray(organizationCandidates) ? organizationCandidates : [])]
    .filter((candidate) => restrictedOrganizationMatchesAnyIdentifier(candidate, normalizedIdentifiers))
    .sort(compareRestrictedOrganizationCandidatePriority)[0] || null;
}

function collectSessionActiveRestrictedOrganizationIdentifiers(session = null) {
  const currentSession = session && typeof session === "object" ? session : {};
  const profile = resolveLoginProfile(currentSession);
  const projectedContexts = [];
  const addProjectedContexts = (value) => {
    if (Array.isArray(value)) {
      value.forEach((entry) => {
        if (entry && typeof entry === "object") {
          projectedContexts.push(entry);
          if (entry.prodCtx && typeof entry.prodCtx === "object") {
            projectedContexts.push(entry.prodCtx);
          }
        }
      });
      return;
    }
    if (value && typeof value === "object") {
      projectedContexts.push(value);
      if (value.prodCtx && typeof value.prodCtx === "object") {
        projectedContexts.push(value.prodCtx);
      }
    }
  };

  addProjectedContexts(profile?.projectedProductContext);
  addProjectedContexts(profile?.projected_product_context);
  addProjectedContexts(profile?.additional_info?.projectedProductContext);
  addProjectedContexts(profile?.additional_info?.projected_product_context);

  const candidates = [
    currentSession,
    currentSession?.imsSession && typeof currentSession.imsSession === "object" ? currentSession.imsSession : null,
    profile,
    profile?.additional_info && typeof profile.additional_info === "object" ? profile.additional_info : null,
    ...projectedContexts,
  ].filter((value) => value && typeof value === "object");

  const identifiers = new Set();
  const collectFromObject = (value) => {
    [
      value?.tenantId,
      value?.tenant_id,
      value?.companyId,
      value?.company_id,
      value?.orgId,
      value?.org_id,
      value?.organizationId,
      value?.organization_id,
      value?.imsOrgId,
      value?.ims_org_id,
      value?.tenantName,
      value?.tenant_name,
      value?.companyName,
      value?.company_name,
      value?.orgName,
      value?.org_name,
      value?.organizationName,
      value?.organization_name,
    ]
      .map((entry) => normalizeOrganizationIdentifier(entry))
      .filter(Boolean)
      .forEach((entry) => identifiers.add(entry));
  };

  candidates.forEach(collectFromObject);
  return [...identifiers];
}

function resolveActiveRestrictedOrganization({ organizationCandidates = [], session = null }) {
  const verifiedClaim = extractVerifiedCustomerOrganizationClaim(session);
  const candidates = Array.isArray(organizationCandidates) ? organizationCandidates : [];
  const verifiedCandidate = findMatchingRestrictedOrganizationCandidate(candidates, [
    verifiedClaim?.rawId,
    verifiedClaim?.id,
  ]);
  const sessionCandidate = verifiedCandidate
    ? null
    : findMatchingRestrictedOrganizationCandidate(candidates, collectSessionActiveRestrictedOrganizationIdentifiers(session));
  const sortedCandidates = [...candidates].sort(compareRestrictedOrganizationCandidatePriority);
  const matchedCandidate = verifiedCandidate || sessionCandidate || sortedCandidates[0] || null;

  if (!matchedCandidate) {
    return {
      key: "",
      name: "Adobe organization unavailable",
      id: "",
      source: "not-resolved",
      authoritative: false,
      resolutionSource: "not-resolved",
    };
  }

  return {
    ...matchedCandidate,
    authoritative: Boolean(
      verifiedCandidate ||
        sessionCandidate ||
        sortedCandidates.length === 1
    ),
    resolutionSource: verifiedCandidate
      ? "verified-claim"
      : sessionCandidate
        ? "session-payload"
        : sortedCandidates.length === 1
          ? "single-candidate"
          : "fallback-sort",
  };
}

function sortRestrictedOrganizationOptions(options = [], activeOrganization = null) {
  const activeKey = String(activeOrganization?.key || "").trim();
  return [...(Array.isArray(options) ? options : [])].sort((left, right) => {
    const leftKey = String(left?.key || "").trim();
    const rightKey = String(right?.key || "").trim();
    if (leftKey === activeKey && rightKey !== activeKey) {
      return -1;
    }
    if (rightKey === activeKey && leftKey !== activeKey) {
      return 1;
    }

    return compareRestrictedOrganizationCandidatePriority(left, right);
  });
}

function isRestrictedOrganizationPickerRecord(value = null) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }

  const hasKey = Object.prototype.hasOwnProperty.call(value, "key");
  const hasLabel = Object.prototype.hasOwnProperty.call(value, "label");
  const hasSource = Object.prototype.hasOwnProperty.call(value, "source");
  const hasSources = Object.prototype.hasOwnProperty.call(value, "sources");
  const hasHinted = Object.prototype.hasOwnProperty.call(value, "hinted");

  return (hasKey && hasLabel) || hasSources || hasHinted || (hasSource && (hasKey || hasLabel));
}

function hasRestrictedOrganizationPickerOnlySource(organization = null) {
  if (!organization || typeof organization !== "object") {
    return false;
  }

  const sources = [
    organization?.source,
    ...(Array.isArray(organization?.sources) ? organization.sources : []),
  ]
    .map((entry) => String(entry || "").trim())
    .filter(Boolean);

  return sources.some((source) => source === "session-picker" || /^targetOrganization\b/i.test(source));
}

function isRestrictedOrganizationAuthoritativeCandidate(organization = null) {
  if (!organization || typeof organization !== "object") {
    return false;
  }
  if (isRestrictedOrganizationPickerRecord(organization)) {
    return false;
  }

  return hasRestrictedOrganizationPickerOnlySource(organization) !== true;
}

function collectAuthoritativeRestrictedOrganizations(value = null) {
  return flattenOrganizations(value).filter((organization) => isRestrictedOrganizationAuthoritativeCandidate(organization));
}

function buildRestrictedOrganizationContext(organizations, sessionData = null, preferredOrg = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : {};
  const profile = resolveLoginProfile(currentSession);
  const accessClaims = parseJwtPayload(currentSession?.accessToken);
  const idClaims = parseJwtPayload(currentSession?.idToken);
  const runtimeConfig = getActiveUnderparImsRuntimeConfig();
  const configuredOrganizations = Array.isArray(runtimeConfig?.organizations) ? runtimeConfig.organizations : [];
  const providedOrganizations = Array.isArray(organizations) ? organizations : flattenOrganizations(organizations);
  const storedOrganizations = hasCanonicalRestrictedStoredOrganizations(currentSession?.detectedOrganizations)
    ? normalizeStoredRestrictedOrganizationCandidates(currentSession.detectedOrganizations).filter(
        (organization) => hasRestrictedOrganizationPickerOnlySource(organization) !== true
      )
    : hasCanonicalRestrictedStoredOrganizations(currentSession?.organizations)
      ? normalizeStoredRestrictedOrganizationCandidates(currentSession.organizations).filter(
          (organization) => hasRestrictedOrganizationPickerOnlySource(organization) !== true
        )
      : [];
  const providedCanonicalOrganizations = hasCanonicalRestrictedStoredOrganizations(providedOrganizations)
    ? normalizeStoredRestrictedOrganizationCandidates(providedOrganizations).filter(
        (organization) => hasRestrictedOrganizationPickerOnlySource(organization) !== true
      )
    : [];
  const authoritativeProvidedOrganizations =
    providedCanonicalOrganizations.length > 0
      ? providedCanonicalOrganizations
      : collectAuthoritativeRestrictedOrganizations(providedOrganizations);
  const returnedOrganizations = [
    ...storedOrganizations,
    ...authoritativeProvidedOrganizations,
  ];
  const optionOrganizations = [...returnedOrganizations];

  const options = collectRestrictedOrganizationCandidates({
    profile,
    accessClaims,
    idClaims,
    organizations: optionOrganizations,
    configuredOrganizations,
  });
  const activeOrganizationCandidates = collectRestrictedOrganizationCandidates({
    profile,
    accessClaims,
    idClaims,
    organizations: returnedOrganizations,
    configuredOrganizations: [],
  });
  const activeOrganization = resolveActiveRestrictedOrganization({
    organizationCandidates: activeOrganizationCandidates,
    session: currentSession,
  });

  return {
    options: sortRestrictedOrganizationOptions(options, activeOrganization),
    detectedOrganizations: sortRestrictedOrganizationOptions(activeOrganizationCandidates, activeOrganization),
    activeOrganization,
  };
}

function resolveAdobePassAccessContext(sessionData = null, preferredOrg = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : {};
  const cachedOrganizations = resolveCachedOrganizationsFromLoginData(currentSession);
  const organizationContext = buildRestrictedOrganizationContext(cachedOrganizations, currentSession, preferredOrg);
  const activeOrganization = organizationContext?.activeOrganization || null;
  const detectedOrganizations = Array.isArray(organizationContext?.detectedOrganizations)
    ? organizationContext.detectedOrganizations
    : [];
  const activeOrganizationTrusted = activeOrganization?.authoritative === true || detectedOrganizations.length === 1;
  const requiredOrganization =
    findAdobePassOrg([
      activeOrganization,
      ...(Array.isArray(organizationContext?.options) ? organizationContext.options : []),
      ...(Array.isArray(state.restrictedOrgOptions) ? state.restrictedOrgOptions : []),
    ].filter((entry) => entry && typeof entry === "object")) || null;
  const activeIsAdobePass = activeOrganizationTrusted && matchesAdobePassOrg(activeOrganization);
  const requiredLabel = firstNonEmptyString([
    requiredOrganization?.label,
    requiredOrganization?.name,
    "@AdobePass",
  ]);

  if (activeIsAdobePass) {
    return {
      eligible: true,
      activeIsAdobePass: true,
      activeOrganization,
      requiredOrganization,
      requiredOrgKey: firstNonEmptyString([requiredOrganization?.key, "org:@adobepass"]),
      requiredOrgId: firstNonEmptyString([requiredOrganization?.orgId, requiredOrganization?.id, "@adobepass"]),
      requiredLabel,
      reason: "",
    };
  }

  if (requiredOrganization) {
    return {
      eligible: false,
      activeIsAdobePass: false,
      activeOrganization,
      requiredOrganization,
      requiredOrgKey: firstNonEmptyString([requiredOrganization?.key, "org:@adobepass"]),
      requiredOrgId: firstNonEmptyString([requiredOrganization?.orgId, requiredOrganization?.id, "@adobepass"]),
      requiredLabel,
      reason: `Switch Adobe Org to ${requiredLabel} to load Adobe Pass media companies.`,
    };
  }

  return {
    eligible: false,
    activeIsAdobePass: false,
    activeOrganization,
    requiredOrganization: null,
    requiredOrgKey: "org:@adobepass",
    requiredOrgId: "@adobepass",
    requiredLabel: "@AdobePass",
    reason: "Adobe Pass org was not detected in the current Adobe session, so UnderPAR stays on the org picker.",
  };
}

function buildRestrictedOrgOptions(organizations, sessionData = null, preferredOrg = null) {
  return buildRestrictedOrganizationContext(organizations, sessionData, preferredOrg).options;
}

function getConfiguredTargetOrganizations(runtimeConfig = getActiveUnderparImsRuntimeConfig()) {
  return Array.isArray(runtimeConfig?.organizations)
    ? runtimeConfig.organizations.filter((entry) => entry && typeof entry === "object")
    : [];
}

function findConfiguredTargetOrganization(options = [], candidate = null) {
  if (!Array.isArray(options) || options.length === 0 || !candidate || typeof candidate !== "object") {
    return null;
  }

  const normalizedKey = String(candidate.key || "").trim();
  if (normalizedKey) {
    const directMatch = options.find((option) => String(option?.key || "").trim() === normalizedKey) || null;
    if (directMatch) {
      return directMatch;
    }
  }

  const normalizedId = normalizeOrganizationIdentifier(
    firstNonEmptyString([
      candidate.id,
      candidate.orgId,
      candidate.organizationId,
      candidate.organization_id,
      extractOrganizationId(candidate),
    ])
  );
  if (normalizedId) {
    const idMatch =
      options.find((option) => {
        return (
          normalizeOrganizationIdentifier(firstNonEmptyString([option?.id, option?.orgId, option?.organizationId])) ===
          normalizedId
        );
      }) || null;
    if (idMatch) {
      return idMatch;
    }
  }

  const normalizedLabel = normalizeOrganizationIdentifier(
    firstNonEmptyString([candidate.label, candidate.name, candidate.orgName, extractOrganizationName(candidate)])
  );
  if (!normalizedLabel) {
    return null;
  }

  return (
    options.find((option) => {
      return (
        normalizeOrganizationIdentifier(firstNonEmptyString([option?.label, option?.name])) === normalizedLabel ||
        normalizeOrganizationIdentifier(firstNonEmptyString([option?.id, option?.orgId])) === normalizedLabel
      );
    }) || null
  );
}

function findMatchingRestrictedOrganizationOption(options = [], candidate = null) {
  if (!Array.isArray(options) || options.length === 0 || !candidate || typeof candidate !== "object") {
    return null;
  }

  const normalizedKey = String(candidate.key || "").trim();
  if (normalizedKey) {
    const directMatch = options.find((option) => String(option?.key || "").trim() === normalizedKey) || null;
    if (directMatch) {
      return directMatch;
    }
  }

  const normalizedOrgId = normalizeOrganizationIdentifier(
    firstNonEmptyString([candidate.orgId, candidate.id, candidate.organizationId, extractOrganizationId(candidate)])
  );
  const normalizedUserId = normalizeOrganizationIdentifier(
    firstNonEmptyString([candidate.userId, candidate.profileGuid, candidate.userGuid, extractUserId(candidate)])
  );
  if (normalizedOrgId || normalizedUserId) {
    const idMatch =
      options.find((option) => {
        const optionOrgId = normalizeOrganizationIdentifier(firstNonEmptyString([option?.orgId, option?.id]));
        const optionUserId = normalizeOrganizationIdentifier(firstNonEmptyString([option?.userId]));
        if (normalizedOrgId && optionOrgId && normalizedOrgId !== optionOrgId) {
          return false;
        }
        if (normalizedUserId && optionUserId && normalizedUserId !== optionUserId) {
          return false;
        }
        return Boolean(
          (normalizedOrgId && optionOrgId && normalizedOrgId === optionOrgId) ||
            (normalizedUserId && optionUserId && normalizedUserId === optionUserId)
        );
      }) || null;
    if (idMatch) {
      return idMatch;
    }
  }

  const normalizedLabel = normalizeOrganizationIdentifier(
    firstNonEmptyString([candidate.label, candidate.name, candidate.orgName, extractOrganizationName(candidate)])
  );
  if (!normalizedLabel) {
    return null;
  }

  return (
    options.find((option) => {
      return (
        normalizeOrganizationIdentifier(firstNonEmptyString([option?.label, option?.name])) === normalizedLabel ||
        normalizeOrganizationIdentifier(firstNonEmptyString([option?.orgId, option?.id])) === normalizedLabel
      );
    }) || null
  );
}

function buildTargetOrganizationContext(
  runtimeConfig = getActiveUnderparImsRuntimeConfig(),
  selectedKey = state.selectedTargetOrganizationKey
) {
  const options = getConfiguredTargetOrganizations(runtimeConfig);
  const normalizedSelectedKey = String(selectedKey || "").trim();
  const explicitSelection = normalizedSelectedKey
    ? findConfiguredTargetOrganization(options, { key: normalizedSelectedKey })
    : null;

  return {
    options,
    selectedOrganization: explicitSelection || null,
    requiresSelection: false,
    selectionMode: explicitSelection ? "manual" : "none",
  };
}

function resolveTargetOrganizationForLogin(
  runtimeConfig = getActiveUnderparImsRuntimeConfig(),
  selectedKey = state.selectedTargetOrganizationKey
) {
  return buildTargetOrganizationContext(runtimeConfig, selectedKey).selectedOrganization;
}

function normalizeRequestedTargetOrganization(targetOrganization = null) {
  if (!targetOrganization || typeof targetOrganization !== "object") {
    return null;
  }

  const tenantId = firstNonEmptyString([
    targetOrganization.tenantId,
    targetOrganization.tenant_id,
    extractTenantOrganizationId(targetOrganization),
  ]);
  const imsOrgId = firstNonEmptyString([
    targetOrganization.imsOrgId,
    targetOrganization.ims_org_id,
    extractImsOrganizationId(targetOrganization),
  ]);
  const id = firstNonEmptyString([
    targetOrganization.id,
    targetOrganization.orgId,
    targetOrganization.organizationId,
    tenantId,
    imsOrgId,
    extractOrganizationId(targetOrganization),
  ]);
  const userId = firstNonEmptyString([
    targetOrganization.userId,
    targetOrganization.clusterUserId,
    extractUserId(targetOrganization),
  ]);
  const name =
    firstNonEmptyString([
      targetOrganization.name,
      targetOrganization.orgName,
      targetOrganization.organizationName,
      targetOrganization.label,
      extractOrganizationName(targetOrganization),
      id ? `Adobe IMS Org ${id}` : "",
    ]) || "Adobe organization";
  const label = firstNonEmptyString([
    targetOrganization.label,
    buildRestrictedOrgOptionLabel({
      name,
      orgId: id,
      userId,
    }),
    name,
  ]);
  const key = firstNonEmptyString([
    targetOrganization.key,
    buildRestrictedOrgOptionKey({
      orgId: id,
      userId,
      name: label,
    }),
  ]);
  if (!key) {
    return null;
  }

  return {
    key,
    id,
    orgId: id,
    tenantId: firstNonEmptyString([tenantId, id && !/@adobeorg$/i.test(id) ? id : ""]),
    imsOrgId: firstNonEmptyString([imsOrgId, /@adobeorg$/i.test(id) ? id : ""]),
    userId,
    clusterUserId: firstNonEmptyString([targetOrganization.clusterUserId, targetOrganization.userId]),
    clusterUserType: firstNonEmptyString([targetOrganization.clusterUserType, targetOrganization.userType]),
    name,
    label,
    hinted: targetOrganization.hinted === true,
    isAdobePass: matchesAdobePassOrg(targetOrganization),
    source: firstNonEmptyString([targetOrganization.source, "session-picker"]),
  };
}

function attachTargetOrganizationToLoginData(loginData = {}, targetOrganization = null) {
  const nextLoginData = loginData && typeof loginData === "object" ? { ...loginData } : {};
  const normalizedTargetOrganization = normalizeRequestedTargetOrganization(targetOrganization);
  if (normalizedTargetOrganization) {
    nextLoginData.targetOrganization = normalizedTargetOrganization;
  } else {
    delete nextLoginData.targetOrganization;
  }
  return nextLoginData;
}

function extractVerifiedCustomerOrganizationClaim(sessionData = null) {
  const idClaims = parseJwtPayload(sessionData?.idToken) || {};
  const accessClaims = parseJwtPayload(sessionData?.accessToken) || {};
  const candidates = [
    { value: idClaims?.org_id, source: "idClaims.org_id" },
    { value: idClaims?.orgId, source: "idClaims.orgId" },
    { value: idClaims?.organizationId, source: "idClaims.organizationId" },
    { value: idClaims?.organization_id, source: "idClaims.organization_id" },
    { value: accessClaims?.org_id, source: "accessClaims.org_id" },
    { value: accessClaims?.orgId, source: "accessClaims.orgId" },
    { value: accessClaims?.organizationId, source: "accessClaims.organizationId" },
    { value: accessClaims?.organization_id, source: "accessClaims.organization_id" },
  ];
  const match = candidates.find((entry) => normalizeOrganizationIdentifier(entry?.value));
  return match
    ? {
        id: normalizeOrganizationIdentifier(match.value),
        rawId: String(match.value || "").trim(),
        source: String(match.source || "unknown"),
      }
    : {
        id: "",
        rawId: "",
        source: "unavailable",
      };
}

function verifyTargetOrganizationSelection(sessionData = null, targetOrganization = null) {
  const normalizedTargetOrganization = normalizeRequestedTargetOrganization(targetOrganization);
  if (!normalizedTargetOrganization?.key) {
    return {
      status: "not-applicable",
      source: "n/a",
      expectedOrgId: "",
      expectedOrgKey: "",
      verifiedOrgId: "",
      resolvedOrgId: "",
      resolvedOrgKey: "",
      message: "No target org was selected before Adobe sign-in.",
    };
  }

  const requestedLabel = firstNonEmptyString([
    normalizedTargetOrganization.label,
    normalizedTargetOrganization.name,
    normalizedTargetOrganization.id,
    "selected Adobe IMS org",
  ]);
  const expectedOrgId = normalizeOrganizationIdentifier(
    firstNonEmptyString([
      normalizedTargetOrganization.imsOrgId,
      normalizedTargetOrganization.tenantId,
      normalizedTargetOrganization.id,
    ])
  );
  const expectedOrgKey = String(normalizedTargetOrganization.key || "").trim();
  const expectedOrgIdentifiers = collectRestrictedOrganizationIdentifierSet(normalizedTargetOrganization);
  const verifiedClaim = extractVerifiedCustomerOrganizationClaim(sessionData);
  const resolvedActiveOrganization = buildRestrictedOrganizationContext(
    resolveCachedOrganizationsFromLoginData(sessionData),
    sessionData,
    null
  ).activeOrganization;
  const resolvedOrgIdentifiers = collectRestrictedOrganizationIdentifierSet(resolvedActiveOrganization);
  const resolvedOrgId = normalizeOrganizationIdentifier(
    firstNonEmptyString([
      resolvedActiveOrganization?.imsOrgId,
      resolvedActiveOrganization?.tenantId,
      resolvedActiveOrganization?.id,
    ])
  );
  const resolvedOrgKey = String(resolvedActiveOrganization?.key || "").trim();

  if (verifiedClaim.id) {
    const verifiedMatch = expectedOrgIdentifiers.has(verifiedClaim.id);
    return {
      status: verifiedMatch ? "verified-match" : "verified-mismatch",
      source: verifiedClaim.source,
      expectedOrgId,
      expectedOrgKey,
      verifiedOrgId: verifiedClaim.id,
      resolvedOrgId,
      resolvedOrgKey,
      message:
        verifiedMatch
          ? `Adobe returned the requested Adobe IMS org ${requestedLabel} via ${verifiedClaim.source}.`
          : `Adobe returned verified org ${verifiedClaim.rawId || verifiedClaim.id} via ${verifiedClaim.source} instead of ${requestedLabel}.`,
    };
  }

  if (resolvedOrgKey) {
    const resolvedMatch =
      resolvedOrgIdentifiers.size > 0 &&
      hasRestrictedOrganizationIdentifierIntersection(expectedOrgIdentifiers, resolvedOrgIdentifiers);
    return {
      status: resolvedMatch ? "derived-match" : "derived-mismatch",
      source: "resolved-payload",
      expectedOrgId,
      expectedOrgKey,
      verifiedOrgId: "",
      resolvedOrgId,
      resolvedOrgKey,
      message:
        resolvedMatch
          ? `Resolved the requested Adobe IMS org ${requestedLabel} from the returned payloads.`
          : `Adobe returned ${firstNonEmptyString([
              resolvedActiveOrganization?.label,
              resolvedActiveOrganization?.name,
              resolvedActiveOrganization?.id,
              "another Adobe IMS org",
            ])} instead of ${requestedLabel}.`,
    };
  }

  return {
    status: "no-org-claim",
    source: "unavailable",
    expectedOrgId,
    expectedOrgKey,
    verifiedOrgId: "",
    resolvedOrgId: "",
    resolvedOrgKey: "",
    message: `Adobe did not return a verifiable org claim for target org ${requestedLabel}.`,
  };
}

function isSuccessfulTargetOrganizationVerification(verification = null) {
  const status = String(verification?.status || "").trim();
  return status === "verified-match" || status === "derived-match";
}

function finalizeRequestedTargetLoginData(loginData = {}, targetOrganization = null, options = {}) {
  const normalizedTargetOrganization = normalizeRequestedTargetOrganization(targetOrganization);
  let finalizedLoginData = attachTargetOrganizationToLoginData(loginData, normalizedTargetOrganization);
  const orgVerification = verifyTargetOrganizationSelection(finalizedLoginData, normalizedTargetOrganization);
  finalizedLoginData.orgVerification = orgVerification;

  if (!normalizedTargetOrganization) {
    return {
      ok: true,
      acceptedReturnedOrganization: false,
      loginData: finalizedLoginData,
      verification: orgVerification,
      message: String(orgVerification?.message || "").trim(),
    };
  }

  log(String(orgVerification?.message || "").trim());
  if (isSuccessfulTargetOrganizationVerification(orgVerification)) {
    return {
      ok: true,
      acceptedReturnedOrganization: false,
      loginData: finalizedLoginData,
      verification: orgVerification,
      message: String(orgVerification?.message || "").trim(),
    };
  }

  if (options?.acceptReturnedOrganization === true) {
    finalizedLoginData = attachTargetOrganizationToLoginData(finalizedLoginData, null);
    finalizedLoginData.orgVerification = {
      ...orgVerification,
      status: "accepted-returned-org",
      expectedOrgKey: "",
      message: `${String(orgVerification?.message || "").trim()} UnderPAR switched to the active returned Adobe org.`,
    };
    return {
      ok: true,
      acceptedReturnedOrganization: true,
      loginData: finalizedLoginData,
      verification: finalizedLoginData.orgVerification,
      message: String(finalizedLoginData?.orgVerification?.message || "").trim(),
    };
  }

  return {
    ok: false,
    acceptedReturnedOrganization: false,
    loginData: null,
    verification: orgVerification,
    message: `${String(orgVerification?.message || "").trim()} UnderPAR kept the prior session so it does not misrepresent the selected Adobe profile. Use Sign In Again if Adobe needs to reopen the chooser.`,
  };
}

function updateRestrictedOrgOptions(organizations, preferredOrg = null, sessionData = null) {
  const organizationContext = buildRestrictedOrganizationContext(organizations, sessionData, preferredOrg);
  const options = Array.isArray(organizationContext?.options) ? organizationContext.options : [];
  const activeOrganization = organizationContext?.activeOrganization || null;
  state.restrictedOrgOptions = options;

  if (options.length === 0) {
    state.selectedRestrictedOrgKey = "";
    return;
  }

  const activeKey = String(activeOrganization?.key || "").trim();
  if (activeKey && options.some((option) => option.key === activeKey)) {
    state.selectedRestrictedOrgKey = activeKey;
    return;
  }

  if (state.selectedRestrictedOrgKey && options.some((option) => option.key === state.selectedRestrictedOrgKey)) {
    return;
  }

  const directPreferredKey = String(preferredOrg?.key || "").trim();
  if (directPreferredKey && options.some((option) => option.key === directPreferredKey)) {
    state.selectedRestrictedOrgKey = directPreferredKey;
    return;
  }

  const preferredMatch = findMatchingRestrictedOrganizationOption(options, preferredOrg);
  if (preferredMatch?.key) {
    state.selectedRestrictedOrgKey = preferredMatch.key;
    return;
  }

  state.selectedRestrictedOrgKey = options[0].key;
}

function clearRestrictedOrgOptions() {
  state.restrictedOrgOptions = [];
  state.selectedRestrictedOrgKey = "";
  state.restrictedOrgSwitchBusy = false;
  state.restrictedLoginLabel = "";
  state.restrictedOrgLabel = "";
  state.restrictedRecoveryLabel = "";
}

function getSelectedRestrictedOrgOption() {
  return state.restrictedOrgOptions.find((option) => option.key === state.selectedRestrictedOrgKey) || null;
}

function isAuthenticatedOrgSwitchOnlySession(sessionData = state.loginData) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : null;
  return Boolean(
    currentSession &&
    state.sessionReady === true &&
    state.restricted !== true &&
    !shouldHydrateAdobePassWorkflowForSession(currentSession)
  );
}

function syncAuthenticatedOrgSwitchOnlyContext(sessionData = null) {
  const currentSession = sessionData && typeof sessionData === "object" ? sessionData : null;
  if (!currentSession) {
    clearRestrictedOrgOptions();
    return;
  }

  const configuredTargetOrganization =
    findConfiguredTargetOrganization(
      getConfiguredTargetOrganizations(),
      currentSession?.targetOrganization && typeof currentSession.targetOrganization === "object"
        ? currentSession.targetOrganization
        : null
    ) ||
    (currentSession?.targetOrganization && typeof currentSession.targetOrganization === "object"
      ? currentSession.targetOrganization
      : null) ||
    null;
  const organizations = resolveCachedOrganizationsFromLoginData(currentSession);
  const detectedOrganizations = collectCanonicalRestrictedDetectedOrganizations(
    {
      ...currentSession,
      organizations,
    },
    organizations
  );
  updateRestrictedOrgOptions(organizations, configuredTargetOrganization, {
    ...currentSession,
    organizations,
    detectedOrganizations,
  });
  updateRestrictedContext(
    {
      ...currentSession,
      organizations,
      detectedOrganizations,
    },
    shouldOfferAdobePassRecoveryForSession(currentSession)
      ? {
          recoveryLabel: firstNonEmptyString([
            resolveProgrammerAccessContext(currentSession).reason,
            state.restrictedRecoveryLabel,
          ]),
        }
      : {}
  );
}

function getProfileDisplayNameRaw(profile) {
  const direct = firstNonEmptyString([profile?.displayName, profile?.fullName, profile?.full_name, profile?.name]);
  if (direct) {
    return direct;
  }

  const firstName = firstNonEmptyString([profile?.firstName, profile?.first_name]);
  const lastName = firstNonEmptyString([profile?.lastName, profile?.last_name]);
  return [firstName, lastName].filter(Boolean).join(" ").trim();
}

function updateRestrictedContext(sessionData, options = {}) {
  const profile = resolveLoginProfile(sessionData);
  const displayName = getLoginDisplayName(sessionData);
  const principalId = getLoginPrincipalId(sessionData);
  const loginLabel = firstNonEmptyString([displayName, principalId])
    ? `Signed in as ${firstNonEmptyString([displayName, principalId])}${displayName && principalId ? ` (${principalId})` : ""}`
    : "Sign-in state is unknown.";

  const orgFromProfile = firstNonEmptyString([
    profile?.organizationName,
    profile?.organization_name,
    profile?.orgName,
    profile?.org_name,
    profile?.tenantName,
    profile?.tenant_name,
    profile?.companyName,
    profile?.company_name,
    profile?.additional_info?.organizationName,
    profile?.additional_info?.organization_name,
    profile?.additional_info?.orgName,
    profile?.additional_info?.org_name,
    profile?.additional_info?.tenantName,
    profile?.additional_info?.tenant_name,
    profile?.additional_info?.companyName,
    profile?.additional_info?.company_name,
  ]);
  const selectedOption = getSelectedRestrictedOrgOption();
  const targetOrganization =
    sessionData?.targetOrganization && typeof sessionData.targetOrganization === "object"
      ? sessionData.targetOrganization
      : null;
  const targetLabel = firstNonEmptyString([targetOrganization?.label, targetOrganization?.name]);
  const orgVerificationMessage = String(sessionData?.orgVerification?.message || "").trim();
  const orgLabel = firstNonEmptyString([
    options.orgLabel,
    orgFromProfile,
    selectedOption?.label,
    options.fallbackOrgLabel,
    "Unknown org profile",
  ]);

  const recoveryLabel = firstNonEmptyString([
    options.recoveryLabel,
    orgVerificationMessage,
    targetLabel ? `Target org: ${targetLabel}. Switch this session or sign in again to choose a different Adobe profile.` : "",
    state.restrictedRecoveryLabel,
    "Choose an Adobe org profile, switch this session, or sign in again to reopen Adobe's profile chooser.",
  ]);

  state.restrictedLoginLabel = loginLabel;
  state.restrictedOrgLabel = `Detected org: ${orgLabel}`;
  state.restrictedRecoveryLabel = recoveryLabel;
}

function isLikelyUrlWithoutScheme(value) {
  if (typeof value !== "string") {
    return false;
  }
  return /^[a-z0-9.-]+\.[a-z]{2,}(\/|$)/i.test(value.trim());
}

function isLikelyImageAssetPath(value) {
  if (typeof value !== "string") {
    return false;
  }

  const normalized = value.trim().replace(/^\.?\//, "");
  if (!normalized || /\s/.test(normalized)) {
    return false;
  }

  return (
    normalized === DEFAULT_AVATAR ||
    normalized === FALLBACK_AVATAR_ASSET ||
    /\.(png|jpg|jpeg|gif|webp|svg)(\?|$)/i.test(normalized)
  );
}

function isBlockedAudienceManagerAvatarReference(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized) {
    return false;
  }
  if (normalized.includes("audiencemanager")) {
    return true;
  }
  if (/^dma[_-]/i.test(normalized)) {
    return true;
  }
  return (
    /^\/?ims\/avatar\/download\/dma[_-]/i.test(normalized) ||
    /^\/?avatar\/download\/dma[_-]/i.test(normalized) ||
    /\/ims\/avatar\/download\/dma[_-]/i.test(normalized)
  );
}

function isLikelyImsAvatarId(value) {
  if (typeof value !== "string") {
    return false;
  }

  const trimmed = value.trim();
  if (isBlockedAudienceManagerAvatarReference(trimmed)) {
    return false;
  }
  if (!/^[a-z0-9_-]{8,}$/i.test(trimmed)) {
    return false;
  }

  // Common IDs and handles that are not avatar download IDs.
  if (/^@/.test(trimmed) || /@adobeorg$/i.test(trimmed)) {
    return false;
  }

  return true;
}

function normalizeAvatarCandidate(value) {
  if (typeof value !== "string") {
    return "";
  }

  const trimmed = value.trim().replace(/^['"]+|['"]+$/g, "");
  if (!trimmed) {
    return "";
  }
  if (isBlockedAudienceManagerAvatarReference(trimmed)) {
    return "";
  }

  if (trimmed.startsWith("data:image/")) {
    return normalizeInlineAvatarData(trimmed);
  }

  if (trimmed.startsWith("blob:")) {
    return trimmed;
  }

  if (trimmed.startsWith("chrome-extension://") || trimmed.startsWith("moz-extension://")) {
    return trimmed;
  }

  if (trimmed.startsWith("//")) {
    return `https:${trimmed}`;
  }

  if (/^\/?api\/profile\/[^/]+\/image(\/|$)/i.test(trimmed)) {
    const normalizedPath = trimmed.startsWith("/") ? trimmed : `/${trimmed}`;
    return `${PPS_PROFILE_BASE_URL}${normalizedPath}`;
  }

  if (/^ims\/avatar\/download\//i.test(trimmed)) {
    return `${IMS_BASE_URL}/${trimmed}`;
  }

  if (/^avatar\/download\//i.test(trimmed)) {
    return `${IMS_BASE_URL}/ims/${trimmed}`;
  }

  if (/^\/ims\/avatar\/download\//i.test(trimmed)) {
    return `${IMS_BASE_URL}${trimmed}`;
  }

  if (trimmed.startsWith("/")) {
    return `${IMS_BASE_URL}${trimmed}`;
  }

  if (!trimmed.includes("://")) {
    if (isLikelyUrlWithoutScheme(trimmed)) {
      return `https://${trimmed}`;
    }

    if (isLikelyImsAvatarId(trimmed)) {
      return `${IMS_BASE_URL}/ims/avatar/download/${encodeURIComponent(trimmed)}`;
    }

    if (!isLikelyImageAssetPath(trimmed)) {
      return "";
    }

    try {
      return chrome.runtime.getURL(trimmed);
    } catch {
      return "";
    }
  }

  try {
    const parsed = new URL(trimmed);
    if (parsed.protocol === "http:") {
      parsed.protocol = "https:";
    }
    if (parsed.protocol !== "https:" && parsed.protocol !== "chrome-extension:" && parsed.protocol !== "moz-extension:") {
      return "";
    }
    return parsed.toString();
  } catch {
    return "";
  }
}

function isPpsProfileImageUrl(url) {
  if (!url || url.startsWith("data:image/") || url.startsWith("blob:")) {
    return false;
  }

  try {
    const parsed = new URL(url);
    return /(^|\.)pps\.services\.adobe\.com$/i.test(parsed.hostname) && /\/api\/profile\/[^/]+\/image(\/|$)/i.test(parsed.pathname);
  } catch {
    return false;
  }
}

function toPpsProfileImageSizeUrl(url, size) {
  const normalized = normalizeAvatarCandidate(url);
  if (!normalized || !isPpsProfileImageUrl(normalized) || !Number.isFinite(size) || size <= 0) {
    return normalized;
  }

  try {
    const parsed = new URL(normalized);
    const nextSize = String(Math.floor(size));
    const withTrailingSize = parsed.pathname.replace(/\/(\d+)(\/?)$/i, `/${nextSize}$2`);

    if (withTrailingSize !== parsed.pathname) {
      parsed.pathname = withTrailingSize;
      return parsed.toString();
    }

    parsed.pathname = `${parsed.pathname.replace(/\/?$/, "")}/${nextSize}`;
    return parsed.toString();
  } catch {
    return normalized;
  }
}

function scoreAvatarCandidatePriority(value) {
  const normalized = normalizeAvatarCandidate(value) || normalizeInlineAvatarData(value);
  if (!normalized) {
    return -1000;
  }

  const lower = normalized.toLowerCase();
  if (
    normalized === FALLBACK_AVATAR ||
    /underpar(?:-round)?-[0-9]+\.png$/i.test(lower) ||
    /underpar(?:-round)?\.ico$/i.test(lower)
  ) {
    return -200;
  }

  if (normalized.startsWith("data:image/")) {
    return 420;
  }
  if (normalized.startsWith("blob:")) {
    return 390;
  }
  if (normalized.startsWith("chrome-extension://") || normalized.startsWith("moz-extension://")) {
    return 320;
  }

  let score = 0;
  if (isPpsProfileImageUrl(normalized)) {
    score += 340;
  }
  if (isImsAvatarDownloadUrl(normalized)) {
    score += 280;
  } else if (/\/ims\/avatar\//i.test(normalized)) {
    score += 220;
  }
  if (/avatar|profile|picture|photo|image/i.test(normalized)) {
    score += 24;
  }
  if (/\.(png|jpe?g|gif|webp|avif|svg)(\?|$)/i.test(normalized)) {
    score += 12;
  }
  if (/^https:\/\//i.test(normalized)) {
    score += 4;
  }

  return score;
}

function prioritizeAvatarCandidates(values) {
  const normalized = [
    ...new Set((values || []).map((value) => normalizeAvatarCandidate(value) || normalizeInlineAvatarData(value)).filter(Boolean)),
  ];
  return normalized
    .map((value, index) => ({
      value,
      index,
      score: scoreAvatarCandidatePriority(value),
    }))
    .sort((left, right) => right.score - left.score || left.index - right.index)
    .map((entry) => entry.value);
}

function inferImageMimeTypeFromBuffer(buffer) {
  if (!buffer) {
    return "";
  }

  const bytes = buffer instanceof Uint8Array ? buffer : new Uint8Array(buffer);
  if (!bytes || bytes.length < 2) {
    return "";
  }

  const hasPrefix = (prefix) => {
    if (!Array.isArray(prefix) || bytes.length < prefix.length) {
      return false;
    }
    for (let index = 0; index < prefix.length; index += 1) {
      if (bytes[index] !== prefix[index]) {
        return false;
      }
    }
    return true;
  };

  if (hasPrefix([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a])) {
    return "image/png";
  }
  if (hasPrefix([0xff, 0xd8, 0xff])) {
    return "image/jpeg";
  }
  if (hasPrefix([0x47, 0x49, 0x46, 0x38])) {
    return "image/gif";
  }
  if (hasPrefix([0x42, 0x4d])) {
    return "image/bmp";
  }

  if (bytes.length >= 12) {
    const riff = String.fromCharCode(bytes[0], bytes[1], bytes[2], bytes[3]);
    const webp = String.fromCharCode(bytes[8], bytes[9], bytes[10], bytes[11]);
    if (riff === "RIFF" && webp === "WEBP") {
      return "image/webp";
    }
  }

  if (bytes.length >= 12) {
    const ftyp = String.fromCharCode(bytes[4], bytes[5], bytes[6], bytes[7]);
    const brand = String.fromCharCode(bytes[8], bytes[9], bytes[10], bytes[11]);
    if (ftyp === "ftyp" && (brand === "avif" || brand === "avis")) {
      return "image/avif";
    }
  }

  try {
    const text = new TextDecoder("utf-8", { fatal: false }).decode(bytes.subarray(0, Math.min(bytes.length, 512)));
    if (/<svg[\s>]/i.test(text)) {
      return "image/svg+xml";
    }
  } catch {
    // Ignore text decoding errors for binary payloads.
  }

  return "";
}

function normalizeInlineAvatarData(value) {
  if (typeof value !== "string") {
    return "";
  }

  const trimmed = value.trim();
  if (!trimmed) {
    return "";
  }

  const normalizeBase64 = (base64Value) => String(base64Value || "").replace(/\s+/g, "");
  const inferMimeType = (normalizedBase64) => {
    if (!normalizedBase64) {
      return "";
    }
    if (normalizedBase64.startsWith("iVBOR")) {
      return "image/png";
    }
    if (normalizedBase64.startsWith("/9j/")) {
      return "image/jpeg";
    }
    if (normalizedBase64.startsWith("R0lGOD")) {
      return "image/gif";
    }
    if (normalizedBase64.startsWith("UklGR")) {
      return "image/webp";
    }
    if (normalizedBase64.startsWith("Qk")) {
      return "image/bmp";
    }
    if (normalizedBase64.startsWith("PHN2Zy")) {
      return "image/svg+xml";
    }
    return "";
  };

  const looksLikeBase64Image = (normalizedBase64) => {
    if (!normalizedBase64 || normalizedBase64.length < 64) {
      return false;
    }
    if (!/^[A-Za-z0-9+/=_-]+$/.test(normalizedBase64)) {
      return false;
    }
    return Boolean(inferMimeType(normalizedBase64));
  };

  const looksLikeBase64Payload = (normalizedBase64) => {
    if (!normalizedBase64 || normalizedBase64.length < 64) {
      return false;
    }
    return /^[A-Za-z0-9+/=_-]+$/.test(normalizedBase64);
  };

  if (/^data:/i.test(trimmed)) {
    const match = trimmed.match(/^data:([^;,]+);base64,(.+)$/i);
    if (!match) {
      return "";
    }

    const rawMime = String(match[1] || "").trim().toLowerCase();
    const normalizedBase64 = normalizeBase64(match[2]);
    const inferredMime = inferMimeType(normalizedBase64);
    const mime = /^image\//i.test(rawMime) ? rawMime : inferredMime;
    const isImageMime = /^image\//i.test(mime);
    const validPayload = isImageMime ? looksLikeBase64Payload(normalizedBase64) : looksLikeBase64Image(normalizedBase64);
    if (!normalizedBase64 || !mime || !validPayload) {
      return "";
    }
    return `data:${mime};base64,${normalizedBase64}`;
  }

  const normalizedBase64 = normalizeBase64(trimmed);
  if (!looksLikeBase64Image(normalizedBase64)) {
    return "";
  }

  const mime = inferMimeType(normalizedBase64) || "image/png";
  return `data:${mime};base64,${normalizedBase64}`;
}

function collectInlineAvatarDataCandidatesFromShape(value) {
  if (!value || typeof value !== "object") {
    return [];
  }

  const candidates = [];
  const seenObjects = new WeakSet();
  const queue = [{ current: value, depth: 0 }];

  while (queue.length > 0) {
    const { current, depth } = queue.shift();
    if (!current || typeof current !== "object" || seenObjects.has(current) || depth > 4) {
      continue;
    }
    seenObjects.add(current);

    if (Array.isArray(current)) {
      const limit = Math.min(current.length, 32);
      for (let index = 0; index < limit; index += 1) {
        const item = current[index];
        if (item && typeof item === "object") {
          queue.push({ current: item, depth: depth + 1 });
        }
      }
      continue;
    }

    for (const [key, entry] of Object.entries(current)) {
      if (entry && typeof entry === "object") {
        queue.push({ current: entry, depth: depth + 1 });
        continue;
      }

      if (typeof entry !== "string") {
        continue;
      }

      const keyLooksRelevant = /avatar|photo|picture|image|thumbnail|icon/i.test(key);
      if (!keyLooksRelevant && !/^data:image\//i.test(entry.trim())) {
        continue;
      }

      const normalized = normalizeInlineAvatarData(entry);
      if (normalized) {
        candidates.push(normalized);
      }
    }
  }

  return [...new Set(candidates)];
}

function getProfileInlineAvatarDataCandidates(profile) {
  if (!profile || typeof profile !== "object") {
    return [];
  }

  const explicitCandidates = [
    profile?.user_image,
    profile?.userImage,
    profile?.additional_info?.user_image,
    profile?.additional_info?.userImage,
    profile?.avatar_data,
    profile?.avatarData,
    profile?.additional_info?.avatar_data,
    profile?.additional_info?.avatarData,
    profile?.picture_data,
    profile?.additional_info?.picture_data,
    profile?.images?.avatar?.data,
    profile?.images?.profile?.data,
  ]
    .map((value) => normalizeInlineAvatarData(value))
    .filter(Boolean);

  const discoveredCandidates = collectInlineAvatarDataCandidatesFromShape(profile);
  return [...new Set([...explicitCandidates, ...discoveredCandidates])];
}

function getProfileInlineAvatarDataUrl(profile) {
  return getProfileInlineAvatarDataCandidates(profile)[0] || "";
}

function toImsAvatarDownloadUrl(identity, size = 128) {
  const raw = String(identity || "").trim();
  if (!raw) {
    return "";
  }
  if (isBlockedAudienceManagerAvatarReference(raw)) {
    return "";
  }

  const normalized = normalizeAvatarCandidate(raw);
  if (normalized) {
    return normalized;
  }

  const imsBase = IMS_BASE_URL;
  const encoded = encodeURIComponent(raw);
  const sizePart = Number.isFinite(size) && size > 0 ? `?size=${encodeURIComponent(String(size))}` : "";
  return `${imsBase}/ims/avatar/download/${encoded}${sizePart}`;
}

function extractProfileImageUrl(profile) {
  const direct = firstNonEmptyString([
    profile?.user_image_url,
    profile?.userImageUrl,
    profile?.additional_info?.user_image_url,
    profile?.additional_info?.userImageUrl,
    profile?.avatar,
    profile?.avatarUrl,
    profile?.avatar_url,
    profile?.additional_info?.avatar,
    profile?.additional_info?.avatarUrl,
    profile?.additional_info?.avatar_url,
    profile?.picture,
    profile?.photo,
  ]);

  const normalized = normalizeAvatarCandidate(direct);
  if (normalized) {
    return normalized;
  }

  const identityFallback = firstNonEmptyString([
    profile?.userId,
    profile?.user_id,
    profile?.sub,
    profile?.id,
  ]);

  return toImsAvatarDownloadUrl(identityFallback);
}

function resolveLoginProfile(loginData) {
  return loginData?.profile || loginData?.userProfile || null;
}

function resolveLoginImageUrl(loginData) {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    return "";
  }
  const direct = normalizeAvatarCandidate(
    firstNonEmptyString([
      loginData?.imageUrl,
      loginData?.user_image_url,
      loginData?.userImageUrl,
      loginData?.avatarUrl,
      loginData?.avatar_url,
    ])
  );
  if (direct) {
    return direct;
  }

  const inlineLoginCandidate = normalizeInlineAvatarData(
    firstNonEmptyString([
      loginData?.user_image,
      loginData?.userImage,
      loginData?.avatarData,
      loginData?.avatar_data,
    ])
  );
  if (inlineLoginCandidate) {
    return inlineLoginCandidate;
  }

  const profile = resolveLoginProfile(loginData) || {};
  const inlineProfileCandidate = getProfileInlineAvatarDataUrl(profile);
  if (inlineProfileCandidate) {
    return inlineProfileCandidate;
  }

  return extractProfileImageUrl(profile);
}

function getProfileAvatarCandidates(profile) {
  const inlineDataCandidates = getProfileInlineAvatarDataCandidates(profile);
  const candidates = [
    profile?.additional_info?.user_image_url,
    profile?.additional_info?.user_image,
    profile?.additional_info?.userImageUrl,
    profile?.additional_info?.userImage,
    profile?.additional_info?.user_picture,
    profile?.additional_info?.picture_url,
    profile?.additional_info?.userPhotoUrl,
    profile?.additional_info?.profile_picture,
    profile?.additional_info?.avatar,
    profile?.additional_info?.avatar_url,
    profile?.additional_info?.avatarUrl,
    profile?.additional_info?.picture,
    profile?.user_image_url,
    profile?.user_image,
    profile?.userImageUrl,
    profile?.userImage,
    profile?.userPhotoUrl,
    profile?.profilePicture,
    profile?.avatar,
    profile?.avatarUrl,
    profile?.avatar_url,
    profile?.picture,
    profile?.photo,
    profile?.photo_url,
    profile?.thumbnailUrl,
    profile?.thumbnail_url,
    profile?.user?.avatar,
    profile?.user?.avatarUrl,
    profile?.profile?.avatar,
    profile?.profile?.avatarUrl,
    profile?.profile?.picture,
    profile?.profile?.photo,
    profile?.imageUrl,
    profile?.images?.avatar?.url,
    profile?.images?.avatar?.href,
    profile?.images?.profile?.url,
    profile?.images?.profile?.href,
    profile?.photo?.url,
    profile?.photo?.href,
  ];

  const identityCandidate = firstNonEmptyString([
    profile?.userId,
    profile?.user_id,
    profile?.sub,
    profile?.id,
  ]);
  const identityAvatarUrl = toImsAvatarDownloadUrl(identityCandidate);
  if (identityAvatarUrl) {
    // Keep user_image_url/avatar fields first; use userId-derived endpoint as fallback only.
    candidates.push(identityAvatarUrl);
  }

  const normalized = [
    ...inlineDataCandidates,
    ...candidates.map((value) => normalizeAvatarCandidate(value)).filter(Boolean),
  ];
  return [...new Set(normalized)];
}

function getProfileAvatarUrl(profile) {
  return getProfileAvatarCandidates(profile)[0] || "";
}

function appendAvatarSize(url, size) {
  if (!url || url.startsWith("data:image/") || url.startsWith("blob:")) {
    return url;
  }

  if (!Number.isFinite(size) || size <= 0) {
    return url;
  }

  try {
    const parsed = new URL(url);
    parsed.searchParams.set("size", String(size));
    return parsed.toString();
  } catch {
    return url;
  }
}

function collectAvatarCandidatesFromProfileShape(profile) {
  if (!profile || typeof profile !== "object") {
    return [];
  }

  const scoredCandidates = [];
  const seenObjects = new WeakSet();
  const stack = [profile];

  while (stack.length > 0) {
    const current = stack.pop();
    if (!current || typeof current !== "object" || seenObjects.has(current)) {
      continue;
    }
    seenObjects.add(current);

    if (Array.isArray(current)) {
      for (const item of current) {
        if (item && typeof item === "object") {
          stack.push(item);
        } else if (typeof item === "string") {
          const normalized = normalizeAvatarCandidate(item);
          if (
            normalized &&
            (/\/ims\/avatar\//i.test(normalized) || /avatar|photo|picture|image/i.test(normalized))
          ) {
            const score = /\/ims\/avatar\/download\//i.test(normalized) ? 80 : 40;
            scoredCandidates.push({ url: normalized, score });
          }
        }
      }
      continue;
    }

    for (const [key, value] of Object.entries(current)) {
      if (value && typeof value === "object") {
        stack.push(value);
        continue;
      }

      if (typeof value !== "string") {
        continue;
      }

      const normalized = normalizeAvatarCandidate(value);
      if (!normalized) {
        continue;
      }

      const keyLooksLikeAvatar = /avatar|photo|picture|image/i.test(key);
      const valueLooksLikeAvatar =
        /\/ims\/avatar\//i.test(normalized) ||
        /avatar|photo|picture|image/i.test(normalized) ||
        /\.(png|jpg|jpeg|gif|webp|svg)(\?|$)/i.test(normalized);

      if (keyLooksLikeAvatar || valueLooksLikeAvatar) {
        let score = 0;
        if (/user|person|profile|self/i.test(key)) {
          score += 30;
        }
        if (/avatar/i.test(key)) {
          score += 18;
        }
        if (/photo|picture|image/i.test(key)) {
          score += 12;
        }
        if (/\/ims\/avatar\/download\//i.test(normalized)) {
          score += 80;
        } else if (/\/ims\/avatar\//i.test(normalized)) {
          score += 50;
        } else if (/\.(png|jpg|jpeg|gif|webp|svg)(\?|$)/i.test(normalized)) {
          score += 22;
        }
        scoredCandidates.push({ url: normalized, score });
      }
    }
  }

  const bestScoreByUrl = new Map();
  for (const candidate of scoredCandidates) {
    const currentScore = bestScoreByUrl.get(candidate.url);
    if (currentScore === undefined || candidate.score > currentScore) {
      bestScoreByUrl.set(candidate.url, candidate.score);
    }
  }

  return [...bestScoreByUrl.entries()]
    .sort((left, right) => right[1] - left[1])
    .map(([url]) => url);
}

function getAvatarCandidates(loginData) {
  const candidates = [];
  const explicitLoginImageUrl = resolveLoginImageUrl(loginData);
  if (explicitLoginImageUrl) {
    candidates.push(explicitLoginImageUrl);
  }

  const persistedAvatar = readPersistedAvatarCandidate(loginData);
  if (persistedAvatar) {
    candidates.push(persistedAvatar);
  }

  const loginProfile = resolveLoginProfile(loginData);
  const profileCandidates = getProfileAvatarCandidates(loginProfile);
  const discoveredProfileCandidates = collectAvatarCandidatesFromProfileShape(loginProfile);
  candidates.push(...profileCandidates);
  candidates.push(...discoveredProfileCandidates);

  candidates.push(DEFAULT_AVATAR);
  return [...new Set(candidates.filter(Boolean))];
}

function getAvatarUrl(loginData) {
  return getAvatarCandidates(loginData)[0] || DEFAULT_AVATAR;
}

function isAvatarUiSafeUrl(url = "") {
  const normalized = normalizeAvatarCandidate(url) || normalizeInlineAvatarData(url);
  if (!normalized) {
    return false;
  }
  if (/^https:\/\//i.test(normalized)) {
    try {
      const parsed = new URL(normalized);
      const host = String(parsed.hostname || "").trim().toLowerCase();
      const path = String(parsed.pathname || "");
      if (
        ((host === "pps.services.adobe.com" || host.endsWith(".pps.services.adobe.com")) &&
          /\/api\/profile\/[^/]+\/image(\/|$)/i.test(path)) ||
        ((host === "ims-na1.adobelogin.com" || host.endsWith(".adobelogin.com")) &&
          /\/ims\/avatar\/download\//i.test(path))
      ) {
        return true;
      }
    } catch {
      return false;
    }
  }
  return (
    normalized.startsWith("data:image/") ||
    normalized.startsWith("blob:") ||
    normalized.startsWith("chrome-extension://") ||
    normalized.startsWith("moz-extension://")
  );
}

function getAvatarRenderUrl(loginData) {
  const resolved = normalizeAvatarCandidate(state.avatarResolvedUrl) || normalizeInlineAvatarData(state.avatarResolvedUrl);
  if (resolved && isAvatarUiSafeUrl(resolved)) {
    return resolved;
  }

  const persistedCandidate = readPersistedAvatarCandidate(loginData);
  const persisted = normalizeAvatarCandidate(persistedCandidate) || normalizeInlineAvatarData(persistedCandidate);
  if (persisted && isAvatarUiSafeUrl(persisted)) {
    return persisted;
  }

  const loginImageUrl = resolveLoginImageUrl(loginData);
  const provisional = normalizeAvatarCandidate(loginImageUrl) || normalizeInlineAvatarData(loginImageUrl);
  if (provisional && isAvatarUiSafeUrl(provisional)) {
    return provisional;
  }

  return FALLBACK_AVATAR;
}

function getSafeAvatarRenderUrl(loginData) {
  const candidate = getAvatarRenderUrl(loginData);
  return isAvatarUiSafeUrl(candidate) ? candidate : FALLBACK_AVATAR;
}

function firstNonEmptyString(values) {
  for (const value of values) {
    if (typeof value === "string" && value.trim().length > 0) {
      return value.trim();
    }
  }
  return "";
}

function getProfileDisplayName(profile) {
  const direct = firstNonEmptyString([profile?.displayName, profile?.fullName, profile?.full_name, profile?.name]);
  if (direct) {
    return direct;
  }

  const firstName = firstNonEmptyString([profile?.firstName, profile?.first_name]);
  const lastName = firstNonEmptyString([profile?.lastName, profile?.last_name]);
  const joined = [firstName, lastName].filter(Boolean).join(" ");
  return joined || "Adobe User";
}

function getProfileEmail(profile) {
  return firstNonEmptyString([
    profile?.email,
    profile?.user_email,
    profile?.emailAddress,
    profile?.mail,
    profile?.additional_info?.email,
    profile?.authId,
    profile?.aa_id,
    profile?.adobeID,
    profile?.additional_info?.authId,
    profile?.additional_info?.aa_id,
  ]);
}

function getProfileIdentity(profile) {
  return firstNonEmptyString([
    profile?.userId,
    profile?.user_id,
    profile?.sub,
    profile?.id,
    profile?.additional_info?.userId,
    profile?.additional_info?.user_id,
    profile?.additional_info?.sub,
    profile?.additional_info?.id,
  ]);
}

function resolveLoginAuthIdValue(loginData, profile = null) {
  const resolvedProfile = profile && typeof profile === "object" ? profile : resolveLoginProfile(loginData) || {};
  return firstNonEmptyString([
    loginData?.imsSession?.authId,
    loginData?.sessionKeys?.authId,
    getProfileEmail(resolvedProfile),
  ]);
}

function resolveLoginUserIdValue(loginData, profile = null) {
  const resolvedProfile = profile && typeof profile === "object" ? profile : resolveLoginProfile(loginData) || {};
  return firstNonEmptyString([
    loginData?.imsSession?.userId,
    loginData?.sessionKeys?.userId,
    getProfileIdentity(resolvedProfile),
  ]);
}

function resolveLoginDisplayNameValue(loginData, profile = null) {
  const resolvedProfile = profile && typeof profile === "object" ? profile : resolveLoginProfile(loginData) || {};
  const displayNameRaw = getProfileDisplayNameRaw(resolvedProfile);
  const displayName = getProfileDisplayName(resolvedProfile);
  if (!isProfileDisplayNamePlaceholder(displayNameRaw) || !isProfileDisplayNamePlaceholder(displayName)) {
    return displayName;
  }
  return firstNonEmptyString([
    resolveLoginAuthIdValue(loginData, resolvedProfile),
    resolveLoginUserIdValue(loginData, resolvedProfile),
    "Adobe User",
  ]);
}

function buildLoginAuthContext(loginData = {}) {
  const profile = resolveLoginProfile(loginData) || {};
  const primaryImsSession = loginData?.imsSession && typeof loginData.imsSession === "object" ? loginData.imsSession : {};
  const restrictedOrganizationContext = buildRestrictedOrganizationContext(
    resolveCachedOrganizationsFromLoginData(loginData),
    loginData,
    null
  );
  const activeOrganization = restrictedOrganizationContext?.activeOrganization || null;
  const detectedOrganizations = Array.isArray(restrictedOrganizationContext?.detectedOrganizations)
    ? restrictedOrganizationContext.detectedOrganizations
    : [];
  const activeOrganizationTrusted = activeOrganization?.authoritative === true || detectedOrganizations.length === 1;
  const principalId = firstNonEmptyString([
    resolveLoginAuthIdValue(loginData, profile),
    resolveLoginUserIdValue(loginData, profile),
  ]);
  const authId = resolveLoginAuthIdValue(loginData, profile);
  const userId = resolveLoginUserIdValue(loginData, profile);
  const verifiedClaim = extractVerifiedCustomerOrganizationClaim(loginData);
  const orgId = firstNonEmptyString([
    activeOrganizationTrusted ? activeOrganization?.orgId : "",
    activeOrganizationTrusted ? activeOrganization?.id : "",
    verifiedClaim?.rawId,
    verifiedClaim?.id,
    primaryImsSession?.orgId,
    profile?.tenantId,
    profile?.tenant_id,
    profile?.companyId,
    profile?.company_id,
    profile?.organizationId,
    profile?.organization_id,
    profile?.additional_info?.tenantId,
    profile?.additional_info?.tenant_id,
    profile?.additional_info?.companyId,
    profile?.additional_info?.company_id,
    profile?.additional_info?.organizationId,
    profile?.additional_info?.organization_id,
  ]);
  const orgName = firstNonEmptyString([
    activeOrganizationTrusted ? activeOrganization?.name : "",
    activeOrganizationTrusted ? activeOrganization?.label : "",
    primaryImsSession?.orgName,
    profile?.organizationName,
    profile?.organization_name,
    profile?.orgName,
    profile?.org_name,
    profile?.companyName,
    profile?.company_name,
    profile?.additional_info?.organizationName,
    profile?.additional_info?.organization_name,
    profile?.additional_info?.orgName,
    profile?.additional_info?.org_name,
    profile?.additional_info?.companyName,
    profile?.additional_info?.company_name,
  ]);

  return {
    principalId,
    authId,
    userId,
    displayName: resolveLoginDisplayNameValue(loginData, profile),
    orgId,
    orgName,
    sessionId: firstNonEmptyString([
      primaryImsSession?.sessionId,
      loginData?.sessionKeys?.sessionId,
    ]),
    tokenId: firstNonEmptyString([
      primaryImsSession?.tokenId,
      loginData?.sessionKeys?.tokenId,
    ]),
    clientId: firstNonEmptyString([
      primaryImsSession?.clientId,
    ]),
    scope: firstNonEmptyString([
      loginData?.scope,
      primaryImsSession?.scope,
    ]),
    expiresAt: coercePositiveNumber([
      loginData?.expiresAt,
      primaryImsSession?.expiresAt,
    ].find((value) => coercePositiveNumber(value) > 0)),
    accessTokenFingerprint: firstNonEmptyString([
      loginData?.sessionKeys?.accessTokenFingerprint,
      loginData?.accessToken ? String(loginData.accessToken).slice(-24) : "",
    ]),
  };
}

function getLoginAuthId(loginData) {
  return firstNonEmptyString([loginData?.authContext?.authId, resolveLoginAuthIdValue(loginData)]);
}

function getLoginEmail(loginData) {
  return getLoginAuthId(loginData);
}

function getLoginIdentity(loginData) {
  return firstNonEmptyString([loginData?.authContext?.userId, resolveLoginUserIdValue(loginData)]);
}

function getLoginPrincipalId(loginData) {
  return firstNonEmptyString([loginData?.authContext?.principalId, getLoginAuthId(loginData), getLoginIdentity(loginData)]);
}

function getLoginDisplayName(loginData) {
  return firstNonEmptyString([loginData?.authContext?.displayName, resolveLoginDisplayNameValue(loginData), "Adobe User"]);
}

function getLoginActiveOrganization(loginData) {
  const currentSession = loginData && typeof loginData === "object" ? loginData : {};
  return buildRestrictedOrganizationContext(
    resolveCachedOrganizationsFromLoginData(currentSession),
    currentSession,
    null
  ).activeOrganization;
}

function normalizeExperienceOrgSlug(activeOrganization) {
  const directId = String(activeOrganization?.id || "").trim();
  if (directId) {
    return encodeURIComponent(directId);
  }

  const normalizedName = String(activeOrganization?.name || "")
    .replace(/^Adobe\s+IMS\s+Org\s+/i, "")
    .trim();
  if (!normalizedName) {
    return "";
  }

  return encodeURIComponent(normalizedName.replace(/\s+/g, "-"));
}

function buildExperienceOrgUrl(activeOrganization) {
  const orgSlug = normalizeExperienceOrgSlug(activeOrganization);
  return orgSlug ? `https://experience.adobe.com/#/@${orgSlug}` : "https://experience.adobe.com";
}

function buildExperienceOrgTitle(activeOrganization) {
  const orgSlug = normalizeExperienceOrgSlug(activeOrganization);
  return orgSlug ? `Open Experience Cloud for ${orgSlug}` : "Open Experience Cloud";
}

function isProfileDisplayNamePlaceholder(displayName = "") {
  const normalized = String(displayName || "")
    .trim()
    .toLowerCase();
  return !normalized || normalized === "adobe user";
}

function getSessionProfileCompleteness(loginData) {
  const profile = resolveLoginProfile(loginData) || {};
  const authContext = buildLoginAuthContext(loginData);
  const displayNameRaw = getProfileDisplayNameRaw(profile);
  const displayName = authContext.displayName || getLoginDisplayName(loginData);
  const principalId = authContext.principalId;
  const authId = authContext.authId;
  const userId = authContext.userId;
  const orgId = authContext.orgId;
  const orgName = authContext.orgName;

  const missing = [];
  if (!principalId) {
    missing.push("principalId");
  }
  if (!orgId) {
    missing.push("organizationId");
  }
  if (!orgName) {
    missing.push("organizationName");
  }

  return {
    complete: missing.length === 0,
    missing,
    displayNameRaw,
    displayName,
    principalId,
    authId,
    email: authId,
    userId,
    orgId,
    orgName,
    authContext,
  };
}

function isProfilePayloadComplete(profilePayload) {
  if (!profilePayload || typeof profilePayload !== "object") {
    return false;
  }
  const pseudoSession = {
    profile: profilePayload,
  };
  return getSessionProfileCompleteness(pseudoSession).complete;
}

function getOrgDisplayName(loginData) {
  return firstNonEmptyString([
    loginData?.authContext?.orgName,
    buildLoginAuthContext(loginData).orgName,
    "Adobe organization unavailable",
  ]);
}

function toEntryValueString(value) {
  if (value === undefined || value === null) {
    return "";
  }
  if (typeof value === "string") {
    return value.trim();
  }
  if (typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }
  return "";
}

function flattenPrimitiveFields(value, prefix, output, options) {
  const { depth, maxDepth, maxEntries, seen } = options;
  if (output.length >= maxEntries || depth > maxDepth || value === null || value === undefined) {
    return;
  }

  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    const entryValue = toEntryValueString(value);
    if (entryValue) {
      output.push({ key: prefix || "value", value: entryValue });
    }
    return;
  }

  if (Array.isArray(value)) {
    if (value.length === 0) {
      return;
    }

    if (value.every((item) => ["string", "number", "boolean"].includes(typeof item))) {
      const joined = value.map((item) => String(item)).join(", ");
      if (joined) {
        output.push({ key: prefix || "value", value: joined });
      }
      return;
    }

    const limit = Math.min(value.length, 8);
    for (let index = 0; index < limit; index += 1) {
      flattenPrimitiveFields(value[index], `${prefix}[${index}]`, output, {
        depth: depth + 1,
        maxDepth,
        maxEntries,
        seen,
      });
      if (output.length >= maxEntries) {
        return;
      }
    }
    return;
  }

  if (typeof value !== "object") {
    return;
  }

  if (seen.has(value)) {
    return;
  }
  seen.add(value);

  const keys = Object.keys(value).sort((a, b) => a.localeCompare(b));
  for (const key of keys) {
    const nextPrefix = prefix ? `${prefix}.${key}` : key;
    flattenPrimitiveFields(value[key], nextPrefix, output, {
      depth: depth + 1,
      maxDepth,
      maxEntries,
      seen,
    });
    if (output.length >= maxEntries) {
      return;
    }
  }
}

function formatAvatarCandidateForMenu(candidate) {
  const value = String(candidate || "").trim();
  if (!value) {
    return "";
  }
  if (/^data:image\//i.test(value)) {
    const header = value.slice(0, value.indexOf(",") + 1);
    return `${header}... [inline payload, ${value.length} chars]`;
  }
  return value;
}

function isLikelyProfileImageReference(value) {
  const text = String(value || "").trim();
  if (!text) {
    return false;
  }
  return (
    /^https?:\/\//i.test(text) ||
    /^\/\//.test(text) ||
    /^\/ims\/avatar\/download\//i.test(text) ||
    /^ims\/avatar\/download\//i.test(text) ||
    /^avatar\/download\//i.test(text) ||
    /^data:image\//i.test(text) ||
    /^blob:/i.test(text) ||
    /adobelogin\.com\/ims\/avatar\//i.test(text) ||
    /\.(png|jpe?g|gif|webp|svg)(\?|$)/i.test(text)
  );
}

function collectProfileImageCandidatesForMenu(profile) {
  if (!profile || typeof profile !== "object") {
    return [];
  }

  const rawCandidates = [];
  const flattened = [];
  flattenPrimitiveFields(profile, "profile", flattened, {
    depth: 0,
    maxDepth: 4,
    maxEntries: 220,
    seen: new WeakSet(),
  });

  for (const entry of flattened) {
    if (!/avatar|photo|picture|image|thumbnail|icon/i.test(String(entry?.key || ""))) {
      continue;
    }
    if (isLikelyProfileImageReference(entry?.value)) {
      rawCandidates.push(String(entry.value).trim());
    }
  }

  const knownCandidates = getProfileAvatarCandidates(profile);
  const discoveredCandidates = collectAvatarCandidatesFromProfileShape(profile);
  const merged = [...new Set([...rawCandidates, ...knownCandidates, ...discoveredCandidates])];
  const normalized = [];
  const seen = new Set();

  const append = (value) => {
    const text = String(value || "").trim();
    if (!text || seen.has(text)) {
      return;
    }
    seen.add(text);
    normalized.push(text);
  };

  for (const candidate of merged) {
    append(candidate);
    const normalizedCandidate = normalizeAvatarCandidate(candidate) || normalizeInlineAvatarData(candidate);
    if (normalizedCandidate && normalizedCandidate !== candidate) {
      append(normalizedCandidate);
    }
  }

  return normalized.slice(0, 80);
}

function buildAvatarMenuEntries(loginData) {
  const profile = resolveLoginProfile(loginData) || {};
  const adobePassWorkflowActive = shouldHydrateAdobePassWorkflowForSession(loginData);
  const authContext =
    loginData?.authContext && typeof loginData.authContext === "object"
      ? loginData.authContext
      : buildLoginAuthContext(loginData);
  const resolvedProfileImage = resolveLoginImageUrl(loginData);
  const profileImageLabel = resolvedProfileImage.startsWith("data:image/")
    ? "[inline image payload]"
    : resolvedProfileImage;
  const entries = [];
  const seenKeys = new Set();

  const pushEntry = (label, value, options = {}) => {
    const normalizedValue = toEntryValueString(value);
    if (!normalizedValue || seenKeys.has(label)) {
      return;
    }
    seenKeys.add(label);
    entries.push({
      key: label,
      value: normalizedValue,
      multiline: options.multiline === true,
      copyValue: String(options.copyValue || "").trim(),
    });
  };

  pushEntry("Name", getLoginDisplayName(loginData));
  pushEntry("Adobe Principal", getLoginPrincipalId(loginData));
  pushEntry("Adobe Auth ID", getLoginAuthId(loginData));
  pushEntry("Organization", getOrgDisplayName(loginData));
  pushEntry("Organization ID", authContext?.orgId);
  if (adobePassWorkflowActive) {
    const cmConsoleAccessToken = getPreferredCmAccessTokenCandidate();
    const cmConsoleClaims = parseJwtPayload(cmConsoleAccessToken) || {};
    const cmConsoleClientId = String(firstNonEmptyString([cmConsoleClaims.client_id, cmConsoleClaims.clientId]) || "")
      .trim()
      .toLowerCase();
    const hasCmConsoleToken = Boolean(cmConsoleAccessToken && isCmConsoleClientId(cmConsoleClientId));
    const cmConsoleStatusText = hasCmConsoleToken
      ? cmConsoleAccessToken
      : state.cmAuthBootstrapPromise || state.cmTenantsPrecheckPending
        ? "Hydrating cm-console-ui bearer..."
        : state.cmTenantsPrecheckLastError
          ? `Unavailable: ${String(state.cmTenantsPrecheckLastError || "").trim()}`
          : "Unavailable: cm-console-ui bearer has not been hydrated yet.";
    pushEntry("cm-console-ui access token", cmConsoleStatusText, {
      multiline: true,
      copyValue: hasCmConsoleToken ? cmConsoleAccessToken : "",
    });
  }
  pushEntry("Profile Image URL", profileImageLabel);
  const allProfileImageCandidates = collectProfileImageCandidatesForMenu(profile);
  const allProfileImageLines =
    allProfileImageCandidates.length > 0
      ? allProfileImageCandidates.map((candidate) => formatAvatarCandidateForMenu(candidate))
      : ["No profile image URL candidates found in profile payload."];
  pushEntry("All Profile Image URLs", allProfileImageLines.join("\n"), { multiline: true });
  pushEntry("User ID", getLoginIdentity(loginData));
  pushEntry(
    "Account Type",
    firstNonEmptyString([profile?.account_type, profile?.additional_info?.account_type, profile?.additional_info?.projectedProductContext])
  );

  const flattened = [];
  flattenPrimitiveFields(profile, "profile", flattened, {
    depth: 0,
    maxDepth: 4,
    maxEntries: 80,
    seen: new WeakSet(),
  });

  for (const entry of flattened) {
    if (!seenKeys.has(entry.key)) {
      seenKeys.add(entry.key);
      entries.push(entry);
    }
  }

  return entries;
}

function getAvatarCacheIdentity(loginData) {
  return firstNonEmptyString([
    getLoginPrincipalId(loginData),
    getLoginAuthId(loginData),
    getLoginIdentity(loginData),
    "anonymous",
  ]);
}

function getAvatarPersistIdentityCandidates(loginData, options = {}) {
  const includeTokenFingerprint = options.includeTokenFingerprint !== false;
  const tokenFingerprint = loginData?.accessToken ? String(loginData.accessToken).slice(-24) : "";
  const candidates = [
    getLoginPrincipalId(loginData),
    getLoginAuthId(loginData),
    getLoginIdentity(loginData),
  ];
  if (includeTokenFingerprint && tokenFingerprint) {
    candidates.push(`token:${tokenFingerprint}`);
  }

  return [...new Set(candidates.map((value) => String(value || "").trim()).filter(Boolean))].slice(0, 12);
}

function hasAvatarPersistProfileIdentity(loginData) {
  const identity = firstNonEmptyString([
    getLoginPrincipalId(loginData),
    getLoginAuthId(loginData),
    getLoginIdentity(loginData),
  ]);
  return Boolean(identity);
}

function getAvatarPersistStorageKeys(loginData, options = {}) {
  const identities = getAvatarPersistIdentityCandidates(loginData, options);
  const keys = [];
  for (const identity of identities) {
    const encodedIdentity = encodeURIComponent(identity);
    keys.push(`${AVATAR_PERSIST_STORAGE_PREFIX}${encodedIdentity}`);
    keys.push(`${LEGACY_AVATAR_PERSIST_STORAGE_PREFIX}${encodedIdentity}`);
  }
  return [...new Set(keys)];
}

function normalizeAvatarPersistIdentityValues(values) {
  const source = Array.isArray(values) ? values : [values];
  const normalized = source
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
  return [...new Set(normalized)].slice(0, 24);
}

function avatarPersistIdentitiesOverlap(leftValues, rightValues) {
  const left = normalizeAvatarPersistIdentityValues(leftValues);
  const right = new Set(normalizeAvatarPersistIdentityValues(rightValues));
  if (left.length === 0 || right.size === 0) {
    return false;
  }
  return left.some((value) => right.has(value));
}

function getAvatarPersistKeyScopeWeight(key, identityKeySet) {
  if (identityKeySet.has(key)) {
    if (key.startsWith(AVATAR_PERSIST_STORAGE_PREFIX)) {
      return 2400;
    }
    if (key.startsWith(LEGACY_AVATAR_PERSIST_STORAGE_PREFIX)) {
      return 2200;
    }
    return 2000;
  }

  if (key === AVATAR_PERSIST_GLOBAL_KEY) {
    return 1200;
  }
  if (key === LEGACY_AVATAR_PERSIST_GLOBAL_KEY) {
    return 1000;
  }
  return 0;
}

function readPersistedAvatarCandidate(loginData) {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    return "";
  }
  const hasProfileIdentity = hasAvatarPersistProfileIdentity(loginData);
  const identityKeys = getAvatarPersistStorageKeys(loginData, {
    includeTokenFingerprint: !hasProfileIdentity,
  });
  const identityKeySet = new Set(identityKeys);
  const activeIdentityHints = normalizeAvatarPersistIdentityValues(
    getAvatarPersistIdentityCandidates(loginData, { includeTokenFingerprint: false })
  );
  const keys = [...new Set([...identityKeys, AVATAR_PERSIST_GLOBAL_KEY, LEGACY_AVATAR_PERSIST_GLOBAL_KEY])];
  if (keys.length === 0) {
    return "";
  }

  let bestCandidate = "";
  let bestScore = Number.NEGATIVE_INFINITY;
  let bestUpdatedAt = 0;

  for (const key of keys) {
    try {
      const raw = localStorage.getItem(key);
      if (!raw) {
        continue;
      }

      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== "object") {
        localStorage.removeItem(key);
        continue;
      }

      if (key === AVATAR_PERSIST_GLOBAL_KEY || key === LEGACY_AVATAR_PERSIST_GLOBAL_KEY) {
        const recordIdentityHints = normalizeAvatarPersistIdentityValues(parsed.identities || parsed.identityHints || []);
        if (
          activeIdentityHints.length > 0 &&
          recordIdentityHints.length > 0 &&
          !avatarPersistIdentitiesOverlap(activeIdentityHints, recordIdentityHints)
        ) {
          continue;
        }
      }

      const expiresAt = Number(parsed.expiresAt || 0);
      if (!Number.isFinite(expiresAt) || expiresAt <= Date.now()) {
        localStorage.removeItem(key);
        continue;
      }

      const candidate = normalizeInlineAvatarData(parsed.dataUrl || "") || normalizeAvatarCandidate(parsed.url || "");
      if (!candidate) {
        localStorage.removeItem(key);
        continue;
      }

      const avatarScore = scoreAvatarCandidatePriority(candidate);
      const scopeScore = getAvatarPersistKeyScopeWeight(key, identityKeySet);
      const totalScore = avatarScore + scopeScore;
      const updatedAt = Number(parsed.updatedAt || 0);
      const normalizedUpdatedAt = Number.isFinite(updatedAt) ? Math.max(0, updatedAt) : 0;

      if (totalScore > bestScore || (totalScore === bestScore && normalizedUpdatedAt > bestUpdatedAt)) {
        bestScore = totalScore;
        bestUpdatedAt = normalizedUpdatedAt;
        bestCandidate = candidate;
      }
    } catch {
      // Ignore malformed local avatar persistence entries.
    }
  }

  return bestCandidate;
}

function writePersistedAvatarCandidate(loginData, payload) {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    return;
  }
  const keys = [
    ...getAvatarPersistStorageKeys(loginData).filter((key) => key.startsWith(AVATAR_PERSIST_STORAGE_PREFIX)),
    AVATAR_PERSIST_GLOBAL_KEY,
  ];
  if (keys.length === 0) {
    return;
  }

  const normalizedResolved = normalizeInlineAvatarData(payload?.resolvedUrl || "") || normalizeAvatarCandidate(payload?.resolvedUrl || "");
  const normalizedDataUrl = normalizeInlineAvatarData(payload?.dataUrl || payload?.resolvedUrl || "");
  const normalizedSource = normalizeAvatarCandidate(payload?.sourceUrl || "");
  const preferredCandidate = normalizedDataUrl || normalizedResolved || normalizedSource;
  if (!preferredCandidate || scoreAvatarCandidatePriority(preferredCandidate) <= -150) {
    return;
  }

  const persistDataUrl =
    normalizedDataUrl && normalizedDataUrl.length <= AVATAR_MAX_LOCALSTORAGE_DATAURL_BYTES ? normalizedDataUrl : "";
  const persistUrl = normalizeAvatarCandidate(
    firstNonEmptyString([
      normalizedSource,
      normalizedResolved.startsWith("https://") ? normalizedResolved : "",
    ])
  );

  if (!persistDataUrl && !persistUrl) {
    return;
  }

  const ttlSeconds = Number(payload?.ttlSeconds || AVATAR_PERSIST_TTL_SECONDS);
  const expiresAt = Date.now() + Math.max(1, ttlSeconds) * 1000;
  const identityHints = normalizeAvatarPersistIdentityValues(
    getAvatarPersistIdentityCandidates(loginData, { includeTokenFingerprint: false })
  );
  const record = JSON.stringify({
    expiresAt,
    url: persistUrl,
    dataUrl: persistDataUrl,
    identities: identityHints,
    updatedAt: Date.now(),
  });

  try {
    for (const key of keys) {
      localStorage.setItem(key, record);
    }
  } catch {
    // Ignore localStorage quota failures.
  }
}

function resetAvatarStateForInteractiveLogin() {
  purgeAvatarCaches();
  clearResolvedAvatar();
}

function resolveAuthAvatarSeed(authData, profile = null) {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    return "";
  }
  const profileSeed = profile ? resolveLoginImageUrl({ profile }) : "";
  return normalizeAvatarCandidate(
    firstNonEmptyString([authData?.capturedAvatarUrl, authData?.imageUrl, profileSeed])
  ) || "";
}

function buildSessionKeySnapshot(loginData = {}) {
  const imsSession = loginData?.imsSession && typeof loginData.imsSession === "object" ? loginData.imsSession : {};
  const authContext = buildLoginAuthContext({
    ...loginData,
    imsSession,
  });
  return pruneEmptyObject({
    principalId: compactStorageString(firstNonEmptyString([authContext?.principalId]), 320),
    userId: compactStorageString(firstNonEmptyString([authContext?.userId]), 220),
    authId: compactStorageString(firstNonEmptyString([authContext?.authId]), 220),
    sessionId: compactStorageString(firstNonEmptyString([authContext?.sessionId, imsSession?.sessionId]), 220),
    tokenId: compactStorageString(firstNonEmptyString([authContext?.tokenId, imsSession?.tokenId]), 220),
    orgId: compactStorageString(firstNonEmptyString([authContext?.orgId]), 220),
    accessTokenFingerprint: compactStorageString(
      firstNonEmptyString([
        authContext?.accessTokenFingerprint,
        loginData?.accessToken ? String(loginData.accessToken).slice(-24) : "",
      ]),
      64
    ),
  });
}

function buildLoginSessionPayloadFromAuth(authData, profile = null, imageUrl = "") {
  const normalizedProfile = profile && typeof profile === "object" ? profile : null;
  const rawOrganizations =
    authData?.organizations && typeof authData.organizations === "object" ? authData.organizations : null;
  const flattenedOrganizations = flattenOrganizations(rawOrganizations);
  const resolvedImageUrl =
    normalizeAvatarCandidate(
      firstNonEmptyString([imageUrl, resolveAuthAvatarSeed(authData, normalizedProfile || undefined)])
    ) || "";
  const detectedOrganizations = collectCanonicalRestrictedDetectedOrganizations(
    {
      accessToken: firstNonEmptyString([authData?.accessToken]),
      idToken: compactStorageString(firstNonEmptyString([authData?.idToken]), 4096),
      organizations: rawOrganizations,
      profile: normalizedProfile,
    },
    flattenedOrganizations
  );
  return buildNormalizedLoginData(
    {
      accessToken: firstNonEmptyString([authData?.accessToken]),
      expiresAt: Number(authData?.expiresAt || 0),
      tokenType: compactStorageString(firstNonEmptyString([authData?.tokenType]), 60) || "bearer",
      scope: compactStorageString(firstNonEmptyString([authData?.scope]), 2048),
      idToken: compactStorageString(firstNonEmptyString([authData?.idToken]), 4096),
      refreshToken: compactStorageString(firstNonEmptyString([authData?.refreshToken]), 4096),
      imsSession:
        authData?.imsSession && typeof authData.imsSession === "object"
          ? authData.imsSession
          : deriveImsSessionSnapshotFromToken(authData?.accessToken || ""),
      cmConsoleAccessToken: "",
      cmConsoleExpiresAt: 0,
      cmConsoleScope: "",
      cmConsoleImsSession: null,
      organizations: rawOrganizations,
      detectedOrganizations,
      profile: normalizedProfile,
      imageUrl: resolvedImageUrl,
    },
    {
      resetBootstrapTokens: true,
    }
  );
}

function getDefaultAdobePassOrgDescriptor() {
  return {
    orgId: ADOBEPASS_ORG_HANDLE,
    userId: null,
    name: "@AdobePass",
    avatarUrl: "",
  };
}

function resolveAuthoritativeAdobePassOrgDescriptor(loginData = {}) {
  const currentSession = loginData && typeof loginData === "object" ? loginData : {};
  const cachedOrganizations = resolveCachedOrganizationsFromLoginData(currentSession);
  const organizationContext = buildRestrictedOrganizationContext(cachedOrganizations, currentSession, null);
  const activeOrganization = organizationContext?.activeOrganization || null;
  const detectedOrganizations = Array.isArray(organizationContext?.detectedOrganizations)
    ? organizationContext.detectedOrganizations
    : [];
  const activeOrganizationTrusted = activeOrganization?.authoritative === true || detectedOrganizations.length === 1;
  const verifiedClaim = extractVerifiedCustomerOrganizationClaim(currentSession);
  const provenAdobePass =
    (activeOrganizationTrusted && matchesAdobePassOrg(activeOrganization)) ||
    matchesAdobePassOrg({
      orgId: firstNonEmptyString([verifiedClaim?.rawId, verifiedClaim?.id]),
    }) ||
    matchesAdobePassOrg(currentSession?.imsSession);

  if (!provenAdobePass) {
    return null;
  }

  const profile = resolveLoginProfile(currentSession);
  const descriptorSource =
    findAdobePassOrg([
      activeOrganizationTrusted ? activeOrganization : null,
      ...detectedOrganizations,
      ...cachedOrganizations,
    ].filter((entry) => entry && typeof entry === "object")) || null;
  if (descriptorSource) {
    const normalizedDescriptor = toAdobePassOrgDescriptor(
      descriptorSource?.raw && typeof descriptorSource.raw === "object" ? descriptorSource.raw : descriptorSource,
      profile
    );
    if (
      normalizedDescriptor &&
      firstNonEmptyString([
        normalizedDescriptor?.orgId,
        normalizedDescriptor?.userId,
        normalizedDescriptor?.name,
        normalizedDescriptor?.avatarUrl,
      ])
    ) {
      return normalizedDescriptor;
    }
  }

  const derivedDescriptor = {
    orgId: firstNonEmptyString([
      activeOrganizationTrusted ? activeOrganization?.orgId : "",
      activeOrganizationTrusted ? activeOrganization?.id : "",
      currentSession?.imsSession?.orgId,
      verifiedClaim?.rawId,
      verifiedClaim?.id,
      ADOBEPASS_ORG_HANDLE,
    ]),
    userId: firstNonEmptyString([
      currentSession?.imsSession?.userId,
    ]),
    name: firstNonEmptyString([
      activeOrganizationTrusted ? activeOrganization?.name : "",
      activeOrganizationTrusted ? activeOrganization?.label : "",
      currentSession?.imsSession?.orgName,
      ADOBEPASS_ORG_DISPLAY_NAME,
    ]),
    avatarUrl: "",
  };

  return firstNonEmptyString([
    derivedDescriptor.orgId,
    derivedDescriptor.userId,
    derivedDescriptor.name,
    derivedDescriptor.avatarUrl,
  ])
    ? derivedDescriptor
    : null;
}

function buildNormalizedLoginData(loginData = {}, options = {}) {
  const resetBootstrapTokens = options.resetBootstrapTokens === true;
  const profile = resolveLoginProfile(loginData);
  const normalizedProfile = profile && typeof profile === "object" ? profile : null;
  const accessToken = firstNonEmptyString([loginData?.accessToken]);
  const expiresAt = coercePositiveNumber(loginData?.expiresAt);
  const derivedImsSession = accessToken ? deriveImsSessionSnapshotFromToken(accessToken) : null;
  const mergedImsSession = mergeImsSessionSnapshots(
    derivedImsSession,
    loginData?.imsSession && typeof loginData?.imsSession === "object" ? loginData.imsSession : null
  );
  if (
    mergedImsSession &&
    (!coercePositiveNumber(mergedImsSession.expiresAt) ||
      (expiresAt && Math.abs(coercePositiveNumber(mergedImsSession.expiresAt) - expiresAt) > 2 * 60 * 1000))
  ) {
    mergedImsSession.expiresAt = expiresAt || coercePositiveNumber(mergedImsSession.expiresAt);
  }

  const normalized = {
    ...loginData,
    accessToken,
    expiresAt,
    tokenType: compactStorageString(firstNonEmptyString([loginData?.tokenType, mergedImsSession?.tokenType]), 60) || "bearer",
    scope: compactStorageString(firstNonEmptyString([loginData?.scope, mergedImsSession?.scope]), 2048),
    idToken: compactStorageString(firstNonEmptyString([loginData?.idToken]), 4096),
    refreshToken: compactStorageString(firstNonEmptyString([loginData?.refreshToken]), 4096),
    cmConsoleAccessToken: resetBootstrapTokens ? "" : compactStorageString(firstNonEmptyString([loginData?.cmConsoleAccessToken]), 4096),
    cmConsoleExpiresAt: resetBootstrapTokens ? 0 : coercePositiveNumber(loginData?.cmConsoleExpiresAt),
    cmConsoleScope: resetBootstrapTokens ? "" : compactStorageString(firstNonEmptyString([loginData?.cmConsoleScope]), 2048),
    cmConsoleImsSession: resetBootstrapTokens
      ? null
      : loginData?.cmConsoleImsSession && typeof loginData.cmConsoleImsSession === "object"
        ? loginData.cmConsoleImsSession
        : null,
    targetOrganization: normalizeRequestedTargetOrganization(loginData?.targetOrganization),
    consoleHydration: normalizeStoredConsoleHydrationSnapshot(loginData?.consoleHydration),
    profile: normalizedProfile,
    imsSession: mergedImsSession,
    imageUrl: "",
    adobePassOrg: null,
  };

  normalized.imageUrl =
    normalizeAvatarCandidate(resolveLoginImageUrl(normalized)) ||
    normalizeAvatarCandidate(readPersistedAvatarCandidate(normalized)) ||
    "";
  normalized.authContext = buildLoginAuthContext(normalized);
  normalized.sessionKeys = buildSessionKeySnapshot(normalized);
  return normalized;
}

async function resolveNormalizedLoginData(loginData = {}, options = {}) {
  const accessToken = firstNonEmptyString([loginData?.accessToken]);
  const fetchProfileEnabled = options.fetchProfile !== false && Boolean(accessToken);
  const [profilePayload, validatedImsSession] = await Promise.all([
    fetchProfileEnabled ? fetchImsSessionProfile(accessToken).catch(() => null) : Promise.resolve(null),
    accessToken ? fetchValidateTokenSessionSnapshot(accessToken).catch(() => null) : Promise.resolve(null),
  ]);

  let resolvedProfile = resolveLoginProfile(loginData);
  if (profilePayload && typeof profilePayload === "object") {
    resolvedProfile = mergeProfilePayloads(resolvedProfile, profilePayload);
  }

  const mergedImsSession = mergeImsSessionSnapshots(
    mergeImsSessionSnapshots(
      accessToken ? deriveImsSessionSnapshotFromToken(accessToken) : null,
      loginData?.imsSession && typeof loginData?.imsSession === "object" ? loginData.imsSession : null
    ),
    validatedImsSession
  );
  const resolvedImsSession = mergeImsSessionSnapshots(mergedImsSession, {
    userId: firstNonEmptyString([
      resolvedProfile?.userId,
      resolvedProfile?.user_id,
      resolvedProfile?.sub,
      resolvedProfile?.id,
    ]),
    authId: firstNonEmptyString([
      resolvedProfile?.authId,
      resolvedProfile?.aa_id,
      resolvedProfile?.adobeID,
      resolvedProfile?.additional_info?.authId,
      resolvedProfile?.additional_info?.aa_id,
    ]),
    expiresAt: coercePositiveNumber(loginData?.expiresAt),
    tokenType: firstNonEmptyString([loginData?.tokenType, mergedImsSession?.tokenType]),
    scope: firstNonEmptyString([loginData?.scope, mergedImsSession?.scope]),
  });

  return buildNormalizedLoginData(
    {
      ...loginData,
      profile: resolvedProfile && typeof resolvedProfile === "object" ? resolvedProfile : null,
      imsSession: resolvedImsSession,
    },
    {
      resetBootstrapTokens: options.resetBootstrapTokens === true,
    }
  );
}

function getAvatarCacheKey(loginData, url, size = 0) {
  const identity = getAvatarCacheIdentity(loginData);
  const normalizedUrl = normalizeAvatarCandidate(url);
  return `${AVATAR_CACHE_STORAGE_PREFIX}${identity}:${size}:${normalizedUrl}`;
}

function readAvatarCacheFromStorage(cacheKey) {
  try {
    const raw = localStorage.getItem(cacheKey);
    if (!raw) {
      return null;
    }

    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") {
      localStorage.removeItem(cacheKey);
      return null;
    }

    const expiresAt = Number(parsed.expiresAt || 0);
    if (expiresAt <= Date.now()) {
      localStorage.removeItem(cacheKey);
      return null;
    }

    const cachedUrl = normalizeAvatarCandidate(parsed.url || "");
    const dataUrl = typeof parsed.dataUrl === "string" ? parsed.dataUrl : "";
    if (dataUrl.startsWith("data:image/")) {
      return {
        sourceUrl: cachedUrl,
        resolvedUrl: dataUrl,
        expiresAt,
      };
    }

    if (cachedUrl) {
      return {
        sourceUrl: cachedUrl,
        resolvedUrl: cachedUrl,
        expiresAt,
      };
    }

    localStorage.removeItem(cacheKey);
    return null;
  } catch {
    return null;
  }
}

function readAvatarCache(cacheKey) {
  const memoryEntry = state.avatarMemoryCache.get(cacheKey);
  if (memoryEntry && memoryEntry.expiresAt > Date.now()) {
    return memoryEntry;
  }

  if (memoryEntry) {
    state.avatarMemoryCache.delete(cacheKey);
  }

  const storageEntry = readAvatarCacheFromStorage(cacheKey);
  if (storageEntry) {
    state.avatarMemoryCache.set(cacheKey, storageEntry);
    return storageEntry;
  }

  return null;
}

function writeAvatarCache(cacheKey, payload) {
  const ttlSeconds = Number(payload?.ttlSeconds || AVATAR_CACHE_TTL_SECONDS);
  const expiresAt = Date.now() + Math.max(1, ttlSeconds) * 1000;
  const sourceUrl = normalizeAvatarCandidate(payload?.sourceUrl || "");
  const resolvedUrl = payload?.resolvedUrl || "";
  const dataUrl = typeof payload?.dataUrl === "string" && payload.dataUrl.startsWith("data:image/")
    ? payload.dataUrl
    : "";

  if (!resolvedUrl && !dataUrl && !sourceUrl) {
    return;
  }

  const entry = {
    sourceUrl,
    resolvedUrl: dataUrl || resolvedUrl || sourceUrl,
    expiresAt,
  };
  state.avatarMemoryCache.set(cacheKey, entry);

  try {
    const persistable = {
      expiresAt,
      url: sourceUrl || normalizeAvatarCandidate(resolvedUrl) || "",
      dataUrl: dataUrl && dataUrl.length <= AVATAR_MAX_LOCALSTORAGE_DATAURL_BYTES ? dataUrl : "",
    };
    localStorage.setItem(cacheKey, JSON.stringify(persistable));
  } catch {
    // Ignore storage quota failures.
  }
}

function blobToDataUrl(blob) {
  if (!blob || blob.size <= 0) {
    return Promise.resolve("");
  }

  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onerror = () => resolve("");
    reader.onload = () => {
      if (typeof reader.result === "string" && reader.result.startsWith("data:image/")) {
        resolve(reader.result);
        return;
      }
      resolve("");
    };
    reader.readAsDataURL(blob);
  });
}

function logAvatarFailureOnce(reason, details = null) {
  if (state.avatarFailureLogged) {
    return;
  }
  state.avatarFailureLogged = true;
  log(`Avatar load failed (${reason}); using placeholder.`, details);
}

function purgeAvatarCaches() {
  state.avatarMemoryCache.clear();
  state.avatarDataUrlPrefetchKeys.clear();
  try {
    const keysToRemove = [];
    for (let index = 0; index < localStorage.length; index += 1) {
      const key = localStorage.key(index);
      if (
        typeof key === "string" &&
        (
          key.startsWith(AVATAR_CACHE_STORAGE_PREFIX) ||
          key.startsWith(LEGACY_AVATAR_CACHE_STORAGE_PREFIX) ||
          key.startsWith(AVATAR_PERSIST_STORAGE_PREFIX) ||
          key.startsWith(LEGACY_AVATAR_PERSIST_STORAGE_PREFIX)
        )
      ) {
        keysToRemove.push(key);
      }
    }

    for (const key of keysToRemove) {
      localStorage.removeItem(key);
    }
  } catch {
    // Ignore localStorage cleanup failures.
  }
}

function purgeDcrCaches() {
  state.dcrEnsureTokenPromiseByKey.clear();
  try {
    const keysToRemove = [];
    for (let index = 0; index < localStorage.length; index += 1) {
      const key = localStorage.key(index);
      if (
        typeof key === "string" &&
        (key.startsWith(`${DCR_CACHE_PREFIX}:`) || key.startsWith(`${LEGACY_DCR_CACHE_PREFIX}:`))
      ) {
        keysToRemove.push(key);
      }
    }

    for (const key of keysToRemove) {
      localStorage.removeItem(key);
    }
  } catch {
    // Ignore localStorage cleanup failures.
  }
}

function clearResolvedAvatar() {
  if (state.avatarObjectUrl) {
    try {
      URL.revokeObjectURL(state.avatarObjectUrl);
    } catch {
      // Ignore revoke errors.
    }
  }
  state.avatarObjectUrl = "";
  state.avatarResolvedUrl = "";
  state.avatarResolveKey = "";
  state.avatarImsRefreshKey = "";
  state.avatarImsRefreshAt = 0;
  state.avatarResolving = false;
  state.avatarFailureLogged = false;
}

function setResolvedAvatarUrl(url, objectUrl = false) {
  const normalized = normalizeAvatarCandidate(url);
  if (objectUrl) {
    if (state.avatarObjectUrl && state.avatarObjectUrl !== normalized) {
      try {
        URL.revokeObjectURL(state.avatarObjectUrl);
      } catch {
        // Ignore revoke errors.
      }
    }
    state.avatarObjectUrl = normalized;
  } else if (state.avatarObjectUrl) {
    try {
      URL.revokeObjectURL(state.avatarObjectUrl);
    } catch {
      // Ignore revoke errors.
    }
    state.avatarObjectUrl = "";
  }

  state.avatarResolvedUrl = normalized;
}

function makeAvatarResolveKey(loginData) {
  const compactAvatarValue = (value) => {
    const normalized = normalizeAvatarCandidate(value) || normalizeInlineAvatarData(value);
    if (!normalized) {
      return "";
    }
    if (normalized.startsWith("data:image/")) {
      const header = normalized.slice(0, normalized.indexOf(",") + 1);
      return `${header}len:${normalized.length}`;
    }
    return normalized;
  };

  const tokenFingerprint = loginData?.accessToken ? String(loginData.accessToken).slice(-16) : "";
  const persistedAvatar = compactAvatarValue(readPersistedAvatarCandidate(loginData));
  const explicitLoginImageUrl = compactAvatarValue(resolveLoginImageUrl(loginData));
  const loginProfile = resolveLoginProfile(loginData) || {};
  const profileCandidates = getProfileAvatarCandidates(loginProfile).map((value) => compactAvatarValue(value));
  const discoveredProfileCandidates = collectAvatarCandidatesFromProfileShape(loginProfile).map((value) =>
    compactAvatarValue(value)
  );
  return JSON.stringify({
    tokenFingerprint,
    persistedAvatar,
    explicitLoginImageUrl,
    profileCandidates,
    discoveredProfileCandidates,
  });
}

function getAvatarRefreshSessionKey(loginData) {
  const tokenFingerprint = loginData?.accessToken ? String(loginData.accessToken).slice(-24) : "";
  const profile = resolveLoginProfile(loginData) || {};
  const identity = firstNonEmptyString([
    profile?.userId,
    profile?.user_id,
    profile?.sub,
    profile?.id,
    profile?.email,
    profile?.user_email,
  ]);
  return `${identity}::${tokenFingerprint}`;
}

function shouldAttemptLiveAvatarRefresh(loginData) {
  const key = getAvatarRefreshSessionKey(loginData);
  const now = Date.now();
  if (!key) {
    return false;
  }

  if (state.avatarImsRefreshKey !== key) {
    state.avatarImsRefreshKey = key;
    state.avatarImsRefreshAt = now;
    return true;
  }

  if (now - Number(state.avatarImsRefreshAt || 0) >= AVATAR_IMS_REFRESH_COOLDOWN_MS) {
    state.avatarImsRefreshAt = now;
    return true;
  }

  return false;
}

function buildAvatarResolveCandidateList(baseCandidates) {
  const normalizedBase = prioritizeAvatarCandidates(baseCandidates || []);
  if (normalizedBase.length === 0) {
    return [];
  }

  const candidates = [];
  const seen = new Set();
  const pushCandidate = (value) => {
    const normalized = normalizeAvatarCandidate(value);
    if (!normalized || seen.has(normalized)) {
      return;
    }
    seen.add(normalized);
    candidates.push(normalized);
  };

  for (const candidate of normalizedBase) {
    pushCandidate(candidate);
  }

  for (const size of AVATAR_SIZE_PREFERENCES) {
    for (const candidate of normalizedBase) {
      if (
        candidate === FALLBACK_AVATAR ||
        /underpar(?:-round)?-[0-9]+\.png$/i.test(candidate) ||
        /underpar(?:-round)?\.ico$/i.test(candidate)
      ) {
        continue;
      }

      if (isPpsProfileImageUrl(candidate)) {
        pushCandidate(toPpsProfileImageSizeUrl(candidate, size));
        continue;
      }

      if (isImsAvatarDownloadUrl(candidate)) {
        continue;
      }
      pushCandidate(appendAvatarSize(candidate, size));
    }
  }

  return prioritizeAvatarCandidates(candidates).slice(0, AVATAR_MAX_RESOLVE_CANDIDATES);
}

async function fetchLiveAvatarCandidatesFromIms(loginData) {
  const token = String(loginData?.accessToken || "").trim();
  const candidates = [];
  const seen = new Set();
  const appendCandidate = (value) => {
    const normalized = normalizeAvatarCandidate(value);
    if (!normalized || seen.has(normalized)) {
      return;
    }
    seen.add(normalized);
    candidates.push(normalized);
  };

  const mergeProfileIntoSession = (incomingProfile) => {
    if (!incomingProfile || typeof incomingProfile !== "object" || !state.loginData) {
      return;
    }

    const mergedProfile = mergeProfilePayloads(resolveLoginProfile(state.loginData), incomingProfile);
    const mergedLoginData = {
      ...state.loginData,
      profile: mergedProfile,
      imageUrl: resolveLoginImageUrl({
        ...state.loginData,
        profile: mergedProfile,
      }),
    };
    state.loginData = mergedLoginData;
  };

  try {
    const profilePayload = await fetchImsSessionProfile(token);
    if (profilePayload && typeof profilePayload === "object") {
      mergeProfileIntoSession(profilePayload);
      for (const candidate of getProfileAvatarCandidates(profilePayload)) {
        appendCandidate(candidate);
      }
      for (const candidate of collectAvatarCandidatesFromProfileShape(profilePayload)) {
        appendCandidate(candidate);
      }
    }
  } catch {
    // Continue with existing in-memory candidates.
  }

  const sessionProfile = resolveLoginProfile(state.loginData);
  for (const candidate of getProfileAvatarCandidates(sessionProfile)) {
    appendCandidate(candidate);
  }
  for (const candidate of collectAvatarCandidatesFromProfileShape(sessionProfile)) {
    appendCandidate(candidate);
  }

  return candidates;
}

function isImsAvatarDownloadUrl(url) {
  if (!url || url.startsWith("data:image/") || url.startsWith("blob:")) {
    return false;
  }

  try {
    const parsed = new URL(url);
    return /(^|\.)adobelogin\.com$/i.test(parsed.hostname) && /\/ims\/avatar\/download\//i.test(parsed.pathname);
  } catch {
    return false;
  }
}

function buildAvatarFetchUrlCandidates(url) {
  const normalized = normalizeAvatarCandidate(url);
  if (!normalized) {
    return [];
  }

  const candidates = [normalized];
  const pushCandidate = (value) => {
    const candidate = normalizeAvatarCandidate(value);
    if (candidate && !candidates.includes(candidate)) {
      candidates.push(candidate);
    }
  };

  if (isPpsProfileImageUrl(normalized)) {
    for (const size of AVATAR_SIZE_PREFERENCES) {
      pushCandidate(toPpsProfileImageSizeUrl(normalized, size));
    }
    return candidates;
  }

  if (!isImsAvatarDownloadUrl(normalized)) {
    for (const size of AVATAR_SIZE_PREFERENCES) {
      pushCandidate(appendAvatarSize(normalized, size));
    }
    return candidates;
  }

  try {
    const parsed = new URL(normalized);
    if (!parsed.searchParams.has("size")) {
      const sized = new URL(parsed.toString());
      sized.searchParams.set("size", String(AVATAR_SIZE_PREFERENCES[0] || 128));
      pushCandidate(sized.toString());
    } else {
      for (const size of AVATAR_SIZE_PREFERENCES) {
        pushCandidate(appendAvatarSize(normalized, size));
      }
    }
  } catch {
    // Keep original candidates only.
  }

  return candidates;
}

function buildAvatarFetchAttempts(accessToken = "", url = "") {
  const baseHeaders = {
    Accept: "image/*,*/*;q=0.8",
  };
  const preferPpsIdentitySessionFirst = isPpsProfileImageUrl(url);

  const attempts = [];
  const seen = new Set();
  const pushAttempt = (headers, credentials) => {
    const key = `${credentials}|${Object.entries(headers)
      .sort((left, right) => String(left[0]).localeCompare(String(right[0])))
      .map(([key, value]) => `${key}:${value}`)
      .join("|")}`;
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    attempts.push({ headers, credentials });
  };

  if (preferPpsIdentitySessionFirst) {
    pushAttempt(baseHeaders, "include");
    pushAttempt(baseHeaders, "omit");
  }

  if (accessToken) {
    pushAttempt(
      {
        ...baseHeaders,
        Authorization: `Bearer ${accessToken}`,
      },
      "omit"
    );
    pushAttempt(
      {
        ...baseHeaders,
        Authorization: `Bearer ${accessToken}`,
      },
      "include"
    );
    pushAttempt(
      {
        Accept: "*/*",
        Authorization: `Bearer ${accessToken}`,
      },
      "omit"
    );

    for (const clientId of getUnderparImsClientIdCandidates(accessToken, ...LEGACY_IMS_AVATAR_CLIENT_IDS)) {
      if (!clientId) {
        continue;
      }
      pushAttempt(
        {
          ...baseHeaders,
          Authorization: `Bearer ${accessToken}`,
          "X-IMS-ClientId": clientId,
          "x-api-key": clientId,
        },
        "omit"
      );
      pushAttempt(
        {
          ...baseHeaders,
          Authorization: `Bearer ${accessToken}`,
          "X-IMS-ClientId": clientId,
          "x-api-key": clientId,
        },
        "include"
      );
    }
  }

  if (!preferPpsIdentitySessionFirst) {
    pushAttempt(baseHeaders, "omit");
    pushAttempt(baseHeaders, "include");
  } else {
    pushAttempt({ Accept: "*/*" }, "include");
    pushAttempt({ Accept: "*/*" }, "omit");
  }
  return attempts;
}

function canUseDirectAvatarLoad(url) {
  if (!url) {
    return Promise.resolve(false);
  }

  const normalized = normalizeAvatarCandidate(url) || normalizeInlineAvatarData(url);
  if (!normalized) {
    return Promise.resolve(false);
  }

  if (
    normalized.startsWith("chrome-extension://") ||
    normalized.startsWith("moz-extension://") ||
    normalized.startsWith("data:image/") ||
    normalized.startsWith("blob:")
  ) {
    return Promise.resolve(true);
  }

  // Avoid direct remote image loads from extension pages; these can emit noisy CORS/PNA
  // console errors in sidepanel/popup contexts. Remote avatars are resolved via background.
  if (/^https?:\/\//i.test(normalized)) {
    return Promise.resolve(false);
  }

  return new Promise((resolve) => {
    const image = new Image();
    let settled = false;

    const done = (result) => {
      if (settled) {
        return;
      }
      settled = true;
      image.onload = null;
      image.onerror = null;
      resolve(result);
    };

    const timeoutId = setTimeout(() => done(false), AVATAR_DIRECT_LOAD_TIMEOUT_MS);
    image.onload = () => {
      clearTimeout(timeoutId);
      done(true);
    };
    image.onerror = () => {
      clearTimeout(timeoutId);
      done(false);
    };
    image.src = normalized;
  });
}

async function fetchAvatarBlobUrl(url) {
  if (
    !url ||
    url.startsWith("data:image/") ||
    url.startsWith("blob:") ||
    url.startsWith("chrome-extension://") ||
    url.startsWith("moz-extension://")
  ) {
    return null;
  }

  // Keep remote avatar network I/O in background.js to avoid sidepanel/popup CORS/PNA noise.
  if (/^https?:\/\//i.test(String(url || "").trim())) {
    return null;
  }

  const urlCandidates = buildAvatarFetchUrlCandidates(url);
  let attemptCount = 0;
  const maxAttempts = 14;
  for (const targetUrl of urlCandidates) {
    const attempts = buildAvatarFetchAttempts(state.loginData?.accessToken || "", targetUrl);
    for (const attempt of attempts) {
      attemptCount += 1;
      if (attemptCount > maxAttempts) {
        return null;
      }

      try {
        const response = await fetch(targetUrl, {
          method: "GET",
          cache: "no-store",
          credentials: attempt.credentials,
          redirect: "follow",
          headers: attempt.headers,
        });

        if (!response.ok) {
          continue;
        }

        const blob = await response.blob();
        if (!blob || blob.size === 0) {
          continue;
        }

        const responseBuffer = await blob.arrayBuffer();
        const responseMimeType = String(blob.type || "").toLowerCase();
        const inferredMimeType = inferImageMimeTypeFromBuffer(responseBuffer);
        const resolvedMimeType = responseMimeType.startsWith("image/") ? responseMimeType : inferredMimeType;
        if (!resolvedMimeType) {
          continue;
        }

        const normalizedBlob =
          responseMimeType === resolvedMimeType ? blob : new Blob([responseBuffer], { type: resolvedMimeType });
        const objectUrl = URL.createObjectURL(normalizedBlob);
        const dataUrl =
          normalizedBlob.size <= AVATAR_MAX_LOCALSTORAGE_DATAURL_BYTES ? await blobToDataUrl(normalizedBlob) : "";
        return { objectUrl, dataUrl };
      } catch {
        // Try next URL/header method.
      }
    }
  }

  return null;
}

async function fetchAvatarDataUrlViaBackground(url, accessToken = "") {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    return "";
  }
  if (!url || url.startsWith("data:image/") || url.startsWith("blob:")) {
    return "";
  }

  const token = firstNonEmptyString([accessToken, state.loginData?.accessToken]);
  const response = await sendRuntimeMessageSafe({
    type: "underpar:fetchAvatarDataUrl",
    url,
    accessToken: token,
  });

  if (response?.ok && typeof response.dataUrl === "string" && response.dataUrl.startsWith("data:image/")) {
    return response.dataUrl;
  }

  return "";
}

function buildAvatarDataUrlPrefetchKey(loginData, url) {
  const sourceUrl = normalizeAvatarCandidate(url);
  if (!sourceUrl) {
    return "";
  }
  const tokenFingerprint = loginData?.accessToken ? String(loginData.accessToken).slice(-24) : "no-token";
  const userFingerprint = getAvatarCacheIdentity(loginData);
  return `${userFingerprint}:${tokenFingerprint}:${sourceUrl}`;
}

function scheduleAvatarDataUrlPrefetch(loginData, url, cacheKey = "") {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    return;
  }
  const sourceUrl = normalizeAvatarCandidate(url);
  if (!sourceUrl || sourceUrl.startsWith("data:image/") || sourceUrl.startsWith("blob:")) {
    return;
  }

  const prefetchKey = buildAvatarDataUrlPrefetchKey(loginData, sourceUrl);
  if (!prefetchKey || state.avatarDataUrlPrefetchKeys.has(prefetchKey)) {
    return;
  }
  state.avatarDataUrlPrefetchKeys.add(prefetchKey);

  void (async () => {
    const token = firstNonEmptyString([loginData?.accessToken, state.loginData?.accessToken]);
    const dataUrl = await fetchAvatarDataUrlViaBackground(sourceUrl, token);
    if (!dataUrl || !state.loginData) {
      return;
    }

    writePersistedAvatarCandidate(state.loginData, {
      sourceUrl,
      resolvedUrl: dataUrl,
      dataUrl,
      ttlSeconds: AVATAR_PERSIST_TTL_SECONDS,
    });
    if (cacheKey) {
      writeAvatarCache(cacheKey, {
        sourceUrl,
        resolvedUrl: dataUrl,
        dataUrl,
        ttlSeconds: AVATAR_CACHE_TTL_SECONDS,
      });
    }

    const currentResolved = normalizeAvatarCandidate(state.avatarResolvedUrl);
    if (!currentResolved || currentResolved === sourceUrl) {
      setResolvedAvatarUrl(dataUrl, false);
      render();
    }
  })();
}

async function ensureResolvedAvatarUrl() {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    clearResolvedAvatar();
    return;
  }
  if (!state.sessionReady || !state.loginData) {
    clearResolvedAvatar();
    return;
  }

  const resolveKey = makeAvatarResolveKey(state.loginData);
  if (state.avatarResolveKey === resolveKey && state.avatarResolvedUrl) {
    return;
  }

  if (state.avatarResolving && state.avatarResolveKey === resolveKey) {
    return;
  }

  state.avatarResolving = true;
  state.avatarResolveKey = resolveKey;

  try {
    const persistResolvedAvatar = (payload) => {
      if (!state.loginData) {
        return;
      }
      writePersistedAvatarCandidate(state.loginData, payload || {});
    };

    const tryResolveCandidates = async (candidateList) => {
      for (const candidate of candidateList) {
        const normalized = normalizeAvatarCandidate(candidate);
        if (!normalized) {
          continue;
        }

        if (normalized.startsWith("data:image/")) {
          const inlineUsable = await canUseDirectAvatarLoad(normalized);
          if (inlineUsable) {
            setResolvedAvatarUrl(normalized, false);
            persistResolvedAvatar({
              sourceUrl: normalized,
              resolvedUrl: normalized,
              dataUrl: normalized,
            });
            render();
            return true;
          }
          continue;
        }

        const cacheKey = getAvatarCacheKey(state.loginData, normalized, 0);
        const cached = readAvatarCache(cacheKey);
        if (cached?.resolvedUrl) {
          const cachedResolved = normalizeAvatarCandidate(cached.resolvedUrl);
          const cachedUsable = cachedResolved && (await canUseDirectAvatarLoad(cachedResolved));

          if (cachedUsable) {
            setResolvedAvatarUrl(cachedResolved, cachedResolved.startsWith("blob:"));
            persistResolvedAvatar({
              sourceUrl: cached.sourceUrl || normalized,
              resolvedUrl: cachedResolved,
              dataUrl: cachedResolved.startsWith("data:image/") ? cachedResolved : "",
            });
            scheduleAvatarDataUrlPrefetch(state.loginData, cached.sourceUrl || normalized, cacheKey);
            render();
            return true;
          }

          state.avatarMemoryCache.delete(cacheKey);
          try {
            localStorage.removeItem(cacheKey);
          } catch {
            // Ignore storage cleanup failures.
          }
        }

        if (/^https?:\/\//i.test(normalized)) {
          const backgroundFirstDataUrl = await fetchAvatarDataUrlViaBackground(normalized);
          if (backgroundFirstDataUrl) {
            setResolvedAvatarUrl(backgroundFirstDataUrl, false);
            persistResolvedAvatar({
              sourceUrl: normalized,
              resolvedUrl: backgroundFirstDataUrl,
              dataUrl: backgroundFirstDataUrl,
            });
            writeAvatarCache(cacheKey, {
              sourceUrl: normalized,
              resolvedUrl: backgroundFirstDataUrl,
              dataUrl: backgroundFirstDataUrl,
              ttlSeconds: AVATAR_CACHE_TTL_SECONDS,
            });
            render();
            return true;
          }
        }

        const directOk = await canUseDirectAvatarLoad(normalized);
        if (directOk) {
          setResolvedAvatarUrl(normalized, normalized.startsWith("blob:"));
          persistResolvedAvatar({
            sourceUrl: normalized,
            resolvedUrl: normalized,
          });
          writeAvatarCache(cacheKey, {
            sourceUrl: normalized,
            resolvedUrl: normalized,
            ttlSeconds: AVATAR_CACHE_TTL_SECONDS,
          });
          scheduleAvatarDataUrlPrefetch(state.loginData, normalized, cacheKey);
          render();
          return true;
        }

        const blobResult = await fetchAvatarBlobUrl(normalized);
        if (blobResult?.objectUrl) {
          setResolvedAvatarUrl(blobResult.objectUrl, true);
          persistResolvedAvatar({
            sourceUrl: normalized,
            resolvedUrl: blobResult.objectUrl,
            dataUrl: blobResult.dataUrl || "",
          });
          writeAvatarCache(cacheKey, {
            sourceUrl: normalized,
            resolvedUrl: blobResult.objectUrl,
            dataUrl: blobResult.dataUrl || "",
            ttlSeconds: AVATAR_CACHE_TTL_SECONDS,
          });
          render();
          return true;
        }

      }
      return false;
    };

    const baseCandidates = getAvatarCandidates(state.loginData);
    const prioritizedCandidates = buildAvatarResolveCandidateList(baseCandidates);
    if (await tryResolveCandidates(prioritizedCandidates)) {
      return;
    }

    if (shouldAttemptLiveAvatarRefresh(state.loginData)) {
      const liveCandidates = await fetchLiveAvatarCandidatesFromIms(state.loginData);
      const retryCandidates = buildAvatarResolveCandidateList([...liveCandidates, ...getAvatarCandidates(state.loginData)]);
      if (await tryResolveCandidates(retryCandidates)) {
        return;
      }
    }

    logAvatarFailureOnce("all-candidates-failed", {
      candidates: prioritizedCandidates,
      hasProfile: Boolean(state.loginData?.profile),
      hasAccessToken: Boolean(state.loginData?.accessToken),
    });
    setResolvedAvatarUrl(FALLBACK_AVATAR);
    render();
  } finally {
    state.avatarResolving = false;
    render();
  }
}

function closeAvatarMenu() {
  state.avatarMenuOpen = false;
  if (els.avatarMenu) {
    els.avatarMenu.hidden = true;
  }
}

function getAvatarMenuCmMatchedTenantSummaryFromService(service = null) {
  const matchedTenants = sanitizePassVaultMatchedTenants(service?.matchedTenants || []);
  if (matchedTenants.length === 0) {
    return null;
  }
  return {
    tenantCount: matchedTenants.length,
    state: "ready",
    text: `CM : ${matchedTenants.length} Active Tenant${matchedTenants.length === 1 ? "" : "s"}`,
  };
}

function getAvatarMenuActiveCmSummaryState() {
  if (!shouldHydrateAdobePassWorkflowForSession(state.loginData)) {
    return null;
  }
  const selectedProgrammer = resolveSelectedProgrammer();
  const selectedProgrammerId = String(selectedProgrammer?.programmerId || "").trim();
  const selectedRuntimeService = selectedProgrammerId ? getCurrentPremiumAppsSnapshot(selectedProgrammerId)?.cm || null : null;
  const selectedCachedService =
    selectedProgrammerId && state.cmServiceByProgrammerId instanceof Map
      ? state.cmServiceByProgrammerId.get(selectedProgrammerId) || null
      : null;

  const preferredSummary =
    getAvatarMenuCmMatchedTenantSummaryFromService(selectedRuntimeService) ||
    getAvatarMenuCmMatchedTenantSummaryFromService(selectedCachedService);
  if (preferredSummary) {
    return preferredSummary;
  }

  const uniqueTenantKeys = new Set();
  const appendFromService = (service) => {
    sanitizePassVaultMatchedTenants(service?.matchedTenants || []).forEach((tenant) => {
      const key = firstNonEmptyString([tenant?.consoleId, tenant?.tenantId, tenant?.displayName]);
      if (key) {
        uniqueTenantKeys.add(key);
      }
    });
  };

  if (state.premiumAppsByProgrammerId instanceof Map) {
    state.premiumAppsByProgrammerId.forEach((services) => appendFromService(services?.cm || null));
  }
  if (state.cmServiceByProgrammerId instanceof Map) {
    state.cmServiceByProgrammerId.forEach((service) => appendFromService(service));
  }

  if (uniqueTenantKeys.size > 0) {
    return {
      tenantCount: uniqueTenantKeys.size,
      state: "ready",
      text: `CM : ${uniqueTenantKeys.size} Active Tenant${uniqueTenantKeys.size === 1 ? "" : "s"}`,
    };
  }

  return null;
}

function getAvatarMenuCmSummaryState() {
  if (!shouldHydrateAdobePassWorkflowForSession(state.loginData)) {
    return null;
  }
  const activeSummary = getAvatarMenuActiveCmSummaryState();
  const catalog =
    state.cmTenantsCatalog && Array.isArray(state.cmTenantsCatalog.tenants) ? state.cmTenantsCatalog : null;
  const summary =
    (state.cmConsoleBootstrapSummary && typeof state.cmConsoleBootstrapSummary === "object"
      ? state.cmConsoleBootstrapSummary
      : null) || buildCmConsoleBootstrapSummaryFromCatalog(catalog);
  if (catalog && Array.isArray(catalog.tenants)) {
    const tenantCount = Math.max(0, Number(summary?.tenantCount || catalog.tenantCount || catalog.tenants.length || 0));
    const applicationCount = Math.max(0, Number(summary?.applicationCount || catalog.applicationCount || 0));
    const policyCount = Math.max(0, Number(summary?.policyCount || catalog.policyCount || 0));
    const fragments = [];
    if (Math.max(0, Number(activeSummary?.tenantCount || 0)) > 0) {
      const activeTenantCount = Math.max(0, Number(activeSummary?.tenantCount || 0));
      fragments.push(`${activeTenantCount} Active Tenant${activeTenantCount === 1 ? "" : "s"}`);
    }
    fragments.push(`${tenantCount} Tenant${tenantCount === 1 ? "" : "s"}`);
    fragments.push(applicationCount > 0 || summary?.summaryReady === true ? `${applicationCount} Applications` : "Loading Applications");
    fragments.push(policyCount > 0 || summary?.summaryReady === true ? `${policyCount} Policies` : "Loading Policies");
    return {
      text: `CM : ${fragments.join(" | ")}`,
      state:
        summary?.summaryReady === true || applicationCount > 0 || policyCount > 0
          ? "ready"
          : state.cmConsoleBootstrapPromise
            ? "loading"
            : "partial",
    };
  }
  if (activeSummary) {
    return activeSummary;
  }
  if (state.cmTenantsCatalogPromise || state.cmTenantsCatalogHydrationPromise) {
    return {
      text: "CM : Loading Tenants...",
      state: "loading",
    };
  }
  if (state.cmTenantsCatalogFetchAttempted) {
    return {
      text: "CM : -- Tenants",
      state: "missing",
    };
  }
  return {
    text: "CM : -- Tenants",
    state: "loading",
  };
}

function syncAvatarMenuUpdateAction() {
  const button = els.getLatestBtn;
  if (!button) {
    return;
  }
  const updateAvailable = state.updateAvailable === true;
  const currentVersion = String(chrome.runtime.getManifest()?.version || "").trim();
  const latestVersion = String(state.latestVersion || "").trim();
  button.hidden = false;
  button.disabled = state.updateCheckPending === true;
  button.textContent = "Get Latest";
  const title = updateAvailable
    ? `Open UnderPAR ${latestVersion ? `v${latestVersion}` : "latest"} package and chrome://extensions${currentVersion ? ` (current v${currentVersion})` : ""}`
    : `Download the latest UnderPAR package and open chrome://extensions${currentVersion ? ` (current v${currentVersion})` : ""}`;
  button.title = title;
  button.setAttribute("aria-label", title);
}

function syncSignInUpdateIndicator() {
  const button = els.signInUpdateIndicator;
  if (!button) {
    return;
  }
  const updateAvailable = state.updateAvailable === true;
  const latestVersion = String(state.latestVersion || "").trim();
  const currentVersion = String(chrome.runtime.getManifest()?.version || "").trim();
  const titleParts = [UNDERPAR_UPDATE_AVAILABLE_HOVER_TEXT];
  if (latestVersion) {
    titleParts.push(`Latest: v${latestVersion}.`);
  }
  if (currentVersion) {
    titleParts.push(`Current: v${currentVersion}.`);
  }
  const title = titleParts.join(" ");
  button.hidden = !updateAvailable;
  button.disabled = state.updateCheckPending === true;
  button.title = title;
  button.setAttribute("aria-label", title);
}

function applyAvatarMenuUpdateState(updateInfo = null) {
  const info = updateInfo && typeof updateInfo === "object" ? updateInfo : null;
  if (info) {
    state.updateAvailable = info?.updateAvailable === true;
    state.latestVersion = String(info?.latestVersion || "").trim();
    state.latestCommitSha = String(info?.latestCommitSha || "").trim();
    state.updateCheckError = String(info?.checkError || "").trim();
  }
  syncAvatarMenuUpdateAction();
  syncSignInUpdateIndicator();
}

async function loadAvatarMenuUpdateState(force = false) {
  state.updateCheckPending = true;
  syncAvatarMenuUpdateAction();
  try {
    const response = await sendRuntimeMessageSafe({
      type: UNDERPAR_GET_UPDATE_STATE_REQUEST_TYPE,
      force: force === true,
    });
    applyAvatarMenuUpdateState(response || null);
    return response || null;
  } catch {
    return null;
  } finally {
    state.updateCheckPending = false;
    syncAvatarMenuUpdateAction();
    syncSignInUpdateIndicator();
    if (state.avatarMenuOpen) {
      renderAvatarMenu();
    }
  }
}

async function triggerGetLatestWorkflow() {
  if (state.updateCheckPending) {
    return;
  }
  closeAvatarMenu();
  setStatus("Starting latest UnderPAR download and opening chrome://extensions...", "info");
  try {
    const response = await sendRuntimeMessageSafe({
      type: UNDERPAR_GET_LATEST_REQUEST_TYPE,
    });
    if (response?.ok === false) {
      setStatus(`Get Latest failed: ${response.error || "Unknown error"}`, "error");
      return;
    }
    state.latestCommitSha = String(response?.latestCommitSha || state.latestCommitSha || "").trim();
    state.latestVersion = String(response?.latestVersion || state.latestVersion || "").trim();
    state.updateCheckError = String(response?.checkError || state.updateCheckError || "").trim();
    if (typeof response?.updateAvailable === "boolean") {
      state.updateAvailable = response.updateAvailable;
    }
    syncAvatarMenuUpdateAction();
    syncSignInUpdateIndicator();
    if (response?.noNewerPackage === true) {
      setStatus(
        String(response?.infoMessage || "No newer UnderPAR package is currently published."),
        "info"
      );
      return;
    }
    const downloadLabel = String(response?.downloadFileName || "").trim() || "latest UnderPAR package";
    if (response?.downloadStarted === true && response?.extensionsOpened === true) {
      setStatus(`Started ${downloadLabel} download and opened chrome://extensions.`, "success");
      return;
    }
    if (response?.downloadStarted === true) {
      setStatus(`Started ${downloadLabel} download. Open chrome://extensions to finish the update.`, "info");
      return;
    }
    if (response?.downloadTabOpened === true && response?.extensionsOpened === true) {
      setStatus("Opened latest UnderPAR package tab and chrome://extensions.", "success");
      return;
    }
    if (response?.downloadTabOpened === true) {
      setStatus("Opened latest UnderPAR package tab. Open chrome://extensions to finish the update.", "info");
      return;
    }
    if (response?.extensionsOpened === true) {
      setStatus("Opened chrome://extensions. Start the latest UnderPAR download to finish the update.", "info");
      return;
    }
    setStatus("Starting latest UnderPAR download and opening chrome://extensions...", "info");
  } catch (error) {
    setStatus(`Get Latest failed: ${error instanceof Error ? error.message : String(error)}`, "error");
  }
}

function renderAvatarMenu() {
  if (!els.avatarMenu || !state.sessionReady || !state.loginData || state.restricted) {
    closeAvatarMenu();
    return;
  }

  const name = getLoginDisplayName(state.loginData);
  const principalId = getLoginPrincipalId(state.loginData) || "No principal available";
  const activeOrganization = getLoginActiveOrganization(state.loginData);
  const adobePassWorkflowActive = shouldHydrateAdobePassWorkflowForSession(state.loginData);

  els.avatarMenuImage.style.backgroundImage = "";
  els.avatarMenuImage.classList.remove("avatar-loading");
  els.avatarMenuImage.classList.add("avatar-ready");
  els.avatarMenuImage.setAttribute("role", "img");
  els.avatarMenuImage.setAttribute("aria-hidden", "false");
  els.avatarMenuImage.setAttribute("aria-label", "UnderPAR account badge");
  els.avatarMenuName.textContent = name;
  els.avatarMenuName.href = buildExperienceOrgUrl(activeOrganization);
  els.avatarMenuName.title = buildExperienceOrgTitle(activeOrganization);
  els.avatarMenuEmail.textContent = principalId;
  els.avatarMenuOrg.textContent = `Organization: ${getOrgDisplayName(state.loginData)}`;

  const entries = buildAvatarMenuEntries(state.loginData);
  els.avatarMenuDetails.innerHTML = "";
  if (entries.length === 0) {
    const empty = document.createElement("div");
    empty.className = "avatar-menu-row";
    const key = document.createElement("span");
    key.className = "avatar-menu-key";
    key.textContent = "Profile";
    const value = document.createElement("span");
    value.className = "avatar-menu-value";
    value.textContent = "No profile details available.";
    empty.appendChild(key);
    empty.appendChild(value);
    els.avatarMenuDetails.appendChild(empty);
  } else {
    for (const entry of entries) {
      const row = document.createElement("div");
      row.className = "avatar-menu-row";
      if (entry.copyValue) {
        row.classList.add("avatar-menu-row-copyable");
      }

      const key = document.createElement("span");
      key.className = "avatar-menu-key";
      key.textContent = entry.key;

      const value = document.createElement("span");
      value.className = "avatar-menu-value";
      if (entry.multiline) {
        value.classList.add("avatar-menu-value-multiline");
      }
      value.textContent = entry.value;

      row.appendChild(key);
      row.appendChild(value);
      if (entry.copyValue) {
        const copyButton = document.createElement("button");
        copyButton.type = "button";
        copyButton.className = "avatar-menu-copy-btn";
        copyButton.textContent = "Copy";
        const copyLabel = `Copy ${entry.key}`;
        copyButton.title = copyLabel;
        copyButton.setAttribute("aria-label", copyLabel);
        copyButton.dataset.copyValue = String(entry.copyValue || "").trim();
        copyButton.addEventListener("click", async (event) => {
          event.preventDefault();
          event.stopPropagation();
          const copyValue = String(copyButton.dataset.copyValue || "").trim();
          if (!copyValue) {
            return;
          }
          copyButton.disabled = true;
          const result = await copyTextToClipboard(copyValue);
          copyButton.disabled = false;
          if (!result?.ok) {
            setStatus(result?.error || `Unable to copy ${entry.key}.`, "error");
            return;
          }
          copyButton.classList.add("copied");
          copyButton.textContent = "Copied";
          window.setTimeout(() => {
            copyButton.classList.remove("copied");
            copyButton.textContent = "Copy";
          }, 1400);
        });
        row.appendChild(copyButton);
      }
      els.avatarMenuDetails.appendChild(row);
    }
  }

  if (els.avatarMenuSystem) {
    els.avatarMenuSystem.innerHTML = "";
    if (adobePassWorkflowActive) {
      const cmSummary = getAvatarMenuCmSummaryState();
      const cmValue = String(cmSummary?.text || "")
        .replace(/^CM\s*:\s*/i, "")
        .trim();
      const systemRow = document.createElement("div");
      systemRow.className = "avatar-menu-row";
      const systemKey = document.createElement("span");
      systemKey.className = "avatar-menu-key";
      systemKey.textContent = "CM";
      const systemValue = document.createElement("span");
      systemValue.className = "avatar-menu-value";
      systemValue.textContent = cmValue || "-- Tenants";
      systemRow.appendChild(systemKey);
      systemRow.appendChild(systemValue);
      els.avatarMenuSystem.appendChild(systemRow);
      els.avatarMenuSystem.hidden = false;
    } else {
      els.avatarMenuSystem.hidden = true;
    }
  }

  syncAvatarMenuUpdateAction();
  els.avatarMenu.hidden = !state.avatarMenuOpen;
}

function openAvatarMenu() {
  if (!state.sessionReady || !state.loginData || state.restricted || state.busy) {
    return;
  }
  state.avatarMenuOpen = true;
  renderAvatarMenu();
  void loadAvatarMenuUpdateState(false);
}

function toggleAvatarMenu() {
  if (state.avatarMenuOpen) {
    closeAvatarMenu();
    return;
  }
  openAvatarMenu();
}

async function clearIdentityTokens() {
  const token = state.loginData?.accessToken;
  if (token && chrome.identity?.removeCachedAuthToken) {
    try {
      await chrome.identity.removeCachedAuthToken({ token });
    } catch {
      // Ignore cache removal errors.
    }
  }

  if (chrome.identity?.clearAllCachedAuthTokens) {
    try {
      await chrome.identity.clearAllCachedAuthTokens();
    } catch {
      // Ignore clear-all errors.
    }
  }
}

async function signOutAndResetSession() {
  if (state.busy) {
    return;
  }

  closeAvatarMenu();
  setBusy(true, "Signing out of UnderPAR...");
  setStatus("", "info");
  state.sessionMonitorSuppressed = true;
  clearRestV2ProfileHarvestSessionState();

  try {
    await persistManualSignOutHold(true, "manual-sign-out");
    await revokeUnderparLoginTokensForLogout(state.loginData);
    await clearIdentityTokens();
    await clearDebugFlowStorageFromChromeStorage();
    purgeAvatarCaches();
    purgeDcrCaches();
    await resetToSignedOutState({
      closeWorkspaceReason: "manual-sign-out",
      statusMessage: "Signed out. Click Sign In when ready.",
    });
  } finally {
    setBusy(false);
    render();
  }
}

async function enforceAdobePassAccess(loginData) {
  const normalizedProfile = resolveLoginProfile(loginData);
  const configuredTargetOrganizations = getConfiguredTargetOrganizations();
  const selectedTargetOrganization =
    findConfiguredTargetOrganization(
      configuredTargetOrganizations,
      loginData?.targetOrganization && typeof loginData.targetOrganization === "object"
        ? loginData.targetOrganization
        : null
    ) ||
    (loginData?.targetOrganization && typeof loginData.targetOrganization === "object" ? loginData.targetOrganization : null);
  const profileSeedData = attachTargetOrganizationToLoginData(
    {
      ...loginData,
      profile: normalizedProfile,
    },
    selectedTargetOrganization
  );
  const normalizedImageUrl =
    normalizeAvatarCandidate(resolveLoginImageUrl(profileSeedData)) ||
    normalizeAvatarCandidate(readPersistedAvatarCandidate(profileSeedData)) ||
    "";
  let organizations = resolveCachedOrganizationsFromLoginData(loginData);
  const preferredOrganizationSeed = selectedTargetOrganization || null;
  let detectedOrganizations = collectCanonicalRestrictedDetectedOrganizations(
    {
      ...profileSeedData,
      profile: normalizedProfile,
      organizations,
    },
    organizations
  );
  updateRestrictedOrgOptions(organizations, preferredOrganizationSeed, {
    ...profileSeedData,
    profile: normalizedProfile,
    organizations,
    detectedOrganizations,
  });

  if (state.restrictedOrgOptions.length === 0 && tokenHasReadOrganizationsScope(loginData?.accessToken)) {
    try {
      const orgPayload = await fetchOrganizations(loginData.accessToken);
      organizations = flattenOrganizations(orgPayload);
      detectedOrganizations = collectCanonicalRestrictedDetectedOrganizations(
        {
          ...profileSeedData,
          profile: normalizedProfile,
          organizations,
        },
        organizations
      );
      updateRestrictedOrgOptions(organizations, preferredOrganizationSeed, {
        ...profileSeedData,
        profile: normalizedProfile,
        organizations,
        detectedOrganizations,
      });
    } catch (error) {
      log("Unable to fetch organizations; keeping local org resolution only", error);
      updateRestrictedOrgOptions(organizations, preferredOrganizationSeed, {
        ...profileSeedData,
        profile: normalizedProfile,
        organizations,
        detectedOrganizations,
      });
      if (isReadOrganizationsScopeError(error)) {
        state.restrictedRecoveryLabel =
          "Adobe did not grant org-picker scope for this session. Use the ZIP.KEY org targets or Sign In Again to reopen Adobe's profile chooser.";
      }
    }
  }
  let pickerOrganizations = [...organizations];

  let accessContext = resolveAdobePassAccessContext(
    {
      ...profileSeedData,
      profile: normalizedProfile,
      imageUrl: normalizedImageUrl,
      organizations,
      detectedOrganizations,
    },
    selectedTargetOrganization || preferredOrganizationSeed
  );

  if (!accessContext.eligible && loginData?.accessToken) {
    try {
      const activeOrganizationSeed = buildRestrictedOrganizationContext(
        organizations,
        {
          ...profileSeedData,
          profile: normalizedProfile,
          imageUrl: normalizedImageUrl,
          organizations,
          detectedOrganizations,
        },
        null
      ).activeOrganization;
      const unifiedShellOrganizations = await fetchUnderparUnifiedShellOrganizations(loginData.accessToken, {
        selectedOrg: resolveRestrictedPickerSelectedOrg(preferredOrganizationSeed, {
          ...profileSeedData,
          profile: normalizedProfile,
          organizations,
          detectedOrganizations,
        }),
        activeOrganization: activeOrganizationSeed,
      });
      if (Array.isArray(unifiedShellOrganizations) && unifiedShellOrganizations.length > 0) {
        pickerOrganizations = [...organizations, ...unifiedShellOrganizations];
        detectedOrganizations = collectCanonicalRestrictedDetectedOrganizations(
          {
            ...profileSeedData,
            profile: normalizedProfile,
            organizations: pickerOrganizations,
          },
          pickerOrganizations
        );
        organizations = pickerOrganizations;
        updateRestrictedOrgOptions(organizations, preferredOrganizationSeed, {
          ...profileSeedData,
          profile: normalizedProfile,
          organizations,
          detectedOrganizations,
        });
        accessContext = resolveAdobePassAccessContext(
          {
            ...profileSeedData,
            profile: normalizedProfile,
            imageUrl: normalizedImageUrl,
            organizations,
            detectedOrganizations,
          },
          selectedTargetOrganization || preferredOrganizationSeed
        );
      }
    } catch (error) {
      log("Unable to load Unified Shell org context before AdobePass access enforcement", error);
    }
  }

  const normalizedOrganizations = organizations.length > 0 ? organizations : loginData?.organizations || null;
  const verificationSeed = {
    ...profileSeedData,
    profile: normalizedProfile,
    imageUrl: normalizedImageUrl,
    organizations: normalizedOrganizations,
    detectedOrganizations,
  };
  const orgVerification = verifyTargetOrganizationSelection(verificationSeed, selectedTargetOrganization);
  const resolvedOrganizationOption =
    accessContext?.activeIsAdobePass && accessContext?.activeOrganization
      ? accessContext.activeOrganization
      : findMatchingRestrictedOrganizationOption(state.restrictedOrgOptions, {
          orgId: firstNonEmptyString([orgVerification?.verifiedOrgId, orgVerification?.resolvedOrgId]),
        }) || null;
  accessContext = resolveAdobePassAccessContext(
    {
      ...verificationSeed,
      orgVerification,
      detectedOrganizations,
    },
    selectedTargetOrganization || preferredOrganizationSeed
  );

  const resolved = {
    ...verificationSeed,
    orgVerification,
  };

  return {
    allowed: accessContext.eligible === true,
    loginData: resolved,
    recoveryLabel: firstNonEmptyString([accessContext.reason]),
  };
}

async function ensureRestrictedOrgOptionsFromToken(accessToken, preferredOrg = null, sessionData = null) {
  const token = String(accessToken || "").trim();
  if (!token) {
    return false;
  }

  const seedSession =
    sessionData && typeof sessionData === "object"
      ? {
          ...sessionData,
          accessToken: firstNonEmptyString([sessionData?.accessToken, token]),
        }
      : {
          accessToken: token,
        };

  const configuredPreferredOrg =
    findConfiguredTargetOrganization(getConfiguredTargetOrganizations(), preferredOrg || seedSession?.targetOrganization) ||
    preferredOrg ||
    seedSession?.targetOrganization ||
    null;
  const selectedOrg = resolveRestrictedPickerSelectedOrg(configuredPreferredOrg, seedSession);
  const cachedOrganizations = resolveCachedOrganizationsFromLoginData(seedSession);
  let mergedOrganizations = [...cachedOrganizations];
  let organizationsScopeDenied = false;

  if (tokenHasReadOrganizationsScope(token)) {
    try {
      const orgPayload = await fetchOrganizations(token);
      mergedOrganizations = [...mergedOrganizations, ...flattenOrganizations(orgPayload)];
    } catch (error) {
      log("Unable to load organizations endpoint org options for restricted picker", error);
      organizationsScopeDenied = isReadOrganizationsScopeError(error);
    }
  }

  try {
    const unifiedShellOrganizations = await fetchUnderparUnifiedShellOrganizations(token, {
      selectedOrg,
      activeOrganization: configuredPreferredOrg,
    });
    if (Array.isArray(unifiedShellOrganizations) && unifiedShellOrganizations.length > 0) {
      mergedOrganizations = [...mergedOrganizations, ...unifiedShellOrganizations];
    }
  } catch (error) {
    log("Unable to load Unified Shell org options for restricted picker", error);
  }

  const detectedOrganizations = collectCanonicalRestrictedDetectedOrganizations(
    {
      ...seedSession,
      organizations: mergedOrganizations,
    },
    mergedOrganizations
  );
  updateRestrictedOrgOptions(mergedOrganizations, configuredPreferredOrg, {
    ...seedSession,
    organizations: mergedOrganizations,
    detectedOrganizations,
  });

  if (state.restrictedOrgOptions.length === 0 && (organizationsScopeDenied || !tokenHasReadOrganizationsScope(token))) {
    state.restrictedRecoveryLabel =
      "Adobe did not return additional org memberships for this session. Use Sign In Again to reopen Adobe's profile chooser.";
  }
  return state.restrictedOrgOptions.length > 0;
}

async function loadManualSignOutHold() {
  try {
    const payload = await chrome.storage.local.get(MANUAL_SIGN_OUT_HOLD_STORAGE_KEY);
    const storedValue = payload?.[MANUAL_SIGN_OUT_HOLD_STORAGE_KEY];
    state.manualSignOutHold = Boolean(
      storedValue === true || (storedValue && typeof storedValue === "object")
    );
  } catch {
    state.manualSignOutHold = false;
  }
  return state.manualSignOutHold === true;
}

async function persistManualSignOutHold(enabled = false, reason = "") {
  const nextEnabled = enabled === true;
  state.manualSignOutHold = nextEnabled;
  try {
    if (nextEnabled) {
      await chrome.storage.local.set({
        [MANUAL_SIGN_OUT_HOLD_STORAGE_KEY]: {
          at: Date.now(),
          reason: String(reason || "manual-sign-out").trim() || "manual-sign-out",
        },
      });
    } else {
      await chrome.storage.local.remove(MANUAL_SIGN_OUT_HOLD_STORAGE_KEY);
    }
  } catch {
    // Ignore sign-out hold persistence failures.
  }
  return state.manualSignOutHold === true;
}

function resolveStoredSessionExpiresAt(loginData, tokenSession) {
  const storedExpiresAt = coercePositiveNumber(loginData?.expiresAt);
  const tokenExpiresAt = coercePositiveNumber(tokenSession?.expiresAt);
  if (!tokenExpiresAt) {
    return storedExpiresAt;
  }
  if (!storedExpiresAt) {
    return tokenExpiresAt;
  }

  if (Math.abs(storedExpiresAt - tokenExpiresAt) > 2 * 60 * 1000) {
    return tokenExpiresAt;
  }

  return Math.min(storedExpiresAt, tokenExpiresAt);
}

async function loadStoredLoginData() {
  if (state.manualSignOutHold === true) {
    return null;
  }
  const stored = await chrome.storage.local.get(STORAGE_KEY);
  const loginData = stored?.[STORAGE_KEY] || null;

  if (!loginData) {
    return null;
  }

  const accessToken = firstNonEmptyString([loginData?.accessToken]);
  if (!accessToken) {
    await chrome.storage.local.remove(STORAGE_KEY);
    return null;
  }
  if (tokenSupportsCmTenantCatalog(accessToken)) {
    await chrome.storage.local.remove(STORAGE_KEY);
    return null;
  }

  const normalizedProfile = resolveLoginProfile(loginData);
  const tokenSnapshot = deriveImsSessionSnapshotFromToken(accessToken);
  const runtimeImsConfig = getActiveUnderparImsRuntimeConfig(
    state.passVault || (await ensurePassVaultLoaded({ forceReload: false }))
  );
  const configuredClientId = String(runtimeImsConfig?.clientId || "").trim();
  const storedClientId = firstNonEmptyString([
    tokenSnapshot?.clientId,
    loginData?.imsSession?.clientId,
    loginData?.imsSession?.client_id,
  ]);
  if (configuredClientId && storedClientId && storedClientId !== configuredClientId) {
    await chrome.storage.local.remove(STORAGE_KEY);
    return null;
  }
  const expiresAt = resolveStoredSessionExpiresAt(loginData, tokenSnapshot);
  if (!expiresAt || expiresAt <= Date.now()) {
    await chrome.storage.local.remove(STORAGE_KEY);
    return null;
  }

  const imsSession = mergeImsSessionSnapshots(
    tokenSnapshot,
    loginData?.imsSession && typeof loginData.imsSession === "object" ? loginData.imsSession : null
  );
  if (imsSession && (!coercePositiveNumber(imsSession.expiresAt) || Math.abs(coercePositiveNumber(imsSession.expiresAt) - expiresAt) > 2 * 60 * 1000)) {
    imsSession.expiresAt = expiresAt;
  }
  return buildNormalizedLoginData(
    {
      ...loginData,
      accessToken,
      expiresAt,
      tokenType: compactStorageString(firstNonEmptyString([loginData?.tokenType]), 60) || "bearer",
      scope: compactStorageString(firstNonEmptyString([loginData?.scope]), 2048),
      idToken: compactStorageString(firstNonEmptyString([loginData?.idToken]), 4096),
      refreshToken: compactStorageString(firstNonEmptyString([loginData?.refreshToken]), 4096),
      imsSession,
      profile: normalizedProfile,
      consoleHydration: normalizeStoredConsoleHydrationSnapshot(loginData?.consoleHydration),
      sessionKeys: loginData?.sessionKeys && typeof loginData.sessionKeys === "object" ? loginData.sessionKeys : null,
    },
    {
      resetBootstrapTokens: true,
    }
  );
}

function pruneEmptyObject(value) {
  if (!value || typeof value !== "object") {
    return {};
  }

  const output = {};
  for (const [key, entry] of Object.entries(value)) {
    if (entry === undefined || entry === null || entry === "") {
      continue;
    }

    if (Array.isArray(entry)) {
      const filtered = entry.filter((item) => item !== undefined && item !== null && item !== "");
      if (filtered.length > 0) {
        output[key] = filtered;
      }
      continue;
    }

    if (typeof entry === "object") {
      const nested = pruneEmptyObject(entry);
      if (Object.keys(nested).length > 0) {
        output[key] = nested;
      }
      continue;
    }

    output[key] = entry;
  }

  return output;
}

function compactStorageString(value, maxLength = 320) {
  if (value === undefined || value === null) {
    return "";
  }
  const text = String(value).trim();
  if (!text) {
    return "";
  }
  if (!Number.isFinite(maxLength) || maxLength <= 0 || text.length <= maxLength) {
    return text;
  }
  return text.slice(0, maxLength);
}

function compactStorageAvatarUrl(value) {
  const normalized = normalizeAvatarCandidate(value);
  if (!normalized || normalized.startsWith("data:image/") || normalized.startsWith("blob:")) {
    return "";
  }
  return normalized;
}

function compactImsSessionForStorage(session) {
  if (!session || typeof session !== "object") {
    return null;
  }

  const compact = pruneEmptyObject({
    tokenId: compactStorageString(firstNonEmptyString([session?.tokenId, session?.id]), 220),
    sessionId: compactStorageString(firstNonEmptyString([session?.sessionId, session?.sid]), 220),
    sessionUrl: compactStorageString(firstNonEmptyString([session?.sessionUrl, session?.session]), 2048),
    userId: compactStorageString(firstNonEmptyString([session?.userId, session?.user_id]), 220),
    authId: compactStorageString(firstNonEmptyString([session?.authId, session?.aa_id]), 220),
    clientId: compactStorageString(firstNonEmptyString([session?.clientId, session?.client_id]), 140),
    tokenType: compactStorageString(firstNonEmptyString([session?.tokenType, session?.type]), 60),
    scope: compactStorageString(firstNonEmptyString([session?.scope]), 2048),
    as: compactStorageString(firstNonEmptyString([session?.as]), 80),
    fg: compactStorageString(firstNonEmptyString([session?.fg]), 120),
    moi: compactStorageString(firstNonEmptyString([session?.moi]), 120),
    pba: compactStorageString(firstNonEmptyString([session?.pba]), 240),
    keyAlias: compactStorageString(firstNonEmptyString([session?.keyAlias, session?.key_alias]), 180),
    stateNonce: compactStorageString(firstNonEmptyString([session?.stateNonce, session?.nonce]), 120),
    stateJslibVersion: compactStorageString(
      firstNonEmptyString([session?.stateJslibVersion, session?.jslibver, session?.jslibVersion]),
      160
    ),
    createdAt: Number(session?.createdAt || session?.created_at || 0),
    issuedAt: Number(session?.issuedAt || session?.issued_at || 0),
    expiresAt: Number(session?.expiresAt || session?.expires_at || 0),
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function compactAdobePassOrgForStorage(org) {
  if (!org || typeof org !== "object") {
    return null;
  }

  const compact = pruneEmptyObject({
    orgId: compactStorageString(org.orgId, 180),
    userId: compactStorageString(org.userId, 180),
    name: compactStorageString(org.name, 240),
    avatarUrl: compactStorageAvatarUrl(org.avatarUrl),
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function compactTargetOrganizationForStorage(targetOrganization) {
  if (!targetOrganization || typeof targetOrganization !== "object") {
    return null;
  }

  const compact = pruneEmptyObject({
    key: compactStorageString(targetOrganization.key, 180),
    id: compactStorageString(firstNonEmptyString([targetOrganization.id, targetOrganization.orgId]), 180),
    orgId: compactStorageString(firstNonEmptyString([targetOrganization.orgId, targetOrganization.id]), 180),
    tenantId: compactStorageString(firstNonEmptyString([targetOrganization.tenantId]), 180),
    imsOrgId: compactStorageString(firstNonEmptyString([targetOrganization.imsOrgId]), 220),
    userId: compactStorageString(targetOrganization.userId, 180),
    clusterUserId: compactStorageString(targetOrganization.clusterUserId, 180),
    clusterUserType: compactStorageString(targetOrganization.clusterUserType, 80),
    label: compactStorageString(firstNonEmptyString([targetOrganization.label, targetOrganization.name]), 240),
    name: compactStorageString(firstNonEmptyString([targetOrganization.name, targetOrganization.label]), 240),
    hinted: targetOrganization.hinted === true,
    isAdobePass: targetOrganization.isAdobePass === true,
    source: compactStorageString(targetOrganization.source, 80),
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function compactStoredConsoleRequestorOptionForStorage(option) {
  if (!option || typeof option !== "object") {
    return null;
  }

  const compact = pruneEmptyObject({
    key: compactStorageString(firstNonEmptyString([option.key, option.id]), 180),
    id: compactStorageString(firstNonEmptyString([option.id, option.key]), 180),
    name: compactStorageString(firstNonEmptyString([option.name, option.label, option.id]), 240),
    label: compactStorageString(firstNonEmptyString([option.label, option.name, option.id]), 320),
    programmerId: compactStorageString(firstNonEmptyString([option.programmerId]), 180),
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function compactStoredConsoleChannelForStorage(channel) {
  if (!channel || typeof channel !== "object") {
    return null;
  }

  const compact = pruneEmptyObject({
    key: compactStorageString(firstNonEmptyString([channel.key, channel.id]), 180),
    id: compactStorageString(firstNonEmptyString([channel.id, channel.key]), 180),
    name: compactStorageString(firstNonEmptyString([channel.name, channel.label, channel.id]), 240),
    label: compactStorageString(firstNonEmptyString([channel.label, channel.name, channel.id]), 320),
    programmerId: compactStorageString(firstNonEmptyString([channel.programmerId]), 180),
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function compactStoredConsoleProgrammerForStorage(programmer) {
  if (!programmer || typeof programmer !== "object") {
    return null;
  }

  const requestorOptions = (Array.isArray(programmer.requestorOptions) ? programmer.requestorOptions : [])
    .map((option) => compactStoredConsoleRequestorOptionForStorage(option))
    .filter(Boolean)
    .slice(0, 250);
  const requestorIds = uniquePreserveOrder(
    (Array.isArray(programmer.requestorIds) ? programmer.requestorIds : [])
      .map((value) => compactStorageString(value, 180))
      .filter(Boolean)
      .slice(0, 250)
  );
  const compact = pruneEmptyObject({
    key: compactStorageString(firstNonEmptyString([programmer.key, programmer.programmerId]), 180),
    programmerId: compactStorageString(firstNonEmptyString([programmer.programmerId]), 180),
    programmerName: compactStorageString(
      firstNonEmptyString([programmer.programmerName, programmer.mediaCompanyName, programmer.programmerId]),
      240
    ),
    mediaCompanyName: compactStorageString(
      firstNonEmptyString([programmer.mediaCompanyName, programmer.programmerName, programmer.programmerId]),
      240
    ),
    label: compactStorageString(
      firstNonEmptyString([programmer.label, programmer.programmerName, programmer.mediaCompanyName, programmer.programmerId]),
      320
    ),
    requestorIds,
    requestorOptions,
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function compactStoredConsoleHydrationSnapshot(snapshot = null) {
  const raw = snapshot && typeof snapshot === "object" ? snapshot : null;
  if (!raw) {
    return null;
  }

  const configurationVersion = Number(raw.configurationVersion || raw.configVersion || 0);
  const hydratedAt = Number(raw.hydratedAt || raw.fetchedAt || raw.updatedAt || 0);
  const grantedAuthorities = uniquePreserveOrder(
    (Array.isArray(raw.grantedAuthorities) ? raw.grantedAuthorities : [])
      .map((value) => compactStorageString(value, 180))
      .filter(Boolean)
      .slice(0, 64)
  );
  const channels = (Array.isArray(raw.channels) ? raw.channels : [])
    .map((channel) => compactStoredConsoleChannelForStorage(channel))
    .filter(Boolean)
    .slice(0, 500);
  const programmers = (Array.isArray(raw.programmers) ? raw.programmers : [])
    .map((programmer) => compactStoredConsoleProgrammerForStorage(programmer))
    .filter(Boolean)
    .slice(0, 500);
  const compact = pruneEmptyObject({
    configurationVersion,
    hydratedAt,
    grantedAuthorities,
    channels,
    programmers,
    programmersApiEndpoint: compactStorageString(firstNonEmptyString([raw.programmersApiEndpoint]), 2048),
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function normalizeStoredConsoleHydrationSnapshot(snapshot = null) {
  const compact = compactStoredConsoleHydrationSnapshot(snapshot);
  if (!compact) {
    return null;
  }

  return {
    configurationVersion: Number(compact.configurationVersion || 0),
    hydratedAt: Number(compact.hydratedAt || 0),
    grantedAuthorities: Array.isArray(compact.grantedAuthorities) ? compact.grantedAuthorities.slice() : [],
    channels: Array.isArray(compact.channels) ? compact.channels.slice() : [],
    programmers: Array.isArray(compact.programmers) ? compact.programmers.slice() : [],
    programmersApiEndpoint: firstNonEmptyString([compact.programmersApiEndpoint]),
  };
}

function buildStoredConsoleHydrationSnapshotFromState() {
  return compactStoredConsoleHydrationSnapshot({
    configurationVersion: Number(state.consoleBootstrapState?.configurationVersion || 0),
    hydratedAt: Date.now(),
    grantedAuthorities: Array.isArray(state.consoleBootstrapState?.grantedAuthorities)
      ? state.consoleBootstrapState.grantedAuthorities
      : [],
    channels: Array.isArray(state.consoleBootstrapState?.channels) ? state.consoleBootstrapState.channels : [],
    programmers: Array.isArray(state.programmers) ? state.programmers : [],
    programmersApiEndpoint: firstNonEmptyString([state.programmersApiEndpoint]),
  });
}

function compactProfileForStorage(profile) {
  if (!profile || typeof profile !== "object") {
    return null;
  }

  const identity = compactStorageString(
    firstNonEmptyString([profile?.userId, profile?.user_id, profile?.sub, profile?.id]),
    180
  );

  const avatarUrl = compactStorageAvatarUrl(
    firstNonEmptyString([
      profile?.user_image_url,
      profile?.userImageUrl,
      profile?.avatar,
      profile?.avatarUrl,
      profile?.avatar_url,
      profile?.additional_info?.user_image_url,
      profile?.additional_info?.userImageUrl,
      profile?.additional_info?.avatar,
      profile?.additional_info?.avatarUrl,
      profile?.additional_info?.avatar_url,
      toImsAvatarDownloadUrl(identity, 128),
    ])
  );

  const roles = (
    Array.isArray(profile?.additional_info?.roles)
      ? profile.additional_info.roles
      : Array.isArray(profile?.roles)
        ? profile.roles
        : []
  )
    .map((role) => compactStorageString(role, 120))
    .filter(Boolean)
    .slice(0, 24);

  const additionalInfo = pruneEmptyObject({
    email: compactStorageString(firstNonEmptyString([profile?.additional_info?.email]), 320),
    account_type: compactStorageString(firstNonEmptyString([profile?.additional_info?.account_type]), 80),
    user_image_url: compactStorageAvatarUrl(
      firstNonEmptyString([
        profile?.additional_info?.user_image_url,
        profile?.additional_info?.userImageUrl,
        profile?.additional_info?.avatar,
        profile?.additional_info?.avatarUrl,
        profile?.additional_info?.avatar_url,
      ])
    ),
    avatarUrl: compactStorageAvatarUrl(
      firstNonEmptyString([
        profile?.additional_info?.avatar,
        profile?.additional_info?.avatarUrl,
        profile?.additional_info?.avatar_url,
      ])
    ),
    roles,
  });

  const compact = pruneEmptyObject({
    userId: identity,
    user_id: identity,
    sub: compactStorageString(firstNonEmptyString([profile?.sub]), 180),
    displayName: compactStorageString(getProfileDisplayName(profile), 180),
    firstName: compactStorageString(firstNonEmptyString([profile?.firstName, profile?.first_name]), 120),
    lastName: compactStorageString(firstNonEmptyString([profile?.lastName, profile?.last_name]), 120),
    email: compactStorageString(getProfileEmail(profile), 320),
    account_type: compactStorageString(
      firstNonEmptyString([profile?.account_type, profile?.additional_info?.account_type]),
      80
    ),
    user_image_url: avatarUrl,
    avatarUrl,
    additional_info: additionalInfo,
  });

  return Object.keys(compact).length > 0 ? compact : null;
}

function buildStoredLoginData(loginData, minimal = false) {
  const profile = minimal ? null : compactProfileForStorage(resolveLoginProfile(loginData));
  const consoleHydration = minimal ? null : compactStoredConsoleHydrationSnapshot(loginData?.consoleHydration);
  const imsSession = compactImsSessionForStorage(loginData?.imsSession);
  const sessionKeys =
    loginData?.sessionKeys && typeof loginData.sessionKeys === "object"
      ? pruneEmptyObject(loginData.sessionKeys)
      : buildSessionKeySnapshot({
          ...loginData,
          profile: resolveLoginProfile(loginData),
          imsSession,
        });
  const fallbackIdentity = firstNonEmptyString([
    imsSession?.userId,
    profile?.userId,
    profile?.user_id,
    profile?.sub,
  ]);
  const fallbackAvatar = fallbackIdentity ? toImsAvatarDownloadUrl(fallbackIdentity, 128) : "";

  const compact = pruneEmptyObject({
    accessToken: compactStorageString(firstNonEmptyString([loginData?.accessToken]), 4096),
    expiresAt: Number(loginData?.expiresAt || 0),
    tokenType: compactStorageString(firstNonEmptyString([loginData?.tokenType, imsSession?.tokenType]), 60),
    scope: compactStorageString(firstNonEmptyString([loginData?.scope, imsSession?.scope]), 2048),
    idToken: compactStorageString(firstNonEmptyString([loginData?.idToken]), 4096),
    refreshToken: compactStorageString(firstNonEmptyString([loginData?.refreshToken]), 4096),
    imageUrl: compactStorageAvatarUrl(
      firstNonEmptyString([
        loginData?.imageUrl,
        loginData?.user_image_url,
        loginData?.avatarUrl,
        loginData?.avatar_url,
        profile?.user_image_url,
        fallbackAvatar,
      ])
    ),
    profile,
    imsSession,
    sessionKeys,
    targetOrganization: compactTargetOrganizationForStorage(loginData?.targetOrganization),
    consoleHydration,
  });

  return compact;
}

function isStorageQuotaError(error) {
  const message = error instanceof Error ? error.message : String(error || "");
  if (!message) {
    return false;
  }
  const normalized = message.toLowerCase();
  return (
    normalized.includes("quota") ||
    normalized.includes("kquotabytes") ||
    normalized.includes("max_write_operations") ||
    normalized.includes("resource::kquotabytes")
  );
}

async function clearDebugFlowStorageFromChromeStorage() {
  try {
    const payload = await chrome.storage.local.get(null);
    const keysToRemove = Object.keys(payload || {}).filter(
      (key) =>
        key === DEBUG_FLOW_STORAGE_INDEX_KEY ||
        key === LEGACY_DEBUG_FLOW_STORAGE_INDEX_KEY ||
        key.startsWith(DEBUG_FLOW_STORAGE_PREFIX) ||
        key.startsWith(LEGACY_DEBUG_FLOW_STORAGE_PREFIX)
    );
    if (keysToRemove.length === 0) {
      return 0;
    }
    await chrome.storage.local.remove(keysToRemove);
    return keysToRemove.length;
  } catch {
    return 0;
  }
}

async function saveLoginData(loginData) {
  const normalized = buildStoredLoginData(loginData, false);
  if (!normalized.accessToken || !normalized.expiresAt || normalized.expiresAt <= 0) {
    return false;
  }

  try {
    await chrome.storage.local.set({ [STORAGE_KEY]: normalized });
    emitCmConsoleTokenForTesting(
      firstNonEmptyString([normalized.cmConsoleAccessToken, normalized.accessToken]),
      "save-login-data"
    );
    return true;
  } catch (error) {
    if (!isStorageQuotaError(error)) {
      log("Unable to persist login data; keeping in-memory session only.", error?.message || String(error));
      return false;
    }

    const removedDebugKeys = await clearDebugFlowStorageFromChromeStorage();
    if (removedDebugKeys > 0) {
      try {
        await chrome.storage.local.set({ [STORAGE_KEY]: normalized });
        emitCmConsoleTokenForTesting(
          firstNonEmptyString([normalized.cmConsoleAccessToken, normalized.accessToken]),
          "save-login-data-retry"
        );
        log("Recovered storage quota by clearing persisted UP debug flow keys.", { removedDebugKeys });
        return true;
      } catch {
        // Fallback to minimal payload below.
      }
    }

    const minimal = buildStoredLoginData(loginData, true);
    if (!minimal.accessToken || !minimal.expiresAt || minimal.expiresAt <= 0) {
      return false;
    }

    try {
      await chrome.storage.local.set({ [STORAGE_KEY]: minimal });
      emitCmConsoleTokenForTesting(
        firstNonEmptyString([minimal.cmConsoleAccessToken, minimal.accessToken]),
        "save-login-data-minimal"
      );
      log("Stored minimal session payload after quota pressure.", { removedDebugKeys });
      return true;
    } catch (retryError) {
      log("Storage quota prevented persisted session write; continuing with in-memory session.", {
        removedDebugKeys,
        error: retryError instanceof Error ? retryError.message : String(retryError),
      });
      return false;
    }
  }
}

async function clearLoginData() {
  await chrome.storage.local.remove(STORAGE_KEY);
}

function clearRefreshTimer() {
  if (state.refreshTimeoutId) {
    clearTimeout(state.refreshTimeoutId);
    state.refreshTimeoutId = null;
  }
}

function stopExperienceCloudSessionMonitor() {
  if (state.sessionMonitorStartTimeoutId) {
    clearTimeout(state.sessionMonitorStartTimeoutId);
    state.sessionMonitorStartTimeoutId = 0;
  }
  if (state.sessionMonitorIntervalId) {
    clearInterval(state.sessionMonitorIntervalId);
    state.sessionMonitorIntervalId = 0;
  }
  state.sessionMonitorBusy = false;
}

function startExperienceCloudSessionMonitor() {
  if (!shouldRunExperienceCloudSessionMonitor()) {
    stopExperienceCloudSessionMonitor();
    return;
  }
  stopExperienceCloudSessionMonitor();

  const tick = () => {
    void runExperienceCloudSessionMonitorTick("interval");
  };

  state.sessionMonitorStartTimeoutId = window.setTimeout(() => {
    state.sessionMonitorStartTimeoutId = 0;
    tick();
    state.sessionMonitorIntervalId = window.setInterval(tick, IMS_SESSION_MONITOR_INTERVAL_MS);
  }, IMS_SESSION_MONITOR_START_DELAY_MS);
}

function getSessionExpiryState() {
  const expiresAt = Number(state.loginData?.expiresAt || 0);
  if (!Number.isFinite(expiresAt) || expiresAt <= 0) {
    return "unknown";
  }
  const now = Date.now();
  if (expiresAt <= now) {
    return "expired";
  }
  if (expiresAt <= now + TOKEN_REFRESH_LEEWAY_MS) {
    return "expiring";
  }
  return "fresh";
}

async function resetToSignedOutState(options = {}) {
  const statusMessage = String(options.statusMessage || "").trim();
  const statusType = options.statusType === "error" ? "error" : options.statusType === "success" ? "success" : "info";
  const preservePassVault = options.preservePassVault !== false;
  clearRefreshTimer();
  stopExperienceCloudSessionMonitor();
  clearPremiumServiceAutoRefreshTimers();
  await clearLoginData();
  if (options.closeWorkspaces !== false) {
    await closeOpenUnderparWorkspaceTabs({
      reason: String(options.closeWorkspaceReason || "signed-out-reset"),
    });
  }
  resetWorkflowForLoggedOut({
    preservePassVault,
  });
  state.loginData = null;
  state.restricted = false;
  state.sessionReady = false;
  state.programmersApiEndpoint = null;
  state.consoleCsrfToken = "";
  state.consoleBootstrapState = null;
  state.mvpdCacheByRequestor.clear();
  state.sessionMonitorConsecutiveInactiveDetections = 0;
  state.sessionMonitorLastProbeSource = "unknown";
  state.sessionMonitorInactivityGuardUntil = 0;
  clearResolvedAvatar();
  setStatus(statusMessage, statusType);
  render();
}

async function runExperienceCloudSessionMonitorTick(trigger = "interval") {
  if (!shouldRunExperienceCloudSessionMonitor()) {
    return;
  }
  if (state.sessionMonitorBusy || state.busy || state.isBootstrapping || state.restrictedOrgSwitchBusy) {
    return;
  }
  if (state.sessionMonitorSuppressed && !state.sessionReady && !state.restricted) {
    return;
  }

  state.sessionMonitorBusy = true;
  try {
    const hasAccessToken = Boolean(normalizeBearerTokenValue(state.loginData?.accessToken || ""));
    if (!hasAccessToken) {
      await resetToSignedOutState({
        statusMessage: "UnderPAR no longer has a valid Adobe session. Click Sign In.",
        statusType: "error",
      });
      return;
    }

    const expiryState = getSessionExpiryState();
    if (expiryState === "fresh") {
      state.sessionMonitorConsecutiveInactiveDetections = 0;
      return;
    }

    if (expiryState === "unknown") {
      return;
    }

    if ((expiryState === "expiring" || expiryState === "expired") && state.sessionReady && state.loginData?.accessToken) {
      const refreshed = await refreshSessionNoTouch();
      if (refreshed) {
        state.sessionMonitorConsecutiveInactiveDetections = 0;
        return;
      }
      await resetToSignedOutState({
        statusMessage: "UnderPAR session expired. Click Sign In to continue.",
        statusType: "error",
      });
    }
  } finally {
    state.sessionMonitorBusy = false;
  }
}

function scheduleNoTouchRefresh() {
  clearRefreshTimer();
}

function resetCmTenantsPrecheckState() {
  state.cmTenantsPrecheckPromise = null;
  state.cmTenantsPrecheckPending = false;
  state.cmTenantsPrecheckComplete = false;
  state.cmTenantsPrecheckLastError = "";
  state.cmTenantsCatalog = null;
  state.cmTenantsCatalogPromise = null;
  state.cmTenantsCatalogHydrated = false;
  state.cmTenantsCatalogHydrationPromise = null;
  state.cmTenantsCatalogRuntimeFresh = false;
  state.cmTenantsCatalogFetchAttempted = false;
  syncMediaCompanySelectAvailability();
}

function shouldAllowTemporaryCmBootstrapTabForActivation(source = "", explicitAllow = false) {
  if (explicitAllow === true) {
    return true;
  }
  const normalizedSource = String(source || "").trim().toLowerCase();
  return normalizedSource === "stored";
}

async function applyActiveLoginSession(loginData, options = {}) {
  const persist = options.persist === true;
  const scheduleRefresh = options.scheduleRefresh !== false && Boolean(loginData?.accessToken);
  const normalizedCmConsoleAccessToken = normalizeBearerTokenValue(firstNonEmptyString([loginData?.cmConsoleAccessToken || ""]));
  if (state.manualSignOutHold === true) {
    await persistManualSignOutHold(false, "session-activated");
  }
  state.loginData = loginData;
  state.cmConsoleBootstrapQualified =
    Boolean(normalizedCmConsoleAccessToken && tokenSupportsCmConsoleRequests(normalizedCmConsoleAccessToken)) &&
    (state.cmTenantsPrecheckComplete === true || hasCmTenantsCatalogEntries());
  state.cmLastHydratedAccessToken = normalizedCmConsoleAccessToken;
  state.cmConsoleTokenConsoleEmitKey = "";
  writePersistedAvatarCandidate(loginData, {
    sourceUrl: loginData?.imageUrl || "",
    resolvedUrl: loginData?.imageUrl || "",
  });
  scheduleAvatarDataUrlPrefetch(loginData, loginData?.imageUrl || "");
  state.restricted = false;
  state.sessionMonitorSuppressed = false;
  state.sessionMonitorConsecutiveInactiveDetections = 0;
  state.sessionMonitorInactivityGuardUntil = Date.now() + IMS_SESSION_MONITOR_INACTIVITY_GUARD_MS;
  state.sessionReady = true;
  if (!shouldHydrateAdobePassWorkflowForSession(loginData)) {
    syncAuthenticatedOrgSwitchOnlyContext(loginData);
  } else {
    clearRestrictedOrgOptions();
  }
  syncMediaCompanySelectAvailability();
  startExperienceCloudSessionMonitor();
  if (persist) {
    await saveLoginData(loginData);
  }
  if (scheduleRefresh) {
    scheduleNoTouchRefresh();
  } else {
    clearRefreshTimer();
  }
}

function resetWorkflowForAuthenticatedHydration() {
  applyProgrammerEntities([]);
  state.programmersLoadInFlight = true;
  if (els.mediaCompanySelect) {
    els.mediaCompanySelect.disabled = true;
    els.mediaCompanySelect.innerHTML = `<option value="">${escapeHtml(getMediaCompanySelectDefaultLabel())}</option>`;
  }
  if (els.requestorSelect) {
    els.requestorSelect.disabled = true;
    els.requestorSelect.innerHTML = '<option value=""></option>';
  }
  if (els.mvpdSelect) {
    els.mvpdSelect.disabled = true;
    els.mvpdSelect.innerHTML = '<option value=""></option>';
  }
  renderPremiumServicesLoading(null, {
    controllerReason: "post-login-hydration",
  });
  syncMediaCompanySelectAvailability();
  syncGlobalQuickLaunchButtons();
}

function resetWorkflowForAuthenticatedImsSession() {
  applyProgrammerEntities([]);
  state.programmersLoadInFlight = false;
  if (els.mediaCompanySelect) {
    els.mediaCompanySelect.disabled = true;
    els.mediaCompanySelect.innerHTML = `<option value="">${escapeHtml(getMediaCompanySelectDefaultLabel())}</option>`;
  }
  if (els.requestorSelect) {
    els.requestorSelect.disabled = true;
    els.requestorSelect.innerHTML = '<option value=""></option>';
  }
  if (els.mvpdSelect) {
    els.mvpdSelect.disabled = true;
    els.mvpdSelect.innerHTML = '<option value=""></option>';
  }
  renderPremiumServices(null, null, {
    controllerReason: "ims-session-only",
  });
  syncMediaCompanySelectAvailability();
  syncGlobalQuickLaunchButtons();
}

async function hydrateAuthenticatedAdobePassSession(source = "session", options = {}) {
  const normalizedSource = String(source || "session").trim() || "session";
  const hydrationToken = ++state.authenticatedHydrationToken;
  const preferredCmBootstrapTabId = Number(options.preferredCmBootstrapTabId || 0);
  const allowBackgroundTemporaryPageContextTab = options.allowBackgroundTemporaryPageContextTab === true;
  const preserveExistingOnFailure = options.preserveExistingOnFailure === true;
  const currentLoginData = state.loginData && typeof state.loginData === "object" ? state.loginData : null;
  if (!shouldHydrateAdobePassWorkflowForSession(currentLoginData)) {
    state.programmersLoadInFlight = false;
    syncMediaCompanySelectAvailability();
    syncGlobalQuickLaunchButtons();
    render();
    return false;
  }

  state.programmersLoadInFlight = preserveExistingOnFailure ? false : true;
  syncMediaCompanySelectAvailability();

  let hydrationResult = await settle(() =>
    hydratePostLoginSessionData(currentLoginData, {
      reason: `activation:${normalizedSource}`,
      preferredTabId: preferredCmBootstrapTabId,
      allowTemporaryPageContextTab: allowBackgroundTemporaryPageContextTab,
      forceRefresh: options.forceRefresh === true,
    })
  );
  let hydratedLoginData = hydrationResult.ok ? hydrationResult.value : currentLoginData;
  const shouldRetryLimitedRestrictedSwitchHydration =
    hydrationResult.ok &&
    hydratedLoginData &&
    allowBackgroundTemporaryPageContextTab &&
    Array.isArray(hydratedLoginData?.console?.programmers) &&
    hydratedLoginData.console.programmers.length === 0 &&
    Number(hydratedLoginData?.console?.configurationVersion || 0) <= 0 &&
    (normalizedSource === "restricted-org-switch" || normalizedSource === "interactive-auto-switch-recovery");
  if (shouldRetryLimitedRestrictedSwitchHydration) {
    log("Retrying Adobe Pass session hydration after limited restricted switch bootstrap", {
      source: normalizedSource,
      configurationVersion: Number(hydratedLoginData?.console?.configurationVersion || 0),
      preferredCmBootstrapTabId,
    });
    await sleep(250);
    hydrationResult = await settle(() =>
      hydratePostLoginSessionData(hydratedLoginData, {
        reason: `activation:${normalizedSource}:retry`,
        preferredTabId: preferredCmBootstrapTabId,
        allowTemporaryPageContextTab: allowBackgroundTemporaryPageContextTab,
        forceRefresh: true,
      })
    );
    if (hydrationResult.ok) {
      hydratedLoginData = hydrationResult.value;
    }
  }
  if (hydrationToken !== state.authenticatedHydrationToken) {
    return false;
  }

  state.programmersLoadInFlight = false;
  syncMediaCompanySelectAvailability();

  let programmersLoadError = null;
  let cmPrecheckError = null;

  if (!hydrationResult.ok) {
    programmersLoadError =
      hydrationResult.error instanceof Error ? hydrationResult.error : new Error(String(hydrationResult.error));
  } else if (hydratedLoginData && typeof hydratedLoginData === "object") {
    state.loginData = hydratedLoginData;
    applyHydratedSessionContextsToState(hydratedLoginData, {
      preserveExistingOnFailure,
      reason: `activation:${normalizedSource}`,
    });
    if (shouldOfferAdobePassRecoveryForSession(hydratedLoginData)) {
      syncAuthenticatedOrgSwitchOnlyContext(hydratedLoginData);
    } else {
      clearRestrictedOrgOptions();
    }
    await saveLoginData(hydratedLoginData).catch(() => false);
    await persistAuthenticatedConsoleHydrationSnapshot().catch(() => null);

    const consoleContext = hydratedLoginData?.console && typeof hydratedLoginData.console === "object"
      ? hydratedLoginData.console
      : null;
    const cmContext = hydratedLoginData?.cm && typeof hydratedLoginData.cm === "object"
      ? hydratedLoginData.cm
      : null;
    const hasProgrammers = Array.isArray(consoleContext?.programmers) && consoleContext.programmers.length > 0;
    const consoleBootstrapIncomplete = !consoleContext?.extendedProfile;
    const consoleConfigurationMissing = Number(consoleContext?.configurationVersion || 0) <= 0;
    const consoleProgrammerMessage = firstNonEmptyString([
      !hasProgrammers && consoleBootstrapIncomplete ? consoleContext?.errors?.extendedProfile : "",
      !hasProgrammers && !consoleConfigurationMissing ? consoleContext?.errors?.configurationVersion : "",
      !hasProgrammers && !consoleConfigurationMissing ? consoleContext?.errors?.programmers : "",
    ]);
    if (consoleProgrammerMessage) {
      programmersLoadError = new Error(consoleProgrammerMessage);
    }

    const cmCatalogReady = hasCmTenantsCatalogEntries(state.cmTenantsCatalog);
    const cmTokenReady =
      Boolean(normalizeBearerTokenValue(firstNonEmptyString([hydratedLoginData?.cmConsoleAccessToken, cmContext?.cmuToken]))) &&
      state.cmConsoleBootstrapQualified === true;
    if (!(cmCatalogReady && cmTokenReady)) {
      const cmErrorMessage = firstNonEmptyString([
        cmContext?.errors?.tenants,
        cmContext?.errors?.cmuToken,
      ]);
      if (cmErrorMessage) {
        cmPrecheckError = new Error(cmErrorMessage);
      }
    }
  }

  if (programmersLoadError) {
    if (!(preserveExistingOnFailure || normalizedSource === "stored")) {
      setStatus(
        firstNonEmptyString([
          String(programmersLoadError?.message || "").trim(),
          "Signed in, but UnderPAR could not load media companies. Refresh the session and retry.",
        ]),
        "error"
      );
    } else {
      clearStatusUnlessCmTenantsPrecheckBlocked();
    }
  } else if (cmPrecheckError) {
    setStatus(
      firstNonEmptyString([
        String(cmPrecheckError?.message || "").trim(),
        "Signed in, but UnderPAR could not hydrate CM and CMU yet.",
      ]),
      "error"
    );
  } else {
    clearStatusUnlessCmTenantsPrecheckBlocked();
  }

  render();
  setUnderparDiagnosticMarker("activation", {
    status: programmersLoadError || cmPrecheckError ? "warning" : "success",
    source: normalizedSource,
    phase: programmersLoadError ? "programmers-load-warning" : cmPrecheckError ? "cm-precheck-warning" : "complete",
    programmersCount: Number(state.programmers.length || 0),
    criticalPathMs: Math.max(0, Date.now() - Number(options.activationStartedAt || Date.now())),
    error: firstNonEmptyString([
      String(programmersLoadError?.message || "").trim(),
      String(cmPrecheckError?.message || "").trim(),
    ]),
  });
  log(`Session hydration completed (${normalizedSource})`, {
    programmersCount: Number(state.programmers.length || 0),
    cmTenantsCount: Number(state.cmTenantsCatalog?.tenants?.length || 0),
    criticalPathMs: Math.max(0, Date.now() - Number(options.activationStartedAt || Date.now())),
    programmersError: String(programmersLoadError?.message || "").trim(),
    cmPrecheckError: String(cmPrecheckError?.message || "").trim(),
  });
  return !(programmersLoadError || cmPrecheckError);
}

async function activateSession(sessionData, source = "unknown", options = {}) {
  const activationStartedAt = Date.now();
  const normalizedSource = String(source || "unknown").trim() || "unknown";
  const allowDeniedRecovery = options.allowDeniedRecovery !== false;
  const allowTemporaryPageContextTab = options.allowTemporaryPageContextTab === true;
  const allowInteractiveConsoleBootstrap = shouldAllowInteractiveConsoleBootstrapForActivation(
    normalizedSource,
    options.allowInteractiveConsoleBootstrap === true
  );
  const activationAllowsTemporaryPageContextTab = shouldAllowTemporaryCmBootstrapTabForActivation(
    normalizedSource,
    allowTemporaryPageContextTab
  );
  const preferredCmBootstrapTabId = Number(options.preferredCmBootstrapTabId || 0);
  setUnderparDiagnosticMarker("activation", {
    status: "pending",
    source: normalizedSource,
    phase: "enforce-access",
    allowDeniedRecovery,
    allowInteractiveConsoleBootstrap,
    allowBackgroundTemporaryPageContextTab: activationAllowsTemporaryPageContextTab,
  });
  const enforced = await enforceAdobePassAccess(sessionData);
  if (!enforced?.loginData) {
    await clearLoginData();
    resetWorkflowForLoggedOut();
    state.loginData = null;
    state.restricted = false;
    state.sessionReady = false;
    clearRefreshTimer();
    setUnderparDiagnosticMarker("activation", {
      status: "error",
      source: normalizedSource,
      phase: "missing-login-data",
      recoveryLabel:
        firstNonEmptyString([enforced?.recoveryLabel]) || "Unable to resolve Adobe session state for this login.",
    });
    setStatus("Unable to resolve Adobe session state for this login. Click Sign In.", "error");
    render();
    return false;
  }

  resetCmTenantsPrecheckState();
  state.consoleCsrfToken = "";
  state.consoleBootstrapState = null;
  const normalizedLoginDataPromise = resolveNormalizedLoginData(enforced.loginData, {
    fetchProfile: true,
    resetBootstrapTokens: true,
  });
  let resolvedLoginData = buildNormalizedLoginData(
    mergeCmConsoleBootstrapIntoLoginData(
      await normalizedLoginDataPromise,
      enforced.loginData
    ),
    {
      resetBootstrapTokens: false,
    }
  );
  const targetOrganizationVerification = verifyTargetOrganizationSelection(
    resolvedLoginData,
    resolvedLoginData?.targetOrganization && typeof resolvedLoginData.targetOrganization === "object"
      ? resolvedLoginData.targetOrganization
      : null
  );
  resolvedLoginData.orgVerification = targetOrganizationVerification;
  const shouldHydrateAdobePassWorkflow = shouldHydrateAdobePassWorkflowForSession(resolvedLoginData);
  const sessionRequiresOrgSelection = shouldOfferAdobePassRecoveryForSession(resolvedLoginData);
  const authenticatedOrgPickerOnly = !shouldHydrateAdobePassWorkflow;

  const sessionProfileCompleteness = getSessionProfileCompleteness(resolvedLoginData);
  if (!sessionProfileCompleteness.complete) {
    await clearLoginData();
    resetWorkflowForLoggedOut();
    state.loginData = null;
    state.restricted = false;
    state.sessionReady = false;
    clearRefreshTimer();
    state.cmTenantsPrecheckPending = false;
    syncMediaCompanySelectAvailability();
    logDecisionPoint("Session activation blocked: incomplete profile", {
      source,
      missing: sessionProfileCompleteness.missing,
      displayName: sessionProfileCompleteness.displayName,
      principalId: sessionProfileCompleteness.principalId,
      authId: sessionProfileCompleteness.authId,
      userId: sessionProfileCompleteness.userId,
      orgId: sessionProfileCompleteness.orgId,
      orgName: sessionProfileCompleteness.orgName,
    });
    setUnderparDiagnosticMarker("activation", {
      status: "error",
      source: normalizedSource,
      phase: "incomplete-profile",
      missing: sessionProfileCompleteness.missing,
    });
    setStatus("Experience Cloud session context is incomplete. Click Sign In.", "error");
    render();
    return false;
  }

  if (
    resolvedLoginData?.targetOrganization &&
    shouldOfferAdobePassRecoveryForSession(resolvedLoginData) &&
    !isSuccessfulTargetOrganizationVerification(targetOrganizationVerification)
  ) {
    const verificationFailureMessage = `${targetOrganizationVerification.message} UnderPAR kept the prior session so it does not misrepresent the selected Adobe profile.`;
    log(verificationFailureMessage);
    setUnderparDiagnosticMarker("activation", {
      status: "error",
      source: normalizedSource,
      phase: "org-verification-mismatch",
      expectedOrgKey: firstNonEmptyString([targetOrganizationVerification?.expectedOrgKey]),
      resolvedOrgKey: firstNonEmptyString([targetOrganizationVerification?.resolvedOrgKey]),
      error: verificationFailureMessage,
    });
    if (state.sessionReady && state.loginData) {
      if (!shouldHydrateAdobePassWorkflowForSession(state.loginData)) {
        syncAuthenticatedOrgSwitchOnlyContext(state.loginData);
        updateRestrictedContext(state.loginData, {
          recoveryLabel: verificationFailureMessage,
        });
      } else {
        clearRestrictedOrgOptions();
      }
    } else {
      clearRestrictedOrgOptions();
    }
    setStatus(verificationFailureMessage, "error");
    render();
    return false;
  }

  if (authenticatedOrgPickerOnly) {
    resolvedLoginData = buildNormalizedLoginData(
      {
        ...resolvedLoginData,
        consoleHydration: null,
      },
      {
        resetBootstrapTokens: true,
      }
    );
    resolvedLoginData.orgVerification = targetOrganizationVerification;
  }

  await applyActiveLoginSession(resolvedLoginData, {
    persist: true,
    scheduleRefresh: true,
  });
  state.cmLastHydratedAccessToken = normalizeBearerTokenValue(
    firstNonEmptyString([resolvedLoginData?.cmConsoleAccessToken || ""])
  );
  const restoredAuthenticatedConsoleHydration =
    normalizedSource === "stored" && shouldHydrateAdobePassWorkflow && !sessionRequiresOrgSelection
      ? restoreStoredAuthenticatedConsoleHydration(resolvedLoginData)
      : false;
  const allowBackgroundTemporaryPageContextTab = restoredAuthenticatedConsoleHydration
    ? false
    : activationAllowsTemporaryPageContextTab;
  if (restoredAuthenticatedConsoleHydration) {
    state.programmersLoadInFlight = false;
    syncMediaCompanySelectAvailability();
    syncGlobalQuickLaunchButtons();
  } else if (shouldHydrateAdobePassWorkflow) {
    resetWorkflowForAuthenticatedHydration();
  } else {
    resetWorkflowForAuthenticatedImsSession();
  }
  render();
  setUnderparDiagnosticMarker("activation", {
    status: "pending",
    source: normalizedSource,
    phase: sessionRequiresOrgSelection
      ? "org-selection-required"
      : shouldHydrateAdobePassWorkflow
        ? "post-login-hydration"
        : "ims-session-ready",
    programmersCount: 0,
    criticalPathMs: Math.max(0, Date.now() - activationStartedAt),
  });
  log(`Session activated (${source})`, {
    expiresAt: resolvedLoginData.expiresAt,
    org: firstNonEmptyString([resolvedLoginData?.authContext?.orgId]),
    orgSelectionRequired: sessionRequiresOrgSelection,
    adobePassWorkflowActive: shouldHydrateAdobePassWorkflow,
    criticalPathMs: Math.max(0, Date.now() - activationStartedAt),
    cmHydrationMode: !shouldHydrateAdobePassWorkflow
      ? "skipped-non-adobepass-org"
      : allowBackgroundTemporaryPageContextTab
        ? "activation-critical-path-temporary-tab-allowed"
        : "activation-background",
  });
  if (shouldHydrateAdobePassWorkflow) {
    void hydrateAuthenticatedAdobePassSession(normalizedSource, {
      activationStartedAt,
      consoleAccessToken: normalizeBearerTokenValue(
        firstNonEmptyString([
          resolvedLoginData?.accessToken,
          getPreferredPrimaryImsAccessTokenCandidate(),
          getPreferredAdobeConsoleAccessTokenCandidate(),
        ])
      ),
      forceRefresh: true,
      allowBackgroundTemporaryPageContextTab,
      preferredCmBootstrapTabId,
      preserveExistingOnFailure: restoredAuthenticatedConsoleHydration,
    }).catch((error) => {
      const resolvedError = error instanceof Error ? error : new Error(String(error));
      if (state.restricted || !state.sessionReady || !state.loginData) {
        return;
      }
      state.programmersLoadInFlight = false;
      syncMediaCompanySelectAvailability();
      setUnderparDiagnosticMarker("activation", {
        status: "warning",
        source: normalizedSource,
        phase: "background-hydration-failed",
        error: resolvedError.message,
      });
      if (!(normalizedSource === "stored" || restoredAuthenticatedConsoleHydration)) {
        setStatus(resolvedError.message, "error");
      } else {
        clearStatusUnlessCmTenantsPrecheckBlocked();
      }
      render();
    });
  }
  return true;
}

async function refreshSessionNoTouch() {
  if (state.silentRefreshPromise) {
    return state.silentRefreshPromise;
  }

  if (state.busy || state.isBootstrapping) {
    return false;
  }

  const refreshPromise = (async () => {
    setUnderparDiagnosticMarker("auth", {
      status: "pending",
      mode: "silent-refresh",
      phase: "launch-web-auth-flow",
    });
    try {
      const authData = await startLogin({ interactive: false, allowFallback: false });
      setUnderparDiagnosticMarker("auth", {
        status: "token-acquired",
        mode: "silent-refresh",
        phase: "token-acquired",
      });
      const profile = await resolveProfileAfterLogin(authData);
      setUnderparDiagnosticMarker("auth", {
        status: "profile-resolved",
        mode: "silent-refresh",
        phase: "profile-resolved",
      });
      const activated = await activateSession(
        attachTargetOrganizationToLoginData(
          buildLoginSessionPayloadFromAuth(authData, profile),
          state.loginData?.targetOrganization && typeof state.loginData.targetOrganization === "object"
            ? state.loginData.targetOrganization
            : null
        ),
        "silent-refresh"
      );
      setUnderparDiagnosticMarker("auth", {
        status: activated === true ? "success" : "incomplete",
        mode: "silent-refresh",
        phase: activated === true ? "activation-complete" : "activation-incomplete",
      });
      return activated === true;
    } catch (error) {
      setUnderparDiagnosticMarker("auth", {
        status: "error",
        mode: "silent-refresh",
        phase: "failed",
        error: error instanceof Error ? error.message : String(error),
      });
      log("No-touch refresh skipped", error?.message || String(error));
      if (state.loginData?.expiresAt && state.loginData.expiresAt > Date.now()) {
        scheduleNoTouchRefresh();
      }
      return false;
    } finally {
      if (state.silentRefreshPromise === refreshPromise) {
        state.silentRefreshPromise = null;
      }
    }
  })();

  state.silentRefreshPromise = refreshPromise;
  return refreshPromise;
}

async function awaitCmBootstrapForExplicitActivation(reason = "session", options = {}) {
  if (!state.sessionReady || !state.loginData || state.restricted) {
    return null;
  }
  try {
    return await ensureCmTenantsPrecheckForActiveSession(`explicit-activation:${String(reason || "session")}`, {
      forceRefresh: options.forceRefresh === true,
      allowTemporaryPageContextTab: options.allowTemporaryPageContextTab === true,
      preferredCmBootstrapTabId: Number(options.preferredCmBootstrapTabId || 0),
    });
  } catch (error) {
    const resolvedError = error instanceof Error ? error : new Error(String(error));
    setStatus(resolvedError.message, "error");
    log("Explicit activation CM bootstrap failed", {
      reason: String(reason || "session"),
      error: resolvedError.message,
    });
    return null;
  }
}

async function attemptSilentBootstrapLogin() {
  return null;
}

function normalizeProgrammersResponse(data) {
  const normalizeEntityList = (items) =>
    items
      .map((item, index) => ({
        key: item?.key || `Programmer:${item?.entityData?.id || item?.id || item?.programmerId || index}`,
        entityData: item?.entityData || item,
      }))
      .filter((entry) => entry.entityData && typeof entry.entityData === "object");

  const looksLikeProgrammerEntity = (candidate) => {
    if (!candidate || typeof candidate !== "object") {
      return false;
    }
    return Boolean(
      candidate.id ||
        candidate.programmerId ||
        candidate["programmer-id"] ||
        candidate.displayName ||
        candidate["display-name"] ||
        candidate.name ||
        candidate.contentProviders ||
        candidate.applications ||
        candidate["media-company"] ||
        candidate.media_company ||
        candidate.mediaCompany ||
        candidate.mediaCompanyName
    );
  };

  if (Array.isArray(data)) {
    return normalizeEntityList(data);
  }

  if (Array.isArray(data?.entities)) {
    return normalizeEntityList(data.entities);
  }

  if (!data || typeof data !== "object") {
    return [];
  }

  const collectionCandidates = [
    data.items,
    data.results,
    data.programmers,
    data.rows,
    data.data,
    data.list,
  ];
  for (const candidate of collectionCandidates) {
    if (Array.isArray(candidate)) {
      const normalized = normalizeEntityList(candidate);
      if (normalized.length > 0) {
        return normalized;
      }
    }
  }

  if (data.entities && typeof data.entities === "object") {
    const normalized = normalizeEntityList(Object.values(data.entities));
    if (normalized.length > 0) {
      return normalized;
    }
  }

  const nestedPayloadCandidates = [data.payload, data.response, data.result];
  for (const candidate of nestedPayloadCandidates) {
    if (!candidate || typeof candidate !== "object") {
      continue;
    }
    const normalized = normalizeProgrammersResponse(candidate);
    if (normalized.length > 0) {
      return normalized;
    }
  }

  const firstArrayValue = Object.values(data).find((value) => Array.isArray(value));
  if (Array.isArray(firstArrayValue)) {
    const normalized = normalizeEntityList(firstArrayValue);
    if (normalized.length > 0) {
      return normalized;
    }
  }

  if (looksLikeProgrammerEntity(data)) {
    return [
      {
        key: data.key || `Programmer:${data.entityData?.id || data.id || "single"}`,
        entityData: data.entityData || data,
      },
    ];
  }

  return [];
}

function computeEntityReferenceId(reference = "") {
  const normalizedReference = String(reference || "").trim();
  if (!normalizedReference) {
    return "";
  }

  const matches = normalizedReference.match(/@[^:]+:(.+)$/);
  return firstNonEmptyString([matches?.[1], normalizedReference]);
}

function normalizeConsoleChannelsResponse(payload) {
  const entities = Array.isArray(payload?.entities) ? payload.entities : Array.isArray(payload) ? payload : [];
  const seen = new Set();
  const channels = [];

  entities.forEach((entity, index) => {
    const entityData = entity?.entityData && typeof entity.entityData === "object" ? entity.entityData : entity;
    if (!entityData || typeof entityData !== "object") {
      return;
    }

    const id = firstNonEmptyString([entityData.id, entity?.id, entity?.key]);
    const key = firstNonEmptyString([id, entity?.key, `channel-${index + 1}`]);
    if (!key || seen.has(key)) {
      return;
    }

    seen.add(key);
    const name = firstNonEmptyString([
      entityData.displayName,
      entityData.name,
      entityData.label,
      entityData.title,
      id ? `Channel ${id}` : `Channel ${index + 1}`,
    ]);
    channels.push({
      key,
      id,
      name,
      label:
        id &&
        normalizeOrganizationIdentifier(name) !== normalizeOrganizationIdentifier(id) &&
        normalizeOrganizationIdentifier(name) !== normalizeOrganizationIdentifier(`Channel ${id}`)
          ? `${name} | ${id}`
          : name,
      programmerId: computeEntityReferenceId(entityData.programmer),
      raw: entityData,
    });
  });

  return channels.sort((left, right) => {
    const leftLabel = firstNonEmptyString([left?.name, left?.label, left?.id]);
    const rightLabel = firstNonEmptyString([right?.name, right?.label, right?.id]);
    return leftLabel.localeCompare(rightLabel, undefined, { sensitivity: "base" });
  });
}

function deriveProgrammerRequestorOptionsFromChannels(programmerData = null, channels = []) {
  if (!programmerData || typeof programmerData !== "object") {
    return [];
  }

  const normalizedProgrammerId = normalizeOrganizationIdentifier(
    firstNonEmptyString([programmerData.id, programmerData.programmerId, programmerData["programmer-id"]])
  );
  const rawServiceProviders = Array.isArray(programmerData?.serviceProviders)
    ? programmerData.serviceProviders
    : Array.isArray(programmerData?.contentProviders)
      ? programmerData.contentProviders
      : [];
  const referencedRequestorIds = new Set(
    rawServiceProviders
      .map((reference) => computeEntityReferenceId(reference))
      .map((value) => String(value || "").trim())
      .filter(Boolean)
  );
  const requestors = [];
  const seen = new Set();
  const pushRequestor = (option) => {
    if (!option || typeof option !== "object") {
      return;
    }

    const id = String(firstNonEmptyString([option.id, option.key]) || "").trim();
    const key = String(firstNonEmptyString([option.key, id]) || "").trim();
    if (!id || !key) {
      return;
    }

    const dedupeKey = key.toLowerCase();
    if (seen.has(dedupeKey)) {
      return;
    }

    seen.add(dedupeKey);
    requestors.push({
      key,
      id,
      name: firstNonEmptyString([option.name, option.label, id]) || id,
      label: firstNonEmptyString([option.label, option.name, id]) || id,
      programmerId: firstNonEmptyString([
        option.programmerId,
        programmerData.id,
        programmerData.programmerId,
        programmerData["programmer-id"],
      ]),
      raw: option.raw || option,
    });
  };

  (Array.isArray(channels) ? channels : []).forEach((channel) => {
    const channelProgrammerId = normalizeOrganizationIdentifier(channel?.programmerId);
    const channelId = String(channel?.id || "").trim();
    const matchesProgrammer =
      normalizedProgrammerId && channelProgrammerId && channelProgrammerId === normalizedProgrammerId;
    const matchesReference = channelId && referencedRequestorIds.has(channelId);
    if (matchesProgrammer || matchesReference) {
      pushRequestor(channel);
    }
  });

  referencedRequestorIds.forEach((requestorId) => {
    pushRequestor({
      key: requestorId,
      id: requestorId,
      name: requestorId,
      label: requestorId,
      programmerId: firstNonEmptyString([
        programmerData.id,
        programmerData.programmerId,
        programmerData["programmer-id"],
      ]),
      raw: {
        id: requestorId,
      },
    });
  });

  return requestors.sort((left, right) =>
    firstNonEmptyString([left?.label, left?.name, left?.id]).localeCompare(
      firstNonEmptyString([right?.label, right?.name, right?.id]),
      undefined,
      { sensitivity: "base" }
    )
  );
}

function extractContentProviderId(reference) {
  const text = String(reference || "");
  const match = text.match(/^@ContentProvider:(.+)$/);
  if (match) {
    return match[1];
  }

  return text.trim() || null;
}

function mapProgrammerEntity(entity, index) {
  const data =
    entity?.entityData && typeof entity.entityData === "object"
      ? entity.entityData
      : entity?.raw && typeof entity.raw === "object"
        ? entity.raw
        : entity && typeof entity === "object"
          ? entity
          : {};
  const programmerId = data.id || data.programmerId || data["programmer-id"] || `programmer-${index + 1}`;
  const programmerName = data.displayName || data["display-name"] || data.name || programmerId;
  const mediaCompanyName =
    data["media-company"] ||
    data.media_company ||
    data.mediaCompany ||
    data.mediaCompanyName ||
    data.company ||
    programmerName ||
    programmerId;

  const requestorOptions =
    Array.isArray(data.requestorOptions) && data.requestorOptions.length > 0
      ? data.requestorOptions
      : deriveProgrammerRequestorOptionsFromChannels(
          data,
          Array.isArray(state?.consoleBootstrapState?.channels) ? state.consoleBootstrapState.channels : []
        );
  const requestorIds =
    requestorOptions.length > 0
      ? uniqueSorted(requestorOptions.map((item) => String(item?.id || item?.key || "").trim()).filter(Boolean))
      : Array.isArray(data.contentProviders)
        ? data.contentProviders.map((item) => extractContentProviderId(item)).filter(Boolean)
        : [];
  const applications = Array.isArray(data.applications) ? data.applications : [];

  return {
    key: `${programmerId}-${index}`,
    programmerId,
    programmerName,
    mediaCompanyName,
    label:
      programmerId &&
      normalizeOrganizationIdentifier(programmerName) !== normalizeOrganizationIdentifier(programmerId)
        ? `${programmerName} | ${programmerId}`
        : programmerName,
    requestorIds,
    requestorOptions,
    applications,
    raw: data,
    source: entity,
  };
}

function uniqueSorted(values) {
  const set = new Set(values.filter(Boolean));
  return [...set].sort((a, b) => String(a).localeCompare(String(b), undefined, { sensitivity: "base" }));
}

function uniquePreserveOrder(values = []) {
  const output = [];
  const seen = new Set();
  (Array.isArray(values) ? values : []).forEach((value) => {
    const normalized = String(value || "").trim();
    if (!normalized || seen.has(normalized)) {
      return;
    }
    seen.add(normalized);
    output.push(normalized);
  });
  return output;
}

function isMediaCompanySelectInteracting() {
  return Boolean(els?.mediaCompanySelect && document?.activeElement === els.mediaCompanySelect);
}

function clearPendingMediaCompanySelectionHydration() {
  const timerId = Number(state.mediaCompanySelectionHydrationTimerId || 0);
  if (timerId > 0) {
    window.clearTimeout(timerId);
  }
  state.mediaCompanySelectionHydrationTimerId = 0;
}

function flushPendingMediaCompanyOptionHydrationState() {
  if (state.mediaCompanyOptionHydrationDeferred !== true) {
    return false;
  }
  applyMediaCompanyOptionHydrationState({ allowDefer: false });
  return true;
}

function flushPendingMediaCompanySelectionHydration() {
  const controllerReason = String(state.pendingMediaCompanySelectionControllerReason || "").trim();
  if (!controllerReason && Number(state.mediaCompanySelectionHydrationTimerId || 0) <= 0) {
    return false;
  }
  clearPendingMediaCompanySelectionHydration();
  state.pendingMediaCompanySelectionControllerReason = "";
  const selectedProgrammer = resolveSelectedProgrammer();
  void hydrateProgrammerSelection(selectedProgrammer, {
    controllerReason: controllerReason || "media-company-change",
  }).catch((error) => {
    setStatus(error instanceof Error ? error.message : String(error), "error");
  });
  return true;
}

function scheduleMediaCompanySelectionHydration(controllerReason = "media-company-change") {
  state.pendingMediaCompanySelectionControllerReason =
    String(controllerReason || "media-company-change").trim() || "media-company-change";
  clearPendingMediaCompanySelectionHydration();
  const delayMs = isMediaCompanySelectInteracting() ? MEDIA_COMPANY_SELECTION_DEBOUNCE_MS : 0;
  if (delayMs <= 0) {
    flushPendingMediaCompanySelectionHydration();
    return;
  }
  state.mediaCompanySelectionHydrationTimerId = window.setTimeout(() => {
    state.mediaCompanySelectionHydrationTimerId = 0;
    flushPendingMediaCompanySelectionHydration();
  }, delayMs);
}

function applyMediaCompanyOptionHydrationState(options = {}) {
  if (!els.mediaCompanySelect) {
    return;
  }
  if (options?.allowDefer !== false && isMediaCompanySelectInteracting()) {
    state.mediaCompanyOptionHydrationDeferred = true;
    return;
  }
  state.mediaCompanyOptionHydrationDeferred = false;

  const programmerByKey = new Map(
    (Array.isArray(state.programmers) ? state.programmers : []).map((programmer) => [String(programmer?.key || "").trim(), programmer])
  );

  const resolveProgrammerCmOptionState = (programmer = null) => {
    const programmerId = String(programmer?.programmerId || "").trim();
    if (!programmerId) {
      return {
        checked: false,
        matchedTenants: [],
      };
    }
    const runtimeService =
      getCurrentPremiumAppsSnapshot(programmerId)?.cm ||
      state.cmServiceByProgrammerId.get(programmerId) ||
      buildPassVaultRuntimeCmServiceSnapshot(getPassVaultMediaCompanyRecord(programmerId)) ||
      null;
    const matchedTenants = sanitizePassVaultMatchedTenants(runtimeService?.matchedTenants || []);
    return {
      checked: Boolean(
        runtimeService &&
          (runtimeService?.checked === true ||
            Number(runtimeService?.fetchedAt || 0) > 0 ||
            Boolean(String(runtimeService?.sourceUrl || "").trim()) ||
            Boolean(String(runtimeService?.loadError || "").trim()))
      ),
      matchedTenants,
    };
  };

  Array.from(els.mediaCompanySelect.options || []).forEach((option) => {
    const optionValue = String(option?.value || "").trim();
    if (!optionValue) {
      option.style.color = "";
      option.title = "";
      delete option.dataset.vaultHydration;
      delete option.dataset.baseLabel;
      return;
    }

    const programmer = programmerByKey.get(optionValue) || null;
    const baseLabel = String(
      option.dataset.baseLabel ||
        option.textContent ||
        `${String(programmer?.programmerName || "").trim()} - ${String(programmer?.programmerId || "").trim()}`
    )
      .replace(/\s+\[CM\]$/i, "")
      .trim();
    option.dataset.baseLabel = baseLabel;
    const cmOptionState = resolveProgrammerCmOptionState(programmer);
    const cmTenantNames = cmOptionState.matchedTenants
      .map((tenant) => String(firstNonEmptyString([tenant?.tenantName, tenant?.tenantId]) || "").trim())
      .filter(Boolean);
    option.textContent = baseLabel;
    const hydrationStatus = getPassVaultProgrammerHydrationStatus(programmer?.programmerId);
    const reusable = isPassVaultProgrammerReadyForReuse(programmer?.programmerId);
    const cmTitle =
      cmTenantNames.length > 0
        ? `CM detected in this environment: ${cmTenantNames.slice(0, 3).join(", ")}${cmTenantNames.length > 3 ? "..." : ""}.`
        : cmOptionState.checked
          ? "CM not detected for this Media Company in the active environment."
          : "";
    if (hydrationStatus === UNDERPAR_VAULT_STATUS_COMPLETE || reusable) {
      option.style.color = "";
      option.style.fontWeight = "";
      option.title = [
        hydrationStatus === UNDERPAR_VAULT_STATUS_COMPLETE
          ? "UnderPAR vault hydrated for this Media Company."
          : "UnderPAR vault already has reusable service mappings and credentials for this Media Company.",
        cmTitle,
      ]
        .filter(Boolean)
        .join(" ");
      option.dataset.vaultHydration = reusable ? UNDERPAR_VAULT_STATUS_COMPLETE : hydrationStatus;
      return;
    }

    option.style.color = "rgba(42, 56, 77, 0.62)";
    option.style.fontWeight = "500";
    option.dataset.vaultHydration = hydrationStatus || UNDERPAR_VAULT_STATUS_PENDING;
    option.title = [
      hydrationStatus === UNDERPAR_VAULT_STATUS_PARTIAL
        ? "UnderPAR has a partial vault record for this Media Company. A refresh may still be required for full credential coverage."
        : "UnderPAR has not fully hydrated this Media Company yet. First selection compiles and persists the vault record.",
      cmTitle,
    ]
      .filter(Boolean)
      .join(" ");
  });

  const selectedProgrammer = resolveSelectedProgrammer();
  const selectedStatus = getPassVaultProgrammerHydrationStatus(selectedProgrammer?.programmerId);
  const selectedReusable = isPassVaultProgrammerReadyForReuse(selectedProgrammer?.programmerId);
  els.mediaCompanySelect.style.color =
    selectedStatus && selectedStatus !== UNDERPAR_VAULT_STATUS_COMPLETE && !selectedReusable ? "rgba(42, 56, 77, 0.72)" : "";
}

function hasCmTenantsCatalogEntries(catalog = state.cmTenantsCatalog) {
  return Boolean(catalog && Array.isArray(catalog.tenants) && catalog.tenants.length > 0);
}

function isMediaCompanySelectionLockedByCmPrecheck() {
  return false;
}

function getMediaCompanySelectDefaultLabel() {
  if (state.programmersLoadInFlight === true) {
    return "-- Loading Media Companies... --";
  }
  return "-- Choose a Media Company --";
}

function syncMediaCompanySelectAvailability() {
  if (!els?.mediaCompanySelect) {
    return;
  }

  const defaultOption = els.mediaCompanySelect.options?.[0] || null;
  if (defaultOption) {
    defaultOption.textContent = getMediaCompanySelectDefaultLabel();
  }

  const sessionRequiresOrgSwitchOnly =
    state.sessionReady === true &&
    Boolean(state.loginData) &&
    state.restricted !== true &&
    !shouldHydrateAdobePassWorkflowForSession(state.loginData);

  if (!state.sessionReady || !state.loginData || state.restricted || sessionRequiresOrgSwitchOnly) {
    els.mediaCompanySelect.disabled = true;
    return;
  }

  const optionCount = Math.max(0, Number(els.mediaCompanySelect.options?.length || 0) - 1);
  els.mediaCompanySelect.disabled = isMediaCompanySelectionLockedByCmPrecheck() || optionCount === 0;
}

async function ensureCmTenantsPrecheckForActiveSession(reason = "session", options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  const normalizedReason = String(reason || "session").trim() || "session";
  const allowTemporaryPageContextTab = options?.allowTemporaryPageContextTab === true;
  const preferredCmBootstrapTabId = Number(options?.preferredCmBootstrapTabId || 0);
  if (state.restricted || !state.loginData) {
    setUnderparDiagnosticMarker("cm_precheck", {
      status: "skipped",
      reason: normalizedReason,
      phase: "no-session",
    });
    return null;
  }
  const explicitAdobePassRecoveryRequested = shouldOfferAdobePassRecoveryForSession(state.loginData);
  if (!shouldHydrateAdobePassWorkflowForSession(state.loginData)) {
    state.cmTenantsPrecheckPending = false;
    state.cmTenantsPrecheckComplete = false;
    state.cmTenantsPrecheckLastError = "";
    setUnderparDiagnosticMarker("cm_precheck", {
      status: explicitAdobePassRecoveryRequested ? "restricted" : "skipped",
      reason: normalizedReason,
      phase: explicitAdobePassRecoveryRequested ? "org-selection-required" : "non-adobepass-org",
    });
    syncMediaCompanySelectAvailability();
    return null;
  }
  if (!forceRefresh && state.cmTenantsPrecheckPromise) {
    setUnderparDiagnosticMarker("cm_precheck", {
      status: "pending",
      reason: normalizedReason,
      phase: "reuse-promise",
    });
    return state.cmTenantsPrecheckPromise;
  }
  const effectiveAllowTemporaryPageContextTab = allowTemporaryPageContextTab;

  const existingCmToken = normalizeBearerTokenValue(getPreferredCmRequestAccessTokenCandidate());
  const cmTokenReady =
    existingCmToken &&
    tokenSupportsCmConsoleRequests(existingCmToken) &&
    isAccessTokenFreshEnough(existingCmToken, 45 * 1000);

  if (!forceRefresh && state.cmTenantsPrecheckComplete === true && hasCmTenantsCatalogEntries() && cmTokenReady) {
    setUnderparDiagnosticMarker("cm_precheck", {
      status: "cache-hit",
      reason: normalizedReason,
      phase: "ready",
      tenantCount: Number(state.cmTenantsCatalog?.tenants?.length || 0),
    });
    syncMediaCompanySelectAvailability();
    return state.cmTenantsCatalog;
  }

  let precheckPromise = null;
  precheckPromise = (async () => {
    state.cmTenantsPrecheckPending = true;
    state.cmTenantsPrecheckComplete = false;
    state.cmTenantsPrecheckLastError = "";
    setUnderparDiagnosticMarker("cm_precheck", {
      status: "pending",
      reason: normalizedReason,
      phase: "bootstrap",
      forceRefresh,
      allowTemporaryPageContextTab: effectiveAllowTemporaryPageContextTab,
    });
    syncMediaCompanySelectAvailability();

    try {
      const cmContext = await buildCmContext(state.loginData, normalizedReason, {
        preferredTabId: preferredCmBootstrapTabId,
        allowTemporaryTab: effectiveAllowTemporaryPageContextTab,
      });
      const catalog =
        buildCmTenantsCatalogFromContext(cmContext, state.cmTenantsCatalog) ||
        (await ensureCmTenantsCatalog({
          forceRefresh,
          allowTemporaryPageContextTab: effectiveAllowTemporaryPageContextTab,
          preferredCmBootstrapTabId,
        }));
      if (!hasCmTenantsCatalogEntries(catalog)) {
        throw new Error("CM tenants load failed: tenant catalog returned no tenants.");
      }

      if (buildCmTenantsCatalogFromContext(cmContext, state.cmTenantsCatalog)) {
        state.cmTenantsCatalog = catalog;
        state.cmTenantsCatalogHydrated = true;
        state.cmTenantsCatalogRuntimeFresh = true;
        syncCmConsoleBootstrapSummaryFromCatalog(catalog, {
          errors: [cmContext?.errors?.reports, cmContext?.errors?.tenants, cmContext?.errors?.cmuToken].filter(Boolean),
        });
        await persistCmTenantsCatalog(catalog).catch(() => false);
      }

      let hydratedToken = normalizeBearerTokenValue(cmuTokenFromContext(cmContext));
      if (!hydratedToken || !tokenSupportsCmConsoleRequests(hydratedToken)) {
        hydratedToken = normalizeBearerTokenValue(
          await ensureCmApiAccessToken({
            forceRefresh,
            freshLeewayMs: 45 * 1000,
            allowTemporaryPageContextTab: effectiveAllowTemporaryPageContextTab,
            preferredCmBootstrapTabId,
          }).catch(() => "")
        );
      }
      if (!hydratedToken || !tokenSupportsCmConsoleRequests(hydratedToken)) {
        emitCmDebugEvent({
          phase: "cm-tenant-precheck-token-missing",
          reason: String(reason || ""),
          tenantCount: Number(catalog?.tenants?.length || 0),
          sourceUrl: String(catalog?.sourceUrl || ""),
        });
        throw new Error(
          firstNonEmptyString([
            cmContext?.errors?.cmuToken,
            "CM token hydrate failed: UnderPAR could not auto-hydrate a cm-console-ui bearer for CMU usage.",
          ])
        );
      }
      await persistResolvedCmGlobalAuthState(hydratedToken, `tenant-precheck:${reason}`).catch(() => null);
      state.cmTenantsPrecheckComplete = true;
      state.cmConsoleBootstrapQualified = true;
      state.cmTenantsPrecheckLastError = "";
      setUnderparDiagnosticMarker("cm_precheck", {
        status: "success",
        reason: normalizedReason,
        phase: "complete",
        tenantCount: Number(catalog?.tenants?.length || 0),
        sourceUrl: String(catalog?.sourceUrl || ""),
      });
      emitCmDebugEvent({
        phase: "cm-tenant-precheck-complete",
        reason: normalizedReason,
        tenantCount: Number(catalog?.tenants?.length || 0),
        sourceUrl: String(catalog?.sourceUrl || ""),
        tokenClientId: String(parseJwtPayload(hydratedToken)?.client_id || ""),
      });
      return catalog;
    } catch (error) {
      const resolvedError = error instanceof Error ? error : new Error(String(error));
      state.cmTenantsPrecheckLastError = resolvedError.message;
      setUnderparDiagnosticMarker("cm_precheck", {
        status: "error",
        reason: normalizedReason,
        phase: "failed",
        error: resolvedError.message,
      });
      emitCmDebugEvent({
        phase: "cm-tenant-precheck-error",
        reason: normalizedReason,
        error: resolvedError.message,
      });
      throw resolvedError;
    } finally {
      state.cmTenantsPrecheckPending = false;
      syncMediaCompanySelectAvailability();
      if (state.avatarMenuOpen) {
        renderAvatarMenu();
      }
      if (state.cmTenantsPrecheckPromise === precheckPromise) {
        state.cmTenantsPrecheckPromise = null;
      }
    }
  })();

  state.cmTenantsPrecheckPromise = precheckPromise;
  return precheckPromise;
}

async function persistResolvedCmGlobalAuthState(accessToken = "", source = "unknown") {
  const normalizedAccessToken = normalizeBearerTokenValue(accessToken);
  if (!normalizedAccessToken || !tokenSupportsCmConsoleRequests(normalizedAccessToken)) {
    return null;
  }

  const tokenClaims = parseJwtPayload(normalizedAccessToken) || {};
  const resolvedImsSession = mergeImsSessionSnapshots(
    deriveImsSessionSnapshotFromToken(normalizedAccessToken),
    state.loginData?.cmConsoleImsSession && typeof state.loginData.cmConsoleImsSession === "object"
      ? state.loginData.cmConsoleImsSession
      : null
  );

  return persistPassVaultCmGlobalState(
    {
      clientId: CM_IMS_PRIMARY_CLIENT_ID,
      tokenClientId: firstNonEmptyString([tokenClaims?.client_id, tokenClaims?.clientId, CM_IMS_PRIMARY_CLIENT_ID]),
      userId: firstNonEmptyString([resolvedImsSession?.userId, tokenClaims?.user_id, tokenClaims?.userId]),
      scope: firstNonEmptyString([tokenClaims?.scope, state.loginData?.cmConsoleScope]),
      expiresAt:
        coercePositiveNumber(resolveAuthResponseExpiry(normalizedAccessToken, coercePositiveNumber(tokenClaims?.expires_in))?.expiresAt) ||
        coercePositiveNumber(state.loginData?.cmConsoleExpiresAt),
      updatedAt: Date.now(),
      tokenFingerprint: getPreferredCmTokenFingerprint(normalizedAccessToken),
      imsSession: resolvedImsSession,
      source: String(source || "unknown"),
    },
    { silent: true }
  );
}

async function hydrateGlobalCmConsoleBootstrapForActiveSession(reason = "session", options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  const preferredCmBootstrapTabId = Number(options?.preferredCmBootstrapTabId || 0);
  if (state.restricted || !state.loginData) {
    return "";
  }

  const existingToken = normalizeBearerTokenValue(getPreferredCmRequestAccessTokenCandidate());
  if (
    existingToken &&
    tokenSupportsCmConsoleRequests(existingToken) &&
    (!forceRefresh || isAccessTokenFreshEnough(existingToken, 45 * 1000))
  ) {
    await persistResolvedCmGlobalAuthState(existingToken, `existing:${reason}`).catch(() => null);
    emitCmDebugEvent({
      phase: "cm-global-hydrate-token-reuse",
      reason: String(reason || ""),
      tokenClientId: String(parseJwtPayload(existingToken)?.client_id || ""),
    });
    return existingToken;
  }

  const resolvedToken = await settle(() =>
    resolveQualifiedCmConsoleAccessToken(
      state.loginData,
      firstNonEmptyString([state.loginData?.cmConsoleAccessToken, getPreferredPrimaryImsAccessTokenCandidate()]),
      {
        preferredTabId: preferredCmBootstrapTabId,
        allowTemporaryTab: options?.allowTemporaryPageContextTab !== false,
      }
    )
  );
  const tokenResult = resolvedToken.ok ? buildCmConsoleBootstrapResult(resolvedToken.value?.token, resolvedToken.value?.source) : null;
  const hydratedToken = normalizeBearerTokenValue(await persistCmTokenBootstrapResult(tokenResult || {}, {}));
  if (hydratedToken && tokenSupportsCmConsoleRequests(hydratedToken)) {
    await persistResolvedCmGlobalAuthState(hydratedToken, `post-login:${reason}`).catch(() => null);
    emitCmDebugEvent({
      phase: "cm-global-hydrate-token-ready",
      reason: String(reason || ""),
      tokenClientId: String(parseJwtPayload(hydratedToken)?.client_id || ""),
      source: String(tokenResult?.source || ""),
    });
    return hydratedToken;
  }

  return "";
}

function populateMediaCompanySelect() {
  state.selectedMvpdId = "";

  const options = [...state.programmers]
    .map((item) => ({
      value: item.key,
      text: firstNonEmptyString([item.label, item.programmerName, item.programmerId]),
    }))
    .sort((left, right) => left.text.localeCompare(right.text, undefined, { sensitivity: "base" }));

  els.mediaCompanySelect.innerHTML = "";
  const defaultOption = document.createElement("option");
  defaultOption.value = "";
  defaultOption.textContent = getMediaCompanySelectDefaultLabel();
  els.mediaCompanySelect.appendChild(defaultOption);

  for (const optionValue of options) {
    const option = document.createElement("option");
    option.value = optionValue.value;
    option.textContent = optionValue.text;
    option.dataset.baseLabel = optionValue.text;
    els.mediaCompanySelect.appendChild(option);
  }

  applyMediaCompanyOptionHydrationState();
  syncMediaCompanySelectAvailability();

  els.requestorSelect.disabled = true;
  els.requestorSelect.innerHTML = '<option value=""></option>';

  els.mvpdSelect.disabled = true;
  els.mvpdSelect.innerHTML = '<option value=""></option>';
  syncGlobalQuickLaunchButtons();
  renderPremiumServices(null);
  refreshRestV2LoginPanels();
  refreshMvpdWorkspaceTools();
}

function getRequestorsForSelectedMediaCompany() {
  const programmer = resolveSelectedProgrammer();
  if (!programmer) {
    return [];
  }

  const requestorOptions = Array.isArray(programmer.requestorOptions)
    ? programmer.requestorOptions
        .filter((option) => option && typeof option === "object")
        .map((option) => ({
          key: String(firstNonEmptyString([option.key, option.id]) || "").trim(),
          id: String(firstNonEmptyString([option.id, option.key]) || "").trim(),
          label: firstNonEmptyString([option.label, option.name, option.id, option.key]),
        }))
        .filter((option) => option.id)
    : [];

  if (requestorOptions.length > 0) {
    return requestorOptions.sort((left, right) =>
      String(firstNonEmptyString([left.label, left.id])).localeCompare(
        String(firstNonEmptyString([right.label, right.id])),
        undefined,
        { sensitivity: "base" }
      )
    );
  }

  return uniqueSorted(programmer.requestorIds || []).map((requestorId) => ({
    key: requestorId,
    id: requestorId,
    label: requestorId,
  }));
}

function populateRequestorSelect() {
  state.selectedMvpdId = "";
  const requestorOptions = getRequestorsForSelectedMediaCompany();
  const selectedRequestorId = String(state.selectedRequestorId || "").trim();

  els.requestorSelect.innerHTML = "";
  const defaultOption = document.createElement("option");
  defaultOption.value = "";
  defaultOption.textContent = "";
  els.requestorSelect.appendChild(defaultOption);

  for (const requestor of requestorOptions) {
    const option = document.createElement("option");
    option.value = String(requestor.id || requestor.key || "").trim();
    option.textContent = firstNonEmptyString([requestor.label, requestor.id, requestor.key]);
    els.requestorSelect.appendChild(option);
  }

  els.requestorSelect.disabled = requestorOptions.length === 0;
  if (selectedRequestorId && requestorOptions.some((option) => String(option.id || "").trim() === selectedRequestorId)) {
    els.requestorSelect.value = selectedRequestorId;
  } else {
    state.selectedRequestorId = "";
    els.requestorSelect.value = "";
  }

  els.mvpdSelect.disabled = true;
  els.mvpdSelect.innerHTML = '<option value=""></option>';
  syncGlobalQuickLaunchButtons();
  refreshRestV2LoginPanels();
  refreshMvpdWorkspaceTools();
}

function getCmMvpdSelectionKey(programmerId = "", requestorId = "", mvpdId = "") {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedRequestorId = String(requestorId || "").trim();
  const normalizedMvpdId = String(mvpdId || "").trim();
  if (!normalizedProgrammerId || !normalizedRequestorId || !normalizedMvpdId) {
    return "";
  }
  return `${normalizedProgrammerId}|${normalizedRequestorId}|${normalizedMvpdId}`;
}

function buildCurrentCmMvpdSelectionKey(programmer = null) {
  const resolvedProgrammer = programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
  return getCmMvpdSelectionKey(
    String(resolvedProgrammer?.programmerId || "").trim(),
    String(state.selectedRequestorId || "").trim(),
    String(state.selectedMvpdId || "").trim()
  );
}

function settlePromiseWithin(promise, timeoutMs = 0, fallbackValue = null) {
  if (!promise || typeof promise.then !== "function") {
    return Promise.resolve(fallbackValue);
  }

  const normalizedTimeoutMs = Math.max(0, Number(timeoutMs || 0));
  if (!normalizedTimeoutMs) {
    return Promise.resolve(promise).catch(() => fallbackValue);
  }

  return new Promise((resolve) => {
    let settled = false;
    const finish = (value) => {
      if (settled) {
        return;
      }
      settled = true;
      if (timerId) {
        window.clearTimeout(timerId);
      }
      resolve(value);
    };
    const timerId = window.setTimeout(() => finish(fallbackValue), normalizedTimeoutMs);
    Promise.resolve(promise)
      .then((value) => finish(value))
      .catch(() => finish(fallbackValue));
  });
}

async function settle(fn) {
  try {
    return {
      ok: true,
      value: await fn(),
    };
  } catch (error) {
    return {
      ok: false,
      error,
    };
  }
}

async function refreshProgrammerPanels(options = {}) {
  const programmer = resolveSelectedProgrammer();
  const forcePremiumRefresh = options.forcePremiumRefresh === true;
  const skipCmBootstrap = options.skipCmBootstrap === true;
  const controllerReason = String(options?.controllerReason || "").trim();
  const requestToken = ++state.premiumPanelRequestToken;
  const cmMvpdSelectionKey = buildCurrentCmMvpdSelectionKey(programmer);
  if (forcePremiumRefresh) {
    state.cmTenantBundleByTenantKey.clear();
    state.cmTenantBundlePromiseByTenantKey.clear();
    state.cmUsageWarmStateByProgrammerId.clear();
    state.cmServiceByMvpdSelectionKey.clear();
    state.cmServiceLoadPromiseByMvpdSelectionKey.clear();
  }

  if (!programmer) {
    renderPremiumServices(null, null, { controllerReason });
    return;
  }
  const programmerId = String(programmer?.programmerId || "").trim();
  const retainedConsoleTabId = Number(options.preferredTabId || 0);
  const programmerApplicationsPromise =
    options.programmerApplicationsPromise && typeof options.programmerApplicationsPromise.then === "function"
      ? options.programmerApplicationsPromise
      : ensureSelectedProgrammerApplicationsLoaded(programmer, {
          forceRefresh: forcePremiumRefresh,
          allowTemporaryPageContextTab: false,
          preferredTabId: retainedConsoleTabId,
          requestTimeoutMs: PREMIUM_APPLICATIONS_FETCH_TIMEOUT_MS,
        });
  setProgrammerWorkspaceHydrationReady(programmerId, false);
  clearProgrammerPremiumHydrationProgress(programmerId);
  esmWorkspaceBroadcastSelectedControllerState(programmer, null, 0, { controllerReason });
  cmBroadcastSelectedControllerState(programmer, null, 0, {
    controllerReason,
    cmAvailabilityResolved: false,
    cmContainerVisible: null,
  });
  mvpdWorkspaceBroadcastSelectedControllerState(programmer, null);

  let provisionalServices = forcePremiumRefresh ? null : getCurrentPremiumAppsSnapshot(programmerId);
  const mergeSelectionServices = (baseServices = null, nextCmService = null, nextCmMvpdService = null) => ({
    ...(baseServices && typeof baseServices === "object" ? baseServices : {}),
    cm: selectPreferredCmRuntimeService(baseServices?.cm, nextCmService),
    cmMvpd: selectPreferredCmRuntimeService(baseServices?.cmMvpd, nextCmMvpdService),
    cmMvpdSelectionKey,
  });
  const summarizeSelectionServices = (baseServices = null, nextCmService = null, nextCmMvpdService = null) =>
    applyPremiumServiceRuntimeSummary(
      programmer,
      mergeSelectionServices(baseServices, nextCmService, nextCmMvpdService),
      {
        cmCatalog: state.cmTenantsCatalog,
      }
    );
  const updateSelectionServicesSnapshot = (baseServices = null, nextCmService = null, nextCmMvpdService = null) => {
    const resolvedServices = summarizeSelectionServices(baseServices, nextCmService, nextCmMvpdService);
    setCurrentPremiumAppsSnapshot(programmerId, resolvedServices);
    provisionalServices = resolvedServices;
    emitPremiumServiceDecisionLogs(programmer, resolvedServices);
    return resolvedServices;
  };
  const computePersistedHydrationStatus = (services = null) => {
    return isProgrammerRuntimeServicesReady(programmerId, services)
      ? UNDERPAR_VAULT_STATUS_COMPLETE
      : UNDERPAR_VAULT_STATUS_PARTIAL;
  };
  const selectionStillCurrent = () =>
    requestToken === state.premiumPanelRequestToken &&
    String(resolveSelectedProgrammer()?.programmerId || "").trim() === programmerId;

  if (!provisionalServices && !forcePremiumRefresh) {
    const vaultRecord = getPassVaultMediaCompanyRecord(programmerId);
    const vaultedServices = markPassVaultBackedValue(
      buildPassVaultRuntimeServicesSnapshot(vaultRecord),
      vaultRecord
    );
    if (vaultedServices) {
      provisionalServices = vaultedServices;
      setCurrentPremiumAppsSnapshot(programmerId, vaultedServices);

      const vaultedApplications = markPassVaultBackedValue(
        buildPassVaultApplicationsSnapshotFromRegisteredApplications(
          getPassVaultRegisteredApplicationsByGuid(vaultRecord)
        ),
        vaultRecord
      );
      if (
        vaultedApplications &&
        typeof vaultedApplications === "object" &&
        !Array.isArray(vaultedApplications) &&
        Object.keys(vaultedApplications).length > 0 &&
        !getCurrentProgrammerApplicationsSnapshot(programmerId)
      ) {
        setCurrentProgrammerApplicationsSnapshot(programmerId, vaultedApplications);
      }
    }
  }

  const cachedCmService =
    state.cmServiceByProgrammerId.get(programmerId) ||
    provisionalServices?.cm ||
    buildPassVaultRuntimeCmServiceSnapshot(getPassVaultMediaCompanyRecord(programmerId)) ||
    null;
  const cachedCmMvpdService = cmMvpdSelectionKey
    ? state.cmServiceByMvpdSelectionKey.get(cmMvpdSelectionKey) || provisionalServices?.cmMvpd || null
    : provisionalServices?.cmMvpd || null;
  const provisionalUiServices =
    !forcePremiumRefresh &&
    provisionalServices &&
    shouldRenderPremiumServicesUi(programmerId, provisionalServices)
      ? updateSelectionServicesSnapshot(provisionalServices, cachedCmService, cachedCmMvpdService)
      : null;
  const reusableServices =
    provisionalUiServices && !shouldForceLivePassVaultProgrammerHydration(programmerId)
      ? provisionalUiServices
      : null;
  if (reusableServices) {
    clearProgrammerPremiumHydrationProgress(programmerId);
    setProgrammerWorkspaceHydrationReady(programmerId, true);
    clearStatusUnlessCmTenantsPrecheckBlocked();
    renderPremiumServices(reusableServices, programmer, { controllerReason });
    return;
  }

  if (provisionalUiServices) {
    const provisionalRuntimeReady = isProgrammerRuntimeServicesReady(programmerId, provisionalUiServices);
    setProgrammerWorkspaceHydrationReady(programmerId, provisionalRuntimeReady);
    renderPremiumServices(provisionalUiServices, programmer, { controllerReason });
  }

  setProgrammerPremiumHydrationProgress(programmerId, {
    step: "detect",
    label: "Detecting premium services...",
  });
  if (!provisionalUiServices) {
    renderPremiumServicesLoading(programmer, { controllerReason });
  }

  try {
    const cmSelectionBootstrapPromise = skipCmBootstrap
      ? Promise.resolve(state.cmTenantsCatalog)
      : ensureCmTenantsPrecheckForActiveSession(`panel-selection:${programmerId}`, {
          forceRefresh: forcePremiumRefresh,
          allowTemporaryPageContextTab: false,
        }).catch(() => null);
    const applicationsData = await programmerApplicationsPromise;
    if (!selectionStillCurrent()) {
      return;
    }

    setCurrentProgrammerApplicationsSnapshot(programmerId, applicationsData);
    const existingRecord = getPassVaultMediaCompanyRecord(programmerId);
    const registeredApplications = buildPassVaultHydrationRegisteredApplications(applicationsData);
    provisionalServices = updateSelectionServicesSnapshot(
      buildPassVaultDirectPremiumServicesSnapshot(
        programmer,
        registeredApplications,
        buildPassVaultServiceHydrationEntries({
          programmer,
          registeredApplications,
          existingRecord,
        }),
        {
          cmServiceSnapshot: cachedCmService,
          cmMvpdServiceSnapshot: cachedCmMvpdService,
          cmMvpdSelectionKey,
        }
      ),
      cachedCmService,
      cachedCmMvpdService
    );
    if (!selectionStillCurrent()) {
      return;
    }

    const provisionalRuntimeReady = isProgrammerRuntimeServicesReady(programmerId, provisionalServices);
    setProgrammerWorkspaceHydrationReady(programmerId, provisionalRuntimeReady);
    renderPremiumServices(provisionalServices, programmer, { controllerReason });

    const premiumHydrationPromise = primeProgrammerServiceHydration(programmer, provisionalServices, {
      forceRefresh: forcePremiumRefresh,
      controllerReason: controllerReason || "panel-selection",
      requestToken,
      renderOnReady: false,
      preferredTabId: retainedConsoleTabId,
      applicationsData,
    });

    let resolvedServices = await premiumHydrationPromise;
    if (!selectionStillCurrent()) {
      return;
    }

    const finalServices = updateSelectionServicesSnapshot(resolvedServices, cachedCmService, cachedCmMvpdService);
    const runtimeReady = isProgrammerRuntimeServicesReady(programmerId, finalServices);
    const uiReady = shouldRenderPremiumServicesUi(programmerId, finalServices);
    if (!uiReady) {
      throw new Error("UnderPAR could not finish premium service hydration.");
    }

    clearProgrammerPremiumHydrationProgress(programmerId);
    setProgrammerWorkspaceHydrationReady(programmerId, runtimeReady);
    clearStatusUnlessCmTenantsPrecheckBlocked();
    renderPremiumServices(finalServices, programmer, { controllerReason });
    void persistPassVaultProgrammerRecord(programmer, finalServices, {
      source: "live",
      hydrationStatus: computePersistedHydrationStatus(finalServices),
    }).catch(() => {});

    const cmSelectionReadyPromise = skipCmBootstrap
      ? Promise.resolve(null)
      : Promise.resolve(cmSelectionBootstrapPromise).catch(() => null);
    const cmServicePromise = skipCmBootstrap
      ? Promise.resolve(cachedCmService)
      : cmSelectionReadyPromise.then(() =>
          ensureCmServiceForProgrammer(programmer, {
            forceRefresh: forcePremiumRefresh,
          }).catch(() => state.cmServiceByProgrammerId.get(programmerId) || cachedCmService)
        );
    const cmMvpdServicePromise =
      skipCmBootstrap || !cmMvpdSelectionKey
        ? Promise.resolve(cachedCmMvpdService)
        : cmSelectionReadyPromise.then(() =>
            ensureCmServiceForSelectedMvpd(programmer, {
              forceRefresh: forcePremiumRefresh,
            }).catch(() => state.cmServiceByMvpdSelectionKey.get(cmMvpdSelectionKey) || cachedCmMvpdService)
          );
    const cmHydrationPromise = Promise.allSettled([cmServicePromise, cmMvpdServicePromise]).then((cmResults) => {
      const nextCmService = selectPreferredCmRuntimeService(
        finalServices?.cm,
        cmResults[0]?.status === "fulfilled" ? cmResults[0].value : cachedCmService
      );
      const nextCmMvpdService = selectPreferredCmRuntimeService(
        finalServices?.cmMvpd,
        cmResults[1]?.status === "fulfilled" ? cmResults[1].value : cachedCmMvpdService
      );
      if (skipCmBootstrap || !shouldShowCmService(nextCmService)) {
        return null;
      }
      return ensureCmHydratedForProgrammer(
        programmer,
        mergeSelectionServices(finalServices, nextCmService, nextCmMvpdService),
        {
          forceRefresh: forcePremiumRefresh,
          reason: "panel-selection",
        }
      ).catch(() => null);
    });

    void Promise.allSettled([cmServicePromise, cmMvpdServicePromise, cmHydrationPromise]).then((results) => {
      if (!selectionStillCurrent()) {
        return;
      }
      const currentServices = getCurrentPremiumAppsSnapshot(programmerId) || finalServices;
      const refreshedCmService = selectPreferredCmRuntimeService(
        currentServices?.cm,
        results[0]?.status === "fulfilled" ? results[0].value : null
      );
      const refreshedCmMvpdService = selectPreferredCmRuntimeService(
        currentServices?.cmMvpd,
        results[1]?.status === "fulfilled" ? results[1].value : null
      );
      const hydratedCmServices =
        results[2]?.status === "fulfilled" && results[2].value?.services && typeof results[2].value.services === "object"
          ? results[2].value.services
          : null;
      const nextServices = updateSelectionServicesSnapshot(
        hydratedCmServices || currentServices,
        refreshedCmService,
        refreshedCmMvpdService
      );
      renderPremiumServices(nextServices, programmer, { controllerReason });
      void persistPassVaultProgrammerRecord(programmer, nextServices, {
        source: "live",
        hydrationStatus: computePersistedHydrationStatus(nextServices),
      }).catch(() => {});
    });
  } catch (error) {
    if (!selectionStillCurrent()) {
      return;
    }
    if (provisionalServices && typeof provisionalServices === "object") {
      const message = error instanceof Error ? error.message : String(error);
      const suppressAccessDeniedStatus =
        isAdobeConsoleAccessDeniedMessage(message) &&
        (shouldShowCmService(provisionalServices?.cm) || shouldShowCmService(provisionalServices?.cmMvpd));
      if (suppressAccessDeniedStatus) {
        clearStatusUnlessCmTenantsPrecheckBlocked();
      } else {
        setStatus(message, "error");
      }
      emitPremiumServiceDecisionLogs(programmer, provisionalServices);
      if (shouldRenderPremiumServicesUi(programmerId, provisionalServices)) {
        renderPremiumServices(provisionalServices, programmer, { controllerReason });
      } else {
        renderPremiumServicesError(error, { controllerReason });
      }
      return;
    }
    renderPremiumServicesError(error, { controllerReason });
  }
}

function extractApplicationGuid(appReference) {
  const value = String(appReference || "").trim();
  const match = value.match(/^@?RegisteredApplication:(.+)$/i);
  if (match) {
    return match[1];
  }
  const tokenMatch = value.match(/@?RegisteredApplication:([A-Za-z0-9-]+)/i);
  if (tokenMatch) {
    return tokenMatch[1];
  }
  return value || null;
}

function resolveApplicationGuidFromEntityData(applicationData = null) {
  if (!applicationData || typeof applicationData !== "object") {
    return "";
  }

  const candidates = [
    applicationData.id,
    applicationData.guid,
    applicationData.applicationId,
    applicationData.application_id,
    applicationData.appId,
    applicationData.registeredApplicationId,
    applicationData.registered_application_id,
    applicationData.entityId,
    applicationData.__underparEntityKey,
    applicationData.key,
  ];

  for (const candidate of candidates) {
    const guid = extractApplicationGuid(candidate);
    if (guid) {
      return guid;
    }
  }

  return "";
}

function normalizeEntityToken(value) {
  return String(value || "").trim().toLowerCase();
}

function extractEntityIdFromToken(value) {
  const text = String(value || "").trim();
  const prefixed = text.match(/^@[^:]+:(.+)$/);
  if (prefixed) {
    return String(prefixed[1] || "").trim();
  }
  return text;
}

function collectRestV2ServiceProviderCandidatesFromApp(appInfo, programmerId) {
  const candidates = [];
  const seen = new Set();

  const pushValue = (value) => {
    if (value == null) {
      return;
    }
    if (Array.isArray(value)) {
      value.forEach((item) => pushValue(item));
      return;
    }
    if (typeof value === "object") {
      return;
    }

    const id = extractEntityIdFromToken(value);
    if (!id) {
      return;
    }

    const key = normalizeEntityToken(id);
    if (!key || seen.has(key)) {
      return;
    }

    seen.add(key);
    candidates.push(id);
  };

  pushValue(appInfo?.appData?.serviceProviders);
  pushValue(appInfo?.appData?.contentProviders);
  pushValue(appInfo?.appData?.requestors);
  pushValue(appInfo?.appData?.requestorIds);
  pushValue(appInfo?.appData?.requestor);
  pushValue(appInfo?.appData?.serviceProvider);
  pushValue(collectPassVaultServiceProviderHintsFromAppData(appInfo?.appData, appInfo?.softwareStatement));

  if (programmerId) {
    pushValue(programmerId);
  }

  return candidates;
}

function appSupportsServiceProvider(appInfo, serviceProviderId, programmerId) {
  const normalizedTarget = normalizeEntityToken(serviceProviderId);
  if (!normalizedTarget) {
    return false;
  }

  const candidates = collectRestV2ServiceProviderCandidatesFromApp(appInfo, programmerId);
  return candidates.some((candidate) => normalizeEntityToken(candidate) === normalizedTarget);
}

function resolveRestV2AppForServiceProvider(restV2Apps, serviceProviderId, programmerId) {
  if (!Array.isArray(restV2Apps) || restV2Apps.length === 0) {
    return null;
  }

  const matched = restV2Apps.find((appInfo) =>
    appSupportsServiceProvider(appInfo, serviceProviderId, programmerId)
  );
  if (matched) {
    return matched;
  }

  return restV2Apps[0];
}

function selectPreferredRestV2AppForRequestor(restV2Apps, requestorId = "", programmerId = "") {
  const candidates = Array.isArray(restV2Apps) ? restV2Apps.filter((item) => item?.guid) : [];
  if (candidates.length === 0) {
    return null;
  }

  const normalizedRequestorId = String(requestorId || "").trim();
  const normalizedProgrammerId = String(programmerId || "").trim();
  const cachedAuthContext = normalizedRequestorId ? getRequestorScopedRestV2AuthContext(normalizedRequestorId) : null;
  if (
    cachedAuthContext &&
    cachedAuthContext.preferredAppGuid &&
    (!normalizedProgrammerId || String(cachedAuthContext.programmerId || "").trim() === normalizedProgrammerId)
  ) {
    const cachedMatch = candidates.find((item) => item.guid === cachedAuthContext.preferredAppGuid) || null;
    if (cachedMatch) {
      return cachedMatch;
    }
  }

  if (normalizedRequestorId) {
    const mapped =
      candidates.find((appInfo) => appSupportsServiceProvider(appInfo, normalizedRequestorId, normalizedProgrammerId)) ||
      null;
    if (mapped) {
      return mapped;
    }
  }

  return candidates[0] || null;
}

function normalizeScope(scope) {
  const normalized = String(scope || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
  if (!normalized) {
    return "";
  }
  return PREMIUM_SERVICE_SCOPE_ALIAS_BY_LABEL[normalized] || normalized;
}

function tokenizeScopeCandidate(value = "") {
  const normalizedValue = String(value || "").replace(/\s+/g, " ").trim();
  if (!normalizedValue) {
    return [];
  }

  const tokens = new Set();
  const pushToken = (candidate) => {
    const normalizedCandidate = String(candidate || "").replace(/\s+/g, " ").trim();
    if (normalizedCandidate) {
      tokens.add(normalizedCandidate);
    }
  };

  pushToken(normalizedValue);
  normalizedValue
    .split(/[,\n;]+/)
    .map((part) => String(part || "").trim())
    .filter(Boolean)
    .forEach((part) => {
      pushToken(part);
      if (!/\s/.test(part)) {
        return;
      }
      const pieces = part.split(/\s+/).filter(Boolean);
      if (pieces.length > 1 && pieces.every((piece) => /[:._-]/.test(piece))) {
        pieces.forEach((piece) => pushToken(piece));
      }
    });

  return [...tokens];
}

const REGISTERED_APPLICATION_SCOPE_FIELD_PATHS = [
  ["scopes"],
  ["scope"],
  ["scopeSet"],
  ["scopeList"],
  ["permissions"],
  ["client", "scopes"],
  ["client", "scope"],
  ["client", "scopeSet"],
  ["client", "scopeList"],
  ["client", "permissions"],
  ["clientApplication", "scopes"],
  ["clientApplication", "scope"],
  ["clientApplication", "scopeSet"],
  ["clientApplication", "scopeList"],
  ["clientApplication", "permissions"],
  ["credentials", "scopes"],
  ["credentials", "scope"],
  ["credentials", "scopeSet"],
  ["credentials", "scopeList"],
  ["credentials", "permissions"],
  ["dcr", "scopes"],
  ["dcr", "scope"],
  ["dcr", "scopeSet"],
  ["dcr", "scopeList"],
  ["dcr", "permissions"],
  ["oauth", "scopes"],
  ["oauth", "scope"],
  ["oauth", "scopeSet"],
  ["oauth", "scopeList"],
  ["oauth", "permissions"],
  ["registeredClient", "scopes"],
  ["registeredClient", "scope"],
  ["registeredClient", "scopeSet"],
  ["registeredClient", "scopeList"],
  ["registeredClient", "permissions"],
  ["__rawEnvelope", "entityData", "scopes"],
  ["__rawEnvelope", "entityData", "scope"],
  ["__rawEnvelope", "entityData", "scopeSet"],
  ["__rawEnvelope", "entityData", "scopeList"],
  ["__rawEnvelope", "entityData", "permissions"],
  ["__rawEnvelope", "scopes"],
  ["__rawEnvelope", "scope"],
  ["__rawEnvelope", "scopeSet"],
  ["__rawEnvelope", "scopeList"],
  ["__rawEnvelope", "permissions"],
];

const REGISTERED_APPLICATION_SCOPE_RELEVANT_FIELD_PATHS = [
  ["client"],
  ["clientApplication"],
  ["registeredClient"],
  ["credentials"],
  ["dcr"],
  ["oauth"],
  ["software"],
  ["claims"],
  ["softwareStatementClaims"],
  ["software_statement_claims"],
  ["__rawEnvelope"],
  ["__rawEnvelope", "entityData"],
  ["__rawEnvelope", "entityData", "client"],
  ["__rawEnvelope", "entityData", "clientApplication"],
  ["__rawEnvelope", "entityData", "registeredClient"],
  ["__rawEnvelope", "entityData", "credentials"],
  ["__rawEnvelope", "entityData", "dcr"],
  ["__rawEnvelope", "entityData", "oauth"],
  ["__rawEnvelope", "entityData", "software"],
];

function getValueAtPath(source, path = []) {
  let current = source;
  for (const key of Array.isArray(path) ? path : []) {
    if (!current || typeof current !== "object") {
      return undefined;
    }
    current = current[key];
  }
  return current;
}

function collectScopeValuesFromValue(value, target = [], seenObjects = new Set()) {
  if (value == null) {
    return target;
  }
  if (Array.isArray(value)) {
    value.forEach((item) => collectScopeValuesFromValue(item, target, seenObjects));
    return target;
  }
  if (typeof value === "object") {
    if (seenObjects.has(value)) {
      return target;
    }
    seenObjects.add(value);
    collectScopeValuesFromValue(value.key, target, seenObjects);
    collectScopeValuesFromValue(value.value, target, seenObjects);
    collectScopeValuesFromValue(value.scope, target, seenObjects);
    collectScopeValuesFromValue(value.scopes, target, seenObjects);
    collectScopeValuesFromValue(value.scopeSet, target, seenObjects);
    collectScopeValuesFromValue(value.scopeList, target, seenObjects);
    collectScopeValuesFromValue(value.permissions, target, seenObjects);
    return target;
  }
  if (typeof value === "string") {
    tokenizeScopeCandidate(value).forEach((part) => target.push(part));
  }
  return target;
}

function getExplicitScopesFromApplication(appData) {
  if (!appData || typeof appData !== "object") {
    return [];
  }

  const rawCandidates = [];
  const seenObjects = new Set();
  REGISTERED_APPLICATION_SCOPE_FIELD_PATHS.forEach((path) => {
    collectScopeValuesFromValue(getValueAtPath(appData, path), rawCandidates, seenObjects);
  });

  return Array.from(new Set(rawCandidates.map((scope) => normalizeScope(scope)).filter(Boolean)));
}

function getDetectionScopesFromApplication(appData) {
  if (!appData || typeof appData !== "object") {
    return [];
  }

  const rawCandidates = [];
  const seenObjects = new Set();
  [appData?.scopes].forEach((value) => {
    collectScopeValuesFromValue(value, rawCandidates, seenObjects);
  });

  return Array.from(new Set(rawCandidates.map((scope) => normalizeScope(scope)).filter(Boolean)));
}

function buildRegisteredApplicationScopeLabels(scopes = []) {
  const normalizedScopes = Array.isArray(scopes)
    ? scopes.map((scope) => String(scope || "").trim()).filter(Boolean)
    : [];
  return ["DEFAULT", ...normalizedScopes.map((scope) => REGISTERED_APPLICATION_SCOPE_LABELS[scope] || scope)].filter(
    Boolean
  );
}

function buildRegisteredApplicationLabel(name = "", scopeLabels = [], fallbackLabel = "") {
  const normalizedName = firstNonEmptyString([name]);
  const scopeSummary = (Array.isArray(scopeLabels) ? scopeLabels : []).filter(Boolean).join(", ");
  return scopeSummary ? `${normalizedName} | ${scopeSummary}` : firstNonEmptyString([fallbackLabel, normalizedName]);
}

function collectKnownScopeMatchesFromSerializedValue(value, target = new Set(), seenObjects = new Set()) {
  if (value == null) {
    return target;
  }

  if (typeof value === "object") {
    if (seenObjects.has(value)) {
      return target;
    }
    seenObjects.add(value);
    try {
      const serialized = JSON.stringify(value).toLowerCase();
      KNOWN_PREMIUM_SERVICE_SCOPES.forEach((scope) => {
        if (serialized.includes(scope)) {
          target.add(scope);
        }
      });
    } catch {
      // Ignore serialization issues.
    }
    if (Array.isArray(value)) {
      value.forEach((item) => collectKnownScopeMatchesFromSerializedValue(item, target, seenObjects));
    } else {
      Object.values(value).forEach((item) => collectKnownScopeMatchesFromSerializedValue(item, target, seenObjects));
    }
    return target;
  }

  const normalizedText = String(value || "").trim().toLowerCase();
  if (normalizedText) {
    KNOWN_PREMIUM_SERVICE_SCOPES.forEach((scope) => {
      if (normalizedText.includes(scope)) {
        target.add(scope);
      }
    });
  }
  return target;
}

function getRelevantSerializedScopeMatchesFromApplication(appData) {
  if (!appData || typeof appData !== "object") {
    return [];
  }

  const matches = new Set();
  const seenObjects = new Set();
  REGISTERED_APPLICATION_SCOPE_RELEVANT_FIELD_PATHS.forEach((path) => {
    collectKnownScopeMatchesFromSerializedValue(getValueAtPath(appData, path), matches, seenObjects);
  });
  return [...matches];
}

function getLegacySerializedScopeMatchesFromApplication(appData) {
  if (!appData || typeof appData !== "object") {
    return [];
  }

  try {
    const serialized = JSON.stringify(appData).toLowerCase();
    return KNOWN_PREMIUM_SERVICE_SCOPES.filter((scope) => serialized.includes(scope));
  } catch {
    return [];
  }
}

function getScopesFromSoftwareStatement(appData) {
  if (!appData || typeof appData !== "object") {
    return [];
  }

  const softwareStatement = extractSoftwareStatementFromAppData(appData);
  if (!softwareStatement) {
    return [];
  }

  const claims = parseJwtPayload(softwareStatement);
  return extractScopeValuesFromTokenClaims(claims);
}

function getScopesFromApplication(appData) {
  if (!appData || typeof appData !== "object") {
    return [];
  }

  const resolved = Array.from(
    new Set(
      [
        ...getExplicitScopesFromApplication(appData),
        ...getScopesFromSoftwareStatement(appData),
        ...getRelevantSerializedScopeMatchesFromApplication(appData),
      ].filter(Boolean)
    )
  );
  if (resolved.length > 0) {
    return resolved;
  }
  return getLegacySerializedScopeMatchesFromApplication(appData);
}

function isProbablyJwt(value) {
  if (!value) {
    return false;
  }
  const token = String(value).trim();
  if (token.length < 60) {
    return false;
  }
  const parts = token.split(".");
  return parts.length === 3 && /^[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+$/.test(token);
}

function extractJwtAndUrls(value) {
  const seen = new Set();
  const jwtCandidates = [];
  const urlCandidates = [];
  const stack = [{ node: value, path: "" }];

  while (stack.length > 0) {
    const { node, path } = stack.pop();

    if (typeof node === "string") {
      const trimmed = node.trim();
      if (isProbablyJwt(trimmed)) {
        const lowerPath = String(path || "").toLowerCase();
        let score = 0;
        if (lowerPath.includes("software") && lowerPath.includes("statement")) {
          score += 100;
        }
        if (lowerPath.includes("software_statement") || lowerPath.includes("softwarestatement")) {
          score += 100;
        }
        if (lowerPath.includes("jwt")) {
          score += 10;
        }
        jwtCandidates.push({ score, value: trimmed });
      }

      if (/^https?:\/\//i.test(trimmed) && /software/i.test(trimmed) && /statement/i.test(trimmed)) {
        urlCandidates.push(trimmed);
      }
      continue;
    }

    if (!node || typeof node !== "object") {
      continue;
    }
    if (seen.has(node)) {
      continue;
    }
    seen.add(node);

    if (Array.isArray(node)) {
      node.forEach((item, index) => {
        stack.push({ node: item, path: `${path}[${index}]` });
      });
      continue;
    }

    Object.entries(node).forEach(([key, nested]) => {
      const nestedPath = path ? `${path}.${key}` : key;
      stack.push({ node: nested, path: nestedPath });
    });
  }

  jwtCandidates.sort((left, right) => right.score - left.score);
  return {
    jwt: jwtCandidates[0]?.value || "",
    jwtScore: Number(jwtCandidates[0]?.score || 0),
    urls: urlCandidates,
  };
}

function extractSoftwareStatementFromAppData(appData) {
  if (!appData || typeof appData !== "object") {
    return "";
  }

  const directCandidates = [
    appData?.softwareStatement,
    appData?.software_statement,
    appData?.softwarestatement,
    appData?.software?.statement,
    appData?.dcr?.softwareStatement,
    appData?.credentials?.softwareStatement,
    appData?.client?.softwareStatement,
    appData?.client?.software_statement,
    appData?.clientApplication?.softwareStatement,
    appData?.clientApplication?.software_statement,
    appData?.registeredClient?.softwareStatement,
    appData?.registeredClient?.software_statement,
    appData?.__rawEnvelope?.softwareStatement,
    appData?.__rawEnvelope?.software_statement,
    appData?.__rawEnvelope?.entityData?.softwareStatement,
    appData?.__rawEnvelope?.entityData?.software_statement,
    appData?.__rawEnvelope?.entityData?.client?.softwareStatement,
    appData?.__rawEnvelope?.entityData?.client?.software_statement,
    appData?.__rawEnvelope?.entityData?.clientApplication?.softwareStatement,
    appData?.__rawEnvelope?.entityData?.clientApplication?.software_statement,
    appData?.__rawEnvelope?.entityData?.registeredClient?.softwareStatement,
    appData?.__rawEnvelope?.entityData?.registeredClient?.software_statement,
    appData?.raw?.softwareStatement,
    appData?.raw?.software_statement,
    appData?.raw?.client?.softwareStatement,
    appData?.raw?.client?.software_statement,
  ];

  for (const candidate of directCandidates) {
    const normalizedCandidate = String(candidate || "").trim();
    if (isProbablyJwt(normalizedCandidate)) {
      return normalizedCandidate;
    }
  }

  const seenObjects = new Set();
  const stack = [appData];
  while (stack.length > 0) {
    const currentNode = stack.pop();
    if (typeof currentNode === "string") {
      const normalizedValue = currentNode.trim();
      if (isProbablyJwt(normalizedValue)) {
        return normalizedValue;
      }
      continue;
    }

    if (!currentNode || typeof currentNode !== "object" || seenObjects.has(currentNode)) {
      continue;
    }
    seenObjects.add(currentNode);

    if (Array.isArray(currentNode)) {
      currentNode.forEach((value) => {
        stack.push(value);
      });
      continue;
    }

    Object.values(currentNode).forEach((value) => {
      stack.push(value);
    });
  }

  return "";
}

function extractSoftwareStatementFromText(text = "") {
  const normalizedText = String(text || "").trim();
  if (!normalizedText) {
    return "";
  }

  if (isProbablyJwt(normalizedText)) {
    return normalizedText;
  }

  try {
    const parsed = JSON.parse(normalizedText);
    if (parsed && typeof parsed === "object") {
      const extracted = extractSoftwareStatementFromAppData(parsed);
      if (extracted) {
        return extracted;
      }
      const dereferenced = extractJwtAndUrls(parsed);
      if (dereferenced.jwt && dereferenced.jwtScore > 0) {
        return dereferenced.jwt;
      }
    }
  } catch {
    // Fall through to direct token extraction.
  }

  const match = normalizedText.match(/[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+/);
  return match && isProbablyJwt(match[0]) ? match[0] : "";
}

function normalizeApplicationsResponse(payload) {
  const normalizeEntity = (item) => {
    const entity = item?.entityData || item;
    if (!entity || typeof entity !== "object") {
      return null;
    }
    const entityKey = String(item?.key || entity?.key || "").trim();
    if (!entityKey) {
      return item && typeof item === "object" && item !== entity ? { ...entity, __rawEnvelope: item } : entity;
    }
    return {
      ...entity,
      __underparEntityKey: entityKey,
      ...(item && typeof item === "object" && item !== entity ? { __rawEnvelope: item } : {}),
    };
  };

  if (Array.isArray(payload)) {
    return payload.map((item) => normalizeEntity(item)).filter((item) => item && typeof item === "object");
  }

  if (Array.isArray(payload?.entities)) {
    return payload.entities.map((item) => normalizeEntity(item)).filter((item) => item && typeof item === "object");
  }

  if (payload && typeof payload === "object") {
    const single = normalizeEntity(payload);
    if (single && typeof single === "object") {
      return [single];
    }
  }

  return [];
}

function normalizeRegisteredApplicationRuntimeRecord(item = null) {
  const source = item && typeof item === "object" && !Array.isArray(item) ? item : null;
  if (!source) {
    return null;
  }

  const guid = resolveApplicationGuidFromEntityData(source);
  const rawEnvelope =
    source?.__rawEnvelope && typeof source.__rawEnvelope === "object" && !Array.isArray(source.__rawEnvelope)
      ? source.__rawEnvelope
      : null;
  const envelopeEntityData =
    rawEnvelope?.entityData && typeof rawEnvelope.entityData === "object" && !Array.isArray(rawEnvelope.entityData)
      ? rawEnvelope.entityData
      : null;
  const appDataSource =
    source?.appData && typeof source.appData === "object" && !Array.isArray(source.appData) ? source.appData : source;
  const appData = {
    ...(envelopeEntityData ? envelopeEntityData : {}),
    ...(appDataSource && typeof appDataSource === "object" ? appDataSource : {}),
  };
  delete appData.appData;

  const id = firstNonEmptyString([guid, source?.id, source?.key]);
  const key = firstNonEmptyString([id, source?.key]);
  const rawScopes = (
    Array.isArray(appData?.scopes) && appData.scopes.length > 0
      ? appData.scopes
      : Array.isArray(source?.scopes)
        ? source.scopes
        : []
  )
    .map((scope) => String(scope || "").trim())
    .filter(Boolean);
  const scopeLabels = buildRegisteredApplicationScopeLabels(rawScopes);
  const appName = firstNonEmptyString([
    appData?.displayName,
    appData?.name,
    appData?.clientId,
    appData?.label,
    appData?.title,
    source?.displayName,
    source?.name,
    source?.clientId,
    source?.label,
    source?.title,
    id ? `Registered Application ${id}` : "",
  ]);
  const softwareStatement = firstNonEmptyString([
    extractSoftwareStatementFromAppData(appData),
    String(source?.softwareStatement || "").trim(),
  ]);
  const fetchOrder = Number(source?.__underparFetchOrder);

  return {
    ...source,
    ...(id ? { id, key, guid: firstNonEmptyString([guid, id]) } : {}),
    ...(appName
      ? {
          name: appName,
          displayName: firstNonEmptyString([appData?.displayName, source?.displayName, appName]),
          label: buildRegisteredApplicationLabel(appName, scopeLabels, firstNonEmptyString([source?.label, appName])),
        }
      : {}),
    clientId: firstNonEmptyString([appData?.clientId, appData?.client_id, source?.clientId, source?.client_id]),
    type: firstNonEmptyString([source?.type, source?.applicationType, appData?.type, appData?.applicationType]),
    ...(Number.isFinite(fetchOrder) && fetchOrder >= 0 ? { __underparFetchOrder: fetchOrder } : {}),
    ...(rawScopes.length > 0 ? { scopes: rawScopes, scopeLabels } : { scopeLabels }),
    ...(softwareStatement ? { softwareStatement } : {}),
    raw:
      source?.raw && typeof source.raw === "object" && !Array.isArray(source.raw)
        ? source.raw
        : appData,
    appData,
  };
}

function normalizeRegisteredApplicationDetailPayload(payload = null) {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
    return null;
  }

  const entityData =
    payload.entityData && typeof payload.entityData === "object" && !Array.isArray(payload.entityData)
      ? payload.entityData
      : payload;
  if (!entityData || typeof entityData !== "object" || Array.isArray(entityData)) {
    return null;
  }

  return {
    ...entityData,
    ...(payload !== entityData ? { __rawEnvelope: payload } : {}),
  };
}

function buildRegisteredApplicationDetailUrlCandidates(guid = "") {
  const normalizedGuid = String(guid || "").trim();
  if (!normalizedGuid) {
    return [];
  }

  const encodedGuid = encodeURIComponent(normalizedGuid);
  return uniquePreserveOrder([
    appendAdobeConsoleConfigurationVersion(`${ADOBE_CONSOLE_BASE}/rest/api/applications/${encodedGuid}`),
    `${ADOBE_CONSOLE_BASE}/rest/api/applications/${encodedGuid}`,
    appendAdobeConsoleConfigurationVersion(`${ADOBE_CONSOLE_BASE}/rest/api/entity/RegisteredApplication/${encodedGuid}`),
    `${ADOBE_CONSOLE_BASE}/rest/api/entity/RegisteredApplication/${encodedGuid}`,
  ]);
}

function mergeHydratedRegisteredApplication(appInfo = null, detailData = null, softwareStatement = "") {
  const baseAppInfo = appInfo && typeof appInfo === "object" && !Array.isArray(appInfo) ? appInfo : {};
  const normalizedDetail =
    detailData && typeof detailData === "object" && !Array.isArray(detailData)
      ? normalizeRegisteredApplicationDetailPayload(detailData) || detailData
      : null;
  const mergedAppData = {
    ...(baseAppInfo?.appData && typeof baseAppInfo.appData === "object" && !Array.isArray(baseAppInfo.appData)
      ? baseAppInfo.appData
      : {}),
    ...(normalizedDetail && typeof normalizedDetail === "object" ? normalizedDetail : {}),
  };
  const mergedRecord =
    normalizeRegisteredApplicationRuntimeRecord({
      ...baseAppInfo,
      ...(normalizedDetail && typeof normalizedDetail === "object" ? normalizedDetail : {}),
      appData: mergedAppData,
      softwareStatement: firstNonEmptyString([
        softwareStatement,
        extractSoftwareStatementFromAppData(normalizedDetail),
        baseAppInfo?.softwareStatement,
        extractSoftwareStatementFromAppData(mergedAppData),
      ]),
    }) || {
      ...baseAppInfo,
      appData: mergedAppData,
    };
  const guid = firstNonEmptyString([
    mergedRecord?.guid,
    mergedRecord?.id,
    resolveApplicationGuidFromEntityData(normalizedDetail),
    resolveApplicationGuidFromEntityData(baseAppInfo),
  ]);

  return {
    ...baseAppInfo,
    ...mergedRecord,
    ...(guid
      ? { guid, id: guid, appRef: firstNonEmptyString([baseAppInfo?.appRef, mergedRecord?.appRef, `@RegisteredApplication:${guid}`]) }
      : {}),
    appData: mergedAppData,
    softwareStatement: firstNonEmptyString([
      mergedRecord?.softwareStatement,
      softwareStatement,
      extractSoftwareStatementFromAppData(mergedAppData),
      baseAppInfo?.softwareStatement,
    ]),
  };
}

async function enrichRegisteredApplicationForHydration(appInfo = null, options = {}) {
  const currentAppInfo =
    appInfo && typeof appInfo === "object" && !Array.isArray(appInfo) ? mergeHydratedRegisteredApplication(appInfo) : null;
  if (!currentAppInfo) {
    return null;
  }

  const guid = firstNonEmptyString([
    currentAppInfo?.guid,
    currentAppInfo?.id,
    resolveApplicationGuidFromEntityData(currentAppInfo?.appData || null),
  ]);
  if (!guid || firstNonEmptyString([currentAppInfo?.softwareStatement])) {
    return currentAppInfo;
  }

  let nextAppInfo = currentAppInfo;
  const requestOptions = options && typeof options === "object" ? options : {};

  try {
    const details = await fetchApplicationDetailsByGuid(guid, requestOptions);
    if (details && typeof details === "object") {
      nextAppInfo = mergeHydratedRegisteredApplication(nextAppInfo, details);
    }
  } catch {
    // Continue to software statement fallback.
  }

  if (!firstNonEmptyString([nextAppInfo?.softwareStatement])) {
    try {
      const softwareStatement = await fetchSoftwareStatementForAppGuid(guid, requestOptions);
      if (softwareStatement) {
        nextAppInfo = mergeHydratedRegisteredApplication(nextAppInfo, null, softwareStatement);
      }
    } catch {
      // Ignore statement fetch failures and return the best hydrated record.
    }
  }

  return nextAppInfo;
}

function getRegisteredApplicationSortLabel(appData = null) {
  return firstNonEmptyString([
    appData?.name,
    appData?.displayName,
    appData?.label,
    appData?.appData?.name,
    appData?.appData?.displayName,
    appData?.appData?.label,
    appData?.guid,
    appData?.id,
  ]);
}

function getAdobeConsoleRequestHeaders(accessToken = "") {
  const headers = {
    Accept: "application/json, text/plain, */*",
    "AP-Request-Id": generateRequestId(),
  };

  if (accessToken) {
    headers.Authorization = `bearer ${accessToken}`;
  }

  const csrfToken = String(state?.consoleCsrfToken || "").trim() || "NO-TOKEN";
  headers["X-CSRF-Token"] = csrfToken;

  return headers;
}

function extractAdobeConsoleGrantedAuthorityValue(entry) {
  if (typeof entry === "string") {
    return entry.trim();
  }
  if (!entry || typeof entry !== "object") {
    return "";
  }
  return firstNonEmptyString([
    entry.authority,
    entry.role,
    entry.name,
    entry.value,
    entry.id,
  ]);
}

function extractAdobeConsoleGrantedAuthorities(payload = null) {
  const candidateArrays = [
    payload?.grantedAuthorities,
    payload?.authorities,
    payload?.roles,
    payload?.profile?.grantedAuthorities,
    payload?.profile?.authorities,
    payload?.profile?.roles,
  ];
  const output = [];
  const seen = new Set();
  candidateArrays.forEach((candidateArray) => {
    (Array.isArray(candidateArray) ? candidateArray : []).forEach((entry) => {
      const normalized = String(extractAdobeConsoleGrantedAuthorityValue(entry) || "").trim();
      const key = normalized.toLowerCase();
      if (!normalized || seen.has(key)) {
        return;
      }
      seen.add(key);
      output.push(normalized);
    });
  });
  return output;
}

async function buildConsoleContext(session, reason = "post-login", options = {}) {
  const currentSession = session && typeof session === "object" ? session : {};
  const previousConsole = currentSession?.console && typeof currentSession.console === "object" ? currentSession.console : {};
  const environment = getActiveAdobePassEnvironment();
  const accessToken = normalizeBearerTokenValue(firstNonEmptyString([currentSession?.accessToken]));
  const hydratedAt = new Date().toISOString();
  const programmerAccess = resolveProgrammerAccessContext(currentSession);
  const preferredTabId = Number(options?.preferredTabId || 0);
  const pageContextTargetRef = { target: null };
  let csrfToken = firstNonEmptyString([previousConsole?.csrfToken, state.consoleCsrfToken, "NO-TOKEN"]);
  let transport = firstNonEmptyString([previousConsole?.transport]);
  let pageContextOrigin = firstNonEmptyString([previousConsole?.pageContextOrigin]);
  let pageContextUrl = firstNonEmptyString([previousConsole?.pageContextUrl]);

  const syncConsoleFetchMeta = (result = null) => {
    if (!result || typeof result !== "object") {
      return;
    }

    const responseHeaders = result?.headers && typeof result.headers === "object" ? result.headers : {};
    const nextCsrfToken = String(
      firstNonEmptyString([
        responseHeaders["x-csrf-token"],
        responseHeaders["X-CSRF-Token"],
        csrfToken,
        state.consoleCsrfToken,
      ]) || ""
    ).trim();
    if (nextCsrfToken) {
      csrfToken = nextCsrfToken;
      state.consoleCsrfToken = nextCsrfToken;
    }
    transport = firstNonEmptyString([result?.shell ? "page-context" : "", result?.transport, transport]);
    pageContextOrigin = firstNonEmptyString([result?.pageContext?.origin, pageContextOrigin]);
    pageContextUrl = firstNonEmptyString([result?.pageContext?.url, pageContextUrl]);
  };

  if (!accessToken) {
    setUnderparDiagnosticMarker("console_bootstrap", {
      status: "skipped",
      phase: "no-access-token",
    });
    return {
      ...previousConsole,
      environmentId: String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key,
      environmentLabel: String(environment?.label || "Production").trim() || "Production",
      baseUrl: ADOBE_CONSOLE_BASE,
      csrfToken: String(state.consoleCsrfToken || "").trim(),
      transport: "",
      pageContextOrigin: "",
      pageContextUrl: "",
      configurationVersion: 0,
      extendedProfile: null,
      roles: [],
      channels: [],
      programmers: [],
      hydratedAt,
      programmerAccess,
      status: "unavailable",
      errors: {
        extendedProfile: "Adobe IMS access token is unavailable.",
        configurationVersion: "Adobe IMS access token is unavailable.",
        channels: "Adobe IMS access token is unavailable.",
        programmers: "Adobe IMS access token is unavailable.",
      },
    };
  }

  const explicitAdobePassRecoveryRequested = shouldOfferAdobePassRecoveryForSession(currentSession);
  if (!shouldHydrateAdobePassWorkflowForSession(currentSession)) {
    setUnderparDiagnosticMarker("console_bootstrap", {
      status: explicitAdobePassRecoveryRequested ? "restricted" : "skipped",
      phase: explicitAdobePassRecoveryRequested ? "org-selection-required" : "non-adobepass-org",
      configurationVersion: 0,
      authoritiesCount: 0,
      hasExtendedProfile: false,
    });
    return {
      ...previousConsole,
      environmentId: String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key,
      environmentLabel: String(environment?.label || "Production").trim() || "Production",
      baseUrl: ADOBE_CONSOLE_BASE,
      csrfToken: String(state.consoleCsrfToken || "").trim(),
      transport: "",
      pageContextOrigin: "",
      pageContextUrl: "",
      configurationVersion: 0,
      extendedProfile: null,
      roles: [],
      channels: [],
      programmers: [],
      hydratedAt,
      programmerAccess,
      status: explicitAdobePassRecoveryRequested ? "org-selection-required" : "skipped",
      errors: {
        extendedProfile: "",
        configurationVersion: "",
        channels: "",
        programmers: "",
      },
    };
  }

  setUnderparDiagnosticMarker("console_bootstrap", {
    status: "pending",
    phase: "fetch",
    forceRefresh: options?.forceRefresh === true,
  });
  log(`Hydrating Adobe Pass console context from ${ADOBE_CONSOLE_BASE} (${reason}).`);

  const buildCommonRequestOptions = () => ({
    timeoutMs: PROGRAMMERS_FETCH_TIMEOUT_MS,
    accessToken,
    preferredTabId,
    pageContextTargetRef,
    headers: {
      Authorization: `bearer ${accessToken}`,
      "X-CSRF-Token": firstNonEmptyString([csrfToken, state.consoleCsrfToken, "NO-TOKEN"]),
    },
  });

  try {
    const extendedProfileResult = await settle(() =>
      fetchAdobeConsoleJsonWithLoginButtonFallback(
        [`${ADOBE_CONSOLE_BASE}/rest/api/user/extendedProfile`],
        "Console extended profile",
        buildCommonRequestOptions()
      )
    );
    if (extendedProfileResult.ok) {
      syncConsoleFetchMeta(extendedProfileResult.value);
    }

    const configurationVersionResult = await settle(() =>
      fetchAdobeConsoleJsonWithLoginButtonFallback(
        [`${ADOBE_CONSOLE_BASE}/rest/api/config/latestActivatedConsoleConfigurationVersion`],
        "Console configuration version",
        buildCommonRequestOptions()
      )
    );
    if (configurationVersionResult.ok) {
      syncConsoleFetchMeta(configurationVersionResult.value);
    }

    const extendedProfile =
      extendedProfileResult.ok && extendedProfileResult.value?.parsed && typeof extendedProfileResult.value.parsed === "object"
        ? extendedProfileResult.value.parsed
        : null;
    const configurationVersion = mvpdWorkspaceExtractConfigurationVersion(configurationVersionResult.ok ? configurationVersionResult.value?.parsed : null, 0);
    const configurationVersionMissingError = configurationVersion > 0
      ? null
      : new Error("Console did not return an activated configuration version.");
    const [channelsResult, programmersResult] =
      configurationVersion > 0
        ? await Promise.all([
            settle(() =>
              fetchConsoleChannelsFromApi({
                accessToken,
                configurationVersion,
                pageContextTargetRef,
                preferredTabId,
              })
            ),
            settle(() =>
              fetchProgrammersFromApi({
                accessToken,
                configurationVersion,
                requireEntities: false,
                pageContextTargetRef,
                preferredTabId,
              })
            ),
          ])
        : [
            {
              ok: false,
              error: configurationVersionMissingError,
            },
            {
              ok: false,
              error: configurationVersionMissingError,
            },
          ];

    const channels = channelsResult.ok ? channelsResult.value : [];
    const programmers = programmersResult.ok ? programmersResult.value : [];
    const roles = extractAdobeConsoleGrantedAuthorities(extendedProfile);
    const errors = {
      extendedProfile: extendedProfileResult.ok ? "" : serializeError(extendedProfileResult.error),
      configurationVersion:
        configurationVersionResult.ok && configurationVersion > 0
          ? ""
          : configurationVersionResult.ok
            ? "Console did not return an activated configuration version."
            : serializeError(configurationVersionResult.error),
      channels: channelsResult.ok ? "" : serializeError(channelsResult.error),
      programmers: programmersResult.ok ? "" : serializeError(programmersResult.error),
    };
    const successfulSegments = [
      extendedProfile ? 1 : 0,
      configurationVersion > 0 ? 1 : 0,
      channelsResult.ok ? 1 : 0,
      programmersResult.ok ? 1 : 0,
    ].reduce((total, value) => total + value, 0);
    const nextConsoleContext = {
      ...previousConsole,
      environmentId: String(environment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.key).trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key,
      environmentLabel: String(environment?.label || "Production").trim() || "Production",
      baseUrl: ADOBE_CONSOLE_BASE,
      csrfToken: String(firstNonEmptyString([csrfToken, state.consoleCsrfToken, ""]) || "").trim(),
      transport,
      pageContextOrigin,
      pageContextUrl,
      configurationVersion,
      extendedProfile,
      roles,
      channels,
      programmers,
      programmersApiEndpoint: firstNonEmptyString([state.programmersApiEndpoint, previousConsole?.programmersApiEndpoint]),
      hydratedAt,
      programmerAccess,
      status: successfulSegments === 4 ? "ready" : successfulSegments > 0 ? "limited" : "unavailable",
      errors,
    };

    setUnderparDiagnosticMarker("console_bootstrap", {
      status: extendedProfile ? "success" : "error",
      phase: extendedProfile ? "complete" : "failed",
      forceRefresh: options?.forceRefresh === true,
      configurationVersion: Number(configurationVersion || 0),
      authoritiesCount: Array.isArray(roles) ? roles.length : 0,
      hasExtendedProfile: Boolean(extendedProfile),
      error: !extendedProfile ? errors.extendedProfile : "",
    });
    return nextConsoleContext;
  } catch (error) {
    const resolvedError = error instanceof Error ? error : new Error(String(error));
    setUnderparDiagnosticMarker("console_bootstrap", {
      status: "error",
      phase: "failed",
      forceRefresh: options?.forceRefresh === true,
      error: resolvedError.message,
    });
    throw resolvedError;
  } finally {
    await closeTemporaryAdobePageContextTarget(pageContextTargetRef?.target?.temporaryTarget || null).catch(() => null);
  }
}

function mergeCmContextIntoLoginData(loginData = {}, cmContext = null) {
  const current = loginData && typeof loginData === "object" ? loginData : {};
  const token = normalizeBearerTokenValue(firstNonEmptyString([cmContext?.cmuToken, current?.cmConsoleAccessToken]));
  if (!token) {
    return current;
  }

  const tokenClaims = parseJwtPayload(token) || {};
  const expiresAt = coercePositiveNumber(Date.parse(firstNonEmptyString([cmContext?.cmuTokenExpiresAt]))) ||
    coercePositiveNumber(resolveAuthResponseExpiry(token, coercePositiveNumber(tokenClaims?.expires_in))?.expiresAt) ||
    coercePositiveNumber(current?.cmConsoleExpiresAt);

  return {
    ...current,
    cmConsoleAccessToken: token,
    cmConsoleExpiresAt: expiresAt,
    cmConsoleScope: compactStorageString(
      firstNonEmptyString([cmContext?.cmuTokenScope, tokenClaims?.scope, current?.cmConsoleScope]),
      2048
    ),
    cmConsoleImsSession: mergeImsSessionSnapshots(
      current?.cmConsoleImsSession && typeof current.cmConsoleImsSession === "object" ? current.cmConsoleImsSession : null,
      {
        ...(deriveImsSessionSnapshotFromToken(token) || {}),
        clientId: firstNonEmptyString([cmContext?.cmuTokenClientId, tokenClaims?.client_id, tokenClaims?.clientId]),
        userId: firstNonEmptyString([cmContext?.cmuTokenUserId, tokenClaims?.user_id, tokenClaims?.userId]),
        scope: firstNonEmptyString([cmContext?.cmuTokenScope, tokenClaims?.scope]),
        expiresAt,
      }
    ),
  };
}

function buildConsoleBootstrapStateFromContext(consoleContext = null, loginData = null) {
  if (!consoleContext || typeof consoleContext !== "object") {
    return null;
  }

  return {
    accessToken: normalizeBearerTokenValue(firstNonEmptyString([loginData?.accessToken])),
    fetchedAt: coercePositiveNumber(Date.parse(firstNonEmptyString([consoleContext?.hydratedAt]))) || Date.now(),
    extendedProfile:
      consoleContext?.extendedProfile && typeof consoleContext.extendedProfile === "object"
        ? consoleContext.extendedProfile
        : null,
    grantedAuthorities: Array.isArray(consoleContext?.roles) ? consoleContext.roles.slice() : [],
    configurationVersion: Number(consoleContext?.configurationVersion || 0),
    channels: Array.isArray(consoleContext?.channels) ? consoleContext.channels.slice() : [],
    programmersApiEndpoint: firstNonEmptyString([consoleContext?.programmersApiEndpoint]),
    errors: {
      extendedProfile: firstNonEmptyString([consoleContext?.errors?.extendedProfile]),
      configurationVersion: firstNonEmptyString([consoleContext?.errors?.configurationVersion]),
      channels: firstNonEmptyString([consoleContext?.errors?.channels]),
      programmers: firstNonEmptyString([consoleContext?.errors?.programmers]),
    },
  };
}

function applyHydratedSessionContextsToState(loginData = null, options = {}) {
  const currentSession = loginData && typeof loginData === "object" ? loginData : state.loginData || null;
  if (!currentSession || typeof currentSession !== "object") {
    return;
  }

  const consoleContext = currentSession?.console && typeof currentSession.console === "object" ? currentSession.console : null;
  const cmContext = currentSession?.cm && typeof currentSession.cm === "object" ? currentSession.cm : null;
  const preserveExistingOnFailure = options?.preserveExistingOnFailure === true;
  const normalizedReason = String(options?.reason || "post-login").trim() || "post-login";
  const consoleProgrammers = Array.isArray(consoleContext?.programmers) ? consoleContext.programmers : [];
  const cmRequiresOrgSelection = cmContext?.status === "org-selection-required";

  state.consoleBootstrapState = buildConsoleBootstrapStateFromContext(consoleContext, currentSession);
  state.consoleCsrfToken = firstNonEmptyString([consoleContext?.csrfToken, state.consoleCsrfToken]);
  state.programmersApiEndpoint = firstNonEmptyString([consoleContext?.programmersApiEndpoint, state.programmersApiEndpoint]);

  if (!(preserveExistingOnFailure && consoleProgrammers.length === 0 && Array.isArray(state.programmers) && state.programmers.length > 0)) {
    applyProgrammerEntities(consoleProgrammers);
  }

  const catalog = buildCmTenantsCatalogFromContext(cmContext, state.cmTenantsCatalog);
  if (catalog) {
    state.cmTenantsCatalog = catalog;
    state.cmTenantsCatalogHydrated = true;
    state.cmTenantsCatalogRuntimeFresh = true;
    state.cmTenantsCatalogFetchAttempted = true;
    syncCmConsoleBootstrapSummaryFromCatalog(catalog, {
      errors: [
        cmContext?.errors?.reports,
        cmContext?.errors?.tenants,
        cmContext?.errors?.cmuToken,
      ].filter(Boolean),
    });
    void persistCmTenantsCatalog(catalog).catch(() => false);
  }

  const cmToken = normalizeBearerTokenValue(
    firstNonEmptyString([currentSession?.cmConsoleAccessToken, cmContext?.cmuToken, state.cmLastHydratedAccessToken])
  );
  const cmCatalogReady = hasCmTenantsCatalogEntries(state.cmTenantsCatalog);
  state.cmTenantsPrecheckPending = false;
  state.cmTenantsPrecheckComplete = cmCatalogReady;
  state.cmTenantsPrecheckLastError = cmCatalogReady || cmRequiresOrgSelection
    ? ""
    : firstNonEmptyString([cmContext?.errors?.tenants, cmContext?.errors?.cmuToken, cmContext?.errors?.reports]);
  state.cmConsoleBootstrapQualified =
    Boolean(cmCatalogReady) && Boolean(cmToken && tokenSupportsCmConsoleRequests(cmToken));
  state.cmLastHydratedAccessToken = cmToken;
  if (cmToken) {
    emitCmConsoleTokenForTesting(cmToken, `post-login-context:${normalizedReason}`);
    void persistResolvedCmGlobalAuthState(cmToken, `post-login-context:${normalizedReason}`).catch(() => null);
  }
  setUnderparDiagnosticMarker("cm_precheck", {
    status: cmCatalogReady ? "success" : cmRequiresOrgSelection ? "restricted" : currentSession?.accessToken ? "error" : "skipped",
    reason: normalizedReason,
    phase: cmCatalogReady ? "complete" : cmRequiresOrgSelection ? "org-selection-required" : currentSession?.accessToken ? "failed" : "no-session",
    tenantCount: Number(state.cmTenantsCatalog?.tenants?.length || 0),
    sourceUrl: String(state.cmTenantsCatalog?.sourceUrl || ""),
    error: cmCatalogReady || cmRequiresOrgSelection ? "" : state.cmTenantsPrecheckLastError,
  });
  syncMediaCompanySelectAvailability();
  syncGlobalQuickLaunchButtons();
}

async function hydratePostLoginSessionData(session, options = {}) {
  const currentSession = session && typeof session === "object" ? session : null;
  if (!currentSession?.accessToken) {
    return currentSession;
  }

  const normalizedReason = String(options?.reason || "post-login").trim() || "post-login";
  const preferredTabId = Number(options?.preferredTabId || 0);
  const allowTemporaryPageContextTab = options?.allowTemporaryPageContextTab === true;
  const [nextConsoleContext, nextCmContext, nextUnifiedShellContext] = await Promise.all([
    buildConsoleContext(currentSession, normalizedReason, {
      preferredTabId,
      forceRefresh: options?.forceRefresh === true,
    }),
    buildCmContext(currentSession, normalizedReason, {
      preferredTabId,
      allowTemporaryTab: allowTemporaryPageContextTab,
    }),
    buildUnifiedShellContext(currentSession, normalizedReason),
  ]);
  const existingOrganizations = resolveCachedOrganizationsFromLoginData(currentSession);
  const activeOrganizationHint = buildRestrictedOrganizationContext(existingOrganizations, currentSession, null).activeOrganization;
  const mergedDetectedOrganizations = mergeRestrictedDetectedOrganizations({
    existingOrganizations: collectCanonicalRestrictedDetectedOrganizations(currentSession, existingOrganizations),
    additionalOrganizations: Array.isArray(nextUnifiedShellContext?.organizations) ? nextUnifiedShellContext.organizations : [],
    activeOrganizationHint,
  });
  const nextLoginData = mergeCmContextIntoLoginData(
    {
      ...currentSession,
      console: nextConsoleContext,
      cm: nextCmContext,
      unifiedShell: nextUnifiedShellContext,
      detectedOrganizations: mergedDetectedOrganizations,
    },
    nextCmContext
  );

  return buildNormalizedLoginData(nextLoginData);
}

function hasAdobeConsoleProgrammerAccess(grantedAuthorities = []) {
  const normalizedAuthorities = (Array.isArray(grantedAuthorities) ? grantedAuthorities : [])
    .map((value) => String(value || "").trim().toUpperCase())
    .filter(Boolean);
  if (normalizedAuthorities.length === 0) {
    return false;
  }
  return normalizedAuthorities.some((value) => ADOBE_CONSOLE_PROGRAMMER_ACCESS_ROLES.includes(value));
}

function captureAdobeConsoleResponseState(response = null) {
  const csrfToken = String(
    firstNonEmptyString([
      response?.headers?.get?.("x-csrf-token"),
      response?.headers?.get?.("X-CSRF-Token"),
    ]) || ""
  ).trim();
  if (csrfToken) {
    state.consoleCsrfToken = csrfToken;
  }
}

function shouldAllowInteractiveConsoleBootstrapForActivation(source = "", explicitAllow = false) {
  if (explicitAllow === true) {
    return true;
  }
  const normalizedSource = String(source || "").trim().toLowerCase();
  if (!normalizedSource) {
    return false;
  }
  return (
    normalizedSource === "interactive" ||
    normalizedSource.includes("interactive") ||
    normalizedSource.includes("restricted") ||
    normalizedSource === "environment-switch"
  );
}

function getAdobeConsoleErrorMessage(parsed, text, statusText = "") {
  return (
    normalizeHttpErrorMessage(
      firstNonEmptyString([
        parsed?.error_description,
        parsed?.error?.description,
        parsed?.error?.message,
        typeof parsed?.error === "string" ? parsed.error : "",
        parsed?.message,
        text,
        statusText,
      ])
    ) || "Request failed."
  );
}

async function fetchWithAbortTimeout(url, init = {}, timeoutMs = 0) {
  const normalizedTimeoutMs = Math.max(0, Number(timeoutMs || 0));
  if (!normalizedTimeoutMs) {
    return fetch(url, init);
  }

  const controller = new AbortController();
  const requestInit = {
    ...init,
    signal: controller.signal,
  };
  const upstreamSignal = init?.signal;
  let removeAbortListener = null;
  if (upstreamSignal && typeof upstreamSignal === "object") {
    if (upstreamSignal.aborted) {
      controller.abort();
    } else if (typeof upstreamSignal.addEventListener === "function") {
      const abortFromUpstream = () => controller.abort();
      upstreamSignal.addEventListener("abort", abortFromUpstream, { once: true });
      removeAbortListener = () => {
        try {
          upstreamSignal.removeEventListener("abort", abortFromUpstream);
        } catch {
          // Ignore listener cleanup issues.
        }
      };
    }
  }

  const timerId = window.setTimeout(() => controller.abort(), Math.max(2000, normalizedTimeoutMs));
  try {
    return await fetch(url, requestInit);
  } finally {
    window.clearTimeout(timerId);
    if (typeof removeAbortListener === "function") {
      removeAbortListener();
    }
  }
}

function isAdobeConsoleTokenExpiredResponse(status, parsed, text = "") {
  if (Number(status) !== 401) {
    return false;
  }

  const errorCode = String(
    firstNonEmptyString([
      parsed?.code,
      parsed?.error_code,
      parsed?.errorCode,
      parsed?.error?.code,
      parsed?.error?.error_code,
      parsed?.error?.errorCode,
    ]) || ""
  )
    .trim()
    .toLowerCase();

  if (errorCode.includes("expired") || errorCode.includes("invalid_token")) {
    return true;
  }

  const normalizedMessage = String(
    firstNonEmptyString([
      parsed?.error_description,
      parsed?.error?.description,
      parsed?.error?.message,
      typeof parsed?.error === "string" ? parsed.error : "",
      parsed?.message,
      text,
    ]) || ""
  )
    .trim()
    .toLowerCase();

  return (
    normalizedMessage.includes("access token is expired") ||
    normalizedMessage.includes("token is expired") ||
    normalizedMessage.includes("expired token") ||
    normalizedMessage.includes("invalid access token")
  );
}

function isAdobeConsoleAccessDeniedResponse(status, parsed, text = "") {
  const normalizedStatus = Number(status || 0);
  if (normalizedStatus !== 401 && normalizedStatus !== 403) {
    return false;
  }

  const payload = parsed && typeof parsed === "object" ? parsed : {};
  const normalizedError = String(
    firstNonEmptyString([
      payload?.error,
      payload?.code,
      payload?.error_code,
      payload?.errorCode,
      payload?.error?.code,
      payload?.error?.error_code,
      payload?.error?.errorCode,
    ]) || ""
  )
    .trim()
    .toLowerCase();
  if (normalizedError === "access_denied" || normalizedError === "unauthorized") {
    return true;
  }

  const normalizedMessage = String(
    firstNonEmptyString([
      payload?.error_description,
      payload?.errorDescription,
      payload?.error?.description,
      payload?.error?.message,
      typeof payload?.error === "string" ? payload.error : "",
      payload?.message,
      text,
    ]) || ""
  )
    .trim()
    .toLowerCase();

  return (
    normalizedMessage.includes("access is denied") ||
    normalizedMessage.includes("access denied") ||
    normalizedMessage.includes("authentication object was not found in the securitycontext") ||
    normalizedMessage.includes("an authentication object was not found in the securitycontext") ||
    normalizedMessage.includes("unauthorized")
  );
}

function isAdobeConsoleAccessDeniedMessage(message = "") {
  const normalizedMessage = String(message || "").trim().toLowerCase();
  if (!normalizedMessage) {
    return false;
  }
  return (
    normalizedMessage.includes("access is denied") ||
    normalizedMessage.includes("access denied") ||
    normalizedMessage.includes("authentication object was not found in the securitycontext") ||
    normalizedMessage.includes("unauthorized") ||
    normalizedMessage.includes("console extended profile failed (401)") ||
    normalizedMessage.includes("console extended profile failed (403)")
  );
}

async function fetchAdobeConsoleJsonWithAuthVariants(urlCandidates, contextLabel, requestOptions = null) {
  const urls = Array.isArray(urlCandidates)
    ? [...new Set(urlCandidates.filter((item) => typeof item === "string" && item.trim()))]
    : [];
  if (urls.length === 0) {
    throw new Error(`${contextLabel} failed: no URL candidates.`);
  }

  const options = requestOptions && typeof requestOptions === "object" ? requestOptions : {};
  const method = String(options.method || "GET")
    .trim()
    .toUpperCase();
  const customHeaders = options.headers && typeof options.headers === "object" ? options.headers : {};
  const body =
    Object.prototype.hasOwnProperty.call(options, "body") && options.body != null
      ? typeof options.body === "string"
        ? options.body
        : JSON.stringify(options.body)
      : undefined;
  const credentials = String(options.credentials || "include");
  const mode = String(options.mode || "cors");
  const timeoutMs = Math.max(0, Number(options.timeoutMs || 0));
  const explicitAuthorization = firstNonEmptyString([customHeaders.Authorization, customHeaders.authorization]);
  const explicitAccessToken = normalizeBearerTokenValue(explicitAuthorization.replace(/^Bearer\s+/i, ""));
  const activeAccessToken = normalizeBearerTokenValue(
    firstNonEmptyString([
      explicitAccessToken,
      options.accessToken,
      getPreferredAdobeConsoleAccessTokenCandidate(),
      state.loginData?.accessToken,
    ])
  );
  if (!activeAccessToken || !isProbablyJwt(activeAccessToken)) {
    throw new Error(`${contextLabel} failed: Adobe Pass console request is missing a valid IMS bearer.`);
  }

  let lastError = null;
  for (const url of urls) {
    try {
      const requestHeaders = {
        ...getAdobeConsoleRequestHeaders(activeAccessToken),
        ...customHeaders,
      };
      const fetchImpl =
        timeoutMs > 0
          ? (targetUrl, init) => fetchWithAbortTimeout(targetUrl, init, timeoutMs)
          : (targetUrl, init) => fetch(targetUrl, init);
      const response = await fetchImpl(url, {
        method,
        credentials,
        mode,
        headers: requestHeaders,
        ...(body != null ? { body } : {}),
      });
      captureAdobeConsoleResponseState(response);

      const text = await response.text().catch(() => "");
      const parsed = parseJsonText(text, null);
      if (response.ok) {
        return {
          url,
          parsed: parsed ?? {},
          text,
          status: response.status,
          headers: toDebugHeadersObject(response.headers || new Headers()),
        };
      }

      const message = getAdobeConsoleErrorMessage(parsed, text, response.statusText);
      lastError = new Error(`${contextLabel} failed (${response.status}): ${message}`);
    } catch (error) {
      const timedOut = Boolean(timeoutMs > 0 && (error?.name === "AbortError" || /abort/i.test(String(error?.message || ""))));
      const message = timedOut
        ? `${contextLabel} timed out after ${timeoutMs}ms.`
        : normalizeHttpErrorMessage(error instanceof Error ? error.message : String(error));
      lastError = new Error(message || `${contextLabel} request failed.`);
    }
  }

  throw lastError || new Error(`${contextLabel} failed.`);
}

async function fetchAdobeConsoleJsonWithShellPageContextVariants(urlCandidates, contextLabel, requestOptions = null) {
  const urls = Array.isArray(urlCandidates)
    ? [...new Set(urlCandidates.filter((item) => typeof item === "string" && item.trim()))]
    : [];
  if (urls.length === 0) {
    return null;
  }

  const options = requestOptions && typeof requestOptions === "object" ? requestOptions : {};
  const preferredTabId = Number(options.preferredTabId || 0);
  const timeoutMs = Math.max(2000, Number(options.timeoutMs || 0) || PREMIUM_APPLICATIONS_FETCH_TIMEOUT_MS);
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([options.accessToken, getPreferredAdobeConsoleAccessTokenCandidate()])
  );
  const pageContextTargetRef =
    options.pageContextTargetRef && typeof options.pageContextTargetRef === "object"
      ? options.pageContextTargetRef
      : null;
  const method = String(options.method || "GET")
    .trim()
    .toUpperCase();
  const headers = options.headers && typeof options.headers === "object" ? { ...options.headers } : {};
  const body =
    Object.prototype.hasOwnProperty.call(options, "body") && options.body != null
      ? typeof options.body === "string"
        ? options.body
        : JSON.stringify(options.body)
      : undefined;

  for (const url of urls) {
    const response = await fetchAdobeConsoleJsonViaShellPageContext(url, {
      method,
      headers,
      body,
      accessToken,
      pageContextTargetRef,
      preferredTabId,
      timeoutMs,
    }).catch(() => null);
    if (!response?.ok) {
      continue;
    }
    return {
      url: String(response.url || url),
      parsed: response.parsed ?? {},
      text: String(response.text || ""),
      status: Number(response.status || 0),
      headers: response.headers && typeof response.headers === "object" ? response.headers : {},
      shell: response.shell && typeof response.shell === "object" ? response.shell : null,
    };
  }

  return null;
}

async function fetchAdobeConsoleJsonWithLoginButtonFallback(urlCandidates, contextLabel, requestOptions = null) {
  const options = requestOptions && typeof requestOptions === "object" ? requestOptions : {};
  const directResult = await fetchAdobeConsoleJsonWithAuthVariants(urlCandidates, contextLabel, {
    ...options,
    preferAuthenticatedHeaders: options.preferAuthenticatedHeaders !== false,
  }).catch((error) => {
    return {
      __underparError: error instanceof Error ? error : new Error(String(error)),
    };
  });
  if (directResult && typeof directResult === "object" && !directResult.__underparError) {
    return directResult;
  }

  const pageContextResult = await fetchAdobeConsoleJsonWithShellPageContextVariants(urlCandidates, contextLabel, {
    ...options,
    pageContextTargetRef:
      options.pageContextTargetRef && typeof options.pageContextTargetRef === "object"
        ? options.pageContextTargetRef
        : null,
  }).catch(() => null);
  if (pageContextResult) {
    return pageContextResult;
  }

  throw directResult?.__underparError || new Error(`${contextLabel} failed.`);
}

function normalizeRegisteredApplicationEntityRef(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  const normalized = raw.replace(/^@+/, "");
  const match = normalized.match(/^RegisteredApplication:(.+)$/i);
  const guid = String(match ? match[1] : normalized).trim();
  if (!guid) {
    return "";
  }
  return `RegisteredApplication:${guid}`;
}

function buildRegisteredApplicationBulkRetrieveRequest(entityRefs = [], configurationVersion = getKnownAdobeConsoleConfigurationVersion()) {
  const entities = uniquePreserveOrder(
    (Array.isArray(entityRefs) ? entityRefs : [entityRefs])
      .map((entityRef) => normalizeRegisteredApplicationEntityRef(entityRef))
      .filter(Boolean)
      .map((entityRef) => entityRef.replace(/^@+/, ""))
  );
  if (entities.length === 0) {
    return null;
  }

  const payload = {
    entities,
  };
  const normalizedConfigurationVersion = Number(configurationVersion || 0);
  if (Number.isFinite(normalizedConfigurationVersion) && normalizedConfigurationVersion > 0) {
    payload.configVersion = normalizedConfigurationVersion;
  }

  return {
    url: `${ADOBE_CONSOLE_BASE}/rest/api/entity/bulkRetrieve`,
    body: JSON.stringify(payload),
    entities,
  };
}

async function fetchRegisteredApplicationsByEntityRefs(entityRefs = [], contextLabel = "Applications load", options = {}) {
  const requestOptions = options && typeof options === "object" ? options : {};
  const bulkRetrieveRequest = buildRegisteredApplicationBulkRetrieveRequest(
    entityRefs,
    requestOptions.configurationVersion
  );
  if (!bulkRetrieveRequest) {
    return [];
  }

  const payload = await fetchAdobeConsoleJsonWithLoginButtonFallback([bulkRetrieveRequest.url], contextLabel, {
    ...requestOptions,
    method: "POST",
    headers: {
      ...(requestOptions.headers && typeof requestOptions.headers === "object" ? requestOptions.headers : {}),
      "Content-Type": "application/json",
    },
    body: bulkRetrieveRequest.body,
    preferAuthenticatedHeaders: requestOptions.preferAuthenticatedHeaders !== false,
  });

  return normalizeApplicationsResponse(payload?.parsed || payload);
}

async function fetchApplicationDetailsByGuid(guid, options = {}) {
  if (!guid) {
    return null;
  }
  const requestOptions = options && typeof options === "object" ? options : {};
  const entityRef = normalizeRegisteredApplicationEntityRef(guid);
  if (entityRef) {
    const bulkEntities = await fetchRegisteredApplicationsByEntityRefs([entityRef], "Application detail", requestOptions).catch(
      () => []
    );
    const bulkEntity = bulkEntities.find((item) => resolveApplicationGuidFromEntityData(item) === String(guid || "").trim()) || bulkEntities[0];
    if (bulkEntity && typeof bulkEntity === "object") {
      return bulkEntity;
    }
  }
  const urlCandidates = buildRegisteredApplicationDetailUrlCandidates(guid);
  const payload = await fetchAdobeConsoleJsonWithLoginButtonFallback(urlCandidates, "Application detail", requestOptions);
  const parsed = normalizeRegisteredApplicationDetailPayload(payload?.parsed ?? null);
  if (!parsed || typeof parsed !== "object") {
    return null;
  }
  return parsed;
}

async function fetchApplicationRawByGuid(guid, options = {}) {
  if (!guid) {
    return { text: "", parsed: null };
  }
  const requestOptions = options && typeof options === "object" ? options : {};
  const bulkRetrieveRequest = buildRegisteredApplicationBulkRetrieveRequest([guid], requestOptions.configurationVersion);
  let bulkFallback = null;
  if (bulkRetrieveRequest) {
    const bulkPayload =
      (await fetchAdobeConsoleJsonWithLoginButtonFallback([bulkRetrieveRequest.url], "Application raw fetch", {
        ...requestOptions,
        method: "POST",
        headers: {
          ...(requestOptions.headers && typeof requestOptions.headers === "object" ? requestOptions.headers : {}),
          "Content-Type": "application/json",
        },
        body: bulkRetrieveRequest.body,
        preferAuthenticatedHeaders: requestOptions.preferAuthenticatedHeaders !== false,
      }).catch(() => null)) ||
      null;
    if (bulkPayload) {
      const bulkEntities = normalizeApplicationsResponse(bulkPayload?.parsed || bulkPayload);
      const bulkEntity =
        bulkEntities.find((item) => resolveApplicationGuidFromEntityData(item) === String(guid || "").trim()) || bulkEntities[0] || null;
      if (bulkEntity && typeof bulkEntity === "object") {
        bulkFallback = {
          text: String(bulkPayload?.text || ""),
          parsed: bulkEntity,
        };
        const bulkStatement = firstNonEmptyString([
          extractSoftwareStatementFromAppData(bulkEntity),
          extractSoftwareStatementFromText(bulkPayload?.text || ""),
        ]);
        if (bulkStatement) {
          return bulkFallback;
        }
      }
    }
  }

  const urlCandidates = buildRegisteredApplicationDetailUrlCandidates(guid);
  for (const candidateUrl of urlCandidates) {
    const payload = await fetchAdobeConsoleJsonWithLoginButtonFallback([candidateUrl], "Application raw fetch", requestOptions).catch(
      () => null
    );
    const parsed = normalizeRegisteredApplicationDetailPayload(payload?.parsed || null);
    if (parsed && typeof parsed === "object") {
      return {
        text: String(payload?.text || ""),
        parsed,
      };
    }
  }

  return bulkFallback || { text: "", parsed: null };
}

async function fetchSoftwareStatementForAppGuid(guid, options = {}) {
  if (!guid) {
    return "";
  }
  const requestOptions = options && typeof options === "object" ? options : {};

  try {
    const details = await fetchApplicationDetailsByGuid(guid, requestOptions);
    const direct = extractSoftwareStatementFromAppData(details);
    if (direct) {
      return direct;
    }
  } catch {
    // Continue to raw fallback.
  }

  let rawPayload = null;
  try {
    rawPayload = await fetchApplicationRawByGuid(guid, requestOptions);
  } catch {
    return "";
  }

  if (rawPayload?.parsed) {
    const extracted = extractSoftwareStatementFromAppData(rawPayload.parsed);
    if (extracted) {
      return extracted;
    }

    const dereference = extractJwtAndUrls(rawPayload.parsed);
    if (dereference.jwt && dereference.jwtScore > 0) {
      return dereference.jwt;
    }

    for (const candidateUrl of dereference.urls) {
      try {
        const response = await fetchWithAbortTimeout(
          candidateUrl,
          {
            method: "GET",
            credentials: "include",
            mode: "cors",
            headers: {
              Accept: "text/plain, application/json, */*",
            },
          },
          Math.max(1000, Number(requestOptions.timeoutMs || PREMIUM_APPLICATION_DETAIL_TIMEOUT_MS))
        );
        if (!response.ok) {
          continue;
        }
        const content = await response.text();
        const candidateStatement = extractSoftwareStatementFromText(content);
        if (candidateStatement) {
          return candidateStatement;
        }
      } catch {
        // Ignore dereference errors and continue.
      }
    }
  }

  const rawTextStatement = extractSoftwareStatementFromText(rawPayload?.text || "");
  if (rawTextStatement) {
    return rawTextStatement;
  }

  return "";
}

async function fetchApplicationsForProgrammer(programmerId, options = {}) {
  if (!programmerId) {
    return {};
  }

  const currentSession = options?.session && typeof options.session === "object" ? options.session : state.loginData || null;
  const resolvedProgrammer =
    state.programmers.find((item) => String(item?.programmerId || "").trim() === String(programmerId || "").trim()) || null;
  const forceRefresh = options.forceRefresh === true;

  if (forceRefresh) {
    state.applicationsByProgrammerId.delete(programmerId);
  }

  const cachedApplications = getCurrentProgrammerApplicationsSnapshot(programmerId);
  const cachedApplicationsAreLive =
    cachedApplications &&
    typeof cachedApplications === "object" &&
    !Array.isArray(cachedApplications) &&
    !isPassVaultBackedValue(cachedApplications);
  if (!forceRefresh && cachedApplicationsAreLive) {
    emitPremiumDecisionDebugEvent(
      {
        phase: "premium-applications-cache-hit",
        programmerId: String(programmerId || ""),
      },
      {
        programmer: resolvedProgrammer,
      }
    );
    return cachedApplications;
  }
  if (!forceRefresh && cachedApplications && !cachedApplicationsAreLive) {
    emitPremiumDecisionDebugEvent(
      {
        phase: "premium-applications-vault-seed-bypass",
        programmerId: String(programmerId || ""),
      },
      {
        programmer: resolvedProgrammer,
      }
    );
  }

  emitPremiumDecisionDebugEvent(
    {
      phase: "premium-applications-request",
      method: "GET",
      programmerId: String(programmerId || ""),
      forceRefresh,
      requestTimeoutMs: Math.max(1000, Number(options.requestTimeoutMs || PREMIUM_APPLICATIONS_FETCH_TIMEOUT_MS)),
    },
    {
      programmer: resolvedProgrammer,
    }
  );

  let result = null;
  try {
    result = await fetchProgrammerRegisteredApplications(currentSession, programmerId, options);
  } catch (error) {
    const resolvedError = error instanceof Error ? error : new Error(String(error));
    emitPremiumDecisionDebugEvent(
      {
        phase: "premium-applications-error",
        programmerId: String(programmerId || ""),
        method: "GET",
        error: resolvedError.message,
      },
      {
        programmer: resolvedProgrammer,
      }
    );
    throw resolvedError;
  }

  const byGuid = {};
  (Array.isArray(result?.applications) ? result.applications : []).forEach((item, index) => {
    const guid = resolveApplicationGuidFromEntityData(item);
    if (!guid) {
      return;
    }
    byGuid[guid] =
      normalizeRegisteredApplicationRuntimeRecord({
        ...(item && typeof item === "object" ? item : {}),
        __underparFetchOrder: index,
      }) || {
        ...(item && typeof item === "object" ? item : {}),
        id: guid,
        __underparFetchOrder: index,
      };
  });

  setCurrentProgrammerApplicationsSnapshot(programmerId, byGuid);
  emitPremiumDecisionDebugEvent(
    {
      phase: "premium-applications-normalized",
      programmerId: String(programmerId || ""),
      applicationCount: Object.keys(byGuid).length,
      lookupCount: 1,
      url: String(result?.url || ""),
      status: Number(result?.status || 0),
    },
    {
      programmer: resolvedProgrammer,
    }
  );
  return byGuid;
}

async function ensureSelectedProgrammerApplicationsLoaded(programmer = null, options = {}) {
  const resolvedProgrammer = programmer && typeof programmer === "object" ? programmer : resolveSelectedProgrammer();
  const programmerId = String(resolvedProgrammer?.programmerId || "").trim();
  if (!programmerId) {
    return {};
  }

  const forceRefresh = options.forceRefresh === true;
  const cachedApplications = getCurrentProgrammerApplicationsSnapshot(programmerId);
  const cachedApplicationsAreLive =
    cachedApplications &&
    typeof cachedApplications === "object" &&
    !Array.isArray(cachedApplications) &&
    !isPassVaultBackedValue(cachedApplications);

  if (!forceRefresh && cachedApplicationsAreLive) {
    return cachedApplications;
  }

  if (!forceRefresh && state.programmerApplicationsLoadPromiseByProgrammerId.has(programmerId)) {
    return state.programmerApplicationsLoadPromiseByProgrammerId.get(programmerId);
  }

  const loadPromise = (async () => {
    const applicationsData = await fetchApplicationsForProgrammer(programmerId, options);
    const normalizedApplications =
      applicationsData && typeof applicationsData === "object" && !Array.isArray(applicationsData) ? applicationsData : {};
    setCurrentProgrammerApplicationsSnapshot(programmerId, normalizedApplications);
    return normalizedApplications;
  })();

  state.programmerApplicationsLoadPromiseByProgrammerId.set(programmerId, loadPromise);

  try {
    return await loadPromise;
  } finally {
    if (state.programmerApplicationsLoadPromiseByProgrammerId.get(programmerId) === loadPromise) {
      state.programmerApplicationsLoadPromiseByProgrammerId.delete(programmerId);
    }
  }
}

async function fetchProgrammerRegisteredApplications(session, programmerId, options = {}) {
  const currentSession = session && typeof session === "object" ? session : null;
  const consoleContext = currentSession?.console && typeof currentSession.console === "object" ? currentSession.console : {};
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([options.accessToken, currentSession?.accessToken])
  );
  const baseUrl = firstNonEmptyString([consoleContext?.baseUrl, ADOBE_CONSOLE_BASE]);
  const configurationVersion = Number(
    options.configurationVersion || consoleContext?.configurationVersion || getKnownAdobeConsoleConfigurationVersion() || 0
  );
  const normalizedProgrammerId = String(programmerId || "").trim();
  const pageContextTargetRef =
    options.pageContextTargetRef && typeof options.pageContextTargetRef === "object"
      ? options.pageContextTargetRef
      : null;
  const preferredTabId = Number(options.preferredTabId || 0);
  const requestTimeoutMs = Math.max(1000, Number(options.requestTimeoutMs || PREMIUM_APPLICATIONS_FETCH_TIMEOUT_MS));

  if (!accessToken || !baseUrl || configurationVersion <= 0 || !normalizedProgrammerId) {
    throw new Error("Registered Applications request is missing console context.");
  }

  const urlCandidates = [
    appendAdobeConsoleConfigurationVersion(
      `${baseUrl}/rest/api/applications?programmer=${encodeURIComponent(normalizedProgrammerId)}`,
      configurationVersion
    ),
  ].filter(Boolean);
  const payload = await fetchAdobeConsoleJsonWithLoginButtonFallback(urlCandidates, "Applications load", {
    timeoutMs: requestTimeoutMs,
    accessToken,
    preferAuthenticatedHeaders: true,
    preferredTabId,
    pageContextTargetRef,
  });

  const responseHeaders = payload?.headers && typeof payload.headers === "object" ? payload.headers : {};
  const nextCsrfToken = String(
    firstNonEmptyString([
      responseHeaders["x-csrf-token"],
      responseHeaders["X-CSRF-Token"],
      state.consoleCsrfToken,
    ]) || ""
  ).trim();
  if (nextCsrfToken) {
    state.consoleCsrfToken = nextCsrfToken;
  }

  return {
    applications: normalizeApplicationsResponse(payload?.parsed || payload),
    csrfToken: nextCsrfToken,
    pageContext: payload?.pageContext || null,
    transport: firstNonEmptyString([payload?.transport, payload?.shell ? "page-context" : ""]),
    url: String(payload?.url || urlCandidates[0] || ""),
    status: Number(payload?.status || 0),
  };
}

function getProgrammerRegisteredApplicationGuids(programmer = null, applicationsData = {}) {
  const ordered = [];
  const seen = new Set();
  const pushGuid = (value) => {
    const guid = extractApplicationGuid(value);
    if (!guid || seen.has(guid)) {
      return;
    }
    seen.add(guid);
    ordered.push(guid);
  };

  const programmerApplications = Array.isArray(programmer?.applications) ? programmer.applications : [];
  programmerApplications.forEach((appRef) => pushGuid(appRef));
  Object.keys(applicationsData || {}).forEach((guid) => pushGuid(guid));
  return ordered;
}

function buildOrderedPremiumServiceCandidates(applicationsArray, applicationsData) {
  if (!applicationsData || typeof applicationsData !== "object") {
    return [];
  }

  const candidates = [];
  for (const [guid, appData] of Object.entries(applicationsData || {})) {
    if (!guid || !appData || typeof appData !== "object") {
      continue;
    }

    const scopes = uniqueSorted(
      (Array.isArray(appData?.scopes) ? appData.scopes : []).map((scope) => normalizeScope(scope)).filter(Boolean)
    );
    if (scopes.length === 0) {
      continue;
    }
    candidates.push({
      guid,
      appRef: `@RegisteredApplication:${guid}`,
      appData,
      appName: appData.name || appData.displayName || guid,
      scopes,
      softwareStatement: extractSoftwareStatementFromAppData(appData),
    });
  }

  candidates.sort((left, right) => {
    const leftLabel = firstNonEmptyString([getRegisteredApplicationSortLabel(left.appData), left.appName, left.guid]);
    const rightLabel = firstNonEmptyString([getRegisteredApplicationSortLabel(right.appData), right.appName, right.guid]);
    const labelComparison = leftLabel.localeCompare(rightLabel, undefined, {
      sensitivity: "base",
    });
    if (labelComparison !== 0) {
      return labelComparison;
    }
    return String(left.guid || "").localeCompare(String(right.guid || ""), undefined, {
      sensitivity: "base",
    });
  });

  return candidates;
}

function findPremiumServiceApplications(applicationsArray, applicationsData, options = {}) {
  const services = {
    degradation: null,
    degradationApps: [],
    esm: null,
    esmApps: [],
    resetTempPass: null,
    resetTempPassApps: [],
    restV2: null,
    restV2Apps: [],
  };

  const candidates = buildOrderedPremiumServiceCandidates(applicationsArray, applicationsData);

  for (const appInfo of candidates) {
    if (degradationAppHasRequiredScope(appInfo)) {
      services.degradationApps.push(appInfo);
    }
    if (appInfo.scopes.includes(PREMIUM_SERVICE_SCOPE_BY_KEY.esm)) {
      services.esmApps.push(appInfo);
    }
    if (appInfo.scopes.includes(PREMIUM_SERVICE_RESET_TEMPPASS_SCOPE)) {
      services.resetTempPassApps.push(appInfo);
    }
    if (appInfo.scopes.includes(PREMIUM_SERVICE_SCOPE_BY_KEY.restV2)) {
      services.restV2Apps.push(appInfo);
    }
  }

  if (services.degradationApps.length > 0) {
    services.degradation = services.degradationApps[0] || null;
  } else {
    services.degradation = null;
  }

  services.esm = services.esmApps[0] || null;
  services.resetTempPass = services.resetTempPassApps[0] || null;
  services.restV2 = services.restV2Apps[0] || null;

  return services;
}

async function enrichPremiumAppsWithSoftwareStatements(premiumApps) {
  const uniqueApps = new Map();
  const pushApp = (appInfo) => {
    if (!appInfo?.guid || uniqueApps.has(appInfo.guid)) {
      return;
    }
    uniqueApps.set(appInfo.guid, appInfo);
  };

  pushApp(premiumApps?.degradation);
  pushApp(premiumApps?.esm);
  pushApp(premiumApps?.restV2);

  const hasServiceProviderHints = (appInfo) => {
    const appData = appInfo?.appData;
    if (!appData || typeof appData !== "object") {
      return false;
    }

    const fields = [
      appData.serviceProviders,
      appData.contentProviders,
      appData.requestors,
      appData.requestorIds,
      appData.requestor,
      appData.serviceProvider,
      appData.__rawEnvelope?.entityData?.serviceProviders,
      appData.__rawEnvelope?.entityData?.contentProviders,
      appData.__rawEnvelope?.entityData?.requestors,
      appData.__rawEnvelope?.entityData?.requestorIds,
    ];

    return fields.some((value) => {
      if (typeof value === "string") {
        return value.trim().length > 0;
      }
      if (Array.isArray(value)) {
        return value.some((item) => String(item || "").trim().length > 0);
      }
      return false;
    });
  };

  for (const appInfo of uniqueApps.values()) {
    if (!appInfo) {
      continue;
    }

    const shouldHydrateDetails =
      !appInfo.softwareStatement || !hasServiceProviderHints(appInfo);
    if (shouldHydrateDetails) {
      try {
        const details = await fetchApplicationDetailsByGuid(appInfo.guid);
        if (details) {
          appInfo.appData = details;
          if (!appInfo.softwareStatement) {
            appInfo.softwareStatement = extractSoftwareStatementFromAppData(details);
          }
        }
      } catch {
        // Continue with next source.
      }
    }

    if (!appInfo.softwareStatement) {
      appInfo.softwareStatement = await fetchSoftwareStatementForAppGuid(appInfo.guid);
    }
  }
}

function collectRestV2AppCandidatesFromPremiumApps(premiumApps) {
  const candidates = [];
  const seen = new Set();

  const pushCandidate = (appInfo) => {
    if (!appInfo?.guid || seen.has(appInfo.guid)) {
      return;
    }
    seen.add(appInfo.guid);
    candidates.push(appInfo);
  };

  if (Array.isArray(premiumApps?.restV2Apps)) {
    premiumApps.restV2Apps.forEach((appInfo) => pushCandidate(appInfo));
  }
  pushCandidate(premiumApps?.restV2);

  return candidates;
}

function hasRestV2AppBeenPrewarmed(programmerId, appGuid) {
  const appSet = state.restV2PrewarmedAppsByProgrammerId.get(getEnvironmentScopedProgrammerKey(programmerId));
  return Boolean(appSet && appSet.has(String(appGuid || "")));
}

function markRestV2AppPrewarmed(programmerId, appGuid) {
  const key = getEnvironmentScopedProgrammerKey(programmerId);
  const guid = String(appGuid || "");
  if (!key || !guid) {
    return;
  }

  const appSet = state.restV2PrewarmedAppsByProgrammerId.get(key) || new Set();
  appSet.add(guid);
  state.restV2PrewarmedAppsByProgrammerId.set(key, appSet);
}

async function prewarmRestV2ForProgrammer(programmer, premiumApps) {
  if (!programmer?.programmerId || !premiumApps) {
    return;
  }

  const candidates = collectRestV2AppCandidatesFromPremiumApps(premiumApps);
  if (candidates.length === 0) {
    return;
  }

  const preferredRequestor =
    String(state.selectedRequestorId || "").trim() ||
    (Array.isArray(programmer.requestorIds) && programmer.requestorIds.length > 0
      ? String(programmer.requestorIds[0] || "").trim()
      : "");

  const prioritized =
    resolveRestV2AppForServiceProvider(candidates, preferredRequestor, programmer.programmerId) || candidates[0];
  const ordered = [prioritized, ...candidates.filter((item) => item?.guid && item.guid !== prioritized?.guid)];

  const toWarm = ordered
    .filter((item) => item?.guid && !hasRestV2AppBeenPrewarmed(programmer.programmerId, item.guid))
    .slice(0, 2);

  for (const app of toWarm) {
    markRestV2AppPrewarmed(programmer.programmerId, app.guid);
    void ensureDcrAccessToken(programmer.programmerId, app, false).catch((error) => {
      log("REST V2 prewarm failed", {
        programmerId: programmer.programmerId,
        appGuid: app.guid,
        error: error instanceof Error ? error.message : String(error),
      });
    });
  }
}

function getDcrCacheKey(programmerId, appGuid, environmentKey = getActiveAdobePassEnvironmentKey()) {
  return `${DCR_CACHE_PREFIX}:${String(environmentKey || DEFAULT_ADOBEPASS_ENVIRONMENT.key)}:${programmerId}:${appGuid}`;
}

function getLegacyUnscopedDcrCacheKey(programmerId, appGuid) {
  return `${DCR_CACHE_PREFIX}:${programmerId}:${appGuid}`;
}

function getLegacyDcrCacheKey(programmerId, appGuid) {
  return `${LEGACY_DCR_CACHE_PREFIX}:${programmerId}:${appGuid}`;
}

function loadDcrCache(programmerId, appGuid) {
  try {
    const environmentKey = getActiveAdobePassEnvironmentKey();
    const vaultCache = choosePassVaultRuntimeDcrCache(
      getPassVaultRegisteredApplicationRecord(programmerId, appGuid, environmentKey)
    );
    if (vaultCache) {
      localStorage.setItem(getDcrCacheKey(programmerId, appGuid, environmentKey), JSON.stringify(vaultCache));
      return vaultCache;
    }
    const scopedCacheKey = getDcrCacheKey(programmerId, appGuid, environmentKey);
    const scopedRaw = localStorage.getItem(scopedCacheKey);
    const raw =
      scopedRaw ||
      (isProductionAdobePassEnvironmentKey(environmentKey)
        ? localStorage.getItem(getLegacyUnscopedDcrCacheKey(programmerId, appGuid)) ||
          localStorage.getItem(getLegacyDcrCacheKey(programmerId, appGuid))
        : "");
    if (!raw) {
      return null;
    }
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") {
      return null;
    }
    const normalized = {
      ...parsed,
      clientId: parsed.clientId || parsed.client_id || "",
      clientSecret: parsed.clientSecret || parsed.client_secret || "",
      accessToken: parsed.accessToken || parsed.access_token || "",
      tokenExpiresAt: Number(parsed.tokenExpiresAt || parsed.expires_at || 0),
      tokenScope: String(parsed.tokenScope || parsed.scope || "").trim(),
    };
    if (!scopedRaw && isProductionAdobePassEnvironmentKey(environmentKey)) {
      localStorage.setItem(scopedCacheKey, JSON.stringify(normalized));
    }
    return normalized;
  } catch {
    return null;
  }
}

function saveDcrCache(programmerId, appGuid, value) {
  try {
    const normalized = {
      ...value,
      clientId: value?.clientId || value?.client_id || "",
      clientSecret: value?.clientSecret || value?.client_secret || "",
      accessToken: value?.accessToken || value?.access_token || "",
      tokenExpiresAt: Number(value?.tokenExpiresAt || value?.expires_at || 0),
      tokenScope: String(value?.tokenScope || value?.scope || "").trim(),
    };
    localStorage.setItem(getDcrCacheKey(programmerId, appGuid), JSON.stringify(normalized));
    void persistPassVaultApplicationDcrCache(programmerId, appGuid, normalized).catch(() => {});
  } catch {
    // Ignore localStorage cache failures.
  }
}

function tokenizeOAuthScopeValue(scopeValue = "") {
  return String(scopeValue || "")
    .split(/[\s,]+/)
    .map((scope) => normalizeScope(scope))
    .filter(Boolean);
}

function extractScopeValuesFromTokenClaims(claims) {
  if (!claims || typeof claims !== "object") {
    return [];
  }

  const values = new Set();
  const append = (value) => {
    if (value == null) {
      return;
    }
    if (Array.isArray(value)) {
      value.forEach((item) => append(item));
      return;
    }
    if (typeof value === "object") {
      if (typeof value.value === "string") {
        append(value.value);
      }
      Object.values(value).forEach((item) => append(item));
      return;
    }
    if (typeof value === "string") {
      tokenizeOAuthScopeValue(value).forEach((scope) => values.add(scope));
    }
  };

  append(claims.scope);
  append(claims.scopes);
  append(claims.scopeSet);
  append(claims.permissions);
  return [...values];
}

function getGrantedPremiumServiceScopes(grantedScopes = []) {
  return uniqueSorted(
    (Array.isArray(grantedScopes) ? grantedScopes : [])
      .map((scope) => normalizeScope(scope))
      .filter((scope) => KNOWN_PREMIUM_SERVICE_SCOPES.includes(scope))
  );
}

function tokenScopeSatisfiesRequiredScope(tokenScope = "", accessToken = "", requiredScope = "", options = {}) {
  const normalizedRequiredScope = normalizeScope(requiredScope);
  if (!normalizedRequiredScope) {
    return true;
  }
  const strictUnknown = options?.strictUnknown === true;
  const requestedScopeHint = normalizeScope(firstNonEmptyString([options?.requestedScopeHint]));

  const granted = new Set(tokenizeOAuthScopeValue(tokenScope));
  const claims = parseJwtPayload(accessToken);
  extractScopeValuesFromTokenClaims(claims).forEach((scope) => granted.add(scope));

  // Some endpoints require explicit token scope evidence (ex: DEGRADATION).
  if (granted.size === 0) {
    if (strictUnknown && requestedScopeHint) {
      return requestedScopeHint === normalizedRequiredScope;
    }
    return !strictUnknown;
  }

  return granted.has(normalizedRequiredScope);
}

function isEsmRequiredServiceScope(requiredScope = "", serviceHint = "") {
  const normalizedRequiredScope = normalizeScope(requiredScope);
  const normalizedServiceHint = normalizeScope(serviceHint);
  return (
    normalizedRequiredScope === normalizeScope(PREMIUM_SERVICE_SCOPE_BY_KEY.esm) ||
    normalizedServiceHint.includes("esm")
  );
}

function shouldAllowImplicitEsmTokenScope(requiredScope = "", serviceHint = "", accessToken = "", attemptedScope = "") {
  if (!isEsmRequiredServiceScope(requiredScope, serviceHint)) {
    return false;
  }
  if (!String(accessToken || "").trim()) {
    return false;
  }
  const normalizedAttemptedScope = normalizeScope(firstNonEmptyString([attemptedScope, requiredScope]));
  return normalizedAttemptedScope === normalizeScope(PREMIUM_SERVICE_SCOPE_BY_KEY.esm);
}

function resolveRequiredPremiumServiceScope(appInfo, debugMeta = null) {
  const explicit = normalizeScope(firstNonEmptyString([debugMeta?.requiredServiceScope]));
  if (explicit) {
    return explicit;
  }

  const serviceHint = normalizeScope(firstNonEmptyString([debugMeta?.service]));
  if (serviceHint.includes("degradation")) {
    return getPreferredDegradationScopeForApp(appInfo) || PREMIUM_SERVICE_SCOPE_BY_KEY.degradation;
  }
  if (serviceHint.includes("esm")) {
    return PREMIUM_SERVICE_SCOPE_BY_KEY.esm;
  }
  if (serviceHint.includes("rest") || serviceHint.includes("profile") || serviceHint.includes("bobtools")) {
    return REST_V2_SCOPE;
  }

  const appScopes = Array.isArray(appInfo?.scopes) ? appInfo.scopes : [];
  const normalizedAppScopes = appScopes.map((scope) => normalizeScope(scope)).filter(Boolean);
  const knownPremiumScopes = new Set(
    [...Object.values(PREMIUM_SERVICE_SCOPE_BY_KEY), ...DEGRADATION_SCOPE_CANDIDATES]
      .map((scope) => normalizeScope(scope))
      .filter(Boolean)
  );
  for (const scope of normalizedAppScopes) {
    if (knownPremiumScopes.has(scope)) {
      return scope;
    }
  }
  return "";
}

function clearDcrCache(programmerId, appGuid) {
  try {
    localStorage.removeItem(getDcrCacheKey(programmerId, appGuid));
    localStorage.removeItem(getLegacyUnscopedDcrCacheKey(programmerId, appGuid));
    localStorage.removeItem(getLegacyDcrCacheKey(programmerId, appGuid));
    void persistPassVaultApplicationDcrCache(programmerId, appGuid, null).catch(() => {});
  } catch {
    // Ignore localStorage cache cleanup failures.
  }
}

function clearDcrTokenCache(programmerId, appGuid) {
  const existing = loadDcrCache(programmerId, appGuid);
  if (!existing) {
    return;
  }
  saveDcrCache(programmerId, appGuid, {
    ...existing,
    accessToken: "",
    tokenExpiresAt: 0,
    tokenScope: "",
  });
}

function toNonEmptyStringOrEmpty(value) {
  if (typeof value !== "string") {
    return "";
  }
  const trimmed = value.trim();
  return trimmed || "";
}

function extractDcrAccessTokenValue(payload) {
  if (!payload || typeof payload !== "object") {
    return "";
  }

  const candidates = [
    payload?.access_token,
    payload?.accessToken,
    payload?.token?.access_token,
    payload?.token?.accessToken,
    payload?.token?.value,
    payload?.token?.token,
    payload?.data?.access_token,
    payload?.data?.accessToken,
    payload?.data?.token,
    payload?.value,
    payload?.tokenValue,
  ];

  for (const candidate of candidates) {
    const text = toNonEmptyStringOrEmpty(candidate);
    if (text) {
      return text;
    }
  }

  return "";
}

async function registerClientWithSoftwareStatement(softwareStatement) {
  const normalizedSoftwareStatement = String(softwareStatement || "").trim();
  if (!normalizedSoftwareStatement) {
    throw new Error("Registered application software statement is unavailable.");
  }

  const requestUrl = `${ADOBE_SP_BASE}/o/client/register`;
  const attempts = [
    {
      label: "DCR JSON register",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        software_statement: normalizedSoftwareStatement,
        grant_types: ["client_credentials"],
        token_endpoint_auth_method: "client_secret_post",
      }),
    },
    {
      label: "DCR form register",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        software_statement: normalizedSoftwareStatement,
      }).toString(),
    },
  ];

  let lastError = "DCR registration failed.";
  for (const attempt of attempts) {
    try {
      const response = await fetchWithRateLimitRetry(
        () =>
          fetch(requestUrl, {
            method: "POST",
            mode: "cors",
            headers: attempt.headers,
            body: attempt.body,
          }),
        attempt.label,
        {
          onRetry: ({ attempt: retryAttempt, maxRetries, delayMs }) => {
            const delaySeconds = Math.max(1, Math.ceil(delayMs / 1000));
            setStatus(
              `DCR registration rate-limited. Retrying in ${delaySeconds}s (${retryAttempt}/${maxRetries})...`,
              "info"
            );
          },
        }
      );

      const text = await response.text().catch(() => "");
      const data = parseJsonOrFormText(text, {}) || {};
      if (!response.ok) {
        const reason = normalizeHttpErrorMessage(text) || response.statusText;
        throw new Error(`${attempt.label} failed (${response.status}): ${reason}`);
      }

      const clientId = firstNonEmptyString([
        String(data?.client_id || "").trim(),
        String(data?.clientId || "").trim(),
        String(data?.clientID || "").trim(),
        String(data?.client?.client_id || "").trim(),
        String(data?.client?.clientId || "").trim(),
      ]);
      const clientSecret = firstNonEmptyString([
        String(data?.client_secret || "").trim(),
        String(data?.clientSecret || "").trim(),
        String(data?.clientSECRET || "").trim(),
        String(data?.client?.client_secret || "").trim(),
        String(data?.client?.clientSecret || "").trim(),
      ]);
      if (!clientId || !clientSecret) {
        throw new Error("DCR response missing client_id/client_secret.");
      }
      return { clientId, clientSecret };
    } catch (error) {
      lastError = error?.message || String(error);
    }
  }

  throw new Error(lastError);
}

async function requestClientCredentialsToken(clientId, clientSecret, debugMeta = null, requestedScope = "", options = {}) {
  const debugFlowId = String(debugMeta?.flowId || "").trim();
  const tokenEndpointUrl = `${ADOBE_SP_BASE}/o/client/token`;
  const normalizedRequestedScope = normalizeScope(requestedScope);
  const normalizedServiceHint = normalizeScope(firstNonEmptyString([debugMeta?.service, debugMeta?.scope]));
  const strictScopeValidation = options?.strictScopeValidation === true;
  const tokenAttemptMode = options?.tokenAttemptMode === "scoped-only" ? "scoped-only" : "default";
  const normalizedAttemptScope = normalizeScope(
    tokenAttemptMode === "scoped-only" ? normalizedRequestedScope : normalizedRequestedScope
  );
  const createTokenAttemptId = (transport) =>
    `token-${String(transport || "attempt")}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  const emitTokenDebugEvent = (phase, details = {}) => {
    emitRestV2DebugEvent(debugFlowId, {
      source: "extension",
      service: String(debugMeta?.service || ""),
      phase,
      requestScope: String(debugMeta?.scope || ""),
      requestorId: String(debugMeta?.requestorId || ""),
      mvpd: String(debugMeta?.mvpd || ""),
      appGuid: String(debugMeta?.appGuid || ""),
      ...details,
    });
  };

  const attempts = ["form", "query"];
  let lastError = `Unable to reach ${tokenEndpointUrl}.`;
  for (const transport of attempts) {
    const attemptId = createTokenAttemptId(transport);
    const requestHeaders =
      transport === "form"
        ? {
            Accept: "application/json",
            "Content-Type": "application/x-www-form-urlencoded",
          }
        : {
            Accept: "application/json",
          };
    const body = new URLSearchParams({
      grant_type: "client_credentials",
      client_id: String(clientId || "").trim(),
      client_secret: String(clientSecret || "").trim(),
    });
    if (normalizedAttemptScope) {
      body.set("scope", normalizedAttemptScope);
    }

    const requestBodyPreview = transport === "form" ? body.toString() : "";
    const requestUrl = transport === "query" ? `${tokenEndpointUrl}?${body.toString()}` : tokenEndpointUrl;

    emitTokenDebugEvent("token-request-attempt", {
      attemptId,
      transport,
      method: "POST",
      url: requestUrl,
      requestHeaders,
      requestBodyPreview,
      oauthScope: normalizedAttemptScope,
    });

    let response;
    let text = "";
    let parsed = {};
    try {
      response = await fetchWithRateLimitRetry(
        () =>
          fetch(requestUrl, {
            method: "POST",
            mode: "cors",
            headers: requestHeaders,
            ...(transport === "form" ? { body: requestBodyPreview } : {}),
          }),
        transport === "form" ? "DCR token form" : "DCR token query",
        {
          onRetry: ({ attempt, maxRetries, delayMs }) => {
            const delaySeconds = Math.max(1, Math.ceil(delayMs / 1000));
            setStatus(
              `DCR token rate-limited. Retrying in ${delaySeconds}s (${attempt}/${maxRetries})...`,
              "info"
            );
          },
        }
      );
      text = await response.text().catch(() => "");
      parsed = parseJsonOrFormText(text, {}) || {};
    } catch (error) {
      lastError = error?.message || String(error);
      emitTokenDebugEvent("token-request-attempt-failed", {
        attemptId,
        transport,
        method: "POST",
        url: requestUrl,
        requestHeaders,
        requestBodyPreview,
        error: lastError,
        oauthScope: normalizedAttemptScope,
      });
      continue;
    }

    if (!response.ok) {
      const reason = normalizeHttpErrorMessage(text) || response.statusText;
      lastError = `${tokenEndpointUrl} returned ${response.status}${reason ? `: ${reason}` : ""}`;
      emitTokenDebugEvent("token-request-attempt-failed", {
        attemptId,
        transport,
        method: "POST",
        url: requestUrl,
        requestHeaders,
        requestBodyPreview,
        status: Number(response.status || 0),
        statusText: String(response.statusText || ""),
        responseHeaders: toDebugHeadersObject(response.headers),
        responsePreview: text ? truncateDebugText(text, 4000) : "",
        error: reason,
        oauthScope: normalizedAttemptScope,
      });
      continue;
    }

    const accessToken = extractDcrAccessTokenValue(parsed);
    if (!accessToken) {
      lastError = "DCR token response did not return an access_token.";
      emitTokenDebugEvent("token-request-attempt-failed", {
        attemptId,
        transport,
        method: "POST",
        url: requestUrl,
        requestHeaders,
        requestBodyPreview,
        status: Number(response.status || 0),
        statusText: String(response.statusText || ""),
        responseHeaders: toDebugHeadersObject(response.headers),
        responsePreview: text ? truncateDebugText(text, 4000) : "",
        error: lastError,
        oauthScope: normalizedAttemptScope,
      });
      continue;
    }

    const expiresInSeconds = Number(
      parsed?.expires_in ||
        parsed?.expiresIn ||
        parsed?.token?.expires_in ||
        parsed?.token?.expiresIn ||
        0
    );
    const ttlSeconds = Number.isFinite(expiresInSeconds) && expiresInSeconds > 0 ? expiresInSeconds : 6 * 60 * 60;
    const tokenClaims = parseJwtPayload(accessToken);
    const tokenScope = firstNonEmptyString([
      String(parsed?.scope || "").trim(),
      String(parsed?.token?.scope || "").trim(),
      String(tokenClaims?.scope || "").trim(),
      normalizedAttemptScope,
    ]);
    const scopeSatisfied = tokenScopeSatisfiesRequiredScope(
      tokenScope,
      accessToken,
      normalizedRequestedScope,
      {
        strictUnknown: strictScopeValidation,
        requestedScopeHint: normalizedAttemptScope,
      }
    );
    const allowImplicitScope = shouldAllowImplicitEsmTokenScope(
      normalizedRequestedScope,
      normalizedServiceHint,
      accessToken,
      normalizedAttemptScope
    );
    if (!scopeSatisfied && !allowImplicitScope) {
      lastError = `Token response missing required scope "${normalizedRequestedScope}".`;
      emitTokenDebugEvent("token-request-attempt-failed", {
        attemptId,
        transport,
        method: "POST",
        url: requestUrl,
        requestHeaders,
        requestBodyPreview,
        status: Number(response.status || 0),
        statusText: String(response.statusText || ""),
        responseHeaders: toDebugHeadersObject(response.headers),
        responsePreview: text ? truncateDebugText(text, 4000) : "",
        error: lastError,
        oauthScope: tokenScope,
      });
      continue;
    }
    if (!scopeSatisfied && allowImplicitScope) {
      emitTokenDebugEvent("token-response-implicit-esm-scope", {
        oauthScope: tokenScope,
        requestedScope: normalizedRequestedScope,
        attemptedScope: normalizedAttemptScope,
      });
    }

    const responseSummary = JSON.stringify({
      token_type: String(parsed?.token_type || parsed?.tokenType || ""),
      expires_in: Number(parsed?.expires_in || parsed?.expiresIn || 0),
      scope: String(tokenScope || ""),
      has_access_token: true,
    });
    emitTokenDebugEvent("token-request-attempt-succeeded", {
      attemptId,
      transport,
      method: "POST",
      url: requestUrl,
      requestHeaders,
      requestBodyPreview,
      status: Number(response.status || 0),
      statusText: String(response.statusText || ""),
      responseHeaders: toDebugHeadersObject(response.headers),
      responsePreview: responseSummary,
      oauthScope: tokenScope,
    });
    emitTokenDebugEvent("token-response", {
      ttlSeconds,
      oauthScope: tokenScope,
    });

    return {
      accessToken,
      tokenExpiresAt: Date.now() + ttlSeconds * 1000,
      tokenScope,
      attemptedScope: normalizedAttemptScope,
    };
  }

  emitTokenDebugEvent("token-request-failed", {
    error: String(lastError || "Token request failed."),
    oauthScope: normalizedRequestedScope,
  });
  throw new Error(lastError);
}

async function ensureDcrAccessToken(programmerId, appInfo, forceRefresh = false, debugMeta = null) {
  if (!programmerId) {
    throw new Error("Media company ID is required.");
  }
  let resolvedAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, appInfo, debugMeta) || appInfo;
  if (!resolvedAppInfo || !resolvedAppInfo.guid) {
    throw new Error("Registered application details are missing.");
  }

  const debugFlowId = String(debugMeta?.flowId || "").trim();
  let requiredServiceScope = resolveRequiredPremiumServiceScope(resolvedAppInfo, debugMeta);
  const normalizedServiceHint = normalizeScope(firstNonEmptyString([debugMeta?.service, debugMeta?.scope]));
  const isEsmRequiredScope = isEsmRequiredServiceScope(requiredServiceScope, normalizedServiceHint);
  const strictScopeValidation = debugMeta?.strictScopeValidation === true || isEsmRequiredScope;
  const tokenAttemptMode =
    debugMeta?.tokenAttemptMode === "scoped-only" || isEsmRequiredScope ? "scoped-only" : "default";
  const allowProvisioning = debugMeta?.allowProvisioning === true;
  const refreshResolvedAppInfo = () => {
    const latestAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, resolvedAppInfo, debugMeta) || resolvedAppInfo;
    if (latestAppInfo?.guid) {
      resolvedAppInfo = latestAppInfo;
      requiredServiceScope = resolveRequiredPremiumServiceScope(resolvedAppInfo, debugMeta);
    }
    return resolvedAppInfo;
  };
  const emitDcrDebugEvent = (phase, details = {}) => {
    emitRestV2DebugEvent(debugFlowId, {
      source: "extension",
      service: String(debugMeta?.service || ""),
      phase,
      requestScope: String(debugMeta?.scope || ""),
      requiredServiceScope: String(requiredServiceScope || ""),
      requestorId: String(debugMeta?.requestorId || ""),
      mvpd: String(debugMeta?.mvpd || ""),
      programmerId: String(programmerId || ""),
      appGuid: String(resolvedAppInfo?.guid || ""),
      appName: String(resolvedAppInfo?.appName || resolvedAppInfo?.guid || ""),
      ...details,
    });
  };

  const promiseKey = getDcrCacheKey(programmerId, resolvedAppInfo.guid);
  if (!forceRefresh && state.dcrEnsureTokenPromiseByKey.has(promiseKey)) {
    emitDcrDebugEvent("token-promise-reuse");
    return state.dcrEnsureTokenPromiseByKey.get(promiseKey);
  }

  const workPromise = (async () => {
    let cache = loadDcrCache(programmerId, resolvedAppInfo.guid) || {};

    const ensureSoftwareStatement = async () => {
      const currentStatement = firstNonEmptyString([
        String(resolvedAppInfo?.softwareStatement || "").trim(),
        extractSoftwareStatementFromAppData(resolvedAppInfo?.appData || null),
        extractSoftwareStatementFromAppData(resolvedAppInfo),
      ]);
      if (currentStatement) {
        resolvedAppInfo.softwareStatement = currentStatement;
        return currentStatement;
      }

      try {
        const hydratedAppInfo = await enrichRegisteredApplicationForHydration(resolvedAppInfo, {
          timeoutMs: PREMIUM_APPLICATION_DETAIL_TIMEOUT_MS,
          preferAuthenticatedHeaders: true,
          preferredTabId: 0,
          allowTemporaryPageContextTab: true,
        });
        if (hydratedAppInfo && typeof hydratedAppInfo === "object") {
          resolvedAppInfo = hydratedAppInfo;
        }
      } catch {
        // Continue to direct software statement fallback.
      }

      if (!resolvedAppInfo.softwareStatement) {
        try {
          resolvedAppInfo.softwareStatement = await fetchSoftwareStatementForAppGuid(resolvedAppInfo.guid, {
            timeoutMs: PREMIUM_APPLICATION_DETAIL_TIMEOUT_MS,
            preferAuthenticatedHeaders: true,
            preferredTabId: 0,
            allowTemporaryPageContextTab: true,
          });
        } catch {
          // Continue and fail below if still missing.
        }
      }
      return String(resolvedAppInfo?.softwareStatement || "").trim();
    };

    if (!cache.clientId || !cache.clientSecret) {
      emitDcrDebugEvent("dcr-registration-required", {
        allowProvisioning,
      });
      if (!allowProvisioning) {
        throw new Error(
          `UnderPAR could not auto-hydrate DCR credentials for ${resolvedAppInfo.appName || resolvedAppInfo.guid} from the registered applications cache yet.`
        );
      }
      const softwareStatement = await ensureSoftwareStatement();
      if (!softwareStatement) {
        throw new Error(`No software statement found on app ${resolvedAppInfo.appName || resolvedAppInfo.guid}`);
      }

      const registered = await registerClientWithSoftwareStatement(softwareStatement);
      cache.clientId = registered.clientId;
      cache.clientSecret = registered.clientSecret;
      saveDcrCache(programmerId, resolvedAppInfo.guid, cache);
      emitDcrDebugEvent("dcr-registration-succeeded");
    }

    const tokenMissing = !cache.accessToken || !cache.tokenExpiresAt;
    const tokenExpired = Date.now() >= Number(cache.tokenExpiresAt) - 60 * 1000;
    const cachedServiceScope = normalizeScope(String(cache.serviceScope || cache.tokenRequestedScope || ""));
    const cacheServiceScopeMismatch = Boolean(
      normalizeScope(requiredServiceScope) && cachedServiceScope !== normalizeScope(requiredServiceScope)
    );
    const tokenScopeMismatch = !tokenScopeSatisfiesRequiredScope(
      String(cache.tokenScope || ""),
      String(cache.accessToken || ""),
      requiredServiceScope,
      {
        strictUnknown: strictScopeValidation,
        requestedScopeHint: String(cache.tokenRequestedScope || cache.serviceScope || ""),
      }
    ) && !shouldAllowImplicitEsmTokenScope(
      requiredServiceScope,
      normalizedServiceHint,
      String(cache.accessToken || ""),
      String(cache.tokenRequestedScope || cache.serviceScope || "")
    );
    if (forceRefresh || tokenMissing || tokenExpired || tokenScopeMismatch || cacheServiceScopeMismatch) {
      emitDcrDebugEvent("token-refresh-required", {
        forceRefresh: forceRefresh === true,
        tokenMissing: tokenMissing === true,
        tokenExpired: tokenExpired === true,
        tokenScopeMismatch: tokenScopeMismatch === true,
        cacheServiceScopeMismatch: cacheServiceScopeMismatch === true,
        cachedServiceScope,
        cachedTokenScope: String(cache.tokenScope || ""),
      });
      const token = await requestClientCredentialsToken(
        cache.clientId,
        cache.clientSecret,
        {
          ...debugMeta,
          appGuid: String(resolvedAppInfo?.guid || ""),
        },
        requiredServiceScope,
        {
          strictScopeValidation,
          tokenAttemptMode,
        }
      );
      cache.accessToken = token.accessToken;
      cache.tokenExpiresAt = token.tokenExpiresAt;
      cache.tokenScope = String(token.tokenScope || "");
      cache.tokenRequestedScope = String(token.attemptedScope || requiredServiceScope || "").trim();
      cache.serviceScope = String(requiredServiceScope || cache.serviceScope || "").trim();
    } else {
      emitDcrDebugEvent("token-cache-hit", {
        tokenExpiresAt: Number(cache.tokenExpiresAt || 0),
        tokenScope: String(cache.tokenScope || ""),
        serviceScope: String(cache.serviceScope || ""),
      });
    }

    saveDcrCache(programmerId, resolvedAppInfo.guid, cache);
    emitDcrDebugEvent("token-ready", {
      tokenExpiresAt: Number(cache.tokenExpiresAt || 0),
    });
    return cache.accessToken;
  })();

  state.dcrEnsureTokenPromiseByKey.set(promiseKey, workPromise);
  try {
    return await workPromise;
  } finally {
    if (state.dcrEnsureTokenPromiseByKey.get(promiseKey) === workPromise) {
      state.dcrEnsureTokenPromiseByKey.delete(promiseKey);
    }
  }
}

function isEsmServiceDebugMeta(debugMeta = null) {
  const serviceHint = normalizeScope(firstNonEmptyString([debugMeta?.service]));
  const requiredScope = normalizeScope(firstNonEmptyString([debugMeta?.requiredServiceScope]));
  return serviceHint.includes("esm") || requiredScope === normalizeScope(PREMIUM_SERVICE_SCOPE_BY_KEY.esm);
}

function shouldAttemptEsmServiceRecovery(error, debugMeta = null) {
  if (!isEsmServiceDebugMeta(debugMeta)) {
    return false;
  }
  const message = String(error?.message || error || "").trim().toLowerCase();
  if (!message) {
    return false;
  }
  return (
    message.includes(normalizeScope(PREMIUM_SERVICE_SCOPE_BY_KEY.esm)) ||
    message.includes("dcr credentials") ||
    message.includes("vault yet") ||
    message.includes("software statement")
  );
}

function getRuntimePremiumServicesSeed(programmerId = "") {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return null;
  }
  const currentServices = getCurrentPremiumAppsSnapshot(normalizedProgrammerId);
  if (currentServices) {
    return currentServices;
  }
  const record = getPassVaultMediaCompanyRecord(normalizedProgrammerId);
  if (!record) {
    return null;
  }
  return markPassVaultBackedValue(buildPassVaultRuntimeServicesSnapshot(record), record);
}

async function recoverEsmServiceSelection(programmerId = "", options = {}) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return null;
  }
  const excludedGuid = String(options?.excludedGuid || "").trim();
  const programmer =
    state.programmers.find((item) => String(item?.programmerId || "").trim() === normalizedProgrammerId) || null;
  if (!programmer) {
    return null;
  }

  const services =
    (await primeProgrammerServiceHydration(programmer, getRuntimePremiumServicesSeed(normalizedProgrammerId), {
      forceRefresh: true,
      controllerReason: "esm-auto-recovery",
    }).catch(() => null)) ||
    getCurrentPremiumAppsSnapshot(normalizedProgrammerId) ||
    null;
  if (services) {
    setCurrentPremiumAppsSnapshot(normalizedProgrammerId, services);
  }
  const recoveredAppInfo =
    collectEsmAppCandidatesFromPremiumApps(services).find(
      (appInfo) => String(appInfo?.guid || "").trim() !== excludedGuid
    ) ||
    (hasEsmScopedApp(services) && String(services?.esm?.guid || "").trim() !== excludedGuid ? services.esm : null);
  const nextServices =
    services && recoveredAppInfo?.guid
      ? {
          ...services,
          esm: recoveredAppInfo,
          esmApps: collectEsmAppCandidatesFromPremiumApps(
            {
              ...services,
              esm: null,
              esmApps: Array.isArray(services?.esmApps)
                ? services.esmApps.filter((appInfo) => String(appInfo?.guid || "").trim() !== excludedGuid)
                : [],
            },
            recoveredAppInfo
          ),
        }
      : services;
  if (nextServices) {
    setCurrentPremiumAppsSnapshot(normalizedProgrammerId, nextServices);
  }
  if (String(resolveSelectedProgrammer()?.programmerId || "").trim() === normalizedProgrammerId && nextServices) {
    renderPremiumServices(nextServices, programmer, {
      controllerReason: "esm-auto-recovery",
    });
  }
  return {
    programmer,
    services: nextServices,
    appInfo: recoveredAppInfo,
  };
}

async function ensureDcrAccessTokenWithEsmRecovery(programmerId, appInfo, forceRefresh = false, debugMeta = null) {
  let resolvedAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, appInfo, debugMeta) || appInfo;
  try {
    const accessToken = await ensureDcrAccessToken(programmerId, resolvedAppInfo, forceRefresh, debugMeta);
    resolvedAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, resolvedAppInfo, debugMeta) || resolvedAppInfo;
    return {
      accessToken,
      appInfo: resolvedAppInfo,
      recovered: false,
    };
  } catch (error) {
    if (!shouldAttemptEsmServiceRecovery(error, debugMeta)) {
      throw error;
    }
    const recovered = await recoverEsmServiceSelection(programmerId, {
      requestorId: String(debugMeta?.requestorId || "").trim(),
      excludedGuid: String(resolvedAppInfo?.guid || "").trim(),
    });
    const recoveredAppInfo = recovered?.appInfo || null;
    if (!recoveredAppInfo?.guid || String(recoveredAppInfo.guid || "").trim() === String(resolvedAppInfo?.guid || "").trim()) {
      throw error;
    }
    return {
      accessToken: await ensureDcrAccessToken(programmerId, recoveredAppInfo, true, {
        ...(debugMeta && typeof debugMeta === "object" ? debugMeta : {}),
        lockAppSelection: true,
      }),
      appInfo: recoveredAppInfo,
      services: recovered?.services || null,
      recovered: true,
    };
  }
}

function shouldAttemptAlternatePremiumServiceRecovery(error, appInfo = null, debugMeta = null) {
  const serviceKey = resolvePremiumServiceKeyForAuth(appInfo, debugMeta);
  if (serviceKey !== "restV2" && serviceKey !== "degradation") {
    return false;
  }

  const message = String(error?.message || error || "").trim().toLowerCase();
  if (!message) {
    return false;
  }

  return (
    message.includes("software statement") ||
    message.includes("dcr credentials") ||
    message.includes("vault yet") ||
    message.includes("client_id/client_secret") ||
    message.includes("access_token") ||
    message.includes("required scope")
  );
}

function selectRecoveredPremiumServiceApp(programmerId = "", serviceKey = "", services = null, options = {}) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedServiceKey = String(serviceKey || "").trim();
  const normalizedRequestorId = String(options?.requestorId || "").trim();
  const excludedGuid = String(options?.excludedGuid || "").trim();
  if (!normalizedProgrammerId || !normalizedServiceKey || !services || typeof services !== "object") {
    return null;
  }

  if (normalizedServiceKey === "restV2") {
    const candidates = collectRestV2AppCandidatesFromPremiumApps(services).filter(
      (entry) => String(entry?.guid || "").trim() !== excludedGuid
    );
    return (
      selectPreferredRestV2AppForRequestor(candidates, normalizedRequestorId, normalizedProgrammerId) ||
      candidates[0] ||
      null
    );
  }

  if (normalizedServiceKey === "degradation") {
    const candidates = resolveDegradationAppCandidates(normalizedProgrammerId, services?.degradation || null, {
      requestorId: normalizedRequestorId,
      preferredGuid: "",
    }).filter((entry) => String(entry?.guid || "").trim() !== excludedGuid);
    return candidates[0] || null;
  }

  return null;
}

function promoteRecoveredPremiumServiceApp(programmerId = "", serviceKey = "", appInfo = null, options = {}) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const normalizedServiceKey = String(serviceKey || "").trim();
  const normalizedRequestorId = String(options?.requestorId || "").trim();
  if (!normalizedProgrammerId || !normalizedServiceKey || !appInfo?.guid) {
    return;
  }

  const services = getCurrentPremiumAppsSnapshot(normalizedProgrammerId);
  if (!services || typeof services !== "object") {
    return;
  }

  if (normalizedServiceKey === "restV2") {
    const nextServices = {
      ...services,
      restV2: appInfo,
    };
    nextServices.restV2Apps = collectPassVaultServiceCredentialCandidates(normalizedProgrammerId, "restV2", nextServices);
    setCurrentPremiumAppsSnapshot(normalizedProgrammerId, nextServices);
    if (normalizedRequestorId) {
      const existingContext = getRequestorScopedRestV2AuthContext(normalizedRequestorId) || {};
      const existingGuids = Array.isArray(existingContext.candidateGuids) ? existingContext.candidateGuids : [];
      setRequestorScopedRestV2AuthContext(normalizedRequestorId, {
        ...existingContext,
        programmerId: normalizedProgrammerId,
        preferredAppGuid: String(appInfo.guid || "").trim(),
        candidateGuids: [...new Set([String(appInfo.guid || "").trim(), ...existingGuids])],
      });
    }
    return;
  }

  if (normalizedServiceKey === "degradation") {
    promoteDegradationAppForProgrammer(normalizedProgrammerId, appInfo, {
      requestorId: normalizedRequestorId,
      preferredGuid: String(appInfo.guid || "").trim(),
    });
  }
}

async function recoverPremiumServiceSelection(programmerId = "", appInfo = null, debugMeta = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const serviceKey = resolvePremiumServiceKeyForAuth(appInfo, debugMeta);
  const requestorId = String(debugMeta?.requestorId || "").trim();
  const failedGuid = String(appInfo?.guid || "").trim();
  if (!normalizedProgrammerId || !serviceKey) {
    return null;
  }

  const programmer =
    state.programmers.find((item) => String(item?.programmerId || "").trim() === normalizedProgrammerId) || null;
  if (!programmer) {
    return null;
  }

  const services =
    (await primeProgrammerServiceHydration(programmer, getRuntimePremiumServicesSeed(normalizedProgrammerId), {
      forceRefresh: true,
      controllerReason: `${serviceKey}-auto-recovery`,
    }).catch(() => null)) ||
    getCurrentPremiumAppsSnapshot(normalizedProgrammerId) ||
    null;
  if (services) {
    setCurrentPremiumAppsSnapshot(normalizedProgrammerId, services);
  }

  const recoveredAppInfo = selectRecoveredPremiumServiceApp(normalizedProgrammerId, serviceKey, services, {
    requestorId,
    excludedGuid: failedGuid,
  });
  if (!recoveredAppInfo?.guid) {
    return null;
  }

  promoteRecoveredPremiumServiceApp(normalizedProgrammerId, serviceKey, recoveredAppInfo, {
    requestorId,
  });

  const selectedProgrammer = resolveSelectedProgrammer();
  if (String(selectedProgrammer?.programmerId || "").trim() === normalizedProgrammerId && services) {
    renderPremiumServices(getCurrentPremiumAppsSnapshot(normalizedProgrammerId) || services, selectedProgrammer, {
      controllerReason: `${serviceKey}-auto-recovery`,
    });
  }

  return {
    programmer,
    services: getCurrentPremiumAppsSnapshot(normalizedProgrammerId) || services,
    appInfo: recoveredAppInfo,
  };
}

async function ensureDcrAccessTokenWithServiceRecovery(programmerId, appInfo, forceRefresh = false, debugMeta = null) {
  if (isEsmServiceDebugMeta(debugMeta)) {
    return ensureDcrAccessTokenWithEsmRecovery(programmerId, appInfo, forceRefresh, debugMeta);
  }

  let resolvedAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, appInfo, debugMeta) || appInfo;
  try {
    const accessToken = await ensureDcrAccessToken(programmerId, resolvedAppInfo, forceRefresh, debugMeta);
    resolvedAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, resolvedAppInfo, debugMeta) || resolvedAppInfo;
    return {
      accessToken,
      appInfo: resolvedAppInfo,
      recovered: false,
    };
  } catch (error) {
    if (!shouldAttemptAlternatePremiumServiceRecovery(error, resolvedAppInfo, debugMeta)) {
      throw error;
    }
    const recovered = await recoverPremiumServiceSelection(programmerId, resolvedAppInfo, debugMeta);
    const recoveredAppInfo = recovered?.appInfo || null;
    if (!recoveredAppInfo?.guid || String(recoveredAppInfo.guid || "").trim() === String(resolvedAppInfo?.guid || "").trim()) {
      throw error;
    }
    return {
      accessToken: await ensureDcrAccessToken(programmerId, recoveredAppInfo, true, debugMeta),
      appInfo: recoveredAppInfo,
      services: recovered?.services || null,
      recovered: true,
    };
  }
}

async function fetchWithPremiumAuth(programmerId, appInfo, url, options = {}, retryStage = "refresh", debugMeta = null) {
  const debugFlowId = String(debugMeta?.flowId || "").trim();
  const workspaceKey = normalizeWorkspaceDebugKey(debugMeta?.workspaceKey || debugMeta?.workspaceOrigin || "");
  const workspaceOrigin = firstNonEmptyString([debugMeta?.workspaceOrigin, getWorkspaceDebugLabel(workspaceKey)]);
  const forceFreshDcrToken = debugMeta?.forceFreshToken === true;
  let resolvedAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, appInfo, debugMeta) || appInfo;
  const tokenResult = await ensureDcrAccessTokenWithServiceRecovery(
    programmerId,
    resolvedAppInfo,
    forceFreshDcrToken,
    {
      ...(debugMeta && typeof debugMeta === "object" ? debugMeta : {}),
      allowProvisioning: debugMeta?.allowProvisioning !== false,
    }
  );
  resolvedAppInfo = tokenResult?.appInfo || resolvedAppInfo;
  const token = tokenResult?.accessToken || "";
  const headers = new Headers(options.headers || {});
  headers.set("Authorization", `Bearer ${token}`);
  if (!headers.has("Accept")) {
    headers.set("Accept", "application/json");
  }
  const requestMethod = String(options.method || "GET").toUpperCase();
  const requestBodyPreview =
    typeof options.body === "string" ? truncateDebugText(options.body, 4000) : options.body ? "[non-string body]" : "";

  emitRestV2DebugEvent(debugFlowId, {
    source: "extension",
    phase: "restv2-request",
    method: requestMethod,
    url: String(url || ""),
    retryStage,
    programmerId: String(programmerId || ""),
    appGuid: String(resolvedAppInfo?.guid || ""),
    appName: String(resolvedAppInfo?.appName || ""),
    requestHeaders: toDebugHeadersObject(headers),
    requestBodyPreview,
    requestorId: String(debugMeta?.requestorId || ""),
    mvpd: String(debugMeta?.mvpd || ""),
    requestorIds: Array.isArray(debugMeta?.requestorIds) ? debugMeta.requestorIds.slice(0, 24) : [],
    mvpdIds: Array.isArray(debugMeta?.mvpdIds) ? debugMeta.mvpdIds.slice(0, 24) : [],
    requestScope: String(debugMeta?.scope || ""),
    service: String(debugMeta?.service || ""),
    endpointUrl: String(debugMeta?.endpointUrl || ""),
    cardId: String(debugMeta?.cardId || ""),
    workspaceKey,
    workspaceOrigin,
  });

  const response = await fetchWithRateLimitRetry(
    () =>
      fetch(url, {
        ...options,
        mode: options.mode || "cors",
        credentials: options.credentials ?? "omit",
        referrerPolicy: options.referrerPolicy || "no-referrer",
        headers,
      }),
    "Premium API",
    {
      onRetry: ({ attempt, maxRetries, delayMs }) => {
        const delaySeconds = Math.max(1, Math.ceil(delayMs / 1000));
        setStatus(`Premium API rate-limited. Retrying in ${delaySeconds}s (${attempt}/${maxRetries})...`, "info");
      },
    }
  );
  let responsePreview = "";
  try {
    responsePreview = truncateDebugText(await response.clone().text(), 4000);
  } catch {
    responsePreview = "";
  }

  emitRestV2DebugEvent(debugFlowId, {
    source: "extension",
    phase: "restv2-response",
    method: requestMethod,
    url: String(url || ""),
    status: Number(response.status || 0),
    statusText: String(response.statusText || ""),
    retryStage,
    programmerId: String(programmerId || ""),
    appGuid: String(resolvedAppInfo?.guid || ""),
    appName: String(resolvedAppInfo?.appName || ""),
    responseHeaders: toDebugHeadersObject(response.headers),
    responsePreview,
    requestorId: String(debugMeta?.requestorId || ""),
    mvpd: String(debugMeta?.mvpd || ""),
    requestorIds: Array.isArray(debugMeta?.requestorIds) ? debugMeta.requestorIds.slice(0, 24) : [],
    mvpdIds: Array.isArray(debugMeta?.mvpdIds) ? debugMeta.mvpdIds.slice(0, 24) : [],
    requestScope: String(debugMeta?.scope || ""),
    service: String(debugMeta?.service || ""),
    endpointUrl: String(debugMeta?.endpointUrl || ""),
    cardId: String(debugMeta?.cardId || ""),
    workspaceKey,
    workspaceOrigin,
  });

  if (response.status === 401 && retryStage === "refresh") {
    const bodyText = await response.clone().text().catch(() => "");
    if (isServiceProviderTokenMismatchError(bodyText)) {
      return response;
    }
    emitRestV2DebugEvent(debugFlowId, {
      source: "extension",
      phase: "restv2-retry",
      reason: "401-refresh",
      url: String(url || ""),
      status: 401,
      responsePreview: truncateDebugText(bodyText, 1200),
      service: String(debugMeta?.service || ""),
      requestScope: String(debugMeta?.scope || ""),
      workspaceKey,
      workspaceOrigin,
    });
    const retryAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, resolvedAppInfo, debugMeta) || resolvedAppInfo;
    await ensureDcrAccessToken(programmerId, retryAppInfo, true, debugMeta);
    return fetchWithPremiumAuth(programmerId, retryAppInfo, url, options, "reprovision", debugMeta);
  }

  if (response.status === 401 && retryStage === "reprovision") {
    const bodyText = await response.clone().text().catch(() => "");
    if (isServiceProviderTokenMismatchError(bodyText)) {
      return response;
    }
    emitRestV2DebugEvent(debugFlowId, {
      source: "extension",
      phase: "restv2-retry",
      reason: "401-reprovision",
      url: String(url || ""),
      status: 401,
      responsePreview: truncateDebugText(bodyText, 1200),
      service: String(debugMeta?.service || ""),
      requestScope: String(debugMeta?.scope || ""),
      workspaceKey,
      workspaceOrigin,
    });
    const retryAppInfo = resolveLatestPremiumServiceAppInfo(programmerId, resolvedAppInfo, debugMeta) || resolvedAppInfo;
    clearDcrTokenCache(programmerId, retryAppInfo.guid);
    await ensureDcrAccessToken(programmerId, retryAppInfo, true, debugMeta);
    return fetchWithPremiumAuth(programmerId, retryAppInfo, url, options, "none", debugMeta);
  }

  if (response.status === 401 && retryStage === "none" && isEsmServiceDebugMeta(debugMeta)) {
    const bodyText = await response.clone().text().catch(() => "");
    if (isServiceProviderTokenMismatchError(bodyText)) {
      return response;
    }
    const recovered = await recoverEsmServiceSelection(programmerId, {
      requestorId: String(debugMeta?.requestorId || "").trim(),
    }).catch(() => null);
    const recoveredAppInfo = recovered?.appInfo || null;
    if (recoveredAppInfo?.guid && String(recoveredAppInfo.guid || "").trim() !== String(resolvedAppInfo?.guid || "").trim()) {
      emitRestV2DebugEvent(debugFlowId, {
        source: "extension",
        phase: "restv2-retry",
        reason: "401-esm-recovery",
        url: String(url || ""),
        status: 401,
        responsePreview: truncateDebugText(bodyText, 1200),
        service: String(debugMeta?.service || ""),
        requestScope: String(debugMeta?.scope || ""),
        appGuid: String(recoveredAppInfo?.guid || ""),
        appName: String(recoveredAppInfo?.appName || recoveredAppInfo?.guid || ""),
        workspaceKey,
        workspaceOrigin,
      });
      return fetchWithPremiumAuth(programmerId, recoveredAppInfo, url, options, "esm-recovery", debugMeta);
    }
  }

  return response;
}

function getProgrammerCandidatesForRequestor(requestorId) {
  if (!requestorId) {
    return [];
  }

  const selectedProgrammer = resolveSelectedProgrammer();
  if (selectedProgrammer && Array.isArray(selectedProgrammer.requestorIds) && selectedProgrammer.requestorIds.includes(requestorId)) {
    return [selectedProgrammer];
  }

  const scoped = state.programmers.filter((item) => {
    return Array.isArray(item.requestorIds) && item.requestorIds.includes(requestorId);
  });

  if (scoped.length > 0) {
    return scoped;
  }

  return state.programmers.filter((item) => Array.isArray(item.requestorIds) && item.requestorIds.includes(requestorId));
}

function normalizeCmMatchText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function tokenizeCmMatchText(value) {
  return normalizeCmMatchText(value)
    .split(/\s+/)
    .map((token) => token.trim())
    .filter((token) => token.length > 0);
}

function normalizeCmUrl(value) {
  const raw = String(value || "").trim();
  if (!raw || !/^https?:\/\//i.test(raw)) {
    return "";
  }
  try {
    const parsed = new URL(raw);
    return parsed.toString();
  } catch {
    return raw;
  }
}

function isAllowedCmRequestUrl(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return false;
  }
  return isCmRelayEligibleUrl(raw);
}

function collectCmUrlsFromValue(value, options = {}) {
  const maxDepth = Math.max(1, Number(options.maxDepth || 4));
  const urls = new Set();
  const visited = new Set();
  const stack = [{ node: value, depth: 0 }];
  while (stack.length > 0) {
    const { node, depth } = stack.pop();
    if (node == null || depth > maxDepth) {
      continue;
    }
    if (typeof node === "string") {
      const normalized = normalizeCmUrl(node);
      if (normalized) {
        urls.add(normalized);
      }
      continue;
    }
    if (typeof node !== "object") {
      continue;
    }
    if (visited.has(node)) {
      continue;
    }
    visited.add(node);
    if (Array.isArray(node)) {
      node.forEach((item) => stack.push({ node: item, depth: depth + 1 }));
      continue;
    }
    Object.entries(node).forEach(([key, nested]) => {
      if (typeof nested === "string") {
        const normalized = normalizeCmUrl(nested);
        if (normalized) {
          urls.add(normalized);
        }
      }
      if (typeof nested === "object") {
        stack.push({ node: nested, depth: depth + 1 });
      }
      if (typeof nested === "string" && /(url|href|link|endpoint|api)/i.test(key)) {
        const normalized = normalizeCmUrl(nested);
        if (normalized) {
          urls.add(normalized);
        }
      }
    });
  }
  return [...urls];
}

function collectCmCollections(value, options = {}) {
  const preferredKeys = Array.isArray(options.preferredKeys)
    ? options.preferredKeys.map((key) => String(key || "").toLowerCase()).filter(Boolean)
    : [];
  const maxDepth = Math.max(1, Number(options.maxDepth || 4));
  const output = [];
  const visited = new Set();
  const stack = [{ node: value, key: "$root", depth: 0 }];
  while (stack.length > 0) {
    const { node, key, depth } = stack.pop();
    if (node == null || depth > maxDepth) {
      continue;
    }
    if (typeof node !== "object") {
      continue;
    }
    if (visited.has(node)) {
      continue;
    }
    visited.add(node);

    if (Array.isArray(node)) {
      const objectCount = node.reduce((count, item) => count + (item && typeof item === "object" ? 1 : 0), 0);
      const normalizedKey = String(key || "").toLowerCase();
      const preferred = preferredKeys.some((preferredKey) => normalizedKey === preferredKey || normalizedKey.includes(preferredKey));
      output.push({
        key: normalizedKey || "$root",
        depth,
        preferred,
        objectCount,
        values: node,
      });
      node.forEach((item) => {
        if (item && typeof item === "object") {
          stack.push({ node: item, key: normalizedKey, depth: depth + 1 });
        }
      });
      continue;
    }

    Object.entries(node).forEach(([childKey, childValue]) => {
      stack.push({ node: childValue, key: childKey, depth: depth + 1 });
    });
  }

  output.sort((left, right) => {
    if (left.preferred !== right.preferred) {
      return left.preferred ? -1 : 1;
    }
    if (left.objectCount !== right.objectCount) {
      return right.objectCount - left.objectCount;
    }
    if (left.values.length !== right.values.length) {
      return right.values.length - left.values.length;
    }
    return left.depth - right.depth;
  });
  return output;
}

function collectCmNameCandidates(item, extra = []) {
  const values = [];
  const pushValue = (value) => {
    if (value == null) {
      return;
    }
    if (Array.isArray(value)) {
      value.forEach((entry) => pushValue(entry));
      return;
    }
    if (typeof value === "object") {
      return;
    }
    const text = String(value || "").trim();
    if (!text) {
      return;
    }
    values.push(text);
  };

  if (item && typeof item === "object") {
    const payload = item.payload && typeof item.payload === "object" ? item.payload : null;
    pushValue(item.name);
    pushValue(item.displayName);
    pushValue(item.display_name);
    pushValue(item.title);
    pushValue(item.label);
    pushValue(item.tenantName);
    pushValue(item.tenant_name);
    pushValue(item.shortName);
    pushValue(item.short_name);
    pushValue(item.code);
    pushValue(item.groupName);
    pushValue(item.group_name);
    pushValue(item.slug);
    pushValue(item.id);
    pushValue(item.tenantId);
    pushValue(item.tenant_id);
    pushValue(item.uuid);
    pushValue(item.consoleId);
    pushValue(item.consoleOwnerId);
    pushValue(item.requestorId);
    pushValue(item.requestor_id);
    if (payload) {
      pushValue(payload.name);
      pushValue(payload.displayName);
      pushValue(payload.display_name);
      pushValue(payload.title);
      pushValue(payload.label);
      pushValue(payload.id);
      pushValue(payload.ownerId);
      pushValue(payload.tenantId);
      pushValue(payload.tenant_id);
      pushValue(payload.orgId);
      pushValue(payload.org_id);
      pushValue(payload.policyId);
      pushValue(payload.policy_id);
      pushValue(payload.applicationId);
      pushValue(payload.application_id);
      pushValue(payload.consoleId);
      pushValue(payload.consoleOwnerId);
      pushValue(payload.code);
      pushValue(payload.slug);
    }
  }
  pushValue(extra);
  return uniqueSorted(values);
}

function extractCmTenantIdFromUrl(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  const readSegments = (text) =>
    String(text || "")
      .split("/")
      .map((segment) => decodeURIComponent(String(segment || "").trim()))
      .filter(Boolean);
  try {
    const parsed = new URL(raw);
    const segments = readSegments(parsed.pathname);
    for (let index = 0; index < segments.length; index += 1) {
      const part = String(segments[index] || "").toLowerCase();
      if ((part === "tenant" || part === "tenants") && segments[index + 1]) {
        return String(segments[index + 1] || "").trim();
      }
    }
    const hashText = String(parsed.hash || "").replace(/^#/, "");
    if (hashText) {
      const hashSegments = readSegments(hashText);
      for (let index = 0; index < hashSegments.length; index += 1) {
        const part = String(hashSegments[index] || "").toLowerCase();
        if ((part === "tenant" || part === "tenants") && hashSegments[index + 1]) {
          return String(hashSegments[index + 1] || "").trim();
        }
      }
      if (hashSegments.length >= 1 && hashSegments.some((part) => String(part).toLowerCase() === "cm-console")) {
        return String(hashSegments[hashSegments.length - 1] || "").trim();
      }
    }
  } catch {
    // Ignore URL parse errors.
  }
  return "";
}

function normalizeCmTenantRecord(item, index = 0, sourceUrl = "") {
  if (item == null) {
    return null;
  }
  if (typeof item !== "object") {
    const primitiveName = String(item || "").trim();
    if (!primitiveName) {
      return null;
    }
    return {
      tenantId: primitiveName,
      tenantName: primitiveName,
      aliases: collectCmNameCandidates(null, [primitiveName]),
      links: sourceUrl ? [sourceUrl] : [],
      raw: item,
      sourceUrl: String(sourceUrl || ""),
    };
  }
  const keys = Object.keys(item).map((key) => String(key || "").toLowerCase());
  const payload = item.payload && typeof item.payload === "object" ? item.payload : null;
  const hasTenantSignal =
    keys.some((key) => key.includes("tenant")) ||
    item.tenantId != null ||
    item.tenant_id != null ||
    item.tenantName != null ||
    item.tenant_name != null ||
    item.consoleId != null ||
    item.consoleOwnerId != null ||
    payload?.tenantId != null ||
    payload?.tenant_id != null ||
    payload?.name != null ||
    payload?.ownerId != null;
  const hasEntityIdentity =
    Boolean(
      firstNonEmptyString([
        item.id,
        item.uuid,
        item.slug,
        item.code,
        item.consoleId,
        item.consoleOwnerId,
        payload?.id,
        payload?.ownerId,
      ])
    ) &&
    Boolean(
      firstNonEmptyString([
        item.name,
        item.displayName,
        item.display_name,
        item.title,
        item.label,
        payload?.name,
        payload?.displayName,
        payload?.display_name,
        payload?.title,
      ])
    );
  const sourceLooksLikeCmCatalog = /(?:cm-console|adobeprimetime\.com|\/cm\/|\/tenant|\/tenants|\/applications|\/policies|\/usage|\/cmu)/i.test(
    String(sourceUrl || "")
  );
  if (!hasTenantSignal && !(hasEntityIdentity && sourceLooksLikeCmCatalog)) {
    return null;
  }
  const links = uniqueSorted(collectCmUrlsFromValue(item).concat(sourceUrl ? [sourceUrl] : []));
  const tenantIdFromLink = firstNonEmptyString(links.map((url) => extractCmTenantIdFromUrl(url)));
  const consoleId = firstNonEmptyString([item.consoleId, payload?.consoleId, payload?.console_id]);
  const tenantId = firstNonEmptyString([
    consoleId,
    item.tenantId,
    item.tenant_id,
    item.id,
    item.uuid,
    item.slug,
    item.code,
    item.tenant,
    payload?.tenantId,
    payload?.tenant_id,
    payload?.id,
    tenantIdFromLink,
    item.name,
    payload?.name,
  ]);
  const tenantName = firstNonEmptyString([
    item.tenantName,
    item.tenant_name,
    item.displayName,
    item.display_name,
    item.tenant,
    item.name,
    item.title,
    payload?.name,
    payload?.displayName,
    payload?.display_name,
    payload?.title,
    consoleId,
    tenantIdFromLink,
    tenantId,
  ]);
  if (!tenantId && !tenantName) {
    return null;
  }
  const aliases = collectCmNameCandidates(item, [consoleId, tenantId, tenantName]);
  return {
    tenantId: String(tenantId || tenantName || `tenant-${index + 1}`),
    tenantName: String(tenantName || tenantId || `Tenant ${index + 1}`),
    aliases,
    links,
    raw: item,
    sourceUrl: String(sourceUrl || ""),
  };
}

function normalizeCmEntityRecord(kind, item, index = 0, tenant = null, fallbackUrl = "") {
  if (!item || typeof item !== "object") {
    return null;
  }
  const kindValue = String(kind || "").trim().toLowerCase();
  const payload = item.payload && typeof item.payload === "object" ? item.payload : null;
  const policyId = firstNonEmptyString([
    item.policyId,
    item.policy_id,
    item.policy?.id,
    payload?.policyId,
    payload?.policy_id,
    payload?.policy?.id,
  ]);
  const applicationId = firstNonEmptyString([
    item.applicationId,
    item.application_id,
    item.appId,
    item.app_id,
    kindValue === "applications" ? item.id : "",
    kindValue === "applications" ? item.uuid : "",
    kindValue === "applications" ? item.slug : "",
    payload?.applicationId,
    payload?.application_id,
    payload?.appId,
    payload?.app_id,
    kindValue === "applications" ? payload?.id : "",
    kindValue === "applications" ? payload?.uuid : "",
    kindValue === "applications" ? payload?.slug : "",
  ]);
  const genericEntityId = firstNonEmptyString([
    item.consoleId,
    item.id,
    item.ruleId,
    item.rule_id,
    item.usageId,
    item.usage_id,
    item.uuid,
    item.slug,
    payload?.id,
    payload?.ruleId,
    payload?.rule_id,
    payload?.usageId,
    payload?.usage_id,
  ]);
  const entityId = firstNonEmptyString([
    kindValue === "applications" ? applicationId : "",
    kindValue === "policies" ? policyId : "",
    genericEntityId,
    policyId,
    applicationId,
    item.name,
    payload?.name,
  ]);
  const name = firstNonEmptyString([
    item.name,
    item.displayName,
    item.display_name,
    item.applicationName,
    item.application_name,
    item.policyName,
    item.policy_name,
    item.ruleName,
    item.rule_name,
    item.title,
    item.label,
    payload?.name,
    payload?.displayName,
    payload?.display_name,
    payload?.applicationName,
    payload?.application_name,
    payload?.policyName,
    payload?.policy_name,
    payload?.ruleName,
    payload?.rule_name,
    payload?.title,
    payload?.label,
    entityId,
  ]);
  if (!entityId && !name) {
    return null;
  }
  const linkCandidates = collectCmUrlsFromValue(item)
    .concat(payload ? collectCmUrlsFromValue(payload) : [])
    .concat(fallbackUrl ? [fallbackUrl] : []);
  const tenantId = String(tenant?.tenantId || "").trim();
  const detailPolicyId = firstNonEmptyString([policyId, kindValue === "policies" ? entityId : ""]);
  const detailApplicationId = firstNonEmptyString([
    applicationId,
    kindValue === "applications" ? entityId : "",
    kindValue === "applications" ? item.id : "",
    kindValue === "applications" ? payload?.id : "",
  ]);
  if (kindValue === "policies" && tenantId && detailPolicyId) {
    linkCandidates.push(
      `${CM_CONFIG_BASE_URL}/maitai/policy/${encodeURIComponent(String(detailPolicyId || "").trim())}?orgId=${encodeURIComponent(
        tenantId
      )}`
    );
  }
  if (kindValue === "applications" && tenantId && detailApplicationId) {
    linkCandidates.push(
      `${CM_CONFIG_BASE_URL}/maitai/applications/${encodeURIComponent(
        String(detailApplicationId || "").trim()
      )}?orgId=${encodeURIComponent(tenantId)}`
    );
  }
  const links = uniqueSorted(linkCandidates.map((value) => normalizeCmUrl(value)).filter(Boolean));
  return {
    kind: kindValue,
    entityId: String(entityId || name || `${kind}-${index + 1}`),
    name: String(name || entityId || `${kind}-${index + 1}`),
    policyId: String(detailPolicyId || ""),
    applicationId: String(detailApplicationId || applicationId || ""),
    tenantId: String(tenant?.tenantId || ""),
    tenantName: String(tenant?.tenantName || ""),
    aliases: collectCmNameCandidates(item, [entityId, name]),
    links,
    raw: payload || item,
    sourceUrl: String(fallbackUrl || ""),
  };
}

function normalizeCmTenantsFromPayload(payload, sourceUrl = "") {
  const pushUniqueTenant = (target, seen, item, index = 0) => {
    const record = normalizeCmTenantRecord(item, index, sourceUrl);
    if (!record) {
      return false;
    }
    const key = normalizeCmMatchText(`${record.tenantId}|${record.tenantName}`);
    if (!key || seen.has(key)) {
      return false;
    }
    seen.add(key);
    target.push(record);
    return true;
  };

  const collections = collectCmCollections(payload, {
    preferredKeys: ["tenants", "tenant", "items", "results", "data"],
    maxDepth: 5,
  });
  const tenants = [];
  const seen = new Set();
  collections.forEach((collection) => {
    collection.values.forEach((item, index) => {
      pushUniqueTenant(tenants, seen, item, index);
    });
  });

  // Defensive fallback: some CM endpoints return object maps instead of arrays.
  if (tenants.length === 0) {
    const objectPayload = payload && typeof payload === "object" ? payload : null;
    if (Array.isArray(payload)) {
      payload.forEach((item, index) => {
        pushUniqueTenant(tenants, seen, item, index);
      });
    } else if (objectPayload) {
      const preferredKeys = new Set(["tenants", "tenant", "items", "results", "data"]);
      const candidateContainers = [];
      Object.entries(objectPayload).forEach(([key, value]) => {
        const normalizedKey = String(key || "").trim().toLowerCase();
        if (!normalizedKey) {
          return;
        }
        if ([...preferredKeys].some((preferredKey) => normalizedKey === preferredKey || normalizedKey.includes(preferredKey))) {
          candidateContainers.push(value);
        }
      });
      if (candidateContainers.length === 0) {
        candidateContainers.push(objectPayload);
      }

      candidateContainers.forEach((container, containerIndex) => {
        if (Array.isArray(container)) {
          container.forEach((item, index) => {
            pushUniqueTenant(tenants, seen, item, index);
          });
          return;
        }
        if (!container || typeof container !== "object") {
          return;
        }
        let pushedChild = false;
        Object.values(container).forEach((child, index) => {
          if (!child || typeof child !== "object") {
            return;
          }
          if (pushUniqueTenant(tenants, seen, child, index)) {
            pushedChild = true;
          }
        });
        if (!pushedChild) {
          pushUniqueTenant(tenants, seen, container, containerIndex);
        }
      });
    }
  }

  return tenants;
}

function normalizeCmResourceListFromPayload(kind, payload, tenant = null, fallbackUrl = "") {
  const kindValue = String(kind || "").trim().toLowerCase();
  const preferredByKind = {
    applications: ["applications", "application", "apps", "items", "data", "results"],
    policies: ["policies", "policy", "rules", "items", "data", "results"],
    usage: ["usage", "cmu", "metrics", "reports", "items", "data", "results"],
  };
  const collections = collectCmCollections(payload, {
    preferredKeys: preferredByKind[kindValue] || ["items", "data", "results"],
    maxDepth: 5,
  });
  const rows = [];
  const seen = new Set();
  collections.forEach((collection) => {
    collection.values.forEach((item, index) => {
      const record = normalizeCmEntityRecord(kindValue, item, index, tenant, fallbackUrl);
      if (!record) {
        return;
      }
      const key = normalizeCmMatchText(`${record.kind}|${record.entityId}|${record.name}|${record.tenantId}`);
      if (seen.has(key)) {
        return;
      }
      seen.add(key);
      rows.push(record);
    });
  });
  return rows;
}

function getCmConsoleTopLevelCollection(payload = null, preferredKeys = []) {
  if (Array.isArray(payload)) {
    return payload.filter((entry) => entry && typeof entry === "object");
  }
  if (!payload || typeof payload !== "object") {
    return [];
  }
  const normalizedPreferredKeys = (Array.isArray(preferredKeys) ? preferredKeys : [])
    .map((key) => String(key || "").trim().toLowerCase())
    .filter(Boolean);
  for (const preferredKey of normalizedPreferredKeys) {
    const directValue = payload?.[preferredKey];
    if (Array.isArray(directValue)) {
      return directValue.filter((entry) => entry && typeof entry === "object");
    }
    const caseInsensitiveKey = Object.keys(payload).find((key) => String(key || "").trim().toLowerCase() === preferredKey);
    if (caseInsensitiveKey && Array.isArray(payload?.[caseInsensitiveKey])) {
      return payload[caseInsensitiveKey].filter((entry) => entry && typeof entry === "object");
    }
  }
  return [];
}

function countCmConsoleSummaryRows(kind = "", payload = null) {
  const normalizedKind = String(kind || "").trim().toLowerCase();
  const preferredKeysByKind = {
    tenant: ["tenants", "items", "data", "results"],
    applications: ["applications", "items", "data", "results"],
    policies: ["policies", "items", "data", "results"],
  };
  return getCmConsoleTopLevelCollection(payload, preferredKeysByKind[normalizedKind] || []).length;
}

function collectCmMatchVariants(values) {
  const variants = new Set();
  (Array.isArray(values) ? values : []).forEach((value) => {
    const normalized = normalizeCmMatchText(value);
    if (!normalized) {
      return;
    }
    variants.add(normalized);
    const parts = tokenizeCmMatchText(normalized);
    if (parts.length >= 2) {
      variants.add(parts.join(""));
      variants.add(parts.map((part) => String(part || "").charAt(0)).join(""));
    }
  });
  return [...variants];
}

function scoreCmTenantMatch(programmer, tenant) {
  const programmerCandidates = uniqueSorted([
    programmer?.mediaCompanyName,
    programmer?.programmerName,
    programmer?.programmerId,
  ]);
  const tenantCandidates = uniqueSorted([tenant?.tenantName, tenant?.tenantId, ...(tenant?.aliases || [])]);

  const programmerNormalized = collectCmMatchVariants(programmerCandidates);
  const tenantNormalized = collectCmMatchVariants(tenantCandidates);
  if (programmerNormalized.length === 0 || tenantNormalized.length === 0) {
    return 0;
  }

  let score = 0;
  programmerNormalized.forEach((pToken) => {
    tenantNormalized.forEach((tToken) => {
      if (pToken === tToken) {
        score = Math.max(score, 100);
        return;
      }
      if (pToken.includes(tToken) || tToken.includes(pToken)) {
        score = Math.max(score, Math.min(88, Math.max(38, Math.floor(Math.min(pToken.length, tToken.length) * 2.2))));
      }
      const pParts = new Set(tokenizeCmMatchText(pToken));
      const tParts = new Set(tokenizeCmMatchText(tToken));
      if (pParts.size === 0 || tParts.size === 0) {
        return;
      }
      let overlap = 0;
      pParts.forEach((part) => {
        if (tParts.has(part)) {
          overlap += 1;
        }
      });
      if (overlap > 0) {
        const ratio = overlap / Math.max(pParts.size, tParts.size);
        score = Math.max(score, Math.floor(22 + ratio * 48));
      }
    });
  });
  return score;
}

function normalizeCmConsoleKey(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "");
}

function collectCmEntityIdCandidates(values = []) {
  return uniqueSorted(
    (Array.isArray(values) ? values : [values])
      .map((value) => String(value || "").trim())
      .filter(Boolean)
      .map((value) => normalizeCmConsoleKey(value))
      .filter(Boolean)
  );
}

function collectCmEntityNameCandidates(values = []) {
  const output = new Set();
  const addCandidate = (value) => {
    const normalized = normalizeCmConsoleKey(value);
    if (!normalized) {
      return;
    }
    output.add(normalized);
  };

  (Array.isArray(values) ? values : [values]).forEach((value) => {
    const raw = String(value || "").trim();
    if (!raw) {
      return;
    }
    addCandidate(raw);

    const allWordTokens = raw
      .replace(/([a-z])([A-Z])/g, "$1 $2")
      .split(/[^A-Za-z0-9]+/g)
      .map((token) => normalizeCmConsoleKey(token))
      .filter((token) => token.length > 0);
    const wordTokens = allWordTokens.filter((token) => token.length >= 3);
    wordTokens.forEach((token) => output.add(token));
    if (allWordTokens.length >= 2) {
      const acronymAll = normalizeCmConsoleKey(allWordTokens.map((token) => String(token || "").charAt(0)).join(""));
      if (acronymAll.length >= 3) {
        output.add(acronymAll);
      }
      const joinedFirstTwo = normalizeCmConsoleKey(`${allWordTokens[0] || ""}${allWordTokens[1] || ""}`);
      if (joinedFirstTwo.length >= 3) {
        output.add(joinedFirstTwo);
      }
    }
    if (wordTokens.length >= 2) {
      const acronym = normalizeCmConsoleKey(wordTokens.map((token) => token.charAt(0)).join(""));
      if (acronym.length >= 3) {
        output.add(acronym);
      }
      const firstWord = normalizeCmConsoleKey(wordTokens[0]);
      if (firstWord.length >= 3) {
        output.add(firstWord);
      }
    }
    if (allWordTokens.length > 0) {
      const firstWordAny = normalizeCmConsoleKey(allWordTokens[0]);
      if (firstWordAny.length >= 2) {
        output.add(firstWordAny);
      }
    }
  });

  return uniqueSorted([...output]);
}

function collectCmProgrammerIdDerivedAliases(values = []) {
  const output = new Set();
  const suffixes = ["de", "dev", "qa", "uat", "test", "stage", "stg", "prod", "production"];
  (Array.isArray(values) ? values : [values]).forEach((value) => {
    const normalized = normalizeCmConsoleKey(value);
    if (!normalized) {
      return;
    }
    output.add(normalized);
    suffixes.forEach((suffix) => {
      if (!normalized.endsWith(suffix)) {
        return;
      }
      const stripped = normalized.slice(0, Math.max(0, normalized.length - suffix.length));
      if (stripped.length >= 3) {
        output.add(stripped);
      }
    });
  });
  return [...output];
}

function collectCmProgrammerIdCandidates(programmer = null) {
  const sourceEntity = programmer?.source?.entityData && typeof programmer.source.entityData === "object" ? programmer.source.entityData : {};
  const sourceKeyRaw = String(programmer?.source?.key || "").trim();
  const sourceKeyMatch = sourceKeyRaw.match(/^Programmer:(.+)$/i);
  const sourceKeyId = sourceKeyMatch ? String(sourceKeyMatch[1] || "").trim() : extractEntityIdFromToken(sourceKeyRaw);
  const baseCandidates = [
    programmer?.programmerId,
    sourceEntity?.id,
    sourceEntity?.programmerId,
    sourceEntity?.["programmer-id"],
    sourceEntity?.["media-company"],
    sourceEntity?.media_company,
    sourceEntity?.mediaCompany,
    sourceEntity?.mediaCompanyId,
    sourceEntity?.["media-company-id"],
    sourceKeyId,
  ];
  return uniqueSorted([...collectCmEntityIdCandidates(baseCandidates), ...collectCmProgrammerIdDerivedAliases(baseCandidates)]);
}

function collectCmProgrammerNameCandidates(programmer = null) {
  const sourceEntity = programmer?.source?.entityData && typeof programmer.source.entityData === "object" ? programmer.source.entityData : {};
  return collectCmEntityNameCandidates([
    programmer?.mediaCompanyName,
    programmer?.programmerName,
    sourceEntity?.displayName,
    sourceEntity?.["display-name"],
    sourceEntity?.name,
    sourceEntity?.mediaCompanyName,
    sourceEntity?.["media-company-name"],
    sourceEntity?.["media-company"],
    sourceEntity?.media_company,
    sourceEntity?.mediaCompany,
  ]);
}

function collectCmMvpdIdCandidates(mvpdId = "", mvpdMeta = null) {
  const baseCandidates = [
    mvpdId,
    mvpdMeta?.id,
    mvpdMeta?.mvpdId,
    mvpdMeta?.code,
    mvpdMeta?.identifier,
  ];
  const suffixes = ["ott", "sso", "prod", "production", "stage", "stg", "qa", "dev", "test", "live"];
  const derived = new Set();
  (Array.isArray(baseCandidates) ? baseCandidates : []).forEach((value) => {
    let normalized = normalizeCmConsoleKey(value);
    if (!normalized) {
      return;
    }
    derived.add(normalized);
    let changed = true;
    while (changed) {
      changed = false;
      for (const suffix of suffixes) {
        if (!normalized.endsWith(suffix)) {
          continue;
        }
        const stripped = normalizeCmConsoleKey(normalized.slice(0, Math.max(0, normalized.length - suffix.length)));
        if (stripped && stripped.length >= 3 && stripped !== normalized) {
          normalized = stripped;
          derived.add(normalized);
          changed = true;
          break;
        }
      }
    }
  });
  return uniqueSorted([...collectCmEntityIdCandidates(baseCandidates), ...derived]);
}

function collectCmMvpdNameCandidates(mvpdName = "", mvpdMeta = null, mvpdLabel = "") {
  return collectCmEntityNameCandidates([
    mvpdName,
    mvpdMeta?.name,
    mvpdMeta?.displayName,
    mvpdMeta?.label,
    mvpdMeta?.description,
    mvpdLabel,
  ]);
}

function collectCmTenantConsoleIdKeys(tenant) {
  const consoleId = firstNonEmptyString([
    tenant?.raw?.consoleId,
    tenant?.raw?.payload?.consoleId,
    tenant?.raw?.payload?.console_id,
    tenant?.tenantId,
  ]);
  const normalized = normalizeCmConsoleKey(consoleId);
  if (!normalized) {
    return [];
  }
  const output = new Set([normalized]);
  String(consoleId || "")
    .split(/[^A-Za-z0-9]+/g)
    .map((token) => normalizeCmConsoleKey(token))
    .filter(Boolean)
    .forEach((token) => {
      output.add(token);
    });
  return [...output];
}

function collectCmTenantIdKeys(tenant) {
  return collectCmEntityIdCandidates([
    tenant?.raw?.consoleId,
    tenant?.raw?.payload?.consoleId,
    tenant?.raw?.payload?.console_id,
    tenant?.tenantId,
  ]);
}

function collectCmTenantNameKeys(tenant) {
  return collectCmEntityNameCandidates([
    tenant?.tenantName,
    tenant?.raw?.payload?.name,
    tenant?.raw?.name,
    ...(Array.isArray(tenant?.aliases) ? tenant.aliases : []),
  ]);
}

function finalizeCmTenantMatches(matches = [], matchPass = "") {
  const seen = new Set();
  const output = [];
  (Array.isArray(matches) ? matches : []).forEach((tenant) => {
    if (!tenant || typeof tenant !== "object") {
      return;
    }
    const key = `${String(tenant?.tenantId || "").trim().toLowerCase()}|${String(tenant?.tenantName || "")
      .trim()
      .toLowerCase()}`;
    if (!key || seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push({
      ...tenant,
      matchPass: String(matchPass || tenant?.matchPass || "").trim(),
    });
  });
  return output;
}

function findCmTenantMatchesByPass(tenants = [], entityKeys = [], passType = "id", keyExtractor = null) {
  const normalizedEntityKeys = new Set(
    (Array.isArray(entityKeys) ? entityKeys : []).map((value) => normalizeCmConsoleKey(value)).filter(Boolean)
  );
  if (normalizedEntityKeys.size === 0 || typeof keyExtractor !== "function") {
    return [];
  }
  const matches = (Array.isArray(tenants) ? tenants : []).filter((tenant) => {
    const tenantKeys = new Set((Array.isArray(keyExtractor(tenant)) ? keyExtractor(tenant) : []).filter(Boolean));
    if (tenantKeys.size === 0) {
      return false;
    }
    for (const key of tenantKeys) {
      if (normalizedEntityKeys.has(normalizeCmConsoleKey(key))) {
        return true;
      }
    }
    return false;
  });
  return finalizeCmTenantMatches(matches, passType);
}

function findCmTenantMatchesByTwoPass(tenants = [], idCandidates = [], nameCandidates = []) {
  const idMatches = findCmTenantMatchesByPass(tenants, idCandidates, "id", collectCmTenantIdKeys);
  if (idMatches.length > 0) {
    return idMatches;
  }
  return findCmTenantMatchesByPass(tenants, nameCandidates, "name", collectCmTenantNameKeys);
}

function collectCmProgrammerConsoleKeys(programmer) {
  const baseCandidates = uniqueSorted(
    collectCmProgrammerIdCandidates(programmer).concat(collectCmProgrammerNameCandidates(programmer))
  );
  const keys = new Set();
  baseCandidates.forEach((value) => {
    const raw = String(value || "").trim();
    if (!raw) {
      return;
    }
    const fullKey = normalizeCmConsoleKey(raw);
    if (fullKey) {
      keys.add(fullKey);
    }
    raw
      .split(/[\s\-_/|:]+/g)
      .map((token) => normalizeCmConsoleKey(token))
      .filter(Boolean)
      .forEach((tokenKey) => {
        keys.add(tokenKey);
      });
  });

  // Business exception: Fox media company maps to two CM tenants.
  if (keys.has("fox")) {
    keys.add("foxsports");
  }

  return [...keys];
}

function collectCmTenantConsoleKeys(tenant) {
  const values = uniqueSorted([
    tenant?.raw?.consoleId,
    tenant?.tenantId,
    tenant?.tenantName,
    tenant?.raw?.payload?.name,
    ...(Array.isArray(tenant?.aliases) ? tenant.aliases : []),
  ]);
  const keys = new Set(
    values
      .map((value) => normalizeCmConsoleKey(value))
      .filter(Boolean)
  );
  return [...keys];
}

function isCmDirectTenantMatch(programmer, tenant) {
  const idMatches = findCmTenantMatchesByPass([tenant], collectCmProgrammerIdCandidates(programmer), "id", collectCmTenantIdKeys);
  if (idMatches.length > 0) {
    return true;
  }
  const nameMatches = findCmTenantMatchesByPass(
    [tenant],
    collectCmProgrammerNameCandidates(programmer),
    "name",
    collectCmTenantNameKeys
  );
  return nameMatches.length > 0;
}

function findCmTenantMatchesForProgrammer(programmer, tenants) {
  return findCmTenantMatchesByTwoPass(
    tenants,
    collectCmProgrammerIdCandidates(programmer),
    collectCmProgrammerNameCandidates(programmer)
  );
}

function findCmTenantMatchesForMvpd(mvpdId = "", mvpdName = "", tenants = [], options = {}) {
  const mvpdMeta = options?.mvpdMeta && typeof options.mvpdMeta === "object" ? options.mvpdMeta : null;
  const mvpdLabel = String(options?.mvpdLabel || "").trim();
  return findCmTenantMatchesByTwoPass(
    tenants,
    collectCmMvpdIdCandidates(mvpdId, mvpdMeta),
    collectCmMvpdNameCandidates(mvpdName, mvpdMeta, mvpdLabel)
  );
}

function getCmTenantScopeForProgrammer(programmer = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const serviceByProgrammerId =
    programmerId && state.cmServiceByProgrammerId instanceof Map
      ? state.cmServiceByProgrammerId.get(programmerId)
      : null;
  const selectedServiceByProgrammerId =
    programmerId && state.premiumAppsByProgrammerId instanceof Map
      ? getCurrentPremiumAppsSnapshot(programmerId)?.cm
      : null;
  const selectedProgrammer = resolveSelectedProgrammer();
  const selectedProgrammerService =
    !programmerId && selectedProgrammer?.programmerId && state.premiumAppsByProgrammerId instanceof Map
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)?.cm
      : null;
  return resolveCmUsageTenantScopeValue(
    serviceByProgrammerId?.matchedTenants?.[0]?.tenantId,
    serviceByProgrammerId?.matchedTenants?.[0]?.tenantName,
    selectedServiceByProgrammerId?.matchedTenants?.[0]?.tenantId,
    selectedServiceByProgrammerId?.matchedTenants?.[0]?.tenantName,
    selectedProgrammerService?.matchedTenants?.[0]?.tenantId,
    selectedProgrammerService?.matchedTenants?.[0]?.tenantName,
    programmer?.tenantId,
    programmer?.tenantName
  );
}

function hasReusableCmSnapshotForSelection(cmService = null) {
  if (!cmService || typeof cmService !== "object") {
    return false;
  }
  if (shouldRetryCachedCmService(cmService)) {
    return false;
  }
  if (isPassVaultBackedValue(cmService)) {
    return (
      (Array.isArray(cmService?.matchedTenants) && cmService.matchedTenants.length > 0) ||
      Boolean(String(cmService?.loadError || "").trim()) ||
      Boolean(String(cmService?.sourceUrl || "").trim()) ||
      Number(cmService?.fetchedAt || 0) > 0
    );
  }
  return true;
}

function emitCmTenantMatchDebugLine(programmer, catalog, matchedTenants, options = {}) {
  const resolvedMatches = Array.isArray(matchedTenants) ? matchedTenants : [];
  const idMatchCandidates = collectCmProgrammerIdCandidates(programmer).slice(0, 16);
  const nameMatchCandidates = collectCmProgrammerNameCandidates(programmer).slice(0, 16);
  const normalizedMediaCompanyKeys = collectCmProgrammerConsoleKeys(programmer).slice(0, 16);
  const normalizedMediaCompanyKey = String(normalizedMediaCompanyKeys[0] || "").trim();
  const matchedTenantConsoleIds = resolvedMatches
    .map((tenant) => String(tenant?.raw?.consoleId || tenant?.tenantId || tenant?.tenantName || "").trim())
    .filter(Boolean)
    .slice(0, 16);
  const matchedTenantConsoleIdsText = matchedTenantConsoleIds.join(", ");
  const selectedMediaCompany = String(programmer?.mediaCompanyName || programmer?.programmerName || programmer?.programmerId || "");
  const cmDecisionSummary = {
    selectedMediaCompany,
    idMatchCandidates,
    nameMatchCandidates,
    normalizedMediaCompanyKey,
    normalizedMediaCompanyKeys,
    matchedTenantConsoleIds,
    matchedTenantConsoleKeys: matchedTenantConsoleIds.map((value) => normalizeCmConsoleKey(value)).filter(Boolean),
    tenantCatalogSourceUrl: String(catalog?.sourceUrl || ""),
    tenantCatalogCount: Number(catalog?.tenants?.length || 0),
    matchedTenantCount: resolvedMatches.length,
    matchPass: String(resolvedMatches?.[0]?.matchPass || "").trim(),
    cacheState: String(options?.cacheState || "live"),
    traceLine: `CM detect | media-company="${selectedMediaCompany || "unknown"}" | normalized-key="${normalizedMediaCompanyKey || "none"}" | matched-consoleIds="${matchedTenantConsoleIdsText || "none"}"`,
  };
  logDecisionPoint("CM tenant match decision", cmDecisionSummary);
  emitCmDebugEvent({
    phase: "cm-tenant-match-decision",
    ...cmDecisionSummary,
  });
  return cmDecisionSummary;
}

function buildSelectedMvpdMatchContext(programmer = null) {
  const programmerId = String(programmer?.programmerId || "").trim();
  const requestorId = String(state.selectedRequestorId || "").trim();
  const mvpdId = String(state.selectedMvpdId || "").trim();
  if (!programmerId || !requestorId || !mvpdId) {
    return null;
  }
  const mvpdMeta = getRestV2MvpdMeta(requestorId, mvpdId);
  const mvpdName = String(firstNonEmptyString([mvpdMeta?.name, mvpdMeta?.displayName, mvpdId]) || mvpdId).trim();
  const mvpdLabel = getRestV2MvpdPickerLabel(requestorId, mvpdId, mvpdMeta);
  return {
    programmerId,
    requestorId,
    mvpdId,
    mvpdName,
    mvpdLabel,
    mvpdMeta,
    selectionKey: getCmMvpdSelectionKey(programmerId, requestorId, mvpdId),
  };
}

function emitCmTenantMatchDebugLineForMvpd(programmer, mvpdContext, catalog, matchedTenants, options = {}) {
  const resolvedMatches = Array.isArray(matchedTenants) ? matchedTenants : [];
  const idMatchCandidates = collectCmMvpdIdCandidates(mvpdContext?.mvpdId, mvpdContext?.mvpdMeta).slice(0, 16);
  const nameMatchCandidates = collectCmMvpdNameCandidates(
    mvpdContext?.mvpdName,
    mvpdContext?.mvpdMeta,
    mvpdContext?.mvpdLabel
  ).slice(0, 16);
  const normalizedMvpdKeys = idMatchCandidates.concat(nameMatchCandidates);
  const matchedTenantConsoleIds = resolvedMatches
    .map((tenant) => String(tenant?.raw?.consoleId || tenant?.tenantId || tenant?.tenantName || "").trim())
    .filter(Boolean)
    .slice(0, 16);
  const matchedTenantConsoleIdsText = matchedTenantConsoleIds.join(", ");
  const selectedMvpd = String(mvpdContext?.mvpdLabel || mvpdContext?.mvpdName || mvpdContext?.mvpdId || "");
  const cmDecisionSummary = {
    selectedMvpd,
    requestorId: String(mvpdContext?.requestorId || ""),
    mvpdId: String(mvpdContext?.mvpdId || ""),
    idMatchCandidates,
    nameMatchCandidates,
    normalizedMvpdKeys,
    matchedTenantConsoleIds,
    matchedTenantConsoleKeys: matchedTenantConsoleIds.map((value) => normalizeCmConsoleKey(value)).filter(Boolean),
    tenantCatalogSourceUrl: String(catalog?.sourceUrl || ""),
    tenantCatalogCount: Number(catalog?.tenants?.length || 0),
    matchedTenantCount: resolvedMatches.length,
    matchPass: String(resolvedMatches?.[0]?.matchPass || "").trim(),
    cacheState: String(options?.cacheState || "live"),
    traceLine: `CM detect (mvpd) | mvpd="${selectedMvpd || "unknown"}" | matched-consoleIds="${matchedTenantConsoleIdsText || "none"}"`,
  };
  logDecisionPoint("CM tenant match decision (MVPD)", cmDecisionSummary);
  emitCmDebugEvent({
    phase: "cm-tenant-match-decision-mvpd",
    programmerId: String(programmer?.programmerId || ""),
    programmerName: String(programmer?.programmerName || ""),
    ...cmDecisionSummary,
    workspaceKey: "mvpd-workspace",
    workspaceOrigin: "MVPD Workspace",
  });
  return cmDecisionSummary;
}

function cmGetTenantCacheKey(tenant) {
  const tenantId = normalizeCmMatchText(tenant?.tenantId);
  const tenantName = normalizeCmMatchText(tenant?.tenantName);
  const key = `${tenantId}|${tenantName}`.replace(/^\|+|\|+$/g, "");
  return key || "";
}

function buildCmTenantEndpointCandidates() {
  // Primary source remains the global CM console tenant catalog.
  // Keep additional candidates as a resiliency fallback across org partitions.
  const orderedCandidates = [
    `${CM_CONFIG_BASE_URL}/core/tenants?orgId=${encodeURIComponent(CM_DEFAULT_TENANT_ORG_HINT)}`,
    ...CM_TENANT_ENDPOINT_CANDIDATES,
  ]
    .map((value) => normalizeCmUrl(value))
    .filter((value) => {
      try {
        const parsed = new URL(String(value || ""));
        return String(parsed.searchParams.get("orgId") || "").trim().toLowerCase() === CM_DEFAULT_TENANT_ORG_HINT;
      } catch {
        return false;
      }
    })
    .filter(Boolean);
  const seen = new Set();
  const uniqueCandidates = [];
  orderedCandidates.forEach((value) => {
    const key = String(value || "").trim();
    if (!key || seen.has(key)) {
      return;
    }
    seen.add(key);
    uniqueCandidates.push(key);
  });
  return uniqueCandidates;
}

function normalizeBearerTokenValue(value) {
  return String(value || "")
    .trim()
    .replace(/^Bearer\s+/i, "")
    .trim();
}

function extractImsAccessTokenFromPayload(payload, rawText = "") {
  const normalizedRawText = String(rawText || "").trim();
  if (!payload && !normalizedRawText) {
    return "";
  }

  if (typeof payload === "string") {
    const directStringToken = normalizeBearerTokenValue(payload);
    if (isProbablyJwt(directStringToken)) {
      return directStringToken;
    }
  }

  if (payload && typeof payload === "object") {
    const nestedToken =
      payload.token && typeof payload.token === "object"
        ? firstNonEmptyString([
            payload.token.access_token,
            payload.token.accessToken,
            payload.token.token,
            payload.token.value,
          ])
        : payload.token;

    const structuredToken = normalizeBearerTokenValue(
      firstNonEmptyString([
        payload.access_token,
        payload.accessToken,
        nestedToken,
        payload.imsToken,
        payload.bearer,
        payload.authToken,
        payload.authorization,
        payload.Authorization,
        payload.value,
      ])
    );
    if (isProbablyJwt(structuredToken)) {
      return structuredToken;
    }

    const extracted = extractJwtAndUrls(payload);
    if (extracted.jwt && extracted.jwtScore >= 0 && isProbablyJwt(extracted.jwt)) {
      return extracted.jwt;
    }
  }

  const rawTextCandidates = [
    typeof payload === "string" ? String(payload || "").trim() : "",
    normalizedRawText,
  ].filter(Boolean);
  for (const candidateText of rawTextCandidates) {
    const structuredMatch = candidateText.match(
      /(?:access_token|accessToken|bearer|authorization|authToken|token)\s*(?:=|:)\s*["']?(Bearer\s+)?([A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+)/i
    );
    if (structuredMatch?.[2] && isProbablyJwt(structuredMatch[2])) {
      return normalizeBearerTokenValue(structuredMatch[2]);
    }
    const rawJwtMatch = candidateText.match(/[A-Za-z0-9_-]{20,}\.[A-Za-z0-9_-]{20,}\.[A-Za-z0-9_-]{20,}/);
    if (rawJwtMatch?.[0] && isProbablyJwt(rawJwtMatch[0])) {
      return normalizeBearerTokenValue(rawJwtMatch[0]);
    }
  }

  return "";
}

function isAccessTokenFreshEnough(accessToken = "", skewMs = 0) {
  const token = normalizeBearerTokenValue(accessToken);
  if (!token || !isProbablyJwt(token)) {
    return false;
  }

  const expiresAt = coercePositiveNumber(resolveAuthResponseExpiry(token, 0)?.expiresAt);
  if (!expiresAt) {
    return true;
  }
  return expiresAt > Date.now() + Math.max(0, Number(skewMs) || 0);
}

function tokenizeScopeSet(scopeValue = "") {
  return String(scopeValue || "")
    .split(/[\s,]+/g)
    .map((scope) => String(scope || "").trim().toLowerCase())
    .filter(Boolean);
}

function isCmConsoleClientId(value = "") {
  return String(value || "").trim().toLowerCase() === CM_IMS_PRIMARY_CLIENT_ID;
}

function getConfiguredUnderparImsClientId() {
  const runtimeConfig = getActiveUnderparImsRuntimeConfig();
  return firstNonEmptyString([
    runtimeConfig?.clientId,
    state.loginData?.imsSession?.clientId,
    state.loginData?.imsSession?.client_id,
  ]);
}

function isUnderparImsClientId(value = "") {
  const normalizedValue = String(value || "").trim().toLowerCase();
  const configuredClientId = String(getConfiguredUnderparImsClientId() || "")
    .trim()
    .toLowerCase();
  return Boolean(normalizedValue && configuredClientId && normalizedValue === configuredClientId);
}

function getPreferredPrimaryImsAccessTokenCandidate() {
  const token = normalizeBearerTokenValue(firstNonEmptyString([state.loginData?.accessToken || ""]));
  if (!token || tokenSupportsCmTenantCatalog(token)) {
    return "";
  }
  return token;
}

function getPreferredAdobeConsoleAccessTokenCandidate() {
  return normalizeBearerTokenValue(getPreferredPrimaryImsAccessTokenCandidate());
}

function getPreferredCmRequestAccessTokenCandidate() {
  return normalizeBearerTokenValue(
    firstNonEmptyString([
      state.cmLastHydratedAccessToken || "",
      state.loginData?.cmConsoleAccessToken || "",
    ])
  );
}

function getPreferredCmAccessTokenCandidate() {
  return normalizeBearerTokenValue(firstNonEmptyString([state.cmLastHydratedAccessToken || "", state.loginData?.cmConsoleAccessToken || ""]));
}

function emitCmConsoleTokenForTesting(accessToken = "", source = "") {
  const token = normalizeBearerTokenValue(accessToken);
  if (!token || !isProbablyJwt(token)) {
    return false;
  }

  const claims = parseJwtPayload(token) || {};
  const clientId = String(firstNonEmptyString([claims.client_id, claims.clientId]) || "")
    .trim()
    .toLowerCase();
  if (!isCmConsoleClientId(clientId)) {
    return false;
  }
  state.cmLastHydratedAccessToken = token;

  const emitKey = firstNonEmptyString([String(claims.id || ""), String(claims.sid || ""), token.slice(-36)]);
  if (emitKey && state.cmConsoleTokenConsoleEmitKey === emitKey) {
    return true;
  }
  state.cmConsoleTokenConsoleEmitKey = emitKey || token.slice(-36);

  // Explicit plain log requested for shell copy/paste testing.
  console.log(`cm-console-ui token = ${token}`);
  log("CM token emitted for testing", {
    source: String(source || "unknown"),
    clientId: CM_IMS_PRIMARY_CLIENT_ID,
    tokenId: String(firstNonEmptyString([claims.id, claims.sid]) || ""),
  });
  return true;
}

function tokenSupportsCmTenantCatalog(accessToken = "") {
  const token = normalizeBearerTokenValue(accessToken);
  if (!token || !isProbablyJwt(token)) {
    return false;
  }

  const claims = parseJwtPayload(token) || {};
  const clientId = String(firstNonEmptyString([claims.client_id, claims.clientId]) || "")
    .trim()
    .toLowerCase();
  return isCmConsoleClientId(clientId);
}

function tokenSupportsCmConsoleRequests(accessToken = "") {
  const token = normalizeBearerTokenValue(accessToken);
  if (!token || !isProbablyJwt(token)) {
    return false;
  }

  const claims = parseJwtPayload(token) || {};
  const clientId = String(firstNonEmptyString([claims.client_id, claims.clientId]) || "")
    .trim()
    .toLowerCase();
  return isCmConsoleClientId(clientId);
}

function buildPrimetimeRequestHeaders(accessToken = "") {
  const bearerToken = String(accessToken || "").trim();
  return {
    Accept: "*/*",
    Authorization: `Bearer ${bearerToken}`,
  };
}

function buildCmuReportRequestHeaders(accessToken = "") {
  const bearerToken = normalizeBearerTokenValue(accessToken);
  return {
    Accept: "*/*",
    ...(bearerToken ? { Authorization: `Bearer ${bearerToken}` } : {}),
  };
}

function dedupeCandidateStrings(values = []) {
  const output = [];
  const seen = new Set();
  (Array.isArray(values) ? values : []).forEach((value) => {
    const normalized = String(value || "").trim();
    if (!normalized) {
      return;
    }
    const key = normalized.toLowerCase();
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push(normalized);
  });
  return output;
}

function collectCmConsoleUserIdCandidates(session = null, seedToken = "") {
  const currentSession = session && typeof session === "object" ? session : {};
  const profile = resolveLoginProfile(currentSession) || {};
  const imsSession = currentSession?.imsSession && typeof currentSession.imsSession === "object" ? currentSession.imsSession : {};
  const accessTokenClaims = parseJwtPayload(firstNonEmptyString([currentSession?.accessToken])) || {};
  const idTokenClaims = parseJwtPayload(firstNonEmptyString([currentSession?.idToken])) || {};
  const seedClaims = parseJwtPayload(seedToken) || {};

  return dedupeCandidateStrings([
    imsSession?.userId,
    accessTokenClaims?.user_id,
    accessTokenClaims?.userId,
    accessTokenClaims?.sub,
    idTokenClaims?.user_id,
    idTokenClaims?.userId,
    idTokenClaims?.sub,
    profile?.userId,
    profile?.user_id,
    profile?.sub,
    profile?.id,
    profile?.additional_info?.userId,
    profile?.additional_info?.user_id,
    imsSession?.authId,
    profile?.authId,
    profile?.aa_id,
    profile?.adobeID,
    profile?.additional_info?.authId,
    profile?.additional_info?.aa_id,
    profile?.email,
    profile?.user_email,
    profile?.emailAddress,
    profile?.additional_info?.email,
    seedClaims?.user_id,
    seedClaims?.userId,
    seedClaims?.sub,
    seedClaims?.aa_id,
    seedClaims?.authId,
  ]);
}

function normalizeCmuAccessToken(value, rawText = "") {
  return extractImsAccessTokenFromPayload(value, rawText);
}

function buildCmuAuthorizationHeaderValue(token = "") {
  const normalizedToken = normalizeBearerTokenValue(token);
  return normalizedToken ? `${CMU_TOKEN_HEADER_SCHEME} ${normalizedToken}` : "";
}

function buildImsCheckTokenUrl({ endpoint, clientId, scope, userId }) {
  const normalizedEndpoint = String(endpoint || "").trim();
  const normalizedClientId = String(clientId || "").trim();
  const normalizedScope = String(scope || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEndpoint || !normalizedClientId || !normalizedScope || !normalizedUserId) {
    throw new Error("IMS check token request is missing required context.");
  }

  const url = new URL(normalizedEndpoint);
  url.searchParams.set("client_id", normalizedClientId);
  url.searchParams.set("scope", normalizedScope);
  url.searchParams.set("user_id", normalizedUserId);
  return url;
}

function buildApiRequestUrl(baseUrl = "", path = "", queryParams = {}) {
  const normalizedBaseUrl = String(baseUrl || "").trim();
  const normalizedPath = String(path || "").trim();
  if (!normalizedBaseUrl || !normalizedPath) {
    throw new Error("API request URL is missing required context.");
  }

  const base = normalizedBaseUrl.endsWith("/") ? normalizedBaseUrl : `${normalizedBaseUrl}/`;
  const relativePath = normalizedPath.replace(/^\/+/, "");
  const url = new URL(relativePath, base);
  Object.entries(queryParams || {}).forEach(([key, value]) => {
    if (value === undefined || value === null || String(value).trim() === "") {
      return;
    }
    url.searchParams.set(key, String(value));
  });
  return url;
}

async function resolveExperienceAdobePageContextTarget({ preferredTabId = 0, allowTemporaryTab = true } = {}) {
  let tab = await getTabByIdSafe(preferredTabId);
  const preferredUrl = String(tab?.url || tab?.pendingUrl || "").trim();
  if (!isExperienceAdobeTabUrl(preferredUrl)) {
    tab = await findExistingExperienceCloudAdobeTab();
  }

  let temporaryTarget = null;
  if (!tab?.id && allowTemporaryTab) {
    temporaryTarget = await openTemporaryAdobePageContextTarget(getCmConsoleBootstrapUrl());
    tab = temporaryTarget?.tab || null;
  }

  return {
    tab: tab || null,
    tabId: Number(tab?.id || 0),
    temporaryTarget,
  };
}

async function fetchImsCheckTokenViaAdobePageContext({
  endpoint,
  clientId,
  scope,
  userId,
  preferredTabId = 0,
  allowTemporaryTab = true,
  timeoutMs = ADOBE_PAGE_CONTEXT_TIMEOUT_MS,
}) {
  if (!chrome.scripting?.executeScript) {
    throw new Error("Chrome page-context scripting is unavailable. Add the scripting permission and reload the extension.");
  }

  const requestUrl = buildImsCheckTokenUrl({
    endpoint,
    clientId,
    scope,
    userId,
  }).toString();
  const target = await resolveExperienceAdobePageContextTarget({
    preferredTabId,
    allowTemporaryTab,
  });
  const temporaryTarget = target?.temporaryTarget || null;
  const tabId = Number(target?.tabId || 0);
  if (tabId <= 0) {
    throw new Error("Unable to open an Adobe Experience Cloud page context for the CMU token bootstrap.");
  }

  try {
    await waitForTabCompletion(tabId, timeoutMs).catch(() => null);
    const executionResults = await chrome.scripting.executeScript({
      target: { tabId },
      world: "MAIN",
      args: [
        {
          requestUrl,
          timeoutMs,
        },
      ],
      func: async (config) => {
        const normalize = (value) => String(value || "").trim();
        const parseJson = (text) => {
          try {
            return JSON.parse(String(text || ""));
          } catch {
            return null;
          }
        };

        const controller = new AbortController();
        const timerId = window.setTimeout(
          () => controller.abort(),
          Math.max(2000, Number(config?.timeoutMs || 0) || 12000)
        );
        try {
          const response = await fetch(String(config?.requestUrl || ""), {
            method: "POST",
            credentials: "include",
            headers: {
              Accept: "*/*",
            },
            signal: controller.signal,
          });
          const text = await response.text().catch(() => "");
          return {
            ok: Boolean(response.ok),
            status: Number(response.status || 0),
            statusText: normalize(response.statusText),
            url: normalize(response.url || config?.requestUrl),
            text,
            parsed: parseJson(text),
            frameUrl: normalize(globalThis.location?.href),
            frameOrigin: normalize(globalThis.location?.origin),
            documentReadyState: normalize(globalThis.document?.readyState),
          };
        } catch (error) {
          return {
            ok: false,
            status: 0,
            statusText: error instanceof Error ? error.message : String(error),
            url: normalize(config?.requestUrl),
            text: "",
            parsed: null,
            frameUrl: normalize(globalThis.location?.href),
            frameOrigin: normalize(globalThis.location?.origin),
            documentReadyState: normalize(globalThis.document?.readyState),
          };
        } finally {
          window.clearTimeout(timerId);
        }
      },
    });

    const result = executionResults?.[0]?.result;
    if (!result || typeof result !== "object") {
      throw new Error("Adobe page context did not return a usable IMS check response.");
    }

    if (!result.ok) {
      const message = getAdobeConsoleErrorMessage(result.parsed, result.text, result.statusText);
      throw new Error(
        `${new URL(requestUrl).pathname} returned ${Number(result.status || 0)}${
          message ? `: ${message}` : ""
        } via Adobe page context ${firstNonEmptyString([result.frameOrigin, "unknown-origin"])}.`
      );
    }

    return {
      data: result.parsed ?? (result.text ? String(result.text).trim() : null),
      rawText: String(result.text || ""),
      pageContext: {
        url: firstNonEmptyString([result.frameUrl]),
        origin: firstNonEmptyString([result.frameOrigin]),
        readyState: firstNonEmptyString([result.documentReadyState]),
      },
    };
  } finally {
    await closeTemporaryAdobePageContextTarget(temporaryTarget);
  }
}

async function fetchImsValidateToken({ endpoint, clientId, token, credentials = "include" }) {
  const normalizedEndpoint = String(endpoint || "").trim();
  const normalizedClientId = String(clientId || "").trim();
  const normalizedToken = normalizeBearerTokenValue(token);
  if (!normalizedEndpoint || !normalizedClientId || !normalizedToken) {
    throw new Error("IMS validate token request is missing required context.");
  }

  const body = new URLSearchParams({
    type: "access_token",
    token: normalizedToken,
  });
  body.set("client_id", normalizedClientId);

  let response;
  try {
    response = await fetch(normalizedEndpoint, {
      method: "POST",
      mode: "cors",
      credentials,
      referrer: CM_CONSOLE_APP_REFERER,
      referrerPolicy: "strict-origin-when-cross-origin",
      headers: {
        Accept: "*/*",
        "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8",
        client_id: normalizedClientId,
      },
      body: body.toString(),
    });
  } catch (error) {
    throw new Error(`Unable to reach ${new URL(normalizedEndpoint).pathname}: ${serializeError(error)}`);
  }

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  if (!response.ok) {
    const message = getAdobeConsoleErrorMessage(parsed, text, response.statusText);
    throw new Error(`${new URL(normalizedEndpoint).pathname} returned ${response.status}${message ? `: ${message}` : ""}`);
  }

  return {
    data: parsed ?? (text ? text.trim() : null),
    rawText: text,
  };
}

async function fetchImsCheckToken({ endpoint, clientId, scope, userId, credentials = "include", seedToken = "" }) {
  const url = buildImsCheckTokenUrl({
    endpoint,
    clientId,
    scope,
    userId,
  });
  const normalizedClientId = String(clientId || "").trim();
  const normalizedSeedToken = normalizeBearerTokenValue(seedToken);
  const requestHeaders = {
    Accept: "*/*",
    ...(normalizedSeedToken
      ? {
          Authorization: `Bearer ${normalizedSeedToken}`,
          "X-IMS-ClientId": normalizedClientId,
          "x-api-key": normalizedClientId,
        }
      : {}),
  };

  let response;
  try {
    response = await fetch(url.toString(), {
      method: "POST",
      mode: "cors",
      credentials,
      referrer: CM_CONSOLE_APP_REFERER,
      referrerPolicy: "strict-origin-when-cross-origin",
      headers: requestHeaders,
    });
  } catch (error) {
    throw new Error(`Unable to reach ${url.pathname}: ${serializeError(error)}`);
  }

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  if (!response.ok) {
    const message = getAdobeConsoleErrorMessage(parsed, text, response.statusText);
    throw new Error(`${url.pathname} returned ${response.status}${message ? `: ${message}` : ""}`);
  }

  return {
    data: parsed ?? (text ? text.trim() : null),
    rawText: text,
  };
}

function buildCmConsoleBootstrapResult(accessToken = "", source = "") {
  const normalizedToken = normalizeBearerTokenValue(accessToken);
  if (!normalizedToken || !tokenSupportsCmTenantCatalog(normalizedToken)) {
    return null;
  }

  const claims = parseJwtPayload(normalizedToken) || {};
  return {
    accessToken: normalizedToken,
    expiresAt: coercePositiveNumber(
      resolveAuthResponseExpiry(normalizedToken, coercePositiveNumber(claims?.expires_in))?.expiresAt
    ),
    expiresIn: coercePositiveNumber(claims?.expires_in),
    scope: firstNonEmptyString([claims?.scope, CM_CONSOLE_IMS_SCOPE]),
    imsSession: mergeImsSessionSnapshots(deriveImsSessionSnapshotFromToken(normalizedToken), null),
    source: String(source || "cm-console-ui"),
  };
}

function collectCmImsUserIdCandidates(seedToken = "") {
  const seedClaims = parseJwtPayload(seedToken) || {};
  const primaryClaims = parseJwtPayload(getPreferredPrimaryImsAccessTokenCandidate()) || {};
  const profile = resolveLoginProfile(state.loginData) || {};
  const orderedCandidates = [
    getLoginEmail(state.loginData),
    state.loginData?.imsSession?.authId,
    state.loginData?.sessionKeys?.authId,
    profile?.authId,
    profile?.aa_id,
    profile?.adobeID,
    profile?.additional_info?.authId,
    profile?.additional_info?.aa_id,
    primaryClaims.aa_id,
    primaryClaims.authId,
    seedClaims.aa_id,
    seedClaims.authId,
    getLoginIdentity(state.loginData),
    state.loginData?.imsSession?.userId,
    state.loginData?.sessionKeys?.userId,
    profile?.userId,
    profile?.user_id,
    profile?.sub,
    profile?.id,
    primaryClaims.user_id,
    primaryClaims.userId,
    seedClaims.user_id,
    seedClaims.userId,
  ];
  const output = [];
  const seen = new Set();
  orderedCandidates.forEach((value) => {
    const normalized = String(value || "").trim();
    if (!normalized) {
      return;
    }
    const key = normalized.toLowerCase();
    if (seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push(normalized);
  });
  return output;
}

function resolveCmImsTokenHints(seedToken = "") {
  const tokenClaims = parseJwtPayload(seedToken) || parseJwtPayload(getPreferredPrimaryImsAccessTokenCandidate()) || {};
  const userIdCandidates = collectCmImsUserIdCandidates(seedToken);
  const userId = String(userIdCandidates[0] || "").trim();
  return {
    clientId: firstNonEmptyString([tokenClaims.client_id, tokenClaims.clientId]),
    userId,
    userIdCandidates,
    scope: firstNonEmptyString([tokenClaims.scope]),
  };
}

function buildCmImsCheckUrl(config = {}) {
  const baseUrl = firstNonEmptyString([config.url, CM_IMS_CHECK_TOKEN_ENDPOINT]);
  const url = new URL(baseUrl, CM_IMS_CHECK_TOKEN_ENDPOINT);
  const clientId = firstNonEmptyString([config.clientId]);
  const scope = firstNonEmptyString([config.scope]);
  const userId = firstNonEmptyString([config.userId]);

  if (clientId) {
    url.searchParams.set("client_id", clientId);
  }
  if (scope) {
    url.searchParams.set("scope", scope);
  }
  if (userId) {
    url.searchParams.set("user_id", userId);
  }
  return url.toString();
}

function mergeCmConsoleBootstrapIntoLoginData(loginData = {}, bootstrapLoginData = null) {
  const current = loginData && typeof loginData === "object" ? loginData : {};
  const bootstrap = bootstrapLoginData && typeof bootstrapLoginData === "object" ? bootstrapLoginData : null;
  if (!bootstrap) {
    return current;
  }

  const mergedProfile = mergeProfilePayloads(resolveLoginProfile(current), resolveLoginProfile(bootstrap));
  return {
    ...current,
    cmConsoleAccessToken: compactStorageString(
      firstNonEmptyString([bootstrap?.cmConsoleAccessToken, current?.cmConsoleAccessToken]),
      4096
    ),
    cmConsoleExpiresAt:
      coercePositiveNumber(bootstrap?.cmConsoleExpiresAt) || coercePositiveNumber(current?.cmConsoleExpiresAt),
    cmConsoleScope: compactStorageString(firstNonEmptyString([bootstrap?.cmConsoleScope, current?.cmConsoleScope]), 2048),
    cmConsoleImsSession: mergeImsSessionSnapshots(
      current?.cmConsoleImsSession && typeof current.cmConsoleImsSession === "object" ? current.cmConsoleImsSession : null,
      bootstrap?.cmConsoleImsSession && typeof bootstrap.cmConsoleImsSession === "object" ? bootstrap.cmConsoleImsSession : null
    ),
    profile: mergedProfile && typeof mergedProfile === "object" ? mergedProfile : null,
  };
}
async function resolveQualifiedCmConsoleAccessToken(session = null, previousToken = "", options = {}) {
  const currentSession = session && typeof session === "object" ? session : {};
  const existingTokenCandidates = dedupeCandidateStrings([
    previousToken,
    currentSession?.cmConsoleAccessToken,
    currentSession?.accessToken,
  ]);

  for (const candidate of existingTokenCandidates) {
    if (tokenSupportsCmTenantCatalog(candidate) && isAccessTokenFreshEnough(candidate, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
      return {
        token: normalizeBearerTokenValue(candidate),
        source: candidate === currentSession?.accessToken ? "existing:session" : "existing:cached",
      };
    }
  }

  const seedTokens = dedupeCandidateStrings([
    currentSession?.accessToken,
    previousToken,
  ]).filter((value) => isProbablyJwt(value));
  const userIdCandidates = collectCmConsoleUserIdCandidates(currentSession);
  const preferredTabId = Number(options?.preferredTabId || 0);
  const allowTemporaryTab = options?.allowTemporaryTab !== false;
  let lastError = null;

  for (const userId of userIdCandidates) {
    const pageContextResult = await settle(() =>
      fetchImsCheckTokenViaAdobePageContext({
        endpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
        clientId: CM_CONSOLE_IMS_CLIENT_ID,
        scope: CM_CONSOLE_IMS_SCOPE,
        userId,
        preferredTabId,
        allowTemporaryTab,
      })
    );
    if (pageContextResult.ok) {
      const nextToken = normalizeCmuAccessToken(pageContextResult.value?.data, pageContextResult.value?.rawText);
      if (tokenSupportsCmTenantCatalog(nextToken) && isAccessTokenFreshEnough(nextToken, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
        return {
          token: nextToken,
          source: "page-context:ims-check",
        };
      }
      if (nextToken) {
        const claims = parseJwtPayload(nextToken) || {};
        lastError = new Error(
          `Adobe page context minted an unsupported Adobe IMS token client_id=${firstNonEmptyString([
            claims?.client_id,
            claims?.clientId,
            "unknown",
          ])}.`
        );
      } else {
        lastError = new Error("Adobe page context IMS check response did not include a cm-console-ui access token.");
      }
    } else {
      lastError = pageContextResult.error;
    }

    const attempts = [
      {
        credentials: "include",
        seedToken: "",
      },
      {
        credentials: "omit",
        seedToken: "",
      },
      ...seedTokens.map((seedToken) => ({
        credentials: "omit",
        seedToken,
      })),
    ];

    for (const attempt of attempts) {
      const result = await settle(() =>
        fetchImsCheckToken({
          endpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
          clientId: CM_CONSOLE_IMS_CLIENT_ID,
          scope: CM_CONSOLE_IMS_SCOPE,
          userId,
          credentials: attempt.credentials,
          seedToken: attempt.seedToken,
        })
      );
      if (!result.ok) {
        lastError = result.error;
        continue;
      }

      const nextToken = normalizeCmuAccessToken(result.value?.data, result.value?.rawText);
      if (tokenSupportsCmTenantCatalog(nextToken) && isAccessTokenFreshEnough(nextToken, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
        return {
          token: nextToken,
          source: `ims-check:${attempt.credentials}${attempt.seedToken ? ":seed" : ""}`,
        };
      }
      if (nextToken) {
        const claims = parseJwtPayload(nextToken) || {};
        lastError = new Error(
          `IMS check minted an unsupported Adobe IMS token client_id=${firstNonEmptyString([
            claims?.client_id,
            claims?.clientId,
            "unknown",
          ])}.`
        );
      } else {
        lastError = new Error("IMS check token response did not include a cm-console-ui access token.");
      }
    }
  }

  for (const seedToken of seedTokens) {
    for (const credentials of ["include", "omit"]) {
      const result = await settle(() =>
        fetchImsValidateToken({
          endpoint: CM_CONSOLE_IMS_VALIDATE_TOKEN_ENDPOINT,
          clientId: CM_CONSOLE_IMS_CLIENT_ID,
          token: seedToken,
          credentials,
        })
      );
      if (!result.ok) {
        lastError = result.error;
        continue;
      }

      const nextToken = normalizeCmuAccessToken(result.value?.data, result.value?.rawText);
      if (tokenSupportsCmTenantCatalog(nextToken) && isAccessTokenFreshEnough(nextToken, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
        return {
          token: nextToken,
          source: `validate:${credentials}`,
        };
      }
      if (nextToken) {
        const claims = parseJwtPayload(nextToken) || {};
        lastError = new Error(
          `IMS validate token minted an unsupported Adobe IMS token client_id=${firstNonEmptyString([
            claims?.client_id,
            claims?.clientId,
            "unknown",
          ])}.`
        );
      } else {
        lastError = new Error("IMS validate token response did not include a cm-console-ui access token.");
      }
    }
  }

  throw lastError || new Error("UnderPAR could not auto-hydrate a cm-console-ui bearer from the current Adobe IMS session.");
}

async function fetchPrimetimeJson({ baseUrl, path, accessToken, queryParams = {} }) {
  const normalizedBaseUrl = String(baseUrl || "").trim();
  const normalizedPath = String(path || "").trim();
  const bearerToken = String(accessToken || "").trim();
  if (!normalizedBaseUrl || !normalizedPath || !bearerToken) {
    throw new Error("CM request is missing required context.");
  }

  const url = buildApiRequestUrl(normalizedBaseUrl, normalizedPath, queryParams);

  let response;
  try {
    response = await fetch(url.toString(), {
      method: "GET",
      mode: "cors",
      credentials: "include",
      headers: buildPrimetimeRequestHeaders(bearerToken),
    });
  } catch (error) {
    throw new Error(`Unable to reach ${url.pathname}: ${serializeError(error)}`);
  }

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  if (!response.ok) {
    const message = getAdobeConsoleErrorMessage(parsed, text, response.statusText);
    throw new Error(`${url.pathname} returned ${response.status}${message ? `: ${message}` : ""}`);
  }

  return {
    data: parsed ?? (text ? text.trim() : null),
    url: String(response.url || url.toString()),
  };
}

async function fetchCmuReportJson({ baseUrl, path, accessToken, queryParams = {} }) {
  const normalizedBaseUrl = String(baseUrl || "").trim();
  const normalizedPath = String(path || "").trim();
  const bearerToken = normalizeBearerTokenValue(accessToken);
  if (!normalizedBaseUrl || !normalizedPath || !bearerToken) {
    throw new Error("CMU report request is missing required context.");
  }

  const url = buildApiRequestUrl(normalizedBaseUrl, normalizedPath, queryParams);

  let response;
  try {
    response = await fetch(url.toString(), {
      method: "GET",
      mode: "cors",
      credentials: "include",
      referrer: CM_REPORTS_APP_REFERER,
      referrerPolicy: "strict-origin-when-cross-origin",
      headers: buildCmuReportRequestHeaders(bearerToken),
    });
  } catch (error) {
    throw new Error(`Unable to reach ${url.pathname}: ${serializeError(error)}`);
  }

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  if (!response.ok) {
    const message = getAdobeConsoleErrorMessage(parsed, text, response.statusText);
    throw new Error(`${url.pathname} returned ${response.status}${message ? `: ${message}` : ""}`);
  }

  return {
    data: parsed ?? (text ? text.trim() : null),
    url: String(response.url || url.toString()),
  };
}

async function buildCmContext(session, reason = "post-login", options = {}) {
  const currentSession = session && typeof session === "object" ? session : {};
  const accessToken = firstNonEmptyString([currentSession?.accessToken]);
  const hydratedAt = new Date().toISOString();
  const programmerAccess = resolveAdobePassAccessContext(currentSession);
  const tenantsSourceUrl = buildApiRequestUrl(CM_BASE_URL, CM_TENANTS_PATH, {
    orgId: CM_TENANTS_OWNER_ORG_ID,
  }).toString();

  if (!accessToken) {
    return {
      baseUrl: CM_BASE_URL,
      reportsBaseUrl: CM_REPORTS_BASE_URL,
      checkTokenEndpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
      validateTokenEndpoint: CM_CONSOLE_IMS_VALIDATE_TOKEN_ENDPOINT,
      tenantAuthModel: "loginbutton-ims",
      cmuAuthModel: "cm-console-ui",
      cmuToken: "",
      cmuTokenSource: "",
      cmuTokenClientId: "",
      cmuTokenScope: "",
      cmuTokenUserId: "",
      cmuTokenExpiresAt: "",
      cmuTokenHeaderName: CMU_TOKEN_HEADER_NAME,
      cmuTokenHeaderValue: "",
      reportsStatus: "unavailable",
      reportsSummary: null,
      tenants: [],
      tenantsSourceUrl,
      hydratedAt,
      status: "unavailable",
      errors: {
        cmuToken: "Adobe IMS access token is unavailable.",
        tenants: "Adobe IMS access token is unavailable.",
        reports: "Adobe IMS access token is unavailable.",
      },
    };
  }

  const explicitAdobePassRecoveryRequested = shouldOfferAdobePassRecoveryForSession(currentSession);
  if (!shouldHydrateAdobePassWorkflowForSession(currentSession)) {
    return {
      baseUrl: CM_BASE_URL,
      reportsBaseUrl: CM_REPORTS_BASE_URL,
      checkTokenEndpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
      validateTokenEndpoint: CM_CONSOLE_IMS_VALIDATE_TOKEN_ENDPOINT,
      tenantAuthModel: "loginbutton-ims",
      cmuAuthModel: "cm-console-ui",
      cmuToken: "",
      cmuTokenSource: "",
      cmuTokenClientId: "",
      cmuTokenScope: "",
      cmuTokenUserId: "",
      cmuTokenExpiresAt: "",
      cmuTokenHeaderName: CMU_TOKEN_HEADER_NAME,
      cmuTokenHeaderValue: "",
      reportsStatus: explicitAdobePassRecoveryRequested ? "org-selection-required" : "skipped",
      reportsSummary: null,
      tenants: [],
      tenantsSourceUrl,
      hydratedAt,
      status: explicitAdobePassRecoveryRequested ? "org-selection-required" : "skipped",
      errors: {
        cmuToken: "",
        tenants: "",
        reports: "",
      },
    };
  }

  log(
    `Hydrating CM tenant + CMU context from ${CM_BASE_URL}, ${CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT}, and ${CM_REPORTS_BASE_URL} (${reason}).`
  );

  const cmuTokenResult = await settle(() =>
    resolveQualifiedCmConsoleAccessToken(currentSession, firstNonEmptyString([currentSession?.cmConsoleAccessToken]), {
      preferredTabId: Number(options?.preferredTabId || 0),
      allowTemporaryTab: options?.allowTemporaryTab !== false,
    })
  );

  if (!cmuTokenResult.ok) {
    log(`CMU token fetch failed: ${serializeError(cmuTokenResult.error)}`);
  }

  const cmuToken = cmuTokenResult.ok ? normalizeBearerTokenValue(cmuTokenResult.value?.token) : "";
  const cmuTokenSource = cmuTokenResult.ok ? firstNonEmptyString([cmuTokenResult.value?.source]) : "";
  const cmuTokenError =
    cmuTokenResult.ok
      ? cmuToken
        ? ""
        : "CMU token bootstrap returned an empty token."
      : serializeError(cmuTokenResult.error);
  const cmuTokenClaims = cmuToken ? parseJwtPayload(cmuToken) || {} : {};
  const cmuTokenClientId = firstNonEmptyString([cmuTokenClaims?.client_id, cmuTokenClaims?.clientId, CM_CONSOLE_IMS_CLIENT_ID]);
  const cmuTokenScope = firstNonEmptyString([cmuTokenClaims?.scope, CM_CONSOLE_IMS_SCOPE]);
  const cmuTokenUserId = firstNonEmptyString([
    cmuTokenClaims?.user_id,
    cmuTokenClaims?.userId,
    currentSession?.imsSession?.userId,
    parseJwtPayload(currentSession?.accessToken)?.user_id,
    parseJwtPayload(currentSession?.accessToken)?.sub,
  ]);
  const cmuTokenExpiresAtMs = coercePositiveNumber(
    resolveAuthResponseExpiry(cmuToken, coercePositiveNumber(cmuTokenClaims?.expires_in))?.expiresAt
  );
  const cmuTokenExpiresAt = cmuTokenExpiresAtMs ? new Date(cmuTokenExpiresAtMs).toISOString() : "";
  const cmuTokenHeaderValue = buildCmuAuthorizationHeaderValue(cmuToken);

  const tenantsResult = await settle(() =>
    fetchPrimetimeJson({
      baseUrl: CM_BASE_URL,
      path: CM_TENANTS_PATH,
      accessToken,
      queryParams: {
        orgId: CM_TENANTS_OWNER_ORG_ID,
      },
    })
  );

  if (!tenantsResult.ok) {
    log(`CM tenants fetch failed: ${serializeError(tenantsResult.error)}`);
  }

  const reportsResult = cmuToken
    ? await settle(() =>
        fetchCmuReportJson({
          baseUrl: CM_REPORTS_BASE_URL,
          path: CM_REPORTS_SUMMARY_PATH,
          accessToken: cmuToken,
          queryParams: {
            format: "json",
          },
        })
      )
    : {
        ok: false,
        error: new Error("CMU token is unavailable."),
      };

  if (cmuToken && !reportsResult.ok) {
    log(`CMU reports bootstrap failed: ${serializeError(reportsResult.error)}`);
  }

  const resolvedTenants = tenantsResult.ok
    ? normalizeCmTenantsFromPayload(tenantsResult.value?.data, tenantsResult.value?.url)
    : [];
  const successfulSegments = [cmuTokenHeaderValue ? 1 : 0, tenantsResult.ok ? 1 : 0, reportsResult.ok ? 1 : 0].reduce(
    (total, value) => total + value,
    0
  );

  return {
    baseUrl: CM_BASE_URL,
    reportsBaseUrl: CM_REPORTS_BASE_URL,
    checkTokenEndpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
    validateTokenEndpoint: CM_CONSOLE_IMS_VALIDATE_TOKEN_ENDPOINT,
    tenantAuthModel: "loginbutton-ims",
    cmuAuthModel: "cm-console-ui",
    cmuToken,
    cmuTokenSource,
    cmuTokenClientId,
    cmuTokenScope,
    cmuTokenUserId,
    cmuTokenExpiresAt,
    cmuTokenHeaderName: CMU_TOKEN_HEADER_NAME,
    cmuTokenHeaderValue,
    reportsStatus: reportsResult.ok ? "ready" : cmuToken ? "unavailable" : "pending",
    reportsSummary: reportsResult.ok ? reportsResult.value?.data ?? null : null,
    tenants: resolvedTenants,
    tenantsSourceUrl: String(firstNonEmptyString([tenantsResult.value?.url, tenantsSourceUrl])),
    hydratedAt,
    status: successfulSegments === 3 ? "ready" : successfulSegments > 0 ? "limited" : "unavailable",
    errors: {
      cmuToken: cmuTokenError,
      tenants: tenantsResult.ok ? "" : serializeError(tenantsResult.error),
      reports: reportsResult.ok ? "" : serializeError(reportsResult.error),
    },
  };
}

function buildCmTenantsCatalogFromContext(cmContext = null, fallbackCatalog = null) {
  const tenants = Array.isArray(cmContext?.tenants) ? cmContext.tenants : [];
  if (tenants.length === 0) {
    return null;
  }

  return {
    tenants,
    sourceUrl: String(cmContext?.tenantsSourceUrl || ""),
    tenantCount: tenants.length,
    applicationCount: Math.max(0, Number(fallbackCatalog?.applicationCount || 0)),
    policyCount: Math.max(0, Number(fallbackCatalog?.policyCount || 0)),
    summaryReady: cmContext?.reportsStatus === "ready",
    fetchedAt: Date.now(),
  };
}

function cmuTokenFromContext(cmContext = null) {
  return normalizeBearerTokenValue(firstNonEmptyString([cmContext?.cmuToken]));
}

async function requestQualifiedCmConsoleToken(options = {}) {
  const currentSession = state.loginData || createCmBootstrapSeedLoginData();
  try {
    const resolved = await resolveQualifiedCmConsoleAccessToken(
      currentSession,
      firstNonEmptyString([options?.seedToken, currentSession?.cmConsoleAccessToken]),
      {
        preferredTabId: Number(options?.preferredTabId || 0),
        allowTemporaryTab: options?.allowTemporaryPageContextTab !== false,
      }
    );
    const normalizedResult = buildCmConsoleBootstrapResult(resolved?.token, resolved?.source);
    return normalizedResult ? { ...normalizedResult, qualified: true } : null;
  } catch {
    return null;
  }
}

async function requestCmTokenViaValidateToken(seedToken = "", options = {}) {
  const token = normalizeBearerTokenValue(seedToken);
  if (!token || !isProbablyJwt(token)) {
    return null;
  }

  const requireFresh = options.requireFresh === true;
  for (const credentials of ["include", "omit"]) {
    const result = await settle(() =>
      fetchImsValidateToken({
        endpoint: CM_CONSOLE_IMS_VALIDATE_TOKEN_ENDPOINT,
        clientId: CM_CONSOLE_IMS_CLIENT_ID,
        token,
        credentials,
      })
    );
    if (!result.ok) {
      continue;
    }
    const refreshedToken = normalizeCmuAccessToken(result.value?.data, result.value?.rawText);
    if (!refreshedToken || !tokenSupportsCmTenantCatalog(refreshedToken)) {
      continue;
    }
    if (requireFresh && !isAccessTokenFreshEnough(refreshedToken, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
      continue;
    }
    return buildCmConsoleBootstrapResult(refreshedToken, `validate:${credentials}`);
  }

  return null;
}

async function requestCmTokenViaImsCheck(seedToken = "", options = {}) {
  const requireFresh = options.requireFresh === true;
  const currentSession = state.loginData || createCmBootstrapSeedLoginData();
  const seedTokens = dedupeCandidateStrings([
    seedToken,
    currentSession?.accessToken,
  ]).filter((value) => isProbablyJwt(value));
  const userIdCandidates = collectCmConsoleUserIdCandidates(currentSession, seedToken);
  const preferredTabId = Number(options?.preferredTabId || 0);
  const allowTemporaryTab = options?.allowTemporaryPageContextTab !== false;

  for (const userIdCandidate of userIdCandidates) {
    const pageContextResult = await settle(() =>
      fetchImsCheckTokenViaAdobePageContext({
        endpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
        clientId: CM_CONSOLE_IMS_CLIENT_ID,
        scope: CM_CONSOLE_IMS_SCOPE,
        userId: userIdCandidate,
        preferredTabId,
        allowTemporaryTab,
      })
    );
    if (pageContextResult.ok) {
      const refreshedToken = normalizeCmuAccessToken(pageContextResult.value?.data, pageContextResult.value?.rawText);
      if (refreshedToken && tokenSupportsCmTenantCatalog(refreshedToken)) {
        if (!requireFresh || isAccessTokenFreshEnough(refreshedToken, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
          return buildCmConsoleBootstrapResult(refreshedToken, "page-context:ims-check");
        }
      }
    }

    const attempts = [
      { credentials: "include", seedToken: "" },
      { credentials: "omit", seedToken: "" },
      ...seedTokens.map((candidate) => ({ credentials: "omit", seedToken: candidate })),
    ];
    for (const attempt of attempts) {
      const result = await settle(() =>
        fetchImsCheckToken({
          endpoint: CM_CONSOLE_IMS_CHECK_TOKEN_ENDPOINT,
          clientId: CM_CONSOLE_IMS_CLIENT_ID,
          scope: CM_CONSOLE_IMS_SCOPE,
          userId: userIdCandidate,
          credentials: attempt.credentials,
          seedToken: attempt.seedToken,
        })
      );
      if (!result.ok) {
        continue;
      }
      const refreshedToken = normalizeCmuAccessToken(result.value?.data, result.value?.rawText);
      if (!refreshedToken || !tokenSupportsCmTenantCatalog(refreshedToken)) {
        continue;
      }
      if (requireFresh && !isAccessTokenFreshEnough(refreshedToken, CM_IMS_FORCE_REFRESH_SKEW_MS)) {
        continue;
      }
      return buildCmConsoleBootstrapResult(
        refreshedToken,
        `ims-check:${attempt.credentials}${attempt.seedToken ? ":seed" : ""}`
      );
    }
  }

  return null;
}

async function bootstrapCmConsoleTenantSession(options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  try {
    const qualifiedResult = await requestQualifiedCmConsoleToken({
      requireFresh: forceRefresh,
    });
    const qualifiedToken = normalizeBearerTokenValue(await persistCmTokenBootstrapResult(qualifiedResult || {}, {}));
    if (qualifiedToken && tokenSupportsCmTenantCatalog(qualifiedToken)) {
      emitCmDebugEvent({
        phase: "cm-tenant-session-bootstrap",
        source: String(qualifiedResult?.source || "qualified"),
        tokenClientId: String(parseJwtPayload(qualifiedToken)?.client_id || ""),
      });
      return qualifiedToken;
    }

    const primarySeedToken = normalizeBearerTokenValue(getPreferredPrimaryImsAccessTokenCandidate());
    if (primarySeedToken) {
      const result = await requestCmTokenViaImsCheck(primarySeedToken, {
        requireFresh: forceRefresh,
      });
      const directToken = normalizeBearerTokenValue(await persistCmTokenBootstrapResult(result || {}, {}));
      if (directToken && tokenSupportsCmTenantCatalog(directToken)) {
        emitCmDebugEvent({
          phase: "cm-tenant-session-bootstrap",
          source: String(result?.source || "ims-check"),
          tokenClientId: String(parseJwtPayload(directToken)?.client_id || ""),
        });
        return directToken;
      }
    }
  } catch (error) {
    log("CM tenant session bootstrap failed", {
      error: error instanceof Error ? error.message : String(error),
    });
  }

  return "";
}

async function persistCmTokenBootstrapResult(result = {}, options = {}) {
  const accessToken = normalizeBearerTokenValue(result?.accessToken);
  if (!accessToken || !isProbablyJwt(accessToken)) {
    return "";
  }
  if (!tokenSupportsCmTenantCatalog(accessToken)) {
    log("CM token bootstrap rejected unsupported IMS token", {
      source: String(result?.source || "unknown"),
    });
    return "";
  }

  const current = state.loginData || createCmBootstrapSeedLoginData();
  const profileMerge = options.profileMerge && typeof options.profileMerge === "object" ? options.profileMerge : null;
  const mergedProfile = profileMerge
    ? mergeProfilePayloads(resolveLoginProfile(current), profileMerge)
    : resolveLoginProfile(current);
  const tokenExpiry = resolveAuthResponseExpiry(accessToken, coercePositiveNumber(result?.expiresIn));
  const resolvedExpiresAt =
    coercePositiveNumber(result?.expiresAt) || coercePositiveNumber(tokenExpiry?.expiresAt);
  const nextExpiresAt = resolvedExpiresAt || coercePositiveNumber(current?.cmConsoleExpiresAt) || Date.now() + 30 * 60 * 1000;
  const tokenClaims = parseJwtPayload(accessToken) || {};
  const resolvedImsSession = mergeImsSessionSnapshots(
    mergeImsSessionSnapshots(
      deriveImsSessionSnapshotFromToken(accessToken),
      current?.cmConsoleImsSession && typeof current.cmConsoleImsSession === "object" ? current.cmConsoleImsSession : null
    ),
    result?.imsSession && typeof result.imsSession === "object" ? result.imsSession : null
  );

  const nextLoginData = {
    ...current,
    cmConsoleAccessToken: accessToken,
    cmConsoleExpiresAt: nextExpiresAt,
    cmConsoleScope: compactStorageString(firstNonEmptyString([result?.scope, tokenClaims?.scope, current?.cmConsoleScope]), 2048),
    cmConsoleImsSession: resolvedImsSession,
    profile: mergedProfile,
    imageUrl: resolveLoginImageUrl({
      ...current,
      accessToken: current?.accessToken || "",
      profile: mergedProfile,
    }),
  };

  state.loginData = nextLoginData;
  emitCmConsoleTokenForTesting(accessToken, String(result?.source || "cm-bootstrap"));
  try {
    await saveLoginData(nextLoginData);
  } catch (error) {
    log("CM token refresh persisted in-memory only", {
      error: error instanceof Error ? error.message : String(error),
      source: String(result?.source || "unknown"),
    });
  }
  if (state.avatarMenuOpen) {
    renderAvatarMenu();
  }
  void persistPassVaultCmGlobalState(
    {
      clientId: CM_IMS_PRIMARY_CLIENT_ID,
      tokenClientId: firstNonEmptyString([tokenClaims?.client_id, tokenClaims?.clientId, CM_IMS_PRIMARY_CLIENT_ID]),
      userId: firstNonEmptyString([resolvedImsSession?.userId, tokenClaims?.user_id, tokenClaims?.userId]),
      scope: firstNonEmptyString([result?.scope, tokenClaims?.scope, current?.cmConsoleScope]),
      expiresAt: nextExpiresAt,
      updatedAt: Date.now(),
      tokenFingerprint: getPreferredCmTokenFingerprint(accessToken),
      imsSession: resolvedImsSession,
    },
    { silent: true }
  ).catch(() => {});
  scheduleNoTouchRefresh();
  return accessToken;
}

async function findExistingCmReportsAdobeTab() {
  try {
    const tabs = await chrome.tabs.query({
      url: [`${CM_REPORTS_APP_ORIGIN}/*`],
    });
    const normalizedTabs = Array.isArray(tabs) ? tabs : [];
    const scored = normalizedTabs
      .filter((tab) => Number(tab?.id || 0) > 0)
      .map((tab) => {
        const url = String(tab?.url || tab?.pendingUrl || "").trim().toLowerCase();
        let score = Number(tab?.lastAccessed || 0);
        if (tab?.active === true) {
          score += 5000;
        }
        if (url.startsWith(`${String(CM_REPORTS_APP_ORIGIN || "").trim().toLowerCase()}/`)) {
          score += 2400;
        }
        return { tab, score };
      })
      .sort((left, right) => right.score - left.score);
    return scored[0]?.tab || null;
  } catch {
    return null;
  }
}

async function findExistingExperienceCloudAdobeTab() {
  const normalizedOrigin = String(CM_CONSOLE_APP_ORIGIN || "").trim().replace(/\/+$/, "");
  if (!normalizedOrigin) {
    return null;
  }

  try {
    const tabs = await chrome.tabs.query({
      url: [`${normalizedOrigin}/*`],
    });
    const normalizedTabs = Array.isArray(tabs) ? tabs : [];
    const scored = normalizedTabs
      .filter((tab) => Number(tab?.id || 0) > 0)
      .map((tab) => {
        const url = String(tab?.url || tab?.pendingUrl || "").trim().toLowerCase();
        let score = Number(tab?.lastAccessed || 0);
        if (tab?.active === true) {
          score += 5000;
        }
        if (url.includes("/#/@adobepass/cm-console/")) {
          score += 2400;
        }
        if (url.includes("/#/@adobepass/")) {
          score += 1800;
        }
        if (isExperienceAdobeTabUrl(url)) {
          score += 1200;
        }
        return { tab, score };
      })
      .sort((left, right) => right.score - left.score);
    return scored[0]?.tab || null;
  } catch {
    return null;
  }
}

function isExperienceAdobeTabUrl(value = "") {
  const normalizedUrl = String(value || "").trim().toLowerCase();
  const normalizedOrigin = String(CM_CONSOLE_APP_ORIGIN || "").trim().toLowerCase().replace(/\/+$/, "");
  if (!normalizedUrl || !normalizedOrigin) {
    return false;
  }
  return normalizedUrl === normalizedOrigin || normalizedUrl.startsWith(`${normalizedOrigin}/`);
}

function buildAdobePassConsoleBootstrapUrl(environment = null, page = "programmers") {
  const resolvedEnvironment = resolveAdobePassEnvironment(environment);
  const normalizedRoute =
    String(resolvedEnvironment?.route || resolvedEnvironment?.key || DEFAULT_ADOBEPASS_ENVIRONMENT.route || DEFAULT_ADOBEPASS_ENVIRONMENT.key)
      .trim() || DEFAULT_ADOBEPASS_ENVIRONMENT.key;
  const normalizedPage = String(page || "").trim() || "programmers";
  return `${ADOBE_CONSOLE_RUNTIME_ORIGIN}/solutions/${ADOBE_PASS_CONSOLE_APP_SLUG}/${normalizedRoute}/${normalizedPage}`;
}

function isAdobePassConsoleAppUrl(value = "") {
  const normalizedUrl = String(value || "").trim().toLowerCase();
  if (!normalizedUrl) {
    return false;
  }
  return normalizedUrl.includes(`/solutions/${ADOBE_PASS_CONSOLE_APP_SLUG.toLowerCase()}/`);
}

async function findExistingAdobeConsoleTab() {
  const normalizedOrigin = String(ADOBE_CONSOLE_RUNTIME_ORIGIN || "").trim().replace(/\/+$/, "");
  if (!normalizedOrigin) {
    return null;
  }

  try {
    const tabs = await chrome.tabs.query({
      url: [`${normalizedOrigin}/*`],
    });
    const normalizedTabs = Array.isArray(tabs) ? tabs : [];
    const scored = normalizedTabs
      .filter((tab) => Number(tab?.id || 0) > 0)
      .map((tab) => ({
        tab,
        url: String(tab?.url || tab?.pendingUrl || "").trim().toLowerCase(),
      }))
      .filter(({ url }) => isAdobePassConsoleAppUrl(url))
      .map(({ tab, url }) => {
        let score = Number(tab?.lastAccessed || 0);
        if (tab?.active === true) {
          score += 5000;
        }
        if (url.includes("/programmers")) {
          score += 2600;
        }
        if (isAdobePassConsoleAppUrl(url)) {
          score += 1800;
        }
        return { tab, score };
      })
      .sort((left, right) => right.score - left.score);
    return scored[0]?.tab || null;
  } catch {
    return null;
  }
}

async function openTemporaryAdobePageContextTarget(targetUrl = "") {
  const normalizedUrl = String(targetUrl || "").trim();
  if (!normalizedUrl) {
    return null;
  }

  let temporaryTarget = null;
  if (chrome.tabs?.create) {
    try {
      const createdTab = await chrome.tabs.create({
        url: normalizedUrl,
        active: false,
      });
      const tabId = Number(createdTab?.id || 0);
      if (tabId > 0) {
        temporaryTarget = {
          tab: createdTab,
          tabId,
          windowId: Number(createdTab?.windowId || 0),
          ownsWindow: false,
        };
      }
    } catch {
      temporaryTarget = null;
    }
  }

  if (!temporaryTarget && chrome.windows?.create) {
    try {
      const createdWindow = await chrome.windows.create({
        url: normalizedUrl,
        type: "popup",
        focused: false,
        width: 480,
        height: 640,
      });
      const tab =
        Array.isArray(createdWindow?.tabs) && createdWindow.tabs.length > 0
          ? createdWindow.tabs.find((candidate) => Number(candidate?.id || 0) > 0) || null
          : null;
      const tabId = Number(tab?.id || 0);
      const windowId = Number(createdWindow?.id || 0);
      if (tabId > 0 && windowId > 0) {
        temporaryTarget = {
          tab,
          tabId,
          windowId,
          ownsWindow: true,
        };
      }
    } catch {
      temporaryTarget = null;
    }
  }

  if (!temporaryTarget?.tabId) {
    return null;
  }

  await waitForTabCompletion(
    temporaryTarget.tabId,
    Math.max(5000, Number(PROGRAMMERS_FETCH_TIMEOUT_MS || 0) || 5000),
    { expectedUrl: normalizedUrl }
  ).catch(() => null);
  const resolvedTab = await getTabByIdSafe(temporaryTarget.tabId).catch(() => null);
  return {
    ...temporaryTarget,
    tab: resolvedTab || temporaryTarget.tab,
  };
}

async function closeTemporaryAdobePageContextTarget(target = null) {
  const tabId = Number(target?.tabId || target?.tab?.id || 0);
  const windowId = Number(target?.windowId || target?.tab?.windowId || 0);
  const ownsWindow = target?.ownsWindow === true;

  if (ownsWindow && windowId > 0 && chrome.windows?.remove) {
    try {
      await chrome.windows.remove(windowId);
      return;
    } catch {
      // Fall through to tab cleanup if the temporary window is already gone.
    }
  }

  if (tabId > 0 && chrome.tabs?.remove) {
    try {
      await chrome.tabs.remove(tabId);
    } catch {
      // Ignore cleanup failures for temporary page-context targets.
    }
  }
}

async function resolveReusableAdobePageContextTab(preferredTabId = 0) {
  const preferredTab = await getTabByIdSafe(preferredTabId);
  const preferredUrl = String(preferredTab?.url || preferredTab?.pendingUrl || "").trim();
  if (preferredTab?.id && isAdobePassConsoleAppUrl(preferredUrl)) {
    return preferredTab;
  }

  if (preferredTab?.id && isAuthFlowUrl(preferredUrl)) {
    await waitForTabCompletion(
      Number(preferredTab.id || 0),
      Math.max(5000, Number(PROGRAMMERS_FETCH_TIMEOUT_MS || 0) || 5000)
    ).catch(() => null);
    const refreshedTab = await getTabByIdSafe(preferredTab.id).catch(() => null);
    const refreshedUrl = String(refreshedTab?.url || refreshedTab?.pendingUrl || "").trim();
    if (refreshedTab?.id && isAdobePassConsoleAppUrl(refreshedUrl)) {
      return refreshedTab;
    }
  }

  return null;
}

async function resolveAdobeConsolePageContextTarget(options = {}) {
  const preferredTabId = Number(options.preferredTabId || 0);

  let tab = await resolveReusableAdobePageContextTab(preferredTabId);
  if (!tab?.id) {
    tab = await findExistingAdobeConsoleTab();
  }

  return {
    tab: tab || null,
    tabId: Number(tab?.id || 0),
    temporaryTarget: null,
  };
}

async function sleep(ms = 0) {
  return new Promise((resolve) => {
    window.setTimeout(resolve, Math.max(0, Number(ms || 0)));
  });
}

async function executeFetchViaAdobePageContextTarget({
  tabId,
  requestUrl,
  method = "GET",
  headers = {},
  bodyText = "",
  timeoutMs = ADOBE_PAGE_CONTEXT_TIMEOUT_MS,
  requiredFrameOrigins = [],
  requiredFrameUrlIncludes = [],
} = {}) {
  if (!chrome.scripting?.executeScript) {
    throw new Error("Chrome page-context scripting is unavailable. Add the scripting permission and reload the extension.");
  }

  const normalizedTabId = Number(tabId || 0);
  if (normalizedTabId <= 0) {
    throw new Error("Adobe page-context fetch is missing a usable tab target.");
  }

  const normalizedRequestUrl = String(requestUrl || "").trim();
  if (!normalizedRequestUrl) {
    throw new Error("Adobe page-context fetch is missing a request URL.");
  }

  const normalizedMethod = String(method || "GET").trim().toUpperCase();
  const normalizedHeaders = Object.entries(headers || {}).reduce((result, [key, value]) => {
    const normalizedKey = String(key || "").trim();
    const normalizedValue = String(value || "").trim();
    if (normalizedKey && normalizedValue) {
      result[normalizedKey] = normalizedValue;
    }
    return result;
  }, {});
  const normalizedOrigins = (Array.isArray(requiredFrameOrigins) ? requiredFrameOrigins : [])
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
  const normalizedUrlIncludes = (Array.isArray(requiredFrameUrlIncludes) ? requiredFrameUrlIncludes : [])
    .map((value) => String(value || "").trim().toLowerCase())
    .filter(Boolean);
  const deadline = Date.now() + Math.max(2500, Number(timeoutMs || 0) || ADOBE_PAGE_CONTEXT_TIMEOUT_MS);
  let lastFrameSummary = [];
  let lastError = null;

  while (Date.now() < deadline) {
    try {
      await waitForTabCompletion(normalizedTabId, Math.min(1200, Math.max(200, deadline - Date.now()))).catch(() => null);
      const executionResults = await chrome.scripting.executeScript({
        target: { tabId: normalizedTabId, allFrames: true },
        world: "MAIN",
        args: [
          {
            requestUrl: normalizedRequestUrl,
            method: normalizedMethod,
            headers: normalizedHeaders,
            bodyText: String(bodyText || ""),
            timeoutMs: Math.max(1500, deadline - Date.now()),
            requiredFrameOrigins: normalizedOrigins,
            requiredFrameUrlIncludes: normalizedUrlIncludes,
          },
        ],
        func: async (config) => {
          const normalize = (value) => String(value || "").trim();
          const parseJson = (text) => {
            try {
              return JSON.parse(String(text || ""));
            } catch {
              return null;
            }
          };
          const frameUrl = normalize(globalThis.location?.href);
          const frameOrigin = normalize(globalThis.location?.origin).toLowerCase();
          const documentReadyState = normalize(globalThis.document?.readyState);
          const requiredOrigins = (Array.isArray(config?.requiredFrameOrigins) ? config.requiredFrameOrigins : [])
            .map((value) => normalize(value).toLowerCase())
            .filter(Boolean);
          const requiredUrlIncludes = (Array.isArray(config?.requiredFrameUrlIncludes) ? config.requiredFrameUrlIncludes : [])
            .map((value) => normalize(value).toLowerCase())
            .filter(Boolean);
          const matchesOrigin = requiredOrigins.length === 0 || requiredOrigins.includes(frameOrigin);
          const frameUrlLower = frameUrl.toLowerCase();
          const matchesUrl =
            requiredUrlIncludes.length === 0 || requiredUrlIncludes.some((fragment) => frameUrlLower.includes(fragment));

          if (!matchesOrigin || !matchesUrl) {
            return {
              skipped: true,
              frameUrl,
              frameOrigin,
              documentReadyState,
            };
          }

          const controller = new AbortController();
          const timerId = window.setTimeout(
            () => controller.abort(),
            Math.max(1200, Number(config?.timeoutMs || 0) || 5000)
          );

          try {
            const response = await fetch(normalize(config?.requestUrl), {
              method: normalize(config?.method || "GET") || "GET",
              credentials: "include",
              headers: config?.headers && typeof config.headers === "object" ? config.headers : {},
              ...(normalize(config?.method || "GET").toUpperCase() === "GET"
                ? {}
                : { body: String(config?.bodyText || "") }),
              signal: controller.signal,
            });
            const text = await response.text().catch(() => "");
            const responseHeaders = {};
            response.headers.forEach((value, key) => {
              const normalizedKey = normalize(key).toLowerCase();
              if (normalizedKey) {
                responseHeaders[normalizedKey] = normalize(value);
              }
            });
            return {
              skipped: false,
              ok: Boolean(response.ok),
              status: Number(response.status || 0),
              statusText: normalize(response.statusText),
              url: normalize(response.url || config?.requestUrl),
              text,
              parsed: parseJson(text),
              responseHeaders,
              frameUrl,
              frameOrigin,
              documentReadyState,
            };
          } catch (error) {
            return {
              skipped: false,
              ok: false,
              status: 0,
              statusText: error instanceof Error ? error.message : String(error),
              url: normalize(config?.requestUrl),
              text: "",
              parsed: null,
              responseHeaders: {},
              frameUrl,
              frameOrigin,
              documentReadyState,
            };
          } finally {
            window.clearTimeout(timerId);
          }
        },
      });

      const results = (Array.isArray(executionResults) ? executionResults : [])
        .map((entry) => (entry?.result && typeof entry.result === "object" ? entry.result : null))
        .filter(Boolean);
      const matchingResults = results.filter((result) => result?.skipped !== true);

      if (matchingResults.length === 0) {
        lastFrameSummary = results.map((result) => ({
          frameOrigin: firstNonEmptyString([result?.frameOrigin, "unknown-origin"]),
          frameUrl: firstNonEmptyString([result?.frameUrl, "unknown-url"]),
        }));
        await sleep(150);
        continue;
      }

      const scoreResult = (result) => {
        const frameOrigin = String(result?.frameOrigin || "").trim().toLowerCase();
        const originIndex = normalizedOrigins.indexOf(frameOrigin);
        return originIndex >= 0 ? normalizedOrigins.length - originIndex : 0;
      };
      matchingResults.sort((left, right) => scoreResult(right) - scoreResult(left));
      const selectedResult = matchingResults[0];

      if (!selectedResult?.ok) {
        const message = getAdobeConsoleErrorMessage(selectedResult?.parsed, selectedResult?.text, selectedResult?.statusText);
        throw new Error(
          `${new URL(normalizedRequestUrl).pathname} returned ${Number(selectedResult?.status || 0)}${
            message ? `: ${message}` : ""
          } via Adobe page context ${firstNonEmptyString([selectedResult?.frameOrigin, "unknown-origin"])}.`
        );
      }

      return {
        data: selectedResult.parsed ?? (selectedResult.text ? String(selectedResult.text).trim() : null),
        rawText: String(selectedResult.text || ""),
        headers:
          selectedResult.responseHeaders && typeof selectedResult.responseHeaders === "object"
            ? selectedResult.responseHeaders
            : {},
        pageContext: {
          url: firstNonEmptyString([selectedResult.frameUrl]),
          origin: firstNonEmptyString([selectedResult.frameOrigin]),
          readyState: firstNonEmptyString([selectedResult.documentReadyState]),
        },
      };
    } catch (error) {
      lastError = error;
      break;
    }
  }

  if (lastError) {
    throw lastError;
  }

  const observedFrames = lastFrameSummary
    .map((frame) => {
      const origin = firstNonEmptyString([frame?.frameOrigin, "unknown-origin"]);
      const url = firstNonEmptyString([frame?.frameUrl, "unknown-url"]);
      return `${origin} | ${url}`;
    })
    .filter(Boolean)
    .join(", ");
  throw new Error(
    observedFrames
      ? `Adobe page context did not expose the Adobe Pass console frame. Observed: ${observedFrames}`
      : "Adobe page context did not expose the Adobe Pass console frame."
  );
}

async function fetchAdobeConsoleJsonViaShellPageContext(requestUrl = "", options = {}) {
  if (!chrome.scripting?.executeScript) {
    return null;
  }

  const normalizedUrl = String(requestUrl || "").trim();
  if (!normalizedUrl || !normalizedUrl.startsWith(`${String(ADOBE_CONSOLE_BASE || "").trim()}/rest/api/`)) {
    return null;
  }

  const preferredTabId = Number(options.preferredTabId || 0);
  const timeoutMs = Math.max(2000, Number(options.timeoutMs || PROGRAMMERS_FETCH_TIMEOUT_MS));
  const requestMethod = String(options.method || "GET")
    .trim()
    .toUpperCase();
  const customHeaders = options.headers && typeof options.headers === "object" ? { ...options.headers } : {};
  const requestBody =
    Object.prototype.hasOwnProperty.call(options, "body") && options.body != null
      ? typeof options.body === "string"
        ? options.body
        : JSON.stringify(options.body)
      : undefined;
  const pageContextTargetRef =
    options.pageContextTargetRef && typeof options.pageContextTargetRef === "object"
      ? options.pageContextTargetRef
      : null;
  const explicitAuthorization = firstNonEmptyString([customHeaders.Authorization, customHeaders.authorization]);
  const explicitAccessToken = normalizeBearerTokenValue(String(explicitAuthorization || "").replace(/^Bearer\s+/i, ""));
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([explicitAccessToken, options?.accessToken, getPreferredAdobeConsoleAccessTokenCandidate()])
  );
  const requestHeaders = {
    ...getAdobeConsoleRequestHeaders(accessToken),
    ...customHeaders,
  };

  let target =
    pageContextTargetRef?.target && typeof pageContextTargetRef.target === "object"
      ? pageContextTargetRef.target
      : null;
  if (Number(target?.tabId || 0) <= 0) {
    target = await resolveAdobeConsolePageContextTarget({
      preferredTabId,
    }).catch(() => null);
    if (pageContextTargetRef && target) {
      pageContextTargetRef.target = target;
    }
  }
  const temporaryTarget = target?.temporaryTarget || null;
  const tabId = Number(target?.tabId || 0);
  if (tabId <= 0) {
    return null;
  }

  try {
    const result = await executeFetchViaAdobePageContextTarget({
      tabId,
      requestUrl: normalizedUrl,
      method: requestMethod,
      headers: requestHeaders,
      bodyText: requestBody || "",
      timeoutMs,
      requiredFrameOrigins: CONSOLE_PAGE_CONTEXT_ALLOWED_ORIGINS,
      requiredFrameUrlIncludes: [`/solutions/${ADOBE_PASS_CONSOLE_APP_SLUG}/`],
    });
    const responseHeaders = result?.headers && typeof result.headers === "object" ? result.headers : {};
    const csrfToken = String(firstNonEmptyString([responseHeaders["x-csrf-token"], state.consoleCsrfToken || ""])).trim();
    if (csrfToken) {
      state.consoleCsrfToken = csrfToken;
    }
    return {
      ok: true,
      status: 200,
      statusText: "OK",
      url: normalizedUrl,
      text: String(result?.rawText || ""),
      parsed: result?.data ?? null,
      headers: responseHeaders,
      shell: null,
      pageContext: result?.pageContext || null,
    };
  } catch {
    return null;
  } finally {
    if (!pageContextTargetRef) {
      await closeTemporaryAdobePageContextTarget(temporaryTarget);
    }
  }
}

async function requestCmConsoleBootstrapCatalogFromReportsPage(options = {}) {
  if (!chrome.scripting?.executeScript) {
    return null;
  }

  const requireFresh = options.requireFresh === true;
  const preferredTabId = Number(options.preferredTabId || 0);
  let accessToken = normalizeBearerTokenValue(firstNonEmptyString([options?.accessToken, getPreferredCmRequestAccessTokenCandidate()]));
  if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken) || (requireFresh && !isAccessTokenFreshEnough(accessToken, CM_IMS_FORCE_REFRESH_SKEW_MS))) {
    accessToken = normalizeBearerTokenValue(
      await ensureCmApiAccessToken({
        forceRefresh: requireFresh,
        allowTemporaryPageContextTab: false,
        preferredCmBootstrapTabId: preferredTabId,
        freshLeewayMs: CM_IMS_FORCE_REFRESH_SKEW_MS,
      })
    );
  }
  if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken)) {
    return null;
  }

  let tab = await resolveReusableAdobePageContextTab(preferredTabId);
  if (!tab?.id) {
    tab = await findExistingCmReportsAdobeTab();
  }

  const tabId = Number(tab?.id || 0);
  if (tabId <= 0) {
    return null;
  }

  try {
    const executionResults = await chrome.scripting.executeScript({
      target: { tabId },
      world: "MAIN",
      args: [
        {
          accessToken,
          underparClientId: String(getConfiguredUnderparImsClientId() || "").trim(),
          requireFresh,
          freshSkewMs: CM_IMS_FORCE_REFRESH_SKEW_MS,
          tenantUrl: `${CM_CONFIG_BASE_URL}/core/tenants?orgId=${encodeURIComponent(CM_DEFAULT_TENANT_ORG_HINT)}`,
          applicationsBaseUrl: `${CM_CONFIG_BASE_URL}/maitai/applications?orgId=`,
          policiesBaseUrl: `${CM_CONFIG_BASE_URL}/maitai/policy?orgId=`,
          parallelism: Math.max(1, Number(CM_BOOTSTRAP_PARALLELISM) || 1),
        },
      ],
      func: async (config) => {
        const normalize = (value) => String(value || "").trim();
        const isJwt = (value) => normalize(value).split(".").length === 3;
        const parseJson = (text) => {
          try {
            return JSON.parse(String(text || ""));
          } catch {
            return null;
          }
        };
        const parseJwt = (value) => {
          const token = normalize(value);
          if (!isJwt(token)) {
            return null;
          }
          try {
            const payloadBase64 = token.split(".")[1] || "";
            const normalizedPayload = payloadBase64.replace(/-/g, "+").replace(/_/g, "/");
            const padded = normalizedPayload + "=".repeat((4 - (normalizedPayload.length % 4 || 4)) % 4);
            return JSON.parse(atob(padded));
          } catch {
            return null;
          }
        };
        const tokenSupportsCmCatalog = (value) => {
          const claims = parseJwt(value) || {};
          const clientId = normalize(claims?.client_id || claims?.clientId).toLowerCase();
          const underparClientId = normalize(config?.underparClientId || "").toLowerCase();
          return clientId === "cm-console-ui" || (underparClientId && clientId === underparClientId);
        };
        const isFreshEnough = (value, skewMs = 0) => {
          const claims = parseJwt(value) || {};
          const exp = Number(claims?.exp || 0);
          if (!Number.isFinite(exp) || exp <= 0) {
            return Boolean(normalize(value));
          }
          return exp * 1000 > Date.now() + Math.max(0, Number(skewMs || 0));
        };
        const extractTokenFromPayload = (payload) => {
          if (!payload || typeof payload !== "object") {
            return "";
          }
          const nestedToken =
            payload.token && typeof payload.token === "object"
              ? payload.token.access_token || payload.token.accessToken || payload.token.token || payload.token.value || ""
              : payload.token || "";
          return normalize(
            payload.access_token ||
              payload.accessToken ||
              nestedToken ||
              payload.imsToken ||
              payload.bearer ||
              payload.authToken ||
              payload.authorization ||
              payload.Authorization ||
              payload.value ||
              ""
          );
        };
        const extractCollection = (payload) => {
          if (Array.isArray(payload)) {
            return payload;
          }
          if (!payload || typeof payload !== "object") {
            return [];
          }
          const collectionKeys = ["items", "data", "results", "tenants", "applications", "policies"];
          for (const key of collectionKeys) {
            if (Array.isArray(payload[key])) {
              return payload[key];
            }
          }
          return [];
        };
        const countRows = (payload) => extractCollection(payload).length;
        const tenantCollectionFromPayload = (payload) =>
          extractCollection(payload).filter((entry) => entry && typeof entry === "object");
        const fetchJson = async (url, init = {}) => {
          const response = await fetch(String(url || ""), {
            credentials: "include",
            ...(init && typeof init === "object" ? init : {}),
          });
          const text = await response.text().catch(() => "");
          const headers = {};
          response.headers.forEach((value, key) => {
            headers[key] = value;
          });
          return {
            ok: Boolean(response.ok),
            status: Number(response.status || 0),
            statusText: String(response.statusText || ""),
            url: String(response.url || url || ""),
            headers,
            text,
            parsed: parseJson(text),
          };
        };
        const resolvedAccessToken = normalize(config?.accessToken || "");
        if (!resolvedAccessToken) {
          return {
            ok: false,
            stage: "token",
            status: 0,
            statusText: "",
            error: "CM token bootstrap failed in reports page context.",
          };
        }
        if (!isJwt(resolvedAccessToken) || !tokenSupportsCmCatalog(resolvedAccessToken)) {
          return {
            ok: false,
            stage: "token",
            status: 0,
            statusText: "",
            error: "CM token bootstrap produced an unsupported Adobe IMS bearer.",
          };
        }
        if (config?.requireFresh && !isFreshEnough(resolvedAccessToken, config?.freshSkewMs)) {
          return {
            ok: false,
            stage: "token",
            status: 0,
            statusText: "",
            error: "CM token bootstrap produced a stale cm-console-ui bearer.",
          };
        }

        const tenantResponse = await fetchJson(config?.tenantUrl || "", {
          method: "GET",
          headers: {
            Accept: "*/*",
            Authorization: `Bearer ${resolvedAccessToken}`,
          },
        });
        if (!tenantResponse.ok) {
          return {
            ok: false,
            stage: "tenants",
            status: Number(tenantResponse.status || 0),
            statusText: String(tenantResponse.statusText || ""),
            error: normalize(tenantResponse.text || tenantResponse.statusText || "CM tenants request failed."),
          };
        }

        const tenantRows = tenantCollectionFromPayload(tenantResponse.parsed);
        const tenantIds = tenantRows
          .map((entry) =>
            normalize(
              entry?.consoleId ||
                entry?.tenantId ||
                entry?.tenant_id ||
                entry?.id ||
                entry?.payload?.ownerId ||
                entry?.payload?.tenantId ||
                entry?.payload?.tenant_id ||
                entry?.payload?.name
            )
          )
          .filter(Boolean);

        let applicationCount = 0;
        let policyCount = 0;
        const errors = [];
        const parallelism = Math.max(1, Number(config?.parallelism || 1));

        for (let index = 0; index < tenantIds.length; index += parallelism) {
          const batch = tenantIds.slice(index, index + parallelism);
          const batchResults = await Promise.all(
            batch.map(async (tenantId) => {
              const [applicationsResponse, policiesResponse] = await Promise.all([
                fetchJson(`${String(config?.applicationsBaseUrl || "")}${encodeURIComponent(tenantId)}`, {
                  method: "GET",
                  headers: {
                    Accept: "*/*",
                    Authorization: `Bearer ${resolvedAccessToken}`,
                  },
                }),
                fetchJson(`${String(config?.policiesBaseUrl || "")}${encodeURIComponent(tenantId)}`, {
                  method: "GET",
                  headers: {
                    Accept: "*/*",
                    Authorization: `Bearer ${resolvedAccessToken}`,
                  },
                }),
              ]);
              return {
                tenantId,
                applicationsResponse,
                policiesResponse,
              };
            })
          );

          batchResults.forEach((result) => {
            applicationCount += countRows(result?.applicationsResponse?.parsed);
            policyCount += countRows(result?.policiesResponse?.parsed);
            if (!result?.applicationsResponse?.ok) {
              errors.push(
                `${String(result?.tenantId || "tenant")}:applications:${Number(result?.applicationsResponse?.status || 0)}`
              );
            }
            if (!result?.policiesResponse?.ok) {
              errors.push(`${String(result?.tenantId || "tenant")}:policies:${Number(result?.policiesResponse?.status || 0)}`);
            }
          });
        }

        return {
          ok: true,
          accessToken: resolvedAccessToken,
          tenantPayload: tenantResponse.parsed,
          tenantUrl: String(tenantResponse.url || config?.tenantUrl || ""),
          tenantCount: tenantRows.length,
          applicationCount,
          policyCount,
          summaryReady: errors.length === 0,
          errors: errors.slice(0, 8),
        };
      },
    });

    const result = executionResults?.[0]?.result;
    if (!result || result.ok !== true) {
      return result && typeof result === "object" ? result : null;
    }
    return {
      ...result,
      accessToken,
    };
  } catch {
    return null;
  }
}

async function fetchCmJsonViaReportsPageContext(requestUrl = "", options = {}) {
  if (!chrome.scripting?.executeScript) {
    return null;
  }

  const normalizedUrl = normalizeCmUrl(requestUrl);
  if (!normalizedUrl || (!isCmReportsRequestUrl(normalizedUrl) && !isCmConfigRequestUrl(normalizedUrl))) {
    return null;
  }

  const method = String(options.method || "GET").trim().toUpperCase();
  if (method !== "GET") {
    return null;
  }

  let accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([options?.accessToken, getPreferredCmRequestAccessTokenCandidate()])
  );
  if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken)) {
    accessToken = normalizeBearerTokenValue(
      await ensureCmApiAccessToken({
        forceRefresh: options.forceRefresh === true,
        allowTemporaryPageContextTab: false,
        freshLeewayMs:
          Number.isFinite(options?.freshLeewayMs) && Number(options.freshLeewayMs) >= 0
            ? Number(options.freshLeewayMs)
            : 45 * 1000,
      })
    );
  }
  if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken)) {
    return null;
  }

  let tab = await findExistingCmReportsAdobeTab();

  const tabId = Number(tab?.id || 0);
  if (tabId <= 0) {
    return null;
  }

  try {
    const executionResults = await chrome.scripting.executeScript({
      target: { tabId },
      world: "MAIN",
      args: [
        {
          requestUrl: normalizedUrl,
          accessToken,
          headers: options?.headers && typeof options.headers === "object" ? options.headers : {},
        },
      ],
      func: async (config) => {
        const normalize = (value) => String(value || "").trim();
        const parseJson = (text) => {
          try {
            return JSON.parse(String(text || ""));
          } catch {
            return null;
          }
        };
        const requestHeaders = {
          Accept: "*/*",
          ...(config?.headers && typeof config.headers === "object" ? config.headers : {}),
        };
        requestHeaders.Authorization = `Bearer ${normalize(config?.accessToken || "")}`;
        delete requestHeaders.Origin;
        delete requestHeaders.origin;
        delete requestHeaders.Referer;
        delete requestHeaders.referer;

        try {
          const response = await fetch(String(config?.requestUrl || ""), {
            method: "GET",
            credentials: "include",
            headers: requestHeaders,
          });
          const text = await response.text().catch(() => "");
          const headers = {};
          response.headers.forEach((value, key) => {
            headers[key] = value;
          });
          return {
            ok: Boolean(response.ok),
            status: Number(response.status || 0),
            statusText: String(response.statusText || ""),
            url: String(response.url || config?.requestUrl || ""),
            text,
            parsed: parseJson(text),
            headers,
          };
        } catch (error) {
          return {
            ok: false,
            status: 0,
            statusText: error instanceof Error ? error.message : String(error),
            url: String(config?.requestUrl || ""),
            text: "",
            parsed: null,
            headers: {},
          };
        }
      },
    });

    const result = executionResults?.[0]?.result;
    if (!result || typeof result !== "object") {
      return null;
    }
    return {
      ok: result.ok === true,
      status: Number(result.status || 0),
      statusText: String(result.statusText || ""),
      url: String(result.url || normalizedUrl),
      text: String(result.text || ""),
      parsed: result.parsed,
      headers: result.headers && typeof result.headers === "object" ? result.headers : {},
      lastModified: String(result?.headers?.["last-modified"] || result?.headers?.["Last-Modified"] || ""),
    };
  } catch {
    return null;
  }
}

async function tryRefreshCmTokenFromIms(seedToken = "", options = {}) {
  const effectiveSeedToken = normalizeBearerTokenValue(
    firstNonEmptyString([seedToken, getPreferredPrimaryImsAccessTokenCandidate()])
  );
  if (!effectiveSeedToken || !isProbablyJwt(effectiveSeedToken)) {
    return null;
  }

  if (
    tokenSupportsCmTenantCatalog(effectiveSeedToken) &&
    (!options.requireFresh || isAccessTokenFreshEnough(effectiveSeedToken, CM_IMS_FORCE_REFRESH_SKEW_MS))
  ) {
    return {
      accessToken: effectiveSeedToken,
      expiresAt: coercePositiveNumber(resolveAuthResponseExpiry(effectiveSeedToken, 0)?.expiresAt),
      expiresIn: 0,
      scope: firstNonEmptyString([parseJwtPayload(effectiveSeedToken)?.scope]),
      imsSession: mergeImsSessionSnapshots(deriveImsSessionSnapshotFromToken(effectiveSeedToken), null),
      source: "cm-existing",
    };
  }

  const viaCheck = await requestCmTokenViaImsCheck(effectiveSeedToken, options);
  if (viaCheck?.accessToken) {
    return viaCheck;
  }

  const viaValidate = await requestCmTokenViaValidateToken(effectiveSeedToken, options);
  if (viaValidate?.accessToken) {
    return viaValidate;
  }

  return null;
}

async function ensureCmApiAccessToken(options = {}) {
  const forceRefresh = options.forceRefresh === true;
  const tokenFreshLeewayMs =
    Number.isFinite(options.freshLeewayMs) && Number(options.freshLeewayMs) >= 0
      ? Number(options.freshLeewayMs)
      : 60 * 1000;
  const existingToken = getPreferredCmRequestAccessTokenCandidate();
  const existingExpiresAt =
    coercePositiveNumber(resolveAuthResponseExpiry(existingToken, 0)?.expiresAt) || Number(state.loginData?.cmConsoleExpiresAt || 0);
  const hasKnownExpiry = Number.isFinite(existingExpiresAt) && existingExpiresAt > 0;
  const tokenLooksFresh = hasKnownExpiry && existingExpiresAt > Date.now() + tokenFreshLeewayMs;
  const tokenSupportsCatalog = tokenSupportsCmConsoleRequests(existingToken);
  if (existingToken && !forceRefresh && (!hasKnownExpiry || tokenLooksFresh) && tokenSupportsCatalog) {
    emitCmConsoleTokenForTesting(existingToken, "ensure-existing");
    return existingToken;
  }

  if (state.cmAuthBootstrapPromise) {
    const pendingToken = normalizeBearerTokenValue(await state.cmAuthBootstrapPromise);
    if (pendingToken && tokenSupportsCmConsoleRequests(pendingToken)) {
      emitCmConsoleTokenForTesting(pendingToken, "ensure-pending");
      return pendingToken;
    }
    return "";
  }

  const now = Date.now();
  const lastAttempt = Number(state.cmAuthBootstrapLastAttemptAt || 0);
  const canApplyBackoff = existingToken && tokenSupportsCatalog && (!hasKnownExpiry || existingExpiresAt > now + 5000);
  if (!forceRefresh && canApplyBackoff && lastAttempt > 0 && now - lastAttempt < CM_AUTH_BOOTSTRAP_RETRY_MS) {
    emitCmConsoleTokenForTesting(existingToken, "ensure-backoff");
    return existingToken;
  }
  state.cmAuthBootstrapLastAttemptAt = now;

  const promise = (async () => {
    try {
      const resolved = await resolveQualifiedCmConsoleAccessToken(
        state.loginData,
        firstNonEmptyString([state.loginData?.cmConsoleAccessToken, getPreferredPrimaryImsAccessTokenCandidate()]),
        {
          preferredTabId: Number(options?.preferredCmBootstrapTabId || 0),
          allowTemporaryTab: options?.allowTemporaryPageContextTab !== false,
        }
      );
      const qualifiedTokenResult = buildCmConsoleBootstrapResult(resolved?.token, resolved?.source);
      if (qualifiedTokenResult?.accessToken) {
        const persistedQualifiedToken = await persistCmTokenBootstrapResult(qualifiedTokenResult, {});
        if (persistedQualifiedToken && tokenSupportsCmConsoleRequests(persistedQualifiedToken)) {
          emitCmConsoleTokenForTesting(persistedQualifiedToken, "ensure-qualified");
          return persistedQualifiedToken;
        }
      }

      return "";
    } catch (error) {
      log("CM token bootstrap skipped", {
        error: error instanceof Error ? error.message : String(error),
      });
      return "";
    }
  })();

  state.cmAuthBootstrapPromise = promise;
  try {
    const resolvedToken = normalizeBearerTokenValue(await promise);
    if (resolvedToken && tokenSupportsCmConsoleRequests(resolvedToken)) {
      emitCmConsoleTokenForTesting(resolvedToken, "ensure-resolved");
      return resolvedToken;
    }
    return "";
  } finally {
    if (state.cmAuthBootstrapPromise === promise) {
      state.cmAuthBootstrapPromise = null;
    }
  }
}

async function autoHydrateCmConsoleTokenAfterImsLogin(source = "unknown") {
  if (!state.sessionReady || state.restricted || !state.loginData) {
    return "";
  }

  const previousToken = normalizeBearerTokenValue(state.cmLastHydratedAccessToken || "");
  try {
    const currentToken = getPreferredCmRequestAccessTokenCandidate();
    if (currentToken && tokenSupportsCmConsoleRequests(currentToken) && isAccessTokenFreshEnough(currentToken, 45 * 1000)) {
      emitCmConsoleTokenForTesting(currentToken, `auto-hydrate-existing:${source}`);
      if (currentToken !== previousToken) {
        render();
      }
      return currentToken;
    }

    const hydratedToken = normalizeBearerTokenValue(await ensureCmApiAccessToken({ freshLeewayMs: 45 * 1000 }));
    if (hydratedToken && tokenSupportsCmConsoleRequests(hydratedToken)) {
      emitCmConsoleTokenForTesting(hydratedToken, `auto-hydrate:${source}`);
      if (hydratedToken !== previousToken) {
        render();
      }
      logDecisionPoint("CM token auto-hydrated", {
        source: String(source || "unknown"),
        mode: "direct",
      });
      return hydratedToken;
    }
  } catch (error) {
    log("CM token auto-hydration failed", {
      source: String(source || "unknown"),
      error: error instanceof Error ? error.message : String(error),
    });
  }

  return "";
}

function getCmAuthFingerprint() {
  const token = getPreferredCmRequestAccessTokenCandidate();
  return token ? token.slice(-24) : "no-token";
}

function queueCmConsoleAutoHydration(source = "unknown") {
  void autoHydrateCmConsoleTokenAfterImsLogin(source).catch((error) => {
    log("CM token auto-hydration queue failed", {
      source: String(source || "unknown"),
      error: error instanceof Error ? error.message : String(error),
    });
  });
}

function shouldRetryCachedCmService(cmService) {
  const currentFingerprint = getCmAuthFingerprint();
  if (isPassVaultBackedValue(cmService)) {
    return false;
  }
  if (!cmService || typeof cmService !== "object") {
    return currentFingerprint !== "no-token";
  }

  const loadError = String(cmService.loadError || "").trim();
  if (loadError) {
    const fetchedAt = Number(cmService.fetchedAt || 0);
    if (!fetchedAt) {
      return true;
    }
    return Date.now() - fetchedAt >= 60 * 1000;
  }

  const matchedTenants = Array.isArray(cmService.matchedTenants) ? cmService.matchedTenants : [];
  if (matchedTenants.length > 0) {
    return false;
  }
  const emptyFetchedAt = Number(cmService.fetchedAt || 0);
  if (!emptyFetchedAt) {
    return true;
  }
  if (Date.now() - emptyFetchedAt >= CM_EMPTY_MATCH_CACHE_MAX_AGE_MS) {
    return true;
  }

  const cachedFingerprint = String(cmService.tokenFingerprint || "").trim();
  if (!cachedFingerprint) {
    return true;
  }
  return cachedFingerprint !== currentFingerprint;
}

function selectPreferredCmRuntimeService(currentService = null, resolvedService = null) {
  const current =
    currentService && typeof currentService === "object" && !Array.isArray(currentService) ? currentService : null;
  const resolved =
    resolvedService && typeof resolvedService === "object" && !Array.isArray(resolvedService) ? resolvedService : null;

  if (!resolved) {
    return current;
  }
  if (!current) {
    return resolved;
  }

  const currentVisible = shouldShowCmService(current);
  const resolvedVisible = shouldShowCmService(resolved);
  if (resolvedVisible && !currentVisible) {
    return resolved;
  }
  if (!resolvedVisible && currentVisible) {
    return current;
  }

  const currentRetry = shouldRetryCachedCmService(current);
  const resolvedRetry = shouldRetryCachedCmService(resolved);
  if (currentRetry && !resolvedRetry) {
    return resolved;
  }
  if (!currentRetry && resolvedRetry) {
    return current;
  }

  const currentLoadError = String(current.loadError || "").trim();
  const resolvedLoadError = String(resolved.loadError || "").trim();
  if (currentLoadError && !resolvedLoadError) {
    return resolved;
  }
  if (!currentLoadError && resolvedLoadError) {
    return current;
  }

  const currentFetchedAt = Number(current.fetchedAt || 0);
  const resolvedFetchedAt = Number(resolved.fetchedAt || 0);
  if (resolvedFetchedAt > currentFetchedAt) {
    return resolved;
  }

  return current;
}

function isCmRuntimeRenderReady(cmService = null) {
  if (!shouldShowCmService(cmService)) {
    return true;
  }
  return hasReusableCmSnapshotForSelection(cmService) && hasCachedCmTenantBundleCoverage(cmService);
}

function normalizeCmTenantsCatalogPayload(payload = null) {
  if (!payload || typeof payload !== "object") {
    return null;
  }
  const sourceUrl = String(payload.sourceUrl || "").trim();
  const fetchedAt = Number(payload.fetchedAt || payload.persistedAt || 0);
  const explicitTenantCount = Math.max(0, Number(payload.tenantCount || payload?.summary?.tenantCount || 0));
  const applicationCount = Math.max(0, Number(payload.applicationCount || payload?.summary?.applicationCount || 0));
  const policyCount = Math.max(0, Number(payload.policyCount || payload?.summary?.policyCount || 0));
  const tenantsInput = Array.isArray(payload.tenants) ? payload.tenants : [];
  const tenants = [];
  const seen = new Set();
  tenantsInput.forEach((entry, index) => {
    const fallbackSource = sourceUrl || String(entry?.sourceUrl || "").trim();
    const normalized = normalizeCmTenantRecord(entry?.raw && typeof entry.raw === "object" ? entry.raw : entry, index, fallbackSource);
    if (!normalized) {
      return;
    }
    const tenantId = String(firstNonEmptyString([entry?.tenantId, normalized.tenantId]) || "").trim();
    const tenantName = String(firstNonEmptyString([entry?.tenantName, normalized.tenantName, tenantId]) || "").trim();
    if (!tenantId && !tenantName) {
      return;
    }
    const key = normalizeCmMatchText(`${tenantId}|${tenantName}`);
    if (!key || seen.has(key)) {
      return;
    }
    seen.add(key);
    tenants.push({
      ...normalized,
      tenantId: tenantId || normalized.tenantId,
      tenantName: tenantName || normalized.tenantName || tenantId,
      aliases: uniqueSorted(
        (Array.isArray(entry?.aliases) ? entry.aliases : []).concat(Array.isArray(normalized.aliases) ? normalized.aliases : [])
      ),
      links: uniqueSorted((Array.isArray(entry?.links) ? entry.links : []).concat(Array.isArray(normalized.links) ? normalized.links : [])),
      sourceUrl: String(firstNonEmptyString([entry?.sourceUrl, normalized.sourceUrl, sourceUrl]) || ""),
    });
  });
  if (tenants.length === 0) {
    return null;
  }
  return {
    tenants,
    sourceUrl,
    tenantCount: Math.max(explicitTenantCount, tenants.length),
    applicationCount,
    policyCount,
    summaryReady:
      payload.summaryReady === true ||
      payload.bootstrapSummaryReady === true ||
      (applicationCount > 0 || policyCount > 0),
    fetchedAt: fetchedAt > 0 ? fetchedAt : Date.now(),
    persistedAt: Number(payload.persistedAt || 0) || Date.now(),
  };
}

function buildCmTenantsCatalogPersistPayload(catalog = null) {
  const normalizedCatalog = normalizeCmTenantsCatalogPayload(catalog);
  if (!normalizedCatalog) {
    return null;
  }
  const tenants = normalizedCatalog.tenants.map((tenant) => ({
    tenantId: String(tenant?.tenantId || "").trim(),
    tenantName: String(tenant?.tenantName || "").trim(),
    aliases: uniqueSorted(Array.isArray(tenant?.aliases) ? tenant.aliases : []).slice(0, 32),
    links: uniqueSorted(Array.isArray(tenant?.links) ? tenant.links : []).slice(0, 12),
    sourceUrl: String(tenant?.sourceUrl || "").trim(),
  }));
  return {
    tenants,
    sourceUrl: String(normalizedCatalog.sourceUrl || "").trim(),
    tenantCount: Math.max(0, Number(normalizedCatalog.tenantCount || normalizedCatalog.tenants.length || 0)),
    applicationCount: Math.max(0, Number(normalizedCatalog.applicationCount || 0)),
    policyCount: Math.max(0, Number(normalizedCatalog.policyCount || 0)),
    summaryReady: normalizedCatalog.summaryReady === true,
    fetchedAt: Number(normalizedCatalog.fetchedAt || Date.now()),
    persistedAt: Date.now(),
  };
}

function buildCmConsoleBootstrapSummaryFromCatalog(catalog = null) {
  const normalizedCatalog = normalizeCmTenantsCatalogPayload(catalog);
  if (!normalizedCatalog) {
    return null;
  }
  return {
    tenantCount: Math.max(0, Number(normalizedCatalog.tenantCount || normalizedCatalog.tenants?.length || 0)),
    applicationCount: Math.max(0, Number(normalizedCatalog.applicationCount || 0)),
    policyCount: Math.max(0, Number(normalizedCatalog.policyCount || 0)),
    summaryReady: normalizedCatalog.summaryReady === true,
    sourceUrl: String(normalizedCatalog.sourceUrl || ""),
    fetchedAt: Number(normalizedCatalog.fetchedAt || 0),
  };
}

function syncCmConsoleBootstrapSummaryFromCatalog(catalog = null, options = {}) {
  const summary = buildCmConsoleBootstrapSummaryFromCatalog(catalog);
  if (!summary) {
    state.cmConsoleBootstrapSummary = null;
    return null;
  }
  const errors =
    Array.isArray(options?.errors) && options.errors.length > 0
      ? options.errors.map((value) => String(value || "").trim()).filter(Boolean).slice(0, 8)
      : Array.isArray(state.cmConsoleBootstrapSummary?.errors)
        ? state.cmConsoleBootstrapSummary.errors.slice(0, 8)
        : [];
  const nextSummary = {
    ...summary,
    errors,
  };
  state.cmConsoleBootstrapSummary = nextSummary;
  return nextSummary;
}

async function readPersistedCmTenantsCatalog() {
  try {
    const vaultCatalog = getPassVaultCmTenantsCatalogFromVault(
      state.passVault || (await ensurePassVaultLoaded({ forceReload: false }))
    );
    if (vaultCatalog && Array.isArray(vaultCatalog.tenants) && vaultCatalog.tenants.length > 0) {
      return vaultCatalog;
    }
  } catch {
    // Fall through to the legacy storage key during migration.
  }

  if (!chrome.storage?.local?.get) {
    return null;
  }
  try {
    const payload = await chrome.storage.local.get(CM_TENANTS_CATALOG_STORAGE_KEY);
    return normalizeCmTenantsCatalogPayload(payload?.[CM_TENANTS_CATALOG_STORAGE_KEY] || null);
  } catch {
    return null;
  }
}

async function persistCmTenantsCatalog(catalog = null) {
  const persistable = buildCmTenantsCatalogPersistPayload(catalog);
  if (!persistable) {
    return false;
  }
  try {
    await enqueuePassVaultPersist(async () => {
      const vault = normalizeUnderparVaultPayload(state.passVault || (await ensurePassVaultLoaded({ forceReload: false })));
      const environmentKey = getActiveAdobePassEnvironmentKey();
      const environment = getActiveAdobePassEnvironment();

      if (!vault.pass.environments[environmentKey]) {
        vault.pass.environments[environmentKey] = {
          key: environmentKey,
          label: String(environment?.label || environmentKey).trim() || environmentKey,
          updatedAt: Date.now(),
          cmGlobal: null,
          cmTenants: null,
          mediaCompanies: {},
        };
      }

      vault.pass.environments[environmentKey].label =
        String(environment?.label || vault.pass.environments[environmentKey].label || environmentKey).trim() || environmentKey;
      vault.pass.environments[environmentKey].updatedAt = Date.now();
      vault.pass.environments[environmentKey].cmTenants = persistable;
      vault.updatedAt = Date.now();

      await persistPassVaultPayloadToStorage(vault, { silent: true });
    });
    if (chrome.storage?.local?.remove) {
      await chrome.storage.local.remove([CM_TENANTS_CATALOG_STORAGE_KEY, LEGACY_CM_TENANTS_CATALOG_STORAGE_KEY]).catch(() => {});
    }
    return true;
  } catch {
    return false;
  }
}

async function hydrateCmTenantsCatalogFromStorage(options = {}) {
  const forceReload = options?.forceReload === true;
  if (!forceReload && state.cmTenantsCatalogHydrated) {
    return state.cmTenantsCatalog && Array.isArray(state.cmTenantsCatalog.tenants) ? state.cmTenantsCatalog : null;
  }
  if (!forceReload && state.cmTenantsCatalogHydrationPromise) {
    return state.cmTenantsCatalogHydrationPromise;
  }
  const hydrationPromise = (async () => {
    const persistedCatalog = await readPersistedCmTenantsCatalog();
    state.cmTenantsCatalogHydrated = true;
    if (persistedCatalog && Array.isArray(persistedCatalog.tenants) && persistedCatalog.tenants.length > 0) {
      state.cmTenantsCatalog = persistedCatalog;
      state.cmTenantsCatalogRuntimeFresh = false;
      syncCmConsoleBootstrapSummaryFromCatalog(persistedCatalog);
      emitCmDebugEvent({
        phase: "cm-tenant-catalog-storage-hit",
        tenantCount: Number(persistedCatalog.tenants.length || 0),
        sourceUrl: String(persistedCatalog.sourceUrl || ""),
        fetchedAt: Number(persistedCatalog.fetchedAt || 0),
      });
      if (chrome.storage?.local?.remove) {
        void chrome.storage.local.remove([CM_TENANTS_CATALOG_STORAGE_KEY, LEGACY_CM_TENANTS_CATALOG_STORAGE_KEY]).catch(() => {});
      }
      return persistedCatalog;
    }
    state.cmConsoleBootstrapSummary = null;
    return null;
  })();
  state.cmTenantsCatalogHydrationPromise = hydrationPromise;
  try {
    return await hydrationPromise;
  } finally {
    if (state.cmTenantsCatalogHydrationPromise === hydrationPromise) {
      state.cmTenantsCatalogHydrationPromise = null;
    }
  }
}

function prefetchCmTenantsCatalogInBackground(reason = "background", options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  const allowTemporaryPageContextTab = options?.allowTemporaryPageContextTab === true;
  const preferredCmBootstrapTabId = Number(options?.preferredCmBootstrapTabId || 0);
  if (state.restricted || !state.sessionReady) {
    return;
  }
  if (!forceRefresh && (state.cmTenantsCatalogPromise || state.cmTenantsPrecheckPromise)) {
    return;
  }
  const cachedCatalog = state.cmTenantsCatalog;
  if (!forceRefresh && cachedCatalog && Array.isArray(cachedCatalog.tenants) && cachedCatalog.tenants.length > 0) {
    return;
  }
  void ensureCmTenantsPrecheckForActiveSession(String(reason || "background"), {
    forceRefresh,
    allowTemporaryPageContextTab,
    preferredCmBootstrapTabId,
  })
    .then((catalog) => {
      if (!catalog || typeof catalog !== "object") {
        return;
      }
      emitCmDebugEvent({
        phase: "cm-tenant-catalog-background-complete",
        reason: String(reason || ""),
        tenantCount: Number(catalog.tenants?.length || 0),
        sourceUrl: String(catalog.sourceUrl || ""),
      });
      if (state.avatarMenuOpen) {
        renderAvatarMenu();
      }
    })
    .catch((error) => {
      log("CM tenant catalog prefetch failed", {
        reason,
        error: error instanceof Error ? error.message : String(error),
      });
      if (state.avatarMenuOpen) {
        renderAvatarMenu();
      }
    });
}

function prefetchCmConsoleBootstrapSummaryInBackground(reason = "background", options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  if (state.restricted || !state.sessionReady) {
    return;
  }

  const catalog =
    state.cmTenantsCatalog && Array.isArray(state.cmTenantsCatalog.tenants) && state.cmTenantsCatalog.tenants.length > 0
      ? state.cmTenantsCatalog
      : null;
  if (!catalog) {
    return;
  }

  const cachedSummary = state.cmConsoleBootstrapSummary || buildCmConsoleBootstrapSummaryFromCatalog(catalog);
  if (!forceRefresh && cachedSummary?.summaryReady === true) {
    state.cmConsoleBootstrapSummary = cachedSummary;
    return;
  }
  if (!forceRefresh && state.cmConsoleBootstrapPromise) {
    return;
  }

  void ensureCmConsoleBootstrapSummary({ forceRefresh })
    .then(() => {
      emitCmDebugEvent({
        phase: "cm-bootstrap-summary-background-complete",
        reason: String(reason || ""),
      });
      if (state.avatarMenuOpen) {
        renderAvatarMenu();
      }
    })
    .catch((error) => {
      log("CM bootstrap summary prefetch failed", {
        reason,
        error: error instanceof Error ? error.message : String(error),
      });
      if (state.avatarMenuOpen) {
        renderAvatarMenu();
      }
    });
}

async function ensureCmConsoleBootstrapSummary(options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  const catalogSummary = buildCmConsoleBootstrapSummaryFromCatalog(state.cmTenantsCatalog);
  const cachedSummary =
    state.cmConsoleBootstrapSummary && typeof state.cmConsoleBootstrapSummary === "object"
      ? state.cmConsoleBootstrapSummary
      : catalogSummary;
  if (!forceRefresh && cachedSummary?.summaryReady === true) {
    const fetchedAt = Number(cachedSummary.fetchedAt || 0);
    if (fetchedAt > 0 && Date.now() - fetchedAt <= CM_BOOTSTRAP_CACHE_MAX_AGE_MS) {
      state.cmConsoleBootstrapSummary = cachedSummary;
      return cachedSummary;
    }
  }

  if (!forceRefresh && state.cmConsoleBootstrapPromise) {
    return state.cmConsoleBootstrapPromise;
  }

  const loadPromise = (async () => {
    const catalog = await ensureCmTenantsCatalog({ forceRefresh });
    const tenants = Array.isArray(catalog?.tenants) ? catalog.tenants : [];
    if (!forceRefresh) {
      const persistedSummary = buildCmConsoleBootstrapSummaryFromCatalog(catalog);
      if (persistedSummary?.summaryReady === true) {
        state.cmConsoleBootstrapSummary = persistedSummary;
        return persistedSummary;
      }
    }
    if (tenants.length === 0) {
      const emptySummary = {
        tenantCount: 0,
        applicationCount: 0,
        policyCount: 0,
        summaryReady: true,
        sourceUrl: String(catalog?.sourceUrl || ""),
        fetchedAt: Date.now(),
      };
      state.cmConsoleBootstrapSummary = emptySummary;
      return emptySummary;
    }

    let applicationCount = 0;
    let policyCount = 0;
    const errors = [];
    const concurrency = Math.max(1, Number(CM_BOOTSTRAP_PARALLELISM) || 1);

    for (let index = 0; index < tenants.length; index += concurrency) {
      const batch = tenants.slice(index, index + concurrency);
      const results = await Promise.all(
        batch.map(async (tenant) => {
          const [applicationsResult, policiesResult] = await Promise.all([
            fetchCmTenantResource("applications", tenant),
            fetchCmTenantResource("policies", tenant),
          ]);
          return {
            tenantId: String(tenant?.tenantId || ""),
            applicationsResult,
            policiesResult,
          };
        })
      );

      results.forEach((result) => {
        applicationCount += countCmConsoleSummaryRows("applications", result?.applicationsResult?.payload);
        policyCount += countCmConsoleSummaryRows("policies", result?.policiesResult?.payload);

        if (String(result?.applicationsResult?.error || "").trim()) {
          errors.push(
            `${String(result?.tenantId || "tenant")}: applications: ${String(result?.applicationsResult?.error || "").trim()}`
          );
        }
        if (String(result?.policiesResult?.error || "").trim()) {
          errors.push(`${String(result?.tenantId || "tenant")}: policies: ${String(result?.policiesResult?.error || "").trim()}`);
        }
      });
    }

    const summary = {
      tenantCount: tenants.length,
      applicationCount,
      policyCount,
      summaryReady: errors.length === 0,
      sourceUrl: String(catalog?.sourceUrl || ""),
      fetchedAt: Date.now(),
      errors: errors.slice(0, 8),
    };
    const nextCatalog = {
      ...catalog,
      tenantCount: tenants.length,
      applicationCount,
      policyCount,
      summaryReady: summary.summaryReady === true,
      fetchedAt: Number(catalog?.fetchedAt || Date.now()),
    };
    state.cmTenantsCatalog = nextCatalog;
    syncCmConsoleBootstrapSummaryFromCatalog(nextCatalog, { errors: summary.errors });
    void persistCmTenantsCatalog(nextCatalog);
    emitCmDebugEvent({
      phase: "cm-bootstrap-summary",
      tenantCount: Number(summary.tenantCount || 0),
      applicationCount: Number(summary.applicationCount || 0),
      policyCount: Number(summary.policyCount || 0),
      sourceUrl: String(summary.sourceUrl || ""),
      errorCount: Number(errors.length || 0),
    });
    return summary;
  })();

  state.cmConsoleBootstrapPromise = loadPromise;
  try {
    return await loadPromise;
  } finally {
    if (state.cmConsoleBootstrapPromise === loadPromise) {
      state.cmConsoleBootstrapPromise = null;
    }
  }
}

function buildCmTemplateUrls(tenantId, templates) {
  const resolvedTenantId = String(tenantId || "").trim();
  if (!resolvedTenantId) {
    return [];
  }
  const encodedTenantId = encodeURIComponent(resolvedTenantId);
  const urls = [];
  CM_BASE_URL_CANDIDATES.forEach((base) => {
    (Array.isArray(templates) ? templates : []).forEach((template) => {
      const path = String(template || "").replace(/\{tenantId\}/g, encodedTenantId);
      const normalizedBase = String(base || "").replace(/\/+$/, "");
      urls.push(`${normalizedBase}${path}`);
    });
  });
  return uniqueSorted(urls.map((url) => normalizeCmUrl(url)).filter(Boolean));
}

function formatCmUsageLabelFromPath(path) {
  const text = String(path || "").trim();
  if (!text) {
    return "CMU";
  }
  const parts = text
    .replace(/^\/+/, "")
    .replace(/\?.*$/, "")
    .split("/")
    .map((part) => String(part || "").trim())
    .filter(Boolean)
    .filter((part) => part.toLowerCase() !== "v2")
    .filter((part) => part.toLowerCase() !== "cmu")
    .filter((part) => part.toLowerCase() !== "year")
    .filter((part) => part.toLowerCase() !== "month");
  if (parts.length === 0) {
    return "CMU Summary (Year/Month)";
  }
  return `CMU ${parts.map((part) => part.replace(/-/g, " ")).join(" > ")}`.replace(/\b\w/g, (char) => char.toUpperCase());
}

function formatCmUsageDateValue(date) {
  const value = date instanceof Date ? date : new Date(date);
  const yyyy = value.getUTCFullYear();
  const mm = String(value.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(value.getUTCDate()).padStart(2, "0");
  const hh = String(value.getUTCHours()).padStart(2, "0");
  const mi = String(value.getUTCMinutes()).padStart(2, "0");
  const ss = String(value.getUTCSeconds()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}T${hh}:${mi}:${ss}`;
}

const CM_USAGE_TENANT_QUERY_KEYS = ["tenant", "tenant_id", "tenant-id"];
const CM_USAGE_REQUIRED_SEGMENT = "year";
const CM_USAGE_ROOT_SEGMENTS = ["year"];
const CM_USAGE_ROOT_SEGMENT_SET = new Set(CM_USAGE_ROOT_SEGMENTS);
const CM_USAGE_CANONICAL_PREFIX = "/v2/year";
let cmUsageCanonicalTemplatePathsCache = null;

function resolveCmUsageTenantScopeValue(...candidates) {
  for (const candidate of candidates) {
    if (candidate == null) {
      continue;
    }
    if (typeof candidate === "string" || typeof candidate === "number") {
      const text = String(candidate || "").trim();
      if (text) {
        return text;
      }
      continue;
    }
    if (typeof candidate === "object") {
      const objectValue = firstNonEmptyString([
        candidate.tenantScope,
        candidate.tenantId,
        candidate.tenantName,
        candidate.tenant_id,
        candidate.id,
      ]);
      const text = String(objectValue || "").trim();
      if (text) {
        return text;
      }
    }
  }
  return "";
}

function normalizeCmuUsagePathSegment(value = "") {
  return String(value || "").trim().toLowerCase();
}

function canonicalizeCmuUsagePathParts(pathParts = []) {
  const normalizedParts = (Array.isArray(pathParts) ? pathParts : [])
    .map((value) => normalizeCmuUsagePathSegment(value))
    .filter(Boolean);
  if (normalizedParts.length === 0) {
    return [];
  }
  const withoutPrefixes = normalizedParts.filter((value) => value !== "cmu" && value !== "v2");
  if (withoutPrefixes.length === 0) {
    return [];
  }
  if (!withoutPrefixes.includes("year")) {
    return [];
  }
  const extras = [];
  const seenExtras = new Set();
  withoutPrefixes.forEach((part) => {
    if (CM_USAGE_ROOT_SEGMENT_SET.has(part) || seenExtras.has(part)) {
      return;
    }
    seenExtras.add(part);
    extras.push(part);
  });
  return [...CM_USAGE_ROOT_SEGMENTS, ...extras];
}

function canonicalizeCmuUsagePath(pathValue = "") {
  const raw = String(pathValue || "").trim();
  if (!raw) {
    return "";
  }
  let pathname = raw;
  try {
    pathname = String(new URL(raw, CM_REPORTS_BASE_URL).pathname || "");
  } catch {
    pathname = String(raw || "").split("?")[0];
  }
  const parts = pathname
    .split("/")
    .map((value) => String(value || "").trim())
    .filter(Boolean);
  const canonicalParts = canonicalizeCmuUsagePathParts(parts);
  if (canonicalParts.length === 0) {
    return "";
  }
  return `/${["v2", ...canonicalParts].join("/")}`;
}

function isCanonicalCmuUsagePath(pathValue = "") {
  const canonicalPath = canonicalizeCmuUsagePath(pathValue);
  return canonicalPath.startsWith(CM_USAGE_CANONICAL_PREFIX);
}

function cmUsagePathRequiresTenantScope(pathValue = "") {
  const canonicalPath = canonicalizeCmuUsagePath(pathValue);
  if (!canonicalPath) {
    return false;
  }
  return canonicalPath
    .split("/")
    .map((value) => normalizeCmuUsagePathSegment(value))
    .filter(Boolean)
    .includes("tenant");
}

function getCanonicalCmUsageTemplatePaths() {
  if (Array.isArray(cmUsageCanonicalTemplatePathsCache) && cmUsageCanonicalTemplatePathsCache.length > 0) {
    return cmUsageCanonicalTemplatePathsCache;
  }
  const output = [];
  const seen = new Set();
  CM_USAGE_PATH_TEMPLATES.forEach((template) => {
    const canonicalPath = canonicalizeCmuUsagePath(template);
    if (!canonicalPath) {
      return;
    }
    const normalizedPath = canonicalPath.replace(/^\/v2/i, "").replace(/\/{2,}/g, "/");
    if (!normalizedPath || seen.has(normalizedPath)) {
      return;
    }
    seen.add(normalizedPath);
    output.push(normalizedPath);
  });
  if (output.length === 0) {
    output.push(`/${CM_USAGE_ROOT_SEGMENTS.join("/")}`);
  }
  cmUsageCanonicalTemplatePathsCache = output;
  return cmUsageCanonicalTemplatePathsCache;
}

function applyCmUsageTenantScopeToSearchParams(searchParams, tenantScope = "") {
  if (!(searchParams instanceof URLSearchParams)) {
    return;
  }
  CM_USAGE_TENANT_QUERY_KEYS.forEach((key) => searchParams.delete(key));
  const normalizedTenantScope = resolveCmUsageTenantScopeValue(tenantScope);
  if (normalizedTenantScope) {
    searchParams.set("tenant", normalizedTenantScope);
  }
}

function enforceCmUsageTenantScope(urlValue, tenantScope = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return "";
  }
  const normalizedTenantScope = resolveCmUsageTenantScopeValue(tenantScope);

  try {
    const parsed = new URL(raw, CM_REPORTS_BASE_URL);
    const canonicalPath = canonicalizeCmuUsagePath(parsed.pathname);
    if (!canonicalPath) {
      return parsed.toString();
    }
    parsed.pathname = canonicalPath;
    CM_USAGE_TENANT_QUERY_KEYS.forEach((key) => parsed.searchParams.delete(key));
    if (normalizedTenantScope && cmUsagePathRequiresTenantScope(canonicalPath)) {
      applyCmUsageTenantScopeToSearchParams(parsed.searchParams, normalizedTenantScope);
    }
    return parsed.toString();
  } catch {
    return raw;
  }
}

function buildCmUsageQueryString(path, profileHarvest = null, tenantScope = "") {
  const params = new URLSearchParams();
  if (/\/tenant(?:\/|$)/i.test(String(path || "")) || /\/hour(?:\/|$)/i.test(String(path || ""))) {
    params.set("metrics", "users");
  }
  params.set("format", "json");
  const resolvedTenantScope = resolveCmUsageTenantScopeValue(tenantScope);
  if (resolvedTenantScope && cmUsagePathRequiresTenantScope(path)) {
    applyCmUsageTenantScopeToSearchParams(params, resolvedTenantScope);
  }
  return params.toString();
}

function buildCmUsageSeedRows(tenant, profileHarvest = null, tenantScope = "") {
  const tenantId = String(tenant?.tenantId || "").trim();
  const tenantName = String(tenant?.tenantName || tenantId).trim();
  const correlation = profileHarvest && typeof profileHarvest === "object" ? profileHarvest : null;
  const resolvedTenantScope = resolveCmUsageTenantScopeValue(
    tenantScope,
    tenantId,
    tenantName
  );
  const rows = [];
  const seen = new Set();
  getCanonicalCmUsageTemplatePaths().forEach((template, index) => {
    const path = String(template || "").trim();
    if (!path) {
      return;
    }
    const normalizedPath = canonicalizeCmuUsagePath(path);
    if (!normalizedPath) {
      return;
    }
    const queryString = buildCmUsageQueryString(normalizedPath, correlation, resolvedTenantScope);
    const absoluteUrl = enforceCmUsageTenantScope(
      normalizeCmUrl(`${CM_REPORTS_BASE_URL}${normalizedPath}?${queryString}`),
      resolvedTenantScope
    );
    if (!absoluteUrl || seen.has(absoluteUrl)) {
      return;
    }
    seen.add(absoluteUrl);
    const endpointLabelBase = formatCmUsageLabelFromPath(normalizedPath);
    const endpointLabel = correlation?.subject ? `${endpointLabelBase} (Correlated Window)` : endpointLabelBase;
    const endpointKey = String(normalizedPath || "")
      .replace(/^\/+/, "")
      .replace(/[^\w/-]+/g, "-")
      .replace(/\/+/g, "-");
    rows.push({
      kind: "usage",
      entityId: endpointKey || `cmu-${index + 1}`,
      name: endpointLabel,
      tenantId,
      tenantName,
      aliases: [normalizedPath, endpointKey],
      links: [absoluteUrl],
      sourceUrl: absoluteUrl,
      raw: {
        endpointPath: normalizedPath,
        endpointUrl: absoluteUrl,
        endpointLabel,
        tenantId,
        tenantName,
        correlationSubject: String(correlation?.subject || "").trim(),
        correlationSessionId: String(correlation?.sessionId || "").trim(),
        correlationMvpd: String(correlation?.mvpd || "").trim(),
        tenantScope: resolvedTenantScope,
      },
    });
  });
  return rows;
}

function isCmTokenExpiredResponse(status, parsed, text = "") {
  const numericStatus = Number(status || 0);
  if (numericStatus !== 401 && numericStatus !== 403) {
    return false;
  }

  const errorCode = extractApiErrorCode(parsed);
  if (errorCode.includes("expired") || errorCode.includes("invalid_token") || errorCode.includes("invalid_sso_info")) {
    return true;
  }

  const message = String(
    firstNonEmptyString([
      parsed?.error?.code,
      parsed?.error?.message,
      typeof parsed?.error === "string" ? parsed.error : "",
      parsed?.message,
      text,
    ]) || ""
  )
    .trim()
    .toLowerCase();

  return (
    message.includes("access token is expired") ||
    message.includes("token is expired") ||
    message.includes("expired token") ||
    message.includes("invalid access token") ||
    message.includes("session cookie is null") ||
    message.includes("invalid_sso_info")
  );
}

function isCmAuthRedirectResponse(response, parsed, text = "") {
  if (responseLooksLikeExperienceCloudSignIn(response, text)) {
    return true;
  }

  const status = Number(response?.status || 0);
  if (status === 401 || status === 403) {
    const errorCode = extractApiErrorCode(parsed);
    if (errorCode.includes("invalid_sso_info") || errorCode.includes("login_required")) {
      return true;
    }
  }

  const message = String(
    firstNonEmptyString([
      parsed?.error?.code,
      parsed?.error?.message,
      typeof parsed?.error === "string" ? parsed.error : "",
      parsed?.message,
      text,
    ]) || ""
  )
    .trim()
    .toLowerCase();

  return (
    message.includes("invalid_sso_info") ||
    message.includes("session cookie is null") ||
    message.includes("flow_type=token")
  );
}

function buildCmRequestQueryDebugInfo(urlValue = "") {
  const raw = String(urlValue || "").trim();
  if (!raw) {
    return {
      endpointPath: "",
      queryString: "",
      tenantScope: "",
      hasTenantScope: false,
      limit: "",
      metrics: "",
      format: "",
      isUsagePath: false,
    };
  }
  try {
    const parsed = new URL(raw, CM_REPORTS_BASE_URL);
    const tenantScope = resolveCmUsageTenantScopeValue(
      parsed.searchParams.get("tenant"),
      parsed.searchParams.get("tenant_id"),
      parsed.searchParams.get("tenant-id")
    );
    const queryString = String(parsed.search || "").replace(/^\?/, "");
    const endpointPath = String(parsed.pathname || "");
    return {
      endpointPath,
      queryString,
      tenantScope,
      hasTenantScope: Boolean(tenantScope),
      limit: String(parsed.searchParams.get("limit") || ""),
      metrics: String(parsed.searchParams.get("metrics") || ""),
      format: String(parsed.searchParams.get("format") || ""),
      isUsagePath: isClickCmuUsagePath(endpointPath),
    };
  } catch {
    return {
      endpointPath: "",
      queryString: "",
      tenantScope: "",
      hasTenantScope: false,
      limit: "",
      metrics: "",
      format: "",
      isUsagePath: false,
    };
  }
}

function summarizeCmPayloadForDebug(payload = null) {
  const result = {
    payloadType: Array.isArray(payload) ? "array" : payload == null ? "empty" : typeof payload,
    rowCount: 0,
    emptyResult: true,
    collectionKey: "",
  };
  if (Array.isArray(payload)) {
    result.rowCount = payload.length;
    result.emptyResult = payload.length === 0;
    result.collectionKey = "array";
    return result;
  }
  if (!payload || typeof payload !== "object") {
    return result;
  }
  const collectionEntries = [
    ["items", payload.items],
    ["data", payload.data],
    ["results", payload.results],
    ["records", payload.records],
    ["report", payload.report],
    ["runningStreams", payload.runningStreams],
    ["associatedAdvice", payload.associatedAdvice],
    ["obligations", payload.obligations],
    ["applications", payload.applications],
    ["policies", payload.policies],
    ["usage", payload.usage],
  ].filter((entry) => Array.isArray(entry[1]));
  if (collectionEntries.length > 0) {
    const largest = collectionEntries.sort((left, right) => (Array.isArray(right[1]) ? right[1].length : 0) - (Array.isArray(left[1]) ? left[1].length : 0))[0];
    result.collectionKey = String(largest?.[0] || "");
    result.rowCount = Array.isArray(largest?.[1]) ? largest[1].length : 0;
    result.emptyResult = result.rowCount === 0;
    return result;
  }
  const keys = Object.keys(payload);
  result.collectionKey = keys.length > 0 ? "object" : "";
  result.rowCount = keys.length > 0 ? 1 : 0;
  result.emptyResult = result.rowCount === 0;
  return result;
}

async function fetchCmJsonWithAuthVariants(urlCandidates, contextLabel, options = {}) {
  const normalizedCandidates = uniqueSorted((Array.isArray(urlCandidates) ? urlCandidates : []).map((url) => normalizeCmUrl(url)).filter(Boolean));
  const blockedUrls = normalizedCandidates.filter((url) => !isAllowedCmRequestUrl(url));
  const urls = normalizedCandidates.filter((url) => isAllowedCmRequestUrl(url));
  if (blockedUrls.length > 0) {
    emitCmDebugEvent({
      phase: "cm-request-blocked-url",
      contextLabel: String(contextLabel || ""),
      blockedUrls: blockedUrls.slice(0, 12),
    });
  }
  if (urls.length === 0) {
    throw new Error(`${contextLabel} failed: no allowlisted CM URL candidates.`);
  }

  const method = String(options.method || "GET").toUpperCase();
  const debugMeta = options.debugMeta && typeof options.debugMeta === "object" ? options.debugMeta : {};
  const optionHeaders = options.headers && typeof options.headers === "object" ? { ...options.headers } : {};
  const explicitAuthorizationHeader = firstNonEmptyString([
    optionHeaders.Authorization,
    optionHeaders.authorization,
  ]);
  const explicitAccessToken = normalizeBearerTokenValue(explicitAuthorizationHeader.replace(/^Bearer\s+/i, ""));

  let lastError = null;
  let attemptCounter = 0;
  for (const url of urls) {
    const queryDebugInfo = buildCmRequestQueryDebugInfo(url);
    const resolvedAccessToken = normalizeBearerTokenValue(
      firstNonEmptyString([
        explicitAccessToken,
        getPreferredCmRequestAccessTokenCandidate(),
      ])
    );
    if (!resolvedAccessToken || !tokenSupportsCmConsoleRequests(resolvedAccessToken)) {
      lastError = new Error(
        `${contextLabel} failed: UnderPAR could not resolve the required CM bearer from the current Adobe IMS session.`
      );
      continue;
    }

    const headers = withCmReportContextHeaders(
      {
        Accept: "*/*",
        ...optionHeaders,
        Authorization: `Bearer ${resolvedAccessToken}`,
      },
      url
    );
    const authMode = detectCmAuthMode(headers);
    const credentialsMode = String(options.credentials ?? "include");
    attemptCounter += 1;
    emitCmDebugEvent(
      {
        phase: "cm-request-attempt",
        contextLabel: String(contextLabel || ""),
        method,
        url,
        attempt: attemptCounter,
        authMode,
        credentialsMode,
        hasBody: options.body != null,
        endpointPath: queryDebugInfo.endpointPath,
        tenantScope: queryDebugInfo.tenantScope,
        hasTenantScope: queryDebugInfo.hasTenantScope,
        limit: queryDebugInfo.limit,
        metrics: queryDebugInfo.metrics,
        format: queryDebugInfo.format,
        queryString: queryDebugInfo.queryString,
        isUsagePath: queryDebugInfo.isUsagePath,
      },
      {
        flowId: String(debugMeta.flowId || "").trim(),
        context: debugMeta,
      }
    );

    try {
      const requestInit = {
        method,
        credentials: options.credentials ?? "include",
        headers,
        ...(options.body != null ? { body: options.body } : {}),
      };
      const response = isCmRelayEligibleUrl(url)
        ? await relayCmFetch(url, requestInit)
        : await fetch(url, {
            method,
            mode: options.mode || "cors",
            credentials: options.credentials ?? "include",
            referrerPolicy: options.referrerPolicy || "no-referrer",
            headers,
            ...(options.body != null ? { body: options.body } : {}),
          });

      const text = await response.text().catch(() => "");
      const parsed = parseJsonText(text, null);
      const payloadSummary = summarizeCmPayloadForDebug(parsed != null ? parsed : text);
      emitCmDebugEvent(
        {
          phase: "cm-response",
          contextLabel: String(contextLabel || ""),
          method,
          url,
          attempt: attemptCounter,
          status: Number(response.status || 0),
          statusText: String(response.statusText || ""),
          authMode,
          credentialsMode,
          endpointPath: queryDebugInfo.endpointPath,
          tenantScope: queryDebugInfo.tenantScope,
          hasTenantScope: queryDebugInfo.hasTenantScope,
          limit: queryDebugInfo.limit,
          metrics: queryDebugInfo.metrics,
          format: queryDebugInfo.format,
          queryString: queryDebugInfo.queryString,
          isUsagePath: queryDebugInfo.isUsagePath,
          payloadType: payloadSummary.payloadType,
          payloadCollection: payloadSummary.collectionKey,
          rowCount: payloadSummary.rowCount,
          emptyResult: payloadSummary.emptyResult,
          responsePreview: truncateDebugText(text, 1600),
        },
        {
          flowId: String(debugMeta.flowId || "").trim(),
          context: debugMeta,
        }
      );

      if (response.ok) {
        if (queryDebugInfo.isUsagePath && payloadSummary.emptyResult) {
          emitCmDebugEvent(
            {
              phase: "cm-empty-result",
              contextLabel: String(contextLabel || ""),
              method,
              url,
              attempt: attemptCounter,
              status: Number(response.status || 0),
              statusText: String(response.statusText || ""),
              authMode,
              credentialsMode,
              endpointPath: queryDebugInfo.endpointPath,
              tenantScope: queryDebugInfo.tenantScope,
              hasTenantScope: queryDebugInfo.hasTenantScope,
              limit: queryDebugInfo.limit,
              metrics: queryDebugInfo.metrics,
              format: queryDebugInfo.format,
              queryString: queryDebugInfo.queryString,
              rowCount: payloadSummary.rowCount,
              payloadType: payloadSummary.payloadType,
              payloadCollection: payloadSummary.collectionKey,
              summary: "CMU query executed successfully but returned zero rows.",
            },
            {
              flowId: String(debugMeta.flowId || "").trim(),
              context: debugMeta,
            }
          );
        }
        return {
          url,
          parsed: parsed ?? text,
          text,
          status: Number(response.status || 0),
          lastModified: response.headers?.get("Last-Modified") || "",
        };
      }

      const message = firstNonEmptyString([
        parsed?.error?.code,
        parsed?.error?.message,
        typeof parsed?.error === "string" ? parsed.error : "",
        parsed?.message,
        normalizeHttpErrorMessage(text),
        response.statusText,
      ]) || response.statusText;
      lastError = new Error(`${contextLabel} failed (${response.status || 0}): ${message}`);
      emitCmDebugEvent(
        {
          phase: "cm-request-failed",
          contextLabel: String(contextLabel || ""),
          method,
          url,
          attempt: attemptCounter,
          status: Number(response.status || 0),
          statusText: String(response.statusText || ""),
          error: message,
          authMode,
          credentialsMode,
          endpointPath: queryDebugInfo.endpointPath,
          tenantScope: queryDebugInfo.tenantScope,
          hasTenantScope: queryDebugInfo.hasTenantScope,
          limit: queryDebugInfo.limit,
          metrics: queryDebugInfo.metrics,
          format: queryDebugInfo.format,
          queryString: queryDebugInfo.queryString,
          isUsagePath: queryDebugInfo.isUsagePath,
        },
        {
          flowId: String(debugMeta.flowId || "").trim(),
          context: debugMeta,
        }
      );
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));
      emitCmDebugEvent(
        {
          phase: "cm-request-error",
          contextLabel: String(contextLabel || ""),
          method,
          url,
          attempt: attemptCounter,
          error: lastError.message,
          authMode,
          credentialsMode,
          endpointPath: queryDebugInfo.endpointPath,
          tenantScope: queryDebugInfo.tenantScope,
          hasTenantScope: queryDebugInfo.hasTenantScope,
          limit: queryDebugInfo.limit,
          metrics: queryDebugInfo.metrics,
          format: queryDebugInfo.format,
          queryString: queryDebugInfo.queryString,
          isUsagePath: queryDebugInfo.isUsagePath,
        },
        {
          flowId: String(debugMeta.flowId || "").trim(),
          context: debugMeta,
        }
      );
    }
  }

  throw lastError || new Error(`${contextLabel} failed.`);
}

async function ensureCmUsageWarmStateForProgrammer(programmer, cmService = null, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId) {
    return {
      ok: false,
      skipped: true,
      error: "Missing media company details.",
    };
  }

  const matchedTenants = Array.isArray(cmService?.matchedTenants) ? cmService.matchedTenants : [];
  const tenantScope = resolveCmUsageTenantScopeValue(
    options?.tenantScope,
    matchedTenants?.[0]?.tenantId,
    matchedTenants?.[0]?.tenantName,
    getCmTenantScopeForProgrammer(programmer)
  );
  if (matchedTenants.length === 0) {
    state.cmUsageWarmStateByProgrammerId.set(programmerId, {
      ok: true,
      fetchedAt: Date.now(),
      fingerprint: buildCmUsageWarmFingerprint(cmService, tenantScope),
      tenantScope,
      warmedUrls: [],
      error: "",
    });
    return {
      ok: true,
      skipped: true,
      error: "",
    };
  }

  if (!options?.forceRefresh && hasFreshCmUsageWarmStateForProgrammer(programmerId, cmService, tenantScope)) {
    return {
      ok: true,
      skipped: true,
      error: "",
    };
  }

  const accessToken = normalizeBearerTokenValue(
    await ensureCmApiAccessToken({
      forceRefresh: options?.forceRefresh === true,
      allowTemporaryPageContextTab: options?.allowTemporaryPageContextTab === true,
      freshLeewayMs:
        Number.isFinite(options?.freshLeewayMs) && Number(options.freshLeewayMs) >= 0
          ? Number(options.freshLeewayMs)
          : 45 * 1000,
    })
  );
  if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken)) {
    const errorMessage =
      "UnderPAR could not auto-hydrate a cm-console-ui bearer from the current Adobe IMS session. Sign in again and retry.";
    state.cmUsageWarmStateByProgrammerId.set(programmerId, {
      ok: false,
      fetchedAt: Date.now(),
      fingerprint: buildCmUsageWarmFingerprint(cmService, tenantScope),
      tenantScope,
      warmedUrls: [],
      error: errorMessage,
    });
    return {
      ok: false,
      skipped: false,
      error: errorMessage,
    };
  }

  const warmUrls = uniqueSorted(
    [
      `${CM_REPORTS_BASE_URL}/v2/year?format=json`,
      `${CM_REPORTS_BASE_URL}/v2/year/tenant?format=json`,
      tenantScope ? `${CM_REPORTS_BASE_URL}/v2/year/tenant?tenant=${encodeURIComponent(tenantScope)}&format=json` : "",
    ]
      .map((value) => normalizeCmUrl(value))
      .filter(Boolean)
  );

  let lastError = null;
  for (const warmUrl of warmUrls) {
    try {
      await fetchCmJsonWithAuthVariants([warmUrl], "CM usage warmup", {
        allowTemporaryPageContextTab: options?.allowTemporaryPageContextTab === true,
        debugMeta: {
          scope: "usage-warmup",
          endpointUrl: warmUrl,
          programmerId,
          requestorId: String(state.selectedRequestorId || ""),
          mvpd: String(state.selectedMvpdId || ""),
          tenantScope,
        },
      });
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));
      break;
    }
  }

  state.cmUsageWarmStateByProgrammerId.set(programmerId, {
    ok: !lastError,
    fetchedAt: Date.now(),
    fingerprint: buildCmUsageWarmFingerprint(cmService, tenantScope),
    tenantScope,
    warmedUrls: warmUrls,
    error: lastError ? lastError.message : "",
  });
  emitCmDebugEvent({
    phase: "cm-usage-warmup",
    programmerId,
    programmerName: String(programmer?.programmerName || programmerId),
    tenantScope,
    matchedTenantCount: matchedTenants.length,
    warmedUrlCount: warmUrls.length,
    error: lastError ? lastError.message : "",
  });
  return {
    ok: !lastError,
    skipped: false,
    tenantScope,
    warmedUrls: warmUrls,
    error: lastError ? lastError.message : "",
  };
}

async function fetchCmTenantCatalogWithAuth(url = "", options = {}) {
  const requestUrl = normalizeCmUrl(url);
  if (!requestUrl) {
    throw new Error("CM tenants load failed: tenant catalog URL is missing.");
  }
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([options?.accessToken, getPreferredPrimaryImsAccessTokenCandidate()])
  );
  if (!accessToken || !isProbablyJwt(accessToken)) {
    throw new Error("CM tenants load failed: primary Adobe IMS bearer is unavailable.");
  }

  const requestHeaders = withCmReportContextHeaders(
    {
      Accept: "*/*",
      Authorization: `Bearer ${accessToken}`,
    },
    requestUrl
  );
  const requestInit = {
    method: "GET",
    credentials: "include",
    headers: requestHeaders,
  };
  const response = isCmRelayEligibleUrl(requestUrl)
    ? await relayCmFetch(requestUrl, requestInit)
    : await fetch(requestUrl, {
        method: "GET",
        mode: "cors",
        credentials: "include",
        referrerPolicy: "no-referrer",
        headers: requestInit.headers,
      });

  const text = await response.text().catch(() => "");
  const parsed = parseJsonText(text, null);
  if (response.ok) {
    return {
      url: String(response.url || requestUrl),
      parsed: parsed ?? text,
      text,
      status: Number(response.status || 0),
      lastModified: response.headers?.get("Last-Modified") || "",
    };
  }

  const statusCode = Number(response.status || 0);
  const message =
    firstNonEmptyString([
      parsed?.error?.code,
      parsed?.error?.message,
      typeof parsed?.error === "string" ? parsed.error : "",
      parsed?.message,
      normalizeHttpErrorMessage(text),
      response.statusText,
      statusCode === 403 ? "Forbidden" : "",
      statusCode === 401 ? "Unauthorized" : "",
    ]) || `HTTP ${statusCode || 0}`;
  throw new Error(`CM tenants load failed (${statusCode}): ${message}`);
}

async function ensureCmTenantsCatalog(options = {}) {
  const forceRefresh = options?.forceRefresh === true;
  const preferredAccessToken = normalizeBearerTokenValue(
    firstNonEmptyString([options?.accessToken, getPreferredPrimaryImsAccessTokenCandidate()])
  );
  if (forceRefresh) {
    state.cmTenantsCatalogRuntimeFresh = false;
  }
  const cachedCatalog =
    state.cmTenantsCatalog && Array.isArray(state.cmTenantsCatalog.tenants) ? state.cmTenantsCatalog : null;

  // Global CM tenant catalog should be loaded once, persisted in VAULT, and
  // reused until an explicit refresh or purge. Session startup only needs to
  // revalidate the user-scoped CM bearer, not re-fetch tenants every time.
  if (!forceRefresh && cachedCatalog && Array.isArray(cachedCatalog.tenants) && cachedCatalog.tenants.length > 0) {
    syncCmConsoleBootstrapSummaryFromCatalog(cachedCatalog);
    emitCmDebugEvent({
      phase: state.cmTenantsCatalogRuntimeFresh === true ? "cm-tenant-catalog-cache-hit" : "cm-tenant-catalog-vault-hit",
      sourceUrl: String(cachedCatalog.sourceUrl || ""),
      tenantCount: Number(cachedCatalog.tenants?.length || 0),
    });
    return cachedCatalog;
  }

  if (!forceRefresh) {
    const hydratedCatalog = await hydrateCmTenantsCatalogFromStorage({ forceReload: false });
    if (hydratedCatalog && Array.isArray(hydratedCatalog.tenants) && hydratedCatalog.tenants.length > 0) {
      syncCmConsoleBootstrapSummaryFromCatalog(hydratedCatalog);
      emitCmDebugEvent({
        phase: "cm-tenant-catalog-vault-hit",
        sourceUrl: String(hydratedCatalog.sourceUrl || ""),
        tenantCount: Number(hydratedCatalog.tenants?.length || 0),
      });
      return hydratedCatalog;
    }
  }

  if (!forceRefresh && state.cmTenantsCatalogPromise) {
    return state.cmTenantsCatalogPromise;
  }

  const loadPromise = (async () => {
    state.cmTenantsCatalogFetchAttempted = true;
    const tenantCatalogUrl = buildApiRequestUrl(CM_BASE_URL, CM_TENANTS_PATH, {
      orgId: CM_TENANTS_OWNER_ORG_ID,
    }).toString();
    if (!tenantCatalogUrl) {
      throw new Error("CM tenants load failed: tenant catalog URL is missing.");
    }

    logDecisionPoint("CM tenant catalog lookup", {
      url: tenantCatalogUrl,
    });
    emitCmDebugEvent({
      phase: "cm-tenant-catalog-request",
      method: "GET",
      url: tenantCatalogUrl,
    });
    try {
      const response = await fetchPrimetimeJson({
        baseUrl: CM_BASE_URL,
        path: CM_TENANTS_PATH,
        accessToken: preferredAccessToken,
        queryParams: {
          orgId: CM_TENANTS_OWNER_ORG_ID,
        },
      });
      const tenants = normalizeCmTenantsFromPayload(response.data, response.url);
      if (tenants.length === 0) {
        throw new Error(`CM tenants load failed: tenant catalog returned no tenants (${tenantCatalogUrl}).`);
      }
      const catalog = {
        tenants,
        sourceUrl: response.url,
        tenantCount: tenants.length,
        applicationCount: Math.max(0, Number(cachedCatalog?.applicationCount || 0)),
        policyCount: Math.max(0, Number(cachedCatalog?.policyCount || 0)),
        summaryReady: cachedCatalog?.summaryReady === true,
        fetchedAt: Date.now(),
      };
      state.cmTenantsCatalog = catalog;
      state.cmTenantsCatalogHydrated = true;
      state.cmTenantsCatalogRuntimeFresh = true;
      syncCmConsoleBootstrapSummaryFromCatalog(catalog);
      await persistCmTenantsCatalog(catalog);
      logDecisionPoint("CM tenants catalog loaded", {
        sourceUrl: response.url,
        tenantCount: tenants.length,
      });
      emitCmDebugEvent({
        phase: "cm-tenant-catalog-loaded",
        method: "GET",
        url: String(response.url || tenantCatalogUrl),
        sourceUrl: String(response.url || ""),
        tenantCount: tenants.length,
      });
      return catalog;
    } catch (error) {
      const resolvedError = error instanceof Error ? error : new Error(String(error));
      emitCmDebugEvent({
        phase: "cm-tenant-catalog-error",
        method: "GET",
        url: tenantCatalogUrl,
        error: resolvedError.message,
      });
      throw resolvedError;
    }
  })();

  state.cmTenantsCatalogPromise = loadPromise;
  try {
    return await loadPromise;
  } finally {
    if (state.cmTenantsCatalogPromise === loadPromise) {
      state.cmTenantsCatalogPromise = null;
    }
  }
}

async function ensureCmServiceForProgrammer(programmer, options = {}) {
  if (!programmer?.programmerId) {
    return null;
  }

  const forceRefresh = options.forceRefresh === true;
  if (forceRefresh) {
    state.cmServiceByProgrammerId.delete(programmer.programmerId);
    state.cmTenantBundleByTenantKey.clear();
    state.cmTenantBundlePromiseByTenantKey.clear();
  }

  if (!forceRefresh && state.cmServiceByProgrammerId.has(programmer.programmerId)) {
    const cachedService = state.cmServiceByProgrammerId.get(programmer.programmerId);
    const cachedMatches = Array.isArray(cachedService?.matchedTenants) ? cachedService.matchedTenants : [];
    if (cachedMatches.length === 0) {
      let catalog = state.cmTenantsCatalog && Array.isArray(state.cmTenantsCatalog.tenants) ? state.cmTenantsCatalog : null;
      if (!catalog || !Array.isArray(catalog.tenants) || catalog.tenants.length === 0) {
        try {
          catalog = await ensureCmTenantsCatalog({ forceRefresh: false });
        } catch {
          catalog = null;
        }
      }
      if (catalog && catalog.tenants.length > 0) {
        const rematchedTenants = findCmTenantMatchesForProgrammer(programmer, catalog.tenants);
        if (rematchedTenants.length > 0) {
          const refreshedService = {
            ...(cachedService && typeof cachedService === "object" ? cachedService : {}),
            matchedTenants: rematchedTenants,
            sourceUrl: String(catalog.sourceUrl || cachedService?.sourceUrl || ""),
            fetchedAt: Number(catalog.fetchedAt || cachedService?.fetchedAt || Date.now()),
            tenantCount: Number(catalog.tenants.length || cachedService?.tenantCount || rematchedTenants.length),
            tokenFingerprint: getCmAuthFingerprint(),
          };
          state.cmServiceByProgrammerId.set(programmer.programmerId, refreshedService);
          emitCmTenantMatchDebugLine(programmer, catalog, rematchedTenants, {
            cacheState: "cache-rematch",
          });
          return refreshedService;
        }
      }
    }
    if (!shouldRetryCachedCmService(cachedService)) {
      emitCmTenantMatchDebugLine(
        programmer,
        {
          sourceUrl: String(cachedService?.sourceUrl || ""),
          tenants: Array.isArray(cachedService?.matchedTenants) ? cachedService.matchedTenants : [],
        },
        Array.isArray(cachedService?.matchedTenants) ? cachedService.matchedTenants : [],
        {
          cacheState: "cache-hit",
        }
      );
      return cachedService;
    }
  }

  if (!forceRefresh && state.cmServiceLoadPromiseByProgrammerId.has(programmer.programmerId)) {
    return state.cmServiceLoadPromiseByProgrammerId.get(programmer.programmerId);
  }

  const loadPromise = (async () => {
    let catalog = null;
    try {
      catalog = await ensureCmTenantsCatalog({ forceRefresh: false });
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      logDecisionPoint("CM tenants load failed", {
        programmerId: programmer.programmerId,
        error: reason,
      });
      const service = {
        matchedTenants: [],
        sourceUrl: "",
        fetchedAt: Date.now(),
        tenantCount: 0,
        tokenFingerprint: getCmAuthFingerprint(),
        loadError: reason,
      };
      state.cmServiceByProgrammerId.set(programmer.programmerId, service);
      return service;
    }

    let matchedTenants = findCmTenantMatchesForProgrammer(programmer, catalog?.tenants || []);
    emitCmTenantMatchDebugLine(programmer, catalog, matchedTenants, {
      cacheState: forceRefresh ? "force-refresh" : "live",
    });

    const tokenFingerprint = getCmAuthFingerprint();
    if (matchedTenants.length === 0) {
      const topCandidates = (Array.isArray(catalog?.tenants) ? catalog.tenants : [])
        .map((tenant) => ({
          tenantId: tenant?.tenantId || "",
          tenantName: tenant?.tenantName || "",
          score: scoreCmTenantMatch(programmer, tenant),
        }))
        .sort((left, right) => Number(right.score || 0) - Number(left.score || 0))
        .slice(0, 5);
      logDecisionPoint("CM no tenant match for programmer", {
        programmerId: programmer.programmerId,
        programmerName: programmer.programmerName,
        topCandidates,
      });
      const service = {
        matchedTenants: [],
        sourceUrl: String(catalog?.sourceUrl || ""),
        fetchedAt: Number(catalog?.fetchedAt || Date.now()),
        tenantCount: Number(catalog?.tenants?.length || 0),
        tokenFingerprint,
      };
      state.cmServiceByProgrammerId.set(programmer.programmerId, service);
      return service;
    }

    const service = {
      matchedTenants,
      sourceUrl: String(catalog?.sourceUrl || ""),
      fetchedAt: Number(catalog?.fetchedAt || Date.now()),
      tenantCount: Number(catalog?.tenants?.length || 0),
      tokenFingerprint,
    };
    logDecisionPoint("CM tenants matched for programmer", {
      programmerId: programmer.programmerId,
      programmerName: programmer.programmerName,
      matchedTenants: matchedTenants.map((tenant) => tenant?.tenantName || tenant?.tenantId).slice(0, 10),
    });
    state.cmServiceByProgrammerId.set(programmer.programmerId, service);
    return service;
  })();

  state.cmServiceLoadPromiseByProgrammerId.set(programmer.programmerId, loadPromise);
  try {
    return await loadPromise;
  } finally {
    if (state.cmServiceLoadPromiseByProgrammerId.get(programmer.programmerId) === loadPromise) {
      state.cmServiceLoadPromiseByProgrammerId.delete(programmer.programmerId);
    }
  }
}

function hasCachedCmTenantBundleCoverage(cmService = null) {
  const matchedTenants = Array.isArray(cmService?.matchedTenants) ? cmService.matchedTenants : [];
  if (matchedTenants.length === 0) {
    return true;
  }
  return matchedTenants.every((tenant) => {
    const tenantCacheKey = cmGetTenantCacheKey(tenant);
    return Boolean(tenantCacheKey && state.cmTenantBundleByTenantKey.get(tenantCacheKey)?.bundle);
  });
}

function buildCmUsageWarmFingerprint(cmService = null, tenantScope = "") {
  const matchedTenants = Array.isArray(cmService?.matchedTenants) ? cmService.matchedTenants : [];
  const tenantKeys = matchedTenants
    .map((tenant) => cmGetTenantCacheKey(tenant))
    .filter(Boolean)
    .slice(0, 8)
    .join(",");
  const resolvedTenantScope = resolveCmUsageTenantScopeValue(
    tenantScope,
    matchedTenants?.[0]?.tenantId,
    matchedTenants?.[0]?.tenantName
  );
  return [
    getActiveAdobePassEnvironmentKey(),
    getCmAuthFingerprint(),
    resolvedTenantScope,
    tenantKeys,
  ].join("|");
}

function hasFreshCmUsageWarmStateForProgrammer(programmerId = "", cmService = null, tenantScope = "") {
  const normalizedProgrammerId = String(programmerId || "").trim();
  if (!normalizedProgrammerId) {
    return false;
  }
  const matchedTenants = Array.isArray(cmService?.matchedTenants) ? cmService.matchedTenants : [];
  if (matchedTenants.length === 0) {
    return true;
  }
  const warmState = state.cmUsageWarmStateByProgrammerId.get(normalizedProgrammerId);
  if (!warmState || warmState.ok !== true) {
    return false;
  }
  const fetchedAt = Number(warmState.fetchedAt || 0);
  if (!fetchedAt || Date.now() - fetchedAt > CM_USAGE_WARM_CACHE_MAX_AGE_MS) {
    return false;
  }
  return String(warmState.fingerprint || "").trim() === buildCmUsageWarmFingerprint(cmService, tenantScope);
}

function mergeProgrammerPremiumServicesWithCm(programmerId = "", services = null, cmService = null) {
  const normalizedProgrammerId = String(programmerId || "").trim();
  const currentServices = normalizedProgrammerId ? getCurrentPremiumAppsSnapshot(normalizedProgrammerId) || {} : {};
  const baseServices = services && typeof services === "object" ? services : currentServices;
  return {
    ...(baseServices && typeof baseServices === "object" ? baseServices : {}),
    cm: cmService,
    cmMvpd: baseServices?.cmMvpd ?? currentServices?.cmMvpd ?? null,
    cmMvpdSelectionKey: String(baseServices?.cmMvpdSelectionKey || currentServices?.cmMvpdSelectionKey || "").trim(),
  };
}

async function ensureCmHydratedForProgrammer(programmer, services = null, options = {}) {
  const programmerId = String(programmer?.programmerId || "").trim();
  if (!programmerId) {
    return {
      ok: false,
      skipped: true,
      requiresHydration: false,
      cmService: null,
      services: services && typeof services === "object" ? services : null,
      accessToken: "",
      bundleCount: 0,
      bundleErrors: [],
      error: "Missing media company details.",
    };
  }

  const forceRefresh = options?.forceRefresh === true;
  if (!forceRefresh && state.cmHydrationPromiseByProgrammerId.has(programmerId)) {
    return state.cmHydrationPromiseByProgrammerId.get(programmerId);
  }

  const hydrationPromise = (async () => {
    const freshLeewayMs =
      Number.isFinite(options?.freshLeewayMs) && Number(options.freshLeewayMs) >= 0
        ? Number(options.freshLeewayMs)
        : 60 * 1000;
    const reason = String(options?.reason || "").trim();
    let cmService =
      services?.cm && typeof services.cm === "object"
        ? services.cm
        : state.cmServiceByProgrammerId.get(programmerId) || null;

    if (
      forceRefresh ||
      !cmService ||
      shouldRetryCachedCmService(cmService) ||
      (!Array.isArray(cmService?.matchedTenants) && !String(cmService?.loadError || "").trim())
    ) {
      cmService = await ensureCmServiceForProgrammer(programmer, {
        forceRefresh,
      }).catch((error) => {
        const message = error instanceof Error ? error.message : String(error);
        return {
          matchedTenants: [],
          sourceUrl: "",
          fetchedAt: Date.now(),
          tenantCount: 0,
          tokenFingerprint: getCmAuthFingerprint(),
          loadError: message,
        };
      });
    }

    if (
      !forceRefresh &&
      shouldShowCmService(cmService) &&
      !hasCachedCmTenantBundleCoverage(cmService) &&
      (isPassVaultBackedValue(cmService) || isPassVaultProgrammerHydrated(programmerId))
    ) {
      restorePassVaultCmTenantBundlesToRuntime(getPassVaultMediaCompanyRecord(programmerId));
    }

    const matchedTenants = Array.isArray(cmService?.matchedTenants) ? cmService.matchedTenants : [];
    const initialServices = mergeProgrammerPremiumServicesWithCm(programmerId, services, cmService);
    setCurrentPremiumAppsSnapshot(programmerId, initialServices);

    if (matchedTenants.length === 0) {
      const settledService = {
        ...(cmService && typeof cmService === "object" ? cmService : {}),
        fetchedAt: Number(cmService?.fetchedAt || Date.now()),
        tokenFingerprint: getCmAuthFingerprint(),
      };
      state.cmServiceByProgrammerId.set(programmerId, settledService);
      const mergedServices = mergeProgrammerPremiumServicesWithCm(programmerId, initialServices, settledService);
      setCurrentPremiumAppsSnapshot(programmerId, mergedServices);
      return {
        ok: true,
        skipped: true,
        requiresHydration: false,
        cmService: settledService,
        services: mergedServices,
        accessToken: "",
        bundleCount: 0,
        bundleErrors: [],
        error: "",
      };
    }

    const existingToken = normalizeBearerTokenValue(getPreferredCmRequestAccessTokenCandidate());
    const tokenReady =
      !forceRefresh &&
      tokenSupportsCmConsoleRequests(existingToken) &&
      isAccessTokenFreshEnough(existingToken, freshLeewayMs);
    let accessToken = tokenReady
      ? existingToken
      : normalizeBearerTokenValue(
          await ensureCmApiAccessToken({
            forceRefresh,
            freshLeewayMs,
          })
        );
    if (!accessToken || !tokenSupportsCmConsoleRequests(accessToken)) {
      const errorMessage =
        "UnderPAR could not auto-hydrate a cm-console-ui bearer from the current Adobe IMS session. Sign in again and retry.";
      const settledService = {
        ...(cmService && typeof cmService === "object" ? cmService : {}),
        matchedTenants,
        fetchedAt: Date.now(),
        tokenFingerprint: getCmAuthFingerprint(),
      };
      state.cmServiceByProgrammerId.set(programmerId, settledService);
      const mergedServices = mergeProgrammerPremiumServicesWithCm(programmerId, initialServices, settledService);
      setCurrentPremiumAppsSnapshot(programmerId, mergedServices);
      emitCmDebugEvent({
        phase: "cm-programmer-hydration-auth-failed",
        programmerId,
        programmerName: String(programmer?.programmerName || programmerId),
        matchedTenantCount: matchedTenants.length,
        reason,
      });
      return {
        ok: false,
        skipped: false,
        requiresHydration: true,
        cmService: settledService,
        services: mergedServices,
        accessToken: "",
        bundleCount: 0,
        bundleErrors: [],
        error: errorMessage,
      };
    }
    await persistResolvedCmGlobalAuthState(accessToken, `programmer-hydrate:${reason || programmerId}`).catch(() => null);

    const hasCachedBundles = hasCachedCmTenantBundleCoverage(cmService);
    const profileHarvest = getCmProfileHarvestForProgrammer(programmer);
    const tenantScope = resolveCmUsageTenantScopeValue(
      options?.tenantScope,
      matchedTenants?.[0]?.tenantId,
      matchedTenants?.[0]?.tenantName,
      getCmTenantScopeForProgrammer(programmer)
    );
    const bundles =
      !forceRefresh && hasCachedBundles
        ? matchedTenants.map((tenant) => {
            const tenantCacheKey = cmGetTenantCacheKey(tenant);
            const cachedBundle = tenantCacheKey ? state.cmTenantBundleByTenantKey.get(tenantCacheKey)?.bundle || null : null;
            if (cachedBundle) {
              return {
                ...cachedBundle,
                usage: {
                  ...(cachedBundle.usage || {}),
                  rows: buildCmUsageSeedRows(tenant, profileHarvest, tenantScope),
                  tenantScope,
                },
              };
            }
            return null;
          }).filter(Boolean)
        : await Promise.all(
            matchedTenants.map((tenant) =>
              loadCmTenantBundle(tenant, {
                forceRefresh,
                profileHarvest,
                tenantScope,
              })
            )
          );
    const bundleErrors = bundles
      .flatMap((bundle) => [bundle?.applications?.error, bundle?.policies?.error])
      .map((value) => String(value || "").trim())
      .filter(Boolean);
    const settledService = {
      ...(cmService && typeof cmService === "object" ? cmService : {}),
      matchedTenants,
      fetchedAt: Date.now(),
      tokenFingerprint: getCmAuthFingerprint(),
      loadError: bundleErrors[0] || "",
    };
    state.cmServiceByProgrammerId.set(programmerId, settledService);
    const mergedServices = mergeProgrammerPremiumServicesWithCm(programmerId, initialServices, settledService);
    setCurrentPremiumAppsSnapshot(programmerId, mergedServices);
    emitCmDebugEvent({
      phase: "cm-programmer-hydration-complete",
      programmerId,
      programmerName: String(programmer?.programmerName || programmerId),
      matchedTenantCount: matchedTenants.length,
      bundleCount: bundles.length,
      bundleErrorCount: bundleErrors.length,
      tenantScope,
      reason,
    });
    return {
      ok: bundleErrors.length === 0,
      skipped: false,
      requiresHydration: true,
      cmService: settledService,
      services: mergedServices,
      accessToken,
      bundleCount: bundles.length,
      bundleErrors,
      error: bundleErrors[0] || "",
    };
  })();

  state.cmHydrationPromiseByProgrammerId.set(programmerId, hydrationPromise);
  try {
    return await hydrationPromise;
  } finally {
    if (state.cmHydrationPromiseByProgrammerId.get(programmerId) === hydrationPromise) {
      state.cmHydrationPromiseByProgrammerId.delete(programmerId);
    }
  }
}

async function ensureCmServiceForSelectedMvpd(programmer, options = {}) {
  if (!programmer?.programmerId) {
    return null;
  }

  const forceRefresh = options.forceRefresh === true;
  const mvpdContext = buildSelectedMvpdMatchContext(programmer);
  if (!mvpdContext?.selectionKey) {
    return null;
  }

  if (forceRefresh) {
    state.cmServiceByMvpdSelectionKey.delete(mvpdContext.selectionKey);
  }

  if (!forceRefresh && state.cmServiceByMvpdSelectionKey.has(mvpdContext.selectionKey)) {
    const cachedService = state.cmServiceByMvpdSelectionKey.get(mvpdContext.selectionKey);
    const cachedMatches = Array.isArray(cachedService?.matchedTenants) ? cachedService.matchedTenants : [];
    if (cachedMatches.length === 0) {
      let catalog = state.cmTenantsCatalog && Array.isArray(state.cmTenantsCatalog.tenants) ? state.cmTenantsCatalog : null;
      if (!catalog || !Array.isArray(catalog.tenants) || catalog.tenants.length === 0) {
        try {
          catalog = await ensureCmTenantsCatalog({ forceRefresh: false });
        } catch {
          catalog = null;
        }
      }
      if (catalog && catalog.tenants.length > 0) {
        const rematchedTenants = findCmTenantMatchesForMvpd(mvpdContext.mvpdId, mvpdContext.mvpdName, catalog.tenants, {
          mvpdMeta: mvpdContext.mvpdMeta,
          mvpdLabel: mvpdContext.mvpdLabel,
        });
        if (rematchedTenants.length > 0) {
          const refreshedService = {
            ...(cachedService && typeof cachedService === "object" ? cachedService : {}),
            serviceType: "cmMvpd",
            requestorId: mvpdContext.requestorId,
            mvpdId: mvpdContext.mvpdId,
            mvpdName: mvpdContext.mvpdName,
            mvpdLabel: mvpdContext.mvpdLabel,
            matchedTenants: rematchedTenants,
            sourceUrl: String(catalog.sourceUrl || cachedService?.sourceUrl || ""),
            fetchedAt: Number(catalog.fetchedAt || cachedService?.fetchedAt || Date.now()),
            tenantCount: Number(catalog.tenants.length || cachedService?.tenantCount || rematchedTenants.length),
            tokenFingerprint: getCmAuthFingerprint(),
            matchPass: String(rematchedTenants?.[0]?.matchPass || "").trim(),
          };
          state.cmServiceByMvpdSelectionKey.set(mvpdContext.selectionKey, refreshedService);
          emitCmTenantMatchDebugLineForMvpd(programmer, mvpdContext, catalog, rematchedTenants, {
            cacheState: "cache-rematch",
          });
          return refreshedService;
        }
      }
    }
    if (!shouldRetryCachedCmService(cachedService)) {
      emitCmTenantMatchDebugLineForMvpd(
        programmer,
        mvpdContext,
        {
          sourceUrl: String(cachedService?.sourceUrl || ""),
          tenants: Array.isArray(cachedService?.matchedTenants) ? cachedService.matchedTenants : [],
        },
        Array.isArray(cachedService?.matchedTenants) ? cachedService.matchedTenants : [],
        { cacheState: "cache-hit" }
      );
      return cachedService;
    }
  }

  if (!forceRefresh && state.cmServiceLoadPromiseByMvpdSelectionKey.has(mvpdContext.selectionKey)) {
    return state.cmServiceLoadPromiseByMvpdSelectionKey.get(mvpdContext.selectionKey);
  }

  const loadPromise = (async () => {
    let catalog = null;
    try {
      catalog = await ensureCmTenantsCatalog({ forceRefresh: false });
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      const service = {
        serviceType: "cmMvpd",
        requestorId: mvpdContext.requestorId,
        mvpdId: mvpdContext.mvpdId,
        mvpdName: mvpdContext.mvpdName,
        mvpdLabel: mvpdContext.mvpdLabel,
        matchedTenants: [],
        sourceUrl: "",
        fetchedAt: Date.now(),
        tenantCount: 0,
        tokenFingerprint: getCmAuthFingerprint(),
        loadError: reason,
      };
      state.cmServiceByMvpdSelectionKey.set(mvpdContext.selectionKey, service);
      return service;
    }

    let matchedTenants = findCmTenantMatchesForMvpd(
      mvpdContext.mvpdId,
      mvpdContext.mvpdName,
      catalog?.tenants || [],
      {
        mvpdMeta: mvpdContext.mvpdMeta,
        mvpdLabel: mvpdContext.mvpdLabel,
      }
    );
    emitCmTenantMatchDebugLineForMvpd(programmer, mvpdContext, catalog, matchedTenants, {
      cacheState: forceRefresh ? "force-refresh" : "live",
    });
    const tokenFingerprint = getCmAuthFingerprint();
    const service = {
      serviceType: "cmMvpd",
      requestorId: mvpdContext.requestorId,
      mvpdId: mvpdContext.mvpdId,
      mvpdName: mvpdContext.mvpdName,
      mvpdLabel: mvpdContext.mvpdLabel,
      matchedTenants,
      sourceUrl: String(catalog?.sourceUrl || ""),
      fetchedAt: Number(catalog?.fetchedAt || Date.now()),
      tenantCount: Number(catalog?.tenants?.length || 0),
      tokenFingerprint,
      matchPass: matchedTenants?.[0]?.matchPass || "",
    };
    state.cmServiceByMvpdSelectionKey.set(mvpdContext.selectionKey, service);
    return service;
  })();

  state.cmServiceLoadPromiseByMvpdSelectionKey.set(mvpdContext.selectionKey, loadPromise);
  try {
    return await loadPromise;
  } finally {
    if (state.cmServiceLoadPromiseByMvpdSelectionKey.get(mvpdContext.selectionKey) === loadPromise) {
      state.cmServiceLoadPromiseByMvpdSelectionKey.delete(mvpdContext.selectionKey);
    }
  }
}

function buildCmResourceUrlCandidates(kind, tenant, profileHarvest = null, tenantScope = "") {
  const tenantId = String(tenant?.tenantId || "").trim();
  const tenantLinks = Array.isArray(tenant?.links) ? tenant.links : [];
  const rawLinks = collectCmUrlsFromValue(tenant?.raw, { maxDepth: 5 });
  const kindValue = String(kind || "").trim().toLowerCase();

  if (kindValue === "applications" && tenantId) {
    return uniqueSorted([`${CM_CONFIG_BASE_URL}/maitai/applications?orgId=${encodeURIComponent(tenantId)}`]);
  }
  if (kindValue === "policies" && tenantId) {
    return uniqueSorted([`${CM_CONFIG_BASE_URL}/maitai/policy?orgId=${encodeURIComponent(tenantId)}`]);
  }
  if (kindValue === "tenant") {
    return uniqueSorted(
      [...tenantLinks, ...rawLinks, `${CM_CONFIG_BASE_URL}/core/tenants?orgId=${encodeURIComponent(CM_DEFAULT_TENANT_ORG_HINT)}`]
        .map((url) => normalizeCmUrl(url))
        .filter(Boolean)
    );
  }
  if (kindValue === "usage") {
    return uniqueSorted(
      buildCmUsageSeedRows(tenant, profileHarvest, tenantScope)
        .map((row) => String(row?.sourceUrl || "").trim())
        .filter(Boolean)
    );
  }

  const keywordByKind = {
    tenant: ["tenant"],
    applications: ["application", "apps"],
    policies: ["policy", "policies", "rule", "rules"],
    usage: ["usage", "cmu", "metric", "report"],
  };
  const keywordList = keywordByKind[kindValue] || [];
  const filteredLinks = uniqueSorted(
    [...tenantLinks, ...rawLinks].filter((url) => {
      if (kindValue === "tenant") {
        return /tenant/i.test(String(url || ""));
      }
      return keywordList.some((keyword) => String(url || "").toLowerCase().includes(keyword));
    })
  );

  const templateByKind = {
    tenant: CM_TENANT_DETAIL_PATH_TEMPLATES,
    applications: CM_APPLICATIONS_PATH_TEMPLATES,
    policies: CM_POLICIES_PATH_TEMPLATES,
    usage: getCanonicalCmUsageTemplatePaths(),
  };
  const templateUrls = buildCmTemplateUrls(tenantId, templateByKind[kindValue] || []);
  return uniqueSorted([...filteredLinks, ...templateUrls].filter(Boolean));
}

async function fetchCmTenantResource(kind, tenant, profileHarvest = null, tenantScope = "") {
  const kindValue = String(kind || "").trim().toLowerCase();
  const candidates = buildCmResourceUrlCandidates(kindValue, tenant, profileHarvest, tenantScope);
  if (candidates.length === 0) {
    return {
      kind: kindValue,
      url: "",
      payload: null,
      lastModified: "",
      rows: [],
      error: `No ${kindValue} endpoints were discovered for tenant "${tenant?.tenantName || tenant?.tenantId || "unknown"}".`,
    };
  }

  let lastError = null;
  for (const candidate of candidates) {
    try {
      const response = await fetchCmJsonWithAuthVariants([candidate], `CM ${kindValue} load`, {
        allowTemporaryPageContextTab: false,
        debugMeta: {
          scope: kindValue,
          endpointUrl: candidate,
          tenantId: String(tenant?.tenantId || ""),
          tenantName: String(tenant?.tenantName || ""),
          requestorId: String(state.selectedRequestorId || ""),
          mvpd: String(state.selectedMvpdId || ""),
        },
      });
      const payload = response.parsed;
      const rows =
        kindValue === "tenant"
          ? payload && typeof payload === "object"
            ? [payload]
            : []
          : normalizeCmResourceListFromPayload(kindValue, payload, tenant, response.url);
      return {
        kind: kindValue,
        url: response.url,
        payload,
        lastModified: response.lastModified || "",
        rows,
        error: "",
      };
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));
    }
  }

  return {
    kind: kindValue,
    url: "",
    payload: null,
    lastModified: "",
    rows: [],
    error: lastError ? lastError.message : `Unable to load CM ${kindValue}.`,
  };
}

async function loadCmTenantBundle(tenant, options = {}) {
  const forceRefresh = options.forceRefresh === true;
  const profileHarvest = options?.profileHarvest && typeof options.profileHarvest === "object" ? options.profileHarvest : null;
  const tenantScope = resolveCmUsageTenantScopeValue(
    options?.tenantScope,
    options?.tenantId,
    tenant?.tenantId,
    tenant?.tenantName
  );
  const tenantCacheKey = cmGetTenantCacheKey(tenant);

  if (!forceRefresh && tenantCacheKey) {
    const cachedEntry = state.cmTenantBundleByTenantKey.get(tenantCacheKey);
    if (cachedEntry?.bundle) {
      const mergedTenant =
        tenant && typeof tenant === "object" ? { ...(cachedEntry.bundle.tenant || {}), ...tenant } : cachedEntry.bundle.tenant;
      const usageRows = buildCmUsageSeedRows(mergedTenant, profileHarvest, tenantScope);
      return {
        ...cachedEntry.bundle,
        tenant: mergedTenant,
        usage: {
          ...(cachedEntry.bundle.usage || {}),
          rows: usageRows,
        },
      };
    }
    if (state.cmTenantBundlePromiseByTenantKey.has(tenantCacheKey)) {
      return state.cmTenantBundlePromiseByTenantKey.get(tenantCacheKey);
    }
  }

  const loadPromise = (async () => {
    const [applications, policies] = await Promise.all([
      fetchCmTenantResource("applications", tenant, profileHarvest, tenantScope),
      fetchCmTenantResource("policies", tenant, profileHarvest, tenantScope),
    ]);
    const tenantDetail = {
      kind: "tenant",
      url: String(tenant?.sourceUrl || ""),
      payload: tenant?.raw && typeof tenant.raw === "object" ? tenant.raw : tenant || null,
      lastModified: "",
      rows: tenant?.raw && typeof tenant.raw === "object" ? [tenant.raw] : [],
      error: "",
    };
    const usage = {
      kind: "usage",
      url: "",
      payload: null,
      lastModified: "",
      rows: buildCmUsageSeedRows(tenant, profileHarvest, tenantScope),
      error: "",
      tenantScope,
    };
    const bundle = {
      tenant,
      tenantDetail,
      applications,
      policies,
      usage,
    };
    if (tenantCacheKey) {
      state.cmTenantBundleByTenantKey.set(tenantCacheKey, {
        fetchedAt: Date.now(),
        bundle,
      });
    }
    return bundle;
  })();

  if (tenantCacheKey) {
    state.cmTenantBundlePromiseByTenantKey.set(tenantCacheKey, loadPromise);
  }
  try {
    return await loadPromise;
  } finally {
    if (tenantCacheKey && state.cmTenantBundlePromiseByTenantKey.get(tenantCacheKey) === loadPromise) {
      state.cmTenantBundlePromiseByTenantKey.delete(tenantCacheKey);
    }
  }
}

const CM_ROW_FLATTEN_MAX_DEPTH = 4;
const CM_ROW_ARRAY_FIELD_LIMIT = 8;
const CM_ROW_PREVIEW_LIMIT = 6;
const CM_ROW_VALUE_CHAR_LIMIT = 1400;

function cmIsPrimitiveRowValue(value) {
  return value == null || typeof value === "string" || typeof value === "number" || typeof value === "boolean";
}

function cmNormalizeRowValue(value) {
  if (value == null) {
    return "";
  }
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return value;
  }
  if (Array.isArray(value)) {
    if (value.every((item) => cmIsPrimitiveRowValue(item))) {
      return truncateDebugText(
        value
          .map((item) => (item == null ? "" : String(item)))
          .filter((item) => String(item).trim() !== "")
          .join(", "),
        CM_ROW_VALUE_CHAR_LIMIT
      );
    }
    return cmSummarizeArrayForRow(value);
  }
  if (typeof value === "object") {
    return cmSummarizeObjectForRow(value);
  }
  return truncateDebugText(String(value), CM_ROW_VALUE_CHAR_LIMIT);
}

function cmExtractEntityLabel(value) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return "";
  }
  return String(
    firstNonEmptyString([
      value.name,
      value.displayName,
      value.display_name,
      value.title,
      value.label,
      value.consoleId,
      value.consoleOwnerId,
      value.id,
      value.tenantId,
      value.tenant_id,
      value.applicationId,
      value.application_id,
      value.policyId,
      value.policy_id,
      value.ruleId,
      value.rule_id,
      value.type,
      value.key,
    ]) || ""
  ).trim();
}

function cmSummarizeObjectForRow(value) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return cmNormalizeRowValue(value);
  }
  const keys = Object.keys(value).map((key) => String(key || "").trim()).filter(Boolean);
  if (keys.length === 0) {
    return "(empty object)";
  }
  const label = cmExtractEntityLabel(value);
  const preview = keys.slice(0, 4).join(", ");
  const more = keys.length > 4 ? ` (+${keys.length - 4} more)` : "";
  return truncateDebugText(label ? `${label} | ${preview}${more}` : `${preview}${more}`, CM_ROW_VALUE_CHAR_LIMIT);
}

function cmSummarizeArrayForRow(value) {
  if (!Array.isArray(value)) {
    return cmNormalizeRowValue(value);
  }
  if (value.length === 0) {
    return "";
  }
  if (value.every((item) => cmIsPrimitiveRowValue(item))) {
    return truncateDebugText(
      value
        .map((item) => (item == null ? "" : String(item)))
        .filter((item) => String(item).trim() !== "")
        .join(", "),
      CM_ROW_VALUE_CHAR_LIMIT
    );
  }
  const labels = [];
  value.forEach((item) => {
    if (labels.length >= CM_ROW_PREVIEW_LIMIT) {
      return;
    }
    if (cmIsPrimitiveRowValue(item)) {
      const normalized = String(item == null ? "" : item).trim();
      if (normalized) {
        labels.push(normalized);
      }
      return;
    }
    if (Array.isArray(item)) {
      labels.push(`${item.length} item${item.length === 1 ? "" : "s"}`);
      return;
    }
    if (item && typeof item === "object") {
      const label = cmExtractEntityLabel(item);
      if (label) {
        labels.push(label);
        return;
      }
      const keyPreview = Object.keys(item)
        .map((key) => String(key || "").trim())
        .filter(Boolean)
        .slice(0, 2)
        .join("/");
      if (keyPreview) {
        labels.push(keyPreview);
      }
    }
  });
  const labelPrefix = labels.length > 0 ? `: ${labels.join(", ")}` : "";
  const overflow = value.length > CM_ROW_PREVIEW_LIMIT ? ` (+${value.length - CM_ROW_PREVIEW_LIMIT} more)` : "";
  return truncateDebugText(`${value.length} item${value.length === 1 ? "" : "s"}${labelPrefix}${overflow}`, CM_ROW_VALUE_CHAR_LIMIT);
}

function cmCollectArrayObjectFields(values) {
  const fields = [];
  const seen = new Set();
  values.slice(0, CM_ROW_PREVIEW_LIMIT).forEach((entry) => {
    if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
      return;
    }
    Object.keys(entry).forEach((rawKey) => {
      const key = String(rawKey || "").trim();
      if (!key || seen.has(key)) {
        return;
      }
      seen.add(key);
      fields.push(key);
    });
  });
  return fields.slice(0, CM_ROW_ARRAY_FIELD_LIMIT);
}

function cmFlattenValueToRow(row, keyPrefix, value, depth = 0, seen = null) {
  const key = String(keyPrefix || "value").trim() || "value";
  const seenRefs = seen instanceof Set ? seen : new Set();

  if (cmIsPrimitiveRowValue(value)) {
    row[key] = cmNormalizeRowValue(value);
    return;
  }

  if (depth >= CM_ROW_FLATTEN_MAX_DEPTH) {
    row[key] = cmNormalizeRowValue(value);
    return;
  }

  if (typeof value === "object") {
    if (seenRefs.has(value)) {
      row[key] = "(circular reference)";
      return;
    }
    seenRefs.add(value);
  }

  if (Array.isArray(value)) {
    row[`${key}.count`] = value.length;
    row[key] = cmSummarizeArrayForRow(value);
    if (value.every((item) => item && typeof item === "object" && !Array.isArray(item))) {
      const fields = cmCollectArrayObjectFields(value);
      fields.forEach((field) => {
        const valuesByField = [];
        const valueSeen = new Set();
        value.forEach((entry) => {
          const normalizedValue = cmNormalizeRowValue(entry?.[field]);
          const normalizedText = String(normalizedValue == null ? "" : normalizedValue).trim();
          if (!normalizedText || valueSeen.has(normalizedText)) {
            return;
          }
          valueSeen.add(normalizedText);
          valuesByField.push(normalizedText);
        });
        if (valuesByField.length > 0) {
          const preview = valuesByField.slice(0, CM_ROW_PREVIEW_LIMIT).join(", ");
          const overflow = valuesByField.length > CM_ROW_PREVIEW_LIMIT ? ` (+${valuesByField.length - CM_ROW_PREVIEW_LIMIT} more)` : "";
          row[`${key}.${field}`] = truncateDebugText(`${preview}${overflow}`, CM_ROW_VALUE_CHAR_LIMIT);
        }
      });
    }
    return;
  }

  if (value && typeof value === "object") {
    const entries = Object.entries(value);
    if (entries.length === 0) {
      row[key] = "(empty object)";
      return;
    }
    entries.forEach(([nestedKey, nestedValue]) => {
      const childKey = String(nestedKey || "").trim();
      if (!childKey) {
        return;
      }
      cmFlattenValueToRow(row, `${key}.${childKey}`, nestedValue, depth + 1, seenRefs);
    });
    return;
  }

  row[key] = cmNormalizeRowValue(value);
}

function cmFlattenObjectToRow(value) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return { value: cmNormalizeRowValue(value) };
  }
  const row = {};
  const seenRefs = new Set();
  Object.entries(value).forEach(([key, nested]) => {
    const normalizedKey = String(key || "").trim();
    if (!normalizedKey) {
      return;
    }
    cmFlattenValueToRow(row, normalizedKey, nested, 0, seenRefs);
  });
  if (Object.keys(row).length === 0) {
    row.value = cmSummarizeObjectForRow(value);
  }
  return row;
}

function cmRowsFromPayload(payload) {
  if (Array.isArray(payload)) {
    if (payload.length === 0) {
      return [];
    }
    if (payload.every((item) => item && typeof item === "object" && !Array.isArray(item))) {
      return payload.map((item) => cmFlattenObjectToRow(item));
    }
    return payload.map((item) => ({ value: cmNormalizeRowValue(item) }));
  }

  if (payload && typeof payload === "object") {
    const collectionCandidates = [
      payload.items,
      payload.data,
      payload.rows,
      payload.results,
      payload.records,
      payload.report,
      payload.runningStreams,
      payload.associatedAdvice,
      payload.obligations,
      payload.applications,
      payload.policies,
      payload.usage,
    ].filter((candidate) => Array.isArray(candidate));

    if (collectionCandidates.length > 0) {
      const largest = collectionCandidates.sort((left, right) => right.length - left.length)[0];
      return cmRowsFromPayload(largest);
    }
    return [cmFlattenObjectToRow(payload)];
  }

  if (payload == null || payload === "") {
    return [];
  }
  return [{ value: cmNormalizeRowValue(payload) }];
}

function cmRowsFromPayloadForRecord(payload, record = null, requestUrl = "") {
  const recordKind = String(record?.kind || "").trim().toLowerCase();
  const normalizedRequestUrl = String(requestUrl || record?.requestUrl || record?.endpointUrl || "").trim();
  const shouldRenderAsObjectRow =
    recordKind === "applications" &&
    cmIsApplicationDetailRequestUrl(normalizedRequestUrl) &&
    payload &&
    typeof payload === "object" &&
    !Array.isArray(payload);

  if (shouldRenderAsObjectRow) {
    return [cmFlattenObjectToRow(payload)];
  }

  return cmRowsFromPayload(payload);
}

function cmColumnsFromPayload(payload) {
  const rows = cmRowsFromPayload(payload);
  if (rows.length === 0) {
    return [];
  }
  return cmColumnsFromRows(rows);
}

function cmColumnsFromPayloadForRecord(payload, record = null, requestUrl = "") {
  const rows = cmRowsFromPayloadForRecord(payload, record, requestUrl);
  if (rows.length === 0) {
    return [];
  }
  return cmColumnsFromRows(rows);
}

function cmColumnsFromRows(rows, preferredColumns = []) {
  const output = [];
  const seen = new Set();
  const pushColumn = (value) => {
    const key = String(value || "").trim();
    if (!key || key.startsWith("__") || seen.has(key)) {
      return;
    }
    seen.add(key);
    output.push(key);
  };

  (Array.isArray(preferredColumns) ? preferredColumns : []).forEach((column) => {
    pushColumn(column);
  });
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    if (!row || typeof row !== "object") {
      return;
    }
    Object.keys(row).forEach((column) => {
      pushColumn(column);
    });
  });
  return output;
}

function cmNormalizeCsvCellValue(value) {
  if (value == null) {
    return "";
  }
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function cmParseTimestampCandidateForSort(row) {
  const tsCandidate = row?.timestamp ?? row?.date ?? row?.time;
  if (tsCandidate == null || tsCandidate === "") {
    return Number.NEGATIVE_INFINITY;
  }
  const parsed = new Date(tsCandidate);
  const ms = parsed.getTime();
  return Number.isFinite(ms) ? ms : Number.NEGATIVE_INFINITY;
}

function cmGetSortableValue(row, column) {
  const normalizedColumn = String(column || "").trim().toLowerCase();
  if (normalizedColumn === "date") {
    const sourceUtcOffsetMinutes = -8 * 60;
    const year = Number(row?.year);
    const month = Number(row?.month);
    const day = Number(row?.day);
    const hour = Number(row?.hour);
    const minute = Number(row?.minute);
    const hasAnyParts = [year, month, day, hour, minute].some((value) => Number.isFinite(value));
    if (!hasAnyParts) {
      return cmParseTimestampCandidateForSort(row);
    }
    const nowPst = new Date(Date.now() + sourceUtcOffsetMinutes * 60 * 1000);
    const fallbackYear = nowPst.getUTCFullYear();
    const ms =
      Date.UTC(
        Number.isFinite(year) ? year : fallbackYear,
        Math.max(0, (Number.isFinite(month) ? month : 1) - 1),
        Number.isFinite(day) ? day : 1,
        Number.isFinite(hour) ? hour : 0,
        Number.isFinite(minute) ? minute : 0
      ) -
      sourceUtcOffsetMinutes * 60 * 1000;
    if (Number.isFinite(ms)) {
      return ms;
    }
    return cmParseTimestampCandidateForSort(row);
  }

  const value = row?.[column];
  if (typeof value === "number") {
    return value;
  }
  if (typeof value === "boolean") {
    return value ? 1 : 0;
  }
  const numeric = Number(value);
  if (Number.isFinite(numeric) && String(value).trim() !== "") {
    return numeric;
  }
  return String(value == null ? "" : value).toLowerCase();
}

function cmSortRowsForCsv(rows, sortRule = null, columns = []) {
  const normalizedSort = esmWorkspaceNormalizeSortRule(sortRule);
  const fallbackColumn = Array.isArray(columns) && columns.length > 0 ? String(columns[0] || "").trim() : "";
  const sortColumn = String(normalizedSort?.col || fallbackColumn || "").trim();
  if (!sortColumn) {
    return [...rows];
  }
  const direction = String(normalizedSort?.dir || "DESC").toUpperCase() === "ASC" ? 1 : -1;
  return [...rows].sort((left, right) => {
    const leftValue = cmGetSortableValue(left, sortColumn);
    const rightValue = cmGetSortableValue(right, sortColumn);
    if (leftValue < rightValue) {
      return -1 * direction;
    }
    if (leftValue > rightValue) {
      return 1 * direction;
    }
    return 0;
  });
}

function cmBuildCsvFileName(cmState, record = null, fallbackCard = null) {
  const programmerSegment = sanitizeHarFileSegment(cmState?.programmer?.programmerId, "cm");
  const tenantSegment = sanitizeHarFileSegment(record?.tenantId || record?.tenantName, "tenant");
  const kindSegment = sanitizeHarFileSegment(record?.kind || fallbackCard?.zoomKey, "report");
  const entitySegment = sanitizeHarFileSegment(record?.title || fallbackCard?.cardId, "dataset");
  const envTag = getAdobePassEnvironmentFileTag();
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  return `cm_${programmerSegment}_${tenantSegment}_${kindSegment}_${entitySegment}_${envTag}_${stamp}.csv`;
}

function cmDownloadRowsAsCsv(rows, options = {}) {
  const normalizedRows = (Array.isArray(rows) ? rows : [])
    .filter((row) => row && typeof row === "object")
    .map((row) => ({ ...row }));
  if (normalizedRows.length === 0) {
    return false;
  }

  const columns = cmColumnsFromRows(normalizedRows, options.columns);
  if (columns.length === 0) {
    return false;
  }
  const sortedRows = cmSortRowsForCsv(normalizedRows, options.sortRule, columns);
  const lines = [
    columns.map((column) => `"${String(column || "").replace(/"/g, '""')}"`).join(","),
    ...sortedRows.map((row) =>
      columns.map((column) => `"${cmNormalizeCsvCellValue(row[column]).replace(/"/g, '""')}"`).join(",")
    ),
  ];

  const blob = new Blob([lines.join("\n")], { type: "text/csv" });
  const blobUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = blobUrl;
  anchor.download = String(options.fileName || "cm-report.csv");
  anchor.click();
  URL.revokeObjectURL(blobUrl);
  return true;
}

async function cmDownloadCsvForCard(cmState, record, card, sortRule, requestToken) {
  const normalizedCard = card && typeof card === "object" ? card : {};
  const isMvpdCmContext = String(cmState?.serviceType || "").trim().toLowerCase() === "cmmvpd";
  const requestContext = cmResolveRequestorMvpdContext(cmState);
  const scopedRecord =
    isMvpdCmContext
      ? {
          ...(record && typeof record === "object" ? record : {}),
          tenantId: firstNonEmptyString([
            String(record?.tenantId || "").trim(),
            String(cmState?.cmService?.matchedTenants?.[0]?.tenantId || "").trim(),
            String(cmState?.tenantScope || "").trim(),
            String(requestContext.mvpdId || "").trim(),
          ]),
          tenantName: firstNonEmptyString([
            String(record?.tenantName || "").trim(),
            String(cmState?.cmService?.matchedTenants?.[0]?.tenantName || "").trim(),
            String(requestContext.mvpdLabel || "").trim(),
            String(requestContext.mvpdId || "").trim(),
          ]),
        }
      : record;
  const requestUrlOverrideRaw = String(normalizedCard.requestUrl || normalizedCard.endpointUrl || "").trim();
  const requestUrlOverride = cmScopeUsageRequestUrl(requestUrlOverrideRaw, cmState, scopedRecord) || requestUrlOverrideRaw;
  const recordRequestUrl = cmScopeUsageRequestUrl(
    String(record?.requestUrl || record?.endpointUrl || "").trim(),
    cmState,
    scopedRecord
  );
  const hasUrlOverrideDiffersFromRecord =
    Boolean(requestUrlOverride) && requestUrlOverride !== recordRequestUrl;
  const recordKind = String(record?.kind || "").trim().toLowerCase();
  let rows = hasUrlOverrideDiffersFromRecord ? [] : Array.isArray(normalizedCard.rows) ? normalizedCard.rows : [];
  let columns = Array.isArray(normalizedCard.columns) ? normalizedCard.columns : [];

  if (rows.length === 0 && record?.payload != null) {
    rows = cmRowsFromPayloadForRecord(record.payload, record, recordRequestUrl);
    columns =
      Array.isArray(record?.columns) && record.columns.length > 0
        ? record.columns
        : cmColumnsFromPayloadForRecord(record.payload, record, recordRequestUrl);
  }

  if (rows.length === 0 && recordKind === "esm-health-xref") {
    const response = await cmFetchEsmHealthXrefReport(record, cmState);
    if (!isCmServiceRequestActive(cmState.section, requestToken, cmState.programmer?.programmerId)) {
      return { ok: false, skipped: true, error: "CM controller is no longer active for the selected media company." };
    }
    rows = Array.isArray(response.rows) ? response.rows : [];
    columns = Array.isArray(response.columns) ? response.columns : cmColumnsFromRows(rows);
    if (!hasUrlOverrideDiffersFromRecord) {
      record.requestUrl = String(response.requestUrl || record.requestUrl || "").trim();
      record.endpointUrl = String(response.requestUrl || record.endpointUrl || "").trim();
      record.columns = columns;
    }
  }

  if (rows.length === 0 && record && recordKind !== "cmv2-op" && recordKind !== "esm-health-xref") {
    const requestUrl = requestUrlOverride || recordRequestUrl;
    if (requestUrl) {
      const response = await fetchCmJsonWithAuthVariants([requestUrl], `CM ${record.kind || "report"} CSV`, {
        allowTemporaryPageContextTab: recordKind === "usage",
        debugMeta: {
          scope: `cm-csv-${String(record.kind || "report")}`,
          endpointUrl: requestUrl,
          cardId: String(normalizedCard?.cardId || record?.cardId || ""),
          programmerId: String(cmState?.programmer?.programmerId || ""),
          requestorId: String(requestContext.requestorId || state.selectedRequestorId || ""),
          mvpd: String(requestContext.mvpdId || state.selectedMvpdId || ""),
          workspaceKey: isMvpdCmContext ? "mvpd-workspace" : "cmu-workspace",
          workspaceOrigin: isMvpdCmContext ? "MVPD Workspace" : "CMU Workspace",
        },
      });
      if (!isCmServiceRequestActive(cmState.section, requestToken, cmState.programmer?.programmerId)) {
        return { ok: false, skipped: true, error: "CM controller is no longer active for the selected media company." };
      }
      const responsePayload = response.parsed;
      rows = cmRowsFromPayloadForRecord(responsePayload, record, requestUrl);
      columns = cmColumnsFromRows(rows);
      if (!hasUrlOverrideDiffersFromRecord) {
        record.payload = responsePayload;
        record.lastModified = String(response.lastModified || record.lastModified || "");
        record.columns = columns;
      }
    }
  }

  if (rows.length === 0) {
    return { ok: false, error: "No CM rows are available to export as CSV." };
  }

  const fileName = cmBuildCsvFileName(cmState, scopedRecord, normalizedCard);
  const started = cmDownloadRowsAsCsv(rows, {
    columns,
    sortRule,
    fileName,
  });
  if (!started) {
    return { ok: false, error: "Unable to build CM CSV from the current report rows." };
  }
  return { ok: true, fileName };
}

function normalizeRestV2MvpdLogoUrl(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  try {
    const parsed = new URL(raw);
    if (!/^https?:$/i.test(parsed.protocol)) {
      return "";
    }
    return parsed.toString();
  } catch {
    if (raw.startsWith("//")) {
      return `https:${raw}`;
    }
    return "";
  }
}

function isRestV2MvpdLogoNodeVisible(node) {
  const visibleValue = firstNonEmptyString([
    node?.visible,
    node?.["@visible"],
    node?.["@_visible"],
    node?._visible,
    node?.attributes?.visible,
  ]);
  const normalized = String(visibleValue || "").trim().toLowerCase();
  if (!normalized) {
    return true;
  }
  return !["false", "0", "no", "hidden"].includes(normalized);
}

function readRestV2MvpdLogoNodeUrl(value) {
  if (!value) {
    return "";
  }
  if (Array.isArray(value)) {
    for (const entry of value) {
      const normalized = readRestV2MvpdLogoNodeUrl(entry);
      if (normalized) {
        return normalized;
      }
    }
    return "";
  }
  if (typeof value === "string") {
    return normalizeRestV2MvpdLogoUrl(value);
  }
  if (typeof value !== "object") {
    return "";
  }
  if (!isRestV2MvpdLogoNodeVisible(value)) {
    return "";
  }
  const candidates = [
    value?.url,
    value?.href,
    value?.value,
    value?.text,
    value?.["#text"],
    value?._text,
    value?._,
    value?.cdata,
    value?.src,
  ];
  for (const candidate of candidates) {
    const normalized = normalizeRestV2MvpdLogoUrl(candidate);
    if (normalized) {
      return normalized;
    }
  }
  return "";
}

function extractRestV2MvpdLogoUrl(item = null) {
  if (!item || typeof item !== "object") {
    return "";
  }
  const candidates = [
    item?.logoUrl,
    item?.logoURL,
    item?.logo,
    item?.proxyLogo,
    item?.proxyLogoUrl,
    item?.proxyLogoURL,
    item?.loginImage,
    item?.loginImageUrl,
    item?.imageUrl,
    item?.assets?.logoUrl,
    item?.images?.logoUrl,
    item?.branding?.logoUrl,
    item?.branding?.logo,
    item?.configuration?.logoUrl,
    item?.config?.logoUrl,
  ];
  for (const candidate of candidates) {
    const normalized = readRestV2MvpdLogoNodeUrl(candidate);
    if (normalized) {
      return normalized;
    }
  }
  return "";
}

function normalizeRestV2MvpdCollection(payload) {
  const collection = payload?.requestor?.mvpds || payload?.mvpds || payload?.requestor?.mvpd || [];
  if (!Array.isArray(collection)) {
    return [];
  }

  return collection
    .map((item) => {
      if (!item || typeof item !== "object") {
        return null;
      }
      const id = firstNonEmptyString([item.id, item.mvpd, item.platformMappingId]);
      if (!id) {
        return null;
      }

      return {
        id,
        name: firstNonEmptyString([item.displayName, item.name, id]) || id,
        logoUrl: extractRestV2MvpdLogoUrl(item),
        isProxy: item.isProxy === false ? false : true,
        boardingStatus: firstNonEmptyString([item.boardingStatus]),
      };
    })
    .filter(Boolean);
}

function formatMvpdPickerLabel(mvpdId = "", metadata = null) {
  const normalizedMvpdId = String(mvpdId || "").trim();
  if (!normalizedMvpdId) {
    return "";
  }
  const displayName = String(firstNonEmptyString([metadata?.name, metadata?.displayName, normalizedMvpdId]) || normalizedMvpdId).trim();
  return `${displayName} (${normalizedMvpdId})`;
}

function normalizeAdobeNavigationUrl(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }

  try {
    const parsed = new URL(raw, ADOBE_SP_BASE);
    const isLocal = parsed.hostname === "localhost" || parsed.hostname === "127.0.0.1";
    if (isLocal && (parsed.pathname.startsWith("/api/v2/") || parsed.pathname.startsWith("/authenticate/"))) {
      return `${ADOBE_SP_BASE}${parsed.pathname}${parsed.search}${parsed.hash}`;
    }
    return parsed.toString();
  } catch {
    return raw;
  }
}

function getRestV2CaseInsensitiveObjectValue(source = null, keyCandidates = []) {
  if (!source || typeof source !== "object") {
    return "";
  }
  const candidates = Array.isArray(keyCandidates) ? keyCandidates : [keyCandidates];
  const normalizedCandidates = candidates.map((key) => String(key || "").trim().toLowerCase()).filter(Boolean);
  if (normalizedCandidates.length === 0) {
    return "";
  }
  for (const [key, value] of Object.entries(source)) {
    const normalizedKey = String(key || "").trim().toLowerCase();
    if (!normalizedKey || !normalizedCandidates.includes(normalizedKey)) {
      continue;
    }
    return String(value || "").trim();
  }
  return "";
}

function getRestV2CaseInsensitiveHeaderValue(headersLike = null, keyCandidates = []) {
  const candidates = Array.isArray(keyCandidates) ? keyCandidates : [keyCandidates];
  const normalizedCandidates = candidates.map((key) => String(key || "").trim().toLowerCase()).filter(Boolean);
  if (normalizedCandidates.length === 0) {
    return "";
  }
  if (headersLike instanceof Headers) {
    for (const [key, value] of headersLike.entries()) {
      const normalizedKey = String(key || "").trim().toLowerCase();
      if (normalizedCandidates.includes(normalizedKey)) {
        return String(value || "").trim();
      }
    }
    return "";
  }
  if (!headersLike || typeof headersLike !== "object") {
    return "";
  }
  return getRestV2CaseInsensitiveObjectValue(headersLike, normalizedCandidates);
}

function decodeURIComponentSafe(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  try {
    return decodeURIComponent(raw);
  } catch {
    return "";
  }
}

function parseRestV2PartnerFrameworkStatusPayload(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return null;
  }
  const decodedUri = decodeURIComponentSafe(raw);
  const decodedBase64Raw = decodeBase64TextSafe(raw);
  const decodedBase64Uri = decodeBase64TextSafe(decodedUri);
  const candidates = dedupeRestV2CandidateStrings([raw, decodedUri, decodedBase64Raw, decodedBase64Uri]);
  for (const candidate of candidates) {
    const parsed = parseJsonText(candidate, null);
    if (parsed && typeof parsed === "object") {
      return parsed;
    }
  }
  return null;
}

function resolveRestV2PartnerFromFrameworkStatus(value = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  const parsedPayload = parseRestV2PartnerFrameworkStatusPayload(raw);
  const directFromParsed = firstNonEmptyString([
    getRestV2CaseInsensitiveObjectValue(parsedPayload, [
      "partner",
      "partnerName",
      "frameworkPartner",
      "frameworkPartnerName",
      "frameworkPartnerId",
    ]),
    getRestV2CaseInsensitiveObjectValue(parsedPayload?.frameworkPartnerInfo, [
      "partner",
      "partnerName",
      "name",
      "id",
      "identifier",
    ]),
    getRestV2CaseInsensitiveObjectValue(parsedPayload?.partner, ["name", "partner", "id"]),
  ]);
  if (directFromParsed) {
    const normalizedDirect = String(directFromParsed || "").trim();
    if (/^(?:ios|tvos)$/i.test(normalizedDirect)) {
      return "Apple";
    }
    return normalizedDirect;
  }
  const frameworkName = firstNonEmptyString([
    getRestV2CaseInsensitiveObjectValue(parsedPayload, ["frameworkName", "framework"]),
    getRestV2CaseInsensitiveObjectValue(parsedPayload?.frameworkProviderInfo, ["frameworkName", "framework"]),
  ]);
  if (/^(?:ios|tvos|appletv|apple-tv)$/i.test(String(frameworkName || "").trim())) {
    return "Apple";
  }
  const decoded = decodeURIComponentSafe(raw);
  const decodedBase64Raw = decodeBase64TextSafe(raw);
  const decodedBase64Uri = decodeBase64TextSafe(decoded);
  const sourceText = [raw, decoded, decodedBase64Raw, decodedBase64Uri].filter(Boolean).join(" ");
  const partnerRegexes = [
    /frameworkname["'=:\s]+(?:ios|tvos|appletv|apple-tv)/i,
    /partner(?:name)?["'=:\s]+([A-Za-z][A-Za-z0-9_-]{1,64})/i,
    /\b(apple|roku|google|amazon|samsung)\b/i,
  ];
  for (const pattern of partnerRegexes) {
    const match = sourceText.match(pattern);
    if (!match) {
      continue;
    }
    if (pattern.source.startsWith("frameworkname")) {
      return "Apple";
    }
    if (match?.[1]) {
      return String(match[1] || "").trim();
    }
  }
  return "";
}

function resolveRestV2PartnerFrameworkStatusFromSessionData(sessionData = null, responseHeaders = null) {
  const existingParameters =
    sessionData?.existingParameters && typeof sessionData.existingParameters === "object" ? sessionData.existingParameters : null;
  const candidates = dedupeRestV2CandidateStrings([
    getRestV2CaseInsensitiveObjectValue(sessionData, [
      "ap-partner-framework-status",
      "AP-Partner-Framework-Status",
      "partnerFrameworkStatus",
      "partner_framework_status",
      "frameworkStatus",
      "framework_status",
    ]),
    getRestV2CaseInsensitiveObjectValue(existingParameters, [
      "ap-partner-framework-status",
      "AP-Partner-Framework-Status",
      "partnerFrameworkStatus",
      "partner_framework_status",
      "frameworkStatus",
      "framework_status",
    ]),
    getRestV2CaseInsensitiveHeaderValue(responseHeaders, [
      "ap-partner-framework-status",
      "AP-Partner-Framework-Status",
    ]),
  ]);
  return firstNonEmptyString(candidates);
}

function resolveRestV2SessionPartnerFromSessionData(sessionData = null, partnerFrameworkStatus = "") {
  const existingParameters =
    sessionData?.existingParameters && typeof sessionData.existingParameters === "object" ? sessionData.existingParameters : null;
  const partner = firstNonEmptyString([
    getRestV2CaseInsensitiveObjectValue(sessionData, [
      "partner",
      "partnerName",
    ]),
    getRestV2CaseInsensitiveObjectValue(existingParameters, [
      "partner",
      "partnerName",
    ]),
    resolveRestV2PartnerFromFrameworkStatus(partnerFrameworkStatus),
  ]);
  return String(partner || "").trim();
}

function resolveRestV2PartnerFrameworkStatusFromContext(context = null) {
  if (!context || typeof context !== "object") {
    return "";
  }
  return firstNonEmptyString([
    String(context.partnerFrameworkStatus || "").trim(),
    String(context?.sessionData?.partnerFrameworkStatus || "").trim(),
    resolveRestV2PartnerFrameworkStatusFromSessionData(context?.sessionData || null, context?.sessionResponseHeaders || null),
  ]);
}

function resolveRestV2PartnerNameFromContext(context = null) {
  if (!context || typeof context !== "object") {
    return "";
  }
  const frameworkStatus = resolveRestV2PartnerFrameworkStatusFromContext(context);
  return firstNonEmptyString([
    String(context.sessionPartner || "").trim(),
    String(context.partner || "").trim(),
    resolveRestV2SessionPartnerFromSessionData(context?.sessionData || null, frameworkStatus),
    resolveRestV2PartnerFromFrameworkStatus(frameworkStatus),
  ]);
}

function resolveMvpdLoginNavigationUrl(sessionData, serviceProviderId) {
  const normalizedServiceProvider = String(serviceProviderId || "").trim();
  const rawUrl = normalizeAdobeNavigationUrl(sessionData?.url || "");
  const actionName = String(sessionData?.actionName || "").trim().toLowerCase();
  const missingParameters = Array.isArray(sessionData?.missingParameters)
    ? sessionData.missingParameters.map((item) => String(item || "").trim().toLowerCase()).filter(Boolean)
    : [];

  let code = String(sessionData?.code || "").trim();
  if (!code && rawUrl) {
    const match = rawUrl.match(/\/sessions\/([^/?#]+)/i);
    if (match && match[1]) {
      code = decodeURIComponent(match[1]);
    }
  }

  const authUrl =
    normalizedServiceProvider && code
      ? `${REST_V2_BASE}/authenticate/${encodeURIComponent(normalizedServiceProvider)}/${encodeURIComponent(code)}`
      : "";
  if (!rawUrl) {
    return authUrl;
  }

  const pointsToSessionEndpoint = /\/api\/v2\/[^/]+\/sessions\/[^/?#]+$/i.test(rawUrl);
  const requiresResumeParameters =
    actionName.includes("resume") ||
    missingParameters.includes("redirecturl") ||
    missingParameters.includes("domainname");

  if (authUrl && (pointsToSessionEndpoint || requiresResumeParameters)) {
    return authUrl;
  }

  return rawUrl || authUrl;
}

function extractRestV2SessionCodeFromValue(value, serviceProviderId = "") {
  const raw = String(value || "").trim();
  if (!raw) {
    return "";
  }
  const normalizedServiceProviderId = String(serviceProviderId || "").trim().toLowerCase();
  const candidates = [];
  const pushCandidate = (candidate) => {
    const normalized = String(candidate || "").trim();
    if (!normalized) {
      return;
    }
    try {
      candidates.push(decodeURIComponent(normalized));
    } catch {
      candidates.push(normalized);
    }
  };

  try {
    const parsed = new URL(raw, ADOBE_SP_BASE);
    const pathSegments = String(parsed.pathname || "")
      .split("/")
      .map((segment) => String(segment || "").trim())
      .filter(Boolean);

    for (let index = 0; index < pathSegments.length; index += 1) {
      const segment = String(pathSegments[index] || "").toLowerCase();
      if (segment === "sessions" && pathSegments[index + 1]) {
        pushCandidate(pathSegments[index + 1]);
      }
      if (segment === "authenticate") {
        const serviceProviderSegment = String(pathSegments[index + 1] || "").trim().toLowerCase();
        const codeSegment = String(pathSegments[index + 2] || "").trim();
        if (
          serviceProviderSegment &&
          codeSegment &&
          (!normalizedServiceProviderId || serviceProviderSegment === normalizedServiceProviderId)
        ) {
          pushCandidate(codeSegment);
        }
      }
    }

    pushCandidate(parsed.searchParams.get("code"));
    pushCandidate(parsed.searchParams.get("sessionCode"));
    pushCandidate(parsed.searchParams.get("session"));
  } catch {
    // Fall through to regex extraction.
  }

  const sessionMatch = raw.match(/\/sessions\/([^/?#]+)/i);
  if (sessionMatch?.[1]) {
    pushCandidate(sessionMatch[1]);
  }
  if (normalizedServiceProviderId) {
    const authenticateMatch = raw.match(
      new RegExp(`/authenticate/${normalizedServiceProviderId.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}/([^/?#]+)`, "i")
    );
    if (authenticateMatch?.[1]) {
      pushCandidate(authenticateMatch[1]);
    }
  } else {
    const authenticateMatch = raw.match(/\/authenticate\/[^/]+\/([^/?#]+)/i);
    if (authenticateMatch?.[1]) {
      pushCandidate(authenticateMatch[1]);
    }
  }

  return firstNonEmptyString(candidates);
}

function collectRestV2SessionCodeCandidates(values = [], serviceProviderId = "") {
  const collection = Array.isArray(values) ? values : [values];
  const candidates = [];
  collection.forEach((value) => {
    const text = String(value || "").trim();
    if (!text) {
      return;
    }
    if (!text.includes("/") && !text.includes("?") && !text.includes("#")) {
      candidates.push(text);
    }
    const extracted = extractRestV2SessionCodeFromValue(text, serviceProviderId);
    if (extracted) {
      candidates.push(extracted);
    }
  });
  return dedupeRestV2CandidateStrings(candidates);
}

function normalizeRestV2MvpdMatchToken(value = "") {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]/g, "");
}

function buildRestV2MvpdMatchTokens(value = "", options = {}) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized) {
    return [];
  }
  const allowSsoAlias = options?.allowSsoAlias === true;
  const tokenSet = new Set();
  const push = (token) => {
    const text = String(token || "").trim().toLowerCase();
    if (text) {
      tokenSet.add(text);
    }
  };

  push(normalized);
  push(normalized.replace(/[\s_-]+/g, "-"));
  push(normalized.replace(/[\s_-]+/g, "_"));
  const compact = normalizeRestV2MvpdMatchToken(normalized);
  push(compact);

  if (allowSsoAlias && compact) {
    const compactWithoutSso = compact.replace(/sso$/i, "");
    if (compactWithoutSso && compactWithoutSso !== compact) {
      push(compactWithoutSso);
    }
    if (compactWithoutSso) {
      push(`${compactWithoutSso}sso`);
    }
  }

  return [...tokenSet];
}

function isRestV2MvpdMatch(candidate = "", target = "", options = {}) {
  const candidateTokens = buildRestV2MvpdMatchTokens(candidate, options);
  const targetTokens = buildRestV2MvpdMatchTokens(target, options);
  if (candidateTokens.length === 0 || targetTokens.length === 0) {
    return false;
  }
  const targetSet = new Set(targetTokens);
  return candidateTokens.some((token) => targetSet.has(token));
}

function isRestV2LikelyPartnerSsoContext(context = null) {
  if (!context || typeof context !== "object") {
    return false;
  }
  const mvpd = String(context.mvpd || "").trim().toLowerCase();
  const sessionAction = String(context.sessionAction || "").trim().toLowerCase();
  const sessionPartner = String(context.sessionPartner || "").trim().toLowerCase();
  const partnerFrameworkStatus = String(resolveRestV2PartnerFrameworkStatusFromContext(context) || "").trim();
  return (
    mvpd.includes("sso") ||
    sessionAction.includes("sso") ||
    sessionPartner.includes("sso") ||
    Boolean(partnerFrameworkStatus)
  );
}

function buildRestV2SessionCreatePayloadCandidates(mvpd) {
  const mvpdId = String(mvpd || "").trim();
  if (!mvpdId) {
    return [];
  }

  const payloads = [];
  const seen = new Set();
  const pushPayload = (domainName = "", redirectUrl = "") => {
    const normalizedDomain = String(domainName || "").trim();
    const normalizedRedirect = String(redirectUrl || "").trim();
    const key = `${normalizedDomain}|${normalizedRedirect}`;
    if (seen.has(key)) {
      return;
    }
    seen.add(key);

    const body = new URLSearchParams();
    body.set("mvpd", mvpdId);
    if (normalizedDomain) {
      body.set("domainName", normalizedDomain);
    }
    if (normalizedRedirect) {
      body.set("redirectUrl", normalizedRedirect);
    }

    payloads.push({
      domainName: normalizedDomain,
      redirectUrl: normalizedRedirect,
      body: body.toString(),
    });
  };

  REST_V2_REDIRECT_CANDIDATES.forEach((redirectUrl) => pushPayload(REST_V2_DEFAULT_DOMAIN, redirectUrl));
  pushPayload(REST_V2_DEFAULT_DOMAIN, "");
  pushPayload("", "");

  return payloads;
}

async function createRestV2SessionForContext(context, options = {}) {
  if (!context?.programmerId || !context?.appInfo?.guid || !context?.serviceProviderId || !context?.mvpd) {
    throw new Error("Create session failed: missing media company, app, requestor, or MVPD.");
  }
  const debugFlowId = String(options.debugFlowId || "").trim();

  const appCandidates = Array.isArray(context.restV2AppCandidates)
    ? context.restV2AppCandidates.filter((item) => item?.guid)
    : [];
  if (appCandidates.length === 0) {
    appCandidates.push(context.appInfo);
  }
  if (!appCandidates.some((item) => item.guid === context.appInfo.guid)) {
    appCandidates.unshift(context.appInfo);
  }

  const payloadCandidates = buildRestV2SessionCreatePayloadCandidates(context.mvpd);
  if (payloadCandidates.length === 0) {
    throw new Error("Create session failed: no payload candidates available.");
  }

  let lastErrorText = "";
  let lastStatus = 0;
  for (const appCandidate of appCandidates) {
    for (const payloadCandidate of payloadCandidates) {
      log("REST V2 create-session attempt", {
        serviceProvider: context.serviceProviderId,
        appGuid: appCandidate.guid,
        domainName: payloadCandidate.domainName || "<none>",
        redirectUrl: payloadCandidate.redirectUrl || "<none>",
      });
      emitRestV2DebugEvent(debugFlowId, {
        source: "extension",
        phase: "create-session-attempt",
        serviceProviderId: context.serviceProviderId,
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        appGuid: appCandidate.guid,
        appName: appCandidate.appName || appCandidate.guid,
        domainName: payloadCandidate.domainName || "",
        redirectUrl: payloadCandidate.redirectUrl || "",
      });

      const response = await fetchWithPremiumAuth(
        context.programmerId,
        appCandidate,
        `${REST_V2_BASE}/${encodeURIComponent(context.serviceProviderId)}/sessions`,
        {
          method: "POST",
          mode: "cors",
          headers: buildRestV2Headers(context.serviceProviderId, {
            "Content-Type": "application/x-www-form-urlencoded",
            Accept: "application/json",
          }),
          body: payloadCandidate.body,
        },
        "refresh",
        {
          flowId: debugFlowId,
          requestorId: context.requestorId,
          mvpd: context.mvpd,
          scope: "create-session",
          lockAppSelection: true,
          allowProvisioning: true,
        }
      );

      const text = await response.text().catch(() => "");
      const parsed = parseJsonText(text, null);
      const responseHeaders = toDebugHeadersObject(response.headers || new Headers());
      if (response.ok) {
        const sessionData = parsed && typeof parsed === "object" ? parsed : {};
        const partnerFrameworkStatus = resolveRestV2PartnerFrameworkStatusFromSessionData(sessionData, responseHeaders);
        const sessionPartner = resolveRestV2SessionPartnerFromSessionData(sessionData, partnerFrameworkStatus);
        if (partnerFrameworkStatus && !String(sessionData?.partnerFrameworkStatus || "").trim()) {
          sessionData.partnerFrameworkStatus = partnerFrameworkStatus;
        }
        if (sessionPartner && !String(sessionData?.partner || "").trim()) {
          sessionData.partner = sessionPartner;
        }
        const locationHeader = response.headers?.get("Location") || "";
        if (!sessionData.url && locationHeader) {
          sessionData.url = locationHeader;
        }
        const loginUrl = resolveMvpdLoginNavigationUrl(sessionData, context.serviceProviderId);
        if (loginUrl) {
          emitRestV2DebugEvent(debugFlowId, {
            source: "extension",
            phase: "create-session-success",
            serviceProviderId: context.serviceProviderId,
            requestorId: context.requestorId,
            mvpd: context.mvpd,
            appGuid: appCandidate.guid,
            appName: appCandidate.appName || appCandidate.guid,
            status: response.status,
            loginUrl,
            sessionPartner: String(sessionPartner || "").trim(),
            partnerFrameworkStatusPresent: Boolean(partnerFrameworkStatus),
            responsePreview: truncateDebugText(text, 2000),
          });
          return {
            loginUrl,
            sessionData,
            payload: payloadCandidate,
            appInfo: appCandidate,
            sessionResponseHeaders: responseHeaders,
            partnerFrameworkStatus: String(partnerFrameworkStatus || "").trim(),
            sessionPartner: String(sessionPartner || "").trim(),
          };
        }
        lastStatus = response.status;
        lastErrorText = "REST V2 session response did not include a login URL/code.";
        continue;
      }

      lastStatus = response.status;
      const message =
        firstNonEmptyString([
          parsed?.code,
          parsed?.error,
          parsed?.message,
          parsed?.description,
          normalizeHttpErrorMessage(text),
          response.statusText,
        ]) || response.statusText;
      lastErrorText = `Create session payload failed (${response.status}): ${message}`;
      log("REST V2 create-session failed", {
        status: response.status,
        message,
        serviceProvider: context.serviceProviderId,
        appGuid: appCandidate.guid,
      });
      emitRestV2DebugEvent(debugFlowId, {
        source: "extension",
        phase: "create-session-failed-attempt",
        serviceProviderId: context.serviceProviderId,
        requestorId: context.requestorId,
        mvpd: context.mvpd,
        appGuid: appCandidate.guid,
        appName: appCandidate.appName || appCandidate.guid,
        status: response.status,
        error: message,
        responsePreview: truncateDebugText(text, 2000),
      });
    }
  }

  if (lastStatus > 0) {
    throw new Error(lastErrorText || `Create session failed (${lastStatus}).`);
  }
  throw new Error(lastErrorText || "Create session failed.");
}

async function fetchRestV2ConfigurationMvpds(programmer, appInfo, requestorId) {
  const response = await fetchWithPremiumAuth(
    programmer.programmerId,
    appInfo,
    `${REST_V2_BASE}/${encodeURIComponent(requestorId)}/configuration`,
    {
      method: "GET",
      mode: "cors",
      headers: buildRestV2Headers(requestorId, {
        Accept: "application/json",
      }),
    },
    "refresh",
    {
      requestorId,
      service: "rest-v2-configuration",
      scope: "configuration",
      requiredServiceScope: REST_V2_SCOPE,
      appGuid: String(appInfo?.guid || ""),
      appName: String(appInfo?.appName || appInfo?.guid || ""),
      lockAppSelection: true,
      allowProvisioning: true,
    }
  );

  const text = await response.text().catch(() => "");
  let payload = null;
  try {
    payload = text ? JSON.parse(text) : null;
  } catch {
    payload = null;
  }

  if (!response.ok) {
    const message =
      firstNonEmptyString([
        payload?.error?.code,
        payload?.error?.message,
        typeof payload?.error === "string" ? payload.error : "",
        payload?.message,
        normalizeHttpErrorMessage(text),
        response.statusText,
      ]) || response.statusText;
    throw new Error(`REST V2 configuration failed (${response.status}): ${message}`);
  }

  const mvpds = normalizeRestV2MvpdCollection(payload || {});
  const map = new Map();
  for (const item of mvpds) {
    if (!map.has(item.id)) {
      map.set(item.id, item);
    }
  }
  return map;
}

function orderRestV2AppCandidatesForRequestor(restV2Apps, resolvedApp, requestorId) {
  const candidates = Array.isArray(restV2Apps) ? restV2Apps : [];
  const byGuid = new Map(candidates.filter((item) => item?.guid).map((item) => [item.guid, item]));
  const context = getRequestorScopedRestV2AuthContext(String(requestorId || "")) || {};
  const ordered = [];
  const seen = new Set();

  const pushCandidate = (candidate) => {
    if (!candidate?.guid || seen.has(candidate.guid)) {
      return;
    }
    seen.add(candidate.guid);
    ordered.push(candidate);
  };

  if (context.preferredAppGuid) {
    pushCandidate(byGuid.get(context.preferredAppGuid));
  }

  if (Array.isArray(context.candidateGuids)) {
    context.candidateGuids.forEach((guid) => {
      pushCandidate(byGuid.get(guid));
    });
  }

  pushCandidate(resolvedApp);
  candidates.forEach((candidate) => pushCandidate(candidate));
  return ordered;
}

async function fetchRestV2ConfigurationUsingCandidateApps(programmer, requestorId, orderedCandidates) {
  const candidates = Array.isArray(orderedCandidates) ? orderedCandidates.filter((item) => item?.guid) : [];
  if (candidates.length === 0) {
    throw new Error("No REST V2 app candidates available.");
  }

  const concurrency = Math.max(1, Number(REST_V2_CONFIG_ATTEMPT_CONCURRENCY) || 1);
  let lastError = null;

  for (let index = 0; index < candidates.length; index += concurrency) {
    const batch = candidates.slice(index, index + concurrency);
    const attempts = batch.map((appInfo) =>
      fetchRestV2ConfigurationMvpds(programmer, appInfo, requestorId)
        .then((map) => ({ map, appInfo }))
        .catch((error) => {
          const normalized = error instanceof Error ? error : new Error(String(error));
          lastError = normalized;
          log("REST V2 configuration attempt failed", {
            requestorId,
            programmerId: programmer?.programmerId || "",
            app: appInfo?.appName || appInfo?.guid || "unknown",
            error: normalized.message,
          });
          throw normalized;
        })
    );

    try {
      return await Promise.any(attempts);
    } catch {
      // Every attempt in this batch failed; continue to next candidate batch.
    }
  }

  throw lastError || new Error("Unable to load MVPDs via REST V2 configuration.");
}

async function loadMvpdsFromRestV2(requestorId) {
  if (!requestorId) {
    return new Map();
  }

  const cachedMvpdMap = getRequestorScopedMvpdCache(requestorId);
  if (cachedMvpdMap) {
    return cachedMvpdMap;
  }

  const existingLoadPromise = getRequestorScopedMvpdLoadPromise(requestorId);
  if (existingLoadPromise) {
    return existingLoadPromise;
  }

  const loadPromise = (async () => {
    const programmers = getProgrammerCandidatesForRequestor(requestorId);
    if (programmers.length === 0) {
      throw new Error(`Unable to find a media company mapping for requestor ${requestorId}.`);
    }

    let lastError = null;
    let hasRestV2Candidate = false;
    for (const programmer of programmers) {
      try {
        await hydrateProgrammerFromPassVault(programmer, {
          forceReload: false,
          forceOverwrite: false,
          forceDcrRestore: true,
        }).catch(() => null);
        let premiumApps = getCurrentPremiumAppsSnapshot(programmer.programmerId);
        if (!premiumApps) {
          const selectedProgrammer = resolveSelectedProgrammer();
          if (String(selectedProgrammer?.programmerId || "").trim() === String(programmer?.programmerId || "").trim()) {
            throw new Error(
              `Premium services for ${programmer.programmerId} are not hydrated in the UnderPAR vault yet. Re-select the media company first.`
            );
          }
          continue;
        }
        let restV2Apps = collectRestV2AppCandidatesFromPremiumApps(premiumApps);
        const requestorPreferredApp = selectPreferredRestV2AppForRequestor(
          restV2Apps,
          requestorId,
          programmer.programmerId
        );
        const requiresRuntimeHydration =
          !isProgrammerRuntimeServicesReady(programmer.programmerId, premiumApps) ||
          !requestorPreferredApp?.guid ||
          !hasPassVaultServiceClientCredentials(programmer.programmerId, requestorPreferredApp);
        if (requiresRuntimeHydration) {
          premiumApps =
            (await primeProgrammerServiceHydration(programmer, premiumApps, {
              forceRefresh: false,
              controllerReason: "requestor-restv2-load",
            }).catch(() => null)) ||
            getCurrentPremiumAppsSnapshot(programmer.programmerId) ||
            premiumApps;
          restV2Apps = collectRestV2AppCandidatesFromPremiumApps(premiumApps);
        }
        if (restV2Apps.length === 0) {
          continue;
        }

        hasRestV2Candidate = true;
        const resolvedApp = selectPreferredRestV2AppForRequestor(restV2Apps, requestorId, programmer.programmerId);
        const orderedCandidates = orderRestV2AppCandidatesForRequestor(restV2Apps, resolvedApp, requestorId);
        const { map, appInfo } = await fetchRestV2ConfigurationUsingCandidateApps(
          programmer,
          requestorId,
          orderedCandidates
        );

        setRequestorScopedMvpdCache(requestorId, map);
        setRequestorScopedRestV2AuthContext(requestorId, {
          programmerId: programmer.programmerId,
          preferredAppGuid: appInfo.guid,
          candidateGuids: orderedCandidates.map((candidate) => candidate.guid).filter(Boolean),
        });
        log("MVPD menu loaded from REST V2 configuration.", {
          requestorId,
          programmerId: programmer.programmerId,
          app: appInfo.appName,
          count: map.size,
        });
        return map;
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));
      }
    }

    if (!hasRestV2Candidate) {
      throw createProgrammersError(
        `No REST V2 scoped app mapping was found for RequestorId "${requestorId}".`,
        "RESTV2_APP_MAPPING_MISSING"
      );
    }
    throw lastError || new Error("Unable to load MVPDs via REST V2 configuration.");
  })();

  setRequestorScopedMvpdLoadPromise(requestorId, loadPromise);
  try {
    return await loadPromise;
  } finally {
    if (getRequestorScopedMvpdLoadPromise(requestorId) === loadPromise) {
      setRequestorScopedMvpdLoadPromise(requestorId, null);
    }
  }
}

async function populateMvpdSelectForRequestor(requestorId) {
  els.mvpdSelect.innerHTML = "";
  const expectedRequestorId = String(requestorId || "");
  const controllerReason = expectedRequestorId ? "requestor-change" : "requestor-clear";

  if (!requestorId) {
    els.mvpdSelect.disabled = true;
    els.mvpdSelect.innerHTML = '<option value=""></option>';
    state.selectedMvpdId = "";
    syncGlobalQuickLaunchButtons();
    refreshRestV2LoginPanels();
    refreshMvpdWorkspaceTools({ controllerReason });
    const selectedProgrammer = resolveSelectedProgrammer();
    const selectedServices = selectedProgrammer?.programmerId
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
      : null;
    mvpdWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices);
    void mvpdWorkspaceRefreshSelectedSnapshot({
      programmer: selectedProgrammer,
      services: selectedServices,
      forceRefresh: false,
      onlyIfWorkspaceOpen: true,
      surfaceMissingSelectionError: false,
    });
    return;
  }

  els.mvpdSelect.disabled = true;
  els.mvpdSelect.innerHTML = '<option value="">Loading MVPD menu (REST V2)...</option>';

  try {
    const merged = await loadMvpdsFromRestV2(requestorId);

    if (String(state.selectedRequestorId || "") !== expectedRequestorId) {
      return;
    }
    els.mvpdSelect.innerHTML = "";

    if (merged.size === 0) {
      els.mvpdSelect.disabled = true;
      els.mvpdSelect.innerHTML = '<option value="">-- No MVPDs available --</option>';
      state.selectedMvpdId = "";
      syncGlobalQuickLaunchButtons();
      refreshRestV2LoginPanels();
      return;
    }

    const defaultOption = document.createElement("option");
    defaultOption.value = "";
    defaultOption.textContent = "";
    els.mvpdSelect.appendChild(defaultOption);

    const entries = [...merged.entries()].sort((a, b) => {
      const aText = formatMvpdPickerLabel(a[0], a[1]);
      const bText = formatMvpdPickerLabel(b[0], b[1]);
      return String(aText).localeCompare(String(bText), undefined, { sensitivity: "base" });
    });

    for (const [mvpdId, meta] of entries) {
      const option = document.createElement("option");
      option.value = mvpdId;
      option.textContent = formatMvpdPickerLabel(mvpdId, meta);
      option.style.fontWeight = meta.isProxy === false ? "700" : "400";
      els.mvpdSelect.appendChild(option);
    }

    els.mvpdSelect.disabled = false;
    state.selectedMvpdId = "";
    els.mvpdSelect.value = "";
    syncGlobalQuickLaunchButtons();
    refreshRestV2LoginPanels();
    refreshMvpdWorkspaceTools();
    const selectedProgrammer = resolveSelectedProgrammer();
    const selectedServices = selectedProgrammer?.programmerId
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
      : null;
    mvpdWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices);
    void mvpdWorkspaceRefreshSelectedSnapshot({
      programmer: selectedProgrammer,
      services: selectedServices,
      forceRefresh: false,
      onlyIfWorkspaceOpen: true,
      surfaceMissingSelectionError: false,
    });
    setStatus("", "info");
  } catch (error) {
    if (String(state.selectedRequestorId || "") !== expectedRequestorId) {
      return;
    }
    els.mvpdSelect.disabled = true;
    els.mvpdSelect.innerHTML = '<option value="">-- MVPD config unavailable --</option>';
    state.selectedMvpdId = "";
    syncGlobalQuickLaunchButtons();
    refreshRestV2LoginPanels();
    refreshMvpdWorkspaceTools();
    const selectedProgrammer = resolveSelectedProgrammer();
    const selectedServices = selectedProgrammer?.programmerId
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
      : null;
    mvpdWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices);
    void mvpdWorkspaceRefreshSelectedSnapshot({
      programmer: selectedProgrammer,
      services: selectedServices,
      forceRefresh: false,
      onlyIfWorkspaceOpen: true,
      surfaceMissingSelectionError: false,
    });
    if (isRestV2ScopedAppMappingMissingError(error)) {
      setStatus("", "info");
    } else {
      const reason = error instanceof Error ? error.message : String(error);
      setStatus(`REST V2 configuration failed for MVPD list: ${reason}`, "error");
    }
  }
}

function createProgrammersError(message, code) {
  const error = new Error(message);
  error.code = code;
  return error;
}

function isExperienceCloudAuthResponseUrl(url) {
  const value = String(url || "").trim();
  if (!value) {
    return false;
  }
  try {
    const parsed = new URL(value);
    const host = String(parsed.hostname || "").toLowerCase();
    if (
      host === "auth.services.adobe.com" ||
      host.endsWith(".auth.services.adobe.com") ||
      host === "idg.adobe.com" ||
      host.endsWith(".idg.adobe.com")
    ) {
      return true;
    }
    if (host === "ims-na1.adobelogin.com" || host.endsWith(".adobelogin.com")) {
      return parsed.pathname.startsWith("/ims/authorize") || parsed.pathname.startsWith("/ims/adobeid/");
    }
  } catch {
    return false;
  }
  return false;
}

function responseLooksLikeExperienceCloudSignIn(response, responseBody = "") {
  const status = Number(response?.status || 0);
  const responseUrl = String(response?.url || "").trim();
  if (response?.redirected && isExperienceCloudAuthResponseUrl(responseUrl)) {
    return true;
  }
  if (isExperienceCloudAuthResponseUrl(responseUrl)) {
    return true;
  }

  const contentType = String(getRestV2CaseInsensitiveHeaderValue(response?.headers, ["content-type"]) || "").toLowerCase();
  const body = String(responseBody || "").toLowerCase();
  if (status === 401 || status === 403) {
    const authHeader = String(getRestV2CaseInsensitiveHeaderValue(response?.headers, ["www-authenticate"]) || "").toLowerCase();
    if (
      body.includes("invalid_sso_info") ||
      body.includes("session cookie is null") ||
      body.includes("session cookie") ||
      body.includes("id=\"adobeid_signin\"") ||
      body.includes("flow_type=token") ||
      authHeader.includes("adobeid") ||
      authHeader.includes("login") ||
      authHeader.includes("invalid_sso_info")
    ) {
      return true;
    }
  }

  if (!contentType.includes("text/html")) {
    return false;
  }

  return (
    body.includes("auth.services.adobe.com") ||
    body.includes("/signin/v2/tokens") ||
    body.includes("flow_type=token") ||
    body.includes("id=\"adobeid_signin\"") ||
    body.includes("credential=sso")
  );
}

async function fetchProgrammersFromApi(options = {}) {
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([
      options.accessToken,
      state.loginData?.accessToken,
      getPreferredPrimaryImsAccessTokenCandidate(),
      getPreferredAdobeConsoleAccessTokenCandidate(),
    ])
  );
  const requireEntities = options.requireEntities !== false;
  const pageContextTargetRef =
    options.pageContextTargetRef && typeof options.pageContextTargetRef === "object"
      ? options.pageContextTargetRef
      : null;
  if (!accessToken || !isProbablyJwt(accessToken)) {
    throw createProgrammersError("Media company load requires a valid UnderPAR Adobe bearer.", "PROGRAMMERS_ACCESS_DENIED");
  }

  const configurationVersion = Number(options.configurationVersion || getKnownAdobeConsoleConfigurationVersion() || 0);
  const endpoints = state.programmersApiEndpoint
    ? uniquePreserveOrder([
        appendAdobeConsoleConfigurationVersion(state.programmersApiEndpoint, configurationVersion),
        ...PROGRAMMER_ENDPOINTS.map((endpoint) => appendAdobeConsoleConfigurationVersion(endpoint, configurationVersion)),
      ])
    : [...PROGRAMMER_ENDPOINTS.map((endpoint) => appendAdobeConsoleConfigurationVersion(endpoint, configurationVersion))];

  let lastError = null;
  for (const endpoint of endpoints) {
    try {
      const payload = await fetchAdobeConsoleJsonWithLoginButtonFallback([endpoint], "Media company load", {
        timeoutMs: PROGRAMMERS_FETCH_TIMEOUT_MS,
        accessToken,
        preferAuthenticatedHeaders: true,
        preferredTabId: Number(options.preferredTabId || 0),
        pageContextTargetRef,
      });
      const normalizedEntities = normalizeProgrammersResponse(payload?.parsed || payload);
      if (requireEntities && normalizedEntities.length === 0) {
        lastError = createProgrammersError(`Endpoint ${endpoint} returned no media companies.`, "PROGRAMMERS_EMPTY");
        continue;
      }
      state.programmersApiEndpoint = endpoint;
      return normalizedEntities;
    } catch (error) {
      const resolvedError = error instanceof Error ? error : new Error(String(error));
      lastError = resolvedError;
    }
  }

  throw lastError || createProgrammersError("Unable to load media companies from API.", "PROGRAMMERS_LOAD_FAILED");
}

async function fetchConsoleChannelsFromApi(options = {}) {
  const accessToken = normalizeBearerTokenValue(
    firstNonEmptyString([
      options.accessToken,
      state.loginData?.accessToken,
      getPreferredPrimaryImsAccessTokenCandidate(),
      getPreferredAdobeConsoleAccessTokenCandidate(),
    ])
  );
  const pageContextTargetRef =
    options.pageContextTargetRef && typeof options.pageContextTargetRef === "object"
      ? options.pageContextTargetRef
      : null;
  if (!accessToken || !isProbablyJwt(accessToken)) {
    throw new Error("Content provider load requires a valid UnderPAR Adobe bearer.");
  }

  const configurationVersion = Number(options.configurationVersion || getKnownAdobeConsoleConfigurationVersion() || 0);
  const endpoints = buildChannelEndpointsForConsoleBase(ADOBE_CONSOLE_BASE).map((endpoint) =>
    appendAdobeConsoleConfigurationVersion(endpoint, configurationVersion)
  );
  const payload = await fetchAdobeConsoleJsonWithLoginButtonFallback(endpoints, "Content provider load", {
    timeoutMs: PROGRAMMERS_FETCH_TIMEOUT_MS,
    accessToken,
    preferAuthenticatedHeaders: true,
    preferredTabId: Number(options.preferredTabId || 0),
    pageContextTargetRef,
  });
  return normalizeConsoleChannelsResponse(payload?.parsed || payload);
}

function resetProgrammerRuntimeState() {
  state.selectedMediaCompany = "";
  state.selectedRequestorId = "";
  state.selectedMvpdId = "";
  state.selectedProgrammerKey = "";
  state.mvpdCacheByRequestor.clear();
  state.mvpdLoadPromiseByRequestor.clear();
  state.restV2AuthContextByRequestor.clear();
  state.applicationsByProgrammerId.clear();
  state.programmerApplicationsLoadPromiseByProgrammerId.clear();
  state.premiumAppsByProgrammerId.clear();
  state.programmerWorkspaceHydrationReadyByKey.clear();
  state.premiumHydrationProgressByProgrammerKey.clear();
  state.restV2ProfileHarvestBySelectionKey.clear();
  state.restV2ProfileHarvestByProgrammerId.clear();
  state.restV2ProfileHarvestBucketByProgrammerId.clear();
  state.restV2ProfileHarvestLast = null;
  state.cmServiceByProgrammerId.clear();
  state.cmServiceLoadPromiseByProgrammerId.clear();
  state.cmHydrationPromiseByProgrammerId.clear();
  state.cmServiceByMvpdSelectionKey.clear();
  state.cmServiceLoadPromiseByMvpdSelectionKey.clear();
  // Keep tenant catalog hydrated for the active signed-in session.
  // CM matching should use this persisted catalog on each selection.
  state.cmTenantsCatalogRuntimeFresh = false;
  state.cmTenantsCatalogFetchAttempted = false;
  state.cmTenantDebugExportedByUrl.clear();
  state.cmTenantBundleByTenantKey.clear();
  state.cmTenantBundlePromiseByTenantKey.clear();
  state.premiumSectionCollapsedByKey.clear();
  state.premiumAutoRefreshMetaByKey.clear();
  state.premiumServiceReminderLogKeys.clear();
  state.premiumServiceDecisionSignatureByProgrammerKey.clear();
  state.premiumPanelRequestToken = 0;
  state.restV2PrewarmedAppsByProgrammerId.clear();
  clearRestV2PreparedLoginState();
  clearCmWorkspaceActivityDebugFlow("programmer-entities-reset", { stopFlow: true });
}

function applyStoredProgrammerSnapshot(entries) {
  const normalizedEntries = (Array.isArray(entries) ? entries : [])
    .map((entry, index) => {
      if (!entry || typeof entry !== "object") {
        return null;
      }

      const programmerId = firstNonEmptyString([entry.programmerId]) || `programmer-${index + 1}`;
      const programmerName = firstNonEmptyString([entry.programmerName, entry.mediaCompanyName, programmerId]) || programmerId;
      const mediaCompanyName = firstNonEmptyString([entry.mediaCompanyName, entry.programmerName, programmerId]) || programmerId;
      const requestorOptions = (Array.isArray(entry.requestorOptions) ? entry.requestorOptions : [])
        .map((option) => {
          if (!option || typeof option !== "object") {
            return null;
          }
          const id = firstNonEmptyString([option.id, option.key]);
          const key = firstNonEmptyString([option.key, option.id, id]);
          if (!id || !key) {
            return null;
          }
          return {
            key,
            id,
            name: firstNonEmptyString([option.name, option.label, id]) || id,
            label: firstNonEmptyString([option.label, option.name, id]) || id,
            programmerId,
            raw: {
              id,
            },
          };
        })
        .filter(Boolean);
      const requestorIds = uniqueSorted(
        [
          ...(Array.isArray(entry.requestorIds) ? entry.requestorIds : []),
          ...requestorOptions.map((option) => option.id),
        ]
          .map((value) => String(value || "").trim())
          .filter(Boolean)
      );

      return {
        key: firstNonEmptyString([entry.key, `${programmerId}-${index}`]) || `${programmerId}-${index}`,
        programmerId,
        programmerName,
        mediaCompanyName,
        label:
          firstNonEmptyString([entry.label]) ||
          (normalizeOrganizationIdentifier(programmerName) !== normalizeOrganizationIdentifier(programmerId)
            ? `${programmerName} | ${programmerId}`
            : programmerName),
        requestorIds,
        requestorOptions,
        applications: [],
        raw: {
          id: programmerId,
          programmerId,
          displayName: programmerName,
          mediaCompanyName,
          requestorOptions,
          contentProviders: requestorIds,
        },
        source: entry,
      };
    })
    .filter(Boolean);

  resetProgrammerRuntimeState();
  state.programmers = normalizedEntries;
  populateMediaCompanySelect();
}

function applyProgrammerEntities(entities) {
  resetProgrammerRuntimeState();
  state.programmers = entities.map((entity, index) => mapProgrammerEntity(entity, index));
  populateMediaCompanySelect();
  // Post-login stays GLOBALS-only. Per-company VAULT/runtime restore remains lazy
  // until explicit Media Company selection or environment restore.
}

function restoreStoredAuthenticatedConsoleHydration(loginData = null) {
  if (!shouldHydrateAdobePassWorkflowForSession(loginData)) {
    return false;
  }
  const snapshot = normalizeStoredConsoleHydrationSnapshot(loginData?.consoleHydration);
  if (!snapshot) {
    return false;
  }

  const configurationVersion = Number(snapshot.configurationVersion || 0);
  const channels = Array.isArray(snapshot.channels) ? snapshot.channels.slice() : [];
  const programmers = Array.isArray(snapshot.programmers) ? snapshot.programmers.slice() : [];
  const grantedAuthorities = Array.isArray(snapshot.grantedAuthorities) ? snapshot.grantedAuthorities.slice() : [];
  if (!(configurationVersion > 0) && channels.length === 0 && programmers.length === 0 && grantedAuthorities.length === 0) {
    return false;
  }

  state.consoleBootstrapState = {
    accessToken: normalizeBearerTokenValue(firstNonEmptyString([loginData?.accessToken])),
    fetchedAt: Number(snapshot.hydratedAt || Date.now()),
    extendedProfile: null,
    grantedAuthorities,
    configurationVersion,
    channels,
    errors: {
      extendedProfile: "",
      configurationVersion: "",
    },
  };
  state.programmersApiEndpoint = firstNonEmptyString([snapshot.programmersApiEndpoint, state.programmersApiEndpoint]);
  if (programmers.length > 0) {
    applyStoredProgrammerSnapshot(programmers);
  }
  syncMediaCompanySelectAvailability();
  syncGlobalQuickLaunchButtons();
  return programmers.length > 0 || configurationVersion > 0 || channels.length > 0;
}

async function persistAuthenticatedConsoleHydrationSnapshot() {
  if (!state.sessionReady || state.restricted || !state.loginData?.accessToken) {
    return false;
  }
  if (!shouldHydrateAdobePassWorkflowForSession(state.loginData)) {
    return false;
  }

  const consoleHydration = buildStoredConsoleHydrationSnapshotFromState();
  if (!consoleHydration) {
    return false;
  }

  const nextLoginData = buildNormalizedLoginData(
    {
      ...state.loginData,
      consoleHydration,
    }
  );
  state.loginData = nextLoginData;
  return saveLoginData(nextLoginData);
}

function createCmBootstrapSeedLoginData() {
  return {
    accessToken: "",
    expiresAt: 0,
    tokenType: "bearer",
    scope: "",
    idToken: "",
    refreshToken: "",
    imsSession: null,
    sessionKeys: null,
    cmConsoleAccessToken: "",
    cmConsoleExpiresAt: 0,
    cmConsoleScope: "",
    cmConsoleImsSession: null,
    profile: null,
    imageUrl: "",
    adobePassOrg: null,
  };
}

function renderBuildInfo() {
  const manifestVersion = String(chrome?.runtime?.getManifest?.()?.version || "").trim();
  if (!els.buildInfo) {
    renderPageEnvironmentBadge();
    return;
  }
  els.buildInfo.textContent = manifestVersion ? `Version ${manifestVersion}` : "Version --";
  renderPageEnvironmentBadge();
}

function renderPageEnvironmentBadge() {
  if (!els.pageEnvBadge || !els.pageEnvBadgeValue) {
    return;
  }
  const environment = getActiveAdobePassEnvironment();
  const registry = getUnderParEnvironmentRegistry();
  const label = String(environment?.label || "").trim() || "Production";
  const title =
    String(
      registry?.buildEnvironmentBadgeTooltip?.(environment, "underpar") ||
        environment?.envBadgeTitle ||
        `Environment : ${label}`
    ).trim() || label;
  els.pageEnvBadgeValue.textContent = "";
  els.pageEnvBadgeValue.setAttribute("aria-hidden", "true");
  els.pageEnvBadge.title = title;
  els.pageEnvBadge.setAttribute("aria-label", title);
}

function renderRestrictedView() {
  if (!els.restrictedOrgSelect) {
    return;
  }

  const options = Array.isArray(state.restrictedOrgOptions) ? state.restrictedOrgOptions : [];
  if (options.length === 0) {
    state.selectedRestrictedOrgKey = "";
  } else if (!options.some((option) => option.key === state.selectedRestrictedOrgKey)) {
    state.selectedRestrictedOrgKey = options[0].key;
  }

  els.restrictedOrgSelect.innerHTML = "";
  if (options.length === 0) {
    const emptyOption = document.createElement("option");
    emptyOption.value = "";
    emptyOption.textContent = "-- No organizations available --";
    els.restrictedOrgSelect.appendChild(emptyOption);
  } else {
    for (const option of options) {
      const optionNode = document.createElement("option");
      optionNode.value = option.key;
      optionNode.textContent = option.label;
      els.restrictedOrgSelect.appendChild(optionNode);
    }
  }

  els.restrictedOrgSelect.value = state.selectedRestrictedOrgKey || "";

  const actionsDisabled = state.busy || state.restrictedOrgSwitchBusy;
  els.restrictedOrgSelect.disabled = actionsDisabled || options.length === 0;
}

function renderSignInView() {
  if (!els.signInHeroBtn) {
    return;
  }

  const signingIn = state.busy && isInteractiveAuthBusyContext(state.busyContext);
  els.signInHeroBtn.disabled = signingIn;
  els.signInHeroBtn.textContent = signingIn ? "Signing In..." : "Sign In";
}

function render() {
  void syncSidepanelControllerBridge();
  syncZipKeyImportView();
  renderDebugConsole();
  const authenticatedOrgSwitchOnly = isAuthenticatedOrgSwitchOnlySession();
  const adobePassWorkflowActive =
    state.sessionReady === true && Boolean(state.loginData) && shouldHydrateAdobePassWorkflowForSession(state.loginData);

  if (state.restricted) {
    clearResolvedAvatar();
    closeAvatarMenu();
    els.authBtn.hidden = false;
    if (els.signInView) {
      els.signInView.hidden = true;
    }
    els.restrictedView.hidden = false;
    els.workflow.hidden = true;
    els.authBtn.classList.add("avatar", "avatar-ready");
    els.authBtn.classList.remove("avatar-loading");
    els.authBtn.style.backgroundImage = "";
    els.authBtn.textContent = "";
    els.authBtn.disabled = true;
    els.authBtn.setAttribute("aria-label", "UnderPAR activity");
    if (!state.busy) {
      els.authBtn.title = "UnderPAR activity";
    }
    renderRestrictedView();
    return;
  }

  const showZipKeyImportGate = shouldShowZipKeyImportGate();
  els.authBtn.hidden = showZipKeyImportGate;
  if (showZipKeyImportGate) {
    clearResolvedAvatar();
    closeAvatarMenu();
    if (els.signInView) {
      els.signInView.hidden = true;
    }
    els.restrictedView.hidden = true;
    els.workflow.hidden = true;
    return;
  }

  if (els.signInView) {
    els.signInView.hidden = Boolean(state.sessionReady && state.loginData);
  }
  els.restrictedView.hidden = !authenticatedOrgSwitchOnly;
  els.workflow.hidden = authenticatedOrgSwitchOnly || !adobePassWorkflowActive;

  if (!state.sessionReady || !state.loginData) {
    const authActionLabel = "UnderPAR activity";
    clearResolvedAvatar();
    closeAvatarMenu();
    els.authBtn.classList.add("avatar", "avatar-ready");
    els.authBtn.classList.remove("avatar-loading");
    els.authBtn.style.backgroundImage = "";
    els.authBtn.disabled = true;
    els.authBtn.setAttribute("aria-label", authActionLabel);
    els.authBtn.textContent = "";
    if (!state.busy) {
      els.authBtn.title = authActionLabel;
    }
    renderSignInView();
    return;
  }

  els.authBtn.classList.add("avatar");
  els.authBtn.classList.remove("avatar-loading");
  els.authBtn.classList.add("avatar-ready");
  els.authBtn.style.backgroundImage = "";
  els.authBtn.textContent = "";
  els.authBtn.disabled = Boolean(state.busy);
  els.authBtn.setAttribute("aria-label", `${getLoginDisplayName(state.loginData)} account menu`);
  if (!state.busy) {
    els.authBtn.title = "Account menu";
  }
  if (authenticatedOrgSwitchOnly) {
    renderRestrictedView();
  }
  syncGlobalQuickLaunchButtons();
  renderAvatarMenu();
  void consumePendingUnderparEsmDeeplink();
}

async function signInInteractive(options = {}) {
  const loginOptions = options && typeof options === "object" ? options : {};
  const configuredTargetOrganizations = getConfiguredTargetOrganizations();
  const requestedTargetOrganization =
    loginOptions?.targetOrganization && typeof loginOptions.targetOrganization === "object"
      ? loginOptions.targetOrganization
      : null;
  const targetOrganization =
    findConfiguredTargetOrganization(configuredTargetOrganizations, requestedTargetOrganization) ||
    requestedTargetOrganization ||
    null;
  cancelPendingBootstrapSession();
  state.sessionMonitorSuppressed = false;
  setBusy(true, "Signing in...");
  setStatus("", "info");
  setUnderparDiagnosticMarker("auth", {
    status: "pending",
    mode: "interactive",
    phase: "launch-web-auth-flow",
  });

  const signInStartedAt = Date.now();
  try {
    if (loginOptions?.forceBrowserLogout === true) {
      setStatus("Resetting Adobe sign-in session before re-authenticating...", "info");
      await runUnderparImsBrowserLogout({
        accessToken: firstNonEmptyString([loginOptions?.accessToken, state.loginData?.accessToken]),
        interactive: true,
      });
    }

    const authData = await startLogin({
      interactive: true,
      allowFallback: true,
      accessToken: firstNonEmptyString([loginOptions?.accessToken]),
      prompt: normalizeUnderparImsPrompt(loginOptions?.prompt || "login", true),
    });
    setUnderparDiagnosticMarker("auth", {
      status: "token-acquired",
      mode: "interactive",
      phase: "token-acquired",
    });
    const authCompletedAt = Date.now();
    resetAvatarStateForInteractiveLogin();
    const profile = await resolveProfileAfterLogin(authData);
    setUnderparDiagnosticMarker("auth", {
      status: "profile-resolved",
      mode: "interactive",
      phase: "profile-resolved",
    });
    const profileResolvedAt = Date.now();
    const imageUrl = resolveAuthAvatarSeed(authData, profile);
    const finalizedLoginDataResult = finalizeRequestedTargetLoginData(
      buildLoginSessionPayloadFromAuth(authData, profile, imageUrl),
      targetOrganization,
      {
        acceptReturnedOrganization: loginOptions?.forceBrowserLogout === true,
      }
    );
    if (!finalizedLoginDataResult.ok || !finalizedLoginDataResult.loginData) {
      setUnderparDiagnosticMarker("auth", {
        status: "error",
        mode: "interactive",
        phase: "org-verification-mismatch",
        error: finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.",
      });
      setStatus(
        finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.",
        "error"
      );
      return;
    }
    if (finalizedLoginDataResult.message) {
      log(finalizedLoginDataResult.message);
    }
    const activated = await activateSession(
      finalizedLoginDataResult.loginData,
      "interactive",
      {
        allowTemporaryPageContextTab: true,
      }
    );

    if (activated) {
      setUnderparDiagnosticMarker("auth", {
        status: "success",
        mode: "interactive",
        phase: "activation-complete",
      });
      log("Interactive sign-in critical path complete", {
        authMs: Math.max(0, authCompletedAt - signInStartedAt),
        profileMs: Math.max(0, profileResolvedAt - authCompletedAt),
        activationMs: Math.max(0, Date.now() - profileResolvedAt),
        totalMs: Math.max(0, Date.now() - signInStartedAt),
        cmHydrationMode: "activation-critical-path",
      });
    }

    if (!activated) {
      setUnderparDiagnosticMarker("auth", {
        status: "incomplete",
        mode: "interactive",
        phase: "activation-incomplete",
      });
      clearStatusUnlessCmTenantsPrecheckBlocked();
      return;
    }

    clearStatusUnlessCmTenantsPrecheckBlocked();
  } catch (error) {
    setUnderparDiagnosticMarker("auth", {
      status: "error",
      mode: "interactive",
      phase: "failed",
      error: error instanceof Error ? error.message : String(error),
    });
    setStatus(error instanceof Error ? error.message : String(error), "error");
  } finally {
    setBusy(false);
    render();
  }
}

async function refreshSessionManual() {
  state.sessionMonitorSuppressed = false;
  setBusy(true, "Refreshing session...");
  setStatus("", "info");
  setUnderparDiagnosticMarker("auth", {
    status: "pending",
    mode: "manual-refresh",
    phase: "launch-web-auth-flow",
  });

  const refreshStartedAt = Date.now();
  try {
    let authData;
    let usedInteractiveLogin = false;
    try {
      authData = await startLogin({ interactive: false, allowFallback: false });
    } catch {
      authData = await startLogin({
        interactive: true,
        allowFallback: true,
        prompt: "login",
      });
      usedInteractiveLogin = true;
    }
    setUnderparDiagnosticMarker("auth", {
      status: "token-acquired",
      mode: "manual-refresh",
      phase: "token-acquired",
      interactiveFallback: usedInteractiveLogin,
    });

    const authCompletedAt = Date.now();

    if (usedInteractiveLogin) {
      resetAvatarStateForInteractiveLogin();
    }

    const profile = await resolveProfileAfterLogin(authData);
    setUnderparDiagnosticMarker("auth", {
      status: "profile-resolved",
      mode: "manual-refresh",
      phase: "profile-resolved",
      interactiveFallback: usedInteractiveLogin,
    });
    const profileResolvedAt = Date.now();
    const imageUrl = resolveAuthAvatarSeed(authData, profile);
    const requestedTargetOrganization =
      state.loginData?.targetOrganization && typeof state.loginData.targetOrganization === "object"
        ? state.loginData.targetOrganization
        : null;
    const finalizedLoginDataResult = finalizeRequestedTargetLoginData(
      buildLoginSessionPayloadFromAuth(authData, profile, imageUrl),
      requestedTargetOrganization,
      {
        acceptReturnedOrganization: false,
      }
    );
    if (!finalizedLoginDataResult.ok || !finalizedLoginDataResult.loginData) {
      setUnderparDiagnosticMarker("auth", {
        status: "error",
        mode: "manual-refresh",
        phase: "org-verification-mismatch",
        interactiveFallback: usedInteractiveLogin,
        error: finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.",
      });
      setStatus(
        finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.",
        "error"
      );
      return;
    }
    if (finalizedLoginDataResult.message) {
      log(finalizedLoginDataResult.message);
    }
    const activated = await activateSession(
      finalizedLoginDataResult.loginData,
      usedInteractiveLogin ? "manual-refresh-interactive" : "manual-refresh",
      {
        allowTemporaryPageContextTab: usedInteractiveLogin,
      }
    );

    if (activated) {
      setUnderparDiagnosticMarker("auth", {
        status: "success",
        mode: "manual-refresh",
        phase: "activation-complete",
        interactiveFallback: usedInteractiveLogin,
      });
      log("Manual refresh critical path complete", {
        interactive: usedInteractiveLogin,
        authMs: Math.max(0, authCompletedAt - refreshStartedAt),
        profileMs: Math.max(0, profileResolvedAt - authCompletedAt),
        activationMs: Math.max(0, Date.now() - profileResolvedAt),
        totalMs: Math.max(0, Date.now() - refreshStartedAt),
        cmHydrationMode: "activation-critical-path",
      });
    }

    if (!activated) {
      setUnderparDiagnosticMarker("auth", {
        status: "incomplete",
        mode: "manual-refresh",
        phase: "activation-incomplete",
        interactiveFallback: usedInteractiveLogin,
      });
      clearStatusUnlessCmTenantsPrecheckBlocked();
      return;
    }

    clearStatusUnlessCmTenantsPrecheckBlocked();
  } catch (error) {
    setUnderparDiagnosticMarker("auth", {
      status: "error",
      mode: "manual-refresh",
      phase: "failed",
      error: error instanceof Error ? error.message : String(error),
    });
    setStatus(error instanceof Error ? error.message : String(error), "error");
  } finally {
    setBusy(false);
    render();
  }
}

async function onRestrictedOrgSwitch() {
  if (state.busy || state.restrictedOrgSwitchBusy || !(state.restricted || isAuthenticatedOrgSwitchOnlySession())) {
    return;
  }

  const selected = getSelectedRestrictedOrgOption();
  if (!selected) {
    state.restrictedRecoveryLabel = "Pick an org profile before switching.";
    setStatus("Choose an Adobe org profile before switching.", "error");
    render();
    return;
  }

  const configuredTarget = findConfiguredTargetOrganization(getConfiguredTargetOrganizations(), selected);
  if (configuredTarget?.key) {
    state.selectedTargetOrganizationKey = configuredTarget.key;
  }

  state.restrictedOrgSwitchBusy = true;
  state.restrictedOrgLabel = `Selected org: ${selected.label}`;
  state.restrictedRecoveryLabel = "Manual org switch in progress...";
  setStatus(`Switching org profile: ${selected.name || selected.orgId || "selected profile"}...`, "info");
  setUnderparDiagnosticMarker("auth", {
    status: "pending",
    mode: "restricted-org-switch",
    phase: "launch-web-auth-flow",
    selectedOrg: selected.label,
  });
  render();

  let activationSucceeded = false;
  try {
    cancelPendingBootstrapSession();
    state.sessionMonitorSuppressed = false;
    setStatus("Resetting Adobe sign-in session before re-authenticating...", "info");
    await runUnderparImsBrowserLogout({
      accessToken: firstNonEmptyString([state.loginData?.accessToken]),
      interactive: true,
    });
    setStatus(`Switching org profile: ${selected.name || selected.orgId || "selected profile"}...`, "info");
    const authData = await startLogin({
      interactive: true,
      allowFallback: true,
      prompt: "login",
    });
    resetAvatarStateForInteractiveLogin();
    const profile = await resolveProfileAfterLogin(authData);
    const imageUrl = resolveAuthAvatarSeed(authData, profile);
    const finalizedLoginDataResult = finalizeRequestedTargetLoginData(
      buildLoginSessionPayloadFromAuth(authData, profile, imageUrl),
      configuredTarget || selected,
      {
        acceptReturnedOrganization: true,
      }
    );
    if (!finalizedLoginDataResult.ok || !finalizedLoginDataResult.loginData) {
      state.restrictedRecoveryLabel =
        finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.";
      setUnderparDiagnosticMarker("auth", {
        status: "error",
        mode: "restricted-org-switch",
        phase: "org-verification-mismatch",
        selectedOrg: selected.label,
        error: finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.",
      });
      setStatus(
        finalizedLoginDataResult?.message || "Adobe returned a different org than UnderPAR requested.",
        "error"
      );
      return;
    }
    if (finalizedLoginDataResult.message) {
      log(finalizedLoginDataResult.message);
    }
    const activated = await activateSession(
      finalizedLoginDataResult.loginData,
      "restricted-org-switch",
      {
        allowDeniedRecovery: false,
        allowTemporaryPageContextTab: true,
      }
    );
    if (activated) {
      activationSucceeded = true;
      setUnderparDiagnosticMarker("auth", {
        status: "success",
        mode: "restricted-org-switch",
        phase: "activation-complete",
        selectedOrg: selected.label,
      });
      clearStatusUnlessCmTenantsPrecheckBlocked();
      return;
    }

    setUnderparDiagnosticMarker("auth", {
      status: "incomplete",
      mode: "restricted-org-switch",
      phase: "activation-incomplete",
      selectedOrg: selected.label,
    });
  } catch (error) {
    state.restrictedRecoveryLabel = "Manual org switch failed. Try Sign In Again or Sign Out and retry.";
    setUnderparDiagnosticMarker("auth", {
      status: "error",
      mode: "restricted-org-switch",
      phase: "failed",
      selectedOrg: selected.label,
      error: error instanceof Error ? error.message : String(error),
    });
    setStatus(error instanceof Error ? error.message : String(error), "error");
  } finally {
    state.restrictedOrgSwitchBusy = false;
    render();
  }
}

async function onRestrictedSignInAgain() {
  if (state.busy || state.restrictedOrgSwitchBusy) {
    return;
  }
  state.selectedTargetOrganizationKey = "";
  state.restrictedRecoveryLabel = "Resetting Adobe sign-in and reopening the profile chooser.";
  await signInInteractive({
    prompt: "login",
    forceBrowserLogout: true,
  });
}

async function onRestrictedSignOut() {
  if (state.busy || state.restrictedOrgSwitchBusy) {
    return;
  }
  await signOutAndResetSession();
}

async function onPrimarySignInClick() {
  if (state.zipKeyImportPending || state.busy || state.restricted) {
    return;
  }

  if (shouldShowZipKeyImportGate()) {
    promptForZipKeyImport();
    return;
  }

  state.selectedTargetOrganizationKey = "";
  await signInInteractive({
    prompt: "login",
    forceBrowserLogout: true,
  });
}

async function onAuthClick() {
  if (state.zipKeyImportPending || state.busy) {
    return;
  }

  if (!state.sessionReady || !state.loginData || state.restricted) {
    return;
  }

  toggleAvatarMenu();
}

function onZipKeyContinue() {
  if (!hasConfiguredUnderparImsClientId()) {
    promptForZipKeyImport();
    return;
  }
  closeZipKeyImportGate();
}

function shouldAttemptSilentBootstrapSession() {
  return (
    !state.sessionReady &&
    !state.restricted &&
    !state.busy &&
    !state.restrictedOrgSwitchBusy &&
    !state.zipKeyImportPending &&
    !state.manualSignOutHold &&
    hasConfiguredUnderparImsClientId()
  );
}

function isBootstrapSessionCurrent(generation) {
  return Number(state.sessionBootstrapGeneration || 0) === Number(generation || 0);
}

function cancelPendingBootstrapSession() {
  state.sessionBootstrapGeneration = Number(state.sessionBootstrapGeneration || 0) + 1;
  state.isBootstrapping = false;
}

async function bootstrapSession(reason = "startup") {
  if (state.isBootstrapping) {
    return;
  }

  const bootstrapGeneration = Number(state.sessionBootstrapGeneration || 0) + 1;
  const normalizedReason = String(reason || "startup").trim() || "startup";
  state.sessionBootstrapGeneration = bootstrapGeneration;
  state.sessionMonitorSuppressed = false;
  state.isBootstrapping = true;
  setBusy(true, "Checking session...");
  setStatus("", "info");
  setUnderparDiagnosticMarker("bootstrap", {
    status: "pending",
    reason: normalizedReason,
    phase: "start",
  });

  try {
    if (!isBootstrapSessionCurrent(bootstrapGeneration)) {
      return;
    }

    if (state.restricted) {
      setUnderparDiagnosticMarker("bootstrap", {
        status: "restricted",
        reason: normalizedReason,
        phase: "complete",
      });
      setStatus("", "info");
      return;
    }

    resetWorkflowForLoggedOut();
    state.loginData = null;
    state.restricted = false;
    state.sessionReady = false;
    clearRefreshTimer();
    stopExperienceCloudSessionMonitor();
    setUnderparDiagnosticMarker("bootstrap", {
      status: "no-session",
      reason: normalizedReason,
      phase: "explicit-sign-in-required",
    });
    setStatus("", "info");
  } finally {
    if (isBootstrapSessionCurrent(bootstrapGeneration)) {
      state.isBootstrapping = false;
      setBusy(false);
      render();
    }
  }
}

function registerEventHandlers() {
  if (underparEventHandlersBound) {
    return;
  }
  underparEventHandlersBound = true;
  registerCoreInteractionHandlers();

  if (els.signInUpdateIndicator) {
    els.signInUpdateIndicator.addEventListener("click", () => {
      void triggerGetLatestWorkflow();
    });
  }

  if (els.signInOrgSelect) {
    els.signInOrgSelect.addEventListener("change", (event) => {
      const nextValue = String(event.target.value || "").trim();
      state.selectedTargetOrganizationKey =
        nextValue === PREAUTH_TARGET_ORG_PLACEHOLDER_VALUE ? "" : nextValue;
      renderSignInView();
    });
  }

  if (els.restrictedOrgSelect) {
    els.restrictedOrgSelect.addEventListener("change", (event) => {
      const previousSelection = String(state.selectedRestrictedOrgKey || "");
      state.selectedRestrictedOrgKey = String(event.target.value || "");
      const selected = getSelectedRestrictedOrgOption();
      if (selected) {
        state.restrictedOrgLabel = `Selected org: ${selected.label}`;
      }
      renderRestrictedView();
      if (
        selected &&
        state.selectedRestrictedOrgKey &&
        state.selectedRestrictedOrgKey !== previousSelection &&
        !state.busy &&
        !state.restrictedOrgSwitchBusy
      ) {
        void onRestrictedOrgSwitch();
      }
    });
  }

  if (els.signOutBtn) {
    els.signOutBtn.addEventListener("click", () => {
      void signOutAndResetSession();
    });
  }

  if (els.getLatestBtn) {
    els.getLatestBtn.addEventListener("click", () => {
      void triggerGetLatestWorkflow();
    });
  }

  if (els.mediaCompanyConsoleLaunchBtn) {
    els.mediaCompanyConsoleLaunchBtn.addEventListener("click", async (event) => {
      event.preventDefault();
      try {
        await openActiveProgrammerConsoleApplications(resolveSelectedProgrammer(), {
          activate: true,
        });
      } catch (error) {
        setStatus(error instanceof Error ? error.message : String(error), "error");
      }
    });
  }

  if (els.mvpdWorkspaceLaunchBtn) {
    els.mvpdWorkspaceLaunchBtn.addEventListener("click", async (event) => {
      event.preventDefault();
      const selectedProgrammer = resolveSelectedProgrammer();
      const selectedServices = selectedProgrammer?.programmerId
        ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
        : null;
      try {
        await mvpdWorkspaceOpenFromRestV2(selectedProgrammer, selectedServices, {
          activate: true,
          forceRefresh: true,
        });
      } catch (error) {
        setStatus(error instanceof Error ? error.message : String(error), "error");
      }
    });
  }

  els.mediaCompanySelect.addEventListener("blur", () => {
    flushPendingMediaCompanySelectionHydration();
    flushPendingMediaCompanyOptionHydrationState();
  });

  els.mediaCompanySelect.addEventListener("keydown", (event) => {
    if (event.key !== "Enter") {
      return;
    }
    window.setTimeout(() => {
      flushPendingMediaCompanySelectionHydration();
      flushPendingMediaCompanyOptionHydrationState();
    }, 0);
  });

  els.mediaCompanySelect.addEventListener("change", (event) => {
    state.selectedProgrammerKey = String(event.target.value || "");
    const controllerReason = "media-company-change";
    const selectedProgrammer = resolveSelectedProgrammer();
    emitGlobalSelectorChangeLog(
      "Media Company",
      state.selectedProgrammerKey,
      selectedProgrammer
        ? `${String(selectedProgrammer.programmerName || "").trim()} - ${String(selectedProgrammer.programmerId || "").trim()}`
        : ""
    );
    scheduleMediaCompanySelectionHydration(controllerReason);
  });

  els.requestorSelect.addEventListener("change", async (event) => {
    const nextRequestorId = String(event.target.value || "").trim();
    try {
      await maybeAutoStopRestV2RecordingForSelectionChange(
        {
          requestorId: nextRequestorId,
          mvpdId: "",
        },
        {
          reason: "Requestor change",
        }
      );
    } catch (error) {
      setStatus(`Auto-stop before Requestor switch failed: ${error instanceof Error ? error.message : String(error)}`, "error");
    }

    state.selectedRequestorId = nextRequestorId;
    state.selectedMvpdId = "";
    emitGlobalSelectorChangeLog("Requestor ID", state.selectedRequestorId, state.selectedRequestorId);
    await refreshProgrammerPanels({
      controllerReason: "requestor-change",
    });
    await populateMvpdSelectForRequestor(state.selectedRequestorId);
    const esmWorkspaceState = getActiveEsmWorkspaceState();
    if (esmWorkspaceState) {
      esmWorkspaceBroadcastControllerState(esmWorkspaceState);
      syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    }
    const degradationState = getActiveDegradationWorkspaceState();
    if (degradationState) {
      degradationSyncGoButtonLabel(degradationState);
      syncDegradationWorkspaceRecordingControls(degradationState);
    }
    const cmState = getActiveCmState();
    if (cmState) {
      cmBroadcastControllerState(cmState);
    }
    const selectedProgrammer = resolveSelectedProgrammer();
    const selectedServices = selectedProgrammer?.programmerId
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
      : null;
    mvpdWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices);
    refreshMvpdWorkspaceTools();
    void mvpdWorkspaceRefreshSelectedSnapshot({
      programmer: selectedProgrammer,
      services: selectedServices,
      forceRefresh: true,
      onlyIfWorkspaceOpen: false,
      surfaceMissingSelectionError: false,
    });
  });

  els.mvpdSelect.addEventListener("change", async (event) => {
    const nextMvpdId = String(event.target.value || "");
    const nextRequestorId = String(state.selectedRequestorId || "").trim();
    try {
      await maybeAutoStopRestV2RecordingForSelectionChange(
        {
          requestorId: nextRequestorId,
          mvpdId: nextMvpdId,
        },
        {
          reason: "MVPD change",
        }
      );
    } catch (error) {
      setStatus(`Auto-stop before MVPD switch failed: ${error instanceof Error ? error.message : String(error)}`, "error");
    }

    state.selectedMvpdId = nextMvpdId;
    const mvpdSelectionLabel = state.selectedMvpdId
      ? String(getRestV2MvpdPickerLabel(String(state.selectedRequestorId || "").trim(), state.selectedMvpdId) || "")
      : "";
    syncGlobalQuickLaunchButtons();
    emitGlobalSelectorChangeLog("MVPD", state.selectedMvpdId, mvpdSelectionLabel);
    const selectedProgrammer = resolveSelectedProgrammer();
    const selectedServices = selectedProgrammer?.programmerId
      ? getCurrentPremiumAppsSnapshot(selectedProgrammer.programmerId)
      : null;
    const mvpdClearLabel = state.selectedMvpdId
      ? getRestV2MvpdPickerLabel(String(state.selectedRequestorId || "").trim(), state.selectedMvpdId)
      : "";
    // Non-negotiable UX: switching MVPD must clear MVPD Workspace immediately before redraw.
    void mvpdWorkspaceSendWorkspaceMessage("workspace-clear", {
      programmerId: String(selectedProgrammer?.programmerId || "").trim(),
      requestorId: String(state.selectedRequestorId || "").trim(),
      mvpdId: String(state.selectedMvpdId || "").trim(),
      mvpdLabel: mvpdClearLabel,
    });
    void refreshProgrammerPanels({ controllerReason: "mvpd-change" });
    refreshRestV2LoginPanels();
    const esmWorkspaceState = getActiveEsmWorkspaceState();
    if (esmWorkspaceState) {
      esmWorkspaceBroadcastControllerState(esmWorkspaceState);
      syncEsmWorkspaceRecordingControls(esmWorkspaceState);
    }
    const degradationState = getActiveDegradationWorkspaceState();
    if (degradationState) {
      degradationSyncGoButtonLabel(degradationState);
      syncDegradationWorkspaceRecordingControls(degradationState);
    }
    const cmState = getActiveCmState();
    if (cmState) {
      cmBroadcastControllerState(cmState);
    }
    mvpdWorkspaceBroadcastSelectedControllerState(selectedProgrammer, selectedServices);
    refreshMvpdWorkspaceTools();
    void mvpdWorkspaceRefreshSelectedSnapshot({
      programmer: selectedProgrammer,
      services: selectedServices,
      forceRefresh: false,
      onlyIfWorkspaceOpen: false,
      surfaceMissingSelectionError: false,
    }).then((snapshotResult) => {
      const expectedProgrammerId = String(selectedProgrammer?.programmerId || "").trim();
      const expectedRequestorId = String(nextRequestorId || "").trim();
      const expectedMvpdId = String(nextMvpdId || "").trim();
      if (snapshotResult?.ok !== true) {
        return;
      }
      if (
        String(resolveSelectedProgrammer()?.programmerId || "").trim() !== expectedProgrammerId ||
        String(state.selectedRequestorId || "").trim() !== expectedRequestorId ||
        String(state.selectedMvpdId || "").trim() !== expectedMvpdId
      ) {
        return;
      }
      const currentServices = expectedProgrammerId
        ? getCurrentPremiumAppsSnapshot(expectedProgrammerId) || selectedServices
        : selectedServices;
      if (currentServices && typeof currentServices === "object") {
        renderPremiumServices(currentServices, selectedProgrammer, {
          controllerReason: "mvpd-resource-snapshot",
        });
      }
    });
  });

  document.addEventListener("click", (event) => {
    if (!state.avatarMenuOpen || !els.avatarMenu) {
      return;
    }

    const target = event.target;
    if (!(target instanceof Node)) {
      closeAvatarMenu();
      return;
    }

    if (els.avatarMenu.contains(target) || els.authBtn.contains(target)) {
      return;
    }
    closeAvatarMenu();
  });

  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape") {
      closeAvatarMenu();
    }
  });

  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState !== "visible") {
      return;
    }
    if (shouldRunExperienceCloudSessionMonitor()) {
      void runExperienceCloudSessionMonitorTick("visibility");
    }
  });

  window.addEventListener("focus", () => {
    if (shouldRunExperienceCloudSessionMonitor()) {
      void runExperienceCloudSessionMonitorTick("focus");
    }
  });

  window.addEventListener(
    "pagehide",
    () => {
      shutdownSidepanelControllerBridge();
      stopExperienceCloudSessionMonitor();
    },
    { once: true }
  );
}

async function settleUnderparInitStep(label = "", task = null, fallbackValue = null) {
  if (typeof task !== "function") {
    return fallbackValue;
  }

  try {
    return await task();
  } catch (error) {
    const normalizedLabel = String(label || "UnderPAR init step").trim() || "UnderPAR init step";
    log(`${normalizedLabel} failed`, {
      error: error instanceof Error ? error.message : String(error),
    });
    return fallbackValue;
  }
}

let underparDeferredStartupTasksScheduled = false;
let underparDeferredStartupTasksPromise = null;

async function runUnderparDeferredStartupTasks() {
  const startupSteps = [
    ["Global network fetch tracker", () => installGlobalNetworkFetchTracker()],
    ["ESM workspace runtime listener", () => ensureEsmWorkspaceRuntimeListener()],
    ["ESM workspace tab watcher", () => ensureEsmWorkspaceWorkspaceTabWatcher()],
    ["BlondieTime workspace runtime listener", () => ensureBlondieTimeWorkspaceRuntimeListener()],
    ["BlondieTime workspace tab watcher", () => ensureBlondieTimeWorkspaceTabWatcher()],
    ["MEG workspace runtime listener", () => ensureMegWorkspaceRuntimeListener()],
    ["MEG workspace tab watcher", () => ensureMegWorkspaceWorkspaceTabWatcher()],
    ["UP Devtools VAULT action listener", () => ensureUpDevtoolsVaultActionListener()],
    ["CM runtime listener", () => ensureCmRuntimeListener()],
    ["CM workspace tab watcher", () => ensureCmWorkspaceTabWatcher()],
    ["MVPD workspace runtime listener", () => ensureMvpdWorkspaceRuntimeListener()],
    ["MVPD workspace tab watcher", () => ensureMvpdWorkspaceTabWatcher()],
    ["REST workspace runtime listener", () => ensureRestWorkspaceRuntimeListener()],
    ["REST workspace tab watcher", () => ensureRestWorkspaceTabWatcher()],
    ["Degradation workspace runtime listener", () => ensureDegradationWorkspaceRuntimeListener()],
    ["Degradation workspace tab watcher", () => ensureDegradationWorkspaceTabWatcher()],
    ["Bobtools workspace runtime listener", () => ensureBobtoolsWorkspaceRuntimeListener()],
    ["Bobtools workspace tab watcher", () => ensureBobtoolsWorkspaceTabWatcher()],
    ["REST V2 login tab watcher", () => ensureRestV2LoginTabWatcher()],
    ["REST V2 Bobtools redirect watcher", () => ensureRestV2BobtoolsRedirectWatcher()],
    ["AdobePASS environment storage listener", () => registerAdobePassEnvironmentStorageListener()],
    ["Pass VAULT storage listener", () => registerPassVaultStorageListener()],
    ["UnderPAR ESM deeplink storage listener", () => registerUnderparEsmDeeplinkStorageListener()],
    ["Sidepanel controller bridge", () => startSidepanelControllerBridge()],
  ];

  for (const [label, task] of startupSteps) {
    await settleUnderparInitStep(label, task);
  }

  window.setTimeout(() => {
    void settleUnderparInitStep("Avatar menu update state", () => loadAvatarMenuUpdateState(false));
  }, 750);
}

function scheduleUnderparDeferredStartupTasks() {
  if (underparDeferredStartupTasksScheduled) {
    return;
  }
  underparDeferredStartupTasksScheduled = true;
  window.setTimeout(() => {
    if (underparDeferredStartupTasksPromise) {
      return;
    }
    underparDeferredStartupTasksPromise = runUnderparDeferredStartupTasks().finally(() => {
      underparDeferredStartupTasksPromise = null;
    });
  }, 0);
}

async function init() {
  if (ENABLE_IMS_AVATAR_RENDERING !== true) {
    purgeAvatarCaches();
  }
  registerCoreInteractionHandlers();
  syncGlobalNetworkActivityIndicator();
  renderBuildInfo();
  renderDebugConsole();
  resetWorkflowForLoggedOut();
  registerEventHandlers();
  await settleUnderparInitStep("Manual sign-out hold load", () => loadManualSignOutHold());
  await settleUnderparInitStep("Initial shell render", () => render());
  let environment = resolveAdobePassEnvironment(DEFAULT_ADOBEPASS_ENVIRONMENT.key);
  try {
    environment = await initializeAdobePassEnvironment();
  } catch (error) {
    applyAdobePassEnvironment(environment);
    log("AdobePASS environment bootstrap failed", error instanceof Error ? error.message : String(error));
  }
  logDecisionPoint(`Sidepanel initialized | UnderPAR ${chrome.runtime?.getManifest?.()?.version || "unknown"}`, {
    location: String(window.location.href || ""),
    adobePassEnvironment: {
      key: String(environment?.key || ""),
      label: String(environment?.label || ""),
      consoleBase: String(environment?.consoleBase || ""),
      mgmtBase: String(environment?.mgmtBase || ""),
      spBase: String(environment?.spBase || ""),
    },
  });
  await settleUnderparInitStep("Pass VAULT load", () => ensurePassVaultLoaded({ forceReload: false }));
  void renderBuildInfo();
  await settleUnderparInitStep("Session bootstrap", () => bootstrapSession("startup"));
  render();
  scheduleUnderparDeferredStartupTasks();
}

void init();
